INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AADE_WEBSERVICE_KEY', 'string', NULL, 'societe', 'Stores the API key (password) credential for the Greek AADE VAT validation web service.', 'Written via admin/company.php (line 283) and rendered as a password input (line 930). Used in societe/checkvat/checkVatGr.php (line 29) and societe/card.php (line 85) as the password for AADE authentication.', 'Setting this value provides the secret credential required to authenticate VAT number lookups against the AADE web service.', 'String (AADE web service API key/password); empty means authentication will fail.', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:283|write|dolibarr_set_const($db, \"AADE_WEBSERVICE_KEY\", GETPOST(\"AADE_WEBSERVICE_KEY\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "societe/checkvat/checkVatGr.php:29|read|$password = getDolGlobalString(''AADE_WEBSERVICE_KEY''); // Get password from request", "societe/card.php:85|read|$p = getDolGlobalString(''AADE_WEBSERVICE_KEY'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AADE_WEBSERVICE_USER', 'string', NULL, 'societe', 'Stores the username credential for the Greek AADE VAT validation web service.', 'Written via admin/company.php (line 282) and displayed as a text input (line 925). Used in societe/checkvat/checkVatGr.php (line 28) and societe/card.php (line 84) to authenticate against the AADE web service.', 'Setting this value enables the Greek VAT number validation feature; leaving it empty disables authentication to the AADE service.', 'String (AADE web service username); empty means the service cannot authenticate.', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:282|write|dolibarr_set_const($db, \"AADE_WEBSERVICE_USER\", GETPOST(\"AADE_WEBSERVICE_USER\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "societe/checkvat/checkVatGr.php:28|read|$username = getDolGlobalString(''AADE_WEBSERVICE_USER''); // Get username from request", "societe/card.php:84|read|$u = getDolGlobalString(''AADE_WEBSERVICE_USER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_AUTOFIX_MISSING_LINK_TO_USER_ON_SALARY_BANK_PAYMENT', 'string', NULL, 'accountancy', 'Automatically fixes missing user links on salary bank payment entries during journal processing.', 'Checked in accountancy/journal/bankjournal.php:594; when set, the journal applies an automatic fix for salary bank payment lines that are missing their user link. No admin UI write found; HIDDEN_GUESS is 1. Only 1 occurrence found.', 'When enabled, the bank journal attempts to repair missing user associations on salary payments during journal generation; the exact repair logic is in the surrounding code block.', 'Any non-empty value = auto-fix enabled; empty = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:594|check|if (getDolGlobalString(''ACCOUNTANCY_AUTOFIX_MISSING_LINK_TO_USER_ON_SALARY_BANK_PAYMENT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_AUXACCOUNT_DONOTSEARCH_ANYWHERE', 'string', NULL, 'core', 'Restricts auxiliary account search to prefix-only matching instead of substring matching.', 'Read in core/ajax/auxaccount.php:74 — when set, the SQL LIKE prefix is empty (exact/prefix match); when unset, a ''%'' wildcard is prepended for substring search.', 'Enabling this constant makes the auxiliary account search faster on large account tables by avoiding full-table substring scans.', 'Empty/unset = substring search (prefix ''%'' added); truthy value = prefix-only search (no leading wildcard).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/auxaccount.php:74|read|$prefix = getDolGlobalString(''ACCOUNTANCY_AUXACCOUNT_DONOTSEARCH_ANYWHERE'') ? '''' : ''%'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_AUXACCOUNT_SEARCH_LIMIT', 'string', NULL, 'core', 'Sets the maximum number of auxiliary account results returned by the accountancy AJAX search.', 'Read as an integer in core/ajax/auxaccount.php:64 with a default of 100. Controls the SQL LIMIT applied to the auxiliary account lookup query.', 'Increasing this limit returns more results but may slow the AJAX response; decreasing it speeds up the search at the cost of completeness.', 'Integer (default 100); maximum number of rows returned by auxiliary account search.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/auxaccount.php:64|read|$limit     = getDolGlobalInt(''ACCOUNTANCY_AUXACCOUNT_SEARCH_LIMIT'', 100);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT', 'bool', NULL, 'compta', 'Sets the subledger account selection mode: 0 = dropdown list, integer N >= 2 = search-to-select triggered after N-1 characters.', 'Checked in admin/system/perf.php:658 and compta/bank/various_payment/card.php:737,68 against value > 0. Read in core/ajax/auxaccount.php:65 where minLength is set to value-1, and in core/class/html.formaccounting.class.php:511. Comment at core/ajax/auxaccount.php:22 states ''Called by select_auxaccount() when ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT >= 2''. Configurable via admin/system/perf.php.', 'Setting to 0 uses a standard dropdown for subledger account selection. Setting to 2 or higher activates an AJAX search triggered after the user types (value-1) characters, improving performance with large subledger account lists.', '0 = dropdown list; integer >= 2 = AJAX search triggered after (value-1) characters typed', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/ajax/auxaccount.php:22  *              Called by select_auxaccount() when ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT >= 2", "core/class/html.formaccounting.class.php:489  * Behavior depends on constant ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT:", "core/ajax/auxaccount.php:65|read|$minLength = getDolGlobalInt(''ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT'', 2) - 1;", "compta/bank/various_payment/card.php:737|check|if (getDolGlobalString(''ACCOUNTANCY_AUXACCOUNT_USE_SEARCH_TO_SELECT'') > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_DISABLE_CLOSURE_LINE_BY_LINE', 'bool', NULL, 'accountancy', 'Disables line-by-line closure processing in the accounting module, merging closure into fewer steps.', 'Checked in accountancy/closure/index.php (lines 358, 430, 424, 447), accountancy/bookkeeping/export.php (lines 219, 837), accountancy/class/bookkeeping.class.php:2841, and accountancy/bookkeeping/listbyaccount.php:213. When set, the ''date_validated'' column is hidden and closure step numbering changes.', 'When enabled, the accounting closure process skips the line-by-line validation step and the date_validated column is disabled in related views; when disabled, line-by-line closure is available.', 'Truthy (non-empty) to disable line-by-line closure; empty/unset to enable it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:837|check|if (!getDolGlobalString(\"ACCOUNTANCY_DISABLE_CLOSURE_LINE_BY_LINE\")) {", "accountancy/closure/index.php:358|check|if (!getDolGlobalString(\"ACCOUNTANCY_DISABLE_CLOSURE_LINE_BY_LINE\")) {", "accountancy/bookkeeping/listbyaccount.php:213|read|''t.date_validated'' => array(''label'' => \"DateValidation\", ''checked'' => ''-1'', ''enabled'' => (string) (int) !getDolGlobalString(\"ACCOUNTANCY_DISABLE_CLOSURE_LINE_BY_LINE\")),", "accountancy/class/bookkeeping.class.php:2841|check|if (getDolGlobalString(\"ACCOUNTANCY_DISABLE_CLOSURE_LINE_BY_LINE\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_DO_NOT_AUTOFILL_ACCOUNT_WITH_GENERIC', 'string', NULL, 'accountancy', 'When enabled, prevents the system from automatically filling an empty product accounting account with the generic account code.', 'Checked once in accountancy/class/accountingaccount.class.php:924 in a condition that also requires suggestedid and code_p to be empty and code_l to be non-empty. No admin UI is configured.', 'Enabling this constant stops the auto-fill fallback that copies a generic account code into the product account field when no specific account is assigned.', 'Truthy (non-empty / 1) = auto-fill disabled; falsy (empty / 0) = auto-fill enabled (default behavior).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountingaccount.class.php:924|check|if (empty($suggestedid) && empty($code_p) && !empty($code_l) && !getDolGlobalString(''ACCOUNTANCY_DO_NOT_AUTOFILL_ACCOUNT_WITH_GENERIC'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_ENABLE_FKDOCDET', 'bool', NULL, 'accountancy', 'When enabled, populates the fk_doc_det (document detail foreign key) field on bookkeeping entries, linking them to their source document lines.', 'Checked in accountancy/class/bookkeeping.class.php at lines 344 and 365 during bookkeeping record creation.', 'Enabling this constant causes bookkeeping entries to store a reference to the originating document detail line, enabling more granular audit tracing.', '0 or unset = fk_doc_det not populated; truthy = fk_doc_det populated on bookkeeping entries.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/bookkeeping.class.php:344|check|if (getDolGlobalString(''ACCOUNTANCY_ENABLE_FKDOCDET'')) {", "accountancy/class/bookkeeping.class.php:365|check|if (getDolGlobalString(''ACCOUNTANCY_ENABLE_FKDOCDET'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_ER_DATE_RECORD', 'string', NULL, 'accountancy', 'Controls whether the expense report date or the record/accounting date is used when transferring expense reports to the accounting journal.', 'Configured via accountancy/admin/index.php:639. Read in accountancy/journal/expensereportsjournal.php:207 which uses it to select the date source. Only 2 occurrences found.', 'When set, the accounting record date is used for expense report journal entries instead of the expense report date.', '0 or unset = use expense report date; non-zero = use record/accounting date', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:639|check|if (getDolGlobalInt(''ACCOUNTANCY_ER_DATE_RECORD'')) {", "accountancy/journal/expensereportsjournal.php:207|check|if (getDolGlobalInt(''ACCOUNTANCY_ER_DATE_RECORD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_FISCALYEAR_DEFAULT', 'string', NULL, 'accountancy', 'Stores the rowid of the default fiscal year used to pre-filter bookkeeping views.', 'Set via accountancy/admin/fiscalyear.php (line 94). When set, bookkeeping pages such as export.php, balance.php, listbyaccount.php, and list.php use this value to filter entries to the selected fiscal year (e.g. accountancy/bookkeeping/export.php:175: `$sql .= " WHERE rowid = " . getDolGlobalInt(''ACCOUNTANCY_FISCALYEAR_DEFAULT'')`).', 'Changing this value redirects all bookkeeping list views to display entries for the newly selected fiscal year by default.', 'Integer (rowid of a fiscal year record); empty/0 means no default filter applied.', 0, 0, 'accountancy/admin/fiscalyear.php|accountancy/admin/fiscalyear.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/fiscalyear.php:94|write|dolibarr_set_const($db, ''ACCOUNTANCY_FISCALYEAR_DEFAULT'', $defaultFiscalYear, ''chaine'', 0, '''', $conf->entity);", "accountancy/bookkeeping/export.php:175|read|$sql .= \" WHERE rowid = \" . getDolGlobalInt(''ACCOUNTANCY_FISCALYEAR_DEFAULT'');", "accountancy/bookkeeping/balance.php:107|read|$sql .= \" WHERE rowid = \" . getDolGlobalInt(''ACCOUNTANCY_FISCALYEAR_DEFAULT'');", "accountancy/admin/fiscalyear.php:201|check|if (getDolGlobalString(''ACCOUNTANCY_FISCALYEAR_DEFAULT'') == (int) $fiscalyearstatic->ref) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_FISCAL_PERIOD_MODE', 'string', NULL, 'accountancy', 'Controls whether accounting entries can be written to closed fiscal periods; ''blockedonclosed'' prevents writes to closed periods.', 'Checked in 14 locations including accountancy/index.php:195, all journal pages (bankjournal.php:1253, purchasesjournal.php:1020, sellsjournal.php:1116, expensereportsjournal.php:636, variousjournal.php:252), and bookkeeping.class.php:305 and :729 which enforce the block at the data layer.', 'When set to ''blockedonclosed'', writing accounting entries to a closed fiscal period is blocked at both UI and class levels; any other value allows writes to closed periods.', '''blockedonclosed'' = block writes to closed fiscal periods; any other value or unset = allow writes', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/index.php:195|check|if (getDolGlobalString(''ACCOUNTANCY_FISCAL_PERIOD_MODE'') != ''blockedonclosed'') {", "accountancy/class/bookkeeping.class.php:305|check|if (getDolGlobalString(''ACCOUNTANCY_FISCAL_PERIOD_MODE'') == ''blockedonclosed'') {", "accountancy/class/bookkeeping.class.php:729|check|if (getDolGlobalString(''ACCOUNTANCY_FISCAL_PERIOD_MODE'') == ''blockedonclosed'') {", "accountancy/journal/bankjournal.php:1253|check|if (getDolGlobalString(''ACCOUNTANCY_FISCAL_PERIOD_MODE'') != ''blockedonclosed'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_HIDE_EXPORT_FILES_MENU', 'bool', NULL, 'core', 'Hides the accounting export files menu entries when set, removing them from the accountancy navigation.', 'Checked with negation at two locations in core/menus/standard/eldy.lib.php:1893 and 2020. No admin UI write detected.', 'Setting this constant removes accounting export file links from the menu. Removing it restores both menu entries.', 'Non-empty = export file menu items hidden; absent/empty = items shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:1893|check|if (!getDolGlobalString(''ACCOUNTANCY_HIDE_EXPORT_FILES_MENU'')) {", "core/menus/standard/eldy.lib.php:2020|check|if (!getDolGlobalString(''ACCOUNTANCY_HIDE_EXPORT_FILES_MENU'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_JOURNAL_USE_CURRENT_MONTH', 'bool', NULL, 'accountancy', 'When enabled, causes the sells journal to default to the current month instead of the previous month for its date range filter.', 'Checked once in accountancy/journal/sellsjournal.php:134. No admin UI is configured.', 'Enabling this constant changes the default date range presented to the user when opening the sells journal.', 'Truthy (non-empty / 1) = default to current month; falsy (empty / 0) = default to previous month.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:134|check|if (getDolGlobalString(''ACCOUNTANCY_JOURNAL_USE_CURRENT_MONTH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_MAX_TOO_MANY_LINES_TO_PROCESS', 'string', NULL, 'accountancy', 'Sets the maximum number of journal lines processed in a single run of the purchases or sells journal to prevent overload.', 'Read in accountancy/journal/purchasesjournal.php:384 and accountancy/journal/sellsjournal.php:418 via getDolGlobalInt with a default of 10000. No admin UI is configured.', 'Lowering this limit causes journal processing to stop earlier, leaving remaining lines unprocessed. The default cap is 10000 lines.', 'Integer; default is 10000.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:384|check|if ($i > getDolGlobalInt(''ACCOUNTANCY_MAX_TOO_MANY_LINES_TO_PROCESS'', 10000)) {", "accountancy/journal/sellsjournal.php:418|check|if ($i > getDolGlobalInt(''ACCOUNTANCY_MAX_TOO_MANY_LINES_TO_PROCESS'', 10000)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_SHOW_DEVELOP_JOURNAL', 'bool', NULL, 'core', 'Controls whether the detailed/developed accounting journal is shown in the menu.', 'Checked in core/menus/standard/auguria.lib.php:462 and core/menus/standard/eldy.lib.php:1855. When not set, the developed journal menu entry is hidden.', 'Setting this constant makes the developed accounting journal menu entry visible; leaving it unset hides that entry.', 'Non-empty = developed journal menu shown; empty or unset = hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/auguria.lib.php:462|check|if (!getDolGlobalString(''ACCOUNTANCY_SHOW_DEVELOP_JOURNAL'')) {", "core/menus/standard/eldy.lib.php:1855|check|if (!getDolGlobalString(''ACCOUNTANCY_SHOW_DEVELOP_JOURNAL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_SHOW_OPENING_BALANCE', 'bool', NULL, 'accountancy', 'Controls whether the opening balance column is displayed in the accounting bookkeeping balance report.', 'Checked in 12 locations across accountancy/bookkeeping/balance.php (lines 486, 515, 587, 592, 637, 668, 696, 701 and more) to conditionally render opening balance data. No admin UI is present.', 'Enabling this causes the opening balance column and related computations to appear in the balance report; disabling it hides that data.', '0 or unset = opening balance not shown; truthy value = opening balance displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/balance.php:486|check|if (getDolGlobalString(''ACCOUNTANCY_SHOW_OPENING_BALANCE'')) {", "accountancy/bookkeeping/balance.php:515|check|if (getDolGlobalString(''ACCOUNTANCY_SHOW_OPENING_BALANCE'')) {", "accountancy/bookkeeping/balance.php:637|check|if (getDolGlobalString(''ACCOUNTANCY_SHOW_OPENING_BALANCE'')) {", "accountancy/bookkeeping/balance.php:696|check|if (getDolGlobalString(''ACCOUNTANCY_SHOW_OPENING_BALANCE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_SHOW_PROD_DESC', 'bool', NULL, 'accountancy', 'Controls whether the product description column is shown in the accounting product account admin page.', 'Checked in accountancy/admin/productaccount.php at lines 608, 642, and 759 to conditionally render the product description column. Configured via accountancy/admin/productaccount.php.', 'Enabling this constant adds a description column to the product accounting account tables; disabling or leaving it unset hides that column.', 'Integer/bool (truthy=shown, 0/empty=hidden)', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:759|check|if (getDolGlobalInt(''ACCOUNTANCY_SHOW_PROD_DESC'')) {", "accountancy/admin/productaccount.php:608|check|if (getDolGlobalInt(''ACCOUNTANCY_SHOW_PROD_DESC'')) {", "accountancy/admin/productaccount.php:642|check|if (getDolGlobalInt(''ACCOUNTANCY_SHOW_PROD_DESC'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_TRUNC_DECIMAL_ON_BALANCE_REPORT', 'string', NULL, 'compta', 'When set to a non-zero integer, truncates decimal digits in balance report amount displays.', 'Checked in 8 locations all within compta/resultat/result.php (lines 393, 424, 448, 473, 643, 654, 664, 699). No admin UI write path exists in the payload.', 'Enabling this constant causes balance report monetary values to be displayed without decimal places.', 'Non-zero integer = truncate decimals in balance report; 0 or unset = show full precision (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/resultat/result.php:393|check|if (getDolGlobalInt(''ACCOUNTANCY_TRUNC_DECIMAL_ON_BALANCE_REPORT'')) {", "compta/resultat/result.php:424|check|if (getDolGlobalInt(''ACCOUNTANCY_TRUNC_DECIMAL_ON_BALANCE_REPORT'')) {", "compta/resultat/result.php:643|check|if (getDolGlobalInt(''ACCOUNTANCY_TRUNC_DECIMAL_ON_BALANCE_REPORT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_USE_EXPENSE_REPORT_VALIDATION_DATE', 'bool', NULL, 'accountancy', 'When enabled, uses the expense report validation date instead of the expense date for accounting line-binding filters.', 'Checked in accountancy/expensereport/lines.php:120 and accountancy/expensereport/list.php:135 where the date column or filter applied depends on this flag.', 'Enabling this constant shifts expense report accounting views to filter and sort by validation date rather than expense date.', 'Non-empty/truthy = use validation date for expense report accounting; empty/unset = use expense date (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/expensereport/lines.php:120|check|if (getDolGlobalString(''ACCOUNTANCY_USE_EXPENSE_REPORT_VALIDATION_DATE'')) {", "accountancy/expensereport/list.php:135|check|if (getDolGlobalString(''ACCOUNTANCY_USE_EXPENSE_REPORT_VALIDATION_DATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_USE_PRODUCT_ACCOUNT_ON_THIRDPARTY', 'bool', NULL, 'accountancy', 'Enables the ability to assign per-product accounting accounts directly on third-party (company) records.', 'Configured via accountancy/admin/index.php. Checked in 9 occurrences including societe/card.php:2042, :3404, accountancy/customer/list.php:961, accountancy/supplier/list.php:975, and accountancy/class/accountingaccount.class.php:870.', 'When enabled, accounting account fields per product appear on the third-party card, allowing overrides of default product accounting accounts for specific customers or suppliers.', '0 or unset = feature disabled; non-empty = feature enabled', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:487|check|if (getDolGlobalString(''ACCOUNTANCY_USE_PRODUCT_ACCOUNT_ON_THIRDPARTY'')) {", "societe/card.php:2042|check|if (getDolGlobalString(''ACCOUNTANCY_USE_PRODUCT_ACCOUNT_ON_THIRDPARTY'')) {", "accountancy/customer/list.php:961|check|if (getDolGlobalString(''ACCOUNTANCY_USE_PRODUCT_ACCOUNT_ON_THIRDPARTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTANCY_VALID_REDIRECT_TO_CARD', 'string', NULL, 'accountancy', 'Redirects the user to the bookkeeping entry card after validating an accounting entry.', 'Checked at accountancy/bookkeeping/card.php:459: ''if (getDolGlobalInt(''ACCOUNTANCY_VALID_REDIRECT_TO_CARD''))''. No admin UI write path is present.', 'When enabled, validating a bookkeeping entry redirects the user to the entry''s card view; when disabled, the default post-validation navigation is used.', '0 or not set = default post-validation navigation; non-zero = redirect to bookkeeping entry card after validation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/card.php:459|check|if (getDolGlobalInt(''ACCOUNTANCY_VALID_REDIRECT_TO_CARD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_', 'string', NULL, 'accountancy', 'Family of dynamic constants (ACCOUNTING_ACCOUNT_{TYPE}_DEPOSIT) that provide accounting account codes for deposit transactions by type.', 'Checked once dynamically in accountancy/class/accountingaccount.class.php:883 by appending strtoupper($type) and ''_DEPOSIT'' to ''ACCOUNTING_ACCOUNT_''. No admin UI is configured.', 'Setting these constants provides an accounting account for deposit entries of the given transaction type.', 'Chart-of-accounts code string; variant pattern is ACCOUNTING_ACCOUNT_{TYPE}_DEPOSIT.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountingaccount.class.php:883|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_'' . strtoupper($type) . ''_DEPOSIT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_CUSTOMER', 'string', NULL, 'accountancy', 'Stores the default general ledger account number used for customer entries in accounting journals.', 'Read across at least 8 journal files including accountancy/journal/bankjournal.php, sellsjournal.php, and treasuryjournal.php (22+ occurrences). Checked against '''' and ''-1'' to detect unconfigured state; the fallback value ''NotDefined'' is a reserved word used to flag missing configuration. No admin UI write found; HIDDEN_GUESS is 1.', 'If not set or set to ''-1'', customer accounting entries cannot be posted in affected journals; correct configuration is required for sales and bank journal processing.', 'String: general ledger account number; '''' or ''-1'' = not configured (treated as error in journals)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:270|read|$account_customer = getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/sellsjournal.php:225|read|$cptcli = getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER'', ''NotDefined'');", "accountancy/journal/bankjournal.php:1290|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER'') == \"\" || getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER'') == ''-1''", "accountancy/journal/sellsjournal.php:1136|read|$acctCustomerNotConfigured = in_array(getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER''), ['''',''-1'']);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_CUSTOMER_DEPOSIT', 'string', NULL, 'accountancy', 'Accounting account number used to book customer deposit invoices in the chart of accounts.', 'Configured via accountancy/admin/defaultaccounts.php (lines 341, 345). Read in accountancy/class/accountingaccount.class.php (lines 887, 910) to fetch the account object, and checked in accountancy/journal/sellsjournal.php (lines 690, 1357) when classifying journal entries for deposit invoices.', 'Setting this to a valid account number causes deposit invoice lines to be posted to that account in the sell journal; leaving it empty or set to ''-1'' skips the deposit-specific accounting path.', 'String: chart-of-accounts account number; ''-1'' means not configured.', 0, 0, 'accountancy/admin/defaultaccounts.php|accountancy/admin/defaultaccounts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/defaultaccounts.php:345|check|if (isModEnabled(''societe'') && getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_DEPOSIT'') && getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_DEPOSIT'') != ''-1'') {", "accountancy/journal/sellsjournal.php:690|check|if ($k == getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_DEPOSIT'')) {", "accountancy/class/accountingaccount.class.php:887|read|$result = $accountdeposittoventilated->fetch(0, getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_DEPOSIT''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_CUSTOMER_RETAINED_WARRANTY', 'string', NULL, 'accountancy', 'Specifies the accounting account code used to record customer retained warranty amounts in the sales journal.', 'Read across four locations in accountancy/journal/sellsjournal.php (lines 509, 574, 984, 1276) to fetch, record, and export the retained warranty account. Used both for bookkeeping entries and journal exports.', 'If not set or set to an invalid account code, retained warranty journal entries will reference an incorrect or missing account, causing bookkeeping errors.', 'String representing a valid accounting account code.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:509|read|$accountingaccountcustomerwarranty->fetch(0, getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_RETAINED_WARRANTY''), true);", "accountancy/journal/sellsjournal.php:574|read|$bookkeeping->numero_compte = getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_RETAINED_WARRANTY'');", "accountancy/journal/sellsjournal.php:984|read|print ''\"''.length_accountg(getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_RETAINED_WARRANTY'')).''\"''.$sep;", "accountancy/journal/sellsjournal.php:1276|read|$accountoshow = length_accountg(getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_RETAINED_WARRANTY''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_CUSTOMER_USE_AUXILIARY_ON_DEPOSIT', 'bool', NULL, 'accountancy', 'Controls whether the auxiliary (third-party) account is applied when posting customer deposit invoices.', 'Configured via accountancy/admin/defaultaccounts.php (lines 199 write, 348 check). Checked in accountancy/journal/sellsjournal.php at lines 689 and 1356 to decide whether auxiliary account details are included in deposit journal entries.', 'When enabled, deposit invoice journal lines include auxiliary account information; when disabled, they are posted without it.', 'yesno (1/0): 1 to use auxiliary account on customer deposits; 0 to disable.', 0, 0, 'accountancy/admin/defaultaccounts.php|accountancy/admin/defaultaccounts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/defaultaccounts.php:199|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ACCOUNT_CUSTOMER_USE_AUXILIARY_ON_DEPOSIT\", $setDisableAuxiliaryAccountOnCustomerDeposit, ''yesno'', 0, '''', $conf->entity);", "accountancy/admin/defaultaccounts.php:348|check|if (getDolGlobalInt(''ACCOUNTING_ACCOUNT_CUSTOMER_USE_AUXILIARY_ON_DEPOSIT'')) {", "accountancy/journal/sellsjournal.php:689|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_USE_AUXILIARY_ON_DEPOSIT'')) {", "accountancy/journal/sellsjournal.php:1356|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_CUSTOMER_USE_AUXILIARY_ON_DEPOSIT'')) {"]', 'high', NULL);
