INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_SUPPLIER_DEPOSIT', 'string', NULL, 'accountancy', 'Accounting account number used to book supplier deposit invoices in the chart of accounts.', 'Configured via accountancy/admin/defaultaccounts.php (lines 368, 372). Read in accountancy/class/accountingaccount.class.php (lines 889, 912) to fetch the account object, and checked in accountancy/journal/purchasesjournal.php (lines 585, 1230) when classifying journal entries for supplier deposits.', 'Setting this to a valid account number causes supplier deposit lines to be posted to that account in the purchase journal; leaving it empty or set to ''-1'' skips the deposit-specific path.', 'String: chart-of-accounts account number; ''-1'' means not configured.', 0, 0, 'accountancy/admin/defaultaccounts.php|accountancy/admin/defaultaccounts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/defaultaccounts.php:372|check|if (isModEnabled(''societe'') && getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_DEPOSIT'') && getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_DEPOSIT'') != ''-1'') {", "accountancy/journal/purchasesjournal.php:585|check|if ($k == getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_DEPOSIT'')) {", "accountancy/class/accountingaccount.class.php:889|read|$result = $accountdeposittoventilated->fetch(0, getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_DEPOSIT''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_SUPPLIER_USE_AUXILIARY_ON_DEPOSIT', 'bool', NULL, 'accountancy', 'Controls whether the auxiliary (third-party) account is applied when posting supplier deposit invoices.', 'Configured via accountancy/admin/defaultaccounts.php (lines 213 write, 375 check). Checked in accountancy/journal/purchasesjournal.php at lines 584 and 1229 to decide whether auxiliary account details are included in supplier deposit journal entries.', 'When enabled, supplier deposit journal lines include auxiliary account information; when disabled, they are posted without it.', 'yesno (1/0): 1 to use auxiliary account on supplier deposits; 0 to disable.', 0, 0, 'accountancy/admin/defaultaccounts.php|accountancy/admin/defaultaccounts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/defaultaccounts.php:213|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ACCOUNT_SUPPLIER_USE_AUXILIARY_ON_DEPOSIT\", $setDisableAuxiliaryAccountOnSupplierDeposit, ''yesno'', 0, '''', $conf->entity);", "accountancy/admin/defaultaccounts.php:375|check|if (getDolGlobalInt(''ACCOUNTING_ACCOUNT_SUPPLIER_USE_AUXILIARY_ON_DEPOSIT'')) {", "accountancy/journal/purchasesjournal.php:584|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_USE_AUXILIARY_ON_DEPOSIT'')) {", "accountancy/journal/purchasesjournal.php:1229|check|if (getDolGlobalString(''ACCOUNTING_ACCOUNT_SUPPLIER_USE_AUXILIARY_ON_DEPOSIT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_SUSPENSE', 'string', NULL, 'accountancy', 'Stores the general ledger suspense account number used when no specific third-party account can be determined.', 'Read in accountancy/journal/bankjournal.php at lines 732, 963, 1192, 1568, and 1474 where it is shown as ''UnknownAccountForThirdparty''. Also read in core/boxes/box_accountancy_suspense_account.php:73. Checked against '''' and ''-1'' at bankjournal.php:1471. No admin UI write found; HIDDEN_GUESS is 1.', 'If not set or set to ''-1'', the bank journal cannot post lines for unknown third parties; when set, those lines are posted to the suspense account for later correction.', 'String: general ledger account number; '''' or ''-1'' = not configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:732|read|$accountingaccountsuspense->fetch(0, getDolGlobalString(''ACCOUNTING_ACCOUNT_SUSPENSE''), true);", "accountancy/journal/bankjournal.php:1471|check|if (!getDolGlobalString(''ACCOUNTING_ACCOUNT_SUSPENSE'') || getDolGlobalString(''ACCOUNTING_ACCOUNT_SUSPENSE'') == ''-1'') {", "accountancy/journal/bankjournal.php:1474|read|$accounttoshow = ''<span class=\"warning small\">''.$langs->trans(''UnknownAccountForThirdparty'', length_accountg(getDolGlobalString(''ACCOUNTING_ACCOUNT_SUSPENSE''))).''</span>'';", "core/boxes/box_accountancy_suspense_account.php:73|read|$suspenseAccount = getDolGlobalString(''ACCOUNTING_ACCOUNT_SUSPENSE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ACCOUNT_TRANSFER_CASH', 'string', NULL, 'accountancy', 'Stores the general ledger account number used for cash transfer entries between bank accounts.', 'Read in accountancy/journal/bankjournal.php:276 and accountancy/journal/treasuryjournal.php:1066, both with ''NotDefined'' as reserved-word fallback. No admin UI write found; HIDDEN_GUESS is 1. Only 2 occurrences found.', 'If not set, cash transfer lines in the bank and treasury journals use ''NotDefined'' as the account, which will cause posting errors.', 'String: general ledger account number; empty = not configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:276|read|$account_transfer = getDolGlobalString(''ACCOUNTING_ACCOUNT_TRANSFER_CASH'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/treasuryjournal.php:1066|read|$account_transfer = getDolGlobalString(''ACCOUNTING_ACCOUNT_TRANSFER_CASH'', ''NotDefined''); // NotDefined is a reserved word"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_BANK_CONCILIATED', 'string', NULL, 'accountancy', 'Filters the bank journal to include only reconciled (conciliated) bank lines, or all lines.', 'Configured via accountancy/admin/index.php:653. Read in accountancy/journal/bankjournal.php:91 and accountancy/journal/treasuryjournal.php:69 as $only_rappro. Value 2 is checked specifically in the admin page; the journal files use the integer value directly as a filter parameter.', 'When set to 2 (or non-zero), the bank and treasury journals show only reconciled bank transactions; when 0 or unset, all bank lines are included.', '0 or unset = all bank lines; 2 = only reconciled/conciliated lines', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:653|check|if (getDolGlobalInt(''ACCOUNTING_BANK_CONCILIATED'') == 2) {", "accountancy/journal/bankjournal.php:91|read|$only_rappro = getDolGlobalInt(''ACCOUNTING_BANK_CONCILIATED'');", "accountancy/journal/treasuryjournal.php:69|read|$only_rappro = getDolGlobalInt(''ACCOUNTING_BANK_CONCILIATED'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_CAN_REOPEN_CLOSED_PERIOD', 'string', NULL, 'accountancy', 'Allows administrators to reopen a closed fiscal year period.', 'Checked in accountancy/admin/fiscalyear_card.php (line 396) to show the reopen button when the period is closed, and at line 176 to authorize the reopen action.', 'Enabling this setting makes the reopen action available for closed fiscal periods; disabling it prevents reopening once a period is closed.', 'Truthy string (non-empty) = reopening closed periods is allowed; empty/not set = reopening is not allowed.', 0, 0, 'accountancy/admin/fiscalyear_card.php|accountancy/admin/fiscalyear_card.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/fiscalyear_card.php:396|check|if (getDolGlobalString(''ACCOUNTING_CAN_REOPEN_CLOSED_PERIOD'') && $object->status == $object::STATUS_CLOSED) {", "accountancy/admin/fiscalyear_card.php:176|read|} elseif ($action == ''reopen'' /* && $permissiontoadd // always true */ && getDolGlobalString(''ACCOUNTING_CAN_REOPEN_CLOSED_PERIOD'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_CLONING_ENABLE_INPUT_JOURNAL', 'bool', NULL, 'accountancy', 'Allows users to specify an input journal when cloning bookkeeping entries, instead of inheriting the source journal.', 'Checked at accountancy/bookkeeping/card.php:773, accountancy/bookkeeping/listbyaccount.php:948, and accountancy/bookkeeping/list.php:923 to show the journal input field on clone. Read at accountancy/class/bookkeeping.class.php:3512-3513 and :3617-3618 to determine whether to use the user-supplied journal or the source entry''s journal.', 'When enabled, cloned bookkeeping entries use the journal code/label entered by the user; when disabled, the source entry''s journal is copied verbatim.', '0 or not set = cloned entry inherits source journal; non-zero = user can specify a new journal when cloning.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/card.php:773|check|if (getDolGlobalString(''ACCOUNTING_CLONING_ENABLE_INPUT_JOURNAL'')) {", "accountancy/class/bookkeeping.class.php:3512|read|$code_journal = getDolGlobalString(''ACCOUNTING_CLONING_ENABLE_INPUT_JOURNAL'') ? $code_journal : $bookKeeping->code_journal;", "accountancy/class/bookkeeping.class.php:3513|read|$journal_label = getDolGlobalString(''ACCOUNTING_CLONING_ENABLE_INPUT_JOURNAL'') ? $accountingJournal->label : $bookKeeping->journal_label;", "accountancy/bookkeeping/list.php:923|check|if (getDolGlobalString(''ACCOUNTING_CLONING_ENABLE_INPUT_JOURNAL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_BALANCE_SHEET_ACCOUNT', 'string', NULL, 'accountancy', 'Specifies the comma-separated list of accounting group codes used to identify balance sheet accounts during fiscal year closure.', 'Configured via accountancy/admin/closure.php:76 and read in accountancy/closure/index.php:125 and accountancy/class/bookkeeping.class.php:3054. The value is split by comma and used to filter balance sheet accounts in closure calculations.', 'An incorrect or empty value will cause the fiscal closure to fail or skip balance sheet account processing; accountancy/closure/index.php:163 blocks closure if the constant is not set.', 'Comma-separated string of accounting group codes (e.g., ''1,2,3''); empty = closure blocked', 0, 0, 'accountancy/admin/closure.php|accountancy/admin/closure.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/closure.php:76|write|if (!dolibarr_set_const($db, ''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_BALANCE_SHEET_ACCOUNT'', $accountinggroupsusedforbalancesheetaccount, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/closure/index.php:163|check|if (!getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_BALANCE_SHEET_ACCOUNT'')) {", "accountancy/closure/index.php:125|read|$accounting_groups_used_for_balance_sheet_account = array_filter(array_map(''trim'', explode('','', getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_BALANCE_SHEET_ACCO", "accountancy/class/bookkeeping.class.php:3054|read|$accounting_groups_used_for_balance_sheet_account = array_filter(array_map(''trim'', explode('','', getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_BALANCE_SHEET_ACCO"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_INCOME_STATEMENT', 'string', NULL, 'accountancy', 'Comma-separated list of accounting groups (account prefixes) used to identify income statement accounts during year-end closure.', 'Set via accountancy/admin/closure.php:85 and displayed as a text input at :178. Parsed as a comma-separated list in accountancy/closure/index.php:126 and accountancy/class/bookkeeping.class.php:2928 and :3055 to filter accounts for income statement processing.', 'Changing this list alters which accounting groups are treated as income statement accounts during the closure process; an empty value blocks closure in accountancy/closure/index.php:166.', 'Comma-separated string of accounting group prefixes (e.g. ''6,7'' for expense and revenue accounts).', 0, 0, 'accountancy/admin/closure.php|accountancy/admin/closure.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/closure.php:85|write|if (!dolibarr_set_const($db, ''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_INCOME_STATEMENT'', $accountinggroupsusedforincomestatement, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/closure/index.php:126|read|$accounting_groups_used_for_income_statement = array_filter(array_map(''trim'', explode('','', getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_INCOME_STATEMENT''))), ''...", "accountancy/closure/index.php:166|read|} elseif (!getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_INCOME_STATEMENT'')) {", "accountancy/class/bookkeeping.class.php:2928|read|$accounting_groups_used_for_income_statement = array_filter(array_map(''trim'', explode('','', getDolGlobalString(''ACCOUNTING_CLOSURE_ACCOUNTING_GROUPS_USED_FOR_INCOME_STATEMENT''))), ''..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_CLOSURE_DEFAULT_JOURNAL', 'string', NULL, 'accountancy', 'Stores the default journal identifier used during accounting closure operations.', 'Written via accountancy/admin/closure.php:67 and read at accountancy/admin/closure.php:159 and accountancy/class/bookkeeping.class.php:3029 where it is passed to max(0, ...) to determine the journal ID.', 'Setting this constant pre-selects the journal for accounting closure entries; an invalid or missing value causes bookkeeping to use journal ID 0.', 'String (used as integer): journal ID; empty = 0 (no default journal)', 0, 0, 'accountancy/admin/closure.php|accountancy/admin/closure.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/closure.php:67|write|if (!dolibarr_set_const($db, ''ACCOUNTING_CLOSURE_DEFAULT_JOURNAL'', $defaultjournal, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/admin/closure.php:159|read|$defaultjournal = getDolGlobalString(''ACCOUNTING_CLOSURE_DEFAULT_JOURNAL'');", "accountancy/class/bookkeeping.class.php:3029|read|$journal_id = max(0, getDolGlobalString(''ACCOUNTING_CLOSURE_DEFAULT_JOURNAL''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_COUNTERPART_VAT_NPR', 'string', NULL, 'accountancy', 'Defines the accounting account code for the counterpart entry of non-recoverable VAT (VAT NPR) in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:269 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the VAT NPR counterpart entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:269|read|$compta_counterpart_tva_npr = getDolGlobalString(''ACCOUNTING_COUNTERPART_VAT_NPR'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DATE_START_BINDING', 'string', NULL, 'accountancy', 'When set, pre-fills the start date filter in accounting line-binding and list pages with a configured binding start date.', 'Checked in 47 locations including accountancy/expensereport/index.php:261, :388, :471, accountancy/customer/index.php:369, :508, :610, :707, and accountancy/customer/list.php:85 where an empty search start date is replaced by this value.', 'Setting this constant causes accounting ventilation and list pages to default their start date filter to this value instead of leaving it blank.', 'Date string or integer used as the default start date for accounting binding pages; unset = no default start date', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/customer/list.php:85|check|if (empty($search_date_start) && getDolGlobalInt(''ACCOUNTING_DATE_START_BINDING'')) {", "accountancy/expensereport/index.php:261|check|if (getDolGlobalInt(''ACCOUNTING_DATE_START_BINDING'')) {", "accountancy/customer/index.php:369|check|if (getDolGlobalInt(''ACCOUNTING_DATE_START_BINDING'')) {", "accountancy/customer/index.php:508|check|if (getDolGlobalInt(''ACCOUNTING_DATE_START_BINDING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DEFAULT_NOTIFIED_VALIDATION_DATE', 'string', NULL, 'accountancy', 'Controls whether the validation date notification checkbox is checked by default on the accounting bookkeeping export page.', 'Read at accountancy/bookkeeping/export.php:839 to set the default state of the validation-date notification checkbox. No admin UI write path is present in the payload.', 'When set to a truthy value, the validation date notification checkbox defaults to checked on the export page.', 'Empty/not set = checkbox unchecked by default; any truthy value = checkbox checked by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:839|read|$checked = getDolGlobalString(''ACCOUNTING_DEFAULT_NOTIFIED_VALIDATION_DATE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DEFAULT_NOT_EXPORT_LETTERING', 'string', NULL, 'accountancy', 'Controls whether lettering is excluded by default when exporting accounting bookkeeping entries.', 'When set, the export page at accountancy/bookkeeping/export.php:815 defaults the lettering exclusion checkbox to checked. Configured in the database (no admin UI write path detected).', 'When enabled, bookkeeping exports will omit lettering information by default unless the user manually overrides the checkbox.', 'Empty/not set = lettering included in export (checkbox unchecked); any truthy value = lettering excluded by default (checkbox checked).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:815|read|$checked = getDolGlobalString(''ACCOUNTING_DEFAULT_NOT_EXPORT_LETTERING'') ? ''true'' : ''false'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DEFAULT_NOT_NOTIFIED_EXPORT_DATE', 'string', NULL, 'accountancy', 'Controls whether the export date notification is disabled by default on the accounting bookkeeping export page.', 'Read at accountancy/bookkeeping/export.php:827 and :832 to set the default state of the export-date notification checkbox. When not set or truthy, the checkbox defaults to enabled; when set to a falsy value, the checkbox defaults to disabled.', 'Changing this value alters the default user experience on the export page regarding whether the export date is recorded/notified.', 'Not set or truthy value = notification enabled by default; falsy value = notification disabled by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:827|read|$checked = (!isset($conf->global->ACCOUNTING_DEFAULT_NOT_NOTIFIED_EXPORT_DATE) || getDolGlobalString(''ACCOUNTING_DEFAULT_NOT_NOTIFIED_EXPORT_DATE''));", "accountancy/bookkeeping/export.php:832|read|''value'' => (getDolGlobalString(''ACCOUNTING_DEFAULT_NOT_NOTIFIED_EXPORT_DATE'') ? ''false'' : ''true''),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DEFAULT_PERIOD_ON_TRANSFER', 'string', NULL, 'accountancy', 'Sets the default accounting period selection used when transferring entries to accounting.', 'Configured via accountancy/admin/index.php:555 using a selectarray. Read in core/lib/accounting.lib.php:384 as $periodbydefaultontransfer with default value 0. Only 2 occurrences found.', 'The selected integer value determines which period is pre-selected when a user initiates an accounting transfer; 0 is the default.', 'Integer: 0 = default period; other values correspond to period options in the admin selectarray', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:555|read|print $form->selectarray($key, $array, getDolGlobalInt(''ACCOUNTING_DEFAULT_PERIOD_ON_TRANSFER'', 0), 0, 0, 0, '''', 0, 0, 0, '''', ''onrightofpage width200'');", "core/lib/accounting.lib.php:384|read|$periodbydefaultontransfer = getDolGlobalInt(''ACCOUNTING_DEFAULT_PERIOD_ON_TRANSFER'', 0);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DISABLE_BINDING_ON_EXPENSEREPORTS', 'bool', NULL, 'accountancy', 'Disables the automatic accounting binding (account assignment) for expense reports.', 'Configured via accountancy/admin/index.php (3 UI references). Checked in 6 occurrences including accountancy/admin/index.php:599, :636, and menu files core/menus/standard/auguria.lib.php:448, core/menus/standard/eldy.lib.php:1796, :1841.', 'When enabled, automatic accounting account binding for expense reports is suppressed and related menu entries are hidden.', '0 or unset = binding on expense reports enabled; non-empty = binding on expense reports disabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:342|write|$res = dolibarr_set_const($db, \"ACCOUNTING_DISABLE_BINDING_ON_EXPENSEREPORTS\", $setdisablebindingonexpensereports, ''yesno'', 0, '''', $conf->entity);", "core/menus/standard/eldy.lib.php:1796|check|if (isModEnabled(''expensereport'') && !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_EXPENSEREPORTS'')) {", "core/menus/standard/auguria.lib.php:448|check|if ($objp->nature == 5 && isModEnabled(''expensereport'') && !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_EXPENSEREPORTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DISABLE_BINDING_ON_PURCHASES', 'bool', NULL, 'core', 'Disables the automatic accounting binding (account assignment) for purchase/supplier invoices.', 'Configured via accountancy/admin/index.php. Checked in 5 occurrences: admin page, and menu files core/menus/standard/eldy.lib.php:1789, :1835 and core/menus/standard/auguria.lib.php:442 where it gates accounting binding menu items for purchases.', 'When enabled, automatic accounting account binding for supplier invoices is suppressed and related menu entries are hidden.', '0 or unset = binding on purchases enabled; non-empty = binding on purchases disabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:328|write|$res = dolibarr_set_const($db, \"ACCOUNTING_DISABLE_BINDING_ON_PURCHASES\", $setdisablebindingonpurchases, ''yesno'', 0, '''', $conf->entity);", "core/menus/standard/eldy.lib.php:1789|check|if (isModEnabled(''supplier_invoice'') && !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_PURCHASES'')) {", "core/menus/standard/auguria.lib.php:442|read|&& !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_PURCHASES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DISABLE_BINDING_ON_SALES', 'bool', NULL, 'core', 'Disables the automatic accounting binding (account assignment) for sales invoices.', 'Configured via accountancy/admin/index.php. Checked in 5 occurrences: admin page, and menu files core/menus/standard/auguria.lib.php:437 and core/menus/standard/eldy.lib.php:1782, :1830 where it gates the display of accounting binding menu items for sales.', 'When enabled, automatic accounting account binding for sales invoices is suppressed and related menu entries are hidden.', '0 or unset = binding on sales enabled; non-empty = binding on sales disabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:314|write|$res = dolibarr_set_const($db, \"ACCOUNTING_DISABLE_BINDING_ON_SALES\", $setdisablebindingonsales, ''yesno'', 0, '''', $conf->entity);", "core/menus/standard/eldy.lib.php:1782|check|if (isModEnabled(''invoice'') && !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_SALES'')) {", "core/menus/standard/auguria.lib.php:437|check|if ($objp->nature == 2 && isModEnabled(''invoice'') && !getDolGlobalString(''ACCOUNTING_DISABLE_BINDING_ON_SALES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DISABLE_TRANSFER_ON_ASSETS', 'bool', NULL, 'accountancy', 'Disables accounting transfer for asset-related journal entries.', 'Configured via accountancy/admin/index.php. Checked in 3 occurrences: admin page display at :612, write at :356, and accountancy/class/accountingjournal.class.php:379 which skips asset transfer when this constant is set.', 'When enabled, asset entries are excluded from accounting journal transfer operations.', '0 or unset = asset transfer enabled; non-empty = asset transfer disabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:356|write|$res = dolibarr_set_const($db, \"ACCOUNTING_DISABLE_TRANSFER_ON_ASSETS\", $setdisabletransferonassets, ''yesno'', 0, '''', $conf->entity);", "accountancy/class/accountingjournal.class.php:379|check|if (isModEnabled(''asset'') && !getDolGlobalInt(''ACCOUNTING_DISABLE_TRANSFER_ON_ASSETS'')) {", "accountancy/admin/index.php:612|check|if (getDolGlobalString(''ACCOUNTING_DISABLE_TRANSFER_ON_ASSETS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_DISABLE_TRANSFER_ON_DISCOUNTS', 'bool', NULL, 'accountancy', 'Disables accounting transfer for discount-related journal entries (both sales and supplier invoices).', 'Configured via accountancy/admin/index.php. Checked in 4 occurrences: admin page display at :625 and write at :370, and accountancy/class/accountingjournal.class.php:385 (sales invoice discounts) and :391 (supplier invoice discounts).', 'When enabled, discount entries from both sales and supplier invoices are excluded from accounting journal transfer operations.', '0 or unset = discount transfer enabled; non-empty = discount transfer disabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:370|write|$res = dolibarr_set_const($db, \"ACCOUNTING_DISABLE_TRANSFER_ON_DISCOUNTS\", $setdisabletransferondiscounts, ''yesno'', 0, '''', $conf->entity);", "accountancy/class/accountingjournal.class.php:385|check|if (isModEnabled(''invoice'') && !getDolGlobalInt(''ACCOUNTING_DISABLE_TRANSFER_ON_DISCOUNTS'')) {", "accountancy/class/accountingjournal.class.php:391|check|if (isModEnabled(''supplier_invoice'') && !getDolGlobalInt(''ACCOUNTING_DISABLE_TRANSFER_ON_DISCOUNTS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ENABLE_AUTOLETTERING', 'bool', NULL, 'accountancy', 'Enables automatic lettering of accounting entries when journals are generated.', 'When set, the autolettering logic is triggered in bankjournal.php:985, purchasesjournal.php:549, and sellsjournal.php:654 — but only when ACCOUNTING_ENABLE_LETTERING is also active. Configured via accountancy/admin/index.php.', 'Disabling this constant stops automatic reconciliation of accounting entries across bank, purchases, and sales journals; entries must then be lettered manually.', 'yesno (1=enabled, 0=disabled)', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:985|check|if ($lettering && getDolGlobalInt(''ACCOUNTING_ENABLE_LETTERING'') && getDolGlobalInt(''ACCOUNTING_ENABLE_AUTOLETTERING'')) {", "accountancy/journal/purchasesjournal.php:549|check|if (getDolGlobalInt(''ACCOUNTING_ENABLE_LETTERING'') && getDolGlobalInt(''ACCOUNTING_ENABLE_AUTOLETTERING'')) {", "accountancy/journal/sellsjournal.php:654|check|if (getDolGlobalInt(''ACCOUNTING_ENABLE_LETTERING'') && getDolGlobalInt(''ACCOUNTING_ENABLE_AUTOLETTERING'')) {", "accountancy/admin/index.php:398|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ENABLE_AUTOLETTERING\", $setenableautolettering, ''yesno'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL', 'bool', NULL, 'accountancy', 'Enables the export of draft (not yet bookkeeping-transferred) journal entries.', 'Set via accountancy/admin/index.php:300 as a ''yesno'' constant. Checked in all major journal files (sellsjournal.php, purchasesjournal.php, bankjournal.php, expensereportsjournal.php, variousjournal.php, treasuryjournal.php) to show the export button for entries with $in_bookkeeping == ''notyet''. The comment at sellsjournal.php:933 states ''to have the button to get this feature enabled, you must enable ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL''.', 'When enabled, journals show an export button for draft entries not yet transferred to bookkeeping; when disabled, only already-transferred entries are exportable.', 'yesno: ''1'' or ''yes'' = enabled; empty or ''0'' = disabled', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:933  // Note that to have the button to get this feature enabled, you must enable ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL", "accountancy/admin/index.php:300|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL\", $setenabledraftexport, ''yesno'', 0, '''', $conf->entity);", "accountancy/journal/bankjournal.php:1306|check|if (getDolGlobalString(''ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL'') && $in_bookkeeping == ''notyet'') {", "accountancy/journal/variousjournal.php:297|check|if (getDolGlobalString(''ACCOUNTING_ENABLE_EXPORT_DRAFT_JOURNAL'') && $in_bookkeeping == ''notyet'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ENABLE_LETTERING', 'bool', NULL, 'accountancy', 'Enables the accounting lettering (account reconciliation/matching) feature.', 'Configured via accountancy/admin/index.php (multiple read/write). Checked in 19 occurrences across accountancy/admin/index.php, accountancy/admin/account.php:115, accountancy/bookkeeping/export.php:813, accountancy/bookkeeping/listbyaccount.php, and accountancy/bookkeeping/list.php among others. Gates lettering-related UI and actions.', 'When enabled, accounting lettering (matching of debit/credit entries for reconciliation) is available; when disabled, related UI elements and account management features are hidden.', '0 or unset = lettering disabled; non-zero = lettering enabled', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php|accountancy/admin/account.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:384|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ENABLE_LETTERING\", $setenablelettering, ''yesno'', 0, '''', $conf->entity);", "accountancy/bookkeeping/export.php:813|check|if (getDolGlobalInt(\"ACCOUNTING_ENABLE_LETTERING\")) {", "accountancy/bookkeeping/listbyaccount.php:848|check|if (getDolGlobalInt(''ACCOUNTING_ENABLE_LETTERING'') && $user->hasRight(''accounting'', ''mouvements'', ''creer'')) {", "accountancy/admin/account.php:115|check|if (!getDolGlobalInt(''ACCOUNTING_ENABLE_LETTERING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ENABLE_MULTI_REPORT', 'bool', NULL, 'accountancy', 'Enables the multi-report feature in the accounting module, allowing chart-of-accounts categories to be assigned to multiple reports.', 'Configured via accountancy/admin/categories_list.php and accountancy/admin/account.php (checked at lines 87, 170, 454, 771, 993). A comment in accountancy/class/accountancycategory.class.php:913 states ''Requires constant ACCOUNTING_ENABLE_MULTI_REPORT''.', 'When enabled, additional report-filtering UI and logic are activated in accounting category administration; when disabled, single-report mode is used.', 'Integer: 1 to enable multi-report mode; 0 or unset for single-report mode.', 0, 0, 'accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories.php|accountancy/admin/account.php|accountancy/admin/account.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Requires constant ACCOUNTING_ENABLE_MULTI_REPORT", "accountancy/admin/categories_list.php:87|check|if (getDolGlobalInt(''ACCOUNTING_ENABLE_MULTI_REPORT'')) {", "accountancy/admin/account.php:771|check|if (getDolGlobalInt(''ACCOUNTING_ENABLE_MULTI_REPORT'')) {", "accountancy/admin/categories.php:98|read|$useNewSystem = (getDolGlobalInt(''ACCOUNTING_ENABLE_MULTI_REPORT''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_ENABLE_TABONTHIRDPARTY', 'bool', NULL, 'accountancy', 'Adds an accounting movements tab on third-party (company) record pages for users with the appropriate rights.', 'When enabled and the accounting module is active, core/lib/company.lib.php:144 injects an extra tab on third-party pages, provided the user holds the ''accounting > mouvements > lire'' right. Configured via accountancy/admin/index.php.', 'Enabling this constant exposes accounting ledger movements directly on the third-party card; disabling it hides that tab.', 'yesno (truthy=tab shown, empty/0=tab hidden)', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/company.lib.php:144|check|if (isModEnabled(''accounting'') && getDolGlobalString(''ACCOUNTING_ENABLE_TABONTHIRDPARTY'') && ($user->hasRight(''accounting'', ''mouvements'', ''lire''))) {", "accountancy/admin/index.php:426|write|$res = dolibarr_set_const($db, \"ACCOUNTING_ENABLE_TABONTHIRDPARTY\", $setenabletabonthirdparty, ''yesno'', 0, '''', $conf->entity);", "accountancy/admin/index.php:865|check|if (getDolGlobalString(''ACCOUNTING_ENABLE_TABONTHIRDPARTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPENSEREPORT_DO_NOT_DISPATCH_TAXES', 'string', NULL, 'accountancy', 'When enabled, prevents tax amounts from being split off expense report lines into a separate accounting entry, keeping tax with the base line.', 'Read in accountancy/journal/expensereportsjournal.php:187 as an integer flag. The inline comment explains: if enabled, tax will NOT get split off from the base entry and credited to a separate tax account.', 'Enabling this constant changes expense report journal generation so that tax amounts remain on the base expense line rather than being dispatched to a dedicated tax account.', '0 or unset = taxes are dispatched to a separate account; 1 = taxes are kept with the base expense line.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/expensereportsjournal.php:187|read|$noTaxDispatchingKeepWithLines = getDolGlobalInt(''ACCOUNTING_EXPENSEREPORT_DO_NOT_DISPATCH_TAXES''); //If enabled, Tax will NOT get split off from the base entry and credited to a s"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_DATE', 'string', NULL, 'accountancy', 'Specifies the date format string used for date fields in accounting exports.', 'Used in accountancy/class/accountancyexport.class.php:1361 via dol_print_date and registered as an export parameter in accountancyexport.class.php:256. The default fallback is ''%Y-%m-%d''. Configured via accountancy/admin/index.php.', 'Changing the date format alters how document dates appear in exported accounting files; an incorrect format string produces malformed dates.', 'strftime-compatible format string; default fallback is ''%Y-%m-%d''', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountancyexport.class.php:256|read|''ACCOUNTING_EXPORT_DATE'' => getDolGlobalString(''ACCOUNTING_EXPORT_DATE'', ''%Y-%m-%d''),", "accountancy/class/accountancyexport.class.php:1361|read|$date_document = dol_print_date($line->doc_date, getDolGlobalString(''ACCOUNTING_EXPORT_DATE''));", "accountancy/admin/index.php:924|read|print ''            jQuery(\"#ACCOUNTING_EXPORT_DATE\").val(\"''.getDolGlobalString(''ACCOUNTING_EXPORT_DATE'').''\");''.\"\\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_ENDLINE', 'string', NULL, 'accountancy', 'Controls the line ending character used when exporting accounting data: 1 produces LF (Unix), any other truthy value produces CRLF (Windows).', 'Read in accountancy/class/accountancyexport.class.php:133 to set the end-of-line sequence for export files. If not set, defaults to LF (\n). Also stored with a default of 1 per accountancyexport.class.php:255.', 'Setting this to 1 produces Unix line endings (\n); setting to any other truthy value produces Windows line endings (\r\n); leaving unset defaults to LF.', '1 = LF (\n); other truthy value = CRLF (\r\n); empty/unset = LF (\n) by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountancyexport.class.php:133|read|$this->end_line = getDolGlobalString(''ACCOUNTING_EXPORT_ENDLINE'') ? (getDolGlobalInt(''ACCOUNTING_EXPORT_ENDLINE'') == 1 ? \"\\n\" : \"\\r\\n\") : \"\\n\";", "accountancy/class/accountancyexport.class.php:255|read|''ACCOUNTING_EXPORT_ENDLINE'' => getDolGlobalString(''ACCOUNTING_EXPORT_ENDLINE'', 1),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_FORMAT', 'string', NULL, 'accountancy', 'Specifies the file format used for accounting journal exports (e.g. ''txt'').', 'Configured via accountancy/admin/index.php:902 (JavaScript sets a select element) with a commented example at line 266 showing ''txt''. Read in accountancy/tpl/export_journal.tpl.php:51 and accountancy/class/accountancyexport.class.php:253 with default ''txt'', and displayed on the export button in accountancy/bookkeeping/balance.php:359.', 'Changing this value switches the output format of all accounting journal export files.', 'String format code (e.g. ''txt''); default ''txt'' per accountancy/class/accountancyexport.class.php:253', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/tpl/export_journal.tpl.php:51|read|$format = getDolGlobalString(''ACCOUNTING_EXPORT_FORMAT'');", "accountancy/class/accountancyexport.class.php:253|read|''ACCOUNTING_EXPORT_FORMAT'' => getDolGlobalString(''ACCOUNTING_EXPORT_FORMAT'', ''txt''),", "accountancy/admin/index.php:266  //\tdolibarr_set_const($db, ''ACCOUNTING_EXPORT_FORMAT'', ''txt'', ''chaine'', 0, '''', $conf->entity);", "accountancy/bookkeeping/balance.php:359|read|$newcardbutton .= dolGetButtonTitle($langs->trans(\"Export\").'' ('' . getDolGlobalString(''ACCOUNTING_EXPORT_FORMAT'').'')'', '''', ''fa fa-file-csv paddingleft'', $_SERVER[''PHP_SELF''], ''expo"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_MODELCSV', 'string', NULL, 'accountancy', 'Selects the export template (model) used when exporting accounting bookkeeping entries.', 'Written in accountancy/admin/index.php:262 and read in accountancy/bookkeeping/export.php:229 to determine which export format is applied. Displayed as a select list in accountancy/admin/index.php:967.', 'Changing this value switches the accounting export format; an invalid or missing model identifier causes the export to fall back to undefined behaviour.', 'String identifier of an available export template as listed in the admin UI select list', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:262|write|if (!dolibarr_set_const($db, ''ACCOUNTING_EXPORT_MODELCSV'', $modelcsv, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/bookkeeping/export.php:229|read|$formatexportset = getDolGlobalString(''ACCOUNTING_EXPORT_MODELCSV'');  // TODO: Verify if this should be int!", "accountancy/admin/index.php:967|read|print $form->selectarray(\"ACCOUNTING_EXPORT_MODELCSV\", $listofexporttemplates, getDolGlobalString(''ACCOUNTING_EXPORT_MODELCSV''), 0, 0, 0, '''', 0, 0, 0, '''', '''', 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_NO_DATE_IN_FILENAME', 'string', NULL, 'accountancy', 'When set to a non-zero integer, omits the date segment from generated accounting export filenames.', 'Read only in accountancy/tpl/export_journal.tpl.php:52, assigned to $nodateexport. No admin UI write path exists in the payload.', 'Setting this to a non-zero value removes the date from export filenames; leaving it unset includes the date.', '0 or unset = include date in filename (default); non-zero integer = omit date', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/tpl/export_journal.tpl.php:52|read|$nodateexport = getDolGlobalInt(''ACCOUNTING_EXPORT_NO_DATE_IN_FILENAME'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_PREFIX_SPEC', 'string', NULL, 'accountancy', 'Specifies a custom prefix string used when building accounting export journal filenames.', 'Read only in accountancy/tpl/export_journal.tpl.php:50 where it is assigned to $prefix for use in export filename construction. No admin UI write path exists in the payload.', 'Changing this value alters the prefix segment of generated accounting export filenames.', 'Free string; used as filename prefix in journal exports', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/tpl/export_journal.tpl.php:50|read|$prefix = getDolGlobalString(''ACCOUNTING_EXPORT_PREFIX_SPEC'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_REMOVE_EXPENSEREPORT_SOURCE_FILE', 'string', NULL, 'accountancy', 'Determines whether the source expense report file is removed after an accounting export.', 'Checked at accountancy/bookkeeping/export.php:861 and in accountancy/class/accountancyexport.class.php:1611 and :1851. When non-zero, the expense report source file is removed; when zero, it is kept.', 'Enabling this constant causes the source expense report file to be deleted after export; disabling it preserves the file.', '0 or not set = source file kept; non-zero = source file removed after export.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:861|check|if (getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_EXPENSEREPORT_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1611|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_EXPENSEREPORT_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1851|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_EXPENSEREPORT_SOURCE_FILE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_REMOVE_INVOICE_SOURCE_FILE', 'string', NULL, 'accountancy', 'Determines whether the source invoice file is removed after an accounting export.', 'Checked at accountancy/bookkeeping/export.php:858 and in accountancy/class/accountancyexport.class.php:1607 and :1847. When the integer value is non-zero, the invoice source file is removed; when zero, it is kept.', 'Enabling this constant causes the source invoice file to be deleted after export; disabling it preserves the file.', '0 or not set = source file kept; non-zero = source file removed after export.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:858|check|if (getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_INVOICE_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1607|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_INVOICE_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1847|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_INVOICE_SOURCE_FILE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_REMOVE_SUPPLIERINVOICE_SOURCE_FILE', 'string', NULL, 'accountancy', 'Determines whether the source supplier invoice file is removed after an accounting export.', 'Checked at accountancy/bookkeeping/export.php:864 and in accountancy/class/accountancyexport.class.php:1615 and :1855. When non-zero, the supplier invoice source file is removed; when zero, it is kept.', 'Enabling this constant causes the source supplier invoice file to be deleted after export; disabling it preserves the file.', '0 or not set = source file kept; non-zero = source file removed after export.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:864|check|if (getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_SUPPLIERINVOICE_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1615|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_SUPPLIERINVOICE_SOURCE_FILE'')) {", "accountancy/class/accountancyexport.class.php:1855|check|if (!getDolGlobalInt(''ACCOUNTING_EXPORT_REMOVE_SUPPLIERINVOICE_SOURCE_FILE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_SEPARATORCSV', 'string', NULL, 'accountancy', 'Defines the field separator character used when exporting accounting journals to CSV.', 'Read in accountancy/class/accountancyexport.class.php:132 as the separator, and in bankjournal.php, purchasesjournal.php, sellsjournal.php, expensereportsjournal.php, and balance.php. The default fallback is a comma ('','') as seen in accountancyexport.class.php:254. Configured via accountancy/admin/index.php.', 'Changing the separator affects all accounting CSV exports; choosing a character that appears in data values will corrupt the CSV structure.', 'Any single character string; default fallback is '','' (comma)', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountancyexport.class.php:132|read|$this->separator = getDolGlobalString(''ACCOUNTING_EXPORT_SEPARATORCSV'');", "accountancy/class/accountancyexport.class.php:254|read|''ACCOUNTING_EXPORT_SEPARATORCSV'' => getDolGlobalString(''ACCOUNTING_EXPORT_SEPARATORCSV'', '',''),", "accountancy/journal/bankjournal.php:1090|read|$sep = getDolGlobalString(''ACCOUNTING_EXPORT_SEPARATORCSV'');", "accountancy/journal/purchasesjournal.php:837|read|$sep = getDolGlobalString(''ACCOUNTING_EXPORT_SEPARATORCSV'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_EXPORT_XIMPORT_FORCE_FILENAME', 'string', NULL, 'accountancy', 'Forces a specific filename for Ciel XIMPORT general-ledger export files instead of the auto-generated name.', 'Read in accountancy/tpl/export_journal.tpl.php:84, conditioned on the format code being ''ciel'' and the export type being ''general_ledger''. A docblock comment in accountancy/class/accountancyexport.class.php:839 references this constant by name.', 'When set, the Ciel general-ledger export uses the forced filename; when unset the default generated filename is used.', 'String filename to force; empty/unset = use auto-generated filename', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/tpl/export_journal.tpl.php:84|read|} elseif ($accountancyexport->getFormatCode($formatexportset) == ''ciel'' && $type_export == \"general_ledger\" && getDolGlobalString(''ACCOUNTING_EXPORT_XIMPORT_FORCE_FILENAME'')) {", "accountancy/class/accountancyexport.class.php:839  * use constant ACCOUNTING_EXPORT_XIMPORT_FORCE_FILENAME"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_FEC_DECIMAL_LENGTH', 'string', NULL, 'core', 'Sets the number of decimal digits used when formatting amounts in FEC accounting exports.', 'Read in core/lib/functions2.lib.php:2793 where it overrides the default of 2 decimal places for FEC output.', 'Changing this alters the precision of all monetary amounts written to FEC export files.', 'Integer number of decimal digits; default 2.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2793|read|$nbdecimal = (!getDolGlobalString(''ACCOUNTING_FEC_DECIMAL_LENGTH'') ? 2 : $conf->global->ACCOUNTING_FEC_DECIMAL_LENGTH);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_FEC_DECIMAL_SEPARATOR', 'string', NULL, 'core', 'Sets the decimal separator character used when formatting amounts in FEC accounting exports.', 'Read in core/lib/functions2.lib.php:2796 where it overrides the default comma '','' separator for FEC output.', 'Changing this alters the decimal separator in all monetary amounts written to FEC export files, which must match the expected format of receiving software.', 'Any character string; default '',''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2796|read|$dec = (!getDolGlobalString(''ACCOUNTING_FEC_DECIMAL_SEPARATOR'') ? '','' : $conf->global->ACCOUNTING_FEC_DECIMAL_SEPARATOR);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_FEC_THOUSAND_SEPARATOR', 'string', NULL, 'core', 'Sets the thousands separator character used when formatting amounts in FEC accounting exports.', 'Read in core/lib/functions2.lib.php:2797 where it overrides the default empty string (no thousands separator) for FEC output.', 'Setting this adds a thousands separator to all monetary amounts in FEC export files.', 'Any character string; default '''' (no separator).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2797|read|$thousand = (!getDolGlobalString(''ACCOUNTING_FEC_THOUSAND_SEPARATOR'') ? '''' : $conf->global->ACCOUNTING_FEC_THOUSAND_SEPARATOR);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE', 'bool', NULL, 'accountancy', 'Forces VAT reverse-charge accounting treatment regardless of the company''s country code.', 'Normally reverse-charge processing in the purchases journal is restricted to French companies (country_code == ''FR''); setting this constant extends that behaviour to all entities. It is also checked in fourn/card.php:326 and elsewhere. Configured via accountancy/admin/index.php.', 'Enabling this constant activates VAT reverse-charge journal entries and related UI for companies outside France; disabling it restricts that treatment to FR-coded companies only.', 'yesno (truthy=forced, empty/0=country-code-dependent)', 0, 0, 'accountancy/admin/index.php|accountancy/admin/defaultaccounts.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:313|check|if (($mysoc->country_code == ''FR'' || getDolGlobalString(''ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE'')) && $obj->vat_reverse_charge == 1 ...", "accountancy/journal/purchasesjournal.php:645|check|if ($mysoc->country_code == ''FR'' || getDolGlobalString(''ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE'')) {", "accountancy/admin/index.php:412|write|$res = dolibarr_set_const($db, \"ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE\", $setenablevatreversecharge, ''yesno'', 0, '''', $conf->entity);", "fourn/card.php:326|check|if (getDolGlobalString(''ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LABEL_OPERATION_ON_TRANSFER', 'string', NULL, 'accountancy', 'Controls how the operation label is generated when accounting entries are transferred to the general ledger.', 'Documented in accountancy/class/bookkeeping.class.php:2615-2618: ''If ACCOUNTING_LABEL_OPERATION_ON_TRANSFER is 0, we concat thirdparty name, ref and label. If ... is 1, we concat thirdparty name, ref. If ... is 2, we return just thirdparty name.'' Configured via accountancy/admin/index.php. 4 occurrences.', 'Setting different integer values changes what information is included in the accounting entry label: 0 gives full detail, 1 omits the label, 2 gives only the third-party name.', '0 = thirdparty name + ref + label; 1 = thirdparty name + ref; 2 = thirdparty name only', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/bookkeeping.class.php:2616  * If ACCOUNTING_LABEL_OPERATION_ON_TRANSFER is 0, we concat thirdparty name, ref and label.", "accountancy/class/bookkeeping.class.php:2617  * If ACCOUNTING_LABEL_OPERATION_ON_TRANSFER is 1, we concat thirdparty name, ref.", "accountancy/class/bookkeeping.class.php:2618  * If ACCOUNTING_LABEL_OPERATION_ON_TRANSFER is 2, we return just thirdparty name", "accountancy/class/bookkeeping.class.php:2615  * Generate label operation when operation is transferred into accounting according to ACCOUNTING_LABEL_OPERATION_ON_TRANSFER"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LENGTH_AACCOUNT', 'string', NULL, 'accountancy', 'Sets the fixed padding length for auxiliary (sub-account) account numbers in the accounting module.', 'Checked and read across 9 occurrences in accountancy/admin/subaccount.php (lines 159-160, 206-207, 254-255) and accountancy/admin/account.php (lines 287-288), where it is used as `$lengthpaddingaccount`.', 'Setting this value enforces zero-padding of auxiliary account codes to the specified length, ensuring uniform account number formatting.', 'Integer (number of digits for padding); 0 or empty means no padding is applied.', 0, 0, 'accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/account.php|accountancy/admin/account.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/subaccount.php:159|check|if (getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT'')) {", "accountancy/admin/subaccount.php:160|read|$lengthpaddingaccount = getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT'');", "accountancy/admin/account.php:288|read|$lengthpaddingaccount = max(getDolGlobalInt(''ACCOUNTING_LENGTH_GACCOUNT''), getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT''));", "accountancy/admin/account.php:287|check|if (getDolGlobalInt(''ACCOUNTING_LENGTH_GACCOUNT'') || getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LENGTH_DESCRIPTION', 'string', NULL, 'accountancy', 'Sets the maximum character length for truncating description text in accounting line-binding and list pages.', 'Configured via accountancy/admin/productaccount.php:763. Read in 7 locations: customer/lines.php:724, expensereport/lines.php:619, customer/list.php:855, expensereport/list.php:663, supplier/lines.php:753, and supplier/list.php:893, all with a default of 32.', 'Increasing this value allows longer description strings to be displayed in accounting tables; decreasing it truncates descriptions more aggressively.', 'Integer character count (default 32); controls truncation of description text in accounting views', 0, 0, 'accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:763|read|$trunclength = getDolGlobalInt(''ACCOUNTING_LENGTH_DESCRIPTION'', 32);", "accountancy/customer/lines.php:724|read|$trunclength = getDolGlobalInt(''ACCOUNTING_LENGTH_DESCRIPTION'', 32);", "accountancy/expensereport/lines.php:619|read|$trunclength = getDolGlobalInt(''ACCOUNTING_LENGTH_DESCRIPTION'', 32);", "accountancy/supplier/lines.php:753|read|$trunclength = getDolGlobalInt(''ACCOUNTING_LENGTH_DESCRIPTION'', 32);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LENGTH_DESCRIPTION_ACCOUNT', 'string', NULL, 'core', 'Sets the maximum character length for account description strings in accounting selectors.', 'Read as integer at core/class/html.formaccounting.class.php:391 via getDolGlobalInt with a default of 50. Controls the $trunclength variable used to truncate account description text in drop-downs.', 'Increasing the value shows longer descriptions in accounting selectors. Decreasing it truncates descriptions more aggressively. Leaving unset defaults to 50 characters.', 'Integer character count (e.g. 50, 100); unset = 50.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formaccounting.class.php:391|read|$trunclength = getDolGlobalInt(''ACCOUNTING_LENGTH_DESCRIPTION_ACCOUNT'', 50);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LENGTH_GACCOUNT', 'string', NULL, 'accountancy', 'Sets the minimum length (padding) applied to general accounting account numbers.', 'Used in accountancy/admin/account.php:288 as one of the two values compared with max() to determine the padding length for account numbers, alongside ACCOUNTING_LENGTH_AACCOUNT. Also read in core/lib/accounting.lib.php:162.', 'Changing this value alters how general account numbers are padded or validated; an inconsistency with ACCOUNTING_LENGTH_AACCOUNT may affect account display and journal entries.', 'Integer representing the desired account number length; 0 or not set = no enforced length', 0, 0, 'accountancy/admin/account.php|accountancy/admin/account.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/account.php:287|check|if (getDolGlobalInt(''ACCOUNTING_LENGTH_GACCOUNT'') || getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT'')) {", "accountancy/admin/account.php:288|read|$lengthpaddingaccount = max(getDolGlobalInt(''ACCOUNTING_LENGTH_GACCOUNT''), getDolGlobalInt(''ACCOUNTING_LENGTH_AACCOUNT''));", "core/lib/accounting.lib.php:162|read|$g = getDolGlobalInt(''ACCOUNTING_LENGTH_GACCOUNT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LETTERING_NBLETTERS', 'string', NULL, 'accountancy', 'Sets the number of characters used to generate lettering codes for accounting reconciliation.', 'Controls the length n of the letter string (''AA''/''aa'', ''AAA''/''aaa'', etc.) generated during manual, auto, or partial reconciliation. Configured via accountancy/admin/index.php and applied in accountancy/class/lettering.class.php:307 with a default fallback of 3.', 'Changing the value alters the length of lettering codes assigned to reconciled entries; shorter codes exhaust the namespace sooner, longer codes provide more capacity.', 'Integer ≥ 1 (number of characters); default fallback is 3', 0, 0, 'accountancy/admin/index.php|accountancy/admin/index.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Generate a string with n char ''A'' (for manual/auto reconcile) or ''a'' (for partial reconcile) where n is ACCOUNTING_LETTERING_NBLETTERS (So ''AA''/''aa'', ''AAA''/''aaa'', ...) @phan-suppress-next-line PhanParamSuspiciousOrder", "accountancy/class/lettering.class.php:307|read|$letter = str_pad(\"\", getDolGlobalInt(''ACCOUNTING_LETTERING_NBLETTERS'', 3), $partial ? ''a'' : ''A'');", "accountancy/admin/index.php:239|write|if (!dolibarr_set_const($db, ''ACCOUNTING_LETTERING_NBLETTERS'', GETPOST(''ACCOUNTING_LETTERING_NBLETTERS''), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LIMIT_LIST_VENTILATION', 'string', NULL, 'accountancy', 'Overrides the default page-size limit for accounting ventilation and bookkeeping list pages.', 'Configured via accountancy/admin/productaccount.php:95 (read into $limit). Read in 10 locations including accountancy/customer/lines.php:78, expensereport/lines.php:71, customer/list.php:90, expensereport/list.php:82, bookkeeping/export.php:145, bookkeeping/listbyaccount.php:143, and bookkeeping/list.php:134, all falling back to $conf->liste_limit.', 'Setting this constant changes the number of rows displayed per page on accounting ventilation and bookkeeping list screens.', 'Integer page-size limit; unset = use the global $conf->liste_limit default', 0, 0, 'accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:95|read|$limit = GETPOSTINT(''limit'') ? GETPOSTINT(''limit'') : getDolGlobalInt(''ACCOUNTING_LIMIT_LIST_VENTILATION'', $conf->liste_limit);", "accountancy/customer/lines.php:78|read|$limit = GETPOSTINT(''limit'') ? GETPOSTINT(''limit'') : getDolGlobalString(''ACCOUNTING_LIMIT_LIST_VENTILATION'', $conf->liste_limit);", "accountancy/bookkeeping/list.php:134|read|$limit = GETPOSTINT(''limit'') ? GETPOSTINT(''limit'') : getDolGlobalString(''ACCOUNTING_LIMIT_LIST_VENTILATION'', $conf->liste_limit);", "accountancy/bookkeeping/export.php:145|read|$limit = GETPOSTINT(''limit'') ? GETPOSTINT(''limit'') : getDolGlobalString(''ACCOUNTING_LIMIT_LIST_VENTILATION'', $conf->liste_limit);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LIST_SORT_VENTILATION_DONE', 'string', NULL, 'accountancy', 'When set to a positive integer, sorts already-ventilated lines to the bottom on accounting line-binding pages.', 'Checked in accountancy/customer/lines.php:92, expensereport/lines.php:85, and supplier/lines.php:93. Written via dolibarr_set_const at customer/lines.php:208, supplier/lines.php:212, and expensereport/lines.php:201 with type ''yesno''.', 'Setting this to a positive integer causes ventilated (already-assigned) accounting lines to be sorted after unventilated lines on binding pages.', 'Positive integer = sort ventilated lines to bottom; 0 or unset = default sort order', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/customer/lines.php:92|check|if (getDolGlobalInt(''ACCOUNTING_LIST_SORT_VENTILATION_DONE'') > 0) {", "accountancy/customer/lines.php:208|write|$res = dolibarr_set_const($db, \"ACCOUNTING_LIST_SORT_VENTILATION_DONE\", $value, ''yesno'', 0, '''', $conf->entity);", "accountancy/expensereport/lines.php:85|check|if (getDolGlobalInt(''ACCOUNTING_LIST_SORT_VENTILATION_DONE'') > 0) {", "accountancy/supplier/lines.php:93|check|if (getDolGlobalInt(''ACCOUNTING_LIST_SORT_VENTILATION_DONE'') > 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LIST_SORT_VENTILATION_TODO', 'string', NULL, 'accountancy', 'Controls whether accounting allocation lists are sorted to show unallocated (todo) items first.', 'Written and read in accountancy/customer/list.php, accountancy/supplier/list.php, and accountancy/expensereport/list.php. When value > 0 (checked at lines :104, :96, :100 respectively), sorting is applied to prioritize pending ventilation items. Stored as ''yesno'' type.', 'Enabling this constant changes the default sort order in accounting allocation lists to surface unallocated entries at the top.', '0 or unset = normal sort order; >0 = sort to show unallocated items first', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/customer/list.php:104|check|if (getDolGlobalInt(''ACCOUNTING_LIST_SORT_VENTILATION_TODO'') > 0) {", "accountancy/supplier/list.php:253|write|$res = dolibarr_set_const($db, \"ACCOUNTING_LIST_SORT_VENTILATION_TODO\", $value, ''yesno'', 0, '''', $conf->entity);", "accountancy/expensereport/list.php:96|check|if (getDolGlobalInt(''ACCOUNTING_LIST_SORT_VENTILATION_TODO'') > 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT1_BUY_ACCOUNT', 'string', NULL, 'accountancy', 'Defines the default accounting account code for local tax 1 on purchases in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:229 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, local tax 1 purchase entries use the reserved string ''NotDefined'', producing unresolved accounting entries.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:229|read|$cptlocaltax1 = getDolGlobalString(''ACCOUNTING_LT1_BUY_ACCOUNT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT1_BUY_REVERSE_CHARGES_CREDIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the credit side of local tax 1 reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:230 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the local tax 1 reverse-charge credit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:230|read|$rcclocaltax1 = getDolGlobalString(''ACCOUNTING_LT1_BUY_REVERSE_CHARGES_CREDIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT1_BUY_REVERSE_CHARGES_DEBIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the debit side of local tax 1 reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:231 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the local tax 1 reverse-charge debit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:231|read|$rcdlocaltax1 = getDolGlobalString(''ACCOUNTING_LT1_BUY_REVERSE_CHARGES_DEBIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT1_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Specifies the accounting account code used for local tax 1 (LT1) on sales in the accounting journal.', 'Read in accountancy/journal/sellsjournal.php:227 to assign the account code for local tax 1 entries in the sales journal. No admin UI writes are present in the payload; configured directly in the database.', 'If not set, the fallback value ''NotDefined'' is used, which will cause LT1 sales journal entries to reference an invalid account code.', 'String representing an accounting account code; defaults to ''NotDefined'' if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:227|read|$cptlocaltax1 = getDolGlobalString(''ACCOUNTING_LT1_SOLD_ACCOUNT'', ''NotDefined'');"]', 'low', NULL);
