INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT2_BUY_REVERSE_CHARGES_CREDIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the credit side of local tax 2 reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:233 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the local tax 2 reverse-charge credit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:233|read|$rcclocaltax2 = getDolGlobalString(''ACCOUNTING_LT2_BUY_REVERSE_CHARGES_CREDIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT2_BUY_REVERSE_CHARGES_DEBIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the debit side of local tax 2 reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:234 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the local tax 2 reverse-charge debit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:234|read|$rcdlocaltax2 = getDolGlobalString(''ACCOUNTING_LT2_BUY_REVERSE_CHARGES_DEBIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_LT2_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Specifies the accounting account code used for local tax 2 (LT2) on sales in the accounting journal.', 'Read in accountancy/journal/sellsjournal.php:228 to assign the account code for local tax 2 entries in the sales journal. No admin UI writes are present in the payload; configured directly in the database.', 'If not set, the fallback value ''NotDefined'' is used, which will cause LT2 sales journal entries to reference an invalid account code.', 'String representing an accounting account code; defaults to ''NotDefined'' if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:228|read|$cptlocaltax2 = getDolGlobalString(''ACCOUNTING_LT2_SOLD_ACCOUNT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_MANAGE_ZERO', 'string', NULL, 'accountancy', 'Controls whether zero-value accounting entries are created or managed differently in the accounting journal.', 'Configured via accountancy/admin/index.php and accountancy/admin/card.php. Checked in 6 occurrences: accountancy/admin/card.php:98, :155, accountancy/admin/index.php:93, core/lib/accounting.lib.php:158, :196, and core/modules/import/modules_import.class.php:1370. Gates zero-value entry handling logic.', 'When enabled, zero-value accounting entries are processed or displayed differently; when disabled, certain zero-value entry operations are skipped.', '0 or unset = zero entries not managed specially; non-empty = zero entries managed', 0, 0, 'accountancy/admin/index.php|accountancy/admin/card.php|accountancy/admin/card.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/card.php:98|check|if (!getDolGlobalString(''ACCOUNTING_MANAGE_ZERO'')) {", "core/lib/accounting.lib.php:158|check|if (getDolGlobalString(''ACCOUNTING_MANAGE_ZERO'')) {", "core/modules/import/modules_import.class.php:1370|check|if (!getDolGlobalString(''ACCOUNTING_MANAGE_ZERO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_MODE', 'string', NULL, 'compta', 'Selects the accounting mode used for financial result calculations (''CREANCES-DETTES'' for accrual or ''RECETTES-DEPENSES'' for cash basis).', 'Configured in admin/compta.php:86 and accountancy/admin/index.php:185. Read by all financial result pages including compta/resultat/projects.php:147, result.php:162, index.php:124, and clientfourn.php:149 with default ''CREANCES-DETTES''. Comments at admin/compta.php:157 and accountancy/admin/index.php:500 describe handling of this parameter.', 'Switching from ''CREANCES-DETTES'' (accrual) to ''RECETTES-DEPENSES'' (cash) changes how all income/expense result reports are computed.', '''CREANCES-DETTES'' = accrual accounting (default); ''RECETTES-DEPENSES'' = cash-basis accounting', 0, 0, 'accountancy/admin/index.php|admin/compta.php|admin/compta.php|accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/compta.php:72|read|$accounting_mode = getDolGlobalString(''ACCOUNTING_MODE'', ''CREANCES-DETTES'');", "admin/compta.php:157  // case of the parameter ACCOUNTING_MODE", "accountancy/admin/index.php:500  // Case of the parameter ACCOUNTING_MODE", "compta/resultat/projects.php:147|read|$modecompta = getDolGlobalString(''ACCOUNTING_MODE'', ''CREANCES-DETTES'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_', 'string', NULL, 'accountancy', 'Family of dynamic constants (ACCOUNTING_PRODUCT_{TYPE}_ACCOUNT, _INTRA_ACCOUNT, _EXPORT_ACCOUNT) that provide accounting account codes for physical product types.', 'Accessed dynamically in accountancy/class/accountingaccount.class.php:796, :800, :803, :806, and :809 by appending a computed suffix (_ACCOUNT, _INTRA_ACCOUNT, _EXPORT_ACCOUNT) to the base prefix ''ACCOUNTING_PRODUCT_''. No admin UI is configured.', 'Setting these constants assigns specific accounting accounts for physical product lines in standard, intra-community, and export sale contexts.', 'Chart-of-accounts code string for each variant; variants are ACCOUNTING_PRODUCT_{TYPE}_ACCOUNT, ACCOUNTING_PRODUCT_{TYPE}_INTRA_ACCOUNT, ACCOUNTING_PRODUCT_{TYPE}_EXPORT_ACCOUNT.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountingaccount.class.php:796|read|$code_l = getDolGlobalString(''ACCOUNTING_PRODUCT_'' . $const_name . ''_ACCOUNT'');", "accountancy/class/accountingaccount.class.php:806|read|$code_l = getDolGlobalString(''ACCOUNTING_PRODUCT_'' . $const_name . ''_INTRA_ACCOUNT'');", "accountancy/class/accountingaccount.class.php:809|read|$code_l = getDolGlobalString(''ACCOUNTING_PRODUCT_'' . $const_name . ''_EXPORT_ACCOUNT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_BUY_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for product (goods) purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:307 and accountancy/journal/purchasesjournal.php:253 as the fallback purchase account for goods. Also used in product/card.php:1931 as the default. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the default ledger account assigned to goods purchase lines in the purchases journal when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:253|read|$compta_prod = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_ACCOUNT'', ''NotDefined'');", "accountancy/admin/productaccount.php:307|read|$aacompta_prodbuy           = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1931|read|$accountancy_code_buy = (GETPOST(''accountancy_code_buy'', ''alpha'') ? (GETPOST(''accountancy_code_buy'', ''alpha'')) : getDolGlobalString(\"ACCOUNTING_PRODUCT_BUY_ACCOUNT\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_BUY_EXPORT_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for export product (goods) purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:309 and productaccount.php:717 as the fallback export purchase account for goods. Also used in product/card.php:1955. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the ledger account used for export goods purchase lines when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:309|read|$aacompta_prodbuy_export    = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "accountancy/admin/productaccount.php:717|read|$compta_prodbuy = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1955|read|$accountancy_code_buy_export = (GETPOST(''accountancy_code_buy_export'') ? GETPOST(''accountancy_code_buy_export'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_PRODUCT_BUY_EXPORT_ACCOUNT"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_BUY_INTRA_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for intra-community product (goods) purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:308 and productaccount.php:714 as the fallback intra-community purchase account for goods. Also used in product/card.php:1943. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the ledger account used for intra-EU goods purchase lines when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:308|read|$aacompta_prodbuy_intra     = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_INTRA_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "accountancy/admin/productaccount.php:714|read|$compta_prodbuy = getDolGlobalString(''ACCOUNTING_PRODUCT_BUY_INTRA_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1943|read|$accountancy_code_buy_intra = (GETPOSTISSET(''accountancy_code_buy_intra'') ? GETPOST(''accountancy_code_buy_intra'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_PRODUCT_BUY_INTRA_ACCOUN"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_MODE', 'string', NULL, 'accountancy', 'Controls the mode used to assign accounting accounts to products in the accounting module.', 'Set via the admin UI at accountancy/admin/productaccount.php. The value is written with dolibarr_set_const when the form is submitted.', 'Changing this value alters how product accounting accounts are determined or displayed in the accounting module.', 'Free string (mode identifier set from $accounting_product_mode form variable).', 0, 0, 'accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["accountancy/admin/productaccount.php:192|write|if (!dolibarr_set_const($db, ''ACCOUNTING_PRODUCT_MODE'', $accounting_product_mode, ''chaine'', 0, '''', $conf->entity)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PRODUCT_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code (not rowid) for product (goods) sales when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:313 and accountancy/journal/sellsjournal.php:245 as the fallback sales account for goods. Also used in product/card.php:1896. A code comment notes this stores the account number, not the accountingaccount rowid. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the default ledger account assigned to goods sales lines in the sells journal when no product-level override exists.', 'Accounting account code string (account number, not rowid); fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// at this time ACCOUNTING_SERVICE_SOLD_ACCOUNT & ACCOUNTING_PRODUCT_SOLD_ACCOUNT are account number not accountingacount rowid", "accountancy/journal/sellsjournal.php:245|read|$compta_prod = getDolGlobalString(''ACCOUNTING_PRODUCT_SOLD_ACCOUNT'', ''NotDefined'');", "accountancy/admin/productaccount.php:313|read|$aacompta_prodsell          = getDolGlobalString(''ACCOUNTING_PRODUCT_SOLD_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1896|read|$accountancy_code_sell = (GETPOSTISSET(''accountancy_code_sell'') ? GETPOST(''accountancy_code_sell'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_PRODUCT_SOLD_ACCOUNT\"));"]', 'high', NULL);
