INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_PURCHASES_DO_NOT_DISPATCH_TAXES', 'string', NULL, 'accountancy', 'When enabled, prevents tax amounts from being split off from the base line entry and credited to a separate tax account in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:235 via getDolGlobalInt. The inline comment reads: ''If enabled, Tax will NOT get split off from the base entry and credited to a separ[ate account]''. No admin UI is configured.', 'Enabling this constant keeps tax amounts embedded in the base purchase line entry rather than dispatching them to a dedicated tax account, affecting the structure of purchase journal entries.', '0 or empty = taxes are dispatched to separate accounts (default); non-zero = taxes remain with the base line entry.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:235|read|$noTaxDispatchingKeepWithLines = getDolGlobalInt(''ACCOUNTING_PURCHASES_DO_NOT_DISPATCH_TAXES''); //If enabled, Tax will NOT get split off from the base entry and credited to a separ"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_REEXPORT', 'string', NULL, 'accountancy', 'Allows re-exporting of accounting bookkeeping entries that have already been exported.', 'Written via accountancy/bookkeeping/export.php:482. Checked at lines 487, 600, 938, 956 to gate re-export paths. The comment at line 600 reads: ''Reexport not enabled (default mode)''. Read at line 643 to pass a flag to fetchAll.', 'When enabled, already-exported bookkeeping entries can be included in subsequent exports; when disabled (default), only unexported entries are included.', 'yesno (1/0): 1 to allow re-export; 0 or unset for default mode (no re-export).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/bookkeeping/export.php:600|check|if (!getDolGlobalString(''ACCOUNTING_REEXPORT'')) {\t// Reexport not enabled (default mode)", "accountancy/bookkeeping/export.php:482|write|if (!dolibarr_set_const($db, \"ACCOUNTING_REEXPORT\", $setreexport, ''yesno'', 0, '''', $conf->entity)) {", "accountancy/bookkeeping/export.php:938|check|if (!getDolGlobalString(''ACCOUNTING_REEXPORT'')) {", "accountancy/bookkeeping/export.php:643|read|$result = $object->fetchAll($sortorder, $sortfield, $limit, $offset, $filter, ''AND'', (getDolGlobalString(''ACCOUNTING_REEXPORT'') ? 1 : 0));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_REPORTS_INCLUDE_LOAN', 'string', NULL, 'compta', 'When enabled, includes loan data in accounting result reports when the loan module is active.', 'Configured via admin/compta.php (yes/no selector at line 203, saved at lines 118 and 124). Checked in compta/resultat/projects.php:946, index.php:887, and clientfourn.php:1238, conditioned additionally on isModEnabled(''loan'') or isModEnabled(''don'') and accounting mode.', 'Enabling this constant causes loan entries to appear in result and balance reports; disabling it hides them.', '1 = include loan lines in reports; empty/0 = exclude (default)', 0, 0, 'admin/compta.php|admin/compta.php|admin/compta.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/compta.php:203|read|print $form->selectyesno(''ACCOUNTING_REPORTS_INCLUDE_LOAN'', (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_LOAN'')));", "compta/resultat/index.php:887|check|if (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_LOAN'') && isModEnabled(''loan'') && ($modecompta == ''CREANCES-DETTES'' || $modecompta == \"RECETTES-DEPENSES\")) {", "compta/resultat/projects.php:946|check|if (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_LOAN'') && isModEnabled(''don'')) {", "compta/resultat/clientfourn.php:1238|check|if (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_LOAN'') && isModEnabled(''don'') && ($modecompta == ''CREANCES-DETTES'' || $modecompta == \"RECETTES-DEPENSES\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_REPORTS_INCLUDE_VARPAY', 'string', NULL, 'compta', 'When enabled, includes bank variable payment lines in accounting result reports.', 'Configured via admin/compta.php (yes/no selector at line 196, saved at lines 104 and 110). Checked in compta/resultat/projects.php:854, index.php:816, and clientfourn.php:1159, all conditioned additionally on isModEnabled(''bank'') and accounting mode.', 'Enabling this constant adds bank payment variation lines to the balance/result reports; disabling it excludes those lines.', '1 = include variable payment lines in reports; empty/0 = exclude (default)', 0, 0, 'admin/compta.php|admin/compta.php|admin/compta.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/compta.php:196|read|print $form->selectyesno(''ACCOUNTING_REPORTS_INCLUDE_VARPAY'', (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_VARPAY'')));", "compta/resultat/index.php:816|check|if (getDolGlobalString(''ACCOUNTING_REPORTS_INCLUDE_VARPAY'') && isModEnabled(\"bank\") && ($modecompta == ''CREANCES-DETTES'' || $modecompta == \"RECETTES-DEPENSES\")) {", "compta/resultat/projects.php:853  //$conf->global->ACCOUNTING_REPORTS_INCLUDE_VARPAY = 1;", "compta/resultat/clientfourn.php:1157  //$conf->global->ACCOUNTING_REPORTS_INCLUDE_VARPAY = 1;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_REVENUESTAMP_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Specifies the accounting account code used for revenue stamp on sales in the accounting journal.', 'Referenced (currently commented out) in accountancy/journal/sellsjournal.php:251 as the account for revenue stamp journal entries. The only occurrence in the payload is commented-out code.', 'Exact behavior unclear from code alone; the sole occurrence is commented out, so the constant has no active effect in the current codebase as evidenced by the payload.', 'String representing an accounting account code; defaults to ''NotDefined'' if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:251  // $compta_revenuestamp = getDolGlobalString(''ACCOUNTING_REVENUESTAMP_SOLD_ACCOUNT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_REVERSE_CHARGE_ALSO_NON_EEC', 'string', NULL, 'accountancy', 'Controls whether reverse-charge VAT logic is also applied to non-EEC countries, in addition to the standard EEC country check.', 'Checked once in accountancy/journal/purchasesjournal.php:313 in a condition that also tests for FR country code and the ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE constant. No admin UI is configured.', 'Enabling this constant extends reverse-charge VAT treatment to supplier transactions from non-EEC countries.', 'Truthy (non-empty / 1) = reverse charge applied also for non-EEC; falsy (empty / 0) = standard EEC-only behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:313|check|if (($mysoc->country_code == ''FR'' || getDolGlobalString(''ACCOUNTING_FORCE_ENABLE_VAT_REVERSE_CHARGE'')) && $obj->vat_reverse_charge == 1 && (in_array($obj->country_code, $country_co"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_', 'string', NULL, 'accountancy', 'Family of dynamic constants (ACCOUNTING_SERVICE_{TYPE}_ACCOUNT, _INTRA_ACCOUNT, _EXPORT_ACCOUNT) that provide accounting account codes for service product types.', 'Accessed dynamically in accountancy/class/accountingaccount.class.php:778, :782, :784, :787, and :790 by appending a computed suffix (_ACCOUNT, _INTRA_ACCOUNT, _EXPORT_ACCOUNT) to the base prefix ''ACCOUNTING_SERVICE_''. No admin UI is configured.', 'Setting these constants assigns specific accounting accounts for service product lines in standard, intra-community, and export sale contexts.', 'Chart-of-accounts code string for each variant; variants are ACCOUNTING_SERVICE_{TYPE}_ACCOUNT, ACCOUNTING_SERVICE_{TYPE}_INTRA_ACCOUNT, ACCOUNTING_SERVICE_{TYPE}_EXPORT_ACCOUNT.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountingaccount.class.php:778|read|$code_l = getDolGlobalString(''ACCOUNTING_SERVICE_'' . $const_name . ''_ACCOUNT'');", "accountancy/class/accountingaccount.class.php:787|read|$code_l = getDolGlobalString(''ACCOUNTING_SERVICE_'' . $const_name . ''_INTRA_ACCOUNT'');", "accountancy/class/accountingaccount.class.php:790|read|$code_l = getDolGlobalString(''ACCOUNTING_SERVICE_'' . $const_name . ''_EXPORT_ACCOUNT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_BUY_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code used for service purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php and accountancy/journal/purchasesjournal.php:255 as the fallback purchase account for services. Also used in product/card.php:1933 as the default when no explicit buy account is entered. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the default ledger account assigned to service purchase lines in the purchases journal for products without a specific account override.', 'Accounting account code string (e.g. chart-of-accounts number); fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:255|read|$compta_prod = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_ACCOUNT'', ''NotDefined'');", "accountancy/admin/productaccount.php:304|read|$aacompta_servbuy           = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1933|read|$accountancy_code_buy = (GETPOST(''accountancy_code_buy'', ''alpha'') ? (GETPOST(''accountancy_code_buy'', ''alpha'')) : getDolGlobalString(\"ACCOUNTING_SERVICE_BUY_ACCOUNT\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_BUY_EXPORT_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for export service purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:306 and productaccount.php:731 as the fallback export purchase account for services. Also used in product/card.php:1957 as the default. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the ledger account used for export service purchase lines when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:306|read|$aacompta_servbuy_export    = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "accountancy/admin/productaccount.php:731|read|$compta_prodbuy = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1957|read|$accountancy_code_buy_export = (GETPOST(''accountancy_code_buy_export'') ? GETPOST(''accountancy_code_buy_export'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_SERVICE_BUY_EXPORT_ACCOUNT"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_BUY_INTRA_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for intra-community service purchases when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:305 and productaccount.php:728 as the fallback intra-community purchase account for services. Also used in product/card.php:1945 as the default. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the ledger account used for intra-EU service purchase lines when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:305|read|$aacompta_servbuy_intra     = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_INTRA_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "accountancy/admin/productaccount.php:728|read|$compta_prodbuy = getDolGlobalString(''ACCOUNTING_SERVICE_BUY_INTRA_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1945|read|$accountancy_code_buy_intra = (GETPOSTISSET(''accountancy_code_buy_intra'') ? GETPOST(''accountancy_code_buy_intra'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_SERVICE_BUY_INTRA_ACCOUN"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code (not rowid) for service sales when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:310 and accountancy/journal/sellsjournal.php:247 as the fallback sales account for services. Also used in product/card.php:1898. A code comment notes this stores the account number, not the accountingaccount rowid. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the default ledger account assigned to service sales lines in the sells journal when no product-level override exists.', 'Accounting account code string (account number, not rowid); fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// at this time ACCOUNTING_SERVICE_SOLD_ACCOUNT & ACCOUNTING_PRODUCT_SOLD_ACCOUNT are account number not accountingacount rowid", "accountancy/journal/sellsjournal.php:247|read|$compta_prod = getDolGlobalString(''ACCOUNTING_SERVICE_SOLD_ACCOUNT'', ''NotDefined'');", "accountancy/admin/productaccount.php:310|read|$aacompta_servsell          = getDolGlobalString(''ACCOUNTING_SERVICE_SOLD_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1898|read|$accountancy_code_sell = (GETPOSTISSET(''accountancy_code_sell'') ? GETPOST(''accountancy_code_sell'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_SERVICE_SOLD_ACCOUNT\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_SERVICE_SOLD_EXPORT_ACCOUNT', 'string', NULL, 'accountancy', 'Default accounting account code for export service sales when no per-product code is set.', 'Read in accountancy/admin/productaccount.php:312 and productaccount.php:699 as the fallback export sales account for services. Also used in product/card.php:1922. Configured via accountancy/admin/productaccount.php.', 'Changing this value alters the ledger account used for export service sales lines when no product-level override exists.', 'Accounting account code string; fallback label is ''CodeNotDef''', 0, 0, 'accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/productaccount.php:312|read|$aacompta_servsell_export   = getDolGlobalString(''ACCOUNTING_SERVICE_SOLD_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "accountancy/admin/productaccount.php:699|read|$compta_prodsell = getDolGlobalString(''ACCOUNTING_SERVICE_SOLD_EXPORT_ACCOUNT'', $langs->trans(\"CodeNotDef\"));", "product/card.php:1922|read|$accountancy_code_sell_export = (GETPOST(''accountancy_code_sell_export'') ? GETPOST(''accountancy_code_sell_export'', ''alpha'') : getDolGlobalString(\"ACCOUNTING_SERVICE_SOLD_EXPORT_ACC"]', 'medium', NULL);
