INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_VAT_BUY_ACCOUNT', 'string', NULL, 'accountancy', 'Defines the default accounting account code used for VAT on purchases in accounting journals.', 'Read in accountancy/journal/purchasesjournal.php:226, accountancy/journal/expensereportsjournal.php:186, accountancy/journal/treasuryjournal.php:363 and :474, accountancy/class/accountingjournal.class.php:806, and compta/journal/purchasesjournal.php:157. Fallback is ''NotDefined''. No admin UI configured.', 'If unset, purchase and expense-report journals use the reserved string ''NotDefined'' as the VAT account code, producing unresolved accounting entries for VAT on purchases.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:226|read|$cpttva = getDolGlobalString(''ACCOUNTING_VAT_BUY_ACCOUNT'', ''NotDefined'');", "accountancy/journal/treasuryjournal.php:363|read|$account_vat_buy = getDolGlobalString(''ACCOUNTING_VAT_BUY_ACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/class/accountingjournal.class.php:806|read|$acc_vat_coll_def = getDolGlobalString(''ACCOUNTING_VAT_BUY_ACCOUNT'');", "accountancy/journal/expensereportsjournal.php:186|read|$account_vat = getDolGlobalString(''ACCOUNTING_VAT_BUY_ACCOUNT'', ''NotDefined'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_VAT_BUY_REVERSE_CHARGES_CREDIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the credit side of VAT reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:227 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the reverse-charge credit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:227|read|$rcctva = getDolGlobalString(''ACCOUNTING_VAT_BUY_REVERSE_CHARGES_CREDIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_VAT_BUY_REVERSE_CHARGES_DEBIT', 'string', NULL, 'accountancy', 'Defines the accounting account code for the debit side of VAT reverse-charge entries in the purchases journal.', 'Read once in accountancy/journal/purchasesjournal.php:228 with fallback ''NotDefined''. No admin UI is configured.', 'If unset, the reverse-charge debit entry uses the reserved string ''NotDefined'', producing an unresolved accounting entry.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/purchasesjournal.php:228|read|$rcdtva = getDolGlobalString(''ACCOUNTING_VAT_BUY_REVERSE_CHARGES_DEBIT'', ''NotDefined'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_VAT_PAY_ACCOUNT', 'string', NULL, 'accountancy', 'Stores the general ledger account number used for VAT payment entries in the bank journal.', 'Read in accountancy/journal/bankjournal.php:273 and :1459, and in accountancy/journal/treasuryjournal.php:710. The ''NotDefined'' reserved-word fallback is applied at both bankjournal and treasuryjournal read sites. No admin UI write found; HIDDEN_GUESS is 1.', 'If not set, VAT payment lines in the bank and treasury journals use ''NotDefined'' as the account, which will cause posting errors.', 'String: general ledger account number; empty = not configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:273|read|$account_pay_vat = getDolGlobalString(''ACCOUNTING_VAT_PAY_ACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/bankjournal.php:1459|read|$account_ledger = getDolGlobalString(''ACCOUNTING_VAT_PAY_ACCOUNT'');", "accountancy/journal/treasuryjournal.php:710|read|$account_pay_vat = getDolGlobalString(''ACCOUNTING_VAT_PAY_ACCOUNT'', ''NotDefined''); // NotDefined is a reserved word"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACCOUNTING_VAT_SOLD_ACCOUNT', 'string', NULL, 'accountancy', 'Defines the default accounting account code used for VAT on sales in accounting journals.', 'Read in accountancy/journal/sellsjournal.php:226, accountancy/journal/treasuryjournal.php:246, compta/journal/sellsjournal.php:193, and accountancy/class/accountingjournal.class.php:1115. The fallback value ''NotDefined'' is used when this constant is not set. No admin UI is configured.', 'If unset, journals use the reserved string ''NotDefined'' as the VAT account code, which will cause incorrect or unresolved accounting entries for VAT on sales.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/sellsjournal.php:226|read|$cpttva = getDolGlobalString(''ACCOUNTING_VAT_SOLD_ACCOUNT'', ''NotDefined'');", "accountancy/journal/treasuryjournal.php:246|read|$account_vat_sold = getDolGlobalString(''ACCOUNTING_VAT_SOLD_ACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/class/accountingjournal.class.php:1115|read|$acc_vat_ded_def  = getDolGlobalString(''ACCOUNTING_VAT_SOLD_ACCOUNT'');", "compta/journal/sellsjournal.php:193|read|$cpttva = getDolGlobalString(''ACCOUNTING_VAT_SOLD_ACCOUNT'', $langs->trans(\"CodeNotDef\"));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ACTION_EVENT_ADDON_PDF', 'string', NULL, 'admin', 'Name of the PDF document template model used for agenda event (action/communication) documents.', 'COMMENTS state: ''Name of PDF model of actioncomm''. Written via admin/agenda_other.php:178, admin/agenda_reminder.php:147-150 (including deletion at line 142) and read/checked across both admin pages. Configurable via admin/agenda_other.php and admin/agenda_reminder.php.', 'Changing this value switches the PDF template used when generating agenda event documents; an invalid model name will prevent document generation.', 'String name of a PDF model class available for action/communication documents (e.g. ''standard''). Empty = default model used.', 0, 0, 'admin/agenda_other.php|admin/agenda_other.php|admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["// $this->const[$r] = [\"ACTION_EVENT_ADDON_PDF\", \"chaine\", \"standard\", ''Name of PDF model of actioncomm'', 0];", "admin/agenda_other.php:178|write|dolibarr_set_const($db, \"ACTION_EVENT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity);", "admin/agenda_other.php:306|check|if (getDolGlobalString(''ACTION_EVENT_ADDON_PDF'') == \"$name\") {", "admin/agenda_reminder.php:147|write|if (dolibarr_set_const($db, \"ACTION_EVENT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADD_UNSPLASH_LOGIN_BACKGROUND', 'string', NULL, 'core', 'Sets a background image URL (e.g. from Unsplash) to display on the Dolibarr login page.', 'When set, the login page renders the value as a CSS background-image URL on the body element (core/tpl/login.tpl.php:217). It is also checked in passwordforgotten and passwordreset templates. Configurable via admin/ihm.php.', 'Setting this changes the login page background from the default theme to the specified image URL. Removing it reverts to the default background style.', 'Any valid image URL string, e.g. ''https://source.unsplash.com/random''', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:216  // For example $conf->global->ADD_UNSPLASH_LOGIN_BACKGROUND = ''https://source.unsplash.com/random''?>", "core/tpl/login.tpl.php:217|read|<body class=\"body bodylogin\" style=\"background-image: url(''<?php echo dol_escape_htmltag(getDolGlobalString(''ADD_UNSPLASH_LOGIN_BACKGROUND'')); ?>'');", "admin/ihm.php:721|check|if (getDolGlobalString(''ADD_UNSPLASH_LOGIN_BACKGROUND'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_ADDON_PDF', 'string', NULL, 'adherents', 'Specifies the PDF generation module to use for member documents.', 'When set, the named PDF module is loaded in adherents/class/adherent.class.php to generate member documents. No admin UI; must be set directly in the database.', 'Setting this value switches the PDF template used for member card generation. Removing it causes the system to fall back to the default module selection logic.', 'PDF module name string; empty = default module used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:2843|read|} elseif (getDolGlobalString(''ADHERENT_ADDON_PDF'')) {", "adherents/class/adherent.class.php:2844|read|$modele = getDolGlobalString(''ADHERENT_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_ADDRESSES_MANAGEMENT', 'string', NULL, 'adherents', 'Switches the member canvas UI labels between member-centric and address-centric terminology.', 'Checked in three consecutive lines of adherents/canvas/default/actions_adherentcard_default.class.php (lines 66, 69, 72) to choose between ''Adherent''/''EditAdherent''/''NewAdherent'' and ''ContactAddress''/''EditAdherentAddress''/''NewAdherentAddress'' translations. No admin UI is provided.', 'Setting this constant changes the display labels in the member canvas, presenting the form as a member record rather than an address record.', 'Non-empty/truthy = member terminology used; empty/unset = address terminology used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/canvas/default/actions_adherentcard_default.class.php:66|read|$out .= (getDolGlobalString(''ADHERENT_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"Adherent\") : $langs->trans(\"ContactAddress\"));", "adherents/canvas/default/actions_adherentcard_default.class.php:69|read|$out .= (getDolGlobalString(''ADHERENT_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"EditAdherent\") : $langs->trans(\"EditAdherentAddress\"));", "adherents/canvas/default/actions_adherentcard_default.class.php:72|read|$out .= (getDolGlobalString(''ADHERENT_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"NewAdherent\") : $langs->trans(\"NewAdherentAddress\"));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_AUTOREGISTER_NOTIF_MAIL', 'string', NULL, 'public', 'Sets the body content of the notification email sent to administrators when a member auto-registers.', 'Read at public/members/new.php:526 as a condition (truthy check alongside subject) and at :548 as the email body passed through makeSubstitution(). No admin UI write found.', 'When set together with ADHERENT_AUTOREGISTER_NOTIF_MAIL_SUBJECT and MAIN_INFO_SOCIETE_MAIL, its content (after substitution) is sent as the admin notification email body.', 'An email body string (supports substitution variables).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:526|read|getDolGlobalString(''ADHERENT_AUTOREGISTER_NOTIF_MAIL'')) {", "public/members/new.php:548|read|$adh->makeSubstitution(getDolGlobalString(''ADHERENT_AUTOREGISTER_NOTIF_MAIL'')),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_AUTOREGISTER_NOTIF_MAIL_SUBJECT', 'string', NULL, 'public', 'Sets the subject line of the notification email sent to administrators when a member auto-registers.', 'Checked at public/members/new.php:525 (requires MAIN_INFO_SOCIETE_MAIL to also be set) and read at :545 as the notification email subject prefixed with the application name.', 'When set together with MAIN_INFO_SOCIETE_MAIL, an admin notification email is sent with this subject on member auto-registration.', 'A subject string; used as the email subject prefixed with ''[AppName] ''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:525|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_MAIL'') && getDolGlobalString(''ADHERENT_AUTOREGISTER_NOTIF_MAIL_SUBJECT'') &&", "public/members/new.php:545|read|''[''.$appli.''] '' . getDolGlobalString(''ADHERENT_AUTOREGISTER_NOTIF_MAIL_SUBJECT''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_BANK_USE', 'string', NULL, 'adherents', 'Controls how member subscription payments are recorded in the banking system.', 'Determines whether subscription payments are recorded directly to a bank account (''bankdirect''), via an invoice (''bankviainvoice''), or not at all. Checked across adherents/subscription.php:864, adherents/subscription/card.php:255-351, and public/payment/paymentok.php:744. Configurable via adherents/admin/member.php:179.', 'Changing this value alters how member subscription payments are processed and recorded: direct bank entry, invoice-based bank entry, or no bank recording.', '''bankdirect'' = direct bank account entry; ''bankviainvoice'' = payment via generated invoice; empty/unset = no bank recording.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:638|check|if (getDolGlobalString(''ADHERENT_BANK_USE'') == ''bankdirect'' || getDolGlobalString(''ADHERENT_BANK_USE'') == ''bankviainvoice'') {", "public/payment/paymentok.php:744|check|if (getDolGlobalString(''ADHERENT_BANK_USE'') == ''bankviainvoice'' && isModEnabled(\"bank\") && isModEnabled(\"societe\") && isModEnabled(''invoice'')) {", "adherents/subscription.php:864|check|if (getDolGlobalString(''ADHERENT_BANK_USE'') == ''bankviainvoice'' && isModEnabled(''bank'') && isModEnabled(''societe'') && isModEnabled(''invoice'')) {", "adherents/admin/member.php:179|write|$res4 = dolibarr_set_const($db, ''ADHERENT_BANK_USE'', GETPOST(''ADHERENT_BANK_USE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_CARDS_ADDON_PDF', 'string', NULL, 'core', 'Specifies the PDF template module class name used to generate member visit/ID cards.', 'Read at core/modules/member/modules_cards.php:97–98 to load the configured PDF template class. The docblock comment at :69 states ''Create a document for visit card according to template defined in ADHERENT_CARDS_ADDON_PDF''. When unset, no specific template is selected.', 'Changing this value switches the PDF template used for member card generation. Leaving it unset means no template class is loaded via this constant.', 'String: PHP class name of the PDF template module (e.g. ''pdf_standard_cards''); empty/unset = no template loaded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/member/modules_cards.php:69  *\tCreate a document for visit card according to template defined in ADHERENT_CARDS_ADDON_PDF", "core/modules/member/modules_cards.php:97|check|if (getDolGlobalString(''ADHERENT_CARDS_ADDON_PDF'')) {", "core/modules/member/modules_cards.php:98|read|$code = getDolGlobalString(''ADHERENT_CARDS_ADDON_PDF'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_CARD_BACKGROUND', 'string', NULL, 'core', 'Specifies the filename (relative to the member output directory) of a background image for member card PDFs.', 'Checked and read in core/modules/member/doc/pdf_standard_member.class.php at lines 139-140. If the file exists at the expected path, it is set as the background image for the generated member card PDF. No admin UI write is present.', 'When set and the referenced file exists, the member card PDF uses it as a background image. When unset or file not found, no background image is applied.', 'Filename string relative to the member output directory; empty or unset for no background.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/member/doc/pdf_standard_member.class.php:139|check|if (getDolGlobalString(''ADHERENT_CARD_BACKGROUND'') && file_exists($conf->adherent->dir_output.''/'' . getDolGlobalString(''ADHERENT_CARD_BACKGROUND''))) {", "core/modules/member/doc/pdf_standard_member.class.php:140|read|$backgroundimage = $conf->adherent->dir_output.''/'' . getDolGlobalString(''ADHERENT_CARD_BACKGROUND'');"]', 'medium', NULL);
