INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_CARD_TYPE', 'string', NULL, 'adherents', 'Specifies the default card model used when printing member identification cards.', 'Set via the admin UI at adherents/admin/member.php:203 and rendered as a dropdown at :754 defaulting to ''CARD''. Also read in adherents/cartes/carte.php:339 and :357 as the pre-selected model for card printing.', 'Changing this value alters which card template is pre-selected on the member card printing page.', 'String name of the card model (e.g. ''CARD''); empty or unset = no default selected', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:754|read|print $form->selectarray(''ADHERENT_CARD_TYPE'', $arrayoflabels, getDolGlobalString(''ADHERENT_CARD_TYPE'', ''CARD''), 1, 0, 0);", "adherents/admin/member.php:203|write|$res1 = dolibarr_set_const($db, ''ADHERENT_CARD_TYPE'', GETPOST(''ADHERENT_CARD_TYPE''), ''chaine'', 0, '''', $conf->entity);", "adherents/cartes/carte.php:339|read|print $form->selectarray(''modelcard'', $arrayoflabels, (GETPOST(''modelcard'') ? GETPOST(''modelcard'') : getDolGlobalString(''ADHERENT_CARD_TYPE'')), 1, 0, 0, '''', 0, 0, 0, '''', '''', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_CC_MAIL_FROM', 'string', NULL, 'adherents', 'Specifies a CC email address to include on member notification emails.', 'When set, the value is used as the CC address when sending member emails in adherents/class/adherent.class.php. No admin UI; must be set directly in the database.', 'Setting this causes a copy of member notification emails to be sent to the specified address. Leaving it empty suppresses the CC.', 'Email address string; empty = no CC', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3331|read|$cc = getDolGlobalString(''ADHERENT_CC_MAIL_FROM'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_CREATE_EXTERNAL_USER_LOGIN', 'string', NULL, 'adherents', 'Controls whether an external user login is automatically created when a member subscription payment is completed.', 'Rendered as a yes/no selector in adherents/admin/member.php:601 and saved via dolibarr_set_const at :178. Checked at public/payment/paymentok.php:900 to trigger external user creation after successful payment.', 'Enabling this causes Dolibarr to create an external user account for new members upon payment confirmation; disabling skips that step.', '0 = do not create external user login; 1 = create external user login on payment', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:601|read|print $form->selectyesno(''ADHERENT_CREATE_EXTERNAL_USER_LOGIN'', getDolGlobalInt(''ADHERENT_CREATE_EXTERNAL_USER_LOGIN''), 1, false, 0, 1);", "adherents/admin/member.php:178|write|$res3 = dolibarr_set_const($db, ''ADHERENT_CREATE_EXTERNAL_USER_LOGIN'', GETPOST(''ADHERENT_CREATE_EXTERNAL_USER_LOGIN'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "public/payment/paymentok.php:900|check|if (getDolGlobalString(''ADHERENT_CREATE_EXTERNAL_USER_LOGIN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_DEFAULT_CREATE_THIRDPARTY', 'string', NULL, 'adherents', 'Automatically creates a linked third-party record when a new member is created.', 'Checked at adherents/card.php:665 and public/members/new.php:564; when set, the member creation workflow also creates a corresponding third-party (company/contact) record. No admin UI is provided.', 'Enabling this constant causes a third-party record to be created automatically alongside each new member.', 'Non-empty/truthy = third-party auto-created on member creation; empty/unset = no automatic third-party creation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:665|check|if (getDolGlobalString(''ADHERENT_DEFAULT_CREATE_THIRDPARTY'')) {", "public/members/new.php:564|check|if (getDolGlobalString(''ADHERENT_DEFAULT_CREATE_THIRDPARTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_DEFAULT_SENDINFOBYMAIL', 'string', NULL, 'adherents', 'Sets the default checked state of the ''send information by email'' checkbox on member subscription and card forms.', 'Read at adherents/subscription.php:1189 and adherents/card.php:1731, 1795, 1856 to pre-check the email notification checkbox when no explicit POST value is present. Configurable via adherents/admin/member.php:177.', 'Enabling this constant causes the email notification checkbox to be pre-checked by default on member-related forms, increasing the likelihood that confirmation emails are sent.', 'Non-empty/truthy = checkbox pre-checked; empty/unset = checkbox unchecked by default.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:1189|read|$tmp = ''<input name=\"sendmail\" type=\"checkbox\"''.(GETPOST(''sendmail'', ''alpha'') ? '' checked'' : (getDolGlobalString(''ADHERENT_DEFAULT_SENDINFOBYMAIL'') ? '' checked'' : '''')).''>'';", "adherents/card.php:1731|read|$formquestion[] = array(''type'' => ''checkbox'', ''name'' => ''send_mail'', ''label'' => $label, ''value'' => (getDolGlobalString(''ADHERENT_DEFAULT_SENDINFOBYMAIL'') ? true : false));", "adherents/admin/member.php:177|write|$res3 = dolibarr_set_const($db, ''ADHERENT_DEFAULT_SENDINFOBYMAIL'', GETPOST(''ADHERENT_DEFAULT_SENDINFOBYMAIL'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "adherents/admin/member.php:606|read|print $form->selectyesno(''ADHERENT_DEFAULT_SENDINFOBYMAIL'', getDolGlobalInt(''ADHERENT_DEFAULT_SENDINFOBYMAIL''), 1, false, 0, 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_EMAIL_TEMPLATE_AUTOREGISTER', 'string', NULL, 'public', 'Specifies the label of the email template sent to members who auto-register via the public membership form.', 'Read at public/members/new.php:497 as the label used to look up the email template for auto-registration confirmation. No admin UI write found.', 'When set to a valid template label, a confirmation email is sent to the new member; when unset, no template-based email is sent.', 'An email template label string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:497|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_AUTOREGISTER'');"]', 'low', NULL);
