INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_EMAIL_TEMPLATE_EXCLUSION', 'string', NULL, 'adherents', 'Specifies the email template label used when sending member exclusion notification emails.', 'Read at adherents/card.php:865 and adherents/card.php:1823 to select the appropriate email template for member exclusion events. No admin UI is provided.', 'Setting this constant to a valid email template label causes that template to be used for member exclusion notification emails.', 'A string matching an email template label; empty/unset = no specific template selected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:865|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_EXCLUSION'');", "adherents/card.php:1823|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_EXCLUSION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_EMAIL_TEMPLATE_MEMBER_VALIDATION', 'string', NULL, 'adherents', 'Specifies the email template label used when sending member validation confirmation emails.', 'Read at adherents/card.php:730 and adherents/card.php:1698 to select the appropriate email template for member validation events. No admin UI is provided.', 'Setting this constant to a valid email template label causes that template to be used for member validation confirmation emails.', 'A string matching an email template label; empty/unset = no specific template selected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:730|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_MEMBER_VALIDATION'');", "adherents/card.php:1698|read|$labeltouse = getDolGlobalString(\"ADHERENT_EMAIL_TEMPLATE_MEMBER_VALIDATION\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_EMAIL_TEMPLATE_REMIND_EXPIRATION', 'string', NULL, 'adherents', 'Specifies the email template to use for membership expiration reminder emails.', 'When set, the named template is loaded in adherents/class/adherent.class.php to compose the reminder email sent to members whose subscription is expiring. No admin UI; must be set directly in the database.', 'Setting this to a valid template name changes the content of expiration reminder emails. Removing it causes the system to use no specific template for reminders.', 'Email template name string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3316|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_REMIND_EXPIRATION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_EMAIL_TEMPLATE_SUBSCRIPTION', 'string', NULL, 'adherents', 'Specifies the email template label used when sending subscription confirmation emails to members.', 'The template label is read at adherents/subscription.php:382 and 1173, and at public/payment/paymentok.php:948, to select the appropriate email template for subscription events. No admin UI is provided.', 'Setting this constant to a valid email template label causes that template to be used for member subscription confirmation emails instead of any default.', 'A string matching an email template label; empty/unset = no specific template selected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:382|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_SUBSCRIPTION'');", "adherents/subscription.php:1173|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_SUBSCRIPTION'');", "public/payment/paymentok.php:948|read|$labeltouse = getDolGlobalString(''ADHERENT_EMAIL_TEMPLATE_SUBSCRIPTION'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_ETIQUETTE_TEXT', 'string', NULL, 'adherents', 'Defines the text template used when printing member address labels.', 'Set via the admin UI at adherents/admin/member.php:220. If not set, adherents/cartes/carte.php:235–236 applies a default template with member title, full name, address, zip, town, and country tokens. The value is passed through make_substitutions at carte.php:238.', 'Changing this value alters the layout of member address labels; clearing it causes Dolibarr to fall back to the built-in default label template.', 'Any string with substitution tokens; empty = default template applied (__MEMBER_TITLE__, __MEMBER_FULLNAME__, __MEMBER_ADDRESS__, __MEMBER_ZIP__ __MEMBER_TOWN__, __MEMBER_COUNTRY__)', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/cartes/carte.php:235|check|if (!getDolGlobalString(''ADHERENT_ETIQUETTE_TEXT'')) {", "adherents/cartes/carte.php:236|write|$conf->global->ADHERENT_ETIQUETTE_TEXT = \"__MEMBER_TITLE__\\n__MEMBER_FULLNAME__\\n__MEMBER_ADDRESS__\\n__MEMBER_ZIP__ __MEMBER_TOWN__\\n__MEMBER_COUNTRY__\";", "adherents/admin/member.php:220|write|$res2 = dolibarr_set_const($db, ''ADHERENT_ETIQUETTE_TEXT'', GETPOST(''ADHERENT_ETIQUETTE_TEXT'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "adherents/cartes/carte.php:238|read|$textleft = make_substitutions(getDolGlobalString(''ADHERENT_ETIQUETTE_TEXT''), $substitutionarray);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_ETIQUETTE_TYPE', 'string', NULL, 'adherents', 'Stores the selected label model (sticker template) used when printing member address cards.', 'Written by adherents/admin/member.php:219 and defaulted to ''CARD'' in the selector at adherents/admin/member.php:818. Read in core/modules/printsheet/modules_labels.php:98-99 to select the label module, and in barcode/printsheet.php:426 and adherents/cartes/carte.php:376 as the pre-selected model.', 'Changing this value changes the default label template applied when printing member cards; the selected value must correspond to an installed label module.', 'Label module code string, e.g. ''CARD''; empty = none selected.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:219|write|$res1 = dolibarr_set_const($db, ''ADHERENT_ETIQUETTE_TYPE'', GETPOST(''ADHERENT_ETIQUETTE_TYPE''), ''chaine'', 0, '''', $conf->entity);", "adherents/admin/member.php:818|read|print $form->selectarray(''ADHERENT_ETIQUETTE_TYPE'', $arrayoflabels, getDolGlobalString(''ADHERENT_ETIQUETTE_TYPE'') ? getDolGlobalString(''ADHERENT_ETIQUETTE_TYPE'') : ''CARD'', 1, 0, 0)", "core/modules/printsheet/modules_labels.php:99|read|$code = getDolGlobalString(''ADHERENT_ETIQUETTE_TYPE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_LOGIN_NOT_REQUIRED', 'string', '1', 'adherents', 'Controls whether a login is required for member (adherent) records; when truthy, login is not required.', 'Managed via adherents/admin/member.php. The comment at adherents/class/adherent.class.php:958 explains: ''If option ADHERENT_LOGIN_NOT_REQUIRED is on, there is no login of member, so we do not overwrite user login to keep existing one.'' The admin UI stores 0 when the user selects ''yes'' (login not required) and 1 when ''no''. Checked in adherents/card.php, adherents/subscription.php, and partnership/partnership_list.php.', 'When set (truthy), member records can be created without a login field. When unset or 0, a login is enforced for members, and the login field is required and may overwrite linked user logins.', '1 (default) = login not required for members; 0 = login required.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// If option ADHERENT_LOGIN_NOT_REQUIRED is on, there is no login of member, so we do not overwrite user login to keep existing one.", "adherents/admin/member.php:175|write|$res1 = dolibarr_set_const($db, ''ADHERENT_LOGIN_NOT_REQUIRED'', GETPOST(''ADHERENT_LOGIN_NOT_REQUIRED'', ''alpha'') ? 0 : 1, ''chaine'', 0, '''', $conf->entity);", "adherents/class/adherent.class.php:959|check|if (!getDolGlobalString(''ADHERENT_LOGIN_NOT_REQUIRED'')) {", "partnership/partnership_list.php:536|check|if (!getDolGlobalString(''ADHERENT_LOGIN_NOT_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAILMAN_ADMIN_PASSWORD', 'string', NULL, 'mailmanspip', 'Admin password used to authenticate API calls to the Mailman mailing-list manager.', 'Referenced only once in mailmanspip/class/mailmanspip.class.php:159. No admin UI writes this constant.', 'Without the correct password, Mailman API calls will fail and member mailing-list subscriptions will not be processed.', 'String: Mailman administrator password.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:159|read|getDolGlobalString(''ADHERENT_MAILMAN_ADMIN_PASSWORD'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAILMAN_LISTS', 'string', NULL, 'mailmanspip', 'Comma-separated list of Mailman mailing lists to subscribe/unsubscribe members to, with optional TYPE: or CATEG: filters.', 'Used in mailmanspip/class/mailmanspip.class.php at lines 330-331 and 400-401 to determine which lists to process. The comment at line 339 documents the format.', 'If empty, no default lists are processed; only explicitly passed lists are used. The format allows filtering by member type or category.', 'Comma-separated list: "mailinglist0,TYPE:typevalue:mailinglist1,CATEG:categvalue:mailinglist2"', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Filter on type something (ADHERENT_MAILMAN_LISTS = \"mailinglist0,TYPE:typevalue:mailinglist1,CATEG:categvalue:mailinglist2\")", "mailmanspip/class/mailmanspip.class.php:330|check|if ($listes == '''' && getDolGlobalString(''ADHERENT_MAILMAN_LISTS'')) {", "mailmanspip/class/mailmanspip.class.php:331|read|$lists = explode('','', getDolGlobalString(''ADHERENT_MAILMAN_LISTS''));", "mailmanspip/class/mailmanspip.class.php:401|read|$lists = explode('','', getDolGlobalString(''ADHERENT_MAILMAN_LISTS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAILMAN_UNSUB_URL', 'string', NULL, 'mailmanspip', 'URL used specifically for unsubscribing members from Mailman mailing lists.', 'Used in mailmanspip/class/mailmanspip.class.php at lines 399 (check) and 424 (passed to callMailman). No admin UI writes this constant.', 'If not set, the unsubscription code path is skipped and members will not be removed from Mailman lists on leave.', 'String: URL of the Mailman unsubscription endpoint.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:399|check|if (getDolGlobalString(''ADHERENT_MAILMAN_UNSUB_URL'')) {", "mailmanspip/class/mailmanspip.class.php:424|read|$result = $this->callMailman($object, $conf->global->ADHERENT_MAILMAN_UNSUB_URL, $list);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAILMAN_URL', 'string', NULL, 'mailmanspip', 'Base URL of the Mailman instance used to subscribe and unsubscribe members.', 'Used in mailmanspip/class/mailmanspip.class.php at lines 329 (check) and 354 (passed to callMailman). No admin UI writes this constant.', 'If not set or incorrect, the callMailman function is not invoked and member mailing-list operations are skipped.', 'String: URL of the Mailman server (e.g. ''http://lists.example.com/mailman'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:329|check|if (getDolGlobalString(''ADHERENT_MAILMAN_URL'')) {", "mailmanspip/class/mailmanspip.class.php:354|read|$result = $this->callMailman($object, $conf->global->ADHERENT_MAILMAN_URL, $list);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAIL_FROM', 'string', NULL, 'adherents', 'Overrides the sender address used for member-related emails, falling back to the global email_from if not set.', 'Used in adherents/class/adherent.class.php and multiple adherents/*.php pages as the From address for membership emails (subscription confirmations, reminders, etc.). When not set, $conf->email_from is used as the fallback. No admin UI; must be set directly in the database.', 'Setting this directs all member notification emails to use the specified sender address. Removing it causes the system to fall back to the global email_from configuration.', 'Email address string; empty = falls back to $conf->email_from', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:508|read|$from = getDolGlobalString(''ADHERENT_MAIL_FROM'', $conf->email_from);", "adherents/class/adherent.class.php:3329|read|$from = getDolGlobalString(''ADHERENT_MAIL_FROM'', $conf->email_from);", "adherents/subscription.php:1191|read|$helpcontent .= ''<b>''.$langs->trans(\"MailFrom\").''</b>: ''.getDolGlobalString(''ADHERENT_MAIL_FROM'', $conf->email_from).''<br>''.\"\\n\";", "adherents/card.php:1715|read|$tmp .= ''<br>''.$langs->trans(\"MailFrom\").'': <b>''.getDolGlobalString(''ADHERENT_MAIL_FROM'', $conf->email_from).''</b>, '';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_MAIL_REQUIRED', 'string', NULL, 'adherents', 'Makes the email address field mandatory when creating or validating a member record.', 'When set, member creation and validation logic in adherents/class/adherent.class.php rejects records with an invalid or missing email. The email field is rendered with a required indicator in adherents/card.php and public/members/new.php. Configured via adherents/admin/member.php.', 'Enabling this enforces a valid email for all members. Disabling it makes email optional during member creation and subscription.', 'Truthy = email required and validated; empty/falsy = email optional', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:673|check|if (getDolGlobalString(''ADHERENT_MAIL_REQUIRED'') && !isValidEmail((string) $this->email)) {", "adherents/admin/member.php:176|write|$res2 = dolibarr_set_const($db, ''ADHERENT_MAIL_REQUIRED'', GETPOST(''ADHERENT_MAIL_REQUIRED'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "adherents/card.php:1215|read|print ''<tr><td>''.(getDolGlobalString(''ADHERENT_MAIL_REQUIRED'') ? ''<span class=\"fieldrequired\">'' : '''')...", "public/members/new.php:872|read|print ''<tr><td>''.(getDolGlobalString(''ADHERENT_MAIL_REQUIRED'') ? ''<span class=\"fieldrequired\">'' : '''')..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS', 'string', NULL, 'adherents', 'Specifies the product or service ID to use when creating an invoice line for a member subscription.', 'When set and the product or service module is enabled, a product line is automatically created on the subscription invoice using the product identified by this ID. Configured via adherents/admin/member.php.', 'Setting this causes subscription invoices to include a line for the specified product. Removing it disables automatic product line creation on subscription invoices.', 'Product/service rowid integer as a string; empty = no product linked to subscriptions', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:2067|check|if (getDolGlobalString(''ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS'') && (isModEnabled(\"product\") || isModEnabled(\"service\"))) {", "adherents/class/adherent.class.php:2068|read|$idprodsubscription = getDolGlobalString(''ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS'');", "adherents/subscription.php:1076|read|$result = $prodtmp->fetch(getDolGlobalInt(''ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS''));", "adherents/admin/member.php:188|write|$res5 = dolibarr_set_const($db, ''ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS'', GETPOST(''ADHERENT_PRODUCT_ID_FOR_SUBSCRIPTIONS'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SPIP_DB', 'string', NULL, 'mailmanspip', 'Name of the MySQL database used by the SPIP CMS for member synchronization.', 'Used exclusively in mailmanspip/class/mailmanspip.class.php (lines 110, 124, 130) to open and log connections to the SPIP MySQL database. No admin UI writes this constant.', 'An incorrect database name will cause the SPIP connection to fail.', 'String: MySQL database name for the SPIP installation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:110|check|if (getDolGlobalString(''ADHERENT_SPIP_SERVEUR'') != '''' && getDolGlobalString(''ADHERENT_SPIP_USER'') != '''' && getDolGlobalString(''ADHERENT_SPIP_PASS'') != '''' && getDolGlobalString(''ADH...", "mailmanspip/class/mailmanspip.class.php:124|read|$resource = getDoliDBInstance(''mysql'', getDolGlobalString(''ADHERENT_SPIP_SERVEUR''), getDolGlobalString(''ADHERENT_SPIP_USER''), getDolGlobalString(''ADHERENT_SPIP_PASS''), getDolGlobal...", "mailmanspip/class/mailmanspip.class.php:130|read|dol_syslog(''Error when connecting to SPIP ''.getDolGlobalString(''ADHERENT_SPIP_SERVEUR'')..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SPIP_PASS', 'string', NULL, 'mailmanspip', 'MySQL password used to authenticate the connection to the SPIP database.', 'Used exclusively in mailmanspip/class/mailmanspip.class.php to open a database connection (line 124) and to log errors (line 130). No admin UI writes this constant.', 'An incorrect password will cause the SPIP database connection to fail and an error will be logged.', 'String: MySQL password for the SPIP database.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:110|check|if (... && getDolGlobalString(''ADHERENT_SPIP_PASS'') != '''' ...", "mailmanspip/class/mailmanspip.class.php:124|read|$resource = getDoliDBInstance(''mysql'', getDolGlobalString(''ADHERENT_SPIP_SERVEUR''), getDolGlobalString(''ADHERENT_SPIP_USER''), getDolGlobalString(''ADHERENT_SPIP_PASS''), ...", "mailmanspip/class/mailmanspip.class.php:130|read|dol_syslog(''Error when connecting to SPIP ''.getDolGlobalString(''ADHERENT_SPIP_SERVEUR'').'' ''.getDolGlobalString(''ADHERENT_SPIP_USER'').'' ''.getDolGlobalString(''ADHERENT_SPIP_PASS'')..."]', 'medium', NULL);
