INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SPIP_SERVEUR', 'string', NULL, 'mailmanspip', 'Hostname or IP of the MySQL server hosting the SPIP database for member synchronization.', 'Used exclusively in mailmanspip/class/mailmanspip.class.php to open a database connection (line 124) and to log connection errors (line 130). No admin UI writes this constant; it must be set directly in the database.', 'If incorrect, the connection to the SPIP MySQL server will fail and an error will be logged via dol_syslog.', 'String: hostname or IP address of the SPIP MySQL server.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:110|check|if (getDolGlobalString(''ADHERENT_SPIP_SERVEUR'') != '''' && getDolGlobalString(''ADHERENT_SPIP_USER'') != '''' ...", "mailmanspip/class/mailmanspip.class.php:124|read|$resource = getDoliDBInstance(''mysql'', getDolGlobalString(''ADHERENT_SPIP_SERVEUR''), getDolGlobalString(''ADHERENT_SPIP_USER''), ...", "mailmanspip/class/mailmanspip.class.php:130|read|dol_syslog(''Error when connecting to SPIP ''.getDolGlobalString(''ADHERENT_SPIP_SERVEUR'')..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SPIP_USER', 'string', NULL, 'mailmanspip', 'MySQL username used to authenticate the connection to the SPIP database.', 'Used exclusively in mailmanspip/class/mailmanspip.class.php to open a database connection (line 124) and to log errors (line 130). No admin UI writes this constant.', 'An incorrect username will cause the SPIP database connection to fail and an error will be logged.', 'String: MySQL username for the SPIP database.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mailmanspip/class/mailmanspip.class.php:110|check|if (... && getDolGlobalString(''ADHERENT_SPIP_USER'') != '''' ...", "mailmanspip/class/mailmanspip.class.php:124|read|$resource = getDoliDBInstance(''mysql'', getDolGlobalString(''ADHERENT_SPIP_SERVEUR''), getDolGlobalString(''ADHERENT_SPIP_USER''), ...", "mailmanspip/class/mailmanspip.class.php:130|read|dol_syslog(''Error when connecting to SPIP ''.getDolGlobalString(''ADHERENT_SPIP_SERVEUR'').'' ''.getDolGlobalString(''ADHERENT_SPIP_USER'')..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SUBSCRIPTION_ACCOUNTINGACCOUNT', 'string', NULL, 'accountancy', 'Stores the general ledger account number used for member subscription payment entries in accounting journals.', 'Read in accountancy/journal/bankjournal.php:275 and :1462, and in accountancy/journal/treasuryjournal.php:1000 with ''NotDefined'' as reserved-word fallback. No admin UI write found; HIDDEN_GUESS is 1.', 'If not set, member subscription payment lines in the bank and treasury journals use ''NotDefined'' as the account, which will cause posting errors.', 'String: general ledger account number; empty = not configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:275|read|$account_pay_subscription = getDolGlobalString(''ADHERENT_SUBSCRIPTION_ACCOUNTINGACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/bankjournal.php:1462|read|$account_ledger = getDolGlobalString(''ADHERENT_SUBSCRIPTION_ACCOUNTINGACCOUNT'');", "accountancy/journal/treasuryjournal.php:1000|read|$account_subscription = getDolGlobalString(''ADHERENT_SUBSCRIPTION_ACCOUNTINGACCOUNT'', ''NotDefined''); // NotDefined is a reserved word"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_SUBSCRIPTION_HIDECOMPLEMENTARYACTIONS', 'bool', NULL, 'adherents', 'Hides the complementary action buttons (bank/invoice) shown after a subscription is recorded.', 'Checked once at adherents/subscription.php:1036; when set, the block offering bank or invoice actions after subscription creation is suppressed, even if the bank or invoice modules are enabled. No admin UI is provided.', 'Enabling this constant removes the complementary action prompts from the subscription workflow, streamlining the interface.', 'Non-empty/truthy = complementary actions hidden; empty/unset = complementary actions shown when bank or invoice module is active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:1036|check|if ((isModEnabled(''bank'') || isModEnabled(''invoice'')) && !getDolGlobalString(''ADHERENT_SUBSCRIPTION_HIDECOMPLEMENTARYACTIONS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_USE_MAILMAN', 'bool', NULL, 'adherents', 'Enables Mailman mailing list synchronization for member subscription and unsubscription events.', 'When set and the mailman/mailmanspip module is enabled, member subscribe/unsubscribe actions trigger Mailman list synchronization calls. Configured via admin/mailman.php.', 'Enabling this causes member events (subscribe, unsubscribe) to be forwarded to configured Mailman lists. Disabling it suppresses Mailman integration entirely.', 'Truthy = Mailman synchronization enabled; empty/falsy = disabled', 0, 0, 'admin/mailman.php|admin/mailman.php|admin/mailman.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:2348|check|if (getDolGlobalString(''ADHERENT_USE_MAILMAN'') && isModEnabled(''mailmanspip'')) {", "admin/mailman.php:106|check|if (($action == ''testsubscribe'' || $action == ''testunsubscribe'') && getDolGlobalString(''ADHERENT_USE_MAILMAN'')) {", "adherents/class/adherent.class.php:2400|check|if (getDolGlobalString(''ADHERENT_USE_MAILMAN'')) {", "adherents/card.php:1733|check|if (isModEnabled(''mailman'') && getDolGlobalString(''ADHERENT_USE_MAILMAN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_USE_SPIP', 'bool', NULL, 'adherents', 'Enables integration between the Members (adherents) module and the SPIP CMS/Mailman system.', 'Configured via admin/spip.php. When enabled, member card actions and the adherent class trigger synchronization with the Mailman/SPIP subsystem (adherents/class/adherent.class.php lines 2368 and 2419, adherents/card.php lines 1736 and 2191).', 'When set, member subscription and unsubscription events trigger calls into the mailmanspip module, propagating changes to external mailing-list or SPIP services.', 'Truthy (non-empty) value enables the integration; empty/unset disables it.', 0, 0, 'admin/spip.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/spip.php:128|check|if (getDolGlobalString(''ADHERENT_USE_SPIP'')) {", "adherents/class/adherent.class.php:2368|check|if (getDolGlobalString(''ADHERENT_USE_SPIP'') && isModEnabled(''mailmanspip'')) {", "adherents/card.php:2191|check|if (isModEnabled(''mailmanspip'') && getDolGlobalString(''ADHERENT_USE_SPIP'')) {", "mailmanspip/class/mailmanspip.class.php:96|check|if (getDolGlobalInt(\"ADHERENT_USE_SPIP\") == 1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ADHERENT_VAT_FOR_SUBSCRIPTIONS', 'string', NULL, 'adherents', 'Controls whether VAT is applied to member subscription invoices and which VAT rate is used.', 'When set to ''defaultforfoundationcountry'', VAT is applied using the default rate for the foundation''s country. Any other value (including empty or ''0'') results in no VAT on subscriptions. Configured via adherents/admin/member.php.', 'Setting this to ''defaultforfoundationcountry'' adds VAT to subscription invoice lines. Any other value suppresses VAT on subscriptions.', '''0'' = NoVatOnSubscription; ''defaultforfoundationcountry'' = use default VAT for foundation country', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:2072|check|if (getDolGlobalString(''ADHERENT_VAT_FOR_SUBSCRIPTIONS'') == ''defaultforfoundationcountry'') {", "adherents/subscription.php:1071|check|if (!getDolGlobalString(''ADHERENT_VAT_FOR_SUBSCRIPTIONS'') || getDolGlobalString(''ADHERENT_VAT_FOR_SUBSCRIPTIONS'') != ''defaultforfoundationcountry'') {", "adherents/admin/member.php:649|read|print $form->selectarray(''ADHERENT_VAT_FOR_SUBSCRIPTIONS'', array(''0'' => $langs->trans(\"NoVatOnSubscription\"), ''defaultforfoundationcountry'' => $langs->trans(\"Default\")), ..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_ADDACTIONFOREMAIL', 'string', NULL, 'core', 'Enables automatic creation of an agenda action event when an email is sent from Dolibarr.', 'Checked in core/lib/functions.lib.php:4500; a commented-out example at line 4454 shows how to set it. The function parameter doc at line 4443 describes its role: ''link to create action if constant AGENDA_ADDACTIONFOREMAIL is on''.', 'When set, sending an email from a presend form triggers an agenda event to be created. Without it, no agenda entry is created.', 'email has a html email link (+ link to create action if constant AGENDA_ADDACTIONFOREMAIL is on). Non-empty = create agenda action on email send; absent/empty = no agenda entry.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:4443  * @param \tint|string\t$addlink\t\t0=no link, 1=email has a html email link (+ link to create action if constant AGENDA_ADDACTIONFOREMAIL is on), ''thirdparty''=link to the thirdparty presend email", "core/lib/functions.lib.php:4454  //global $conf; $conf->global->AGENDA_ADDACTIONFOREMAIL = 1;", "core/lib/functions.lib.php:4500|check|if (getDolGlobalString(''AGENDA_ADDACTIONFOREMAIL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_ADDACTIONFORPHONE', 'string', NULL, 'core', 'Enables a link to create an agenda event when a phone number is clicked via the Click-to-Dial or phone link mechanism.', 'Checked in core/lib/functions.lib.php:5109. The function parameter doc at line 4827 describes its role: ''add link to create event (if conf->global->AGENDA_ADDACTIONFORPHONE set)''. No admin UI write detected.', 'When set, phone number display includes a link to create an agenda event. Without it, no agenda entry link is shown alongside phone numbers.', '''AC_TEL''=add link to clicktodial (if module enabled) and add link to create event (if conf->global->AGENDA_ADDACTIONFORPHONE set). Non-empty = show agenda event link; absent/empty = no link.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:4827  * \t@param \tstring\t$addlink\t    ''''=no link to create action, ''AC_TEL''=add link to clicktodial (if module enabled) and add link to create event (if conf->global->AGENDA_ADDACTIONFORPHONE set), ''tel''=Force \"tel:...\" link", "core/lib/functions.lib.php:5109|check|if (getDolGlobalString(''AGENDA_ADDACTIONFORPHONE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_ADDACTIONFORSKYPE', 'string', NULL, 'core', 'Enables automatic creation of an agenda action event when a Skype call link is used.', 'Checked in core/lib/functions.lib.php:4704. No admin UI write detected.', 'When set, using a Skype call link triggers creation of an agenda event. Without it, no agenda entry is created for Skype interactions.', 'Non-empty = create agenda action for Skype; absent/empty = no agenda entry.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:4704|check|if (getDolGlobalString(''AGENDA_ADDACTIONFORSKYPE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_ALL_CALENDARS', 'string', NULL, 'comm', 'Controls whether the agenda defaults to showing all calendars without a filter type restriction.', 'Checked in comm/action/pertype.php:63, comm/action/list.php:133, and comm/action/index.php:72 to skip defaulting the filter type when no explicit filter is set.', 'Enabling this constant causes all event types to be displayed by default on agenda views without pre-filtering by type.', 'Truthy value = all calendars shown by default; empty/unset = default filter type applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/pertype.php:63|check|if (empty($filtert) && !getDolGlobalString(''AGENDA_ALL_CALENDARS'')) {", "comm/action/list.php:133|check|if (empty($filtert) && !getDolGlobalString(''AGENDA_ALL_CALENDARS'')) {", "comm/action/index.php:72|check|if (empty($filtert) && !getDolGlobalString(''AGENDA_ALL_CALENDARS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_ALWAYS_HIDE_AUTO', 'bool', NULL, 'comm', 'Hides automatically-generated agenda events (type ''AC_OTH_AUTO'') from all agenda views.', 'Checked in comm/action/pertype.php:700, comm/action/peruser.php:877, comm/action/list.php:1030, comm/action/index.php:948, and core/class/html.formactions.class.php:398; skips rendering when the event type code is ''AC_OTH_AUTO''.', 'Enabling this constant removes auto-generated events from display in all agenda views and event type selector lists.', 'Truthy value = auto events hidden; empty/unset = auto events visible.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/pertype.php:700|check|if (getDolGlobalString(''AGENDA_ALWAYS_HIDE_AUTO'') && $obj->type_code == ''AC_OTH_AUTO'') {", "comm/action/peruser.php:877|check|if (getDolGlobalString(''AGENDA_ALWAYS_HIDE_AUTO'') && $obj->type_code == ''AC_OTH_AUTO'') {", "comm/action/list.php:1030|check|if (getDolGlobalString(''AGENDA_ALWAYS_HIDE_AUTO'') && $obj->type_code == ''AC_OTH_AUTO'') {", "core/class/html.formactions.class.php:398|check|if (array_key_exists(''AC_OTH_AUTO'', $arraylist) && getDolGlobalString(''AGENDA_ALWAYS_HIDE_AUTO'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_AUTOSET_END_DATE_WITH_DELTA_HOURS', 'string', NULL, 'comm', 'Sets the number of hours added to the start date to auto-compute the end date of a new agenda event.', 'Read as an integer in comm/action/card.php:1513 with a default of 1 hour. The computed end date is stored in $datef.', 'Changing this value changes how far into the future the default event end time is set relative to the start time.', 'Integer number of hours (default 1); 0 = end date same as start date.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/card.php:1513|read|$datef = dol_time_plus_duree($datep, getDolGlobalInt(''AGENDA_AUTOSET_END_DATE_WITH_DELTA_HOURS'', 1), ''h'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_BEGIN_TIME', 'string', NULL, 'comm', 'Sets the default begin time (as a time string) pre-filled when creating a new agenda event.', 'Read in comm/action/index.php:1965 as getDolGlobalString(''AGENDA_DEFAULT_BEGIN_TIME'') and assigned to $hourminsec.', 'Setting this constant pre-populates the start time field when creating agenda events; leaving it unset lets the UI use its own default.', 'Time string (e.g. ''HH:MM:SS'' or similar format); empty/unset = no default', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["$hourminsec = getDolGlobalString(''AGENDA_DEFAULT_BEGIN_TIME'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_FILTER_STATUS', 'string', NULL, 'comm', 'Sets the default event status filter applied to agenda views.', 'Written in admin/agenda_other.php:99 and admin/agenda_reminder.php:89; read in comm/action/pertype.php:158, comm/action/peruser.php:163, comm/action/list.php:110, and comm/action/index.php:149 to pre-select the status filter.', 'Changing this constant alters which event status is pre-selected as the default filter across all agenda listing views.', 'String status code; empty/unset = no default status filter.', 0, 0, 'admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda_other.php:99|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_FILTER_STATUS'', GETPOST(''AGENDA_DEFAULT_FILTER_STATUS''), ''chaine'', 0, '''', $conf->entity);", "admin/agenda_reminder.php:89|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_FILTER_STATUS'', GETPOST(''AGENDA_DEFAULT_FILTER_STATUS''), ''chaine'', 0, '''', $conf->entity);", "comm/action/pertype.php:158|read|$status = ((!getDolGlobalString(''AGENDA_DEFAULT_FILTER_STATUS'') || $disabledefaultvalues) ? '''' : getDolGlobalString(''AGENDA_DEFAULT_FILTER_STATUS''));", "comm/action/list.php:110|read|$search_status = ((!getDolGlobalString(''AGENDA_DEFAULT_FILTER_STATUS'') || $disabledefaultvalues) ? '''' : $conf->global->AGENDA_DEFAULT_FILTER_STATUS);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_FILTER_TYPE', 'string', NULL, 'comm', 'Sets the default event type filter applied to agenda views.', 'Written in admin/agenda_other.php:98 and admin/agenda_reminder.php:88; read in comm/action views to pre-select the action type filter. A commented module default of ''AC_NON_AUTO'' is noted in core/modules/modAgenda.class.php:93.', 'Changing this constant alters which event type is pre-selected as the default filter on all agenda listing views.', 'String action code (e.g. ''AC_NON_AUTO''); empty/unset = no default type filter.', 0, 0, 'admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/modAgenda.class.php:93  // $this->const[] = array(''AGENDA_DEFAULT_FILTER_TYPE'', ''chaine'', ''AC_NON_AUTO'', ''Default filter for type of event on agenda'', 0, ''current'');", "admin/agenda_other.php:98|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_FILTER_TYPE'', $defaultfilter, ''chaine'', 0, '''', $conf->entity);", "admin/agenda_reminder.php:88|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_FILTER_TYPE'', GETPOST(''AGENDA_DEFAULT_FILTER_TYPE''), ''chaine'', 0, '''', $conf->entity);", "admin/agenda_other.php:413|read|print $formactions->select_type_actions(getDolGlobalString(''AGENDA_DEFAULT_FILTER_TYPE''), \"AGENDA_DEFAULT_FILTER_TYPE\", '''', (getDolGlobalString(''AGENDA_USE_EVENT_TYPE'') ? -1 : 1),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_FILTER_TYPE_FOR_OBJECT', 'string', NULL, 'hrm', 'Sets the default event/action type filter pre-selected on agenda tabs of object detail pages.', 'Read in 52 locations across object agenda pages (e.g. asset/model/agenda.php:58, partnership/partnership_agenda.php:61, projet/agenda.php:72) as the fallback value for the ''actioncode'' filter when no POST parameter is provided.', 'Setting this constant pre-filters the agenda tab by a specific action code on every object detail page that displays an agenda; clearing it shows all event types by default.', 'Action code string (e.g. ''AC_TEL''); empty string or unset = no type filter applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asset/model/agenda.php:58|read|$actioncode = GETPOST(\"actioncode\", \"alpha\", 3) ? GETPOST(\"actioncode\", \"alpha\", 3) : (GETPOST(\"actioncode\") == ''0'' ? ''0'' : getDolGlobalString(''AGENDA_DEFAULT_FILTER_TYPE_FOR_OBJEC", "partnership/partnership_agenda.php:61|read|$actioncode = GETPOST(\"actioncode\", \"alpha\", 3) ? GETPOST(\"actioncode\", \"alpha\", 3) : (GETPOST(\"actioncode\") == ''0'' ? ''0'' : getDolGlobalString(''AGENDA_DEFAULT_FILTER_TYPE_FOR_OBJEC", "compta/facture/messaging.php:60|read|$actioncode = GETPOST(\"actioncode\", \"alpha\", 3) ? GETPOST(\"actioncode\", \"alpha\", 3) : (GETPOST(\"actioncode\") == ''0'' ? ''0'' : getDolGlobalString(''AGENDA_DEFAULT_FILTER_TYPE_FOR_OBJEC"]', 'high', NULL);
