INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_REMINDER_EMAIL_MODEL', 'string', NULL, 'comm', 'Stores the ID of the default email template used for agenda event reminders.', 'Written via admin/agenda_reminder.php:93 from the POST field ''AGENDA_DEFAULT_REMINDER_EMAIL_MODELmodel_mail''. Read in comm/action/card.php lines 1955 and 2576.', 'Changing this value changes which email template is pre-selected for reminders on new events.', 'Integer ID of an email template; 0 or unset = no default email template.', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/agenda_reminder.php:93|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_REMINDER_EMAIL_MODEL'', GETPOSTINT(''AGENDA_DEFAULT_REMINDER_EMAIL_MODELmodel_mail''), ''chaine'', 0, '''', $conf->entity);", "comm/action/card.php:1955|read|$reminderDefaultEmailModel = getDolGlobalInt(''AGENDA_DEFAULT_REMINDER_EMAIL_MODEL'');", "comm/action/card.php:2576|read|$reminderDefaultEmailModel = getDolGlobalString(''AGENDA_DEFAULT_REMINDER_EMAIL_MODEL'');"]', 'high', NULL);
