INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_REMINDER_OFFSET', 'string', NULL, 'comm', 'Sets the global default reminder offset (numeric value) applied to new agenda event reminders.', 'Written via admin/agenda_reminder.php:91 and read in comm/action/card.php lines 1953 and 2574 with a default of 30. This is the system-level default; AGENDA_REMINDER_DEFAULT_OFFSET is the per-session override.', 'Changing this value changes the pre-filled reminder offset for all new events globally; individual events can still override it.', 'Integer (default 30); unit determined by AGENDA_DEFAULT_REMINDER_OFFSET_UNIT.', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/agenda_reminder.php:91|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_REMINDER_OFFSET'', GETPOSTINT(''AGENDA_DEFAULT_REMINDER_OFFSET''), ''chaine'', 0, '''', $conf->entity);", "comm/action/card.php:1953|read|$reminderDefaultOffset = getDolGlobalInt(''AGENDA_DEFAULT_REMINDER_OFFSET'', 30);", "comm/action/card.php:2574|read|$reminderDefaultOffset = getDolGlobalString(''AGENDA_DEFAULT_REMINDER_OFFSET'', 30);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_REMINDER_OFFSET_UNIT', 'string', NULL, 'comm', 'Stores the time unit for the global default reminder offset (e.g. minutes, hours).', 'Written via admin/agenda_reminder.php:92 from the POST field ''AGENDA_DEFAULT_REMINDER_OFFSET_UNIT_type_duration''. Read in comm/action/card.php lines 1954 and 2575.', 'Changing this value changes the unit applied to the default reminder offset for all new events.', 'String time-unit identifier (e.g. ''m'' for minutes, ''h'' for hours); empty/unset = no default unit.', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/agenda_reminder.php:92|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_REMINDER_OFFSET_UNIT'', GETPOST(''AGENDA_DEFAULT_REMINDER_OFFSET_UNIT_type_duration''), ''chaine'', 0, '''', $conf->entity);", "comm/action/card.php:1954|read|$reminderDefaultUnit = getDolGlobalString(''AGENDA_DEFAULT_REMINDER_OFFSET_UNIT'');", "comm/action/card.php:2575|read|$reminderDefaultUnit = getDolGlobalString(''AGENDA_DEFAULT_REMINDER_OFFSET_UNIT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DEFAULT_VIEW', 'string', NULL, 'comm', 'Sets the default calendar view mode (e.g. month, list, per-user, per-type) on the agenda.', 'Written in admin/agenda_other.php:100 and admin/agenda_reminder.php:90; read in comm/action/index.php:152 (default ''show_month''), comm/action/list.php:113 (default ''show_list''), comm/action/pertype.php:161, and comm/action/peruser.php:167.', 'Changing this constant determines which calendar view is displayed by default when a user first opens the agenda.', 'String view name: ''show_month'', ''show_list'', ''show_pertype'', ''show_peruser'', or other supported view identifiers.', 0, 0, 'admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda_other.php:100|write|dolibarr_set_const($db, ''AGENDA_DEFAULT_VIEW'', GETPOST(''AGENDA_DEFAULT_VIEW''), ''chaine'', 0, '''', $conf->entity);", "comm/action/index.php:152|read|$defaultview = getDolGlobalString(''AGENDA_DEFAULT_VIEW'', ''show_month'');\t// default for app", "comm/action/list.php:113|read|$mode = getDolGlobalString(''AGENDA_DEFAULT_VIEW'', ''show_list'');", "user/param_ihm.php:452  // Landing page for Agenda - AGENDA_DEFAULT_VIEW"]', 'high', NULL);
