INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_DISABLE_EXACT_USER_EMAIL_COMPARE_FOR_EXTERNAL_CALENDAR', 'bool', NULL, 'user', 'Disables exact email-address matching when linking users to external calendar events.', 'Referenced in a docblock at user/class/user.class.php:4381 and checked at :4397; when set, the exact email comparison for external calendar user matching is bypassed.', 'Enabling this constant relaxes user-matching logic for external calendars, which may allow looser associations; disabling it enforces exact email comparison.', 'Empty/unset = exact email comparison enforced; any truthy value = exact email comparison disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/user.class.php:4381  * Use AGENDA_DISABLE_EXACT_USER_EMAIL_COMPARE_FOR_EXTERNAL_CALENDAR", "user/class/user.class.php:4397|check|if (getDolGlobalString(''AGENDA_DISABLE_EXACT_USER_EMAIL_COMPARE_FOR_EXTERNAL_CALENDAR'')) {"]', 'low', NULL);
