INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_EXPORT_FIX_TZ', 'string', NULL, 'comm', 'Applies a timezone offset correction (in hours) to event timestamps during iCal/xCal export.', 'Written in admin/agenda_xcal.php:83; read as a signed integer offset in comm/action/class/actioncomm.class.php at lines 2368 and 2372 (start/end dates), 2406-2407 (created/modified), and 2482 (timestamp adjustment).', 'Setting this constant shifts all exported event timestamps by the specified number of hours, correcting timezone discrepancies in iCal exports.', 'Integer number of hours (positive or negative) subtracted from event timestamps during export; empty/unset = no correction applied.', 0, 0, 'admin/agenda_xcal.php|admin/agenda_xcal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda_xcal.php:83|write|$i += dolibarr_set_const($db, ''AGENDA_EXPORT_FIX_TZ'', $AGENDA_EXPORT_FIX_TZ, ''chaine'', 0, '''', $conf->entity);", "comm/action/class/actioncomm.class.php:2368|read|$datestart = (int) $this->db->jdate($obj->datep) - (getDolGlobalInt(''AGENDA_EXPORT_FIX_TZ'') * 3600);", "comm/action/class/actioncomm.class.php:2372|read|$dateend = (int) $this->db->jdate($obj->datep2) - (getDolGlobalInt(''AGENDA_EXPORT_FIX_TZ'') * 3600);", "comm/action/class/actioncomm.class.php:2482|read|$timestampStart -= ($conf->global->AGENDA_EXPORT_FIX_TZ * 3600);"]', 'high', NULL);
