INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_MAX_EVENTS_ON_PAGE_WITHOUT_PAGINATION', 'string', NULL, 'core', 'Sets the maximum number of agenda events displayed on a page before pagination is applied, defaulting to 100.', 'Read with getDolGlobalInt at core/lib/company.lib.php:2155 and core/lib/functions.lib.php:16607, both using a default of 100. No comment is present in the payload.', 'Increasing the value allows more events per page without pagination; decreasing it triggers pagination sooner, which may improve rendering performance for busy calendars.', 'Integer; default is 100 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:2155|read|$MAXWITHOUTPAGINATION = getDolGlobalInt(''AGENDA_MAX_EVENTS_ON_PAGE_WITHOUT_PAGINATION'', 100);", "core/lib/functions.lib.php:16607|read|$MAXWITHOUTPAGINATION = getDolGlobalInt(''AGENDA_MAX_EVENTS_ON_PAGE_WITHOUT_PAGINATION'', 100);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_NB_WEEKS_IN_VIEW_PER_USER', 'string', NULL, 'comm', 'Sets the number of weeks displayed in the per-user agenda week view.', 'Read in comm/action/peruser.php:416; the value is multiplied by 7 to get the number of days to show, with a default of 7 days (1 week) when unset.', 'Changing this constant adjusts the date range visible in the per-user agenda view.', 'Integer number of weeks; empty/unset = 1 week (7 days) shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/peruser.php:416|read|$nb_weeks_to_show = (getDolGlobalString(''AGENDA_NB_WEEKS_IN_VIEW_PER_USER'')) ? ((int) $conf->global->AGENDA_NB_WEEKS_IN_VIEW_PER_USER * 7) : 7;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_NOTIFICATION_METHOD', 'string', NULL, 'core', 'Specifies the JavaScript notification method used for agenda reminders in the browser (default ''jnotify'').', 'Read in core/js/lib_notification.js.php:81 and :123. The value is resolved first from user preference via getDolUserString, falling back to getDolGlobalString with a hardcoded default of ''jnotify''.', 'Changing this constant alters the global default notification method for all users who have not set a personal preference.', 'String identifying the notification method; default is ''jnotify''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["var methodfornotification = ''<?php print getDolUserString(''AGENDA_NOTIFICATION_METHOD'', getDolGlobalString(''AGENDA_NOTIFICATION_METHOD'', ''jnotify'')); ?>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_NO_TRANSPARENT_ON_NOT_BUSY', 'string', NULL, 'comm', 'Disables the transparent/opacity rendering of non-busy agenda events in calendar views.', 'Checked in comm/action/index.php:2202 and comm/action/peruser.php at lines 2344, 2361, 2378, 2395, and comm/action/pertype.php at lines 1253 and 1270 to suppress the ''opacitymedium'' CSS class.', 'Enabling this constant prevents non-busy events from being rendered with reduced opacity, making all events appear at full opacity regardless of busy status.', 'Truthy value = no transparency on non-busy events; empty/unset = non-busy events rendered with reduced opacity.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/index.php:2198  //if (empty($event->transparency) && empty($conf->global->AGENDA_NO_TRANSPARENT_ON_NOT_BUSY)) print '' opacitymedium'';\t// Not busy", "comm/action/index.php:2202|check|if (empty($event->transparency) && !getDolGlobalString(''AGENDA_NO_TRANSPARENT_ON_NOT_BUSY'')) {", "comm/action/pertype.php:1253|check|if (!getDolGlobalString(''AGENDA_NO_TRANSPARENT_ON_NOT_BUSY'')) {", "comm/action/peruser.php:2344|check|if (!empty($ev[''busy'']) && !getDolGlobalString(''AGENDA_NO_TRANSPARENT_ON_NOT_BUSY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_REMINDER_BROWSER', 'string', NULL, 'comm', 'Enables browser-based push reminders for agenda events.', 'Checked across admin/agenda_reminder.php (lines 197, 275, 298), main.inc.php:2063, comm/action/class/actioncomm.class.php:2704, and comm/action/card.php:165 and :168 to enable or disable the browser reminder feature and its UI controls.', 'Enabling this activates browser push notification reminders for agenda events; disabling it suppresses the browser reminder feature and its UI.', '0 or unset = browser reminders disabled; 1 (truthy) = browser reminders enabled', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2063|check|if (isModEnabled(''agenda'') && getDolGlobalString(''AGENDA_REMINDER_BROWSER'')) {", "admin/agenda_reminder.php:197|check|if (!getDolGlobalString(''AGENDA_REMINDER_BROWSER'')) {", "comm/action/card.php:168|read|''disabled'' => (getDolGlobalString(''AGENDA_REMINDER_BROWSER'') ? 0 : 1),", "comm/action/class/actioncomm.class.php:2704|check|if (!getDolGlobalString(''AGENDA_REMINDER_BROWSER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_REMINDER_BROWSER_SOUND', 'string', NULL, 'core', 'Enables a browser sound when an agenda reminder notification fires.', 'Checked in core/js/lib_notification.js.php:158. The value is resolved first from user preference via getDolUserString, falling back to getDolGlobalString.', 'Setting this constant (or the user-level preference) causes a sound to play on browser reminder notifications; leaving it empty suppresses sound.', 'Any non-empty value = play sound on reminder; empty/unset = no sound', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolUserString(''AGENDA_REMINDER_BROWSER_SOUND'', getDolGlobalString(''AGENDA_REMINDER_BROWSER_SOUND''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_REMINDER_DEFAULT_OFFSET', 'string', NULL, 'comm', 'Sets the default reminder offset value pre-filled when adding a reminder to an agenda event.', 'Read in comm/action/card.php at lines 1932 and 2508 with a default of 30. Used to pre-populate the offset input field and to set the reminder''s offsetvalue property.', 'Changing this value changes the numeric reminder offset shown by default; users can still override it per event.', 'Integer (default 30); unit determined by AGENDA_DEFAULT_REMINDER_OFFSET_UNIT.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/card.php:1932|read|print ''<input class=\"width50\" type=\"number\" name=\"offsetvalue\" value=\"''.(GETPOSTISSET(''offsetvalue'') ? GETPOSTINT(''offsetvalue'') : getDolGlobalInt(''AGENDA_REMINDER_DEFAULT_OFFSET'',", "comm/action/card.php:2508|read|$actionCommReminder->offsetvalue = getDolGlobalInt(''AGENDA_REMINDER_DEFAULT_OFFSET'', 30);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_REMINDER_EMAIL', 'string', NULL, 'comm', 'Enables the email reminder feature for agenda events.', 'Written in admin/agenda_reminder.php at lines 88 and 89; checked in admin/agenda_reminder.php at lines 213, 227, 275, 298, 316, and in comm/action/card.php at lines 1943 and 2544, and in comm/action/class/actioncomm.class.php:2701.', 'Enabling this constant activates email reminders for agenda events, allowing the system to send reminder emails before scheduled events.', 'Truthy value = email reminders enabled; empty/unset = email reminders disabled.', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda_reminder.php:275|check|if (getDolGlobalString(''AGENDA_REMINDER_BROWSER'') || getDolGlobalString(''AGENDA_REMINDER_EMAIL'') || getDolGlobalString(''AGENDA_REMINDER_SMS'')) {", "admin/agenda_reminder.php:316|check|if (getDolGlobalString(''AGENDA_REMINDER_EMAIL'')) {", "comm/action/card.php:1943|check|if (getDolGlobalString(''AGENDA_REMINDER_EMAIL'')) {", "comm/action/class/actioncomm.class.php:2701|check|if (!getDolGlobalString(''AGENDA_REMINDER_EMAIL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_REMINDER_SMS', 'string', NULL, 'admin', 'Enables SMS reminders for agenda events when set to a truthy value.', 'Controls whether the SMS reminder channel is active for agenda events. Checked in admin/agenda_reminder.php to conditionally display SMS reminder settings, and in comm/action/class/actioncomm.class.php and comm/action/card.php to conditionally enable SMS reminder functionality.', 'When unset or falsy, SMS reminders are disabled and not offered as an option. When set, SMS reminders are enabled and users can configure them for agenda events.', 'Truthy string (enabled) or empty/unset (disabled).', 0, 0, 'admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php|admin/agenda_reminder.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/agenda_reminder.php:251|check|if (getDolGlobalString(''AGENDA_REMINDER_SMS'')) {", "admin/agenda_reminder.php:265|check|if (!getDolGlobalString(''AGENDA_REMINDER_SMS'')) {", "comm/action/class/actioncomm.class.php:2935|check|if (!getDolGlobalString(''AGENDA_REMINDER_SMS'')) {", "comm/action/card.php:192|read|$enablereminders = getDolGlobalString(''AGENDA_REMINDER_EMAIL'') || getDolGlobalString(''AGENDA_REMINDER_BROWSER'') || getDolGlobalString(''AGENDA_REMINDER_SMS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_SHOWOWNERONLY_ONPERUSERVIEW', 'bool', NULL, 'comm', 'Restricts the per-user agenda view to show only events owned by the current user.', 'Checked in comm/action/peruser.php:1675 to filter events to the current user''s own events.', 'Enabling this constant prevents users from seeing other users'' events in the per-user calendar view.', 'Truthy value = show own events only; empty/unset = all accessible events shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/peruser.php:1675|check|if (getDolGlobalString(''AGENDA_SHOWOWNERONLY_ONPERUSERVIEW'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_SHOW_LINKED_OBJECT', 'bool', NULL, 'comm', 'Enables display of the linked object on agenda event cards in the month view.', 'Checked in comm/action/index.php:2356 when an event has a linked element; also controls the ''visible'' attribute of the fk_element field in comm/action/class/actioncomm.class.php:447.', 'Enabling this constant causes linked business objects (e.g. invoices, orders) to be shown on event tiles in the agenda.', 'Truthy value = linked object shown; empty/unset = linked object hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/index.php:2356|check|if (!empty($event->fk_element) && $event->fk_element > 0 && !empty($event->elementtype) && getDolGlobalString(''AGENDA_SHOW_LINKED_OBJECT'')) {", "comm/action/class/actioncomm.class.php:447|read|\"fk_element\" => array(\"type\" => \"integer\", \"label\" => \"LinkedObject\", \"enabled\" => \"getDolGlobalString(''AGENDA_SHOW_LINKED_OBJECT'')\", ''position'' => 145, ''notnull'' => 0, \"visible\" =>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_SHOW_PERTYPE', 'bool', NULL, 'core', 'When enabled, shows agenda events grouped or filtered per event type in the agenda view.', 'Checked in core/lib/agenda.lib.php:553; when set, a code path that displays events per type is activated. No admin UI page is listed.', 'Enabling this constant changes how agenda events are presented, activating per-type grouping or filtering.', '1 or any truthy value = show per type; 0 or unset = default view.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/agenda.lib.php:553|check|if (getDolGlobalString(''AGENDA_SHOW_PERTYPE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_SORT_EVENT_TYPE_BY_POSITION_FIRST', 'string', NULL, 'comm', 'Makes event type position the primary sort criterion in agenda event type lists.', 'Checked in comm/action/class/cactioncomm.class.php:188; the comment at line 186 states: ''If AGENDA_SORT_EVENT_TYPE_BY_POSITION_FIRST is defined, we use position as main sort criterion''. No admin UI; only one occurrence.', 'When set, event types are sorted by their position field first rather than by default ordering, changing the display order in agenda dropdowns.', 'Truthy string (sort by position first) or empty/unset (default sort order).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/class/cactioncomm.class.php:186  // If AGENDA_SORT_EVENT_TYPE_BY_POSITION_FIRST is defined, we use position as main sort criterion", "comm/action/class/cactioncomm.class.php:188|check|if (getDolGlobalString(''AGENDA_SORT_EVENT_TYPE_BY_POSITION_FIRST'')) {"]', 'medium', NULL);
