INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_USE_COLOR_PER_EVENT_TYPE', 'bool', NULL, 'comm', 'Enables color-coding of agenda events based on their event type.', 'Checked in comm/action/peruser.php at lines 1822 (combined with AGENDA_USE_EVENT_TYPE), 2010, and 2046; a commented note in comm/action/index.php:2053 reads: ''May be we need this: if (getDolGlobalString(AGENDA_USE_COLOR_PER_EVENT_TYPE))''.', 'Enabling this constant causes events in the per-user agenda view to be rendered with colors corresponding to their event type.', 'Truthy value = color-per-event-type enabled; empty/unset = no type-based coloring.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/peruser.php:1822|check|if (getDolGlobalString(''AGENDA_USE_EVENT_TYPE'') && getDolGlobalString(''AGENDA_USE_COLOR_PER_EVENT_TYPE'')) {", "comm/action/peruser.php:2010|check|if (getDolGlobalString(''AGENDA_USE_COLOR_PER_EVENT_TYPE'')) {", "comm/action/peruser.php:2046|check|if (getDolGlobalString(''AGENDA_USE_COLOR_PER_EVENT_TYPE'')) {", "comm/action/index.php:2053  /* May be we need this: if (getDolGlobalString(''AGENDA_USE_COLOR_PER_EVENT_TYPE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_USE_EVENT_TYPE', 'bool', NULL, 'comm', 'Enables the event type classification system on the agenda, showing event type selectors and type-based filtering.', 'Written and read in admin/agenda_other.php (lines 370, 377, 411, 413). Checked across 44 occurrences in multiple files including comm/action/pertype.php:566, comm/action/peruser.php:735, comm/action/list.php:495, and comm/action/document.php:235.', 'Enabling this constant activates event type classification across all agenda views, enabling type selectors, type-based filtering, and type display.', 'Truthy value = event type system enabled; empty/unset = event types not used.', 0, 0, 'admin/agenda_other.php|admin/agenda_other.php|admin/agenda_other.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda_other.php:369  //print ajax_constantonoff(''AGENDA_USE_EVENT_TYPE'');\tDo not use ajax here, we need to reload page to change other combo list", "admin/agenda_other.php:370|check|if (!getDolGlobalString(''AGENDA_USE_EVENT_TYPE'')) {", "comm/action/pertype.php:566|check|if (!getDolGlobalString(''AGENDA_USE_EVENT_TYPE'')) {", "comm/action/document.php:235|check|if (getDolGlobalString(''AGENDA_USE_EVENT_TYPE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_USE_EVENT_TYPE_DEFAULT', 'bool', NULL, 'admin', 'Sets the default event type code pre-selected when creating a new agenda event.', 'Written via admin/agenda_other.php and admin/agenda_reminder.php. Read in comm/action/card.php:1488 with fallback to ''AC_RDV''. When the value is empty or ''-1'', the type selector is not pre-filled (line 1512).', 'Changing this value alters the event type automatically selected on the new-event form, affecting data consistency for organisations that want all events to default to a specific type.', 'String event type code (e.g. ''AC_RDV''); ''-1'' or empty = no default pre-selection.', 0, 0, 'admin/agenda_other.php|admin/agenda_reminder.php|admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/card.php:1488|read|$default = getDolGlobalString(''AGENDA_USE_EVENT_TYPE_DEFAULT'', ''AC_RDV'');", "comm/action/card.php:1512|check|if (GETPOST(\"actioncode\", ''aZ09'') == ''AC_RDV'' || (!getDolGlobalString(''AGENDA_USE_EVENT_TYPE_DEFAULT'') || getDolGlobalString(''AGENDA_USE_EVENT_TYPE_DEFAULT'') == ''-1'')) {", "admin/agenda_other.php:97|write|dolibarr_set_const($db, ''AGENDA_USE_EVENT_TYPE_DEFAULT'', GETPOST(''AGENDA_USE_EVENT_TYPE_DEFAULT''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENDA_USE_MULTISELECT_TYPE', 'bool', NULL, 'core', 'Enables a multi-select event-type filter widget on agenda event lists when AGENDA_USE_EVENT_TYPE is also active.', 'Read at core/lib/company.lib.php:2327 inside select_type_actions; the third argument switches between single and multi-select mode based on this constant. No comment is present in the payload.', 'Enabling multi-select allows users to filter agenda events by multiple action types simultaneously; disabling it restricts filtering to a single type.', 'Any truthy value enables multi-select; unset uses single-select.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:2327|read|$out .= $formactions->select_type_actions($actioncode, \"actioncode\", '''', getDolGlobalString(''AGENDA_USE_EVENT_TYPE'') ? -1 : 1, 0, (getDolGlobalString(''AGENDA_USE_MULTISELECT_TYPE'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AGENT_CONTACT_TYPE', 'string', NULL, 'margin', 'Defines the contact type code used to identify sales agents linked to invoices in the margin agent report.', 'Written via margin/admin/margin.php at line 85 and read in margin/agentMargins.php at line 171 to build the SQL JOIN on element_contact; when unset the join uses -1 (no match). The admin UI at margin/admin/margin.php renders a contact-type selector.', 'Changing this alters which contact type is recognized as a sales agent, directly affecting which contacts appear in the agent margin report.', 'String: contact type code (e.g. internal contact type code); unset = no agent contact join (-1)', 0, 0, 'margin/admin/margin.php|margin/admin/margin.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["margin/admin/margin.php:85|write|if (dolibarr_set_const($db, ''AGENT_CONTACT_TYPE'', GETPOST(''AGENT_CONTACT_TYPE''), ''chaine'', 0, '''', $conf->entity) <= 0) {", "margin/agentMargins.php:171|read|$sql .= \" LEFT JOIN \".MAIN_DB_PREFIX.\"element_contact e ON e.element_id = f.rowid and e.statut = 4 and e.fk_c_type_contact = \".(!getDolGlobalString(''AGENT_CONTACT_TYPE'') ? -1 : $co", "margin/admin/margin.php:225|read|print $formcompany->selectTypeContact($facture, getDolGlobalString(''AGENT_CONTACT_TYPE''), \"AGENT_CONTACT_TYPE\", \"internal\", \"code\", 1, \"maxwidth250\");", "margin/agentMargins.php:179|check|if (getDolGlobalString(''AGENT_CONTACT_TYPE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_API_', 'string', NULL, 'ai', 'Family of dynamic constants (AI_API_<SERVICE>_KEY, _URL, _MODEL_*) holding credentials and endpoints for each configured AI provider.', 'These constants are assembled at runtime by concatenating ''AI_API_'' with the uppercased service name and a suffix (_KEY, _URL, _MODEL_TEXT, _MODEL_DOCPARSING, etc.) as seen in ai/class/ai.class.php:79,124,165,168. The comment in ai/admin/setup.php:87 notes that constants ending with _KEY are encrypted when saved to the database. Managed via ai/admin/server_mcp.php.', 'Setting the _KEY constant for a service provides the authentication credential; the _URL constant overrides the default endpoint; _MODEL_* constants select the AI model used for each function.', 'String values per suffix: _KEY = API authentication key (encrypted); _URL = API endpoint URL; _MODEL_TEXT = model name for text generation; _MODEL_DOCPARSING = model name for document parsing.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/setup.php:87  /*$item = $formSetup->newItem(''AI_API_''.strtoupper($ia).''_ENDPOINT'');  // Name of constant must end with _KEY so it is encrypted when saved into database.", "ai/class/ai.class.php:79|read|$this->apiKey = getDolGlobalString(''AI_API_''.strtoupper($this->apiService).''_KEY'');", "ai/class/ai.class.php:124|read|$this->apiEndpoint = getDolGlobalString(''AI_API_''.strtoupper($this->apiService).''_URL'', $arrayofai[$this->apiService][''url'']);", "ai/class/ai.class.php:165|read|$model = getDolGlobalString(''AI_API_''.strtoupper($this->apiService).''_MODEL_DOCPARSING'', $arrayofai[$this->apiService][$function][''default'']);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_API_CUSTOM_URL', 'string', NULL, 'ai', 'Specifies the API endpoint URL when the AI service is set to ''custom''.', 'Checked in ai/class/ai.class.php:116 — if the endpoint is still empty and the service is ''custom'' and this constant is unset, an error condition is triggered.', 'If the AI service is ''custom'' and this constant is not set, the AI module will fail to initialize the endpoint, preventing AI calls.', 'String: full URL of the custom AI API endpoint; must be set when AI_API_SERVICE = ''custom''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/class/ai.class.php:116|check|if (empty($this->apiEndpoint) && $this->apiService == ''custom'' && !getDolGlobalString(''AI_API_CUSTOM_URL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_API_SERVICE', 'string', NULL, 'ai', 'Selects the AI provider service (e.g. chatgpt) used by the Dolibarr AI module.', 'Determines which AI backend is instantiated in ai/class/ai.class.php:78. Defaults to ''chatgpt'' when unset. Configurable via ai/admin/setup.php and also used in ai/admin/custom_prompt.php and ai/admin/server_mcp.php.', 'Changing this value switches all AI-powered features to the specified provider; the corresponding API key and endpoint constants for that provider must also be set.', 'String identifier of the AI service, e.g. ''chatgpt'', ''custom''; empty/unset = defaults to ''chatgpt''.', 0, 0, 'ai/admin/custom_prompt.php|ai/admin/setup.php|ai/admin/setup.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/class/ai.class.php:78|read|$this->apiService = getDolGlobalString(''AI_API_SERVICE'', ''chatgpt'');", "ai/admin/custom_prompt.php:80|read|$aiservice = getDolGlobalString(''AI_API_SERVICE'', ''chatgpt'');", "ai/admin/server_mcp.php:301|read|$currentService = getDolGlobalString(''AI_API_SERVICE'');", "ai/admin/setup.php:238|check|if (getDolGlobalString(\"AI_API_SERVICE\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_ASK_FOR_CONFIRMATION', 'string', NULL, 'ai', 'Controls whether the AI MCP module prompts the user for confirmation before executing actions.', 'Written as an integer via ai/admin/server_mcp.php:69 and read at line 263 with a default of 1.', 'Setting to a truthy value enables confirmation prompts before AI-driven actions; setting to 0 disables them.', 'Integer: 1 (default) to ask for confirmation; 0 to skip confirmation.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:69|write|$res = dolibarr_set_const($db, \"AI_ASK_FOR_CONFIRMATION\", GETPOSTINT(\"AI_ASK_FOR_CONFIRMATION\"), ''int'', 0, '''', $conf->entity);", "ai/admin/server_mcp.php:263|read|print $form->selectarray(''AI_ASK_FOR_CONFIRMATION'', $confirmation_options, getDolGlobalInt(''AI_ASK_FOR_CONFIRMATION'', 1), 0, 0, 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_CONFIGURATIONS_PROMPT', 'string', NULL, 'ai', 'Stores the JSON-encoded configuration of custom AI prompts per function, managed via the AI admin UI.', 'Contains a JSON string of prompt configurations read and written by ai/admin/custom_prompt.php (lines 113, 150, 175, 197). At generation time, ai/class/ai.class.php:181 decodes this JSON to select the appropriate prompt.', 'Changing this value alters the system prompts sent to the AI for each configured function; clearing it resets to default built-in prompts.', 'JSON-encoded string of prompt configurations keyed by function; empty/unset = default prompts are used.', 0, 0, 'ai/admin/custom_prompt.php|ai/admin/custom_prompt.php|ai/admin/custom_prompt.php|ai/admin/custom_prompt.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/custom_prompt.php:113|read|$currentConfigurationsJson = getDolGlobalString(''AI_CONFIGURATIONS_PROMPT'');", "ai/admin/custom_prompt.php:150|write|$result = dolibarr_set_const($db, ''AI_CONFIGURATIONS_PROMPT'', $newConfigurationsJson, ''chaine'', 0, '''', $conf->entity);", "ai/class/ai.class.php:181|read|$configurationsJson = getDolGlobalString(''AI_CONFIGURATIONS_PROMPT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_DEBUG', 'string', NULL, 'ai', 'Enables debug logging for AI content generation calls.', 'When set, the AI class writes a dedicated log file dolibarr_ai.log each time generateContent() is called. Checked in ai/class/ai.class.php at lines 289, 339, and 400. The comment in ai/ajax/generate_content.php:89 describes the behaviour verbatim.', 'Enabling this constant creates verbose AI request/response logs; it should be disabled in production to avoid log bloat and potential data exposure.', 'Empty/unset = no AI debug log; truthy value = dolibarr_ai.log is written on each AI call.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/ajax/generate_content.php:89  // Note: The option AI_DEBUG will generate a log file dolibarr_ai.log when calling generateContent()", "ai/class/ai.class.php:289|check|if (getDolGlobalString(\"AI_DEBUG\")) {", "ai/class/ai.class.php:339|check|if (getDolGlobalString(\"AI_DEBUG\")) {", "ai/class/ai.class.php:400|check|if (getDolGlobalString(\"AI_DEBUG\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_DEFAULT_INPUT_MODE', 'string', NULL, 'ai', 'Sets the default input mode for AI interactions in the MCP module.', 'Written and read in ai/admin/server_mcp.php. The value is selected from an array of input modes via a dropdown in the AI admin UI.', 'Changing this value changes the default interaction mode presented to users of the AI MCP interface.', 'A string key from the available input_modes array, as configured in the AI admin UI.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:81|write|$res = dolibarr_set_const($db, \"AI_DEFAULT_INPUT_MODE\", GETPOST(\"AI_DEFAULT_INPUT_MODE\"), ''chaine'', 0, '''', $conf->entity);", "ai/admin/server_mcp.php:239|read|print $form->selectarray(''AI_DEFAULT_INPUT_MODE'', $input_modes, getDolGlobalString(''AI_DEFAULT_INPUT_MODE''), 0, 0, 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_INTENT_PROMPT', 'string', NULL, 'ai', 'Stores the custom intent prompt text used by the AI MCP module to interpret user requests.', 'Written via ai/admin/server_mcp.php:88 and read at line 203 with a fallback to a default prompt text.', 'Changing this value alters the system prompt sent to the AI for intent detection; clearing it reverts to the built-in default prompt.', 'A free-form string containing the intent detection prompt. Falls back to a default prompt if empty.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:203|read|$currentPrompt = getDolGlobalString(''AI_INTENT_PROMPT'', $defaultPromptText);", "ai/admin/server_mcp.php:88|write|$res = dolibarr_set_const($db, \"AI_INTENT_PROMPT\", GETPOST(\"AI_INTENT_PROMPT\"), ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_LOG_REQUESTS', 'string', NULL, 'ai', 'Controls whether AI module HTTP requests are logged.', 'Checked once in ai/lib/ai.lib.php:325 via getDolGlobalInt(''AI_LOG_REQUESTS''). When the value is falsy (0 or unset), the logging branch is skipped (if (!getDolGlobalInt(''AI_LOG_REQUESTS''))).', 'If set to a truthy integer, AI requests are logged. If unset or 0, request logging is suppressed.', 'Non-zero integer = logging enabled. 0 or unset = logging disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/lib/ai.lib.php:325|check|if (!getDolGlobalInt(''AI_LOG_REQUESTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_LOG_RETENTION', 'string', NULL, 'ai', 'Sets the number of days AI MCP interaction logs are retained (0 means forever).', 'Written as an integer via ai/admin/server_mcp.php:74 and read at line 278 with a default of 30. The UI shows ''(0 = Forever)''.', 'Increasing this value retains logs longer; setting to 0 keeps logs indefinitely.', 'Integer number of days to retain logs. 0 = Forever. Default: 30.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:74|write|$res = dolibarr_set_const($db, \"AI_LOG_RETENTION\", GETPOST(\"AI_LOG_RETENTION\"), ''int'', 0, '''', $conf->entity);", "ai/admin/server_mcp.php:278|read|print ''<td><input type=\"number\" name=\"AI_LOG_RETENTION\" value=\"'' . getDolGlobalInt(''AI_LOG_RETENTION'', 30) . ''\" size=\"5\"> (0 = Forever)</td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_MCP_API_KEY', 'string', NULL, 'ai', 'Stores the API key used to authenticate requests to the AI MCP (Model Context Protocol) server.', 'Read and written in ai/admin/server_mcp.php. The key is stored via dolibarr_set_const and retrieved with getDolGlobalString for use in MCP server authentication.', 'Changing or clearing this key will break authentication with the configured MCP server.', 'A secret API key string for MCP server authentication.', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:189|read|$apiKey = getDolGlobalString(''AI_MCP_API_KEY'');", "ai/admin/server_mcp.php:160|write|if (dolibarr_set_const($db, ''AI_MCP_API_KEY'', $newKey, ''chaine'', 0, '''', $conf->entity) > 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AI_MCP_USER_ID', 'string', NULL, 'ai', 'Stores the Dolibarr user ID used as the identity for AI MCP server operations.', 'Written as an integer via ai/admin/server_mcp.php:137 and displayed as a user selector at line 345.', 'Changing this value changes which Dolibarr user account the AI MCP server acts as when performing operations.', 'A valid Dolibarr user ID (integer).', 0, 0, 'ai/admin/server_mcp.php|ai/admin/server_mcp.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["ai/admin/server_mcp.php:137|write|$res = dolibarr_set_const($db, \"AI_MCP_USER_ID\", $user_id,  ''int'', 0, '''', $conf->entity);", "ai/admin/server_mcp.php:345|read|print $form->select_dolusers(getDolGlobalInt(''AI_MCP_USER_ID''), ''AI_MCP_USER_ID'', 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ALLOW_THEME_JS', 'bool', NULL, 'core', 'Allows loading of a theme-specific JavaScript file.', 'Checked at main.inc.php:2118 to conditionally include a theme JS file.', 'Enabling this loads theme-specific JavaScript; disabling or unsetting it skips that file.', '0 or unset = theme JS not loaded; 1 (truthy) = theme JS loaded', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2118|check|if (getDolGlobalString(''ALLOW_THEME_JS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ALLOW_USE_KITS_INTO_BOM_AND_MO', 'bool', NULL, 'mrp', 'Allows kit-type products (sub-products) to be used as components inside Bills of Materials and Manufacturing Orders.', 'Checked in mrp/class/mo.class.php at line 328. When PRODUIT_SOUSPRODUITS is enabled but this flag is absent, the code blocks MO creation for kit products.', 'Without this flag, kit products cannot be used as BOM components or MO products when the sub-products feature is active.', '0 or unset = kits not allowed in BOM/MO; 1 = kits allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''PRODUIT_SOUSPRODUITS'') && !getDolGlobalString(''ALLOW_USE_KITS_INTO_BOM_AND_MO'') && $this->fk_product > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_ALLOW_PASSWORD_RESET', 'bool', NULL, 'user', 'Enables the API endpoint that allows resetting user passwords via the REST API.', 'Checked in user/class/api_users.class.php at line 526. When not set, the password reset API call is refused. The code comment shows the expected usage: //$conf->global->API_ALLOW_PASSWORD_RESET = 1;', 'Setting this to 1 enables the password reset API endpoint; leaving it unset or setting it to 0 causes the API to refuse password reset requests.', '//$conf->global->API_ALLOW_PASSWORD_RESET = 1;', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/api_users.class.php:525  //$conf->global->API_ALLOW_PASSWORD_RESET = 1;", "user/class/api_users.class.php:526|check|if (!getDolGlobalString(''API_ALLOW_PASSWORD_RESET'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_CONTRAT_PUTLINE_OUTPUT_LINE_ONLY', 'string', NULL, 'contrat', 'When enabled, the contract API PUT line endpoint returns only the updated line object instead of the full contract.', 'Checked in contrat/class/api_contracts.class.php:502 to decide the response payload of the PUT line API endpoint. No admin UI write path is present in the payload.', 'Enabling this constant changes the API response of the contract PUT line endpoint to return only the line data. Leaving it unset causes the full contract object to be returned.', 'Truthy value to return line only; unset or 0 to return full contract.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/class/api_contracts.class.php:502|check|if (getDolGlobalInt(''API_CONTRAT_PUTLINE_OUTPUT_LINE_ONLY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_COUNTER_COUNT', 'string', NULL, 'api', 'Running count of API requests made since counting was enabled.', 'Read and incremented once in api/class/api_access.class.php:282 via dolibarr_set_const. No admin UI writes this constant; it is updated programmatically on each API call when API_COUNTER_ENABLED is set.', 'This value increases by 1 on each API call when counting is active; resetting it to 0 restarts the counter.', 'Integer: cumulative count of API requests.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_access.class.php:282|read|dolibarr_set_const($this->db, ''API_COUNTER_COUNT'', getDolGlobalInt(''API_COUNTER_COUNT'') + 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_COUNTER_ENABLED', 'bool', NULL, 'api', 'Enables counting of API requests via the API_COUNTER_COUNT constant.', 'Checked once in api/class/api_access.class.php:278. When true, the counter increment logic at line 282 runs. No admin UI writes this constant.', 'When enabled, every API call increments the API_COUNTER_COUNT constant; when disabled, no counting occurs.', 'Truthy (non-empty) to enable API request counting; empty/unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_access.class.php:278|check|if (getDolGlobalString(''API_COUNTER_ENABLED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_DISABLE_COMPRESSION', 'bool', NULL, 'api', 'Disables HTTP response compression for the Dolibarr REST API.', 'Set via api/admin/index.php and read at api/index.php:425. When set, compression is disabled and the response is output directly instead of using the compressed returnResponse handler. See comment: ''If API_DISABLE_COMPRESSION is set, returnResponse is false => It use default handling so output result directly.''', 'Disabling compression increases response size but removes the overhead of encoding; enabling compression (default) reduces bandwidth usage.', '0 or not set = compression enabled (if client accepts encoding); non-zero = compression disabled.', 0, 0, 'api/admin/index.php|api/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/index.php:424  // If API_DISABLE_COMPRESSION is set, returnResponse is false => It use default handling so output result directly.", "api/index.php:425|read|$usecompression = (!getDolGlobalString(''API_DISABLE_COMPRESSION'') && !empty($_SERVER[''HTTP_ACCEPT_ENCODING'']));", "api/admin/index.php:92|write|if (dolibarr_set_const($db, ''API_DISABLE_COMPRESSION'', GETPOSTINT(''status''), ''chaine'', 0, '''', 0) <= 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_DISABLE_LOGIN_API', 'bool', NULL, 'api', 'Disables the Dolibarr REST API login endpoint to prevent credential-based API authentication.', 'When enabled, the API login class and related endpoints reject requests at api/class/api_login.class.php:45 and api/index.php:289. Visible in admin/system/security.php:793 with a recommended value of 1.', 'Setting to 1 blocks all API authentication via the login endpoint; clients relying on token-based login via the API will fail. The admin security page marks 1 as the recommended value.', '0 = login API enabled (default); 1 = login API disabled (recommended for security)', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/security.php:793|print ''<strong>API_DISABLE_LOGIN_API</strong> = ''.getDolGlobalString(''API_DISABLE_LOGIN_API'', ''0'').'' &nbsp; <span class=\"opacitymedium\">(''.$langs->trans(\"Recommended\")''... (Recommended): 1)''", "api/class/api_login.class.php:44  //$conf->global->API_DISABLE_LOGIN_API = 1;", "api/class/api_login.class.php:45|check|if (getDolGlobalString(''API_DISABLE_LOGIN_API'')) {", "api/index.php:289|check|if ($file_searched == ''api_login.class.php'' && getDolGlobalString(''API_DISABLE_LOGIN_API'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_ENABLE_COUNT_CALLS', 'bool', NULL, 'api', 'Enables counting of successful API calls per user.', 'Set via api/admin/index.php and checked at api/index.php:475 and user/card.php:2164. When enabled (or when $dolibarr_api_count_always_enabled is set), API call counts are recorded for users with an API key on successful (HTTP 200) responses.', 'Enabling this constant activates API call tracking; disabling it stops counting unless the global variable $dolibarr_api_count_always_enabled overrides it.', '0 or not set = call counting disabled (unless overridden by global variable); non-zero = call counting enabled.', 0, 0, 'api/admin/index.php|api/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/index.php:475|check|if ((getDolGlobalInt(\"API_ENABLE_COUNT_CALLS\") || !empty($dolibarr_api_count_always_enabled)) && $api->r->responseCode == 200) {", "user/card.php:2164|check|if ($object->api_key && (getDolGlobalString(''API_ENABLE_COUNT_CALLS'') || !empty($dolibarr_api_count_always_enabled))) {", "api/admin/index.php:99|write|if (dolibarr_set_const($db, ''API_ENABLE_COUNT_CALLS'', GETPOSTINT(''status''), ''chaine'', 0, '''', 0) <= 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_ENDPOINT_RULES', 'string', NULL, 'api', 'Defines access rules for API endpoints as a comma-separated list of endpoint:flag pairs.', 'Displayed in admin/system/security.php:789 and processed in api/index.php:369-371. A COMMENT shows the expected format: ''$conf->global->API_ENDPOINT_RULES = "endpoint1:1,endpoint2:1,..."''. The value is exploded by comma and each entry parsed to enforce endpoint-level access control.', 'Setting this restricts or grants access to specific API endpoints; an empty or undefined value means no endpoint-level rules are applied.', '''endpoint1:1,endpoint2:1,...'' — comma-separated list of endpoint name and access flag pairs; empty = no endpoint rules', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/index.php:369  // $conf->global->API_ENDPOINT_RULES = ''endpoint1:1,endpoint2:1,...''", "api/index.php:370|check|if (getDolGlobalString(''API_ENDPOINT_RULES'')) {", "api/index.php:371|read|$listofendpoints = explode('','', getDolGlobalString(''API_ENDPOINT_RULES''));", "admin/system/security.php:789|read|print ''<strong>API_ENDPOINT_RULES</strong> = ''.getDolGlobalString(''API_ENDPOINT_RULES'', ...)"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_EXPLORER_DISABLED', 'bool', NULL, 'api', 'Disables the Dolibarr API explorer (Redoc UI) and related explorer endpoints.', 'Checked at api/admin/explorer_withredoc.php:49 to block access to the explorer UI, and at api/index.php:146 to block explorer URLs via pattern match. Configured in api/admin/explorer_withredoc.php (listed in ADMIN_UI).', 'When enabled, the API explorer UI is inaccessible and requests to explorer URLs are rejected; when disabled, the API explorer is available.', '0 or not set = API explorer accessible; non-zero = API explorer disabled.', 0, 0, 'api/admin/explorer_withredoc.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/admin/explorer_withredoc.php:49|check|if (getDolGlobalString(''API_EXPLORER_DISABLED'')) {", "api/index.php:146|check|if (preg_match(''/api\\/index\\.php\\/explorer/'', $url) && getDolGlobalString(''API_EXPLORER_DISABLED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_IN_TOKEN_TABLE', 'string', NULL, 'user', 'Enables use of the oauth_token database table for storing and validating API tokens instead of user profile tokens.', 'Checked in api/class/api_access.class.php (lines 137, 279), user/card.php (lines 1278, 2147, 2789), and core/lib/api.lib.php:44. The comment at user/card.php:2006 documents the purpose.', 'When enabled, API authentication uses the oauth_token table; when disabled, API tokens are managed via user profile fields.', 'Integer: 1 to enable oauth_token table for API tokens; 0 or unset to use the default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// API_IN_TOKEN_TABLE=1 to enable use of oaut_token table for API tokens", "api/class/api_access.class.php:279|check|if (!getDolGlobalString(''API_IN_TOKEN_TABLE'')) {", "core/lib/api.lib.php:44|check|if (getDolGlobalString(''API_IN_TOKEN_TABLE'')) {", "user/card.php:2147|check|if (getDolGlobalString(''API_IN_TOKEN_TABLE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_LOGINS_ALLOWED_FOR_CONST_READ', 'bool', NULL, 'api', 'Restricts the API endpoint for reading configuration constants to a specific user login.', 'Read at api/class/api_setup.class.php:2779 and :2813: ''&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ''))''. No admin UI write path is present.', 'When set, only the user whose login matches the value can access the const-read API endpoints; when empty, standard permission checks apply.', 'Empty/not set = standard permission check applies; login string = only this user login can access the const-read endpoints.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:2779|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ''))) {", "api/class/api_setup.class.php:2813|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_CONST_READ''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_LOGINS_ALLOWED_FOR_GET_COMPANY', 'bool', NULL, 'api', 'Restricts the API endpoint for retrieving company information to a specific user login.', 'Read at api/class/api_setup.class.php:2656: ''&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_COMPANY'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_COMPANY''))''. No admin UI write path is present.', 'When set, only the user whose login matches the value can access the get-company API endpoint; when empty, standard permission checks apply.', 'Empty/not set = standard permission check applies; login string = only this user login can access the get-company endpoint.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:2656|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_COMPANY'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_COMPANY''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_LOGINS_ALLOWED_FOR_GET_EXTRAFIELDS', 'bool', NULL, 'api', 'Restricts the API endpoint for retrieving extra fields to a specific user login.', 'Read at api/class/api_setup.class.php:1426: ''&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_EXTRAFIELDS'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_EXTRAFIELDS''))''. No admin UI write path is present.', 'When set, only the user whose login matches the value can access the get-extrafields API endpoint; when empty, standard permission checks apply.', 'Empty/not set = standard permission check applies; login string = only this user login can access the get-extrafields endpoint.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:1426|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_EXTRAFIELDS'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_EXTRAFIELDS''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_LOGINS_ALLOWED_FOR_GET_MODULES', 'bool', NULL, 'api', 'Restricts the API endpoint for listing modules to a specific user login.', 'Read at api/class/api_setup.class.php:3179, :3205, and :3305: ''&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES''))''. No admin UI write path is present.', 'When set, only the user whose login matches the value can access the get-modules API endpoints; when empty, standard permission checks apply.', 'Empty/not set = standard permission check applies; login string = only this user login can access the get-modules endpoints.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:3179|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES''))) {", "api/class/api_setup.class.php:3205|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES''))) {", "api/class/api_setup.class.php:3305|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_GET_MODULES''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_LOGINS_ALLOWED_FOR_INTEGRITY_CHECK', 'bool', NULL, 'api', 'Restricts the API integrity check endpoint to a specific user login.', 'Read at api/class/api_setup.class.php:2858: ''&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_INTEGRITY_CHECK'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_INTEGRITY_CHECK''))''. No admin UI write path is present.', 'When set, only the user whose login matches the value can invoke the API integrity check; when empty, standard permission checks apply.', 'Empty/not set = standard permission check applies; login string = only this user login can access the integrity check endpoint.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:2858|read|&& (!getDolGlobalString(''API_LOGINS_ALLOWED_FOR_INTEGRITY_CHECK'') || DolibarrApiAccess::$user->login != getDolGlobalString(''API_LOGINS_ALLOWED_FOR_INTEGRITY_CHECK''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_PRODUCTION_DO_NOT_ALWAYS_REFRESH_CACHE', 'string', NULL, 'api', 'Prevents the API from forcing a cache refresh on every request in production mode.', 'Only one occurrence in api/index.php:180. When not set (default), the API forces cache refresh ($refreshcache = true); when set, cache refresh is disabled ($refreshcache = false).', 'Setting this can improve API performance in production by reusing cached data, but stale cache entries will not be invalidated on each call.', 'Empty/0 = cache is always refreshed on API calls; truthy = cache refresh is suppressed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/index.php:180|read|$refreshcache = (getDolGlobalString(''API_PRODUCTION_DO_NOT_ALWAYS_REFRESH_CACHE'') ? false : true);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_PRODUCTION_MODE', 'string', NULL, 'api', 'Switches the REST API between production mode (strict) and development/debug mode.', 'Configured via api/admin/index.php (written at line 63, read at line 145). Also read in api/class/api.class.php:62 to set the $production_mode flag that controls API error verbosity.', 'When enabled, the API runs in production mode with reduced error detail; when disabled, more verbose debug information is returned.', 'Boolean string: truthy to enable production mode; falsy/unset for development mode.', 0, 0, 'api/admin/index.php|api/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/admin/index.php:63|write|if (dolibarr_set_const($db, ''API_PRODUCTION_MODE'', $status, ''chaine'', 0, '''', 0) > 0) {", "api/admin/index.php:145|read|$production_mode = getDolGlobalBool(''API_PRODUCTION_MODE'');", "api/class/api.class.php:62|read|$production_mode = getDolGlobalBool(''API_PRODUCTION_MODE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('API_RESTRICT_ON_IP', 'string', NULL, 'api', 'Restricts API access to a space-separated list of allowed IP addresses.', 'Configured via api/admin/index.php and checked at api/index.php:225 and api/admin/explorer_withredoc.php:58. When set, incoming requests are validated against the list; non-matching IPs are logged and denied. Value is split by space: ''$allowedip = explode('' '', getDolGlobalString(''API_RESTRICT_ON_IP''))''.', 'Setting a non-empty value blocks all API access from IPs not in the list; leaving it empty allows access from any IP.', 'Empty/not set = no IP restriction; space-separated IP addresses = only those IPs are allowed.', 0, 0, 'api/admin/index.php|api/admin/explorer_withredoc.php|api/admin/explorer_withredoc.php|api/admin/explorer_withredoc.php|api/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/admin/explorer_withredoc.php:59|read|$allowedip = explode('' '', getDolGlobalString(''API_RESTRICT_ON_IP''));", "api/index.php:226|read|$allowedip = explode('' '', getDolGlobalString(''API_RESTRICT_ON_IP''));", "api/index.php:229|read|dol_syslog(''Remote ip is ''.$ipremote.'', not into list '' . getDolGlobalString(''API_RESTRICT_ON_IP''));", "api/admin/index.php:105|write|if (dolibarr_set_const($db, ''API_RESTRICT_ON_IP'', GETPOST(''API_RESTRICT_ON_IP'', ''alpha'')) <= 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_ACCOUNTANCY_CATEGORY', 'string', NULL, 'core', 'Specifies the accounting plan category type used to filter accountancy accounts for asset lines.', 'Read twice in core/tpl/objectline_view.tpl.php:622 and :635 where it is used in a SQL WHERE clause to filter chart-of-accounts entries by pcg_type. No admin UI write was found; HIDDEN_GUESS is 1.', 'Changing this value alters which accountancy category is queried when resolving accountancy codes for asset object lines.', 'A string matching a valid pcg_type value from the chart of accounts', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_view.tpl.php:622|read|$accountancy_category_asset = getDolGlobalString(''ASSET_ACCOUNTANCY_CATEGORY'');", "core/tpl/objectline_view.tpl.php:635|read|$sql .= \" WHERE pcg_type = ''\" . $this->db->escape($conf->global->ASSET_ACCOUNTANCY_CATEGORY) . \"''\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_ADVANCED_MASK', 'string', NULL, 'core', 'Stores the numbering mask used by the Advanced asset numbering module.', 'Read in mod_asset_advanced.php at lines 85 (UI display of current mask) and 130 (mask retrieval for reference generation). No dolibarr_set_const write is present in the payload.', 'Changing this mask alters how new asset reference numbers are generated by the Advanced module.', 'A mask pattern string; empty = no mask.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_asset_advanced.php:85|read|value=''...getDolGlobalString(''ASSET_ADVANCED_MASK'')...", "mod_asset_advanced.php:130|read|$mask = getDolGlobalString(''ASSET_ADVANCED_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_ASSET_ADDON', 'string', NULL, 'asset', 'Specifies the numbering module class name used to generate asset reference numbers.', 'Read in asset/class/asset.class.php:1662 to determine the active numbering add-on. If not set, the default ''mod_asset_standard'' is applied (asset/class/asset.class.php:1655). The class name is also used to build the include file path.', 'Changing this constant selects a different numbering scheme for assets; an invalid class name will cause asset reference generation to fail.', 'String class name of a numbering module (e.g. ''mod_asset_standard'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["asset/class/asset.class.php:1654|check|if (!getDolGlobalString(''ASSET_ASSET_ADDON'')) {", "asset/class/asset.class.php:1655|write|$conf->global->ASSET_ASSET_ADDON = ''mod_asset_standard'';", "asset/class/asset.class.php:1661|read|$file = getDolGlobalString(''ASSET_ASSET_ADDON'') . \".php\";", "asset/class/asset.class.php:1662|read|$classname = getDolGlobalString(''ASSET_ASSET_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_ASSET_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) for ODT document templates used by the generic asset ODT module.', 'Read in doc_generic_asset_odt.modules.php at line 136 (split into list of dirs), line 164 (display in UI), and line 176 (existence check). No admin UI write via dolibarr_set_const is present in the payload.', 'Changing this path redirects the module to a different set of ODT template directories; an invalid path disables ODT template loading.', 'Comma-separated directory path(s); empty = no custom ODT path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["doc_generic_asset_odt.modules.php:136|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''ASSET_ASSET_ADDON_PDF_ODT_PATH''))));", "doc_generic_asset_odt.modules.php:164|read|$texte .= getDolGlobalString(''ASSET_ASSET_ADDON_PDF_ODT_PATH'');", "doc_generic_asset_odt.modules.php:176|check|if (getDolGlobalString(''ASSET_ASSET_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_DEPRECIATION_DURATION_PER_MONTH', 'string', NULL, 'asset', 'Sets the assumed number of days per month used in asset depreciation calculations.', 'Used in asset/class/asset.class.php:1100 to define the number of days per month when computing depreciation periods. Defaults to 30 if not set.', 'Changing this value alters the length of depreciation sub-periods. A value other than 30 changes how monthly depreciation amounts are distributed.', 'Integer number of days (default: 30)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["asset/class/asset.class.php:1100|read|$nb_days_in_month = getDolGlobalInt(''ASSET_DEPRECIATION_DURATION_PER_MONTH'', 30);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_DEPRECIATION_DURATION_PER_YEAR', 'string', NULL, 'asset', 'Number of days in a year used for asset depreciation duration calculations (default 360).', 'Read in asset/class/asset.class.php:1099 with a fallback default of 360 into $nb_days_in_year. No admin UI page is listed.', 'Changing this value alters the year-length assumption used in depreciation calculations; setting it to 365 switches from a financial 360-day year to a calendar year.', 'Integer number of days. Default fallback is 360.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["asset/class/asset.class.php:1099|read|$nb_days_in_year = getDolGlobalInt(''ASSET_DEPRECIATION_DURATION_PER_YEAR'', 360);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_DISPOSAL_VAT', 'string', NULL, 'accountancy', 'Specifies the default VAT rate percentage applied when disposing of assets in the accounting journal.', 'Read at accountancy/class/accountingjournal.class.php:613, where its integer value is used as the disposal VAT rate; if the value is 0 or less, the code falls back to 20. Only one occurrence is present in the payload.', 'Setting this constant overrides the default 20% VAT rate used during asset disposal journal entries.', 'Positive integer representing a VAT percentage (e.g. 20). Values <= 0 cause the code to fall back to 20.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/class/accountingjournal.class.php:613|read|$disposal_vat = getDolGlobalInt(''ASSET_DISPOSAL_VAT'') > 0 ? getDolGlobalInt(''ASSET_DISPOSAL_VAT'') : 20;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASSET_ROUND_INTEGER_NUMBER_UPWARDS', 'string', NULL, 'asset', 'Controls whether integer depreciation amounts are rounded upwards.', 'Checked in asset/class/asset.class.php:1156; when set to 1, rounding of depreciation integer values is done upward.', 'Setting to 1 rounds depreciation values upward, which may increase total depreciation amounts per period.', '1 = round upwards; 0 or unset = no upward rounding', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["asset/class/asset.class.php:1156|check|if (getDolGlobalInt(''ASSET_ROUND_INTEGER_NUMBER_UPWARDS'') == 1) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_CONTEXT', 'string', NULL, 'asterisk', 'Specifies the Asterisk dialplan context used when originating outbound calls.', 'Read in asterisk/wrapper.php:144 with a default of ''from-internal''.', 'Changing this value routes outbound calls through a different Asterisk dialplan context.', 'String: Asterisk dialplan context name. Defaults to ''from-internal'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:144|read|$strContext = getDolGlobalString(''ASTERISK_CONTEXT'', ''from-internal'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_HOST', 'string', NULL, 'asterisk', 'Specifies the hostname or IP address of the Asterisk AMI server for click-to-call integration.', 'Read in asterisk/wrapper.php:131 with a default of ''127.0.0.1''.', 'Changing this value redirects Asterisk AMI connections to the specified host.', 'String: hostname or IP address. Defaults to ''127.0.0.1'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:131|read|$strHost = getDolGlobalString(''ASTERISK_HOST'', ''127.0.0.1'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_INDICATIF', 'string', NULL, 'asterisk', 'Sets the country/area dialling prefix used by the Asterisk click-to-call wrapper when placing outbound calls.', 'Checked in asterisk/wrapper.php:115: if set to ''NONE'', the value is cleared to an empty string. Read at asterisk/wrapper.php:138 with a default of ''0''.', 'Setting this to ''NONE'' strips any prefix from dialled numbers; setting it to a string prepends that string as a dialling prefix; leaving it empty uses ''0'' as the default prefix.', '''NONE'' = no prefix used; any other string = used as dialling prefix; default ''0'' when empty.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:115|check|if (getDolGlobalString(''ASTERISK_INDICATIF'') == ''NONE'') {", "asterisk/wrapper.php:116|write|$conf->global->ASTERISK_INDICATIF = '''';", "asterisk/wrapper.php:138|read|$prefix = getDolGlobalString(''ASTERISK_INDICATIF'', ''0'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_MAX_RETRY', 'string', NULL, 'asterisk', 'Sets the maximum number of retry attempts for an Asterisk outbound call origination.', 'Read in asterisk/wrapper.php:153 with a default of ''2''.', 'Changing this value increases or decreases how many times the Asterisk AMI will retry a failed call origination.', 'String (integer): maximum retry count. Defaults to ''2'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:153|read|$strMaxRetry = getDolGlobalString(''ASTERISK_MAX_RETRY'', \"2\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_PORT', 'string', NULL, 'asterisk', 'Specifies the TCP port used to connect to the Asterisk AMI server.', 'Read in asterisk/wrapper.php:141 with a default of 5038.', 'Changing this value changes the port used for the Asterisk AMI connection.', 'Integer: TCP port number. Defaults to 5038 when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:141|read|$port = getDolGlobalInt(''ASTERISK_PORT'', 5038);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_PRIORITY', 'string', NULL, 'asterisk', 'Sets the dialplan priority used when Asterisk originates an outbound call.', 'Read in asterisk/wrapper.php:150 with a default of ''1''.', 'Changing this value selects a different dialplan priority for originated calls.', 'String (integer): Asterisk dialplan priority. Defaults to ''1'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:150|read|$strPriority = getDolGlobalString(''ASTERISK_PRIORITY'', ''1'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_TYPE', 'string', NULL, 'asterisk', 'Specifies the Asterisk channel type prefix used when initiating calls (e.g., ''SIP/'', ''PJSIP/'').', 'Read in asterisk/wrapper.php:135 with a default of ''SIP/''.', 'Changing this value selects the channel technology used for outbound click-to-call origination.', 'String: Asterisk channel type prefix (e.g., ''SIP/'', ''PJSIP/''). Defaults to ''SIP/'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:135|read|$channel = getDolGlobalString(''ASTERISK_TYPE'', ''SIP/'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ASTERISK_WAIT_TIME', 'string', NULL, 'asterisk', 'Sets the maximum time (in seconds) the Asterisk AMI will wait for the call to be answered.', 'Read in asterisk/wrapper.php:147 with a default of ''30''.', 'Changing this value adjusts how long the Asterisk server waits for the callee to answer before abandoning the call attempt.', 'String (integer seconds): wait time before abandoning call. Defaults to ''30'' when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["asterisk/wrapper.php:147|read|$strWaitTime = getDolGlobalString(''ASTERISK_WAIT_TIME'', ''30'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AUDIT_ENABLE_PREFIX_SESSION', 'bool', NULL, 'admin', 'Controls whether session-prefix filtering is enabled on the audit/event log list page.', 'Read at admin/tools/listevents.php:127-128 as both the ''checked'' and ''enabled'' state of a UI control, making it configurable through the admin UI at admin/tools/listevents.php.', 'Enabling this constant activates session-prefix display/filtering in the audit log UI; disabling it turns off that option.', '0 or unset = session prefix disabled; 1 = session prefix enabled.', 0, 0, 'admin/tools/listevents.php|admin/tools/listevents.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/listevents.php:127|read|''checked'' => getDolGlobalInt(''AUDIT_ENABLE_PREFIX_SESSION''),", "admin/tools/listevents.php:128|read|''enabled'' => getDolGlobalInt(''AUDIT_ENABLE_PREFIX_SESSION''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('AVAILABILITIES_ADDON_PDF', 'string', NULL, 'bookcal', 'Specifies the PDF template module name used to generate documents for availability records in BookCal.', 'Read at bookcal/class/availabilities.class.php:964-965; when set, its value is assigned as the PDF model name for availability document generation.', 'Setting this constant changes which PDF template is used for availability documents; leaving it unset falls back to the default template.', 'Empty/unset = use default PDF model; a module name string = use that PDF template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["bookcal/class/availabilities.class.php:964|read|} elseif (getDolGlobalString(''AVAILABILITIES_ADDON_PDF'')) {", "bookcal/class/availabilities.class.php:965|read|$modele = getDolGlobalString(''AVAILABILITIES_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANKADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF template module used to generate bank account (RIB) documents.', 'Set via admin/bank.php UI. Read in societe/paymentmodes.php:1724-1725 to select the model and in public/onlinesign/newonlinesign.php:567 as the default template for online signing. 9 occurrences across admin and runtime files.', 'Changing this value switches the PDF template used for RIB/bank account document generation including for online signing.', 'String: name of the PDF addon module; empty = no default template selected', 0, 0, 'admin/bank.php|admin/bank.php|admin/bank.php|admin/bank.php|admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/bank.php:201|write|if (dolibarr_set_const($db, \"BANKADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "societe/paymentmodes.php:1724|check|if (getDolGlobalString(''BANKADDON_PDF'')) {", "public/onlinesign/newonlinesign.php:567|read|$defaulttemplate = getDolGlobalString(\"BANKADDON_PDF\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ACCOUNT_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'societe', 'Allows external (public) download of bank account documents.', 'Checked in 2 occurrences: societe/paymentmodes.php:1940 gates external download UI, and core/class/commonobject.class.php:6383 checks it specifically for the ''bank_account'' element to enable external download links.', 'When enabled, download links for bank account documents are made available to external/public users.', '0 or unset = external download disabled; non-empty = external download enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/paymentmodes.php:1940|check|if (getDolGlobalString(''BANK_ACCOUNT_ALLOW_EXTERNAL_DOWNLOAD'')) {", "core/class/commonobject.class.php:6383|check|if ($this->element == ''bank_account'' && getDolGlobalInt(\"BANK_ACCOUNT_ALLOW_EXTERNAL_DOWNLOAD\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ALLOW_TRANSACTION_DELETION_EVEN_IF_IN_ACCOUNTING', 'bool', NULL, 'compta', 'Permits deletion of bank transactions that have already been recorded in accounting entries.', 'By default, transactions linked to accounting records are protected from deletion. Setting this constant removes that protection. Checked at compta/bank/class/account.class.php:2406.', 'Enabling this allows deletion of transactions already present in accounting, which may create inconsistencies between the bank register and accounting records.', '0 or empty = deletion blocked when transaction is in accounting; non-empty = deletion allowed regardless', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:2406|check|if (!getDolGlobalString(''BANK_ALLOW_TRANSACTION_DELETION_EVEN_IF_IN_ACCOUNTING'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ASK_PAYMENT_BANK_DURING_ORDER', 'string', NULL, 'commande', 'Prompts the user to select a bank account during order creation or validation.', 'Written via dolibarr_set_const at admin/order.php:234. Checked in commande/card.php:2422 and :3257 to display bank account selection. Also checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:128 to decide whether to inherit the bank account from the third party.', 'Enabling this displays a bank account selector during order processing; disabling skips that prompt and falls back to inheriting the account from the customer.', '0 or empty = bank account not requested during order; non-empty = bank account selector shown', 0, 0, 'admin/order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/order.php:234|write|$res = dolibarr_set_const($db, \"BANK_ASK_PAYMENT_BANK_DURING_ORDER\", $value, ''chaine'', 0, '''', $conf->entity);", "commande/card.php:2422|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_ORDER'') && isModEnabled(\"bank\")) {", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:128|check|if (empty($object->fk_account) && !empty($object->thirdparty->fk_account) && !getDolGlobalInt(''BANK_ASK_PAYMENT_BANK_DURING_ORDER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ASK_PAYMENT_BANK_DURING_PROPOSAL', 'string', NULL, 'supplier_proposal', 'Enables display of a bank account selection field on supplier and customer proposal forms.', 'Written via admin/propal.php (line 172). Checked across 5 occurrences in supplier_proposal/card.php (lines 1615, 2079) and comm/propal/card.php (lines 2473, 3293), always conditioned on the bank module being enabled.', 'Enabling this setting adds a bank account selector to the proposal validation workflow.', 'Truthy string (non-empty) = bank selector shown on proposals; empty/not set = bank selector hidden.', 0, 0, 'admin/propal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/propal.php:172|write|$res = dolibarr_set_const($db, \"BANK_ASK_PAYMENT_BANK_DURING_PROPOSAL\", $value, ''chaine'', 0, '''', $conf->entity);", "supplier_proposal/card.php:1615|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_PROPOSAL'') && isModEnabled(\"bank\")) {", "comm/propal/card.php:2473|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_PROPOSAL'') && isModEnabled(\"bank\")) {", "comm/propal/card.php:3293|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_PROPOSAL'') && isModEnabled(\"bank\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_ORDER', 'string', NULL, 'fourn', 'Adds a bank account selection field to the supplier order form when the bank module is enabled.', 'Configured via admin/supplier_order.php:203 and checked in fourn/commande/card.php:2067 and :2575.', 'Enabling this prompts users to select a bank account directly on the supplier order; disabling it omits the bank account field from the order form.', 'Empty/0 = no bank account field on order form; truthy = bank account field shown (requires bank module)', 0, 0, 'admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/supplier_order.php:203|write|$res = dolibarr_set_const($db, \"BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_ORDER\", $value, ''chaine'', 0, '''', $conf->entity);", "fourn/commande/card.php:2067|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_ORDER'') && isModEnabled(\"bank\")) {", "fourn/commande/card.php:2575|check|if (getDolGlobalString(''BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_ORDER'') && isModEnabled(\"bank\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_PROPOSAL', 'string', NULL, 'admin', 'Controls whether the user is prompted to select a payment bank when creating or validating a supplier proposal.', 'Written in admin/supplier_proposal.php:158 via dolibarr_set_const.', 'Enabling this setting adds a bank-selection step during supplier proposal creation or validation.', 'Non-empty/truthy = bank selection prompt shown; empty/unset = no prompt.', 0, 0, 'admin/supplier_proposal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"BANK_ASK_PAYMENT_BANK_DURING_SUPPLIER_PROPOSAL\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_CAN_RECONCILIATE_CASHACCOUNT', 'string', NULL, 'compta', 'Allows bank reconciliation to be performed on cash-type accounts.', 'By default, reconciliation is blocked for accounts of type TYPE_CASH. Setting this constant enables reconciliation for cash accounts. Checked in compta/bank/class/account.class.php:487 and :1501, and in core/lib/bank.lib.php:103.', 'Without this constant, cash accounts are excluded from reconciliation flows. Enabling it lifts that restriction.', '0 or empty = cash accounts cannot be reconciled; non-empty = cash accounts can be reconciled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:487|check|if ($this->type == Account::TYPE_CASH && !getDolGlobalString(''BANK_CAN_RECONCILIATE_CASHACCOUNT'')) {", "compta/bank/class/account.class.php:1501|check|if (!getDolGlobalString(''BANK_CAN_RECONCILIATE_CASHACCOUNT'')) {", "core/lib/bank.lib.php:103|check|if ($object->type != Account::TYPE_CASH || getDolGlobalString(''BANK_CAN_RECONCILIATE_CASHACCOUNT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_CAN_REOPEN_DIRECT_DEBIT_OR_CREDIT_TRANSFER', 'string', NULL, 'compta', 'Allows reopening of direct debit or credit transfer bank orders that have already been processed.', 'Checked in compta/prelevement/card.php:448 and compta/prelevement/requests.php:448 to conditionally show or enable the reopen action. No admin UI is present.', 'Enabling this constant allows users to reopen closed direct debit or credit transfer orders; without it, that action is not available.', '0 or unset = reopening not allowed; any truthy value = reopening allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/card.php:448|check|if (getDolGlobalString(''BANK_CAN_REOPEN_DIRECT_DEBIT_OR_CREDIT_TRANSFER'')) {", "compta/prelevement/requests.php:448|check|if (getDolGlobalString(''BANK_CAN_REOPEN_DIRECT_DEBIT_OR_CREDIT_TRANSFER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_CHEQUERECEIPT_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to cheque receipt documents.', 'Written in admin/chequereceipts.php:96 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on cheque receipt PDFs.', 'Arbitrary string text.', 0, 0, 'admin/chequereceipts.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"BANK_CHEQUERECEIPT_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_COLORIZE_MOVEMENT', 'string', NULL, 'admin', 'Enables color-coding of debit and credit movements in the bank entries list.', 'Toggled via admin/bank.php (written as 1 at :104, written as 0 at :109). Checked at admin/bank.php:456 and :470 and at compta/bank/bankentries_list.php:1468 to apply or suppress row coloring.', 'Enabling this causes bank transaction rows to be colored differently based on movement direction; disabling shows uniform row styling.', '0 = movements not colorized; 1 = movements colorized', 0, 0, 'admin/bank.php|admin/bank.php|admin/bank.php|admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/bank.php:104|write|if (dolibarr_set_const($db, \"BANK_COLORIZE_MOVEMENT\", 1, ''chaine'', 0, '''', $conf->entity) > 0) {", "admin/bank.php:109|write|if (dolibarr_set_const($db, \"BANK_COLORIZE_MOVEMENT\", 0, ''chaine'', 0, '''', $conf->entity) > 0) {", "compta/bank/bankentries_list.php:1468|check|if (!getDolGlobalString(''BANK_COLORIZE_MOVEMENT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_COLORIZE_MOVEMENT_COLOR', 'string', NULL, 'admin', 'Stores the color used to colorize a category of bank account movements in the bank admin settings.', 'Set via the admin UI at admin/bank.php. Indexed per movement category (e.g. BANK_COLORIZE_MOVEMENT_COLOR1), it holds the color string for that category.', 'Changing this value alters the color applied to the corresponding bank movement category in the display.', 'Free string (color code); named with numeric suffix per category index ($i).', 0, 0, 'admin/bank.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/bank.php:129|write|$res = dolibarr_set_const($db, ''BANK_COLORIZE_MOVEMENT_COLOR''.$i, $color, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_COLORIZE_MOVEMENT_COLOR1', 'string', NULL, 'compta', 'Defines the hex color used to highlight one direction of bank movements when colorization is enabled.', 'Read at compta/bank/bankentries_list.php:1472 with a default of ''fca955'' (orange). The value is prepended with ''#'' to form a CSS color.', 'Setting this value changes the highlight color for one movement direction in the bank entries list.', '6-character hex color string without ''#'' (default: fca955)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/bankentries_list.php:1472|read|$color = ''#'' . getDolGlobalString(''BANK_COLORIZE_MOVEMENT_COLOR1'', ''fca955'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_COLORIZE_MOVEMENT_COLOR2', 'string', NULL, 'compta', 'Defines the hex color used to highlight the other direction of bank movements when colorization is enabled.', 'Read at compta/bank/bankentries_list.php:1475 with a default of ''7fdb86'' (green). The value is prepended with ''#'' to form a CSS color.', 'Setting this value changes the highlight color for the second movement direction in the bank entries list.', '6-character hex color string without ''#'' (default: 7fdb86)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/bankentries_list.php:1475|read|$color = ''#'' . getDolGlobalString(''BANK_COLORIZE_MOVEMENT_COLOR2'', ''7fdb86'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_DISABLE_CHECK_DEPOSIT', 'bool', NULL, 'index.php', 'Disables the check deposit feature in the bank module, hiding the related menu entry and dashboard block.', 'Checked in index.php:296 (to hide the check deposit sub-block on the dashboard) and in core/menus/standard/eldy.lib.php:2168 (to hide the check deposit menu item). No admin UI is present.', 'Setting this constant hides the check deposit UI from both the menu and the dashboard across the application.', 'Boolean flag: truthy = check deposit hidden; 0 or unset = check deposit displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:296|check|if (!getDolGlobalString(''BANK_DISABLE_CHECK_DEPOSIT'')) {", "core/menus/standard/eldy.lib.php:2168|check|if (!getDolGlobalString(''BANK_DISABLE_CHECK_DEPOSIT'') && isModEnabled(''bank'') && (isModEnabled(''invoice'') || getDolGlobalString(''MAIN_MENU_CHEQUE_DEPOSIT_ON''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_DISABLE_DIRECT_INPUT', 'bool', NULL, 'compta', 'Disables direct manual entry of bank transactions from the bank entries list.', 'Checked in admin/bank.php:510 (admin UI) and compta/bank/bankentries_list.php:906 to suppress the direct-input form or button.', 'Enabling this hides or disables the UI element that allows direct manual creation of bank transactions.', '0 or empty = direct input allowed; non-empty = direct input disabled', 0, 0, 'admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/bank.php:510|check|if (getDolGlobalString(''BANK_DISABLE_DIRECT_INPUT'')) {", "compta/bank/bankentries_list.php:906|check|if (!getDolGlobalString(''BANK_DISABLE_DIRECT_INPUT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_ENABLE_POS_CASHCONTROL', 'bool', NULL, 'blockedlog', 'Signals that an external POS module requires cash control tracking in the blockedlog.', 'Read at blockedlog/class/blockedlog.class.php:307 where it is OR-combined with isModEnabled(''cashdesk'') and isModEnabled(''takepos'') to determine whether POS cash control is active. The comment at line 306 states this must be set to 1 by all external POS modules.', 'Setting this constant to 1 activates cash control blockedlog tracking for external POS modules that do not have a native Dolibarr module enable flag.', '$conf->global->BANK_ENABLE_POS_CASHCONTROL must be set to 1 by all external POS modules.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:306  // $conf->global->BANK_ENABLE_POS_CASHCONTROL must be set to 1 by all external POS modules", "blockedlog/class/blockedlog.class.php:307|read|$moduleposenabled = (isModEnabled(''cashdesk'') || isModEnabled(''takepos'') || getDolGlobalString(''BANK_ENABLE_POS_CASHCONTROL''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_PAYMENT_MODES_FOR_DEPOSIT_MANAGEMENT', 'string', NULL, 'compta', 'Defines the comma-separated list of payment mode codes managed through the cheque deposit interface.', 'Read in compta/paiement/cheque/index.php:57, card.php:104, and list.php:88 via explode('','', getDolGlobalString(..., ''CHQ'')). The comments in all three files state: ''// Example: BANK_PAYMENT_MODES_FOR_DEPOSIT_MANAGEMENT = \''CHQ\'',\''TRA\''''.', 'Changing this constant alters which payment mode codes are included in the deposit management workflow; removing a code excludes those payments from the deposit lists.', 'Comma-separated payment mode codes; default is ''CHQ''. Example: ''CHQ'',''TRA''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["// Example: BANK_PAYMENT_MODES_FOR_DEPOSIT_MANAGEMENT = ''CHQ'',''TRA''", "$arrayofpaymentmodetomanage = explode('','', getDolGlobalString(''BANK_PAYMENT_MODES_FOR_DEPOSIT_MANAGEMENT'', ''CHQ''));", "if (getDolGlobalString(''BANK_PAYMENT_MODES_FOR_DEPOSIT_MANAGEMENT'', ''CHQ'') == ''CHQ'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_REPORT_LAST_NUM_RELEVE', 'string', NULL, 'admin', 'Controls whether the last bank statement number is automatically carried forward to the next statement.', 'Toggled via admin/bank.php (written as 1 at :91, written as 0 at :96). Checked at admin/bank.php:526 and compta/bank/bankentries_list.php:1031. The comment at bankentries_list.php:1030 explicitly documents its purpose.', 'Enabling this causes the last statement number to be reported automatically; disabling requires the number to be entered manually each time.', '0 = last statement number not auto-reported; 1 = last statement number automatically reported', 0, 0, 'admin/bank.php|admin/bank.php|admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/bankentries_list.php:1030  // Using BANK_REPORT_LAST_NUM_RELEVE to automatically report last num (or not)", "admin/bank.php:91|write|if (dolibarr_set_const($db, \"BANK_REPORT_LAST_NUM_RELEVE\", 1, ''chaine'', 0, '''', $conf->entity) > 0) {", "admin/bank.php:96|write|if (dolibarr_set_const($db, \"BANK_REPORT_LAST_NUM_RELEVE\", 0, ''chaine'', 0, '''', $conf->entity) > 0) {", "compta/bank/bankentries_list.php:1031|check|if (getDolGlobalString(''BANK_REPORT_LAST_NUM_RELEVE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_SHOW_ORDER_OPTION', 'bool', NULL, 'compta', 'Selects the ordering field used to sort bank account transactions in the account register.', 'Configurable via admin/bank.php. When set to ''1'', one sort order is applied; numeric values select among available sort options; a regex replacement on the value derives the final field name (compta/bank/class/account.class.php:1960). Set via dolibarr_set_const at admin/bank.php:83.', 'Changing this value alters the default sort order of bank transaction listings. The value is used both as a flag and as a field-name pattern.', 'Empty = default ordering; ''1'' = sort by BankAccountNumber; numeric value = selects sort index; string = sort field pattern', 0, 0, 'admin/bank.php|admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:1947|check|if (is_numeric(getDolGlobalString(''BANK_SHOW_ORDER_OPTION''))) {", "compta/bank/class/account.class.php:1948|check|if (getDolGlobalString(''BANK_SHOW_ORDER_OPTION'') == ''1'') {", "compta/bank/class/account.class.php:1960|read|preg_replace(''/ ?[^Bank]AccountNumber ?/'', ''BankAccountNumber'', $conf->global->BANK_SHOW_ORDER_OPTION)", "admin/bank.php:83|write|if (dolibarr_set_const($db, \"BANK_SHOW_ORDER_OPTION\", GETPOST(''value'', ''alpha''), ''chaine'', 0, '''', $conf->entity) > 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_STATEMENT_REGEX_RULE', 'string', NULL, 'compta', 'Defines a regular expression that bank statement reference numbers must match.', 'When set, the value is used as a regex pattern validated against the statement number (num_releve) via preg_match. If the number does not match, an error is added to the object. Checked at compta/bank/class/account.class.php:2569–2571.', 'Setting a regex forces statement reference numbers to conform to that pattern; non-matching values trigger a validation error preventing save.', 'Empty = no format constraint; any valid regex string = pattern that statement numbers must match', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:2570|check|if (!preg_match(''/'' . getDolGlobalString(''BANK_STATEMENT_REGEX_RULE'').''/'', $this->num_releve)) {", "compta/bank/class/account.class.php:2571|read|$this->errors[] = $langs->trans(\"ErrorBankStatementNameMustFollowRegex\", getDolGlobalString(''BANK_STATEMENT_REGEX_RULE''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_TRANSFER_ASK_CHQ_NUMBER_OF_SRC_ACCOUNT', 'string', NULL, 'compta', 'Enables prompting for a cheque number from the source account during a bank transfer.', 'Checked twice in compta/bank/transfer.php (lines 318 and 369) to conditionally render a cheque-number input field in the transfer form.', 'Enabling this constant causes an additional input field to appear on the bank transfer form, requesting the cheque number of the source account.', 'Empty/not set = cheque number field not shown; any truthy string = field displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/transfer.php:369|check|if (getDolGlobalString(''BANK_TRANSFER_ASK_CHQ_NUMBER_OF_SRC_ACCOUNT'')) {", "compta/bank/transfer.php:318|check|if (getDolGlobalString(''BANK_TRANSFER_ASK_CHQ_NUMBER_OF_SRC_ACCOUNT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BANK_USE_OLD_VARIOUS_PAYMENT', 'bool', NULL, 'compta', 'Enables the legacy inline various payment entry form in bank entries list instead of the modern miscellaneous payments module.', 'Checked at compta/bank/bankentries_list.php:812, :389, and :910. When set, the old inline form is shown and the new miscellaneous payment path is bypassed. When unset, the default is to use the new miscellaneous payments module (bankentries_list.php:910 comment: ''Default is to record miscellaneous direct entries using miscellaneous payments''). Also controls a menu entry in core/menus/standard/eldy.lib.php:1705 and a project element tab in projet/element.php:782.', 'When unset, the modern miscellaneous payments workflow is used and the corresponding menu entry is shown. When set, the old inline payment form is activated and the new menu entry is hidden.', 'Truthy value = legacy inline various payment form enabled; empty/unset = modern miscellaneous payments used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/bankentries_list.php:910|check|if (!getDolGlobalString(''BANK_USE_OLD_VARIOUS_PAYMENT'')) {\t// Default is to record miscellaneous direct entries using miscellaneous payments", "compta/bank/bankentries_list.php:812|check|if ($user->hasRight(''banque'', ''modifier'') && $action == ''addline'' && getDolGlobalString(''BANK_USE_OLD_VARIOUS_PAYMENT'')) {", "core/menus/standard/eldy.lib.php:1705|check|if (isModEnabled(''bank'') && !getDolGlobalString(''BANK_USE_OLD_VARIOUS_PAYMENT'')) {", "projet/element.php:782|read|''test'' => isModEnabled(\"bank\") && $user->hasRight(''banque'', ''lire'') && !getDolGlobalString(''BANK_USE_OLD_VARIOUS_PAYMENT'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_FORCEIMGSCALEHEIGHT', 'string', NULL, 'barcode', 'Forces a specific image scale height for barcode images on printed label sheets.', 'Used in a single location: barcode/printsheet.php:322 reads the value (defaulting to 1) into $forceimgscaleheight.', 'Setting a numeric value overrides the default scale height of barcode images on label stickers.', 'Numeric value; default 1.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:322|read|$forceimgscaleheight = getDolGlobalString(''BARCODE_FORCEIMGSCALEHEIGHT'', 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_FORCEIMGSCALEWIDTH', 'string', NULL, 'barcode', 'Forces a specific image scale width for barcode images on printed label sheets.', 'Used in a single location: barcode/printsheet.php:321 reads the value (defaulting to 1) into $forceimgscalewidth.', 'Setting a numeric value overrides the default scale width of barcode images on label stickers.', 'Numeric value; default 1.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:321|read|$forceimgscalewidth = getDolGlobalString(''BARCODE_FORCEIMGSCALEWIDTH'', 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_INIT_MAX', 'string', NULL, 'barcode', 'Sets the maximum number of barcode records to initialise per batch run in the barcode initialisation script.', 'Used in a single location: barcode/codeinit.php:56 reads the value with a default of 1000 into $maxperinit.', 'Increasing this value allows more barcodes to be initialised per script execution; decreasing it limits the batch size.', 'Integer; default 1000.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/codeinit.php:56|read|$maxperinit = getDolGlobalInt(''BARCODE_INIT_MAX'', 1000);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_LABEL_FOOTER_TEXT', 'string', NULL, 'barcode', 'Defines a substitution-enabled text string printed in the footer area of barcode label stickers.', 'Used in a single location: barcode/printsheet.php:318 reads the value and passes it through make_substitutions() before printing.', 'Setting this constant populates the footer text zone of barcode label stickers; leaving it empty renders no footer text.', 'Any string value; substitution tokens are expanded at print time.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:318|read|$textfooter = make_substitutions(getDolGlobalString(''BARCODE_LABEL_FOOTER_TEXT''), $substitutionarray);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_LABEL_HEADER_TEXT', 'string', NULL, 'barcode', 'Defines a substitution-enabled text string printed in the header area of barcode label stickers.', 'Used in a single location: barcode/printsheet.php:313 reads the value and passes it through make_substitutions() before printing.', 'Setting this constant populates the header text zone of barcode label stickers; leaving it empty renders no header text.', 'Any string value; substitution tokens are expanded at print time.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:313|read|$textheader = make_substitutions(getDolGlobalString(''BARCODE_LABEL_HEADER_TEXT''), $substitutionarray);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_LABEL_LEFT_TEXT', 'string', NULL, 'barcode', 'Defines a substitution-enabled text string printed on the left area of barcode label stickers.', 'Used in a single location: barcode/printsheet.php:309 reads the value and passes it through make_substitutions() to allow variable replacement before printing.', 'Setting this constant populates the left text zone of barcode label stickers; leaving it empty uses the default sticker text.', 'Any string value; substitution tokens (as supported by make_substitutions) are expanded at print time.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:309|read|$textleft = make_substitutions(getDolGlobalString(''BARCODE_LABEL_LEFT_TEXT'', $txtforsticker), $substitutionarray);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_LABEL_RIGHT_TEXT', 'string', NULL, 'barcode', 'Defines a substitution-enabled text string printed on the right area of barcode label stickers.', 'Used in a single location: barcode/printsheet.php:320 reads the value and passes it through make_substitutions() before printing.', 'Setting this constant populates the right text zone of barcode label stickers; leaving it empty renders no right-side text.', 'Any string value; substitution tokens are expanded at print time.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["barcode/printsheet.php:320|read|$textright = make_substitutions(getDolGlobalString(''BARCODE_LABEL_RIGHT_TEXT''), $substitutionarray);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_ON_RECEPTION_PDF', 'string', NULL, 'admin', 'Enables printing barcodes on reception PDF documents when the barcode module is active.', 'Written in admin/pdf_other.php at line 172 and displayed as a select at line 789. Checked in pdf_squille.modules.php at line 384 in conjunction with the barcode module being enabled.', 'Enabling this constant (with the barcode module active) causes barcodes to be printed on reception PDFs. Disabling it omits barcodes.', 'Non-zero integer to enable barcodes on reception PDFs (requires barcode module); 0 or unset to disable.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:172|write|dolibarr_set_const($db, \"BARCODE_ON_RECEPTION_PDF\", GETPOSTINT(\"BARCODE_ON_RECEPTION_PDF\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/reception/doc/pdf_squille.modules.php:384|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_ON_RECEPTION_PDF'')) {", "admin/pdf_other.php:789|read|print $form->selectarray(\"BARCODE_ON_RECEPTION_PDF\", $arrval, getDolGlobalString(''BARCODE_ON_RECEPTION_PDF''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_ON_SHIPPING_PDF', 'string', NULL, 'core', 'Controls whether barcodes are printed on shipping PDFs when the barcode module is enabled.', 'Managed via the admin UI at admin/pdf_other.php where it is written with dolibarr_set_const and presented as a select array. In pdf_rouget.modules.php and pdf_espadon.modules.php, the check combines isModEnabled(''barcode'') with this constant before rendering barcode content.', 'Setting a truthy value (with the barcode module active) causes barcodes to be printed on shipping PDFs. Clearing the value suppresses barcode output even if the barcode module is enabled.', 'Empty/unset = no barcode on shipping PDF; any truthy value (with barcode module enabled) = barcode printed.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:169|dolibarr_set_const($db, \"BARCODE_ON_SHIPPING_PDF\", GETPOSTINT(\"BARCODE_ON_SHIPPING_PDF\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:742|print $form->selectarray(\"BARCODE_ON_SHIPPING_PDF\", $arrval, getDolGlobalString(''BARCODE_ON_SHIPPING_PDF''));", "pdf_rouget.modules.php:428|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_ON_SHIPPING_PDF'')) {", "pdf_espadon.modules.php:531|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_ON_SHIPPING_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_ON_STOCKTRANSFER_PDF', 'string', NULL, 'admin', 'Controls whether barcodes are printed on stock-transfer PDF documents.', 'Configured via admin/pdf_other.php (UI write at line 175, select array at line 814). Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php:446 alongside a check that the barcode module is enabled.', 'When set to a truthy value (and the barcode module is enabled), barcodes are rendered on stock-transfer PDFs. When unset or 0, barcodes are omitted.', 'Value from the configured select array in admin/pdf_other.php; 0 or empty to disable barcodes.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:175|write|dolibarr_set_const($db, \"BARCODE_ON_STOCKTRANSFER_PDF\", GETPOSTINT(\"BARCODE_ON_STOCKTRANSFER_PDF\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:814|read|print $form->selectarray(\"BARCODE_ON_STOCKTRANSFER_PDF\", $arrval, getDolGlobalString(''BARCODE_ON_STOCKTRANSFER_PDF''));", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:446|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_ON_STOCKTRANSFER_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_PRODUCT_ADDON_NUM', 'string', NULL, 'product', 'Identifies the active automatic barcode numbering module used for product records.', 'Written by admin/barcode.php:63 (set) and admin/barcode.php:68 (delete). Read in admin/barcode.php:297 to highlight the selected module, in barcode/codeinit.php:182 and :194 during initialisation, and in product/class/product.class.php:1355 and :6947 when auto-generating product barcodes.', 'Setting this constant activates a specific numbering module for auto-generating product barcodes; clearing it disables automatic barcode numbering for products.', 'Module filename string (e.g. ''mod_barcode_product_standard''); empty = no automatic numbering.', 0, 0, 'admin/barcode.php|admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/barcode.php:63|write|$res = dolibarr_set_const($db, \"BARCODE_PRODUCT_ADDON_NUM\", $barcodenumberingmodule, ''chaine'', 0, '''', $conf->entity);", "barcode/codeinit.php:182|check|if (getDolGlobalString(''BARCODE_PRODUCT_ADDON_NUM'')) {", "barcode/codeinit.php:194|check|if ($file == getDolGlobalString(''BARCODE_PRODUCT_ADDON_NUM'')) {", "product/class/product.class.php:1355|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_PRODUCT_ADDON_NUM'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_STANDARD_PRODUCT_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the standard product barcode generation module.', 'Managed via admin/barcode.php; if unset when the standard module is active, the admin page writes a default of ''04{0000000000}'' at line 65. The mask is read and applied in core/modules/barcode/mod_barcode_product_standard.php at lines 196 and 334.', 'Changing this mask alters the format of auto-generated product barcodes; removing it causes the admin page to reset it to the default ''04{0000000000}''.', 'Mask string, e.g. ''04{0000000000}''; default set to ''04{0000000000}'' if unset.', 0, 0, 'admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/barcode.php:65|write|$res = dolibarr_set_const($db, \"BARCODE_STANDARD_PRODUCT_MASK\", ''04{0000000000}'', ''chaine'', 0, '''', $conf->entity);", "core/modules/barcode/mod_barcode_product_standard.php:196|read|$mask = getDolGlobalString(''BARCODE_STANDARD_PRODUCT_MASK'');", "core/modules/barcode/mod_barcode_product_standard.php:334|read|$mask = !getDolGlobalString(''BARCODE_STANDARD_PRODUCT_MASK'') ? '''' : $conf->global->BARCODE_STANDARD_PRODUCT_MASK;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_STANDARD_THIRDPARTY_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the standard third-party barcode generation module.', 'Managed via admin/barcode.php; if unset when the standard thirdparty module is active, the admin page writes a default of ''04{0000000000}'' at line 75. The mask is read and applied in core/modules/barcode/mod_barcode_thirdparty_standard.php at lines 220 and 355.', 'Changing this mask alters the format of auto-generated third-party barcodes; removing it causes the admin page to reset it to the default ''04{0000000000}''.', 'Mask string, e.g. ''04{0000000000}''; default set to ''04{0000000000}'' if unset.', 0, 0, 'admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/barcode.php:75|write|$res = dolibarr_set_const($db, \"BARCODE_STANDARD_THIRDPARTY_MASK\", ''04{0000000000}'', ''chaine'', 0, '''', $conf->entity);", "core/modules/barcode/mod_barcode_thirdparty_standard.php:220|read|$mask = getDolGlobalString(''BARCODE_STANDARD_THIRDPARTY_MASK'');", "core/modules/barcode/mod_barcode_thirdparty_standard.php:355|read|$mask = !getDolGlobalString(''BARCODE_STANDARD_THIRDPARTY_MASK'') ? '''' : $conf->global->BARCODE_STANDARD_THIRDPARTY_MASK;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_THIRDPARTY_ADDON_NUM', 'string', NULL, 'admin', 'Identifies the active automatic barcode numbering module used for third-party records.', 'Written by admin/barcode.php:73 (set) and admin/barcode.php:78 (delete). Read in admin/barcode.php:366 to highlight the selected module in the admin UI, and checked in barcode/codeinit.php:77 before initialising third-party barcodes.', 'Setting this constant activates a specific numbering module for auto-generating third-party barcodes; clearing it disables automatic numbering.', 'Module filename string (e.g. ''mod_barcode_thirdparty_standard''); empty = no automatic numbering.', 0, 0, 'admin/barcode.php|admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/barcode.php:73|write|$res = dolibarr_set_const($db, \"BARCODE_THIRDPARTY_ADDON_NUM\", $barcodenumberingmodule, ''chaine'', 0, '''', $conf->entity);", "admin/barcode.php:366|check|if (getDolGlobalString(''BARCODE_THIRDPARTY_ADDON_NUM'') && getDolGlobalString(''BARCODE_THIRDPARTY_ADDON_NUM'') == \"$file\") {", "barcode/codeinit.php:77|check|if (getDolGlobalString(''BARCODE_THIRDPARTY_ADDON_NUM'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_USE_ON_PRODUCT', 'bool', NULL, 'product', 'Enables barcode functionality on product records when the barcode module is active.', 'Configurable via the admin UI at admin/barcode.php (checked/displayed at lines 257, 396, 502, 533). Also read in product/card.php at lines 234, 2243, and 2592 to show barcode fields on the product card.', 'Enabling this activates barcode display and generation on product records; disabling it hides barcode fields from product pages.', 'truthy = enable barcodes on products; empty/not set = disable', 0, 0, 'admin/barcode.php|admin/barcode.php|admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/barcode.php:257|check|if (getDolGlobalString(''BARCODE_USE_ON_PRODUCT'') && isModEnabled(''product'')) {", "product/card.php:234|read|$createbarcode = (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_USE_ON_PRODUCT''));", "product/card.php:2243|read|$showbarcode = (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_USE_ON_PRODUCT''));", "product/card.php:1414|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_USE_ON_PRODUCT'') && getDolGlobalString(''BARCODE_PRODUCT_ADDON_NUM'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BARCODE_USE_ON_THIRDPARTY', 'bool', NULL, 'admin', 'When enabled, activates barcode field display and functionality on third-party records.', 'Checked in admin/barcode.php:325, :396, :502, :544 to conditionally render barcode configuration options when the societe module is active. Also checked in societe/card.php:1610, :2485, :3072 to display the barcode field on third-party cards. Seven occurrences across two files; written via admin/barcode.php.', 'Enabling this constant adds a barcode input field to third-party cards and activates related barcode configuration sections in the barcode admin panel.', 'Boolean flag; unset or 0 = barcode not shown on third parties; any truthy value = barcode field displayed.', 0, 0, 'admin/barcode.php|admin/barcode.php|admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/barcode.php:325|check|if (getDolGlobalString(''BARCODE_USE_ON_THIRDPARTY'') && isModEnabled(''societe'')) {", "societe/card.php:1610|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_USE_ON_THIRDPARTY'')) {", "admin/barcode.php:396|check|if (getDolGlobalString(''BARCODE_USE_ON_PRODUCT'') || getDolGlobalString(''BARCODE_USE_ON_THIRDPARTY'')) {", "societe/card.php:3072|check|if (isModEnabled(''barcode'') && getDolGlobalString(''BARCODE_USE_ON_THIRDPARTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BILL_ADD_PAYMENT_VALIDATION', 'string', NULL, 'compta', 'Enables a payment validation workflow for customer and supplier invoices, adding a ''payments to validate'' queue and menu entry.', 'Checked across fourn/paiement/card.php, compta/payment_sc/card.php, compta/paiement/card.php, and core/menus/standard/eldy.lib.php. The file compta/paiement/tovalidate.php:23 describes it as: ''Page list payment to validate. Visible in menu when option BILL_ADD_PAYMENT_VALIDATION is on.''', 'Enabling this constant activates the payment validation step, shows the validation status column in payment lists (compta/paiement/list.php:129), and adds the corresponding menu entry.', 'Boolean/truthy: non-empty enables the validation workflow; empty/unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* \tbrief      Page list payment to validate. Visible in menu when option BILL_ADD_PAYMENT_VALIDATION is on.", "if (getDolGlobalString(''BILL_ADD_PAYMENT_VALIDATION'')) {", "''enabled'' => (getDolGlobalString(''BILL_ADD_PAYMENT_VALIDATION''))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ADD_ACTIONS_SUPPORTED', 'string', NULL, 'core', 'Extends the list of event action codes that are recorded in the blockedlog with a comma-separated custom list.', 'When set, blockedlog/class/blockedlog.class.php:327 merges its comma-separated value into the supported events array. core/triggers/interface_50_modBlockedlog_ActionsBlockedLog.class.php:72 does the same for the trigger''s qualified element list, and line 155 uses it to match individual action codes.', 'Setting this constant adds custom action codes to the blockedlog; removing it restricts logging to the built-in supported actions.', 'Comma-separated list of action code strings (e.g. ''MY_ACTION,OTHER_ACTION''). Empty or unset means no additional actions.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:327|read|$tmparrayofmoresupportedevents = explode('','', getDolGlobalString(''BLOCKEDLOG_ADD_ACTIONS_SUPPORTED''));", "core/triggers/interface_50_modBlockedlog_ActionsBlockedLog.class.php:72|read|$listofqualifiedelement = array_merge($listofqualifiedelement, explode('','', getDolGlobalString(''BLOCKEDLOG_ADD_ACTIONS_SUPPORTED'')));", "core/triggers/interface_50_modBlockedlog_ActionsBlockedLog.class.php:155|read||| (getDolGlobalString(''BLOCKEDLOG_ADD_ACTIONS_SUPPORTED'') && in_array($action, explode('','', getDolGlobalString(''BLOCKEDLOG_ADD_ACTIONS_SUPPORTED''))))", "blockedlog/class/blockedlog.class.php:321|check|if (getDolGlobalString(''BLOCKEDLOG_ADD_ACTIONS_SUPPORTED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ADD_DEBUG_INFO', 'string', NULL, 'blockedlog', 'Enables inclusion of additional debug information in blockedlog records.', 'Checked at blockedlog/class/blockedlog.class.php:1339 to conditionally append debug data to a blockedlog entry. Only one occurrence is present in the payload.', 'Enabling this constant causes extra debug fields to be written into blockedlog records.', 'Truthy value enables debug info in blockedlog records; absent or falsy omits it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:1339|check|if (getDolGlobalString(''BLOCKEDLOG_ADD_DEBUG_INFO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ADD_OLD_CASHCONTROL_VALIDATE', 'string', NULL, 'blockedlog', 'Enables inclusion of legacy cash control validation events in the blockedlog.', 'Checked at blockedlog/class/blockedlog.class.php:313 to conditionally add old-style cash control validate events to the blocked log processing. Only one occurrence is present in the payload.', 'Enabling this constant causes legacy cash control validation events to be processed into the blockedlog chain.', 'Truthy value includes legacy cash control validate events; absent or falsy excludes them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:313|check|if (getDolGlobalString(''BLOCKEDLOG_ADD_OLD_CASHCONTROL_VALIDATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_AUTHORITY_URL', 'string', NULL, 'blockedlog', 'Stores the URL of the remote authority used to verify blockedlog entries.', 'Read at blockedlog/admin/blockedlog.php:207 as an editable text input and checked at blockedlog/admin/blockedlog_list.php:579 and 866 alongside BLOCKEDLOG_USE_REMOTE_AUTHORITY. Configurable via admin UI.', 'This URL is used as the remote verification endpoint when BLOCKEDLOG_USE_REMOTE_AUTHORITY is enabled. An invalid or unreachable URL would cause verification to fail.', 'A valid URL string pointing to the remote authority endpoint.', 0, 0, 'blockedlog/admin/blockedlog.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''BLOCKEDLOG_USE_REMOTE_AUTHORITY'') && getDolGlobalString(''BLOCKEDLOG_AUTHORITY_URL'')) {", "print ''<input type=\"text\" name=\"BLOCKEDLOG_AUTHORITY_URL\" value=\"'' . getDolGlobalString(''BLOCKEDLOG_AUTHORITY_URL'').''\" size=\"40\" />'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_DEBUG', 'string', NULL, 'blockedlog', 'Enables debug output on the blockedlog list admin page to assist developers in diagnosing verification issues.', 'Checked 8 times across blockedlog/admin/blockedlog_list.php at lines 373, 404, 462, 572, 586, 681, 754, and 806. The inline comments at lines 373, 586, 681, and 754 describe it as: ''If in experimental or develop mode, we add some debug information. It may help developers to find origin of bugs.''', 'Enabling this constant causes additional debug information to be printed inline on the blockedlog list page.', 'Boolean/truthy: non-empty enables debug output; empty/unset disables it.', 0, 0, 'blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(\"BLOCKEDLOG_DEBUG\")) {\t// If in experimental or develop mode, we add some debug information. It may help developers to find origin of bugs."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_DISABLE_NOT_ALLOWED_FOR_COUNTRY', 'bool', NULL, 'core', 'Stores a comma-separated list of country codes for which the BlockedLog module is disabled.', 'Read at blockedlog/admin/blockedlog.php:240 (exploded into an array for a multi-select) and at core/modules/modBlockedLog.class.php:89, 99–100. The module activation logic at lines 99–100 checks if $mysoc->country_code appears in this list to suppress the module.', 'If the installation''s company country code is in this list, the BlockedLog module is disabled for that entity.', 'A comma-separated string of ISO country codes (e.g. ''FR,DE''); empty means the module is not disabled for any country.', 0, 0, 'blockedlog/admin/blockedlog.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["/*if (getDolGlobalString(''BLOCKEDLOG_DISABLE_NOT_ALLOWED_FOR_COUNTRY'')) {", "$tmp = explode('','', getDolGlobalString(''BLOCKEDLOG_DISABLE_NOT_ALLOWED_FOR_COUNTRY''));", "&& in_array((empty($mysoc->country_code) ? '''' : $mysoc->country_code), explode('','', getDolGlobalString(''BLOCKEDLOG_DISABLE_NOT_ALLOWED_FOR_COUNTRY'')))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ENABLE_DONATION', 'bool', NULL, 'blockedlog', 'Extends the unalterable blockedlog to include donation records, for countries that legally require it.', 'Checked at blockedlog/class/blockedlog.class.php:257 together with isModEnabled(''don'') to include donation events in the blocked log chain. Only one occurrence is present in the payload.', 'Enabling this constant causes donation records to be included in the unalterable audit log; disabling it excludes them.', 'Truthy value includes donations in the blocked log; absent or falsy excludes them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:257|check|if (isModEnabled(''don'') && getDolGlobalString(''BLOCKEDLOG_ENABLE_DONATION'')) {\t// For countries that need unalterable logs for donations"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ENABLE_MEMBER', 'bool', NULL, 'blockedlog', 'Extends the unalterable blockedlog to include membership management records, for countries that legally require it.', 'Checked at blockedlog/class/blockedlog.class.php:280 together with isModEnabled(''member'') to include membership events in the blocked log chain. Only one occurrence is present in the payload.', 'Enabling this constant causes membership records to be included in the unalterable audit log; disabling it excludes them.', 'Truthy value includes membership records in the blocked log; absent or falsy excludes them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:280|check|if (isModEnabled(''member'') && getDolGlobalString(''BLOCKEDLOG_ENABLE_MEMBER'')) {\t// For countries that need unalterable logs for membership management"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_ENTITY_FINGERPRINT', 'string', NULL, 'blockedlog', 'Stores the unique numeric fingerprint identifying the Dolibarr entity within the blockedlog chain.', 'Checked at blockedlog/class/blockedlog.class.php:1816 to determine if a fingerprint needs to be created; written at lines 1824 and 1826 during creation; read at line 1833 and returned to callers. The dolibarr_set_const call uses the description ''Numeric Unique Fingerprint''.', 'This value is auto-generated and should not be manually altered; changing it would break fingerprint continuity in the blockedlog chain.', 'Auto-generated string fingerprint. Created automatically if absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:1816|check|if (!getDolGlobalString(''BLOCKEDLOG_ENTITY_FINGERPRINT'')) { // creation of a unique fingerprint", "blockedlog/class/blockedlog.class.php:1824|write|dolibarr_set_const($db, ''BLOCKEDLOG_ENTITY_FINGERPRINT'', $fingerprint, ''chaine'', 0, ''Numeric Unique Fingerprint'', $conf->entity);", "blockedlog/class/blockedlog.class.php:1826|write|$conf->global->BLOCKEDLOG_ENTITY_FINGERPRINT = $fingerprint;", "blockedlog/class/blockedlog.class.php:1833|read|return getDolGlobalString(''BLOCKEDLOG_ENTITY_FINGERPRINT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_FOR_TAX_AUDITOR', 'string', NULL, 'blockedlog', 'Controls whether and to whom the blockedlog audit view is accessible for tax auditor purposes.', 'Read at blockedlog/lib/blockedlog.lib.php:487. The comments at lines 478–479 explain the two access modes: value ''1'' grants access to external users ($user->socid set), and value ''2'' grants access regardless of user type.', 'Setting to ''1'' allows external users to view the blockedlog for tax auditing. Setting to ''2'' allows any user type to access it. An unset or ''0'' value disables tax auditor access.', 'Must be an external user and BLOCKEDLOG_FOR_TAX_AUDITOR must be set to 1 OR BLOCKEDLOG_FOR_TAX_AUDITOR must be set to 2.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* Must be an external user and BLOCKEDLOG_FOR_TAX_AUDITOR must be set to 1 OR", "* BLOCKEDLOG_FOR_TAX_AUDITOR must be set to 2", "return (((getDolGlobalString(''BLOCKEDLOG_FOR_TAX_AUDITOR'') && $user->socid) || getDolGlobalString(''BLOCKEDLOG_FOR_TAX_AUDITOR'') == ''2'') ? 1 : 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_HMAC_KEY', 'string', NULL, 'core', 'Stores the HMAC secret key used to sign and verify blockedlog records.', 'Read at blockedlog/class/blockedlog.class.php:1579, install/upgrade2.php:5633, and core/modules/modBlockedLog.class.php:201. Written during upgrade at install/upgrade2.php:5638. The comment states it starts with ''BLOCKEDLOGHMAC....'' and is not stored as clear data but is decrypted at read time.', 'Changing or removing this key breaks HMAC verification of all existing blockedlog records, making the audit chain unverifiable.', 'BLOCKEDLOG_HMAC_KEY is a HMAC key starting with ''BLOCKEDLOGHMAC....'', but it is not stored as a clear data. It will be decrypted later.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:1578  // BLOCKEDLOG_HMAC_KEY is a HMAC key starting with ''BLOCKEDLOGHMAC....'', but it is not stored as a clear data. It will be decrypted later.", "install/upgrade2.php:5638|write|$result = dolibarr_set_const($db, ''BLOCKEDLOG_HMAC_KEY'', $hmac_secret_key, ''chaine'', 0, ''The secret key for HMAC used for blockedlog record'', 0);", "blockedlog/class/blockedlog.class.php:1579|read|$hmac_encoded_secret_key = getDolGlobalString(''BLOCKEDLOG_HMAC_KEY'');", "core/modules/modBlockedLog.class.php:201|read|$hmac_encoded_secret_key = getDolGlobalString(''BLOCKEDLOG_HMAC_KEY'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_LAST_RECORD_FINGERPRINT', 'string', NULL, 'blockedlog', 'Stores the fingerprint of the last record in the blockedlog chain for continuity verification.', 'Written at blockedlog/class/blockedlog.class.php:1830 with initial value ''0:none''. The check at line 1829 is commented out, suggesting this may have been auto-initialized in a prior version. Only two occurrences are present in the payload.', 'This value is managed automatically by the blockedlog system; manual alteration would break chain integrity.', 'String in format ''sequence:hash''. Initial value is ''0:none''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/class/blockedlog.class.php:1830|write|dolibarr_set_const($db, ''BLOCKEDLOG_LAST_RECORD_FINGERPRINT'', ''0:none'', ''chaine'', 0, ''Last record fingerprint'', $conf->entity);", "blockedlog/class/blockedlog.class.php:1829  /*if (!getDolGlobalString(''BLOCKEDLOG_LAST_RECORD_FINGERPRINT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_MAX_FOR_SHOWN_LINKS', 'bool', NULL, 'blockedlog', 'Sets the maximum number of linked records shown per blockedlog list entry.', 'Read at blockedlog/admin/blockedlog_list.php:130 with a default of 100. Only 1 occurrence.', 'Reducing this value limits the number of links rendered per log entry in the blockedlog admin list.', 'An integer; default is 100.', 0, 0, 'blockedlog/admin/blockedlog_list.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$MAXFORSHOWNLINKS = getDolGlobalInt(''BLOCKEDLOG_MAX_FOR_SHOWN_LINKS'', 100);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_MAX_LINES', 'string', NULL, 'blockedlog', 'Sets the maximum number of log lines processed or displayed in blockedlog list and archive pages.', 'Read at blockedlog/admin/blockedlog_list.php:129 and blockedlog/admin/blockedlog_archives.php:134, both with a default of 10000.', 'Reducing this value limits the number of log entries processed per request; increasing it allows more entries but may impact performance.', 'An integer; default is 10000.', 0, 0, 'blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_archives.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$MAXLINES = getDolGlobalInt(''BLOCKEDLOG_MAX_LINES'', 10000);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING', 'string', NULL, 'blockedlog', 'Controls the probability denominator for blockedlog tracking pings; lower values increase ping frequency.', 'Read at blockedlog/lib/blockedlog.lib.php:443 with a max cap of 10. The comment at line 442 states the probability is between 1/10 by default and 1/1 if set to 1. A separate line at lib:440 forces it to 1 to guarantee every call is tracked.', 'Setting to 1 forces a ping on every call; the default of 10 means roughly a 1/10 chance per call. Cannot be set lower than 1/10 per the code comment.', 'Integer 1–10; default 10. Comment: ''Probability will be between 1/10 by default and 1/1 if const BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING is set to 1. Can''t be lower than 1/10.''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Probability will be between 1/10 by default and 1/1 if const BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING is set to 1. Can''t be lower than 1/10.", "$conf->global->BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING = 1;\t\t// Force probability to 1", "$BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING = min(10, getDolGlobalInt(''BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING'', 10));", "//$BLOCKEDLOG_RANDOMRANGE_FOR_TRACKING = 1;\t// To force track at every call"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_ADDRESS', 'string', NULL, 'blockedlog', 'Stores the street address of the company used in blockedlog registration data.', 'Written via blockedlog/admin/registration.php:133 and read at line 421 as the default field value. Also consumed at main.inc.php:3887 as ''company_address'' in the ping payload, falling back to $mysoc->address.', 'Changing this value updates the company address transmitted in blockedlog registration payloads.', 'Any string address; falls back to $mysoc->address when not set.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_ADDRESS\", $company_address, ''chaine'', 0, '''', $conf->entity);", "''company_address'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_ADDRESS'', $mysoc->address),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_COUNTRY_CODE', 'string', NULL, 'blockedlog', 'Stores the company country code used for blockedlog chain registration.', 'Read in blockedlog/admin/registration.php:345 and 414 (with fallback to $mysoc->country_code), blockedlog/lib/blockedlog.lib.php:142, and main.inc.php:3891. Written via blockedlog/admin/registration.php:125.', 'Changing this value updates the country code sent in blockedlog registration payloads.', 'String. ISO country code (e.g. ''FR''). Defaults to $mysoc->country_code when absent.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/registration.php:345|read|''country_code'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_COUNTRY_CODE'', $mysoc->country_code),", "blockedlog/lib/blockedlog.lib.php:142|read|$companycountrycode = getDolGlobalString(''BLOCKEDLOG_REGISTRATION_COUNTRY_CODE'', $mysoc->country_code);", "blockedlog/admin/registration.php:125|write|$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_COUNTRY_CODE\", $company_country_code, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:3891|read|''country_code'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_COUNTRY_CODE'', $mysoc->country_code),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_EMAIL', 'string', NULL, 'blockedlog', 'Stores the company email address used for blockedlog chain registration.', 'Read in blockedlog/admin/registration.php:339 and 403 (with fallback to $mysoc->email), blockedlog/lib/blockedlog.lib.php:141, and main.inc.php:3885. Written via blockedlog/admin/registration.php:121.', 'Changing this value updates the contact email sent in blockedlog registration payloads.', 'String. Company email address. Defaults to $mysoc->email when absent.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/registration.php:339|read|''company_email'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_EMAIL'', $mysoc->email),", "blockedlog/lib/blockedlog.lib.php:141|read|$companyemail = getDolGlobalString(''BLOCKEDLOG_REGISTRATION_EMAIL'', $mysoc->email);", "blockedlog/admin/registration.php:121|write|$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_EMAIL\", $company_email, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:3885|read|''company_email'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_EMAIL'', $mysoc->email),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_IDPROF1', 'string', NULL, 'blockedlog', 'Stores the company''s first professional identifier used for blockedlog chain registration.', 'Read in blockedlog/admin/registration.php:340 and 410 (with fallback to $mysoc->idprof1), blockedlog/lib/blockedlog.lib.php:143, and main.inc.php:3886. Written via blockedlog/admin/registration.php:129.', 'Changing this value updates the professional identifier sent in blockedlog registration payloads.', 'String. First professional identifier (e.g. SIREN number). Defaults to $mysoc->idprof1 when absent.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/registration.php:340|read|''company_idprof1'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_IDPROF1'', $mysoc->idprof1),", "blockedlog/lib/blockedlog.lib.php:143|read|$companyidprof1 = getDolGlobalString(''BLOCKEDLOG_REGISTRATION_IDPROF1'', $mysoc->idprof1);", "blockedlog/admin/registration.php:129|write|$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_IDPROF1\", $company_idprof1, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:3886|read|''company_idprof1'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_IDPROF1'', $mysoc->idprof1),"]', 'high', NULL);
