INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_STATE', 'string', NULL, 'blockedlog', 'Stores the state/region ID of the company used in blockedlog registration data.', 'Written via blockedlog/admin/registration.php:137 and read at lines 333 and 431 to populate the state field in registration forms. Also read at main.inc.php:3888 as ''company_state'' in the ping payload, falling back to $mysoc->state.', 'Changing this value updates the company state transmitted in blockedlog registration payloads.', 'An integer state ID (as stored in llx_c_departements); falls back to $mysoc->state when not set.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_STATE\", $company_state, ''chaine'', 0, '''', $conf->entity);", "''company_state'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_STATE'', $mysoc->state),", "$company_state = getState(getDolGlobalInt(''BLOCKEDLOG_REGISTRATION_STATE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_TEL', 'string', NULL, 'blockedlog', 'Overrides the company telephone number used in blockedlog registration data with a custom value.', 'Stores a custom phone number for blockedlog registration, falling back to $mysoc->phone when not set. Referenced at blockedlog/lib/blockedlog.lib.php:144 in a commented-out line.', 'If set, the custom phone number would be used instead of the company''s default phone in registration payloads.', 'Any string phone number value.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["//$companytel = getDolGlobalString(''BLOCKEDLOG_REGISTRATION_TEL'', $mysoc->phone);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_TOWN', 'string', NULL, 'blockedlog', 'Stores the city/town of the company used in blockedlog registration data.', 'Written via blockedlog/admin/registration.php:145 and read at line 441 as the default field value. Also consumed at main.inc.php:3890 as ''company_town'' in the ping payload, falling back to $mysoc->town.', 'Changing this value updates the company town transmitted in blockedlog registration payloads.', 'Any string town name; falls back to $mysoc->town when not set.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_TOWN\", $company_town, ''chaine'', 0, '''', $conf->entity);", "''company_town'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_TOWN'', $mysoc->town),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_REGISTRATION_ZIP', 'string', NULL, 'blockedlog', 'Stores the postal/ZIP code of the company used in blockedlog registration data.', 'Written via blockedlog/admin/registration.php:141 and read at line 436 as the default field value. Also consumed at main.inc.php:3889 as ''company_zip'' in the ping payload, falling back to $mysoc->zip.', 'Changing this value updates the company ZIP code transmitted in blockedlog registration payloads.', 'Any string postal code; falls back to $mysoc->zip when not set.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/registration.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res = dolibarr_set_const($db, \"BLOCKEDLOG_REGISTRATION_ZIP\", $company_zip, ''chaine'', 0, '''', $conf->entity);", "''company_zip'' => getDolGlobalString(''BLOCKEDLOG_REGISTRATION_ZIP'', $mysoc->zip),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_SCAN_ALL_FOR_LOWERIDINERROR', 'string', NULL, 'blockedlog', 'When set, triggers a full scan of all blockedlog entries to detect records with IDs lower than an entry in error.', 'Checked at blockedlog/admin/blockedlog_list.php:417 only. Only 1 occurrence and no admin UI or comments explaining the exact behavior.', 'Enabling this constant activates an extended scan mode in the blockedlog list; exact behavior beyond triggering the branch is unclear from the single occurrence.', 'Boolean/truthy: non-empty enables the full scan.', 0, 0, 'blockedlog/admin/blockedlog_list.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''BLOCKEDLOG_SCAN_ALL_FOR_LOWERIDINERROR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BLOCKEDLOG_USE_REMOTE_AUTHORITY', 'bool', NULL, 'blockedlog', 'Enables verification of blockedlog entries against a remote authority URL.', 'Checked at blockedlog/admin/blockedlog.php:197 and at blockedlog_list.php:579 and 866 in conjunction with BLOCKEDLOG_AUTHORITY_URL. A commented-out block at blockedlog_archives.php:1289 also references it. Configurable via admin UI on those pages.', 'When enabled (and BLOCKEDLOG_AUTHORITY_URL is set), blockedlog list and archive pages attempt to verify log entries against the remote authority endpoint.', 'Boolean/truthy: non-empty enables remote authority verification.', 0, 0, 'blockedlog/admin/blockedlog.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_archives.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''BLOCKEDLOG_USE_REMOTE_AUTHORITY'')) {", "if (getDolGlobalString(''BLOCKEDLOG_USE_REMOTE_AUTHORITY'') && getDolGlobalString(''BLOCKEDLOG_AUTHORITY_URL'')) {", "/*if (getDolGlobalString(''BLOCKEDLOG_USE_REMOTE_AUTHORITY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_ADDON', 'string', NULL, 'bom', 'Selects the numbering module (add-on) used to generate reference numbers for Bills of Materials.', 'Stores the class name of the active BOM reference numbering add-on. Read in bom/class/bom.class.php:881-882 where the value is used as a filename and class name to instantiate the numbering module. Configurable via admin/bom.php.', 'Changing this value switches the numbering module used for new BOM references; existing references are unaffected.', 'String: name of a numbering module class (e.g. ''mod_bom_standard''). Must match an existing .php file in the BOM module.', 0, 0, 'admin/bom.php|admin/bom.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["bom/class/bom.class.php:868  *  defined into BOM_ADDON", "bom/class/bom.class.php:881|read|$file = getDolGlobalString(''BOM_ADDON'') . \".php\";", "bom/class/bom.class.php:882|read|$classname = getDolGlobalString(''BOM_ADDON'');", "admin/bom.php:148|write|dolibarr_set_const($db, \"BOM_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_ADDON_PDF', 'string', NULL, 'admin', 'Selects the PDF template module used to generate PDF documents for Bills of Materials.', 'Stores the name of the active PDF model for BOMs. Read in bom/class/bom.class.php:1331-1332 to select the PDF generation class. Configurable via admin/bom.php.', 'Changing this value switches the PDF template used when generating BOM documents; no effect on already-generated files.', 'String: name of a PDF model class available in the BOM module.', 0, 0, 'admin/bom.php|admin/bom.php|admin/bom.php|admin/bom.php|admin/bom.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["bom/class/bom.class.php:1331|read|} elseif (getDolGlobalString(''BOM_ADDON_PDF'')) {", "bom/class/bom.class.php:1332|read|$modele = getDolGlobalString(''BOM_ADDON_PDF'');", "admin/bom.php:133|write|if (dolibarr_set_const($db, \"BOM_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/bom.php:127|check|if (getDolGlobalString(''BOM_ADDON_PDF'') == \"$value\") {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path for ODT templates used in BOM document generation.', 'Read once in core/modules/bom/doc/doc_generic_bom_odt.modules.php at line 114. The trimmed value is used as the base path for locating ODT template files.', 'Setting this constant redirects ODT template lookup for BOM documents to the specified path; leaving it unset results in an empty path.', 'A directory path string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/bom/doc/doc_generic_bom_odt.modules.php:114|read|$odtPath = trim(getDolGlobalString(''BOM_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_ADVANCED_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the Advanced BOM module for bill-of-materials references.', 'Read in core/modules/bom/mod_bom_advanced.php at line 139 for mask-based reference generation, and at line 90 to populate the mask input field in the module''s configuration UI.', 'Changing this value alters the format of BOM reference numbers generated by the Advanced module; leaving it unset results in an empty mask.', 'Any valid mask string for BOM numbering.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/bom/mod_bom_advanced.php:139|read|$mask = getDolGlobalString(''BOM_ADVANCED_MASK'');", "core/modules/bom/mod_bom_advanced.php:90|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskBom\" value=\"''.getDolGlobalString(''BOM_ADVANCED_MASK'').''\">'', $tooltip, 1,"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_BOX_LAST_BOMS_SHOW_VALIDATE_USER', 'bool', NULL, 'core', 'Shows the user who validated each BOM in the last BOMs dashboard widget.', 'Checked in core/boxes/box_boms.php:130 to conditionally include the validator''s identity in the BOM box output.', 'Enabling this constant adds a ''validated by'' user column or field to the last-BOMs dashboard box.', 'Empty/not set = validator not shown; any truthy string = validator displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_boms.php:130|check|if (getDolGlobalString(''BOM_BOX_LAST_BOMS_SHOW_VALIDATE_USER'')) {"]', 'low', NULL);
