INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Defines the watermark text displayed on draft BOM PDF documents.', 'Configurable via the admin UI at admin/bom.php (written at line 151, displayed at line 534 as a text input). No occurrence in the PDF generation code is present in this payload.', 'Setting this to a non-empty string causes the specified text to appear as a watermark on draft BOM documents; clearing it removes the watermark.', 'string (watermark text); empty = no watermark', 0, 0, 'admin/bom.php|admin/bom.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/bom.php:151|write|$res = dolibarr_set_const($db, \"BOM_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "admin/bom.php:534|read|print ''<input class=\"flat minwidth200\" type=\"text\" name=\"BOM_DRAFT_WATERMARK\" value=\"''.dol_escape_htmltag(getDolGlobalString(''BOM_DRAFT_WATERMARK'')).''\">'';"]', 'medium', NULL);
