INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_MAX_VISIBLE_PHOTO', 'string', NULL, 'core', 'Sets the maximum number of Bill of Materials photos displayed in the BOM view, defaulting to 5.', 'Read as an integer in core/lib/functions.lib.php:3470 with a default of 5. No admin UI write detected.', 'Increasing this value shows more BOM photos simultaneously. Decreasing it limits the visible photo count.', 'Integer; default 5.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3470|read|$maxvisiblephotos = getDolGlobalInt(''BOM_MAX_VISIBLE_PHOTO'', 5);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_NODISPLAYIFNOPHOTO', 'string', NULL, 'core', 'Hides the BOM photo display area entirely when no photo is available.', 'Checked in core/lib/functions.lib.php:3477; the photo block is suppressed when no photos exist and this constant is set. No admin UI write detected.', 'Setting this constant removes the empty photo placeholder from BOM views. Without it, the photo area is shown even without an image.', 'Non-empty = hide photo area when no photo; absent/empty = always show photo area.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3477|check|if (getDolGlobalString(''BOM_NODISPLAYIFNOPHOTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_SHOW_ALL_BOM_BY_DEFAULT', 'bool', NULL, 'mrp', 'Controls whether all Bill of Materials (BOM) lines are expanded (shown) by default in BOM and MRP views.', 'Checked in mrp/tpl/originproductline.tpl.php and bom/tpl/objectline_view.tpl.php. When falsy, a closed-folder icon is shown and BOM lines are collapsed; when truthy, an open-folder icon is shown and all BOM lines are displayed. No admin UI is configured.', 'Enabling this constant causes BOM sub-lines to be expanded by default in the UI, improving visibility at the cost of a more cluttered display.', 'Truthy (non-empty / 1) = all BOM lines shown expanded by default; falsy (empty / 0) = BOM lines collapsed by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mrp/tpl/originproductline.tpl.php:76|read|print(!getDolGlobalString(''BOM_SHOW_ALL_BOM_BY_DEFAULT'') ? img_picto('''', ''folder'') : img_picto('''', ''folder-open''));", "bom/tpl/objectline_view.tpl.php:128|read|print(!getDolGlobalString(''BOM_SHOW_ALL_BOM_BY_DEFAULT'') ? img_picto('''', ''folder'') : img_picto('''', ''folder-open''));", "mrp/tpl/originproductline.tpl.php:146|check|if (!getDolGlobalString(''BOM_SHOW_ALL_BOM_BY_DEFAULT'')) {", "bom/tpl/objectline_view.tpl.php:308|check|if (!getDolGlobalString(''BOM_SHOW_ALL_BOM_BY_DEFAULT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_SUB_BOM', 'string', NULL, 'bom', 'Enables the use of sub-BOMs (nested Bills of Materials) within a BOM or Manufacturing Order.', 'Checked in admin/bom.php at line 479, mrp/class/mo.class.php at line 1785, and bom/ template files at lines 74 and 155. Also used in bom/bom_net_needs.php at line 245 for tree-view rendering of nested BOM needs.', 'When disabled, sub-BOM lines are hidden from BOM and MO line templates and the net-needs tree view is suppressed. Enabling it allows hierarchical BOM structures.', '0 or unset = sub-BOMs disabled; 1 = sub-BOMs enabled', 0, 0, 'admin/bom.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''BOM_SUB_BOM'')) {", "if (getDolGlobalString(''BOM_SUB_BOM'')) {", "if (getDolGlobalString(''BOM_SUB_BOM'') && $filtertype != 1) {", "if (getDolGlobalString(''BOM_SUB_BOM'')  && $action == ''treeview'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOM_USE_SEARCH_TO_SELECT', 'bool', NULL, 'admin', 'Enables the search-to-select (ajax combobox) mode for BOM selection dropdowns instead of a plain select.', 'Configurable via admin UI at admin/bom.php (written at line 157, displayed at line 504) and shown in admin/system/perf.php at lines 628 and 631. The combobox is activated in core/class/html.form.class.php:3070.', 'Enabling this activates an AJAX-powered search input for selecting BOMs, improving performance with large datasets; disabling it uses a plain dropdown.', 'string/int; truthy = use search-to-select; empty/not set = plain select', 0, 0, 'admin/bom.php|admin/system/perf.php|admin/system/perf.php|admin/bom.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/bom.php:157|write|$res = dolibarr_set_const($db, \"BOM_USE_SEARCH_TO_SELECT\", $bomsearch, ''chaine'', 0, '''', $conf->entity);", "admin/bom.php:504|read|print $form->selectarray(\"activate_BOM_USE_SEARCH_TO_SELECT\", $arrval, getDolGlobalString(\"BOM_USE_SEARCH_TO_SELECT\")).''</td>'';", "admin/system/perf.php:628|check|if (!getDolGlobalString(''BOM_USE_SEARCH_TO_SELECT'')) {", "core/class/html.form.class.php:3070|read|$out .= ajax_combobox($htmlname, $events, getDolGlobalInt(\"BOM_USE_SEARCH_TO_SELECT\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOOKCAL_AVAILABILITIES_ADDON', 'string', NULL, 'core', 'Selects the add-on module class used to generate availability reference numbers in the BookCal module.', 'Read in core/modules/modAi.class.php:331-332. When empty, defaults to ''mod_availabilities_standard''; otherwise uses the configured value as both the class name and the PHP file path under /core/modules/commande/.', 'Changing this constant switches the availability numbering add-on; an incorrect value will cause a missing-file error when generating availability references.', 'String module name, e.g. ''mod_availabilities_standard''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["''class''=>(empty($conf->global->BOOKCAL_AVAILABILITIES_ADDON) ? ''mod_availabilities_standard'' : $conf->global->BOOKCAL_AVAILABILITIES_ADDON),", "''path''=>\"/core/modules/commande/\".(empty($conf->global->BOOKCAL_AVAILABILITIES_ADDON) ? ''mod_availabilities_standard'' : $conf->global->BOOKCAL_AVAILABILITIES_ADDON).''.php''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOOKCAL_PUBLIC_INTERFACE_TOPIC', 'string', NULL, 'public', 'Sets the page title/topic displayed in the public BookCal (appointment booking) interface header.', 'Read at public/bookcal/index.php:151 as the topic argument to htmlPrintOnlineHeader(); falls back to the translated string ''BookCalSystem'' if unset. Referenced in bookcal/admin/setup.php:77 as a setup configuration constant.', 'If set, the public booking page header will display this custom topic string instead of the default translated label.', 'Any string; defaults to trans(''BookCalSystem'') if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["bookcal/admin/setup.php:77  // Setup conf BOOKCAL_PUBLIC_INTERFACE_TOPIC", "public/bookcal/index.php:151|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''BOOKCAL_PUBLIC_INTERFACE_TOPIC'', $langs->trans(\"BookCalSystem\")), ''BOOKCAL_PUBLIC_INTERFACE_IMAGE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOOKCAL_SECUREKEY', 'string', NULL, 'bookcal', 'Provides the secret key used to generate a secure hash for BookCal calendar public access URLs.', 'Read at bookcal/calendar_card.php:387; the value is combined with ''bookcal'' and the object ID then hashed with MD5 to produce $encodedsecurekey.', 'Changing this key invalidates any existing calendar public-access URLs; leaving it empty results in a hash derived from an empty key string.', 'Any string = used as the secret key component; empty = hash built from empty string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["bookcal/calendar_card.php:387|read|$encodedsecurekey = dol_hash(getDolGlobalString(''BOOKCAL_SECUREKEY'').''bookcal''.((int) $object->id), ''md5'');"]', 'low', NULL);
