INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BOOKMARKS_SHOW_IN_MENU', 'bool', NULL, 'bookmarks', 'Sets the maximum number of bookmark links displayed in the top navigation menu.', 'Written by bookmarks/admin/bookmark.php:54 and displayed as a text input at bookmarks/admin/bookmark.php:94. Read in bookmarks/bookmarks.lib.php:116 and :150 and core/bookmarks_page.php:113 as a loop limit: bookmarks are iterated while the count is below this value.', 'Setting a number limits the menu to that many bookmark entries; leaving it empty shows all bookmarks in the menu.', 'Integer string = maximum number of bookmarks shown in menu; empty/0 = no limit (all bookmarks shown).', 0, 0, 'bookmarks/admin/bookmark.php|bookmarks/admin/bookmark.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["bookmarks/admin/bookmark.php:54|write|$res = dolibarr_set_const($db, \"BOOKMARKS_SHOW_IN_MENU\", $showmenu, ''chaine'', 0, '''', $conf->entity);", "bookmarks/bookmarks.lib.php:116|read|while ((!getDolGlobalString(''BOOKMARKS_SHOW_IN_MENU'') || $i < getDolGlobalInt(''BOOKMARKS_SHOW_IN_MENU'')) && $obj = $db->fetch_object($resql)) {", "core/bookmarks_page.php:113|read|while ((!getDolGlobalString(''BOOKMARKS_SHOW_IN_MENU'') || $i < $conf->global->BOOKMARKS_SHOW_IN_MENU) && $obj = $db->fetch_object($resql)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('BUYPRICEHISTORY_PRODUCTFOURNISSEURPRICE_ADDON', 'string', NULL, 'product', 'Specifies the add-on class name used for buy-price history numbering on supplier product prices.', 'Checked and read in product/class/productfournisseurprice.class.php (lines 901, 905, 908, 909). If not set, the code writes the default value ''mod_productfournisseurprice_standard'' (line 902) before loading the class. The add-on filename is derived by appending ''.php'' to the constant value.', 'Changing this value to a custom add-on class name replaces the standard buy-price history numbering logic with the specified module.', 'String class name; default ''mod_productfournisseurprice_standard'' when not set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/class/productfournisseurprice.class.php:901|check|if (!getDolGlobalString(''BUYPRICEHISTORY_PRODUCTFOURNISSEURPRICE_ADDON'')) {", "product/class/productfournisseurprice.class.php:902|write|$conf->global->BUYPRICEHISTORY_PRODUCTFOURNISSEURPRICE_ADDON = ''mod_productfournisseurprice_standard'';", "product/class/productfournisseurprice.class.php:908|read|$file = getDolGlobalString(''BUYPRICEHISTORY_PRODUCTFOURNISSEURPRICE_ADDON'') . \".php\";", "product/class/productfournisseurprice.class.php:909|read|$classname = getDolGlobalString(''BUYPRICEHISTORY_PRODUCTFOURNISSEURPRICE_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CALENDAR_ADDON_PDF', 'string', NULL, 'bookcal', 'Specifies the PDF template module name used to generate documents for calendar records in BookCal.', 'Read at bookcal/class/calendar.class.php:979-980; when set, its value is assigned as the PDF model name for calendar document generation.', 'Setting this constant changes which PDF template is used for calendar documents; leaving it unset falls back to the default template.', 'Empty/unset = use default PDF model; a module name string = use that PDF template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["bookcal/class/calendar.class.php:979|read|} elseif (getDolGlobalString(''CALENDAR_ADDON_PDF'')) {", "bookcal/class/calendar.class.php:980|read|$modele = getDolGlobalString(''CALENDAR_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CANDIDATURE_ADDON', 'string', NULL, 'emailcollector', 'Selects the add-on module used to generate reference numbers for job candidature records.', 'Read in emailcollector/class/emailcollector.class.php:3806. Defaults to ''mod_candidature_simple'' when empty.', 'Changing this constant switches the candidature numbering module; an invalid value will cause a class-not-found error.', 'String module name, e.g. ''mod_candidature_simple''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$modele = empty($conf->global->CANDIDATURE_ADDON) ? ''mod_candidature_simple'' : $conf->global->CANDIDATURE_ADDON;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_FORCE_DECREASE_STOCK', 'string', NULL, 'takepos', 'Deprecated constant that formerly forced stock decrease on TakePOS sales; no longer functional.', 'Checked once at takepos/admin/terminal.php:359. The adjacent comment at line 358 reads: ''Deprecated: CASHDESK_FORCE_DECREASE_STOCK is now always false. No more required/used.'' Configurable via the admin UI at takepos/admin/terminal.php.', 'This constant has no effect on current behavior; it is retained only for backward compatibility and should not be set.', 'Deprecated — value has no effect', 0, 0, 'takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// Deprecated: CASHDESK_FORCE_DECREASE_STOCK is now always false. No more required/used.", "if (isModEnabled(''productbatch'') && getDolGlobalString(''CASHDESK_FORCE_DECREASE_STOCK'') && !getDolGlobalString(''CASHDESK_NO_DECREASE_STOCK''.$terminal)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_CASH', 'string', NULL, 'takepos', 'Stores the bank account ID used for cash payments at a TakePOS terminal (suffix is the terminal number, e.g., CASHDESK_ID_BANKACCOUNT_CASH1).', 'The suffixed form (CASHDESK_ID_BANKACCOUNT_CASH{N}) holds the bank account ID for terminal N. Written and read via takepos/admin/terminal.php (lines 94, 226, 228). Also checked in compta/cashcontrol/cashcontrol_card.php:206 and read in takepos/invoice.php:256 for backward compatibility.', 'Changing this value reassigns the cash bank account linked to a terminal; an unset or invalid value may prevent cash payment processing at that terminal.', 'Integer: ID of a bank account (type cash). Empty or 0 = no cash bank account configured for the terminal.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/terminal.php:94|write|$res = dolibarr_set_const($db, \"CASHDESK_ID_BANKACCOUNT_CASH\".$terminaltouse, ...", "takepos/invoice.php:256|read|$bankaccount = getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CASH''.$_SESSION[\"takeposterminal\"]);            // For backward compatibility", "compta/cashcontrol/cashcontrol_card.php:206|check|if (!getDolGlobalString(''CASHDESK_ID_BANKACCOUNT_CASH'') && !getDolGlobalString(''CASHDESK_ID_BANKACCOUNT_CASH1'')) {", "takepos/admin/terminal.php:226|read|print $form->select_comptes(getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CASH''.$terminaltouse), ''CASHDESK_ID_BANKACCOUNT_CASH''.$terminaltouse, 0, \"courant=2\", 1, '''', 0"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_CASH1', 'string', NULL, 'compta', 'Stores the bank account ID for cash payments at TakePOS terminal 1, used for legacy compatibility checks.', 'Checked in core/modules/modTakePos.class.php:331 and compta/cashcontrol/cashcontrol_card.php:206. Functionally equivalent to CASHDESK_ID_BANKACCOUNT_CASH with suffix 1; the generic CASHDESK_ID_BANKACCOUNT_CASH (no suffix) is also checked for backward compatibility.', 'If this constant is not set, the TakePOS module check at modTakePos.class.php:331 will trigger a warning or block activation.', 'Integer: ID of a cash bank account for terminal 1. Empty or 0 = not configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/modTakePos.class.php:331|check|if (!getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CASH1'')) {", "compta/cashcontrol/cashcontrol_card.php:206|check|if (!getDolGlobalString(''CASHDESK_ID_BANKACCOUNT_CASH'') && !getDolGlobalString(''CASHDESK_ID_BANKACCOUNT_CASH1'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_CB', 'string', NULL, 'takepos', 'ID of the bank account used for credit/debit card (CB) payments on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:100 and rendered as a bank account selector at terminal.php:244. Checked at terminal.php:246 to conditionally display the selected account.', 'Setting this to a valid bank account ID ensures card payments are recorded against the correct account.', 'Integer: ID of a Dolibarr bank account; empty = no account configured for card payments', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_BANKACCOUNT_CB\".$terminaltouse, (GETPOST(''CASHDESK_ID_BANKACCOUNT_CB''.$terminaltouse, ''alpha'') > 0 ? GETPOST(''CASHDESK_ID_BANKACCOUNT_CB", "print $form->select_comptes(getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CB''.$terminaltouse), ''CASHDESK_ID_BANKACCOUNT_CB''.$terminaltouse, 0, \"courant=1\", 1, '''', 0, ''maxwidth500 widthc", "if (getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CB''.$terminaltouse)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_CHEQUE', 'string', NULL, 'takepos', 'ID of the bank account used for cheque payments on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:97 and rendered as a bank account selector at terminal.php:235. Read in takepos/invoice.php:258 as `$bankaccount` for backward compatibility when recording cheque payments.', 'Setting this to a valid bank account ID ensures cheque payments are recorded against the correct account; leaving it empty may cause payment recording to fall back to a default.', 'Integer: ID of a Dolibarr bank account; empty = no account configured for cheque', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_BANKACCOUNT_CHEQUE\".$terminaltouse, (GETPOST(''CASHDESK_ID_BANKACCOUNT_CHEQUE''.$terminaltouse, ''alpha'') > 0 ? GETPOST(''CASHDESK_ID_BANKAC", "print $form->select_comptes(getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CHEQUE''.$terminaltouse), ''CASHDESK_ID_BANKACCOUNT_CHEQUE''.$terminaltouse, 0, \"courant=1\", 1, '''', 0, ''maxwidth50", "$bankaccount = getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_CHEQUE''.$_SESSION[\"takeposterminal\"]);    // For backward compatibility"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_STRIPETERMINAL', 'string', NULL, 'takepos', 'Stripe Terminal reader ID associated with a TakePOS terminal for card payments (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:103 and rendered as a select list of readers at terminal.php:284.', 'Setting this to a valid Stripe Terminal reader ID links that hardware reader to the POS terminal for card payment processing.', 'Stripe Terminal reader ID string; empty = no reader configured', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_BANKACCOUNT_STRIPETERMINAL\".$terminaltouse, GETPOST(''CASHDESK_ID_BANKACCOUNT_STRIPETERMINAL''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', ", "print $form->selectarray(''CASHDESK_ID_BANKACCOUNT_STRIPETERMINAL''.$terminaltouse, $reader, getDolGlobalString(''CASHDESK_ID_BANKACCOUNT_STRIPETERMINAL''.$terminaltouse));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_BANKACCOUNT_SUMUP', 'string', NULL, 'takepos', 'ID of the bank account used for SumUp payments on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:106 and rendered as a bank account selector at terminal.php:292. Checked at terminal.php:294 to conditionally display the selected account.', 'Setting this to a valid bank account ID ensures SumUp payments are recorded against the correct account.', 'Integer: ID of a Dolibarr bank account; empty = no account configured for SumUp', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_BANKACCOUNT_SUMUP\".$terminaltouse, (GETPOST(''CASHDESK_ID_BANKACCOUNT_SUMUP''.$terminaltouse, ''alpha'') > 0 ? GETPOST(''CASHDESK_ID_BANKACCO", "print $form->select_comptes(getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_SUMUP''.$terminaltouse), ''CASHDESK_ID_BANKACCOUNT_SUMUP''.$terminaltouse, 0, \"courant=1\", 1, '''', 0, ''maxwidth500 ", "if (getDolGlobalInt(''CASHDESK_ID_BANKACCOUNT_SUMUP''.$terminaltouse)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_PROJECT', 'string', NULL, 'takepos', 'ID of the project automatically linked to invoices created on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:91 and read at terminal.php:373 into `$projectid`. Used in takepos/invoice.php:186-187 to set `$invoice->fk_project` when the project module is enabled.', 'Setting this to a valid project ID causes all invoices generated on that terminal to be linked to that project; leaving it empty means no project association is made.', 'Integer: ID of a Dolibarr project; empty = no project linked', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_PROJECT\".$terminaltouse, (GETPOSTINT(''projectid'') > 0 ? GETPOSTINT(''projectid'') : ''''), ''chaine'', 0, '''', $conf->entity);", "if (isModEnabled(''project'') && getDolGlobalInt(\"CASHDESK_ID_PROJECT\".$takeposterminal)) {", "$invoice->fk_project = getDolGlobalInt(\"CASHDESK_ID_PROJECT\".$takeposterminal);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_THIRDPARTY', 'string', NULL, 'takepos', 'ID of the default third-party (customer) associated with a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:88 and displayed in a company selector at terminal.php:217. Read in takepos/receipt.php:247 and takepos/index.php:99 to load the default customer for the terminal session.', 'Changing this value reassigns the default customer used for POS sales on the corresponding terminal, affecting invoice creation and receipt display.', 'Integer: ID of a Dolibarr third-party record; empty = no default customer', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_THIRDPARTY\".$terminaltouse, (GETPOSTINT(''socid'') > 0 ? GETPOSTINT(''socid'') : ''''), ''chaine'', 0, '''', $conf->entity);", "if ($object->socid != getDolGlobalInt(''CASHDESK_ID_THIRDPARTY''.$_SESSION[\"takeposterminal\"])) {", "$socid = getDolGlobalInt(''CASHDESK_ID_THIRDPARTY'' . $term);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_THIRDPARTY1', 'string', NULL, 'core', 'Stores the ID of the default customer third-party record pre-configured in the TakePos setup.', 'Checked at core/modules/modTakePos.class.php:277 with the comment: If a customer has already been set into the TakePos setup page. No admin UI writes this constant in the payload; it appears to be set only through the TakePos setup workflow.', 'Setting this pre-assigns a default customer to the point-of-sale terminal; leaving it unset allows the cashier to select a customer at transaction time.', 'Integer ID of an existing third-party/customer record.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modTakePos.class.php:277|check|if (!getDolGlobalInt(''CASHDESK_ID_THIRDPARTY1'')) {\t// If a customer has already ben set into the TakePos setup page"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_ID_WAREHOUSE', 'string', NULL, 'takepos', 'ID of the warehouse used for stock movements on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:118 and rendered as a warehouse selector at terminal.php:351. Checked extensively in takepos/ajax/ajax.php (lines 126, 284, 310, 328, 339) to control stock availability checks and stock decrement operations.', 'Setting this to a valid warehouse ID enables stock tracking and decrements for sales on that terminal; without it, stock management for the terminal is disabled or uses defaults.', 'Integer: ID of a Dolibarr warehouse; empty = no warehouse configured', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"CASHDESK_ID_WAREHOUSE\".$terminaltouse, (GETPOST(''CASHDESK_ID_WAREHOUSE''.$terminaltouse, ''alpha'') > 0 ? GETPOST(''CASHDESK_ID_WAREHOUSE''.$terminaltous", "if ($prod->stock_warehouse[getDolGlobalString(''CASHDESK_ID_WAREHOUSE''.$_SESSION[''takeposterminal''])]->real <= 0) {", "if (getDolGlobalInt(''CASHDESK_ID_WAREHOUSE''.$_SESSION[''takeposterminal''])) {", "if (!$disabled && !getDolGlobalString(''CASHDESK_ID_WAREHOUSE''.$terminal)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_NO_DECREASE_STOCK', 'string', NULL, 'takepos', 'Disables automatic stock decrease at the POS terminal level when enabled.', 'Configured per-terminal via takepos/admin/terminal.php (UI write at line 121, with the terminal suffix appended). The value is also read globally in core/modules/modProductBatch.class.php:139 and written there (line 141). A commented-out yes/no selector at line 328 indicates the feature is partially exposed in the UI.', 'When set for a terminal, stock is not decremented upon POS sales for that terminal. When the ProductBatch module is activated, this constant may be auto-set.', 'Truthy value (e.g. 1) to disable stock decrease; 0 or empty to allow stock decrease.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/terminal.php:121|write|$res = dolibarr_set_const($db, \"CASHDESK_NO_DECREASE_STOCK\".$terminaltouse, GETPOST(''CASHDESK_NO_DECREASE_STOCK''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "core/modules/modProductBatch.class.php:139|check|if (!getDolGlobalString(''CASHDESK_NO_DECREASE_STOCK'')) {", "core/modules/modProductBatch.class.php:141|write|$res = dolibarr_set_const($db, \"CASHDESK_NO_DECREASE_STOCK\", 1, ''chaine'', 0, '''', $conf->entity);", "takepos/admin/terminal.php:333|read|$disabled = getDolGlobalInt(''CASHDESK_NO_DECREASE_STOCK''.$terminal);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_READER_KEYCODE_FOR_ENTER', 'string', NULL, 'takepos', 'Key code sent by the barcode reader to signal end-of-scan (Enter) on a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:143 and displayed as a text input at terminal.php:380. Read in takepos/index.php:177 into `$keyCodeForEnter` for use in the POS JavaScript barcode scanning logic.', 'Setting this to the correct key code for the barcode scanner''s end-of-scan signal ensures barcodes are correctly parsed; an incorrect value causes barcode scanning to malfunction.', 'Integer key code (e.g. 13 for Enter, or a scanner-specific code); 0 or absent = use default', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, ''CASHDESK_READER_KEYCODE_FOR_ENTER''.$terminaltouse, (GETPOSTINT(''CASHDESK_READER_KEYCODE_FOR_ENTER''.$terminaltouse) > 0 ? GETPOSTINT(''CASHDESK_READER", "$keyCodeForEnter = getDolGlobalInt(''CASHDESK_READER_KEYCODE_FOR_ENTER''.$_SESSION[''takeposterminal'']) > 0 ? getDolGlobalString(''CASHDESK_READER_KEYCODE_FOR_ENTER''.$_SESSION[''takepos", "print ''<input type=\"text\" class=\"width50\" name=\"CASHDESK_READER_KEYCODE_FOR_ENTER''.$terminaltouse.''\" value=\"''.getDolGlobalString(''CASHDESK_READER_KEYCODE_FOR_ENTER''.$terminaltouse)"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CASHDESK_SERVICES', 'string', NULL, 'takepos', 'Controls whether services are enabled in the TakePOS cash desk module (commented out in admin UI).', 'Referenced in takepos/admin/setup.php:298 inside a commented-out print statement for a yes/no selector. The setting exists in the admin UI file but the rendering line is disabled.', 'No active effect while commented out; if re-enabled, enabling this would allow service products to be used in TakePOS.', '1 = enabled, 0 = disabled (inferred from selectyesno usage).', 0, 0, 'takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["//print $form->selectyesno(\"CASHDESK_SERVICES\", $conf->global->CASHDESK_SERVICES, 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORIE_RECURSIV_ADD', 'string', NULL, 'categories', 'When enabled, adding a category also recursively adds all its parent categories.', 'Configured via the categories admin UI (categories/admin/categorie.php:112). Checked in categories/class/categorie.class.php:866 to trigger recursive parent-category addition when an object is assigned to a category.', 'Enabling this constant causes parent categories to be automatically added whenever a category is assigned. Disabling it limits assignment to the directly selected category only.', 'Truthy value to enable recursive parent-category addition; unset or 0 to disable.', 0, 0, 'categories/admin/categorie.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["categories/admin/categorie.php:112|check|if (!getDolGlobalString(''CATEGORIE_RECURSIV_ADD'')) {", "categories/class/categorie.class.php:866|check|if (getDolGlobalString(''CATEGORIE_RECURSIV_ADD'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_ADD_DESC_INTO_DOC', 'string', NULL, 'core', 'Appends the category description into document lines when the category module is enabled.', 'Checked in core/lib/pdf.lib.php:2187 only when a product ID exists and the category module is enabled. No admin UI write is present.', 'Enabling this injects category description text into PDF document lines for products with categories; disabling it omits this text.', 'truthy = add category description into documents; empty/not set = do not add', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2187|check|if (getDolGlobalString(''CATEGORY_ADD_DESC_INTO_DOC'') && $idprod && isModEnabled(''category'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_ASSIGNED_TO_A_CUSTOMER', 'string', NULL, 'categories', 'When enabled, restricts category association operations to categories belonging to a specific customer (thirdparty).', 'Checked in categories/class/categorie.class.php:593, :609, and :699 to filter or adjust category logic based on thirdparty assignment. The constant''s role is documented in the class property comment at line 289: ''Id of thirdparty when CATEGORY_ASSIGNED_TO_A_CUSTOMER is set''. No admin UI write path is present in the payload.', 'Enabling this constant activates thirdparty-scoped category filtering in the categorie class. Leaving it unset applies the default category association logic.', 'Truthy value (thirdparty ID or flag) to enable customer-scoped category filtering; unset or 0 for default behaviour.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["categories/class/categorie.class.php:289  * @var int\t\t  Id of thirdparty when CATEGORY_ASSIGNED_TO_A_CUSTOMER is set", "categories/class/categorie.class.php:593|check|if (getDolGlobalString(''CATEGORY_ASSIGNED_TO_A_CUSTOMER'')) {", "categories/class/categorie.class.php:609|check|if (getDolGlobalString(''CATEGORY_ASSIGNED_TO_A_CUSTOMER'')) {", "categories/class/categorie.class.php:699|check|if (getDolGlobalString(''CATEGORY_ASSIGNED_TO_A_CUSTOMER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_EDIT_IN_MENU_NOT_IN_POPUP', 'string', NULL, 'core', 'Controls whether category edit links in the Eldy menu open in a full page rather than a popup dialog.', 'Checked at 16+ locations in core/menus/standard/eldy.lib.php, always paired with isModEnabled(''category''). No admin UI write found; must be set manually.', 'When enabled, clicking category links navigates to a full edit page. When absent or empty, the default popup behavior is used.', 'Non-empty string = open in full page; absent/empty = open in popup.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:1267|check|if (isModEnabled(''category'') && getDolGlobalString(''CATEGORY_EDIT_IN_MENU_NOT_IN_POPUP'')) {", "core/menus/standard/eldy.lib.php:1352|check|if (getDolGlobalString(''CATEGORY_EDIT_IN_MENU_NOT_IN_POPUP'')) {", "core/menus/standard/eldy.lib.php:1377|check|if (isModEnabled(''category'') && getDolGlobalString(''CATEGORY_EDIT_IN_MENU_NOT_IN_POPUP'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_GRAPHSTATS_ON_PRODUCTS', 'string', NULL, 'product', 'Enables the category-based graph statistics block on the product index dashboard page.', 'Checked in product/index.php:250; when enabled and the category module is active and the user has category read rights, the graph stats block is rendered.', 'Enabling adds a category statistics graph to the product dashboard; disabling hides it.', 'Truthy value to enable category graph stats on products; absent or falsy to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/index.php:250|check|if (isModEnabled(''category'') && getDolGlobalString(''CATEGORY_GRAPHSTATS_ON_PRODUCTS'') && $user->hasRight(''categorie'', ''read'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_GRAPHSTATS_ON_THIRDPARTIES', 'string', NULL, 'societe', 'Specifies a category label (or numeric ID) for which a graph of thirdparties per category is displayed on the thirdparty dashboard.', 'Checked and read in societe/index.php:215, :226, :227. When set to a non-numeric value it is used as a label filter (LIKE match); when numeric it is used directly. The graph is only rendered when the category module is enabled and this constant is set.', 'Setting this to a category label or ID causes a thirdparty-count-by-category graph to appear on the societe dashboard. Leaving it unset suppresses the graph.', 'Category label string (for LIKE match) or numeric category ID.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/index.php:215|check|if (isModEnabled(''category'') && getDolGlobalString(''CATEGORY_GRAPHSTATS_ON_THIRDPARTIES'')) {", "societe/index.php:226|check|if (!is_numeric(getDolGlobalString(''CATEGORY_GRAPHSTATS_ON_THIRDPARTIES''))) {", "societe/index.php:227|read|$sql .= \" AND c.label like ''\".$db->escape(getDolGlobalString(''CATEGORY_GRAPHSTATS_ON_THIRDPARTIES'')).\"''\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_MAX_VISIBLE_PHOTO', 'string', NULL, 'core', 'Sets the maximum number of category photos displayed in the category view, defaulting to 5.', 'Read as an integer in core/lib/functions.lib.php:3449 with a default of 5. No admin UI write detected.', 'Increasing this value shows more category photos simultaneously. Decreasing it limits the visible photo count.', 'Integer; default 5.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3449|read|$maxvisiblephotos = getDolGlobalInt(''CATEGORY_MAX_VISIBLE_PHOTO'', 5);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_NODISPLAYIFNOPHOTO', 'string', NULL, 'core', 'Hides the category photo display area entirely when no photo is available.', 'Checked in core/lib/functions.lib.php:3456; the photo block is suppressed when no photos exist and this constant is set. No admin UI write detected.', 'Setting this constant removes the empty photo placeholder from category views. Without it, the photo area is rendered even without an image.', 'Non-empty = hide photo area when no photo; absent/empty = always show photo area.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3456|check|if (getDolGlobalString(''CATEGORY_NODISPLAYIFNOPHOTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_SHOW_COUNTS', 'bool', NULL, 'categories', 'When enabled, displays item counts alongside category entries in category list and view pages.', 'Checked in categories/categorie_list.php:391, :417 and categories/viewcat.php:460, :486 to conditionally render count columns or values next to category names. No admin UI write path is present in the payload.', 'Enabling this constant adds item counts to category listings and category view pages. Leaving it unset hides the count information.', 'Truthy value to show counts; unset or 0 to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["categories/categorie_list.php:391|check|if (getDolGlobalString(''CATEGORY_SHOW_COUNTS'')) {", "categories/categorie_list.php:417|check|if (getDolGlobalString(''CATEGORY_SHOW_COUNTS'')) {", "categories/viewcat.php:460|check|if (getDolGlobalString(''CATEGORY_SHOW_COUNTS'')) {", "categories/viewcat.php:486|check|if (getDolGlobalString(''CATEGORY_SHOW_COUNTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CATEGORY_USE_OTHER_FIELD_IN_TRANSLATION', 'bool', NULL, 'categories', 'When enabled, uses an alternative field for category translation display on the translation management page.', 'Checked in categories/traduction.php:320 to conditionally render an alternative field column in the category translation interface. No admin UI write path is present in the payload.', 'Enabling this constant causes the category translation page to display and use an alternative field for translations. Leaving it unset uses the default translation field.', 'Truthy value to use alternate field in translation; unset or 0 for default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["categories/traduction.php:320|check|if (getDolGlobalString(''CATEGORY_USE_OTHER_FIELD_IN_TRANSLATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CAT_HIGH_QUALITY_IMAGES', 'string', NULL, 'core', 'Forces PDF generators to use full-resolution product images instead of thumbnails.', 'Checked in 17 locations across expedition, reception, stocktransfer, commande, and facture PDF modules. Inline comment at core/modules/reception/doc/pdf_squille.modules.php:195 states: ''If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb if defined and then original photo''.', 'When not set, PDF generators prefer thumbnails if available and fall back to original. When enabled, full-resolution images are used directly in PDFs, increasing file size.', 'If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb if defined and then original photo; set to 1 to always use full-resolution images', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/reception/doc/pdf_squille.modules.php:195  // If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb if defined and then original photo", "core/modules/expedition/doc/pdf_rouget.modules.php:233  // If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb if defined and then original photo", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:241  // If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb if defined and then original photo", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:241|check|if (!getDolGlobalInt(''CAT_HIGH_QUALITY_IMAGES'')) {\t\t// If CAT_HIGH_QUALITY_IMAGES not defined, we use thumb"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CDAV_CONTACT_TAG', 'string', NULL, 'dav', 'Overrides the constant CDAV_CONTACT_TAG used to filter contacts exposed via CardDAV.', 'Checked at dav/dav.lib.php:27; if set, the PHP constant CDAV_CONTACT_TAG is defined with its value (dav/dav.lib.php:28). A code comment at line 25 notes: ''// define CDAV_CONTACT_TAG if not''.', 'Setting this value filters which contacts are exposed to CardDAV clients based on the specified tag.', 'String (contact tag name to filter CardDAV-exposed contacts); empty = constant not defined via this setting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dav/dav.lib.php:25  // define CDAV_CONTACT_TAG if not", "dav/dav.lib.php:27|check|if (getDolGlobalString(''CDAV_CONTACT_TAG'')) {", "dav/dav.lib.php:28|read|define(''CDAV_CONTACT_TAG'', getDolGlobalString(''CDAV_CONTACT_TAG''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CDAV_URI_KEY', 'string', NULL, 'dav', 'Overrides the constant CDAV_URI_KEY used as the key for building CalDAV/CardDAV URIs.', 'Checked at dav/dav.lib.php:36; if set, the PHP constant CDAV_URI_KEY is defined with its value (dav/dav.lib.php:37). A code comment at line 34 notes: ''// define CDAV_URI_KEY if not''.', 'Setting this value changes the key used for constructing DAV resource URIs.', 'String (key used to build DAV URIs); empty = constant not defined via this setting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dav/dav.lib.php:34  // define CDAV_URI_KEY if not", "dav/dav.lib.php:36|check|if (getDolGlobalString(''CDAV_URI_KEY'')) {", "dav/dav.lib.php:37|read|define(''CDAV_URI_KEY'', getDolGlobalString(''CDAV_URI_KEY''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CERTIFICATE_CRT', 'string', NULL, 'core', 'Stores the digital certificate (PEM string or path) used to cryptographically sign generated PDF documents.', 'Read across 6 occurrences in PDF generation modules; some fallback to a per-user value via getDolUserString (e.g. core/modules/facture/doc/pdf_octopus.modules.php:459 and pdf_sponge.modules.php:389). No admin UI write is present.', 'Setting this value enables digital signatures on PDFs; a per-user override takes precedence where getDolUserString is used.', 'String (PEM certificate content or file path); empty = no PDF signing.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:349|read|$cert = getDolGlobalString(''CERTIFICATE_CRT'');", "core/modules/facture/doc/pdf_octopus.modules.php:459|read|$cert = getDolUserString(''CERTIFICATE_CRT'', getDolGlobalString(''CERTIFICATE_CRT''));", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:299|read|$cert = !getDolGlobalString(''CERTIFICATE_CRT'') ? '''' : $conf->global->CERTIFICATE_CRT;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CERTIFICATE_CRT_PRIVATE', 'string', NULL, 'core', 'Stores the global private certificate used for electronic signing of invoice and asset PDFs.', 'Read in core/modules/facture/doc/pdf_octopus.modules.php at line 460, pdf_sponge.modules.php at line 390, and pdf_standard_asset.modules.php at line 264; in each case it is used as the default fallback when the per-user certificate (getDolUserString) is not set.', 'Setting this constant provides a global private certificate for PDF signing. A per-user certificate (CERTIFICATE_CRT_PRIVATE on the user record) takes precedence over this global value.', 'A PEM-encoded private certificate string; empty/unset = no global certificate (per-user certificate still applies if set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/doc/pdf_octopus.modules.php:460|read|$certprivate = getDolUserString(''CERTIFICATE_CRT_PRIVATE'', getDolGlobalString(''CERTIFICATE_CRT_PRIVATE''));", "core/modules/facture/doc/pdf_sponge.modules.php:390|read|$certprivate = getDolUserString(''CERTIFICATE_CRT_PRIVATE'', getDolGlobalString(''CERTIFICATE_CRT_PRIVATE''));", "core/modules/asset/doc/pdf_standard_asset.modules.php:264|read|$certprivate = getDolUserString(''CERTIFICATE_CRT_PRIVATE'', getDolGlobalString(''CERTIFICATE_CRT_PRIVATE''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CHARTOFACCOUNTS', 'string', NULL, 'accountancy', 'Stores the rowid of the active chart of accounts (accounting system) used throughout the accountancy module.', 'Configured via accountancy/admin/account.php:213. Read extensively: accountancy/admin/card.php lines 89, 146, 213 use it to query the accounting_system table; accountancy/admin/productaccount.php:328 and account.php:259 read it for the active plan comptable. Also read in asset/admin/setup.php:556.', 'Changing this value switches the entire chart of accounts used for account mapping, product accounting, and asset management.', 'Integer rowid referencing the llx_accounting_system table', 0, 0, 'accountancy/admin/card.php|accountancy/admin/card.php|accountancy/admin/card.php|accountancy/admin/productaccount.php|accountancy/admin/account.php|accountancy/admin/account.php|asset/admin/setup.php|accountancy/admin/account.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/account.php:213|write|if (!dolibarr_set_const($db, ''CHARTOFACCOUNTS'', $chartofaccounts, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/admin/card.php:89|read|$sql = \"SELECT pcg_version FROM \" . MAIN_DB_PREFIX . \"accounting_system WHERE rowid = \".((int) getDolGlobalInt(''CHARTOFACCOUNTS''));", "accountancy/admin/productaccount.php:328|read|$pcgverid = getDolGlobalString(''CHARTOFACCOUNTS'');", "accountancy/admin/account.php:259|read|$pcgver = getDolGlobalInt(''CHARTOFACCOUNTS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CHECKLASTVERSION_EXTERNALMODULE', 'string', NULL, 'admin', 'Triggers an automatic version check against an external source for all external modules when the admin module list is built.', 'The code comment warns: ''Setting CHECKLASTVERSION_EXTERNALMODULE to on is a bad practice to activate a check on an external access during the building of the admin page.'' (admin/modules.php:1026). The check fires for every external module when the constant is set (admin/modules.php:1025).', 'Enabling this constant causes an external network request per module during admin page rendering, which can significantly slow down the modules list. It is explicitly noted in the code as bad practice.', '0 or unset = no automatic version check; non-zero = version check triggered on page load for all external modules', 0, 0, 'admin/modules.php|admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1026  // Setting CHECKLASTVERSION_EXTERNALMODULE to on is a bad practice to activate a check on an external access during the building of the admin page.", "admin/modules.php:1025|check|if ($objMod->isCoreOrExternalModule() == ''external'' && ($action == ''checklastversion'' || getDolGlobalString(''CHECKLASTVERSION_EXTERNALMODULE''))) {", "admin/modules.php:416|read|$checkOldValue = getDolGlobalInt(''CHECKLASTVERSION_EXTERNALMODULE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CHEQUERECEIPTS_ADDON', 'string', NULL, 'compta', 'Specifies the active numbering module (addon) used to generate cheque receipt reference numbers.', 'Configured via admin/chequereceipts.php which reads, writes, and validates the value. If not set, the code defaults to ''mod_chequereceipts_mint.php'' (admin/chequereceipts.php:58). The class name is loaded at runtime from this constant (compta/paiement/cheque/class/remisecheque.class.php:449).', 'Changing this constant switches the numbering module for cheque receipts; an invalid or missing module name will cause reference generation to fail.', 'String filename of the numbering module (e.g. ''mod_chequereceipts_mint''); defaults to ''mod_chequereceipts_mint.php''', 0, 0, 'admin/chequereceipts.php|admin/chequereceipts.php|admin/chequereceipts.php|admin/chequereceipts.php|admin/chequereceipts.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!getDolGlobalString(''CHEQUERECEIPTS_ADDON'')) {", "$conf->global->CHEQUERECEIPTS_ADDON = ''mod_chequereceipts_mint.php'';", "dolibarr_set_const($db, \"CHEQUERECEIPTS_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "$classname = getDolGlobalString(''CHEQUERECEIPTS_ADDON'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CHEQUERECEIPTS_THYME_MASK', 'string', NULL, 'core', 'Stores the numbering mask used by the Thyme cheque receipt numbering module.', 'Read in mod_chequereceipt_thyme.php at lines 84 (UI display) and 136 (mask retrieval for reference generation). No dolibarr_set_const write is present in the payload.', 'Changing this mask alters how new cheque receipt reference numbers are generated by the Thyme module.', 'A mask pattern string; empty = no mask.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_chequereceipt_thyme.php:84|read|value=''...getDolGlobalString(''CHEQUERECEIPTS_THYME_MASK'')...", "mod_chequereceipt_thyme.php:136|read|$mask = getDolGlobalString(''CHEQUERECEIPTS_THYME_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CHEQUERECEIPT_ADDON_PDF', 'string', NULL, 'core', 'Specifies the PDF template module to use for generating cheque receipt documents.', 'When set, its value is read at core/modules/cheque/modules_chequereceipts.php:152 to select the PDF generation module. If unset, the default module selection logic applies.', 'Changing this switches the PDF layout used for cheque receipts; removing it reverts to the default module.', 'String name of the PDF module class for cheque receipts.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/cheque/modules_chequereceipts.php:151|check|if (getDolGlobalString(''CHEQUERECEIPT_ADDON_PDF'')) {", "core/modules/cheque/modules_chequereceipts.php:152|read|$modele = getDolGlobalString(''CHEQUERECEIPT_ADDON_PDF'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CKEDITOR_NATIVE_SPELLCHECKER', 'string', NULL, 'core', 'Controls whether the CKEditor native browser spell checker is enabled or disabled.', 'Read at core/class/doleditor.class.php:323; when set, disableNativeSpellChecker is set to ''false'' (enabling native spell check), otherwise ''true'' (disabling it). No admin UI; hidden setting.', 'Setting to a truthy value enables the browser''s native spell checking within CKEditor. Leaving unset disables native spell checking.', '0 or empty = native spell checker disabled (disableNativeSpellChecker: true); non-empty = native spell checker enabled (disableNativeSpellChecker: false)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:323|read|disableNativeSpellChecker: ''.(getDolGlobalString(''CKEDITOR_NATIVE_SPELLCHECKER'') ? ''false'' : ''true'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CLICKTODIAL_DO_NOT_USE_AJAX_CALL', 'bool', NULL, 'core', 'Disables AJAX for Click-to-Dial calls, falling back to a direct (non-asynchronous) request instead.', 'Checked with negation in core/lib/functions.lib.php:5087; AJAX is used only when this constant is absent or empty. No admin UI write detected.', 'Setting this constant forces Click-to-Dial to use a synchronous request instead of AJAX. Without it, calls are initiated via AJAX.', 'Non-empty = AJAX disabled (use direct call); absent/empty = AJAX used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5087|check|if (!getDolGlobalString(''CLICKTODIAL_DO_NOT_USE_AJAX_CALL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CLICKTODIAL_FORCENEWTARGET', 'string', NULL, 'core', 'Forces Click-to-Dial links to open in a new browser tab or window.', 'Checked in core/lib/functions.lib.php:5094; when set, link target is overridden to open a new window. No admin UI write detected.', 'Setting this constant causes Click-to-Dial URLs to open in a new tab. Without it, the default link behavior is used.', 'Non-empty = open in new tab/window; absent/empty = default target.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5094|check|if (getDolGlobalString(''CLICKTODIAL_FORCENEWTARGET'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CLICKTODIAL_KEY_FOR_CIDLOOKUP', 'string', NULL, 'admin', 'Security key required to authenticate external CID (Caller ID) lookup requests to the Dolibarr public click-to-dial endpoint.', 'Written via admin/clicktodial.php:62 and displayed as a text input at clicktodial.php:154. The public endpoint public/clicktodial/cidlookup.php:80 rejects requests where the submitted securitykey does not match this constant. The admin page also shows the full lookup URL incorporating this key.', 'If this key is absent or does not match the incoming request, the CID lookup endpoint returns an authentication error, preventing external phone systems from resolving caller IDs.', 'Any string (acts as a shared secret/token for the CID lookup URL)', 0, 0, 'admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$url = $urlwithroot.''/public/clicktodial/cidlookup.php?securitykey=''.getDolGlobalString(''CLICKTODIAL_KEY_FOR_CIDLOOKUP'', ''ValueToDefine'').''&phone=...'';", "$result3 = dolibarr_set_const($db, \"CLICKTODIAL_KEY_FOR_CIDLOOKUP\", GETPOST(\"CLICKTODIAL_KEY_FOR_CIDLOOKUP\"), ''chaine'', 0, '''', $conf->entity);", "if ($securitykey != getDolGlobalString(''CLICKTODIAL_KEY_FOR_CIDLOOKUP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CLICKTODIAL_URL', 'string', NULL, 'admin', 'Defines the Click-to-Dial URL template used to initiate calls, supporting placeholders for login, password, extension, and phone number.', 'Set via dolibarr_set_const in admin/clicktodial.php:61, read in core/lib/functions.lib.php:5069 with error fallback ''ErrorClickToDialModuleNotConfigured''. Validated in admin/clicktodial.php:169-191 for placeholder consistency. Has a full admin UI at admin/clicktodial.php.', 'Changing this URL alters the endpoint called when a user clicks a phone number. Incorrect or missing placeholders (__LOGIN__, __PASSWORD__, __PHONEFROM__) trigger warnings in the admin UI.', 'URL string with optional placeholders: __LOGIN__, __PASSWORD__, __PHONEFROM__, and phone number placeholder. Default fallback: ''ErrorClickToDialModuleNotConfigured''.', 0, 0, 'admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/clicktodial.php:61|write|$result2 = dolibarr_set_const($db, \"CLICKTODIAL_URL\", GETPOST(\"CLICKTODIAL_URL\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/functions.lib.php:5069|read|$urlmask = getDolGlobalString(''CLICKTODIAL_URL'', ''ErrorClickToDialModuleNotConfigured'');", "admin/clicktodial.php:185|check|if (preg_match(''/__LOGIN__/'', getDolGlobalString(''CLICKTODIAL_URL'')) && empty($user->clicktodial_login)) {", "user/clicktodial.php:151|check|if (!getDolGlobalString(''CLICKTODIAL_URL'') && empty($object->clicktodial_url)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS', 'bool', NULL, 'admin', 'Switches phone number display to use native ''tel:'' links instead of the Click-to-Dial URL mechanism.', 'Set via dolibarr_set_const in admin/clicktodial.php:60 and read in admin/clicktodial.php:104 as a yes/no select. Also checked in core/lib/functions.lib.php:5060 as an OR condition alongside browser phone layout detection.', 'Enabling this renders phone numbers as standard tel: HTML links, which triggers the OS dialer on mobile devices. Disabling it uses the Click-to-Dial URL template instead.', '1 = use tel: links; 0 or absent = use Click-to-Dial URL.', 0, 0, 'admin/clicktodial.php|admin/clicktodial.php|admin/clicktodial.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/clicktodial.php:60|write|$result1 = dolibarr_set_const($db, \"CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS\", GETPOST(\"CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS\"), ''chaine'', 0, '''', $conf->entity);", "admin/clicktodial.php:104|read|print $form->selectyesno(\"CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS\", getDolGlobalString(''CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS''), 1).''<br>'';", "core/lib/functions.lib.php:5060|check|if ($addlink == ''tel'' || $conf->browser->layout == ''phone'' || (isModEnabled(''clicktodial'') && getDolGlobalString(''CLICKTODIAL_USE_TEL_LINK_ON_PHONE_NUMBERS''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_ADDON', 'string', NULL, 'commande', 'Specifies the numbering module class used to generate customer order reference numbers.', 'Documented in commande/class/commande.class.php:455 as: defined into COMMANDE_ADDON. Written via admin/order.php:156; read in commande/class/commande.class.php:469 to instantiate the class. Default is ''mod_commande_marbre'' as referenced in core/modules/modCommande.class.php:363.', 'Changing this switches the order reference numbering logic to a different module class; removing it causes the system to use the default ''mod_commande_marbre'' module.', 'String class name of the order numbering module; default ''mod_commande_marbre''.', 0, 0, 'admin/order.php|admin/order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:455  *  defined into COMMANDE_ADDON", "admin/order.php:156|write|dolibarr_set_const($db, \"COMMANDE_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "core/modules/modCommande.class.php:363|read|''class'' => getDolGlobalString(''COMMANDE_ADDON'', ''mod_commande_marbre''),", "commande/class/commande.class.php:469|read|$classname = getDolGlobalString(''COMMANDE_ADDON'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the name of the PDF generation module to use by default for sales order documents.', 'Written in admin/order.php:141 and read in commande/class/commande.class.php:4228-4229 to select the PDF module, and in commande/card.php:2506 as the pre-selected template. Configurable via admin/order.php.', 'Changing this value switches the default PDF template used for sales order generation. Removing it falls back to the system default.', 'String name of the PDF module (e.g. ''einstein''); empty = use system default', 0, 0, 'admin/order.php|admin/order.php|admin/order.php|admin/order.php|admin/order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/order.php:141|write|if (dolibarr_set_const($db, \"COMMANDE_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "commande/class/commande.class.php:4228|read|} elseif (getDolGlobalString(''COMMANDE_ADDON_PDF'')) {", "commande/class/commande.class.php:4229|read|$modele = getDolGlobalString(''COMMANDE_ADDON_PDF'');", "commande/card.php:2506|read|$preselected = getDolGlobalString(''COMMANDE_ADDON_PDF'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Stores the filesystem path to the directory containing ODT template files for order document generation.', 'Used in core/modules/commande/doc/doc_generic_order_odt.modules.php:120 where it is read and trimmed to resolve the ODT template path. The COMMENTS in the payload cite core/class/commondocgenerator.class.php:82 which documents this as the constant to use to scan ODT files.', 'Setting this to a valid directory path allows the ODT-based order document generator to locate custom templates. An empty or invalid path causes the generator to fall back to its default template location.', 'Any non-empty string = filesystem path to the ODT templates directory; empty/unset = default path used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["doc_generic_order_odt.modules.php:120|$odtPath = trim(getDolGlobalString(''COMMANDE_ADDON_PDF_ODT_PATH''));", "commondocgenerator.class.php:82|* @var string\tThe name of constant to use to scan ODT files (Example: ''COMMANDE_ADDON_PDF_ODT_PATH'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_DISABLE_ADD_INTERVENTION', 'bool', NULL, 'commande', 'Disables the action to create a linked intervention from a customer order card.', 'Checked via getDolGlobalInt in commande/card.php:3550. When non-zero, the ''add intervention'' button is hidden. No admin UI write is present.', 'Setting this constant removes the intervention creation action from the customer order UI. Leaving it unset (or zero) keeps the action available.', 'Non-zero integer = intervention creation action hidden; 0 or unset = action shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3550|check|if (!getDolGlobalInt(''COMMANDE_DISABLE_ADD_INTERVENTION'')) {"]', 'low', NULL);
