INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_DRAFT_WATERMARK', 'string', NULL, 'core', 'Stores the watermark text to overlay on draft sales order PDFs.', 'Configurable via the admin UI at admin/order.php. When a sales order is in draft status and this constant is set, its value is used as the watermark in pdf_einstein.modules.php and pdf_eratosthene.modules.php, and also referenced (currently commented out) in delivery and supplier order PDF modules. The COMMENTS in the payload show commented-out usage in pdf_vinci, pdf_muscadet, pdf_zenith, and pdf_cornas.', 'Setting a non-empty value causes draft order PDFs to display the specified watermark text. Clearing the value removes the watermark from draft PDFs.', 'Any non-empty string = watermark text displayed on draft order PDFs; empty/unset = no watermark.', 0, 0, 'admin/order.php|admin/order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/order.php:159|$res = dolibarr_set_const($db, \"COMMANDE_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "pdf_einstein.modules.php:201|if ($object->statut == $object::STATUS_DRAFT && getDolGlobalString(''COMMANDE_DRAFT_WATERMARK'')) {", "pdf_storm.modules.php:707|if ($object->statut == 0 && getDolGlobalString(''COMMANDE_DRAFT_WATERMARK'')) {", "/*if($object->statut==0 && getDolGlobalString(''COMMANDE_DRAFT_WATERMARK''))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_EMAIL_SENDER', 'string', NULL, 'core', 'Overrides the From email address when sending customer order emails.', 'Checked in core/tpl/card_presend.tpl.php:195 for the ''commande'' element. When set, frommail is replaced with this value (line 196).', 'Setting this causes the From address on customer order emails to be replaced with the configured address.', 'Empty/not set = default sender used; email address string = used as From address for customer order emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:195|check|if ($object->element === ''commande'' && getDolGlobalString(''COMMANDE_EMAIL_SENDER'')) {", "core/tpl/card_presend.tpl.php:196|read|$formmail->frommail = getDolGlobalString(''COMMANDE_EMAIL_SENDER'');"]', 'low', NULL);
