INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_SENDBYEMAIL_FOR_ALL_STATUS', 'string', NULL, 'commande', 'Enables the ''Send by email'' action on orders regardless of their status.', 'Checked in commande/card.php:3483. Without this constant, the send-by-email button is only shown for orders with status greater than draft. No admin UI write is present.', 'Setting this constant makes the email action available on draft orders as well as validated/processed ones. Leaving it unset restricts email sending to non-draft orders.', 'Truthy = email action available for all statuses including draft; falsy or unset = only for post-draft statuses.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3483|check|if ($object->status > Commande::STATUS_DRAFT || getDolGlobalString(''COMMANDE_SENDBYEMAIL_FOR_ALL_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_SUPPLIER_ADDON_NUMBER', 'string', NULL, 'core', 'Specifies the numbering module class name used to generate supplier order reference numbers.', 'Set via admin/supplier_order.php:164 and read at fourn/class/fournisseur.commande.class.php:1166 to instantiate the numbering class. The comment at :1152 states: ''numbering model defined within COMMANDE_SUPPLIER_ADDON_NUMBER''. Defaults to ''mod_commande_fournisseur_muguet'' when not set (core/modules/modFournisseur.class.php:868).', 'Changing this value switches the supplier order reference numbering scheme to the specified module class; an invalid class name breaks number generation.', 'Not set = uses default ''mod_commande_fournisseur_muguet'' module; string = class name of the numbering module to use.', 0, 0, 'admin/supplier_order.php|admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:1152  *  numbering model defined within COMMANDE_SUPPLIER_ADDON_NUMBER", "fourn/class/fournisseur.commande.class.php:1166|read|$classname = getDolGlobalString(''COMMANDE_SUPPLIER_ADDON_NUMBER'');", "core/modules/modFournisseur.class.php:868|read|''class'' => (!getDolGlobalString(''COMMANDE_SUPPLIER_ADDON_NUMBER'') ? ''mod_commande_fournisseur_muguet'' : $conf->global->COMMANDE_SUPPLIER_ADDON_NUMBER),", "admin/supplier_order.php:164|write|dolibarr_set_const($db, \"COMMANDE_SUPPLIER_ADDON_NUMBER\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMMANDE_SUPPLIER_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF generation module used to produce supplier order documents.', 'Configured via admin/supplier_order.php (multiple write operations at lines 147, 150, 142, 159) and checked/read in fourn/commande/card.php:3129 to determine which PDF model to use: ''$modelpdf = (!empty($object->model_pdf) ? $object->model_pdf : (!getDolGlobalString(''COMMANDE_SUPPLIER_ADDON_PDF'') ? '''' : $conf->global->COMMANDE_SUPPLIER_ADDON_PDF))''.', 'Changing this value switches the PDF template used for supplier order documents; leaving it empty disables the default PDF template selection.', 'Not set or empty = no default PDF model configured; string = name of the PDF module class to use for supplier orders.', 0, 0, 'admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:3129|check|$modelpdf = (!empty($object->model_pdf) ? $object->model_pdf : (!getDolGlobalString(''COMMANDE_SUPPLIER_ADDON_PDF'') ? '''' : $conf->global->COMMANDE_SUPPLIER_ADDON_PDF));", "admin/supplier_order.php:147|write|if (dolibarr_set_const($db, \"COMMANDE_SUPPLIER_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/supplier_order.php:433|check|if (getDolGlobalString(''COMMANDE_SUPPLIER_ADDON_PDF'') == \"$name\") {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ADDON_PDF', 'string', NULL, 'societe', 'Specifies the PDF template module name used to generate company (third-party) PDF documents.', 'Written in societe/admin/societe.php:162 via dolibarr_set_const. Read in societe/class/societe.class.php:5479 to set the active PDF model. Checked in core/tpl/card_presend.tpl.php:136 to handle the case where no model is defined.', 'If unset, the presend card template handles the missing-model case. When set, the named PDF module is used to generate company documents.', 'Name of the PDF addon module (e.g. a class name string); empty means no model selected.', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:162|write|dolibarr_set_const($db, \"COMPANY_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity);", "societe/class/societe.class.php:5479|read|$modele = getDolGlobalString(''COMPANY_ADDON_PDF'');", "core/tpl/card_presend.tpl.php:136|check|if ($object->element == ''societe'' && !getDolGlobalString(''COMPANY_ADDON_PDF'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) to scan for ODT templates used in company/third-party document generation.', 'Read in core/modules/societe/doc/doc_generic_odt.modules.php. Per the code comment in core/lib/functions2.lib.php: ''with the constant that contains list of directories to scan (COMPANY_ADDON_PDF_ODT_PATH, ...)''. The value is split on commas/newlines to build a directory list.', 'Changing this value redirects ODT template discovery for company documents to the specified directories; leaving it unset skips custom template directory scanning.', 'Comma- or newline-separated list of directory paths.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/functions2.lib.php:1897  // with the constant that contains list of directories to scan (COMPANY_ADDON_PDF_ODT_PATH, ...).", "core/modules/societe/doc/doc_generic_odt.modules.php:117|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''COMPANY_ADDON_PDF_ODT_PATH''))));", "core/modules/societe/doc/doc_generic_odt.modules.php:163|check|if (getDolGlobalString(''COMPANY_ADDON_PDF_ODT_PATH'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_CLEAN_REGEX', 'string', NULL, 'core', 'Defines a regex pattern applied to accountancy codes in the Aquarium module to extract and keep only captured groups.', 'Used in core/modules/societe/mod_codecompta_aquarium.php. Per the code comments: ''Apply a regex replacement pattern on code if COMPANY_AQUARIUM_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed.'' Example in code: ''^..(..)..''.', 'Setting this constant applies a preg_replace transformation to generated codes, retaining only the portions matched by capturing groups; leaving it unset skips this transformation.', 'Apply a regex replacement pattern on code if COMPANY_AQUARIUM_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed. Example: $conf->global->COMPANY_AQUARIUM_CLEAN_REGEX=''^..(..)..'';', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:197  // Apply a regex replacement pattern on code if COMPANY_AQUARIUM_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed.", "core/modules/societe/mod_codecompta_aquarium.php:187  //$conf->global->COMPANY_AQUARIUM_CLEAN_REGEX=''^..(..)..'';", "core/modules/societe/mod_codecompta_aquarium.php:198|check|if (getDolGlobalString(''COMPANY_AQUARIUM_CLEAN_REGEX'')) {\t// Example: $conf->global->COMPANY_AQUARIUM_CLEAN_REGEX=''^..(..)..'';", "core/modules/societe/mod_codecompta_aquarium.php:199|read|$codetouse = preg_replace(''/'' . getDolGlobalString(''COMPANY_AQUARIUM_CLEAN_REGEX'').''/'', ''\\1\\2\\3'', (string) $codetouse);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_MASK_CUSTOMER', 'string', NULL, 'core', 'Defines the accountancy code prefix used for customers in the Aquarium module.', 'Used in core/modules/societe/mod_codecompta_aquarium.php. If unset or empty, defaults to ''411''. The value is assigned to prefixcustomeraccountancycode and used when building customer accountancy codes.', 'Changing this value alters the prefix prepended to customer accountancy codes generated by the Aquarium module; the default fallback is ''411''.', 'Numeric string (e.g. ''411''); defaults to ''411'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:75|read|if (!isset($conf->global->COMPANY_AQUARIUM_MASK_CUSTOMER) || trim($conf->global->COMPANY_AQUARIUM_MASK_CUSTOMER) == '''') {", "core/modules/societe/mod_codecompta_aquarium.php:76|write|$conf->global->COMPANY_AQUARIUM_MASK_CUSTOMER = ''411'';", "core/modules/societe/mod_codecompta_aquarium.php:86|read|$this->prefixcustomeraccountancycode = getDolGlobalString(''COMPANY_AQUARIUM_MASK_CUSTOMER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_MASK_SUPPLIER', 'string', NULL, 'core', 'Defines the accountancy code prefix used for suppliers in the Aquarium module.', 'Used in core/modules/societe/mod_codecompta_aquarium.php. If unset or empty, defaults to ''401''. The value is assigned to prefixsupplieraccountancycode and used when building supplier accountancy codes.', 'Changing this value alters the prefix prepended to supplier accountancy codes generated by the Aquarium module; the default fallback is ''401''.', 'Numeric string (e.g. ''401''); defaults to ''401'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:78|read|if (!isset($conf->global->COMPANY_AQUARIUM_MASK_SUPPLIER) || trim($conf->global->COMPANY_AQUARIUM_MASK_SUPPLIER) == '''') {", "core/modules/societe/mod_codecompta_aquarium.php:79|write|$conf->global->COMPANY_AQUARIUM_MASK_SUPPLIER = ''401'';", "core/modules/societe/mod_codecompta_aquarium.php:87|read|$this->prefixsupplieraccountancycode = getDolGlobalString(''COMPANY_AQUARIUM_MASK_SUPPLIER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_NO_PREFIX', 'string', NULL, 'core', 'Controls whether the Aquarium accountancy code module omits the prefix when generating company codes.', 'Used exclusively in core/modules/societe/mod_codecompta_aquarium.php. When set, the prefix step is skipped during accountancy code generation. The value is also displayed in the module''s info text output.', 'Enabling this constant causes the Aquarium module to generate accountancy codes without a prefix; disabling or unsetting it restores prefix-based code generation.', 'Any truthy string to enable; empty or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:82|check|if (getDolGlobalString(''COMPANY_AQUARIUM_NO_PREFIX'')) {", "core/modules/societe/mod_codecompta_aquarium.php:127|check|if (getDolGlobalString(''COMPANY_AQUARIUM_NO_PREFIX'')) {", "core/modules/societe/mod_codecompta_aquarium.php:128|read|$texte .= $langs->trans(''COMPANY_AQUARIUM_NO_PREFIX'').'' = '' . getDolGlobalString(''COMPANY_AQUARIUM_NO_PREFIX'').\"<br>\\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_REMOVE_ALPHA', 'string', NULL, 'core', 'Controls whether alphabetic characters are stripped from accountancy codes in the Aquarium module.', 'Used in core/modules/societe/mod_codecompta_aquarium.php. Per the code comment: ''Remove special alpha if COMPANY_AQUARIUM_REMOVE_ALPHA is set to 1''. Only one occurrence in the codebase.', 'Setting this to 1 activates removal of alphabetic characters from generated accountancy codes in the Aquarium module.', 'Remove special alpha if COMPANY_AQUARIUM_REMOVE_ALPHA is set to 1', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:193  // Remove special alpha if COMPANY_AQUARIUM_REMOVE_ALPHA is set to 1", "core/modules/societe/mod_codecompta_aquarium.php:194|check|if (getDolGlobalString(''COMPANY_AQUARIUM_REMOVE_ALPHA'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_AQUARIUM_REMOVE_SPECIAL', 'string', NULL, 'core', 'Controls whether special characters are stripped from accountancy codes in the Aquarium module.', 'Used in core/modules/societe/mod_codecompta_aquarium.php. Per the code comment: ''Remove special char if COMPANY_AQUARIUM_REMOVE_SPECIAL is set to 1 or not set (default)''. Special character removal is active both when the constant is truthy and when it is not set.', 'Setting this to 1 or leaving it unset causes special characters to be removed from generated codes; explicitly setting it to 0 disables removal.', 'Remove special char if COMPANY_AQUARIUM_REMOVE_SPECIAL is set to 1 or not set (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_aquarium.php:189  // Remove special char if COMPANY_AQUARIUM_REMOVE_SPECIAL is set to 1 or not set (default)", "core/modules/societe/mod_codecompta_aquarium.php:190|check|if (!isset($conf->global->COMPANY_AQUARIUM_REMOVE_SPECIAL) || getDolGlobalString(''COMPANY_AQUARIUM_REMOVE_SPECIAL'')) {", "core/modules/societe/mod_codecompta_aquarium.php:120|check|if (getDolGlobalInt(''COMPANY_AQUARIUM_REMOVE_SPECIAL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_CLEAN_REGEX', 'string', NULL, 'core', 'Defines a regex pattern applied to accountancy codes in the Digitaria module to retain only captured groups.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. Per code comments: ''Apply a regex replacement pattern on code if COMPANY_DIGITARIA_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed.'' Applied via preg_replace keeping groups \1\2\3.', 'Setting this constant applies a regex transformation to generated codes, retaining only captured groups and removing the rest; leaving it unset skips this transformation.', 'Apply a regex replacement pattern on code if COMPANY_DIGITARIA_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed. Example: $conf->global->COMPANY_DIGITARIA_CLEAN_REGEX=''^..(..)..'';', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:137  // Apply a regex replacement pattern on code if COMPANY_DIGITARIA_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed.", "core/modules/societe/mod_codecompta_digitaria.php:243  // Apply a regex replacement pattern on code if COMPANY_DIGITARIA_CLEAN_REGEX is set. Value must be a regex with parenthesis. The part into parenthesis is kept, the rest removed.", "core/modules/societe/mod_codecompta_digitaria.php:244|check|if (getDolGlobalString(''COMPANY_DIGITARIA_CLEAN_REGEX'')) {\t// Example: $conf->global->COMPANY_DIGITARIA_CLEAN_REGEX=''^..(..)..'';", "core/modules/societe/mod_codecompta_digitaria.php:245|read|$codetouse = (string) preg_replace(''/'' . getDolGlobalString(''COMPANY_DIGITARIA_CLEAN_REGEX'').''/'', ''\\1\\2\\3'', $codetouse);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_CLEAN_WORDS', 'string', NULL, 'core', 'Defines a semicolon-separated list of words to be removed from company names when generating accountancy codes in the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. When set, the value is split on '';'' and each word is stripped from the company name before code generation. The value is also displayed in the module configuration info text.', 'Setting this constant removes the listed words from company names prior to code generation; leaving it unset skips this word-cleaning step.', 'Semicolon-separated list of words to remove (e.g. ''SARL;SAS;SA'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:235|check|if (getDolGlobalString(''COMPANY_DIGITARIA_CLEAN_WORDS'')) {", "core/modules/societe/mod_codecompta_digitaria.php:236|read|$cleanWords = explode(\";\", getDolGlobalString(''COMPANY_DIGITARIA_CLEAN_WORDS''));", "core/modules/societe/mod_codecompta_digitaria.php:158|check|if (getDolGlobalString(''COMPANY_DIGITARIA_CLEAN_WORDS'')) {", "core/modules/societe/mod_codecompta_digitaria.php:159|read|$texte .= $conf->global->COMPANY_DIGITARIA_CLEAN_WORDS;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_MASK_CUSTOMER', 'string', NULL, 'core', 'Defines the accountancy code prefix for customers in the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. If unset or empty, defaults to ''411''. Assigned to prefixcustomeraccountancycode and rendered in the module''s configuration form.', 'Changing this value alters the customer accountancy code prefix generated by the Digitaria module; the default fallback is ''411''.', 'Numeric string (e.g. ''411''); defaults to ''411'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:83|read|if (!isset($conf->global->COMPANY_DIGITARIA_MASK_CUSTOMER) || trim($conf->global->COMPANY_DIGITARIA_MASK_CUSTOMER) == '''') {", "core/modules/societe/mod_codecompta_digitaria.php:84|write|$conf->global->COMPANY_DIGITARIA_MASK_CUSTOMER = ''411'';", "core/modules/societe/mod_codecompta_digitaria.php:89|read|$this->prefixcustomeraccountancycode = getDolGlobalString(''COMPANY_DIGITARIA_MASK_CUSTOMER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_MASK_NBCHARACTER_CUSTOMER', 'string', NULL, 'core', 'Sets the number of characters used in the customer accountancy code generated by the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. If unset or empty, defaults to ''5''. Assigned to customeraccountancycodecharacternumber and displayed in the module''s configuration form.', 'Changing this value controls how many characters are used when truncating or padding customer accountancy codes; the default fallback is ''5''.', 'Numeric string indicating character count (e.g. ''5''); defaults to ''5'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:92|read|if (!isset($conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_CUSTOMER) || trim($conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_CUSTOMER) == '''') {", "core/modules/societe/mod_codecompta_digitaria.php:93|write|$conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_CUSTOMER = ''5'';", "core/modules/societe/mod_codecompta_digitaria.php:98|read|$this->customeraccountancycodecharacternumber = getDolGlobalString(''COMPANY_DIGITARIA_MASK_NBCHARACTER_CUSTOMER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_MASK_NBCHARACTER_SUPPLIER', 'string', NULL, 'core', 'Sets the number of characters used in the supplier accountancy code generated by the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. If unset or empty, defaults to ''5''. Assigned to supplieraccountancycodecharacternumber and displayed in the module''s configuration form.', 'Changing this value controls how many characters are used when truncating or padding supplier accountancy codes; the default fallback is ''5''.', 'Numeric string indicating character count (e.g. ''5''); defaults to ''5'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:95|read|if (!isset($conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_SUPPLIER) || trim($conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_SUPPLIER) == '''') {", "core/modules/societe/mod_codecompta_digitaria.php:96|write|$conf->global->COMPANY_DIGITARIA_MASK_NBCHARACTER_SUPPLIER = ''5'';", "core/modules/societe/mod_codecompta_digitaria.php:99|read|$this->supplieraccountancycodecharacternumber = getDolGlobalString(''COMPANY_DIGITARIA_MASK_NBCHARACTER_SUPPLIER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_MASK_SUPPLIER', 'string', NULL, 'core', 'Defines the accountancy code prefix for suppliers in the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. If unset or empty, defaults to ''401''. Assigned to prefixsupplieraccountancycode and rendered in the module''s configuration form.', 'Changing this value alters the supplier accountancy code prefix generated by the Digitaria module; the default fallback is ''401''.', 'Numeric string (e.g. ''401''); defaults to ''401'' if empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:86|read|if (!isset($conf->global->COMPANY_DIGITARIA_MASK_SUPPLIER) || trim($conf->global->COMPANY_DIGITARIA_MASK_SUPPLIER) == '''') {", "core/modules/societe/mod_codecompta_digitaria.php:87|write|$conf->global->COMPANY_DIGITARIA_MASK_SUPPLIER = ''401'';", "core/modules/societe/mod_codecompta_digitaria.php:90|read|$this->prefixsupplieraccountancycode = getDolGlobalString(''COMPANY_DIGITARIA_MASK_SUPPLIER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_REMOVE_SPECIAL', 'string', NULL, 'core', 'Controls whether special characters are stripped from accountancy codes in the Digitaria module.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. Per code comments: ''Remove special char if COMPANY_DIGITARIA_REMOVE_SPECIAL is set to 1 or not set (default)''. Removal is active when the constant is truthy or not set.', 'Setting to 1 or leaving unset causes special characters to be removed from generated codes; explicitly setting to 0 disables removal.', 'Remove special char if COMPANY_DIGITARIA_REMOVE_SPECIAL is set to 1 or not set (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:133  // Remove special char if COMPANY_DIGITARIA_REMOVE_SPECIAL is set to 1 or not set (default)", "core/modules/societe/mod_codecompta_digitaria.php:239  // Remove special char if COMPANY_DIGITARIA_REMOVE_SPECIAL is set to 1 or not set (default)", "core/modules/societe/mod_codecompta_digitaria.php:134|check|if (!isset($conf->global->COMPANY_DIGITARIA_REMOVE_SPECIAL) || getDolGlobalString(''COMPANY_DIGITARIA_REMOVE_SPECIAL'')) {", "core/modules/societe/mod_codecompta_digitaria.php:240|check|if (!isset($conf->global->COMPANY_DIGITARIA_REMOVE_SPECIAL) || getDolGlobalString(''COMPANY_DIGITARIA_REMOVE_SPECIAL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DIGITARIA_UNIQUE_CODE', 'string', NULL, 'core', 'Controls whether the Digitaria module enforces unique accountancy codes across companies.', 'Used in core/modules/societe/mod_codecompta_digitaria.php. Per code comments: ''If value is not unique (if COMPANY_DIGITARIA_UNIQUE_CODE is set to 0), we show this'' and ''Unique index on code if COMPANY_DIGITARIA_UNIQUE_CODE is set to 1 or not set (default)''.', 'Setting to 1 or leaving unset enforces unique code constraint; setting to 0 disables the uniqueness check and displays an informational note.', '1 or not set = enforce unique codes (default); 0 = allow duplicate codes', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codecompta_digitaria.php:141  // If value is not unique (if COMPANY_DIGITARIA_UNIQUE_CODE is set to 0), we show this", "core/modules/societe/mod_codecompta_digitaria.php:251  // Unique index on code if COMPANY_DIGITARIA_UNIQUE_CODE is set to 1 or not set (default)", "core/modules/societe/mod_codecompta_digitaria.php:142|check|if (!getDolGlobalString(''COMPANY_DIGITARIA_UNIQUE_CODE'', ''1'')) {", "core/modules/societe/mod_codecompta_digitaria.php:252|check|if (getDolGlobalString(''COMPANY_DIGITARIA_UNIQUE_CODE'', ''1'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_DONOTSEARCH_ANYWHERE', 'string', NULL, 'admin', 'Restricts third-party name searches to prefix matching (instead of substring matching) to allow database index usage.', 'Checked in admin/system/perf.php (line 709) and societe/ajax/ajaxcompanies.php:116. Read in core/class/html.form.class.php:1652: `$prefix = !getDolGlobalString(''COMPANY_DONOTSEARCH_ANYWHERE'') ? ''%'' : ''''; // Can use index if COMPANY_DONOTSEARCH_ANYWHERE is on`.', 'Enabling this setting changes the SQL LIKE pattern from `%search%` to `search%`, enabling index use and improving search performance at the cost of not matching mid-string occurrences.', 'Truthy string (non-empty) = prefix search only (index-optimized); empty/not set = substring search (full LIKE with leading wildcard).', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.form.class.php:1652|read|$prefix = !getDolGlobalString(''COMPANY_DONOTSEARCH_ANYWHERE'') ? ''%'' : ''''; // Can use index if COMPANY_DONOTSEARCH_ANYWHERE is on", "societe/ajax/ajaxcompanies.php:116|check|if (getDolGlobalString(''COMPANY_DONOTSEARCH_ANYWHERE'')) {   // Can use index", "admin/system/perf.php:709|check|if (!getDolGlobalString(''COMPANY_DONOTSEARCH_ANYWHERE'')) {", "admin/system/perf.php:713|read|print img_picto('''', ''tick'', ''class=\"pictofixedwidth\"'').'' ''.$langs->trans(\"YouHaveXObjectAndSearchOptimOn\", $nb, …"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ELEPHANT_DATE_START', 'string', NULL, 'core', 'Defines the start date threshold used by the Elephant module when assigning customer codes based on company creation date.', 'Read in core/modules/societe/mod_codeclient_elephant.php. Used alongside COMPANY_ELEPHANT_DATE_START_ENABLE: when that flag is enabled and a company''s creation date is before this value, a specific code assignment path is taken.', 'Changing this date alters which companies are subject to the date-based code assignment logic in the Elephant module.', 'A date string value compared against company creation date.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codeclient_elephant.php:127|read|$datedb = getDolGlobalString(''COMPANY_ELEPHANT_DATE_START'');", "core/modules/societe/mod_codeclient_elephant.php:326|check|if (getDolGlobalString(''COMPANY_ELEPHANT_DATE_START_ENABLE'') && $soc->date_creation < getDolGlobalString(''COMPANY_ELEPHANT_DATE_START'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ELEPHANT_DATE_START_ENABLE', 'bool', NULL, 'core', 'Enables the date-based code assignment logic in the Elephant module.', 'Checked in core/modules/societe/mod_codeclient_elephant.php alongside COMPANY_ELEPHANT_DATE_START. When truthy, companies with a creation date before the value of COMPANY_ELEPHANT_DATE_START follow a separate code assignment path.', 'Enabling this flag activates the date-threshold code assignment logic; disabling it bypasses the date check.', 'Truthy value to enable date-based logic; empty or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codeclient_elephant.php:326|check|if (getDolGlobalString(''COMPANY_ELEPHANT_DATE_START_ENABLE'') && $soc->date_creation < getDolGlobalString(''COMPANY_ELEPHANT_DATE_START'')) {", "core/modules/societe/mod_codeclient_elephant.php:146|read|$isEnabled = getDolGlobalString(''COMPANY_ELEPHANT_DATE_START_ENABLE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ELEPHANT_MASK_CUSTOMER', 'string', NULL, 'core', 'Defines the numbering mask for customer codes in the Elephant module.', 'Read in core/modules/societe/mod_codeclient_elephant.php at multiple locations (lines 247, 288, 337) for generating customer codes, and at line 115 to populate the configuration form input. Falls back to empty string when unset.', 'Changing this value alters the mask pattern used to generate customer codes in the Elephant module; leaving it unset produces an empty mask.', 'Any valid mask string for customer code generation; empty string if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codeclient_elephant.php:247|read|$mask = getDolGlobalString(''COMPANY_ELEPHANT_MASK_CUSTOMER'');", "core/modules/societe/mod_codeclient_elephant.php:337|read|$mask = !getDolGlobalString(''COMPANY_ELEPHANT_MASK_CUSTOMER'') ? '''' : $conf->global->COMPANY_ELEPHANT_MASK_CUSTOMER;", "core/modules/societe/mod_codeclient_elephant.php:288|read|$mask = getDolGlobalString(''COMPANY_ELEPHANT_MASK_CUSTOMER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_ELEPHANT_MASK_SUPPLIER', 'string', NULL, 'core', 'Defines the numbering mask for supplier codes in the Elephant module.', 'Read in core/modules/societe/mod_codeclient_elephant.php at multiple locations (lines 250, 293, 340) for generating supplier codes, and at line 123 to populate the configuration form input. Falls back to empty string when unset.', 'Changing this value alters the mask pattern used to generate supplier codes in the Elephant module; leaving it unset produces an empty mask.', 'Any valid mask string for supplier code generation; empty string if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/mod_codeclient_elephant.php:250|read|$mask = getDolGlobalString(''COMPANY_ELEPHANT_MASK_SUPPLIER'');", "core/modules/societe/mod_codeclient_elephant.php:340|read|$mask = !getDolGlobalString(''COMPANY_ELEPHANT_MASK_SUPPLIER'') ? '''' : $conf->global->COMPANY_ELEPHANT_MASK_SUPPLIER;", "core/modules/societe/mod_codeclient_elephant.php:293|read|$mask = getDolGlobalString(''COMPANY_ELEPHANT_MASK_SUPPLIER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_HIDE_INACTIVE_IN_COMBOBOX', 'bool', NULL, 'core', 'Hides inactive (closed/archived) companies from third-party selection comboboxes.', 'When set, core/class/html.form.class.php filters out inactive companies from the SQL query used to populate the third-party selector. Configurable via the admin UI at societe/admin/societe.php. Saved via dolibarr_set_const.', 'Enabling this constant removes inactive companies from all third-party comboboxes; disabling it shows all companies regardless of status.', 'Non-empty (truthy) hides inactive companies; empty or undefined shows all.', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:1639|check|if (getDolGlobalString(''COMPANY_HIDE_INACTIVE_IN_COMBOBOX'')) {", "societe/admin/societe.php:315|write|$result = dolibarr_set_const($db, \"COMPANY_HIDE_INACTIVE_IN_COMBOBOX\", $status, ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_NEWFORM_TEXT', 'string', NULL, 'public', 'Sets a translation key whose translated text is displayed at the bottom of the public company registration form.', 'Checked and read at public/company/new.php:300-301; the value is passed through $langs->trans() before being printed. No admin UI write found.', 'If set, the translated value of this key appears as a text message below the public company registration form.', 'A translation key string; the translated text is rendered on the form.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/company/new.php:300|check|if (getDolGlobalString(''COMPANY_NEWFORM_TEXT'')) {", "public/company/new.php:301|read|print $langs->trans(getDolGlobalString(''COMPANY_NEWFORM_TEXT'')) . \"<br>\\n\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_SHOW_ADDRESS_SELECTLIST', 'bool', NULL, 'societe', 'Enables display of ZIP code and town in third-party selection dropdowns.', 'Written via societe/admin/societe.php (line 223). Read in societe/class/societe.class.php (lines 987-988) to set `showoncombobox` for zip and town fields. Checked in core/class/html.form.class.php:1616 and societe/ajax/ajaxcompanies.php (lines 104, 108, 163). COMMENT: `//$this->fields[''fk_pays''][''showoncombobox''] = $conf->global->COMPANY_SHOW_ADDRESS_SELECTLIST;`.', 'Enabling this setting adds the city and ZIP code alongside the company name in third-party autocomplete lists.', '0 or empty = only company name shown; 1 = ZIP and town shown in dropdowns.', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:989  //$this->fields[''fk_pays''][''showoncombobox''] = $conf->global->COMPANY_SHOW_ADDRESS_SELECTLIST;", "societe/class/societe.class.php:987|read|$this->fields[''zip''][''showoncombobox''] = getDolGlobalInt(''COMPANY_SHOW_ADDRESS_SELECTLIST'');", "societe/class/societe.class.php:988|read|$this->fields[''town''][''showoncombobox''] = getDolGlobalInt(''COMPANY_SHOW_ADDRESS_SELECTLIST'');", "societe/admin/societe.php:223|write|$res = dolibarr_set_const($db, \"COMPANY_SHOW_ADDRESS_SELECTLIST\", $val, ''yesno'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('COMPANY_USE_SEARCH_TO_SELECT', 'bool', NULL, 'core', 'Enables Ajax autocomplete search for third-party (company) selection dropdowns instead of loading the full list.', 'Controls whether company selector inputs use an Ajax autocomplete widget. When set, the numeric value is used as the minimum character count before triggering search, defaulting to 2 if non-numeric. Configured via societe/admin/societe.php.', 'When disabled, the full company list is loaded in the selector. When enabled, an Ajax endpoint is called after the configured minimum number of characters are typed.', 'Empty/0 = disabled (full list loaded); positive integer = minimum chars to trigger Ajax search (default 2 if non-numeric value set)', 0, 0, 'societe/admin/societe.php|admin/system/perf.php|admin/system/perf.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.formcompany.class.php:659|read|$minLength = (is_numeric(getDolGlobalString(''COMPANY_USE_SEARCH_TO_SELECT'')) ? $conf->global->COMPANY_USE_SEARCH_TO_SELECT : 2);", "admin/system/perf.php:565|check|if (!getDolGlobalString(''COMPANY_USE_SEARCH_TO_SELECT'')) {", "core/lib/ajax.lib.php:463  * TODO: It is used when COMPANY_USE_SEARCH_TO_SELECT and CONTACT_USE_SEARCH_TO_SELECT are set by html.formcompany.class.php. Should use ajax_autocompleter instead like done by html.form.class.php for select_produits.", "societe/admin/societe.php:85|write|$res = dolibarr_set_const($db, \"COMPANY_USE_SEARCH_TO_SELECT\", $companysearch, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONFERENCEORBOOTHATTENDEE_ADDON_PDF', 'string', NULL, 'eventorganization', 'Specifies the PDF template module name used to generate documents for conference/booth attendee records.', 'Read at conferenceorboothattendee.class.php:1093-1094; when set, its value is used as the PDF model name, overriding the default model selection logic.', 'Setting this constant changes which PDF template is rendered for attendee documents; leaving it unset falls back to the default template selection.', 'Empty/unset = use default PDF model; a module name string = use that PDF template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["eventorganization/class/conferenceorboothattendee.class.php:1093|read|} elseif (getDolGlobalString(''CONFERENCEORBOOTHATTENDEE_ADDON_PDF'')) {", "eventorganization/class/conferenceorboothattendee.class.php:1094|read|$modele = getDolGlobalString(''CONFERENCEORBOOTHATTENDEE_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONFERENCEORBOOTH_ADDON_PDF', 'string', NULL, 'eventorganization', 'Specifies the PDF template module name used to generate documents for conference/booth records.', 'Read at conferenceorbooth.class.php:820-821; when set, its value is assigned as the PDF model name, overriding the default selection.', 'Setting this constant changes which PDF template is rendered for conference/booth documents; leaving it unset falls back to the default template selection.', 'Empty/unset = use default PDF model; a module name string = use that PDF template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["eventorganization/class/conferenceorbooth.class.php:820|read|} elseif (getDolGlobalString(''CONFERENCEORBOOTH_ADDON_PDF'')) {", "eventorganization/class/conferenceorbooth.class.php:821|read|$modele = getDolGlobalString(''CONFERENCEORBOOTH_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACTS_DEFAULT_ROLES', 'string', NULL, 'societe', 'Stores the comma-separated list of default role codes automatically assigned to new contacts created for a third party.', 'Written via societe/admin/societe.php:124 using implode('','', $rolessearch) and read at societe/admin/societe.php:974 with explode. Applied in societe/class/societe.class.php:1235-1236 when creating a contact, setting $contact->roles from the exploded value.', 'When set, newly created contacts inherit the specified roles automatically; when empty, no default roles are assigned.', 'String: comma-separated role codes (e.g. ''BILLING,SHIPPING''); empty = no default roles', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:124|write|$res = dolibarr_set_const($db, \"CONTACTS_DEFAULT_ROLES\", implode('','', $rolessearch), ''chaine'', 0, '''', $conf->entity);", "societe/class/societe.class.php:1235|check|if (getDolGlobalString(''CONTACTS_DEFAULT_ROLES'')) {", "societe/class/societe.class.php:1236|read|$contact->roles = explode('','', getDolGlobalString(''CONTACTS_DEFAULT_ROLES''));", "societe/admin/societe.php:974|read|$selected = explode('','', getDolGlobalString(''CONTACTS_DEFAULT_ROLES''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_DONOTSEARCH_ANYWHERE', 'string', NULL, 'contact', 'Restricts contact AJAX search to use exact-prefix matching instead of substring (LIKE ''%...'') matching.', 'Read once at contact/ajax/contact.php:140 where the prefix variable is set to '''' when the constant is on, allowing database index use. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant improves contact search performance on large datasets by avoiding leading-wildcard SQL patterns, but limits results to contacts whose names begin with the search term.', '0 (search anywhere, leading wildcard) or 1 (prefix search only, can use index)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/ajax/contact.php:140|read|$prefix = getDolGlobalString(''CONTACT_DONOTSEARCH_ANYWHERE'') ? '''' : ''%''; // Can use index if CONTACT_DONOTSEARCH_ANYWHERE is on"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_HIDE_INACTIVE_IN_COMBOBOX', 'bool', NULL, 'core', 'Hides inactive contacts from contact selection comboboxes.', 'When set, core/class/html.form.class.php filters out inactive contacts from the SQL query populating the contact selector. Only one occurrence in the payload; no admin UI write; hidden setting.', 'Enabling this constant removes inactive contacts from all contact comboboxes; disabling it (or leaving unset) shows all contacts.', 'Non-empty (truthy) hides inactive contacts; empty or undefined shows all.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:1890|check|if (getDolGlobalString(''CONTACT_HIDE_INACTIVE_IN_COMBOBOX'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_PHONEMOBILE_SHOW_LINK_TO_WHATSAPP', 'bool', NULL, 'core', 'Adds a WhatsApp link next to the contact mobile phone number when set.', 'Checked in core/lib/functions.lib.php:5118 guarded by $withpicto == ''mobile'', so the link only appears for mobile phone fields. No admin UI write detected.', 'Enabling this constant displays a WhatsApp icon/link next to mobile numbers on contact views. Without it, no WhatsApp link is shown.', 'Non-empty = show WhatsApp link on mobile field; absent/empty = no WhatsApp link.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5118|check|if (getDolGlobalString(''CONTACT_PHONEMOBILE_SHOW_LINK_TO_WHATSAPP'') && $withpicto == ''mobile'') {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_SEARCH_AUTOFOCUS', 'string', NULL, 'core', 'Enables autofocus on the contact search input field in combobox/select widgets.', 'In core/class/html.form.class.php, the autofocus HTML attribute on the search input for contact selection is controlled by this constant. Only one occurrence in the payload; no admin UI write; hidden setting.', 'Enabling this constant causes the contact search field to receive focus automatically when the selector opens; disabling it leaves focus management to the browser default.', 'Non-empty (truthy) enables autofocus; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:1520|read|$out .= ''<input type=\"text\" class=\"'' . $morecss . ''\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_value . ''\"''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_SHOW_EMAIL_PHONE_TOWN_SELECTLIST', 'bool', NULL, 'core', 'Shows email, phone, and town information alongside contact names in contact selection dropdowns.', 'When enabled, additional fields (email, phone, town) are rendered next to contact names in contact selector lists. Configured via societe/admin/societe.php.', 'Enabling this provides more context in contact selectors at the cost of wider list entries. Disabling it shows only the contact name.', 'Truthy = show additional fields; empty/falsy = hide', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:237|write|$res = dolibarr_set_const($db, \"CONTACT_SHOW_EMAIL_PHONE_TOWN_SELECTLIST\", $val, ''yesno'', 0, '''', $conf->entity);", "core/class/html.form.class.php:1878|check|if ($showsoc > 0 || getDolGlobalString(''CONTACT_SHOW_EMAIL_PHONE_TOWN_SELECTLIST'')) {", "core/class/html.form.class.php:1942|check|if (getDolGlobalString(''CONTACT_SHOW_EMAIL_PHONE_TOWN_SELECTLIST'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_USE_COMPANY_ADDRESS', 'bool', NULL, 'contact', 'Forces contact records to inherit the linked company''s address fields when the contact''s own address is empty.', 'When enabled, address, zip, town, phone, fax, and email fields are copied from the associated third-party if the contact''s own fields are blank. Checked in contact/card.php:730, :749, :752, :786, :789, :820, and in contact/canvas/actions_contactcard_common.class.php:151.', 'Enabling this ensures contacts always display address data even when no explicit contact address is entered, by falling back to the company address.', '0 or empty = contact address is used as-is; non-empty = company address fills in blank contact fields', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/card.php:730|check|if (((isset($objsoc->typent_code) && $objsoc->typent_code == ''TE_PRIVATE'') || getDolGlobalString(''CONTACT_USE_COMPANY_ADDRESS'')) && dol_strlen(trim($object->address)) == 0) {", "contact/card.php:749|check|if (((isset($objsoc->typent_code) && $objsoc->typent_code == ''TE_PRIVATE'') || getDolGlobalString(''CONTACT_USE_COMPANY_ADDRESS'')) && dol_strlen(trim($object->zip)) == 0) {", "contact/canvas/actions_contactcard_common.class.php:151|check|if ((isset($objsoc->typent_code) && $objsoc->typent_code == ''TE_PRIVATE'') || getDolGlobalString(''CONTACT_USE_COMPANY_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTACT_USE_SEARCH_TO_SELECT', 'bool', NULL, 'comm', 'Enables Ajax autocomplete search for contact selection dropdowns instead of loading the full contact list.', 'Controls whether contact selector inputs use an Ajax autocomplete widget. When set, the numeric value is used as the minimum character count before triggering search. Configured via societe/admin/societe.php.', 'When enabled, the Ajax contact endpoint checks that the number of characters in the filter is at or above the configured minimum to avoid denial-of-service attacks. Disabling it loads the full contact list in selectors.', 'Empty/0 = disabled; positive integer = minimum chars to trigger Ajax search', 0, 0, 'societe/admin/societe.php|admin/system/perf.php|admin/system/perf.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/ajax/contact.php:157  // If CONTACT_USE_SEARCH_TO_SELECT is set, check that nb of chars in $filter is >= to avoid DOS attack", "societe/admin/societe.php:98|write|$res = dolibarr_set_const($db, \"CONTACT_USE_SEARCH_TO_SELECT\", $contactsearch, ''chaine'', 0, '''', $conf->entity);", "comm/action/card.php:1789  // FIXME Use a select without the \"multiple\" (not supported when CONTACT_USE_SEARCH_TO_SELECT is on) or allow use only when $object->socid is set...", "contact/ajax/contact.php:158|check|if (getDolGlobalInt(''CONTACT_USE_SEARCH_TO_SELECT'') && $nbchar < getDolGlobalInt(''CONTACT_USE_SEARCH_TO_SELECT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ADDON', 'string', NULL, 'contrat', 'Specifies the numbering module class used to generate contract reference numbers.', 'Read in contrat/class/contrat.class.php:321 to load the appropriate numbering class; the class file is included via contrat/class/contrat.class.php:2649. The default value is ''mod_contract_serpis'' as set in admin/contract.php:59. Configurable via admin/contract.php.', 'Changing this value switches the contract reference numbering algorithm. If the specified module class does not exist, contract number generation will fail.', 'String name of a module class under core/modules/contract/; default is ''mod_contract_serpis''.', 0, 0, 'admin/contract.php|admin/contract.php|admin/contract.php|admin/contract.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/class/contrat.class.php:321|read|$classname = getDolGlobalString(''CONTRACT_ADDON'');", "contrat/class/contrat.class.php:2649|read|require_once DOL_DOCUMENT_ROOT.\"/core/modules/contract/\" . getDolGlobalString(''CONTRACT_ADDON'').''.php'';", "admin/contract.php:59|write|$conf->global->CONTRACT_ADDON = ''mod_contract_serpis'';", "admin/contract.php:153|write|dolibarr_set_const($db, \"CONTRACT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF generation module used to produce contract documents.', 'Written and read in admin/contract.php (lines 130, 131, 136, 139, 148) for selection and persistence. Used in contrat/card.php:703 to conditionally generate PDFs and in contrat/class/contrat.class.php:2550 to select the PDF module. Configurable via the admin UI at admin/contract.php.', 'Changing this value switches the PDF template used for contract documents. Deleting it disables automatic PDF generation for contracts.', 'String name of a PDF module class; unset means no default PDF type defined and automatic PDF generation is skipped.', 0, 0, 'admin/contract.php|admin/contract.php|admin/contract.php|admin/contract.php|admin/contract.php|admin/contract.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/card.php:703|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_AUTOUPDATE'') && getDolGlobalString(''CONTRACT_ADDON_PDF'')) {    // No generation if default type not defined", "admin/contract.php:136|write|if (dolibarr_set_const($db, \"CONTRACT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/contract.php:148|write|dolibarr_del_const($db, \"CONTRACT_ADDON_PDF\", $conf->entity);", "contrat/class/contrat.class.php:2550|read|} elseif (getDolGlobalString(''CONTRACT_ADDON_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ADDON_PDF_ODT_PATH', 'string', 'DOL_DATA_ROOT/doctemplates/contracts', 'core', 'Specifies the directory path(s) where ODT contract document templates are stored.', 'Read in core/modules/contract/doc/doc_generic_contract_odt.modules.php:124, :151, and :159. The value is split by comma and newline to build the list of template directories. Defaults to ''DOL_DATA_ROOT/doctemplates/contracts''.', 'Changing this constant redirects contract ODT template lookups to different directories; an invalid path causes template loading to fail.', 'Comma or newline-separated directory path(s) (default: ''DOL_DATA_ROOT/doctemplates/contracts'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/contract/doc/doc_generic_contract_odt.modules.php:124|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim($conf->global->CONTRACT_ADDON_PDF_ODT_PATH)));", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:151|read|$texte .= getDolGlobalString(''CONTRACT_ADDON_PDF_ODT_PATH'');", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:159|check|if (getDolGlobalString(''CONTRACT_ADDON_PDF_ODT_PATH'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for contract documents.', 'Checked in core/class/commonobject.class.php:6386 and core/lib/functions.lib.php:10743. When set, a public download link is generated for contract (contrat) objects.', 'Enabling this constant exposes contract documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6386|check|if ($this->element == ''contrat'' && getDolGlobalInt(\"CONTRACT_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10743|check|if (getDolGlobalString(''CONTRACT_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''contrat'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ALLOW_ONLINESIGN', 'bool', NULL, 'admin', 'Enables online signature functionality for non-draft contracts.', 'When set, contrat/card.php:2408 shows the online sign action for contracts not in draft status. Also checked at admin/contract.php:546 to display the related configuration UI, and written at admin/contract.php:174. Only 3 occurrences across 2 files.', 'Enabling this constant makes the online signature action available on validated contracts.', 'Non-empty/truthy = online signature enabled; empty/unset = online signature not shown.', 0, 0, 'admin/contract.php|admin/contract.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/contract.php:174|write|if (!dolibarr_set_const($db, \"CONTRACT_ALLOW_ONLINESIGN\", $value, ''int'', 0, '''', $conf->entity)) {", "admin/contract.php:546|check|if (getDolGlobalString(''CONTRACT_ALLOW_ONLINESIGN'')) {", "contrat/card.php:2408|check|if ($object->status != Contrat::STATUS_DRAFT && getDolGlobalString(''CONTRACT_ALLOW_ONLINESIGN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY', 'bool', NULL, 'core', 'Controls whether contracts from other third parties can be linked; value is ''all'' or a comma-separated list of third-party IDs.', 'COMMENTS state: ''CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY is \''all\'' or a list of ids separated by coma.'' Checked and read across four lines in core/class/html.formcontract.class.php (lines 88, 90, 91, 138). When unset or falsy, only contracts belonging to the current third party are shown.', 'Setting this to ''all'' allows linking any contract regardless of third party; setting it to a comma-separated list of IDs restricts linking to those specific third parties.', ''''' or unset = only same third-party contracts; ''all'' = all contracts; comma-separated integer IDs = contracts from those specific third parties.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["// CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY is ''all'' or a list of ids separated by coma.", "core/class/html.formcontract.class.php:88|check|if (!getDolGlobalString(''CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'')) {", "core/class/html.formcontract.class.php:90|read|} elseif (getDolGlobalString(''CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'') != ''all'') {", "core/class/html.formcontract.class.php:138|check|if (!getDolGlobalString(''CONTRACT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'') && $socid > 0 && (!empty($obj->fk_soc) && $obj->fk_soc != $socid)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_CREATE_FROM_INVOICE', 'string', NULL, 'compta', 'When enabled, shows an action button to create a contract directly from an existing invoice.', 'Checked in compta/facture/card.php:6634 to conditionally display the contract creation action. Only one occurrence is present in the payload.', 'Enabling this constant adds a ''create contract'' action to the invoice view, allowing a contract to be generated from the invoice.', '0 or unset = contract creation from invoice not available; truthy = contract creation from invoice enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:6634|check|if (getDolGlobalString(''CONTRACT_CREATE_FROM_INVOICE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_DISABLE_AUTOSET_AS_CLIENT_ON_CONTRACT_VALIDATION', 'bool', NULL, 'contrat', 'When enabled, prevents automatically marking a third party as a customer when a contract is validated.', 'Checked in contrat/class/contrat.class.php:546; if set, the auto-promotion of a third party to client status on contract validation is skipped. Only one occurrence is present in the payload. No admin UI write is present.', 'Enabling this constant means validating a contract will not automatically set the linked third party as a customer, preserving the existing client status.', 'Boolean flag; unset or 0 = auto-set as client on validation; any truthy value = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/class/contrat.class.php:546|check|if (!getDolGlobalString(''CONTRACT_DISABLE_AUTOSET_AS_CLIENT_ON_CONTRACT_VALIDATION'') && $this->thirdparty->fournisseur == 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_DRAFT_WATERMARK', 'string', NULL, 'core', 'Defines the watermark text overlaid on draft contract PDF documents.', 'Saved via admin/contract.php:159 and displayed in the admin UI at admin/contract.php:529. Read in core/modules/contract/doc/pdf_strato.modules.php:167-168; when the contract is in draft status and the constant is set, the value is applied as a watermark.', 'Setting this constant adds the specified text as a watermark on draft contract PDFs; clearing it removes the watermark.', 'String (e.g. ''DRAFT''); empty = no watermark', 0, 0, 'admin/contract.php|admin/contract.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/contract.php:159|write|$res2 = dolibarr_set_const($db, \"CONTRACT_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "admin/contract.php:529|read|print ''<input class=\"flat minwidth200\" type=\"text\" name=\"CONTRACT_DRAFT_WATERMARK\" value=\"''.dol_escape_htmltag(getDolGlobalString(''CONTRACT_DRAFT_WATERMARK'')).''\">'';", "core/modules/contract/doc/pdf_strato.modules.php:167|check|if ($object->status == $object::STATUS_DRAFT && (getDolGlobalString(''CONTRACT_DRAFT_WATERMARK''))) {", "core/modules/contract/doc/pdf_strato.modules.php:168|read|$this->watermark = getDolGlobalString(''CONTRACT_DRAFT_WATERMARK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_EXCLUDE_SERVICES_STATUS_FOR_INVOICE', 'string', NULL, 'compta', 'Specifies a comma-separated list of contract service statuses that are excluded when generating an invoice from a contract.', 'Read and conditionally set in compta/facture/card.php at lines 1922-1925. Defaults to ''5'' if not already set (line 1923). Service lines whose status matches any value in this list are skipped during invoice creation from a contract.', 'Changing this value alters which contract service lines are included or excluded when generating invoices from contracts.', 'Comma-separated integer statuses; defaults to ''5'' if not set. Lines with a status in this list are excluded from invoice generation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:1923|write|$conf->global->CONTRACT_EXCLUDE_SERVICES_STATUS_FOR_INVOICE = ''5'';", "compta/facture/card.php:1922|read|if (!isset($conf->global->CONTRACT_EXCLUDE_SERVICES_STATUS_FOR_INVOICE)) {", "compta/facture/card.php:1925|check|if ($srcobject->element == ''contrat'' && in_array($lines[$i]->statut, explode('','', getDolGlobalString(''CONTRACT_EXCLUDE_SERVICES_STATUS_FOR_INVOICE'')))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Contract documents.', 'Set via the admin UI at admin/contract.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Contract documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/contract.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/contract.php:156|write|$res1 = dolibarr_set_const($db, \"CONTRACT_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_HIDE_CLOSED_SERVICES_BY_DEFAULT', 'bool', NULL, 'contrat', 'Hides closed service lines on the contract card by default unless the user explicitly requests to show them.', 'When enabled, contrat/card.php:1682 and 1953 skip rendering lines with STATUS_CLOSED unless the action is ''showclosedlines'', and contrat/card.php:2349 shows a reveal button when closed services exist. Configurable via admin/contract.php:162.', 'Enabling this constant causes closed service lines to be hidden by default on contract cards, reducing visual clutter; users can still reveal them via the ''showclosedlines'' action.', 'Non-empty/truthy = closed services hidden by default; empty/unset = all services shown.', 0, 0, 'admin/contract.php|admin/contract.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/contract.php:162|write|$res3 = dolibarr_set_const($db, \"CONTRACT_HIDE_CLOSED_SERVICES_BY_DEFAULT\", $value, ''chaine'', 0, '''', $conf->entity);", "contrat/card.php:1682|check|if (getDolGlobalString(''CONTRACT_HIDE_CLOSED_SERVICES_BY_DEFAULT'') && $objp->statut == ContratLigne::STATUS_CLOSED && $action != ''showclosedlines'') {", "contrat/card.php:1953|check|if (getDolGlobalString(''CONTRACT_HIDE_CLOSED_SERVICES_BY_DEFAULT'') && $object->lines[$cursorline - 1]->statut == ContratLigne::STATUS_CLOSED && $action != ''showclosedlines'') {", "contrat/card.php:2349|check|if (getDolGlobalString(''CONTRACT_HIDE_CLOSED_SERVICES_BY_DEFAULT'') && $object->nbofservicesclosed > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_HIDE_CLOSED_SERVICES_IN_GRAPH', 'bool', NULL, 'contrat', 'Hides closed contract services from the contract index graph.', 'When not set, all services (including closed ones) are included in the contract index graph query in contrat/index.php. No admin UI; must be set directly in the database.', 'Enabling this filters out closed services from the contract graph, reducing the displayed service count. Disabling it shows all services regardless of status.', 'Truthy = closed services hidden from graph; empty/falsy = all services shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/index.php:197|check|if (!getDolGlobalString(''CONTRACT_HIDE_CLOSED_SERVICES_IN_GRAPH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_HIDE_MYCOMPANY_SIGNATURE_SECTION_PDF', 'bool', NULL, 'core', 'Hides the issuing company signature section on contract PDF documents.', 'Checked in core/modules/contract/doc/pdf_strato.modules.php:617. When set, the signature block for the issuing company is omitted from the PDF.', 'Setting this constant removes the issuing company signature section from generated contract PDFs.', 'Non-empty = signature section hidden; empty or unset = section shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:617|check|if (!getDolGlobalString(''CONTRACT_HIDE_MYCOMPANY_SIGNATURE_SECTION_PDF'')) {"]', 'low', NULL);
