INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_HIDE_UNSELECTABLES', 'bool', NULL, 'core', 'When enabled, hides unselectable contract lines from the contract selection form.', 'Checked in core/class/html.formcontract.class.php:73; when the constant is set, the form applies filtering to hide entries that cannot be selected. No admin UI page is listed.', 'Enabling this constant removes visually disabled contract options from the form, producing a cleaner list for end users.', '1 or any truthy value = hide unselectables; 0 or unset = show all.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formcontract.class.php:73|check|if (getDolGlobalString(''CONTRACT_HIDE_UNSELECTABLES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_MAGRE_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the ''magre'' contract numbering module.', 'Read in core/modules/contract/mod_contract_magre.php:81 (UI display) and :129 (mask application). The mask string is used to generate contract reference numbers according to the Magre pattern.', 'Changing this mask alters the format of automatically generated contract reference numbers when the Magre module is active.', 'Mask string (e.g. ''{YYYY}{MM}{DD}-{####}'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/contract/mod_contract_magre.php:81|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskcontract\" value=\"''.getDolGlobalString(\"CONTRACT_MAGRE_MASK\").''\">'', $toolt", "core/modules/contract/mod_contract_magre.php:129|read|$mask = getDolGlobalString(\"CONTRACT_MAGRE_MASK\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_NEW_CONTRACT_ON_RENEWAL', 'string', NULL, 'comm', 'When set, creates a new contract on renewal instead of renewing the existing one.', 'Checked in comm/propal/card.php:622: the condition skips a block when the origin is a contract renewal AND this constant is set, altering the renewal behavior when converting a proposal.', 'Enabling this changes the contract renewal flow so that a new contract object is created rather than extending the current one.', '0 or unset = renew existing contract; non-zero = create new contract on renewal.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:622|check|if (($origin != ''contrat'' || $renewal != ''true'') && !getDolGlobalInt(''CONTRACT_NEW_CONTRACT_ON_RENEWAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_ONLINE_SIGNATURE_SECURITY_TOKEN', 'string', NULL, 'core', 'Provides the secret seed string used to generate the security token for the contract online-signature public link.', 'Read in core/lib/signature.lib.php:143, core/ajax/onlineSign.php:84, and public/onlinesign/newonlinesign.php:151 as $securekeyseed via getDolGlobalString(''CONTRACT_ONLINE_SIGNATURE_SECURITY_TOKEN''). No admin UI write is present; the value must be set manually.', 'If changed or cleared, any previously distributed public signature links for contracts will become invalid because the derived token will no longer match.', 'Arbitrary string (secret seed). Empty string disables token-based verification.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/signature.lib.php:143|read|$securekeyseed = getDolGlobalString(''CONTRACT_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "core/ajax/onlineSign.php:84|read|$securekeyseed = getDolGlobalString(''CONTRACT_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "public/onlinesign/newonlinesign.php:151|read|$securekeyseed = getDolGlobalString(''CONTRACT_ONLINE_SIGNATURE_SECURITY_TOKEN'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SHOW_SIGNATURE_STATUS_WITH_SERVICE_STATUS', 'bool', NULL, 'contrat', 'When enabled, displays the contract signature status alongside the service status on contract pages.', 'Checked in contrat/card.php:2358 and contrat/class/contrat.class.php:2007 to conditionally render signature status information. No admin UI write is present; two occurrences across two files.', 'Enabling this constant causes signature status to be shown together with service status on the contract card and in related class logic.', 'Boolean flag; unset or 0 = signature status not shown with service status; any truthy value = shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/card.php:2358|check|if (getDolGlobalString(''CONTRACT_SHOW_SIGNATURE_STATUS_WITH_SERVICE_STATUS'') && $object->status > Contrat::STATUS_DRAFT) {", "contrat/class/contrat.class.php:2007|check|if (getDolGlobalString(''CONTRACT_SHOW_SIGNATURE_STATUS_WITH_SERVICE_STATUS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SHOW_TOTAL_OF_PRODUCT_AS_PRICE', 'bool', NULL, 'contrat', 'Hides the total amount display for contract product lines in the linked object block template.', 'Checked at contrat/tpl/linkedobjectblock.tpl.php:65; when set, the condition !getDolGlobalString(''CONTRACT_SHOW_TOTAL_OF_PRODUCT_AS_PRICE'') is false, which suppresses the total display in the linked objects block.', 'Setting this changes how contract product line totals are displayed in linked object blocks.', '0 or unset = total shown; 1 = total hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/tpl/linkedobjectblock.tpl.php:65|check|if ($user->hasRight(''contrat'', ''lire'') && !getDolGlobalString(''CONTRACT_SHOW_TOTAL_OF_PRODUCT_AS_PRICE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SIGNATURE_ON_ALL_PAGES', 'string', NULL, 'core', 'Controls whether the online signature image is stamped on every page of the contract PDF rather than a specific page only.', 'Checked in core/ajax/onlineSign.php:410 and :439 via getDolGlobalString(''CONTRACT_SIGNATURE_ON_ALL_PAGES''). When truthy the signature block is rendered on every page of the contract PDF.', 'Enabling this constant causes the signature image to appear on every page of the contract PDF. Disabling it restricts signature placement to a specific page.', 'Non-empty string = enabled (stamp on all pages). Empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:410|check|if (getDolGlobalString(\"CONTRACT_SIGNATURE_ON_ALL_PAGES\")) {", "core/ajax/onlineSign.php:439|check|if (!getDolGlobalString(\"CONTRACT_SIGNATURE_ON_ALL_PAGES\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SIGNATURE_WFORIMG', 'string', NULL, 'core', 'Sets the width of the signature image inserted into the contract PDF during online signing.', 'Checked and read in core/ajax/onlineSign.php:424-425 via getDolGlobalString(''CONTRACT_SIGNATURE_WFORIMG''). When set, the value is passed as $param[''wforimg''] to the PDF rendering layer.', 'If set, the signature image is rendered at the specified width in the contract PDF. If unset, the default image width applies.', 'Numeric or string value representing the image width passed to the PDF engine. Empty/unset = default width.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:424|check|if (getDolGlobalString(\"CONTRACT_SIGNATURE_WFORIMG\")) {", "core/ajax/onlineSign.php:425|read|$param[''wforimg''] = getDolGlobalString(\"CONTRACT_SIGNATURE_WFORIMG\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SIGNATURE_XFORIMGSTART', 'string', NULL, 'core', 'Sets the X coordinate (horizontal offset) for positioning the signature image on the contract PDF page.', 'Checked and read in core/ajax/onlineSign.php:414-415 via getDolGlobalString(''CONTRACT_SIGNATURE_XFORIMGSTART''). When set, the value is passed as $param[''xforimgstart''] to the PDF rendering layer.', 'If set, overrides the default horizontal position of the signature image on the contract PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the X coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:414|check|if (getDolGlobalString(\"CONTRACT_SIGNATURE_XFORIMGSTART\")) {", "core/ajax/onlineSign.php:415|read|$param[''xforimgstart''] = getDolGlobalString(\"CONTRACT_SIGNATURE_XFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SIGNATURE_YFORIMGSTART', 'string', NULL, 'core', 'Sets the Y coordinate (vertical offset) for positioning the signature image on the contract PDF page.', 'Checked and read in core/ajax/onlineSign.php:419-420 via getDolGlobalString(''CONTRACT_SIGNATURE_YFORIMGSTART''). When set, the value is passed as $param[''yforimgstart''] to the PDF rendering layer.', 'If set, overrides the default vertical position of the signature image on the contract PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the Y coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:419|check|if (getDolGlobalString(\"CONTRACT_SIGNATURE_YFORIMGSTART\")) {", "core/ajax/onlineSign.php:420|read|$param[''yforimgstart''] = getDolGlobalString(\"CONTRACT_SIGNATURE_YFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SUPPORT_PRODUCTS', 'string', NULL, 'core', 'Enables product (type=0) lines in addition to services on contracts.', 'By default, contracts only allow service-type lines (product_type=1). When this constant is set, contrat/card.php:368 also accepts product_type=0, and core/tpl/objectline_create.tpl.php:287 and 1353 adjust their filtering accordingly. Also affects mailing module eligibility at core/modules/mailings/thirdparties_services_expired.modules.php:73. No admin UI is provided.', 'Enabling this constant allows physical products to be added as lines on contracts; disabling it restricts contracts to services only.', 'Non-empty/truthy = products allowed on contracts; empty/unset = only services allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/card.php:368|check|if ($product_type == 1 || (getDolGlobalString(''CONTRACT_SUPPORT_PRODUCTS'') && in_array($product_type, array(0, 1)))) { \t// TODO Exclude also deee", "core/tpl/objectline_create.tpl.php:287|check|if (!empty($object->element) && $object->element == ''contrat'' && !getDolGlobalString(''CONTRACT_SUPPORT_PRODUCTS'')) {", "contrat/card.php:1353|check|if (!getDolGlobalString(''CONTRACT_SUPPORT_PRODUCTS'')) {", "core/modules/mailings/thirdparties_services_expired.modules.php:73|check|if (!getDolGlobalString(''CONTRACT_SUPPORT_PRODUCTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CONTRACT_SYNC_PLANNED_DATE_OF_SERVICES', 'string', NULL, 'contrat', 'Triggers synchronisation of the planned dates of contract service lines when a contract operation is performed.', 'Checked at contrat/class/contratligne.class.php:727 within a !$error guard; when set, additional date synchronisation logic is executed for contract lines.', 'Enabling this activates planned date synchronisation on contract service lines during contract operations.', '0 or unset = no date synchronisation; 1 = planned dates of service lines are synchronised.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/class/contratligne.class.php:727|check|if (!$error && getDolGlobalString(''CONTRACT_SYNC_PLANNED_DATE_OF_SERVICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CREATE_NEW_SALARY_WITHOUT_AUTO_PAYMENT', 'string', NULL, 'salaries', 'Disables the automatic creation of a payment record when a new salary entry is saved.', 'Read in salaries/card.php:77 where its negation determines the value of $auto_create_paiement. When the constant is set, auto-payment creation is suppressed.', 'Enabling this setting requires users to create salary payments manually; leaving it empty allows payment records to be created automatically on salary creation.', 'Empty/0 = auto-payment enabled (default); non-empty = auto-payment disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["salaries/card.php:77|read|$auto_create_paiement = !getDolGlobalString(''CREATE_NEW_SALARY_WITHOUT_AUTO_PAYMENT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CREATE_NEW_VAT_WITHOUT_AUTO_PAYMENT', 'string', NULL, 'compta', 'Disables automatic payment creation when a new VAT declaration is created.', 'Checked in compta/tva/card.php:68 where it controls the $auto_create_payment flag: if the constant is set, auto_create_payment is false. Only one occurrence found.', 'When enabled, creating a new VAT record will not automatically generate an associated payment entry.', '0 or unset = auto payment created; non-empty = no auto payment', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/tva/card.php:68|read|$auto_create_payment = !getDolGlobalString(''CREATE_NEW_VAT_WITHOUT_AUTO_PAYMENT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CREDITTRANSFER_USTRD', 'string', NULL, 'compta', 'Sets a custom unstructured remittance information (Ustrd) string in SEPA credit transfer XML.', 'Read in bonprelevement.class.php:2550 as <Ustrd> with an auto-generated fallback from invoice ref and comment. Displayed in admin/paymentbybanktransfer.php:205 for configuration.', 'Setting a non-empty value replaces the per-invoice remittance information in SEPA credit transfer XML with this fixed string; leaving it empty causes the system to generate the Ustrd from the invoice reference and comment.', 'Non-empty string=fixed Ustrd used, empty=auto-generated from invoice ref and comment', 0, 0, 'admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/paymentbybanktransfer.php:205|read|print ''<input type=\"text\" name=\"CREDITTRANSFER_USTRD\" value=\"''.$conf->global->CREDITTRANSFER_USTRD.''\" class=\"width100\"></td>'';", "compta/prelevement/class/bonprelevement.class.php:2550|read|$XML_CREDITOR .= ''\t\t\t\t\t<Ustrd>'' . getDolGlobalString(''CREDITTRANSFER_USTRD'', dolEscapeXML(dol_trunc(dol_string_nospecial(dol_string_unaccent($row_ref . ($row_comment ? '' - '' . $row"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CRON_DISABLE_KEY_CHANGE', 'bool', NULL, 'cron', 'Controls whether the cron security key (CRON_KEY) can be modified or refreshed via the admin UI.', 'Checked at cron/admin/cron.php:103-129; value 1 prevents modification, value -1 hides the refresh button, value 0 allows full key management. Comment at line 99 states: ''Security key for cron (if CRON_DISABLE_KEY_CHANGE is 1: modification is not allowed, -1: no button refresh)''.', 'Setting this to 1 locks the cron key and prevents admin changes; setting it to -1 hides the key refresh button; 0 or unset allows full key management.', '1 = modification not allowed; -1 = no refresh button shown; 0 or unset = full key management allowed.', 0, 0, 'cron/admin/cron.php|cron/admin/cron.php|cron/admin/cron.php|cron/admin/cron.php|cron/admin/cron.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["cron/admin/cron.php:99  // Security key for cron (if CRON_DISABLE_KEY_CHANGE is 1: modification is not allowed, -1: no button refresh)", "cron/admin/cron.php:103|check|if (getDolGlobalInt(''CRON_DISABLE_KEY_CHANGE'') > 0) {", "cron/admin/cron.php:107|check|if (getDolGlobalInt(''CRON_DISABLE_KEY_CHANGE'') != 1) {", "cron/admin/cron.php:113|read|} elseif (getDolGlobalInt(''CRON_DISABLE_KEY_CHANGE'') == -1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CRON_DISABLE_TUTORIAL_CRON', 'bool', NULL, 'core', 'Suppresses the tutorial/help banner shown on the cron job list page.', 'Checked at core/lib/cron.lib.php:143 as a negated condition; the tutorial block is rendered only when this constant is not set. No comment is present in the payload.', 'Setting this constant hides the cron tutorial notice from the scheduler page; unsetting it allows the tutorial to be displayed.', 'Any truthy value hides the tutorial; unset shows it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/cron.lib.php:143|check|if (!getDolGlobalString(''CRON_DISABLE_TUTORIAL_CRON'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CRON_KEY', 'string', NULL, 'cron', 'Security key required to authorize execution of cron jobs via URL or the cron interface.', 'Written at cron/admin/cron.php:57 and validated at cron/card.php:108 and cron/list.php:210 by comparing against the request parameter. Also checked at public/cron/cron_run_jobs_by_url.php:103. Configurable via cron/admin/cron.php.', 'Setting this key requires callers to provide a matching ''securitykey'' parameter to execute cron jobs, preventing unauthorized job execution.', 'Any non-empty string = key is enforced and must match the ''securitykey'' request parameter; empty/unset = no key validation.', 0, 0, 'cron/admin/cron.php|cron/admin/cron.php|cron/admin/cron.php|cron/admin/cron.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["cron/card.php:108|check|if (getDolGlobalString(''CRON_KEY'') && getDolGlobalString(''CRON_KEY'') != $securitykey) {", "cron/list.php:210|check|if (getDolGlobalString(''CRON_KEY'') && getDolGlobalString(''CRON_KEY'') != $securitykey) {", "public/cron/cron_run_jobs_by_url.php:103|check|if ($key != getDolGlobalString(''CRON_KEY'')) {", "cron/admin/cron.php:57|write|$i += dolibarr_set_const($db, ''CRON_KEY'', GETPOST(\"CRON_KEY\"), ''chaine'', 0, '''', 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CRON_MAX_DELAY_FOR_JOBS', 'string', NULL, 'public', 'Sets the maximum age in hours beyond which cron jobs are considered overdue and filtered into the run query.', 'In public/cron/cron_run_jobs_by_url.php at line 148, the value (defaulting to 24 if unset) is multiplied by 3600 to compute a seconds threshold appended to the SQL WHERE clause on datelastrun. No admin UI write path is present.', 'Increasing this value widens the window of jobs considered for execution; decreasing it narrows it. The default is 24 hours.', 'Integer: maximum age in hours (default 24) for jobs to be included in the cron run query', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/cron/cron_run_jobs_by_url.php:148|read|$sql .= \" AND datelastrun <= ''\".$db->idate(dol_now() - getDolGlobalInt(''CRON_MAX_DELAY_FOR_JOBS'', 24) * 3600, ''gmt'').\"''\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('CRON_WARNING_DELAY_HOURS', 'string', NULL, 'cron', 'Sets the number of hours after which a delayed cron job triggers a warning.', 'When set, cron/admin/cron.php:140 displays an admin info message and cron/list.php:511 appends a warning text referencing the configured delay hours value. Configurable via cron/admin/cron.php.', 'Setting this constant causes warnings to appear in the cron admin and list pages when jobs are delayed beyond the specified number of hours.', 'A positive integer representing hours; empty/unset = no delay warning shown.', 0, 0, 'cron/admin/cron.php|cron/admin/cron.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["cron/admin/cron.php:139|check|if (getDolGlobalString(''CRON_WARNING_DELAY_HOURS'')) {", "cron/admin/cron.php:140|read|print info_admin($langs->trans(\"WarningCronDelayed\", getDolGlobalString(''CRON_WARNING_DELAY_HOURS''))).''<br>'';", "cron/list.php:510|check|if (getDolGlobalString(''CRON_WARNING_DELAY_HOURS'')) {", "cron/list.php:511|read|$text .= $langs->trans(\"WarningCronDelayed\", getDolGlobalString(''CRON_WARNING_DELAY_HOURS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DATABASE_PWD_ENCRYPTED', 'string', NULL, 'admin', 'Indicates whether user and member passwords are stored in encrypted (hashed) form in the database.', 'Managed via admin/security.php with entity=0 (all entities) as noted in COMMENTS: ''We set entity=0 (all) because DATABASE_PWD_ENCRYPTED is a setup into conf file, so always shared for everybody.'' Member and user class COMMENTS confirm: ''Clear password in database (defined if DATABASE_PWD_ENCRYPTED=0)''.', 'Setting this to 1 activates password hashing; clearing it stores passwords in clear text. This is a global (entity=0) setting affecting all entities.', '0/empty = passwords stored as clear text; 1 = passwords stored encrypted/hashed', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/security.php|admin/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/security.php|admin/security.php|admin/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security.php:73  // We set entity=0 (all) because DATABASE_PWD_ENCRYPTED is a setup into conf file, so always shared for everybody", "user/class/user.class.php:203  * @var string Clear password in database (defined if DATABASE_PWD_ENCRYPTED=0)", "adherents/class/adherent.class.php:83  * @var string Clear password in database (defined if DATABASE_PWD_ENCRYPTED=0)", "admin/security.php:75|write|dolibarr_set_const($db, \"DATABASE_PWD_ENCRYPTED\", \"1\", ''chaine'', 0, '''', $entityforall);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DATE_LIVRAISON_WEEK_DELAY', 'string', NULL, 'supplier_proposal', 'Sets the default delivery date as a number of weeks from today when creating a proposal.', 'Checked via `is_numeric()` in supplier_proposal/card.php:1635 and comm/propal/card.php:2520. When numeric, the delivery date is computed as `time() + (7 * getDolGlobalInt(''DATE_LIVRAISON_WEEK_DELAY'') * 24 * 60 * 60)` (supplier_proposal/card.php:1636 and comm/propal/card.php:2521).', 'Setting this to an integer pre-fills the delivery date field with today plus the specified number of weeks; setting to 0 pre-fills today''s date.', 'Integer (number of weeks); 0 = today; positive integer = N weeks from today; empty/not numeric = no default delivery date.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1635|check|if (is_numeric(getDolGlobalString(''DATE_LIVRAISON_WEEK_DELAY''))) {\t// If value set to 0 or a num, not empty", "supplier_proposal/card.php:1636|read|$tmpdte = time() + (7 * getDolGlobalInt(''DATE_LIVRAISON_WEEK_DELAY'') * 24 * 60 * 60);", "comm/propal/card.php:2520|check|if (is_numeric(getDolGlobalString(''DATE_LIVRAISON_WEEK_DELAY''))) {\t// If value set to 0 or a num, not empty", "comm/propal/card.php:2521|read|$tmpdte = time() + (7 * getDolGlobalInt(''DATE_LIVRAISON_WEEK_DELAY'') * 24 * 60 * 60);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DAV_ALLOW_ECM_DIR', 'bool', NULL, 'dav', 'Enables access to the ECM (Electronic Content Management) directory via the DAV file server when the ECM module is enabled.', 'Checked at dav/fileserver.php:205; access is granted only if both the ECM module is enabled and this constant is set.', 'Enabling this allows DAV clients to access the ECM directory; it has no effect if the ECM module is disabled.', '0 or unset = ECM directory not accessible via DAV; 1 = accessible (requires ECM module enabled).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dav/fileserver.php:205|check|if (isModEnabled(''ecm'') && getDolGlobalString(''DAV_ALLOW_ECM_DIR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DAV_ALLOW_PUBLIC_DIR', 'bool', NULL, 'dav', 'Enables access to the public documents directory via the DAV file server.', 'Checked at dav/fileserver.php:199 and dav/fileserver.php:235 to grant access to the public directory; also checked at admin/dav.php:209 in the admin UI.', 'Enabling this allows DAV clients to browse and access public documents; disabling it blocks this directory from DAV access.', '0 or unset = public directory not accessible via DAV; 1 = accessible.', 0, 0, 'admin/dav.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/dav.php:209|check|if (getDolGlobalString(''DAV_ALLOW_PUBLIC_DIR'')) {", "dav/fileserver.php:199|check|if (getDolGlobalString(''DAV_ALLOW_PUBLIC_DIR'')) {", "dav/fileserver.php:235|check|if ((!getDolGlobalString(''DAV_ALLOW_PUBLIC_DIR'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DAV_DISABLE_BROWSER', 'bool', NULL, 'dav', 'Disables the DAV browser interface, preventing directory listing via web browser on the DAV endpoint.', 'Checked at dav/fileserver.php:248; when the constant is not set, the browser interface is enabled.', 'Setting this to a truthy value prevents browser-based directory listing of the DAV server.', '0 or unset = browser interface enabled; any truthy value = browser interface disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dav/fileserver.php:248|check|if (!getDolGlobalString(''DAV_DISABLE_BROWSER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DAV_RESTRICT_ON_IP', 'string', NULL, 'dav', 'Restricts access to the DAV file server to a space-separated list of allowed IP addresses.', 'Checked at dav/fileserver.php:81; if set, the remote IP is compared against the space-delimited list (dav/fileserver.php:82) and access is denied with a syslog entry if not matched (dav/fileserver.php:85).', 'Setting this value limits DAV access to the listed IPs only; removing or leaving it empty disables IP-based access restriction.', 'Space-separated list of allowed IP addresses (e.g. ''192.168.1.1 10.0.0.5''); empty = no restriction.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dav/fileserver.php:81|check|if (getDolGlobalString(''DAV_RESTRICT_ON_IP'')) {", "dav/fileserver.php:82|read|$allowedip = explode('' '', getDolGlobalString(''DAV_RESTRICT_ON_IP''));", "dav/fileserver.php:85|read|dol_syslog(''Remote ip is ''.$ipremote.'', not into list '' . getDolGlobalString(''DAV_RESTRICT_ON_IP''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DEBUGBAR_LOGS_LINES_NUMBER', 'string', NULL, 'admin', 'Sets the maximum number of log lines loaded and displayed in the debug bar log collector.', 'Read in debugbar/class/DataCollector/DolLogsCollector.php:61 to set $this->maxnboflines (defaulting to 250). Written via admin/debugbar.php:59 and displayed with a default of ''250'' at admin/debugbar.php:113, which notes that a high number ''slows seriously output''.', 'Increasing this value loads more log lines in the debug bar but degrades page performance; decreasing it speeds up the debug bar display.', 'Positive integer. Default is 250.', 0, 0, 'admin/debugbar.php|admin/debugbar.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["debugbar/class/DataCollector/DolLogsCollector.php:61|read|$this->maxnboflines = getDolGlobalInt(''DEBUGBAR_LOGS_LINES_NUMBER'', 250); // High number slows seriously output", "admin/debugbar.php:113|read|print ''<td><input type=\"text\" class=\"flat width75\" name=\"DEBUGBAR_LOGS_LINES_NUMBER\" value=\"''.getDolGlobalString(''DEBUGBAR_LOGS_LINES_NUMBER'', ''250'').''\">''; // This slow seriously o", "admin/debugbar.php:59|write|$result1 = dolibarr_set_const($db, \"DEBUGBAR_LOGS_LINES_NUMBER\", GETPOSTINT(''DEBUGBAR_LOGS_LINES_NUMBER''), ''chaine'', 0, '''', 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DEBUGBAR_USE_LOG_FILE', 'bool', NULL, 'admin', 'Enables reading log entries from the log file instead of the in-memory log buffer in the debug bar.', 'Read in debugbar/class/DataCollector/DolLogsCollector.php:102 as $uselogfile. Written via admin/debugbar.php:60 and rendered as a yes/no select at admin/debugbar.php:107.', 'Enabling this constant causes the debug bar log collector to source entries from the log file; disabling it uses the in-memory buffer.', '1 = use log file; 0 = use in-memory buffer.', 0, 0, 'admin/debugbar.php|admin/debugbar.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["debugbar/class/DataCollector/DolLogsCollector.php:102|read|$uselogfile =  getDolGlobalInt(''DEBUGBAR_USE_LOG_FILE'');", "admin/debugbar.php:60|write|$result2 = dolibarr_set_const($db, \"DEBUGBAR_USE_LOG_FILE\", GETPOSTINT(''DEBUGBAR_USE_LOG_FILE''), ''chaine'', 0, '''', 0);", "admin/debugbar.php:107|read|print $form->selectyesno(''DEBUGBAR_USE_LOG_FILE'', getDolGlobalString(''DEBUGBAR_USE_LOG_FILE''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DECREASE_ONLY_UNINVOICEDPRODUCTS', 'string', NULL, 'product', 'Restricts stock decrease compensation to orders that have not yet been invoiced.', 'Checked in product/class/product.class.php:3703. The comment at line 3704 states: ''If option DECREASE_ONLY_UNINVOICEDPRODUCTS is on, we make a compensation but only if order not yet invoice.'' Line 3735 states: ''If option DECREASE_ONLY_UNINVOICEDPRODUCTS is off, we make a compensation with lines of invoices linked to the order''.', 'When enabled, only uninvoiced orders are considered for stock compensation; when disabled, invoiced order lines are also included.', 'Truthy string (compensation limited to uninvoiced orders) or empty/unset (compensation includes invoiced orders).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:3704  // If option DECREASE_ONLY_UNINVOICEDPRODUCTS is on, we make a compensation but only if order not yet invoice.", "product/class/product.class.php:3735  // If option DECREASE_ONLY_UNINVOICEDPRODUCTS is off, we make a compensation with lines of invoices linked to the order", "product/class/product.class.php:3703|check|if (getDolGlobalString(''DECREASE_ONLY_UNINVOICEDPRODUCTS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DEFAULT_SEARCH_INTO_MODULE', 'string', NULL, 'core', 'Specifies the default module to pre-select in the global search form when the page loads.', 'Read in core/ajax/selectsearchbox.php:211 where its value is concatenated as ''searchinto'' + value to identify the default search key; checked at line 210 to determine whether a default module override is configured.', 'Setting this causes the search box to default to a specific module''s search result set rather than the generic search.', 'A module suffix string matching the ''searchinto*'' key (e.g. ''invoice'', ''shipment''); empty/unset = no default override.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/selectsearchbox.php:210|check|if (getDolGlobalString(''DEFAULT_SEARCH_INTO_MODULE'')) {", "core/ajax/selectsearchbox.php:211|read|$key = ''searchinto'' . getDolGlobalString(''DEFAULT_SEARCH_INTO_MODULE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DELIVERY_ADDON_NUMBER', 'string', NULL, 'delivery', 'Specifies the numbering module used to generate delivery order reference numbers.', 'Set via admin/delivery.php:194 and read at delivery/class/delivery.class.php:427. The selected module class name is used to instantiate the numbering logic for new delivery records.', 'Changing this value switches the numbering scheme applied to new delivery orders; existing references are unaffected.', 'Name string of the numbering module class file (without .php extension).', 0, 0, 'admin/delivery.php|admin/delivery.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/delivery.php:194|write|dolibarr_set_const($db, \"DELIVERY_ADDON_NUMBER\", $value, ''chaine'', 0, '''', $conf->entity);", "delivery/class/delivery.class.php:427|read|$modName = getDolGlobalString(''DELIVERY_ADDON_NUMBER'');", "admin/delivery.php:291|check|if (getDolGlobalString(''DELIVERY_ADDON_NUMBER'') == \"$file\") {", "delivery/class/delivery.class.php:425|check|if (getDolGlobalString(''DELIVERY_ADDON_NUMBER'')) {"]', 'high', NULL);
