INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DELIVERY_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Delivery documents.', 'Set via the admin UI at admin/delivery.php. The $free variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Delivery documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/delivery.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delivery.php:113|write|$res = dolibarr_set_const($db, \"DELIVERY_FREE_TEXT\", $free, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
