INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DELIVERY_PDF_HIDE_SHIPPED', 'bool', NULL, 'core', 'Hides the shipped-quantity column in delivery order PDFs generated by the Storm module.', 'Read in pdf_storm.modules.php at line 991 within the column status map: the shipped column is active when this constant is NOT set. No admin UI write is present.', 'Enabling this removes the shipped-quantity column from delivery PDFs; disabling restores it.', 'Truthy (non-empty) = column hidden; empty/unset = column shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_storm.modules.php:991|read|''status'' => !getDolGlobalString(''DELIVERY_PDF_HIDE_SHIPPED''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DELIVERY_SAPHIR_MASK', 'string', NULL, 'core', 'Stores the numbering mask used by the Saphir delivery order numbering module.', 'Read in mod_delivery_saphir.php at lines 95 (UI display) and 148 (mask retrieval for number generation). No dolibarr_set_const write is present in the payload.', 'Changing this mask alters how new delivery order reference numbers are generated by the Saphir module.', 'A mask pattern string; empty = no mask.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_delivery_saphir.php:95|read|value=''...getDolGlobalString(''DELIVERY_SAPHIR_MASK'')...", "mod_delivery_saphir.php:148|read|$mask = getDolGlobalString(''DELIVERY_SAPHIR_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DEPOSIT_AS_CREDIT_AVAILABLE_EVEN_UNPAID', 'string', NULL, 'compta', 'When enabled, allows a down payment invoice to be closed and its credit used even if the paid amount does not match the invoice total.', 'Checked in compta/facture/card.php:6767. The inline comment at line 6766 states: ''We can close a down payment only if paid amount is same than amount of down payment (by definition). We can bypass this if hidden and unstable option DEPOSIT_AS_CREDIT_AVAILABLE_EVEN_UNPAID is set.''', 'Enabling this constant bypasses the requirement that a down payment be fully paid before its credit can be applied, which the code comment describes as a hidden and unstable option.', '0 or unset = down payment must be fully paid before credit use; truthy = credit use allowed regardless of paid amount.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:6766  // We can close a down payment only if paid amount is same than amount of down payment (by definition). We can bypass this if hidden and unstable option DEPOSIT_AS_CREDIT_AVAILABLE_EVEN_UNPAID is set.", "compta/facture/card.php:6767|check|if (price2num($object->total_ttc, ''MT'') <= price2num($sumofpaymentall, ''MT'') || getDolGlobalInt(''DEPOSIT_AS_CREDIT_AVAILABLE_EVEN_UNPAID'') || ($object->type == Facture::STATUS_ABAN"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISABLE_BAD_REPUTATION_PRODUCT_PRICE', 'bool', NULL, 'fourn', 'When enabled, suppresses supplier prices for products marked with the ''DONOTORDER'' reputation flag.', 'Checked once in fourn/ajax/getSupplierPrices.php:81. No admin UI writes this constant.', 'When set, products flagged with supplier_reputation=''DONOTORDER'' will have their price suppressed in the supplier price lookup AJAX response.', 'Integer: 1 to disable prices for ''DONOTORDER'' products; 0 or unset to show them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/ajax/getSupplierPrices.php:81|check|if (getDolGlobalInt(\"DISABLE_BAD_REPUTATION_PRODUCT_PRICE\") && $productSupplier->supplier_reputation == \"DONOTORDER\") {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISABLE_CHECK_ON_MALWARE_MODULES', 'bool', NULL, 'admin', 'Disables the malware/compliance check performed on external modules during version checking.', 'Referenced in admin/modules.php:1037 to skip the compliance check when set, and in admin/modules.php:1556 to pre-check the ''checkforcompliance'' checkbox if not set. Both uses are in the context of external module management.', 'Enabling this constant bypasses the malware check for external modules, removing a security verification step. Disabling restores compliance checking.', 'Empty/unset = compliance check enabled; non-empty = compliance check disabled', 0, 0, 'admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1037|check|if ($objMod->isCoreOrExternalModule() == ''external'' && $action == ''checklastversion'' && !getDolGlobalString(''DISABLE_CHECK_ON_MALWARE_MODULES'')) {", "admin/modules.php:1556|read|print ''<span class=\"opacitymedium\"><input class=\"paddingright\" type=\"checkbox\" name=\"checkforcompliance\" id=\"checkforcompliance\"''.(getDolGlobalString(''DISABLE_CHECK_ON_MALWARE_MODU"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISCOUNT_SPLIT_MORE_THAN_TWO_PARTS', 'string', NULL, 'comm', 'Enables splitting a discount across more than two parts in the discount management UI.', 'Checked in comm/remx.php:658 and comm/remx.php:952 in combination with MAIN_DISABLE_JAVASCRIPT; the feature is only activated when JavaScript is also enabled.', 'Enabling this constant allows discount lines to be split into more than two parts; it has no effect when JavaScript is disabled.', '0 or not set = only two-part split allowed; non-zero integer = more than two parts allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/remx.php:658|check|if (getDolGlobalInt(''DISCOUNT_SPLIT_MORE_THAN_TWO_PARTS'') && !getDolGlobalInt(''MAIN_DISABLE_JAVASCRIPT'')) {", "comm/remx.php:952|check|if (getDolGlobalInt(''DISCOUNT_SPLIT_MORE_THAN_TWO_PARTS'') && !getDolGlobalInt(''MAIN_DISABLE_JAVASCRIPT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISPLAY_DISCOUNTED_SUPPLIER_PRICE', 'string', NULL, 'core', 'Controls whether supplier prices shown in product combo/select lists are displayed after applying the discount percentage.', 'Used exclusively in core/class/html.form.class.php (lines 4260–4546). When truthy, prices are multiplied by (1 - remise_percent/100) before display in option labels and values; when falsy the raw supplier price is shown.', 'Enabling causes all supplier price fields in product selectors to reflect the post-discount price. Disabling shows the gross price, which may lead to misinterpretation of supplier pricing.', 'Truthy = display discounted price (fprice * (1 - remise_percent/100)); empty/unset/falsy = display raw supplier price.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:4260|read|$optlabel .= '' - '' . price($objp->fprice * (getDolGlobalString(''DISPLAY_DISCOUNTED_SUPPLIER_PRICE'') ? (1 - $objp->remise_percent / 100) : 1), 1, $langs, 0, 0, -1, $conf->currency)", "core/class/html.form.class.php:4534|read|$opt .= price($objp->fprice * (getDolGlobalString(''DISPLAY_DISCOUNTED_SUPPLIER_PRICE'') ? (1 - $objp->remise_percent / 100) : 1), 1, $langs, 0, 0, -1, $conf->currency) . \"/\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISPLAY_MARGIN_RATES', 'string', NULL, 'margin', 'Enables display of margin rate columns and fields across invoices, orders, and margin reports.', 'Configured in margin/admin/margin.php at line 159. Checked in over 40 locations including core/tpl/objectline_title.tpl.php, core/tpl/objectline_edit.tpl.php, and margin tab files. A JS property comment documents it as a boolean configuration flag.', 'Disabling this constant hides all margin-rate display columns site-wide. Enabling it shows margin rates on document lines and margin report pages, subject to user rights.', '0 or unset = margin rates hidden; 1 = margin rates displayed', 0, 0, 'margin/admin/margin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* @property {boolean} conf.DISPLAY_MARGIN_RATES", "if (!getDolGlobalString(''DISPLAY_MARGIN_RATES'')) {", "if (getDolGlobalString(''DISPLAY_MARGIN_RATES'') && $user->hasRight(''margins'', ''liretous'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DISPLAY_MARK_RATES', 'string', NULL, 'margin', 'Enables display of mark-up rate columns and fields across invoices, orders, and margin reports.', 'Configured in margin/admin/margin.php at line 176. Checked in over 40 locations including core/tpl/objectline_edit.tpl.php and margin tab files. A JS property comment documents it as a boolean configuration flag alongside DISPLAY_MARGIN_RATES.', 'Disabling this constant hides all mark-rate columns site-wide. Enabling it shows mark-up rates on document lines and margin report pages.', '0 or unset = mark rates hidden; 1 = mark rates displayed', 0, 0, 'margin/admin/margin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* @property {boolean} conf.DISPLAY_MARK_RATES", "if (!getDolGlobalString(''DISPLAY_MARK_RATES'')) {", "if (getDolGlobalString(''DISPLAY_MARK_RATES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DOC_SHOW_CUSTOMER_CODE', 'bool', NULL, 'core', 'When set, shows the customer code in stock transfer proforma PDF documents.', 'Checked in a single location in core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php combined with a non-empty $object->thirdparty->code_client check before rendering the customer code field.', 'Enabling this adds the customer code to the proforma document when the third party has a customer code set. Disabling (or leaving unset) suppresses the field.', 'Empty/unset = hide customer code; any truthy value (with non-empty code_client) = show customer code.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eagle_proforma.modules.php:1333|if (getDolGlobalString(''DOC_SHOW_CUSTOMER_CODE'') && !empty($object->thirdparty->code_client)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DOC_SHOW_FIRST_SALES_REP', 'bool', NULL, 'core', 'Controls whether the first assigned sales representative is printed in generated PDF documents.', 'Written via admin/pdf.php:191 and rendered in the admin UI at admin/pdf.php:662. Checked in 18 locations across invoice, order, contract, and stocktransfer PDF modules.', 'When enabled, the name of the first sales representative assigned to the object is included in the PDF output.', '0 (hide sales rep) or 1 (show first sales rep)', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:191|write|dolibarr_set_const($db, \"DOC_SHOW_FIRST_SALES_REP\", GETPOST(''DOC_SHOW_FIRST_SALES_REP'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:662|read|print $form->selectarray(\"DOC_SHOW_FIRST_SALES_REP\", $arrval, getDolGlobalString(''DOC_SHOW_FIRST_SALES_REP''));", "core/modules/commande/doc/pdf_einstein.modules.php:1478|check|if (getDolGlobalString(''DOC_SHOW_FIRST_SALES_REP'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:2179|check|if (getDolGlobalString(''DOC_SHOW_FIRST_SALES_REP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DOL_URL_ROOT_DOCUMENT_PHP', 'string', NULL, 'comm', 'Overrides the default URL used to serve Dolibarr documents, replacing the standard document.php wrapper.', 'When set, this URL replaces DOL_URL_ROOT.''/document.php'' in file serving contexts. The comment in core/class/html.formfile.class.php:977 reads ''DOL_URL_ROOT_DOCUMENT_PHP can be used to set another wrapper''. Also checked in comm/action/rapport/index.php:186 and admin/geoipmaxmind.php:118.', 'Setting this to a custom URL redirects all document download links to the specified wrapper, useful for custom authentication or CDN integration.', 'String: full URL of the document wrapper; empty/unset = defaults to DOL_URL_ROOT.''/document.php''.', 0, 0, 'admin/geoipmaxmind.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formfile.class.php:977|read|$documenturl = getDolGlobalString(''DOL_URL_ROOT_DOCUMENT_PHP'', DOL_URL_ROOT.''/document.php''); // DOL_URL_ROOT_DOCUMENT_PHP can be used to set another wrapper", "admin/geoipmaxmind.php:118|read|$documenturl = getDolGlobalString(''DOL_URL_ROOT_DOCUMENT_PHP'', DOL_URL_ROOT.''/document.php'');", "comm/action/rapport/index.php:187|read|$documenturl = getDolGlobalString(''DOL_URL_ROOT_DOCUMENT_PHP''); // To use another wrapper", "comm/action/rapport/index.php:186|read|if (isset($conf->global->DOL_URL_ROOT_DOCUMENT_PHP)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_ACCOUNTINGACCOUNT', 'string', NULL, 'don', 'Stores the general ledger account number used for donation payment entries in accounting journals.', 'Configured via don/admin/donation.php:124 (write) and displayed with a select_account widget at line 359. Read in accountancy/journal/bankjournal.php:274 and accountancy/journal/treasuryjournal.php:777 with ''NotDefined'' as reserved-word fallback.', 'If not set, donation payment lines in the bank and treasury journals use ''NotDefined'' as the account, which will cause posting errors.', 'String: general ledger account number; empty = not configured', 0, 0, 'don/admin/donation.php|don/admin/donation.php|don/admin/donation.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["don/admin/donation.php:124|write|$res = dolibarr_set_const($db, \"DONATION_ACCOUNTINGACCOUNT\", $account, ''chaine'', 0, '''', $conf->entity);", "accountancy/journal/bankjournal.php:274|read|$account_pay_donation = getDolGlobalString(''DONATION_ACCOUNTINGACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/treasuryjournal.php:777|read|$account_pay_donation = getDolGlobalString(''DONATION_ACCOUNTINGACCOUNT'', ''NotDefined''); // NotDefined is a reserved word", "don/admin/donation.php:359|read|print $formaccounting->select_account(getDolGlobalString(''DONATION_ACCOUNTINGACCOUNT''), ''DONATION_ACCOUNTINGACCOUNT'', 1, array(), 1, 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_ART200', 'string', NULL, 'don', 'Selects the fiscal article 200 tax-reduction option shown on the French Cerfa donation receipt PDF.', 'Read at don/admin/donation.php:402 to populate a dropdown selector. Checked at core/modules/dons/html_cerfafr.modules.php:199; when the integer value is >= 1, the article 200 section is included in the Cerfa PDF.', 'Enabling this option (value >= 1) causes the French Cerfa PDF to include the article 200 tax-reduction checkbox; leaving it unset or 0 omits that section.', 'Integer: 0 or unset = article 200 not included; >= 1 = article 200 included in Cerfa PDF.', 0, 0, 'don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:402|read|print $form->selectarray(\"DONATION_ART200\", $arrval, getDolGlobalString(''DONATION_ART200''));", "core/modules/dons/html_cerfafr.modules.php:199|check|if (getDolGlobalInt(''DONATION_ART200'') >= 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_ART238', 'string', NULL, 'don', 'Selects the fiscal article 238 tax-reduction option shown on the French Cerfa donation receipt PDF.', 'Read at don/admin/donation.php:413 to populate a dropdown selector. Checked at core/modules/dons/html_cerfafr.modules.php:209; when the integer value is >= 1, the article 238 section is included in the Cerfa PDF.', 'Enabling this option (value >= 1) causes the French Cerfa PDF to include the article 238 tax-reduction checkbox; leaving it unset or 0 omits that section.', 'Integer: 0 or unset = article 238 not included; >= 1 = article 238 included in Cerfa PDF.', 0, 0, 'don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:413|read|print $form->selectarray(\"DONATION_ART238\", $arrval, getDolGlobalString(''DONATION_ART238''));", "core/modules/dons/html_cerfafr.modules.php:209|check|if (getDolGlobalInt(''DONATION_ART238'') >= 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_ART978', 'string', NULL, 'don', 'Selects the fiscal article 978 tax-reduction option shown on the French Cerfa donation receipt PDF.', 'Read at don/admin/donation.php:424 to populate a dropdown selector. Checked at core/modules/dons/html_cerfafr.modules.php:219; when the integer value is >= 1, the article 978 section is included in the Cerfa PDF.', 'Enabling this option (value >= 1) causes the French Cerfa PDF to include the article 978 tax-reduction checkbox; leaving it unset or 0 omits that section.', 'Integer: 0 or unset = article 978 not included; >= 1 = article 978 included in Cerfa PDF.', 0, 0, 'don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:424|read|print $form->selectarray(\"DONATION_ART978\", $arrval, getDolGlobalString(''DONATION_ART978''));", "core/modules/dons/html_cerfafr.modules.php:219|check|if (getDolGlobalInt(''DONATION_ART978'') >= 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_COUNTERS_ARE_PUBLIC', 'string', NULL, 'don', 'Controls whether donation counters (totals or counts) are displayed publicly on the donation page.', 'Written via don/admin/website.php:84 and rendered as a yes/no selector at don/admin/website.php:205 using getDolGlobalInt. Configurable via the donation admin UI.', 'Enabling this constant exposes aggregated donation statistics to unauthenticated visitors on the public donation page.', '1 = counters visible publicly; 0 or unset = counters hidden.', 0, 0, 'don/admin/website.php|don/admin/website.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/website.php:84|write|$res = dolibarr_set_const($db, \"DONATION_COUNTERS_ARE_PUBLIC\", $publiccounters, ''chaine'', 0, '''', $conf->entity);", "don/admin/website.php:205|read|print $form->selectyesno(\"DONATION_COUNTERS_ARE_PUBLIC\", getDolGlobalInt(''DONATION_COUNTERS_ARE_PUBLIC''), 1, false, 0, 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_ENABLE_PUBLIC', 'bool', NULL, 'don', 'Enables the public-facing online donation form accessible without authentication.', 'Written via don/admin/website.php (lines 69, 71, 82) and checked at don/admin/website.php:148/165 and public/donations/new.php:95. When unset or 0, access to the public donation page is blocked.', 'Setting this to 1 opens the public donation form to unauthenticated visitors; setting to 0 or leaving unset blocks public access.', '1 = public donation form enabled; 0 or unset = public form disabled.', 0, 0, 'don/admin/website.php|don/admin/website.php|don/admin/website.php|don/admin/website.php|don/admin/website.php|don/admin/website.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/website.php:69|write|dolibarr_set_const($db, ''DONATION_ENABLE_PUBLIC'', 1, ''chaine'', 0, '''', $conf->entity);", "don/admin/website.php:148|check|if (!getDolGlobalString(''DONATION_ENABLE_PUBLIC'')) {", "public/donations/new.php:95|check|if (!getDolGlobalString(''DONATION_ENABLE_PUBLIC'')) {", "don/admin/website.php:165|check|if (getDolGlobalString(''DONATION_ENABLE_PUBLIC'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_EXT_URL_SUBSCRIPTION_INFO', 'string', NULL, 'public', 'Specifies an external URL displayed as an information link on the public donation payment form.', 'Checked and read at public/payment/newpayment.php:2126-2127; when set, a ''SeeHere'' link pointing to this URL is rendered on the donation form.', 'When set, a link to this URL appears on the donation form for additional information; when unset, no link is shown.', 'An external URL string; empty/unset means no info link is shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:2126|check|if (getDolGlobalString(''DONATION_EXT_URL_SUBSCRIPTION_INFO'')) {", "public/payment/newpayment.php:2127|read|print '' - <a href=\"'' . getDolGlobalString(''DONATION_EXT_URL_SUBSCRIPTION_INFO'').''\" rel=\"external\" target=\"_blank\" rel=\"noopener noreferrer\">''.$langs->trans(\"SeeHere\").''</a>'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_INVOICE_MIN_AMOUNT', 'string', NULL, 'public', 'Sets the minimum accepted amount for a public donation invoice submission.', 'Read at public/invoice/new.php:545 via max() to enforce a floor on the amount, checked at :258 to reject amounts at or below this value, and used at :260 to display an error message with the minimum. Described in the file header as ''Minimum amount''.', 'Amounts submitted below or equal to this value are rejected with an error; the floor is enforced server-side.', 'Minimum amount (numeric float/int string)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/invoice/new.php:33  *  DONATION_INVOICE_MIN_AMOUNT                   Minimum amount", "public/invoice/new.php:545|read|$amount = max(0, (float) $amount, (float) getDolGlobalInt(\"DONATION_INVOICE_MIN_AMOUNT\"));", "public/invoice/new.php:258|check|if (!$amount || $amount <= (float) getDolGlobalString(\"DONATION_INVOICE_MIN_AMOUNT\")) {", "public/invoice/new.php:260|read|$errmsg .= $langs->trans(\"ErrorFieldMinimumAmount\", (float) getDolGlobalString(\"DONATION_INVOICE_MIN_AMOUNT\")).\"<br>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_MESSAGE', 'string', NULL, 'core', 'Custom free-text message displayed on the donation form and embedded in donation PDF documents.', 'Written via don/admin/donation.php:142 and rendered in a textarea at don/admin/donation.php:374. Read and substituted into the Cerfa PDF template at core/modules/dons/html_cerfafr.modules.php:180 and conditionally inserted as an HTML block in core/modules/dons/html_generic.modules.php:159-160.', 'Setting this constant inserts a custom message into both the donation input form and generated donation documents; leaving it empty omits the message block.', 'Arbitrary HTML/text string. Empty or unset = no message displayed.', 0, 0, 'don/admin/donation.php|don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:374|read|print ''<textarea name=\"DONATION_MESSAGE\" class=\"flat\" cols=\"80\">'' . getDolGlobalString(''DONATION_MESSAGE'').''</textarea>'';", "core/modules/dons/html_cerfafr.modules.php:180|read|$form = str_replace(''__DONATION_MESSAGE__'', getDolGlobalString(''DONATION_MESSAGE''), $form);", "core/modules/dons/html_generic.modules.php:159|check|if (getDolGlobalString(''DONATION_MESSAGE'')) {", "core/modules/dons/html_generic.modules.php:160|read|$donationMessage = ''<div id=\"donation-message\"><p>'' . getDolGlobalString(''DONATION_MESSAGE'').''</p></div>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_MIN_AMOUNT', 'string', NULL, 'public', 'Minimum amount required for a donation submission on the public donation form.', 'COMMENTS state: ''DONATION_MIN_AMOUNT   Minimum amount''. Written via don/admin/website.php:83 and enforced in public/donations/new.php:218-220 (form validation) and public/donations/new.php:541 (max with 0). Also enforced in public/payment/newpayment.php:2152-2153.', 'Setting a positive value prevents donors from submitting amounts below the threshold; the form displays an error and the payment amount is floored to the minimum.', 'Numeric value representing the minimum donation amount in the default currency. 0 or unset = no minimum enforced.', 0, 0, 'don/admin/website.php|don/admin/website.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["public/donations/new.php:33  *  DONATION_MIN_AMOUNT                   Minimum amount", "public/donations/new.php:218|check|if (!GETPOST(''amount'') || GETPOST(''amount'') < getDolGlobalInt(''DONATION_MIN_AMOUNT'')) {", "public/donations/new.php:541|read|$amount = max(0, (float) $amount, (float) getDolGlobalInt(\"DONATION_MIN_AMOUNT\"));", "public/payment/newpayment.php:2153|read|$valtoshow = max(getDolGlobalString(''DONATION_MIN_AMOUNT''), $valtoshow);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_NEWFORM_AMOUNT', 'string', NULL, 'public', 'Sets the pre-filled default donation amount displayed and submitted on the public donation payment form.', 'Checked and read at public/payment/newpayment.php:2123, :2129, :2140, :2141, :2144, :2145; used both as the displayed value and as the submitted amount when set.', 'When set, the donation form pre-fills with this amount; when unset, the user must enter an amount manually.', 'A numeric amount string; empty/unset means no default amount is pre-filled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:2141|read|$valtoshow = getDolGlobalString(''DONATION_NEWFORM_AMOUNT'');", "public/payment/newpayment.php:2145|read|$amount = getDolGlobalString(''DONATION_NEWFORM_AMOUNT'');", "public/payment/newpayment.php:2140|check|if (getDolGlobalString(''DONATION_NEWFORM_AMOUNT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_NEWFORM_EDITAMOUNT', 'string', NULL, 'public', 'When enabled, allows the user to edit the donation amount on the public payment form even when a default amount is set.', 'Checked at public/payment/newpayment.php:2139 in combination with DONATION_NEWFORM_AMOUNT; when set, the amount field is editable. No admin UI write found.', 'When set, donors can modify the pre-filled amount; when unset, the default amount from DONATION_NEWFORM_AMOUNT is used as-is.', '0 or unset = amount not editable; non-zero = amount editable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:2139|check|if (getDolGlobalString(''DONATION_NEWFORM_EDITAMOUNT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_NEWFORM_PAYONLINE', 'string', NULL, 'public', 'Specifies the online payment method suggested on the public donation form (e.g. paypal, paybox, stripe, or ''all'').', 'COMMENTS state: ''DONATION_NEWFORM_PAYONLINE   Suggest payment with paypal, paybox or stripe''. Written via don/admin/website.php:85 and checked/read in public/donations/new.php:320, :326, :327, :537. When set to ''-1'', the payment redirect is skipped.', 'Setting this to a specific payment provider name restricts online payment to that provider; ''all'' enables all configured providers; ''-1'' disables online payment suggestion.', 'Payment provider name string (e.g. ''paypal'', ''paybox'', ''stripe''); ''all'' = all providers; ''-1'' = no online payment; unset = no payment method suggested.', 0, 0, 'don/admin/website.php|don/admin/website.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["public/donations/new.php:34  *  DONATION_NEWFORM_PAYONLINE            Suggest payment with paypal, paybox or stripe", "public/donations/new.php:320|check|if (getDolGlobalString(''DONATION_NEWFORM_PAYONLINE'') && getDolGlobalString(''DONATION_NEWFORM_PAYONLINE'') != ''-1'') {", "public/donations/new.php:326|check|if (getDolGlobalString(''DONATION_NEWFORM_PAYONLINE'') != ''-1'' && getDolGlobalString(''DONATION_NEWFORM_PAYONLINE'') != ''all'') {", "public/donations/new.php:327|read|$urlback .= ''&paymentmethod=''.urlencode(getDolGlobalString(''DONATION_NEWFORM_PAYONLINE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_NOTE_PUBLIC', 'string', NULL, 'core', 'Enables display of the public note on donation documents when its value is >= 1.', 'Checked once in core/modules/dons/html_generic.modules.php at line 153: the public note is printed only when this constant is >= 1 and note_public is non-empty. No admin UI write is present.', 'Setting this to 1 or higher causes the donation''s public note to appear on donation documents; setting it to 0 or leaving it unset suppresses the note.', 'Integer >= 1 = public note shown; 0 or unset = public note hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["html_generic.modules.php:153|check|if (getDolGlobalInt(''DONATION_NOTE_PUBLIC'') >= 1 && !empty($don->note_public)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_PUBLIC_INTERFACE', 'string', NULL, 'public', 'Sets the topic/title string displayed in the public donation registration page header.', 'Read at public/donations/new.php:164 as the topic argument to htmlPrintOnlineHeader(). No admin UI write found.', 'If set, the public donation page header displays this custom string as the page topic.', 'Any string used as the public donation interface header topic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/donations/new.php:164|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''DONATION_PUBLIC_INTERFACE''), ''DONATION_IMAGE_PUBLIC_REGISTRATION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONATION_USE_THIRDPARTIES', 'bool', NULL, 'don', 'Links donation records to third-party (company/contact) entities when the Societe module is enabled.', 'Configured in don/admin/donation.php:342 via a selectarray UI and checked extensively in don/card.php and don/list.php. When enabled, donation forms require or display a third-party selector, and statistics are grouped by third-party.', 'Enabling this constant associates donations with third-party records, enabling CRM-style tracking; disabling it keeps donations standalone without a third-party link.', 'String value selected from an array in admin; truthy enables third-party linkage, empty/falsy disables it.', 0, 0, 'don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:342|read|print $form->selectarray(\"DONATION_USE_THIRDPARTIES\", $arrval, getDolGlobalString(''DONATION_USE_THIRDPARTIES''));", "don/card.php:414|check|if (isModEnabled(\"societe\") && getDolGlobalString(''DONATION_USE_THIRDPARTIES'')) {", "don/list.php:670|check|if (getDolGlobalString(''DONATION_USE_THIRDPARTIES'')) {", "don/stats/index.php:218|check|if (getDolGlobalString(''DONATION_USE_THIRDPARTIES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DONT_INCLUDE_COMPLETED_ELEMENTS_LINKS', 'string', NULL, 'core', 'When enabled, excludes completed elements from the linked-elements selector list.', 'Read at core/class/html.form.class.php:10485 into $dontIncludeCompletedItems, which controls whether completed items appear in element link selectors.', 'Enabling hides completed tasks/elements from link selectors, reducing clutter. Disabling (leaving unset) includes all elements regardless of completion status.', 'Truthy = exclude completed elements from link selectors; empty/unset = include all elements.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:10485|read|$dontIncludeCompletedItems = getDolGlobalString(''DONT_INCLUDE_COMPLETED_ELEMENTS_LINKS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DON_ADDON_MODEL', 'string', NULL, 'don', 'Selects the active PDF document template (addon model) used to generate donation documents.', 'Set and read via the donation admin page at don/admin/donation.php. The value is the model name string; it is read in don/class/don.class.php:1063-1064 to load the appropriate PDF class. Multiple write and check occurrences confirm it is an actively managed admin setting.', 'Changing the value switches the PDF layout used for donation documents; deleting the constant (via dolibarr_del_const) reverts to the default template.', 'String; name of a donation PDF addon model class available in the system.', 0, 0, 'don/admin/donation.php|don/admin/donation.php|don/admin/donation.php|don/admin/donation.php|don/admin/donation.php|don/admin/donation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/admin/donation.php:97|write|if (dolibarr_set_const($db, \"DON_ADDON_MODEL\", $value, ''chaine'', 0, '''', $conf->entity)) {", "don/class/don.class.php:1063|read|} elseif (getDolGlobalString(''DON_ADDON_MODEL'')) {", "don/class/don.class.php:1064|read|$modele = getDolGlobalString(''DON_ADDON_MODEL'');", "don/admin/donation.php:115|write|dolibarr_del_const($db, ''DON_ADDON_MODEL'', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('DO_NOT_TRY_TO_DEFRAGMENT_STOCKS_WAREHOUSE', 'string', NULL, 'product', 'Reverses warehouse stock sort order to DESC to skip defragmentation-friendly ordering.', 'Read in product/class/product.class.php:6350 and product/class/productbatch.class.php:535. Comments on both lines note that ASC order is important for expedition card to avoid stock fragmentation; setting this constant switches to DESC.', 'When set, stock rows are fetched in descending quantity order, preventing the defragmentation behaviour that ASC ordering provides for shipment picks.', 'Truthy string (DESC order, no defragmentation) or empty/unset (ASC order, defragmentation-friendly).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6350|read|$sql .= \" ORDER BY ps.reel \".(getDolGlobalString(''DO_NOT_TRY_TO_DEFRAGMENT_STOCKS_WAREHOUSE'') ? ''DESC'' : ''ASC''); // Note : qty ASC is important for expedition card, to avoid stock", "product/class/productbatch.class.php:535|read|$sql .= \", t.qty \".(!getDolGlobalString(''DO_NOT_TRY_TO_DEFRAGMENT_STOCKS_WAREHOUSE'') ? ''ASC'' : ''DESC''); // Note : qty ASC is important for expedition card, to avoid stock fragmenta"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ECM_AUTO_TREE_HIDEN', 'bool', NULL, 'core', 'Hides the automatic directory tree in the ECM (Electronic Content Management) module when enabled.', 'Referenced in admin/ecm.php, core/lib/ecm.lib.php, ecm/index_auto.php, and core/modules/modECM.class.php. The module menu entry for the ECM auto tree is also conditionally suppressed based on this constant (modECM.class.php:182).', 'Enabling this constant hides the automatic ECM folder tree from the UI and the module menu. Disabling restores the tree view.', 'Empty/unset = tree visible; non-empty = tree hidden', 0, 0, 'admin/ecm.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ecm.php:111|check|if (!getDolGlobalString(''ECM_AUTO_TREE_HIDEN'')) {", "core/lib/ecm.lib.php:57|check|if (!getDolGlobalString(''ECM_AUTO_TREE_HIDEN'')) {", "ecm/index_auto.php:316|check|if (!getDolGlobalString(''ECM_AUTO_TREE_HIDEN'')) {", "core/modules/modECM.class.php:182|read|''enabled'' => ''($user->hasRight(\"ecm\", \"read\") || $user->hasRight(\"ecm\", \"upload\")) && !getDolGlobalInt(\"ECM_AUTO_TREE_HIDEN\")'',"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ECM_SHOW_GENERATE_WEBP_BUTTON', 'bool', NULL, 'core', 'Shows a button to generate WebP versions of images in the file manager.', 'Checked in core/tpl/filemanager.tpl.php:129 to conditionally render the WebP generation button.', 'Enabling this constant adds a WebP image generation button to the file manager interface.', 'Integer 1 = button shown; 0 or unset = button hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/filemanager.tpl.php:129|check|if (getDolGlobalInt(''ECM_SHOW_GENERATE_WEBP_BUTTON'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EDIT_ORDER_SHIPMENT_ON_PROCESS', 'string', NULL, 'commande', 'Allows editing of an order that is in ''shipment on process'' status.', 'Checked in commande/card.php:3527. Normally editing is restricted to validated status; with this constant set, orders in STATUS_SHIPMENTONPROCESS are also editable. No admin UI write is present.', 'Setting this constant grants edit rights on orders in shipment-on-process status. Leaving it unset restricts editing to orders in validated status only.', 'Truthy = orders in shipment-on-process status are editable; falsy or unset = only validated orders are editable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3527|check|if (($object->status == Commande::STATUS_VALIDATED || ($object->status == Commande::STATUS_SHIPMENTONPROCESS && getDolGlobalString(''EDIT_ORDER_SHIPMENT_ON_PROCESS''))) && $usercancr"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILCOLLECTOR_ISNOTANSWER_USE_REFERENCES', 'bool', NULL, 'admin', 'Causes emails with generic References headers to be treated as replies when applying the ''isnotanswer'' collector filter.', 'When enabled, the email collector checks the References header even for emails not otherwise identified as answers. The comment states: ''Consider generic References as answer for isnotanswer filter.'' Configured via a select dropdown in admin/emailcollector_list.php.', 'Enabling this constant allows emails with References headers to match the ''isnotanswer'' filter as if they were replies; disabling it restricts the filter to emails identified as answers by other means.', 'Integer: non-zero enables References-based answer detection; 0 disables it.', 0, 0, 'admin/emailcollector_list.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// EMAILCOLLECTOR_ISNOTANSWER_USE_REFERENCES: Consider generic References as answer for \"isnotanswer\" filter.", "emailcollector/class/emailcollector.class.php:2076|check|if (!$isanswer && getDolGlobalInt(''EMAILCOLLECTOR_ISNOTANSWER_USE_REFERENCES'') && !empty($headers[''References''])) {", "admin/emailcollector_list.php:815|read|print $form->selectarray(\"EMAILCOLLECTOR_ISNOTANSWER_USE_REFERENCES\", $arrval, getDolGlobalInt(''EMAILCOLLECTOR_ISNOTANSWER_USE_REFERENCES'', 0));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILCOLLECTOR_NO_FILTER_ON_DATE_IF_THERE_IS_A_TARGETDIR', 'string', NULL, 'emailcollector', 'Disables the date-based filter on email collection when a target directory is configured.', 'In emailcollector/class/emailcollector.class.php at line 1560, the inline comment states ''Use the last date of successful check as a filter if there is no target dir''; when both a targetdir and this constant are set, the date filter is skipped. No admin UI write path is present.', 'Setting this causes the collector to fetch all emails regardless of date when a target directory is present, rather than only those newer than the last successful run.', '0 or unset = apply date filter even with target dir; non-zero = skip date filter when target dir is set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:1560|check|if (empty($targetdir) || !getDolGlobalString(''EMAILCOLLECTOR_NO_FILTER_ON_DATE_IF_THERE_IS_A_TARGETDIR'')) {\t// Use the last date of successful check as a filter if there is no targ"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILCOLLECTOR_USE_IN_REPLY_TO_TO_DETECT_ANSWERS', 'bool', NULL, 'emailcollector', 'Enables using the In-Reply-To email header to detect whether an incoming email is a reply to a Dolibarr-sent message.', 'In emailcollector/class/emailcollector.class.php at lines 2048 and 2079, when set the In-Reply-To header is additionally checked to determine if a message is an answer. No admin UI write path is present.', 'Enabling this improves reply detection accuracy by also checking the In-Reply-To header, not just References.', '0 or unset = only References header checked; non-zero = also check In-Reply-To header', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:2048|check|if (getDolGlobalString(''EMAILCOLLECTOR_USE_IN_REPLY_TO_TO_DETECT_ANSWERS'')) {", "emailcollector/class/emailcollector.class.php:2079|check|if (!$isanswer && getDolGlobalString(''EMAILCOLLECTOR_USE_IN_REPLY_TO_TO_DETECT_ANSWERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILCOLLECTOR_USE_THIS_THIRDPARTY_ID_IF_DUPLICATE', 'bool', NULL, 'emailcollector', 'Specifies a fallback third-party ID to use when the email collector finds multiple matching third parties for a sender.', 'In emailcollector/class/emailcollector.class.php at lines 2948-2949, the inline comment states ''If 2 thirdparty found, we will use a generic one defined by EMAILCOLLECTOR_USE_THIS...''; when result == -2 (duplicate found) and this constant is set, its integer value is used as the thirdparty ID. No admin UI write path is present.', 'Setting this prevents collection failures caused by duplicate third-party matches by designating a specific fallback third party.', 'Integer: ID of the llx_societe record to use as fallback when multiple thirdparties match; 0 or unset = no fallback', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:2948|check|if (getDolGlobalInt(''EMAILCOLLECTOR_USE_THIS_THIRDPARTY_ID_IF_DUPLICATE'') && $result == -2) {\t// If 2 thirdparty found, we will use a generic one defined by EMAILCOLLECTOR_USE_THIS", "emailcollector/class/emailcollector.class.php:2949|read|$idtouseforthirdparty = getDolGlobalInt(''EMAILCOLLECTOR_USE_THIS_THIRDPARTY_ID_IF_DUPLICATE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILINGS_SUPPORT_ALSO_SMS', 'string', NULL, 'comm', 'Enables SMS support alongside email in the mass mailing (emailings) module.', 'Referenced across comm/mailing/list.php, comm/mailing/index.php, and comm/mailing/card.php. When set to a non-zero integer, additional SMS-related UI sections and logic branches are activated in the mailing interface.', 'Enabling this constant unlocks SMS sending capabilities within the emailings module. Disabling hides SMS-related options and paths.', '0 or unset = email only; 1 = SMS support also enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/list.php:454|check|if (getDolGlobalInt(''EMAILINGS_SUPPORT_ALSO_SMS'')) {", "comm/mailing/index.php:76|check|if (getDolGlobalInt(''EMAILINGS_SUPPORT_ALSO_SMS'')) {", "comm/mailing/card.php:862|check|if (getDolGlobalInt(''EMAILINGS_SUPPORT_ALSO_SMS'')) {", "comm/mailing/list.php:508|check|if (getDolGlobalInt(''EMAILINGS_SUPPORT_ALSO_SMS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILING_CAN_EDIT_BACKGROUND_COLOR', 'string', NULL, 'comm', 'Intended to enable background color editing in the email content editor, but the code is currently commented out.', 'Both occurrences in comm/mailing/card.php (lines 927 and 1418) are inside PHP block comments (/* ... */). The constant has no active effect in the codebase as of the payload.', 'Exact behavior unclear from code alone — the feature is commented out. No active effect is produced by setting or clearing this constant in the current code.', 'Any value; currently has no effect as all usage is commented out', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:927  /* if (getDolGlobalString(''EMAILING_CAN_EDIT_BACKGROUND_COLOR'')) {", "comm/mailing/card.php:1418  /* if (getDolGlobalString(''EMAILING_CAN_EDIT_BACKGROUND_COLOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILING_MAIL_SENDMODE', 'string', NULL, 'comm', 'Overrides the email sending mode specifically for mass mailing campaigns.', 'Read in comm/mailing/card.php:997 into $sendingmode, which is subsequently used to select the mail transport (e.g. ''mail'' for PHP mail, or SMTP-based modes). This overrides the global MAIN_MAIL_SENDMODE for the mailing context.', 'Setting this constant changes the transport used for mailing campaigns independently of the global mail configuration. Clearing it causes the mailing to use the system default sending mode.', 'A sending mode string identifier (e.g. ''mail'' for PHP mail function, or an SMTP-based mode string); empty = system default sending mode', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:997|read|$sendingmode = getDolGlobalString(''EMAILING_MAIL_SENDMODE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAILING_USE_ADVANCED_SELECTOR', 'bool', NULL, 'core', 'Switches the mailing target selector to an advanced mode in the emailing module.', 'Checked in core/lib/emailing.lib.php:53 to branch between a standard and an advanced recipient-selection UI. No comment is present in the payload describing exact differences between the two modes.', 'Enabling this constant activates a different recipient-selection interface for emailing campaigns; the precise behavioral differences are not described in the available code.', 'Any truthy value activates the advanced selector; unset uses the standard selector.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/emailing.lib.php:53|check|if (getDolGlobalString(''EMAILING_USE_ADVANCED_SELECTOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EMAIL_ALTERNATIVE_HOST_SIGNATURE', 'string', NULL, 'emailcollector', 'Specifies an alternative hostname used to match Dolibarr tracking IDs in incoming email references.', 'Used in emailcollector/class/emailcollector.class.php at lines 2037-2038 and 2403-2404 to match the pattern ''dolibarr-([a-z]+)([0-9]+)@<hostname>'' in email References and In-Reply-To headers for tracking ID detection. No admin UI write path is present.', 'Setting this allows the email collector to recognize tracking IDs in replies that were sent from an alternative hostname, enabling correct thread linking.', 'String: alternative email hostname (e.g. ''mail.example.com'') used to match Dolibarr tracking references', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:2037|read|} elseif (getDolGlobalString(''EMAIL_ALTERNATIVE_HOST_SIGNATURE'')) {", "emailcollector/class/emailcollector.class.php:2038|check|if (preg_match(''/dolibarr-([a-z]+)([0-9]+)@''.preg_quote(getDolGlobalString(''EMAIL_ALTERNATIVE_HOST_SIGNATURE''), ''/'').''/'', $referencesforanswer)) {", "emailcollector/class/emailcollector.class.php:2403|check|if (empty($resultsearchtrackid) && getDolGlobalString(''EMAIL_ALTERNATIVE_HOST_SIGNATURE'')) {", "emailcollector/class/emailcollector.class.php:2404|read|$resultsearchtrackid = preg_match(''/dolibarr-([a-z]+)([0-9]+)@''.preg_quote(getDolGlobalString(''EMAIL_ALTERNATIVE_HOST_SIGNATURE''), ''/'').''/'', $reference, $reg);\t// trackid found"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ENTREPOT_EXTRA_STATUS', 'string', NULL, 'product', 'Enables extended warehouse status filtering beyond the default open/closed states.', 'When set, additional warehouse statuses are available for filtering in stock views and product stock calculations. Cited in product/stock/class/entrepot.class.php and product/class/product.class.php.', 'When enabled, filtering on warehouse status is possible in stock-at-date reports and product stock queries. Disabling it restricts warehouse filtering to basic status values.', 'Truthy = extra warehouse statuses available for filtering; empty/falsy = standard statuses only', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/stock/class/entrepot.class.php:211  * Used when ENTREPOT_EXTRA_STATUS is on;", "product/class/product.class.php:6308  * If ENTREPOT_EXTRA_STATUS is set, filtering on warehouse status is possible.", "product/class/html.formproduct.class.php:310|check|if ((!getDolGlobalString(''ENTREPOT_EXTRA_STATUS'')) && ($filterstatus === \"warehouseinternal\")) {", "product/stock/stockatdate.php:167|check|if (getDolGlobalString(''ENTREPOT_EXTRA_STATUS'') && count($warehouseStatus)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ENTREPOT_WAREHOUSEINTERNAL_NOT_SELL', 'string', NULL, 'core', 'Prevents selection of internal-type warehouses as a shipping source on document lines.', 'Checked in core/tpl/objectline_create.tpl.php:293 to conditionally filter out warehouses flagged as internal from the warehouse selection on new document lines.', 'Enabling this constant hides internal warehouses from the warehouse selector when adding product lines to orders or deliveries.', 'Empty/not set = all warehouses selectable; any truthy string = internal warehouses excluded from selection', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:293|check|if (getDolGlobalString(''ENTREPOT_WAREHOUSEINTERNAL_NOT_SELL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVALUATION_ADDON_PDF', 'string', NULL, 'hrm', 'Specifies the PDF add-on module name to use for HRM evaluation document generation.', 'Read in hrm/class/evaluation.class.php at lines 1027–1028. Used as an alternative PDF model selector when set. No admin UI write is present.', 'Setting this to a valid PDF add-on module name switches the PDF generation template for evaluations; leaving it empty uses the default model.', 'string module name; empty = use default PDF model', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/evaluation.class.php:1027|read|} elseif (getDolGlobalString(''EVALUATION_ADDON_PDF'')) {", "hrm/class/evaluation.class.php:1028|read|$modele = getDolGlobalString(''EVALUATION_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_CATEG_THIRDPARTY_BOOTH', 'string', NULL, 'public', 'Stores the ID of the third-party category to assign when a booth suggestion is submitted via the public form.', 'In public/project/suggestbooth.php at line 342, the integer value is used to fetch a category object that will be associated with the booth registrant''s third party. No admin UI write path is present.', 'Setting this links new booth-submitter third parties to the specified category; leaving it unset skips category assignment.', 'Integer: ID of the llx_categorie record to use as the thirdparty category for booth registrants', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/suggestbooth.php:342|read|$resultcategory = $category->fetch(getDolGlobalInt(''EVENTORGANIZATION_CATEG_THIRDPARTY_BOOTH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_CATEG_THIRDPARTY_CONF', 'string', NULL, 'public', 'Stores the ID of the third-party category to assign when a conference suggestion is submitted via the public form.', 'In public/project/suggestconference.php at line 341, the integer value is used to fetch a category object that will be associated with the conference submitter''s third party. No admin UI write path is present.', 'Setting this links new conference-submitter third parties to the specified category; leaving it unset skips category assignment.', 'Integer: ID of the llx_categorie record to use as the thirdparty category for conference submitters', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/suggestconference.php:341|read|$resultcategory = $category->fetch(getDolGlobalInt(''EVENTORGANIZATION_CATEG_THIRDPARTY_CONF''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_CONFERENCEORBOOTHATTENDEE_ADDON', 'string', NULL, 'eventorganization', 'Specifies the numbering module class name used to generate reference numbers for conference/booth attendee records.', 'Checked at conferenceorboothattendee.class.php:1023-1031; if unset, the code defaults to ''mod_conferenceorboothattendee_standard''. The value is used both to derive the PHP filename to include and the classname to instantiate.', 'Changing this constant switches the attendee reference numbering algorithm; if the referenced module file does not exist the numbering step will fail.', 'Empty/unset = defaults to ''mod_conferenceorboothattendee_standard''; any valid module class name string = use that module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["eventorganization/class/conferenceorboothattendee.class.php:1024|write|$conf->global->EVENTORGANIZATION_CONFERENCEORBOOTHATTENDEE_ADDON = ''mod_conferenceorboothattendee_standard'';", "eventorganization/class/conferenceorboothattendee.class.php:1031|read|$classname = getDolGlobalString(''EVENTORGANIZATION_CONFERENCEORBOOTHATTENDEE_ADDON'');", "eventorganization/class/conferenceorboothattendee.class.php:1030|read|$file = getDolGlobalString(''EVENTORGANIZATION_CONFERENCEORBOOTHATTENDEE_ADDON'') . \".php\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_DEFAULT_NOTE_ON_REGISTRATION', 'string', NULL, 'public', 'Specifies a default note string to display to attendees at the end of the event registration form.', 'In public/eventorganization/attendee_new.php at lines 935-936, when set the value is processed (replacing literal \n with newlines) and displayed as $notetoshow. No admin UI write path is present.', 'Setting this shows a custom note at the bottom of the public attendee registration form; leaving it unset shows no note.', 'String: note text to display on the registration form; use \n for line breaks', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/eventorganization/attendee_new.php:935|check|if (getDolGlobalString(''EVENTORGANIZATION_DEFAULT_NOTE_ON_REGISTRATION'')) {", "public/eventorganization/attendee_new.php:936|read|$notetoshow = str_replace(''\\n'', \"\\n\", getDolGlobalString(''EVENTORGANIZATION_DEFAULT_NOTE_ON_REGISTRATION''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_DISABLE_RETREIVE_THIRDPARTY_FROM_NAME', 'bool', NULL, 'public', 'Disables the automatic lookup of an existing third party by name during event attendee registration.', 'In public/eventorganization/attendee_new.php at line 392, the thirdparty-by-name lookup is only performed when this constant is not set. No admin UI write path is present.', 'Setting this prevents the system from matching new attendee registrations to existing third parties by name, always creating a new entry.', '0 or unset = thirdparty lookup by name enabled; non-zero = lookup disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/eventorganization/attendee_new.php:392|check|if (!getDolGlobalString(''EVENTORGANIZATION_DISABLE_RETREIVE_THIRDPARTY_FROM_NAME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_ENABLE_PUBLIC', 'bool', NULL, 'admin', 'Controls whether the public-facing event organization interface is enabled.', 'Referenced in admin/eventorganization_public.php:230 inside a commented-out conditional, indicating the feature is managed from that admin page. The admin UI file is admin/eventorganization_public.php.', 'Enabling this constant activates the public event organization interface; disabling it suppresses it.', 'Truthy = public event organization enabled; falsy or unset = disabled.', 0, 0, 'admin/eventorganization_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/eventorganization_public.php:230|check|//if (getDolGlobalString(''EVENTORGANIZATION_ENABLE_PUBLIC'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_FILTERATTENDEES_CAT', 'string', NULL, 'eventorganization', 'Restricts conference/booth attendee records to third-parties belonging to a specific category.', 'When set, conferenceorboothattendee.class.php:250-251 appends a JOIN against the category-company table so that the fk_soc field only accepts companies linked to the configured category ID.', 'Setting a category ID limits attendee registration to companies in that category; leaving unset imposes no category restriction.', 'Empty/unset = no category filter; a category rowid = restrict to that category.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["eventorganization/class/conferenceorboothattendee.class.php:250|check|if (getDolGlobalString(''EVENTORGANIZATION_FILTERATTENDEES_CAT'')) {", "eventorganization/class/conferenceorboothattendee.class.php:251|read|$this->fields[''fk_soc''][''type''] .= '' AND rowid IN (SELECT DISTINCT c.fk_soc FROM ''.MAIN_DB_PREFIX.''categorie_societe as c WHERE c.fk_categorie=''.(int) $conf->global->EVENTORGANIZAT"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_FILTERATTENDEES_TYPE', 'string', NULL, 'eventorganization', 'Restricts conference/booth attendee records to third-parties of a specific client type.', 'Checked at conferenceorboothattendee.class.php:253-256; when set to a non-empty, non-''-1'' value it appends a client-type condition on the fk_soc field using the integer value of the constant.', 'Setting a numeric client type restricts attendee lookup to matching company types; a value of '''' or ''-1'' disables the filter.', 'Empty/unset or ''-1'' = no type filter; a numeric client type integer = restrict to that type.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["eventorganization/class/conferenceorboothattendee.class.php:255|read|&& getDolGlobalString(''EVENTORGANIZATION_FILTERATTENDEES_TYPE'') !== ''-1'') {", "eventorganization/class/conferenceorboothattendee.class.php:256|read|$this->fields[''fk_soc''][''type''] .= '' AND (client:=:''.((int) getDolGlobalInt(''EVENTORGANIZATION_FILTERATTENDEES_TYPE'', 0) . '')'');", "eventorganization/class/conferenceorboothattendee.class.php:254|read|&& getDolGlobalString(''EVENTORGANIZATION_FILTERATTENDEES_TYPE'') !== ''''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE', 'string', NULL, 'public', 'Stores the URL of an image displayed on the public event organization subscription and attendee pages.', 'Checked in public/eventorganization/subscriptionok.php:143 and public/eventorganization/attendee_new.php:217; when set, the image URL is rendered as an <img> tag on both pages (lines 145 and 219 respectively). No admin UI write is present.', 'Setting this constant causes a custom image to appear on the public-facing event subscription and confirmation pages; leaving it unset suppresses the image.', 'String URL of the image to display; unset/empty = no image shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/eventorganization/subscriptionok.php:143|check|if (getDolGlobalString(''EVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE'')) {", "public/eventorganization/subscriptionok.php:145|read|print ''<img id=\"idEVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE\" src=\"'' . getDolGlobalString(''EVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE'').''\">'';", "public/eventorganization/attendee_new.php:217|check|if (getDolGlobalString(''EVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE'')) {", "public/eventorganization/attendee_new.php:219|read|print ''<img id=\"idEVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE\" src=\"'' . getDolGlobalString(''EVENTORGANIZATION_IMAGE_PUBLIC_INTERFACE'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_SECUREKEY', 'string', NULL, 'eventorganization', 'Provides the secret key used to generate MD5 hashes for securing public event organization URLs.', 'Read in 26 occurrences across eventorganization/ files including conferenceorbooth_document.php:371, conferenceorbooth_contact.php:352, conferenceorbooth_list.php:536, and conferenceorboothattendee_card.php:457 via dol_hash(...''md5'').', 'Changing or clearing this constant invalidates all previously generated secure links for event organization public pages.', 'Arbitrary string used as HMAC/hash salt; empty/unset = insecure or broken public links.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["eventorganization/conferenceorbooth_document.php:371|read|$encodedsecurekey = dol_hash(getDolGlobalString(''EVENTORGANIZATION_SECUREKEY'').''conferenceorbooth''.((int) $projectstatic->id), ''md5'');", "eventorganization/conferenceorbooth_contact.php:352|read|$encodedsecurekey = dol_hash(getDolGlobalString(''EVENTORGANIZATION_SECUREKEY'').''conferenceorbooth''.((int) $projectstatic->id), ''md5'');", "eventorganization/conferenceorbooth_list.php:536|read|$encodedsecurekey = dol_hash(getDolGlobalString(''EVENTORGANIZATION_SECUREKEY'').''conferenceorbooth''.((int) $project->id), ''md5'');", "eventorganization/conferenceorboothattendee_card.php:457|read|$encodedsecurekey = dol_hash(getDolGlobalString(\"EVENTORGANIZATION_SECUREKEY\").''conferenceorbooth''.((int) $projectstatic->id), ''md5'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_TASK_LABEL', 'string', NULL, 'core', 'Defines a newline-separated list of task labels to create automatically when an event-organization event is saved.', 'Read in core/triggers/interface_50_modEventOrganization_EventOrganization.class.php:84 via explode(''\n'', ...) and applied when the event has usage_organize_event set. Checked at line 83 before any task creation occurs.', 'Setting this constant causes the EventOrganization trigger to create one task per line of the value whenever a qualifying event is saved. Clearing it disables automatic task creation.', 'Empty/not set = no tasks auto-created; newline-separated strings = one task label per line', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modEventOrganization_EventOrganization.class.php:83|check|if (getDolGlobalString(''EVENTORGANIZATION_TASK_LABEL'') && !empty($object->usage_organize_event)) {", "core/triggers/interface_50_modEventOrganization_EventOrganization.class.php:84|read|$taskToDo = explode(\"\\n\", getDolGlobalString(''EVENTORGANIZATION_TASK_LABEL''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_TEMPLATE_EMAIL_AFT_SUBS_BOOTH', 'string', NULL, 'public', 'Specifies the email template ID sent to booth subscribers after a successful event organization payment.', 'Read as an integer at public/payment/paymentok.php:1855 with the inline comment ''Email sent after registration for a Booth''. No admin UI write found.', 'Setting this to a valid email template ID causes a confirmation email to be sent to booth registrants after payment.', 'An integer email template ID; unset or 0 means no email is sent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/paymentok.php:1855|read|$idoftemplatetouse = getDolGlobalInt(''EVENTORGANIZATION_TEMPLATE_EMAIL_AFT_SUBS_BOOTH'');\t// Email sent after registration for a Booth"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_TEMPLATE_EMAIL_AFT_SUBS_EVENT', 'string', NULL, 'public', 'Stores the ID of the email template to send after an event organization subscription is completed.', 'Read in public/eventorganization/attendee_new.php at line 671 and in public/payment/paymentok.php at line 1618 with the inline comment ''Email to send for Event organization registration''. No admin UI write path is present.', 'Setting this enables a template-based confirmation email after event registration or payment; leaving it unset sends no template email.', 'Integer: ID of the email template to use for post-subscription event organization emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/eventorganization/attendee_new.php:671|read|$labeltouse = getDolGlobalInt(''EVENTORGANIZATION_TEMPLATE_EMAIL_AFT_SUBS_EVENT'');", "public/payment/paymentok.php:1618|read|$idoftemplatetouse = getDolGlobalInt(''EVENTORGANIZATION_TEMPLATE_EMAIL_AFT_SUBS_EVENT'');\t// Email to send for Event organization registration"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_TEMPLATE_EMAIL_ASK_BOOTH', 'string', NULL, 'public', 'Stores the ID of the email template to use when sending a confirmation email after a booth suggestion is submitted.', 'In public/project/suggestbooth.php at line 526, the integer value is read into $labeltouse to select the email template for the booth request confirmation. No admin UI write path is present.', 'Setting this enables a template-based confirmation email to be sent after a booth suggestion; leaving it unset sends no template email.', 'Integer: ID of the email template to use for booth-request confirmation emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/suggestbooth.php:526|read|$labeltouse = getDolGlobalInt(''EVENTORGANIZATION_TEMPLATE_EMAIL_ASK_BOOTH'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EVENTORGANIZATION_TEMPLATE_EMAIL_ASK_CONF', 'string', NULL, 'public', 'Stores the ID of the email template to use when sending a confirmation email after a conference suggestion is submitted.', 'In public/project/suggestconference.php at line 458, the integer value is read into $labeltouse to select the email template for the conference request confirmation. No admin UI write path is present.', 'Setting this enables a template-based confirmation email after a conference suggestion; leaving it unset sends no template email.', 'Integer: ID of the email template to use for conference-request confirmation emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/suggestconference.php:458|read|$labeltouse = getDolGlobalInt(''EVENTORGANIZATION_TEMPLATE_EMAIL_ASK_CONF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPEDITION_ADDON_NUMBER', 'string', NULL, 'admin', 'Selects the active numbering module (addon) for shipment/expedition reference number generation.', 'Configured via admin/expedition.php (UI writes at lines 65 and 167). If not set, it defaults to ''mod_expedition_safor'' (line 65). The value is used in expedition/class/expedition.class.php:384-385 to load the corresponding module file and class.', 'Changing this constant switches the numbering scheme for all future shipment references. The chosen module file must exist; otherwise reference generation will fail.', 'Name of a valid expedition numbering module (e.g. ''mod_expedition_safor''); default is ''mod_expedition_safor''.', 0, 0, 'admin/expedition.php|admin/expedition.php|admin/expedition.php|admin/expedition.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/expedition.php:64|check|if (!getDolGlobalString(''EXPEDITION_ADDON_NUMBER'')) {", "admin/expedition.php:65|write|$conf->global->EXPEDITION_ADDON_NUMBER = ''mod_expedition_safor'';", "expedition/class/expedition.class.php:384|read|$file = getDolGlobalString(''EXPEDITION_ADDON_NUMBER'') . \".php\";", "expedition/class/expedition.class.php:385|read|$classname = getDolGlobalString(''EXPEDITION_ADDON_NUMBER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPEDITION_ADDON_PDF', 'string', NULL, 'admin', 'Selects the active PDF template module for shipment/expedition document generation.', 'Configured via admin/expedition.php (UI writes at lines 155 and 158). The value is read in expedition/class/expedition.class.php:3316-3317 to determine which PDF model to use, and displayed in a select list on expedition/card.php:1627.', 'Changing this constant switches the PDF template applied to all newly generated shipment documents. The selected module must be available; otherwise document generation falls back or fails.', 'Name of a valid expedition PDF module (e.g. a template slug string); empty to use the default.', 0, 0, 'admin/expedition.php|admin/expedition.php|admin/expedition.php|admin/expedition.php|admin/expedition.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/expedition.php:155|write|if (dolibarr_set_const($db, \"EXPEDITION_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "expedition/class/expedition.class.php:3316|read|} elseif (getDolGlobalString(''EXPEDITION_ADDON_PDF'')) {", "expedition/class/expedition.class.php:3317|read|$modele = getDolGlobalString(''EXPEDITION_ADDON_PDF'');", "expedition/card.php:1627|read|print $form->selectarray(''model'', $list, getDolGlobalString(''EXPEDITION_ADDON_PDF''), 0, 0, 0, '''', 0, 0, 0, '''', ''widthcentpercentminusx'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPEDITION_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Stores the filesystem path to the directory containing ODT template files for shipment document generation.', 'Used in a single location in core/modules/expedition/doc/doc_generic_shipment_odt.modules.php:116 where it is read and trimmed to resolve the ODT template path.', 'Setting this to a valid directory path allows the ODT-based shipment document generator to locate custom templates. An empty or invalid path causes the generator to fall back to its default template location.', 'Any non-empty string = filesystem path to the ODT templates directory; empty/unset = default path used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["doc_generic_shipment_odt.modules.php:116|$odtPath = trim(getDolGlobalString(''EXPEDITION_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPEDITION_ALLOW_ONLINESIGN', 'bool', NULL, 'expedition', 'Enables the online signature feature on shipment cards.', 'Read once in expedition/card.php at line 3872 using getDolGlobalInt; the result is stored in $useonlinesignature which controls whether the online signature widget is shown.', 'Setting this constant to a non-zero integer activates the online signature option on shipment documents. If unset or zero, the online signature feature is not available.', 'Non-zero integer to enable online signature; 0 or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/card.php:3872|read|$useonlinesignature = getDolGlobalInt(''EXPEDITION_ALLOW_ONLINESIGN'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPEDITION_RIBERA_MASK', 'string', NULL, 'core', 'Defines the reference number mask used by the ''ribera'' numbering module for shipment/expedition references.', 'Read in core/modules/expedition/mod_expedition_ribera.php at lines 91 and 139 to render the mask input field and to format generated references. No admin UI write outside the module configuration page.', 'Changing the mask alters the format of newly generated expedition references when the ribera module is active.', 'Mask string (as supported by the ribera module''s mask syntax); empty string disables custom formatting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expedition/mod_expedition_ribera.php:139|read|$mask = getDolGlobalString(''EXPEDITION_RIBERA_MASK'');", "core/modules/expedition/mod_expedition_ribera.php:91|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskexpedition\" value=\"''.getDolGlobalString(''EXPEDITION_RIBERA_MASK'').''\">'', $"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_ADDON', 'string', NULL, 'expensereport', 'Selects the numbering addon module used to generate expense report reference numbers.', 'Set via admin/expensereport.php:156 and read in expensereport/class/expensereport.class.php:1744-1748 to load the numbering class file and instantiate it for reference generation.', 'Changing this value switches the numbering scheme for expense report references; an incorrect value will cause reference generation to fail.', 'String; the class name (without .php extension) of a numbering addon in the expense report module.', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:156|write|dolibarr_set_const($db, \"EXPENSEREPORT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "expensereport/class/expensereport.class.php:1744|check|if (getDolGlobalString(''EXPENSEREPORT_ADDON'')) {", "expensereport/class/expensereport.class.php:1747|read|$file = getDolGlobalString(''EXPENSEREPORT_ADDON'') . \".php\";", "expensereport/class/expensereport.class.php:1748|read|$classname = getDolGlobalString(''EXPENSEREPORT_ADDON'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_ADDON_PDF', 'string', NULL, 'admin', 'Selects the active PDF document template addon used to generate expense report PDF documents.', 'Set and managed via admin/expensereport.php (lines 129-144) with dolibarr_set_const and dolibarr_del_const. Read in expensereport/class/expensereport.class.php:2488 to determine which PDF class to instantiate.', 'Changing this value switches the PDF layout for expense reports; deleting the constant reverts to the system default template.', 'String; name of an expense report PDF addon model available in the system.', 0, 0, 'admin/expensereport.php|admin/expensereport.php|admin/expensereport.php|admin/expensereport.php|admin/expensereport.php|admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:141|write|if (dolibarr_set_const($db, \"EXPENSEREPORT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/expensereport.php:144|write|$conf->global->EXPENSEREPORT_ADDON_PDF = $value;", "expensereport/class/expensereport.class.php:2488|read|} elseif (getDolGlobalString(''EXPENSEREPORT_ADDON_PDF'')) {", "admin/expensereport.php:413|check|if (getDolGlobalString(''EXPENSEREPORT_ADDON_PDF'') == \"$name\") {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_ALLOW_OVERLAPPING_PERIODS', 'bool', NULL, 'expensereport', 'Allows multiple expense reports to cover overlapping date periods for the same user.', 'Checked at expensereport/card.php:317; the overlap-period validation is skipped when this constant is set.', 'Enabling this constant removes the overlap check, allowing concurrent expense reports with the same date range; disabling it enforces non-overlapping periods.', 'Empty/unset = overlapping periods forbidden; any truthy value = overlapping periods allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:317|check|if (!$error && !getDolGlobalString(''EXPENSEREPORT_ALLOW_OVERLAPPING_PERIODS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_ASK_PAYMENTMODE_ON_CREATION', 'string', NULL, 'expensereport', 'Controls whether the payment method field is shown when creating or editing an expense report.', 'Checked at expensereport/card.php:1545, :1665, and :1822; the payment-mode UI element is rendered only when this constant is set.', 'Enabling this constant displays the payment method selector on expense report creation and edit views; disabling it hides that field.', 'Empty/unset = payment mode field hidden; any truthy value = payment mode field shown on creation/edit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:1545|check|if (getDolGlobalString(''EXPENSEREPORT_ASK_PAYMENTMODE_ON_CREATION'')) {", "expensereport/card.php:1665|check|if (getDolGlobalString(''EXPENSEREPORT_ASK_PAYMENTMODE_ON_CREATION'')) {", "expensereport/card.php:1822|check|if (getDolGlobalString(''EXPENSEREPORT_ASK_PAYMENTMODE_ON_CREATION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES', 'string', NULL, 'admin', 'Blocks the creation of expense report lines when the line date falls outside the report''s defined date range.', 'Configured via admin/expensereport.php. When active, two guards in expensereport/card.php (lines 1216 and 1382) check this constant and prevent line additions if the date is out of range. The admin UI offers a yes/no selector for this option.', 'Enabling this setting enforces date discipline on expense reports, preventing users from adding lines with dates outside the report period. Disabling allows lines regardless of date.', '0 = disabled (no date range enforcement); 1 = enabled (line creation blocked if date is out of range)', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:524|read|print $form->selectyesno(''EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES'', getDolGlobalString(''EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES'') ? 1 : 0, 1);", "expensereport/card.php:1216|check|if (getDolGlobalString(''EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES'')) {", "expensereport/card.php:1382|check|if (getDolGlobalString(''EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES'')) {", "admin/expensereport.php:178|write|$res6 = dolibarr_set_const($db, ''EXPENSEREPORT_BLOCK_LINE_CREATION_IF_NOT_BETWEEN_DATES'', intval($linesblocked), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_CALCULATE_MILEAGE_EXPENSE_COEFFICIENT_ON_CURRENT_YEAR', 'string', NULL, 'expensereport', 'When enabled, calculates the mileage expense coefficient based on the current year rather than the default period.', 'Checked at expensereport/class/expensereport.class.php:2766 using getDolGlobalInt; when set to a non-zero value, a current-year-based coefficient lookup is performed.', 'Enabling this constant switches mileage coefficient resolution to use the current calendar year; disabling it uses the default period.', '0 or unset = default period for coefficient; non-zero integer = use current year.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/class/expensereport.class.php:2766|check|if (getDolGlobalInt(''EXPENSEREPORT_CALCULATE_MILEAGE_EXPENSE_COEFFICIENT_ON_CURRENT_YEAR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_DEFAULT_VALIDATOR', 'string', NULL, 'expensereport', 'Sets the default approver (validator) user ID pre-selected when creating a new expense report.', 'Checked and read at expensereport/card.php:1532-1533; when set, $defaultselectuser is assigned the constant''s value with a comment: ''Can force default approver''.', 'Setting this constant pre-selects a specific user as approver on new expense reports; leaving it unset uses no default approver.', 'Empty/unset = no default approver; a user ID string = pre-select that user as approver.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:1532|check|if (getDolGlobalString(''EXPENSEREPORT_DEFAULT_VALIDATOR'')) {", "expensereport/card.php:1533|read|$defaultselectuser = getDolGlobalString(''EXPENSEREPORT_DEFAULT_VALIDATOR''); // Can force default approver"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_DEFAULT_VALIDATOR_UNCHANGEABLE', 'string', NULL, 'expensereport', 'Prevents users from changing the pre-selected default validator on an expense report.', 'Checked at expensereport/card.php:1538 in a ternary that locks the validator select control when both EXPENSEREPORT_DEFAULT_VALIDATOR and this constant are set.', 'Enabling this constant (together with EXPENSEREPORT_DEFAULT_VALIDATOR) makes the approver field read-only for the user; disabling it leaves the approver selectable.', 'Empty/unset = approver can be changed; any truthy value (with EXPENSEREPORT_DEFAULT_VALIDATOR set) = approver locked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:1538|check|$s = $form->select_dolusers($defaultselectuser, \"fk_user_validator\", 1, null, ((empty($defaultselectuser) || !getDolGlobalString(''EXPENSEREPORT_DEFAULT_VALIDATOR_UNCHANGEABLE'')) ? "]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_DISABLE_ATTACHMENT_ON_LINES', 'bool', NULL, 'expensereport', 'Disables the file attachment control on individual expense report lines.', 'Checked in expensereport/tpl/expensereport_linktofile.tpl.php:33 and at expensereport/card.php:2398, 2538, and 2554; the attachment UI element is rendered only when this constant is NOT set.', 'Enabling this constant (setting to a truthy value) hides the per-line attachment widget across expense report views; leaving it unset preserves the attachment functionality.', 'Empty/unset = attachments on lines enabled; any truthy value = attachments on lines disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/tpl/expensereport_linktofile.tpl.php:33|check|if (!getDolGlobalString(''EXPENSEREPORT_DISABLE_ATTACHMENT_ON_LINES'')) {", "expensereport/card.php:2398|check|if (!getDolGlobalString(''EXPENSEREPORT_DISABLE_ATTACHMENT_ON_LINES'')) {", "expensereport/card.php:2538|check|if (!getDolGlobalString(''EXPENSEREPORT_DISABLE_ATTACHMENT_ON_LINES'')) {", "expensereport/card.php:2554|check|if (!getDolGlobalString(''EXPENSEREPORT_DISABLE_ATTACHMENT_ON_LINES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Stores the watermark text printed on draft expense report PDF documents.', 'Set via admin/expensereport.php:164 with a free-text input field (admin/expensereport.php:498). Applied in core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:688 via pdf_watermark when the expense report status is 0 (draft).', 'Setting this constant causes the specified text to be rendered as a watermark on draft expense report PDFs; leaving it empty suppresses the watermark.', 'String; any text to display as a watermark on draft PDFs.', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:164|write|$res2 = dolibarr_set_const($db, \"EXPENSEREPORT_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "admin/expensereport.php:498|read|print ''<input class=\"flat minwidth200\" type=\"text\" name=\"EXPENSEREPORT_DRAFT_WATERMARK\" value=\"''.dol_escape_htmltag(getDolGlobalString(''EXPENSEREPORT_DRAFT_WATERMARK'')).''\">'';", "core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:687|check|if ($object->fk_statut == 0 && getDolGlobalString(''EXPENSEREPORT_DRAFT_WATERMARK'')) {", "core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:688|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', $conf->global->EXPENSEREPORT_DRAFT_WATERMARK);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_FILE_IS_REQUIRED', 'string', NULL, 'expensereport', 'Specifies whether a file attachment is required when submitting an expense report.', 'Read at expensereport/card.php:141 into $fileRequired; the value is used to drive attachment validation logic on the expense report form.', 'Setting this constant to a truthy value enforces file attachment at submission; leaving it unset or empty makes the attachment optional.', 'Empty/unset = attachment not required; any truthy value = attachment required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:141|read|$fileRequired = getDolGlobalString(''EXPENSEREPORT_FILE_IS_REQUIRED'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY', 'string', NULL, 'admin', 'Forces expense report line amounts to be entered inclusive of taxes only, disabling the tax-exclusive unit price field.', 'Configured via admin/expensereport.php. When enabled, the tax-exclusive unit price input is rendered disabled on expense report lines (expensereport/card.php:1715). The admin UI uses a yes/no selector to toggle the value (admin/expensereport.php:518).', 'Enabling this setting removes the tax-exclusive price field from expense report entry, ensuring all amounts entered already include taxes. Disabling restores the standard dual-amount input.', '0 = disabled (both inclusive and exclusive amounts allowed); 1 = enabled (only tax-inclusive amounts accepted)', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:518|read|print $form->selectyesno(''EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY'', getDolGlobalString(''EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY'') ? 1 : 0, 1);", "expensereport/card.php:1715|read|$taxlessUnitPriceDisabled = getDolGlobalString(''EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY'') ? '' disabled'' : '''';", "expensereport/card.php:2754|check|if (getDolGlobalString(''EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY'')) {", "admin/expensereport.php:175|write|$res5 = dolibarr_set_const($db, ''EXPENSEREPORT_FORCE_LINE_AMOUNTS_INCLUDING_TAXES_ONLY'', intval($amounts), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Expense Report documents.', 'Set via the admin UI at admin/expensereport.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Expense Report documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/expensereport.php:161|write|$res1 = dolibarr_set_const($db, \"EXPENSEREPORT_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_LINES_SORTED_BY_ROWID', 'string', NULL, 'expensereport', 'Controls whether expense report lines are sorted by their database row ID rather than the default order.', 'Checked at expensereport/class/expensereport.class.php:1146; when set, the line sort order is changed to sort by rowid.', 'Enabling this constant changes line ordering on expense reports to ascending rowid; disabling it reverts to the default sort.', 'Empty/unset = default sort order; any truthy value = lines sorted by rowid.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/class/expensereport.class.php:1146|check|if (getDolGlobalString(''EXPENSEREPORT_LINES_SORTED_BY_ROWID'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_NO_DEFAULT_VAT', 'string', NULL, 'expensereport', 'Suppresses automatic default VAT rate population on expense report lines.', 'Checked at expensereport/card.php:2664; when set, the default VAT rate is not pre-filled on expense report line creation.', 'Enabling this constant forces users to manually enter VAT on each expense line; disabling it auto-populates the default VAT rate.', 'Empty/unset = default VAT auto-filled; any truthy value = no default VAT applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:2664|check|if (getDolGlobalString(''EXPENSEREPORT_NO_DEFAULT_VAT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_OVERRIDE_VAT', 'string', NULL, 'core', 'Allows overriding the VAT selection on expense reports even when the seller''s VAT option is disabled.', 'Checked at core/class/html.form.class.php:7581. The comments at :7578–:7579 describe it as ''a strange option that allow to override/enable VAT regardless of seller vat option - needed for expense report''. When unset, VAT selection is disabled when the seller does not use VAT.', 'Enabling this constant forces the VAT selector to remain active on expense report lines regardless of the company VAT configuration. Disabling (leaving unset) hides VAT selection when the seller is not subject to VAT.', 'Truthy = enable VAT override on expense reports; empty/unset = respect seller VAT setting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7578  // When we are seller and we do not use VAT, we want to force to disable VAT selection, except if EXPENSEREPORT_OVERRIDE_VAT is set", "core/class/html.form.class.php:7579  // EXPENSEREPORT_OVERRIDE_VAT is a strange option that allow to override/enable VAT regardless of sellet vat option - needed for expense report if", "core/class/html.form.class.php:7581|check|if (!getDolGlobalString(''EXPENSEREPORT_OVERRIDE_VAT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_PREFILL_DATES_WITH_CURRENT_MONTH', 'string', NULL, 'admin', 'Pre-fills the expense report date range fields with the current month''s start and end dates.', 'Set via admin/expensereport.php:172 with a yes/no selector (admin/expensereport.php:512). Checked in expensereport/card.php:86 to auto-populate date fields when creating a new expense report.', 'Enabling this constant automatically fills in the current month date range on new expense reports, reducing data entry effort; disabling it leaves the date fields blank.', 'Yes/no integer (1=prefill current month, 0=leave blank); set via selectyesno in the admin UI.', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:172|write|$res4 = dolibarr_set_const($db, ''EXPENSEREPORT_PREFILL_DATES_WITH_CURRENT_MONTH'', intval($dates), ''chaine'', 0, '''', $conf->entity);", "admin/expensereport.php:512|read|print $form->selectyesno(''EXPENSEREPORT_PREFILL_DATES_WITH_CURRENT_MONTH'', getDolGlobalString(''EXPENSEREPORT_PREFILL_DATES_WITH_CURRENT_MONTH'') ? 1 : 0, 1);", "expensereport/card.php:86|check|if (getDolGlobalString(''EXPENSEREPORT_PREFILL_DATES_WITH_CURRENT_MONTH'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_PROJECT_IS_REQUIRED', 'string', NULL, 'admin', 'Makes the project field mandatory on expense report entries when the project module is enabled.', 'Set via admin/expensereport.php:168 with a yes/no selector (admin/expensereport.php:505). Read in expensereport/card.php:140 to set $projectRequired, which gates project field validation.', 'Enabling this constant forces users to assign a project to every expense report; disabling it makes the project field optional.', 'Yes/no integer (1=required, 0=optional); set via selectyesno in the admin UI.', 0, 0, 'admin/expensereport.php|admin/expensereport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/expensereport.php:168|write|$res3 = dolibarr_set_const($db, ''EXPENSEREPORT_PROJECT_IS_REQUIRED'', GETPOSTINT(''EXPENSEREPORT_PROJECT_IS_REQUIRED''), ''chaine'', 0, '''', $conf->entity);", "admin/expensereport.php:505|read|print $form->selectyesno(''EXPENSEREPORT_PROJECT_IS_REQUIRED'', getDolGlobalString(''EXPENSEREPORT_PROJECT_IS_REQUIRED'') ? 1 : 0, 1);", "expensereport/card.php:140|read|$projectRequired = isModEnabled(''project'') && getDolGlobalString(''EXPENSEREPORT_PROJECT_IS_REQUIRED'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_SAND_MASK', 'string', NULL, 'core', 'Defines the reference number mask used by the ''sand'' numbering module for expense reports.', 'Read in core/modules/expensereport/mod_expensereport_sand.php at lines 93 and 140 to obtain the mask string that formats generated expense-report reference numbers. No admin UI write is present.', 'Changing the mask alters the format of newly generated expense-report reference numbers; existing references are unaffected.', 'A mask string (format depends on the sand module''s mask syntax); empty string disables custom formatting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/mod_expensereport_sand.php:93|read|$mask = getDolGlobalString(''EXPENSEREPORT_SAND_MASK'');", "core/modules/expensereport/mod_expensereport_sand.php:140|read|$mask = getDolGlobalString(''EXPENSEREPORT_SAND_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_SEND_EMAIL_ON_STATUS_PAID', 'string', NULL, 'expensereport', 'Triggers sending an email notification when an expense report status changes to paid.', 'Checked at expensereport/card.php:1092; when set, an email notification is sent upon the paid-status transition.', 'Enabling this constant sends an email when an expense report is marked as paid; disabling it suppresses that notification.', 'Empty/unset = no email on paid status; any truthy value = email sent on paid status.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:1092|check|if (getDolGlobalString(''EXPENSEREPORT_SEND_EMAIL_ON_STATUS_PAID'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSEREPORT_USE_OLD_NUMBERING_RULE', 'bool', NULL, 'core', 'Enables a legacy numbering rule in the ''jade'' expense-report numbering module when set.', 'Read in core/modules/expensereport/mod_expensereport_jade.php:134 as a boolean check to branch into an older numbering code path. No admin UI write is present.', 'Enabling this flag switches expense-report number generation in the jade module to the old rule; disabling it (or leaving it unset) uses the current rule.', 'Truthy value (e.g. 1) to activate old rule; empty or 0 to use current rule.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/mod_expensereport_jade.php:134|check|if (getDolGlobalString(''EXPENSEREPORT_USE_OLD_NUMBERING_RULE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPENSE_REPORT_PREFIX', 'string', NULL, 'core', 'Defines an optional prefix string prepended to expense-report reference numbers by the jade numbering module.', 'Read in core/modules/expensereport/mod_expensereport_jade.php:168-169; if set, it is prepended to the generated reference. No admin UI write is present.', 'When set, all new expense-report references generated by the jade module will start with this prefix. When unset, no prefix is added.', 'Arbitrary string prefix; empty or unset means no prefix.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/mod_expensereport_jade.php:168|check|if (getDolGlobalString(''EXPENSE_REPORT_PREFIX'')) {", "core/modules/expensereport/mod_expensereport_jade.php:169|read|$prefix = getDolGlobalString(''EXPENSE_REPORT_PREFIX'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORTS_SHARE_MODELS', 'string', NULL, 'core', 'When enabled, makes all export and import templates visible to all users regardless of who owns them.', 'Checked in imports/import.php:1486, exports/export.php:1200, and core/class/html.formother.class.php:158 and :227. The inline comment on each check reads ''EXPORTS_SHARE_MODELS means all templates are visible, whatever is owner.'' No admin UI is configured.', 'Enabling this constant removes ownership filtering on export/import templates, making every template accessible to all users.', 'Truthy (non-empty / 1) = all templates visible to all users; falsy (empty / 0) = templates filtered by owner.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["imports/import.php:1486|check|if (!getDolGlobalString(''EXPORTS_SHARE_MODELS'')) {\t// EXPORTS_SHARE_MODELS means all templates are visible, whatever is owner.", "exports/export.php:1200|check|if (!getDolGlobalString(''EXPORTS_SHARE_MODELS'')) {\t// EXPORTS_SHARE_MODELS means all templates are visible, whatever is owner.", "core/class/html.formother.class.php:158|check|if (!getDolGlobalString(''EXPORTS_SHARE_MODELS'')) {\t// EXPORTS_SHARE_MODELS means all templates are visible, whatever is owner.", "core/class/html.formother.class.php:227|check|if (!getDolGlobalString(''EXPORTS_SHARE_MODELS'')) {\t// EXPORTS_SHARE_MODELS means all templates are visible, whatever is owner."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORTTOOL_CATEGORIES', 'string', NULL, 'core', 'When set, includes category-related data in export tool definitions for products and services.', 'Checked in at least 14 occurrences across core/modules/modService.class.php and core/modules/modProduct.class.php, consistently guarding blocks that add category fields or joins to export definitions.', 'Enabling this enriches product and service exports with category data. Disabling (or leaving unset) excludes category fields from those exports.', 'Empty/unset = no category data in exports; any truthy value = category fields included in product/service exports.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["modService.class.php:203|if (getDolGlobalString(''EXPORTTOOL_CATEGORIES'')) {", "modService.class.php:238|if (getDolGlobalString(''EXPORTTOOL_CATEGORIES'')) {", "modProduct.class.php:259|if (getDolGlobalString(''EXPORTTOOL_CATEGORIES'')) {", "modService.class.php:291|if (getDolGlobalString(''EXPORTTOOL_CATEGORIES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_CSV_FORCE_CHARSET', 'string', NULL, 'core', 'Forces the character encoding used for CSV exports.', 'Used throughout core/modules/export (exportcsv.class.php, export_csvutf8.modules.php, export_csviso.modules.php) and core/lib/functions2.lib.php:3076 to override the output charset. The comment at functions2.lib.php:3065 states: ''Expected output character set (UTF-8, ISO-8859-1, ...). Default empty will use the value into EXPORT_CSV_FORCE_CHARSET.''', 'Changing this alters the byte encoding of all CSV export files; export modules for UTF-8 and ISO-8859-1 write this constant automatically.', '''UTF-8'' = UTF-8 encoding; ''ISO-8859-1'' = Latin-1 encoding; empty/unset = use system default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:3065  * @param\tstring\t\t\t\t$charset\tExpected output character set (''UTF-8'', ''ISO-8859-1'', ...). Default '''' will use the value into EXPORT_CSV_FORCE_CHARSET.", "core/modules/export/export_csvutf8.modules.php:78|write|$conf->global->EXPORT_CSV_FORCE_CHARSET = ''UTF-8'';", "core/modules/export/export_csviso.modules.php:51|write|$conf->global->EXPORT_CSV_FORCE_CHARSET = ''ISO-8859-1'';", "core/modules/export/exportcsv.class.php:248|read|$outputlangs->charset_output = getDolGlobalString(''EXPORT_CSV_FORCE_CHARSET'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_CSV_SEPARATOR_TO_USE', 'string', NULL, 'core', 'Sets the column separator character used for CSV exports.', 'Written via the admin UI at admin/export.php:59 and read in core/lib/functions2.lib.php:3079 and both CSV export modules. The comment at functions2.lib.php:3066 states: ''CSV char separator (often comma or semicolon). Default empty will use the value into EXPORT_CSV_SEPARATOR_TO_USE.''', 'Changing this alters the delimiter in all CSV export files; a mismatch with the recipient''s expectations will cause import failures.', 'Any short string (typically '','' or '';''); empty/unset = use module default.', 0, 0, 'admin/export.php|admin/export.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:3066  * @param\tstring\t\t\t\t$separator\tCSV char separator (often '','' or '';''). Default '''' will use the value into EXPORT_CSV_SEPARATOR_TO_USE.", "admin/export.php:59|write|dolibarr_set_const($db, ''EXPORT_CSV_SEPARATOR_TO_USE'', GETPOST(''EXPORT_CSV_SEPARATOR_TO_USE'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/modules/export/export_csvutf8.modules.php:48|read|$this->separator = getDolGlobalString(''EXPORT_CSV_SEPARATOR_TO_USE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_LABEL_FOR_SELECT', 'string', NULL, 'core', 'When set, uses the label field instead of the technical identifier in export and import extra-field selects.', 'Checked in core/extrafieldsinexport.inc.php:69 and core/extrafieldsinimport.inc.php:66. Both files share the same condition guard.', 'Enabling this constant changes how extra-field select values are represented in export/import files, affecting compatibility with external tools expecting technical keys.', 'Any non-empty value = use label for select in export/import; empty/unset = use technical value', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolGlobalString(''EXPORT_LABEL_FOR_SELECT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_MAX_EXECUTION_TIME', 'string', NULL, 'blockedlog', 'Sets the maximum PHP execution time in seconds allowed for export operations.', 'Read at blockedlog/admin/blockedlog_list.php:122, blockedlog/admin/blockedlog_archives.php:127, and exports/export.php:301, all with the inline comment ''5mn if not defined'' and a default of 300 seconds.', 'Increasing this value allows larger exports to complete without hitting a PHP timeout; decreasing it causes exports to abort sooner.', 'An integer number of seconds; default is 300 (5 minutes).', 0, 0, 'blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_archives.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$max_execution_time_for_importexport = getDolGlobalInt(''EXPORT_MAX_EXECUTION_TIME'', 300); // 5mn if not defined"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_NAME_WITH_DT', 'string', NULL, 'exports', 'When set, appends a date-time stamp to the exported file name.', 'Checked at exports/class/export.class.php:745. Only 1 occurrence and no admin UI or comment explaining the exact format.', 'Enabling this constant causes the export file name to include a date-time component.', 'Boolean/truthy: non-empty enables date-time in the filename.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''EXPORT_NAME_WITH_DT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_PREFIX_SPEC', 'string', NULL, 'exports', 'When set, prepends a custom string prefix to the exported file name.', 'Checked at exports/class/export.class.php:740 and read at line 741: the filename becomes the prefix + ''_'' + datatoexport. Only 2 occurrences and no admin UI.', 'Setting this constant changes the generated export file name to start with the specified prefix followed by an underscore.', 'Any string; prepended to the export filename as ''<prefix>_<datatoexport>''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''EXPORT_PREFIX_SPEC'')) {", "$filename = getDolGlobalString(''EXPORT_PREFIX_SPEC'') . \"_\".$datatoexport;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXPORT_TSV_FORCE_CHARSET', 'string', NULL, 'core', 'Forces a specific character set encoding for TSV export output.', 'Read in three locations in core/modules/export/export_tsv.modules.php: at line 269 to override $outputlangs->charset_output, at line 238 as an argument to tsv_clean(), and at line 358 to set the $charset variable. No admin UI write is present.', 'Setting this constant forces all TSV export data to be encoded in the specified character set, overriding the default output language charset. Leaving it unset uses the default charset.', 'A charset string (e.g. ''UTF-8'', ''ISO-8859-1''); empty or unset = default output language charset used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/export/export_tsv.modules.php:269|read|$outputlangs->charset_output = getDolGlobalString(''EXPORT_TSV_FORCE_CHARSET'');", "core/modules/export/export_tsv.modules.php:238|read|$newvalue = $this->tsv_clean($newvalue, getDolGlobalString(''EXPORT_TSV_FORCE_CHARSET''));", "core/modules/export/export_tsv.modules.php:358|read|$charset = getDolGlobalString(''EXPORT_TSV_FORCE_CHARSET'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXTERNALRSS_USE_SIMPLEXML', 'bool', NULL, 'core', 'Forces the RSS parser to use PHP''s SimpleXMLElement instead of the default array-based parser.', 'Checked in core/class/rssparser.class.php at lines 336, 419, 472, 480, 518, and 535. The COMMENTS entry states: ''* @var SimpleXMLElement|array<string,mixed>  SimpleXMLElement when getDolGlobalString(''EXTERNALRSS_USE_SIMPLEXML'')''.', 'Enabling this constant causes the RSS parser to return a SimpleXMLElement object; disabling it returns an array. Code that consumes the parser output must handle both types.', 'Truthy string to use SimpleXMLElement; empty/unset to use array-based parsing.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/rssparser.class.php:108  * @var SimpleXMLElement|array<string,mixed>  SimpleXMLElement when getDolGlobalString(''EXTERNALRSS_USE_SIMPLEXML'')", "core/class/rssparser.class.php:336|check|if (getDolGlobalString(''EXTERNALRSS_USE_SIMPLEXML'')) {", "core/class/rssparser.class.php:419|check|if (getDolGlobalString(''EXTERNALRSS_USE_SIMPLEXML'')) {", "core/class/rssparser.class.php:480|check|if (getDolGlobalString(''EXTERNALRSS_USE_SIMPLEXML'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXTERNAL_RSS_TITLE_', 'string', NULL, 'admin', 'Stores the display title for an indexed external RSS feed configured in the admin RSS settings.', 'Written and deleted in admin/external_rss.php:115 and :176. The constant name is built as EXTERNAL_RSS_TITLE_ concatenated with the RSS feed index number.', 'Changing this constant updates the label shown for the corresponding RSS feed widget.', 'String title for the RSS feed.', 0, 0, 'admin/external_rss.php|admin/external_rss.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$result1 = dolibarr_set_const($db, \"EXTERNAL_RSS_TITLE_\".GETPOSTINT(\"norss\"), GETPOST($external_rss_title), ''chaine'', 0, '''', $conf->entity);", "$result1 = dolibarr_del_const($db, \"EXTERNAL_RSS_TITLE_\".GETPOSTINT(\"norss\"), $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXTERNAL_RSS_URLRSS_', 'string', NULL, 'admin', 'Stores the URL for an indexed external RSS feed displayed in Dolibarr, keyed by feed number.', 'Set via the admin UI at admin/external_rss.php. The constant name is dynamic (e.g. EXTERNAL_RSS_URLRSS_1). The payload shows a deletion call for a specific feed number from the norss POST parameter.', 'Removing or changing these constants alters which external RSS feed URLs are configured and displayed in Dolibarr.', 'String (RSS feed URL); name includes numeric feed index suffix.', 0, 0, 'admin/external_rss.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/external_rss.php:179|write|$result2 = dolibarr_del_const($db, \"EXTERNAL_RSS_URLRSS_\".GETPOSTINT(\"norss\"), $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('EXTERNAL_USERS_ARE_AUTHORIZED', 'string', NULL, 'comm', 'Grants external (third-party contact) users access to the emailing module, overriding the default restriction.', 'Checked in five mailing PHP files (targetemailing.php:106, info.php:46, card.php:118, advtargetemailing.php:122, list.php:109) with the pattern: if (!getDolGlobalString(''EXTERNAL_USERS_ARE_AUTHORIZED'') && $user->socid > 0) — deny access when unset and user is external.', 'When unset, external users (socid > 0) are blocked from all mailing pages. When set to a truthy value, external users with the mailing read right gain access.', 'Non-empty string = external users allowed. Empty/unset = external users denied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/targetemailing.php:106|check|if (!$user->hasRight(''mailing'', ''lire'') || (!getDolGlobalString(''EXTERNAL_USERS_ARE_AUTHORIZED'') && $user->socid > 0)) {", "comm/mailing/info.php:46|check|if (!$user->hasRight(''mailing'', ''lire'') || (!getDolGlobalString(''EXTERNAL_USERS_ARE_AUTHORIZED'') && $user->socid > 0)) {", "comm/mailing/card.php:118|check|if (!$user->hasRight(''mailing'', ''lire'') || (!getDolGlobalString(''EXTERNAL_USERS_ARE_AUTHORIZED'') && $user->socid > 0)) {", "comm/mailing/list.php:109|check|if (!$user->hasRight(''mailing'', ''lire'') || (!getDolGlobalString(''EXTERNAL_USERS_ARE_AUTHORIZED'') && $user->socid > 0)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTUREFOURN_REUSE_NOTES_ON_CREATE_FROM', 'bool', NULL, 'fourn', 'Controls whether public and private notes are carried over when creating a supplier invoice from another document.', 'Checked in fourn/facture/card.php at lines 2345-2346. When set, getDefaultCreateValueFor uses the source object''s note_public and note_private as default values for the new supplier invoice.', 'Without this flag the notes fields start empty on the new invoice. Enabling it pre-fills both public and private notes from the originating document.', '0 or unset = notes not copied; 1 = notes copied from source document', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$note_public = $object->getDefaultCreateValueFor(''note_public'', ((!empty($origin) && !empty($originid) && is_object($objectsrc) && getDolGlobalString(''FACTUREFOURN_REUSE_NOTES_ON_C", "$note_private = $object->getDefaultCreateValueFor(''note_private'', ((!empty($origin) && !empty($originid) && is_object($objectsrc) && getDolGlobalString(''FACTUREFOURN_REUSE_NOTES_ON"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTUREREC_SUPPORT_RULE_FOR_LINES', 'string', NULL, 'compta', 'Enables support for date rules applied to individual lines on recurring invoices.', 'Checked at compta/facture/card-rec.php:1367 and :1740 to conditionally display line-level date rule controls. Also used as an ''enabled'' condition for the ''rule_for_lines_dates'' field in compta/facture/class/facture-rec.class.php:284.', 'When enabled, recurring invoice lines can have individual date rules configured; when disabled, the date rule field and its UI are hidden.', '0 or not set = line-level date rules not available; non-zero = line-level date rules enabled on recurring invoices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card-rec.php:1367|check|if (getDolGlobalInt(\"FACTUREREC_SUPPORT_RULE_FOR_LINES\")) {", "compta/facture/class/facture-rec.class.php:284|read|''rule_for_lines_dates'' => array(''type'' => ''varchar(255)'', ''label'' => ''RuleForLinesDates'', ''enabled'' => ''getDolGlobalInt(\"FACTUREREC_SUPPORT_RULE_FOR_LINES\")'', ''visible'' => 1,"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ADDON', 'string', NULL, 'compta', 'Specifies the numbering module used to generate reference numbers for customer invoices.', 'Configured via admin/invoice.php:168 and used in compta/facture/class/facture.class.php:5130+. COMMENTS confirm it controls numbering: ''according to numbering module defined into constant FACTURE_ADDON''. Defaults to ''mod_facture_terre'' or ''mod_facture_mercure'' depending on context.', 'Changing this value switches the invoice reference numbering scheme; selecting a deprecated module triggers a warning in the admin UI.', 'String name of an invoice numbering module (e.g., ''mod_facture_terre'', ''mod_facture_mercure'')', 0, 0, 'admin/invoice.php|admin/invoice.php|admin/invoice.php|admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:5099  *      according to numbering module defined into constant FACTURE_ADDON", "admin/invoice.php:168|write|dolibarr_set_const($db, \"FACTURE_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "compta/facture/class/facture.class.php:5130|check|if (!getDolGlobalString(''FACTURE_ADDON'')) {", "compta/facture/class/facture.class.php:5131|write|$conf->global->FACTURE_ADDON = ''mod_facture_terre'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ADDON_PDF', 'string', NULL, 'compta', 'Specifies the PDF template module used for generating customer invoice documents.', 'Set via admin/invoice.php:154 and read in 19+ locations across invoice, supplier payment, and product lot admin pages. The selected module name is used to load and render PDF documents for customer invoices. Admin UI available at admin/invoice.php.', 'Changing this value switches the PDF layout used when generating customer invoices.', 'Name string of the PDF module (e.g. a module identifier matching an available invoice PDF template).', 0, 0, 'admin/supplier_payment.php|product/admin/product_lot.php|admin/invoice.php|admin/invoice.php|admin/invoice.php|admin/supplier_payment.php|admin/invoice.php|admin/invoice.php|product/admin/product_lot.php|admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/invoice.php:154|write|if (dolibarr_set_const($db, \"FACTURE_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/invoice.php:604|check|if (getDolGlobalString(''FACTURE_ADDON_PDF'') == (string) $name) {", "admin/supplier_payment.php:92|check|if (getDolGlobalString(\"FACTURE_ADDON_PDF\") == \"$value\") {", "product/admin/product_lot.php:116|check|if (getDolGlobalString(''FACTURE_ADDON_PDF'') == \"$value\") {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ADDON_PDF_', 'string', NULL, 'admin', 'Selects the PDF template add-on for a specific invoice type, identified by the integer type suffix.', 'Written in admin/invoice.php:234 via dolibarr_set_const. The constant name is built as FACTURE_ADDON_PDF_ concatenated with the integer invoice type.', 'Changing this constant switches the PDF layout/template used when generating invoices of the corresponding type.', 'String PDF template/add-on name.', 0, 0, 'admin/invoice.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, ''FACTURE_ADDON_PDF_''.intval($type), $value, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) where ODT invoice template files are stored.', 'Read in core/modules/facture/doc/doc_generic_invoice_odt.modules.php at lines 127 and 154; at line 127 the value is split by comma/newline into a list of directories to search for ODT templates. Checked at line 162 to determine whether to scan those paths.', 'Setting this constant to one or more comma-separated directory paths enables the ODT invoice module to find custom templates. If unset, the module cannot locate any templates.', 'Comma-separated or newline-separated directory paths pointing to ODT template files.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/doc/doc_generic_invoice_odt.modules.php:127|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim($conf->global->FACTURE_ADDON_PDF_ODT_PATH)));", "core/modules/facture/doc/doc_generic_invoice_odt.modules.php:154|read|$texte .= getDolGlobalString(''FACTURE_ADDON_PDF_ODT_PATH'');", "core/modules/facture/doc/doc_generic_invoice_odt.modules.php:162|check|if (getDolGlobalString(''FACTURE_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_CHQ_NUMBER', 'string', NULL, 'core', 'Stores the bank account identifier used to print cheque/payment details on invoices, proposals, and orders.', 'Written via admin/invoice.php:174, admin/order.php:189, and admin/propal.php:132. Read in many places including admin/propal.php:587 and 603 to populate select options, and admin/invoice.php:757 to retrieve the configured bank account. Used across proposals, orders, and invoice PDF generation.', 'Changing this value changes the bank account whose details appear in cheque payment sections of generated documents.', '''-1'' = use company default (mysoc); any other value = ID of the selected bank account; empty = none configured', 0, 0, 'admin/propal.php|admin/propal.php|admin/order.php|admin/invoice.php|admin/order.php|admin/order.php|admin/invoice.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/invoice.php:174|write|$res = dolibarr_set_const($db, \"FACTURE_CHQ_NUMBER\", $chq, ''chaine'', 0, '''', $conf->entity);", "admin/propal.php:587|read|print ''<option value=\"-1\"''.(getDolGlobalString(''FACTURE_CHQ_NUMBER'') ? '' selected'' : '''').''>''.$langs->trans(\"MenuCompanySetup\").'' (''.($mysoc->name ? $mysoc->name : $langs->trans(\"No", "admin/invoice.php:757|read|$FACTURE_CHQ_NUMBER = getDolGlobalInt(''FACTURE_CHQ_NUMBER'');", "admin/order.php:189|write|$res = dolibarr_set_const($db, \"FACTURE_CHQ_NUMBER\", $chq, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_DEPOSITS_ARE_JUST_PAYMENTS', 'string', NULL, 'compta', 'When enabled, deposit invoices are treated as simple payments rather than standalone invoices, suppressing credit note generation from them.', 'Checked in 56 occurrences across compta/facture/card.php, compta/stats/, comm/propal/card.php, commande/card.php, expedition/shipment.php, and accountancy/admin/index.php. Comments at core/class/commoninvoice.class.php:381 state: ''Should always be empty, except if option FACTURE_DEPOSITS_ARE_JUST_PAYMENTS is on for sale invoices (not recommended)''. Same note appears at core/class/discount.class.php:710.', 'When enabled, deposit invoices are processed as payments only and do not generate discounts or credit notes. This mode is explicitly noted as ''not recommended'' in the source code comments.', 'Truthy value = deposits treated as payments only (not recommended); empty/unset = deposits treated as standard invoice type.', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["*  Should always be empty, except if option FACTURE_DEPOSITS_ARE_JUST_PAYMENTS is on for sale invoices (not recommended),", "*  Should always be empty, except if option FACTURE_DEPOSITS_ARE_JUST_PAYMENTS or FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS is on (not recommended).", "compta/facture/card.php:6820|check|if (($object->type == Facture::TYPE_STANDARD || ($object->type == Facture::TYPE_DEPOSIT && !getDolGlobalString(''FACTURE_DEPOSITS_ARE_JUST_PAYMENTS'')) || ...", "accountancy/admin/index.php:481|check|if (getDolGlobalString(''FACTURE_DEPOSITS_ARE_JUST_PAYMENTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_DRAFT_WATERMARK', 'string', NULL, 'core', 'Sets the text string used as a watermark on draft invoice and asset PDFs.', 'Written in admin/invoice.php at line 188 and displayed as a text input at line 857. Read in pdf_octopus.modules.php at line 297, pdf_sponge.modules.php at line 231, and pdf_standard_asset.modules.php at line 818 to set $this->watermark; the watermark is only applied when invoice status is STATUS_DRAFT.', 'Setting this constant to a non-empty string causes a visible watermark (e.g. ''DRAFT'') to appear on draft invoice and draft asset PDFs. Clearing it removes the watermark.', 'Any non-empty string to use as the watermark text; empty/unset = no watermark.', 0, 0, 'admin/invoice.php|admin/invoice.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/invoice.php:188|write|$res = dolibarr_set_const($db, \"FACTURE_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "core/modules/facture/doc/pdf_octopus.modules.php:296|check|if ($object->status == $object::STATUS_DRAFT && (getDolGlobalString(''FACTURE_DRAFT_WATERMARK''))) {", "core/modules/facture/doc/pdf_octopus.modules.php:297|read|$this->watermark = getDolGlobalString(''FACTURE_DRAFT_WATERMARK'');", "core/modules/asset/doc/pdf_standard_asset.modules.php:818|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', $conf->global->FACTURE_DRAFT_WATERMARK);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ENABLE_NEGATIVE', 'bool', NULL, 'compta', 'When enabled, allows creation and validation of invoices with a negative total amount (excluding credit notes).', 'Checked in compta/facture/card.php:422 to skip the blocking error when total_ttc is negative, and referenced in card.php:5004 in a comment confirming this condition only occurs when this constant is on.', 'Without this constant, invoices with a negative total (other than credit notes) are blocked from validation. Enabling it permits negative-total standard invoices.', '0 or unset = negative-total invoices blocked; truthy = negative-total invoices allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:422|check|if (!getDolGlobalString(''FACTURE_ENABLE_NEGATIVE'') && $object->total_ttc < 0) {", "compta/facture/card.php:5004|check|if ($object->type != Facture::TYPE_CREDIT_NOTE && $object->total_ttc < 0) { \t\t// Can happen only if getDolGlobalString(''FACTURE_ENABLE_NEGATIVE'') is on"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_ENABLE_NEGATIVE_LINES', 'bool', NULL, 'compta', 'Allows negative unit price lines to be added to invoices and credit notes.', 'Checked in compta/facture/card.php:452, :2538, :2543, :3207, :3208 and compta/facture/class/facture.class.php:4705. Without this constant, the system rejects lines with negative HT or TTC prices; credit notes are also affected when combined with INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN.', 'When not set, any invoice line with a negative price is rejected. Enabling it allows negative amounts on standard invoices and influences credit note line handling.', 'Empty/0 = negative lines forbidden; truthy = negative lines allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:452|check|if (($tmp_total_ht < 0 || $tmp_total_ht_devise < 0) && !getDolGlobalString(''FACTURE_ENABLE_NEGATIVE_LINES'')) {", "compta/facture/card.php:2543|check|if (((float) $price_ht < 0 || (float) $price_ttc < 0) && !getDolGlobalString(''FACTURE_ENABLE_NEGATIVE_LINES'')) {", "compta/facture/class/facture.class.php:4705|check|if ($this->type == self::TYPE_CREDIT_NOTE  && !getDolGlobalInt(''FACTURE_ENABLE_NEGATIVE_LINES'') && !getDolGlobalInt(''INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_LOCAL_TAX1_OPTION', 'string', NULL, 'core', 'Controls whether local tax 1 is applied on invoices and related documents.', 'Written via admin/company.php at line 258 and displayed as radio buttons at lines 797 and 815. Checked against ''localtax1on'' in multiple PDF generation modules (e.g. core/modules/supplier_order/doc/pdf_cornas.modules.php line 1044, pdf_muscadet.modules.php line 875) and in core/tpl/objectline_title.tpl.php at line 91.', 'Setting to ''localtax1on'' activates local tax 1 on invoice lines and document totals; other values or empty disables it.', '''localtax1on'' = local tax 1 active; ''localtax1off'' or empty = local tax 1 inactive', 0, 0, 'admin/company.php|admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:258|write|dolibarr_set_const($db, \"FACTURE_LOCAL_TAX1_OPTION\", $uselocaltax1, ''chaine'', 0, '''', $conf->entity);", "core/modules/supplier_order/doc/pdf_cornas.modules.php:1044|check|if (getDolGlobalString(''FACTURE_LOCAL_TAX1_OPTION'') == ''localtax1on'' && $object->total_localtax1 > 0) {", "core/modules/supplier_order/doc/pdf_muscadet.modules.php:875|check|if (getDolGlobalString(''FACTURE_LOCAL_TAX1_OPTION'') == ''localtax1on'' && $object->total_localtax1 > 0) {", "core/tpl/objectline_title.tpl.php:91|check|if (getDolGlobalString(''FACTURE_LOCAL_TAX1_OPTION'') || getDolGlobalString(''FACTURE_LOCAL_TAX2_OPTION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_LOCAL_TAX2_OPTION', 'string', NULL, 'core', 'Controls whether the second local tax (localtax2) is enabled or disabled on invoices and related documents.', 'Configured via admin/company.php (written by dolibarr_set_const). Checked across invoice, order, and proposal PDF modules to decide whether to display or compute the second local tax column. Value ''localtax2on'' enables local tax 2; absence or ''localtax2off'' disables it.', 'Setting this to ''localtax2on'' causes local tax 2 amounts to be rendered in PDF documents and included in totals. Disabling it suppresses the localtax2 column and computations in those documents.', '''localtax2on'' = local tax 2 enabled; ''localtax2off'' or empty = local tax 2 disabled', 0, 0, 'admin/company.php|admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:259|write|dolibarr_set_const($db, \"FACTURE_LOCAL_TAX2_OPTION\", $uselocaltax2, ''chaine'', 0, '''', $conf->entity);", "core/modules/supplier_order/doc/pdf_cornas.modules.php:1053|check|if (getDolGlobalString(''FACTURE_LOCAL_TAX2_OPTION'') == ''localtax2on'' && $object->total_localtax2 > 0) {", "admin/company.php:841|read|print ''<tr class=\"oddeven\"><td><input type=\"radio\" name=\"optionlocaltax2\" id=\"lt2\" value=\"localtax2on\"''", "core/modules/supplier_order/doc/pdf_muscadet.modules.php:884|check|if (getDolGlobalString(''FACTURE_LOCAL_TAX2_OPTION'') == ''localtax2on'' && $object->total_localtax2 > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_MERCURE_MASK_CREDIT', 'string', NULL, 'core', 'Stores the numbering mask pattern for credit notes in the Mercure invoice numbering module.', 'Used in core/modules/facture/mod_facture_mercure.php in two locations: line 109 populates a UI input, and line 174 retrieves it to generate credit note reference numbers.', 'Changing the mask pattern alters how new credit note numbers are generated by the Mercure module. Clearing it causes the module to have no mask for credit notes.', 'Any string = mask pattern for Mercure credit note numbering; empty/unset = no mask pattern.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_facture_mercure.php:109|value=''\".getDolGlobalString(\"FACTURE_MERCURE_MASK_CREDIT\").\"''", "mod_facture_mercure.php:174|$mask = getDolGlobalString(''FACTURE_MERCURE_MASK_CREDIT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_MERCURE_MASK_DEPOSIT', 'string', NULL, 'core', 'Defines the numbering mask used for deposit invoices in the Mercure invoice module.', 'Read in core/modules/facture/mod_facture_mercure.php at line 176 to set the mask for deposit invoices. It is also exposed as a text input field in the module configuration UI at line 122.', 'If unset, deposit invoices have no dedicated mask and will use module defaults, which may cause numbering conflicts with regular invoices.', 'A mask pattern string compatible with the Mercure numbering module; no explicit enumeration in code.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/mod_facture_mercure.php:176|read|$mask = getDolGlobalString(''FACTURE_MERCURE_MASK_DEPOSIT'');", "core/modules/facture/mod_facture_mercure.php:122|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskdeposit\" value=\"''.getDolGlobalString(\"FACTURE_MERCURE_MASK_DEPOSIT\").''\">"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_MERCURE_MASK_INVOICE', 'string', NULL, 'core', 'Stores the numbering mask pattern for standard invoices in the Mercure invoice numbering module.', 'Used in core/modules/facture/mod_facture_mercure.php in three locations: line 101 populates a UI input, line 172 provides it as the fallback for FACTURE_MERCURE_MASK_REPLACEMENT, and line 178 retrieves it directly for standard invoice numbering.', 'Changing the mask pattern alters how new standard invoice numbers are generated by the Mercure module. Clearing it causes the module to have no mask for standard invoices.', 'Any string = mask pattern for Mercure standard invoice numbering; empty/unset = no mask pattern.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_facture_mercure.php:101|value=''\".getDolGlobalString(\"FACTURE_MERCURE_MASK_INVOICE\").\"''", "mod_facture_mercure.php:172|$mask = getDolGlobalString(''FACTURE_MERCURE_MASK_REPLACEMENT'', getDolGlobalString(''FACTURE_MERCURE_MASK_INVOICE''));", "mod_facture_mercure.php:178|$mask = getDolGlobalString(''FACTURE_MERCURE_MASK_INVOICE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_MERCURE_MASK_REPLACEMENT', 'string', NULL, 'core', 'Defines the numbering mask used for replacement invoices in the Mercure invoice module.', 'Read in core/modules/facture/mod_facture_mercure.php at line 172 to set the mask for replacement invoices, falling back to FACTURE_MERCURE_MASK_INVOICE if unset. It is also exposed as a text input field in the module configuration UI at line 115.', 'If unset, replacement invoices fall back to the standard invoice mask (FACTURE_MERCURE_MASK_INVOICE), so numbering sequences for replacement invoices will not be distinct.', 'A mask pattern string compatible with the Mercure numbering module (e.g. ''{YYYY}{MM}-{####}''); no explicit enumeration in code.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/mod_facture_mercure.php:172|read|$mask = getDolGlobalString(''FACTURE_MERCURE_MASK_REPLACEMENT'', getDolGlobalString(''FACTURE_MERCURE_MASK_INVOICE''));", "core/modules/facture/mod_facture_mercure.php:115|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskreplacement\" value=\"''.getDolGlobalString(\"FACTURE_MERCURE_MASK_REPLACEMEN"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_PAYMENTS_INVOICE_REQUESTED_SORT_FIRST', 'string', NULL, 'compta', 'When enabled, sorts the requested invoice to the top of the invoice list in the payment entry form.', 'Checked once in compta/paiement.php:623 via getDolGlobalInt with a negation check. No admin UI is configured.', 'Enabling this constant reorders the invoice list so that the specifically requested invoice appears first.', 'Non-zero = requested invoice sorted first; 0 or empty = default sort order (default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:623|check|if (!getDolGlobalInt(''FACTURE_PAYMENTS_INVOICE_REQUESTED_SORT_FIRST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS', 'string', NULL, 'accountancy', 'Allows a single payment to be applied across invoices from different third parties.', 'Set via admin/payment.php:92 and checked in accountancy/journal/bankjournal.php:388 and compta/paiement.php:606. The comment at bankjournal.php:385 states ''in case option FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS is on, payment could be for more than one third-partie''.', 'When enabled, payments can span multiple third parties'' invoices and bank journal entries are grouped accordingly; when disabled (bankjournal.php:480-481), amounts are added per matching third party only.', 'yesno: ''1'' or ''yes'' = enabled; ''0'' or empty = disabled', 0, 0, 'admin/payment.php|admin/payment.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:385  // in case option FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS is on, payment could be for more than one third-partie", "accountancy/journal/bankjournal.php:480  // if FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS is off we add $amounttouse", "admin/payment.php:286|read|print $form->selectyesno(\"FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS\", getDolGlobalInt(''FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS''), 1);", "compta/paiement.php:606|check|if (getDolGlobalString(''FACTURE_PAYMENTS_ON_DIFFERENT_THIRDPARTIES_BILLS'') && !empty($facture->thirdparty->parent)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_PAYMENTS_ON_SUBSIDIARY_COMPANIES', 'string', NULL, 'compta', 'When enabled, allows payment entries to include invoices from subsidiary companies of the selected third party.', 'Checked once in compta/paiement.php:610. No admin UI is configured.', 'Enabling this constant extends the invoice list in the payment form to include invoices belonging to subsidiary companies.', 'Truthy (non-empty / 1) = subsidiary company invoices included; falsy (empty / 0) = only direct company invoices shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:610|check|if (getDolGlobalString(''FACTURE_PAYMENTS_ON_SUBSIDIARY_COMPANIES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_PAYMENTS_SHOW_LINK_TO_INPUT_ORIGIN_IS_MORE_THAN', 'bool', NULL, 'compta', 'Sets a threshold above which a link to the payment input origin is displayed on the payment page.', 'Checked once in compta/paiement.php:584 in a condition also testing that $action != ''add_paiement''. No admin UI is configured.', 'When set to a non-empty value, the UI shows an origin link on the payment page under the configured condition.', 'Numeric threshold or truthy string; empty = link never shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:584|check|if ($action != ''add_paiement'' && getDolGlobalString(''FACTURE_PAYMENTS_SHOW_LINK_TO_INPUT_ORIGIN_IS_MORE_THAN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_PAYMENT_FIX_LINK_TO_BANK', 'string', NULL, 'compta', 'Forces a fixed bank account link on payment records and pre-selects that account in the payment list search.', 'Checked in compta/paiement/list.php:522 to show a fix-link action for users with payment permission, and read at :675 to pre-select the account in the search dropdown when set.', 'Enabling this constant causes a bank account to be pre-selected and a fix-link action to appear on the payment list; disabling it removes both behaviors.', 'Any non-empty value (interpreted as account identifier) = enable fixed bank account link; empty/unset = no fixed link', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!empty($permissiontopay) && getDolGlobalString(''FACTURE_PAYMENT_FIX_LINK_TO_BANK'')) {", "getDolGlobalString(''FACTURE_PAYMENT_FIX_LINK_TO_BANK'') ? 1 : 0"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_REMINDER_EMAIL', 'string', NULL, 'compta', 'Guards a commented-out invoice reminder email block, suggesting it was intended to control whether reminder emails are sent for invoices.', 'Referenced in compta/facture/class/facture.class.php:6225 inside a commented-out conditional block. The surrounding code is disabled, so this constant has no active effect in the current codebase.', 'No active effect; the block using this constant is commented out.', 'Empty/unset disables the (commented-out) block; any non-empty value would have enabled it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["/*if (empty($conf->global->FACTURE_REMINDER_EMAIL)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_REUSE_NOTES_ON_CREATE_FROM', 'bool', NULL, 'compta', 'When enabled, copies the public and private notes from the source document into a new invoice created from it.', 'Checked in compta/facture/card.php at lines 3865 and 3866 when populating default note_public and note_private values during invoice creation from a source object.', 'Enabling this constant causes invoices created from source documents to inherit both public and private notes from the source.', '0 or unset = notes are not copied from source; truthy = notes are copied from source document.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:3865|check|$note_public = $object->getDefaultCreateValueFor(''note_public'', ((!empty($origin) && !empty($originid) && is_object($objectsrc) && getDolGlobalString(''FACTURE_REUSE_NOTES_ON_CREATE", "compta/facture/card.php:3866|check|$note_private = $object->getDefaultCreateValueFor(''note_private'', ((!empty($origin) && !empty($originid) && is_object($objectsrc) && getDolGlobalString(''FACTURE_REUSE_NOTES_ON_CREA"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_RIB_NUMBER', 'string', NULL, 'core', 'Stores the identifier of the bank account (RIB) to print by default on invoices, orders, and proposals.', 'Holds the rowid or account number of the bank account selected for inclusion in generated documents. Written by admin/invoice.php, admin/order.php, and admin/propal.php. Used in over 30 PDF generation modules to decide whether to print bank details.', 'Setting this causes the corresponding bank account details to appear on generated PDF documents (invoices, orders, proposals). Clearing it removes the default bank account from those documents.', 'String matching a bank account rowid/identifier; empty = no default bank account printed', 0, 0, 'admin/propal.php|admin/order.php|admin/invoice.php|admin/order.php|admin/invoice.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/invoice.php:173|write|$res = dolibarr_set_const($db, \"FACTURE_RIB_NUMBER\", $rib, ''chaine'', 0, '''', $conf->entity);", "admin/order.php:601|read|print getDolGlobalString(''FACTURE_RIB_NUMBER'') == $row[0] ? '' selected'' : '''';", "core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php:1009|check|if (!empty($object->fk_account) || !empty($object->fk_bank) || getDolGlobalInt(''FACTURE_RIB_NUMBER'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:878|check|if ($object->fk_account > 0 || $object->fk_bank > 0 || getDolGlobalInt(''FACTURE_RIB_NUMBER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_SENDBYEMAIL_FOR_ALL_STATUS', 'string', NULL, 'compta', 'When enabled, allows the ''send by email'' action to be shown on invoices of any status, not just validated or closed ones.', 'Checked in compta/facture/card.php:6681 as an override to display the email send button regardless of invoice status. Only one occurrence is present in the payload.', 'Enabling this constant makes the email action available on draft invoices and other non-standard statuses.', '0 or unset = email action shown only for validated or closed invoices; truthy = email action shown for all statuses.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:6681|check|if (($object->status == Facture::STATUS_VALIDATED || $object->status == Facture::STATUS_CLOSED) || getDolGlobalString(''FACTURE_SENDBYEMAIL_FOR_ALL_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS', 'string', NULL, 'compta', 'When enabled, treats supplier deposit invoices as simple payments rather than as real invoices generating discount lines (not recommended).', 'Checked in 38 locations across accountancy/admin/index.php:484, fourn/commande/card.php:2515, compta/resultat pages, and supplier_proposal/card.php:1984. Code comments at core/class/commoninvoice.class.php:382 state this option is ''not recommended'' for purchase invoices, and core/class/discount.class.php:710 notes it should ''always be empty''.', 'Enabling this option causes supplier deposit invoices to be processed as payments, bypassing discount line generation; this is explicitly flagged as not recommended in the source.', 'Non-empty/truthy = deposits treated as payments (not recommended); empty = standard deposit invoice behaviour (default)', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commoninvoice.class.php:382  *  of FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS is on for purchase invoices (not recommended).", "core/class/commoninvoice.class.php:391  // FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS was never supported for purchase invoice, so we can return 0 with no need of SQL for this case.", "core/class/discount.class.php:710  *  Should always be empty, except if option FACTURE_DEPOSITS_ARE_JUST_PAYMENTS or FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS is on (not recommended).", "accountancy/admin/index.php:484|check|if (getDolGlobalString(''FACTURE_SUPPLIER_DEPOSITS_ARE_JUST_PAYMENTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_TVAOPTION', 'string', NULL, 'admin', 'Controls whether the company is subject to VAT (TVA) on invoices.', 'Written via admin/company.php at line 257 and displayed as radio buttons at lines 766 and 776. Read in societe/class/societe.class.php at line 4910 as an integer to set the tva_assuj property. Also checked in admin/dict.php at line 1555.', 'Enabling this constant marks the company as VAT-liable; disabling it marks the company as not subject to VAT, affecting invoice tax calculations.', '''1'' = subject to VAT; ''0'' or empty = not subject to VAT', 0, 0, 'admin/company.php|admin/company.php|admin/dict.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:257|write|dolibarr_set_const($db, \"FACTURE_TVAOPTION\", $usevat, ''chaine'', 0, '''', $conf->entity);", "admin/company.php:766|read|print ''<tr class=\"oddeven\"><td><label><input type=\"radio\" name=\"optiontva\" id=\"use_vat\" value=\"1\"''.(!getDolGlobalString(''FACTURE_TVAOPTION'') ? \"\" : \" checked\").\"", "admin/dict.php:1555|check|if ($id == DICT_TVA && !getDolGlobalString(''FACTURE_TVAOPTION'')) {", "societe/class/societe.class.php:4910|read|$this->tva_assuj = getDolGlobalInt(''FACTURE_TVAOPTION'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FACTURE_VALIDATED_IN_AMOUNT', 'string', NULL, 'core', 'When set to 1, enables amount-based validation mode for invoices.', 'Read once in core/lib/invoice.lib.php:444 via getDolGlobalInt(''FACTURE_VALIDATED_IN_AMOUNT'') == 1, yielding the boolean $amount_mode. Exact behavior of $amount_mode beyond this check is not visible in the payload.', 'If set to 1, activates amount-based invoice validation logic. If unset or not 1, standard validation applies.', '1 = amount-based validation enabled. 0 or unset = standard validation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/invoice.lib.php:444|read|$amount_mode = (getDolGlobalInt(''FACTURE_VALIDATED_IN_AMOUNT'') == 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FAC_FORCE_DATE_VALIDATION', 'string', NULL, 'compta', 'Forces the invoice date to be set to the validation date when an invoice is validated.', 'Set via admin/invoice.php:216 and checked in compta/facture/class/facture.class.php:3703 and :3725 with the inline comment ''If option enabled, we force invoice date''. Also read at compta/facture/card.php:4950 and :5480 to hide the manual date edit option. Admin UI at admin/invoice.php:872.', 'Enabling this prevents users from manually setting an invoice date that differs from the validation date; the date is overwritten at validation time.', '0 or unset = invoice date set manually; truthy value = invoice date forced to validation date.', 0, 0, 'admin/invoice.php|admin/invoice.php|admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:3703|check|if (getDolGlobalString(''FAC_FORCE_DATE_VALIDATION'')) {\t// If option enabled, we force invoice date", "compta/facture/class/facture.class.php:3725|check|if (getDolGlobalString(''FAC_FORCE_DATE_VALIDATION'')) {\t// If option enabled, we force invoice date", "admin/invoice.php:872|read|print $form->selectyesno(\"forcedate\", getDolGlobalInt(''FAC_FORCE_DATE_VALIDATION'', 0), 1);", "compta/facture/card.php:5480|check|if ($action != ''editinvoicedate'' && $object->status == $object::STATUS_DRAFT && $usercancreate && !getDolGlobalString(''FAC_FORCE_DATE_VALIDATION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FATURE_LOCAL_TAX2_OPTION', 'string', NULL, 'core', 'Appears to be a misspelling of FACTURE_LOCAL_TAX2_OPTION, referenced in a commented-out code block for local tax 2 handling.', 'The sole occurrence is in core/modules/commande/doc/pdf_einstein.modules.php:1145 inside a commented-out block (//if ...). The comment references both FACTURE_LOCAL_TAX2_OPTION and FATURE_LOCAL_TAX2_OPTION (the typo variant) with a value check for ''localtax2on''.', 'Exact behavior unclear from code alone — the entire usage is commented out. This constant is not actively read or written in any live code path.', 'Referenced value in commented code: ''localtax2on''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_einstein.modules.php:1145|//if (getDolGlobalString(''FACTURE_LOCAL_TAX2_OPTION'') && getDolGlobalString(''FATURE_LOCAL_TAX2_OPTION'') == ''localtax2on'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ALLOW_ANY_CONTENT', 'bool', NULL, 'core', 'Allows any HTML content in the WYSIWYG editor instead of restricting to a predefined safe set of tags.', 'Checked at core/class/doleditor.class.php:221-222; when set, $restrictContent is set to false, disabling tag filtering. No admin UI; hidden setting.', 'Enabling this allows users to insert arbitrary HTML in the editor, which reduces XSS protection. Leaving unset restricts content to a safe predefined tag list.', '0 or empty = only predefined list of html tags are allowed; non-empty = all HTML content allowed in the editor', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:222|read|$restrictContent = !getDolGlobalString(''FCKEDITOR_ALLOW_ANY_CONTENT''); // Only predefined list of html tags are allowed or all", "core/class/doleditor.class.php:221|read|if (isset($conf->global->FCKEDITOR_ALLOW_ANY_CONTENT)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_EDITORNAME', 'string', NULL, 'core', 'Specifies which rich-text editor to use when the FCKeditor module is enabled.', 'Read at core/class/doleditor.class.php:136 with $defaulteditor as fallback. The comment at line 134 states the value can be ''ckeditor'' or ''fckeditor''. Checked in main.inc.php:2035 to load CKEditor assets.', 'Setting this to ''ckeditor'' loads CKEditor; setting it to ''fckeditor'' loads the older FCKeditor.', '''ckeditor'' = use CKEditor (default when fckeditor module enabled); ''fckeditor'' = use FCKeditor', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/doleditor.class.php:134  // Name of extended editor to use (FCKEDITOR_EDITORNAME can be ''ckeditor'' or ''fckeditor'')", "core/class/doleditor.class.php:136|read|$this->tool = getDolGlobalString(''FCKEDITOR_EDITORNAME'', $defaulteditor);", "main.inc.php:2035|check|if (empty($disableforlogin) && (isModEnabled(''fckeditor'') && (!getDolGlobalString(''FCKEDITOR_EDITORNAME'') || getDolGlobalString(''FCKEDITOR_EDITORNAME'') == ''ckeditor'') && !defined(''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_', 'bool', NULL, 'admin', 'Enables or disables the FCKeditor/CKeditor rich-text editor for a specific field or context identified by the constant suffix.', 'Written in admin/fckeditor.php:107 (set to ''1'') and :115 (set to ''0'') via dolibarr_set_const. The constant name is built as FCKEDITOR_ENABLE_ concatenated with a field/context identifier.', 'Setting to ''1'' activates the rich-text editor for the corresponding field; setting to ''0'' disables it and falls back to plain text.', '''1'' = editor enabled; ''0'' = editor disabled.', 0, 0, 'admin/fckeditor.php|admin/fckeditor.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["dolibarr_set_const($db, \"FCKEDITOR_ENABLE_\".$const, \"1\", ''chaine'', 0, '''', $conf->entity);", "dolibarr_set_const($db, \"FCKEDITOR_ENABLE_\".$const, \"0\", ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_DETAILS', 'bool', NULL, 'product', 'Enables the rich-text (FCKeditor/DolEditor) editor for product and intervention line description fields.', 'Passed as the editor-enable parameter to DolEditor instances in fichinter/card.php:1678 and 1759, product/card.php:1644 and 2275, contrat/card.php:1875, product/price_suppliers.php:843, and others (15 total occurrences). Written via admin/fckeditor.php:111 which sets it to ''1''. The comment in core/tpl/objectline_create.tpl.php:763 references it as a boolean conf property.', 'Enabling this constant activates the rich-text editor for description fields on product and intervention line forms; disabling it falls back to a plain textarea.', '1 = rich-text editor enabled; 0 or absent = plain textarea.', 0, 0, 'admin/tools/ui/components/inputs.php|admin/fckeditor.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:763  * @property {boolean} conf.FCKEDITOR_ENABLE_DETAILS", "admin/fckeditor.php:111|write|dolibarr_set_const($db, \"FCKEDITOR_ENABLE_DETAILS\", \"1\", ''chaine'', 0, '''', $conf->entity);", "fichinter/card.php:1678|read|$doleditor = new DolEditor(''np_desc'', $objp->description, '''', 164, ''dolibarr_details'', '''', false, true, getDolGlobalInt(''FCKEDITOR_ENABLE_DETAILS''), ROWS_2, ''90%'');", "product/card.php:1644|read|$doleditor = new DolEditor(''desc'', GETPOST(''desc'', ''restricthtml''), '''', 160, ''dolibarr_details'', '''', false, true, getDolGlobalString(''FCKEDITOR_ENABLE_DETAILS''), ROWS_4, ''90%'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_DETAILS_FULL', 'bool', NULL, 'core', 'Enables the FCKEditor (rich text editor) for the product description field on document line create and edit forms.', 'When set, a DolEditor rich text editor is rendered for the line description field in both objectline_create.tpl.php:453 and objectline_edit.tpl.php:193.', 'Enabling this constant replaces the plain textarea with a full rich-text editor for line descriptions, affecting both line creation and editing.', 'Truthy value = FCKEditor enabled; empty/unset = plain textarea.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:453|check|if (getDolGlobalString(''FCKEDITOR_ENABLE_DETAILS_FULL'')) {", "core/tpl/objectline_edit.tpl.php:193|check|if (getDolGlobalString(''FCKEDITOR_ENABLE_DETAILS_FULL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_MAIL', 'bool', NULL, 'admin', 'Enables the CKEditor (FCKEditor) rich-text editor for mail composition fields in tickets and mail templates.', 'Checked across admin/ticket.php, admin/ticket_public.php, and admin/mails_templates.php. When enabled, DolEditor instances use CKEditor for mail body fields; when disabled, plain text areas are used.', 'Enabling activates the WYSIWYG HTML editor for mail fields; disabling falls back to plain text input.', 'Truthy integer (1) to enable CKEditor for mail fields; 0 or absent to use plain text.', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php|admin/ticket_public.php|admin/ticket_public.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ticket.php:680|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_MAIL'')) {", "admin/ticket_public.php:505|read|$ckeditorenabledforticket = getDolGlobalInt(''FCKEDITOR_ENABLE_MAIL'') ? true : false;", "admin/mails_templates.php:928|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_MAIL'')) {", "admin/ticket.php:790|read|$doleditor = new DolEditor(''TICKET_MESSAGE_MAIL_INTRO'', $mail_intro, ''100%'', 90, ''dolibarr_mailings'', '''', false, true, getDolGlobalInt(''FCKEDITOR_ENABLE_MAIL''), ROWS_2, ''70'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_MAILING', 'bool', NULL, 'comm', 'Enables the CKEditor (FCKEditor) rich-text editor for the mailing body editor in the mass-mailing module.', 'Read in comm/mailing/card.php at lines 962, 1432, 1707 as the usehtmleditor parameter for DolEditor. Checked in comm/mailing/card.php:1273 to enable the full editor toolbar, and in comm/mailing/class/mailing.class.php:429 to detect HTML content.', 'Enabling activates WYSIWYG HTML editing for mailing bodies; disabling falls back to plain text.', 'Truthy integer (1) to enable CKEditor for mailings; 0 or absent to use plain text.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1273|check|if (isModEnabled(''fckeditor'') && getDolGlobalInt(''FCKEDITOR_ENABLE_MAILING'') && $object->messtype != ''sms'') {", "comm/mailing/class/mailing.class.php:429|check|if (getDolGlobalString(''FCKEDITOR_ENABLE_MAILING'') && dol_textishtml(dol_html_entity_decode($obj->body, ENT_COMPAT | ENT_HTML5))) {", "comm/mailing/card.php:962|read|$doleditor = new DolEditor(''bodyemail'', GETPOST(''bodyemail'', ''restricthtmlallowunvalid''), '''', 600, ''dolibarr_mailings'', '''', true, -1, getDolGlobalInt(''FCKEDITOR_ENABLE_MAILING'')", "comm/mailing/card.php:1432|read|$doleditor = new DolEditor(''bodyemail'', $object->body, '''', 600, ''dolibarr_mailings'', '''', false, -1, getDolGlobalInt(''FCKEDITOR_ENABLE_MAILING''), 20, ''100%'', $readonly);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_NOTE_PRIVATE', 'bool', NULL, 'compta', 'Enables the rich-text (FCKeditor/DolEditor) editor for the private notes field on documents.', 'Checked in core/tpl/notes.tpl.php:131 and used across compta/facture, fichinter, contact, comm/propal, commande, product, and other card pages (23 occurrences) to switch the note_private field between plain textarea and rich-text editor. No admin UI write path detected.', 'Enabling this constant activates the rich-text editor for private note fields; disabling it falls back to a plain textarea.', 'Truthy string/bool=rich-text editor enabled, empty/0=plain textarea', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/notes.tpl.php:131|check|if (isModEnabled(''fckeditor'') && getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PRIVATE'')) {", "compta/facture/card.php:4695|read|$doleditor = new DolEditor(''note_private'', (string) $note_private, '''', 80, ''dolibarr_notes'', ''In'', false, false, !getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PRIVATE'') ? 0 : 1,", "product/card.php:1826|read|$doleditor = new DolEditor(''note_private'', GETPOST(''note_private'', ''restricthtml''), '''', 140, ''dolibarr_details'', '''', false, true, getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PRIVATE''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_NOTE_PUBLIC', 'bool', NULL, 'compta', 'Enables the rich-text (FCKeditor/DolEditor) editor for the public notes field on documents.', 'Checked in core/tpl/notes.tpl.php:126 and used across fichinter, contrat, contact, commande, reception, fourn/commande, and other card pages (21 occurrences) to switch the note_public field between plain textarea and rich-text editor. No admin UI write path detected.', 'Enabling this constant activates the rich-text editor for public note fields; disabling it falls back to a plain textarea (DolEditor called with toolbar=0).', 'Truthy string/bool=rich-text editor enabled, empty/0=plain textarea', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/notes.tpl.php:126|check|if (isModEnabled(''fckeditor'') && getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PUBLIC'')) {", "fichinter/card.php:1110|read|$doleditor = new DolEditor(''note_public'', (string) $note_public, '''', 80, ''dolibarr_notes'', ''In'', false, false, !getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PUBLIC'') ? 0 : 1, ROWS_3,", "reception/card.php:1314|read|$doleditor = new DolEditor(''note_public'', (string) $note_public, '''', 80, ''dolibarr_notes'', ''In'', false, false, !getDolGlobalString(''FCKEDITOR_ENABLE_NOTE_PUBLIC'') ? 0 : 1, ROWS_3,"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_PDF', 'bool', NULL, 'core', 'Enables a PDF-related plugin or feature in the WYSIWYG editor.', 'Checked (negated) at core/class/doleditor.class.php:262. No admin UI; hidden setting. Exact behavior beyond the guard check is unclear from code alone.', 'Enabling this activates the PDF plugin in the WYSIWYG editor. Leaving unset keeps the plugin disabled.', '0 or empty = PDF plugin disabled in editor; non-empty = PDF plugin enabled in editor', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:262|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_PDF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_SCAYT_AUTOSTARTUP', 'bool', NULL, 'core', 'Enables automatic startup of the SCAYT (Spell Check As You Type) feature in the WYSIWYG editor.', 'Checked at core/class/doleditor.class.php:269. No admin UI; hidden setting.', 'Enabling this starts the SCAYT spell checker automatically when the editor loads. Leaving unset requires manual activation.', '0 or empty = SCAYT does not auto-start; non-empty = SCAYT auto-starts when the editor loads', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:269|check|if (getDolGlobalString(''FCKEDITOR_ENABLE_SCAYT_AUTOSTARTUP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_SOCIETE', 'bool', NULL, 'projet', 'Enables the rich-text (FCKEditor/DolEditor) widget on note and description fields across project, task, and third-party forms.', 'Checked in 16 locations. projet/tasks/task.php:121 disables a behaviour when this constant is absent; projet/card.php:924 and :1338 pass it as the editor-enable flag to DolEditor; projet/tasks.php:885 and webportal/class/html.formwebportal.class.php:1268 also use it as the enable condition.', 'Enabling this constant activates the rich-text editor on description and note fields in project and task forms; disabling reverts to plain-text areas.', 'Non-zero/non-empty = rich-text editor enabled; 0 or unset = plain-text textarea.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/task.php:121|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_SOCIETE'')) {", "projet/card.php:924|read|$doleditor = new DolEditor(''description'', GETPOST(\"description\", ''restricthtml''), '''', 90, ''dolibarr_notes'', '''', false, true, isModEnabled(''fckeditor'') && getDolGlobalString(''FCKEDI", "projet/card.php:1338|read|$doleditor = new DolEditor(''description'', $object->description, '''', 90, ''dolibarr_notes'', '''', false, true, isModEnabled(''fckeditor'') && getDolGlobalInt(''FCKEDITOR_ENABLE_SOCIETE''),", "webportal/class/html.formwebportal.class.php:1268|read|$doleditor = new DolEditor($htmlName, $value, '''', 200, ''dolibarr_notes'', ''In'', false, false, isModEnabled(''fckeditor'') && getDolGlobalInt(''FCKEDITOR_ENABLE_SOCIETE''), ROWS_5, ''90%''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_SPECIALCHAR', 'bool', NULL, 'admin', 'Enables the special character insertion plugin in the FCKeditor/CKEditor WYSIWYG toolbar.', 'Written in admin/fckeditor.php:120 (enable) and deleted at :123 (disable). Checked (negated) at core/class/doleditor.class.php:253 to add the special character plugin. Configurable via admin/fckeditor.php.', 'Enabling adds the special character tool to the editor toolbar. Disabling removes it.', '0 or empty = special character plugin disabled; 1 = special character plugin enabled in the editor', 0, 0, 'admin/fckeditor.php|admin/fckeditor.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fckeditor.php:120|write|dolibarr_set_const($db, \"FCKEDITOR_ENABLE_SPECIALCHAR\", \"1\", ''chaine'', 0, '''', $conf->entity);", "admin/fckeditor.php:123|write|dolibarr_del_const($db, \"FCKEDITOR_ENABLE_SPECIALCHAR\", $conf->entity);", "core/class/doleditor.class.php:253|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_SPECIALCHAR'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_TICKET', 'bool', NULL, 'core', 'Controls whether the rich text (CKEditor) editor is enabled on the ticket module and on which interfaces.', 'Checked in public/ticket/create_ticket.php and core/class/html.formticket.class.php. Value 0 disables the editor, 1 enables it on the back-office only, and 2 enables it on both back-office and the public page.', 'Setting to 2 exposes a rich-text editor on the public ticket page, which the source code flags as very dangerous. Setting to 0 forces plain-text input everywhere.', '0=no rich text editor, 1=allowed on backoffice only, 2=allowed on backoffice and public page (very dangerous)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// 0=no reich text editor, 1=allowed on backoffice only, 2=allowed on backoffice and public page (very dangerous)", "if (getDolGlobalInt(''FCKEDITOR_ENABLE_TICKET'') >= 2) {", "$ckeditorenabledforticket = (getDolGlobalString(''FCKEDITOR_ENABLE_TICKET'') >= 1);\t\t// 0=no, 1=from backoffice only, 2=from backoffice+public (very dangerous)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_USERSIGN', 'bool', NULL, 'admin', 'Enables the rich-text (FCKeditor/DolEditor) editor for user email signature fields when set to a truthy value.', 'Referenced in admin/mails_senderprofile_list.php (lines 449, 481) and user/card.php (lines 1462, 3090). The editor''s wysiwygtype parameter is set to 1 when the constant is non-empty, and 0 (plain textarea) otherwise.', 'Enabling this constant activates the rich-text editor for signature fields; disabling it reverts signatures to plain-text input.', 'Empty/0 = plain textarea; any non-empty/truthy value = rich-text editor enabled.', 0, 0, 'admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_senderprofile_list.php:481|read|!getDolGlobalString(''FCKEDITOR_ENABLE_USERSIGN'') ? 0 : 1, ROWS_4, ''90%''", "user/card.php:3090|read|!getDolGlobalString(''FCKEDITOR_ENABLE_USERSIGN'') ? 0 :", "admin/mails_senderprofile_list.php:449|read|!getDolGlobalString(''FCKEDITOR_ENABLE_USERSIGN'')", "user/card.php:1462|read|getDolGlobalString(''FCKEDITOR_ENABLE_USERSIGN'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_ENABLE_WSC', 'bool', NULL, 'core', 'Enables the WSC (Web Spell Checker) plugin in the WYSIWYG editor, noting it reached end-of-life in December 2021.', 'Checked (negated) at core/class/doleditor.class.php:259 with inline comment ''spellchecker has end of life december 2021''. No admin UI; hidden setting.', 'Enabling this adds the deprecated WSC spell checker to the editor. Leaving unset keeps the plugin disabled given its end-of-life status.', '0 or empty = WSC spell checker plugin disabled; non-empty = WSC spell checker plugin enabled (end of life December 2021)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:259|check|if (!getDolGlobalString(''FCKEDITOR_ENABLE_WSC'')) {\t// spellchecker has end of life december 2021"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_SKIN', 'string', NULL, 'core', 'Specifies the CKEditor skin (theme) used by the Dolibarr rich text editor.', 'Read in core/lib/doleditor.lib.php:52 and core/class/doleditor.class.php:250 with a default of ''moono-lisa'', which is noted as the default with CKEditor 4.6. No admin UI manages this constant.', 'Changing this alters the visual theme of the CKEditor interface; incorrect skin names will cause the editor to fall back or fail to render.', 'Skin name string; default with ckeditor 4.6 : moono-lisa.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:250|read|$skin = getDolGlobalString(''FCKEDITOR_SKIN'', ''moono-lisa'');\t\t// default with ckeditor 4.6 : moono-lisa", "core/lib/doleditor.lib.php:52|read|$selected_theme = getDolGlobalString(''FCKEDITOR_SKIN'', ''moono-lisa'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FCKEDITOR_TEST', 'string', NULL, 'admin', 'Stores a test string used to validate and preview the FCKEditor/rich-text editor configuration in the Dolibarr admin panel.', 'Written via admin/fckeditor.php:131 through dolibarr_set_const and read back at admin/fckeditor.php:266 to populate a DolEditor instance for preview, and at admin/fckeditor.php:271 to print the raw value. Managed entirely via the admin UI at admin/fckeditor.php.', 'Changing this value alters the content shown in the editor test/preview field; it has no effect on production document generation.', 'Any string (used as editor preview content)', 0, 0, 'admin/fckeditor.php|admin/fckeditor.php|admin/fckeditor.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$result = dolibarr_set_const($db, ''FCKEDITOR_TEST'', $fckeditor_test, ''chaine'', 0, '''', $conf->entity);", "$editor = new DolEditor(''formtestfield'', getDolGlobalString(''FCKEDITOR_TEST'', ''Test''), '''', 200, $mode, ''In'', true, $uselocalbrowser, 1, 120, ''8'', $readonly);", "print getDolGlobalString(''FCKEDITOR_TEST'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHEINTER_ADDON', 'string', NULL, 'fichinter', 'Selects the numbering module used to generate reference numbers for intervention sheets.', 'Stores the class name suffix of the active numbering module for intervention sheets. Used in fichinter/class/fichinter.class.php:1032-1033 to build the filename and class name, and in fichinter/card.php:53-54 to require the module file. Configured via admin/fichinter.php.', 'Changing this value switches the numbering algorithm applied to new intervention sheet references.', 'Name suffix of the numbering module (e.g. ''mod_fichinter_mercure''). Must match a file in core/modules/fichinter/.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/class/fichinter.class.php:1019  *\tdepending on the module numbering assets within FICHEINTER_ADDON", "fichinter/class/fichinter.class.php:1032|read|$file = \"mod_\" . getDolGlobalString(''FICHEINTER_ADDON'').\".php\";", "fichinter/card.php:53|check|if (getDolGlobalString(''FICHEINTER_ADDON'') && is_readable(DOL_DOCUMENT_ROOT.\"/core/modules/fichinter/mod_\" . getDolGlobalString(''FICHEINTER_ADDON'').\".php\")) {", "admin/fichinter.php:153|write|dolibarr_set_const($db, \"FICHEINTER_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHEINTER_ADDON_PDF', 'string', NULL, 'admin', 'Selects the PDF template module used to generate intervention sheet documents on disk.', 'Stores the name of the active PDF template for intervention sheets. Referenced in core/modules/fichinter/modules_fichinter.php:125 and fichinter/class/fichinter.class.php:841-842 to load the correct template. Configured via admin/fichinter.php.', 'Changing this value switches the PDF layout used for all intervention documents generated afterward.', 'Name of the PDF template module (e.g. ''soleil''). Empty or unset disables PDF generation via template.', 0, 0, 'admin/fichinter.php|admin/fichinter.php|admin/fichinter.php|admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/fichinter/modules_fichinter.php:102  *  Create an intervention document on disk using template defined into FICHEINTER_ADDON_PDF", "fichinter/class/fichinter.class.php:841|read|} elseif (getDolGlobalString(''FICHEINTER_ADDON_PDF'')) {", "fichinter/class/fichinter.class.php:842|read|$modele = getDolGlobalString(''FICHEINTER_ADDON_PDF'');", "admin/fichinter.php:138|write|if (dolibarr_set_const($db, \"FICHEINTER_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'admin', 'Enables a public external download link for validated intervention sheet documents.', 'When set and the intervention is not in draft status, fichinter/card.php:2007 renders the external download link. core/lib/functions.lib.php:10748 checks both this constant and the object type to build the external link. Written via admin/fichinter.php:247.', 'Enabling this constant adds an external download URL to validated intervention sheets; disabling it hides that link.', '1 = external download enabled; 0 or absent = disabled.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:2007|check|if ($object->status != Fichinter::STATUS_DRAFT && getDolGlobalString(''FICHINTER_ALLOW_EXTERNAL_DOWNLOAD'')) {", "core/lib/functions.lib.php:10748|check|if (getDolGlobalString(''FICHINTER_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''fichinter'') {", "admin/fichinter.php:247|write|$res = dolibarr_set_const($db, \"FICHINTER_ALLOW_EXTERNAL_DOWNLOAD\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);", "admin/fichinter.php:672|read|print ''<input type=\"checkbox\" name=\"FICHINTER_ALLOW_EXTERNAL_DOWNLOAD\"''.(getDolGlobalString(\"FICHINTER_ALLOW_EXTERNAL_DOWNLOAD\") ? '' checked'' : '''').''>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_ALLOW_ONLINE_SIGN', 'bool', NULL, 'admin', 'Enables an online signature link for validated intervention sheets.', 'When set and the intervention is not in draft status, fichinter/card.php:2013 renders the online signature button. Written via admin/fichinter.php:234 and displayed as a checkbox at admin/fichinter.php:656.', 'Enabling this constant adds an online signature option to validated intervention sheets; disabling it hides that option.', '1 = online signature enabled; 0 or absent = disabled.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:2013|check|if ($object->status != Fichinter::STATUS_DRAFT && getDolGlobalString(''FICHINTER_ALLOW_ONLINE_SIGN'')) {", "admin/fichinter.php:234|write|$res = dolibarr_set_const($db, \"FICHINTER_ALLOW_ONLINE_SIGN\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);", "admin/fichinter.php:656|read|print ''<input type=\"checkbox\" name=\"FICHINTER_ALLOW_ONLINE_SIGN\"''.(getDolGlobalString(\"FICHINTER_ALLOW_ONLINE_SIGN\") ? '' checked'' : '''').''>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_ARTIC_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the ''Arctic'' automatic numbering module for intervention sheets.', 'Used exclusively within core/modules/fichinter/mod_arctic.php. At line 96 it is displayed in a configuration input field; at line 142 it is loaded as the active mask for number generation.', 'Changing the mask alters the format of newly generated intervention-sheet reference numbers; existing references are unaffected.', 'Any mask string accepted by the Arctic numbering module (e.g. ''{YYYY}{MM}{0000}'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/fichinter/mod_arctic.php:96|read|value=\"''.getDolGlobalString(\"FICHINTER_ARTIC_MASK\").\"''>\"", "core/modules/fichinter/mod_arctic.php:142|read|$mask = getDolGlobalString(\"FICHINTER_ARTIC_MASK\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_CLASSIFY_BILLED', 'string', NULL, 'fichinter', 'Enables a dedicated ''billed'' status classification for intervention sheets, controlling billing-state workflow and trigger handling.', 'When set, fichinter/card.php:1943 activates the billed classification path (noted as deprecated in the comment on that line). When unset, admin/agenda.php:202 discards the FICHINTER_CLASSIFY_BILLED and FICHINTER_CLASSIFY_UNBILLED triggers. fichinter/card.php:1966 gates the billing action button on this constant being absent and the status being between draft and closed.', 'Enabling this constant activates the legacy billed-status workflow for intervention sheets; disabling it suppresses the related triggers and billing action.', 'Truthy value enables billed classification; absent or falsy disables it. The code marks this option as deprecated.', 0, 0, 'admin/agenda.php|admin/agenda.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/agenda.php:201  // Discard special case: If option FICHINTER_CLASSIFY_BILLED is not set, we discard both trigger FICHINTER_CLASSIFY_BILLED and FICHINTER_CLASSIFY_UNBILLED", "fichinter/card.php:1943|check|if (getDolGlobalString(''FICHINTER_CLASSIFY_BILLED'')) {    // Option deprecated. In a future, billed must be managed with a dedicated field to 0 or 1", "fichinter/card.php:1966|check|if (!getDolGlobalString(''FICHINTER_CLASSIFY_BILLED'') && $object->status > Fichinter::STATUS_DRAFT && $object->status < Fichinter::STATUS_CLOSED) {", "modulebuilder/template/core/triggers/interface_99_modMyModule_MyModuleTriggers.class.php:253  //case ''FICHINTER_CLASSIFY_BILLED'':\t\t\t// TODO Replace it with FICHINTER_BILLED"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_DATE_WITHOUT_HOUR', 'string', NULL, 'fichinter', 'Displays intervention line dates without the time component, using date-only format.', 'When set, fichinter/card.php:1627 formats the intervention date using ''day'' instead of ''dayhour'', and fichinter/card.php:1698 and 1783-1791 adjust the date picker widget accordingly. core/modules/fichinter/doc/pdf_soleil.modules.php:315 also switches PDF date formatting. Written via admin/fichinter.php:221.', 'Enabling this constant strips the time portion from all intervention date displays and pickers; disabling it shows full date and time.', '1 = date only (no hour); 0 or absent = date and hour shown.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:1627|read|print ''<td class=\"center\" width=\"150\">''.(!getDolGlobalString(''FICHINTER_DATE_WITHOUT_HOUR'') ? dol_print_date($db->jdate($objp->date_intervention), ''dayhour'') : dol_print_date($db->", "core/modules/fichinter/doc/pdf_soleil.modules.php:315|check|if (!getDolGlobalString(''FICHINTER_DATE_WITHOUT_HOUR'')) {", "admin/fichinter.php:221|write|$res = dolibarr_set_const($db, \"FICHINTER_DATE_WITHOUT_HOUR\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);", "fichinter/card.php:1698|check|if (getDolGlobalString(''FICHINTER_DATE_WITHOUT_HOUR'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_DISABLE_DETAILS', 'bool', NULL, 'fichinter', 'Controls visibility of the intervention line details section, with support for a partial-disable mode.', 'Checked extensively across fichinter/card.php and fichinter/card-rec.php. A value of ''1'' disables line details but still allows closing a draft with zero lines (fichinter/card.php:1869). A value of ''2'' keeps detail columns visible (fichinter/card.php:1507 checks for ''2'' as an exception). fichinter/list.php:162 disables the duration column when this is set.', 'Setting to ''1'' hides intervention line details and the add-line form; setting to ''2'' hides the add-line form but retains detail columns; absent or ''0'' shows full details.', '0 or absent = full details shown; ''1'' = details disabled; ''2'' = add-line form hidden but detail columns visible.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:1507|check|if (!getDolGlobalString(''FICHINTER_DISABLE_DETAILS'') || getDolGlobalString(''FICHINTER_DISABLE_DETAILS'') == ''2'') {", "fichinter/card.php:1869|check|if ($object->status == Fichinter::STATUS_DRAFT && (count($object->lines) > 0 || getDolGlobalString(''FICHINTER_DISABLE_DETAILS'') == ''1'')) {", "fichinter/list.php:162|read|''fd.duree'' => array(''label'' => ''DurationOfLine'', ''type'' => ''duration'', ''checked'' => ''1'', ''enabled'' => !getDolGlobalString(''FICHINTER_DISABLE_DETAILS'') ? ''1'' : ''0''),", "fichinter/card.php:1728|check|if ($object->status == 0 && $user->hasRight(''ficheinter'', ''creer'') && $action != ''editline'' && (!getDolGlobalString(''FICHINTER_DISABLE_DETAILS'') || getDolGlobalString(''FICHINTER_DI"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Specifies the watermark text overlaid on draft intervention (fichinter) PDF documents.', 'Written via admin/fichinter.php:169 and displayed in the settings UI at :579. Applied in core/modules/fichinter/doc/pdf_soleil.modules.php:155-156 when the intervention status is draft.', 'Setting a non-empty string overlays that text as a watermark on draft fichinter PDFs. Leaving empty disables the draft watermark.', 'Empty = no watermark on draft PDFs; any string = text used as watermark on draft intervention PDFs', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fichinter.php:169|write|$res = dolibarr_set_const($db, \"FICHINTER_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "core/modules/fichinter/doc/pdf_soleil.modules.php:155|check|if ($object->status == $object::STATUS_DRAFT && (getDolGlobalString(''FICHINTER_DRAFT_WATERMARK''))) {", "core/modules/fichinter/doc/pdf_soleil.modules.php:156|read|$this->watermark = getDolGlobalString(''FICHINTER_DRAFT_WATERMARK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_EMPTY_LINE_DESC', 'string', NULL, 'fichinter', 'Allows intervention lines to be saved without a description.', 'When absent, fichinter/card.php:594 blocks saving a line if no description is provided via GETPOST and the constant is unset. fichinter/card.php:1757 applies the same guard on line edit. Only two occurrences are present in the payload.', 'Enabling this constant removes the mandatory description requirement for intervention lines; disabling it enforces description entry.', 'Truthy value allows empty descriptions; absent or falsy requires a description.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:594|check|if (!GETPOST(''np_desc'', ''restricthtml'') && !getDolGlobalString(''FICHINTER_EMPTY_LINE_DESC'')) {", "fichinter/card.php:1757|check|if (!getDolGlobalString(''FICHINTER_EMPTY_LINE_DESC'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Intervention (fichinter) documents.', 'Set via the admin UI at admin/fichinter.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Intervention documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/fichinter.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fichinter.php:156|write|$res = dolibarr_set_const($db, \"FICHINTER_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_HIDE_ADD_CONTACT_THIPARTY', 'bool', NULL, 'fichinter', 'When set, hides the ''Add third-party contact'' button on the fichinter (intervention) contact page.', 'Checked at fichinter/contact.php:173 only. Only 1 occurrence and no admin UI.', 'Enabling this constant removes the option to add third-party contacts on intervention records.', 'Boolean/truthy: non-empty hides the button.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''FICHINTER_HIDE_ADD_CONTACT_THIPARTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_HIDE_ADD_CONTACT_USER', 'bool', NULL, 'fichinter', 'When set, hides the ''Add internal user contact'' button on the fichinter (intervention) contact page.', 'Checked at fichinter/contact.php:170 only. Only 1 occurrence and no admin UI.', 'Enabling this constant removes the option to add internal user contacts on intervention records.', 'Boolean/truthy: non-empty hides the button.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''FICHINTER_HIDE_ADD_CONTACT_USER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_HIDE_EMPTY_DURATION', 'bool', NULL, 'fichinter', 'Hides the duration cell on intervention lines that have a zero or empty duration value.', 'Checked at fichinter/card.php:1553 to suppress rendering of the duration cell when duration is empty. Only one occurrence is present in the payload.', 'Enabling this constant hides empty duration cells in the intervention line list; disabling it always shows the duration cell.', 'Truthy value hides empty duration cells; absent or falsy always shows the duration cell.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:1553|check|if (getDolGlobalString(''FICHINTER_HIDE_EMPTY_DURATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_ONLINE_SIGNATURE_SECURITY_TOKEN', 'string', NULL, 'core', 'Provides the secret seed string used to generate the security token for the intervention sheet online-signature public link.', 'Read in core/lib/signature.lib.php:163, core/ajax/onlineSign.php:86, and public/onlinesign/newonlinesign.php:153 as $securekeyseed via getDolGlobalString(''FICHINTER_ONLINE_SIGNATURE_SECURITY_TOKEN''). No admin UI write is present; the value must be set manually.', 'If changed or cleared, any previously distributed public signature links for intervention sheets will become invalid because the derived token will no longer match.', 'Arbitrary string (secret seed). Empty string disables token-based verification.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/signature.lib.php:163|read|$securekeyseed = getDolGlobalString(''FICHINTER_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "core/ajax/onlineSign.php:86|read|$securekeyseed = getDolGlobalString(''FICHINTER_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "public/onlinesign/newonlinesign.php:153|read|$securekeyseed = getDolGlobalString(''FICHINTER_ONLINE_SIGNATURE_SECURITY_TOKEN'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_PRINT_PRODUCTS', 'string', NULL, 'fichinter', 'Allows product-type lines (not just services) to be added and displayed on intervention sheets.', 'When set, fichinter/card.php:414 accepts product-type lines in addition to services. fichinter/card.php:1189 passes an empty filter to printOriginLinesList (showing all types), whereas without it only ''services'' are shown. Written via admin/fichinter.php:182.', 'Enabling this constant allows products to appear on intervention sheets; disabling it restricts lines to services only.', '1 = products included; 0 or absent = services only.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:414|check|if ($product_type == Product::TYPE_SERVICE || getDolGlobalString(''FICHINTER_PRINT_PRODUCTS'')) { //only services except if config includes products", "fichinter/card.php:1189|read|$objectsrc->printOriginLinesList(!getDolGlobalString(''FICHINTER_PRINT_PRODUCTS'') ? ''services'' : ''''); // Show only service, except if option FICHINTER_PRINT_PRODUCTS is on", "admin/fichinter.php:182|write|$res = dolibarr_set_const($db, \"FICHINTER_PRINT_PRODUCTS\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);", "admin/fichinter.php:591|check|if (getDolGlobalString(\"FICHINTER_PRINT_PRODUCTS\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_SIGNATURE_ON_ALL_PAGES', 'string', NULL, 'core', 'Controls whether the online signature image is stamped on every page of the intervention sheet PDF rather than a specific page only.', 'Checked in core/ajax/onlineSign.php:549 and :578 via getDolGlobalString(''FICHINTER_SIGNATURE_ON_ALL_PAGES''). When truthy the signature block is rendered on every page of the fichinter PDF.', 'Enabling this constant causes the signature image to appear on every page of the intervention sheet PDF. Disabling it restricts signature placement to a specific page.', 'Non-empty string = enabled (stamp on all pages). Empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:549|check|if (getDolGlobalString(\"FICHINTER_SIGNATURE_ON_ALL_PAGES\")) {", "core/ajax/onlineSign.php:578|check|if (!getDolGlobalString(\"FICHINTER_SIGNATURE_ON_ALL_PAGES\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_SIGNATURE_WFORIMG', 'string', NULL, 'core', 'Sets the width of the signature image inserted into the intervention sheet PDF during online signing.', 'Checked and read in core/ajax/onlineSign.php:563-564 via getDolGlobalString(''FICHINTER_SIGNATURE_WFORIMG''). When set, the value is passed as $param[''wforimg''] to the PDF rendering layer.', 'If set, the signature image is rendered at the specified width in the fichinter PDF. If unset, the default image width applies.', 'Numeric or string value representing the image width passed to the PDF engine. Empty/unset = default width.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:563|check|if (getDolGlobalString(\"FICHINTER_SIGNATURE_WFORIMG\")) {", "core/ajax/onlineSign.php:564|read|$param[''wforimg''] = getDolGlobalString(\"FICHINTER_SIGNATURE_WFORIMG\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_SIGNATURE_XFORIMGSTART', 'string', NULL, 'core', 'Sets the X coordinate (horizontal offset) for positioning the signature image on the intervention sheet PDF page.', 'Checked and read in core/ajax/onlineSign.php:553-554 via getDolGlobalString(''FICHINTER_SIGNATURE_XFORIMGSTART''). When set, the value is passed as $param[''xforimgstart''] to the PDF rendering layer.', 'If set, overrides the default horizontal position of the signature image on the fichinter PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the X coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:553|check|if (getDolGlobalString(\"FICHINTER_SIGNATURE_XFORIMGSTART\")) {", "core/ajax/onlineSign.php:554|read|$param[''xforimgstart''] = getDolGlobalString(\"FICHINTER_SIGNATURE_XFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_SIGNATURE_YFORIMGSTART', 'string', NULL, 'core', 'Sets the Y coordinate (vertical offset) for positioning the signature image on the intervention sheet PDF page.', 'Checked and read in core/ajax/onlineSign.php:558-559 via getDolGlobalString(''FICHINTER_SIGNATURE_YFORIMGSTART''). When set, the value is passed as $param[''yforimgstart''] to the PDF rendering layer.', 'If set, overrides the default vertical position of the signature image on the fichinter PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the Y coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:558|check|if (getDolGlobalString(\"FICHINTER_SIGNATURE_YFORIMGSTART\")) {", "core/ajax/onlineSign.php:559|read|$param[''yforimgstart''] = getDolGlobalString(\"FICHINTER_SIGNATURE_YFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_USE_PLANNED_AND_DONE_DATES', 'bool', NULL, 'fichinter', 'Enables planned and done date fields on intervention sheet cards.', 'Checked at fichinter/card.php:1431 to conditionally render planned/done date input fields. Only one occurrence is present in the payload.', 'Enabling this constant adds planned and done date fields to intervention sheet cards; disabling it hides them.', 'Truthy value shows planned and done date fields; absent or falsy hides them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:1431|check|if (getDolGlobalString(''FICHINTER_USE_PLANNED_AND_DONE_DATES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_USE_SERVICE_DURATION', 'bool', NULL, 'admin', 'Automatically populates the intervention line duration from the linked service product''s duration value.', 'When set, fichinter/card.php:445 uses the product''s duration_value to pre-fill the intervention line duration. Written via admin/fichinter.php:195 and rendered as a checkbox at admin/fichinter.php:608.', 'Enabling this constant causes service product durations to be copied into intervention lines automatically; disabling it leaves duration blank.', '1 = auto-fill duration from service; 0 or absent = no auto-fill.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:445|check|if ($prod->duration_value && getDolGlobalString(''FICHINTER_USE_SERVICE_DURATION'')) {", "admin/fichinter.php:195|write|$res = dolibarr_set_const($db, \"FICHINTER_USE_SERVICE_DURATION\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);", "admin/fichinter.php:608|read|print ''<input type=\"checkbox\" name=\"FICHINTER_USE_SERVICE_DURATION\"''.(getDolGlobalString(\"FICHINTER_USE_SERVICE_DURATION\") ? '' checked'' : '''').''>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FICHINTER_WITHOUT_DURATION', 'string', NULL, 'fichinter', 'Disables duration tracking on intervention sheet lines, hiding duration fields and setting duration to zero.', 'When set, fichinter/card.php:611 forces duration to 0, fichinter/card.php:1630 hides the duration cell, and fichinter/card.php:1707 and 1800 skip duration-related display blocks. Duration validation checks at fichinter/card.php:598 and 602 are also bypassed. Written via admin/fichinter.php:208.', 'Enabling this constant removes duration fields from intervention lines entirely; disabling it restores duration entry and display.', '1 = duration disabled and set to zero; 0 or absent = duration enabled.', 0, 0, 'admin/fichinter.php|admin/fichinter.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:611|read|$duration = !getDolGlobalString(''FICHINTER_WITHOUT_DURATION'') ? convertTime2Seconds(GETPOSTINT(''durationhour''), GETPOSTINT(''durationmin'')) : 0;", "fichinter/card.php:1630|read|print ''<td class=\"right\" width=\"150\">''.(!getDolGlobalString(''FICHINTER_WITHOUT_DURATION'') ? convertSecondToTime($objp->duree) : '''').''</td>'';", "fichinter/card.php:598|check|if (!getDolGlobalString(''FICHINTER_WITHOUT_DURATION'') && !GETPOSTINT(''durationhour'') && !GETPOSTINT(''durationmin'')) {", "admin/fichinter.php:208|write|$res = dolibarr_set_const($db, \"FICHINTER_WITHOUT_DURATION\", ($val == ''on'' ? 1 : 0), ''bool'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FOURN_PRODUCT_AVAILABILITY', 'string', NULL, 'product', 'Enables the availability delay field on supplier product price records.', 'When non-zero, an availability column is shown in product/price_suppliers.php:972 and the fk_availability field on supplier product records is active. The class comment at fourn/class/fournisseur.product.class.php:178 describes it as an ID for availability delay, visible only when this option is on.', 'Enabling this adds the availability delay field to supplier pricing views; disabling hides it.', '0 = availability field hidden; non-zero = availability field visible and used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.product.class.php:178  * @var int ID availability delay - visible/used if option FOURN_PRODUCT_AVAILABILITY is on (duplicate information compared to delivery delay)", "product/price_suppliers.php:972|read|''pfp.fk_availability'' => array(''label'' => $langs->trans(\"Availability\"), ''enabled'' => (string) getDolGlobalInt(''FOURN_PRODUCT_AVAILABILITY''), ''checked'' => ''0'', ''position'' => 4),", "product/price_suppliers.php:585|check|if (getDolGlobalInt(''FOURN_PRODUCT_AVAILABILITY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FROM_MAIL_DONT_USE_INPUT_FILE_MULTIPLE', 'bool', NULL, 'core', 'Disables the HTML multiple-file input attribute in the mail form file attachment field.', 'Checked once in core/class/html.formmail.class.php:975. When not set (default), the multiple attribute is used. No admin UI write is present.', 'Enabling this restricts the file input to single-file selection; disabling it (default) allows selecting multiple files at once.', 'truthy = disable multiple file input; empty/not set = allow multiple file selection', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:975|check|if (!getDolGlobalString(''FROM_MAIL_DONT_USE_INPUT_FILE_MULTIPLE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_CONNECT_TIMEOUT', 'string', NULL, 'core', 'Overrides the default FTP connection timeout of 40 seconds.', 'Read at core/lib/ftp.lib.php:55; when unset the fallback value 40 is used. The expression is ''$connecttimeout = (!getDolGlobalString(...) ? 40 : $conf->global->FTP_CONNECT_TIMEOUT)''. No comment is present in the payload.', 'Setting a shorter timeout makes FTP connections fail faster on unreachable servers; a longer value accommodates slow networks.', 'Integer (seconds); default is 40 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ftp.lib.php:55|read|$connecttimeout = (!getDolGlobalString(''FTP_CONNECT_TIMEOUT'') ? 40 : $conf->global->FTP_CONNECT_TIMEOUT);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_CONNECT_WITH_SFTP', 'string', NULL, 'core', 'Switches the FTP connection library to use SFTP (SSH File Transfer Protocol) instead of plain FTP.', 'Checked extensively across core/lib/ftp.lib.php (lines 57, 69, 149, 166, 176, 194, 202) and ftp/index.php:469, branching all connection and file-operation logic between FTP and SFTP code paths.', 'Enabling SFTP uses encrypted SSH-based file transfer; disabling it uses plain FTP or FTP-SSL depending on FTP_CONNECT_WITH_SSL.', 'Any truthy value enables SFTP; unset uses FTP (or FTP-SSL if FTP_CONNECT_WITH_SSL is set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ftp.lib.php:57|check|if (getDolGlobalString(''FTP_CONNECT_WITH_SFTP'')) {", "core/lib/ftp.lib.php:149|check|if (!getDolGlobalString(''FTP_CONNECT_WITH_SFTP'')) {", "core/lib/ftp.lib.php:176|check|if (getDolGlobalString(''FTP_CONNECT_WITH_SFTP'')) {", "ftp/index.php:469|check|if (getDolGlobalString(''FTP_CONNECT_WITH_SFTP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_CONNECT_WITH_SSL', 'string', NULL, 'core', 'Enables FTP over SSL (FTPS) for the FTP connection when SFTP is not selected.', 'Checked at core/lib/ftp.lib.php:60 as an elseif branch after the SFTP check, and displayed in the FTP info page at ftp/index.php:401 as a yes/no label ''FTPs (FTP over SSH)''.', 'Enabling this constant causes Dolibarr to use an SSL-encrypted FTP connection; without it (and without SFTP), a plain unencrypted FTP connection is used.', 'Any truthy value enables FTP-SSL; unset uses plain FTP (unless FTP_CONNECT_WITH_SFTP is set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ftp.lib.php:60|read|} elseif (getDolGlobalString(''FTP_CONNECT_WITH_SSL'')) {", "ftp/index.php:401|read|print $langs->trans(\"FTPs (FTP over SSH)\").\": <b>\".yn(getDolGlobalString(''FTP_CONNECT_WITH_SSL'')).\"</b><br>\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_NAME_', 'string', NULL, 'ftp', 'Stores the display name or label for an indexed FTP server connection profile in the FTP client module.', 'Written and deleted in ftp/admin/ftpclient.php:115 and :147. The constant name is built as FTP_NAME_ concatenated with an entry index.', 'Changing this constant updates the human-readable label shown for the corresponding FTP connection entry.', 'String label/name.', 0, 0, 'ftp/admin/ftpclient.php|ftp/admin/ftpclient.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$result5 = dolibarr_set_const($db, \"FTP_NAME_\".$entry, GETPOST($ftp_name, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$result5 = dolibarr_del_const($db, \"FTP_NAME_\".$entry, $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_PASSIVE_', 'string', NULL, 'ftp', 'Controls whether passive mode is used for an indexed FTP server connection profile in the FTP client module.', 'Written and deleted in ftp/admin/ftpclient.php:118 and :150. The constant name is built as FTP_PASSIVE_ concatenated with an entry index.', 'Enabling passive mode is typically required when the FTP client is behind a firewall; disabling it uses active mode.', 'Non-empty/truthy = passive mode; empty/unset = active mode.', 0, 0, 'ftp/admin/ftpclient.php|ftp/admin/ftpclient.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$result6 = dolibarr_set_const($db, \"FTP_PASSIVE_\".$entry, GETPOST($ftp_passive, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$result6 = dolibarr_del_const($db, \"FTP_PASSIVE_\".$entry, $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('FTP_PASSWORD_', 'string', NULL, 'ftp', 'Stores the login password for an indexed FTP server connection profile in the FTP client module.', 'Written and deleted in ftp/admin/ftpclient.php:112 and :144. The constant name is built as FTP_PASSWORD_ concatenated with an entry index.', 'Changing this constant changes the password used to authenticate to the corresponding FTP server.', 'String password.', 0, 0, 'ftp/admin/ftpclient.php|ftp/admin/ftpclient.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$result4 = dolibarr_set_const($db, \"FTP_PASSWORD_\".$entry, GETPOST($ftp_password, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$result4 = dolibarr_del_const($db, \"FTP_PASSWORD_\".$entry, $conf->entity);"]', 'medium', NULL);
