INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GENBARCODE_BARCODETYPE_THIRDPARTY', 'string', NULL, 'core', 'Stores the default barcode type (format) used when generating barcodes for third parties.', 'Written by admin/barcode.php:99 and rendered as a selector at admin/barcode.php:548. Read in core/modules/barcode/mod_barcode_thirdparty_standard.php:216 for automatic numbering and in barcode/printsheet.php:154-155 and core/class/commonobject.class.php:2057 as a fallback type when none is defined on the record.', 'Setting this value changes the barcode format applied to third-party records when no per-record override is present; clearing it disables the fallback.', 'Stores a barcode type ID (integer as string) referencing the selected format; empty = no default.', 0, 0, 'admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/barcode.php:99|write|$res = dolibarr_set_const($db, \"GENBARCODE_BARCODETYPE_THIRDPARTY\", $coder_id, ''chaine'', 0, '''', $conf->entity);", "core/modules/barcode/mod_barcode_thirdparty_standard.php:216|read|$type = getDolGlobalString(''GENBARCODE_BARCODETYPE_THIRDPARTY'');", "barcode/printsheet.php:154|check|if (empty($fk_barcode_type) && getDolGlobalString(''GENBARCODE_BARCODETYPE_THIRDPARTY'')) {", "core/class/commonobject.class.php:2057|read|$idtype = getDolGlobalString(''GENBARCODE_BARCODETYPE_THIRDPARTY'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GENBARCODE_LOCATION', 'string', NULL, 'admin', 'Stores the filesystem path to the external genbarcode binary used for barcode image generation.', 'Configured via admin/barcode.php (UI write at line 95). The path is checked for existence at admin/barcode.php:523; if set and the file does not exist, an ''ErrorFileNotFound'' error is displayed. The value is read in core/lib/barcode.lib.php:66 to set the barcode generator location.', 'If the path is set but points to a non-existent file, barcode generation will fail and an error is shown. If left empty, the system uses a default or compiled-in barcode generator.', 'Absolute filesystem path string to the genbarcode executable; empty string to use the default.', 0, 0, 'admin/barcode.php|admin/barcode.php|admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/barcode.php:523|check|if (getDolGlobalString(''GENBARCODE_LOCATION'') && !@file_exists(getDolGlobalString(''GENBARCODE_LOCATION''))) {", "admin/barcode.php:525|read|print ''<br><span class=\"error\">''.$langs->trans(\"ErrorFileNotFound\", getDolGlobalString(''GENBARCODE_LOCATION'')).''</span>'';", "core/lib/barcode.lib.php:65|check|if (getDolGlobalString(''GENBARCODE_LOCATION'')) {", "core/lib/barcode.lib.php:66|read|$genbarcode_loc = getDolGlobalString(''GENBARCODE_LOCATION'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GEOIPMAXMIND_COUNTRY_DATAFILE', 'string', NULL, 'admin', 'Stores the filesystem path to the MaxMind GeoIP country database file.', 'Written via admin/geoipmaxmind.php:78 and read in admin/geoipmaxmind.php:138, 180, 185, and core/lib/functions.lib.php:5290, 5327 to locate the data file for IP-to-country resolution.', 'Changing this path redirects GeoIP lookups to a different database file. An invalid path will cause GeoIP resolution to fail.', 'An absolute filesystem path string pointing to the MaxMind country data file; empty = no custom path configured', 0, 0, 'admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/geoipmaxmind.php:78|write|$res2 = dolibarr_set_const($db, \"GEOIPMAXMIND_COUNTRY_DATAFILE\", $gimcdf, ''chaine'', 0, '''', $conf->entity);", "admin/geoipmaxmind.php:138|read|$datafile = getDolGlobalString(''GEOIPMAXMIND_COUNTRY_DATAFILE'');", "core/lib/functions.lib.php:5327|read|$datafile = getDolGlobalString(''GEOIPMAXMIND_COUNTRY_DATAFILE'');", "core/lib/functions.lib.php:5290|read|$datafile = getDolGlobalString(''GEOIPMAXMIND_COUNTRY_DATAFILE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GEOIPMAXMIND_COUNTRY_DATAFILE_EMBEDDED', 'string', NULL, 'admin', 'Stores the filename of the embedded MaxMind GeoIP country database file (relative to the Dolibarr data directory).', 'Read in admin/geoipmaxmind.php:141, 264 and core/lib/functions.lib.php:5293. The value is appended to the data directory path ($diroffile) to locate the embedded database. Checked at geoipmaxmind.php:263 before use.', 'Setting this to a valid filename enables the embedded GeoIP data file path. Clearing it disables the embedded file lookup.', 'A relative filename string appended to the data directory to form the full embedded data file path; empty = embedded file not used', 0, 0, 'admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/geoipmaxmind.php:263|check|if (getDolGlobalString(\"GEOIPMAXMIND_COUNTRY_DATAFILE_EMBEDDED\")) {", "admin/geoipmaxmind.php:141|read|$datafile = $diroffile . ''/'' . getDolGlobalString(''GEOIPMAXMIND_COUNTRY_DATAFILE_EMBEDDED'');", "core/lib/functions.lib.php:5293|read|$datafile = $diroffile . ''/'' . getDolGlobalString(''GEOIPMAXMIND_COUNTRY_DATAFILE_EMBEDDED'');", "admin/geoipmaxmind.php:264|read|$geoipfile = getDolGlobalString(\"GEOIPMAXMIND_COUNTRY_DATAFILE_EMBEDDED\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GEOIP_VERSION', 'string', NULL, 'admin', 'Specifies the GeoIP library version or backend to use for IP-to-country lookups.', 'Extensively checked in admin/geoipmaxmind.php across 19 occurrences. The value ''php'' selects the PHP-based GeoIP backend; when unset, the system defaults to version ''2'' (written at admin/geoipmaxmind.php:53 as $conf->global->GEOIP_VERSION = ''2''). The admin UI exposes this setting.', 'Changing this value switches the GeoIP resolution backend. Setting it to ''php'' activates the PHP legacy path; other values (e.g. ''2'') select alternative backends.', '''php'' = PHP-based GeoIP library; ''2'' = GeoIP version 2 backend (default when not set)', 0, 0, 'admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/geoipmaxmind.php:69|check|if (getDolGlobalString(''GEOIP_VERSION'') == ''php'') {", "admin/geoipmaxmind.php:52|check|if (!getDolGlobalString(\"GEOIP_VERSION\")) {", "admin/geoipmaxmind.php:53|write|$conf->global->GEOIP_VERSION = ''2'';", "admin/geoipmaxmind.php:137|check|if (getDolGlobalString(''GEOIP_VERSION'') == ''php'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GOOGLE_ENABLE_GMAPS', 'bool', NULL, 'core', 'Enables a Google Maps link on thirdparty (company/societe) address fields when the Google module is active.', 'Checked in core/lib/functions.lib.php:5371 for element types ''thirdparty'' or ''societe'' with isModEnabled(''google''). No admin UI write detected.', 'Setting this constant adds a Google Maps link to thirdparty address displays. Without it, no map link appears.', 'Non-empty = show Google Maps link on thirdparty; absent/empty = no link. Requires Google module enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5371|check|if (($element == ''thirdparty'' || $element == ''societe'') && isModEnabled(''google'') && getDolGlobalString(''GOOGLE_ENABLE_GMAPS'')) {"]', 'low', NULL);
