INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('GRAPH_USE_FISCAL_YEAR', 'bool', NULL, 'core', 'Switches dashboard graph widgets from the calendar year to the fiscal year as the time axis.', 'Checked with negation (!getDolGlobalString(...)) in six box files: box_graph_orders_permonth.php:73, box_graph_invoices_peryear.php:71, box_graph_invoices_supplier_permonth.php:72, box_graph_orders_supplier_permonth.php:72, box_graph_propales_permonth.php:73, and box_graph_invoices_permonth.php:74.', 'Enabling this causes all per-month and per-year graph widgets to align their date range with the configured fiscal year rather than the January–December calendar year.', 'Empty/not set = calendar year used; any truthy string = fiscal year used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_graph_orders_permonth.php:73|check|if (!getDolGlobalString(''GRAPH_USE_FISCAL_YEAR'')) {", "core/boxes/box_graph_invoices_peryear.php:71|check|if (!getDolGlobalString(''GRAPH_USE_FISCAL_YEAR'')) {", "core/boxes/box_graph_invoices_permonth.php:74|check|if (!getDolGlobalString(''GRAPH_USE_FISCAL_YEAR'')) {", "core/boxes/box_graph_propales_permonth.php:73|check|if (!getDolGlobalString(''GRAPH_USE_FISCAL_YEAR'')) {"]', 'high', NULL);
