INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_ADDON_PDF', 'string', NULL, 'admin', 'Selects the active PDF document template used for holiday request documents.', 'Set and deleted via admin/holiday.php (dolibarr_set_const at line 134, dolibarr_del_const at line 129). The selected value is compared against available PDF module names (lines 128, 398) to highlight the active template in the admin UI.', 'Changing this value switches which PDF template is used to generate holiday request documents.', 'String name of the PDF module; empty = no PDF module selected.', 0, 0, 'admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/holiday.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/holiday.php:134|write|if (dolibarr_set_const($db, \"HOLIDAY_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/holiday.php:128|check|if (getDolGlobalString(''HOLIDAY_ADDON_PDF'') == \"$value\") {", "admin/holiday.php:398|check|if (getDolGlobalString(''HOLIDAY_ADDON_PDF'') == $name) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_ALLOW_ZERO_IN_DIC', 'bool', NULL, 'core', 'Allows zero values in the holiday dictionary; without it, zero values may break the dictionary admin when Multicompany is not used.', 'Checked in core/lib/functions.lib.php:626 with an inline comment warning that this constant breaks the dictionary admin without Multicompany.', 'Enabling this constant permits zero-value entries in the holiday dictionary. The comment warns it can break dictionary administration without the Multicompany module.', 'Non-empty = allow zero; absent/empty = zero values not allowed. Note: this constant break the dictionary admin without Multicompany.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:626|check|if (getDolGlobalString(''HOLIDAY_ALLOW_ZERO_IN_DIC'')) { // this constant break the dictionary admin without Multicompany"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_CAN_APPROVE_ONLY_THE_SUBORDINATES', 'string', NULL, 'holiday', 'Restricts holiday approval so that an approver can only approve requests for their direct subordinates.', 'Checked in three holiday files (holiday/document.php:103, holiday/info.php:76, holiday/card.php:105). Each check also requires permissiontoapprove and that the current user is the designated validator; setting this constant removes that self-approval path. Marked with a TODO comment in the source.', 'When set, an approver who is the designated validator cannot approve their own or non-subordinate requests via the standard path. When unset, any user with approve permission who is the validator may approve.', 'Truthy = restrict approval to subordinates only; falsy or unset = no subordinate restriction.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/document.php:103|check|if ($permissiontoapprove && $object->fk_validator == $user->id && !getDolGlobalString(''HOLIDAY_CAN_APPROVE_ONLY_THE_SUBORDINATES'')) {", "holiday/info.php:76|check|if ($permissiontoapprove && $object->fk_validator == $user->id && !getDolGlobalString(''HOLIDAY_CAN_APPROVE_ONLY_THE_SUBORDINATES'')) {", "holiday/card.php:105|check|if ($permissiontoapprove && $object->fk_validator == $user->id && !getDolGlobalString(''HOLIDAY_CAN_APPROVE_ONLY_THE_SUBORDINATES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_DECREASE_AT_END_OF_MONTH', 'string', NULL, 'holiday', 'Controls the decrease amount applied to holiday balances at the end of each month.', 'Read as an integer in holiday/class/holiday.class.php:1686 and holiday/card.php (lines 644, 877) to compute the monthly balance decrease. Checked in admin/holiday.php:564 to conditionally show related UI. Set via admin/holiday.php.', 'Changing this value alters how many holiday days are deducted from balances at month-end processing.', 'Integer representing the decrease amount; 0 or unset = no end-of-month decrease.', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/holiday.php:564|check|if (getDolGlobalString(''HOLIDAY_DECREASE_AT_END_OF_MONTH'')) {", "holiday/class/holiday.class.php:1686|read|$decrease = getDolGlobalInt(''HOLIDAY_DECREASE_AT_END_OF_MONTH'');", "holiday/card.php:644|read|$decrease = getDolGlobalInt(''HOLIDAY_DECREASE_AT_END_OF_MONTH'');", "holiday/card.php:877|read|$decrease = getDolGlobalInt(''HOLIDAY_DECREASE_AT_END_OF_MONTH'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_DEFAULT_VALIDATOR', 'string', NULL, 'holiday', 'Sets the default approver user ID for holiday requests.', 'Checked and read in holiday/card_group.php:617-618 and holiday/card.php:1243-1244. The comment in the source explicitly states ''// Can force default approver''. No admin UI write is present.', 'Setting this constant forces a specific user as the pre-selected approver when creating holiday requests, for both individual and group cards. Unsetting it leaves the approver selector empty by default.', 'A user ID (integer as string); empty or unset = no default approver forced.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/card_group.php:617|check|if (getDolGlobalString(''HOLIDAY_DEFAULT_VALIDATOR'')) {", "holiday/card_group.php:618|read|$defaultselectuser = getDolGlobalString(''HOLIDAY_DEFAULT_VALIDATOR''); // Can force default approver", "holiday/card.php:1243|check|if (getDolGlobalString(''HOLIDAY_DEFAULT_VALIDATOR'')) {", "holiday/card.php:1244|read|$defaultselectuser = getDolGlobalString(''HOLIDAY_DEFAULT_VALIDATOR''); // Can force default approver"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_DISALLOW_NEGATIVE_BALANCE', 'bool', NULL, 'holiday', 'Blocks the submission or approval of holiday requests that would result in a negative leave balance.', 'Checked in holiday/class/holiday.class.php at lines 782, 906, and 1035, all evaluating ($balance - $daysAsked) < 0 combined with this constant. No admin UI write is present.', 'When set, attempts to request or approve leave that would push the balance below zero are blocked at the class level. Leaving it unset permits negative balances.', 'Truthy = negative balance requests blocked; falsy or unset = negative balances permitted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/class/holiday.class.php:782|check|if (($balance - $daysAsked) < 0 && getDolGlobalString(''HOLIDAY_DISALLOW_NEGATIVE_BALANCE'')) {", "holiday/class/holiday.class.php:906|check|if (($balance - $daysAsked) < 0 && getDolGlobalString(''HOLIDAY_DISALLOW_NEGATIVE_BALANCE'')) {", "holiday/class/holiday.class.php:1035|check|if (($balance - $daysAsked) < 0 && getDolGlobalString(''HOLIDAY_DISALLOW_NEGATIVE_BALANCE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Sets the watermark text printed on draft holiday request PDF documents.', 'Configured via admin/holiday.php: saved with dolibarr_set_const (line 155) and displayed in a text input (line 600). The value is used by the PDF generation code as the draft watermark string.', 'Changing this value changes the watermark text shown on draft holiday documents; clearing it removes the watermark.', 'Arbitrary string (watermark text); empty = no watermark.', 0, 0, 'admin/holiday.php|admin/holiday.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/holiday.php:155|write|$res2 = dolibarr_set_const($db, \"HOLIDAY_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "admin/holiday.php:600|read|print ''<input ... name=\"HOLIDAY_DRAFT_WATERMARK\" value=\"''.dol_escape_htmltag(getDolGlobalString(''HOLIDAY_DRAFT_WATERMARK'')).''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Holiday/leave request documents.', 'Set via the admin UI at admin/holiday.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Holiday documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/holiday.php:152|write|$res1 = dolibarr_set_const($db, \"HOLIDAY_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_HIDE_APPROVER_ABOUT_NEGATIVE_BALANCE', 'bool', NULL, 'holiday', 'Suppresses warnings shown to the approver when a holiday request would result in a negative leave balance.', 'Checked in holiday/card_group.php:763 and holiday/card.php:541. When not set, a negative balance warning is displayed to the approver. No admin UI write is present.', 'Setting this constant hides negative-balance warnings for approvers. Unsetting it causes those warnings to appear during approval review.', 'Truthy = negative balance warning hidden; falsy or unset = warning shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/card_group.php:763|check|if (!getDolGlobalString(''HOLIDAY_HIDE_APPROVER_ABOUT_NEGATIVE_BALANCE'')) {", "holiday/card.php:541|check|if (!getDolGlobalString(''HOLIDAY_HIDE_APPROVER_ABOUT_NEGATIVE_BALANCE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_HIDE_APPROVER_ABOUT_TOO_LOW_DELAY', 'bool', NULL, 'holiday', 'Suppresses warnings shown to the approver when a holiday request has too short a notice period.', 'Checked in holiday/card_group.php:751 and holiday/card.php:529. When this constant is not set, warnings about insufficient lead time are displayed to the approver. No admin UI write is present.', 'Setting this constant hides delay-related warnings for approvers reviewing holiday requests. Unsetting it causes those warnings to be displayed.', 'Truthy = warning hidden; falsy or unset = warning shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/card_group.php:751|check|if (!getDolGlobalString(''HOLIDAY_HIDE_APPROVER_ABOUT_TOO_LOW_DELAY'')) {", "holiday/card.php:529|check|if (!getDolGlobalString(''HOLIDAY_HIDE_APPROVER_ABOUT_TOO_LOW_DELAY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_HIDE_BALANCE', 'bool', NULL, 'holiday', 'Hides the holiday (leave) balance display or replaces it with a translated label string.', 'Checked in hrm/index.php, holiday/list.php, and holiday/card.php. When empty, balance is shown. When set to a non-numeric string, that string is used as a translation key to display a custom label instead of the balance (hrm/index.php:198-199, holiday/card.php:1159-1161).', 'Setting this to a non-numeric string replaces the numeric balance with a translated label. Setting to a numeric value hides the balance display. Clearing it restores the standard balance view.', 'Empty/unset = balance shown; numeric string = balance hidden; non-numeric string = value used as translation key displayed instead of balance', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/index.php:173|check|if (!getDolGlobalString(''HOLIDAY_HIDE_BALANCE'')) {", "hrm/index.php:198|read|} elseif (!is_numeric(getDolGlobalString(''HOLIDAY_HIDE_BALANCE''))) {", "hrm/index.php:199|read|print $langs->trans(getDolGlobalString(''HOLIDAY_HIDE_BALANCE'')).''<br>'';", "holiday/card.php:1159|read|} elseif (!is_numeric(getDolGlobalString(''HOLIDAY_HIDE_BALANCE''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_HIDE_FOR_NON_SALARIES', 'bool', NULL, 'holiday', 'Hides holiday-related pages and features for users who are not classified as salaried employees.', 'Checked across five holiday module files (holiday/document.php:79, holiday/card_group.php:82, holiday/list.php:618, holiday/info.php:52, holiday/card.php:78), all gating display of holiday content on this flag. No admin UI write is present.', 'When set, non-salaried users will not see holiday documents, group cards, lists, info pages, or individual cards. Unsetting it makes those pages visible to all users with the relevant permissions.', 'Truthy = hide holiday UI for non-salaried users; falsy or unset = show to all.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/document.php:79|check|if (getDolGlobalString(''HOLIDAY_HIDE_FOR_NON_SALARIES'')) {", "holiday/card_group.php:82|check|if (getDolGlobalString(''HOLIDAY_HIDE_FOR_NON_SALARIES'')) {", "holiday/list.php:618|check|if (getDolGlobalString(''HOLIDAY_HIDE_FOR_NON_SALARIES'')) {", "holiday/card.php:78|check|if (getDolGlobalString(''HOLIDAY_HIDE_FOR_NON_SALARIES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HOLIDAY_IMMACULATE_MASK', 'string', NULL, 'core', 'Stores the numbering mask pattern used by the immaculate holiday reference numbering module.', 'Used in core/modules/holiday/mod_holiday_immaculate.php in two locations: line 87 populates a UI input field, and line 134 retrieves the mask to generate holiday references.', 'Changing the mask pattern alters how new holiday references are formatted by the immaculate module. Clearing it results in no mask being applied.', 'Any string = mask pattern for holiday reference generation; empty/unset = no mask pattern.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_holiday_immaculate.php:87|value=''\".getDolGlobalString(''HOLIDAY_IMMACULATE_MASK'').\"''", "mod_holiday_immaculate.php:134|$mask = getDolGlobalString(''HOLIDAY_IMMACULATE_MASK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HRMTEST_EVALUATION_ADDON', 'string', NULL, 'hrm', 'Specifies the numbering add-on module class name for HRM evaluations, defaulting to ''mod_evaluation_standard''.', 'Read and checked in hrm/class/evaluation.class.php at lines 956, 957, 960, 963, and 964. When not set, the code forces $conf->global->HRMTEST_EVALUATION_ADDON = ''mod_evaluation_standard''; then loads the corresponding .php file.', 'Changing this to a different add-on class name switches the numbering module used for evaluation references; an invalid value will cause a file-load failure.', 'string class name, e.g. ''mod_evaluation_standard''; default set to ''mod_evaluation_standard'' when empty', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/evaluation.class.php:956|check|if (!getDolGlobalString(''HRMTEST_EVALUATION_ADDON'')) {", "hrm/class/evaluation.class.php:957|write|$conf->global->HRMTEST_EVALUATION_ADDON = ''mod_evaluation_standard'';", "hrm/class/evaluation.class.php:963|read|$file = getDolGlobalString(''HRMTEST_EVALUATION_ADDON'') . \".php\";", "hrm/class/evaluation.class.php:964|read|$classname = getDolGlobalString(''HRMTEST_EVALUATION_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HRM_DEFAULT_SKILL_DESCRIPTION', 'string', NULL, 'hrm', 'Sets the default description text applied to new skill rank detail records when no description is provided.', 'Read once in hrm/class/skill.class.php:269 via getDolGlobalString(''HRM_DEFAULT_SKILL_DESCRIPTION'', $langs->trans(''NoDescription'')). When set, its value overrides the translated ''NoDescription'' fallback.', 'If set, newly created skill detail records use this string as their default description. If unset, the translation of ''NoDescription'' is used instead.', 'Arbitrary string. Default: translated ''NoDescription'' when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/skill.class.php:269|read|$defaultSkillDesc = getDolGlobalString(''HRM_DEFAULT_SKILL_DESCRIPTION'', $langs->trans(\"NoDescription\"));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HRM_EVALUATION_ADVANCED_MASK', 'string', NULL, 'core', 'Stores the numbering mask used by the Advanced HRM evaluation numbering module.', 'Read in mod_evaluation_advanced.php at lines 90 (UI display) and 143 (mask retrieval for reference generation). No dolibarr_set_const write is present in the payload.', 'Changing this mask alters how new HRM evaluation reference numbers are generated by the Advanced module.', 'A mask pattern string; empty = no mask.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_evaluation_advanced.php:90|read|value=''...getDolGlobalString(''HRM_EVALUATION_ADVANCED_MASK'')...", "mod_evaluation_advanced.php:143|read|$mask = getDolGlobalString(''HRM_EVALUATION_ADVANCED_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HRM_JOB_POSITON_ENDING_COMMENT', 'string', NULL, 'hrm', 'Enables the ''abandonment comment'' field on HRM job position records.', 'Read at hrm/class/position.class.php line 105 via getDolGlobalInt to set the ''enabled'' attribute of the ''abort_comment'' varchar(255) field definition. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant activates the abandonment-comment field on job position records, allowing users to record a reason for ending a position.', 'Integer/bool; 0 or absent = field disabled; non-zero = field enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/position.class.php:105|read|''abort_comment'' => array(''type'' => ''varchar(255)'', ''label'' => ''AbandonmentComment'', ''enabled'' => ''getDolGlobalInt(\"HRM_JOB_POSITON_ENDING_COMMENT\")'', ''position'' => 502"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('HRM_MAXRANK', 'string', NULL, 'hrm', 'Sets the maximum number of skill rank levels (skill detail rows) that can be defined per skill.', 'Comment in hrm/class/skill.class.php:261: ''@param int $i Rank from which we want to create skilldets (level $i to HRM_MAXRANK will be created)''. Read in hrm/class/skill.class.php:268, hrm/skill_card.php:109, and hrm/lib/hrm_skillrank.lib.php:131 via getDolGlobalInt(''HRM_MAXRANK'', Skill::DEFAULT_MAX_RANK_PER_SKILL). Written via admin/hrm.php:505 if not already set.', 'Increasing this value allows more rank levels per skill; decreasing it limits the number of rank rows that can be created. The fallback is Skill::DEFAULT_MAX_RANK_PER_SKILL when unset.', 'Integer number of max rank levels. Default: Skill::DEFAULT_MAX_RANK_PER_SKILL when unset.', 0, 0, 'admin/hrm.php|admin/hrm.php|admin/hrm.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/skill.class.php:261  * @param int \t$i \t\tRank from which we want to create skilldets (level $i to HRM_MAXRANK will be created)", "hrm/class/skill.class.php:268|read|$maxNumberSkill = getDolGlobalInt(''HRM_MAXRANK'', self::DEFAULT_MAX_RANK_PER_SKILL);", "hrm/skill_card.php:109|read|$MaxNumberSkill = getDolGlobalInt(''HRM_MAXRANK'', Skill::DEFAULT_MAX_RANK_PER_SKILL);", "admin/hrm.php:505|write|$conf->global->HRM_MAXRANK = Skill::DEFAULT_MAX_RANK_PER_SKILL;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMAP_FORCE_NORSH', 'string', NULL, 'emailcollector', 'Forces the IMAP connection to disable RSH (remote shell) connections.', 'In emailcollector/class/emailcollector.class.php at line 837, when either the per-collector norsh flag or this global constant is set, the norsh IMAP option is applied. No admin UI write path is present.', 'Enabling this disables RSH for all email collector IMAP connections, which is a security hardening measure.', '0 or unset = use per-collector norsh setting; non-zero = force norsh disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:837|check|if (!empty($this->norsh) || getDolGlobalString(''IMAP_FORCE_NORSH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMAP_FORCE_NOSSL', 'string', NULL, 'emailcollector', 'Forces the IMAP connection to use no SSL/TLS, overriding the per-collector SSL setting.', 'In emailcollector/class/emailcollector.class.php at line 828, when the collector''s imap_encryption is empty or ''ssl'' and this constant is set, the no-SSL connection path is taken. No admin UI write path is present.', 'Enabling this forces all email collector IMAP connections to connect without SSL/TLS, which may be required for non-standard server configurations.', '0 or unset = use per-collector encryption setting; non-zero = force no SSL', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:828|check|} elseif (empty($this->imap_encryption) || ($this->imap_encryption == ''ssl'' && getDolGlobalString(''IMAP_FORCE_NOSSL''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMAP_FORCE_TLS', 'string', NULL, 'emailcollector', 'Forces TLS encryption for IMAP connections in the email collector, overriding the per-collector encryption setting.', 'In emailcollector/class/emailcollector.class.php at line 826, when set the connection string is built with TLS flags. No admin UI write path is present.', 'Enabling this forces all email collector IMAP connections to use TLS regardless of their individual encryption setting.', '0 or unset = use per-collector encryption setting; non-zero = force TLS', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:826|check|if (getDolGlobalString(''IMAP_FORCE_TLS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_CSV_FORCE_CHARSET', 'string', NULL, 'core', 'Forces a specific character set for reading CSV import files, overriding automatic detection.', 'Checked in core/modules/import/import_csv.modules.php at line 279. When set, the value is compared (case-insensitively) to determine the charset; ''utf8'' triggers UTF-8 reading mode.', 'Setting this constant to ''utf8'' forces UTF-8 charset handling for CSV imports; other values or unsetting it may result in a different charset branch being taken.', 'Character set name string (e.g. ''utf8''); compared case-insensitively.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/import/import_csv.modules.php:279|check|if (getDolGlobalString(''IMPORT_CSV_FORCE_CHARSET'')) {\t// Forced charset", "core/modules/import/import_csv.modules.php:280|read|if (strtolower($conf->global->IMPORT_CSV_FORCE_CHARSET) == ''utf8'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_CSV_SEPARATOR_TO_USE', 'string', NULL, 'imports', 'Specifies the field separator character used when parsing CSV import files.', 'Read in admin/import.php:102, imports/import.php:710, and core/modules/import/import_csv.modules.php:109. The default when unset is '',''. Configurable via the admin/import.php UI.', 'Changing this separator affects how CSV data is split into fields during import; using the wrong separator causes fields to be misread.', 'Single character string; default is '',''.', 0, 0, 'admin/import.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/import.php:102|read|print ''<td width=\"60\" align=\"center\"><input size=\"3\" class=\"flat\" type=\"text\" name=\"value\" value=\"''.getDolGlobalString(''IMPORT_CSV_SEPARATOR_TO_USE'', '','').''\">''", "imports/import.php:710|read|$separator = (!getDolGlobalString(''IMPORT_CSV_SEPARATOR_TO_USE'') ? '','' : $conf->global->IMPORT_CSV_SEPARATOR_TO_USE);", "core/modules/import/import_csv.modules.php:109|read|$this->separator = (GETPOST(''separator'') ? GETPOST(''separator'') : getDolGlobalString(''IMPORT_CSV_SEPARATOR_TO_USE'', '',''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_MAX_EXECUTION_TIME', 'string', NULL, 'imports', 'Sets the maximum execution time in seconds allowed for import/export operations.', 'Read twice in imports/import.php:1532 and :2076 via getDolGlobalInt. The inline comment reads ''5mn if not defined''. The default when unset is 300. No admin UI is configured.', 'Increasing this value allows longer-running imports to complete; decreasing it causes large imports to be aborted earlier.', 'Integer (seconds); default is 300 (5 minutes).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["imports/import.php:1532|read|$max_execution_time_for_importexport = getDolGlobalInt(''IMPORT_MAX_EXECUTION_TIME'', 300); // 5mn if not defined", "imports/import.php:2076|read|$max_execution_time_for_importexport = getDolGlobalInt(''IMPORT_MAX_EXECUTION_TIME'', 300); // 5mn if not defined"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_MAX_NB_OF_ERRORS', 'string', NULL, 'imports', 'Sets the maximum number of errors tolerated before an import operation is halted.', 'Read in imports/import.php:1875 via getDolGlobalInt and in imports/import.php:2318 via getDolGlobalString, both defaulting to 50. No admin UI is configured.', 'Reducing this limit causes imports to abort sooner when errors are encountered. Increasing it allows more errors before stopping.', 'Integer; default is 50.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["imports/import.php:1875|read|$maxnboferrors = getDolGlobalInt(''IMPORT_MAX_NB_OF_ERRORS'', 50);", "imports/import.php:2318|read|$maxnboferrors = !getDolGlobalString(''IMPORT_MAX_NB_OF_ERRORS'') ? 50 : $conf->global->IMPORT_MAX_NB_OF_ERRORS;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_MAX_NB_OF_WARNINGS', 'string', NULL, 'imports', 'Sets the maximum number of warnings tolerated before an import operation is halted.', 'Read in imports/import.php:1876 via getDolGlobalInt and in imports/import.php:2319 via getDolGlobalString, both defaulting to 50. No admin UI is configured.', 'Reducing this limit causes imports to abort sooner when warnings accumulate. Increasing it allows more warnings before stopping.', 'Integer; default is 50.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["imports/import.php:1876|read|$maxnbofwarnings = getDolGlobalInt(''IMPORT_MAX_NB_OF_WARNINGS'', 50);", "imports/import.php:2319|read|$maxnbofwarnings = !getDolGlobalString(''IMPORT_MAX_NB_OF_WARNINGS'') ? 50 : $conf->global->IMPORT_MAX_NB_OF_WARNINGS;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_TRIGGER_ENRICH_OBJECT', 'string', NULL, 'core', 'Enables enriched trigger context (full object data) during CSV/data imports.', 'Read in core/modules/import/modules_import.class.php at line 779. Per the code comment: ''optional richer trigger context can be enabled with IMPORT_TRIGGER_ENRICH_OBJECT''. Cast to bool via getDolGlobalInt.', 'Setting this to 1 causes the import process to pass a fully populated object to triggers; leaving it unset uses a leaner trigger context.', 'optional richer trigger context can be enabled with IMPORT_TRIGGER_ENRICH_OBJECT', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/import/modules_import.class.php:786  // - optional richer trigger context can be enabled with IMPORT_TRIGGER_ENRICH_OBJECT.", "core/modules/import/modules_import.class.php:779|read|$needenrichobject = (bool) getDolGlobalInt(''IMPORT_TRIGGER_ENRICH_OBJECT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('IMPORT_TRIGGER_MODE_DEFAULT', 'string', NULL, 'imports', 'Sets the default trigger mode used during data imports, controlling how triggers are fired per imported line.', 'Read in imports/import.php:165 and core/modules/import/modules_import.class.php:469 with a default of ''strict_line''. No admin UI is configured.', 'Changing this value alters the default trigger-firing behavior for all import operations that do not explicitly override the mode.', 'String mode name; default is ''strict_line''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["imports/import.php:165|read|$importtriggermode = getDolGlobalString(''IMPORT_TRIGGER_MODE_DEFAULT'', ''strict_line'');", "core/modules/import/modules_import.class.php:469|read|$mode = (string) getDolGlobalString(''IMPORT_TRIGGER_MODE_DEFAULT'', ''strict_line'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTERVENTION_ADDLINE_FREEDUREATION', 'string', NULL, 'fichinter', 'Allows free-form (unconstrained) duration entry on intervention line add and edit forms.', 'Checked at fichinter/card.php:1709 and 1802 to conditionally render a free-duration input instead of the standard hour/minute selector. Note: the constant name contains a typo (''FREEDUREATION''). Only two occurrences are present in the payload.', 'Enabling this constant replaces the structured duration picker with a free-form duration input on intervention lines; disabling it uses the standard picker.', 'Truthy value enables free-form duration entry; absent or falsy uses the standard hour/minute picker.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fichinter/card.php:1709|check|if (getDolGlobalString(''INTERVENTION_ADDLINE_FREEDUREATION'')) {", "fichinter/card.php:1802|check|if (getDolGlobalString(''INTERVENTION_ADDLINE_FREEDUREATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_CATEG_FRAISDEPORT', 'string', NULL, 'intracommreport', 'Identifies the product category ID to treat as shipping costs (frais de port) in intracomm DEB exports.', 'Configurable via the admin UI at intracommreport/admin/intracommreport.php (written at line 86, displayed as a category selector at line 176). Checked in intracommreport/class/intracommreport.class.php at lines 405 and 419; the category is fetched at line 407.', 'Setting this to a valid category ID causes products in that category to be identified and handled as shipping costs in the DEB export; leaving it at 0 skips shipping-cost filtering.', 'integer (product category ID); 0 = no shipping cost category filter', 0, 0, 'intracommreport/admin/intracommreport.php|intracommreport/admin/intracommreport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/admin/intracommreport.php:86|write|dolibarr_set_const($db, \"INTRACOMMREPORT_CATEG_FRAISDEPORT\", GETPOST(\"INTRACOMMREPORT_CATEG_FRAISDEPORT\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/class/intracommreport.class.php:405|check|if ($exporttype == ''deb'' && getDolGlobalInt(''INTRACOMMREPORT_CATEG_FRAISDEPORT'') > 0) {", "intracommreport/class/intracommreport.class.php:407|read|$categ_fraisdeport->fetch(getDolGlobalInt(''INTRACOMMREPORT_CATEG_FRAISDEPORT''));", "intracommreport/class/intracommreport.class.php:419|check|if (getDolGlobalInt(''INTRACOMMREPORT_CATEG_FRAISDEPORT'') > 0 && $categ_fraisdeport->containsObject(''product'', $res->id_prod)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_NIV_OBLIGATION_', 'string', NULL, 'intracommreport', 'Stores the declaration type code for a given flow type (suffix = uppercased flow type) in intracomm reports.', 'Read once in intracommreport/class/intracommreport.class.php:331 as a dynamic key: ''INTRACOMMREPORT_NIV_OBLIGATION_''.strtoupper($type), then output as the declarationTypeCode in the XML. No admin UI write is present in this payload.', 'Setting the appropriately suffixed constant (e.g. INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION) to the correct code ensures compliant declaration type codes in the XML.', 'string (declaration type code); suffix is the uppercased flow type', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/class/intracommreport.class.php:331|read|$declaration->addChild(''declarationTypeCode'', getDolGlobalString(''INTRACOMMREPORT_NIV_OBLIGATION_''.strtoupper($type)));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_NIV_OBLIGATION_EXPEDITION', 'string', NULL, 'intracommreport', 'Stores the obligation level for Intrastat expeditions (exports) used in the Intrastat report configuration.', 'Set at intracommreport/admin/intracommreport.php:85 and displayed in a selectarray at intracommreport/admin/intracommreport.php:169. No comment is present in the payload and no class-level read is present.', 'Changing this value adjusts the declared obligation level for export flows in the Intrastat setup; the exact effect on report generation is not visible in the available payload.', 'String; a valid obligation level code from the admin selectarray choices.', 0, 0, 'intracommreport/admin/intracommreport.php|intracommreport/admin/intracommreport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/admin/intracommreport.php:85|write|dolibarr_set_const($db, \"INTRACOMMREPORT_NIV_OBLIGATION_EXPEDITION\", GETPOST(\"INTRACOMMREPORT_NIV_OBLIGATION_EXPEDITION\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/admin/intracommreport.php:169|read|print $form->selectarray(''INTRACOMMREPORT_NIV_OBLIGATION_EXPEDITION'', $arraychoices, getDolGlobalString(''INTRACOMMREPORT_NIV_OBLIGATION_EXPEDITION''), 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION', 'string', NULL, 'intracommreport', 'Stores the obligation level for Intrastat introductions (imports) used in the Intrastat report configuration.', 'Set at intracommreport/admin/intracommreport.php:84 and displayed in a selectarray at intracommreport/admin/intracommreport.php:161. No comment is present in the payload and the constant is not read in any class file in the payload.', 'Changing this value adjusts the declared obligation level for import flows in the Intrastat setup; the exact effect on report generation is not visible in the available payload.', 'String; a valid obligation level code from the admin selectarray choices.', 0, 0, 'intracommreport/admin/intracommreport.php|intracommreport/admin/intracommreport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/admin/intracommreport.php:84|write|dolibarr_set_const($db, \"INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION\", GETPOST(\"INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/admin/intracommreport.php:161|read|print $form->selectarray(''INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION'', $arraychoices, getDolGlobalString(''INTRACOMMREPORT_NIV_OBLIGATION_INTRODUCTION''), 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_NUM_AGREMENT', 'string', NULL, 'intracommreport', 'Stores the agreement number (envelopeId) used in intracomm report XML declarations.', 'Read once in intracommreport/class/intracommreport.class.php:310 and directly output as the envelopeId child in the XML envelope. No admin UI write is present.', 'Setting this to the correct agreement number ensures the envelopeId is populated correctly in the declaration XML; leaving it empty produces an empty envelopeId.', 'string (agreement number)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/class/intracommreport.class.php:310|read|$envelope->addChild(''envelopeId'', getDolGlobalString(''INTRACOMMREPORT_NUM_AGREMENT''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_ROLE_ACTEUR', 'string', NULL, 'intracommreport', 'Stores the party role code (partyRole) used when generating the Intrastat XML report.', 'Set via admin/intracommreport.php:83 and read into the XML attribute $party->addAttribute(''partyRole'', ...) at intracommreport/class/intracommreport.class.php:316. Selected from an array of choices in the admin UI.', 'Changing this value alters the partyRole attribute in the Intrastat declaration XML, which must match the value required by the national customs authority.', 'String; a valid partyRole code from the choices available in the admin selectarray.', 0, 0, 'intracommreport/admin/intracommreport.php|intracommreport/admin/intracommreport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/admin/intracommreport.php:83|write|dolibarr_set_const($db, \"INTRACOMMREPORT_ROLE_ACTEUR\", GETPOST(\"INTRACOMMREPORT_ROLE_ACTEUR\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/class/intracommreport.class.php:316|read|$party->addAttribute(''partyRole'', $conf->global->INTRACOMMREPORT_ROLE_ACTEUR);", "intracommreport/admin/intracommreport.php:153|read|print $form->selectarray(''INTRACOMMREPORT_ROLE_ACTEUR'', $arraychoices, getDolGlobalString(''INTRACOMMREPORT_ROLE_ACTEUR''), 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INTRACOMMREPORT_TYPE_ACTEUR', 'string', NULL, 'intracommreport', 'Specifies the actor type (e.g. PSI) for intracomm report XML declarations.', 'Configurable via the admin UI at intracommreport/admin/intracommreport.php (written at line 82, displayed as a select at line 145). Used in intracommreport/class/intracommreport.class.php at lines 315 and 323.', 'Setting this to ''PSI'' triggers a specific code path in the declaration; other values use the default path. Incorrect values may produce non-compliant declarations.', 'string (actor type code), e.g. ''PSI''; selected from predefined array choices', 0, 0, 'intracommreport/admin/intracommreport.php|intracommreport/admin/intracommreport.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["intracommreport/admin/intracommreport.php:82|write|dolibarr_set_const($db, \"INTRACOMMREPORT_TYPE_ACTEUR\", GETPOST(\"INTRACOMMREPORT_TYPE_ACTEUR\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/class/intracommreport.class.php:315|read|$party->addAttribute(''partyType'', $conf->global->INTRACOMMREPORT_TYPE_ACTEUR);", "intracommreport/class/intracommreport.class.php:323|check|if (getDolGlobalString(''INTRACOMMREPORT_TYPE_ACTEUR'') === ''PSI'') {", "intracommreport/admin/intracommreport.php:145|read|print $form->selectarray(''INTRACOMMREPORT_TYPE_ACTEUR'', $arraychoices, getDolGlobalString(''INTRACOMMREPORT_TYPE_ACTEUR''), 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVENTORY_INCLUDE_SUB_WAREHOUSE', 'string', NULL, 'product', 'Includes stock from sub-warehouses when loading inventory lines for a parent warehouse.', 'Checked at product/inventory/inventory.php lines 514 and 629, product/inventory/card.php lines 298 and 429, and product/inventory/class/inventory.class.php line 286. COMMENT at core/actions_addupdatedelete.inc.php:546 states: ''// Can happen when the conf INVENTORY_INCLUDE_SUB_WAREHOUSE is set''.', 'Enabling this constant causes inventory loading to include stock from child warehouses of the selected warehouse. Disabling it restricts inventory to the directly selected warehouse.', 'Boolean/integer flag; 0 or absent = only selected warehouse; non-zero = selected warehouse plus sub-warehouses included.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_addupdatedelete.inc.php:546  // Can happen when the conf INVENTORY_INCLUDE_SUB_WAREHOUSE is set", "product/inventory/inventory.php:514|check|if (getDolGlobalInt(''INVENTORY_INCLUDE_SUB_WAREHOUSE'') && !empty($object->fk_warehouse)) {", "product/inventory/card.php:298|check|if (getDolGlobalInt(''INVENTORY_INCLUDE_SUB_WAREHOUSE'') && !empty($object->fk_warehouse)) {", "product/inventory/class/inventory.class.php:286|check|if (!empty($include_sub_warehouse) && getDolGlobalInt(''INVENTORY_INCLUDE_SUB_WAREHOUSE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVENTORY_MANAGE_REAL_PMP', 'string', NULL, 'product', 'Enables management and display of the real weighted-average purchase price (PMP) during inventory operations.', 'Checked at 8 locations in product/inventory/inventory.php (lines 230, 256, 976, 1019, 1145, 1202, 1258, 1337); real PMP fields and calculations are shown or processed only when this constant is set.', 'Enabling this constant activates real-PMP columns and processing in the inventory workflow. Disabling it hides those fields.', 'Boolean/string flag; absent/falsy = real PMP not managed; truthy = real PMP managed and displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/inventory/inventory.php:1145|check|if (getDolGlobalString(''INVENTORY_MANAGE_REAL_PMP'')) {", "product/inventory/inventory.php:230|check|if (!empty($line->pmp_real) && getDolGlobalString(''INVENTORY_MANAGE_REAL_PMP'')) {", "product/inventory/inventory.php:976|check|if (getDolGlobalString(''INVENTORY_MANAGE_REAL_PMP'')) {", "product/inventory/inventory.php:1258|check|if (getDolGlobalString(''INVENTORY_MANAGE_REAL_PMP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICEREC_SET_AUTOFILL_DATE_END', 'string', NULL, 'compta', 'Controls the default auto-fill behavior for the end date on recurring invoice lines.', 'Read at compta/facture/class/facture-rec.class.php:462 and core/tpl/objectline_view.tpl.php:262 as ''$default_end_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_END'')''. No admin UI write path is present.', 'The integer value sets the default auto-fill mode for line end dates on recurring invoices; the exact enumerated values are not documented in the payload.', 'Integer value controlling the default end date auto-fill mode for recurring invoice lines.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture-rec.class.php:462|read|$default_end_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_END'');", "core/tpl/objectline_view.tpl.php:262|read|$default_end_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_END'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICEREC_SET_AUTOFILL_DATE_START', 'string', NULL, 'compta', 'Controls the default auto-fill behavior for the start date on recurring invoice lines.', 'Read at core/tpl/objectline_view.tpl.php:261 and compta/facture/class/facture-rec.class.php:461 as ''$default_start_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_START'')''. No admin UI write path is present.', 'The integer value sets the default auto-fill mode for line start dates on recurring invoices; the exact enumerated values are not documented in the payload.', 'Integer value controlling the default start date auto-fill mode for recurring invoice lines.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_view.tpl.php:261|read|$default_start_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_START'');", "compta/facture/class/facture-rec.class.php:461|read|$default_start_fill = getDolGlobalInt(''INVOICEREC_SET_AUTOFILL_DATE_START'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ADD_DEPOSIT_DATE', 'string', NULL, 'core', 'Adds a deposit date column or field to invoice line displays and PDF outputs.', 'Checked in societe/consumption.php:685, contact/consumption.php:591, core/tpl/objectline_view.tpl.php:167, core/lib/pdf.lib.php:2073, and core/lib/doc.lib.php:90 to conditionally render a deposit date element across consumption views and document generation.', 'Enabling this constant causes deposit date information to appear in invoice line views and generated PDF documents.', 'Truthy value adds deposit date display; absent or falsy omits it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/consumption.php:685|check|if (getDolGlobalString(''INVOICE_ADD_DEPOSIT_DATE'')) {", "core/tpl/objectline_view.tpl.php:167|check|if (getDolGlobalString(''INVOICE_ADD_DEPOSIT_DATE'')) {", "core/lib/pdf.lib.php:2073|check|if (getDolGlobalString(''INVOICE_ADD_DEPOSIT_DATE'')) {", "core/lib/doc.lib.php:90|check|if (getDolGlobalString(''INVOICE_ADD_DEPOSIT_DATE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ADD_EPC_QR_CODE', 'string', NULL, 'core', 'Controls placement of an EPC (European Payments Council) QR code on invoice PDFs to facilitate bank transfers.', 'Written in admin/pdf_other.php at lines 139 and 141 (set/del) and displayed as a select at line 566. Checked in pdf_octopus.modules.php at lines 558, 577, and 1608 and pdf_sponge.modules.php at lines 507 and 1674 to place the QR code in-line or at the bottom when there is a remaining balance and the payment mode is bank transfer (VIR).', 'Setting to ''1'' adds the EPC QR code inline on the invoice (for bank transfer payment mode); setting to ''bottom'' places it at the bottom of the last page when a balance remains. Leaving unset omits the QR code entirely.', '''1'' = add EPC QR code inline (payment mode VIR); ''bottom'' = add at bottom of last page when remaining balance > 0; empty/unset = no QR code.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/doc/pdf_octopus.modules.php:577|check|if (getDolGlobalString(''INVOICE_ADD_EPC_QR_CODE'') == ''1'' && (empty($object->mode_reglement_code) || $object->mode_reglement_code == ''VIR'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:1608|check|if (getDolGlobalString(''INVOICE_ADD_EPC_QR_CODE'') == ''bottom'' && ($object->getRemainToPay() > 0)) {", "core/modules/facture/doc/pdf_sponge.modules.php:507|check|if (getDolGlobalString(''INVOICE_ADD_EPC_QR_CODE'') == ''1'' && (empty($object->mode_reglement_code) || $object->mode_reglement_code == ''VIR'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:1674|check|if ((getDolGlobalString(''INVOICE_ADD_EPC_QR_CODE'') == ''bottom'') && ($object->getRemainToPay() > 0)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ADD_EXTRAFIELD_IN_NOTE', 'string', NULL, 'core', 'Appends extra field data to the notes section of supplier invoice PDF documents.', 'Checked in core/modules/supplier_invoice/doc/pdf_canelle.modules.php:335. When set, extra field content is included in the notes area of the Canelle supplier invoice PDF template. No admin UI write is present.', 'Setting this constant causes extra fields to be appended to the invoice notes on the Canelle PDF. Leaving it unset omits extra fields from the notes.', 'Truthy = extra fields appended to notes; falsy or unset = extra fields omitted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_invoice/doc/pdf_canelle.modules.php:335|check|if (getDolGlobalString(''INVOICE_ADD_EXTRAFIELD_IN_NOTE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ADD_SWISS_QR_CODE', 'string', NULL, 'core', 'Controls the placement of a Swiss QR code on invoice PDFs, configured via the admin UI.', 'Managed via the admin UI at admin/pdf_other.php (written, deleted, and displayed as a select array). Checked in modules_facture.php, pdf_octopus.modules.php, and pdf_sponge.modules.php with the value ''bottom'' to determine QR code placement, and compared against ''bottom'' negation for alternative layout.', 'Setting this to ''bottom'' places the Swiss QR code at the bottom of the invoice PDF. Other values or clearing may disable or reposition the QR code depending on template logic.', '''bottom'' = Swiss QR code added at the bottom of the invoice PDF; other/unset = QR code not placed at bottom.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:145|dolibarr_set_const($db, \"INVOICE_ADD_SWISS_QR_CODE\", GETPOST(\"INVOICE_ADD_SWISS_QR_CODE\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:571|if (getDolGlobalString(''INVOICE_ADD_SWISS_QR_CODE'') == ''bottom'') {", "modules_facture.php:268|if (getDolGlobalString(''INVOICE_ADD_SWISS_QR_CODE'') == ''bottom'') {", "modules_facture.php:159|if (getDolGlobalString(''INVOICE_ADD_SWISS_QR_CODE'') != ''bottom'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ADD_ZATCA_QR_CODE', 'string', NULL, 'admin', 'Enables adding a ZATCA-compliant QR code to invoice PDFs (Saudi Arabia e-invoicing standard).', 'Written in admin/pdf_other.php at lines 133 and 147 (set/del) and displayed as a select at line 555. Checked in pdf_octopus.modules.php at line 552 and pdf_sponge.modules.php at line 482.', 'Enabling this constant causes invoice PDFs to include a ZATCA QR code for Saudi e-invoicing compliance. Disabling it omits the QR code from PDFs.', 'Truthy value to add ZATCA QR code; empty/unset to omit.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:133|write|dolibarr_set_const($db, \"INVOICE_ADD_ZATCA_QR_CODE\", GETPOSTINT(\"INVOICE_ADD_ZATCA_QR_CODE\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/facture/doc/pdf_octopus.modules.php:552|check|if (getDolGlobalString(''INVOICE_ADD_ZATCA_QR_CODE'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:482|check|if (getDolGlobalString(''INVOICE_ADD_ZATCA_QR_CODE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for customer invoice documents.', 'Checked in core/class/commonobject.class.php:6380 and core/lib/functions.lib.php:10738. When set, a public download link is generated for invoice (facture) objects.', 'Enabling this constant exposes invoice documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6380|check|if ($this->element == ''facture'' && getDolGlobalInt(\"INVOICE_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10738|check|if (getDolGlobalString(''INVOICE_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''facture'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ALLOW_FREE_REF', 'bool', NULL, 'compta', 'When enabled, allows free-form reference entry on draft invoices for companies outside the EEC.', 'Checked in compta/facture/card.php:5293 for draft invoices of non-EEC companies. Only one occurrence is present in the payload.', 'Enabling this constant allows users to manually enter an arbitrary reference number on draft invoices for non-EEC entities.', '0 or unset = free reference entry not allowed; truthy = free reference entry allowed for non-EEC draft invoices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:5293|check|if ($object->status == $object::STATUS_DRAFT && !$mysoc->isInEEC() && getDolGlobalString(''INVOICE_ALLOW_FREE_REF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ALLOW_POS_SOURCE_EDIT', 'bool', NULL, 'compta', 'When enabled, displays the POS source field on invoice forms even when TakePos is not enabled and no module source is set.', 'Checked in compta/facture/card.php:5419 as an override condition to show the POS source field. Only one occurrence is present in the payload.', 'Enabling this constant forces the POS source field to be visible on invoices regardless of whether TakePos is active.', '0 or unset = POS source field shown only when TakePos is enabled or module_source is set; truthy = POS source field always shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:5419|check|if (isModEnabled(''takepos'') || $object->module_source || getDolGlobalString(''INVOICE_ALLOW_POS_SOURCE_EDIT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED', 'bool', NULL, 'compta', 'When enabled, allows a credit note to be reused as credit even when it has been only partially refunded.', 'Checked in compta/facture/card.php at lines 1029 and 6759 in conditions related to credit note reuse and display of the credit reuse action.', 'Enabling this constant permits partially-refunded credit notes to be applied as credits, which would not otherwise be allowed.', '0 or unset = credit reuse blocked if partially refunded; truthy = credit reuse allowed even if partially refunded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:1029|check|if (getDolGlobalString(''INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED'') && $object->type == Facture::TYPE_CREDIT_NOTE) {", "compta/facture/card.php:6759|read|&& (getDolGlobalString(''INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED'') || $sumofpayment == 0) && $object->total_ht < 0"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_AUTO_NEXT_MONTH_ON_LINES', 'string', NULL, 'compta', 'Automatically advances line service dates to the next month when cloning an invoice.', 'Checked in a single location at compta/facture/class/facture.class.php:1351, where it triggers date advancement for lines that have both date_start and date_end set. No admin UI is present.', 'When enabled, cloned invoice lines with service date ranges have those dates shifted forward by one month automatically.', '0 or unset = dates are copied as-is on clone; truthy value = line dates are advanced to the next month.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:1351|check|if (getDolGlobalString(''INVOICE_AUTO_NEXT_MONTH_ON_LINES'') && !empty($line->date_start) && !empty($line->date_end)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_BE_EDITED_EVEN_IF_PAYMENT_DONE', 'string', NULL, 'compta', 'When enabled, allows editing of an invoice that has already been fully paid.', 'Checked in compta/facture/card.php at lines 862 and 6591 as an override condition that permits editing when payment has been recorded.', 'Enabling this constant allows modification of fully paid invoices, which can lead to discrepancies between recorded payments and invoice amounts.', '0 or unset = editing blocked when payment is done; truthy = editing allowed even after payment.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:862|check|if (getDolGlobalString(''INVOICE_CAN_BE_EDITED_EVEN_IF_PAYMENT_DONE'') || ($resteapayer == $object->total_ttc && empty($object->paye))) {", "compta/facture/card.php:6591|check|if (getDolGlobalString(''INVOICE_CAN_BE_EDITED_EVEN_IF_PAYMENT_DONE'') || ($resteapayer == price2num($object->total_ttc, ''MT'', 1) && empty($object->paye))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_DELETE_PAYMENT_EVEN_IF_INVOICE_CLOSED', 'string', NULL, 'compta', 'Allows deletion of a payment even when at least one linked invoice is already marked as paid.', 'By default, compta/paiement/card.php:602 blocks deletion if any linked invoice has paye==1. Setting this constant overrides that guard. The comment explicitly states it is for maintenance purposes only and should never be used in production.', 'Enabling this constant removes a safety guard and permits deletion of payments linked to closed invoices, which can break invoice/payment reconciliation. It must not be used in production.', 'Truthy string (deletion allowed on closed invoices) or empty/unset (deletion blocked). // If at least one invoice is paid, disable delete. INVOICE_CAN_DELETE_PAYMENT_EVEN_IF_INVOICE_CLOSED Can be use for maintenance purpose. Never use this in production', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["compta/paiement/card.php:601  // If at least one invoice is paid, disable delete. INVOICE_CAN_DELETE_PAYMENT_EVEN_IF_INVOICE_CLOSED Can be use for maintenance purpose. Never use this in production", "compta/paiement/card.php:602|check|if ($objp->paye == 1 && !getDolGlobalString(''INVOICE_CAN_DELETE_PAYMENT_EVEN_IF_INVOICE_CLOSED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_NEVER_BE_CANCELED', 'string', NULL, 'compta', 'When enabled, prevents invoices from being canceled regardless of user permissions.', 'Checked in compta/facture/card.php:6798 and fourn/facture/card.php:4340 to suppress the cancel action on both customer and supplier invoices.', 'Enabling this constant removes the cancel action from all invoices, enforcing a no-cancellation policy across the invoicing module.', '0 or unset = cancellation allowed under normal conditions; truthy = cancellation always blocked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:6798|check|if (!getDolGlobalString(''INVOICE_CAN_NEVER_BE_CANCELED'')) {", "fourn/facture/card.php:4340|check|if (!getDolGlobalString(''INVOICE_CAN_NEVER_BE_CANCELED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_NEVER_BE_EDITED', 'string', NULL, 'compta', 'When enabled, prevents any editing of validated invoices regardless of payment status.', 'Checked in compta/facture/card.php at lines 809, 4961, and 6586. When set, the confirm_modif action is blocked (line 809) and the edit UI is suppressed for validated invoices (line 4961 and 6586).', 'Enabling this constant makes validated invoices permanently read-only, blocking all editing actions even for users with unvalidate permissions.', '0 or unset = editing allowed under normal conditions; truthy = editing always blocked for validated invoices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4961|check|if (getDolGlobalString(''INVOICE_CAN_NEVER_BE_EDITED'')) {", "compta/facture/card.php:809|read|} elseif ($action == ''confirm_modif'' && $usercanunvalidate && !getDolGlobalString(''INVOICE_CAN_NEVER_BE_EDITED'')) {", "compta/facture/card.php:6586|check|if ($object->status == Facture::STATUS_VALIDATED && !getDolGlobalString(''INVOICE_CAN_NEVER_BE_EDITED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_NEVER_BE_REMOVED', 'string', NULL, 'core', 'Prevents deletion of any invoice when set to 1, overriding all other deletion permission checks.', 'Checked at core/class/commoninvoice.class.php:725 and :898 to block invoice deletion. The comment at :873 confirms: ''If hidden option INVOICE_CAN_NEVER_BE_REMOVED is 1 -> no (0)''. No admin UI; hidden setting.', 'Setting to 1 makes all invoices permanently non-deletable regardless of status or user permissions. Setting to 0 or leaving unset allows normal deletion rules to apply.', '0 or empty = normal deletion rules apply; 1 = no invoice can ever be removed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/commoninvoice.class.php:873  *  If hidden option INVOICE_CAN_NEVER_BE_REMOVED is 1 -> no (0)", "core/class/commoninvoice.class.php:725|check|if (getDolGlobalInt(''INVOICE_CAN_NEVER_BE_REMOVED'')) {", "core/class/commoninvoice.class.php:898|check|if (getDolGlobalInt(''INVOICE_CAN_NEVER_BE_REMOVED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID', 'string', NULL, 'compta', 'When enabled, allows marking an invoice as paid even when no payment has been recorded (full remaining balance), bypassing the partial-payment restriction.', 'Checked in compta/facture/card.php at lines 5155, 5158, 6777, and 6793 in the paid-status transition logic.', 'Enabling this constant allows the ''paid'' action to be triggered on invoices with an outstanding balance equal to the full invoice amount, without requiring a recorded payment.', '0 or unset = invoice can only be marked paid when balance is zero or partially reduced; truthy = paid action allowed even when full balance remains.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:5155|check|if ($action == ''paid'' && ($resteapayer <= 0 || (getDolGlobalString(''INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID'') && $resteapayer == $object->total_ttc))) {", "compta/facture/card.php:5158|check|if ($action == ''paid'' && $resteapayer > 0 && (!getDolGlobalString(''INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID'') || $resteapayer != $object->total_ttc)) {", "compta/facture/card.php:6793|check|if ($object->status == Facture::STATUS_VALIDATED && $object->paye == 0 && $resteapayer > 0 && (!getDolGlobalString(''INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID'') || $resteapayer !="]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CATEGORY_OF_OPERATION', 'string', NULL, 'core', 'Specifies the category of operation for invoice PDF generation, used notably for French VAT self-billing rules.', 'Written in admin/pdf_other.php at line 151 and displayed as a select at line 593. Also written programmatically in master.inc.php at line 330 and api/class/api_access.class.php at line 184 where it is set to 1. Checked in pdf_octopus.modules.php at lines 1449 and 1877 and pdf_sponge.modules.php at lines 1515 and 2135 comparing against values 1 and 2.', 'Setting to 1 or 2 activates specific invoice category logic (e.g. different VAT or self-billing sections) in PDF templates. The value is also forced to 1 automatically in API access and master.inc.php contexts.', 'Integer: 1 or 2 trigger specific category-of-operation rendering branches in PDF templates; 0 or unset applies no special category logic.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["master.inc.php:330|write|$conf->global->INVOICE_CATEGORY_OF_OPERATION = 1;", "api/class/api_access.class.php:184|write|$conf->global->INVOICE_CATEGORY_OF_OPERATION = 1;", "core/modules/facture/doc/pdf_octopus.modules.php:1449|check|if (getDolGlobalInt(''INVOICE_CATEGORY_OF_OPERATION'') == 2 && $this->categoryOfOperation >= 0) {", "core/modules/facture/doc/pdf_octopus.modules.php:1877|check|if (getDolGlobalInt(''INVOICE_CATEGORY_OF_OPERATION'') == 1 && $this->categoryOfOperation >= 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CHECK_POSTERIOR_DATE', 'string', NULL, 'compta', 'Requires that a new invoice date is not earlier than the most recent existing invoice date for the same entity.', 'Set via admin/invoice.php:248 and checked in core/actions_massactions.inc.php:1050, compta/facture/class/facture.class.php:3575, and compta/facture/card.php:402. Admin UI available at admin/invoice.php.', 'Enabling this enforces chronological ordering of invoice dates, blocking validation if the new date is earlier than the last recorded invoice date.', '0 or unset = no posterior date check; truthy value = invoice date must not be before the most recent invoice date.', 0, 0, 'admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/invoice.php:248|write|$res = dolibarr_set_const($db, ''INVOICE_CHECK_POSTERIOR_DATE'', $check_posterior_date, ''chaine'', 0, '''', $conf->entity);", "compta/facture/class/facture.class.php:3575|check|if (getDolGlobalString(''INVOICE_CHECK_POSTERIOR_DATE'')) {", "compta/facture/card.php:402|check|if (getDolGlobalString(''INVOICE_CHECK_POSTERIOR_DATE'')) {", "core/actions_massactions.inc.php:1050|check|if (!empty($toselect) && getDolGlobalString(''INVOICE_CHECK_POSTERIOR_DATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_CREDIT_NOTE_STANDALONE', 'string', NULL, 'compta', 'When enabled, allows credit notes to be created without being linked to a source invoice (standalone credit notes).', 'Checked across compta/facture/card.php and fourn/facture/card.php (multiple lines) to conditionally allow or block the creation of credit notes without a source invoice. Also auto-set to 1 for Greek companies in master.inc.php:348.', 'When disabled (default for non-GR), credit notes must be linked to a source invoice. Enabling it allows standalone credit notes on both customer and supplier invoice screens.', '0 or unset = credit notes must reference a source invoice; 1 = standalone credit notes are allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["master.inc.php:348|write|$conf->global->INVOICE_CREDIT_NOTE_STANDALONE = 1;", "master.inc.php:346|read|if ($mysoc->country_code == ''GR'' && !isset($conf->global->INVOICE_CREDIT_NOTE_STANDALONE)) {", "compta/facture/card.php:1280|check|if (!($sourceinvoice > 0) && !getDolGlobalString(''INVOICE_CREDIT_NOTE_STANDALONE'')) {", "fourn/facture/card.php:881|check|if (!($sourceinvoice > 0) && !getDolGlobalString(''INVOICE_CREDIT_NOTE_STANDALONE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DEFAULT_UNPAYED_SORT_ORDER', 'string', NULL, 'compta', 'Sets the default sort order on the invoice list when filtering for unpaid invoices.', 'Read in compta/facture/list.php at lines 219-220. When no explicit sort order is provided and the status filter is set to ''1'' (validated/unpaid), the value of this constant is applied as the sort order.', 'Setting this constant changes how unpaid invoices are ordered by default on the list page, without requiring the user to click a column header.', 'SQL sort direction string such as ''ASC'' or ''DESC'', applied to the current sort field', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!$sortorder && getDolGlobalString(''INVOICE_DEFAULT_UNPAYED_SORT_ORDER'') && $search_status == ''1'') {", "$sortorder = getDolGlobalString(''INVOICE_DEFAULT_UNPAYED_SORT_ORDER'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DEPOSIT_INVOICE_ONLY_SAME_LINES', 'string', NULL, 'compta', 'When enabled, restricts deposit invoices to include only the same lines as the source order rather than all lines.', 'Checked in compta/facture/card.php at lines 4080 and 4139 during deposit invoice creation logic.', 'Enabling this constant changes which lines are included when generating a deposit invoice from an order.', '0 or unset = deposit invoice line selection is unrestricted; truthy = only lines matching the source are included.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4080|check|if (!getDolGlobalInt(''INVOICE_DEPOSIT_INVOICE_ONLY_SAME_LINES'')) {", "compta/facture/card.php:4139|check|if (!getDolGlobalInt(''INVOICE_DEPOSIT_INVOICE_ONLY_SAME_LINES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DEPOSIT_VARIABLE_MODE_DETAIL_LINES_IN_DESCRIPTION', 'string', NULL, 'compta', 'Includes detailed line descriptions in the description field when generating variable-mode deposit invoice lines.', 'Checked in a single location at compta/facture/class/facture.class.php:1871, combined with a check for non-empty descriptions keyed by VAT rate. No admin UI is present.', 'When set, the deposit invoice line description will include the per-VAT-rate detail text accumulated during line processing.', '0 or unset = no detail lines in description; truthy value = per-VAT-rate descriptions included in deposit line description.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:1871|check|if (getDolGlobalString(''INVOICE_DEPOSIT_VARIABLE_MODE_DETAIL_LINES_IN_DESCRIPTION'') && !empty($descriptions[$tva])) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DIABLE_MASS_DELETION_ON_DRAFT_INVOICES', 'string', NULL, 'compta', 'Disables the mass-deletion action on draft invoices in the invoice list.', 'Checked in compta/facture/list.php at line 1491. When set, the mass-deletion button or action for draft invoices is suppressed.', 'Setting this constant prevents bulk deletion of draft invoices from the list view, reducing the risk of accidental data loss.', '0 or unset = mass deletion of draft invoices allowed; 1 = mass deletion disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''INVOICE_DIABLE_MASS_DELETION_ON_DRAFT_INVOICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISABLE_AUTOMATIC_RECURRING_INVOICE', 'bool', NULL, 'compta', 'When enabled, disables the automatic creation of recurring invoices from templates.', 'Checked in compta/facture/card.php:3879 and fourn/facture/card.php:2352 to suppress the automatic recurring invoice generation logic for both customer and supplier invoices.', 'Enabling this constant prevents Dolibarr from automatically generating invoices from recurring invoice templates.', '0 or unset = automatic recurring invoice generation active; truthy = automatic generation disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:3879|check|if (!getDolGlobalString(''INVOICE_DISABLE_AUTOMATIC_RECURRING_INVOICE'')) {", "fourn/facture/card.php:2352|check|if (!getDolGlobalString(''INVOICE_DISABLE_AUTOMATIC_RECURRING_INVOICE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISABLE_CREDIT_NOTE', 'bool', NULL, 'compta', 'When enabled, disables the credit note invoice type, preventing its creation for both customer and supplier invoices.', 'Checked in compta/facture/card.php:4280 and fourn/facture/card.php:2659 to suppress the credit note creation option.', 'Enabling this constant removes the ability to create credit notes for both customer and supplier invoices.', '0 or unset = credit note type available; truthy = credit note type disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4280|check|if (!getDolGlobalString(''INVOICE_DISABLE_CREDIT_NOTE'')) {", "fourn/facture/card.php:2659|check|if (!getDolGlobalString(''INVOICE_DISABLE_CREDIT_NOTE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISABLE_DEPOSIT', 'bool', NULL, 'core', 'When enabled, disables the deposit invoice type, preventing its creation on both customer and supplier invoice screens.', 'Checked in compta/facture/card.php:4088, fourn/facture/card.php:2510, and core/modules/facture/mod_facture_mercure.php:120. Auto-set to 1 for Greek companies in master.inc.php:344 and via API in api/class/api_access.class.php:198.', 'Enabling this constant removes the deposit invoice option from invoice creation and numbering module logic for both customer and supplier invoices.', '0 or unset = deposit invoice type available; 1 = deposit invoice type disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["master.inc.php:344|write|$conf->global->INVOICE_DISABLE_DEPOSIT = 1;", "master.inc.php:342|read|if ($mysoc->country_code == ''GR'' && !isset($conf->global->INVOICE_DISABLE_DEPOSIT)) {", "compta/facture/card.php:4088|check|if (!getDolGlobalString(''INVOICE_DISABLE_DEPOSIT'')) {", "core/modules/facture/mod_facture_mercure.php:120|check|if (!getDolGlobalString(''INVOICE_DISABLE_DEPOSIT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISABLE_REPLACEMENT', 'bool', NULL, 'master.inc.php', 'When enabled, disables the replacement invoice type, preventing its creation for both customer and supplier invoices.', 'Checked in admin/invoice.php:433, compta/facture/card.php:4207, core/modules/facture/mod_facture_mercure.php:113, and core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:116. Also auto-set to 1 for Greek companies and via API. Visible and configurable via admin/invoice.php (ADMIN_UI present).', 'Enabling this constant removes the replacement invoice option from the invoice creation UI and from invoice numbering module logic.', '0 or unset = replacement invoice type available; 1 = replacement invoice type disabled.', 0, 0, 'admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["master.inc.php:336|write|$conf->global->INVOICE_DISABLE_REPLACEMENT = 1;", "admin/invoice.php:433|check|if (!getDolGlobalString(''INVOICE_DISABLE_REPLACEMENT'')) {", "core/modules/facture/mod_facture_mercure.php:113|check|if (!getDolGlobalString(''INVOICE_DISABLE_REPLACEMENT'')) {", "api/class/api_access.class.php:190|write|$conf->global->INVOICE_DISABLE_REPLACEMENT = 1;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISABLE_SOURCE', 'bool', NULL, 'compta', 'When enabled, hides the source document selector on invoice forms, preventing users from linking an invoice to a source object.', 'Checked in compta/facture/card.php at lines 4556 and 5512 to conditionally show or hide the source document field.', 'Enabling this constant removes the source document field from the invoice UI, so invoices cannot be linked to source orders or proposals.', '0 or unset = source document field shown; truthy = source document field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4556|check|if (!getDolGlobalInt(''INVOICE_DISABLE_SOURCE'')) {", "compta/facture/card.php:5512|check|if (!getDolGlobalInt(''INVOICE_DISABLE_SOURCE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DISALLOW_REOPEN', 'bool', NULL, 'compta', 'When enabled, prevents validated invoices from being reopened (set back to draft status).', 'Checked in compta/facture/card.php:165 to block the reopen action on invoices. No admin UI write is present in the payload.', 'Enabling this constant removes the ability to reopen validated invoices, enforcing a one-way validation workflow.', '0 or unset = reopening allowed; truthy = reopening disallowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:165|check|if (getDolGlobalString(''INVOICE_DISALLOW_REOPEN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_DO_NOT_PROPAGATE_REF_CUSTOMER_OF_SRC_TO_INVOICE', 'string', NULL, 'compta', 'When enabled, prevents the customer reference from the source document from being propagated to a new invoice created from it.', 'Checked in compta/facture/card.php:3761 during invoice creation from a source object. Only one occurrence is present in the payload.', 'Enabling this constant means invoices created from orders or other source documents will not inherit the customer reference of the source.', '0 or unset = customer reference propagated from source; truthy = customer reference not propagated.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:3761|check|if (getDolGlobalString(\"INVOICE_DO_NOT_PROPAGATE_REF_CUSTOMER_OF_SRC_TO_INVOICE\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_EMAIL_SENDER', 'string', NULL, 'core', 'Overrides the From email address when sending customer invoices or salary slips by email.', 'Checked in core/tpl/card_presend.tpl.php:185 for the ''facture'' element and line 180 for ''salary''. When set, frommail is replaced with this value (line 186).', 'Setting this causes the From address on customer invoice and salary emails to be replaced with the configured address, regardless of the user or company default.', 'Empty/not set = default sender used; email address string = used as From address for invoice and salary emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:185|check|if ($object->element === ''facture'' && getDolGlobalString(''INVOICE_EMAIL_SENDER'')) {", "core/tpl/card_presend.tpl.php:180|check|if ($object->element == ''salary'' && getDolGlobalString(''INVOICE_EMAIL_SENDER'')) {", "core/tpl/card_presend.tpl.php:186|read|$formmail->frommail = getDolGlobalString(''INVOICE_EMAIL_SENDER'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_EMAIL_SENDER_NAME', 'string', NULL, 'core', 'Overrides the From display name when sending customer invoice or salary slip emails.', 'Read in core/tpl/card_presend.tpl.php:182 and :187 to set fromname for both salary and invoice send scenarios.', 'Setting this replaces the sender display name in the From field of invoice and salary emails with the configured string.', 'Empty string = default sender name used; any string = used as From display name for invoice and salary emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:182|read|$formmail->fromname = getDolGlobalString(''INVOICE_EMAIL_SENDER_NAME'', '''');", "core/tpl/card_presend.tpl.php:187|read|$formmail->fromname = getDolGlobalString(''INVOICE_EMAIL_SENDER_NAME'', '''');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_ENABLE_NEGATIVE_QTY', 'bool', NULL, 'compta', 'When enabled, allows negative quantities to be entered on invoice lines.', 'Checked in compta/facture/card.php at lines 2567 and 3202; without this constant, a qty < 0 triggers a blocking error.', 'Disabling or leaving unset blocks negative quantities on invoice lines. Enabling it permits negative quantities, which can be used for returns or corrections.', '0 or unset = negative quantities blocked; truthy = negative quantities allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:2567|check|if ($qty < 0 && !getDolGlobalString(''INVOICE_ENABLE_NEGATIVE_QTY'')) {", "compta/facture/card.php:3202|check|if ($qty < 0 && !getDolGlobalString(''INVOICE_ENABLE_NEGATIVE_QTY'')) {"]', 'medium', NULL);
