INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_HIDE_LINKED_OBJECT', 'bool', NULL, 'admin', 'Hides the linked object section on invoice PDFs when enabled.', 'Written in admin/pdf_other.php at line 166 and displayed as a select at line 638. Checked (negated) in pdf_octopus.modules.php at line 2196 and pdf_sponge.modules.php at line 2431; the linked object block is shown only when this constant is falsy.', 'Enabling this constant removes the linked object references from invoice PDFs. Disabling it (or leaving unset) shows the linked object section.', 'Truthy string to hide linked objects; empty/unset to show linked objects.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:166|write|dolibarr_set_const($db, \"INVOICE_HIDE_LINKED_OBJECT\", GETPOSTINT(\"INVOICE_HIDE_LINKED_OBJECT\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/facture/doc/pdf_octopus.modules.php:2196|check|if (!getDolGlobalString(''INVOICE_HIDE_LINKED_OBJECT'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:2431|check|if (!getDolGlobalString(''INVOICE_HIDE_LINKED_OBJECT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_HIDE_UNSELECTABLES', 'bool', NULL, 'core', 'When enabled, hides invoices that cannot be selected from invoice selector lists.', 'Checked at core/class/html.form.class.php:11767. When truthy, unselectable invoice entries are hidden from the selector; when falsy, they are shown (typically greyed out or disabled).', 'Enabling keeps invoice selectors clean by removing non-selectable entries. Disabling shows all invoices including those that cannot be chosen.', 'Truthy = hide unselectable invoices from selector; empty/unset = show all invoices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:11767|check|if (getDolGlobalString(''INVOICE_HIDE_UNSELECTABLES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_INCUDE_DETAILS_OF_LOTS_SERIALS', 'string', NULL, 'compta', 'When enabled, includes batch/lot/serial number details on invoice lines when the product batch module is active.', 'Checked in compta/facture/card.php:2825 alongside the productbatch module check. Only one occurrence is present in the payload.', 'Enabling this constant causes invoice line details to include lot and serial number information for batch-tracked products.', '0 or unset = lot/serial details not shown on invoice lines; truthy = lot/serial details included.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:2825|check|if (isModEnabled(''productbatch'') && !empty($lines[$i]->detail_batch) && is_array($lines[$i]->detail_batch) && getDolGlobalString(''INVOICE_INCUDE_DETAILS_OF_LOTS_SERIALS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN', 'string', NULL, 'compta', 'Preserves discount lines with negative sub-prices when creating invoices from orders or shipments instead of converting them.', 'Checked in compta/facture/card.php:1936, expedition/list.php:367, commande/list.php:549, and compta/facture/class/facture.class.php:4705. When not set, lines with a negative subprice are excluded; when set, they are kept as-is from the origin document.', 'Without this setting, negative-price discount lines from source documents are stripped during invoice creation. Enabling it retains those lines verbatim.', 'Empty/0 = negative subprice lines removed from copied invoices; truthy = negative subprice lines kept as in origin', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:1936|check|if ($lines[$i]->subprice < 0 && !getDolGlobalString(''INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN'')) {", "expedition/list.php:367|check|if ($lines[$i]->subprice < 0 && !getDolGlobalString(''INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN'')) {", "commande/list.php:549|check|if ($lines[$i]->subprice < 0 && !getDolGlobalString(''INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN'')) {", "compta/facture/class/facture.class.php:4705|check|if ($this->type == self::TYPE_CREDIT_NOTE  && !getDolGlobalInt(''FACTURE_ENABLE_NEGATIVE_LINES'') && !getDolGlobalInt(''INVOICE_KEEP_DISCOUNT_LINES_AS_IN_ORIGIN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_MAX_FUTURE_DELAY', 'string', NULL, 'compta', 'Maximum number of seconds an invoice date may be in the future relative to the current time.', 'Checked in 16 locations across compta/facture/card.php, fourn/facture/card.php, compta/facture/class/facture.class.php, and compta/facture/prelevement.php. When the invoice date exceeds now + this value, validation is blocked. When the constant is not set (falsy), no future date limit is enforced (compta/facture/card.php:536). No admin UI is present.', 'Setting this value enforces a maximum allowed future date on invoices; leaving it unset disables future date validation.', 'Integer number of seconds; 0 or unset = no maximum future date limit enforced.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:535|check|if ($newdate > (dol_now(''tzuserrel'') + getDolGlobalInt(''INVOICE_MAX_FUTURE_DELAY''))) {", "compta/facture/card.php:536|check|if (!getDolGlobalString(''INVOICE_MAX_FUTURE_DELAY'')) {", "compta/facture/class/facture.class.php:1720|check|if ($date > (dol_get_last_hour(dol_now(''tzuserrel'')) + getDolGlobalInt(''INVOICE_MAX_FUTURE_DELAY''))) {", "fourn/facture/card.php:830|read|} elseif ($dateinvoice > (dol_get_last_hour(dol_now(''tzuserrel'')) + getDolGlobalInt(''INVOICE_MAX_FUTURE_DELAY''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_NO_PAYMENT_DETAILS', 'string', NULL, 'core', 'Suppresses the payment details section on invoice and related PDF documents.', 'Checked across 8 occurrences in core/lib/pdf.lib.php, pdf_octopus.modules.php, pdf_sponge.modules.php, pdf_canelle.modules.php, and other module PDFs. When truthy, payment history blocks are not rendered. No admin UI write is present.', 'Enabling this removes all payment detail sections from generated invoice PDFs, including paid amounts, credit notes, and deposits.', 'Truthy string (non-empty) = hide payment details; absent/empty = show payment details when amounts exist.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1054|check|if ((($deja_regle > 0 || $creditnoteamount > 0 || $depositsamount > 0) && !getDolGlobalString(''INVOICE_NO_PAYMENT_DETAILS''))", "core/modules/facture/doc/pdf_octopus.modules.php:412|check|if (!getDolGlobalString(''INVOICE_NO_PAYMENT_DETAILS'') && $nbpayments > 0) {", "core/modules/facture/doc/pdf_sponge.modules.php:345|check|if (!getDolGlobalString(''INVOICE_NO_PAYMENT_DETAILS'') && $nbpayments > 0) {", "core/modules/supplier_invoice/doc/pdf_canelle.modules.php:815|check|if (($deja_regle > 0 || $creditnoteamount > 0 || $depositsamount > 0) && !getDolGlobalString(''INVOICE_NO_PAYMENT_DETAILS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_NUMBERING_MARS_FORCE_PREFIX', 'string', NULL, 'core', 'When set, overrides the default prefix used by the Mars invoice numbering module.', 'Checked in core/modules/facture/mod_facture_mars.php:91-92. When the constant is set, $this->prefixinvoice is assigned its value, overriding the module''s default prefix.', 'Setting this forces the Mars numbering module to use the specified prefix for all new invoice numbers. Clearing it causes the module to use its built-in default prefix.', 'Any non-empty string = forced prefix for Mars invoice numbering; empty/unset = default prefix used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_facture_mars.php:91|if (getDolGlobalString(''INVOICE_NUMBERING_MARS_FORCE_PREFIX'')) {", "mod_facture_mars.php:92|$this->prefixinvoice = getDolGlobalString(''INVOICE_NUMBERING_MARS_FORCE_PREFIX'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_NUMBERING_TERRE_FORCE_PREFIX', 'string', NULL, 'core', 'When set, overrides the default prefix used by the Terre invoice numbering module.', 'Checked in core/modules/facture/mod_facture_terre.php:94-95. When the constant is set, $this->prefixinvoice is assigned its value, overriding the module''s built-in default prefix.', 'Setting this forces the Terre numbering module to use the specified prefix for all new invoice numbers. Clearing it causes the module to use its built-in default prefix.', 'Any non-empty string = forced prefix for Terre invoice numbering; empty/unset = default prefix used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_facture_terre.php:94|if (getDolGlobalString(''INVOICE_NUMBERING_TERRE_FORCE_PREFIX'')) {", "mod_facture_terre.php:95|$this->prefixinvoice = getDolGlobalString(''INVOICE_NUMBERING_TERRE_FORCE_PREFIX'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_PAYMENT_ENABLE_STRUCTURED_COMMUNICATION', 'bool', NULL, 'core', 'Enables structured communication (Belgian OGM/VCS format) on invoices and SEPA payment files.', 'Checked in bonprelevement.class.php:2465 specifically for Belgian companies (country_code == ''BE''), in core/lib/functions.lib.php:10723 for facture objects, and in PDF modules pdf_octopus and pdf_sponge at lines 1631 and 1697. No admin UI write path exists.', 'Enabling this constant activates structured payment references on invoices and in SEPA XML for Belgian entities; without it, unstructured references are used.', 'Truthy string/bool=structured communication enabled, empty/0=disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2465|check|if (getDolGlobalString(''INVOICE_PAYMENT_ENABLE_STRUCTURED_COMMUNICATION'') && $mysoc->country_code == ''BE'') {", "core/lib/functions.lib.php:10723|check|if (getDolGlobalString(''INVOICE_PAYMENT_ENABLE_STRUCTURED_COMMUNICATION'') && $object->element == ''facture'') {", "core/modules/facture/doc/pdf_octopus.modules.php:1631|check|if (getDolGlobalString(''INVOICE_PAYMENT_ENABLE_STRUCTURED_COMMUNICATION'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:1697|check|if (getDolGlobalString(''INVOICE_PAYMENT_ENABLE_STRUCTURED_COMMUNICATION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_POINTOFTAX_DATE', 'string', NULL, 'compta', 'Enables a separate point-of-tax date field on invoice and related document forms.', 'Checked in 7 locations: compta/facture/card.php:4476 and :5494, comm/propal/card.php:2849, commande/card.php:2775, core/modules/facture/doc/pdf_octopus.modules.php:2146, pdf_sponge.modules.php:2381, and compta/facture/class/facture.class.php:372 where the field is conditionally enabled. No admin UI is present.', 'Enabling this causes a point-of-tax date field to appear on invoices, proposals, and orders, and that date is included in PDF document rendering.', '0 or unset = point-of-tax date field hidden; truthy value = field displayed and active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4476|check|if (getDolGlobalString(''INVOICE_POINTOFTAX_DATE'')) {", "compta/facture/class/facture.class.php:372|read|''date_pointoftax'' => array(''type'' => ''date'', ''label'' => ''DatePointOfTax'', ''enabled'' => ''getDolGlobalString(\"INVOICE_POINTOFTAX_DATE\")'', ''visible'' => -1, ''position'' => 270),", "core/modules/facture/doc/pdf_octopus.modules.php:2146|check|if (getDolGlobalString(''INVOICE_POINTOFTAX_DATE'')) {", "commande/card.php:2775|check|if (getDolGlobalString(''INVOICE_POINTOFTAX_DATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_POSITIVE_CREDIT_NOTE', 'string', NULL, 'core', 'Forces credit note (type 2 invoice) amounts to be displayed as positive values in PDFs.', 'Checked across core/lib/pdf.lib.php and core/modules/facture/doc/pdf_octopus.modules.php whenever object type == 2 (credit note). 16+ occurrences across multiple invoice PDF modules. No admin UI write is present.', 'Enabling this flips sign display of credit note lines and totals to positive in PDFs; disabling it uses native negative values.', 'truthy = display credit note amounts as positive; empty/not set = use native negative amounts', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2457|check|if (isset($object->type) && $object->type == 2 && getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE'')) {", "core/lib/pdf.lib.php:2500|check|if (isset($object->type) && $object->type == 2 && getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:873|check|if (isset($object->type) && $object->type == 2 && getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:1112|check|if ($object->type == 2 && getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_POSITIVE_CREDIT_NOTE_SCREEN', 'string', NULL, 'compta', 'When enabled, displays credit note amounts as positive values on the invoice screen and related views, inverting the usual sign display.', 'Checked in compta/facture/card.php:5795, compta/facture/card-rec.php:1806, compta/facture/prelevement.php:619, and core/tpl/objectline_view.tpl.php:117 for credit note type invoices and supplier invoices.', 'Enabling this constant changes the sign display of credit note amounts to positive across invoice, recurring invoice, direct debit, and line views.', '0 or unset = credit note amounts displayed as negative (standard); truthy = credit note amounts displayed as positive.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:5795|check|if (getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE_SCREEN'') && $object->type == $object::TYPE_CREDIT_NOTE) {", "core/tpl/objectline_view.tpl.php:117|check|if (getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE_SCREEN'') && in_array($object->element, array(''facture'', ''invoice_supplier''))) {", "compta/facture/card-rec.php:1806|check|if (getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE_SCREEN'') && $object->type == $object::TYPE_CREDIT_NOTE) {", "compta/facture/prelevement.php:619|check|if (getDolGlobalString(''INVOICE_POSITIVE_CREDIT_NOTE_SCREEN'') && $object->type == $object::TYPE_CREDIT_NOTE) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_PRODUCTID_DEPOSIT', 'string', NULL, 'compta', 'Sets the product ID to associate with deposit invoice lines.', 'Read in 4 locations: compta/facture/class/facture.class.php:1882 (twice), compta/facture/card.php:1842, and fourn/facture/card.php:1278 (which falls back to SUPPLIER_INVOICE_PRODUCTID_DEPOSIT or this constant). Used as the fk_product parameter when inserting deposit lines. No admin UI is present.', 'Setting this to a valid product ID links deposit invoice lines to that product for accounting and reporting purposes; when unset (or 0), no product is linked.', 'Integer product ID; 0 or unset = no product linked to deposit lines.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:1882|read|(!getDolGlobalString(''INVOICE_PRODUCTID_DEPOSIT'') ? 0 : $conf->global->INVOICE_PRODUCTID_DEPOSIT), // fk_product", "compta/facture/card.php:1842|read|getDolGlobalInt(''INVOICE_PRODUCTID_DEPOSIT''), // fk_product", "fourn/facture/card.php:1278|read|getDolGlobalInt(''SUPPLIER_INVOICE_PRODUCTID_DEPOSIT'', getDolGlobalInt(''INVOICE_PRODUCTID_DEPOSIT'')), // fk_product"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_REC_CAN_DISABLE_DOCUMENT_FILE_GENERATION', 'bool', NULL, 'compta', 'Allows users to disable automatic document file generation for recurring invoices.', 'When set, compta/facture/card-rec.php:1482 and 2064 display an option to suppress file generation for customer recurring invoices. fourn/facture/card-rec.php:1103 and 1461 apply the same gate for supplier recurring invoices.', 'Enabling this constant exposes a UI option to skip file generation on recurring invoice records; disabling it hides that option.', 'Truthy value enables the disable-file-generation option; absent or falsy hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card-rec.php:1482|check|if (getDolGlobalString(''INVOICE_REC_CAN_DISABLE_DOCUMENT_FILE_GENERATION'')) {", "compta/facture/card-rec.php:2064|check|if (getDolGlobalString(''INVOICE_REC_CAN_DISABLE_DOCUMENT_FILE_GENERATION'')) {", "fourn/facture/card-rec.php:1103|check|if (getDolGlobalString(''INVOICE_REC_CAN_DISABLE_DOCUMENT_FILE_GENERATION'')) {", "fourn/facture/card-rec.php:1461|check|if (getDolGlobalString(''INVOICE_REC_CAN_DISABLE_DOCUMENT_FILE_GENERATION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_REC_DATE_TO_YES', 'string', NULL, 'core', 'Controls whether a date-to field is shown or enabled for recurring invoice lines on the document line creation form.', 'Checked in core/tpl/objectline_create.tpl.php:462 to conditionally alter the rendering of recurring invoice date fields.', 'Enabling this constant causes the recurring invoice date-to field to be shown or activated on the line creation form.', 'Truthy value = date-to field shown/enabled; empty/unset = field hidden or disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:462|check|if (getDolGlobalString(''INVOICE_REC_DATE_TO_YES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_REC_PRICE_MAY_CHANGE', 'string', NULL, 'compta', 'Flags that prices on recurring invoices are allowed to change between generations.', 'Read at compta/facture/card-rec.php:1521 and assigned to the variable $flag_price_may_change, which is then used to control price-change logic for recurring customer invoices. Only one occurrence is present in the payload.', 'Setting this constant signals that recurring invoice prices are not fixed; the exact downstream effect depends on code beyond the single visible occurrence.', 'Truthy value indicates prices may change; absent or falsy treats prices as fixed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card-rec.php:1521|read|$flag_price_may_change = getDolGlobalString(''INVOICE_REC_PRICE_MAY_CHANGE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_RETAINED_WARRANTY_LIMITED_TO_FINAL_SITUATION', 'string', NULL, 'compta', 'Restricts retained warranty accounting entries to final situation invoices only.', 'Checked in compta/facture/class/facture.class.php:6048 and :6083, and accountancy/journal/sellsjournal.php:342. A TODO comment notes this setting should eventually be stored as a flag on the invoice itself.', 'When enabled, retained warranty journal entries are only generated for the final situation invoice; intermediate situation invoices skip retained warranty accounting.', 'Empty/0 = retained warranty applied to all situation invoices; truthy = only applied on final situation invoice', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:6040  // TODO : add a flag on invoices to store this conf : INVOICE_RETAINED_WARRANTY_LIMITED_TO_FINAL_SITUATION", "compta/facture/class/facture.class.php:6048|check|if ($this->isSituationInvoice() && getDolGlobalString(''INVOICE_RETAINED_WARRANTY_LIMITED_TO_FINAL_SITUATION'')) {", "accountancy/journal/sellsjournal.php:342|check|if (getDolGlobalString(''INVOICE_USE_RETAINED_WARRANTY'') && $obj->retained_warranty > 0 && (!getDolGlobalString(''INVOICE_RETAINED_WARRANTY_LIMITED_TO_FINAL_SITUATION'') || !empty($ob"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SHOW_ALSO_LOCALTAX1_LINE_IF_ZERO', 'bool', NULL, 'core', 'Forces display of the local tax 1 line in PDF invoice tax summaries even when the tax amount is zero.', 'Checked at core/lib/pdf.lib.php:823 and :957; when truthy, a local tax 1 summary line is rendered even if the tax key amount is zero. No admin UI write is present.', 'Enabling this ensures local tax 1 always appears in the tax breakdown table on invoices, even for zero-amount entries.', 'Truthy string (non-empty) = always show local tax 1 line; absent/empty = only show when tax amount is non-zero.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:823|check|if ($tvakey != 0 || getDolGlobalString(''INVOICE_SHOW_ALSO_LOCALTAX1_LINE_IF_ZERO'')) {", "core/lib/pdf.lib.php:957|check|if ($tvakey != 0 || getDolGlobalString(''INVOICE_SHOW_ALSO_LOCALTAX1_LINE_IF_ZERO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SHOW_ALSO_LOCALTAX2_LINE_IF_ZERO', 'bool', NULL, 'core', 'Forces display of the local tax 2 line in PDF invoice tax summaries even when the tax amount is zero.', 'Checked at core/lib/pdf.lib.php:861 and :995; when truthy, a local tax 2 summary line is rendered even if the tax key amount is zero. No admin UI write is present.', 'Enabling this ensures local tax 2 always appears in the tax breakdown table on invoices, even for zero-amount entries.', 'Truthy string (non-empty) = always show local tax 2 line; absent/empty = only show when tax amount is non-zero.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:861|check|if ($tvakey != 0 || getDolGlobalString(''INVOICE_SHOW_ALSO_LOCALTAX2_LINE_IF_ZERO'')) {", "core/lib/pdf.lib.php:995|check|if ($tvakey != 0 || getDolGlobalString(''INVOICE_SHOW_ALSO_LOCALTAX2_LINE_IF_ZERO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SHOW_ALSO_VAT_LINE_IF_ZERO', 'bool', NULL, 'core', 'Forces display of the VAT line in PDF invoice tax summaries even when the VAT amount is zero.', 'Checked at core/lib/pdf.lib.php:918; when truthy, a VAT summary line is rendered even if the tax key amount is zero. No admin UI write is present.', 'Enabling this ensures a VAT line always appears in the tax breakdown on invoices, even for zero-amount VAT entries.', 'Truthy string (non-empty) = always show VAT line; absent/empty = only show when VAT amount is non-zero.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:918|check|if ($tvakey != 0 || getDolGlobalString(''INVOICE_SHOW_ALSO_VAT_LINE_IF_ZERO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SHOW_POS', 'bool', NULL, 'compta', 'Forces display of point-of-sale source columns (POS module, terminal, print count) in the invoice list and object definition, even without cashdesk/takepos modules enabled.', 'Checked in core/modules/modFacture.class.php:549, :709, :724 and compta/facture/list.php:263 alongside cashdesk/takepos module checks. The facture.class.php field definitions at lines 381-383 use the same condition to enable POS-related fields. No admin UI is present.', 'Enabling this constant causes POS-related columns and fields to appear in invoice lists and forms even if the cashdesk and takepos modules are not enabled.', '0 or unset = POS columns shown only when cashdesk or takepos is enabled; 1 = POS columns always shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/list.php:263|read|$showpos = (isModEnabled(''cashdesk'') || isModEnabled(''takepos'') || getDolGlobalInt(''INVOICE_SHOW_POS'')) ? ''1'' : ''0'';", "core/modules/modFacture.class.php:549|check|if (!empty($conf->cashdesk->enabled) || !empty($conf->takepos->enabled) || getDolGlobalString(''INVOICE_SHOW_POS'')) {", "compta/facture/class/facture.class.php:381|read|''module_source'' => array(''type'' => ''varchar(32)'', ''label'' => ''POSModule'', ''langfile'' => ''cashdesk'', ''enabled'' => \"(isModEnabled(''cashdesk'') || isModEnabled(''takepos'') || getDolGlob..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SHOW_SHIPPING_ADDRESS', 'bool', NULL, 'admin', 'Controls whether the shipping address is printed on invoice PDFs.', 'Written in admin/pdf_other.php at lines 154 and 155 (set/del) and displayed as a select at line 514. Checked in pdf_octopus.modules.php at lines 611 and 2310 and pdf_sponge.modules.php at line 2545 via getDolGlobalInt.', 'Enabling this constant causes invoice PDFs to include the customer''s shipping address. Disabling it omits the shipping address from invoices.', 'Non-zero integer to show shipping address; 0 or unset to hide it.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:154|write|dolibarr_set_const($db, \"INVOICE_SHOW_SHIPPING_ADDRESS\", GETPOSTINT(\"INVOICE_SHOW_SHIPPING_ADDRESS\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/facture/doc/pdf_octopus.modules.php:611|check|if (getDolGlobalInt(''INVOICE_SHOW_SHIPPING_ADDRESS'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:2310|check|if (getDolGlobalInt(''INVOICE_SHOW_SHIPPING_ADDRESS'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:2545|check|if (getDolGlobalInt(''INVOICE_SHOW_SHIPPING_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SITUATION_CAN_BE_REMOVED_EVEN_IF_NOT_LAST', 'string', NULL, 'core', 'Allows situation invoices to be deleted even when they are not the last in their billing cycle.', 'Checked (negated) at core/class/commoninvoice.class.php:776, :831, and :946 — when NOT set, situation invoices that are not last in cycle are blocked from deletion. No admin UI; hidden setting.', 'When set, situation invoices can be deleted regardless of their position in the cycle. When unset (default), only the last situation invoice in a cycle can be removed.', 'Empty = only last situation invoice in cycle can be removed; non-empty = any situation invoice can be removed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/commoninvoice.class.php:776|check|if (!getDolGlobalString(''INVOICE_SITUATION_CAN_BE_REMOVED_EVEN_IF_NOT_LAST'') && $this->situation_cycle_ref && method_exists($this, ''is_last_in_cycle'')) {", "core/class/commoninvoice.class.php:831|check|if (!getDolGlobalString(''INVOICE_SITUATION_CAN_BE_REMOVED_EVEN_IF_NOT_LAST'') && $this->situation_cycle_ref && method_exists($this, ''is_last_in_cycle'')) {", "core/class/commoninvoice.class.php:946|check|if (!getDolGlobalString(''INVOICE_SITUATION_CAN_BE_REMOVED_EVEN_IF_NOT_LAST'') && $this->situation_cycle_ref && method_exists($this, ''is_last_in_cycle'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SITUATION_CAN_FORCE_UPDATE_DESCRIPTION', 'string', NULL, 'core', 'Allows editing the description on situation invoice lines even when they would normally be locked.', 'Checked in core/tpl/subtotal_edit.tpl.php:119 and core/tpl/objectline_edit.tpl.php:180 to unlock the description field on situation invoice line edit forms.', 'Enabling this constant permits users to modify description text on situation invoice lines that are otherwise read-only.', 'Empty/not set = description locked on situation invoice lines; any truthy string = description editable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/subtotal_edit.tpl.php:119|check|if (getDolGlobalString(''INVOICE_SITUATION_CAN_FORCE_UPDATE_DESCRIPTION'')) {", "core/tpl/objectline_edit.tpl.php:180|check|if (getDolGlobalString(''INVOICE_SITUATION_CAN_FORCE_UPDATE_DESCRIPTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_COND_ID', 'string', NULL, 'compta', 'Specifies the default payment condition ID applied to the retained warranty portion of situation invoices.', 'Read and displayed via admin/invoice_situation.php (lines 118-121) and compta/facture/card.php (lines 4512, 4516, 5733). Configurable via the admin UI at admin/invoice_situation.php.', 'Changing this value alters the default payment condition assigned to retained warranty amounts on situation invoices.', 'Integer ID referencing a payment condition from the payment conditions table; used as fallback when no per-invoice condition is set.', 0, 0, 'admin/invoice_situation.php|admin/invoice_situation.php|admin/invoice_situation.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/invoice_situation.php:118|check|if (getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_COND_ID'') && isset($form->cache_conditions_paiements[getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_WARR", "compta/facture/card.php:4512|read|$retained_warranty_fk_cond_reglement = getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_COND_ID'');", "compta/facture/card.php:5733|check|$retained_warranty_fk_cond_reglement = !empty($retained_warranty_fk_cond_reglement) ? $retained_warranty_fk_cond_reglement : getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_PERCENT', 'string', NULL, 'compta', 'Specifies the default retained warranty percentage applied to situation invoices when no per-invoice value has been set.', 'Read in compta/facture/card.php:4503 as the fallback for $retained_warranty, and in core/modules/facture/doc/pdf_octopus.modules.php:3581 to compute the retained warranty rate for PDF generation.', 'Changing this value alters the default retained warranty rate applied to situation invoices and their PDF output.', 'Numeric percentage value (e.g. ''5'' for 5%); used as fallback when the invoice-level retained warranty is not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4503|check|$retained_warranty_js_default = !empty($retained_warranty) ? $retained_warranty : getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_PERCENT'');", "core/modules/facture/doc/pdf_octopus.modules.php:3581|read|$retainedWarrantyRate = (float) ($object->retained_warranty ? price2num($object->retained_warranty) : price2num(getDolGlobalString(''INVOICE_SITUATION_DEFAULT_RETAINED_WARRANTY_PERC"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SITUATION_USE_DGD', 'bool', NULL, 'core', 'Activates DGD (Décompte Général Définitif) mode for situation invoices in the Octopus PDF module.', 'Checked once in pdf_octopus.modules.php at line 3501 to branch into DGD-specific rendering logic. No admin UI write is present; only one occurrence found.', 'Enabling this switches situation invoice PDF rendering to DGD mode; the exact additional output depends on the DGD branch code.', 'Truthy integer = DGD mode active; 0 or unset = standard mode.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_octopus.modules.php:3501|check|if (getDolGlobalInt(''INVOICE_SITUATION_USE_DGD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SUBTYPE_ENABLED', 'bool', NULL, 'compta', 'When enabled, activates invoice subtype fields on customer and supplier invoice forms (required for Greek e-invoicing compliance).', 'Checked across compta/facture/card.php, compta/facture/card-rec.php, fourn/facture/card.php, fourn/facture/card-rec.php, and master.inc.php. Auto-set to 1 for Greek companies in master.inc.php:352.', 'Enabling this constant shows the invoice subtype selector on invoice and recurring invoice forms for both customer and supplier invoices.', '0 or unset = subtype field hidden; 1 = subtype field shown and active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["master.inc.php:352|write|$conf->global->INVOICE_SUBTYPE_ENABLED = 1;", "master.inc.php:350|read|if ($mysoc->country_code == ''GR'' && !isset($conf->global->INVOICE_SUBTYPE_ENABLED)) {", "compta/facture/card.php:4429|check|if (getDolGlobalInt(''INVOICE_SUBTYPE_ENABLED'')) {", "fourn/facture/card.php:2755|check|if (getDolGlobalInt(''INVOICE_SUBTYPE_ENABLED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SUPPLIER_ADDON_NUMBER', 'string', NULL, 'fourn', 'Specifies the numbering module (class name) used to generate supplier invoice reference numbers.', 'Read in fourn/class/fournisseur.facture.class.php:3037 to load the numbering class, with a fallback to ''mod_facture_fournisseur_cactus'' when not set (lines 3031 and 3036). Configured via admin/supplier_invoice.php:175. The comment at line 3018 states the number is generated ''according to numbering module defined into constant INVOICE_SUPPLIER_ADDON_NUMBER''.', 'Changing this constant switches the supplier invoice numbering algorithm; if the specified class does not exist, invoice number generation will fail.', 'String: class/module name (e.g. ''mod_facture_fournisseur_cactus''); empty = default cactus module used', 0, 0, 'admin/supplier_invoice.php|admin/supplier_invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.facture.class.php:3018  *      according to numbering module defined into constant INVOICE_SUPPLIER_ADDON_NUMBER", "fourn/class/fournisseur.facture.class.php:3031|write|$conf->global->INVOICE_SUPPLIER_ADDON_NUMBER = ''mod_facture_fournisseur_cactus'';", "fourn/class/fournisseur.facture.class.php:3037|read|$classname = getDolGlobalString(''INVOICE_SUPPLIER_ADDON_NUMBER'');", "admin/supplier_invoice.php:175|write|dolibarr_set_const($db, \"INVOICE_SUPPLIER_ADDON_NUMBER\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_SUPPLIER_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF generation module (template name) used when printing supplier invoices.', 'Set via admin/supplier_invoice.php (multiple write operations at lines 156, 159, 168) and checked at fourn/class/fournisseur.facture.class.php:3302 to determine which PDF template to use. The admin page lists available PDF modules and allows selecting the active one.', 'Changing this constant switches the PDF template for supplier invoices; removing it disables PDF generation with a specific template.', 'String: PDF module/template name; empty = no specific PDF module selected', 0, 0, 'admin/supplier_invoice.php|admin/supplier_invoice.php|admin/supplier_invoice.php|admin/supplier_invoice.php|admin/supplier_invoice.php|admin/supplier_invoice.php|admin/supplier_invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/supplier_invoice.php:156|write|if (dolibarr_set_const($db, \"INVOICE_SUPPLIER_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/supplier_invoice.php:426|check|if (getDolGlobalString(\"INVOICE_SUPPLIER_ADDON_PDF\") == \"$name\") {", "fourn/class/fournisseur.facture.class.php:3302|check|if (getDolGlobalString(''INVOICE_SUPPLIER_ADDON_PDF'')) {", "admin/supplier_invoice.php:150|check|if (getDolGlobalString(''INVOICE_SUPPLIER_ADDON_PDF'') == \"$value\") {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_USE_DEFAULT_DOCUMENT', 'bool', NULL, 'compta', 'When enabled, automatically selects the default document template for new invoices, bypassing manual template selection.', 'Checked in admin/invoice.php:654 (labeled ''Hidden conf''), compta/facture/card.php:4394, and compta/facture/card.php:4630. Admin UI is present (admin/invoice.php), though the comment labels it as hidden.', 'Enabling this constant causes the default document template to be pre-selected automatically when creating or viewing invoices.', '0 or unset = no automatic template selection; truthy = default document template is auto-selected.', 0, 0, 'admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/invoice.php:654|check|if (getDolGlobalString(''INVOICE_USE_DEFAULT_DOCUMENT'')) { // Hidden conf", "compta/facture/card.php:4394|check|if (getDolGlobalString(''INVOICE_USE_DEFAULT_DOCUMENT'')) { // Hidden conf", "compta/facture/card.php:4630|check|if (getDolGlobalString(''INVOICE_USE_DEFAULT_DOCUMENT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_USE_RETAINED_WARRANTY', 'bool', NULL, 'compta', 'Enables the retained warranty (retenue de garantie) feature on situation invoices.', 'Configured via accountancy/admin/defaultaccounts.php (line 124). Checked in compta/facture/card.php (lines 188, 2173, 4490) and accountancy/journal/sellsjournal.php (lines 342, 558, 976, 1268) to gate retained-warranty fields and accounting journal entries. A comment in compta/facture/class/facture.class.php:6042 notes that the retained_warranty field is populated independently once the feature is active.', 'When enabled, situation invoices can carry a retained warranty amount; this amount is tracked separately in the accounting sell journal and related reports.', 'Truthy (non-empty) to enable retained warranty; empty/unset to disable.', 0, 0, 'accountancy/admin/defaultaccounts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/defaultaccounts.php:124|check|if (getDolGlobalString(''INVOICE_USE_RETAINED_WARRANTY'')) {", "accountancy/journal/sellsjournal.php:342|check|if (getDolGlobalString(''INVOICE_USE_RETAINED_WARRANTY'') && $obj->retained_warranty > 0 ...", "// note : we don''t need to test INVOICE_USE_RETAINED_WARRANTY because if $this->retained_warranty is not empty it''s because it was set when this conf was active", "compta/facture/class/facture.class.php:6042  // note : we don''t need to test INVOICE_USE_RETAINED_WARRANTY..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_USE_SITUATION', 'bool', NULL, 'compta', 'Enables situation invoicing mode; value 1 activates standard situation invoices and value 2 enables the Octopus PDF situation template.', 'Configured via admin/invoice.php:680. Read in 52 locations across accountancy/index.php:135, accountancy/customer/index.php:656, customer/lines.php:735, customer/list.php:866, and compta/facture/class/factureligne.class.php:1084. Comment at core/modules/facture/doc/pdf_octopus.modules.php:178 states: ''If hidden option INVOICE_USE_SITUATION is set to 2, we can show the invoice situation template''. Comment at compta/facture/class/factureligne.class.php:931 notes: ''Returns situation_percent of the previous line. Used when INVOICE_USE_SITUATION = 1.''', 'Setting to 1 activates situation invoice tracking with percent-based line amounts; setting to 2 additionally enables the Octopus PDF situation template. Known accounting inaccuracies exist when set to 1 (noted in TODO comments at accountancy/customer/index.php:389 and :529).', '0 or unset = disabled; 1 = situation invoices enabled; 2 = situation invoices + Octopus PDF template enabled', 0, 0, 'admin/invoice.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/facture/doc/pdf_octopus.modules.php:178  // If hidden option INVOICE_USE_SITUATION is set to 2, we can show the invoice situation template", "compta/facture/class/factureligne.class.php:931  * Returns situation_percent of the previous line. Used when INVOICE_USE_SITUATION = 1.", "accountancy/customer/index.php:389  // TODO When INVOICE_USE_SITUATION = 1, values here are wrong. There is no compensation on bad stored amounts", "accountancy/index.php:135|check|if (getDolGlobalInt(''INVOICE_USE_SITUATION'') == 1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_USE_SITUATION_CREDIT_NOTE', 'bool', NULL, 'compta', 'Enables credit note support tied to situation (progress billing) invoices.', 'Checked in compta/facture/class/facture.class.php:5406, core/class/html.formmargin.class.php:114, and compta/facture/card.php:6833. When enabled, situation invoices with a situation_counter above zero can have associated credit notes and margin display is adjusted.', 'Enabling this allows credit notes to be linked to situation invoices; without it, this credit note path for situation invoices is suppressed.', 'Empty/0 = situation credit notes disabled; truthy = situation credit notes enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:5406|check|if (getDolGlobalString(''INVOICE_USE_SITUATION_CREDIT_NOTE'')) {", "core/class/html.formmargin.class.php:114|read||| ($object->element == ''facture'' && $object->type == $object::TYPE_CREDIT_NOTE && getDolGlobalInt(''INVOICE_USE_SITUATION_CREDIT_NOTE'') && $object->situation_counter > 0))", "compta/facture/card.php:6833|read|&& getDolGlobalInt(''INVOICE_USE_SITUATION_CREDIT_NOTE'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_USE_SITUATION_RETAINED_WARRANTY', 'bool', NULL, 'core', 'Compatibility alias that copies its value into INVOICE_USE_RETAINED_WARRANTY when the latter is not set.', 'Checked in core/modules/facture/doc/pdf_octopus.modules.php at line 172; if this constant is set and INVOICE_USE_RETAINED_WARRANTY is not, the code assigns INVOICE_USE_SITUATION_RETAINED_WARRANTY''s value to the global INVOICE_USE_RETAINED_WARRANTY at line 174.', 'Setting this constant enables retained warranty calculation on situation invoices as a fallback when INVOICE_USE_RETAINED_WARRANTY is absent. It has no effect if INVOICE_USE_RETAINED_WARRANTY is already set.', 'Truthy string to activate retained warranty via this alias; empty/unset to rely on INVOICE_USE_RETAINED_WARRANTY directly.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/doc/pdf_octopus.modules.php:172|check|if (getDolGlobalString(''INVOICE_USE_SITUATION_RETAINED_WARRANTY'') && !getDolGlobalString(''INVOICE_USE_RETAINED_WARRANTY'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:174|read|$conf->global->INVOICE_USE_RETAINED_WARRANTY = getDolGlobalString(''INVOICE_USE_SITUATION_RETAINED_WARRANTY'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_VAT_SHOW_REVERSE_CHARGE_MENTION', 'bool', NULL, 'core', 'Enables a reverse-charge VAT mention on invoices sent to EEC customers in a different country.', 'When set, PDF invoice modules (pdf_octopus, pdf_sponge) append a reverse-charge mention for cross-border EEC transactions. The check requires both a country code mismatch and the emitter being in the EEC. No admin UI write is present.', 'Enabling this adds the reverse-charge mention to applicable invoices; disabling suppresses it.', 'Truthy (non-empty) = mention shown; empty/unset = mention not shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_octopus.modules.php:1334|read|} elseif (getDolGlobalString(\"INVOICE_VAT_SHOW_REVERSE_CHARGE_MENTION\") && $this->emetteur->country_code != $object->thirdparty->country_code && $this->emetteur->isInEEC()", "pdf_sponge.modules.php:1401|read|} elseif (getDolGlobalString(\"INVOICE_VAT_SHOW_REVERSE_CHARGE_MENTION\") && $this->emetteur->country_code != $object->thirdparty->country_code && $this->emetteur->isInEEC()"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('INVOICE_VAT_TO_USE_ON_CREDIT_NOTE_WHEN_GENERATED_FROM_REMAIN_TO_PAY', 'bool', NULL, 'compta', 'Specifies the VAT rate (or mode) to apply when generating a credit note from an invoice''s remaining amount to pay.', 'Read in compta/facture/card.php at lines 1490, 1499, and 1500. If set to ''default'', the default product VAT rate is used; if set to a positive float, that numeric rate is applied directly.', 'Setting this constant controls which VAT rate is assigned to automatically generated credit notes for remaining balances, overriding the default behavior.', '''default'' = use default product VAT rate; positive float string = use that numeric VAT rate; empty/unset = standard logic applies.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:1490|check|if (getDolGlobalString(''INVOICE_VAT_TO_USE_ON_CREDIT_NOTE_WHEN_GENERATED_FROM_REMAIN_TO_PAY'') == ''default'') {", "compta/facture/card.php:1499|read|} elseif ((float) getDolGlobalString(''INVOICE_VAT_TO_USE_ON_CREDIT_NOTE_WHEN_GENERATED_FROM_REMAIN_TO_PAY'') > 0) {", "compta/facture/card.php:1500|read|$tva_tx = (float) getDolGlobalString(''INVOICE_VAT_TO_USE_ON_CREDIT_NOTE_WHEN_GENERATED_FROM_REMAIN_TO_PAY'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('JOB_ADDON_PDF', 'string', NULL, 'hrm', 'Specifies the PDF addon module used to generate PDF documents for HRM job records.', 'Read at hrm/class/job.class.php lines 977 and 978; if the constant is set, its value is used as the PDF model name for generating job documents.', 'Changing this value switches the PDF template used when generating HRM job documents. Clearing it disables PDF generation via this constant.', 'String; value equals the name of the PDF addon module to use.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/job.class.php:977|read|} elseif (getDolGlobalString(''JOB_ADDON_PDF'')) {", "hrm/class/job.class.php:978|read|$modele = getDolGlobalString(''JOB_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADDON', 'string', NULL, 'knowledgemanagement', 'Specifies the numbering module class name used to generate references for knowledge records.', 'Defaults to ''mod_knowledgerecord_standard'' if not set, as shown in admin/knowledgemanagement.php:73 and knowledgemanagement/class/knowledgerecord.class.php:1040. The value is used to load the corresponding PHP class file at knowledgemanagement/class/knowledgerecord.class.php:1046. Configurable via the admin UI at admin/knowledgemanagement.php.', 'Changing this value selects a different numbering/reference-generation module for knowledge records; an invalid class name will cause the reference generation to fail.', 'String: name of a module class (e.g., ''mod_knowledgerecord_standard''). Defaults to ''mod_knowledgerecord_standard'' when empty.', 0, 0, 'admin/knowledgemanagement.php|admin/knowledgemanagement.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/knowledgemanagement.php:73|write|$conf->global->KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADDON = ''mod_knowledgerecord_standard'';", "knowledgemanagement/class/knowledgerecord.class.php:1046|read|$file = getDolGlobalString(''KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADDON'') . \".php\";", "knowledgemanagement/class/knowledgerecord.class.php:1040|write|$conf->global->KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADDON = ''mod_knowledgerecord_standard'';", "knowledgemanagement/class/knowledgerecord.class.php:1047|read|$classname = getDolGlobalString(''KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADDON'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADVANCED_MASK', 'string', NULL, 'knowledgemanagement', 'Stores the numbering mask pattern used by the ''advanced'' numbering module for knowledge records.', 'Read at knowledgemanagement/core/modules/knowledgemanagement/mod_knowledgerecord_advanced.php:141 as `$mask = getDolGlobalString(''KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADVANCED_MASK'')`. Also displayed in the mask configuration input at line 88. 2 occurrences in 1 file.', 'When unset, the advanced numbering module uses no mask and reference generation fails or falls back. When set, the mask pattern is applied to generate knowledge record references.', 'String (numbering mask pattern); empty/unset = no mask defined.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["knowledgemanagement/core/modules/knowledgemanagement/mod_knowledgerecord_advanced.php:141|read|$mask = getDolGlobalString(''KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADVANCED_MASK'');", "knowledgemanagement/core/modules/knowledgemanagement/mod_knowledgerecord_advanced.php:88|read|... value=\"''.getDolGlobalString(''KNOWLEDGEMANAGEMENT_KNOWLEDGERECORD_ADVANCED_MASK'')..."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('KNOWLEDGERECORD_ADDON_PDF', 'string', NULL, 'knowledgemanagement', 'Specifies the PDF template module to use when generating PDF documents for knowledge records.', 'When set, the value is read as the PDF model name in knowledgemanagement/class/knowledgerecord.class.php at lines 1110–1111. No admin UI entry is present in the payload.', 'Setting this constant selects a custom PDF template for knowledge record documents; leaving it empty causes the default template selection logic to apply.', 'String: name of a PDF template module. Empty = use default template logic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["knowledgemanagement/class/knowledgerecord.class.php:1110|read|} elseif (getDolGlobalString(''KNOWLEDGERECORD_ADDON_PDF'')) {", "knowledgemanagement/class/knowledgerecord.class.php:1111|read|$modele = getDolGlobalString(''KNOWLEDGERECORD_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_ADMIN_DN', 'string', NULL, 'admin', 'Specifies the Distinguished Name (DN) of the LDAP administrator account used to bind and search the directory.', 'Assigned to $ldap->searchUser in core/class/ldap.class.php and used alongside LDAP_ADMIN_PASS to perform authenticated LDAP binds. Displayed in bind success/failure messages in admin/ldap.php. Configurable via the admin UI at admin/ldap.php.', 'Changing this value alters the account used for LDAP authentication; an incorrect DN will cause bind failures and prevent directory synchronization.', 'A valid LDAP DN string for the admin/bind account, e.g. ''cn=admin,dc=example,dc=com''.', 0, 0, 'admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:288|read|$this->searchUser = getDolGlobalString(''LDAP_ADMIN_DN'');", "admin/ldap.php:298|check|if (getDolGlobalString(''LDAP_ADMIN_DN'') && getDolGlobalString(''LDAP_ADMIN_PASS'')) {", "admin/ldap.php:259|read|print ''<input class=\"minwidth300\" type=\"text\" name=\"admin\" value=\"''.getDolGlobalString(''LDAP_ADMIN_DN'').''\">'';", "admin/ldap.php:95|write|if (!dolibarr_set_const($db, ''LDAP_ADMIN_DN'', GETPOST(\"admin\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_ADMIN_PASS', 'string', NULL, 'admin', 'Stores the password for the LDAP administrator account used to bind to the directory.', 'Assigned to $ldap->searchPassword in core/class/ldap.class.php and used together with LDAP_ADMIN_DN to perform authenticated LDAP binds. Rendered as a password input in admin/ldap.php. Configurable via the admin UI at admin/ldap.php.', 'Changing this value alters the credential used for LDAP authentication; an incorrect password will cause bind failures and prevent directory synchronization.', 'A string containing the LDAP admin account password.', 0, 0, 'admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:289|read|$this->searchPassword = getDolGlobalString(''LDAP_ADMIN_PASS'');", "admin/ldap.php:298|check|if (getDolGlobalString(''LDAP_ADMIN_DN'') && getDolGlobalString(''LDAP_ADMIN_PASS'')) {", "admin/ldap.php:265|read|print ''<input class=\"minwidth150\" type=\"password\" name=\"pass\" value=\"''.dol_escape_htmltag(getDolGlobalString(''LDAP_ADMIN_PASS'')).''\">'';", "admin/ldap.php:98|write|if (!dolibarr_set_const($db, ''LDAP_ADMIN_PASS'', GETPOST(\"pass\", ''none''), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_ACTIVE', 'string', NULL, 'core', 'Determines the active LDAP synchronisation direction for contacts (Dolibarr-to-LDAP, LDAP-to-Dolibarr, or disabled).', 'Set via admin/ldap.php:107 using a radio-button selector (line 176) and checked in core/triggers/interface_50_modLdap_Ldapsynchro.class.php:375, 394, 429 to gate contact synchronisation trigger logic. Also used in contact/ldap.php:151, 157 and core/lib/ldap.lib.php:62.', 'Changing this value enables, disables, or reverses the LDAP synchronisation direction for contacts, affecting whether contact changes are pushed to or pulled from LDAP.', 'One of the Ldap::SYNCHRO_* constants; empty/unset = synchronisation disabled.', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap.php:107|write|if (!dolibarr_set_const($db, ''LDAP_CONTACT_ACTIVE'', GETPOST(\"activecontact\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap.php:176|read|print $formldap->selectLdapDnSynchroActive(getDolGlobalInt(''LDAP_CONTACT_ACTIVE''), ''activecontact'', array(Ldap::SYNCHRO_LDAP_TO_DOLIBARR));", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:375|check|if (getDolGlobalString(''LDAP_CONTACT_ACTIVE'')) {", "contact/ldap.php:151|check|if (getDolGlobalString(''LDAP_CONTACT_ACTIVE'') && getDolGlobalInt(''LDAP_CONTACT_ACTIVE'') != Ldap::SYNCHRO_LDAP_TO_DOLIBARR) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_DN', 'string', NULL, 'contact', 'Defines the LDAP Distinguished Name (DN) base path under which contact entries are stored.', 'Set via admin/ldap_contacts.php:63 and read at lines 168, 299, and in contact/class/contact.class.php:806–808 to construct the DN for LDAP contact operations. Also displayed in contact/ldap.php:129.', 'Changing this value redirects all LDAP contact read and write operations to a different branch of the LDAP directory tree.', 'A valid LDAP DN string, e.g. ''ou=contacts,dc=example,dc=com''.', 0, 0, 'admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_contacts.php:63|write|if (!dolibarr_set_const($db, ''LDAP_CONTACT_DN'', GETPOST(\"contactdn\"), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_contacts.php:168|read|print ''<input size=\"48\" type=\"text\" name=\"contactdn\" value=\"'' . getDolGlobalString(''LDAP_CONTACT_DN'').''\">'';", "contact/class/contact.class.php:806|read|$dn = getDolGlobalString(''LDAP_KEY_CONTACTS'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_CONTACTS'')].\",.\" . getDolGlobalString(''LDAP_CONTACT_DN'');", "contact/ldap.php:129|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPContactDn\").''</td><td class=\"valeur\" colspan=\"3\">''.getDolGlobalString(''LDAP_CONTACT_DN'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_FIELD_ADDRESS', 'string', NULL, 'admin', 'Maps the Dolibarr contact address to the corresponding LDAP attribute name for synchronisation.', 'Set via admin/ldap_contacts.php:97 and displayed at line 256; used in contact/class/contact.class.php:864–865 where the contact''s address is conditionally written to the LDAP entry under this attribute.', 'Changing this value changes which LDAP attribute receives the contact''s address during synchronisation.', 'Any valid LDAP attribute name string, e.g. ''street''.', 0, 0, 'admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_contacts.php:97|write|if (!dolibarr_set_const($db, ''LDAP_CONTACT_FIELD_ADDRESS'', GETPOST(\"fieldaddress\"), ''chaine'', 0, '''', $conf->entity)) {", "contact/class/contact.class.php:864|check|if ($this->address && getDolGlobalString(''LDAP_CONTACT_FIELD_ADDRESS'')) {", "contact/class/contact.class.php:865|read|$info[getDolGlobalString(''LDAP_CONTACT_FIELD_ADDRESS'')] = $this->address;", "admin/ldap_contacts.php:256|read|print ''<input size=\"25\" type=\"text\" name=\"fieldaddress\" value=\"'' . getDolGlobalString(''LDAP_CONTACT_FIELD_ADDRESS'').''\">'';"]', 'high', NULL);
