INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_FIELD_COUNTRY', 'string', NULL, 'admin', 'Maps the Dolibarr contact country code to the corresponding LDAP attribute name for synchronisation.', 'Set via admin/ldap_contacts.php:106 and displayed at line 277; used in contact/class/contact.class.php:873–874 where the contact''s country_code is conditionally written to the LDAP entry under this attribute.', 'Changing this value changes which LDAP attribute receives the contact''s country code during synchronisation.', 'Any valid LDAP attribute name string, e.g. ''c''.', 0, 0, 'admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_contacts.php:106|write|if (!dolibarr_set_const($db, ''LDAP_CONTACT_FIELD_COUNTRY'', GETPOST(\"fieldcountry\"), ''chaine'', 0, '''', $conf->entity)) {", "contact/class/contact.class.php:873|check|if ($this->country_code && getDolGlobalString(''LDAP_CONTACT_FIELD_COUNTRY'')) {", "contact/class/contact.class.php:874|read|$info[getDolGlobalString(''LDAP_CONTACT_FIELD_COUNTRY'')] = $this->country_code;", "admin/ldap_contacts.php:277|read|print ''<input size=\"25\" type=\"text\" name=\"fieldcountry\" value=\"'' . getDolGlobalString(''LDAP_CONTACT_FIELD_COUNTRY'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_FIELD_DESCRIPTION', 'string', NULL, 'contact', 'Maps the Dolibarr contact private note to the corresponding LDAP attribute name for synchronisation.', 'Used only in contact/class/contact.class.php at lines 888–889, where the contact''s note_private (stripped of HTML) is written to the LDAP entry under this attribute name if the constant is set.', 'Setting this value causes the contact''s private note to be exported as an LDAP attribute; leaving it unset omits the note from LDAP entries.', 'Any valid LDAP attribute name string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/class/contact.class.php:888|check|if ($this->note_private && getDolGlobalString(''LDAP_CONTACT_FIELD_DESCRIPTION'')) {", "contact/class/contact.class.php:889|read|$info[getDolGlobalString(''LDAP_CONTACT_FIELD_DESCRIPTION'')] = dol_string_nohtmltag($this->note_private, 2);"]', 'low', NULL);
