INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_CONTACT_OBJECT_CLASS', 'string', NULL, 'admin', 'Specifies the LDAP objectClass(es) assigned to contact entries when synchronising contacts to LDAP.', 'Set via admin/ldap_contacts.php:66 and read at line 300; consumed in contact/class/contact.class.php:831 where the value is split by comma and assigned as the objectclass array for the LDAP entry.', 'Changing this value changes the LDAP schema classes applied to contact entries, which can break compatibility with the LDAP server''s schema if set incorrectly.', 'A comma-separated list of LDAP objectClass names, e.g. ''inetOrgPerson,organizationalPerson''.', 0, 0, 'admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_contacts.php:66|write|if (!dolibarr_set_const($db, ''LDAP_CONTACT_OBJECT_CLASS'', GETPOST(\"objectclass\"), ''chaine'', 0, '''', $conf->entity)) {", "contact/class/contact.class.php:831|read|$info[\"objectclass\"] = explode('','', getDolGlobalString(''LDAP_CONTACT_OBJECT_CLASS''));", "admin/ldap_contacts.php:176|read|print ''<input size=\"48\" type=\"text\" name=\"objectclass\" value=\"'' . getDolGlobalString(''LDAP_CONTACT_OBJECT_CLASS'').''\">'';", "admin/ldap_contacts.php:300|read|$objectclass = getDolGlobalString(''LDAP_CONTACT_OBJECT_CLASS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_', 'string', NULL, 'user', 'Provides a dynamic per-social-network LDAP field name mapping, where the suffix is the uppercased social network label.', 'Used dynamically in user/class/user.class.php and user/card.php. The constant name is constructed at runtime as ''LDAP_FIELD_'' + strtoupper(social_network_label). The value is the LDAP attribute name to map the corresponding social network field to.', 'Setting LDAP_FIELD_<NETWORK> to an LDAP attribute name causes that social network value to be written to and read from the specified LDAP attribute during user synchronization.', 'LDAP attribute name string corresponding to the social network field.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/user.class.php:3578|check|if (!empty($this->socialnetworks[$value[''label'']]) && getDolGlobalString(''LDAP_FIELD_''.strtoupper($value[''label'']))) {", "user/class/user.class.php:3579|read|$info[getDolGlobalString(''LDAP_FIELD_''.strtoupper($value[''label'']))] = $this->socialnetworks[$value[''label'']];", "user/card.php:764|read|$required_fields[] = getDolGlobalString(''LDAP_FIELD_''.strtoupper($socialnetwork));", "user/card.php:795|read|$ldap_social[$socialnetwork] = $attribute[getDolGlobalString(''LDAP_FIELD_''.strtoupper($socialnetwork))];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_ADDRESS', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s street address.', 'Configured via admin/ldap_users.php (written at line 110, displayed at line 321). In user/class/user.class.php:3582-3583, used to populate the address attribute in the LDAP entry when the user has an address.', 'Changing this value redirects address data to a different LDAP attribute; clearing it disables address synchronisation to LDAP.', 'Any valid LDAP attribute name (e.g. ''street'', ''postalAddress'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:110|write|dolibarr_set_const($db, ''LDAP_FIELD_ADDRESS'', GETPOST(\"fieldaddress\")", "user/class/user.class.php:3582|check|if ($this->address && getDolGlobalString(''LDAP_FIELD_ADDRESS'')) {", "user/class/user.class.php:3583|read|$info[getDolGlobalString(''LDAP_FIELD_ADDRESS'')] = $this->address;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_COMPANY', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s associated company/organisation name.', 'Configured via admin/ldap_users.php (written at line 107, displayed at line 314). In user/class/user.class.php:3594-3598, the constant is checked and used as the key to set the company name in the LDAP info array when the user belongs to a third party.', 'Changing this value redirects LDAP company-name reads and writes to a different attribute; clearing it disables company-name propagation to LDAP.', 'Any valid LDAP attribute name (e.g. ''o'', ''company'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:107|write|dolibarr_set_const($db, ''LDAP_FIELD_COMPANY'', GETPOST(\"fieldcompany\")", "user/class/user.class.php:3594|check|if ($this->socid > 0 && getDolGlobalString(''LDAP_FIELD_COMPANY'')) {", "user/class/user.class.php:3598|read|$info[getDolGlobalString(''LDAP_FIELD_COMPANY'')] = $soc->name;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_COUNTRY', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s country.', 'Configured via admin/ldap_users.php (written at line 119, displayed at line 342). Only 2 occurrences are present in the payload; no usage in user class files is shown.', 'Changing or clearing this value alters which LDAP attribute receives the country value during user synchronisation.', 'Any valid LDAP attribute name (e.g. ''c'', ''co'', ''countryName'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:119|write|dolibarr_set_const($db, ''LDAP_FIELD_COUNTRY'', GETPOST(\"fieldcountry\")", "admin/ldap_users.php:342|read|print ''<input size=\"25\" type=\"text\" name=\"fieldcountry\" value=\"''.getDolGlobalString(''LDAP_FIELD_COUNTRY'').''\">''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_DESCRIPTION', 'string', NULL, 'user', 'Specifies the LDAP attribute name that stores the user''s description (mapped from the public note).', 'Configured via admin/ldap_users.php (written at line 122, displayed at line 356). In user/class/user.class.php:3591-3592, when the user has a public note and the constant is set, the sanitised note is stored under this LDAP attribute. Also referenced in user/card.php:758 and 962 and user.class.php:3881.', 'Changing this value redirects the user''s public note to a different LDAP attribute; clearing it disables description synchronisation.', 'Any valid LDAP attribute name (e.g. ''description'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:122|write|dolibarr_set_const($db, ''LDAP_FIELD_DESCRIPTION'', GETPOST(\"fielddescription\")", "user/class/user.class.php:3591|check|if ($this->note_public && getDolGlobalString(''LDAP_FIELD_DESCRIPTION'')) {", "user/class/user.class.php:3592|read|$info[getDolGlobalString(''LDAP_FIELD_DESCRIPTION'')] = dol_string_nohtmltag($this->note_public, 2);", "user/card.php:758|read|getDolGlobalString(''LDAP_FIELD_DESCRIPTION''),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_FAX', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s fax number for synchronization.', 'Written in admin/ldap_users.php:104, displayed and used in UI at :307 and :309; mapped to $this->attr_fax in core/class/ldap.class.php:304 and used in user/card.php:786.', 'Setting the correct LDAP attribute ensures the user fax number is properly imported from LDAP. An incorrect value leaves fax empty after sync.', 'String LDAP attribute name (e.g. ''facsimileTelephoneNumber''); empty = no fax attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:304|read|$this->attr_fax        = getDolGlobalString(''LDAP_FIELD_FAX'');", "admin/ldap_users.php:104|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_FAX'', GETPOST(\"fieldfax\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:786|read|$ldap_fax = $attribute[getDolGlobalString(''LDAP_FIELD_FAX'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_FIRSTNAME', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s first name for synchronization.', 'Written in admin/ldap_users.php:92, displayed and used in UI at :251 and :253; mapped to $this->attr_firstname in core/class/ldap.class.php:301 and used in user/card.php:780.', 'Setting the correct LDAP attribute ensures the user first name is properly imported from LDAP. An incorrect value leaves first name empty after sync.', 'String LDAP attribute name (e.g. ''givenName''); empty = no first name attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:301|read|$this->attr_firstname  = getDolGlobalString(''LDAP_FIELD_FIRSTNAME'');", "admin/ldap_users.php:92|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_FIRSTNAME'', GETPOST(\"fieldfirstname\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:780|read|$ldap_firstname = $attribute[getDolGlobalString(''LDAP_FIELD_FIRSTNAME'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_FULLNAME', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s full name.', 'Configured via admin/ldap_users.php (written at line 74, displayed at line 237). It is passed as a parameter when reading and writing LDAP user entries (admin/ldap_users.php:485, user/card.php:949) and can be selected as the LDAP key field for users.', 'Changing this value redirects LDAP full-name reads and writes to a different attribute; mismatches with the actual LDAP schema will break user synchronisation.', 'Any valid LDAP attribute name (e.g. ''cn'', ''displayName'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:74|write|dolibarr_set_const($db, ''LDAP_FIELD_FULLNAME'', GETPOST(\"fieldfullname\")", "admin/ldap_users.php:239|read|getDolGlobalString(''LDAP_KEY_USERS'') == getDolGlobalString(''LDAP_FIELD_FULLNAME'') ? '' checked''", "admin/ldap_users.php:485|read|getDolGlobalString(''LDAP_FIELD_FULLNAME''),", "user/card.php:949|read|getDolGlobalString(''LDAP_FIELD_FULLNAME''),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_GROUPID', 'string', NULL, 'user', 'Specifies the LDAP attribute name that stores the user''s primary group ID (gidNumber).', 'Configured via admin/ldap_users.php (written at line 131, displayed at line 370). In user/class/user.class.php:3665-3671, when set, the primary group ID is written as ''65534'' (no group) or the first group''s Dolibarr ID under this LDAP attribute.', 'Changing this value redirects group-ID data to a different LDAP attribute; clearing it disables group-ID synchronisation.', 'Any valid LDAP attribute name (e.g. ''gidNumber'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:131|write|dolibarr_set_const($db, ''LDAP_FIELD_GROUPID'', GETPOST(\"fieldgroupid\")", "user/class/user.class.php:3665|check|if (getDolGlobalString(''LDAP_FIELD_GROUPID'')) {", "user/class/user.class.php:3668|read|$info[getDolGlobalString(''LDAP_FIELD_GROUPID'')] = ''65534'';", "user/class/user.class.php:3671|read|$info[getDolGlobalString(''LDAP_FIELD_GROUPID'')] = $groupforuser->id;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_HOMEDIRECTORY', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s home directory path.', 'Configured via admin/ldap_users.php (written at line 137, displayed at line 384). In user/class/user.class.php:3676-3677, used together with LDAP_FIELD_HOMEDIRECTORYPREFIX: the full path is built as prefix + ''/'' + login and stored under this attribute.', 'Changing this value redirects home-directory data to a different LDAP attribute; clearing it or clearing LDAP_FIELD_HOMEDIRECTORYPREFIX disables home-directory synchronisation.', 'Any valid LDAP attribute name (e.g. ''homeDirectory'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:137|write|dolibarr_set_const($db, ''LDAP_FIELD_HOMEDIRECTORY'', GETPOST(\"fieldhomedirectory\")", "user/class/user.class.php:3676|check|if (getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORY'') && getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORYPREFIX'')) {", "user/class/user.class.php:3677|read|$info[getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORY'')] = getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORYPREFIX'').\"/\".$this->login;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_HOMEDIRECTORYPREFIX', 'string', NULL, 'admin', 'Specifies the filesystem path prefix prepended to the login name to build the LDAP home-directory value.', 'Configured via admin/ldap_users.php (written at line 140, displayed at line 391). In user/class/user.class.php:3676-3677, used together with LDAP_FIELD_HOMEDIRECTORY: the full path is built as this prefix + ''/'' + login.', 'Changing this value alters the home-directory path written to LDAP for all users; clearing it or clearing LDAP_FIELD_HOMEDIRECTORY disables home-directory synchronisation.', 'Any filesystem path prefix string (e.g. ''/home'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:140|write|dolibarr_set_const($db, ''LDAP_FIELD_HOMEDIRECTORYPREFIX'', GETPOST(\"fieldhomedirectoryprefix\")", "user/class/user.class.php:3676|check|if (getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORY'') && getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORYPREFIX'')) {", "user/class/user.class.php:3677|read|$info[getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORY'')] = getDolGlobalString(''LDAP_FIELD_HOMEDIRECTORYPREFIX'').\"/\".$this->login;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_LOGIN', 'string', NULL, 'admin', 'Specifies the LDAP attribute name used as the user login field when authenticating or syncing via LDAP.', 'Configured in admin/ldap_users.php and read by core/class/ldap.class.php:298 as attr_login and by core/login/functions_ldap.php:160 during login checks. Also used in user/card.php for user synchronization.', 'Changing this value changes which LDAP attribute is mapped to the Dolibarr login field; an incorrect value will break LDAP authentication.', 'A valid LDAP attribute name string, e.g. ''uid'', ''sAMAccountName''.', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/ldap.class.php:298|read|$this->attr_login      = getDolGlobalString(''LDAP_FIELD_LOGIN''); //unix", "core/login/functions_ldap.php:160|check|if (getDolGlobalString(''LDAP_FIELD_LOGIN'') && !empty($ldap->login)) {", "core/login/functions_ldap.php:162|read|dol_syslog(\"functions_ldap::check_user_password_ldap login is now $login (LDAP_FIELD_LOGIN=\".getDolGlobalString(''LDAP_FIELD_LOGIN'').\")\");", "admin/ldap_users.php:77|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_LOGIN'', GETPOST(\"fieldlogin\"), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_LOGIN_SAMBA', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the Samba/Active Directory login for user mapping.', 'Written in admin/ldap_users.php:80, displayed and used in UI at :265 and :267; mapped to $this->attr_sambalogin in core/class/ldap.class.php:299 and used in user/card.php:750 and :782.', 'Changing this to the correct LDAP attribute enables proper Samba login field mapping during user sync. An incorrect attribute name prevents Samba login retrieval.', 'String LDAP attribute name (e.g. ''samAccountName''); empty = no Samba login attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:299|read|$this->attr_sambalogin = getDolGlobalString(''LDAP_FIELD_LOGIN_SAMBA''); //samba, activedirectory", "admin/ldap_users.php:80|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_LOGIN_SAMBA'', GETPOST(\"fieldloginsamba\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:782|read|$ldap_loginsmb = $attribute[getDolGlobalString(''LDAP_FIELD_LOGIN_SAMBA'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_MAIL', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s email address for synchronization.', 'Written in admin/ldap_users.php:95, displayed and used in UI at :286 and :288; mapped to $this->attr_mail in core/class/ldap.class.php:302 and used in user/card.php:788.', 'Setting the correct LDAP attribute ensures the user email is properly imported from LDAP. An incorrect value leaves email empty after sync.', 'String LDAP attribute name (e.g. ''mail''); empty = no email attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:302|read|$this->attr_mail       = getDolGlobalString(''LDAP_FIELD_MAIL'');", "admin/ldap_users.php:95|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_MAIL'', GETPOST(\"fieldmail\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:788|read|$ldap_mail = $attribute[getDolGlobalString(''LDAP_FIELD_MAIL'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_MEMBER_END_LASTSUBSCRIPTION', 'string', NULL, 'adherents', 'Maps the member''s last subscription end date to its corresponding LDAP attribute name.', 'When set, the member''s datefin (last subscription end date, formatted as dayhourldap) is written to the LDAP attribute named by this constant during sync. Also used in core/triggers/interface_50_modLdap_Ldapsynchro.class.php. Configured via admin/ldap_members.php.', 'Setting this enables the last subscription end date to be synchronised to LDAP. Leaving it empty suppresses this field from LDAP sync.', 'LDAP attribute name string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:137|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_MEMBER_END_LASTSUBSCRIPTION'', GETPOST(\"fieldendlastsubscription\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3052|check|if ($this->datefin && getDolGlobalString(''LDAP_FIELD_MEMBER_END_LASTSUBSCRIPTION'')) {", "adherents/class/adherent.class.php:3053|read|$info[getDolGlobalString(''LDAP_FIELD_MEMBER_END_LASTSUBSCRIPTION'')] = dol_print_date($this->datefin, ''dayhourldap'');", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:523|read||| getDolGlobalString(''LDAP_FIELD_MEMBER_END_LASTSUBSCRIPTION'')) {"]', 'high', NULL);
