INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_MEMBER_LASTSUBSCRIPTION_DATE', 'string', NULL, 'adherents', 'Maps the member''s last subscription date to its corresponding LDAP attribute name.', 'When set, the member''s last_subscription_date (formatted as dayhourldap) is written to the LDAP attribute named by this constant during sync. Also used in core/triggers/interface_50_modLdap_Ldapsynchro.class.php. Configured via admin/ldap_members.php.', 'Setting this enables the last subscription date to be synchronised to LDAP. Leaving it empty suppresses this field from LDAP sync.', 'LDAP attribute name string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:148|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_MEMBER_LASTSUBSCRIPTION_DATE'', GETPOST(\"fieldlastsubscriptiondate\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3094|check|if ($this->last_subscription_date && getDolGlobalString(''LDAP_FIELD_MEMBER_LASTSUBSCRIPTION_DATE'')) {", "adherents/class/adherent.class.php:3095|read|$info[getDolGlobalString(''LDAP_FIELD_MEMBER_LASTSUBSCRIPTION_DATE'')] = dol_print_date($this->last_subscription_date, ''dayhourldap'');", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:521|read||| getDolGlobalString(''LDAP_FIELD_MEMBER_LASTSUBSCRIPTION_DATE'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_MEMBER_STATUS', 'string', NULL, 'adherents', 'Maps the member status value to its corresponding LDAP attribute name.', 'When set, the member''s statut value is written to the LDAP attribute named by this constant during sync. Also used by core/triggers/interface_50_modLdap_Ldapsynchro.class.php. Configured via admin/ldap_members.php.', 'Setting this enables the member status to be synchronised to LDAP. Leaving it empty suppresses status sync.', 'LDAP attribute name string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:134|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_MEMBER_STATUS'', GETPOST(\"fieldstatus\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3049|check|if (isset($this->statut) && getDolGlobalString(''LDAP_FIELD_MEMBER_STATUS'')) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:496|check|if (getDolGlobalString(''LDAP_FIELD_MEMBER_STATUS'')) {", "adherents/class/adherent.class.php:3050|read|$info[getDolGlobalString(''LDAP_FIELD_MEMBER_STATUS'')] = $this->statut;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_MOBILE', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s mobile phone number for synchronization.', 'Written in admin/ldap_users.php:101, displayed and used in UI at :300 and :302; mapped to $this->attr_mobile in core/class/ldap.class.php:305 and used in user/card.php:787.', 'Setting the correct LDAP attribute ensures the user mobile number is properly imported from LDAP. An incorrect value leaves mobile empty after sync.', 'String LDAP attribute name (e.g. ''mobile''); empty = no mobile attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:305|read|$this->attr_mobile     = getDolGlobalString(''LDAP_FIELD_MOBILE'');", "admin/ldap_users.php:101|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_MOBILE'', GETPOST(\"fieldmobile\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:787|read|$ldap_mobile = $attribute[getDolGlobalString(''LDAP_FIELD_MOBILE'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_NAME', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s last name (surname) for synchronization.', 'Written in admin/ldap_users.php:89, displayed and used in UI at :244 and :246; mapped to $this->attr_name in core/class/ldap.class.php:300 and used in user/card.php:779.', 'Setting the correct LDAP attribute ensures the user last name is properly imported from LDAP. An incorrect value leaves last name empty after sync.', 'String LDAP attribute name (e.g. ''sn''); empty = no last name attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:300|read|$this->attr_name       = getDolGlobalString(''LDAP_FIELD_NAME'');", "admin/ldap_users.php:89|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_NAME'', GETPOST(\"fieldname\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:779|read|$ldap_lastname = $attribute[getDolGlobalString(''LDAP_FIELD_NAME'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_PASSWORD', 'string', NULL, 'user', 'Maps the Dolibarr user plaintext password to the corresponding LDAP attribute name for synchronisation.', 'Set via admin/ldap_users.php:83 and displayed at line 272; used in user/class/user.class.php:3631 where the unencrypted password (pass_indatabase) is written to the LDAP entry under this attribute. Also passed to the LDAP sync function at admin/ldap_users.php:490.', 'Changing this value changes which LDAP attribute receives the user''s plaintext password during synchronisation; an unset value means no plaintext password is written to LDAP.', 'Any valid LDAP attribute name string, e.g. ''userPassword''.', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_users.php:83|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_PASSWORD'', GETPOST(\"fieldpassword\"), ''chaine'', 0, '''', $conf->entity)) {", "user/class/user.class.php:3631|read|$info[getDolGlobalString(''LDAP_FIELD_PASSWORD'')] = $this->pass_indatabase; // $this->pass_indatabase = unencrypted password", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:641|check|if (getDolGlobalString(''LDAP_FIELD_PASSWORD'') || getDolGlobalString(''LDAP_FIELD_PASSWORD_CRYPTED'')) {", "admin/ldap_users.php:272|read|print ''<input size=\"25\" type=\"text\" name=\"fieldpassword\" value=\"''.getDolGlobalString(''LDAP_FIELD_PASSWORD'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_PASSWORD_CRYPTED', 'string', NULL, 'user', 'Maps the Dolibarr user encrypted password to the corresponding LDAP attribute name for synchronisation.', 'Set via admin/ldap_users.php:86 and displayed at line 279; used in user/class/user.class.php:3624 and 3633 where the crypted password (pass_indatabase_crypted) is written to the LDAP entry under this attribute. Also passed at admin/ldap_users.php:491.', 'Changing this value changes which LDAP attribute receives the user''s encrypted password during synchronisation; an unset value means no crypted password is written to LDAP.', 'Any valid LDAP attribute name string.', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_users.php:86|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_PASSWORD_CRYPTED'', GETPOST(\"fieldpasswordcrypted\"), ''chaine'', 0, '''', $conf->entity)) {", "user/class/user.class.php:3624|check|if ($this->pass_indatabase_crypted && getDolGlobalString(''LDAP_FIELD_PASSWORD_CRYPTED'')) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:641|check|if (getDolGlobalString(''LDAP_FIELD_PASSWORD'') || getDolGlobalString(''LDAP_FIELD_PASSWORD_CRYPTED'')) {", "user/class/user.class.php:3633|check|if (getDolGlobalString(''LDAP_FIELD_PASSWORD_CRYPTED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_PHONE', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that holds the user''s phone number for synchronization.', 'Written in admin/ldap_users.php:98, displayed and used in UI at :293 and :295; mapped to $this->attr_phone in core/class/ldap.class.php:303 and used in user/card.php:785.', 'Setting the correct LDAP attribute ensures the user phone number is properly imported from LDAP. An incorrect value leaves phone empty after sync.', 'String LDAP attribute name (e.g. ''telephoneNumber''); empty = no phone attribute mapped', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:303|read|$this->attr_phone      = getDolGlobalString(''LDAP_FIELD_PHONE'');", "admin/ldap_users.php:98|write|if (!dolibarr_set_const($db, ''LDAP_FIELD_PHONE'', GETPOST(\"fieldphone\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:785|read|$ldap_phone = $attribute[getDolGlobalString(''LDAP_FIELD_PHONE'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_SID', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s Windows Security Identifier (SID).', 'Configured via admin/ldap_users.php (written at line 125, displayed at line 363). It can be selected as the LDAP key field (line 365). Used in user/card.php:789 to read the SID attribute from LDAP, and in user.class.php:3876 when building the info array.', 'Changing this value redirects SID reads and writes to a different LDAP attribute; selecting it as the key field makes SID the primary lookup key for user synchronisation.', 'Any valid LDAP attribute name (e.g. ''sambaSID'', ''objectSid'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:125|write|dolibarr_set_const($db, ''LDAP_FIELD_SID'', GETPOST(\"fieldsid\")", "admin/ldap_users.php:365|read|getDolGlobalString(''LDAP_KEY_USERS'') == getDolGlobalString(''LDAP_FIELD_SID'') ? '' checked''", "user/card.php:789|read|$ldap_sid = $attribute[getDolGlobalString(''LDAP_FIELD_SID'')];", "user/class/user.class.php:3876|read|$tmpvar = getDolGlobalString(''LDAP_FIELD_SID'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_SKYPE', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s Skype identifier.', 'Referenced in admin/ldap_users.php:494 (passed to the LDAP read function) and user/card.php:959 (passed when displaying the user card). No admin write occurrence is shown in the payload.', 'Changing this value redirects Skype data to a different LDAP attribute; clearing it disables Skype field synchronisation.', 'Any valid LDAP attribute name (e.g. ''skypeHandle'').', 0, 0, 'admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:494|read|getDolGlobalString(''LDAP_FIELD_SKYPE''),", "user/card.php:959|read|getDolGlobalString(''LDAP_FIELD_SKYPE''),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_TITLE', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s job title.', 'Configured via admin/ldap_users.php (written at line 128, displayed at line 349). Used in admin/ldap_users.php:497, user/card.php:757 and 961 when reading/displaying LDAP user data, and in user/class/user.class.php:3879 when building the LDAP info array.', 'Changing this value redirects job-title data to a different LDAP attribute; clearing it disables title synchronisation.', 'Any valid LDAP attribute name (e.g. ''title'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:128|write|dolibarr_set_const($db, ''LDAP_FIELD_TITLE'', GETPOST(\"fieldtitle\")", "admin/ldap_users.php:497|read|getDolGlobalString(''LDAP_FIELD_TITLE''),", "user/card.php:757|read|getDolGlobalString(''LDAP_FIELD_TITLE''),", "user/class/user.class.php:3879|read|$tmpvar = getDolGlobalString(''LDAP_FIELD_TITLE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_TOWN', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s town/city.', 'Configured via admin/ldap_users.php (written at line 116, displayed at line 335). In user/class/user.class.php:3588-3589, used to populate the town attribute in the LDAP entry when the user has a town.', 'Changing this value redirects town data to a different LDAP attribute; clearing it disables town synchronisation to LDAP.', 'Any valid LDAP attribute name (e.g. ''l'', ''localityName'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:116|write|dolibarr_set_const($db, ''LDAP_FIELD_TOWN'', GETPOST(\"fieldtown\")", "user/class/user.class.php:3588|check|if ($this->town && getDolGlobalString(''LDAP_FIELD_TOWN'')) {", "user/class/user.class.php:3589|read|$info[getDolGlobalString(''LDAP_FIELD_TOWN'')] = $this->town;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_USERID', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s numeric UID (uidNumber).', 'Configured via admin/ldap_users.php (written at line 134, displayed at line 377). In user/class/user.class.php:3662-3663, when set, the Dolibarr user ID ($this->id) is written under this LDAP attribute.', 'Changing this value redirects UID data to a different LDAP attribute; clearing it disables UID synchronisation.', 'Any valid LDAP attribute name (e.g. ''uidNumber'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:134|write|dolibarr_set_const($db, ''LDAP_FIELD_USERID'', GETPOST(\"fielduserid\")", "user/class/user.class.php:3662|check|if (getDolGlobalString(''LDAP_FIELD_USERID'')) {", "user/class/user.class.php:3663|read|$info[getDolGlobalString(''LDAP_FIELD_USERID'')] = $this->id;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FIELD_ZIP', 'string', NULL, 'admin', 'Specifies the LDAP attribute name that stores the user''s postal code.', 'Configured via admin/ldap_users.php (written at line 113, displayed at line 328). In user/class/user.class.php:3585-3586, used to populate the zip attribute in the LDAP entry when the user has a zip code.', 'Changing this value redirects postal-code data to a different LDAP attribute; clearing it disables postal-code synchronisation to LDAP.', 'Any valid LDAP attribute name (e.g. ''postalCode'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:113|write|dolibarr_set_const($db, ''LDAP_FIELD_ZIP'', GETPOST(\"fieldzip\")", "user/class/user.class.php:3585|check|if ($this->zip && getDolGlobalString(''LDAP_FIELD_ZIP'')) {", "user/class/user.class.php:3586|read|$info[getDolGlobalString(''LDAP_FIELD_ZIP'')] = $this->zip;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_FILTER_CONNECTION', 'string', NULL, 'admin', 'Defines the LDAP filter string applied when searching for users during authentication and synchronization.', 'Written in admin/ldap_users.php:71, displayed in the UI at :220. Applied in core/class/ldap.class.php:293 as $this->filter and used in user/card.php:1595 to build a compound search filter.', 'Changing this filter restricts or broadens which LDAP entries are matched during user lookup and import. An incorrect filter can block all LDAP authentication.', 'LDAP filter string (e.g. ''(objectClass=person)''); empty = no additional filter applied', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:293|read|$this->filter              = getDolGlobalString(''LDAP_FILTER_CONNECTION''); // Filter on user", "admin/ldap_users.php:71|write|if (!dolibarr_set_const($db, ''LDAP_FILTER_CONNECTION'', GETPOST(\"filterconnection\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:1595|read|$userSearchFilter = ''('' . getDolGlobalString(''LDAP_FILTER_CONNECTION'').''(''.$ldap->getUserIdentifier().''=''.$object->login.''))'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_DN', 'string', NULL, 'admin', 'LDAP Distinguished Name (DN) of the directory branch used to search for groups.', 'Written via admin/ldap_groups.php:65 and read at lines 147, 237, 245, 339 in the same file, as well as user/group/ldap.php:139. Used as the base DN parameter in ldap->getRecords() calls at admin/ldap_groups.php:317. Configurable via admin/ldap_groups.php.', 'Changing this value redirects all LDAP group lookups to a different directory branch; an incorrect DN will cause group synchronisation to fail.', 'LDAP DN string, e.g. ''ou=groups,dc=example,dc=com''. Empty = LDAP group search disabled.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:65|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_DN'', GETPOST(\"group\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_groups.php:317|read|$ldapgroups = $ldap->getRecords(''*'', getDolGlobalString(''LDAP_GROUP_DN''), getDolGlobalString(''LDAP_KEY_GROUPS''), $required_fields, ''group'');", "admin/ldap_groups.php:237|read|$dn = getDolGlobalString(''LDAP_GROUP_DN'');", "user/group/ldap.php:139|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPGroupDn\").''</td><td class=\"valeur\">''.getDolGlobalString(''LDAP_GROUP_DN'').\"</td></tr>\\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FIELD_DESCRIPTION', 'string', NULL, 'admin', 'Name of the LDAP attribute mapped to the Dolibarr user group description/note.', 'Written via admin/ldap_groups.php:78 and read at lines 200, 202, 308. Used in user/class/usergroup.class.php:971-972 where, if set and $this->note is non-empty, the group''s note is written to the LDAP attribute named by this constant. Configurable via admin/ldap_groups.php.', 'Changing this value remaps which LDAP attribute receives the group description during synchronisation; leaving it unset skips writing the description attribute.', 'LDAP attribute name string, e.g. ''description''. Empty = attribute not written.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:78|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_FIELD_DESCRIPTION'', GETPOST(\"fielddescription\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "user/class/usergroup.class.php:971|check|if ($this->note && getDolGlobalString(''LDAP_GROUP_FIELD_DESCRIPTION'')) {", "user/class/usergroup.class.php:972|read|$info[getDolGlobalString(''LDAP_GROUP_FIELD_DESCRIPTION'')] = dol_string_nohtmltag($this->note, 2);", "admin/ldap_groups.php:200|read|print ''<input size=\"25\" type=\"text\" name=\"fielddescription\" value=\"''.getDolGlobalString(''LDAP_GROUP_FIELD_DESCRIPTION'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FIELD_FULLNAME', 'string', NULL, 'admin', 'Name of the LDAP attribute mapped to the Dolibarr user group full name.', 'Written via admin/ldap_groups.php:74 and read at lines 184 and 186. Used in user/class/usergroup.class.php:967-968 where, if set and $this->name is non-empty, the group''s name is written to the LDAP attribute named by this constant. Configurable via admin/ldap_groups.php.', 'Changing this value remaps which LDAP attribute receives the group''s full name during synchronisation; leaving it unset skips writing the full-name attribute.', 'LDAP attribute name string, e.g. ''cn''. Empty = attribute not written.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:74|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_FIELD_FULLNAME'', GETPOST(\"fieldfullname\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "user/class/usergroup.class.php:967|check|if ($this->name && getDolGlobalString(''LDAP_GROUP_FIELD_FULLNAME'')) {", "user/class/usergroup.class.php:968|read|$info[getDolGlobalString(''LDAP_GROUP_FIELD_FULLNAME'')] = $this->name;", "admin/ldap_groups.php:184|read|print ''<input size=\"25\" type=\"text\" name=\"fieldfullname\" value=\"''.getDolGlobalString(''LDAP_GROUP_FIELD_FULLNAME'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FIELD_GROUPID', 'string', NULL, 'admin', 'Maps the Dolibarr group ID to the corresponding LDAP attribute name used as the group''s numeric identifier.', 'Set via admin/ldap_groups.php:84 and displayed at line 214; read in admin/ldap_groups.php:310 and checked in core/triggers/interface_50_modLdap_Ldapsynchro.class.php:288 and user/group/ldap.php:80 where it is used to detect missing gidNumber for posixGroup entries. Written via user/class/usergroup.class.php:985.', 'Changing this value changes which LDAP attribute is used to store the group''s numeric ID during synchronisation.', 'Any valid LDAP attribute name string, e.g. ''gidNumber''.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_groups.php:84|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_FIELD_GROUPID'', GETPOST(\"fieldgroupid\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:288|check|if (empty($info[getDolGlobalString(''LDAP_GROUP_FIELD_GROUPID'')]) && in_array(''posixGroup'', $info[''objectclass''])) {", "user/class/usergroup.class.php:984|check|if (getDolGlobalString(''LDAP_GROUP_FIELD_GROUPID'')) {", "user/class/usergroup.class.php:985|read|$info[getDolGlobalString(''LDAP_GROUP_FIELD_GROUPID'')] = $this->id;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FIELD_GROUPMEMBERS', 'string', NULL, 'admin', 'Name of the LDAP attribute that stores the list of members for a group entry.', 'Written via admin/ldap_groups.php:81 and read at lines 207, 209, 309. Used in user/class/usergroup.class.php:974-982 where, if set, member values are collected and written to the LDAP attribute named by this constant. Configurable via admin/ldap_groups.php.', 'Changing this value remaps which LDAP attribute stores group membership; an incorrect value will prevent member lists from being written to or read from LDAP correctly.', 'LDAP attribute name string, e.g. ''member'' or ''memberUid''. Empty = group members not synchronised.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:81|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_FIELD_GROUPMEMBERS'', GETPOST(\"fieldgroupmembers\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "user/class/usergroup.class.php:974|check|if (getDolGlobalString(''LDAP_GROUP_FIELD_GROUPMEMBERS'')) {", "user/class/usergroup.class.php:982|read|$info[getDolGlobalString(''LDAP_GROUP_FIELD_GROUPMEMBERS'')] = (!empty($valueofldapfield) ? $valueofldapfield : '''');", "admin/ldap_groups.php:207|read|print ''<input size=\"25\" type=\"text\" name=\"fieldgroupmembers\" value=\"''.getDolGlobalString(''LDAP_GROUP_FIELD_GROUPMEMBERS'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FIELD_NAME', 'string', NULL, 'admin', 'Name of the LDAP attribute mapped to the Dolibarr user group short name (currently commented out and not actively used).', 'The COMMENTS show that all write and read usages of this constant are commented out: admin/ldap_groups.php:77 (''//if (! dolibarr_set_const(...)''), admin/ldap_groups.php:307 (''// getDolGlobalString(...)''), and user/class/usergroup.class.php:970 (''//if ($this->name && !empty(...)''). The UI still renders the field at line 192 using $conf->global->LDAP_GROUP_FIELD_NAME directly.', 'Because all functional usages are commented out, changing this value has no effect on LDAP synchronisation in the current codebase.', 'LDAP attribute name string. Currently unused in active code paths.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["//if (! dolibarr_set_const($db, ''LDAP_GROUP_FIELD_NAME'',GETPOST(\"fieldname\", ''alphanohtml''),''chaine'',0,'''',$conf->entity)) $error++;", "// getDolGlobalString(''LDAP_GROUP_FIELD_NAME''),", "//if ($this->name && !empty($conf->global->LDAP_GROUP_FIELD_NAME)) $info[$conf->global->LDAP_GROUP_FIELD_NAME] = $this->name;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_FILTER', 'string', NULL, 'admin', 'LDAP search filter applied when querying group entries from the directory.', 'Written via admin/ldap_groups.php:71 and read at line 163 (admin UI input). Also read in core/class/ldap.class.php:294 with the inline comment ''// Filter on groups'', where it is assigned to $this->filtergroup. Configurable via admin/ldap_groups.php.', 'Changing this value modifies which LDAP entries are returned in group searches; an invalid filter syntax will cause LDAP group queries to fail.', 'LDAP filter string, e.g. ''(objectClass=groupOfNames)''. Empty = no filter applied.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/ldap.class.php:294|read|$this->filtergroup         = getDolGlobalString(''LDAP_GROUP_FILTER''); // Filter on groups", "admin/ldap_groups.php:71|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_FILTER'', GETPOST(\"filter\"), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_groups.php:163|read|print ''<input size=\"48\" type=\"text\" name=\"filter\" value=\"''.getDolGlobalString(''LDAP_GROUP_FILTER'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_GROUP_OBJECT_CLASS', 'string', NULL, 'admin', 'LDAP object class used to identify and filter group entries in the directory.', 'Written via admin/ldap_groups.php:68 and read at lines 155, 238, 246. Also used in user/class/usergroup.class.php:964 where it is exploded by comma into an array for the ''objectclass'' LDAP attribute. Configurable via admin/ldap_groups.php.', 'Changing this value alters which LDAP entries are treated as groups; an incorrect value will prevent group records from being found or written correctly.', 'LDAP object class string, e.g. ''groupOfNames'' or ''posixGroup''. Comma-separated values are supported.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:68|write|if (!dolibarr_set_const($db, ''LDAP_GROUP_OBJECT_CLASS'', GETPOST(\"objectclass\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_groups.php:238|read|$objectclass = getDolGlobalString(''LDAP_GROUP_OBJECT_CLASS'');", "user/class/usergroup.class.php:964|read|$info[\"objectclass\"] = explode('','', getDolGlobalString(''LDAP_GROUP_OBJECT_CLASS''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_CONTACTS', 'string', NULL, 'admin', 'Specifies the LDAP field used as the unique key (RDN) for contact entries when synchronising with LDAP.', 'Configured via admin/ldap_contacts.php (write at line 116, radio-button selection at lines 195–237) and consumed in contact/class/contact.class.php:806 to build the distinguished name for a contact LDAP entry.', 'Changing this value changes which LDAP attribute is used as the RDN when creating or updating contact entries in the LDAP directory.', 'One of: LDAP_CONTACT_FIELD_FULLNAME, LDAP_CONTACT_FIELD_NAME, LDAP_CONTACT_FIELD_FIRSTNAME, LDAP_CONTACT_FIELD_COMPANY, LDAP_CONTACT_FIELD_MAIL, LDAP_CONTACT_FIELD_PHONE, LDAP_CONTACT_FIELD_HOMEPHONE.', 0, 0, 'admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php|admin/ldap_contacts.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_contacts.php:116|write|if (!dolibarr_set_const($db, ''LDAP_KEY_CONTACTS'', $valkey, ''chaine'', 0, '''', $conf->entity)) {", "contact/class/contact.class.php:806|read|$dn = getDolGlobalString(''LDAP_KEY_CONTACTS'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_CONTACTS'')].\",.\" . getDolGlobalString(''LDAP_CONTACT_DN'');", "admin/ldap_contacts.php:195|read|print ''<td class=\"right\"><input type=\"radio\" name=\"key\" value=\"LDAP_CONTACT_FIELD_FULLNAME\"''.(getDolGlobalString(''LDAP_KEY_CONTACTS'') && getDolGlobalString(''LDAP_KEY_CONTACTS'') =="]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_GROUPS', 'string', NULL, 'admin', 'Name of the LDAP attribute used as the unique key when searching and identifying groups.', 'Written via admin/ldap_groups.php:94 and read extensively across that file (lines 186, 202, 209, 306, 317) as the key parameter passed to ldap->getRecords(). The radio-button UI at lines 186-209 lets admins choose among LDAP_GROUP_FIELD_FULLNAME, LDAP_GROUP_FIELD_DESCRIPTION, etc. Configurable via admin/ldap_groups.php.', 'Changing this value alters which LDAP attribute is used to uniquely identify groups; an incorrect value will break group lookup and synchronisation.', 'LDAP attribute name string selected from the configured group field constants (e.g. ''cn'', ''description''). Must match an actual LDAP attribute present on group entries.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap_groups.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_groups.php:317|read|$ldapgroups = $ldap->getRecords(''*'', getDolGlobalString(''LDAP_GROUP_DN''), getDolGlobalString(''LDAP_KEY_GROUPS''), $required_fields, ''group'');", "admin/ldap_groups.php:94|write|if (!dolibarr_set_const($db, ''LDAP_KEY_GROUPS'', $valkey, ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_groups.php:306|read|getDolGlobalString(''LDAP_KEY_GROUPS''),", "admin/ldap_groups.php:186|read|print ''<td class=\"right\"><input type=\"radio\" name=\"key\" value=\"LDAP_GROUP_FIELD_FULLNAME\"''.((getDolGlobalString(''LDAP_KEY_GROUPS'') == getDolGlobalString(''LDAP_GROUP_FIELD_FULLNAME''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_MEMBERS', 'string', NULL, 'admin', 'Defines the LDAP field used as the unique key (RDN) when building the distinguished name for member entries.', 'Stores the name of the LDAP attribute selected as the member entry key, such as the full name, login, or email field. Used in adherents/class/adherent.class.php to construct the DN and in core/triggers/interface_50_modLdap_Ldapsynchro.class.php for synchronisation. Configured via admin/ldap_members.php.', 'Changing this value alters which LDAP attribute is used as the entry identifier for all member LDAP operations. An incorrect value will cause LDAP sync to fail.', 'LDAP attribute constant name, e.g. LDAP_MEMBER_FIELD_FULLNAME, LDAP_MEMBER_FIELD_NAME, LDAP_MEMBER_FIELD_LOGIN, LDAP_MEMBER_FIELD_LOGIN_SAMBA, LDAP_MEMBER_FIELD_MAIL', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:161|write|if (!dolibarr_set_const($db, ''LDAP_KEY_MEMBERS'', $valkey, ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:2941|read|$dn = getDolGlobalString(''LDAP_KEY_MEMBERS'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_MEMBERS'')]\".\" . getDolGlobalString(''LDAP_MEMBER_DN'');", "adherents/class/adherent.class.php:2995|check|if (getDolGlobalString(''LDAP_KEY_MEMBERS'') && getDolGlobalString(''LDAP_KEY_MEMBERS'') == getDolGlobalString($constname)) {", "admin/ldap_members.php:449|read|$key = getDolGlobalString(''LDAP_KEY_MEMBERS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_MEMBERS_TYPES', 'string', NULL, 'admin', 'Specifies the LDAP naming/key attribute used to identify member-type entries in the directory.', 'Written in admin/ldap_members_types.php:87 and read in :171, :178, :185, :205, and adherents/class/adherent_type.class.php:1159 and :1165 to construct LDAP distinguished names for member types. Also displayed in adherents/type_ldap.php:118.', 'Changing this value alters which LDAP attribute is used as the key for member-type DN construction; an incorrect value will break LDAP synchronization for member types.', 'Any valid LDAP attribute name string (e.g. ''LDAP_MEMBER_TYPE_FIELD_FULLNAME'', ''LDAP_MEMBER_TYPE_FIELD_DESCRIPTION'', ''LDAP_MEMBER_TYPE_FIELD_GROUPMEMBERS'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:87|write|if (!dolibarr_set_const($db, ''LDAP_KEY_MEMBERS_TYPES'', $valkey, ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1159|read|$dn = getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'')].\",.\" . getDolGlobalString(''LDAP_MEMBER_TYPE_DN'');", "adherents/type_ldap.php:118|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPNamingAttribute\").''</td><td class=\"valeur\">'' . getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_MEMBER_TYPES', 'string', NULL, 'admin', 'Stores the selected LDAP field key used to map Dolibarr member types to LDAP attributes.', 'Read in the admin UI at admin/ldap_members_types.php:178 as a radio-button selection among LDAP field options (e.g. LDAP_MEMBER_TYPE_FIELD_DESCRIPTION). Only one admin UI occurrence is present in the payload.', 'Changing this value alters which LDAP attribute Dolibarr uses when synchronising member type data to the directory; an incorrect value will cause mapping failures.', 'String; a valid LDAP field key constant such as LDAP_MEMBER_TYPE_FIELD_DESCRIPTION.', 0, 0, 'admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ldap_members_types.php:178|read|print ''<td class=\"right\"><input type=\"radio\" name=\"key\" value=\"LDAP_MEMBER_TYPE_FIELD_DESCRIPTION\"''.((getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'') && getDolGlobalString(''LDAP_KEY_M"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_KEY_USERS', 'string', NULL, 'admin', 'Specifies the LDAP attribute used as the unique key when searching and synchronising user records.', 'Configured via admin/ldap_users.php (written at line 150). It is passed as the key field to ldap->getRecords (line 507) and compared against each candidate field (LDAP_FIELD_FULLNAME, LDAP_FIELD_NAME, LDAP_FIELD_LOGIN, etc.) to mark the selected radio button in the admin UI. A commented-out alternative filter usage is preserved at line 506.', 'Changing this value alters which LDAP attribute is used to look up and match users; selecting an attribute absent in the LDAP schema will break user import and synchronisation.', 'The value of one of the configured LDAP field constants (e.g. the value stored in LDAP_FIELD_LOGIN, LDAP_FIELD_FULLNAME, etc.).', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:507|read|$ldapusers = $ldap->getRecords(''*'', getDolGlobalString(''LDAP_USER_DN''), getDolGlobalString(''LDAP_KEY_USERS''), $required_fields, 1);", "admin/ldap_users.php:506  // $filter = ''(''.ldap_escape(getDolGlobalString(''LDAP_KEY_USERS''), '''', LDAP_ESCAPE_FILTER).''=*)''", "admin/ldap_users.php:239|read|getDolGlobalString(''LDAP_KEY_USERS'') == getDolGlobalString(''LDAP_FIELD_FULLNAME'') ? '' checked''", "admin/ldap_users.php:150|write|dolibarr_set_const($db, ''LDAP_KEY_USERS'', $valkey, ''chaine'', 0, '''', $conf->entity)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_ACTIVE', 'string', NULL, 'core', 'Controls whether and in which direction member data is synchronised between Dolibarr and the LDAP directory.', 'Checked extensively in core/triggers/interface_50_modLdap_Ldapsynchro.class.php to gate member sync operations; compared against Ldap::SYNCHRO_DOLIBARR_TO_LDAP to determine sync direction. Configurable via admin/ldap.php using a select form.', 'Enabling sync causes member create/update/delete events in Dolibarr to be propagated to the LDAP directory; disabling it stops all automatic member synchronisation.', 'Integer: value corresponding to Ldap::SYNCHRO_DOLIBARR_TO_LDAP enables Dolibarr-to-LDAP sync; 0 or empty disables sync.', 0, 0, 'admin/ldap.php|admin/ldap_members.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modLdap_Ldapsynchro.class.php:449|check|if (getDolGlobalString(''LDAP_MEMBER_ACTIVE'') && getDolGlobalInt(''LDAP_MEMBER_ACTIVE'') == Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {", "admin/ldap.php:183|read|print $formldap->selectLdapDnSynchroActive(getDolGlobalInt(''LDAP_MEMBER_ACTIVE''), ''activemembers'', array(), 2);", "admin/ldap.php:110|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_ACTIVE'', GETPOST(\"activemembers\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_members.php:446|check|if (getDolGlobalString(''LDAP_MEMBER_ACTIVE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_DN', 'string', NULL, 'adherents', 'Defines the LDAP Distinguished Name (DN) base path where member entries are stored.', 'Holds the DN string used as the base for member LDAP entries, e.g. ''ou=members,dc=example,dc=com''. Used in adherents/class/adherent.class.php to build the full entry DN and in adherents/ldap.php for display. Configured via admin/ldap_members.php.', 'Setting this to the correct LDAP branch ensures member records are created and searched in the right location. An incorrect value will cause LDAP operations on members to target the wrong directory branch.', 'LDAP DN string, e.g. ''ou=members,dc=example,dc=com''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:64|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_DN'', GETPOST(\"user\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:2941|read|$dn = getDolGlobalString(''LDAP_KEY_MEMBERS'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_MEMBERS'')].\",\" . getDolGlobalString(''LDAP_MEMBER_DN'');", "adherents/class/adherent.class.php:2944|read|$dn = getDolGlobalString(''LDAP_MEMBER_DN'');", "adherents/ldap.php:153|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPMemberDn\").''</td><td class=\"valeur\">''.getDolGlobalString(''LDAP_MEMBER_DN'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_', 'string', NULL, 'adherents', 'Dynamic prefix used to map member social network values to LDAP attribute names (e.g. LDAP_MEMBER_FIELD_TWITTER).', 'The code builds a constant name at runtime by appending the uppercased social network label to this prefix, then writes the corresponding social network value to the LDAP attribute named by the result. No admin UI; must be set directly in the database.', 'Setting LDAP_MEMBER_FIELD_<NETWORK> (e.g. LDAP_MEMBER_FIELD_TWITTER) enables the corresponding social network field to be synchronised to LDAP for member entries.', 'LDAP attribute name string; constant name is LDAP_MEMBER_FIELD_ + uppercased social network label', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3024|check|if ($this->socialnetworks[$value[''label'']] && getDolGlobalString(''LDAP_MEMBER_FIELD_''.strtoupper($value[''label'']))) {", "adherents/class/adherent.class.php:3025|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_''.strtoupper($value[''label'']))] = $this->socialnetworks[$value[''label'']];"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_ADDRESS', 'string', NULL, 'adherents', 'Maps the member address to its corresponding LDAP attribute name.', 'When set, the member''s address value is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the address field to be synchronised to LDAP. Leaving it empty suppresses address sync.', 'LDAP attribute name string, e.g. ''postalAddress''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:113|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_ADDRESS'', GETPOST(\"fieldaddress\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3011|check|if ($this->address && getDolGlobalString(''LDAP_MEMBER_FIELD_ADDRESS'')) {", "adherents/class/adherent.class.php:3012|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_ADDRESS'')] = $this->address;"]', 'medium', NULL);
