INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_NOTE_PUBLIC', 'string', NULL, 'adherents', 'Maps the member public note to its corresponding LDAP attribute name.', 'When set, the member''s note_public value (stripped of HTML) is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the public note to be synchronised to LDAP. Leaving it empty suppresses this field from LDAP sync.', 'LDAP attribute name string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:128|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_NOTE_PUBLIC'', GETPOST(\"fieldnotepublic\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3043|check|if ($this->note_public && getDolGlobalString(''LDAP_MEMBER_FIELD_NOTE_PUBLIC'')) {", "adherents/class/adherent.class.php:3044|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_NOTE_PUBLIC'')] = dol_string_nohtmltag($this->note_public, 2);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_PASSWORD', 'string', NULL, 'adherents', 'Maps the member''s unencrypted password to its corresponding LDAP attribute name.', 'When set, the member''s plain-text password (pass or pass_indatabase) is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this causes the unencrypted password to be stored in the named LDAP attribute on sync. This should only be used when the LDAP server itself handles hashing.', 'LDAP attribute name string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3079|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD'')] = $this->pass_indatabase; // $this->pass_indatabase = Unencrypted password", "adherents/class/adherent.class.php:3059|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD'')] = $this->pass; // this->pass = Unencrypted password", "admin/ldap_members.php:83|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_PASSWORD'', GETPOST(\"fieldpassword\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3058|check|if (getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_PASSWORD_CRYPTED', 'string', NULL, 'adherents', 'Maps the member''s crypted password to its corresponding LDAP attribute name.', 'When set, the member''s hashed password is written to the LDAP attribute named by this constant during sync, using OpenLDAP password hash format. Configured via admin/ldap_members.php.', 'Setting this enables synchronisation of a hashed password to LDAP using the dol_hash openldap scheme. Leaving it empty suppresses crypted password sync.', 'LDAP attribute name string, e.g. ''userPassword''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3062|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD_CRYPTED'')] = dol_hash($this->pass, ''openldap''); // Create OpenLDAP password (see LDAP_PASSWORD_HASH_TYPE)", "adherents/class/adherent.class.php:3073|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD_CRYPTED'')] = dolGetLdapPasswordHash($this->pass_indatabase_crypted, ''md5frommd5'');", "admin/ldap_members.php:86|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_PASSWORD_CRYPTED'', GETPOST(\"fieldpasswordcrypted\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3061|check|if (getDolGlobalString(''LDAP_MEMBER_FIELD_PASSWORD_CRYPTED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_PHONE', 'string', NULL, 'adherents', 'Maps the member office phone number to its corresponding LDAP attribute name.', 'When set, the member''s phone value is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the office phone number to be synchronised to LDAP. Leaving it empty suppresses phone sync.', 'LDAP attribute name string, e.g. ''telephoneNumber''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:98|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_PHONE'', GETPOST(\"fieldphone\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3028|check|if ($this->phone && getDolGlobalString(''LDAP_MEMBER_FIELD_PHONE'')) {", "adherents/class/adherent.class.php:3029|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PHONE'')] = $this->phone;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_PHONE_PERSO', 'string', NULL, 'adherents', 'Maps the member personal phone number to its corresponding LDAP attribute name.', 'When set, the member''s phone_perso value is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the personal phone number to be synchronised to LDAP. Leaving it empty suppresses personal phone sync.', 'LDAP attribute name string, e.g. ''homePhone''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:101|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_PHONE_PERSO'', GETPOST(\"fieldphoneperso\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3031|check|if ($this->phone_perso && getDolGlobalString(''LDAP_MEMBER_FIELD_PHONE_PERSO'')) {", "adherents/class/adherent.class.php:3032|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_PHONE_PERSO'')] = $this->phone_perso;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_TITLE', 'string', NULL, 'adherents', 'Maps the member job title/position to its corresponding LDAP attribute name.', 'When set, the member''s poste (position/title) value is written to the LDAP attribute named by this constant during sync. No admin UI; must be set directly in the database.', 'Setting this enables the member''s position field to be synchronised to LDAP. Leaving it empty suppresses that field from LDAP sync.', 'LDAP attribute name string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:3005|check|if ($this->poste && getDolGlobalString(''LDAP_MEMBER_FIELD_TITLE'')) {", "adherents/class/adherent.class.php:3006|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_TITLE'')] = $this->poste;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_TOWN', 'string', NULL, 'adherents', 'Maps the member town/city to its corresponding LDAP attribute name.', 'When set, the member''s town value is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the town field to be synchronised to LDAP. Leaving it empty suppresses town sync.', 'LDAP attribute name string, e.g. ''l''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:119|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_TOWN'', GETPOST(\"fieldtown\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3017|check|if ($this->town && getDolGlobalString(''LDAP_MEMBER_FIELD_TOWN'')) {", "adherents/class/adherent.class.php:3018|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_TOWN'')] = $this->town;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FIELD_ZIP', 'string', NULL, 'adherents', 'Maps the member postal code to its corresponding LDAP attribute name.', 'When set, the member''s zip/postal code value is written to the LDAP attribute named by this constant during sync. Configured via admin/ldap_members.php.', 'Setting this enables the postal code to be synchronised to LDAP. Leaving it empty suppresses zip code sync.', 'LDAP attribute name string, e.g. ''postalCode''', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:116|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FIELD_ZIP'', GETPOST(\"fieldzip\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:3014|check|if ($this->zip && getDolGlobalString(''LDAP_MEMBER_FIELD_ZIP'')) {", "adherents/class/adherent.class.php:3015|read|$info[getDolGlobalString(''LDAP_MEMBER_FIELD_ZIP'')] = $this->zip;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_FILTER', 'string', NULL, 'admin', 'Defines the LDAP filter string applied when searching for member entries during member synchronization.', 'Written in admin/ldap_members.php:70, displayed in UI at :229. Applied in core/class/ldap.class.php:295 as $this->filtermember.', 'Changing this filter restricts which LDAP entries are matched during member import/sync. An incorrect filter can prevent member synchronization.', 'LDAP filter string (e.g. ''(objectClass=inetOrgPerson)''); empty = no additional filter applied for members', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:295|read|$this->filtermember        = getDolGlobalString(''LDAP_MEMBER_FILTER''); // Filter on member", "admin/ldap_members.php:70|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_FILTER'', GETPOST(\"filterconnection\"), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap_members.php:229|read|print ''<input size=\"48\" type=\"text\" name=\"filterconnection\" value=\"'' . getDolGlobalString(''LDAP_MEMBER_FILTER'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_OBJECT_CLASS', 'string', NULL, 'admin', 'Defines the LDAP objectClass value(s) assigned to member entries.', 'Holds a comma-separated string of LDAP object class names applied to member entries when they are created or updated. Used in adherents/class/adherent.class.php. Configured via admin/ldap_members.php.', 'Setting this to valid LDAP object class names ensures member entries conform to the directory schema. An incorrect value will cause LDAP write operations to fail schema validation.', 'Comma-separated LDAP object class names string', 0, 0, 'admin/ldap_members.php|admin/ldap_members.php|admin/ldap_members.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members.php:67|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_OBJECT_CLASS'', GETPOST(\"objectclass\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent.class.php:2970|read|$info[\"objectclass\"] = explode('','', getDolGlobalString(''LDAP_MEMBER_OBJECT_CLASS''));", "admin/ldap_members.php:451|read|$objectclass = getDolGlobalString(''LDAP_MEMBER_OBJECT_CLASS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_ACTIVE', 'string', NULL, 'core', 'Controls the synchronization direction between Dolibarr member types and LDAP.', 'Compared against Ldap::SYNCHRO_DOLIBARR_TO_LDAP across admin/ldap_members_types.php:202 and multiple trigger points in core/triggers/interface_50_modLdap_Ldapsynchro.class.php (lines 460, 578, 696, 735, 759). Configurable via admin/ldap.php:113.', 'Changing this value enables or disables automatic push of member type changes from Dolibarr to LDAP when triggers fire.', 'Value equal to Ldap::SYNCHRO_DOLIBARR_TO_LDAP = sync from Dolibarr to LDAP enabled; other values = sync disabled.', 0, 0, 'admin/ldap_members_types.php|admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modLdap_Ldapsynchro.class.php:460|check|if (getDolGlobalString(''LDAP_MEMBER_TYPE_ACTIVE'') && getDolGlobalInt(''LDAP_MEMBER_TYPE_ACTIVE'') === Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {", "admin/ldap_members_types.php:202|check|if (getDolGlobalInt(''LDAP_MEMBER_TYPE_ACTIVE'') === Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {", "admin/ldap.php:113|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_ACTIVE'', GETPOST(\"activememberstypes\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:578|check|if (getDolGlobalString(''LDAP_MEMBER_TYPE_ACTIVE'') && getDolGlobalInt(''LDAP_MEMBER_TYPE_ACTIVE'') === Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_DN', 'string', NULL, 'adherents', 'Specifies the LDAP Distinguished Name (DN) base path for member-type entries.', 'Written in admin/ldap_members_types.php:64 and read in :140, :206, adherents/class/adherent_type.class.php:1159 and :1162, and displayed in adherents/type_ldap.php:115.', 'Changing this value redirects LDAP member-type operations to a different DN; an incorrect value will cause LDAP member-type synchronization to fail.', 'Any valid LDAP distinguished name string (e.g. ''ou=membertypes,dc=example,dc=com'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:64|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_DN'', GETPOST(\"membertype\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1159|read|$dn = getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'') . \"=\".$info[getDolGlobalString(''LDAP_KEY_MEMBERS_TYPES'')].\",.\" . getDolGlobalString(''LDAP_MEMBER_TYPE_DN'');", "adherents/class/adherent_type.class.php:1162|read|$dn = getDolGlobalString(''LDAP_MEMBER_TYPE_DN'');", "adherents/type_ldap.php:115|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPMemberTypeDn\").''</td><td class=\"valeur\">'' . getDolGlobalString(''LDAP_MEMBER_TYPE_DN'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_FIELD_DESCRIPTION', 'string', NULL, 'admin', 'Specifies the LDAP attribute name used to store the description/public note of a member type.', 'Written in admin/ldap_members_types.php:74, displayed in :176 and :178, and applied in adherents/class/adherent_type.class.php:1194-1195 to map the member-type public note to the LDAP attribute.', 'Changing this value remaps which LDAP attribute receives the member-type public note during synchronization.', 'Any valid LDAP attribute name string (e.g. ''description'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:74|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_FIELD_DESCRIPTION'', GETPOST(\"fielddescription\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1194|check|if ($this->note_public && getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_DESCRIPTION'')) {", "adherents/class/adherent_type.class.php:1195|read|$info[getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_DESCRIPTION'')] = dol_string_nohtmltag($this->note_public, 0, ''UTF-8'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_FIELD_FULLNAME', 'string', NULL, 'admin', 'Specifies the LDAP attribute name used to store the full name of a member type.', 'Written in admin/ldap_members_types.php:71, displayed in :169 and :171, and applied in adherents/class/adherent_type.class.php:1191-1192 to map the member-type label to the LDAP attribute.', 'Changing this value remaps which LDAP attribute receives the member-type label during synchronization.', 'Any valid LDAP attribute name string (e.g. ''cn'', ''displayName'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:71|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_FIELD_FULLNAME'', GETPOST(\"fieldfullname\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1191|check|if ($this->label && getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_FULLNAME'')) {", "adherents/class/adherent_type.class.php:1192|read|$info[getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_FULLNAME'')] = $this->label;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_FIELD_GROUPMEMBERS', 'string', NULL, 'admin', 'Specifies the LDAP attribute name used to store the list of members within a member type.', 'Written in admin/ldap_members_types.php:77, displayed in :183 and :185, and applied in adherents/class/adherent_type.class.php:1197 and :1205 to populate the LDAP group-members attribute.', 'Changing this value remaps which LDAP attribute receives the list of members for a member-type group during synchronization.', 'Any valid LDAP attribute name string (e.g. ''member'', ''uniqueMember'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:77|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_FIELD_GROUPMEMBERS'', GETPOST(\"fieldmembertypemembers\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1197|check|if (getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_GROUPMEMBERS'')) {", "adherents/class/adherent_type.class.php:1205|read|$info[getDolGlobalString(''LDAP_MEMBER_TYPE_FIELD_GROUPMEMBERS'')] = (!empty($valueofldapfield) ? $valueofldapfield : '''');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_MEMBER_TYPE_OBJECT_CLASS', 'string', NULL, 'admin', 'Specifies the LDAP objectClass value(s) for member-type entries.', 'Written in admin/ldap_members_types.php:67, displayed in :148, used in :207, and applied as a comma-separated list in adherents/class/adherent_type.class.php:1184.', 'Changing this value alters the objectClass attribute set on member-type LDAP entries during synchronization.', 'Comma-separated list of LDAP objectClass names (e.g. ''groupOfNames,top'')', 0, 0, 'admin/ldap_members_types.php|admin/ldap_members_types.php|admin/ldap_members_types.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap_members_types.php:67|write|if (!dolibarr_set_const($db, ''LDAP_MEMBER_TYPE_OBJECT_CLASS'', GETPOST(\"objectclass\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/class/adherent_type.class.php:1184|read|$info[\"objectclass\"] = explode('','', getDolGlobalString(''LDAP_MEMBER_TYPE_OBJECT_CLASS''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_PASSWORD_HASH_TYPE', 'string', NULL, 'core', 'Specifies the hashing algorithm used when storing or verifying LDAP passwords.', 'Configured in admin/ldap.php and read in core/lib/security.lib.php:316-318 with a default of ''md5'' when absent. The value is passed to dolGetLdapPasswordHash().', 'Changing this value alters the password hashing algorithm for LDAP authentication; a mismatch with existing stored hashes will break LDAP login.', 'A string identifying the hash algorithm, e.g. ''md5'' (default), or other values supported by dolGetLdapPasswordHash().', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/security.lib.php:316|read|return array(''pass_encrypted'' => dolGetLdapPasswordHash($chain, getDolGlobalString(''LDAP_PASSWORD_HASH_TYPE'', ''md5'')), ''pass_encoding'' => ''ldappasswordhash''", "core/lib/security.lib.php:318|read|return dolGetLdapPasswordHash($chain, getDolGlobalString(''LDAP_PASSWORD_HASH_TYPE'', ''md5''));", "admin/ldap.php:116|write|if (!dolibarr_set_const($db, ''LDAP_PASSWORD_HASH_TYPE'', GETPOST(\"LDAP_PASSWORD_HASH_TYPE\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "admin/ldap.php:249|read|print $formldap->selectLdapPasswordHashType(getDolGlobalString(''LDAP_PASSWORD_HASH_TYPE''), ''LDAP_PASSWORD_HASH_TYPE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SEND_EMPTY_MEMBERS_TO_GROUP', 'string', NULL, 'core', 'Controls whether empty member lists are sent to LDAP group entries during synchronisation.', 'Checked in core/triggers/interface_50_modLdap_Ldapsynchro.class.php at lines 293, 313, and 338; when not set, empty member arrays are suppressed from the LDAP update; when set, empty member lists and null member sets are included.', 'When set, LDAP group entries receive an empty member attribute, which may clear existing members; when not set, empty member lists are not transmitted to LDAP.', 'Empty/unset = empty member lists suppressed; non-empty = empty member lists sent to LDAP.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modLdap_Ldapsynchro.class.php:293|check|if (isset($info[''member'']) && empty($info[''member'']) && !getDolGlobalString(''LDAP_SEND_EMPTY_MEMBERS_TO_GROUP'')) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:313|check|if ($object->members === null && getDolGlobalString(''LDAP_SEND_EMPTY_MEMBERS_TO_GROUP'')) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:338|check|if (isset($info[''member'']) && empty($info[''member'']) && !getDolGlobalString(''LDAP_SEND_EMPTY_MEMBERS_TO_GROUP'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_DN', 'string', NULL, 'admin', 'Specifies the base Distinguished Name (DN) of the LDAP server used for directory operations.', 'Assigned to both $ldap->dn and $ldap->domain in core/class/ldap.class.php when the LDAP connection is initialized. Configurable via the admin UI at admin/ldap.php and saved via dolibarr_set_const.', 'Changing this value alters the root search base and domain used for all LDAP directory queries; an incorrect DN will break directory connectivity.', 'A valid LDAP DN string, e.g. ''dc=example,dc=com''.', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:284|read|$this->dn = getDolGlobalString(''LDAP_SERVER_DN'');", "core/class/ldap.class.php:287|read|$this->domain = getDolGlobalString(''LDAP_SERVER_DN'');", "admin/ldap.php:239|read|print ''<input class=\"minwidth300\" type=\"text\" name=\"dn\" value=\"''.getDolGlobalString(''LDAP_SERVER_DN'').''\">'';", "admin/ldap.php:92|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_DN'', GETPOST(\"dn\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_HOST', 'string', NULL, 'core', 'Hostname or IP address of the primary LDAP server.', 'Stored and read as the primary server address; added to the server list in core/class/ldap.class.php:277 ($this->server[]). Connection is only attempted when the value is non-empty (core/class/ldap.class.php:276). Configurable via admin/ldap.php.', 'Changing or clearing this value redirects or disables the primary LDAP connection; all LDAP-dependent features (login, sync) will fail if the host is unreachable.', 'String: hostname or IP address of the LDAP server (e.g. ''ldap.example.com'' or ''192.168.1.10'').', 0, 0, 'admin/ldap.php|admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/ldap.class.php:276|check|if (getDolGlobalString(''LDAP_SERVER_HOST'')) {", "core/class/ldap.class.php:277|read|$this->server[] = getDolGlobalString(''LDAP_SERVER_HOST'');", "admin/ldap.php:83|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_HOST'', GETPOST(\"host\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "contact/ldap.php:135|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPPrimaryServer\").''</td><td class=\"valeur\" colspan=\"3\">''.getDolGlobalString(''LDAP_SERVER_HOST'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_HOST_SLAVE', 'string', NULL, 'adherents', 'Hostname or IP address of the secondary (slave/replica) LDAP server.', 'When non-empty, added to the LDAP server list in core/class/ldap.class.php:280 as a fallback server. Configurable via admin/ldap.php and displayed in several LDAP info pages.', 'Setting this value enables a secondary LDAP server for failover; clearing it removes the fallback, leaving only the primary server.', 'String: hostname or IP address of the secondary LDAP server (e.g. ''ldap2.example.com'').', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/ldap.class.php:279|check|if (getDolGlobalString(''LDAP_SERVER_HOST_SLAVE'')) {", "core/class/ldap.class.php:280|read|$this->server[] = getDolGlobalString(''LDAP_SERVER_HOST_SLAVE'');", "admin/ldap.php:86|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_HOST_SLAVE'', GETPOST(\"slave\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)) {", "contact/ldap.php:136|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPSecondaryServer\").''</td><td class=\"valeur\" colspan=\"3\">''.getDolGlobalString(''LDAP_SERVER_HOST_SLAVE'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_PORT', 'string', NULL, 'admin', 'TCP port number used to connect to the LDAP server.', 'Used when establishing the LDAP TCP connection; displayed in connection success/failure messages at admin/ldap.php:295-331. The default shown in the admin UI input is ''389''. Configurable via admin/ldap.php.', 'Changing this port affects all LDAP connections; an incorrect port will cause connection failures for all LDAP-dependent features.', 'Integer as string: TCP port number (default ''389'' for plain LDAP; ''636'' for LDAPS).', 0, 0, 'admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap.php:234|read|print ''<input class=\"width75\" type=\"text\" name=\"port\" value=\"''.getDolGlobalString(''LDAP_SERVER_PORT'', ''389'').''\">'';", "admin/ldap.php:295|read|print ''<span class=\"ok\">''.$langs->trans(\"LDAPTCPConnectOK\", $ldap->connectedServer, getDolGlobalString(''LDAP_SERVER_PORT'')).''</span>'';", "admin/ldap.php:89|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_PORT'', GETPOSTINT(\"port\"), ''chaine'', 0, '''', $conf->entity)) {", "adherents/ldap.php:163|read|print ''<tr><td>LDAP ''.$langs->trans(\"LDAPServerPort\").''</td><td class=\"valeur\">''.getDolGlobalString(''LDAP_SERVER_PORT'').\"</td></tr>\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_PROTOCOLVERSION', 'string', NULL, 'adherents', 'Specifies the LDAP protocol version used when connecting to the LDAP server.', 'Stored as a string and assigned to the ldapProtocolVersion property of the LDAP connection object in core/class/ldap.class.php. Also governs conditional logic in adherents/class/adherent.class.php and user/class/user.class.php. Configured via admin/ldap.php.', 'Changing this value alters the protocol version negotiated with the LDAP server. Setting it to a version not supported by the server will cause connection failures.', 'Protocol version string, e.g. ''2'' or ''3''', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/ldap.class.php:283|read|$this->ldapProtocolVersion = getDolGlobalString(''LDAP_SERVER_PROTOCOLVERSION'');", "adherents/class/adherent.class.php:3064|read|} elseif (getDolGlobalString(''LDAP_SERVER_PROTOCOLVERSION'') !== ''3'') {", "admin/ldap.php:80|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_PROTOCOLVERSION'', GETPOST(\"LDAP_SERVER_PROTOCOLVERSION\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "user/class/user.class.php:3618|read|} elseif (getDolGlobalString(''LDAP_SERVER_PROTOCOLVERSION'') !== ''3'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_TYPE', 'string', NULL, 'core', 'Specifies the type of LDAP server (e.g. standard LDAP, Active Directory, eGroupware) for authentication and synchronisation.', 'Controls LDAP-specific behaviour throughout the stack. Checked in core/login/functions_ldap.php:191 for ''activedirectory'' to adjust bind logic, in contact/class/contact.class.php:895 for ''egroupware'', and in core/triggers/interface_50_modLdap_Ldapsynchro.class.php:227 for sync direction. Configurable via admin/ldap.php.', 'Changing this value alters how Dolibarr authenticates users and synchronises data with the LDAP server; an incorrect type will break LDAP login or sync.', 'String: ''openldap'' (standard LDAP), ''activedirectory'' (Microsoft Active Directory), ''egroupware''.', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/login/functions_ldap.php:191|check|if (getDolGlobalString(''LDAP_SERVER_TYPE'') == \"activedirectory\") {", "contact/class/contact.class.php:895|check|if (getDolGlobalString(''LDAP_SERVER_TYPE'') == ''egroupware'') {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:227|check|if (getDolGlobalInt(\"LDAP_SYNCHRO_ACTIVE\") === Ldap::SYNCHRO_DOLIBARR_TO_LDAP && getDolGlobalString(''LDAP_SERVER_TYPE'') == \"activedirectory\") {", "admin/ldap.php:74|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_TYPE'', GETPOST(\"type\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SERVER_USE_TLS', 'bool', NULL, 'admin', 'Enables TLS encryption for the LDAP server connection.', 'When set to a truthy value, the LDAP class activates TLS on the connection (core/class/ldap.class.php:393). Configurable via a yes/no select in the admin UI at admin/ldap.php and stored via dolibarr_set_const.', 'Enabling TLS secures the LDAP connection; disabling it leaves the connection unencrypted.', 'Non-empty (truthy) enables TLS; empty or ''0'' disables it.', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/ldap.class.php:393|check|if (getDolGlobalString(''LDAP_SERVER_USE_TLS'')) {", "admin/ldap.php:244|read|print $form->selectyesno(''usetls'', getDolGlobalInt(''LDAP_SERVER_USE_TLS''), 1);", "admin/ldap.php:101|write|if (!dolibarr_set_const($db, ''LDAP_SERVER_USE_TLS'', GETPOST(\"usetls\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_SYNCHRO_ACTIVE', 'string', NULL, 'core', 'Determines the active LDAP synchronisation direction globally (Dolibarr-to-LDAP, LDAP-to-Dolibarr, or disabled).', 'Set via admin/ldap.php:104 and displayed at line 166; checked extensively across admin/ldap_groups.php, admin/ldap_users.php, and core/triggers/interface_50_modLdap_Ldapsynchro.class.php to gate all LDAP synchronisation trigger logic for users, groups, and contacts.', 'Changing this value enables, disables, or reverses the global LDAP synchronisation direction, affecting whether all object changes are pushed to or pulled from LDAP.', 'One of the Ldap::SYNCHRO_* constants (e.g. Ldap::SYNCHRO_DOLIBARR_TO_LDAP, Ldap::SYNCHRO_LDAP_TO_DOLIBARR); empty/unset = synchronisation disabled.', 0, 0, 'admin/ldap_groups.php|admin/ldap_groups.php|admin/ldap.php|admin/ldap.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap.php:104|write|if (!dolibarr_set_const($db, ''LDAP_SYNCHRO_ACTIVE'', GETPOST(\"activesynchro\", ''aZ09''), ''chaine'', 0, '''', $conf->entity)) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:87|check|if (getDolGlobalString(''LDAP_SYNCHRO_ACTIVE'') && getDolGlobalInt(''LDAP_SYNCHRO_ACTIVE'') === Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {", "admin/ldap_groups.php:233|check|if (getDolGlobalInt(''LDAP_SYNCHRO_ACTIVE'') === Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {", "admin/ldap_users.php:410|check|if (getDolGlobalString(''LDAP_SYNCHRO_ACTIVE'') == Ldap::SYNCHRO_DOLIBARR_TO_LDAP) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_USERACCOUNTCONTROL', 'string', NULL, 'admin', 'Stores the userAccountControl value to set on LDAP user entries when synchronising users to Active Directory.', 'Set via admin/ldap.php:77 with a displayed default of 512; read in admin/ldap.php:212 and assigned to $info[''userAccountControl''] in core/triggers/interface_50_modLdap_Ldapsynchro.class.php:97 during user sync.', 'Changing this value alters the userAccountControl flags written to Active Directory user entries during synchronisation.', 'An integer string representing an Active Directory userAccountControl bitmask; default display value is ''512'' (normal account).', 0, 0, 'admin/ldap.php|admin/ldap.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ldap.php:212|read|print ''<input class=\"width75\" type=\"text\" name=\"userAccountControl\" value=\"''.getDolGlobalString(''LDAP_USERACCOUNTCONTROL'', ''512'').''\">'';", "admin/ldap.php:77|write|if (!dolibarr_set_const($db, ''LDAP_USERACCOUNTCONTROL'', GETPOSTINT(\"userAccountControl\"), ''chaine'', 0, '''', $conf->entity)) {", "core/triggers/interface_50_modLdap_Ldapsynchro.class.php:97|read|$info[''userAccountControl''] = getDolGlobalString(''LDAP_USERACCOUNTCONTROL'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_USER_DN', 'string', NULL, 'admin', 'Specifies the LDAP Distinguished Name (DN) of the branch where user entries are stored.', 'Used as the base DN when searching for or synchronizing user records in the LDAP directory. Read by both admin/ldap_users.php (for listing and sync operations) and user/card.php (for individual user lookups). Configurable via the admin UI at admin/ldap_users.php.', 'Changing this value redirects all LDAP user lookups and synchronization operations to the specified DN; an incorrect value will cause user queries to fail.', 'A valid LDAP DN string, e.g. ''ou=users,dc=example,dc=com''.', 0, 0, 'admin/ldap.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:507|read|$ldapusers = $ldap->getRecords(''*'', getDolGlobalString(''LDAP_USER_DN''), getDolGlobalString(''LDAP_KEY_USERS''), $required_fields, 1);", "admin/ldap.php:168|check|if (getDolGlobalString(''LDAP_SYNCHRO_ACTIVE'') && !getDolGlobalString(''LDAP_USER_DN'')) {", "admin/ldap_users.php:65|write|if (!dolibarr_set_const($db, ''LDAP_USER_DN'', GETPOST(\"user\"), ''chaine'', 0, '''', $conf->entity)) {", "user/card.php:774|read|$ldapusers = $ldap->getRecords($selecteduser, getDolGlobalString(''LDAP_USER_DN''), getDolGlobalString(''LDAP_KEY_USERS''), $required_fields);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LDAP_USER_OBJECT_CLASS', 'string', NULL, 'admin', 'Specifies the LDAP objectClass value(s) used to identify user entries in the LDAP directory.', 'Configured via admin/ldap_users.php (written at line 68, displayed at line 212). In user/class/user.class.php:3546 the value is split by comma and assigned to the ''objectclass'' attribute when building the LDAP user entry.', 'Changing this value alters the objectClass set on LDAP user records created or updated by Dolibarr; an incorrect value will cause LDAP write operations to fail.', 'Comma-separated LDAP objectClass names (e.g. ''inetOrgPerson,posixAccount'').', 0, 0, 'admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php|admin/ldap_users.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ldap_users.php:68|write|dolibarr_set_const($db, ''LDAP_USER_OBJECT_CLASS'', GETPOST(\"objectclass\")", "user/class/user.class.php:3546|read|$info[\"objectclass\"] = explode('','', getDolGlobalString(''LDAP_USER_OBJECT_CLASS''));", "admin/ldap_users.php:212|read|print ''<input size=\"48\" type=\"text\" name=\"objectclass\" value=\"''.getDolGlobalString(''LDAP_USER_OBJECT_CLASS'').''\">''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LIST_OF_QUALIFIED_INVOICES_LIMIT_DEFINED', 'string', NULL, 'compta', 'Sets a SQL LIMIT on the number of qualified invoices retrieved in a situation invoice query.', 'Used only in compta/facture/class/facture.class.php:5427 and :5430. When the integer value is greater than 0, it is applied as a database row limit via plimit().', 'Setting a positive integer limits the situation invoice list query result set; leaving it unset or at 0 applies no limit.', '0 or empty = no limit applied; positive integer = maximum number of qualified invoices returned', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:5427|check|if (getDolGlobalInt(''LIST_OF_QUALIFIED_INVOICES_LIMIT_DEFINED'') > 0) {", "compta/facture/class/facture.class.php:5430|read|$sql .= $this->db->plimit(getDolGlobalInt(''LIST_OF_QUALIFIED_INVOICES_LIMIT_DEFINED''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LOAN_ACCOUNTING_ACCOUNT_CAPITAL', 'string', NULL, 'accountancy', 'Specifies the accounting account code for loan capital repayment entries in the treasury journal and loan card.', 'Read in accountancy/journal/treasuryjournal.php:844 with fallback ''NotDefined'', and used as the default account in loan/card.php:379 when no POST value is provided. No admin UI is configured.', 'If unset, loan capital entries in the treasury journal use the reserved string ''NotDefined'', resulting in unresolved accounting entries.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/treasuryjournal.php:844|read|$account_pay_loan_capital = getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_CAPITAL'', ''NotDefined''); // NotDefined is a reserved word", "loan/card.php:379|read|print $formaccounting->select_account(GETPOST(''accountancy_account_capital'') ? GETPOST(''accountancy_account_capital'') : getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_CAPITAL'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LOAN_ACCOUNTING_ACCOUNT_INSURANCE', 'string', NULL, 'accountancy', 'Specifies the accounting account code for loan insurance payment entries in the treasury journal and loan card.', 'Read in accountancy/journal/treasuryjournal.php:846 with fallback ''NotDefined'', and used as the default account in loan/card.php:385 when no POST value is provided. No admin UI is configured.', 'If unset, loan insurance entries in the treasury journal use the reserved string ''NotDefined'', resulting in unresolved accounting entries.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/treasuryjournal.php:846|read|$account_pay_loan_insurance = getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_INSURANCE'', ''NotDefined''); // NotDefined is a reserved word", "loan/card.php:385|read|print $formaccounting->select_account(GETPOST(''accountancy_account_insurance'') ? GETPOST(''accountancy_account_insurance'') : getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_INSURANCE'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LOAN_ACCOUNTING_ACCOUNT_INTEREST', 'string', NULL, 'accountancy', 'Specifies the accounting account code for loan interest repayment entries in the treasury journal and loan card.', 'Read in accountancy/journal/treasuryjournal.php:845 with fallback ''NotDefined'', and used as the default account in loan/card.php:391 when no POST value is provided. No admin UI is configured.', 'If unset, loan interest entries in the treasury journal use the reserved string ''NotDefined'', resulting in unresolved accounting entries.', 'A chart-of-accounts code string; ''NotDefined'' is the reserved fallback used when the constant is absent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/treasuryjournal.php:845|read|$account_pay_loan_interest = getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_INTEREST'', ''NotDefined''); // NotDefined is a reserved word", "loan/card.php:391|read|print $formaccounting->select_account(GETPOST(''accountancy_account_interest'') ? GETPOST(''accountancy_account_interest'') : getDolGlobalString(''LOAN_ACCOUNTING_ACCOUNT_INTEREST'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('LOT_ADVANCED_MASK', 'string', NULL, 'product', 'Defines the global mask pattern used for advanced lot number generation when no product-specific mask is set.', 'Read in core/modules/product_batch/mod_lot_advanced.php at lines 71 and 153 as the primary mask. Also read in product/card.php at lines 1562 and 2179 as the inherited mask, with line 2174 preferring the product''s own batch_mask when available.', 'Changing this mask changes the format of automatically generated lot numbers for all products that do not override it with a product-specific mask.', 'string (mask pattern); empty = no auto-generation pattern', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/product_batch/mod_lot_advanced.php:71|read|$mask = getDolGlobalString(''LOT_ADVANCED_MASK'');", "core/modules/product_batch/mod_lot_advanced.php:153|read|$mask = getDolGlobalString(''LOT_ADVANCED_MASK'');", "product/card.php:2174|check|$mask = !empty($object->batch_mask) ? $object->batch_mask : getDolGlobalString(''LOT_ADVANCED_MASK'');", "product/card.php:1562|read|$inherited_mask_lot = getDolGlobalString(''LOT_ADVANCED_MASK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_CONTACT_DEFAULT_BULK_STATUS', 'string', NULL, 'societe', 'Sets the default bulk email opt-out status applied to new contacts when the emailing module is enabled.', 'Written in admin/mailing.php:95 and displayed in admin/mailing.php:208 for configuration. Read in contact/card.php:856 as default value for the no_email field on new contact forms. The COMMENTS confirm: ''Default value is in MAILING_CONTACT_DEFAULT_BULK_STATUS that you can modify in setup of module emailing''.', 'Changing this value alters the pre-selected opt-out status for all newly created contacts. A value of 2 triggers additional JavaScript behavior on the contact creation form.', 'Integer stored as string; 0 = opted-in by default, 1 = opted-out by default, 2 = opted-out with additional UI enforcement (value 2 triggers JS).', 0, 0, 'admin/mailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/card.php:855  // Default value is in MAILING_CONTACT_DEFAULT_BULK_STATUS that you can modify in setup of module emailing", "contact/card.php:833|check|if ($conf->use_javascript_ajax && getDolGlobalInt(''MAILING_CONTACT_DEFAULT_BULK_STATUS'') == 2) {", "admin/mailing.php:95|write|$res = dolibarr_set_const($db, \"MAILING_CONTACT_DEFAULT_BULK_STATUS\", $contactbulkdefault, ''chaine'', 0, '''', $conf->entity);", "contact/card.php:856|read|print $form->selectyesno(''no_email'', (GETPOSTISSET(\"no_email\") ? GETPOSTINT(\"no_email\") : getDolGlobalInt(''MAILING_CONTACT_DEFAULT_BULK_STATUS'')), 1, false, (int) (getDolGlobalInt("]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_DELAY', 'string', NULL, 'comm', 'Sets a delay in seconds between each email sent during a mailing campaign.', 'Written via admin/mailing.php:91 and read in comm/mailing/card.php:447-448. The value is cast to float and used as argument to usleep() (multiplied by 1,000,000 to convert seconds to microseconds). The log entry confirms: ''Wait a delay of MAILING_DELAY=''.', 'Increasing the delay slows the mailing send rate, which can help avoid being flagged as spam or overloading an SMTP server. Setting to 0 or empty disables the inter-email delay.', 'A numeric value in seconds (float accepted); 0 or empty = no delay between emails', 0, 0, 'admin/mailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:447|read|dol_syslog(\"Wait a delay of MAILING_DELAY=\".((float) $conf->global->MAILING_DELAY));", "comm/mailing/card.php:448|read|usleep((int) ((float) $conf->global->MAILING_DELAY * 1000000));", "admin/mailing.php:91|write|$res = dolibarr_set_const($db, \"MAILING_DELAY\", $mailingdelay, ''chaine'', 0, '''', $conf->entity);", "comm/mailing/card.php:446|check|if (getDolGlobalString(''MAILING_DELAY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_EMAIL_ERRORSTO', 'string', NULL, 'admin', 'Sets the email address to which mailing delivery errors (bounces) should be reported.', 'Written via admin/mailing.php:87 and read in both admin/mailing.php:174 (UI display) and comm/mailing/card.php:899 as the default for the ''errorsto'' field. Validated as a correct email format before saving.', 'Changing this value redirects delivery error notifications to a different address. An invalid email format is rejected by the admin UI.', 'A valid email address string; empty = no specific error recipient configured', 0, 0, 'admin/mailing.php|admin/mailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mailing.php:87|write|$res = dolibarr_set_const($db, \"MAILING_EMAIL_ERRORSTO\", $mailerror, ''chaine'', 0, '''', $conf->entity);", "admin/mailing.php:175|check|if (getDolGlobalString(''MAILING_EMAIL_ERRORSTO'') && !isValidEmail(getDolGlobalString(''MAILING_EMAIL_ERRORSTO''))) {", "admin/mailing.php:174|read|print ''<input class=\"minwidth100\" type=\"text\" name=\"MAILING_EMAIL_ERRORSTO\" value=\"'' . getDolGlobalString(''MAILING_EMAIL_ERRORSTO'') . ''\">'';", "comm/mailing/card.php:899|read|print ''<td>''.img_picto('''', ''email'', ''class=\"pictofixedwidth\"'').''<input class=\"flat minwidth200\" name=\"errorsto\" value=\"''.getDolGlobalString(''MAILING_EMAIL_ERRORSTO'', getDolGlobalSt"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_EMAIL_FROM', 'string', 'no-reply@mydomain.tld', 'public', 'Sets the default sender email address for mass mailing campaigns.', 'Written via admin/mailing.php:83 and read in multiple files including comm/mailing/card.php:893, public/payment/paymentok.php:2274, public/project/suggestbooth.php:545, and public/eventorganization/attendee_new.php:691. Validated as a correct email format before saving.', 'Changing this value updates the From address used in mailing campaigns and public event emails. An invalid email format is rejected by the admin UI.', 'A valid email address string; default ''no-reply@mydomain.tld'' when unset', 0, 0, 'admin/mailing.php|admin/mailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mailing.php:83|write|$res = dolibarr_set_const($db, \"MAILING_EMAIL_FROM\", $mailfrom, ''chaine'', 0, '''', $conf->entity);", "admin/mailing.php:165|check|if (getDolGlobalString(''MAILING_EMAIL_FROM'') && !isValidEmail(getDolGlobalString(''MAILING_EMAIL_FROM''))) {", "public/payment/paymentok.php:2274|read|$from = getDolGlobalString(''MAILING_EMAIL_FROM'', getDolGlobalString(\"MAIN_MAIL_EMAIL_FROM\"));", "public/project/suggestbooth.php:545|read|$from = getDolGlobalString(''MAILING_EMAIL_FROM'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_EMAIL_REPLYTO', 'string', NULL, 'comm', 'Sets the default Reply-To email address for mailing campaigns.', 'Read once in comm/mailing/card.php:902 as the default for the ''replyto'' input field. Falls back to MAIN_MAIL_REPLY_TO when not set, as shown by the getDolGlobalString fallback pattern.', 'Setting this value pre-populates the Reply-To field in mailing campaigns. Leaving it empty causes the system to fall back to MAIN_MAIL_REPLY_TO.', 'A valid email address string; empty = falls back to MAIN_MAIL_REPLY_TO', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:902|read|print ''<td>''.img_picto('''', ''email'', ''class=\"pictofixedwidth\"'').''<input class=\"flat minwidth200\" name=\"replyto\" value=\"''.getDolGlobalString(''MAILING_EMAIL_REPLYTO'', getDolGlobalStri"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_EMAIL_UNSUBSCRIBE_KEY', 'string', NULL, 'comm', 'Stores the secret key used to generate and verify HMAC security tokens for mailing unsubscribe and read-tracking links.', 'Set via admin/mailing.php:105 and displayed at line 195; used in public/emailing/mailing-unsubscribe.php:79 and public/emailing/mailing-read.php:114 to validate the securitykey parameter, and in multiple admin and core files to construct __CHECK_READ__ and __UNSUBSCRIBE_URL__ substitution values.', 'Changing this value invalidates all previously generated unsubscribe and read-tracking links that used the old key.', 'Any non-empty string; used as the base for dol_hash(key.''-''.tag.''-''.email.''-''.mtid, ''md5'').', 0, 0, 'admin/mailing.php|admin/mails.php|admin/mails_emailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mailing.php:105|write|$res = dolibarr_set_const($db, \"MAILING_EMAIL_UNSUBSCRIBE_KEY\", $checkread_key, ''chaine'', 0, '''', $conf->entity);", "public/emailing/mailing-unsubscribe.php:79|check|if ($securitykey != dol_hash(getDolGlobalString(''MAILING_EMAIL_UNSUBSCRIBE_KEY'').\"-\".$tag.\"-\".$email.\"-\".$mtid, ''md5'')) {", "public/emailing/mailing-read.php:114|check|if ($securitykey != dol_hash(getDolGlobalString(''MAILING_EMAIL_UNSUBSCRIBE_KEY'').\"-\".$tag.\"-\".$email.\"-\".$mtid, ''md5'')) {", "core/tpl/card_presend.tpl.php:330|read|$checkRead .= ''&securitykey=''.(getDolGlobalString(''MAILING_EMAIL_UNSUBSCRIBE_KEY'') ? urlencode(getDolGlobalString(''MAILING_EMAIL_UNSUBSCRIBE_KEY'')) : \"\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_LIMIT_SENDBYCLI', 'string', NULL, 'comm', 'Controls whether sending emails via CLI is allowed and sets no numeric cap when undefined or 0.', 'Defined in conf.php (not via the admin UI) via $dolibarr_main_mailing_limit_sendbycli. Checked in comm/mailing/card.php:1058 before allowing CLI-based mailing sends. When not set or >= 0, sending is permitted; when set to -1, sending via CLI is forbidden.', 'Setting to -1 forbids all CLI-based email sending. Leaving undefined or set to 0 imposes no limit on CLI sends.', '-1=forbidden, 0 or undefined=no limit', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T10:47:32+00:00', '["comm/mailing/card.php:1007  // MAILING_LIMIT_SENDBYCLI may be defined or not (-1=forbidden, 0 or undefined=no limit).", "comm/mailing/card.php:1058|check|if (!isset($conf->global->MAILING_LIMIT_SENDBYCLI) || getDolGlobalInt(''MAILING_LIMIT_SENDBYCLI'') >= 0) {"]', 'low', '$dolibarr_main_mailing_limit_sendbycli (conf.php) → ${conf->global->MAILING_LIMIT_SENDBYCLI}');
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_LIMIT_SENDBYDAY', 'string', NULL, 'comm', 'Sets a daily cap on the number of emails sent; 0 or undefined means no daily limit.', 'Defined in conf.php (not via the admin UI) via $dolibarr_main_mailing_limit_sendbyday. Checked in comm/mailing/card.php:1051 and used to display a warning at card.php:1052 when the daily limit applies.', 'When set to a positive integer, a warning is shown indicating the daily send limit. When 0 or undefined, no daily limit is enforced.', '0 or undefined=no limit', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T10:47:32+00:00', '["comm/mailing/card.php:1008  // MAILING_LIMIT_SENDBYDAY may be defined or not (0 or undefined=no limit).", "comm/mailing/card.php:1051|check|if (getDolGlobalInt(''MAILING_LIMIT_SENDBYDAY'') > 0) {", "comm/mailing/card.php:1052|read|$text .= $langs->trans(''WarningLimitSendByDay'', getDolGlobalInt(''MAILING_LIMIT_SENDBYDAY''));"]', 'low', '$dolibarr_main_mailing_limit_sendbyday (conf.php) → ${conf->global->MAILING_LIMIT_SENDBYDAY}');
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_LIMIT_SENDBYWEB', 'string', '25', 'comm', 'Limits the number of recipients allowed per web-triggered mailing send; -1 forbids sending via web entirely.', 'Defined in conf.php (not via the admin UI) via $dolibarr_main_mailing_limit_sendbyweb, though it can also be written through the admin UI at admin/mailing.php (admin/mailing.php:99). Checked in multiple places including core/tpl/massactions_pre.tpl.php:357 and comm/mailing/card.php:1530 to restrict recipient count during web-based sends. The comment notes it is always defined to something != 0, and can also be set to ''default''.', 'When set to -1, web-based sending is forbidden. When set to a positive integer, sends exceeding that recipient count are blocked with a warning.', '-1=forbidden', 0, 0, 'admin/mailing.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T10:47:32+00:00', '["comm/mailing/card.php:1006  // MAILING_LIMIT_SENDBYWEB is always defined to something != 0 (-1=forbidden).", "comm/mailing/card.php:1529  // MAILING_LIMIT_SENDBYWEB can be ''default''", "core/tpl/massactions_pre.tpl.php:357|check|if (getDolGlobalString(''MAILING_LIMIT_SENDBYWEB'') && count($listofselectedrecipientobjid) > $conf->global->MAILING_LIMIT_SENDBYWEB) {", "admin/mailing.php:99|write|$res = dolibarr_set_const($db, \"MAILING_LIMIT_SENDBYWEB\", $batchlimit, ''chaine'', 1, '''', 0);"]', 'high', '$dolibarr_main_mailing_limit_sendbyweb (conf.php) → ${conf->global->MAILING_LIMIT_SENDBYWEB}');
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_LIMIT_WARNING_NOPHPMAIL', 'string', NULL, 'comm', 'Stores a translation key for a warning message displayed when the mailing send mode is not PHP mail().', 'Checked in comm/mailing/card.php at lines 1030 and 1045, both conditioned on sendingmode != ''mail''. The value is passed to $langs->transnoentitiesnoconv() and shown as a warning event message.', 'Setting this to a valid translation key causes a warning to appear on the mailing page when a non-PHP-mail sending mode is active. Clearing it suppresses the warning.', 'A translation key string whose translated value is shown as a warning when sendingmode is not ''mail''; empty = no warning', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1030|check|if (getDolGlobalString(''MAILING_LIMIT_WARNING_NOPHPMAIL'') && $sendingmode != ''mail'') {", "comm/mailing/card.php:1031|read|setEventMessages($langs->transnoentitiesnoconv($conf->global->MAILING_LIMIT_WARNING_NOPHPMAIL), null, ''warnings'');", "comm/mailing/card.php:1045|check|if (getDolGlobalString(''MAILING_LIMIT_WARNING_NOPHPMAIL'') && $sendingmode != ''mail'') {", "comm/mailing/card.php:1046|read|setEventMessages($langs->transnoentitiesnoconv($conf->global->MAILING_LIMIT_WARNING_NOPHPMAIL), null, ''warnings'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_LIMIT_WARNING_PHPMAIL', 'string', NULL, 'comm', 'Stores a translation key for a warning message displayed when the mailing send mode is PHP mail().', 'Checked in comm/mailing/card.php at lines 1027 and 1042, both conditioned on sendingmode == ''mail''. The value is passed to $langs->transnoentitiesnoconv() and shown as a warning event message.', 'Setting this to a valid translation key causes a warning to appear on the mailing page when PHP mail() is the active sending mode. Clearing it suppresses the warning.', 'A translation key string whose translated value is shown as a warning when sendingmode is ''mail''; empty = no warning', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1027|check|if (getDolGlobalString(''MAILING_LIMIT_WARNING_PHPMAIL'') && $sendingmode == ''mail'') {", "comm/mailing/card.php:1028|read|setEventMessages($langs->transnoentitiesnoconv($conf->global->MAILING_LIMIT_WARNING_PHPMAIL), null, ''warnings'');", "comm/mailing/card.php:1042|check|if (getDolGlobalString(''MAILING_LIMIT_WARNING_PHPMAIL'') && $sendingmode == ''mail'') {", "comm/mailing/card.php:1043|read|setEventMessages($langs->transnoentitiesnoconv($conf->global->MAILING_LIMIT_WARNING_PHPMAIL), null, ''warnings'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_NO_USING_PHPMAIL', 'string', NULL, 'comm', 'Prevents the use of PHP''s built-in mail() function for sending mailing campaigns when EMAILING_MAIL_SENDMODE is ''mail''.', 'The code comment states: ''MAILING_NO_USING_PHPMAIL may be defined or not.'' (comm/mailing/card.php:1005). Checked in both comm/mailing/card.php:1009 and core/class/CMailFile.class.php:886 when the sending mode is ''mail''.', 'Enabling this constant blocks PHP mail() from being used in mailing campaigns even if the send mode is ''mail'', forcing an error or alternative path. Disabling allows PHP mail() to be used.', 'Empty/unset = PHP mail() allowed when sendmode is ''mail''; non-empty = PHP mail() blocked for mailing campaigns', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1005  // MAILING_NO_USING_PHPMAIL may be defined or not.", "comm/mailing/card.php:1009|check|if (getDolGlobalString(''MAILING_NO_USING_PHPMAIL'') && $sendingmode == ''mail'') {", "core/class/CMailFile.class.php:886|check|if ($this->sendcontext == ''emailing'' && getDolGlobalString(''MAILING_NO_USING_PHPMAIL'') && $sendingmode == ''mail'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_SMS_FROM', 'string', NULL, 'comm', 'Sets the default sender phone number or identifier for SMS mailing campaigns.', 'Read once in comm/mailing/card.php:896 as the default value for the ''fromphone'' input field in the mailing card form, used when EMAILINGS_SUPPORT_ALSO_SMS is active.', 'Setting this value pre-populates the SMS sender field in mailing campaigns. Leaving it empty results in no default SMS sender.', 'A phone number or SMS sender identifier string; empty = no default SMS sender', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:896|read|print ''<td>''.img_picto('''', ''email'', ''class=\"pictofixedwidth\"'').''<input class=\"flat minwidth200\" name=\"fromphone\" value=\"''.(GETPOSTISSET(''fromphone'') ? GETPOST(''fromphone'') : getDol"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_SMTP_SETUP_EMAILS_FOR_QUESTIONS', 'string', NULL, 'core', 'Stores an email address displayed in warnings when the SMTP setup requires attention for mailing campaigns.', 'Checked in both comm/mailing/card.php:1022 and core/class/CMailFile.class.php:901. When set, the value is passed to $langs->trans(''MailSendSetupIs3'', ...) to produce a warning message shown to the user and logged as an error.', 'Setting this constant causes a warning with the configured email address to appear when the mailing SMTP setup triggers the MailSendSetupIs3 condition. Clearing it suppresses the warning.', 'An email address string shown in the SMTP setup warning message; empty = no warning displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1022|check|if (getDolGlobalString(''MAILING_SMTP_SETUP_EMAILS_FOR_QUESTIONS'')) {", "comm/mailing/card.php:1023|read|setEventMessages($langs->trans(\"MailSendSetupIs3\", getDolGlobalString(''MAILING_SMTP_SETUP_EMAILS_FOR_QUESTIONS'')), null, ''warnings'');", "core/class/CMailFile.class.php:901|check|if (getDolGlobalString(''MAILING_SMTP_SETUP_EMAILS_FOR_QUESTIONS'')) {", "core/class/CMailFile.class.php:902|read|$this->error .= ''<br>''.$langs->trans(\"MailSendSetupIs3\", getDolGlobalString(''MAILING_SMTP_SETUP_EMAILS_FOR_QUESTIONS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAILING_USE_NEW_PATH_FOR_FILES', 'bool', NULL, 'comm', 'Switches the mailing attachment directory from a legacy 2-level subdirectory layout to a flat (new) path layout.', 'Read in seven locations across comm/mailing/targetemailing.php and comm/mailing/card.php via the pattern: get_exdir($object->id, getDolGlobalInt(''MAILING_USE_NEW_PATH_FOR_FILES'') ? 0 : 2, 0, 1, $object, ''mailing''). When truthy, level=0 (flat); when falsy, level=2 (subdirectory).', 'Enabling this constant moves mailing file storage to the flat path layout; disabling keeps the legacy two-level subdirectory structure. Changing this after mailings have files stored risks broken file references.', 'Non-empty/non-zero = new flat path (level 0). Empty/unset/0 = legacy 2-level path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/targetemailing.php:289|read|$upload_dir = $conf->mailing->dir_output.\"/\".get_exdir($object->id, getDolGlobalInt(''MAILING_USE_NEW_PATH_FOR_FILES'') ? 0 : 2, 0, 1, $object, ''mailing'');", "comm/mailing/card.php:125|read|$upload_dir = $conf->mailing->dir_output.\"/\".get_exdir($object->id, getDolGlobalInt(''MAILING_USE_NEW_PATH_FOR_FILES'') ? 0 : 2, 0, 1, $object, ''mailing'');", "comm/mailing/card.php:635|read|$upload_dir = $conf->mailing->dir_output.\"/\".get_exdir($object->id, getDolGlobalInt(''MAILING_USE_NEW_PATH_FOR_FILES'') ? 0 : 2, 0, 1, $object, ''mailing'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_DISABLE_UTF7_ENCODE_OF_DIR', 'bool', NULL, 'emailcollector', 'Disables UTF-7 encoding of IMAP mailbox folder names in the email collector.', 'Checked in emailcollector/class/emailcollector.class.php at lines 1351, 1795, and 3989; when not set, folder names are encoded to UTF-7 before use in IMAP commands. No admin UI write path is present.', 'Setting this skips UTF-7 encoding of mailbox folder names, which may be needed for servers that do not expect UTF-7 encoded folder names.', '0 or unset = UTF-7 encode folder names; non-zero = skip UTF-7 encoding', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:1351|check|if (!getDolGlobalString(''MAIL_DISABLE_UTF7_ENCODE_OF_DIR'')) {", "emailcollector/class/emailcollector.class.php:1795|check|if (!getDolGlobalString(''MAIL_DISABLE_UTF7_ENCODE_OF_DIR'')) {", "emailcollector/class/emailcollector.class.php:3989|check|if (!getDolGlobalString(''MAIL_DISABLE_UTF7_ENCODE_OF_DIR'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_FORCE_DELIVERY_RECEIPT_INVOICE', 'string', NULL, 'core', 'Forces a delivery receipt request on invoice send emails regardless of user selection.', 'Checked once in core/class/html.formmail.class.php:1448 when the model is ''facture_send''. No admin UI write is present.', 'Enabling this always requests a delivery receipt for invoice emails; disabling it leaves the delivery receipt up to user choice.', 'truthy = force delivery receipt for invoices; empty/not set = user-controlled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:1448|check|if (getDolGlobalString(''MAIL_FORCE_DELIVERY_RECEIPT_INVOICE'') && !empty($this->param[''models'']) && $this->param[''models''] == ''facture_send'') {"]', 'low', NULL);
