INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_FORCE_DELIVERY_RECEIPT_SUPPLIER_PROPOSAL', 'string', NULL, 'core', 'Forces a delivery receipt request on supplier proposal send emails regardless of user selection.', 'Checked once in core/class/html.formmail.class.php:1442 when the model is ''supplier_proposal_send''. No admin UI write is present.', 'Enabling this always requests a delivery receipt for supplier proposal emails; disabling it leaves the delivery receipt up to user choice.', 'truthy = force delivery receipt for supplier proposals; empty/not set = user-controlled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:1442|check|if (getDolGlobalString(''MAIL_FORCE_DELIVERY_RECEIPT_SUPPLIER_PROPOSAL'') && !empty($this->param[''models'']) && $this->param[''models''] == ''supplier_proposal_send'') {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_FROM_EMAILS_TO_CONSIDER_SENDING', 'string', NULL, 'emailcollector', 'Specifies a comma-separated list of email addresses to treat as outgoing sender addresses during email collection.', 'The COMMENT in emailcollector/class/emailcollector.class.php:2740 states ''If sender is in the list MAIL_FROM_EMAILS_TO_CONSIDER_SENDING''. At line 2741, the value is split on commas and trimmed to build an array of sender addresses. No admin UI write path is present.', 'Setting this causes the collector to recognize emails from the listed addresses as outgoing (sent) messages rather than incoming ones.', 'String: comma-separated list of email addresses to treat as outgoing senders', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:2740  // If sender is in the list MAIL_FROM_EMAILS_TO_CONSIDER_SENDING", "emailcollector/class/emailcollector.class.php:2741|read|$arrayofemailtoconsidersender = array_filter(array_map(''trim'', explode('','', getDolGlobalString(''MAIL_FROM_EMAILS_TO_CONSIDER_SENDING''))));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MASS_ACTION_ADD_LAST_IF_MAIN_DOC_NOT_FOUND', 'string', NULL, 'core', 'Attaches the last main document when the primary document is not found during mass-action email sending.', 'Checked in core/class/html.formmail.class.php:924 and core/actions_massactions.inc.php:456. The second check also requires $objectobj->last_main_doc to be non-empty before attaching.', 'Enabling this causes the last available main document to be attached as a fallback; disabling it skips attachment when the primary document is missing.', 'truthy = attach last main doc as fallback; empty/not set = do not attach', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:924|check|if (getDolGlobalString(''MAIL_MASS_ACTION_ADD_LAST_IF_MAIN_DOC_NOT_FOUND'')) {", "core/actions_massactions.inc.php:456|check|if (getDolGlobalString(''MAIL_MASS_ACTION_ADD_LAST_IF_MAIN_DOC_NOT_FOUND'') && !empty($objectobj->last_main_doc)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MASS_ACTION_SEARCH_MOST_RECENT_FILE_IF_NOT_FOUND', 'string', NULL, 'core', 'When enabled, falls back to the most recent matching file if the expected attachment file is not found during a mass-mail action.', 'Checked in core/actions_massactions.inc.php:440; when the integer value is truthy and $filepath is set but does not exist on disk, the system searches for the most recent file instead. No admin UI page is listed.', 'Enabling this constant prevents mass-mail failures caused by missing attachment files by substituting the most recently available matching file.', '1 = search for most recent file as fallback; 0 or unset = missing files are not substituted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_massactions.inc.php:440|check|if (getDolGlobalInt(''MAIL_MASS_ACTION_SEARCH_MOST_RECENT_FILE_IF_NOT_FOUND'') && isset($filepath) && !dol_is_file($filepath)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MAX_NB_OF_RECIPIENTS_BCC_IN_SAME_EMAIL', 'string', NULL, 'core', 'Sets the maximum number of BCC recipients allowed in a single outgoing email.', 'If unset, the code at core/class/CMailFile.class.php:930 writes a default of 10 at runtime. The limit is enforced at line 933 by comparing the BCC recipient count against this value.', 'Lowering this value restricts BCC recipients per email; raising it permits more. If unset, the effective default is 10.', 'Integer; defaults to 10 if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:929|check|if (!getDolGlobalString(''MAIL_MAX_NB_OF_RECIPIENTS_BCC_IN_SAME_EMAIL'')) {", "core/class/CMailFile.class.php:930|write|$conf->global->MAIL_MAX_NB_OF_RECIPIENTS_BCC_IN_SAME_EMAIL = 10;", "core/class/CMailFile.class.php:933|read|if (count($tmparray3) > $conf->global->MAIL_MAX_NB_OF_RECIPIENTS_BCC_IN_SAME_EMAIL) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MAX_NB_OF_RECIPIENTS_CC_IN_SAME_EMAIL', 'string', NULL, 'core', 'Sets the maximum number of CC recipients allowed in a single outgoing email.', 'If unset, the code at core/class/CMailFile.class.php:921 writes a default of 10 at runtime. The limit is enforced at line 924 by comparing the CC recipient count against this value.', 'Lowering this value restricts CC recipients per email; raising it permits more. If unset, the effective default is 10.', 'Integer; defaults to 10 if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:920|check|if (!getDolGlobalString(''MAIL_MAX_NB_OF_RECIPIENTS_CC_IN_SAME_EMAIL'')) {", "core/class/CMailFile.class.php:921|write|$conf->global->MAIL_MAX_NB_OF_RECIPIENTS_CC_IN_SAME_EMAIL = 10;", "core/class/CMailFile.class.php:924|read|if (count($tmparray2) > $conf->global->MAIL_MAX_NB_OF_RECIPIENTS_CC_IN_SAME_EMAIL) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MAX_NB_OF_RECIPIENTS_IN_SAME_EMAIL', 'string', NULL, 'core', 'Sets the maximum total number of recipients (To + CC + BCC combined) allowed in a single outgoing email.', 'Described in core/class/CMailFile.class.php:910 as: check number of recipient is lower or equal than MAIL_MAX_NB_OF_RECIPIENTS_IN_SAME_EMAIL. If unset, the code at line 939 writes a default of 10. Enforced at line 941 against the combined count.', 'Lowering this restricts total recipients per email; raising it permits more combined recipients. If unset, the effective default is 10.', 'Integer; defaults to 10 if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:910  // Check number of recipient is lower or equal than MAIL_MAX_NB_OF_RECIPIENTS_IN_SAME_EMAIL", "core/class/CMailFile.class.php:939|write|$conf->global->MAIL_MAX_NB_OF_RECIPIENTS_IN_SAME_EMAIL = 10;", "core/class/CMailFile.class.php:941|read|if ((count($tmparray1) + count($tmparray2) + count($tmparray3)) > $conf->global->MAIL_MAX_NB_OF_RECIPIENTS_IN_SAME_EMAIL) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_MAX_NB_OF_RECIPIENTS_TO_IN_SAME_EMAIL', 'string', NULL, 'core', 'Sets the maximum number of To recipients allowed in a single outgoing email.', 'If unset, the code at core/class/CMailFile.class.php:912 writes a default of 10 at runtime. The limit is enforced at line 915 by comparing the To recipient count against this value.', 'Lowering this value restricts To recipients per email; raising it permits more. If unset, the effective default is 10.', 'Integer; defaults to 10 if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:911|check|if (!getDolGlobalString(''MAIL_MAX_NB_OF_RECIPIENTS_TO_IN_SAME_EMAIL'')) {", "core/class/CMailFile.class.php:912|write|$conf->global->MAIL_MAX_NB_OF_RECIPIENTS_TO_IN_SAME_EMAIL = 10;", "core/class/CMailFile.class.php:915|read|if (count($tmparray1) > $conf->global->MAIL_MAX_NB_OF_RECIPIENTS_TO_IN_SAME_EMAIL) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_PREFIX_FOR_EMAIL_ID', 'string', NULL, 'core', 'Sets a custom prefix string used when constructing the Message-ID header for outgoing emails.', 'Checked and read at core/lib/functions.lib.php:1585-1587. When set to ''SERVER_NAME'', the server name is used instead of the literal value. A comment at line 1593 notes the recommended value when this constant is not defined.', 'Changing this value alters the Message-ID prefix in outgoing emails. Using ''SERVER_NAME'' dynamically uses the server hostname.', 'Any string prefix, or ''SERVER_NAME'' to use the server hostname. The recommended value if MAIL_PREFIX_FOR_EMAIL_ID is not defined (may be not defined for old versions).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:1585|check|if (getDolGlobalString(''MAIL_PREFIX_FOR_EMAIL_ID'')) {\t// If MAIL_PREFIX_FOR_EMAIL_ID is set", "core/lib/functions.lib.php:1586|check|if (getDolGlobalString(''MAIL_PREFIX_FOR_EMAIL_ID'') != ''SERVER_NAME'') {", "core/lib/functions.lib.php:1593  // The recommended value if MAIL_PREFIX_FOR_EMAIL_ID is not defined (may be not defined for old versions)"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIL_SMTP_USE_FROM_FOR_HELO', 'bool', NULL, 'core', 'Controls the domain name sent in the SMTP HELO/EHLO command, with three modes: string domain, domain from sender address, or domain from Dolibarr URL.', 'Read extensively in core/class/smtps.class.php. COMMENTS state: ''If value of MAIL_SMTP_USE_FROM_FOR_HELO is a string, we use it as domain name''; ''If value of MAIL_SMTP_USE_FROM_FOR_HELO is 1, we use the domain in the from.''; ''If value of MAIL_SMTP_USE_FROM_FOR_HELO is 2, we use the domain in the $dolibarr_main_url_root.'' An inline note states ''default value is forced to MAIL_SMTP_USE_FROM_FOR_HELO=2 if not set''.', 'Changing this value alters which domain is advertised during the SMTP handshake, affecting mail server acceptance and DMARC/SPF alignment.', 'String or int: a literal domain string = use as HELO domain; 1 = use sender''s domain; 2 = use dolibarr_main_url_root domain (default when unset).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/smtps.class.php:570  // If value of MAIL_SMTP_USE_FROM_FOR_HELO is a string, we use it as domain name", "core/class/smtps.class.php:573  // If value of MAIL_SMTP_USE_FROM_FOR_HELO is 1, we use the domain in the from.", "core/class/smtps.class.php:580  // If value of MAIL_SMTP_USE_FROM_FOR_HELO is 2, we use the domain in the $dolibarr_main_url_root.", "core/class/smtps.class.php:568|check|if (getDolGlobalString(''MAIL_SMTP_USE_FROM_FOR_HELO'')) {\t// Note that default value is forced to MAIL_SMTP_USE_FROM_FOR_HELO=2 if not set"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT', 'string', NULL, 'comm', 'Allows adding contacts from any third-party (not just the event''s linked third-party) to an agenda event.', 'When set, the contact selector uses socid=0 (all contacts) instead of restricting to the event''s socid. Seen in comm/action/card.php lines 1780, 1792, 2361, 2365, 2369. Two comments warn this can hang on large databases.', 'Enabling this on a large database risks slow page loads or timeouts due to loading all contacts without a third-party filter.', 'Empty/unset = contacts filtered to the event''s third-party; truthy value = all contacts selectable (Warning: MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT will hangs on large databases).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/card.php:1781  // Warning: MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT will hangs on large databases", "comm/action/card.php:1780|check|if (getDolGlobalInt(''MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT'')) {", "comm/action/card.php:1792|read|print $form->select_contact(getDolGlobalString(''MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT'') ? 0 : $object->socid, $selected, ''socpeopleassigned'', 1, '''', '''', 1, ''minwidth300 widthcentperce", "comm/action/card.php:2368  // Warning: MAIN_ACTIONCOM_CAN_ADD_ANY_CONTACT will hangs on large databases"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ACTIVATE_FILECACHE', 'string', NULL, 'core', 'Enables file-based caching for dashboard box content to reduce repeated database queries.', 'Set via admin/boxes.php:63 and admin/system/perf.php (read at line 759); checked in core/boxes/modules_boxes.php:465 to decide whether to serve box content from a file cache. Temporarily overridden in core/boxes/box_activity.php:83 and restored at line 436 during box rendering.', 'Enabling this constant causes box content to be written to and served from a file cache for the duration defined by MAIN_ACTIVATE_FILECACHE_DELAY; disabling it forces live queries for every page load.', '0 or empty = file cache disabled; non-zero = file cache enabled.', 0, 0, 'admin/system/perf.php|admin/system/perf.php|admin/boxes.php|admin/boxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/boxes.php:63|write|dolibarr_set_const($db, \"MAIN_ACTIVATE_FILECACHE\", GETPOST(\"MAIN_ACTIVATE_FILECACHE\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "core/boxes/modules_boxes.php:465|check|if (getDolGlobalString(''MAIN_ACTIVATE_FILECACHE'')) {", "core/boxes/box_activity.php:83|write|$conf->global->MAIN_ACTIVATE_FILECACHE = 1;", "admin/system/perf.php:759|read|print yn(getDolGlobalInt(''MAIN_ACTIVATE_FILECACHE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ACTIVATE_FILECACHE_DELAY', 'string', NULL, 'core', 'Sets the cache duration in seconds for the dashboard box file cache.', 'Read in admin/boxes.php:463 and core/boxes/modules_boxes.php:268 with a default of 900 seconds (15 minutes) when the constant is not set.', 'Increasing this value extends how long box content is served from the file cache before refreshing; decreasing it causes more frequent cache invalidation.', 'Integer number of seconds; default is 900 (15 minutes).', 0, 0, 'admin/boxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/modules_boxes.php:268|read|$cachetime = getDolGlobalInt(''MAIN_ACTIVATE_FILECACHE_DELAY'', 900); // 900 : 15mn", "admin/boxes.php:463|read|print '' <span class=\"opacitymedium\">(''.getDolGlobalInt(''MAIN_ACTIVATE_FILECACHE_DELAY'', 900).\" \".$langs->trans(\"seconds\").\")</span>\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ACTIVATE_VALIDATION_RESULT', 'string', NULL, 'core', 'Enables field-level validation via validateField() on object fields marked with ''validate'' => 1, as an alternative to requiring MAIN_FEATURES_LEVEL >= 1.', 'Checked alongside MAIN_FEATURES_LEVEL in core/actions_addupdatedelete.inc.php:194 and 354, asset/class/assetdepreciationoptions.class.php:305, and core/class/fieldsmanager.class.php:874 and 914. Multiple class docblocks state: ''validate'' is 1 if you need to validate the field with $this->validateField(). Need MAIN_ACTIVATE_VALIDATION_RESULT.', 'When set, field validation via validateField() is active for all object fields with ''validate'' => 1, even without MAIN_FEATURES_LEVEL >= 1.', 'Empty/unset = validation only active when MAIN_FEATURES_LEVEL >= 1; non-empty = validation always active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societeaccount.class.php:89  *\t''validate'' is 1 if you need to validate the field with $this->validateField(). Need MAIN_ACTIVATE_VALIDATION_RESULT.", "mrp/class/moline.class.php:89  *\t''validate'' is 1 if you need to validate the field with $this->validateField(). Need MAIN_ACTIVATE_VALIDATION_RESULT.", "core/actions_addupdatedelete.inc.php:194|check|if (getDolGlobalInt(''MAIN_FEATURES_LEVEL'') >= 1 || getDolGlobalString(''MAIN_ACTIVATE_VALIDATION_RESULT'')) {", "core/class/fieldsmanager.class.php:874|check|if (getDolGlobalInt(''MAIN_FEATURES_LEVEL'') >= 1 || getDolGlobalString(''MAIN_ACTIVATE_VALIDATION_RESULT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_CREATOR_IN_NOTE', 'string', NULL, 'core', 'Adds the proposal creator''s name to the notes section of proposal PDF documents.', 'Checked in pdf_cyan.modules.php:412 and pdf_azur.modules.php:434 with a secondary condition that the author user ID is set ($object->user_author_id > 0). No admin UI write is present.', 'When set, the creator''s information is appended to the notes area on proposal PDFs. Unsetting it omits this addition.', 'Truthy = creator info added to notes; falsy or unset = creator info omitted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:412|check|if (getDolGlobalString(''MAIN_ADD_CREATOR_IN_NOTE'') && $object->user_author_id > 0) {", "core/modules/propale/doc/pdf_azur.modules.php:434|check|if (getDolGlobalString(''MAIN_ADD_CREATOR_IN_NOTE'') && $object->user_author_id > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_EVENT_ON_ELEMENT_CARD', 'string', NULL, 'fourn', 'Intended to add an event/agenda shortcut button on element cards; all usages are currently commented out in the codebase.', 'All 4 occurrences in fourn/commande/card.php:2893, fourn/facture/card.php:4347, projet/card.php:1663, and comm/propal/card.php:3581 are inside commented-out code blocks. COMMENTS confirm: ''Add hidden condition because this is not a "workflow" action so should appears somewhere else on page.''', 'This constant has no active effect as all code paths checking it are commented out; setting or unsetting it does not change any visible behavior.', 'Empty/0 = no effect (code commented out); truthy = no effect (code commented out)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2893  /*if (isModEnabled(''agenda'') && getDolGlobalString(''MAIN_ADD_EVENT_ON_ELEMENT_CARD'')) \t// Add hidden condition because this is not a \"workflow\" action so should appears somewhere else on page.", "fourn/facture/card.php:4347  /*if (isModEnabled(''agenda'') && getDolGlobalString(''MAIN_ADD_EVENT_ON_ELEMENT_CARD'')) { \t// Add hidden condition because this is not a \"workflow\" action so should appears somewhere else on page.", "comm/propal/card.php:3581  /*if (isModEnabled(''agenda'') && !empty($conf->global->MAIN_ADD_EVENT_ON_ELEMENT_CARD)) \t// Add hidden condition because this is not a \"workflow\" action so should appears somewhere else on page."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_ICONPICKER_JS', 'string', NULL, 'core', 'Enables loading of the icon-picker JavaScript library for icon selection fields in forms.', 'Checked via getDolGlobalInt in core/class/html.form.class.php:12899, core/class/extrafields.class.php:1341, and webportal/class/html.formwebportal.class.php:1442. No admin UI writes this constant.', 'When non-zero, the icon-picker JS component is included in pages that render icon selection fields.', 'Integer: 1 to enable the icon picker JS; 0 or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/html.formwebportal.class.php:1442|check|if (getDolGlobalInt(''MAIN_ADD_ICONPICKER_JS'')) {", "core/class/html.form.class.php:12899|check|if (getDolGlobalInt(''MAIN_ADD_ICONPICKER_JS'')) {", "core/class/extrafields.class.php:1341|check|if (getDolGlobalInt(''MAIN_ADD_ICONPICKER_JS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_LINE_AT_POSITION', 'string', NULL, 'compta', 'Enables inserting a new document line at a specific position rather than always appending it at the end.', 'Checked in 3 locations: compta/facture/class/facture.class.php:2904, fourn/class/fournisseur.facture.class.php:1399, and core/tpl/objectline_create.tpl.php:421. No admin UI is present.', 'Enabling this changes line insertion behaviour so that new lines can be placed at a chosen position in the document line list.', '0 or unset = new lines are appended at the end; truthy value = new lines can be inserted at a specific position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:2904|check|if (getDolGlobalString(''MAIN_ADD_LINE_AT_POSITION'')) {", "fourn/class/fournisseur.facture.class.php:1399|check|if (getDolGlobalString(''MAIN_ADD_LINE_AT_POSITION'')) {", "core/tpl/objectline_create.tpl.php:421|check|if (getDolGlobalString(''MAIN_ADD_LINE_AT_POSITION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_MORE_EXAMPLE_IN_ACCURANCY_SETUP', 'string', NULL, 'admin', 'Controls whether additional examples are displayed in the accuracy/rounding setup section of the limits admin page.', 'Checked at admin/limits.php:316; when set, additional example content is rendered in that section of the UI. Configurable via the admin UI at admin/limits.php.', 'Setting this constant adds illustrative examples to the accuracy setup UI; leaving it unset hides those examples.', 'Empty/unset = no extra examples shown; any truthy value = extra examples displayed.', 0, 0, 'admin/limits.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/limits.php:316|check|if (getDolGlobalString(''MAIN_ADD_MORE_EXAMPLE_IN_ACCURANCY_SETUP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_PDF_BACKGROUND', 'string', NULL, 'core', 'Specifies a background image file to overlay on generated PDF documents using FPDI.', 'Checked across 75 occurrences in PDF generation modules; some also require MAIN_DISABLE_FPDI to be unset (e.g. core/modules/stock/doc/pdf_standard_stock.modules.php:236). No admin UI write is present.', 'Setting this to a file path adds a background image to all generated PDFs; it has no effect if MAIN_DISABLE_FPDI is set.', 'String (path to background image file); empty or unset = no background image.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/stock/doc/pdf_standard_stock.modules.php:236|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:322|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:273|check|if (getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADD_SALE_REP_SIGNATURE_IN_NOTE', 'string', NULL, 'core', 'When enabled, appends the sales representative''s signature block to the note/footer section of generated PDF documents.', 'Checked in 9+ locations across multiple PDF generation modules: expense report, stock transfer, orders (einstein, eratosthene), invoices (octopus, sponge), supplier proposal (aurore), proposal (cyan). In each module the same check triggers signature inclusion.', 'Enabling causes sales rep signatures to appear in PDF notes across all supported document types. Disabling omits signatures from PDFs.', 'Truthy = include sales rep signature in PDF note section; empty/unset = no signature added.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:325|check|if (getDolGlobalString(''MAIN_ADD_SALE_REP_SIGNATURE_IN_NOTE'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:356|check|if (getDolGlobalString(''MAIN_ADD_SALE_REP_SIGNATURE_IN_NOTE'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:2758|check|if (getDolGlobalString(''MAIN_ADD_SALE_REP_SIGNATURE_IN_NOTE'')) {", "core/modules/propale/doc/pdf_cyan.modules.php:392|check|if (getDolGlobalString(''MAIN_ADD_SALE_REP_SIGNATURE_IN_NOTE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADMIN_TOOLS_EXPORT_FILES_EXEC_TIME_LIMIT', 'string', NULL, 'admin', 'Sets the PHP execution time limit (in seconds) for the file-archive export tool.', 'Read in admin/tools/export_files.php:103 with a default of 1800 seconds (30 minutes) when the constant is not set. The inline comment confirms the 30-minute default.', 'Increasing this value allows longer-running file exports to complete; decreasing it may cause the export to be killed by PHP before finishing.', 'Integer number of seconds (default: 1800).', 0, 0, 'admin/tools/export_files.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/export_files.php:103|read|$ExecTimeLimit = getDolGlobalInt(''MAIN_ADMIN_TOOLS_EXPORT_FILES_EXEC_TIME_LIMIT'', 1800);; // 30mn"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ADMIN_TOOLS_PURGE_EXEC_TIME_LIMIT', 'string', NULL, 'admin', 'Sets the PHP execution time limit (in seconds) for the admin purge tool.', 'Read in admin/tools/purge.php:69 with a default of 600 seconds (10 minutes) when the constant is not set.', 'Increasing this value allows longer purge operations to complete; decreasing it may abort purge jobs before they finish.', 'Integer number of seconds (default: 600).', 0, 0, 'admin/tools/purge.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/purge.php:69|read|$ExecTimeLimit = getDolGlobalInt(''MAIN_ADMIN_TOOLS_PURGE_EXEC_TIME_LIMIT'', 600);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AGENDA_EXPORT_CACHE', 'string', NULL, 'core', 'Sets the cache duration in seconds for the public agenda iCal/vCal export feed.', 'Written via admin/agenda_xcal.php:82 and read in core/lib/xcal.lib.php:75-78 where it is checked (must be > 60) and decomposed into hours, minutes, seconds via convertSecondToTime. Also checked in public/agenda/agendaexport.php:295-296 to determine the cache delay.', 'If set to a value greater than 60, the exported calendar feed is cached for that many seconds, reducing database load for frequent subscribers. If unset or 60 or below, caching is not applied.', 'Integer number of seconds. Must be > 60 for caching to activate (per core/lib/xcal.lib.php:75 check). 0 or unset = no cache.', 0, 0, 'admin/agenda_xcal.php|admin/agenda_xcal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/xcal.lib.php:75|check|if (getDolGlobalString(''MAIN_AGENDA_EXPORT_CACHE'') && getDolGlobalInt(''MAIN_AGENDA_EXPORT_CACHE'') > 60) {", "core/lib/xcal.lib.php:76|read|$hh = convertSecondToTime(getDolGlobalInt(''MAIN_AGENDA_EXPORT_CACHE''), \"hour\");", "public/agenda/agendaexport.php:295|check|if (getDolGlobalString(''MAIN_AGENDA_EXPORT_CACHE'')) {", "admin/agenda_xcal.php:82|write|$i += dolibarr_set_const($db, ''MAIN_AGENDA_EXPORT_CACHE'', $MAIN_AGENDA_EXPORT_CACHE, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AGENDA_EXPORT_PAST_DELAY', 'string', NULL, 'admin', 'Sets the number of days into the past that agenda events are included in the iCal export.', 'Configured via admin/agenda_xcal.php (dolibarr_set_const at line 81). Read at admin/agenda_xcal.php:56 with a default of 100 days, and at public/agenda/agendaexport.php:154 where it filters events not older than the delay.', 'Increasing this value includes older past events in the exported calendar feed; decreasing it trims older events from the export.', 'Positive integer (days); default = 100.', 0, 0, 'admin/agenda_xcal.php|admin/agenda_xcal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/agenda_xcal.php:56|read|$MAIN_AGENDA_EXPORT_PAST_DELAY = getDolGlobalInt(''MAIN_AGENDA_EXPORT_PAST_DELAY'', 100);", "admin/agenda_xcal.php:81|write|$i += dolibarr_set_const($db, ''MAIN_AGENDA_EXPORT_PAST_DELAY'', $MAIN_AGENDA_EXPORT_PAST_DELAY, ''chaine'', 0, '''', $conf->entity);", "public/agenda/agendaexport.php:154|read|$filters[''notolderthan''] = getDolGlobalInt(''MAIN_AGENDA_EXPORT_PAST_DELAY'', 100);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AGENDA_XCAL_EXPORTKEY', 'string', NULL, 'admin', 'Secret key that authenticates public iCal/vCal/RSS agenda export URLs.', 'Comment in core/modules/modAgenda.class.php:108: "Securekey for the public link". Read in admin/agenda_xcal.php:55 and written at line 80. Used in admin/agenda_xcal.php:197-226 to construct public export URLs containing the key as the exportkey parameter.', 'Changing this key invalidates all previously shared public agenda export URLs. Clearing it disables key-based access control for the export feed.', 'Arbitrary string (secret key). Example default from comment: "123456".', 0, 0, 'admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php|admin/agenda_xcal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/modAgenda.class.php:108  //$this->const[] = array(\"MAIN_AGENDA_XCAL_EXPORTKEY\", \"chaine\", \"123456\", \"Securekey for the public link\");", "admin/agenda_xcal.php:80|write|$i += dolibarr_set_const($db, ''MAIN_AGENDA_XCAL_EXPORTKEY'', $MAIN_AGENDA_XCAL_EXPORTKEY, ''chaine'', 0, '''', $conf->entity);", "admin/agenda_xcal.php:202|check|if (getDolGlobalString(''MAIN_AGENDA_XCAL_EXPORTKEY'')) {", "admin/agenda_xcal.php:197|read|$urlvcal = ''<a href=\"''.$urlwithroot.''/public/agenda/agendaexport.php?format=vcal''.$getentity.''&exportkey=''.urlencode(getDolGlobalString(''MAIN_AGENDA_XCAL_EXPORTKEY'', ''...'',"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_AUTOMATIC_CONCILIATION', 'bool', NULL, 'core', 'Enables automatic bank reconciliation (conciliation) functionality in the bank library.', 'Read in core/lib/bank.lib.php:57 as getDolGlobalBool(''MAIN_ALLOW_AUTOMATIC_CONCILIATION''). The inline comment ''TODO'' suggests the feature may be incomplete.', 'Setting this constant activates automatic conciliation logic in the bank module; the full effect depends on code gated by this flag.', '1/true = allow automatic conciliation; 0/empty = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["$allowautomaticconciliation = getDolGlobalBool(''MAIN_ALLOW_AUTOMATIC_CONCILIATION''); // TODO"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_BACKUP_BY_EMAIL', 'bool', NULL, 'core', 'Controls whether the scheduled database backup job that sends backup by email is available in the Cron module.', 'Referenced in core/modules/modCron.class.php:100 as part of a cron job definition for the sendBackup method of the Utils class. No admin UI; hidden setting.', 'Enabling this makes the email-based database backup cron job available; the exact guard behavior is unclear from code alone.', '0 or empty = backup by email job not enabled; 1 = backup by email cron job enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modCron.class.php:100|read|2=>array(''entity''=>0, ''label''=>''MakeSendLocalDatabaseDumpShort'', ''jobtype''=>''method'', ''class''=>''core/class/utils.class.php'', ''objectname''=>''Utils'', ''method''=>''sendBackup'', ''paramet"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_INTEGRITY_CHECK_ON_UNSTABLE', 'bool', NULL, 'blockedlog', 'Allows the file integrity check to run even when the running Dolibarr version is an alpha, beta, or RC release.', 'Checked at blockedlog/admin/filecheck.php:172 alongside a preg_match for ''beta|alpha|rc'' in DOL_VERSION. No admin UI writes this value, and there is only one occurrence.', 'Without this constant, the integrity check is skipped for unstable versions. Setting it to a truthy value forces the check to run regardless of version stability.', 'Boolean/truthy: non-empty enables integrity check on unstable versions.', 0, 0, 'blockedlog/admin/filecheck.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (preg_match(''/beta|alpha|rc/i'', DOL_VERSION) || getDolGlobalString(''MAIN_ALLOW_INTEGRITY_CHECK_ON_UNSTABLE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_LINK_STARTING_WITH_FILE', 'bool', NULL, 'core', 'Allows links starting with the ''file://'' protocol to be used as external links on Dolibarr objects.', 'Checked in core/actions_linkedfiles.inc.php:125 and :232 to permit or block file:// URLs when adding linked files. Displayed in admin/system/security.php:1032 as a security information item.', 'When unset, file:// links are rejected for security; when set, file:// links are accepted as external links.', 'Bool-like string: empty/unset = file:// links blocked; non-empty = file:// links allowed.', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/actions_linkedfiles.inc.php:125|read|&& (substr($link, 0, 7) != ''file://'' || !getDolGlobalString(''MAIN_ALLOW_LINK_STARTING_WITH_FILE''))) {", "core/actions_linkedfiles.inc.php:232|read|&& (substr($link->url, 0, 7) != ''file://'' || !getDolGlobalString(''MAIN_ALLOW_LINK_STARTING_WITH_FILE''))) {", "admin/system/security.php:1032|read|print ''<strong>MAIN_ALLOW_LINK_STARTING_WITH_FILE</strong> = ''.getDolGlobalString(''MAIN_ALLOW_LINK_STARTING_WITH_FILE'', ..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_LOCAL_LINKS_AS_EXTERNAL_LINKS', 'bool', NULL, 'core', 'Permits local filesystem links to be treated as external links when attaching linked files.', 'When this constant is not set, local links are blocked in core/actions_linkedfiles.inc.php:141. The constant is referenced in admin/system/security.php:1039, indicating it is a security-related toggle.', 'Disabling (or leaving unset) blocks local links from being processed as external links, which is the default secure behaviour. Enabling it relaxes that restriction.', 'Truthy (non-empty/non-zero) = allow local links as external; falsy or unset = block local links.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/actions_linkedfiles.inc.php:141|check|if (!getDolGlobalString(''MAIN_ALLOW_LOCAL_LINKS_AS_EXTERNAL_LINKS'')) {", "admin/system/security.php:1039  // MAIN_ALLOW_LOCAL_LINKS_AS_EXTERNAL_LINKS"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_OBFUSCATION_METHODS_IN_DOL_EVAL', 'bool', NULL, 'core', 'Allows PHP functions that can obfuscate callable names to be used inside dol_eval expressions.', 'Checked at core/lib/functions.lib.php:12374 and 12451. The comment at line 12451 states ''We disallow all function that allow to obfuscate the real name of a function''. When this constant is absent or falsy, such functions are blocked. Displayed in admin/system/security.php:1035.', 'Enabling this constant is a security risk as it permits obfuscation techniques inside evaluated expressions; disabling it (the default) blocks those techniques.', '0 or empty = obfuscation functions blocked in dol_eval; any truthy value = obfuscation functions permitted', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:12451|check|if (!getDolGlobalString(''MAIN_ALLOW_OBFUSCATION_METHODS_IN_DOL_EVAL'')) {\t// We disallow all function that allow to obfuscate the real name of a function", "core/lib/functions.lib.php:12374|check|if (!getDolGlobalString(''MAIN_ALLOW_OBFUSCATION_METHODS_IN_DOL_EVAL'')) {", "admin/system/security.php:1035|read|print ''<strong>MAIN_ALLOW_OBFUSCATION_METHODS_IN_DOL_EVAL</strong> = ''.getDolGlobalString(''MAIN_ALLOW_OBFUSCATION_METHODS_IN_DOL_EVAL'', ''<span class=\"opacitymedium\">''.$langs->trans"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_OLD_VAR_OBJ_IN_DOL_EVAL', 'bool', NULL, 'core', 'Permits legacy $object and $obj variable references inside dol_eval expressions.', 'Checked at core/lib/functions.lib.php:11988 and 12270. When set, the eval context includes older-style variable names that were available in previous Dolibarr versions.', 'Enabling this constant restores backward-compatible variable names in evaluated expressions; disabling it enforces the stricter modern variable scope.', '0 or empty = old $object/$obj variables not allowed in dol_eval; any truthy value = old variable names permitted', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:11988|check|if (getDolGlobalString(''MAIN_ALLOW_OLD_VAR_OBJ_IN_DOL_EVAL'')) {", "core/lib/functions.lib.php:12270|check|if (getDolGlobalString(''MAIN_ALLOW_OLD_VAR_OBJ_IN_DOL_EVAL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_SVG_FILES_AS_EXTERNAL_LINKS', 'bool', NULL, 'admin', 'Allows SVG files to be used as external links attached to Dolibarr objects.', 'Checked in core/actions_linkedfiles.inc.php:133 to block SVG external links when unset. Displayed in admin/system/security.php:1029 as a security information item.', 'When unset, attaching SVG files as external links is blocked for security reasons; when set this restriction is lifted.', 'Bool-like string: empty/unset = SVG external links blocked; non-empty = SVG external links allowed.', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/actions_linkedfiles.inc.php:133|check|if (!getDolGlobalString(''MAIN_ALLOW_SVG_FILES_AS_EXTERNAL_LINKS'')) {", "admin/system/security.php:1029|read|print ''<strong>MAIN_ALLOW_SVG_FILES_AS_EXTERNAL_LINKS</strong> = ''.getDolGlobalString(''MAIN_ALLOW_SVG_FILES_AS_EXTERNAL_LINKS'', ..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_SVG_FILES_AS_IMAGES', 'bool', NULL, 'core', 'Enables SVG files to be accepted and rendered as images throughout Dolibarr.', 'Visible in admin/system/security.php:811 with a default display value of ''0''. When enabled, SVG is allowed in the file manager connector (core/filemanagerdol/connectors/php/config.inc.php:172) and in image processing (core/lib/images.lib.php:71, core/lib/functions.lib.php:13838).', 'Enabling this allows SVG uploads and rendering; because SVG can contain active content, this has security implications noted in the security admin page.', '0 = SVG files not accepted as images; 1 = SVG files accepted as images', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/security.php:811|read|print ''<strong>MAIN_ALLOW_SVG_FILES_AS_IMAGES</strong> = ''.getDolGlobalString(''MAIN_ALLOW_SVG_FILES_AS_IMAGES'', ''0'')", "core/lib/images.lib.php:71|check|if ($acceptsvg || getDolGlobalString(''MAIN_ALLOW_SVG_FILES_AS_IMAGES'')) {", "core/filemanagerdol/connectors/php/config.inc.php:172|check|if (getDolGlobalString(''MAIN_ALLOW_SVG_FILES_AS_IMAGES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_UNSECURED_FALLBACK_FOR_SELECTOBJECT', 'bool', NULL, 'core', 'Permits a fallback that dynamically loads arbitrary class files in the selectobject AJAX endpoint when the object type is not recognised.', 'When set, core/ajax/selectobject.php:121 allows loading a class file specified by the $classpath parameter (matching *.class.php) even when $objecttmp could not be resolved through the normal registry. This bypasses the standard class-registry security check.', 'Enabling this constant introduces a path-traversal risk if $classpath is not strictly validated upstream; it should only be set in controlled environments.', 'Empty/unset = strict class registry enforced; truthy value = dynamic class-file fallback enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/selectobject.php:121|check|if (getDolGlobalString(\"MAIN_ALLOW_UNSECURED_FALLBACK_FOR_SELECTOBJECT\") && empty($objecttmp) && !empty($classpath) && preg_match(''/\\.class\\.php$/'', $classpath)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_WYSIWYG_EVEN_ON_UNSECURED_EXTERNAL_HTTP_URL', 'bool', NULL, 'core', 'Allows WYSIWYG editor content to embed unsecured external HTTP (non-HTTPS) URLs when set.', 'Read in core/lib/functions2.lib.php:2944 via getDolGlobalInt; the value is stored in $allowUrlInHTTP which controls whether plain HTTP external URLs are permitted in WYSIWYG content.', 'Enabling this permits WYSIWYG content to reference plain HTTP URLs, which may expose users to mixed-content security warnings in the browser.', '0 or unset = unsecured HTTP URLs blocked in WYSIWYG; non-zero = allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2944|read|$allowUrlInHTTP = getDolGlobalInt(''MAIN_ALLOW_WYSIWYG_EVEN_ON_UNSECURED_EXTERNAL_HTTP_URL'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALLOW_WYSIWYG_LOCAL_MEDIAS_ON_PRIVATE_NETWORK', 'bool', NULL, 'core', 'Allows WYSIWYG editor content to embed local or private-network media URLs when set.', 'Read in core/lib/functions2.lib.php:2937; the comment at line 2919 explains: ''except if MAIN_ALLOW_WYSIWYG_LOCAL_MEDIAS_ON_PRIVATE_NETWORK is set, in which case we accept also if instance has a local or private network URL.'' The comment at line 2941 shows how to use this constant to allow local URLs.', 'Enabling this permits WYSIWYG content to reference private-network URLs for media, which is otherwise blocked as a security measure.', '0 or unset = local/private-network media URLs blocked in WYSIWYG; 1 = allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2919  // except if MAIN_ALLOW_WYSIWYG_LOCAL_MEDIAS_ON_PRIVATE_NETWORK is net, in which case we accept also if instance has a local or private network URL.", "core/lib/functions2.lib.php:2941  //dol_syslog(\"WYSIWYG Editor : local media not allowed (checked IP: {$iptocheck}). Use MAIN_ALLOW_WYSIWYG_LOCAL_MEDIAS_ON_PRIVATE_NETWORK = 1 to allow local URL into WYSIWYG html content\");", "core/lib/functions2.lib.php:2937|read|$allowPrivateNetworkIP = getDolGlobalInt(''MAIN_ALLOW_WYSIWYG_LOCAL_MEDIAS_ON_PRIVATE_NETWORK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALL_TOWN_TO_UPPER', 'string', NULL, 'core', 'Forces the town/city field to uppercase.', 'Checked in core/class/commonpeople.class.php:391. When set, the town value is converted to uppercase.', 'Enabling this constant causes the town field to be stored and displayed in uppercase.', 'Non-empty = town uppercased; empty or unset = original case preserved', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonpeople.class.php:391|check|if (getDolGlobalString(''MAIN_ALL_TOWN_TO_UPPER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALL_TO_UPPER', 'string', NULL, 'core', 'Forces all name fields to uppercase.', 'Checked in core/class/commonpeople.class.php:384. When set, name-related fields are converted entirely to uppercase.', 'Enabling this constant causes all name fields to be stored and displayed in uppercase.', 'Non-empty = all names uppercased; empty or unset = original case preserved', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonpeople.class.php:384|check|if (getDolGlobalString(''MAIN_ALL_TO_UPPER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ALWAYS_CREATE_LOCK_AFTER_LAST_UPGRADE', 'string', NULL, 'core', 'Forces creation of the install.lock file after every upgrade, regardless of whether the version is the latest.', 'When enabled, Dolibarr creates the install.lock file after upgrade completion even if not on the last version. Referenced in install/step5.php:524 and install/step5.php:574 and displayed in admin/system/security.php:814.', 'Enabling this constant ensures the install directory is locked after every upgrade step, preventing re-execution of the installer.', 'Empty/not set = lock only created on last version upgrade; any non-empty value = always create lock', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["install/step5.php:359  // The install.lock file is created few lines later if version is last one or if option MAIN_ALWAYS_CREATE_LOCK_AFTER_LAST_UPGRADE is on", "install/step5.php:524|check|if (!empty($force_install_lockinstall) || getDolGlobalString(''MAIN_ALWAYS_CREATE_LOCK_AFTER_LAST_UPGRADE'')) {", "install/step5.php:574|check|if (!empty($force_install_lockinstall) || getDolGlobalString(''MAIN_ALWAYS_CREATE_LOCK_AFTER_LAST_UPGRADE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ANTIVIRUS_ALLOW_JS_IN_PDF', 'bool', NULL, 'core', 'Disables the antivirus check that rejects PDF files containing JavaScript.', 'In core/lib/files.lib.php, when this constant is not set, uploaded PDF files are scanned and rejected if JavaScript is detected. Setting this constant bypasses that check. No admin UI write; hidden setting.', 'Enabling this constant allows PDF files with embedded JavaScript to pass the antivirus upload check; disabling it (or leaving unset) causes such files to be rejected.', 'Non-empty (truthy) allows JS in PDFs; empty or undefined blocks them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:1418|check|if (!getDolGlobalString(''MAIN_ANTIVIRUS_ALLOW_JS_IN_PDF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ANTIVIRUS_COMMAND', 'string', NULL, 'admin', 'Path to the antivirus executable used to scan uploaded files.', 'Written via admin/security_file.php:104 and read in core/class/antivir.class.php:138 with default ''/usr/bin/clamdscan''. Also read in admin/security_file.php:251 to derive the base directory of the command. Shown in admin/system/security.php:621.', 'Changing this constant redirects file scanning to the specified antivirus binary. If unset, the system defaults to /usr/bin/clamdscan.', 'File path string to the antivirus binary. Default: ''/usr/bin/clamdscan''.', 0, 0, 'admin/security_file.php|admin/security_file.php|admin/system/security.php|admin/system/security.php|admin/security_file.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/antivir.class.php:138|read|$command = getDolGlobalString(''MAIN_ANTIVIRUS_COMMAND'', ''/usr/bin/clamdscan'');", "admin/security_file.php:104|write|$res5 = dolibarr_set_const($db, \"MAIN_ANTIVIRUS_COMMAND\", trim($antivircommand), ''chaine'', 0, '''', $conf->entity);", "admin/security_file.php:251|read|$basedir = preg_replace(''/''.''\"/'', '''', dirname($conf->global->MAIN_ANTIVIRUS_COMMAND));", "admin/system/security.php:621|read|print '' &nbsp; - '' . getDolGlobalString(''MAIN_ANTIVIRUS_COMMAND'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ANTIVIRUS_PARAM', 'string', NULL, 'admin', 'Command-line parameters passed to the antivirus binary when scanning an uploaded file.', 'Written via admin/security_file.php:105 and read in core/class/antivir.class.php:139 and :148. Line 148 checks whether the param string contains %file (the placeholder for the scanned file path).', 'If the parameter string does not contain %file, the antivirus scan invocation will not include the target file path, rendering scanning ineffective. Correct parameters must include %file.', 'String of CLI arguments for the antivirus command. Must contain ''%file'' as placeholder for the uploaded file path.', 0, 0, 'admin/security_file.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/antivir.class.php:139|read|$param = getDolGlobalString(''MAIN_ANTIVIRUS_PARAM'');", "core/class/antivir.class.php:148|check|if (!preg_match(''/%file/'', getDolGlobalString(''MAIN_ANTIVIRUS_PARAM''))) {", "admin/security_file.php:105|write|$res6 = dolibarr_set_const($db, \"MAIN_ANTIVIRUS_PARAM\", trim($antivirparam), ''chaine'', 0, '''', $conf->entity);", "admin/security_file.php:271|read|print ''<input type=\"text\" ''.(defined(''MAIN_ANTIVIRUS_PARAM'') ? ''disabled '' : '''').''name=\"MAIN_ANTIVIRUS_PARAM\"...''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ANTIVIRUS_UPLOAD_ON', 'string', NULL, 'admin', 'Enables antivirus scanning of uploaded files.', 'Checked in admin/security_file.php:233 and :242, and in core/lib/files.lib.php:1394 via getDolGlobalString(''MAIN_ANTIVIRUS_UPLOAD_ON''). Also displayed in admin/system/security.php:616-617 as a yes/no indicator.', 'When enabled, every uploaded file is scanned using the command defined in MAIN_ANTIVIRUS_COMMAND. When disabled, uploads bypass antivirus scanning.', 'Non-empty string = antivirus scanning enabled. Empty/unset = scanning disabled.', 0, 0, 'admin/security_file.php|admin/security_file.php|admin/system/security.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_file.php:233|check|if (!getDolGlobalString(''MAIN_ANTIVIRUS_UPLOAD_ON'')) {", "admin/security_file.php:242|check|if (getDolGlobalString(''MAIN_ANTIVIRUS_UPLOAD_ON'')) {", "core/lib/files.lib.php:1394|check|if (getDolGlobalString(''MAIN_ANTIVIRUS_UPLOAD_ON'')) {", "admin/system/security.php:617|read|print yn(!getDolGlobalString(''MAIN_ANTIVIRUS_UPLOAD_ON'') ? 0 : 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_API_DEBUG', 'string', NULL, 'api', 'When set to 1, enables saving of API request/response logs into the file ''dolibarr_api.log''.', 'Checked in api/index.php (lines 195, 443) and api/class/api.class.php:70. The comment at api/index.php:194 documents the behavior explicitly.', 'When enabled, API activity is logged to dolibarr_api.log; when disabled, no API-specific log file is written.', 'Integer: 1 to enable API debug logging; 0 or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// If MAIN_API_DEBUG is set to 1, we save logs into file \"dolibarr_api.log\"", "api/index.php:195|check|if (getDolGlobalString(''MAIN_API_DEBUG'')) {", "api/class/api.class.php:70|check|if (getDolGlobalString(''MAIN_API_DEBUG'')) {", "api/index.php:443|check|if (getDolGlobalString(''MAIN_API_DEBUG'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_API_KEY', 'string', NULL, 'api', 'Salt or secret key used to generate API tokens via hashing in the login endpoint.', 'Used at api/class/api_login.class.php:162 where a token is produced by hashing the login, a uniqid, and this constant together. No admin UI is present; value must be set manually.', 'Changing this key invalidates all previously issued API tokens derived from it, requiring clients to re-authenticate.', 'Any string value used as a cryptographic salt for API token generation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_login.class.php:162|read|$token = dol_hash($login.uniqid().getDolGlobalString(''MAIN_API_KEY''), ''1'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_APPLICATION_TITLE', 'string', NULL, 'public', 'Sets a custom application title that replaces ''Dolibarr'' in page headers, emails, and notifications.', 'Written in admin/security_other.php at line 80. Read across 65 occurrences including core/get_info.php, core/actions_massactions.inc.php, and holiday/card.php. When set, the custom title is used instead of the default product name.', 'Changing this value rebrands the application name site-wide in all UI areas and outgoing emails that include the application title.', 'String; empty or unset = default ''Dolibarr'' title used', 0, 0, 'admin/security_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res1 = dolibarr_set_const($db, \"MAIN_APPLICATION_TITLE\", GETPOST(\"MAIN_APPLICATION_TITLE\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''MAIN_APPLICATION_TITLE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_APPLY_DISCOUNT_ON_UNIT_PRICE_THEN_ROUND_BEFORE_MULTIPLICATION_BY_QTY', 'string', NULL, 'core', 'When set, applies the line discount to the unit price and rounds the result before multiplying by quantity.', 'Checked in core/lib/price.lib.php at line 201; when truthy, the discounted unit price is rounded (using the rounding key from this constant''s value) before multiplying by quantity (line 203). No admin UI write is present.', 'Enabling this changes the price calculation order: discount is applied to unit price first, then rounded, then multiplied by qty; this can produce slightly different totals from the default behavior.', 'Non-empty string = rounding key used in price2num; empty/unset = standard calculation (discount applied after multiplication).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/price.lib.php:201|check|if ($remise_percent_ligne && getDolGlobalString(''MAIN_APPLY_DISCOUNT_ON_UNIT_PRICE_THEN_ROUND_BEFORE_MULTIPLICATION_BY_QTY'')) {", "core/lib/price.lib.php:203|read|$tot_avec_remise_ligne = (float) price2num($pu * (1 - ((float) $remise_percent_ligne / 100)), getDolGlobalString(''MAIN_APPLY_DISCOUNT_ON_UNIT_PRICE_THEN_ROUND_BEFORE_MULTIPLICATION_BY_QTY''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL', 'string', NULL, 'admin', 'Stores the OpenID Connect authorization endpoint URL used to initiate OIDC login.', 'Written by admin/openid_connect.php:87 and read in core/lib/openid_connect.lib.php:99 to build the OIDC authorization redirect URL. Configurable via admin/openid_connect.php.', 'Changing this value points the OIDC login flow to a different authorization server; an incorrect URL prevents OIDC authentication.', 'String: full HTTPS URL of the OIDC authorization endpoint.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:87|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL'', $authorize_url, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:99|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL'').''?client_id=''.urlencode(getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'')).''&redirect_uri=''.urlencode(ope", "admin/openid_connect.php:286|read|print ''<input name=\"MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL\" ...''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_CLAIM_EMAIL', 'string', NULL, 'admin', 'Specifies the OIDC claim name used to extract the user''s email address from the identity token.', 'Written by admin/openid_connect.php:150 and read in core/lib/openid_connect.lib.php:121 with a default of ''email''. Configurable via admin/openid_connect.php.', 'Changing this value allows mapping a non-standard claim (e.g. a custom claim name) to the Dolibarr user''s email field; an incorrect value causes the email not to be populated after OIDC login.', 'String: OIDC claim name (default ''email'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:150|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_CLAIM_EMAIL'', $value, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:121|read|$claim_email = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLAIM_EMAIL'', ''email'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_CLAIM_FIRSTNAME', 'string', NULL, 'admin', 'Specifies the OIDC claim name used to extract the user''s first name from the identity token.', 'Written by admin/openid_connect.php:136 and read in core/lib/openid_connect.lib.php:122 with a default of ''given_name''. Configurable via admin/openid_connect.php.', 'Changing this value maps a custom OIDC claim to the Dolibarr user''s firstname field; an incorrect claim name results in the firstname not being set after login.', 'String: OIDC claim name (default ''given_name'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:136|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_CLAIM_FIRSTNAME'', $value, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:122|read|$claim_firstname = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLAIM_FIRSTNAME'', ''given_name'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_CLAIM_LASTNAME', 'string', NULL, 'admin', 'Specifies the OIDC claim name used to extract the user''s last name from the identity token.', 'Written by admin/openid_connect.php:143 and read in core/lib/openid_connect.lib.php:123 with a default of ''family_name''. Configurable via admin/openid_connect.php.', 'Changing this value maps a custom OIDC claim to the Dolibarr user''s lastname field; an incorrect claim name results in the lastname not being set after login.', 'String: OIDC claim name (default ''family_name'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:143|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_CLAIM_LASTNAME'', $value, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:123|read|$claim_lastname = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLAIM_LASTNAME'', ''family_name'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_CLIENT_ID', 'string', NULL, 'core', 'Stores the OAuth2/OIDC client identifier registered with the identity provider.', 'Written by admin/openid_connect.php:66. Used in the authorization URL (core/lib/openid_connect.lib.php:99), the token request (core/login/functions_openid_connect.php:94), and the logout URL (user/logout.php:116). Configurable via admin/openid_connect.php.', 'An incorrect or missing client ID causes all OIDC authentication and logout flows to fail.', 'String: client_id value as registered with the identity provider.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:66|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'', $client_id, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:99|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL'').''?client_id=''.urlencode(getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'')).", "core/login/functions_openid_connect.php:94|read|''client_id''     => getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID''),", "user/logout.php:116|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_LOGOUT_URL'') . ''?client_id='' . getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'') . ''&returnTo='' . urlencode($url);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_CLIENT_SECRET', 'string', NULL, 'admin', 'Stores the OAuth2/OIDC client secret used to authenticate Dolibarr with the OpenID Connect provider.', 'Written via admin/openid_connect.php:73 and read in core/login/functions_openid_connect.php:95 as ''client_secret'' in the authentication parameter array. Displayed as a password input in admin/openid_connect.php:270.', 'Changing this secret invalidates the current OIDC provider handshake; the new secret must match what is registered at the identity provider.', 'Arbitrary secret string provided by the OIDC identity provider. Must be kept confidential.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:73|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_CLIENT_SECRET'', $client_secret, ''chaine'', 0, '''', 0);", "core/login/functions_openid_connect.php:95|read|''client_secret'' => getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_SECRET''),", "admin/openid_connect.php:270|read|print ''<input type=\"password\" name=\"MAIN_AUTHENTICATION_OIDC_CLIENT_SECRET\"..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR', 'string', NULL, 'admin', 'Specifies the default Dolibarr user ID to assign as creator when a new user is provisioned via OpenID Connect.', 'Read in core/lib/openid_connect.lib.php:169 via getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR'', 1) to set the creator_id for new OIDC-provisioned accounts. Configured via admin/openid_connect.php where it is written with dolibarr_set_const.', 'Changing this value alters which user is recorded as the creator for all newly provisioned OIDC accounts. If unset, the fallback default of 1 (superadmin) is used.', 'Integer user ID. Falls back to 1 when not set (getDolGlobalInt default).', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:129|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR'', $value, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:169|read|$creator_id = getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR'', 1);", "admin/openid_connect.php:361|read|$creator_val = GETPOSTISSET(''MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR'') ? GETPOSTINT(''MAIN_AUTHENTICATION_OIDC_DEFAULT_CREATOR'') : getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAULT"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP', 'string', NULL, 'admin', 'Specifies the default Dolibarr group ID to assign to a new user provisioned via OpenID Connect.', 'Read in core/lib/openid_connect.lib.php:190 via getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP'') to determine the group for new OIDC accounts. Configured and written in admin/openid_connect.php.', 'Changing this value changes the group membership assigned to all newly created OIDC accounts. If unset, no default group is applied.', 'Integer group ID. No default applied when absent.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:122|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP'', $value, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:190|read|$default_group = getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP'');", "admin/openid_connect.php:370|read|$defaultgroup_val = GETPOSTISSET(''MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP'') ? GETPOSTINT(''MAIN_AUTHENTICATION_OIDC_DEFAULT_GROUP'') : getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_DEFAUL"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_LOGIN_CLAIM', 'string', NULL, 'core', 'Specifies which OIDC userinfo claim field is used as the Dolibarr login identifier.', 'Written via admin/openid_connect.php:59 and checked/read in core/login/functions_openid_connect.php:135-136: when set, $login_claim is assigned the constant''s value to identify which claim from the userinfo response maps to the Dolibarr username. Displayed in admin/openid_connect.php:254.', 'Changing this constant alters which claim from the OIDC userinfo response is matched against Dolibarr usernames. An incorrect claim name will prevent login matching.', 'String name of the OIDC claim (e.g. ''email'', ''preferred_username''). Empty/unset = default claim used.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/login/functions_openid_connect.php:135|check|if (getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_LOGIN_CLAIM'')) {", "core/login/functions_openid_connect.php:136|read|$login_claim = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_LOGIN_CLAIM'');", "admin/openid_connect.php:59|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_LOGIN_CLAIM'', $client_id, ''chaine'', 0, '''', 0);", "admin/openid_connect.php:254|read|print ''<input name=\"MAIN_AUTHENTICATION_OIDC_LOGIN_CLAIM\"..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_LOGOUT_URL', 'string', NULL, 'admin', 'Stores the OpenID Connect provider''s logout endpoint URL used to redirect users on Dolibarr logout.', 'Configured via admin/openid_connect.php and consumed in user/logout.php:111-116, where it is appended with client_id and returnTo parameters to build the full OIDC logout redirect URL. Requires MAIN_AUTHENTICATION_OIDC_ON to be active.', 'Setting this URL enables single sign-out with the OIDC provider; leaving it empty means logout only clears the Dolibarr session without notifying the identity provider.', 'String; a valid HTTPS URL to the OIDC provider''s end_session_endpoint.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:108|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_LOGOUT_URL'', $logout_url, ''chaine'', 0, '''', 0);", "user/logout.php:111|check|if (getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_ON'', 0) > 0 && !empty($_SESSION[''OPENID_CONNECT'']) && getDolGlobalString(\"MAIN_AUTHENTICATION_OIDC_LOGOUT_URL\")) {", "user/logout.php:116|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_LOGOUT_URL'') . ''?client_id='' . getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'') . ''&returnTo='' . urlencode($url);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_ON', 'string', NULL, 'core', 'Enables OpenID Connect (OIDC) authentication and shows the OIDC login button on the login page.', 'When set to a positive integer, core/tpl/login.tpl.php:181 and 452 render the OIDC login button if the openid_connect authentication method is configured. Also controls OIDC logout redirect at user/logout.php:111 and is required by core/login/functions_openid_connect.php:45. Configurable via admin/openid_connect.php.', 'Setting this to a positive integer activates OIDC login and logout integration; setting it to 0 or leaving it unset disables OIDC UI elements.', 'Positive integer = OIDC enabled and login button shown; 0 or unset = OIDC disabled.', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:181|check|if (getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_ON'', 0) > 0 && isset($conf->file->main_authentication) && preg_match(''/openid_connect/'', $conf->file->main_authentication)) {", "core/login/functions_openid_connect.php:45|check|if (getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_ON'', 0) <= 0) {", "user/logout.php:111|check|if (getDolGlobalInt(''MAIN_AUTHENTICATION_OIDC_ON'', 0) > 0 && !empty($_SESSION[''OPENID_CONNECT'']) && getDolGlobalString(\"MAIN_AUTHENTICATION_OIDC_LOGOUT_URL\")) {", "admin/openid_connect.php:199|check|if (!getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_ON'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_SCOPES', 'string', NULL, 'admin', 'Stores the OAuth2 scopes requested during the OIDC authorization flow.', 'Written by admin/openid_connect.php:80 and included in the authorization URL built in core/lib/openid_connect.lib.php:99. Configurable via admin/openid_connect.php.', 'Changing the scopes alters what user information is requested from the identity provider; missing required scopes (e.g. ''openid'', ''email'') cause authentication failures.', 'Space-separated string of OAuth2 scope names (e.g. ''openid email profile'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:80|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_SCOPES'', $scopes, ''chaine'', 0, '''', 0);", "core/lib/openid_connect.lib.php:99|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_AUTHORIZE_URL'').''?client_id=''.urlencode(getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_CLIENT_ID'')).''&redirect_uri=''.urlencode(ope", "admin/openid_connect.php:278|read|print ''<input name=\"MAIN_AUTHENTICATION_OIDC_SCOPES\" ...''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_TOKEN_URL', 'string', NULL, 'admin', 'Specifies the token endpoint URL of the OpenID Connect provider used to exchange an authorization code for tokens.', 'Written via admin/openid_connect.php:94 and read in core/login/functions_openid_connect.php:100 via getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_TOKEN_URL'') as the target of a POST request to obtain tokens. Displayed in admin/openid_connect.php:294.', 'Setting an incorrect URL will cause OIDC token exchange to fail and prevent user login via OpenID Connect. Must match the provider''s token endpoint.', 'URL string of the OIDC token endpoint (e.g. ''https://provider.example.com/token'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:94|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_TOKEN_URL'', $value, ''chaine'', 0, '''', 0);", "core/login/functions_openid_connect.php:100|read|$token_response = getURLContent(getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_TOKEN_URL''), ''POST'', http_build_query($auth_param), 1, array(), array(''https''), 2);", "admin/openid_connect.php:294|read|print ''<input name=\"MAIN_AUTHENTICATION_OIDC_TOKEN_URL\"..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OIDC_USERINFO_URL', 'string', NULL, 'admin', 'Specifies the userinfo endpoint URL of the OpenID Connect provider used to retrieve authenticated user attributes.', 'Written via admin/openid_connect.php:101 and read in core/login/functions_openid_connect.php:128 via getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_USERINFO_URL'') as the target of a GET request for user information. Displayed in admin/openid_connect.php:302.', 'Setting an incorrect URL will cause user attribute retrieval to fail after token exchange, preventing successful OIDC login. Must match the provider''s userinfo endpoint.', 'URL string of the OIDC userinfo endpoint (e.g. ''https://provider.example.com/userinfo'').', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/openid_connect.php:101|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OIDC_USERINFO_URL'', $value, ''chaine'', 0, '''', 0);", "core/login/functions_openid_connect.php:128|read|$userinfo_response = getURLContent(getDolGlobalString(''MAIN_AUTHENTICATION_OIDC_USERINFO_URL''), ''GET'', '''', 1, $userinfo_headers, array(''https''), 2);", "admin/openid_connect.php:302|read|print ''<input name=\"MAIN_AUTHENTICATION_OIDC_USERINFO_URL\"..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OPENID_URL', 'string', NULL, 'core', 'Stores the base URL for the OpenID Connect authentication provider used on the login page.', 'Read in core/tpl/login.tpl.php:461 and core/class/openid.class.php:386 and :509 to construct the OpenID Connect authorization URL. No admin UI write found; HIDDEN_GUESS is 1.', 'When set, the login page displays an OpenID Connect login button linking to this URL with the OIDC state parameter appended. Removing it disables the OpenID Connect login option.', 'Any valid OpenID Connect authorization endpoint URL', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:458|check|if (!getDolGlobalString(\"MAIN_AUTHENTICATION_OPENID_URL\")) {", "core/tpl/login.tpl.php:461|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OPENID_URL'').''&state='' . openid_connect_get_state();", "core/class/openid.class.php:386|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OPENID_URL'');", "core/class/openid.class.php:509|read|$url = getDolGlobalString(''MAIN_AUTHENTICATION_OPENID_URL'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTHENTICATION_OPENID_URL_IMG', 'string', NULL, 'admin', 'Stores the URL of a logo image to display on the OpenID Connect login button.', 'Written via admin/openid_connect.php:115 and displayed in core/tpl/login.tpl.php:467. When the value is set, an img tag with height 50px is rendered; otherwise a translatable label is shown.', 'Changing this URL updates the image shown on the OpenID Connect login button on the login page.', 'Any valid image URL string; empty/unset shows default text label', 0, 0, 'admin/openid_connect.php|admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/openid_connect.php:115|write|$res = dolibarr_set_const($db, ''MAIN_AUTHENTICATION_OPENID_URL_IMG'', $openid_url_img, ''chaine'', 0, '''', 0);", "core/tpl/login.tpl.php:467|read|print getDolGlobalString(''MAIN_AUTHENTICATION_OPENID_URL_IMG'') ? ''<img src=\"''.getDolGlobalString(''MAIN_AUTHENTICATION_OPENID_URL_IMG'').''\" height=\"50px\" >'' : $langs->trans(\"LoginUsi", "admin/openid_connect.php:334|read|print ''<input name=\"MAIN_AUTHENTICATION_OPENID_URL_IMG\" id=\"MAIN_AUTHENTICATION_OPENID_URL_IMG\" class=\"minwidth400 centpercent\" value=\"...''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTOFILL_DATE', 'string', NULL, 'fourn', 'Controls whether date fields on payment and invoice forms are pre-filled with the current date.', 'Read in 11 locations across payment and invoice pages (e.g. fourn/commande/card.php:1922, compta/paiement.php:528, salaries/payment_salary.php:219). When truthy, the date variable is set to an empty string (triggering today''s date autofill); when falsy, it is set to -1 (leaving the field empty).', 'Enabling this constant pre-fills date fields with today''s date on payment and invoice entry forms; disabling leaves date fields blank by default.', 'Non-empty/non-zero = date fields auto-filled with current date; 0 or unset = date fields left empty.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:1922|read|$dateinvoice\t\t= getDolGlobalString(''MAIN_AUTOFILL_DATE'') ? '''' : -1;", "compta/paiement.php:528|read|$datepayment = ($datepayment == '''' ? (getDolGlobalString(''MAIN_AUTOFILL_DATE'') ? '''' : -1) : $datepayment);", "salaries/payment_salary.php:219|read|$datepayment = getDolGlobalString(''MAIN_AUTOFILL_DATE'') ? '''' : (GETPOST(\"remonth\") ? $datepaye : -1);", "fourn/facture/paiement.php:403|read|$dateinvoice = ($datefacture == '''' ? (getDolGlobalString(''MAIN_AUTOFILL_DATE'') ? '''' : -1) : $datefacture);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTOFILL_DATE_ORDER', 'string', NULL, 'commande', 'Controls whether the order date field is auto-filled with the current date on the order creation form.', 'Read in commande/card.php:2227 and commande/card.php:2257. When set, $dateorder is set to '''' (which triggers auto-fill); when not set, it is set to -1 (keep empty). No admin UI write is present.', 'Setting this constant causes the order date field to be pre-populated with today''s date. Leaving it unset keeps the date field empty by default.', 'Truthy = date auto-filled; falsy or unset = date field left empty (-1).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:2227|read|$dateorder = getDolGlobalString(''MAIN_AUTOFILL_DATE_ORDER'') ? '''' : -1;", "commande/card.php:2257|read|$dateorder = getDolGlobalString(''MAIN_AUTOFILL_DATE_ORDER'') ? '''' : -1;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTO_OPEN_SELECT2_ON_FOCUS_FOR_CUSTOMER_PRODUCTS', 'string', NULL, 'core', 'Automatically opens the Select2 dropdown on focus for the customer product selector in document lines.', 'When enabled, the Select2 widget for customer products on document line creation forms opens automatically upon receiving focus. Referenced in core/tpl/objectline_create.tpl.php:302.', 'Enabling this constant changes the focus behavior of the customer product selector, opening the dropdown immediately without a click.', 'Truthy value = auto-open on focus; empty/unset = standard Select2 behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:302|check|if (getDolGlobalString(''MAIN_AUTO_OPEN_SELECT2_ON_FOCUS_FOR_CUSTOMER_PRODUCTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTO_OPEN_SELECT2_ON_FOCUS_FOR_SUPPLIER_PRODUCTS', 'string', NULL, 'core', 'Automatically opens the Select2 dropdown on focus for the supplier product selector in document lines.', 'When enabled, the Select2 widget for supplier products on document line creation forms opens automatically upon receiving focus. Referenced in core/tpl/objectline_create.tpl.php:344.', 'Enabling this constant changes the focus behavior of the supplier product selector, opening the dropdown immediately without a click.', 'Truthy value = auto-open on focus; empty/unset = standard Select2 behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:344|check|if (getDolGlobalString(''MAIN_AUTO_OPEN_SELECT2_ON_FOCUS_FOR_SUPPLIER_PRODUCTS'')) {", "core/tpl/objectline_create.tpl.php:350  //console.log(''focus on a select2 because of MAIN_AUTO_OPEN_SELECT2_ON_FOCUS_FOR_SUPPLIER_PRODUCTS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTO_TIMESTAMP_IN_PRIVATE_NOTES', 'string', NULL, 'core', 'Automatically prepend a timestamp when saving private notes on a record.', 'When enabled, Dolibarr inserts a timestamp into private notes at save time. Checked in core/tpl/notes.tpl.php:74.', 'Enabling this causes every save of a private note to prepend a timestamp, making note history traceable.', 'Empty/not set = disabled; any truthy string = enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/notes.tpl.php:74|check|if (getDolGlobalString(''MAIN_AUTO_TIMESTAMP_IN_PRIVATE_NOTES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_AUTO_TIMESTAMP_IN_PUBLIC_NOTES', 'string', NULL, 'core', 'Automatically prepend a timestamp when saving public notes on a record.', 'When enabled, Dolibarr inserts a timestamp into public notes at save time. Checked in core/tpl/notes.tpl.php:63.', 'Enabling this causes every save of a public note to prepend a timestamp, making note history traceable.', 'Empty/not set = disabled; any truthy string = enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/notes.tpl.php:63|check|if (getDolGlobalString(''MAIN_AUTO_TIMESTAMP_IN_PUBLIC_NOTES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BANK_ACCOUNTANCY_CODE_ALWAYS_REQUIRED', 'string', NULL, 'compta', 'Makes the accountancy code field mandatory when creating or updating a bank account.', 'Checked in compta/bank/card.php at lines 210, 320, 653, and 1120 to enforce that account_number is not empty and to mark the accountancy code field as required in the UI.', 'Enabling this constant prevents saving a bank account without an accountancy code, enforcing accounting integration compliance.', 'Truthy value = accountancy code required; empty/unset = field optional.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/card.php:210|check|if (getDolGlobalInt(''MAIN_BANK_ACCOUNTANCY_CODE_ALWAYS_REQUIRED'') && empty($object->account_number)) {", "compta/bank/card.php:320|check|if (getDolGlobalInt(''MAIN_BANK_ACCOUNTANCY_CODE_ALWAYS_REQUIRED'') && empty($object->account_number)) {", "compta/bank/card.php:653|check|if (getDolGlobalString(''MAIN_BANK_ACCOUNTANCY_CODE_ALWAYS_REQUIRED'')) {", "compta/bank/card.php:1120|check|if (getDolGlobalString(''MAIN_BANK_ACCOUNTANCY_CODE_ALWAYS_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BARCODE_CODE_ALWAYS_REQUIRED', 'string', NULL, 'core', 'Forces barcode codes to be required even when the active barcode module marks them as optional.', 'When set, core/modules/barcode/modules_barcode.class.php overrides the code_null flag at six check points (lines 163, 167, 174, 178, 185, 189), making barcode entry mandatory regardless of the module''s own nullability setting.', 'Enabling this makes barcode entry mandatory system-wide; disabling it defers to each module''s own code_null setting.', 'Any non-empty string value forces barcode codes to be required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/barcode/modules_barcode.class.php:163|check|if (getDolGlobalString(''MAIN_BARCODE_CODE_ALWAYS_REQUIRED'') && !empty($this->code_null)) {", "core/modules/barcode/modules_barcode.class.php:167|check|if (getDolGlobalString(''MAIN_BARCODE_CODE_ALWAYS_REQUIRED'') && !empty($this->code_null)) {", "core/modules/barcode/modules_barcode.class.php:174|check|if (getDolGlobalString(''MAIN_BARCODE_CODE_ALWAYS_REQUIRED'') && !empty($this->code_null)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BOX_ACTIVITY_DURATION', 'string', NULL, 'core', 'Sets the number of periods used to calculate the activity duration displayed in the activity dashboard box.', 'Checked and read in core/boxes/box_activity.php at lines 85 and 86; the value is assigned to $nbofperiod.', 'Changing this constant alters how many periods are included in the activity box calculations.', 'Integer number of periods; empty/unset = default period used by the box.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_activity.php:85|check|if (getDolGlobalString(''MAIN_BOX_ACTIVITY_DURATION'')) {", "core/boxes/box_activity.php:86|read|$nbofperiod = getDolGlobalString(''MAIN_BOX_ACTIVITY_DURATION'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BOX_ENABLE_BEST_CUSTOMERS', 'bool', NULL, 'core', 'Enables display of the best customers dashboard box.', 'Checked in core/boxes/box_goodcustomers.php:60; the box is skipped when this constant is not set.', 'Enabling this constant activates the best customers dashboard widget; without it the box does not render.', 'Truthy value = box enabled; empty/unset = box disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_goodcustomers.php:60|check|if (!getDolGlobalString(''MAIN_BOX_ENABLE_BEST_CUSTOMERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BROWSER_NOTIFICATION_CHECK_FIRST_EXECUTION', 'string', NULL, 'core', 'Sets the delay (in seconds) before the first browser notification check runs after page load (minimum 3).', 'Read in core/js/lib_notification.js.php:102 as: max(3, getDolGlobalInt(''MAIN_BROWSER_NOTIFICATION_CHECK_FIRST_EXECUTION'', 0)). Values below 3 are clamped to 3.', 'Increasing the value delays the first notification poll after page load; values below 3 have no effect due to the clamping.', 'Integer number of seconds; values below 3 are clamped to 3; default is 0 (clamped to 3)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["var time_first_execution = <?php echo max(3, getDolGlobalInt(''MAIN_BROWSER_NOTIFICATION_CHECK_FIRST_EXECUTION'', 0)); ?>;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BROWSER_NOTIFICATION_FREQUENCY', 'string', NULL, 'core', 'Sets the polling interval (in seconds) for browser-side agenda notifications.', 'Read in core/js/lib_notification.js.php:75 where it is used as: max(1, getDolGlobalInt(''MAIN_BROWSER_NOTIFICATION_FREQUENCY'')). A commented-out reference also appears in core/ajax/check_notifications.php:107 noting it is ''Always defined''.', 'Increasing the value reduces polling frequency; decreasing it increases how often the browser checks for new notifications.', 'Integer number of seconds >= 1; values below 1 are clamped to 1', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["/*$time_update = (int) $conf->global->MAIN_BROWSER_NOTIFICATION_FREQUENCY; // Always defined", "print ''var time_auto_update = ''.max(1, getDolGlobalInt(''MAIN_BROWSER_NOTIFICATION_FREQUENCY'')).'';''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BUGTRACK_ENABLELINK', 'bool', NULL, 'core', 'Enables a bug-tracker link in the footer, optionally pointing to GitHub or a custom URL.', 'Written in admin/ihm.php:287 and displayed as a text input at :545. Checked in main.inc.php:3335, :3389, :3392, and :3427-3428 to render the bug-tracker link; ''github'' triggers a GitHub-specific URL, any other value is used directly as the base URL.', 'Setting to ''github'' adds a link to the GitHub issue tracker; setting to another URL uses that as the bug base URL; unsetting removes the link.', ''''' or unset = bug tracker link hidden; ''github'' = link to GitHub issues; any other URL string = link to that URL', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3392|check|if (getDolGlobalString(''MAIN_BUGTRACK_ENABLELINK'') == ''github'') {", "main.inc.php:3427|read|} elseif (getDolGlobalString(''MAIN_BUGTRACK_ENABLELINK'')) {", "main.inc.php:3428|read|$bugbaseurl = getDolGlobalString(''MAIN_BUGTRACK_ENABLELINK'');", "admin/ihm.php:545|read|print ''<input type=\"text\" name=\"MAIN_BUGTRACK_ENABLELINK\" value=\"'' . getDolGlobalString(''MAIN_BUGTRACK_ENABLELINK'') . ''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BUILD_LOGIN_RULE', 'string', NULL, 'core', 'Specifies the algorithm used to auto-generate a login from a user''s first and last name.', 'Checked in core/lib/functions2.lib.php and user/card.php (5 occurrences total): values ''flastname'' and ''f.lastname'' select different formatting rules. The comment at functions2.lib.php:2004 shows the example value ''f.lastname''.', 'Setting this determines the pattern of auto-generated logins; leaving it unset uses the default login construction logic.', '''flastname'' = first initial concatenated with last name; ''f.lastname'' = first initial, separator, last name; other/unset = default rule.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2004  //$conf->global->MAIN_BUILD_LOGIN_RULE = ''f.lastname'';", "core/lib/functions2.lib.php:2010|check|if (getDolGlobalString(''MAIN_BUILD_LOGIN_RULE'') == ''flastname'') {", "core/lib/functions2.lib.php:2014|read|} elseif (getDolGlobalString(''MAIN_BUILD_LOGIN_RULE'') == ''f.lastname'') {", "user/card.php:1090|check|if (getDolGlobalString(''MAIN_BUILD_LOGIN_RULE'') == ''flastname'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BUTTON_HIDE_UNAUTHORIZED', 'bool', NULL, 'theme', 'Hides action buttons for non-admin users when they lack permission for the associated action.', 'When enabled, buttons are hidden rather than shown as disabled for users without the required permission. Referenced in core/lib/functions.lib.php:14945, core/class/html.formfile.class.php:194, and theme/eldy/btn.inc.php:412. The admin UI write is commented out in admin/ihm.php:280, suggesting the setting is managed manually or via another mechanism.', 'Enabling this setting removes unauthorised action buttons from the UI for non-admin users, reducing visual clutter and preventing confusion over disabled controls.', 'Empty/0 = disabled (buttons shown as disabled); non-empty = enabled (buttons hidden for non-admin users without permission).', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:14945|check|if (getDolGlobalString(''MAIN_BUTTON_HIDE_UNAUTHORIZED'') && (!$user->admin) && $status <= 0) {", "core/class/html.formfile.class.php:194|check|if (!$perm && getDolGlobalString(''MAIN_BUTTON_HIDE_UNAUTHORIZED'')) {", "theme/eldy/btn.inc.php:412|<?php if (getDolGlobalString(''MAIN_BUTTON_HIDE_UNAUTHORIZED'') && (!$user->admin)) { ?>", "admin/ihm.php:280  //dolibarr_set_const($db, \"MAIN_BUTTON_HIDE_UNAUTHORIZED\", GETPOST(\"MAIN_BUTTON_HIDE_UNAUTHORIZED\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_BUTTON_POSITION_FIRST_OR_LEFT', 'string', NULL, 'core', 'Controls button ordering in action bar: when set, main action button is placed first/left; when unset, the default order is main action first, then complementary, then cancel at end.', 'Checked at core/class/html.form.class.php:12439 via getDolGlobalInt. The comment at :12438 states ''If MAIN_BUTTON_POSITION_FIRST_OR_LEFT not set, default is to have main action first, then complementary, then cancel at end''.', 'Changing this value reorders buttons in action bars throughout the UI. The default (unset/0) already places the main action first, so this constant modifies the complementary/cancel layout.', 'If MAIN_BUTTON_POSITION_FIRST_OR_LEFT not set, default is to have main action first, then complementary, then cancel at end.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:12438  // If MAIN_BUTTON_POSITION_FIRST_OR_LEFT not set, default is to have main action first, then complementary, then cancel at end", "core/class/html.form.class.php:12439|check|if (!getDolGlobalInt(''MAIN_BUTTON_POSITION_FIRST_OR_LEFT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CACHE_COUNT', 'string', NULL, 'core', 'Enables shared memory caching for count/aggregate data when set to a non-empty value.', 'Checked in core/lib/memory.lib.php:78 and 185 before using the cache; the comment at memory.lib.php:61 states: ''Save data into a memory area shared by all users, all sessions on server. Note: MAIN_CACHE_COUNT must be set.'' Displayed and toggled via admin/system/perf.php.', 'Enabling this activates server-wide caching for count data, reducing database load; disabling it means counts are always fetched live.', '0 or unset = no caching; 1 = caching enabled.', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/memory.lib.php:61  * \tSave data into a memory area shared by all users, all sessions on server. Note: MAIN_CACHE_COUNT must be set.", "core/lib/memory.lib.php:78|check|if (!getDolGlobalString(''MAIN_CACHE_COUNT'')) {", "admin/system/perf.php:773|check|if (getDolGlobalInt(''MAIN_CACHE_COUNT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CAN_EDIT_SUPPLIER_ON_SUPPLIER_ORDER', 'string', NULL, 'fourn', 'Allows the supplier (third party) to be changed on a supplier order when the order is in draft status.', 'Checked across 4 occurrences in fourn/commande/card.php:355, :2435, :2444, :2445. When set, an ''edit_thirdparty'' action is available and the supplier field becomes editable on draft orders.', 'Enabling this adds a UI control to change the supplier on a draft supplier order; disabling it prevents supplier modification regardless of status.', 'Empty/0 = supplier cannot be changed after creation; truthy = supplier editable on draft orders', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:355|check|if (getDolGlobalString(''MAIN_CAN_EDIT_SUPPLIER_ON_SUPPLIER_ORDER'') && $action == ''set_thirdparty'' && $usercancreate && $object->status == CommandeFournisseur::STATUS_DRAFT) {", "fourn/commande/card.php:2435|check|if (getDolGlobalString(''MAIN_CAN_EDIT_SUPPLIER_ON_SUPPLIER_ORDER'') && !empty($usercancreate) && $action == ''edit_thirdparty'') {", "fourn/commande/card.php:2444|check|if (!getDolGlobalString(''MAIN_CAN_EDIT_SUPPLIER_ON_SUPPLIER_ORDER'') || $action != ''edit_thirdparty'') {", "fourn/commande/card.php:2445|check|if (getDolGlobalString(''MAIN_CAN_EDIT_SUPPLIER_ON_SUPPLIER_ORDER'') && $object->status == CommandeFournisseur::STATUS_DRAFT) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CARE_GRANDCHILD', 'string', NULL, 'core', 'Controls whether grandchild object relationships are processed during object operations.', 'Read as an integer in core/class/commonobject.class.php:3554. When set, the result governs grandchild handling logic in parent-child object trees.', 'Enabling this constant causes grandchild records to be included in relationship processing; leaving it unset skips grandchild handling.', 'Integer; 0 or unset = grandchild not processed; non-zero = grandchild processed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:3554|read|$grandchild = getDolGlobalInt(''MAIN_CARE_GRANDCHILD'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION', 'string', NULL, 'fourn', 'Controls whether the product description and line description are concatenated in inverted order when adding a product line to a document.', 'Read across 9 files including supplier_proposal/card.php:888, fourn/commande/card.php:712, comm/propal/card.php:1562, and reception/card.php:1012, always passed as the `$invert` parameter to `dol_concatdesc`. COMMENT from core/lib/functions.lib.php:10166: `@param bool $invert invert order of description lines (we often use config MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION in this parameter)`.', 'Enabling this setting causes the product description to be appended after the line description (inverted order) rather than before it.', 'Truthy string (non-empty) = invert concatenation order; empty/not set = normal concatenation order.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:10166  *  @param  bool    $invert         invert order of description lines (we often use config MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION in this parameter)", "supplier_proposal/card.php:888|read|$desc = dol_concatdesc($desc, $line_desc, false, getDolGlobalString(''MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION'') ? true : false);", "fourn/commande/card.php:712|read|$desc = dol_concatdesc($desc, $line_desc, false, getDolGlobalString(''MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION'') ? true : false);", "comm/propal/card.php:1562|read|$desc = dol_concatdesc($desc, $line_desc, false, getDolGlobalString(''MAIN_CHANGE_ORDER_CONCAT_DESCRIPTION'') ? true : false);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CHECKBOX_LEFT_COLUMN', 'string', NULL, 'compta', 'Moves the row-selection checkbox column from the right side to the left side of list tables.', 'Checked in 791 locations across virtually all list pages (e.g. accountancy/admin/template/list.php:438, accountancy/admin/subaccount.php:367). Each list page checks this constant twice — once to render the left checkbox column and once to omit the right checkbox column.', 'Enabling this constant repositions row checkboxes to the leftmost column on all list views, changing the visual layout of every list page.', 'Non-empty = checkboxes on the left; 0 or unset = checkboxes on the right.', 0, 0, 'accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/template/list.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/report_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/categories_list.php|accountancy/admin/account.php|accountancy/admin/account.php|accountancy/admin/account.php|accountancy/admin/account.php|accountancy/admin/account.php|accountancy/admin/account.php|accountancy/admin/account.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|blockedlog/admin/blockedlog_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/emailcollector_list.php|admin/system/modules.php|admin/system/modules.php|admin/system/modules.php|admin/system/modules.php|admin/system/modules.php|admin/system/modules.php|admin/system/modules.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/mails_senderprofile_list.php|admin/tools/listevents.php|admin/tools/listevents.php|admin/tools/listevents.php|admin/tools/listevents.php|admin/tools/listevents.php|admin/tools/listevents.php|admin/dict.php|admin/dict.php|admin/dict.php|admin/dict.php|admin/dict.php|admin/dict.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/template/list.php:438|check|if (getDolGlobalString(''MAIN_CHECKBOX_LEFT_COLUMN'')) {", "accountancy/admin/template/list.php:489|check|if (!getDolGlobalString(''MAIN_CHECKBOX_LEFT_COLUMN'')) {", "accountancy/admin/subaccount.php:367|check|if (getDolGlobalString(''MAIN_CHECKBOX_LEFT_COLUMN'')) {", "accountancy/admin/subaccount.php:388|check|if (!getDolGlobalString(''MAIN_CHECKBOX_LEFT_COLUMN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_COMPANY_CODE_ALWAYS_REQUIRED', 'string', NULL, 'core', 'Forces company/product codes to be mandatory even when the numbering module allows null codes.', 'When set, code generator modules such as core/modules/societe/mod_codeclient_monkey.php:176 and core/modules/product/mod_codeproduct_leopard.php:124 treat an empty code as an error regardless of the module''s code_null setting. Also enforced during member subscription at adherents/subscription.php:935. No admin UI is provided.', 'Enabling this constant prevents saving records without a code, overriding any ''optional code'' setting in the active numbering module.', 'Non-empty/truthy = code always required; empty/unset = code requirement follows the numbering module''s code_null setting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/product/mod_codeproduct_leopard.php:124|check|} elseif (empty($code) && (!$this->code_null || getDolGlobalString(''MAIN_COMPANY_CODE_ALWAYS_REQUIRED''))) {", "core/modules/societe/mod_codeclient_monkey.php:176|check|} elseif (empty($code) && (!$this->code_null || getDolGlobalString(''MAIN_COMPANY_CODE_ALWAYS_REQUIRED''))) {", "core/modules/product/modules_product.class.php:137|check|if (getDolGlobalString(''MAIN_COMPANY_CODE_ALWAYS_REQUIRED'') && !empty($this->code_null)) {", "adherents/subscription.php:935|check|if (getDolGlobalString(''MAIN_COMPANY_CODE_ALWAYS_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_COMPANY_PERENTITY_SHARED', 'string', NULL, 'accountancy', 'When enabled, uses per-entity company accounting account records instead of shared company account data.', 'Configured via accountancy/admin/index.php:490. Checked in 46 locations including societe/class/societe.class.php:1120, :1842, :2530, accountancy/customer/index.php:141 and :148, and accountancy/customer/lines.php:245 and :273.', 'Enabling this constant switches third-party (societe) accounting account lookups to per-entity tables, supporting distinct account assignments per entity in a multi-company setup.', 'Non-empty = use per-entity company accounting accounts; empty/unset = use shared company accounts', 0, 0, 'accountancy/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:490|check|if (getDolGlobalString(''MAIN_COMPANY_PERENTITY_SHARED'')) {", "societe/class/societe.class.php:1120|check|if (getDolGlobalString(''MAIN_COMPANY_PERENTITY_SHARED'')) {", "societe/class/societe.class.php:1842|check|if (!$error && getDolGlobalString(''MAIN_COMPANY_PERENTITY_SHARED'')) {", "accountancy/customer/index.php:141|check|if (getDolGlobalString(''MAIN_COMPANY_PERENTITY_SHARED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CONTRACT_CODE_ALWAYS_REQUIRED', 'string', NULL, 'core', 'Forces contract reference codes to always be required, even when the numbering module allows null codes.', 'Used in core/modules/contract/mod_contract_olive.php to override the module''s code_null property. When set, an empty contract code triggers a validation error regardless of the module''s default behavior. No admin UI write is present; hidden setting.', 'Enabling this constant makes contract code mandatory even when the active numbering module would normally allow it to be empty; disabling it defers to the module''s own code_null setting.', 'Non-empty (truthy) forces code to be required; empty or undefined defers to module default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/contract/mod_contract_olive.php:110|check|if (empty($code) && $this->code_null && !getDolGlobalString(''MAIN_CONTRACT_CODE_ALWAYS_REQUIRED'')) {", "core/modules/contract/mod_contract_olive.php:112|check|} elseif (empty($code) && (!$this->code_null || getDolGlobalString(''MAIN_CONTRACT_CODE_ALWAYS_REQUIRED''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_COPY_FILE_IN_EVENT_AUTO', 'string', NULL, 'core', 'Controls whether files are copied into automatically created agenda events.', 'Checked in core/triggers/interface_50_modAgenda_ActionsAuto.class.php:1672 after a successful auto-event creation ($ret > 0), to decide whether to copy associated files into the event.', 'Enabling this causes Dolibarr to copy files into events created by the agenda auto-action trigger; disabling skips that file copy step.', '0 or empty = files not copied into auto-created events; non-empty = files copied', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modAgenda_ActionsAuto.class.php:1672|check|if ($ret > 0 && getDolGlobalString(''MAIN_COPY_FILE_IN_EVENT_AUTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CORE_ERROR', 'string', NULL, 'core', 'Signals a core initialization error, preventing normal page rendering.', 'Checked at main.inc.php:3722 to branch into an error display. The comment at :3733 notes the constant cannot be changed once defined.', 'When set, Dolibarr displays a core error state rather than the normal page.', '0 = no core error; non-zero = core error detected', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3722|check|if (getDolGlobalString(''MAIN_CORE_ERROR'')) {", "main.inc.php:3733  //define(\"MAIN_CORE_ERROR\",0);      // Constant was defined and we can''t change value of a constant"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_COUNTER_WITH_LESS_3_DIGITS', 'string', NULL, 'core', 'Allows numbering mask counters with fewer than 3 digits when set to a non-empty value.', 'Checked in core/lib/functions2.lib.php:855 where a counter shorter than 3 digits normally triggers an error; setting this constant bypasses that validation.', 'Setting this permits very short counter masks that would otherwise be rejected, which risks number collision if counter sequences are not carefully managed.', 'Empty/unset = enforce minimum 3-digit counter; any non-empty string = allow shorter counters.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:855|check|if (dol_strlen($maskcounter) < 3 && !getDolGlobalString(''MAIN_COUNTER_WITH_LESS_3_DIGITS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CREATEFROM_KEEP_LINE_ORIGIN_INFORMATION', 'string', NULL, 'compta', 'Changes how origin references are stored on document lines: when set, stores the origin line ID and line type instead of the parent document ID and type.', 'Checked in compta/facture/class/facture.class.php:974, comm/propal/class/propal.class.php:1353, and commande/class/commande.class.php:1116. Multiple docblock comments at propal.class.php:632-633, commande.class.php:1584-1585, and facture.class.php:4160-4161 explain that $origin and $origin_id take line-level values (''orderdet'', ''propaldet'', line id) when set, vs document-level values otherwise. No admin UI is present.', 'Enabling this causes document line origin fields to reference the specific source line (''orderdet''/''propaldet'' + line id) rather than the source document (''order''/''propal'' + document id).', '0 or unset = origin fields store document-level reference; truthy value = origin fields store line-level reference (''orderdet'', ''propaldet'', etc.).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/propal/class/propal.class.php:632  *      @param\t\tstring\t\t\t$origin\t\t\t\tDepend on global conf MAIN_CREATEFROM_KEEP_LINE_ORIGIN_INFORMATION can be ''orderdet'', ''propaldet''..., else ''order'',''propal,''....", "comm/propal/class/propal.class.php:633  *      @param\t\tint\t\t\t\t$origin_id\t\t\tDepend on global conf MAIN_CREATEFROM_KEEP_LINE_ORIGIN_INFORMATION can be Id of origin object (aka line id), else object id", "commande/class/commande.class.php:1584  * \t@param\t\tstring\t\t    $origin\t\t\t\tDepend on global conf MAIN_CREATEFROM_KEEP_LINE_ORIGIN_INFORMATION can be ''orderdet'', ''propaldet''..., else ''order'',''propal,''....", "compta/facture/class/facture.class.php:974|check|if (getDolGlobalString(''MAIN_CREATEFROM_KEEP_LINE_ORIGIN_INFORMATION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CRON_EXEC_TIME_LIMIT', 'string', NULL, 'cron', 'Sets the PHP execution time limit (in seconds) applied before each cron job runs.', 'Read once at cron/class/cronjob.class.php:1316 using getDolGlobalInt with a default of 600 seconds. No admin UI is provided.', 'Setting this constant overrides the default 600-second PHP execution time limit for cron jobs; lower values may cause long-running jobs to fail.', 'A positive integer representing seconds; default is 600 if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["cron/class/cronjob.class.php:1316|read|$ExecTimeLimit = getDolGlobalInt(''MAIN_CRON_EXEC_TIME_LIMIT'', 600);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CRON_MEMORY_LIMIT', 'string', NULL, 'cron', 'Sets the PHP memory limit applied before each cron job runs.', 'Read once at cron/class/cronjob.class.php:1324 using getDolGlobalString. No admin UI is provided.', 'Setting this constant overrides the PHP memory limit for cron job execution; an insufficient value may cause jobs to fail with out-of-memory errors.', 'A PHP memory limit string (e.g., ''256M'', ''512M''); empty/unset = PHP default memory limit is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["cron/class/cronjob.class.php:1324|read|$MemoryLimit = getDolGlobalString(''MAIN_CRON_MEMORY_LIMIT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CSS_LONGMESSSAGECUT', 'string', NULL, 'theme', 'Sets the maximum height in pixels for long message boxes in the CSS of both Eldy and MD themes.', 'Read in theme/eldy/global.inc.php:1367 and theme/md/style.css.php:1498 with a default of 250 pixels. Two occurrences across two files. No admin UI write is present.', 'Changing this value alters the height at which long message content is clipped in the theme CSS.', 'Integer pixel value; default is 250 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:1367|read|max-height: <?php print getDolGlobalInt(''MAIN_CSS_LONGMESSSAGECUT'', 250); ?>px;", "theme/md/style.css.php:1498|read|max-height: <?php print getDolGlobalInt(''MAIN_CSS_LONGMESSSAGECUT'', 250); ?>px;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CSS_SHORTMESSSAGECUT', 'string', NULL, 'theme', 'Sets the maximum height in pixels for short message boxes in the CSS of both Eldy and MD themes.', 'Read in theme/eldy/global.inc.php:1361 and theme/md/style.css.php:1492 with a default of 125 pixels. Two occurrences across two files. No admin UI write is present.', 'Changing this value alters the height at which short message content is clipped in the theme CSS.', 'Integer pixel value; default is 125 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:1361|read|max-height: <?php print getDolGlobalInt(''MAIN_CSS_SHORTMESSSAGECUT'', 125); ?>px;", "theme/md/style.css.php:1492|read|max-height: <?php print getDolGlobalInt(''MAIN_CSS_SHORTMESSSAGECUT'', 125); ?>px;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CURL_DEBUG', 'string', NULL, 'core', 'Enables detailed cURL request/response logging to the dolibarr_curl.log file when set.', 'Checked at 8 locations in core/lib/geturl.lib.php. The inline comment at line 33 documents: ''You can enable constant MAIN_CURL_DEBUG to get detail of output/input into dolibarr_curl.log file.'' No admin UI write is present.', 'When enabled, all cURL HTTP calls are logged with full request and response details to dolibarr_curl.log, which aids in debugging outbound HTTP issues. Leaving this on in production generates large log files.', 'Truthy integer (e.g. 1) to enable cURL debug logging; 0 or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/geturl.lib.php:33  * You can enable constant MAIN_CURL_DEBUG to get detail of output/input into dolibarr_curl.log file.", "core/lib/geturl.lib.php:326|check|if (getDolGlobalInt(''MAIN_CURL_DEBUG'')) {", "core/lib/geturl.lib.php:59|check|if (getDolGlobalInt(''MAIN_CURL_DEBUG'')) {", "core/lib/geturl.lib.php:67|check|if (getDolGlobalInt(''MAIN_CURL_DEBUG'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CURL_DISABLE_VERIFYPEER', 'bool', NULL, 'paypal', 'Disables cURL SSL peer certificate verification for outbound HTTP requests including PayPal API calls.', 'Checked at paypal/lib/paypal.lib.php:498 and core/lib/geturl.lib.php:113; when set, CURLOPT_SSL_VERIFYPEER is disabled for the cURL session.', 'Disabling peer verification removes SSL certificate validation, which reduces security for all outbound cURL requests.', '0 or unset = verify peer (default); any truthy value = skip verification.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/lib/paypal.lib.php:498|check|if (getDolGlobalString(''MAIN_CURL_DISABLE_VERIFYPEER'')) {", "core/lib/geturl.lib.php:113|check|if (getDolGlobalString(''MAIN_CURL_DISABLE_VERIFYPEER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CURL_GET_RESPONSE_HEADER', 'string', NULL, 'core', 'Instructs the cURL wrapper to include HTTP response headers in the returned response body.', 'Checked in core/lib/geturl.lib.php at lines 96 and 374. Line 374 comments: ''In this case, response contains header + body''. No admin UI write is present.', 'When enabled, the response returned by the cURL wrapper contains both headers and body concatenated; consuming code must be prepared to parse both. When disabled, only the body is returned.', 'Truthy integer (e.g. 1) to include response headers; 0 or unset for body-only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/geturl.lib.php:96|check|if (getDolGlobalInt(''MAIN_CURL_GET_RESPONSE_HEADER'')) {", "core/lib/geturl.lib.php:374|check|if (getDolGlobalInt(''MAIN_CURL_GET_RESPONSE_HEADER'')) { // In this case, response contains header + body"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CURL_SSLVERSION', 'string', NULL, 'core', 'Overrides the SSL/TLS version used by the Dolibarr cURL HTTP client.', 'Checked and read in core/lib/geturl.lib.php at lines 102-103. When set, the value is interpreted as either a numeric cURL constant or a named constant string, and passed as the CURLOPT_SSLVERSION option. No admin UI write is present.', 'When set, forces all outbound cURL requests to use the specified SSL version, which can resolve compatibility issues with certain servers or cause connection failures if the version is unsupported.', 'Numeric cURL CURLOPT_SSLVERSION value (e.g. 6 for TLSv1.2) or a named constant string (e.g. ''CURL_SSLVERSION_TLSv1_2''); empty or unset uses the cURL default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/geturl.lib.php:102|check|if (getDolGlobalString(''MAIN_CURL_SSLVERSION'')) {", "core/lib/geturl.lib.php:103|read|$sslversion = is_numeric(getDolGlobalString(''MAIN_CURL_SSLVERSION'')) ? getDolGlobalInt(''MAIN_CURL_SSLVERSION'') : constant(getDolGlobalString(''MAIN_CURL_SSLVERSION''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_CUSTOMERS_ARE_COMPANIES_EVEN_IF_SET_AS_INDIVIDUAL', 'string', NULL, 'societe', 'Forces customers to be treated as companies even when explicitly set as individuals.', 'Checked in societe/class/societe.class.php at line 4478; a source comment notes it is ''never or rarely set''.', 'Setting this constant overrides the individual classification for customers and treats them as companies regardless of their stored type.', '0 or empty = individual setting respected; any truthy value = customer always treated as company', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4478|check|if (!getDolGlobalString(''MAIN_CUSTOMERS_ARE_COMPANIES_EVEN_IF_SET_AS_INDIVIDUAL'')) {\t// never or rarely set"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DASHBOARD_USE_TOTAL_HT', 'bool', NULL, 'comm', 'Switches commercial dashboard amount columns from TTC (tax-inclusive) to HT (tax-exclusive) totals.', 'Read in at least 8 locations in comm/index.php (lines 193, 225, 229, 297, 326, 330, 398, 429 and more) to select between total_ht and total_ttc when rendering dashboard summary rows.', 'Enabling this causes the commercial dashboard to display pre-tax amounts instead of tax-inclusive totals across all proposal, order, and invoice summary rows.', 'Empty/not set = TTC (tax-inclusive) totals shown; any truthy string = HT (tax-exclusive) totals shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/index.php:193|read|$total += (getDolGlobalString(''MAIN_DASHBOARD_USE_TOTAL_HT'') ? $obj->total_ht : $obj->total_ttc);", "comm/index.php:225|read|print ''<td class=\"nowrap right tdamount amount\">''.price((getDolGlobalString(''MAIN_DASHBOARD_USE_TOTAL_HT'') ? $obj->total_ht : $obj->total_ttc)).''</td>'';", "comm/index.php:297|read|$total += (getDolGlobalString(''MAIN_DASHBOARD_USE_TOTAL_HT'') ? $obj->total_ht : $obj->total_ttc);", "comm/index.php:326|read|print ''<td class=\"nowrap right tdamount amount\">''.price(getDolGlobalString(''MAIN_DASHBOARD_USE_TOTAL_HT'') ? $obj->total_ht : $obj->total_ttc).''</td>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DATABASE_PWD_CONFIG_ENCRYPTED', 'string', NULL, 'admin', 'Marks whether the database password stored in the configuration is encrypted.', 'Referenced in admin/security.php:130 and :142 inside commented-out code. Setting to ''1'' would mark the password as encrypted; deleting the constant would revert to unencrypted.', 'No active effect while commented out; if uncommented, enabling this constant would signal that the database password in conf.php is stored in encrypted form.', '''1'' = password is encrypted; constant absent = password is plain text.', 0, 0, 'admin/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// dolibarr_set_const($db, \"MAIN_DATABASE_PWD_CONFIG_ENCRYPTED\", \"1\");", "// dolibarr_del_const($db, \"MAIN_DATABASE_PWD_CONFIG_ENCRYPTED\",$conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DATE_IN_MEMORY_ARE_NOT_GMT', 'string', NULL, 'core', 'Indicates that dates stored in memory by the application are in local time rather than GMT.', 'Checked at the start of core/lib/date.lib.php:166 to decide the behaviour of date conversion functions. When absent or falsy, dates in memory are treated as GMT (the default Dolibarr convention).', 'Enabling this constant changes how date conversion functions interpret in-memory timestamps; incorrect configuration leads to systematic date offset errors across the application.', 'Empty/unset = dates in memory are GMT (default); truthy value = dates in memory are in local time.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/date.lib.php:166|check|if (!function_exists(''getDolGlobalString'') || !getDolGlobalString(''MAIN_DATE_IN_MEMORY_ARE_NOT_GMT'')) {  // Add function_exists to allow usage of this function with minimal context"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DB_AUTOFIX_BAD_SQL_REQUEST', 'string', NULL, 'core', 'Enables automatic correction of malformed SQL queries in the PostgreSQL database driver.', 'Checked once at core/db/pgsql.class.php:527. No admin UI write was found; HIDDEN_GUESS is 1.', 'When enabled, the PostgreSQL driver attempts to auto-repair SQL requests that would otherwise fail due to syntax or compatibility issues.', '0 (no auto-fix) or 1 (auto-fix bad SQL)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/db/pgsql.class.php:527|check|if (getDolGlobalString(''MAIN_DB_AUTOFIX_BAD_SQL_REQUEST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEBUG_DOL_BUILDURL', 'string', NULL, 'core', 'Enables debug output for the dol_buildurl() URL construction function.', 'Checked in core/lib/functions.lib.php:1793; debug output is activated when the constant is set. No admin UI write detected.', 'Enabling this constant activates debug-level logging or output inside dol_buildurl(). It should only be set in development or troubleshooting contexts.', 'Non-empty = debug output active; absent/empty = debug suppressed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:1793|check|if (getDolGlobalString(''MAIN_DEBUG_DOL_BUILDURL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_END_HOUR', 'string', NULL, 'core', 'Sets the default hour value pre-filled in the service end date hour field on document line forms.', 'When non-empty, jQuery sets the value of #date_endhour to this constant''s value on both the create form (core/tpl/objectline_create.tpl.php:663-664) and the edit form (core/tpl/objectline_edit.tpl.php:481-482).', 'Setting this constant causes the end hour field to be pre-populated with the specified hour value, overriding the blank default.', 'Any non-empty string/integer representing an hour; empty/unset = field left blank.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:663|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_END_HOUR'')) {", "core/tpl/objectline_create.tpl.php:664|read|print ''jQuery(\"#date_endhour\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_END_HOUR'').''\");'';", "core/tpl/objectline_edit.tpl.php:481|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_END_HOUR'') != '''') {", "core/tpl/objectline_edit.tpl.php:482|read|print ''jQuery(\"#date_endhour\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_END_HOUR'').''\");'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_END_MIN', 'string', NULL, 'core', 'Sets the default minute value pre-filled in the service end date minute field on document line forms.', 'When non-empty, jQuery sets the value of #date_endmin to this constant''s value on both the create form (core/tpl/objectline_create.tpl.php:666-667) and the edit form (core/tpl/objectline_edit.tpl.php:484-485).', 'Setting this constant causes the end minute field to be pre-populated with the specified minute value, overriding the blank default.', 'Any non-empty string/integer representing a minute; empty/unset = field left blank.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:666|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_END_MIN'')) {", "core/tpl/objectline_create.tpl.php:667|read|print ''jQuery(\"#date_endmin\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_END_MIN'').''\");'';", "core/tpl/objectline_edit.tpl.php:484|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_END_MIN'') != '''') {", "core/tpl/objectline_edit.tpl.php:485|read|print ''jQuery(\"#date_endmin\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_END_MIN'').''\");'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_HOUR', 'string', NULL, 'core', 'Sets the default hour value pre-filled in date/time fields rendered by the form helper.', 'Read at core/class/html.form.class.php:7814 via getDolGlobalString with a fallback of ''23'' when the hour parameter $h is -1, or empty string otherwise. Controls the $shour variable used when rendering time inputs.', 'Changing this value alters the default hour shown in date/time selectors throughout the application. Leaving it unset relies on the context-dependent fallback (''23'' or empty).', 'String representing hour (e.g. ''0''–''23''); unset = fallback to ''23'' when $h == -1, else empty.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7814|read|$shour = getDolGlobalString(''MAIN_DEFAULT_DATE_HOUR'', ($h == -1 ? ''23'' : ''''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_MIN', 'string', NULL, 'core', 'Sets the default minute value pre-filled in date/time fields rendered by the form helper.', 'Read at core/class/html.form.class.php:7815 via getDolGlobalString with a fallback of ''59'' when $h is -1, or empty string otherwise. Controls the $smin variable for time input rendering.', 'Changing this value alters the default minute shown in date/time selectors. Leaving it unset uses the context-dependent fallback (''59'' or empty).', 'String representing minutes (e.g. ''0''–''59''); unset = fallback to ''59'' when $h == -1, else empty.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7815|read|$smin = getDolGlobalString(''MAIN_DEFAULT_DATE_MIN'', ($h == -1 ? ''59'' : ''''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_SEC', 'string', NULL, 'core', 'Sets the default second value pre-filled in date/time fields rendered by the form helper.', 'Read at core/class/html.form.class.php:7816 via getDolGlobalString with a fallback of ''59'' when $h is -1, or empty string otherwise. Controls the $ssec variable for time input rendering.', 'Changing this value alters the default second shown in date/time selectors. Leaving it unset uses the context-dependent fallback (''59'' or empty).', 'String representing seconds (e.g. ''0''–''59''); unset = fallback to ''59'' when $h == -1, else empty.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7816|read|$ssec = getDolGlobalString(''MAIN_DEFAULT_DATE_SEC'', ($h == -1 ? ''59'' : ''''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_START_HOUR', 'string', NULL, 'core', 'Sets the default hour value pre-filled in the service start date hour field on document line forms.', 'When non-empty, jQuery sets the value of #date_starthour to this constant''s value on both the create form (core/tpl/objectline_create.tpl.php:655-656) and the edit form (core/tpl/objectline_edit.tpl.php:463-464).', 'Setting this constant causes the start hour field to be pre-populated with the specified hour value, overriding the blank default.', 'Any non-empty string/integer representing an hour; empty/unset = field left blank.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:655|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_START_HOUR'') != '''') {", "core/tpl/objectline_create.tpl.php:656|read|print ''jQuery(\"#date_starthour\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_START_HOUR'').''\");'';", "core/tpl/objectline_edit.tpl.php:463|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_START_HOUR'') != '''') {", "core/tpl/objectline_edit.tpl.php:464|read|print ''jQuery(\"#date_starthour\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_START_HOUR'').''\");'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_DATE_START_MIN', 'string', NULL, 'core', 'Sets the default minute value pre-filled in the service start date minute field on document line forms.', 'When non-empty, jQuery sets the value of #date_startmin to this constant''s value on both the create form (core/tpl/objectline_create.tpl.php:658-659) and the edit form (core/tpl/objectline_edit.tpl.php:466-467).', 'Setting this constant causes the start minute field to be pre-populated with the specified minute value, overriding the blank default.', 'Any non-empty string/integer representing a minute; empty/unset = field left blank.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:658|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_START_MIN'') != '''') {", "core/tpl/objectline_create.tpl.php:659|read|print ''jQuery(\"#date_startmin\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_START_MIN'').''\");'';", "core/tpl/objectline_edit.tpl.php:466|check|if (getDolGlobalString(''MAIN_DEFAULT_DATE_START_MIN'') != '''') {", "core/tpl/objectline_edit.tpl.php:467|read|print ''jQuery(\"#date_startmin\").val(\"'' . getDolGlobalString(''MAIN_DEFAULT_DATE_START_MIN'').''\");'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_LANGUAGE_FILTER', 'string', NULL, 'core', 'Restricts the language selector in admin forms to a specific language, filtering out all others.', 'Used in core/class/html.formadmin.class.php. When set, the value is used as a filter key added to the language filter array (line 83), limiting the displayed language list to only the matching entry.', 'Setting this constant causes the language selection UI to show only the specified language, effectively locking the admin language choice. Clearing it restores the full language list.', 'A language code string (e.g. ''fr_FR'') to filter the list to; empty or unset means no filter.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formadmin.class.php:79|check|if (getDolGlobalString(''MAIN_DEFAULT_LANGUAGE_FILTER'')) {", "core/class/html.formadmin.class.php:83|read|$filter[getDolGlobalString(''MAIN_DEFAULT_LANGUAGE_FILTER'')] = 1;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_PAYMENT_TERM_ID', 'string', NULL, 'core', 'Sets the application-wide default payment term ID pre-selected in payment term dropdowns.', 'Checked and read in core/class/html.form.class.php:4960 and :4962 to pre-select a payment term when none is specified. Also read in societe/card.php:1110. The COMMENTS warn: ''Constant MAIN_DEFAULT_PAYMENT_TERM_ID can be used to set default value but scope is all application, probably not what you want.''', 'Setting this value pre-selects the specified payment term across all payment term selectors in the application. Because the scope is application-wide, this affects all entities and contexts.', 'Integer ID of a payment term record; unset or 0 = no application-wide default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.form.class.php:4906  *    Constant MAIN_DEFAULT_PAYMENT_TERM_ID can be used to set default value but scope is all application, probably not what you want.", "core/class/html.form.class.php:4960|check|if (empty($selected) && strpos($htmlname, ''search_'') !== 0 && getDolGlobalInt(''MAIN_DEFAULT_PAYMENT_TERM_ID'')) {", "core/class/html.form.class.php:4962|read|$selected = getDolGlobalInt(''MAIN_DEFAULT_PAYMENT_TERM_ID'');", "societe/card.php:1110|read|$paymentTermId = getDolGlobalString(''MAIN_DEFAULT_PAYMENT_TERM_ID'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_PAYMENT_TYPE_ID', 'string', NULL, 'core', 'Sets the application-wide default payment type ID pre-selected in payment type dropdowns.', 'Checked and read in core/class/html.form.class.php:5105 and :5107 to pre-select a payment type when none is specified. Also read in societe/card.php:1115. The COMMENTS note: ''Constant MAIN_DEFAULT_PAYMENT_TYPE_ID can used to set default value but scope is all application, probably not what you want.''', 'Setting this value pre-selects the specified payment type across all payment type selectors in the application. Because the scope is application-wide, this affects all entities and contexts.', 'Integer ID of a payment type record; unset or 0 = no application-wide default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.form.class.php:5070  * Constant MAIN_DEFAULT_PAYMENT_TYPE_ID can used to set default value but scope is all application, probably not what you want.", "core/class/html.form.class.php:5105|check|if (empty($selected) && strpos($htmlname, ''search_'') !== 0 && getDolGlobalString(''MAIN_DEFAULT_PAYMENT_TYPE_ID'')) {", "core/class/html.form.class.php:5107|read|$selected = getDolGlobalString(''MAIN_DEFAULT_PAYMENT_TYPE_ID'');", "societe/card.php:1115|read|$paymentTypeId = getDolGlobalString(''MAIN_DEFAULT_PAYMENT_TYPE_ID'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_WAREHOUSE', 'string', NULL, 'product', 'Sets the default warehouse pre-selected in warehouse dropdowns across purchase, sale, and stock forms.', 'Configured via admin/stock.php (written at line 140, read at line 785). Checked in comm/propal/card.php:2350, commande/card.php:2288, product/stock/tpl/stockcorrection.tpl.php:168, and product/class/html.formproduct.class.php:328 when no warehouse is explicitly selected.', 'Setting this constant causes the specified warehouse to be pre-selected in warehouse pickers when no other warehouse is set, streamlining stock operations.', 'Integer warehouse ID; -1 or empty = no default warehouse.', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:140|write|$res = dolibarr_set_const($db, \"MAIN_DEFAULT_WAREHOUSE\", $value, ''chaine'', 0, '''', $conf->entity);", "admin/stock.php:785|read|print $formproduct->selectWarehouses(getDolGlobalInt(''MAIN_DEFAULT_WAREHOUSE'', -1), ''default_warehouse'', '''', 1, 0, 0, '''', 0, 0, array(), ''left reposition'');", "comm/propal/card.php:2350|check|if (empty($object->warehouse_id) && getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE'')) {", "commande/card.php:2288|check|if (empty($object->warehouse_id) && getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_WAREHOUSE_USER', 'bool', NULL, 'user', 'Controls whether a per-user default warehouse preference is enabled.', 'Configured via admin/stock.php (read at line 797, checked at line 802). Checked in user/card.php at lines 1490, 1869, and 2948, in user/list.php:742, in product/stock/replenish.php:100, and in product/class/html.formproduct.class.php:332.', 'Enabling this constant activates the per-user warehouse preference feature, allowing each user to have a different default warehouse.', 'Truthy value = per-user default warehouse enabled; empty/unset = feature disabled.', 0, 0, 'admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:797|read|print $form->selectarray(\"MAIN_DEFAULT_WAREHOUSE_USER\", $arrval, getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE_USER''));", "user/card.php:1490|check|if (isModEnabled(''stock'') && getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE_USER'')) {", "product/stock/replenish.php:100|check|if (!GETPOSTISSET(''fk_warehouse'') && (empty($fk_entrepot) || $fk_entrepot <= 0) && getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE_USER'')) {", "product/class/html.formproduct.class.php:332|check|if (is_scalar($selected) && ($selected == ''-2'' || $selected == ''ifone'') && getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE_USER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_WORKING_DAYS', 'string', NULL, 'projet', 'Defines the default working day range (e.g. ''1-5'') used to pre-select days in activity and action views.', 'Stored as a dash-separated string such as ''1-5'' representing day indices. Configured via admin/ihm.php and read in comm/action/pertype.php:151, comm/action/peruser.php:147, projet/activity/perday.php:648, and projet/activity/perweek.php:527 where it is split on ''-'' to derive day boundaries.', 'Changing this value alters the default day range pre-filled in project activity per-day and per-week views as well as action-by-type and action-by-user views.', '''1-5'' (Monday to Friday, default); any dash-separated day index range', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/action/pertype.php:151|read|$tmp = getDolGlobalString(''MAIN_DEFAULT_WORKING_DAYS'', ''1-5'');", "projet/activity/perday.php:648|read|$tmparray = explode(''-'', getDolGlobalString(''MAIN_DEFAULT_WORKING_DAYS''));", "admin/ihm.php:496|read|print ''<input type=\"text\" name=\"MAIN_DEFAULT_WORKING_DAYS\" size=\"5\" value=\"'' . getDolGlobalString(''MAIN_DEFAULT_WORKING_DAYS'', ''1-5'') . ''\">'';", "admin/ihm.php:284|write|dolibarr_set_const($db, \"MAIN_DEFAULT_WORKING_DAYS\", GETPOST(\"MAIN_DEFAULT_WORKING_DAYS\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_WORKING_HOURS', 'string', NULL, 'comm', 'Sets the default working hours range (e.g. ''9-18'') used in agenda views to define the visible day range.', 'Written in admin/ihm.php:285 and read in admin/ihm.php:502, comm/action/pertype.php:135, comm/action/peruser.php:131, and comm/action/index.php:1861; the default fallback is ''9-18''.', 'Changing this constant adjusts the start and end hours of the working day displayed in agenda calendar views.', 'String in ''HH-HH'' format (e.g. ''9-18''); default fallback = ''9-18''.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:502|read|print ''<input type=\"text\" name=\"MAIN_DEFAULT_WORKING_HOURS\" size=\"5\" value=\"'' . getDolGlobalString(''MAIN_DEFAULT_WORKING_HOURS'', ''9-18'') . ''\">'';", "admin/ihm.php:285|write|dolibarr_set_const($db, \"MAIN_DEFAULT_WORKING_HOURS\", GETPOST(\"MAIN_DEFAULT_WORKING_HOURS\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "comm/action/pertype.php:135|read|$tmp = getDolGlobalString(''MAIN_DEFAULT_WORKING_HOURS'', ''9-18'');", "comm/action/index.php:1861|read|$tmp = explode(''-'', getDolGlobalString(''MAIN_DEFAULT_WORKING_HOURS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEFAULT_WORKSTATION', 'string', NULL, 'product', 'Sets the default workstation pre-selected in workstation dropdowns.', 'Checked and read in product/class/html.formproduct.class.php at lines 451, 452, and 455 when the selected value is ''-2'' or ''ifone''.', 'Setting this constant causes the specified workstation to be pre-selected in workstation pickers when no explicit selection is made.', 'String workstation identifier; ''-2'' or ''ifone'' triggers the default lookup.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/class/html.formproduct.class.php:451|check|if (($selected == ''-2'' || $selected == ''ifone'') && getDolGlobalString(''MAIN_DEFAULT_WORKSTATION'')) {", "product/class/html.formproduct.class.php:452|read|$selected = getDolGlobalString(''MAIN_DEFAULT_WORKSTATION'');", "product/class/html.formproduct.class.php:455|check|if (($selected == ''-2'' || $selected == ''ifone'') && getDolGlobalString(''MAIN_DEFAULT_WORKSTATION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_ACTIONS_TODO', 'string', '7', 'core', 'Number of days before a pending action is considered overdue and triggers a warning.', 'Read as an integer and multiplied by 24*60*60 to produce a delay in seconds across comm/action/list.php, comm/action/card.php, comm/action/document.php, core/boxes/box_actions.php:113, core/boxes/box_actions_future.php:120, and resource/element_resource.php:331. Default is 7 days set in admin/delais.php:168 with comment ''Must be same value than into conf.class.php''. Managed via admin/delais.php.', 'Increasing this value gives more days before an action is flagged as late; decreasing it makes warnings appear sooner. Affects all action-list and dashboard views that highlight overdue items.', 'Integer number of days; default 7', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/delais.php:168|write|$conf->global->MAIN_DELAY_ACTIONS_TODO = 7; // Must be same value than into conf.class.php", "core/boxes/box_actions_future.php:120|read|$delay_warning = getDolGlobalInt(''MAIN_DELAY_ACTIONS_TODO'') * 24 * 60 * 60;", "core/boxes/box_actions.php:113|read|$delay_warning = getDolGlobalInt(''MAIN_DELAY_ACTIONS_TODO'') * 24 * 60 * 60;", "resource/element_resource.php:331|read|$delay_warning = getDolGlobalInt(''MAIN_DELAY_ACTIONS_TODO'') * 24 * 60 * 60;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_BANK_CREDIT_TRANSFER', 'string', NULL, 'core', 'Number of days before pending bank credit-transfer operations trigger a warning indicator (default 15).', 'Read in core/class/conf.class.php:1275, the value (multiplied by 86400) populates $this->warning_delays[''bank_credit_transfer'']. The fallback default of 15 is passed inline to getDolGlobalInt. No admin UI page is listed.', 'Adjusting this value changes the threshold at which outstanding credit-transfer operations appear as warnings on the dashboard.', 'Integer number of days (fallback default 15). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1275|read|$this->warning_delays[''bank_credit_transfer''] = getDolGlobalInt(''MAIN_DELAY_BANK_CREDIT_TRANSFER'', 15) * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_BANK_DIRECT_DEBIT', 'string', NULL, 'core', 'Number of days before pending bank direct-debit operations trigger a warning indicator (default 15).', 'Read in core/class/conf.class.php:1274, the value (multiplied by 86400) populates $this->warning_delays[''bank_direct_debit'']. The fallback default of 15 is passed inline to getDolGlobalInt. No admin UI page is listed.', 'Adjusting this value changes the threshold at which outstanding direct-debit operations appear as warnings on the dashboard.', 'Integer number of days (fallback default 15). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1274|read|$this->warning_delays[''bank_direct_debit''] = getDolGlobalInt(''MAIN_DELAY_BANK_DIRECT_DEBIT'', 15) * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_CHEQUES_TO_DEPOSIT', 'string', NULL, 'core', 'Number of days before undeposited cheques trigger a warning indicator.', 'Read in core/class/conf.class.php:1273 and :1279, the value (multiplied by 86400) populates $this->warning_delays[''bank_cheque_to_be_deposited''] and $this->bank->cheque->warning_delay. No admin UI page is listed.', 'Setting this value causes the system to flag cheques that have not been deposited within the configured number of days.', 'Integer number of days (no default set). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1273|read|$this->warning_delays[''bank_cheque_to_be_deposited''] = getDolGlobalInt(''MAIN_DELAY_CHEQUES_TO_DEPOSIT'') * 86400;", "core/class/conf.class.php:1279|read|$this->bank->cheque->warning_delay = getDolGlobalInt(''MAIN_DELAY_CHEQUES_TO_DEPOSIT'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_CUSTOMER_BILLS_UNPAYED', 'string', '31', 'core', 'Sets the number of days after customer invoice due date before unpaid invoices trigger a warning.', 'Read in core/class/conf.class.php:1255 and 1259, multiplied by 86400 for the customer invoice warning_delay.', 'Increasing this value extends the period before unpaid customer invoices are flagged. Decreasing it triggers earlier payment warnings.', 'Integer number of days; default 31 (configured DEFAULT)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1255|read|$this->warning_delays[''invoice''] = getDolGlobalInt(''MAIN_DELAY_CUSTOMER_BILLS_UNPAYED'') * 86400;", "core/class/conf.class.php:1259|read|$this->facture->client->warning_delay = getDolGlobalInt(''MAIN_DELAY_CUSTOMER_BILLS_UNPAYED'') * 86400;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_EXPENSEREPORTS', 'string', NULL, 'core', 'Number of days before expense reports pending approval trigger a warning indicator.', 'Read in core/class/conf.class.php:1282 and :1285, the value (multiplied by 86400) populates $this->warning_delays[''expensereport_approve''] and $this->expensereport->approve->warning_delay. No admin UI page is listed.', 'Setting a non-zero value causes the system to flag expense reports that have been awaiting approval longer than the configured number of days.', 'Integer number of days (no default set). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1282|read|$this->warning_delays[''expensereport_approve''] = getDolGlobalInt(''MAIN_DELAY_EXPENSEREPORTS'') * 86400;", "core/class/conf.class.php:1285|read|$this->expensereport->approve->warning_delay = getDolGlobalInt(''MAIN_DELAY_EXPENSEREPORTS'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_EXPENSEREPORTS_TO_PAY', 'string', '31', NULL, 'Defines the number of days delay threshold for expense reports awaiting payment, used in alerting or reporting.', 'No occurrences found in the payload beyond the metadata. Default value is ''31''. Exact behavior is unclear from code alone.', 'Exact behavior unclear from code alone. Adjusting this value would change the delay threshold used to flag overdue expense report payments.', 'Integer string (number of days); default ''31''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["TYPE: string | DEFAULT: ''31'' | MODULE: None", "HIDDEN_GUESS: 1 | ADMIN_UI: ", "OCC: 0"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_HOLIDAYS', 'string', NULL, 'core', 'Number of days before leave requests pending approval trigger a warning indicator.', 'Read in core/class/conf.class.php:1290 and :1292, the value (multiplied by 86400) populates $this->warning_delays[''holiday_approve''] and $this->holiday->approve->warning_delay. No admin UI page is listed.', 'Setting a non-zero value causes the system to flag leave requests that have been awaiting approval longer than the configured number of days.', 'Integer number of days (no default set). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1290|read|$this->warning_delays[''holiday_approve''] = getDolGlobalInt(''MAIN_DELAY_HOLIDAYS'') * 86400;", "core/class/conf.class.php:1292|read|$this->holiday->approve->warning_delay = getDolGlobalInt(''MAIN_DELAY_HOLIDAYS'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_MEMBERS', 'string', '31', 'core', 'Sets the number of days after a membership subscription expires before a warning is triggered.', 'Written in admin/delais.php:165 with a default of 0 when not set. Read in core/class/conf.class.php:1214 and 1216 and multiplied by 86400 to convert days to seconds for the warning_delay on subscriptions.', 'Increasing this value extends the grace period before overdue membership warnings appear. Setting to 0 disables the delay-based warning.', 'Integer number of days; default 31 (configured DEFAULT); 0 = no delay warning', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1214|read|$this->warning_delays[''subscription''] = getDolGlobalInt(''MAIN_DELAY_MEMBERS'') * 86400;", "core/class/conf.class.php:1216|read|$this->adherent->subscription->warning_delay = getDolGlobalInt(''MAIN_DELAY_MEMBERS'') * 86400;", "admin/delais.php:165|write|$conf->global->MAIN_DELAY_MEMBERS = 0; // Must be same value than into conf.class.php"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_MRP', 'string', NULL, 'core', 'Number of days before MRP (manufacturing) production orders trigger a warning indicator.', 'Read in core/class/conf.class.php:1295 and :1297, the value (multiplied by 86400) populates $this->warning_delays[''mrp''] and $this->mrp->progress->warning_delay. No admin UI page is listed.', 'Setting a non-zero value causes the system to flag MRP orders whose progress has stalled beyond the configured number of days.', 'Integer number of days (no default set). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1295|read|$this->warning_delays[''mrp''] = getDolGlobalInt(''MAIN_DELAY_MRP'') * 86400;", "core/class/conf.class.php:1297|read|$this->mrp->progress->warning_delay = getDolGlobalInt(''MAIN_DELAY_MRP'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_NOT_ACTIVATED_SERVICES', 'string', '0', 'core', 'Number of days before inactive (not yet started) contract services trigger a warning indicator.', 'Read in core/class/conf.class.php:1263 and :1268, the value (multiplied by 86400) populates $this->warning_delays[''contract_inactive''] and $this->contrat->services->inactifs->warning_delay. No admin UI page is listed.', 'Setting a non-zero value causes the system to flag contract services that remain inactive beyond the configured number of days.', 'Integer number of days (default ''0''). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1263|read|$this->warning_delays[''contract_inactive''] = getDolGlobalInt(''MAIN_DELAY_NOT_ACTIVATED_SERVICES'') * 86400;", "core/class/conf.class.php:1268|read|$this->contrat->services->inactifs->warning_delay = getDolGlobalInt(''MAIN_DELAY_NOT_ACTIVATED_SERVICES'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_ORDERS_TO_PROCESS', 'string', '2', 'admin', 'Sets the number of days after order creation before unprocessed orders trigger a warning.', 'Written multiple times in admin/delais.php with a default of 2 days. Read in core/class/conf.class.php and multiplied by 86400 for warning_delay. The admin/delais.php file resets the value to 2 in multiple conditions.', 'Increasing this value gives more time before orders are flagged as overdue. Decreasing it triggers earlier warnings for pending orders.', 'Integer number of days; default 2', 0, 0, 'admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/delais.php:171|write|$conf->global->MAIN_DELAY_ORDERS_TO_PROCESS = 2;", "admin/delais.php:170|read|if (!isset($conf->global->MAIN_DELAY_ORDERS_TO_PROCESS)) {", "admin/delais.php:177|write|$conf->global->MAIN_DELAY_ORDERS_TO_PROCESS = 2;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_PROJECT_TO_CLOSE', 'string', NULL, 'core', 'Sets the number of days before a project''s expected close date at which a warning is triggered.', 'Read in core/class/conf.class.php:1223 and 1225, both with a default of 7 days when not set. Multiplied by 86400 to convert to seconds for warning_delay on projects.', 'Increasing this value gives earlier warnings for projects approaching their close date. Decreasing it shortens the warning window.', 'Integer number of days; default 7 when not set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1223|read|$this->warning_delays[''project''] = (getDolGlobalInt(''MAIN_DELAY_PROJECT_TO_CLOSE'', 7) * 86400);", "core/class/conf.class.php:1225|read|$this->projet->warning_delay = (getDolGlobalInt(''MAIN_DELAY_PROJECT_TO_CLOSE'', 7) * 86400);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_PROPALS_TO_BILL', 'string', '7', 'core', 'Sets the number of days after proposal acceptance before unbilled proposals trigger a billing warning.', 'Read in core/class/conf.class.php:1239 and 1243, multiplied by 86400 for the proposal billing warning_delay.', 'Increasing this value extends the grace period before accepted proposals are flagged for invoicing. Decreasing it triggers earlier billing warnings.', 'Integer number of days; default 7 (configured DEFAULT)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1239|read|$this->warning_delays[''proposal_invoice''] = getDolGlobalInt(''MAIN_DELAY_PROPALS_TO_BILL'') * 86400;", "core/class/conf.class.php:1243|read|$this->propal->facturation->warning_delay = getDolGlobalInt(''MAIN_DELAY_PROPALS_TO_BILL'') * 86400;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_PROPALS_TO_CLOSE', 'string', '31', 'core', 'Sets the number of days after proposal creation before open proposals trigger a closing warning.', 'Read in core/class/conf.class.php:1238 and 1242, multiplied by 86400 for the proposal close warning_delay.', 'Increasing this value delays when open proposals are flagged for closing. Decreasing it triggers earlier closing warnings.', 'Integer number of days; default 31 (configured DEFAULT)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1238|read|$this->warning_delays[''proposal_close''] = getDolGlobalInt(''MAIN_DELAY_PROPALS_TO_CLOSE'') * 86400;", "core/class/conf.class.php:1242|read|$this->propal->cloture->warning_delay = getDolGlobalInt(''MAIN_DELAY_PROPALS_TO_CLOSE'') * 86400;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_RUNNING_SERVICES', 'string', '0', 'core', 'Number of days before expired (running but past end-date) contract services trigger a warning indicator.', 'Read in core/class/conf.class.php:1264 and :1269, the value (multiplied by 86400) populates $this->warning_delays[''contract_expired''] and $this->contrat->services->expires->warning_delay. No admin UI page is listed.', 'A non-zero value causes the system to flag contract services that have exceeded their end date by more than the configured number of days.', 'Integer number of days (default ''0''). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1264|read|$this->warning_delays[''contract_expired''] = getDolGlobalInt(''MAIN_DELAY_RUNNING_SERVICES'') * 86400;", "core/class/conf.class.php:1269|read|$this->contrat->services->expires->warning_delay = getDolGlobalInt(''MAIN_DELAY_RUNNING_SERVICES'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_SUPPLIER_BILLS_TO_PAY', 'string', '2', 'core', 'Number of days before unpaid supplier invoices trigger a warning indicator in the dashboard.', 'Read in core/class/conf.class.php:1256 and :1260, the value (multiplied by 86400) is assigned to both $this->warning_delays[''supplier_invoice''] and $this->facture->fournisseur->warning_delay. No admin UI page is listed; the constant is set via the database global.', 'Increasing the value extends the grace period before overdue supplier invoices raise a dashboard alert; decreasing it makes warnings appear sooner.', 'Integer number of days (default ''2''). 0 means no delay warning.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1256|read|$this->warning_delays[''supplier_invoice''] = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_BILLS_TO_PAY'') * 86400;", "core/class/conf.class.php:1260|read|$this->facture->fournisseur->warning_delay = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_BILLS_TO_PAY'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_SUPPLIER_ORDERS_TO_PROCESS', 'string', '7', 'core', 'Sets the number of days after supplier order creation before unprocessed supplier orders trigger a warning.', 'Written in admin/delais.php:174 with a default of 7 days. Read in core/class/conf.class.php:1231 and 1235 with a fallback of 7, multiplied by 86400 for the warning_delay on purchase orders.', 'Increasing this value extends the grace period before supplier orders are flagged. Decreasing it shortens the warning window.', 'Integer number of days; default 7', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/delais.php:174|write|$conf->global->MAIN_DELAY_SUPPLIER_ORDERS_TO_PROCESS = 7;", "core/class/conf.class.php:1231|read|$this->warning_delays[''purchase_order''] = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_ORDERS_TO_PROCESS'', 7) * 86400;", "core/class/conf.class.php:1235|read|$this->commande->fournisseur->warning_delay = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_ORDERS_TO_PROCESS'', 7) * 86400;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_SUPPLIER_PROPALS_TO_BILL', 'string', NULL, 'core', 'Sets the number of days after supplier proposal acceptance before unbilled supplier proposals trigger a billing warning.', 'Read in core/class/conf.class.php:1248 and 1252, multiplied by 86400 for the supplier_proposal billing warning_delay.', 'Increasing this value extends the grace period before accepted supplier proposals are flagged for invoicing. Decreasing it triggers earlier billing warnings.', 'Integer number of days; unset/0 = no warning delay configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1248|read|$this->warning_delays[''supplier_proposal_invoice''] = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_PROPALS_TO_BILL'') * 86400;", "core/class/conf.class.php:1252|read|$this->supplier_proposal->facturation->warning_delay = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_PROPALS_TO_BILL'') * 86400;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_SUPPLIER_PROPALS_TO_CLOSE', 'string', NULL, 'core', 'Sets the number of days after supplier proposal creation before open supplier proposals trigger a closing warning.', 'Read in core/class/conf.class.php:1247 and 1251, multiplied by 86400 for the supplier_proposal close warning_delay.', 'Increasing this value delays when open supplier proposals are flagged for closing. Decreasing it triggers earlier warnings.', 'Integer number of days; unset/0 = no warning delay configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1247|read|$this->warning_delays[''supplier_proposal_close''] = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_PROPALS_TO_CLOSE'') * 86400;", "core/class/conf.class.php:1251|read|$this->supplier_proposal->cloture->warning_delay = getDolGlobalInt(''MAIN_DELAY_SUPPLIER_PROPALS_TO_CLOSE'') * 86400;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_TASKS_TODO', 'string', NULL, 'core', 'Sets the number of days before a task''s due date at which a warning is triggered.', 'Read in core/class/conf.class.php:1224 and 1227, both with a default of 7 days when not set. Multiplied by 86400 to convert to seconds for warning_delay on tasks.', 'Increasing this value provides earlier warnings for overdue tasks. Decreasing it shortens the warning window.', 'Integer number of days; default 7 when not set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1224|read|$this->warning_delays[''task''] = (getDolGlobalInt(''MAIN_DELAY_TASKS_TODO'', 7) * 86400);", "core/class/conf.class.php:1227|read|$this->projet->task->warning_delay = (getDolGlobalInt(''MAIN_DELAY_TASKS_TODO'', 7) * 86400);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DELAY_TRANSACTIONS_TO_CONCILIATE', 'string', '62', 'core', 'Number of days before unreconciled bank transactions trigger a warning indicator.', 'Read in core/class/conf.class.php:1272 and :1278, the value (multiplied by 86400) populates $this->warning_delays[''bank_cheque_to_conciliate''] and $this->bank->rappro->warning_delay. No admin UI page is listed.', 'Increasing the value extends the period before old unreconciled bank entries raise an alert; decreasing it makes warnings appear sooner.', 'Integer number of days (default ''62''). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1272|read|$this->warning_delays[''bank_cheque_to_conciliate''] = getDolGlobalInt(''MAIN_DELAY_TRANSACTIONS_TO_CONCILIATE'') * 86400;", "core/class/conf.class.php:1278|read|$this->bank->rappro->warning_delay = getDolGlobalInt(''MAIN_DELAY_TRANSACTIONS_TO_CONCILIATE'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DEPOSIT_MULTI_TVA', 'string', NULL, 'compta', 'Enables splitting deposit invoice discount lines into multiple lines, one per VAT rate.', 'Checked in 7 locations: compta/facture/card.php:1749 and :1872, fourn/facture/card.php:1194 and :1302, and compta/facture/class/facture.class.php:1809 and :1912. The inline comment at card.php:1749 explicitly states the purpose. No admin UI is present.', 'Enabling this causes deposit balance invoice adjustment lines to be split by VAT rate rather than consolidated into a single line.', '0 or unset = single consolidated adjustment line; truthy value = one line per VAT rate.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:1749|check|if (getDolGlobalString(''MAIN_DEPOSIT_MULTI_TVA'')) {\t// We want to split the discount line into several lines, one per vat rate.", "compta/facture/card.php:1866|read|(getDolGlobalString(''MAIN_DEPOSIT_MULTI_TVA'') ? 0 : 1)", "compta/facture/class/facture.class.php:1809|check|if (getDolGlobalString(''MAIN_DEPOSIT_MULTI_TVA'')) {", "fourn/facture/card.php:1194|check|if (getDolGlobalString(''MAIN_DEPOSIT_MULTI_TVA'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DIRECT_STATUS_UPDATE', 'string', NULL, 'core', 'Enables inline AJAX-based status toggling for third-parties and products directly from list views.', 'When set, list pages render AJAX toggle controls (via objectonoff.php) for entity status fields, as documented in core/ajax/objectonoff.php:23 and core/lib/ajax.lib.php:777. Requires JavaScript/AJAX to be enabled and appropriate create rights.', 'Enabling this constant adds interactive status-switch UI elements to list views; disabling it removes those controls, requiring users to open the record to change status.', 'Any truthy value enables inline status updates; unset disables the feature.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/objectonoff.php:23  *       \t\t\tThis Ajax service is often called when option MAIN_DIRECT_STATUS_UPDATE is set.", "core/lib/ajax.lib.php:777  *  This uses the ajax service objectonoff.php (May be called when MAIN_DIRECT_STATUS_UPDATE is set for some pages)", "core/lib/functions.lib.php:3613|check|if (!empty($conf->use_javascript_ajax) && $user->hasRight(''societe'', ''creer'') && getDolGlobalString(''MAIN_DIRECT_STATUS_UPDATE'')) {", "product/list.php:2415|check|if (!empty($conf->use_javascript_ajax) && $user->hasRight(\"produit\", \"creer\") && getDolGlobalString(''MAIN_DIRECT_STATUS_UPDATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEDRAFTSTATUS', 'bool', NULL, 'projet', 'Globally disables the ''Draft'' status step across multiple modules, forcing objects to skip draft and go directly to an active status.', 'Checked in projet/card.php:1691 and :1116, projet/class/project.class.php:577, and compta/paiement/cheque/class/remisecheque.class.php:304. When set, the draft button is hidden and newly created objects bypass the draft state. Module-specific overrides (e.g. MAIN_DISABLEDRAFTSTATUS_PROJECT) exist alongside this global flag.', 'Enabling this constant removes the draft status from affected modules application-wide; disabling restores the normal draft workflow.', 'Non-empty = draft status disabled globally; 0 or unset = draft workflow active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/card.php:1691|check|if (!getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') && !getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT'')) {", "projet/class/project.class.php:577|check|if (!$error && (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT''))) {", "compta/paiement/cheque/class/remisecheque.class.php:304|check|if (!$this->errno && (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_CHEQUE''))) {", "projet/card.php:1116|check|if (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEDRAFTSTATUS_CHEQUE', 'bool', NULL, 'compta', 'Disables the draft status specifically for cheque receipts, forcing them to bypass the draft workflow step.', 'Checked in compta/paiement/cheque/class/remisecheque.class.php:304 alongside MAIN_DISABLEDRAFTSTATUS. Either constant being set triggers the same behavior for cheque remittances.', 'Setting this constant causes cheque receipts to skip the draft status; clearing it restores the standard draft workflow for cheque remittances.', 'Any non-empty value = disable draft status for cheque receipts; empty/unset = draft status active', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!$this->errno && (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_CHEQUE''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEDRAFTSTATUS_DONATION', 'bool', NULL, 'don', 'Would disable the draft status creation step for donations when enabled (currently commented-out code).', 'The only occurrence in the payload is a commented-out check at don/class/don.class.php:487; the constant is not actively evaluated. Its purpose is inferred from its name and the commented code pattern alongside MAIN_DISABLEDRAFTSTATUS.', 'Because the check is commented out, setting this constant currently has no effect on donation draft status behaviour.', 'Any truthy value was intended to disable draft status for donations; currently inoperative.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["don/class/don.class.php:487  //if (!$error && (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_DONATION''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEDRAFTSTATUS_PROJECT', 'bool', NULL, 'projet', 'Disables the ''Draft'' status step specifically for the project module.', 'Checked in 3 locations, all within the project module: projet/card.php:1691 hides the draft button, projet/class/project.class.php:577 skips draft on save, and projet/card.php:1116 hides the validate button when draft is disabled.', 'Enabling this constant removes the draft step from project creation, bypassing draft for projects only; it mirrors the effect of MAIN_DISABLEDRAFTSTATUS but scoped to projects.', 'Non-empty = draft status disabled for projects; 0 or unset = draft workflow active for projects.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/card.php:1691|check|if (!getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') && !getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT'')) {", "projet/class/project.class.php:577|check|if (!$error && (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT''))) {", "projet/card.php:1116|check|if (getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS'') || getDolGlobalString(''MAIN_DISABLEDRAFTSTATUS_PROJECT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEPROFIDRULES', 'bool', NULL, 'societe', 'Disables validation rules applied to professional identifier fields on third parties.', 'Checked in societe/class/societe.class.php at lines 4306 and 4367 to bypass profid validation rules, and in core/class/html.formcompany.class.php at line 962 to skip related form-level checks.', 'Enabling this constant bypasses profid format and mandatory rules, allowing any value to be saved in professional identifier fields.', '0 or empty = rules enforced; any truthy value = rules disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4306|check|if (getDolGlobalString(''MAIN_DISABLEPROFIDRULES'')) {", "societe/class/societe.class.php:4367|check|if (getDolGlobalString(''MAIN_DISABLEPROFIDRULES'')) {", "core/class/html.formcompany.class.php:962|check|if (!getDolGlobalString(''MAIN_DISABLEPROFIDRULES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLEVATCHECK', 'bool', NULL, 'societe', 'Disables VAT number validation for third parties located in the European Economic Area.', 'Checked in societe/canvas/company/actions_card_company.class.php at lines 105, 133, and 161, and in societe/card.php at lines 1790, 2703, and 3220, always combined with isInEEC(). When not set, VAT validation is performed on save.', 'Setting this constant skips the VAT number format/existence check for EEC companies, which may be needed when the validation service is unavailable or for non-standard VAT numbers.', '0 or unset = VAT check enabled for EEC third parties; 1 = VAT check disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''MAIN_DISABLEVATCHECK'')) {", "if ($conf->use_javascript_ajax && !getDolGlobalString(''MAIN_DISABLEVATCHECK'')) {", "if (!getDolGlobalString(''MAIN_DISABLEVATCHECK'') && isInEEC($object)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_AJAX_COMBOX', 'bool', NULL, 'core', 'Disables the AJAX combo-box (Select2) enhancement globally across the application.', 'Checked in core/lib/ajax.lib.php:484; when set, the AJAX combo-box widget is not loaded.', 'Disabling the AJAX combo-box reverts all enhanced dropdowns to plain HTML selects, removing autocomplete and search features.', 'Truthy value to disable AJAX combo-box; absent or falsy to keep it enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ajax.lib.php:484|check|if (getDolGlobalString(''MAIN_DISABLE_AJAX_COMBOX'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_ALL_MAILS', 'bool', NULL, 'admin', 'Globally disables all outgoing email sending from the application.', 'Checked in admin/mails.php:693 to display a warning, and used in admin/mails.php:873, 902, 1015, 1052 to suppress test and live email send actions. Also checked in admin/mails_passwordreset.php:599, admin/mails_ticket.php:574, and additional files (20 total occurrences) to block email dispatch.', 'Setting this constant to a truthy value prevents any email from being sent application-wide; removing it restores normal email delivery.', 'Truthy value disables all mail sending; absent or falsy allows normal email operation.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:693|check|if (getDolGlobalString(''MAIN_DISABLE_ALL_MAILS'')) {", "admin/mails.php:1052|check|if (!in_array($action, array(''testconnect'', ''test'', ''testhtml'')) && !getDolGlobalString(''MAIN_DISABLE_ALL_MAILS'')) {", "admin/mails_passwordreset.php:599|check|if (getDolGlobalString(''MAIN_DISABLE_ALL_MAILS'')) {", "admin/mails_ticket.php:574|check|if (getDolGlobalString(''MAIN_DISABLE_ALL_MAILS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_ALL_SMS', 'bool', NULL, 'admin', 'Globally disables all SMS sending from Dolibarr when enabled.', 'Configured via admin/sms.php (UI write at line 62, displayed as yes/no at line 193). Checked in core/class/CSMSFile.class.php:179: when set, the SMS send code path is skipped.', 'Setting this to a truthy value prevents any SMS from being sent system-wide, regardless of other SMS configuration.', 'Truthy value (e.g. 1) to disable all SMS; 0 or empty to allow SMS sending.', 0, 0, 'admin/sms.php|admin/sms.php|admin/sms.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/sms.php:193|read|print $form->selectyesno(''MAIN_DISABLE_ALL_SMS'', getDolGlobalString(''MAIN_DISABLE_ALL_SMS''), 1);", "core/class/CSMSFile.class.php:179|check|if (!getDolGlobalString(''MAIN_DISABLE_ALL_SMS'')) {", "admin/sms.php:62|write|dolibarr_set_const($db, \"MAIN_DISABLE_ALL_SMS\", GETPOST(\"MAIN_DISABLE_ALL_SMS\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_AUTOFIX_CORRUPTED_LINES_WHEN_TOTAL_DOES_NOT_MATCH_RECALCULATION_FROM_UP', 'bool', NULL, 'core', 'Disables automatic correction of document lines when the total does not match recalculation from the line level.', 'Checked in core/class/commonobject.class.php:4184; when this constant is not set, Dolibarr auto-corrects corrupted lines where the stored total diverges from line-level recalculation. Non-deposit lines are subject to this check.', 'Setting this constant prevents automatic line correction, leaving inconsistencies in document totals uncorrected.', '0 or unset = auto-fix enabled; 1 = auto-fix disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:4184|check|if ($obj->description != ''(DEPOSIT)'' && !getDolGlobalInt(''MAIN_DISABLE_AUTOFIX_CORRUPTED_LINES_WHEN_TOTAL_DOES_NOT_MATCH_RECALCULATION_FROM_UP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_AUTO_UPDATE_OF_TMS_FIELDS', 'bool', NULL, 'core', 'Disables the automatic update of the tms (timestamp) field during record saves.', 'Checked in core/class/commonobject.class.php:10801 and 11111 with the inline comment ''If we want the explicit update of tms fields instead of deprecated u''. When set, the tms field is only updated when explicitly provided in the field values.', 'Enabling this constant prevents automatic timestamp refresh on every save, requiring callers to explicitly set tms when needed.', 'Non-empty = auto-update disabled; empty or unset = auto-update enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:10801|check|if (getDolGlobalString(''MAIN_DISABLE_AUTO_UPDATE_OF_TMS_FIELDS'') && array_key_exists(''tms'', $fieldvalues)) {\t// If we want the explicit update of tms fields instead of deprecated u", "core/class/commonobject.class.php:11111|check|if (getDolGlobalString(''MAIN_DISABLE_AUTO_UPDATE_OF_TMS_FIELDS'') && array_key_exists(''tms'', $fieldvalues)) {\t// If we want the explicit update of tms fields instead of deprecated u"]', 'medium', NULL);
