INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_CONTACTS_TAB', 'bool', NULL, 'core', 'Hides the Contacts tab on record detail pages across many modules.', 'COMMENT: `Called by bloc_showhide.tpl.php, itself called when MAIN_DISABLE_CONTACTS_TAB or MAIN_DISABLE_NOTES_TAB are set` (core/ajax/extraparams.php:23). Checked across 31 occurrences including core/lib/company.lib.php:57, supplier_proposal/card.php:2200, and fourn/commande/card.php (lines 1778, 2764).', 'Enabling this setting removes the Contacts tab from all affected record pages, hiding contact associations from the UI.', 'Truthy string (non-empty) = Contacts tab hidden; empty/not set = Contacts tab shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/ajax/extraparams.php:23  *\t\t\t\tCalled bu bloc_showhide.tpl.php, itself called when MAIN_DISABLE_CONTACTS_TAB or MAIN_DISABLE_NOTES_TAB are set", "core/lib/company.lib.php:57|check|if (!getDolGlobalString(''MAIN_DISABLE_CONTACTS_TAB'') && $user->hasRight(''societe'', ''contact'', ''lire'')) {", "supplier_proposal/card.php:2200|check|if (getDolGlobalString(''MAIN_DISABLE_CONTACTS_TAB'')) {", "fourn/commande/card.php:1778|check|if (getDolGlobalString(''MAIN_DISABLE_CONTACTS_TAB'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_DEFAULT_FILTER_FOR_QUICK_SEARCH', 'bool', NULL, 'core', 'Disables the default filter applied during quick search, allowing broader or unfiltered search results.', 'Checked with negation in core/lib/functions.lib.php:1237; the default filter is applied only when this constant is absent or empty. No admin UI write detected.', 'Setting this constant removes the default search filter, potentially returning a wider set of results. Without it, the default filter narrows quick search output.', 'Non-empty = default filter disabled; absent/empty = default filter active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:1237|check|if (!getDolGlobalString(''MAIN_DISABLE_DEFAULT_FILTER_FOR_QUICK_SEARCH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_DNS_GET_RECORD', 'bool', NULL, 'admin', 'Disables the DNS SPF record lookup that uses PHP''s dns_get_record() function in the mail configuration admin page.', 'When set, the dns_get_record() call in admin/mails.php is skipped even if the function exists and a domain is available to test. Only one occurrence in the payload.', 'Enabling this constant prevents DNS SPF checks from running in the mail admin page; disabling it allows the check to run when dns_get_record() is available.', 'Non-empty (truthy) disables the DNS lookup; empty or undefined allows it.', 0, 0, 'admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails.php:1124|check|if (!empty($domaintotest) && function_exists(''dns_get_record'') && !getDolGlobalString(''MAIN_DISABLE_DNS_GET_RECORD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_DNS_GET_RECORD_FOR_IP_RESOLUTION', 'bool', NULL, 'core', 'Disables the use of dns_get_record() for IP address resolution in outbound URL checks when set.', 'Checked in core/lib/geturl.lib.php:406 alongside a function_exists check for dns_get_record. No admin UI write is present.', 'When set, Dolibarr skips the dns_get_record() call during IP resolution for outbound HTTP requests. This can be used as a workaround on servers where dns_get_record() is unavailable or misbehaves.', 'Truthy value (e.g. 1) to disable dns_get_record usage; 0 or empty to allow it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/geturl.lib.php:406|check|if (function_exists(''dns_get_record'') && !getDolGlobalString(''MAIN_DISABLE_DNS_GET_RECORD_FOR_IP_RESOLUTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_EDIT_PREDEF_PRICEHT', 'bool', NULL, 'core', 'Disables editing of the predefined unit price (excl. tax) field on document line forms.', 'Exposed as a boolean to JavaScript in core/tpl/objectline_create.tpl.php:690 and documented as a JS property at line 768 of the same file.', 'When enabled, users cannot modify the pre-tax unit price of a predefined product on document lines.', 'Truthy boolean = editing disabled; false/unset = editing allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:690|read|''MAIN_DISABLE_EDIT_PREDEF_PRICEHT'' => (bool) getDolGlobalInt(''MAIN_DISABLE_EDIT_PREDEF_PRICEHT''),", "core/tpl/objectline_create.tpl.php:768  * @property {boolean} conf.MAIN_DISABLE_EDIT_PREDEF_PRICEHT"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_EDIT_PREDEF_PRICETTC', 'bool', NULL, 'core', 'Disables editing of the predefined unit price (incl. tax) field on document line forms.', 'Exposed as a boolean to JavaScript in core/tpl/objectline_create.tpl.php:691.', 'When enabled, users cannot modify the tax-inclusive unit price of a predefined product on document lines.', 'Truthy boolean = editing disabled; false/unset = editing allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:691|read|''MAIN_DISABLE_EDIT_PREDEF_PRICETTC'' => (bool) getDolGlobalInt(''MAIN_DISABLE_EDIT_PREDEF_PRICETTC''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_EXTERNALMODULES_COMMUNITY', 'bool', NULL, 'admin', 'Disables the display and installation of community (GitHub) modules even when MAIN_ENABLE_EXTERNALMODULES_COMMUNITY is set.', 'Checked in admin/modules.php:1392 as a guard that must be absent for the community module section to render. Acts as an override to suppress community modules.', 'Setting this constant prevents community modules from appearing regardless of MAIN_ENABLE_EXTERNALMODULES_COMMUNITY. Clearing it restores normal behaviour.', 'Empty/unset = community modules not suppressed; non-empty = community modules section disabled', 0, 0, 'admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1392|check|if (!getDolGlobalString(''MAIN_DISABLE_EXTERNALMODULES_COMMUNITY'') && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_COMMUNITY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_EXTERNALMODULES_DOLISTORE', 'bool', NULL, 'admin', 'Disables the display and installation of Dolistore modules even when MAIN_ENABLE_EXTERNALMODULES_DOLISTORE is set.', 'Checked in admin/modules.php:1359 as a guard that must be absent for the Dolistore section to render. Acts as an override to suppress Dolistore modules.', 'Setting this constant prevents the Dolistore module section from appearing regardless of MAIN_ENABLE_EXTERNALMODULES_DOLISTORE. Clearing it restores normal behaviour.', 'Empty/unset = Dolistore not suppressed; non-empty = Dolistore modules section disabled', 0, 0, 'admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1359|check|if (!getDolGlobalString(''MAIN_DISABLE_EXTERNALMODULES_DOLISTORE'') && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_DOLISTORE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_EXTRAFIELDS_CHECK_FOR_UPDATE', 'bool', NULL, 'core', 'Disables validation checks on extra field attribute names during update operations.', 'When truthy, bypasses two checks in core/actions_extrafields.inc.php: the minimum-length check (attribute name < 3 chars) and the reserved-word check. Intended as a developer or maintenance escape hatch with no admin UI.', 'Disabling these checks allows attribute names that are shorter than 3 characters or match reserved words to be saved, which may cause database or query errors.', 'Truthy string (checks disabled) or empty/unset (checks enforced).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_extrafields.inc.php:357|check|if (strlen(GETPOST(''attrname'', ''aZ09'')) < 3 && !getDolGlobalString(''MAIN_DISABLE_EXTRAFIELDS_CHECK_FOR_UPDATE'')) {", "core/actions_extrafields.inc.php:367|check|if (in_array(strtoupper(GETPOST(''attrname'', ''aZ09'')), $listofreservedwords) && !getDolGlobalString(''MAIN_DISABLE_EXTRAFIELDS_CHECK_FOR_UPDATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_FORCE_SAVEAS', 'bool', NULL, 'core', 'Controls whether file downloads are forced as Save-As (Content-Disposition: attachment) or can be displayed inline.', 'Checked across 10 occurrences in core/class/html.formfile.class.php:996, :1243, :1541, :2160, webportal/controllers/document.controller.class.php:137, ecm/class/ecmfiles.class.php:1069, and others. When value equals 2, inline display is forced; any other truthy value disables the forced Save-As header.', 'Setting to 2 allows documents to open inline in the browser; any truthy value disables the forced download prompt; leaving unset forces Save-As behavior.', '0/empty = force Save-As download; 1 = disable forced Save-As; 2 = force inline display', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.formfile.class.php:1243|check|if (getDolGlobalInt(''MAIN_DISABLE_FORCE_SAVEAS'') == 2) {", "webportal/controllers/document.controller.class.php:137|check|if (getDolGlobalString(''MAIN_DISABLE_FORCE_SAVEAS'')) {", "core/modules/member/doc/pdf_standard_member.class.php:501|check|if (getDolGlobalString(''MAIN_DISABLE_FORCE_SAVEAS'')) {", "ecm/class/ecmfiles.class.php:1069|check|if (getDolGlobalInt(''MAIN_DISABLE_FORCE_SAVEAS'') == 2) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_FORCE_SAVEAS_WEBSITE', 'bool', NULL, 'core', 'When enabled, disables the forced Save-As behaviour in website container wrappers, allowing normal page rendering instead.', 'Checked in multiple website template wrapper files (install/doctemplates/websites/*/containers/wrapper.php and website/samples/wrapper.php) to determine whether to bypass the forced save-as download behaviour. No admin UI write path is present in the payload.', 'Enabling this constant suppresses the forced file download (Save-As) triggered by website container wrappers, allowing the page to render normally in the browser.', 'Truthy value to disable forced Save-As; unset or 0 to keep default Save-As behaviour.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["install/doctemplates/websites/website_template-homesubmenu_dev/containers/wrapper.php:68|check|if (getDolGlobalString(''MAIN_DISABLE_FORCE_SAVEAS_WEBSITE'')) {", "website/samples/wrapper.php:121|check|if (getDolGlobalString(''MAIN_DISABLE_FORCE_SAVEAS_WEBSITE'')) {", "install/doctemplates/websites/website_template-association_exp/containers/wrapper.php:116|check|if (getDolGlobalString(''MAIN_DISABLE_FORCE_SAVEAS_WEBSITE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_FPDI', 'bool', NULL, 'core', 'When enabled, disables the FPDI library used to embed PDF background images into generated PDF documents.', 'Checked in 11 locations across multiple PDF generation modules (stock, stocktransfer, expedition, supplier_order, accountancy, etc.) always in the pattern: if (!MAIN_DISABLE_FPDI && MAIN_ADD_PDF_BACKGROUND). When this constant is set, the background embedding block is skipped.', 'Enabling prevents PDF background images from being applied to any generated documents, which may be needed if FPDI is unavailable or causes errors. Disabling allows background images when MAIN_ADD_PDF_BACKGROUND is also set.', 'Truthy = disable FPDI/PDF background embedding; empty/unset = FPDI enabled (backgrounds applied when MAIN_ADD_PDF_BACKGROUND is set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stock/doc/pdf_standard_stock.modules.php:236|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:322|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {", "core/modules/expedition/doc/pdf_rouget.modules.php:306|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {", "core/modules/supplier_order/doc/pdf_cornas.modules.php:294|check|if (!getDolGlobalString(''MAIN_DISABLE_FPDI'') && getDolGlobalString(''MAIN_ADD_PDF_BACKGROUND'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_FREE_LINES', 'bool', NULL, 'compta', 'Prevents adding free-text lines (without a linked product) to documents such as invoices, orders, and proposals.', 'Checked in reception/card.php:933, compta/facture/card.php:2496, commande/card.php:991, comm/propal/card.php:1263, expedition/card.php:1196, contrat/card.php:506, compta/facture/card-rec.php:556, and core/tpl/objectline_create.tpl.php:212. When set and $idprod <= 0, the free line is rejected. No admin UI write path exists.', 'Enabling this constant blocks entry of any document line not tied to a product reference; this enforces product-only line entry across invoices, orders, proposals, contracts, shipments, and receptions.', 'Truthy string/bool=free lines blocked, empty/0=free lines allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:933|check|if (getDolGlobalString(''MAIN_DISABLE_FREE_LINES'') && $idprod <= 0) {", "compta/facture/card.php:2496|check|if (getDolGlobalString(''MAIN_DISABLE_FREE_LINES'') && $idprod <= 0) {", "core/tpl/objectline_create.tpl.php:212|check|if (!getDolGlobalString(''MAIN_DISABLE_FREE_LINES'')) {", "commande/card.php:991|check|if (getDolGlobalString(''MAIN_DISABLE_FREE_LINES'') && $idprod <= 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_FULL_SCANLIST', 'bool', NULL, 'product', 'Disables the full table scan used to count total records on list pages, improving performance on large datasets.', 'Checked in 153 locations across admin list pages (e.g. accountancy/admin/template/list.php:283, accountancy/admin/fiscalyear.php:130, api/admin/token_list.php:182). When set, the full scan COUNT query is skipped, reducing database load on large tables.', 'Enabling this constant removes the total-row count from list views, which improves performance but removes pagination totals.', 'Non-zero = full scan disabled (better performance); 0 or unset = full scan enabled.', 0, 0, 'accountancy/admin/template/list.php|accountancy/admin/fiscalyear.php|accountancy/admin/subaccount.php|accountancy/admin/productaccount.php|api/admin/token_list.php|accountancy/admin/categories.php|accountancy/admin/account.php|hrm/admin/admin_establishment.php|admin/emailcollector_list.php|admin/mails_senderprofile_list.php|admin/dict.php|admin/tools/listevents.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/template/list.php:283|check|if (!getDolGlobalInt(''MAIN_DISABLE_FULL_SCANLIST'')) {", "accountancy/admin/fiscalyear.php:130|check|if (!getDolGlobalInt(''MAIN_DISABLE_FULL_SCANLIST'')) {", "api/admin/token_list.php:182|check|if (!getDolGlobalInt(''MAIN_DISABLE_FULL_SCANLIST'')) {", "hrm/admin/admin_establishment.php:115|check|if (!getDolGlobalInt(''MAIN_DISABLE_FULL_SCANLIST'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_GLOBAL_BOXSTATS', 'bool', NULL, 'theme', 'When enabled, suppresses the global statistics box from appearing on the opened dashboard.', 'Checked in theme/eldy/info-box.inc.php:254, theme/md/info-box.inc.php:400, and core/boxes/box_dolibarr_state_board.php:69. The global stats box is only rendered when this constant is falsy AND MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD is set. No admin UI write path is present in the payload.', 'Enabling this constant hides the global statistics dashboard box from all users. Leaving it unset allows the box to appear when MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD is also set.', 'Truthy value to disable; unset or 0 to allow global stats box.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/info-box.inc.php:254|check|<?php if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_BOXSTATS'') && getDolGlobalString(''MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD'')) { ?>", "theme/md/info-box.inc.php:400|check|<?php if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_BOXSTATS'') && getDolGlobalString(''MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD'')) { ?>", "core/boxes/box_dolibarr_state_board.php:69|check|if (empty($user->socid) && !getDolGlobalString(''MAIN_DISABLE_GLOBAL_BOXSTATS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_GLOBAL_WORKBOARD', 'bool', NULL, 'index.php', 'Disables the global workboard statistics section on the Dolibarr home dashboard.', 'Checked in admin/ihm.php:606 (to decide whether to render workboard options) and in index.php:181 (to skip loading workboard data). When set, the workboard block is not rendered.', 'Enabling this constant hides the workboard section from the dashboard, reducing page load for installations that do not need it.', 'Boolean flag: truthy value = workboard disabled; 0 or unset = workboard displayed.', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:181|check|if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_WORKBOARD'') && getDolGlobalInt(''MAIN_OPTIMIZEFORTEXTBROWSER'') < 2) {", "admin/ihm.php:606|check|if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_WORKBOARD'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_JAVASCRIPT', 'bool', NULL, 'comm', 'Disables JavaScript/AJAX features globally across the Dolibarr interface.', 'Read in core/class/conf.class.php:946 to set the global use_javascript_ajax flag. Configurable via admin/ihm.php (write line 279, though currently commented out). Also checked in comm/remx.php to gate discount-split features.', 'Setting this to a truthy value disables all JavaScript and AJAX-dependent UI components. This affects dynamic product selectors, inline editing, and other interactive elements.', '0 or not set = JavaScript enabled; 1 = JavaScript/AJAX disabled', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:946|read|$this->use_javascript_ajax = (int) !getDolGlobalInt(''MAIN_DISABLE_JAVASCRIPT'');", "admin/ihm.php:279|write|//dolibarr_set_const($db, \"MAIN_DISABLE_JAVASCRIPT\", GETPOST(\"MAIN_DISABLE_JAVASCRIPT\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "comm/remx.php:658|check|if (getDolGlobalInt(''DISCOUNT_SPLIT_MORE_THAN_TWO_PARTS'') && !getDolGlobalInt(''MAIN_DISABLE_JAVASCRIPT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_JQUERY_JNOTIFY', 'bool', NULL, 'core', 'Disables the jQuery jNotify plugin used for in-page notification pop-ups.', 'Checked in main.inc.php:1992, core/js/lib_head.js.php:1511, and core/lib/functions.lib.php:11492 and :11517 to suppress jNotify loading and usage.', 'Enabling this prevents jNotify pop-up notifications from being displayed; messages fall back to static display instead.', '0 or unset = jNotify enabled; 1 (truthy) = jNotify disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1992|check|if (!getDolGlobalString(''MAIN_DISABLE_JQUERY_JNOTIFY'') && !defined(''DISABLE_JQUERY_JNOTIFY'')) {", "core/js/lib_head.js.php:1511|check|if (!getDolGlobalString(''MAIN_DISABLE_JQUERY_JNOTIFY'') && !defined(''DISABLE_JQUERY_JNOTIFY'')) {", "core/lib/functions.lib.php:11517|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_DISABLE_JQUERY_JNOTIFY'') && empty($keepembedded)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_LDAP_TAB', 'bool', NULL, 'core', 'Hides the LDAP tab on user, group, member, and contact detail pages for non-admin users.', 'Checked in core/lib/usergroups.lib.php:57 and :264, core/lib/member.lib.php:48 and :198, and core/lib/contact.lib.php:47 with the pattern: !getDolGlobalString(''MAIN_DISABLE_LDAP_TAB'') || !empty($user->admin). When set, the LDAP tab is suppressed unless the user is an admin.', 'Setting this constant removes the LDAP tab from all relevant entity pages for non-admin users. Admin users always retain the LDAP tab regardless of this setting.', 'Non-empty string = LDAP tab hidden for non-admins. Empty/unset = LDAP tab visible for all.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/usergroups.lib.php:57|read|&& (!getDolGlobalString(''MAIN_DISABLE_LDAP_TAB'') || !empty($user->admin))) {", "core/lib/usergroups.lib.php:264|read|&& (!getDolGlobalString(''MAIN_DISABLE_LDAP_TAB'') || !empty($user->admin))) {", "core/lib/member.lib.php:48|read|&& (!getDolGlobalString(''MAIN_DISABLE_LDAP_TAB'') || !empty($user->admin))) {", "core/lib/contact.lib.php:47|read|&& (!getDolGlobalString(''MAIN_DISABLE_LDAP_TAB'') || !empty($user->admin))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_METEO', 'bool', NULL, 'admin', 'Controls whether and how the weather-indicator widget is shown on the Dolibarr home dashboard.', 'Read in index.php:182 to set $showweather (0=hidden, 1=shown, 2=shown but hidden on mobile). Selectable via admin/delais.php using a dropdown with labelled options. The value 1 fully disables the widget; value 2 hides it only on small screens.', 'Changing this value shows or hides the weather/health indicator on the dashboard; value 2 keeps it visible on desktop only.', 'Integer: 0 or unset = widget shown; 1 = widget disabled; 2 = widget shown but hidden on smartphones.', 0, 0, 'admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:182|read|$showweather = (!getDolGlobalString(''MAIN_DISABLE_METEO'') || getDolGlobalInt(''MAIN_DISABLE_METEO'') == 2) ? 1 : 0;", "index.php:702|read|$appendClass = (getDolGlobalInt(''MAIN_DISABLE_METEO'') == 2 ? '' hideonsmartphone'' : '''');", "admin/delais.php:315|check|if (!getDolGlobalString(''MAIN_DISABLE_METEO'') || getDolGlobalInt(''MAIN_DISABLE_METEO'') != 1) {", "admin/delais.php:202|write|dolibarr_set_const($db, \"MAIN_DISABLE_METEO\", GETPOST(\"MAIN_DISABLE_METEO\"), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_MULTIPLE_FILEUPLOAD', 'bool', NULL, 'core', 'Disables multiple-file selection on file upload inputs.', 'Checked at core/upload_page.php:328 and core/class/html.formfile.class.php:247; when set, the file input renders as a single-file selector (name=''userfile'') instead of a multi-file selector (name=''userfile[]'' with the ''multiple'' attribute). No admin UI is provided.', 'Enabling this constant restricts file upload inputs to one file at a time, preventing bulk uploads.', 'Non-empty/truthy = multiple file upload disabled; empty/unset = multiple file upload allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/upload_page.php:328|read|$out .= ((getDolGlobalString(''MAIN_DISABLE_MULTIPLE_FILEUPLOAD'') || $disablemulti) ? '' name=\"userfile\"'' : '' name=\"userfile[]\" multiple'');", "core/class/html.formfile.class.php:247|read|$out .= ((getDolGlobalString(''MAIN_DISABLE_MULTIPLE_FILEUPLOAD'') || $disablemulti) ? '' name=\"userfile\"'' : '' name=\"userfile[]\" multiple'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_NEW_OPENED_DASH_BOARD', 'bool', NULL, 'index.php', 'Disables the new-style opened-items dashboard panel on the Dolibarr home page.', 'Checked in index.php:542; when set the new opened dashboard section is skipped. No admin UI is present.', 'Setting this constant prevents the new opened-items panel from being rendered on the home page.', 'Boolean flag: truthy = panel disabled; 0 or unset = panel displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:542|check|if (!getDolGlobalString(''MAIN_DISABLE_NEW_OPENED_DASH_BOARD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_NOTES_TAB', 'bool', NULL, 'core', 'Hides the Notes tab on record detail pages across many modules.', 'COMMENT: `Called by bloc_showhide.tpl.php, itself called when MAIN_DISABLE_CONTACTS_TAB or MAIN_DISABLE_NOTES_TAB are set` (core/ajax/extraparams.php:23). Checked across 31 occurrences including core/lib/product.lib.php (lines 207, 341), product/card.php (lines 2472, 3023), core/lib/contact.lib.php:111, and supplier_proposal/card.php:2206.', 'Enabling this setting removes the Notes tab from all affected record pages, hiding notes from the UI.', 'Truthy string (non-empty) = Notes tab hidden; empty/not set = Notes tab shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/ajax/extraparams.php:23  *\t\t\t\tCalled bu bloc_showhide.tpl.php, itself called when MAIN_DISABLE_CONTACTS_TAB or MAIN_DISABLE_NOTES_TAB are set", "core/lib/product.lib.php:207|check|if (!getDolGlobalString(''MAIN_DISABLE_NOTES_TAB'')) {", "supplier_proposal/card.php:2206|check|if (getDolGlobalString(''MAIN_DISABLE_NOTES_TAB'')) {", "fourn/commande/card.php:2770|check|if (getDolGlobalString(''MAIN_DISABLE_NOTES_TAB'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_OTHER_LINK', 'bool', NULL, 'fourn', 'Hides the ''Other'' link section (cross-module navigation links) on record detail pages across many modules.', 'Checked across 33 occurrences including supplier_proposal/card.php:1943, compta/facture/card.php:5303, fourn/facture/card.php:3356, and contrat/messaging.php:196, always as `if (!getDolGlobalString(''MAIN_DISABLE_OTHER_LINK'') && $object->thirdparty->id > 0)`.', 'Enabling this setting removes the cross-module ''Other'' navigation links from all affected record pages, simplifying the UI.', 'Truthy string (non-empty) = ''Other'' links hidden; empty/not set = ''Other'' links shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1943|check|if (!getDolGlobalString(''MAIN_DISABLE_OTHER_LINK'') && $object->thirdparty->id > 0) {", "compta/facture/card.php:5303|check|if (!getDolGlobalString(''MAIN_DISABLE_OTHER_LINK'') && $object->thirdparty->id > 0) {", "fourn/facture/card.php:3356|check|if (!getDolGlobalString(''MAIN_DISABLE_OTHER_LINK'') && $object->thirdparty->id > 0) {", "fourn/facture/messaging.php:179|check|if (!getDolGlobalString(''MAIN_DISABLE_OTHER_LINK'') && $object->thirdparty->id > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_PDF_AUTOUPDATE', 'bool', NULL, 'fourn', 'When set, disables the automatic regeneration of PDF documents after record saves or status changes.', 'Checked in 133 locations across supplier_proposal/class/supplier_proposal.class.php:1821, supplier_proposal/card.php (lines 228, 536, 623, 688, 741, 1057, 1154), and many other modules. Code comments at adherents/class/adherent.class.php:2164 show that PDF generation is forced regardless: ''Generate PDF (whatever is option MAIN_DISABLE_PDF_AUTOUPDATE) so we can include it into email''.', 'Setting this constant prevents automatic PDF file regeneration on saves and status changes across all modules, reducing disk I/O and generation time.', 'Non-empty/truthy = disable auto PDF regeneration; empty/unset = auto-regenerate PDFs (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:1821|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_AUTOUPDATE'')) {", "adherents/class/adherent.class.php:2164  // Generate PDF (whatever is option MAIN_DISABLE_PDF_AUTOUPDATE) so we can include it into email", "supplier_proposal/card.php:228|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_AUTOUPDATE'')) {", "compta/facture/card-rec.php:766  /*if (empty($conf->global->MAIN_DISABLE_PDF_AUTOUPDATE))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_PDF_COMPRESSION', 'bool', NULL, 'core', 'Disables output compression when generating PDF files.', 'Checked across 51 occurrences in PDF generation modules and core/ajax/onlineSign.php; when set, PDF output is generated without compression.', 'Disabling compression increases PDF file sizes but can aid debugging or compatibility with certain PDF processors.', '0 or unset = PDF compression enabled; 1 = PDF compression disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/rapport/pdf_paiement.class.php:394|check|if (getDolGlobalString(''MAIN_DISABLE_PDF_COMPRESSION'')) {", "core/ajax/onlineSign.php:178|check|if (getDolGlobalString(''MAIN_DISABLE_PDF_COMPRESSION'')) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:341|check|if (getDolGlobalString(''MAIN_DISABLE_PDF_COMPRESSION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_PDF_THUMBS', 'bool', NULL, 'expensereport', 'Disables PDF thumbnail generation via Imagick, useful when the thumbnail generation causes errors.', 'Checked with negation in three files: core/lib/functions.lib.php:3548, expensereport/tpl/expensereport_linktofile.tpl.php:97, and expensereport/card.php:2324. Each occurrence includes the inline comment about Imagick trouble.', 'Setting this constant prevents PDF thumbnail creation across core file handling and expense reports. Without it, thumbnails are generated using Imagick when available.', 'If you experience trouble with pdf thumb generation and imagick, you can disable here. Non-empty = thumbnails disabled; absent/empty = thumbnails enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3548|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_THUMBS'')) {\t\t// If you experience trouble with pdf thumb generation and imagick, you can disable here.", "expensereport/tpl/expensereport_linktofile.tpl.php:97|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_THUMBS'')) {\t\t// If you experience trouble with pdf thumb generation and imagick, you can disable here.", "expensereport/card.php:2324|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_THUMBS'')) {\t\t// If you experience trouble with pdf thumb generation and imagick, you can disable here."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_PROPAGATE_NOTES_FROM_ORIGIN', 'bool', NULL, 'compta', 'Disables automatic propagation of notes from an origin document when creating a new document.', 'Checked with negation in 4 locations: compta/facture/class/facture.class.php:1505, :1642, :1771, and commande/class/commande.class.php:1480. Notes are propagated when this constant is not set; setting it prevents that behaviour. No admin UI is present.', 'When set, notes from the origin document are not copied to the new document; when unset, notes are propagated automatically.', '0 or unset = notes are propagated from origin; truthy value = notes are not propagated.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:1505|check|if (!getDolGlobalString(''MAIN_DISABLE_PROPAGATE_NOTES_FROM_ORIGIN'')) {", "compta/facture/class/facture.class.php:1642|check|if (!getDolGlobalString(''MAIN_DISABLE_PROPAGATE_NOTES_FROM_ORIGIN'')) {", "compta/facture/class/facture.class.php:1771|check|if (!getDolGlobalString(''MAIN_DISABLE_PROPAGATE_NOTES_FROM_ORIGIN'')) {", "commande/class/commande.class.php:1480|check|if (!getDolGlobalString(''MAIN_DISABLE_PROPAGATE_NOTES_FROM_ORIGIN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_RECURRING_EVENTS', 'bool', NULL, 'comm', 'Disables the recurring/repeat event feature in the agenda module.', 'When set to a non-zero integer, the $userepeatevent flag is forced to 0 in comm/action/card.php at lines 584 and 1533, hiding the recurring event UI. The same logic appears commented out at line 2197.', 'Enabling this constant removes the repeat-event UI from action/event cards, preventing users from creating recurring agenda entries.', '0 or unset = recurring events enabled; non-zero = recurring events disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/action/card.php:584|read|$userepeatevent = (getDolGlobalInt(''MAIN_DISABLE_RECURRING_EVENTS'') ? 0 : 1);", "comm/action/card.php:1533|read|$userepeatevent = (getDolGlobalInt(''MAIN_DISABLE_RECURRING_EVENTS'') ? 0 : 1);", "comm/action/card.php:2197  // $userepeatevent = (getDolGlobalInt(''MAIN_DISABLE_RECURRING_EVENTS'') ? 0 : 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_SELECT2_FOCUS_PROTECTION', 'bool', NULL, 'core', 'Disables the Select2 focus-protection workaround in the Dolibarr JavaScript head library.', 'Checked in core/js/lib_head.js.php:1648. When set (or when the constant DISABLE_SELECT2_FOCUS_PROTECTION is defined), the focus-protection code block is skipped.', 'Setting this constant disables the Select2 focus fix, which may expose focus-related UI bugs in browsers where the workaround was needed.', 'Any non-empty value = disable Select2 focus protection; empty/unset = protection active', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!getDolGlobalString(''MAIN_DISABLE_SELECT2_FOCUS_PROTECTION'') && !defined(''DISABLE_SELECT2_FOCUS_PROTECTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_SUGGEST_REF_AS_PREFIX', 'bool', NULL, 'core', 'Disables automatic suggestion of the document reference as a filename prefix in document upload areas.', 'Checked in core/tpl/document_actions_post_headers.tpl.php:116, :118, and expensereport/tpl/expensereport_addfile.tpl.php:49. No admin UI write was found; HIDDEN_GUESS is 1.', 'When enabled, the document upload form no longer pre-fills the document name prefix with the parent record''s reference.', '0 (suggest prefix, default behavior) or 1 (disable suggestion)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/document_actions_post_headers.tpl.php:116|check|if (!isset($savingdocmask) || getDolGlobalString(''MAIN_DISABLE_SUGGEST_REF_AS_PREFIX'')) {", "core/tpl/document_actions_post_headers.tpl.php:118|check|if (!getDolGlobalString(''MAIN_DISABLE_SUGGEST_REF_AS_PREFIX'')) {", "expensereport/tpl/expensereport_addfile.tpl.php:49|check|if (!getDolGlobalString(''MAIN_DISABLE_SUGGEST_REF_AS_PREFIX'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_TCPDI', 'bool', NULL, 'core', 'Disables the use of the TCPDI library for PDF import/merge operations.', 'Checked in core/lib/pdf.lib.php:181 and :192; when set, TCPDI is not used even if the class exists.', 'Enabling this constant prevents TCPDI from being loaded, disabling PDF import or merge features that depend on it.', 'Truthy value to disable TCPDI; absent or falsy to allow TCPDI if the class exists.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:181|check|if (!getDolGlobalString(''MAIN_DISABLE_TCPDI'')) {", "core/lib/pdf.lib.php:192|check|if (!getDolGlobalString(''MAIN_DISABLE_TCPDI'') && class_exists(''TCPDI'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_TRUNC', 'bool', NULL, 'core', 'Disables all string truncation performed by Dolibarr''s truncation helper when set to 1.', 'The comment in core/lib/functions.lib.php:5565 states ''MAIN_DISABLE_TRUNC=1 can disable all truncings''. The truncation function at line 5579 skips truncation entirely when this constant is truthy.', 'Setting this to 1 causes all truncated strings (labels, descriptions, etc.) to be rendered at full length, which may break fixed-width UI layouts.', '1 = disable all truncation; 0 or empty = normal truncation applies', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5565  *  MAIN_DISABLE_TRUNC=1 can disable all truncings", "core/lib/functions.lib.php:5579|check|if (empty($size) || getDolGlobalString(''MAIN_DISABLE_TRUNC'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISABLE_WRAPPING_ON_COLUMN_TITLE', 'bool', NULL, 'core', 'Disables the tooltip title attribute added to column header cells to prevent text wrapping hints.', 'Used in the column-header rendering function at core/lib/functions.lib.php:7209 and 7223. When set, the code omits the title attribute from column headers. Commented-out legacy code at lines 7222 and 7250 shows the same pattern was retained across refactors.', 'Enabling this constant removes column-title tooltips from list views, which suppresses wrapping prevention behavior in column headers.', '0 or empty = column title tooltips generated; any truthy value = column title tooltips suppressed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7209|check|if (!getDolGlobalString(''MAIN_DISABLE_WRAPPING_ON_COLUMN_TITLE'') && $wrapcolumntitle) {", "core/lib/functions.lib.php:7223|read|$tagstart .= ($name && !getDolGlobalString(''MAIN_DISABLE_WRAPPING_ON_COLUMN_TITLE'') && $wrapcolumntitle && !dol_textishtml($name)) ? '' title=\"'' . dolPrintHTMLForAttribute($langs->t", "//$out .= (getDolGlobalString(''MAIN_DISABLE_WRAPPING_ON_COLUMN_TITLE'') ? '''' : '' title=\"''.dol_escape_htmltag($langs->trans($name)).''\""]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISALLOW_MEDIAS_IN_EMAIL_TEMPLATES', 'bool', NULL, 'core', 'Disables the inclusion of local media links in email templates when set to a non-zero integer.', 'Read in core/lib/functions2.lib.php:2915 via getDolGlobalInt; when non-zero, acceptlocallinktomedia is set to 0, preventing local media from being embedded in email template content.', 'Setting this to 1 prevents local media files from being referenced in email templates, which can avoid broken image links when emails are sent externally.', '0 or unset = local media links allowed; 1 = local media links disallowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2915|read|$acceptlocallinktomedia = getDolGlobalInt(''MAIN_DISALLOW_MEDIAS_IN_EMAIL_TEMPLATES'') ? 0 : 1;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISALLOW_SELECT2_WITH_SMARTPHONE', 'bool', NULL, 'core', 'Disables Select2 enhanced dropdowns on smartphone/phone layout browsers.', 'Checked in core/lib/ajax.lib.php:480; when the browser layout is ''phone'' and this constant is set, Select2 is not activated for that session.', 'Enabling forces plain HTML selects on mobile browsers, which may improve compatibility but removes Select2 autocomplete features on phones.', 'Truthy value to disable Select2 on phone layout; absent or falsy to allow Select2 on all layouts.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ajax.lib.php:480|check|if (!empty($conf->browser->layout) && $conf->browser->layout == ''phone'' && getDolGlobalString(''MAIN_DISALLOW_SELECT2_WITH_SMARTPHONE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISALLOW_URL_INTO_DESCRIPTIONS', 'bool', NULL, 'core', 'Controls whether and how URL links are disallowed inside description fields.', 'Checked at core/lib/functions.lib.php:9820 and 9824, and in core/class/doleditor.class.php:265. The comments at admin/system/security.php:1024-1025 document the two modes: ''= 1, disallow url links except if on the local wrapper document.php or viewimage.php'' and ''= 2, disallow all urls link''.', 'Setting to 1 blocks external URLs while allowing local ones; setting to 2 blocks all URLs in descriptions; 0 or unset allows all URLs.', '1 = disallow url links except if on the local wrapper document.php or viewimage.php; 2 = disallow all urls link; 0 or empty = URLs allowed', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/security.php:1024  // MAIN_DISALLOW_URL_INTO_DESCRIPTIONS = 1, disallow url links except if on the local wrapper document.php or viewimage.php", "admin/system/security.php:1025  // MAIN_DISALLOW_URL_INTO_DESCRIPTIONS = 2, disallow all urls link", "core/lib/functions.lib.php:9820|check|if (getDolGlobalInt(''MAIN_DISALLOW_URL_INTO_DESCRIPTIONS'') == 2 || $check == ''restricthtmlnolink'') {", "core/lib/functions.lib.php:9824|read|} elseif (getDolGlobalInt(''MAIN_DISALLOW_URL_INTO_DESCRIPTIONS'') == 1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DISPLAY_SQL_INSTALL_LOG', 'string', NULL, 'core', 'Controls whether SQL execution output is displayed during module install/uninstall SQL script runs.', 'Read in core/modules/DolibarrModules.class.php at lines 1319, 1344, 1369, 1394, and 1419: the second argument to run_sql() is set to 0 (verbose) when the constant is non-empty, or 1 (silent) when it is empty.', 'Setting this to a non-empty value causes SQL install/uninstall log output to be displayed; leaving it empty suppresses the output.', 'Empty = SQL log suppressed (default); any non-empty value = SQL log displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/DolibarrModules.class.php:1319|read|$result = run_sql($dir.$file, !getDolGlobalString(''MAIN_DISPLAY_SQL_INSTALL_LOG'') ? 1 : 0, 0, 1);", "core/modules/DolibarrModules.class.php:1344|read|$result = run_sql($dir.$file, !getDolGlobalString(''MAIN_DISPLAY_SQL_INSTALL_LOG'') ? 1 : 0, 0, 1);", "core/modules/DolibarrModules.class.php:1369|read|$result = run_sql($dir.$file, !getDolGlobalString(''MAIN_DISPLAY_SQL_INSTALL_LOG'') ? 1 : 0, 0, 1);", "core/modules/DolibarrModules.class.php:1394|read|$result = run_sql($dir.$file, !getDolGlobalString(''MAIN_DISPLAY_SQL_INSTALL_LOG'') ? 1 : 0, 0, 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENTS_DESCRIPTION_FIRST', 'string', NULL, 'core', 'Controls whether the description field is rendered before the product label in PDF line items.', 'Checked at core/lib/pdf.lib.php:2094; when truthy, the description is placed before the label in the line item output order. No admin UI write is present; must be set manually.', 'Enabling this reverses the default order so the product description appears before the product label in PDF line items.', 'Truthy string (non-empty) = description first; absent/empty = label first (default order).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2094|check|if (getDolGlobalString(''MAIN_DOCUMENTS_DESCRIPTION_FIRST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENTS_LIST_IN_TWOCOLUMNS', 'string', NULL, 'core', 'Renders the attached document list in a two-column layout instead of the default single-column layout.', 'Checked three times in core/tpl/document_actions_post_headers.tpl.php at lines 186, 217, and 235 to switch between single- and two-column rendering. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant changes the document list layout to two columns, affecting display width and arrangement of listed files.', '0 (single column) or 1 (two columns)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/document_actions_post_headers.tpl.php:186|check|if (getDolGlobalString(''MAIN_DOCUMENTS_LIST_IN_TWOCOLUMNS'')) {", "core/tpl/document_actions_post_headers.tpl.php:217|check|if (getDolGlobalString(''MAIN_DOCUMENTS_LIST_IN_TWOCOLUMNS'')) {", "core/tpl/document_actions_post_headers.tpl.php:235|check|if (getDolGlobalString(''MAIN_DOCUMENTS_LIST_IN_TWOCOLUMNS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENTS_LOGO_HEIGHT', 'string', NULL, 'admin', 'Sets the height (in pixels) of the logo printed on PDF documents.', 'Written at admin/pdf.php:153 via dolibarr_set_const and displayed in a text input at :532 using getDolGlobalInt with a default of 20. Configurable through the admin UI at admin/pdf.php.', 'Changing this integer value resizes the logo in generated PDF documents; the default is 20 when unset.', 'Integer (pixels); default = 20 when unset.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf.php:532|read|print ''<input type=\"text\" class=\"maxwidth50\" name=\"MAIN_DOCUMENTS_LOGO_HEIGHT\" value=\"''.getDolGlobalInt(''MAIN_DOCUMENTS_LOGO_HEIGHT'', 20).''\">'';", "admin/pdf.php:153|write|dolibarr_set_const($db, \"MAIN_DOCUMENTS_LOGO_HEIGHT\", GETPOSTINT(\"MAIN_DOCUMENTS_LOGO_HEIGHT\"), ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENTS_WITH_PICTURE_HEIGHT', 'string', NULL, 'core', 'Sets the maximum height in pixels for pictures embedded in PDF documents, defaulting to 32.', 'Read in core/lib/pdf.lib.php:3151 with a default of 32 when not set. No admin UI write is present.', 'Increasing the value allows taller embedded images; decreasing it or leaving it unset uses the 32px default.', 'integer (pixels); default = 32', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:3151|read|$maxheight = getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_HEIGHT'', 32);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENTS_WITH_PICTURE_WIDTH', 'string', NULL, 'core', 'Sets the column width in millimetres reserved for product pictures in PDF documents.', 'Written via admin/pdf_other.php:118 and read in 24 locations including core/modules/stocktransfer/doc/pdf_eagle.modules.php:144, core/modules/expedition/doc/pdf_rouget.modules.php:135, and core/lib/pdf.lib.php:3150. Default fallback value is 20 mm as shown in the comment.', 'Changing this value alters the width of the picture column in all PDF generators that include product images; the default is 20 mm when not set.', 'Integer value in millimetres; default 20 mm when not set (e.g. getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'', 20))', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:1278  // \t''width'' => (!getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'') ? 20 : getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'')), // in mm", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:144|read|$this->posxpicture = $this->posxweightvol - getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'', 20); // width of images", "core/modules/expedition/doc/pdf_rouget.modules.php:135|read|$this->posxpicture = $this->posxweightvol - getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'', 20); // width of images", "core/lib/pdf.lib.php:3150|read|$maxwidth = getDolGlobalInt(''MAIN_DOCUMENTS_WITH_PICTURE_WIDTH'', 20);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENT_DISABLE_NOEXE_IN_MEDIAS_DIR', 'bool', NULL, 'api', 'Disables the .noexe protection specifically for files uploaded into the public media directory.', 'Checked in api/class/api_documents.class.php:1207 and core/lib/files.lib.php:1512. The inline comment states: ''We never add .noexe on files into media directory'' when this flag is set and the upload is within the media dir. No admin UI is present.', 'When set, files uploaded to the public media directory are exempt from .noexe suffix appending even if they have executable content.', '0 or unset = .noexe rules apply uniformly; 1 = .noexe not added for files in the media directory.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_documents.class.php:1207|check|if (strpos($upload_dir, $publicmediasdirwithslash) !== 0 || !getDolGlobalInt(\"MAIN_DOCUMENT_DISABLE_NOEXE_IN_MEDIAS_DIR\")) {\t// We never add .noexe on files into media directory", "core/lib/files.lib.php:1512|check|if (strpos($upload_dir, $publicmediasdirwithslash) !== 0 || !getDolGlobalInt(\"MAIN_DOCUMENT_DISABLE_NOEXE_IN_MEDIAS_DIR\")) {\t// We never add .noexe on files into media directory"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOCUMENT_IS_OUTSIDE_WEBROOT_SO_NOEXE_NOT_REQUIRED', 'string', NULL, 'core', 'Disables the automatic appending of the .noexe extension to uploaded executable files.', 'Checked in core/lib/files.lib.php:1505, api/class/api_documents.class.php:1200, and core/actions_linkedfiles.inc.php:283. The comment at core/lib/files.lib.php:1441 explains that .noexe is added when a file has executable content unless this constant is set. Displayed in admin/system/security.php:1044.', 'When set, executable uploaded files will not have .noexe appended, which is safe only if the document directory is outside the webroot. When unset, executable files receive the .noexe suffix as a security measure.', '0 or unset = .noexe extension is appended to executable files (default/secure); truthy value = .noexe is not appended (only safe if documents are outside webroot).', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/files.lib.php:1441  *  - Extension .noexe may be added if file is executable and MAIN_DOCUMENT_IS_OUTSIDE_WEBROOT_SO_NOEXE_NOT_REQUIRED is not set.", "core/lib/files.lib.php:1505|check|if (isAFileWithExecutableContent($dest_file) && !getDolGlobalString(''MAIN_DOCUMENT_IS_OUTSIDE_WEBROOT_SO_NOEXE_NOT_REQUIRED'')) {", "api/class/api_documents.class.php:1200|check|if (isAFileWithExecutableContent($dest_file) && !getDolGlobalString(''MAIN_DOCUMENT_IS_OUTSIDE_WEBROOT_SO_NOEXE_NOT_REQUIRED'')) {", "core/actions_linkedfiles.inc.php:283|check|if (isAFileWithExecutableContent($filenameto) && !getDolGlobalString(''MAIN_DOCUMENT_IS_OUTSIDE_WEBROOT_SO_NOEXE_NOT_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_CREATE_METAFILE', 'string', NULL, 'core', 'Enables generation of a meta file alongside document files when they are created.', 'The comment states: ''This feature to generate the meta file is enabled only if option MAIN_DOC_CREATE_METAFILE is set.'' In core/lib/files.lib.php, when this constant is not set, meta file generation is skipped. No admin UI; hidden setting.', 'Setting this constant enables meta file creation alongside document generation; leaving it unset skips meta file generation.', 'Non-empty (truthy) enables meta file generation; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:1879  *  This feature to generate the meta file is enabled only if option MAIN_DOC_CREATE_METAFILE is set.", "core/lib/files.lib.php:1889|check|if (!getDolGlobalString(''MAIN_DOC_CREATE_METAFILE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_ODT_IMAGE_RATIO', 'string', NULL, 'core', 'Sets a scale ratio applied to images embedded in ODT documents generated from templates.', 'Checked across 46 occurrences in ODT generation modules; when set, the ratio value overrides the default image scaling used during ODT template substitution.', 'Setting this value scales images in generated ODT documents; leaving it unset uses the default image dimensions.', 'Numeric string (scale ratio, e.g. ''0.5'' for half size); empty or unset = default scaling.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:411|check|if (getDolGlobalString(''MAIN_DOC_ODT_IMAGE_RATIO'')) {", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:393|check|if (getDolGlobalString(''MAIN_DOC_ODT_IMAGE_RATIO'')) {", "core/modules/member/doc/doc_generic_member_odt.class.php:357|check|if (getDolGlobalString(''MAIN_DOC_ODT_IMAGE_RATIO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_SORT_FIELD', 'string', NULL, 'projet', 'Specifies the default field used to sort documents in document list views across multiple modules.', 'Checked and read across at least 10 occurrences in document list pages including projet/document.php (line 77-78), societe/document.php (line 69-70), contact/document.php (line 76-77), comm/propal/document.php, and commande/document.php.', 'Setting this value changes the default sort column applied to document lists in the affected modules.', 'String (field name, e.g. ''date'', ''name''); empty means the default sort field for each page is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/document.php:77|check|if (getDolGlobalString(''MAIN_DOC_SORT_FIELD'')) {", "projet/document.php:78|read|$sortfield = getDolGlobalString(''MAIN_DOC_SORT_FIELD'');", "societe/document.php:70|read|$sortfield = getDolGlobalString(''MAIN_DOC_SORT_FIELD'');", "contact/document.php:77|read|$sortfield = getDolGlobalString(''MAIN_DOC_SORT_FIELD'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_SORT_ORDER', 'string', NULL, 'projet', 'Specifies the default sort direction (ASC or DESC) for document lists across multiple modules.', 'Checked and read across at least 10 occurrences in document list pages including projet/document.php (line 80-81), societe/document.php (line 72-73), contact/document.php (line 79-80), comm/propal/document.php, and commande/document.php.', 'Setting this value changes the default sort direction applied to document lists in the affected modules.', 'String (''ASC'' or ''DESC''); empty means the default sort order for each page is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/document.php:80|check|if (getDolGlobalString(''MAIN_DOC_SORT_ORDER'')) {", "projet/document.php:81|read|$sortorder = getDolGlobalString(''MAIN_DOC_SORT_ORDER'');", "societe/document.php:73|read|$sortorder = getDolGlobalString(''MAIN_DOC_SORT_ORDER'');", "contact/document.php:80|read|$sortorder = getDolGlobalString(''MAIN_DOC_SORT_ORDER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_UPLOAD_NOT_RENAME_BY_DEFAULT', 'string', NULL, 'core', 'Prevents automatic renaming of uploaded documents by default when set.', 'Read in core/class/html.formfile.class.php:289 to determine the initial checked state of the rename checkbox: when set, the checkbox defaults to unchecked (no rename). No admin UI write is present.', 'When enabled, uploaded files retain their original names by default; when not set, automatic renaming is applied.', 'Truthy value (e.g. 1) to disable rename by default; empty or 0 to rename by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formfile.class.php:289|read|$rename = getDolGlobalString(''MAIN_DOC_UPLOAD_NOT_RENAME_BY_DEFAULT'') ? '''' : ''checked'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_USE_OBJECT_THIRDPARTY_NAME', 'bool', NULL, 'core', 'Controls whether the object''s linked third-party name is used instead of the default name in ODT document generation for companies.', 'Checked once in core/modules/societe/doc/doc_generic_odt.modules.php at line 264. When set, an alternative name source is used during document substitution variable construction.', 'Enabling this constant switches the name field in generated ODT documents to use the linked third-party object''s name.', 'Truthy value to use third-party name; empty or unset to use the default name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/doc/doc_generic_odt.modules.php:264|check|if (getDolGlobalString(''MAIN_DOC_USE_OBJECT_THIRDPARTY_NAME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOC_USE_TIMING', 'bool', NULL, 'core', 'Enables timing/profiling output during ODT document generation for debugging purposes.', 'Checked across 44 occurrences in ODT document generation modules (e.g. contracts, stock, users, members, shipments, orders) at the start of the document build process.', 'Enabling this activates timing measurements during document generation; it is a debugging aid with no effect on the generated document content.', '0 or unset = no timing output; 1 = timing output enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:291|check|if (getDolGlobalString(''MAIN_DOC_USE_TIMING'')) {", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:277|check|if (getDolGlobalString(''MAIN_DOC_USE_TIMING'')) {", "core/modules/user/doc/doc_generic_user_odt.modules.php:303|check|if (getDolGlobalString(''MAIN_DOC_USE_TIMING'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOLEDITOR_HEIGHT', 'string', NULL, 'core', 'Sets the height (in pixels) of the DolEditor rich text editor on document line create and edit forms.', 'The value is passed directly as the height argument to DolEditor in core/tpl/objectline_create.tpl.php:456 and core/tpl/objectline_edit.tpl.php:196; the default fallback is 100.', 'Changing this constant adjusts the visible height of the line description editor on both the create and edit templates.', 'Integer (pixels); default fallback = 100.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:456|read|$doleditor = new DolEditor(''dp_desc'', GETPOST(''dp_desc'', ''restricthtml''), '''', getDolGlobalInt(''MAIN_DOLEDITOR_HEIGHT'', 100), $toolbarname, '''', false, true, $enabled, $nbrows, ''98%''", "core/tpl/objectline_edit.tpl.php:196|read|$doleditor = new DolEditor(''product_desc'', GETPOSTISSET(''product_desc'') ? GETPOST(''product_desc'', ''restricthtml'') : $line->description, '''', getDolGlobalInt(''MAIN_DOLEDITOR_HEIGHT'',"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOLIBARR_USER_TIMEZONE', 'string', NULL, 'core', 'Sets a fallback timezone used in cron/CLI contexts where no user session timezone is available, defaulting to UTC.', 'Checked in core/lib/functions.lib.php:3943 with a default of ''UTC''; the comment at line 3942 explains this is used when there is no session (e.g. in cron). No admin UI write detected.', 'Changing this value shifts date/time calculations in cron jobs to the specified timezone. Without it, UTC is used as the fallback.', 'if no session (by example in cron) may use MAIN_DOLIBARR_USER_TIMEZONE instead UTC. Any valid PHP timezone string (e.g., ''Europe/Berlin'', ''Indian/...''); default ''UTC''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3942  // if no session (by example in cron) may use MAIN_DOLIBARR_USER_TIMEZONE instead UTC", "core/lib/functions.lib.php:3943|check|$offsettzstring = (empty($_SESSION[''dol_tz_string'']) ? getDolGlobalString(''MAIN_DOLIBARR_USER_TIMEZONE'', ''UTC'') : $_SESSION[''dol_tz_string'']);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DOL_SCRIPTS_ROOT', 'string', NULL, 'core', 'Specifies the filesystem path to the Dolibarr scripts root directory, used for locating the odt2pdf conversion script and cron scripts.', 'Checked and read at includes/odtphp/odf.php lines 941 and 944 to build the odt2pdf.sh command path. Also checked and read at core/lib/cron.lib.php lines 134 and 135 to set the path to cron scripts.', 'Setting this constant enables ODT-to-PDF conversion via the odt2pdf.sh script and provides the base path for cron scripts. Clearing it disables those integrations.', 'String; filesystem path to the scripts root directory, e.g. ''/var/www/dolibarr/scripts''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/odtphp/odf.php:944|read|$command = dol_sanitizePathName(getDolGlobalString(''MAIN_DOL_SCRIPTS_ROOT'')).''/scripts/odt2pdf/odt2pdf.sh ''.escapeshellarg($tmpname).'' ''.escapeshellarg($paramodt2pdf);", "includes/odtphp/odf.php:941|check|if (getDolGlobalString(''MAIN_DOL_SCRIPTS_ROOT'')) {", "core/lib/cron.lib.php:134|check|if (getDolGlobalString(''MAIN_DOL_SCRIPTS_ROOT'')) {", "core/lib/cron.lib.php:135|read|$pathtoscript = getDolGlobalString(''MAIN_DOL_SCRIPTS_ROOT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DONT_KEEP_NOTE_ON_CLONING', 'string', NULL, 'compta', 'Suppresses copying of notes when cloning invoices or proposals.', 'Checked with value == 1 in compta/facture/class/facture.class.php:1336, fourn/class/fournisseur.facture.class.php:3242, and comm/propal/class/propal.class.php:1593 to skip note propagation during clone operations. No admin UI is present.', 'When set to 1, notes from the original document are not copied to the cloned document.', '0 or unset = notes are copied on clone; 1 = notes are not copied on clone.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:1336|check|if (getDolGlobalInt(''MAIN_DONT_KEEP_NOTE_ON_CLONING'') == 1) {", "fourn/class/fournisseur.facture.class.php:3242|check|if (getDolGlobalInt(''MAIN_DONT_KEEP_NOTE_ON_CLONING'') == 1) {", "comm/propal/class/propal.class.php:1593|check|if (getDolGlobalInt(''MAIN_DONT_KEEP_NOTE_ON_CLONING'') == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DONT_SHIP_MORE_THAN_ORDERED', 'string', NULL, 'expedition', 'Prevents shipping a quantity greater than the quantity ordered on the source order line.', 'Checked once in expedition/card.php at line 495; when set as a non-zero integer and the cumulative shipped quantity exceeds the ordered quantity, the over-shipment is blocked.', 'Enabling this constant enforces that shipped quantities cannot exceed ordered quantities. Disabling it permits over-shipment without restriction.', 'Non-zero integer to block over-shipment; 0 or unset to allow any quantity.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/card.php:495|check|if (getDolGlobalInt(\"MAIN_DONT_SHIP_MORE_THAN_ORDERED\") && $subtotalqty > $objectsrc->lines[$i]->qty) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DO_FETCH_IN_ONE_SQL_REQUEST', 'string', NULL, 'compta', 'Enables fetching invoice lines via a single consolidated SQL request instead of individual queries.', 'Configured via admin/system/perf.php (read at line 799, checked at line 793). Read in compta/facture/class/facture.class.php (lines 2207, 2476) and compta/facture/class/factureligne.class.php:204 to control the fetch strategy for invoice lines.', 'When enabled, invoice line loading uses a single SQL query which can improve performance on large invoice sets; when disabled or unset, the default fetch strategy is used.', 'Integer: non-zero to enable single-SQL fetch; 0 or unset to use the default.', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/perf.php:799|read|print '' = ''.getDolGlobalString(''MAIN_DO_FETCH_IN_ONE_SQL_REQUEST'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefined\").''</span>'');", "compta/facture/class/facture.class.php:2207|read|$doFetchInOneSqlRequest = getDolGlobalInt(''MAIN_DO_FETCH_IN_ONE_SQL_REQUEST'');", "compta/facture/class/factureligne.class.php:204|read|$doFetchInOneSqlRequest = getDolGlobalInt(''MAIN_DO_FETCH_IN_ONE_SQL_REQUEST'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DO_NOT_AUTOFILL_DATE_INVOICE', 'string', NULL, 'compta', 'When enabled, prevents the invoice date field from being auto-filled on new invoice creation, leaving it empty by default.', 'Read in compta/facture/card.php:3701 to set $dateinvoice to -1 (keep empty) instead of '''' (auto-fill). Only one occurrence is present in the payload.', 'Enabling this constant requires users to manually enter the invoice date instead of having it auto-populated.', '0 or unset = invoice date is auto-filled (''''); truthy = invoice date is left empty (-1).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:3701|read|$dateinvoice = (getDolGlobalString(''MAIN_DO_NOT_AUTOFILL_DATE_INVOICE'') ? -1 : '''');\t\t// By default '''' so we will autofill date. -1 means keep empty."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DO_NOT_AUTOFILL_DATE_ORDER', 'string', NULL, 'commande', 'Prevents the order date field from being auto-filled when displaying the order form.', 'Read in commande/card.php:2387 with an inline comment: ''// By default '''' so we will autofill date. -1 means keep empty.'' When set, $dateorder is -1 (empty); when not set, it is '''' (auto-fill). No admin UI write is present.', 'Setting this constant keeps the order date field empty by default instead of auto-filling it. Leaving it unset causes the date to be auto-filled.', 'Truthy = date field kept empty; falsy or unset = date auto-filled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:2387|read|$dateorder = (getDolGlobalString(''MAIN_DO_NOT_AUTOFILL_DATE_ORDER'') ? -1 : '''');\t\t// By default '''' so we will autofill date. -1 means keep empty."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DO_NOT_AUTOFILL_DATE_PROPOSAL', 'string', NULL, 'comm', 'Controls whether the proposal creation date field is auto-filled or left empty by default.', 'When set, the proposal date field is initialized to -1 (kept empty) instead of being auto-filled with the current date. Seen in comm/propal/card.php:2240.', 'If enabled, users must manually enter the proposal date; if absent or empty, the date is auto-filled automatically.', 'Empty/unset = auto-fill date; any truthy value = keep date field empty (-1).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:2240|read|$datepropal = (getDolGlobalString(''MAIN_DO_NOT_AUTOFILL_DATE_PROPOSAL'') ? -1 : '''');  // By default '''' so we will autofill date. -1 means keep empty."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DUPLICATE_CONTACTS_TAB_ON_CUSTOMER_CARD', 'string', NULL, 'comm', 'Duplicates the contacts tab on the customer card.', 'Checked in comm/card.php:1828 to conditionally render an additional contacts tab on the customer card.', 'Enabling this constant causes the contacts tab to appear twice on the customer card.', 'Truthy value = contacts tab duplicated; empty/unset = single contacts tab.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/card.php:1828|check|if (getDolGlobalString(''MAIN_DUPLICATE_CONTACTS_TAB_ON_CUSTOMER_CARD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DUPLICATE_CONTACTS_TAB_ON_MAIN_CARD', 'string', NULL, 'societe', 'Displays a contacts tab directly on the main third-party card in addition to the dedicated contacts page.', 'When set, societe/card.php:933 renders the contacts section on the main company card (subject to SOCIETE_DISABLE_CONTACTS and SOCIETE_ADDRESSES_MANAGEMENT) and societe/card.php:3605 adds a tab. fourn/card.php:1114 also checks it for supplier cards.', 'Enabling this constant duplicates the contacts tab on main entity cards; disabling it removes that duplicate.', 'Truthy value shows contacts on the main card; absent or falsy hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/card.php:1114|check|if (getDolGlobalString(''MAIN_DUPLICATE_CONTACTS_TAB_ON_MAIN_CARD'')) {", "societe/card.php:933|check|if (getDolGlobalString(''MAIN_DUPLICATE_CONTACTS_TAB_ON_MAIN_CARD'') && (!getDolGlobalString(''SOCIETE_DISABLE_CONTACTS'') || getDolGlobalString(''SOCIETE_ADDRESSES_MANAGEMENT''))) {", "societe/card.php:3605|check|if (getDolGlobalString(''MAIN_DUPLICATE_CONTACTS_TAB_ON_MAIN_CARD'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DURATION_OF_WORKDAY', 'string', NULL, 'projet', 'Defines the number of seconds in a workday, used when converting time durations to a days-hours-minutes display.', 'Read as $conf->global->MAIN_DURATION_OF_WORKDAY and passed to convertSecondToTime() across multiple files including projet/tasks/time.php:518, :711, :869, projet/element.php:1900, fichinter/card.php:1510, fichinter/card-rec.php:353, and ticket/card.php:1240. No admin UI write path is present in the payload.', 'Setting this to the number of seconds in a workday (e.g. 28800 for 8 hours) controls how time totals are broken into days versus hours in duration displays.', 'Integer number of seconds per workday (e.g. 28800 = 8 hours).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/time.php:518|read|$qtyhourtext = convertSecondToTime($timespent_data[''timespent''], ''all'', $conf->global->MAIN_DURATION_OF_WORKDAY);", "fichinter/card.php:1510|read|print ''<td>''.convertSecondToTime($object->duration, ''all'', $conf->global->MAIN_DURATION_OF_WORKDAY).'' (''.convertDurationtoHour($object->duration, \"s\").'' ''.$langs->trans(\"HourShort\"", "ticket/card.php:1240|read|print $foundinter ? convertSecondToTime($timing, ''all'', getDolGlobalInt(''MAIN_DURATION_OF_WORKDAY'')) : '''';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_DURATION_STEP', 'string', NULL, 'core', 'Sets the minute step increment used in duration/time-interval selectors.', 'Read as integer at core/class/html.form.class.php:8302 via getDolGlobalInt into $step, which controls the granularity of duration input selectors. Only one occurrence found.', 'Setting a larger step reduces the number of selectable minute values. Leaving it at 0 or unset applies the default step defined in the form code.', 'Integer representing minutes per step (e.g. 5, 15, 30); 0 or unset = code default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:8302|read|$step = getDolGlobalInt(''MAIN_DURATION_STEP'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EASTER_EGG_COMMITSTRIP', 'string', NULL, 'core', 'Enables a hidden easter egg feature (CommitStrip) on the login page.', 'Checked once at core/tpl/login.tpl.php:559. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant activates the CommitStrip easter egg display on the login page.', '0 (disabled) or any truthy value (enabled)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:559|check|if (getDolGlobalString(''MAIN_EASTER_EGG_COMMITSTRIP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ECM_DISABLE_JS', 'bool', NULL, 'core', 'Disables JavaScript-based AJAX interactions in the ECM (Electronic Content Management) file manager UI.', 'Checked in 14 locations across core/tpl/filemanager.tpl.php (lines 118, 183, 321, 404), core/ajax/ajaxdirtree.php:162, ecm/index_auto.php:446 and 559, and website/index.php:3078 to switch between AJAX-driven and static/manual-refresh file tree modes.', 'When set, the file manager falls back to static page refreshes and disables the AJAX directory tree; when unset, AJAX interactions are used when JavaScript is available.', 'Empty/unset = AJAX file manager enabled (if JS available); non-empty = AJAX disabled, static mode used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/filemanager.tpl.php:183|check|if ((!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_ECM_DISABLE_JS'')) || !empty($section)) {", "core/tpl/filemanager.tpl.php:321|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_ECM_DISABLE_JS'')) {", "core/ajax/ajaxdirtree.php:162|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_ECM_DISABLE_JS'')) {", "ecm/index_auto.php:559|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_ECM_DISABLE_JS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EDIT_LINE_ALLOW_ALL_UNIT_TYPE', 'bool', NULL, 'reception', 'When set, allows editing a line''s unit type to any unit regardless of the existing unit assignment.', 'Checked in reception/tpl/objectline_edit.tpl.php:142, core/tpl/objectline_edit.tpl.php:317, and expedition/tpl/objectline_edit.tpl.php:142. When absent and the line has an existing fk_unit, the unit selector is restricted.', 'Setting this constant allows users to freely change the unit type on existing document lines; without it, unit editing is restricted when a unit is already assigned.', 'Non-empty/truthy = allow any unit type selection; empty/unset = restrict unit editing (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/tpl/objectline_edit.tpl.php:142|check|if (!empty($line->fk_unit) && !getDolGlobalString(''MAIN_EDIT_LINE_ALLOW_ALL_UNIT_TYPE'')) {", "core/tpl/objectline_edit.tpl.php:317|check|if (!empty($line->fk_unit) && !getDolGlobalString(''MAIN_EDIT_LINE_ALLOW_ALL_UNIT_TYPE'')) {", "expedition/tpl/objectline_edit.tpl.php:142|check|if (!empty($line->fk_unit) && !getDolGlobalString(''MAIN_EDIT_LINE_ALLOW_ALL_UNIT_TYPE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAILCOLLECTOR_MAIL_WITHOUT_HEADER', 'string', NULL, 'emailcollector', 'Controls whether e-mail headers are hidden from messages collected by the email collector.', 'When set, the email collector skips header inclusion for collected messages, as checked at emailcollector/class/emailcollector.class.php:3182, :3476, and :3626. No admin UI write is present; this is a hidden option.', 'If enabled, collected e-mail messages will not include their headers in the stored content.', 'Hide e-mail headers from collected messages', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/emailcollector_list.php:796  // MAIN_EMAILCOLLECTOR_MAIL_WITHOUT_HEADER: Hide e-mail headers from collected messages", "emailcollector/class/emailcollector.class.php:3182|check|if (!getDolGlobalString(''MAIN_EMAILCOLLECTOR_MAIL_WITHOUT_HEADER'')) {", "emailcollector/class/emailcollector.class.php:3476|check|if (!getDolGlobalString(''MAIN_EMAILCOLLECTOR_MAIL_WITHOUT_HEADER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAILCOLLECTOR_TICKET_CATEGORY_CODE', 'string', NULL, 'emailcollector', 'Overrides the default ticket category code used when the email collector creates tickets from collected messages.', 'Used at emailcollector/class/emailcollector.class.php:3634 to set the category_code on tickets created by the collector, falling back to the dictionary default if not set. No admin UI write found.', 'If set, all tickets created by the email collector will use this category code instead of the dictionary default.', 'A ticket category code string; if unset, defaults to the code with use_default=1 in c_ticket_category.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:3634|read|$tickettocreate->category_code = (getDolGlobalString(''MAIN_EMAILCOLLECTOR_TICKET_CATEGORY_CODE'', dol_getIdFromCode($this->db, 1, ''c_ticket_category'', ''use_default'', ''code'', 1)));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAILCOLLECTOR_TICKET_SEVERITY_CODE', 'string', NULL, 'emailcollector', 'Overrides the default ticket severity code used when the email collector creates tickets from collected messages.', 'Used at emailcollector/class/emailcollector.class.php:3635 to set the severity_code on tickets created by the collector, falling back to the dictionary default if not set. No admin UI write found.', 'If set, all tickets created by the email collector will use this severity code instead of the dictionary default.', 'A ticket severity code string; if unset, defaults to the code with use_default=1 in c_ticket_severity.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:3635|read|$tickettocreate->severity_code = (getDolGlobalString(''MAIN_EMAILCOLLECTOR_TICKET_SEVERITY_CODE'', dol_getIdFromCode($this->db, 1, ''c_ticket_severity'', ''use_default'', ''code'', 1)));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAILCOLLECTOR_TICKET_TYPE_CODE', 'string', NULL, 'emailcollector', 'Overrides the default ticket type code used when the email collector creates tickets from collected messages.', 'Used at emailcollector/class/emailcollector.class.php:3633 to set the type_code on tickets created by the collector, falling back to the dictionary default if not set. No admin UI write found.', 'If set, all tickets created by the email collector will use this type code instead of the dictionary default.', 'A ticket type code string; if unset, defaults to the code with use_default=1 in c_ticket_type.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:3633|read|$tickettocreate->type_code = (getDolGlobalString(''MAIN_EMAILCOLLECTOR_TICKET_TYPE_CODE'', dol_getIdFromCode($this->db, 1, ''c_ticket_type'', ''use_default'', ''code'', 1)));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_COLLECTOR_ACCEPT_EMOJIS', 'string', NULL, 'emailcollector', 'Controls whether emoji characters are removed from collected email subjects and bodies.', 'In emailcollector/class/emailcollector.class.php at lines 2130, 2139, and 2178, the integer value (defaulting to 1 if unset) is passed to removeEmoji() for subject and body processing. No admin UI write path is present.', 'Setting to 1 (default) retains emojis in collected emails; setting to 0 strips emoji characters from subjects and message text.', 'Integer: passed to removeEmoji(); default 1 = keep emojis; 0 = remove emojis', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["emailcollector/class/emailcollector.class.php:2130|read|$overview[''subject''] = removeEmoji($overview[''subject''], getDolGlobalInt(''MAIN_EMAIL_COLLECTOR_ACCEPT_EMOJIS'', 1));", "emailcollector/class/emailcollector.class.php:2139|read|$overview[0]->subject = removeEmoji($overview[0]->subject, getDolGlobalInt(''MAIN_EMAIL_COLLECTOR_ACCEPT_EMOJIS'', 1));", "emailcollector/class/emailcollector.class.php:2178|read|$messagetext = removeEmoji($messagetext, getDolGlobalInt(''MAIN_EMAIL_COLLECTOR_ACCEPT_EMOJIS'', 1));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_DISABLE_ADD_CONTENT_ENCODING_8BIT', 'bool', NULL, 'core', 'Disables the automatic addition of a Content-Transfer-Encoding: 8bit header to outgoing emails.', 'When absent (negated check), the 8bit content encoding header is added at core/class/CMailFile.class.php:1738. Setting this constant prevents the header from being appended.', 'Setting this omits the 8-bit content encoding declaration, which may affect mail server compatibility; leaving it unset includes the header.', 'Any non-empty string value disables the 8bit encoding header.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1738|check|if (!getDolGlobalString(\"MAIN_EMAIL_DISABLE_ADD_CONTENT_ENCODING_8BIT\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_SUPPORT_ACK', 'string', NULL, 'core', 'Enables delivery receipt (acknowledgement) support in the email form when the delivery receipt option is requested.', 'Checked in core/class/html.formmail.class.php:892 only when $this->withdeliveryreceipt is non-empty. No admin UI write is present.', 'Enabling this activates delivery receipt headers when the mail form has the delivery-receipt option set; disabling it suppresses the receipt even when requested.', 'truthy/non-zero = enable delivery receipt support; 0/empty = disable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:892|check|if (!empty($this->withdeliveryreceipt) && getDolGlobalInt(''MAIN_EMAIL_SUPPORT_ACK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES', 'string', NULL, 'admin', 'Enables editing of email template content for document lines (line-level content_lines field) in the mailing templates admin.', 'Documented at admin/mails_templates.php:186 with the comment ''Set MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES to allow edit of template for lines''. Controls visibility of the content_lines field in cemailtemplate.class.php:64 and multiple display branches in admin/mails_templates.php.', 'Enabling this constant exposes the content_lines field for editing in email templates, allowing per-line content customisation; disabling it hides that field.', 'Any truthy value enables line-level template editing; unset or empty disables it.', 0, 0, 'admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails_templates.php:186  // Set MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES to allow edit of template for lines", "core/class/cemailtemplate.class.php:64|read|\"content_lines\" => array(\"type\" => \"text\", \"label\" => \"Contentlines\", \"enabled\" => \"getDolGlobalString(''MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES'')\", ''position'' => 80, ''notnull'' => 0,", "admin/mails_templates.php:188|check|if (!getDolGlobalString(''MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES'')) {", "admin/mails_templates.php:897|check|if (getDolGlobalString(''MAIN_EMAIL_TEMPLATES_FOR_OBJECT_LINES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_USECCC', 'string', NULL, 'core', 'Sets the default BCC (hidden copy) email address added to all outgoing emails.', 'Read in core/tpl/massactions_pre.tpl.php:306, core/tpl/card_presend.tpl.php:429, and comm/mailing/card.php:1353 to populate the withtoccc field of the mail form. The comment in core/class/html.formmail.class.php:1321 confirms the field is shown when this constant is set.', 'Setting this causes all email send forms to pre-populate the BCC field with the configured address, resulting in every outgoing email being silently copied.', 'Empty/not set = no BCC; email address string = that address is added as BCC', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.formmail.class.php:1321  * This information is show when MAIN_EMAIL_USECCC is set.", "core/tpl/massactions_pre.tpl.php:306|read|$formmail->withtoccc = getDolGlobalString(''MAIN_EMAIL_USECCC'');", "core/tpl/card_presend.tpl.php:429|read|$formmail->withtoccc = getDolGlobalString(''MAIN_EMAIL_USECCC'');", "comm/mailing/card.php:1353|read|$formmail->withtoccc = getDolGlobalString(''MAIN_EMAIL_USECCC'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EMAIL_USE_LAYOUT', 'bool', NULL, 'core', 'Enables the email layout selector in the mail form and mailing card.', 'Read in comm/mailing/card.php:1676 and core/class/html.formmail.class.php:1102. When set, the layout link/selector is shown alongside the rich-text editor.', 'Enabling this shows a layout chooser for outgoing emails; disabling it hides the layout option.', 'truthy/non-zero = show layout selector; 0/empty = hide layout selector', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:1676|read|$showlinktolayout = getDolGlobalInt(''MAIN_EMAIL_USE_LAYOUT'') ? ''emailing'' : '''';", "core/class/html.formmail.class.php:1102|read|$showlinktolayout = ($formmail->withfckeditor && getDolGlobalInt(''MAIN_EMAIL_USE_LAYOUT'')) ? $formmail->withlayout : '''';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_ACCENT_INSENSITIVE_SEARCH', 'bool', NULL, 'core', 'Enables accent-insensitive (and lowercase) search in AJAX combo-box lookups.', 'Checked in core/lib/ajax.lib.php:520 with an inline comment ''// lowercase + remove accents'', indicating the search normalizes input to ignore diacritics.', 'Enabling makes search fields match accented and non-accented characters interchangeably, improving search UX for languages with diacritics.', 'Truthy value to enable accent-insensitive search; absent or falsy to use default (accent-sensitive) search.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/ajax.lib.php:520|check|if (getDolGlobalString(''MAIN_ENABLE_ACCENT_INSENSITIVE_SEARCH'')) {\t// lowercase + remove accents"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_AJAX_TOOLTIP', 'bool', NULL, 'webportal', 'Enables AJAX-based tooltips on linked-object fields rendered via fetch calls rather than inline HTML.', 'When enabled, object fetch routines (e.g. in projet/class/project.class.php:1447, salaries/class/salary.class.php:658) switch to an AJAX tooltip path instead of inline rendering. The admin UI at admin/system/perf.php reads and displays the value (admin/system/perf.php:769).', 'Enabling this constant activates AJAX tooltips site-wide; disabling reverts to the default non-AJAX tooltip rendering.', 'Non-zero = AJAX tooltips enabled; 0 or unset = disabled.', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/perf.php:762|check|if (getDolGlobalInt(''MAIN_ENABLE_AJAX_TOOLTIP'')) {", "admin/system/perf.php:769|read|print yn(getDolGlobalInt(''MAIN_ENABLE_AJAX_TOOLTIP''));", "projet/class/project.class.php:1447|check|if (getDolGlobalInt(''MAIN_ENABLE_AJAX_TOOLTIP'')) {", "salaries/class/salary.class.php:658|check|if (getDolGlobalInt(''MAIN_ENABLE_AJAX_TOOLTIP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_DEFAULT_VALUES', 'string', '1', 'admin', 'Enables the default values feature, which pre-fills form fields with administrator-defined defaults.', 'Written (set to 1 or 0) via admin/defaultvalues.php:122-124. Checked in core/lib/functions.lib.php:1135 and user/class/user.class.php:841. Comment at core/lib/functions.lib.php:1125: ''Same if option MAIN_ENABLE_DEFAULT_VALUES is not set''. Also checked in admin/defaultvalues.php:219, 227, 369 to guard the management UI.', 'When enabled (non-empty), Dolibarr pre-fills eligible form fields with the configured defaults. When disabled, default value injection is skipped and the management UI blocks modifications.', '1 = enabled (default values active). 0 or empty = disabled.', 0, 0, 'admin/defaultvalues.php|admin/defaultvalues.php|admin/defaultvalues.php|admin/defaultvalues.php|admin/defaultvalues.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:1125  // If we did a click on a field to sort, we do no apply default values. Same if option MAIN_ENABLE_DEFAULT_VALUES is not set", "core/lib/functions.lib.php:1135|check|if (getDolGlobalString(''MAIN_ENABLE_DEFAULT_VALUES'')) {", "admin/defaultvalues.php:122|write|dolibarr_set_const($db, ''MAIN_ENABLE_DEFAULT_VALUES'', 1, ''chaine'', 0, '''', $conf->entity);", "admin/defaultvalues.php:219|check|if (!getDolGlobalString(''MAIN_ENABLE_DEFAULT_VALUES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_EXTERNALMODULES_COMMUNITY', 'bool', NULL, 'admin', 'Enables browsing and installing modules from the community (GitHub) repository in the module administration page.', 'The code comment states: ''MAIN_ENABLE_EXTERNALMODULES_COMMUNITY is 1 if we enabled the community modules'' (admin/modules.php:94). When set, GitHub-sourced modules are fetched (admin/remotestore/class/externalModules.class.php:406) and search includes the GitHub source (admin/modules.php:95).', 'Enabling activates community module discovery from GitHub. Disabling hides community modules from the module list.', '0 or unset = community modules not shown; 1 = community modules enabled', 0, 0, 'admin/modules.php|admin/modules.php|admin/remotestore/class/externalModules.class.php|admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:94  // MAIN_ENABLE_EXTERNALMODULES_COMMUNITY is 1 if we enabled the community modules", "admin/modules.php:95|read|$options[''search_source_github''] = getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_COMMUNITY'');", "admin/remotestore/class/externalModules.class.php:406|check|if (!empty($this->githubFileStatus) && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_COMMUNITY'')) {", "admin/modules.php:1392|check|if (!getDolGlobalString(''MAIN_DISABLE_EXTERNALMODULES_COMMUNITY'') && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_COMMUNITY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_EXTERNALMODULES_DOLISTORE', 'bool', NULL, 'admin', 'Enables browsing and installing modules from the Dolistore remote repository in the module administration page.', 'The code comment states: ''MAIN_ENABLE_EXTERNALMODULES_DOLISTORE is 1 if we enabled the dolistore modules'' (admin/modules.php:92). When set, the Dolistore API is queried (admin/remotestore/class/externalModules.class.php:389) and search results include Dolistore modules (admin/modules.php:93).', 'Enabling this constant activates Dolistore module browsing and installation. Disabling it (or leaving unset) hides Dolistore modules from the list.', '0 or unset = Dolistore modules not shown; 1 = Dolistore modules enabled', 0, 0, 'admin/modules.php|admin/modules.php|admin/remotestore/class/externalModules.class.php|admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:92  // MAIN_ENABLE_EXTERNALMODULES_DOLISTORE is 1 if we enabled the dolistore modules", "admin/modules.php:93|read|$options[''search_source_dolistore''] = getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_DOLISTORE'');", "admin/remotestore/class/externalModules.class.php:389|check|if ($this->dolistoreApiStatus > 0 && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_DOLISTORE'')) {", "admin/modules.php:1359|check|if (!getDolGlobalString(''MAIN_DISABLE_EXTERNALMODULES_DOLISTORE'') && getDolGlobalInt(''MAIN_ENABLE_EXTERNALMODULES_DOLISTORE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_FONT_ROBOTO', 'bool', NULL, 'core', 'Enables loading the Roboto web font for the UI.', 'Checked at main.inc.php:1864 to conditionally include the Roboto font resource in the page.', 'Enabling this loads the Roboto font; disabling or unsetting it skips the font load.', '0 or unset = Roboto font not loaded; 1 (truthy) = Roboto font loaded', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1864|check|if (getDolGlobalString(''MAIN_ENABLE_FONT_ROBOTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_IMPORT_LINKED_OBJECT_LINES', 'bool', NULL, 'mrp', 'Enables the ''Import lines from linked object'' button on document line sections.', 'Checked in 10 locations across linkedobjectblock templates (e.g. compta/facture/tpl/linkedobjectblock.tpl.php:76, mrp/tpl/linkedobjectblock.tpl.php:74, comm/propal/tpl/linkedobjectblock.tpl.php:66, reception/tpl/linkedobjectblock.tpl.php:70). The button is rendered only when both $showImportButton and this constant are truthy.', 'Enabling this constant activates an import button that allows copying line items from a linked source document into the current document.', 'Non-zero/non-empty = import lines button visible; 0 or unset = button hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/tpl/linkedobjectblock.tpl.php:76|check|if (!empty($showImportButton) && getDolGlobalString(''MAIN_ENABLE_IMPORT_LINKED_OBJECT_LINES'')) {", "mrp/tpl/linkedobjectblock.tpl.php:74|check|if (!empty($showImportButton) && getDolGlobalInt(''MAIN_ENABLE_IMPORT_LINKED_OBJECT_LINES'')) {", "comm/propal/tpl/linkedobjectblock.tpl.php:66|check|if (!empty($showImportButton) && getDolGlobalInt(''MAIN_ENABLE_IMPORT_LINKED_OBJECT_LINES'')) {", "reception/tpl/linkedobjectblock.tpl.php:70|check|<?php if (!empty($showImportButton) && getDolGlobalInt(''MAIN_ENABLE_IMPORT_LINKED_OBJECT_LINES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_LOGINS_PRIVACY', 'bool', NULL, 'user', 'Controls visibility of user login date information in user lists and profile pages.', 'Checked in user/card.php and user/list.php across 9 occurrences. When set to 0, last/previous login dates are shown in user lists and on card pages. When set to 1, only the current user can see their own login dates.', 'Setting to 0 exposes login date columns to all authorized viewers; setting to 1 restricts login date visibility so each user can only see their own.', '0 = login dates visible to all; 1 = login dates visible only to the user themselves.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/card.php:2174|check|if ((getDolGlobalInt(''MAIN_ENABLE_LOGINS_PRIVACY'') == 0) || (getDolGlobalInt(''MAIN_ENABLE_LOGINS_PRIVACY'') == 1 && $object->id == $user->id)) {", "user/list.php:1382|check|if (!empty($arrayfields[''u.datelastlogin''][''checked'']) && getDolGlobalInt(''MAIN_ENABLE_LOGINS_PRIVACY'') == 0) {", "user/list.php:162|check|if (getDolGlobalInt(''MAIN_ENABLE_LOGINS_PRIVACY'') == 0) {", "user/list.php:853|check|if (!empty($arrayfields[''u.datelastlogin''][''checked'']) && getDolGlobalInt(''MAIN_ENABLE_LOGINS_PRIVACY'') == 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_LOG_INLINE_HTML', 'bool', NULL, 'core', 'Enables inline HTML log rendering triggered by the ''log'' GET parameter; marked as deprecated in source comments.', 'Checked in core/lib/functions.lib.php:2845 with GETPOSTINT(''log''). A comment at line 2843 marks it as TODO for removal: ''MAIN_ENABLE_LOG_INLINE_HTML should be deprecated and use a log handler dedicated to HTML output''.', 'Setting this constant enables a legacy inline HTML log mechanism when the log parameter is passed. It should not be used in new deployments as it is flagged for deprecation.', 'Non-empty = inline HTML log active with ?log parameter; absent/empty = disabled. //TODO: Remove this. MAIN_ENABLE_LOG_INLINE_HTML should be deprecated and use a log handler dedicated to HTML output.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:2843  //TODO: Remove this. MAIN_ENABLE_LOG_INLINE_HTML should be deprecated and use a log handler dedicated to HTML output", "core/lib/functions.lib.php:2845|check|if (getDolGlobalString(''MAIN_ENABLE_LOG_INLINE_HTML'') && GETPOSTINT(\"log\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_LOG_TO_HTML', 'string', '0', 'core', 'Enables in-page HTML log output during install and upgrade procedures, and optionally during normal requests when the logtohtml request parameter is present.', 'Set to 1 during install/upgrade in install/step5.php:263, install/step5.php:464, install/inc.php:262, install/upgrade2.php:208, install/check.php:444, install/repair.php:328, install/upgrade2.php:317. Checked at core/lib/functions.lib.php:2834 with GETPOST(''logtohtml'').', 'When active, log messages are accumulated and rendered inline in the HTML page. This is enabled automatically during install/upgrade and can be triggered during normal operation via the logtohtml request parameter.', '1 = log to HTML output enabled; 0 or absent = disabled. Default: ''0''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["install/step5.php:263|write|$conf->global->MAIN_ENABLE_LOG_TO_HTML = 1;", "install/upgrade2.php:317|write|$conf->global->MAIN_ENABLE_LOG_TO_HTML = 1;\t\t// Add also log into conf->logbuffer.", "core/lib/functions.lib.php:2834|check|if ((!empty($_REQUEST[''logtohtml'']) && getDolGlobalString(''MAIN_ENABLE_LOG_TO_HTML''))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_MULTISELECT_TYPE', 'bool', NULL, 'core', 'Enables multi-select filtering by event type on the agenda calendar view.', 'Checked in admin/agenda_other.php:409 and core/lib/agenda.lib.php:98. The comment in agenda.lib.php notes: ''We use an option here because it adds bugs when used on agenda page "peruser" and "list"''. Configured via admin/agenda_other.php.', 'Enabling this constant allows users to filter the agenda by selecting multiple event types simultaneously; it is disabled by default due to known bugs on the ''peruser'' and ''list'' agenda views.', '1 = enable multi-select type filter; 0 or unset = disable.', 0, 0, 'admin/agenda_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/agenda.lib.php:98|check|if (getDolGlobalString(''MAIN_ENABLE_MULTISELECT_TYPE'')) {     // We use an option here because it adds bugs when used on agenda page \"peruser\" and \"list\"", "admin/agenda_other.php:409|check|if (getDolGlobalString(''MAIN_ENABLE_MULTISELECT_TYPE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_OVERWRITE_TRANSLATION', 'string', '1', 'admin', 'Enables the custom translation overwrite feature, allowing administrators to define per-entity translation overrides through the admin UI.', 'Configured via admin/translation.php (UI writes at lines 120 and 122). Checked at multiple points (lines 234, 241, 362, 366) to gate editing and display of custom translations. Also checked in core/class/translate.class.php:538 to apply overrides during translation loading.', 'When enabled (default ''1''), custom translation overrides can be managed via admin/translation.php and are applied at runtime. When disabled, overrides are not applied and the UI restricts editing.', '1 to enable overwrite translation (default); 0 to disable.', 0, 0, 'admin/translation.php|admin/translation.php|admin/translation.php|admin/translation.php|admin/translation.php|admin/translation.php|admin/translation.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/translation.php:120|write|dolibarr_set_const($db, ''MAIN_ENABLE_OVERWRITE_TRANSLATION'', 1, ''chaine'', 0, '''', $conf->entity);", "admin/translation.php:122|write|dolibarr_set_const($db, ''MAIN_ENABLE_OVERWRITE_TRANSLATION'', 0, ''chaine'', 0, '''', $conf->entity);", "core/class/translate.class.php:538|check|if (!$found && getDolGlobalString(''MAIN_ENABLE_OVERWRITE_TRANSLATION'')) {", "admin/translation.php:234|check|if (!getDolGlobalString(''MAIN_ENABLE_OVERWRITE_TRANSLATION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ENABLE_PRODUCTS_CONTACTS_TAB', 'bool', NULL, 'core', 'Enables a Contacts tab on product/service pages.', 'Checked in core/lib/product.lib.php:175. When set, a contacts tab is added to the product/service navigation.', 'Setting this constant adds a Contacts tab to product/service pages; clearing it removes the tab.', 'Any non-empty value = show Contacts tab on products/services; empty/unset = no tab', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolGlobalString(''MAIN_ENABLE_PRODUCTS_CONTACTS_TAB'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXEC_USE_POPEN', 'bool', NULL, 'admin', 'Selects the PHP execution method used for shell commands: popen (method 2) instead of exec (method 1).', 'Configurable via admin/system/security.php. Read in admin/system/security.php line 67 (defaulting to 1), described in line 234 as ''exec or popen can be used depending on MAIN_EXEC_USE_POPEN option''. Used in includes/odtphp/odf.php line 888 (''1 or 2''), core/class/utils.class.php line 441, and admin/tools/dolibarr_export.php line 301.', 'Enabling this constant switches shell execution from exec() to popen(), which is required on some server configurations where exec() is disabled. The admin security page documents the current setting.', '1 = popen used; 0 or absent = exec used. From odf.php:888: $execmethod = (getDolGlobalString(''MAIN_EXEC_USE_POPEN'') ? 2 : 1); // 1 or 2.', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/tools/dolibarr_export.php|admin/tools/dolibarr_export.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/security.php:234|read|print ''<span class=\"opacitymedium\" title=\"exec or popen can be used depending on MAIN_EXEC_USE_POPEN option, currently to ''.getDolGlobalInt(''MAIN_EXEC_USE_POPEN'').''\">''", "includes/odtphp/odf.php:888|read|$execmethod = (getDolGlobalString(''MAIN_EXEC_USE_POPEN'') ? 2 : 1);\t// 1 or 2", "admin/tools/dolibarr_export.php:301|check|if (getDolGlobalString(''MAIN_EXEC_USE_POPEN'')) {", "admin/system/security.php:67|read|$execmethod = getDolGlobalInt(''MAIN_EXEC_USE_POPEN'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXPENSEREPORT_COMBINE_GRAPH_STAT', 'string', NULL, 'expensereport', 'Sets the combine threshold for the expense report statistics graph; defaults to 0.05 when unset.', 'Read at expensereport/index.php:175; when unset or empty the graph''s combine property is set to 0.05, otherwise it is set to the constant''s value.', 'Changing this value alters how small slices are grouped in the expense report statistics graph; the default combine threshold is 0.05.', 'Empty/unset = 0.05 (default combine threshold); a numeric float string = use that threshold.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/index.php:175|read|$dolgraph->combine = !getDolGlobalString(''MAIN_EXPENSEREPORT_COMBINE_GRAPH_STAT'') ? 0.05 : $conf->global->MAIN_EXPENSEREPORT_COMBINE_GRAPH_STAT;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXPENSE_APPLY_ENTIRE_OFFSET', 'string', NULL, 'expensereport', 'Controls whether the entire offset amount is applied during expense report calculation.', 'Checked at expensereport/class/expensereport.class.php:2178; when set, an alternative offset-application code path is taken.', 'Enabling this constant changes how offsets are applied in expense calculations; disabling it uses the default partial-offset behavior.', 'Empty/unset = default offset behavior; any truthy value = entire offset applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/class/expensereport.class.php:2178|check|if (getDolGlobalString(''MAIN_EXPENSE_APPLY_ENTIRE_OFFSET'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTERNAL_MAIL_SPF_STRING_TO_ADD', 'string', NULL, 'admin', 'Stores an SPF record string to display as a recommendation when using PHP mail() sending mode.', 'When set, admin/mails.php displays the SPF string as a warning or informational notice to administrators. The inline comment states it is not defined by default and depends on the platform. Only one occurrence is present in the payload.', 'Setting this value causes an SPF recommendation string to appear in the mail configuration admin page; leaving it unset suppresses that notice.', 'Any SPF record string; not defined by default.', 0, 0, 'admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails.php:1060|check|if (getDolGlobalString(''MAIN_EXTERNAL_MAIL_SPF_STRING_TO_ADD'')) {\t// Not defined by default. Depend on platform."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS', 'string', NULL, 'admin', 'Stores the list of IP addresses from which emails are sent, used for display and SPF diagnostics in the mail admin page.', 'Holds a comma-separated list of IP addresses (or a URL) representing the server''s outgoing mail IPs. The comment states: ''MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS is list of IPs where email is sent from. Example: 1.2.3.4, [aaaa:bbbb:cccc:dddd].'' A second comment notes it can also be a URL to dynamically detect the public IP. Configured via admin/mails.php.', 'When set, admin/mails.php explodes the value by comma and displays each IP; changing or clearing it affects which IPs are shown in the SPF diagnostic section.', 'Comma-separated IP addresses, e.g. ''1.2.3.4, [aaaa:bbbb:cccc:dddd]''; or a URL for dynamic detection. Not defined by default.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS is list of IPs where email is sent from. Example: ''1.2.3.4, [aaaa:bbbb:cccc:dddd]''.", "// If MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS is an URL to get/show the public IP/name of server detected dynamically", "admin/mails.php:1079|read|$arrayipstoshow = explode('','', getDolGlobalString(''MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS''));", "admin/mails.php:1076|check|if (getDolGlobalString(''MAIN_EXTERNAL_SMTP_CLIENT_IP_ADDRESS'')) {\t// Not defined by default. Depend on platform."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTERNAL_SMTP_SPF_STRING_TO_ADD', 'string', NULL, 'admin', 'Stores the SPF string to include in a warning shown to users when a preset SMTP server requires SPF record updates.', 'When set, admin/mails.php displays a warning (using the ''WarningPHPMailSPF'' translation key) containing this value. The inline comment states: ''Should be required only if you have preset the Dolibarr to use your own SMTP and you want to warn users to update their SPF record.'' Two occurrences in admin/mails.php.', 'Setting this value triggers an SPF update warning in the mail admin UI; clearing it suppresses that warning.', 'Any SPF record string; not defined by default.', 0, 0, 'admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails.php:1072|check|if (getDolGlobalString(''MAIN_EXTERNAL_SMTP_SPF_STRING_TO_ADD'')) {\t// Should be required only if you have preset the Dolibarr to use your own SMTP and you want to warn users to upda", "admin/mails.php:1074|read|$text .= $langs->trans(\"WarningPHPMailSPF\", getDolGlobalString(''MAIN_EXTERNAL_SMTP_SPF_STRING_TO_ADD''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_CODE_AUTOFILL_DISABLED', 'bool', NULL, 'core', 'Disables automatic code autofill in the extra-fields administration form.', 'Checked as an integer in core/tpl/admin_extrafields_add.tpl.php:164 to conditionally render the autofill UI block.', 'Setting this to 1 prevents the extra-fields admin form from auto-populating the code field, requiring manual entry.', '0 or not set = autofill enabled; 1 = autofill disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/admin_extrafields_add.tpl.php:164|check|<?php if (!getDolGlobalInt(''MAIN_EXTRAFIELDS_CODE_AUTOFILL_DISABLED'')) : ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_DISABLED', 'bool', NULL, 'comm', 'Globally disables extra fields (custom attributes) processing across all modules.', 'When set, extra field processing is skipped in reception, expedition, mailing, and other modules across at least 14 occurrences in multiple files. Checked in reception/class/reception.class.php:1021, comm/mailing/class/advtargetemailing.class.php:614, and expedition/class/expedition.class.php:1352 among others.', 'Enabling this constant prevents extra fields from being saved or displayed throughout Dolibarr, effectively disabling all custom attribute functionality.', '0 or unset = extra fields enabled; non-empty = extra fields disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/class/reception.class.php:1021|check|if (!getDolGlobalInt(''MAIN_EXTRAFIELDS_DISABLED'') && is_array($array_options) && count($array_options) > 0) {", "comm/mailing/class/advtargetemailing.class.php:614|check|if (!getDolGlobalString(''MAIN_EXTRAFIELDS_DISABLED'')) {", "expedition/class/expedition.class.php:1352|check|if (!getDolGlobalString(''MAIN_EXTRAFIELDS_DISABLED'') && is_array($array_options) && count($array_options) > 0) { // For avoid conflicts if trigger used"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_DISABLE_SELECT2', 'bool', NULL, 'core', 'Disables the Select2 JavaScript widget for extra-field dropdowns and multi-selects.', 'Checked across 11+ occurrences in commonobject.class.php, extrafields.class.php, and field-type classes. When set, Select2 is not applied to multi-select extrafield inputs even when JavaScript/Ajax is enabled.', 'Setting this constant causes extrafield selects to render as plain HTML selects instead of enhanced Select2 widgets.', 'Non-empty = Select2 disabled; empty or unset = Select2 enabled (when Ajax is active)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:8087|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_EXTRAFIELDS_DISABLE_SELECT2'')) {", "core/class/extrafields.class.php:1435|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_EXTRAFIELDS_DISABLE_SELECT2'')) {", "core/class/commonobject.class.php:8120|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_EXTRAFIELDS_DISABLE_SELECT2'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_ENABLE_NEW_SELECT2', 'bool', NULL, 'core', 'Enables the Select2 JavaScript widget for extra field dropdowns (sellist type) instead of the standard HTML select.', 'Checked at core/class/extrafields.class.php:1468 and :1501 and at core/class/fields/sellistfield.class.php:93 (requires use_javascript_ajax). No admin UI; hidden setting.', 'Enabling this activates Select2 for extra field list selectors, providing search and enhanced UI. Disabling reverts to native HTML select elements.', '0 or empty = native HTML select for extra fields; non-empty = Select2 widget enabled for sellist extra fields', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/extrafields.class.php:1468|check|if (getDolGlobalString(''MAIN_EXTRAFIELDS_ENABLE_NEW_SELECT2'')) {", "core/class/extrafields.class.php:1501|check|if (!getDolGlobalString(''MAIN_EXTRAFIELDS_ENABLE_NEW_SELECT2'')) {", "core/class/fields/sellistfield.class.php:93|check|if (!empty($conf->use_javascript_ajax) && getDolGlobalString(''MAIN_EXTRAFIELDS_ENABLE_NEW_SELECT2'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_LIMIT_SELLIST_SQL', 'string', NULL, 'core', 'Sets the SQL LIMIT applied to extrafield select-list (sellist) queries.', 'Used in core/class/commonobject.class.php:8260, core/class/extrafields.class.php:1678, and core/class/fields/commonsellistfield.class.php:316 to cap the number of rows returned in sellist dropdown queries. Defaults to 1000.', 'Lowering the limit reduces the number of options shown in sellist extrafield dropdowns; raising it allows more results at the cost of potentially larger queries.', 'Integer (default: 1000)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:8260|read|$sql .= '' LIMIT '' . getDolGlobalInt(''MAIN_EXTRAFIELDS_LIMIT_SELLIST_SQL'', 1000);", "core/class/extrafields.class.php:1678|read|$sql .= '' LIMIT '' . getDolGlobalInt(''MAIN_EXTRAFIELDS_LIMIT_SELLIST_SQL'', 1000);", "core/class/fields/commonsellistfield.class.php:316|read|$limit = getDolGlobalInt(''MAIN_EXTRAFIELDS_LIMIT_SELLIST_SQL'', $fieldInfos->optionsSqlLimit ?? 1000);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRAFIELDS_USE_TWO_COLUMS', 'bool', NULL, 'core', 'Enables a two-column layout for extrafields display on object cards.', 'Checked in core/class/commonobject.class.php:9677; when set, extrafields are rendered in a two-column grid based on the field index parity.', 'Setting this constant switches extrafield rendering from a single-column to a two-column layout.', 'Non-empty = two-column layout; empty or unset = single-column layout', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:9677|check|if (getDolGlobalString(''MAIN_EXTRAFIELDS_USE_TWO_COLUMS'') && ($e % 2) == 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_EXTRALANGUAGES_DISABLED', 'bool', NULL, 'core', 'Disables the extra languages (multi-language field values) feature across the application.', 'Checked in core/class/commonobject.class.php at lines 7298 and 7758 to skip extra-language processing, and in societe/class/societe.class.php:1881 to skip the trigger that saves extra-language values. No admin UI write found; HIDDEN_GUESS is 1.', 'When enabled, extra-language field values are not loaded, saved, or processed, preventing conflicts if the feature causes issues with certain triggers.', 'Any non-empty value = feature disabled; empty = extra languages enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:7758|check|if (getDolGlobalString(''MAIN_EXTRALANGUAGES_DISABLED'')) {", "core/class/commonobject.class.php:7298|check|if (getDolGlobalString(''MAIN_EXTRALANGUAGES_DISABLED'')) {", "societe/class/societe.class.php:1881|check|if (!$error && !getDolGlobalString(''MAIN_EXTRALANGUAGES_DISABLED'')) { // For avoid conflicts if trigger used"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FAVICON_URL', 'string', NULL, 'core', 'Specifies a custom URL for the browser favicon, overriding the default Dolibarr favicon.', 'Checked and read in both main.inc.php:1729-1730 and core/lib/security2.lib.php:301-302 to set the $favicon variable used when rendering the HTML head.', 'Setting this replaces the default favicon with the URL provided; unsetting it reverts to the default Dolibarr favicon.', 'Any valid URL string pointing to a favicon image; empty/unset = default Dolibarr favicon is used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1729|check|if (getDolGlobalString(''MAIN_FAVICON_URL'')) {", "main.inc.php:1730|read|$favicon = getDolGlobalString(''MAIN_FAVICON_URL'');", "core/lib/security2.lib.php:302|read|$favicon = getDolGlobalString(''MAIN_FAVICON_URL'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FEATUREES_LEVEL', 'string', NULL, 'core', 'Controls the feature level displayed in extra-fields help tooltips within the admin UI.', 'Read in core/tpl/admin_extrafields_add.tpl.php:208-209 and core/tpl/admin_extrafields_edit.tpl.php:279-280, used to build tooltip content for sellist and chkbxlst extra-field types.', 'Changing this value alters the help content presented in extra-field parameter tooltips in the admin interface.', 'String value controlling which feature-level help text is shown; exact enumeration not documented in payload', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/admin_extrafields_add.tpl.php:208|read|<span id=\"helpsellist\" class=\"spanforparamtooltip\"><?php print $form->textwithpicto('''', $langs->trans(\"ExtrafieldParamHelpsellist\").''<br>''.$langs->trans(\"ExtrafieldParamHelpsellist", "core/tpl/admin_extrafields_edit.tpl.php:279|read|<span id=\"helpsellist\" class=\"spanforparamtooltip\"><?php print $form->textwithpicto('''', $langs->trans(\"ExtrafieldParamHelpsellist\").''<br>''.$langs->trans(\"ExtrafieldParamHelpsellist"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FEATURES_LEVEL', 'string', '0', 'admin', 'Controls which experimental and development features are visible in the Dolibarr UI (0=stable only, 1=experimental, 2=development).', 'Checked in 275+ locations across the codebase. Comments in takepos/admin/setup.php:472-473 state: ''if ($module->version == ''development'' && $conf->global->MAIN_FEATURES_LEVEL < 2) continue'' and ''if ($module->version == ''experimental'' && $conf->global->MAIN_FEATURES_LEVEL < 1) continue''. comm/mailing/advtargetemailing.php:24 states ''Visible when MAIN_FEATURES_LEVEL is 1''. Configurable via multiple admin pages.', 'Setting to 1 exposes experimental features; setting to 2 also exposes development-level features. Setting to 0 (default) limits the UI to stable features only.', '0 = stable features only (default); 1 = stable + experimental features visible; 2 = stable + experimental + development features visible.', 0, 0, 'projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/subaccount.php|accountancy/admin/index.php|accountancy/admin/index.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|blockedlog/admin/blockedlog_list.php|recruitment/admin/setup_candidatures.php|recruitment/admin/setup_candidatures.php|recruitment/admin/setup_candidatures.php|recruitme