|admin/propal.php|admin/modulehelp.php|admin/modulehelp.php|admin/modulehelp.php|admin/hrm.php|admin/hrm.php|admin/hrm.php|admin/hrm.php|admin/workflow.php|admin/workflow.php|admin/pdf_other.php|admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/holiday.php|admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php|admin/supplier_proposal.php|admin/supplier_proposal.php|admin/supplier_proposal.php|admin/supplier_proposal.php|admin/contract.php|admin/contract.php|admin/contract.php|admin/contract.php|admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php|admin/chequereceipts.php|admin/chequereceipts.php|admin/expedition.php|admin/expedition.php|admin/expedition.php|admin/expedition.php|admin/supplier_invoice.php|admin/supplier_invoice.php|admin/stock.php|admin/stock.php|admin/translation.php|admin/order.php|admin/order.php|admin/order.php|admin/order.php|admin/fichinter.php|admin/fichinter.php|admin/fichinter.php|admin/fichinter.php|admin/barcode.php|admin/barcode.php|admin/stocktransfer.php|admin/stocktransfer.php|admin/stocktransfer.php|admin/stocktransfer.php|admin/knowledgemanagement.php|admin/knowledgemanagement.php|admin/knowledgemanagement.php|admin/knowledgemanagement.php|admin/taxes.php|admin/usergroup.php|admin/usergroup.php|admin/mrp.php|admin/mrp.php|admin/mrp.php|admin/mrp.php|admin/dict.php|admin/multicurrency.php|admin/invoice.php|admin/invoice.php|admin/invoice.php|admin/invoice.php|admin/invoice.php|admin/security.php|admin/security.php|takepos/admin/setup.php|takepos/admin/setup.php|takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/setup.php|takepos/admin/setup.php|admin/prelevement.php|admin/prelevement.php|admin/paymentbybanktransfer.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/setup.php:472  //  if ($module->version == ''development'' && $conf->global->MAIN_FEATURES_LEVEL < 2) continue;", "takepos/admin/setup.php:473  //  if ($module->version == ''experimental'' && $conf->global->MAIN_FEATURES_LEVEL < 1) continue;", "comm/mailing/advtargetemailing.php:24  *       \\brief     Page to define emailing targets. Visible when MAIN_FEATURES_LEVEL is 1.", "projet/admin/project.php:348|check|if ($module->version == ''development'' && getDolGlobalInt(''MAIN_FEATURES_LEVEL'') < 2) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FEATURE_TO_SHOW_TOP_MENU_URL_IN_FRAME', 'bool', NULL, 'admin', 'Enables experimental support for rendering top-menu URLs in an iframe within the admin menu editor.', 'Checked at admin/menus/edit.php:416 and :550 (where it is also combined with a check that the menu type is ''top''). A reference also exists in core/class/conf.class.php:1022.', 'Enabling this constant activates the iframe rendering path for top-menu URLs in the menu editor; disabling it keeps the standard link behavior.', 'Empty/unset = iframe rendering disabled; any truthy value = top-menu URLs rendered in frame.', 0, 0, 'admin/menus/edit.php|admin/menus/edit.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/menus/edit.php:416|check|if (getDolGlobalString(\"MAIN_FEATURE_TO_SHOW_TOP_MENU_URL_IN_FRAME\")) {", "admin/menus/edit.php:550|check|if (getDolGlobalString(\"MAIN_FEATURE_TO_SHOW_TOP_MENU_URL_IN_FRAME\") && $menu->type == ''top'') {", "core/class/conf.class.php:1022  // MAIN_FEATURE_TO_SHOW_TOP_MENU_URL_IN_FRAME"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FICHINTER_EXPORT_CACHE', 'string', NULL, 'admin', 'Sets the cache duration in seconds for the public fichinter iCal/vCal export feed.', 'Written in admin/fichinter_xcal.php:81, read and applied as cache delay at public/fichinter/agendaexport.php:250-251.', 'Setting a non-zero value enables HTTP caching of the calendar export for the specified duration. Leaving empty or zero disables export caching.', '0 or empty = no cache; positive integer = cache duration in seconds for the calendar export', 0, 0, 'admin/fichinter_xcal.php|admin/fichinter_xcal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fichinter_xcal.php:81|write|$i += dolibarr_set_const($db, ''MAIN_FICHINTER_EXPORT_CACHE'', $MAIN_FICHINTER_EXPORT_CACHE, ''chaine'', 0, '''', $conf->entity);", "public/fichinter/agendaexport.php:250|check|if (getDolGlobalString(''MAIN_FICHINTER_EXPORT_CACHE'')) {", "public/fichinter/agendaexport.php:251|read|$cachedelay = getDolGlobalString(''MAIN_FICHINTER_EXPORT_CACHE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FICHINTER_EXPORT_FIX_TZ', 'string', NULL, 'public', 'Applies a fixed timezone offset (in hours) to all dates exported in the fichinter iCal/vCal feed.', 'Written in admin/fichinter_xcal.php:82; applied as a subtraction in hours at public/fichinter/agendaexport.php:584 and :630-631 for start, created, and modified dates. The comment at :588 confirms the pattern: ''// $dateend = $db->jdate($obj->datee) - ((int) getDolGlobalString(''MAIN_FICHINTER_EXPORT_FIX_TZ'', 0) * 3600);''.', 'Setting an integer value shifts all exported event timestamps by that many hours. A value of 0 or empty applies no offset.', '0 or empty = no timezone correction; integer (positive or negative) = number of hours to subtract from exported event timestamps', 0, 0, 'admin/fichinter_xcal.php|admin/fichinter_xcal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/fichinter/agendaexport.php:588  // \t$dateend = $db->jdate($obj->datee) - ((int) getDolGlobalString(''MAIN_FICHINTER_EXPORT_FIX_TZ'', 0) * 3600);", "public/fichinter/agendaexport.php:584|read|$datestart = $db->jdate($obj->date) - ((int) getDolGlobalString(''MAIN_FICHINTER_EXPORT_FIX_TZ'', 0) * 3600);", "public/fichinter/agendaexport.php:630|read|$event[''created''] = $db->jdate($obj->datec) - ((int) getDolGlobalString(''MAIN_FICHINTER_EXPORT_FIX_TZ'', 0) * 3600);", "admin/fichinter_xcal.php:82|write|$i += dolibarr_set_const($db, ''MAIN_FICHINTER_EXPORT_FIX_TZ'', $MAIN_FICHINTER_EXPORT_FIX_TZ, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FICHINTER_EXPORT_PAST_DELAY', 'string', NULL, 'admin', 'Sets the maximum age in days of interventions included in the public iCal/vCal export feed, defaulting to 100 days.', 'Written in admin/fichinter_xcal.php:80 and defaulted to 100 at :100 and public/fichinter/agendaexport.php:81; used at agendaexport.php:120 as the ''notolderthan'' filter. The comment at admin/fichinter_xcal.php:243 shows: ''// $defaultnotolderthan = getDolGlobalString(''MAIN_FICHINTER_EXPORT_PAST_DELAY'', 100);''.', 'Increasing the value includes older interventions in the calendar feed; decreasing it limits the feed to more recent entries. Default is 100 days when not set.', 'Integer number of days; empty or 0 triggers default of 100 days', 0, 0, 'admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fichinter_xcal.php:243  // $defaultnotolderthan = getDolGlobalString(''MAIN_FICHINTER_EXPORT_PAST_DELAY'', 100);", "admin/fichinter_xcal.php:100|write|$conf->global->MAIN_FICHINTER_EXPORT_PAST_DELAY = 100;", "public/fichinter/agendaexport.php:120|read|$filters[''notolderthan''] = getDolGlobalString(''MAIN_FICHINTER_EXPORT_PAST_DELAY'', 100);", "public/fichinter/agendaexport.php:81|write|$conf->global->MAIN_FICHINTER_EXPORT_PAST_DELAY = 100; // default limit"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FICHINTER_XCAL_EXPORTKEY', 'string', NULL, 'admin', 'Defines the secret export key required to access the public iCal/vCal feed for interventions (fichinter).', 'Written and read extensively in admin/fichinter_xcal.php (19 occurrences); the key is embedded in the public export URL as the ''exportkey'' parameter used to authenticate access to agendaexport.php.', 'Changing this key invalidates existing calendar subscription URLs. Leaving it empty prevents authenticated access to the public calendar feed.', 'Empty = key not defined (export URL shows placeholder ''...''); any string = the secret key embedded in the public export URL', 0, 0, 'admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php|admin/fichinter_xcal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fichinter_xcal.php:79|write|$i += dolibarr_set_const($db, ''MAIN_FICHINTER_XCAL_EXPORTKEY'', $MAIN_FICHINTER_XCAL_EXPORTKEY, ''chaine'', 0, '''', $conf->entity);", "admin/fichinter_xcal.php:198|read|$urlvcal = ''<a href=\"''.$urlwithroot.''/public/fichinter/agendaexport.php?format=vcal''.$getentity.''&exportkey=''.urlencode(getDolGlobalString(''MAIN_FICHINTER_XCAL_EXPORTKEY'', ''...''))", "admin/fichinter_xcal.php:203|check|if (getDolGlobalString(''MAIN_FICHINTER_XCAL_EXPORTKEY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIELDS_NEW_OBJECT_KEY_PREFIX', 'string', NULL, 'core', 'Adds the ''object_'' prefix to new-object key names in the fields manager.', 'Read at core/class/fieldsmanager.class.php lines 389 and 460; the key prefix is set to ''object_'' when this constant is truthy, or to '''' (empty string) otherwise.', 'Enabling this constant causes new object keys in the fields manager to be prefixed with ''object_''. Disabling it uses no prefix.', 'Integer/bool; 0 or absent = no prefix (empty string); non-zero = ''object_'' prefix applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/fieldsmanager.class.php:389|read|$keyPrefix = getDolGlobalInt(''MAIN_FIELDS_NEW_OBJECT_KEY_PREFIX'') ? ''object_'' : '''';", "core/class/fieldsmanager.class.php:460|read|$patternObjectPrefix = getDolGlobalInt(''MAIN_FIELDS_NEW_OBJECT_KEY_PREFIX'') ? ''object_'' : '''';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIELDS_SORT_WITH_EXTRA_FIELDS', 'string', NULL, 'core', 'Controls whether extra fields are included when sorting the fields manager field list.', 'Checked at core/class/fieldsmanager.class.php lines 301 (negated: sort without extra fields) and 310 (affirmative: sort with extra fields); the sorting path branches on the value of this constant.', 'Enabling this constant includes extra fields in the sort order of the fields manager. Disabling it sorts only core fields.', 'Integer/bool; 0 or absent = extra fields excluded from sort; non-zero = extra fields included in sort.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/fieldsmanager.class.php:301|check|if (!getDolGlobalInt(''MAIN_FIELDS_SORT_WITH_EXTRA_FIELDS'')) {", "core/class/fieldsmanager.class.php:310|check|if (getDolGlobalInt(''MAIN_FIELDS_SORT_WITH_EXTRA_FIELDS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILECHECK_LOCAL_EXT', 'string', NULL, 'api', 'Specifies an additional extension appended after ''.xml'' in the local file integrity check XML filename.', 'Read at blockedlog/admin/filecheck.php:141 and api/class/api_setup.class.php:2874 to construct the XML filename: ''filelist-''+DOL_VERSION+getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'')+''.xml''+getDolGlobalString(''MAIN_FILECHECK_LOCAL_EXT''). Admin UI present via blockedlog/admin/filecheck.php.', 'Setting this value appends a custom extension after ''.xml'' in the integrity check file name, enabling use of compressed or variant formats.', 'Empty/not set = filename ends with ''.xml''; string = extension appended after ''.xml'' (e.g. ''.gz'' for compressed files).', 0, 0, 'blockedlog/admin/filecheck.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/filecheck.php:141|read|$xmlshortfile = dol_sanitizeFileName(GETPOST(''xmlshortfile'', ''alpha'') ? GETPOST(''xmlshortfile'', ''alpha'') : ''filelist-''.DOL_VERSION.getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'')", "api/class/api_setup.class.php:2874|read|$xmlshortfile = dol_sanitizeFileName(''filelist-''.DOL_VERSION.getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'').''.xml''.getDolGlobalString(''MAIN_FILECHECK_LOCAL_EXT''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILECHECK_LOCAL_SUFFIX', 'string', NULL, 'api', 'Specifies a suffix appended to the local file integrity check XML filename.', 'Read at blockedlog/admin/filecheck.php:141 and api/class/api_setup.class.php:2874 to construct the XML filename: ''filelist-''+DOL_VERSION+getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'')+''.xml''+getDolGlobalString(''MAIN_FILECHECK_LOCAL_EXT''). Admin UI present via blockedlog/admin/filecheck.php.', 'Setting this value appends a custom suffix to the integrity check XML file name, allowing use of customized or locally-named file lists.', 'Empty/not set = no suffix added to XML filename; string = suffix appended between version and ''.xml'' extension.', 0, 0, 'blockedlog/admin/filecheck.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/filecheck.php:141|read|$xmlshortfile = dol_sanitizeFileName(GETPOST(''xmlshortfile'', ''alpha'') ? GETPOST(''xmlshortfile'', ''alpha'') : ''filelist-''.DOL_VERSION.getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'')", "api/class/api_setup.class.php:2874|read|$xmlshortfile = dol_sanitizeFileName(''filelist-''.DOL_VERSION.getDolGlobalString(''MAIN_FILECHECK_LOCAL_SUFFIX'').''.xml''.getDolGlobalString(''MAIN_FILECHECK_LOCAL_EXT''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILECHECK_URL', 'string', NULL, 'api', 'Specifies a custom remote URL for fetching the file integrity check XML manifest.', 'Checked at blockedlog/admin/filecheck.php:150 and api/class/api_setup.class.php:2883: ''if (empty($xmlremote) && getDolGlobalString(''MAIN_FILECHECK_URL''))'' followed by ''$xmlremote = getDolGlobalString(''MAIN_FILECHECK_URL'')''. Admin UI present via blockedlog/admin/filecheck.php.', 'When set, the integrity check uses the specified URL to fetch the remote XML manifest instead of the default Dolibarr URL.', 'Empty/not set = default remote manifest URL used; URL string = custom remote URL for the integrity check XML file.', 0, 0, 'blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["blockedlog/admin/filecheck.php:150|check|if (empty($xmlremote) && getDolGlobalString(''MAIN_FILECHECK_URL'')) {", "blockedlog/admin/filecheck.php:151|read|$xmlremote = getDolGlobalString(''MAIN_FILECHECK_URL'');", "api/class/api_setup.class.php:2883|check|if (empty($xmlremote) && getDolGlobalString(''MAIN_FILECHECK_URL'')) {", "api/class/api_setup.class.php:2884|read|$xmlremote = getDolGlobalString(''MAIN_FILECHECK_URL'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILESYSTEM_ENCODING', 'string', NULL, 'core', 'Specifies the filesystem character encoding used when reading or writing files.', 'Checked and read at core/lib/functions.lib.php:11812-11813, and also at admin/system/dolibarr.php:370-371. When set, its value is used to handle filename encoding conversions for filesystem operations.', 'Setting an incorrect encoding value will cause file path encoding errors; leaving it unset uses the system default encoding.', 'Any valid encoding identifier string (e.g. ''UTF-8'', ''ISO-8859-1''); empty/unset = system default used', 0, 0, 'admin/system/dolibarr.php|admin/system/dolibarr.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/dolibarr.php:370|check|if (getDolGlobalString(''MAIN_FILESYSTEM_ENCODING'')) {", "admin/system/dolibarr.php:371|read|$tmp = getDolGlobalString(''MAIN_FILESYSTEM_ENCODING'');", "core/lib/functions.lib.php:11812|check|if (getDolGlobalString(''MAIN_FILESYSTEM_ENCODING'')) {", "core/lib/functions.lib.php:11813|read|$tmp = getDolGlobalString(''MAIN_FILESYSTEM_ENCODING'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILE_EXTENSION_UPLOAD_RESTRICTION', 'string', NULL, 'admin', 'Comma-separated list of file extensions that are forbidden from being uploaded.', 'Written via admin/security_file.php:106 and read in core/lib/files.lib.php:2078 as $fileextensionrestriction with fallback to implode('','', getExecutableContent()). Displayed in admin/system/security.php:632 as an explode/implode of the value.', 'Setting this constant restricts uploads to exclude the listed extensions. If unset, the fallback uses the result of getExecutableContent() (a built-in list of dangerous extensions).', 'Comma-separated string of file extensions (e.g. ''php,exe,sh''). Empty/unset = falls back to getExecutableContent() list.', 0, 0, 'admin/security_file.php|admin/system/security.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/files.lib.php:2078|read|$fileextensionrestriction = getDolGlobalString(\"MAIN_FILE_EXTENSION_UPLOAD_RESTRICTION\", implode('','', getExecutableContent()));", "admin/security_file.php:106|write|$res7 = dolibarr_set_const($db, \"MAIN_FILE_EXTENSION_UPLOAD_RESTRICTION\", GETPOST(''MAIN_FILE_EXTENSION_UPLOAD_RESTRICTION'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/system/security.php:632|read|print implode('', '', explode('','', getDolGlobalString(''MAIN_FILE_EXTENSION_UPLOAD_RESTRICTION'')));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FILL_SERVICE_DATES_FROM_LAST_SERVICE_LINE', 'string', NULL, 'core', 'Pre-fills service start/end dates on a new line from the dates of the previous service line in the document.', 'Checked in core/tpl/objectline_create.tpl.php:604 and core/tpl/objectline_edit.tpl.php:424 when the object already has lines and the current index is greater than zero.', 'Enabling this constant causes service date fields to be pre-populated from the preceding line, reducing manual data entry for recurring services.', 'Truthy value = pre-fill from last service line; empty/unset = dates left blank.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_edit.tpl.php:424|check|if (getDolGlobalString(''MAIN_FILL_SERVICE_DATES_FROM_LAST_SERVICE_LINE'') && !empty($object->lines) && $i > 0) {", "core/tpl/objectline_create.tpl.php:604|check|if (getDolGlobalString(''MAIN_FILL_SERVICE_DATES_FROM_LAST_SERVICE_LINE'') && !empty($object->lines)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FINISHED_LINES_OPACITY', 'string', NULL, 'fourn', 'Applies reduced opacity styling to completed/finished rows in list views across multiple modules.', 'Checked in project, supplier proposal, supplier order, invoice (customer and supplier), customer proposal, and customer order list pages. When value equals 1 and the row''s status indicates completion, the CSS class ''opacitymedium'' is applied. No admin UI write path exists.', 'Setting this to 1 makes finished/closed rows visually dimmed in list views; any other value or empty leaves all rows at full opacity.', '1=apply opacitymedium CSS class to finished rows, other/empty=no opacity change', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/list.php:2076|read|... ((getDolGlobalInt(''MAIN_FINISHED_LINES_OPACITY'') == 1 && $object->status > 1) ? ''opacitymedium'' : '''')", "supplier_proposal/list.php:1165|read|... ((getDolGlobalInt(''MAIN_FINISHED_LINES_OPACITY'') == 1 && $obj->status > 1) ? ''opacitymedium'' : '''')", "fourn/commande/list.php:1862|read|... ((getDolGlobalInt(''MAIN_FINISHED_LINES_OPACITY'') == 1 && $obj->billed == 1) ? ''opacitymedium'' : '''')", "compta/facture/list.php:2415|read|... ((getDolGlobalInt(''MAIN_FINISHED_LINES_OPACITY'') == 1 && $obj->status > 1) ? '' opacit"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRSTNAME_NAME_POSITION', 'string', NULL, 'core', 'Controls the display order of first name and last name throughout the application.', 'Written by admin/ihm.php:289 and rendered as a selector at admin/ihm.php:509. A comment at core/class/html.form.class.php:2440 states: ''$fullNameMode is 0=Lastname+Firstname (MAIN_FIRSTNAME_NAME_POSITION=1), 1=Firstname+Lastname (MAIN_FIRSTNAME_NAME_POSITION=0)''. Checked in core/class/html.form.class.php:2343 and :2442, core/class/html.formother.class.php:581, and opensurvey/list.php:265.', 'Setting this to 0 displays names as Firstname Lastname; setting to 1 displays names as Lastname Firstname across all name-formatting functions.', '0 = Firstname + Lastname order; 1 = Lastname + Firstname order.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// $fullNameMode is 0=Lastname+Firstname (MAIN_FIRSTNAME_NAME_POSITION=1), 1=Firstname+Lastname (MAIN_FIRSTNAME_NAME_POSITION=0)", "core/class/html.form.class.php:2343|check|if (!getDolGlobalString(''MAIN_FIRSTNAME_NAME_POSITION'')) {    // MAIN_FIRSTNAME_NAME_POSITION is 0 means firstname+lastname", "core/class/html.formother.class.php:581|check|if (!getDolGlobalString(''MAIN_FIRSTNAME_NAME_POSITION'')) {\t// MAIN_FIRSTNAME_NAME_POSITION is 0 means firstname+lastname", "admin/ihm.php:289|write|dolibarr_set_const($db, \"MAIN_FIRSTNAME_NAME_POSITION\", GETPOST(\"MAIN_FIRSTNAME_NAME_POSITION\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRST_PING_OK_DATE', 'string', NULL, 'core', 'Records the date and time of the first successful ping response received from Dolibarr''s registration/ping service.', 'Written automatically by the AJAX handler at core/ajax/pingresult.php when a ping response is successfully processed. Not set via the admin UI.', 'This is a system-recorded timestamp; modifying it would misrepresent when the instance first successfully pinged the Dolibarr service.', 'Date string in ''dayhourlog'' GMT format (e.g. ''20240101120000'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/ajax/pingresult.php:86|write|dolibarr_set_const($db, ''MAIN_FIRST_PING_OK_DATE'', dol_print_date($now, ''dayhourlog'', ''gmt''), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRST_PING_OK_ID', 'string', NULL, 'core', 'Stores the identifier and version recorded when the Dolibarr instance first successfully sends a ping.', 'Written in core/ajax/pingresult.php:87 as a hash plus DOL_VERSION string. Read in install/step2.php:619 to determine the state of the ping opt-out checkbox.', 'Changing or clearing this constant affects whether the instance is considered to have previously opted in to pinging, altering the installer checkbox state.', 'String: ''<hash> - <DOL_VERSION>''; ''disabled'' = ping explicitly opted out; empty/unset = no ping recorded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/ajax/pingresult.php:87|write|dolibarr_set_const($db, ''MAIN_FIRST_PING_OK_ID'', $hash_unique_id.'' - ''.DOL_VERSION, ''chaine'', 0, '''', $conf->entity);", "install/step2.php:619|read|$out .= ''<input type=\"checkbox\" name=\"dolibarrpingno\" id=\"dolibarrpingno\"''.((getDolGlobalString(''MAIN_FIRST_PING_OK_ID'') == ''disabled'') ? '''' : '' value=\"checked\" checked=\"true\"'').''>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRST_REGISTRATION_OK_DATE', 'string', NULL, 'blockedlog', 'Records the date-time when the first successful blockedlog registration ping was completed.', 'Written by core/ajax/pingresult.php:98 using dol_print_date($now, ''dayhourlog'', ''gmt'') after a successful registration. Read across blockedlog admin pages (registration.php:316, documentation.php:178, blockedlog.php:168) to display the date and to determine registration status at blockedlog/lib/blockedlog.lib.php:169.', 'If cleared or absent, isRegistrationOK() returns false and the blockedlog registration is considered incomplete, affecting compliance status display.', 'A date-time string in ''dayhourlog'' GMT format (e.g. ''20240115143022''); empty/unset means not yet registered.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/registration.php|blockedlog/admin/documentation.php|blockedlog/admin/documentation.php|blockedlog/admin/blockedlog.php|blockedlog/admin/blockedlog.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, ''MAIN_FIRST_REGISTRATION_OK_DATE'', dol_print_date($now, ''dayhourlog'', ''gmt''), ''chaine'', 0, '''', $conf->entity);", "return isRegistrationDataSaved() && (bool) getDolGlobalString(''MAIN_FIRST_REGISTRATION_OK_DATE'');", "$htmltext .= getDolGlobalString(''MAIN_FIRST_REGISTRATION_OK_DATE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRST_REGISTRATION_OK_ID', 'string', NULL, 'core', 'Records the unique registration ID and Dolibarr version string from the first successful registration ping.', 'Written automatically by the AJAX handler at core/ajax/pingresult.php when registration succeeds. The value combines a hash unique ID with the DOL_VERSION constant. Not set via the admin UI.', 'This is a system-recorded identifier; modifying it would misrepresent the instance''s registration fingerprint.', 'String in format ''<hash_unique_id> - <DOL_VERSION>''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/ajax/pingresult.php:99|write|dolibarr_set_const($db, ''MAIN_FIRST_REGISTRATION_OK_ID'', $hash_unique_id.'' - ''.DOL_VERSION, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIRST_TO_UPPER', 'string', NULL, 'core', 'Forces the first character of the first name field to uppercase.', 'Checked in core/class/commonpeople.class.php:376. When set, the first name value is capitalized.', 'Enabling this constant ensures the first name always starts with an uppercase letter.', 'Non-empty = first name capitalized; empty or unset = original case preserved', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonpeople.class.php:376|check|if (getDolGlobalString(''MAIN_FIRST_TO_UPPER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIX_FLASH_ON_CHROME', 'string', NULL, 'core', 'Enables a workaround for a CSS flash/rendering issue on Chrome.', 'Checked at main.inc.php:1917 to conditionally apply the fix.', 'Enabling this activates a Chrome-specific rendering workaround; disabling or unsetting it leaves the default rendering behavior.', '0 or unset = fix not applied; 1 (truthy) = Chrome flash fix applied', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1917|check|if (getDolGlobalString(''MAIN_FIX_FLASH_ON_CHROME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FIX_FOR_BUGGED_MTA', 'string', '1', 'admin', 'Enables a workaround for mail transfer agents that do not support CRLF line endings in email body content.', 'When enabled, CMailFile uses LF-only line endings (\n) instead of CRLF (\r\n) when wrapping email body text. Checked across admin/mails.php, admin/mails_passwordreset.php, admin/mails_ticket.php, and admin/mails_emailing.php to show warnings when the send mode is ''mail''. Default value is ''1''.', 'Enabling this constant changes the line ending character used in email bodies from \r\n to \n; disabling it restores standard CRLF line endings required by RFC 2822.', 'Non-empty string (truthy) enables the fix; empty or undefined disables it.', 0, 0, 'admin/mails.php|admin/mails_passwordreset.php|admin/mails_ticket.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1809|read|$strContentAltText = trim(wordwrap($strContentAltText, 75, !getDolGlobalString(''MAIN_FIX_FOR_BUGGED_MTA'') ? \"\\r\\n\" : \"\\n\"));", "core/class/CMailFile.class.php:1818|read|$strContent = rtrim(wordwrap($strContent, 75, !getDolGlobalString(''MAIN_FIX_FOR_BUGGED_MTA'') ? \"\\r\\n\" : \"\\n\"));", "admin/mails.php:1037|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail'') == ''mail'' && !getDolGlobalString(''MAIN_FIX_FOR_BUGGED_MTA'')) {", "core/class/CMailFile.class.php:272|check|if (getDolGlobalString(''MAIN_FIX_FOR_BUGGED_MTA'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FONTAWESOME_DIRECTORY', 'string', NULL, 'core', 'Specifies the directory path for FontAwesome icons, overriding the default location.', 'Read at main.inc.php:1893 to set $fontawesome_directory, with a default of ''/theme/common/fontawesome-5''.', 'Changing this redirects all FontAwesome icon loads to the specified directory.', 'Any valid server-relative path string; empty/unset = defaults to ''/theme/common/fontawesome-5''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1893|read|$fontawesome_directory = getDolGlobalString(''MAIN_FONTAWESOME_DIRECTORY'', ''/theme/common/fontawesome-5'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FONTAWESOME_FAMILY', 'string', NULL, 'theme', 'Specifies the Font Awesome CSS font-family name used for icons across the Eldy and MD themes.', 'Read across many theme files including theme/eldy/dropdown.inc.php:420, theme/md/dropdown.inc.php:176, :438, theme/eldy/btn.inc.php:215, theme/eldy/main_menu_fa_icons.inc.php:57, and theme/eldy/global.inc.php:1649, :4211, :8860 to set the CSS font-family for icon elements. Falls back to ''Font Awesome 5 Free'' if unset. No admin UI write path is present in the payload.', 'Setting this to a different font family name replaces the Font Awesome icon font used throughout the interface. Leaving it unset defaults to ''Font Awesome 5 Free''.', 'CSS font-family name string. Defaults to ''Font Awesome 5 Free''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/dropdown.inc.php:420|read|font-family: \"<?php echo getDolGlobalString(''MAIN_FONTAWESOME_FAMILY'', ''Font Awesome 5 Free''); ?>\";", "theme/md/dropdown.inc.php:176|read|font-family: \"<?php echo getDolGlobalString(''MAIN_FONTAWESOME_FAMILY'', ''Font Awesome 5 Free''); ?>\";", "theme/eldy/btn.inc.php:215|read|font-family: \"<?php echo getDolGlobalString(''MAIN_FONTAWESOME_FAMILY'', ''Font Awesome 5 Free''); ?>\";", "theme/eldy/global.inc.php:1649|read|font-family: \"<?php echo getDolGlobalString(''MAIN_FONTAWESOME_FAMILY'', ''Font Awesome 5 Free''); ?>\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FONTAWESOME_ICON_STYLE', 'string', NULL, 'core', 'Overrides the default FontAwesome icon style prefix used throughout the UI.', 'Read at core/lib/functions.lib.php:5797 with a default fallback of ''fas''. Setting this constant changes the prefix applied to icon class names globally.', 'Changing this value alters all FontAwesome icon rendering; using an invalid prefix will break icon display site-wide.', 'Any valid FontAwesome style prefix string (e.g. ''fas'', ''far'', ''fal'', ''fad''); default is ''fas''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5797|read|$fa = getDolGlobalString(''MAIN_FONTAWESOME_ICON_STYLE'', ''fas'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCELANGDIR', 'string', NULL, 'core', 'Forces translation file loading from a custom subdirectory path appended to each language directory.', 'Checked and read in core/class/translate.class.php at lines 130, 134, and 395. The inline comment at line 134 documents: ''For example $conf->global->MAIN_FORCELANGDIR is "/mymodule" meaning we search files into "/mymodule/langs/xx_XX"''. No admin UI write is present.', 'When set, all translation file lookups are redirected to the specified subdirectory, allowing custom or module-specific language files to override defaults. When unset, the standard language directory structure is used.', 'Subdirectory path string (e.g. ''/mymodule''); empty or unset to use default language directories.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/translate.class.php:134|read|$newdir = $dir . getDolGlobalString(''MAIN_FORCELANGDIR''); // For example $conf->global->MAIN_FORCELANGDIR is ''/mymodule'' meaning we search files into ''/mymodule/langs/xx_XX''", "core/class/translate.class.php:130|check|if (getDolGlobalString(''MAIN_FORCELANGDIR'')) {", "core/class/translate.class.php:395|check|if (!getDolGlobalString(''MAIN_FORCELANGDIR'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCETHEME', 'string', NULL, 'core', 'Forces all users to use a specific UI theme, overriding individual user theme preferences.', 'Checked in main.inc.php:1191 to suppress per-user theme selection, and in core/lib/usergroups.lib.php:433-435 where a warning is displayed showing the forced theme name.', 'When set, individual users cannot change their theme; the named theme is applied globally.', 'Any valid theme name string; empty/unset = users may choose their own theme', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1191|check|if (!getDolGlobalString(''MAIN_FORCETHEME'') && getDolUserString(''MAIN_THEME'')) {", "core/lib/usergroups.lib.php:433|check|if (getDolGlobalString(''MAIN_FORCETHEME'')) {", "core/lib/usergroups.lib.php:435|read|print $langs->trans(\"WarningThemeForcedTo\", getDolGlobalString(''MAIN_FORCETHEME''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_DISABLE_MAIL_SPOOFING', 'bool', NULL, 'core', 'Disables email spoofing by enforcing strict sender identity controls.', 'When set, anti-spoofing enforcement is activated at core/class/CMailFile.class.php:721. No admin UI manages this constant.', 'Enabling this restricts the ability to set arbitrary From addresses, reducing the risk of sender spoofing.', 'Any non-empty string value enables anti-spoofing enforcement.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:721|check|if (getDolGlobalString(''MAIN_FORCE_DISABLE_MAIL_SPOOFING'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_DOWNLOAD_IN_HTML_FORMFILE', 'string', NULL, 'core', 'Forces file download (instead of inline display) for documents rendered via the html.formfile component.', 'Read as an integer in core/class/html.formfile.class.php at lines 1035, 1654, and 2201 to set the forcedownload flag used when generating file links.', 'When set to a truthy integer, clicking document links triggers a download prompt rather than in-browser display. When 0 or unset, files open inline if the browser supports the format.', 'Integer: 1 to force download; 0 or unset to allow inline display.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formfile.class.php:1035|read|$forcedownload = getDolGlobalInt(''MAIN_FORCE_DOWNLOAD_IN_HTML_FORMFILE'');", "core/class/html.formfile.class.php:1654|read|$forcedownload = getDolGlobalInt(''MAIN_FORCE_DOWNLOAD_IN_HTML_FORMFILE'');", "core/class/html.formfile.class.php:2201|read|$forcedownload = getDolGlobalInt(''MAIN_FORCE_DOWNLOAD_IN_HTML_FORMFILE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_READFILE_WITH_FREAD', 'string', NULL, 'core', 'Forces file download/read operations to use the fread() method instead of the default mechanism.', 'Checked at core/lib/functions.lib.php:15850. When truthy, the file output function takes the fread-based code path.', 'Enabling this constant changes the file-read strategy to fread(), which affects how large files are streamed to the client.', '0 or empty = default file read method; any truthy value = fread() used for file output', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:15850|check|if (getDolGlobalString(''MAIN_FORCE_READFILE_WITH_FREAD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_READFILE_WITH_STREAM_COPY', 'string', NULL, 'core', 'Forces file download/read operations to use stream_copy_to_stream() instead of the default mechanism.', 'Checked at core/lib/functions.lib.php:15853. When truthy, the file output function takes the stream_copy code path.', 'Enabling this constant changes the file-read strategy to stream_copy_to_stream(), which affects how files are streamed to the client.', '0 or empty = default file read method; any truthy value = stream_copy_to_stream() used for file output', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:15853|check|if (getDolGlobalString(''MAIN_FORCE_READFILE_WITH_STREAM_COPY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_RELOAD_PAGE', 'string', NULL, 'core', 'Forces a full page reload instead of an AJAX row update after drag-and-drop reordering operations.', 'Read via getDolGlobalInt into $forcereloadpage at variants/list.php:873, core/tpl/subtotal_ajaxrow.tpl.php:62, and core/tpl/ajaxrow.tpl.php:61. 3 occurrences across 3 files.', 'When unset or 0, row reordering uses AJAX without a full page reload. When set to a non-zero value, a full page reload is triggered after row order changes.', 'Integer: non-zero = force full page reload after row reorder; 0 or unset = AJAX update only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["variants/list.php:873|read|$forcereloadpage = getDolGlobalInt(''MAIN_FORCE_RELOAD_PAGE'');", "core/tpl/subtotal_ajaxrow.tpl.php:62|read|$forcereloadpage = getDolGlobalInt(''MAIN_FORCE_RELOAD_PAGE'');", "core/tpl/ajaxrow.tpl.php:61|read|$forcereloadpage = getDolGlobalInt(''MAIN_FORCE_RELOAD_PAGE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_SHARING_ON_ANY_UPLOADED_FILE', 'string', NULL, 'core', 'Forces sharing to be enabled on every uploaded file regardless of individual file settings.', 'In core/lib/files.lib.php, when this constant is set, sharing is activated on all uploaded files. No admin UI write; hidden setting. Only one occurrence in the payload.', 'Enabling this constant makes all uploaded files publicly shareable; disabling it (or leaving unset) preserves per-file sharing settings.', 'Non-empty (truthy) forces sharing on all uploads; empty or undefined leaves sharing controlled per file.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2328|check|if (getDolGlobalString(''MAIN_FORCE_SHARING_ON_ANY_UPLOADED_FILE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FORCE_STATE_INTO_ADDRESS', 'string', NULL, 'core', 'Forces the state/province to be included in formatted address strings for all countries, not just those that normally use it.', 'Checked in core/class/commonpeople.class.php:244-245 and webportal/class/webportalmember.class.php:471-472 with the comment ''If MAIN_FORCE_STATE_INTO_ADDRESS is on, state is already returned previously with getFullAddress''. Also used in core/lib/functions.lib.php:3803.', 'When enabled, the state field appears in address output for all countries regardless of country-specific rules; without it, only AU, CA, US, CN automatically include the state.', '0 or unset = state shown only for countries that use it (AU, CA, US, CN); non-empty = state always shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonpeople.class.php:244  // If MAIN_FORCE_STATE_INTO_ADDRESS is on, state is already returned previously with getFullAddress", "webportal/class/webportalmember.class.php:471  // If MAIN_FORCE_STATE_INTO_ADDRESS is on, state is already returned previously with getFullAddress", "core/lib/functions.lib.php:3803|check|if (isset($object->country_code) && in_array($object->country_code, array(''AU'', ''CA'', ''US'', ''CN'')) || getDolGlobalString(''MAIN_FORCE_STATE_INTO_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FRANCE_TODO_LOI_FINANCE', 'string', NULL, 'core', 'Placeholder constant related to French finance law compliance requirements, read during trigger processing.', 'Read at core/class/interfaces.class.php:114 with getDolGlobalString; the payload provides only a single read occurrence and no comment describing its semantics. Exact behavior unclear from code alone.', 'The effect of setting this constant cannot be determined from the available payload evidence alone.', 'Unknown; no documented values in payload.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/interfaces.class.php:114|read|getDolGlobalString(''MAIN_FRANCE_TODO_LOI_FINANCE'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_FREE_PRODUCT_CHECKED_BY_DEFAULT', 'string', NULL, 'core', 'Controls which entry mode radio button (free-text or product/service) is pre-selected when adding document lines.', 'Read in core/tpl/objectline_create.tpl.php:230 to decide the checked state, and checked in core/class/html.form.class.php:1250 (''product'') and :1257 (''service'') to pre-select the product type radio.', 'Setting to ''product'' pre-selects the product radio; setting to ''service'' pre-selects the service radio; leaving unset defaults to the standard selection logic.', 'Empty/not set = default selection; ''product'' = product radio pre-selected; ''service'' = service radio pre-selected', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:230|read|print((GETPOST(''prod_entry_mode'', ''alpha'') == ''free'' || getDolGlobalString(''MAIN_FREE_PRODUCT_CHECKED_BY_DEFAULT'')) ? '' checked'' : '''');", "core/class/html.form.class.php:1250|check|if (0 == $selected || ($selected == -1 && getDolGlobalString(''MAIN_FREE_PRODUCT_CHECKED_BY_DEFAULT'') == ''product'')) {", "core/class/html.form.class.php:1257|check|if (1 == $selected || ($selected == -1 && getDolGlobalString(''MAIN_FREE_PRODUCT_CHECKED_BY_DEFAULT'') == ''service'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DELIVERY_WITH_PICTURE', 'string', NULL, 'core', 'Enables inclusion of product pictures in delivery order PDFs generated by the Storm module.', 'Checked in pdf_storm.modules.php at lines 186 and 960. Line 960 additionally requires $this->atleastonephoto to be non-empty, meaning pictures are rendered only when the constant is set and at least one photo exists. No admin UI write is present.', 'Enabling this causes product images to appear in delivery PDFs when photos are available; disabling suppresses all images.', 'Truthy (non-empty) = pictures included (if available); empty/unset = no pictures.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_storm.modules.php:186|check|if (getDolGlobalString(''MAIN_GENERATE_DELIVERY_WITH_PICTURE'')) {", "pdf_storm.modules.php:960|check|if (getDolGlobalString(''MAIN_GENERATE_DELIVERY_WITH_PICTURE'') && !empty($this->atleastonephoto)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_HIDE_DESC', 'bool', NULL, 'core', 'Hides line-item description text when generating PDF or other documents.', 'Written via admin/pdf.php (line 142) and shown as a yes/no selector (line 601). Read across at least 26 files including supplier_proposal/card.php:91, reception/card.php:122, and api/class/api_documents.class.php:236 to set the `$hidedesc` flag.', 'Enabling this setting causes generated documents to omit line-item description text.', '0 = show descriptions (default); 1 = hide descriptions.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:142|write|dolibarr_set_const($db, \"MAIN_GENERATE_DOCUMENTS_HIDE_DESC\", GETPOST(\"MAIN_GENERATE_DOCUMENTS_HIDE_DESC\"), ''chaine'', 0, '''', $conf->entity);", "api/class/api_documents.class.php:236|read|$hidedesc = !getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_HIDE_DESC'') ? 0 : 1;", "supplier_proposal/card.php:91|read|$hidedesc = (GETPOSTINT(''hidedesc'') ? GETPOSTINT(''hidedesc'') : (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_HIDE_DESC'') ? 1 : 0));", "admin/pdf.php:601|read|print $form->selectyesno(''MAIN_GENERATE_DOCUMENTS_HIDE_DESC'', getDolGlobalInt(''MAIN_GENERATE_DOCUMENTS_HIDE_DESC''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS', 'bool', NULL, 'core', 'Hides line-item detail rows when generating PDF or other documents.', 'Written via admin/pdf.php (line 139) and shown as a yes/no selector (line 611). Read across at least 26 files including supplier_proposal/card.php:90, reception/card.php:121, and api/class/api_documents.class.php:235 to set the `$hidedetails` flag.', 'Enabling this setting causes generated documents to omit line-item detail rows; documents will show only summary-level information.', '0 = show details (default); 1 = hide details.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:139|write|dolibarr_set_const($db, \"MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS\", GETPOST(\"MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS\"), ''chaine'', 0, '''', $conf->entity);", "api/class/api_documents.class.php:235|read|$hidedetails = !getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS'') ? 0 : 1;", "supplier_proposal/card.php:90|read|$hidedetails = (GETPOSTINT(''hidedetails'') ? GETPOSTINT(''hidedetails'') : (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS'') ? 1 : 0));", "admin/pdf.php:611|read|print $form->selectyesno(''MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS'', getDolGlobalInt(''MAIN_GENERATE_DOCUMENTS_HIDE_DETAILS''), 1);"]', 'high', NULL);
