INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_SUPPLIER_PROPOSAL_WITHOUT_UNIT_PRICE', 'string', NULL, 'admin', 'Suppresses the unit price column in supplier proposal PDF documents when enabled.', 'Written in admin/pdf_other.php at line 106 and displayed as a select at line 666. Checked (negated) in core/modules/supplier_proposal/doc/pdf_zenith.modules.php at line 1596; the unit price column is rendered only when this constant is falsy.', 'Enabling this constant hides the unit price column from supplier proposal PDFs. Disabling it (or leaving unset) shows the unit price column.', 'Truthy string to hide unit price column; empty/unset to show unit price column.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:106|write|dolibarr_set_const($db, \"MAIN_GENERATE_DOCUMENTS_SUPPLIER_PROPOSAL_WITHOUT_UNIT_PRICE\", GETPOST(\"MAIN_GENERATE_DOCUMENTS_SUPPLIER_PROPOSAL_WITHOUT_UNIT_PRICE\"), ''chaine'', 0, '''', $c", "core/modules/supplier_proposal/doc/pdf_zenith.modules.php:1596|check|if (!getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_SUPPLIER_PROPOSAL_WITHOUT_UNIT_PRICE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT', 'string', NULL, 'core', 'Suppresses VAT/tax columns and totals from all generated PDF documents.', 'Written via admin/pdf.php:118 and rendered via admin/pdf.php:502 with selectyesno. Checked in 41 locations across expense report, order, invoice, supplier order, and proposal PDF modules. Often evaluated together with MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN.', 'When enabled, VAT amounts and related columns are omitted from all generated PDF documents; the layout adapts to exclude tax sections.', '0 (VAT shown) or 1 (VAT hidden from documents)', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:118|write|dolibarr_set_const($db, \"MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT\", GETPOST(\"MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:502|read|print $form->selectyesno(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'', getDolGlobalInt(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT''), 1);", "core/modules/supplier_invoice/doc/pdf_canelle.modules.php:128  /* if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') || getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:464|check|if (!getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') && !getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN', 'string', NULL, 'core', 'Hides the VAT column specifically in generated PDF documents while leaving VAT totals intact.', 'Checked in 23 locations across order, supplier order, proposal, product, and stocktransfer PDF modules. No admin UI write was found; HIDDEN_GUESS is 1. Typically used in conjunction with MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT.', 'When set, the VAT rate/amount column is removed from PDF line item tables without necessarily removing the total VAT section.', '0 (VAT column shown) or 1 (VAT column hidden)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/supplier_invoice/doc/pdf_canelle.modules.php:128  /* if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') || getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:464|check|if (!getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') && !getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {", "core/modules/stock/doc/pdf_standard_stock.modules.php:130|check|if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') || getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:1306|check|if (!getDolGlobalInt(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT'') && !getDolGlobalInt(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_COLUMN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_IFNULL', 'string', NULL, 'core', 'When set, suppresses the VAT line from generated PDF documents when the VAT amount is null or zero.', 'Checked in 7 PDF modules (pdf_einstein, pdf_eratosthene, pdf_octopus, pdf_sponge, pdf_aurore, pdf_cyan, pdf_azur) combined with a $tvaisnull condition before rendering the VAT row.', 'Enabling this removes the VAT line from PDFs whenever the computed VAT is null/zero. Disabling (or leaving unset) causes the VAT line to be rendered regardless of the VAT amount.', 'Empty/unset = always show VAT line; any truthy value = hide VAT line when VAT is null or zero.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_einstein.modules.php:999|if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_IFNULL'') && $tvaisnull) {", "pdf_eratosthene.modules.php:1261|if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_IFNULL'') && $tvaisnull) {", "pdf_octopus.modules.php:1719|if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_IFNULL'') && $tvaisnull) {", "pdf_cyan.modules.php:1354|if (getDolGlobalString(''MAIN_GENERATE_DOCUMENTS_WITHOUT_VAT_IFNULL'') && $tvaisnull) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_INVOICES_WITH_PICTURE', 'string', NULL, 'core', 'Enables inclusion of product pictures in invoice PDF documents.', 'Read via admin/pdf_other.php:503 (select UI) and checked in core/modules/facture/doc/pdf_octopus.modules.php:310, :2472 and core/modules/facture/doc/pdf_sponge.modules.php:244, :2707. The modulebuilder reference at line 1290 is commented out.', 'When enabled, invoice PDF generators include product images in the document output when at least one photo is available.', '0 (no pictures in invoices) or 1 (include pictures in invoices)', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:1290  // if (getDolGlobalInt(''MAIN_GENERATE_INVOICES_WITH_PICTURE'') && !empty($this->atleastonephoto)) {", "core/modules/facture/doc/pdf_octopus.modules.php:310|check|if (getDolGlobalString(''MAIN_GENERATE_INVOICES_WITH_PICTURE'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:2472|check|if (getDolGlobalString(''MAIN_GENERATE_INVOICES_WITH_PICTURE'') && !empty($this->atleastonephoto)) {", "admin/pdf_other.php:503|read|print $form->selectarray(\"MAIN_GENERATE_INVOICES_WITH_PICTURE\", $arrval, getDolGlobalString(''MAIN_GENERATE_INVOICES_WITH_PICTURE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_MYOBJECT_WITH_PICTURE', 'string', NULL, 'modulebuilder', 'Enables inclusion of product pictures in PDF documents generated for MyObject records.', 'Checked once at modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:213. This is a module-builder placeholder constant. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant causes the PDF generator to include product images in MyObject PDF output.', '0 (no pictures) or 1 (include pictures)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:213|check|if (getDolGlobalInt(''MAIN_GENERATE_MYOBJECT_WITH_PICTURE''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_ORDERS_WITH_PICTURE', 'string', NULL, 'core', 'When set, includes product pictures in generated sales order PDF documents.', 'Managed via the admin UI at admin/pdf_other.php as a select array. Checked in pdf_eratosthene.modules.php and pdf_eagle_proforma.modules.php before including product images. In pdf_eratosthene.modules.php, the second check is combined with $this->atleastonephoto.', 'Setting a truthy value causes product images to be embedded in sales order PDFs. Clearing the value omits product pictures.', 'Empty/unset = no pictures in order PDFs; any truthy value = include product pictures.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:381|print $form->selectarray(\"MAIN_GENERATE_ORDERS_WITH_PICTURE\", $arrval, getDolGlobalString(''MAIN_GENERATE_ORDERS_WITH_PICTURE''));", "pdf_eagle_proforma.modules.php:1589|if (getDolGlobalString(''MAIN_GENERATE_ORDERS_WITH_PICTURE'')) {", "pdf_eratosthene.modules.php:207|if (getDolGlobalInt(''MAIN_GENERATE_ORDERS_WITH_PICTURE'')) {", "pdf_eratosthene.modules.php:2031|if (getDolGlobalInt(''MAIN_GENERATE_ORDERS_WITH_PICTURE'') && !empty($this->atleastonephoto)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_PROPOSALS_WITH_PICTURE', 'string', NULL, 'core', 'Enables inclusion of product images in generated proposal PDFs.', 'Written in admin/pdf_other.php at line 96 and displayed as a select at line 301. Checked in pdf_azur.modules.php at lines 223 and 1492 and pdf_cyan.modules.php at lines 200 and 2163 to conditionally render product photos in PDF output.', 'Enabling this constant causes proposal PDFs to include product images when available. Disabling it omits images from proposals.', 'Truthy string to include product pictures; empty/unset to omit pictures.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:96|write|dolibarr_set_const($db, \"MAIN_GENERATE_PROPOSALS_WITH_PICTURE\", GETPOST(\"MAIN_GENERATE_PROPOSALS_WITH_PICTURE\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:2163|check|if (getDolGlobalString(''MAIN_GENERATE_PROPOSALS_WITH_PICTURE'') && !empty($this->atleastonephoto)) {", "core/modules/propale/doc/pdf_azur.modules.php:1492|check|if (getDolGlobalString(''MAIN_GENERATE_PROPOSALS_WITH_PICTURE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_SHIPMENT_WITH_PICTURE', 'string', NULL, 'core', 'When set, includes product pictures in generated shipment PDF documents.', 'Checked in pdf_rouget.modules.php, pdf_espadon.modules.php, and pdf_squille.modules.php before including product images in the PDF layout. In pdf_espadon.modules.php the check is combined with $this->atleastonephoto to guard the photo rendering section.', 'Enabling this causes product images to be embedded in shipment and reception PDFs. Disabling (or leaving unset) omits product pictures from those documents.', 'Empty/unset = no pictures in shipment PDFs; any truthy value = include product pictures.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:211|if (getDolGlobalString(''MAIN_GENERATE_SHIPMENT_WITH_PICTURE'')) {", "pdf_espadon.modules.php:179|if (getDolGlobalString(''MAIN_GENERATE_SHIPMENT_WITH_PICTURE'')) {", "pdf_espadon.modules.php:1423|if (getDolGlobalString(''MAIN_GENERATE_SHIPMENT_WITH_PICTURE'') && !empty($this->atleastonephoto)) {", "pdf_squille.modules.php:172|if (getDolGlobalString(''MAIN_GENERATE_SHIPMENT_WITH_PICTURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_STOCKTRANSFER_WITH_PICTURE', 'string', NULL, 'core', 'Includes product images in generated stock-transfer PDF documents when enabled.', 'Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php at lines 219 and 269, and in core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php:192 to conditionally render product images in the PDF.', 'When set, product images are embedded in stock-transfer PDF output. When unset, images are omitted.', 'Truthy value (e.g. 1) to include product images; 0 or empty to omit them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:219|check|if (getDolGlobalString(''MAIN_GENERATE_STOCKTRANSFER_WITH_PICTURE'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:269|check|if (getDolGlobalString(''MAIN_GENERATE_STOCKTRANSFER_WITH_PICTURE'')) {", "core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php:192|check|if (getDolGlobalString(''MAIN_GENERATE_STOCKTRANSFER_WITH_PICTURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_SUPPLIER_ORDER_WITH_PICTURE', 'string', NULL, 'core', 'Enables inclusion of product pictures in supplier order PDFs generated by Cornas and Muscadet modules.', 'Checked in pdf_cornas.modules.php at lines 188 and 1625, and in pdf_muscadet.modules.php at line 200. No admin UI write is present.', 'Enabling this causes product images to appear in supplier order PDFs when photos are available; disabling suppresses all images.', 'Truthy (non-empty) = pictures included; empty/unset = no pictures.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_cornas.modules.php:188|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_ORDER_WITH_PICTURE'')) {", "pdf_muscadet.modules.php:200|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_ORDER_WITH_PICTURE'')) {", "pdf_cornas.modules.php:1625|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_ORDER_WITH_PICTURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GENERATE_SUPPLIER_PROPOSAL_WITH_PICTURE', 'string', NULL, 'core', 'Enables inclusion of product images in supplier proposal PDF documents.', 'When set, product images are included in the PDF generation logic for both the zenith template (core/modules/supplier_proposal/doc/pdf_zenith.modules.php:186 and 1565) and the aurore template (core/modules/supplier_proposal/doc/pdf_aurore.modules.php:198).', 'Enabling this embeds product pictures in supplier proposal PDFs; disabling it omits images.', 'Any non-empty string value enables product image inclusion in supplier proposal PDFs.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/doc/pdf_zenith.modules.php:186|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_PROPOSAL_WITH_PICTURE'')) {", "core/modules/supplier_proposal/doc/pdf_aurore.modules.php:198|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_PROPOSAL_WITH_PICTURE'')) {", "core/modules/supplier_proposal/doc/pdf_zenith.modules.php:1565|check|if (getDolGlobalString(''MAIN_GENERATE_SUPPLIER_PROPOSAL_WITH_PICTURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GET_LOCALTAXES_VALUES_FROM_THIRDPARTY', 'string', NULL, 'core', 'Forces local tax rate retrieval from the third-party record rather than the default tax table.', 'The comment at core/lib/functions.lib.php:8130 states ''For some country MAIN_GET_LOCALTAXES_VALUES_FROM_THIRDPARTY is forced to on.'' The constant is programmatically set to 1 at line 8132 for such countries, and checked at line 8136 to route local tax lookups.', 'When active, local tax values are read from the third-party (customer/supplier) record; disabling it reverts to the default tax table lookup.', '0 or empty = local taxes from default table; 1 = local taxes from third-party record (forced for some countries)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:8130  // For some country MAIN_GET_LOCALTAXES_VALUES_FROM_THIRDPARTY is forced to on.", "core/lib/functions.lib.php:8132|write|$conf->global->MAIN_GET_LOCALTAXES_VALUES_FROM_THIRDPARTY = 1;", "core/lib/functions.lib.php:8136|check|if (getDolGlobalString(''MAIN_GET_LOCALTAXES_VALUES_FROM_THIRDPARTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GOOGLE_AD_CLIENT', 'string', NULL, 'public', 'Stores the Google AdSense client ID used to display ads on the Dolibarr public demo page.', 'Checked at public/demo/index.php line 456 (requires both MAIN_GOOGLE_AD_CLIENT and MAIN_GOOGLE_AD_SLOT to be set, and the Google module enabled). Read at line 460 to emit the google_ad_client JavaScript variable. Also referenced at core/lib/security2.lib.php line 292.', 'Setting this constant (together with MAIN_GOOGLE_AD_SLOT) enables Google AdSense ads on the public demo page. Clearing it disables the ad block.', 'String; Google AdSense publisher ID (e.g. ''ca-pub-XXXXXXXXXXXXXXXX''). Both MAIN_GOOGLE_AD_CLIENT and MAIN_GOOGLE_AD_SLOT must be set for ads to appear.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["public/demo/index.php:456|check|if (isModEnabled(''google'') && getDolGlobalString(''MAIN_GOOGLE_AD_CLIENT'') && getDolGlobalString(''MAIN_GOOGLE_AD_SLOT'')) {", "public/demo/index.php:460|read|print ''google_ad_client = \"'' . getDolGlobalString(''MAIN_GOOGLE_AD_CLIENT'').''\"'';", "core/lib/security2.lib.php:292|read|$main_google_ad_client = ((getDolGlobalString(''MAIN_GOOGLE_AD_CLIENT'') && getDolGlobalString(''MAIN_GOOGLE_AD_SLOT'')) ? 1 : 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GOOGLE_AD_HEIGHT', 'string', NULL, 'public', 'Specifies the height value used for a Google ad unit rendered on the public demo page.', 'In public/demo/index.php at line 463, the value is printed directly into a JavaScript variable assignment for google_ad_height. No admin UI write path is present.', 'Changing this value alters the height of the Google ad unit on the public demo page.', 'String/integer: height in pixels for the Google ad unit', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/demo/index.php:463|read|print ''google_ad_height = '' . getDolGlobalString(''MAIN_GOOGLE_AD_HEIGHT'').'';''."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GOOGLE_AD_SLOT', 'string', NULL, 'public', 'Stores the Google AdSense ad-slot ID used to display ads on the Dolibarr public demo page.', 'Checked at public/demo/index.php line 456 (requires both MAIN_GOOGLE_AD_CLIENT and MAIN_GOOGLE_AD_SLOT to be set, and the Google module enabled). Read at line 461 to emit the google_ad_slot JavaScript variable. Also referenced at core/lib/security2.lib.php line 292.', 'Setting this constant (together with MAIN_GOOGLE_AD_CLIENT) enables Google AdSense ads on the public demo page. Clearing it disables the ad block.', 'String; Google AdSense ad slot ID (numeric string). Both MAIN_GOOGLE_AD_CLIENT and MAIN_GOOGLE_AD_SLOT must be set for ads to appear.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["public/demo/index.php:456|check|if (isModEnabled(''google'') && getDolGlobalString(''MAIN_GOOGLE_AD_CLIENT'') && getDolGlobalString(''MAIN_GOOGLE_AD_SLOT'')) {", "public/demo/index.php:461|read|print ''google_ad_slot = \"'' . getDolGlobalString(''MAIN_GOOGLE_AD_SLOT'').''\"'';", "core/lib/security2.lib.php:292|read|$main_google_ad_client = ((getDolGlobalString(''MAIN_GOOGLE_AD_CLIENT'') && getDolGlobalString(''MAIN_GOOGLE_AD_SLOT'')) ? 1 : 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GOOGLE_AD_WIDTH', 'string', NULL, 'public', 'Specifies the width value used for a Google ad unit rendered on the public demo page.', 'In public/demo/index.php at line 462, the value is printed directly into a JavaScript variable assignment for google_ad_width. No admin UI write path is present.', 'Changing this value alters the width of the Google ad unit on the public demo page.', 'String/integer: width in pixels for the Google ad unit', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/demo/index.php:462|read|print ''google_ad_width = '' . getDolGlobalString(''MAIN_GOOGLE_AD_WIDTH'').'';''."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GOOGLE_AN_ID', 'string', NULL, 'core', 'Stores one or more Google Analytics tracking IDs used to inject GA scripts into pages.', 'Checked and read at core/lib/functions.lib.php:13252-13253. Requires the ''google'' module to be enabled. The value is split by comma to support multiple tracking IDs. Listed in the docblock at line 13031.', 'Setting this constant enables Google Analytics tracking on all pages; leaving it empty disables GA injection.', 'Comma-separated string of Google Analytics tracking IDs (e.g. ''UA-XXXXX-Y,G-XXXXXXXXXX''); empty/unset = no GA tracking', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:13031  * \t\tjs for conf->global->MAIN_GOOGLE_AN_ID", "core/lib/functions.lib.php:13252|check|if (isModEnabled(''google'') && getDolGlobalString(''MAIN_GOOGLE_AN_ID'')) {", "core/lib/functions.lib.php:13253|read|$tmptagarray = explode('','', getDolGlobalString(''MAIN_GOOGLE_AN_ID''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_GRANDTOTAL_LIST_SHOW', 'bool', NULL, 'core', 'Shows a grand total row at the bottom of list views when the list is paginated.', 'Checked in core/tpl/list_print_total.tpl.php:123 in combination with a condition that the result count meets the page limit, indicating pagination is active.', 'Enabling this constant adds a grand-total summary row to paginated lists, providing aggregated figures across all pages.', 'Empty/not set = grand total row not shown; any truthy string = grand total row displayed on paginated lists', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/list_print_total.tpl.php:123|check|if (getDolGlobalString(''MAIN_GRANDTOTAL_LIST_SHOW'') && (!(is_null($limit) || $num < $limit))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HELPCENTER_LINKTOUSE', 'string', NULL, 'core', 'Specifies a custom help center URL to display on the login page.', 'Checked at core/lib/security2.lib.php:276 to render a help center link, and read at core/tpl/login.tpl.php:204 to populate $helpcenterlink. Also interacts with MAIN_SECURITY_DISABLEFORGETPASSLINK at security2.lib.php:271. No admin UI is provided.', 'Setting this constant to a URL causes a custom help center link to appear on the login page; leaving it empty hides the help center link.', 'A URL string; empty/unset = no custom help center link shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/security2.lib.php:276|check|if (getDolGlobalString(''MAIN_HELPCENTER_LINKTOUSE'')) {", "core/tpl/login.tpl.php:204|read|$helpcenterlink = getDolGlobalString(''MAIN_HELPCENTER_LINKTOUSE'');", "core/lib/security2.lib.php:271|check|if (!getDolGlobalString(''MAIN_SECURITY_DISABLEFORGETPASSLINK'') || getDolGlobalString(''MAIN_HELPCENTER_LINKTOUSE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HELP_DISABLELINK', 'bool', NULL, 'imports', 'Disables the help/documentation link shown in the page toolbar and import pages.', 'Checked at main.inc.php:2319 and used in imports/import.php:1781 and :2275 to suppress help page links. The write in admin/ihm.php:297 is commented out, indicating the setting is managed externally or manually.', 'Enabling this hides help links from the page toolbar and import pages.', '0 or unset = help link shown; 1 (truthy) = help link hidden', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:297  //dolibarr_set_const($db, \"MAIN_HELP_DISABLELINK\", GETPOST(\"MAIN_HELP_DISABLELINK\", ''aZ09''), ''chaine'', 0, '''', 0); // Param for all entities", "main.inc.php:2319|check|if (!getDolGlobalString(''MAIN_HELP_DISABLELINK'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {", "imports/import.php:1781|read|if ($helppagename && empty($conf->global->MAIN_HELP_DISABLELINK))", "imports/import.php:2275|read|if ($helppagename && empty($conf->global->MAIN_HELP_DISABLELINK))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_AMOUNT_BEFORE_DISCOUNT', 'bool', NULL, 'core', 'Hides the amount-before-discount line in invoice PDFs generated by the Sponge module.', 'Checked in pdf_sponge.modules.php at line 1924: the pre-discount amount is printed only when this constant is NOT set and the invoice type is not 2. No admin UI write is present.', 'Enabling this suppresses the pre-discount amount in applicable invoice PDFs; disabling allows it to appear.', 'Truthy (non-empty) = pre-discount amount hidden; empty/unset = pre-discount amount shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_sponge.modules.php:1924|check|if (!getDolGlobalString(''MAIN_HIDE_AMOUNT_BEFORE_DISCOUNT'') && $object->type != 2) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_AMOUNT_DISCOUNT', 'bool', NULL, 'core', 'Hides the discount amount column in invoice PDFs generated by the Sponge module.', 'Checked in pdf_sponge.modules.php at line 1911: the discount amount is only printed when this constant is NOT set and the invoice type is not 2. No admin UI write is present.', 'Enabling this suppresses the discount amount line in applicable invoice PDFs; disabling allows it to appear.', 'Truthy (non-empty) = discount amount hidden; empty/unset = discount amount shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_sponge.modules.php:1911|check|if (!getDolGlobalString(''MAIN_HIDE_AMOUNT_DISCOUNT'') && $object->type != 2) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_INACTIVETAB_ON_PRINT', 'bool', NULL, 'core', 'Hides inactive tabs from the print layout when set, so only the active tab content appears on print.', 'Read in core/lib/functions.lib.php:3220; when set, inactive tab elements receive the ''hideonprint'' CSS class. No admin UI write detected.', 'Enabling this constant suppresses inactive tabs in printed output. Without it, all tabs are printed regardless of active state.', 'Non-empty = inactive tabs hidden on print; absent/empty = all tabs printed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3220|read|$out .= ''<div class=\"inline-block tabsElem'' . ($isactive ? '' tabsElemActive'' : '''') . ((!$isactive && getDolGlobalString(''MAIN_HIDE_INACTIVETAB_ON_PRINT'')) ? '' hideonprint'' : '''') ."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_LEFT_MENU', 'bool', NULL, 'core', 'When enabled, hides the left navigation menu panel from the Dolibarr interface.', 'Read in core/class/conf.class.php:1318, the boolean value is cast to int and stored in $this->dol_hide_leftmenu. No admin UI page is listed.', 'Enabling this constant removes the left sidebar from all pages, which can be useful for embedded or kiosk deployments.', '1 = hide left menu; 0 or unset = show left menu.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1318|read|$this->dol_hide_leftmenu = (int) (bool) getDolGlobalInt(''MAIN_HIDE_LEFT_MENU'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_LINK_BY_REF_IN_LINKTO', 'bool', NULL, 'core', 'Controls whether the ''link by reference'' feature is visible and functional in the link-to UI.', 'Checked in core/actions_dellink.inc.php:57 and core/class/html.form.class.php:10634, 10664, and 10730 to gate display and processing of the link-by-reference input in the object linking form.', 'When set, the link-by-reference input is hidden and the corresponding action is not processed; when unset, the feature is shown and operational.', 'Empty/unset = feature enabled; non-empty = feature hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/actions_dellink.inc.php:57|check|if ($action == ''addlinkbyref'' && !empty($permissiondellink) && !$cancellink && $id > 0 && !empty($addlinkref) && !getDolGlobalString(''MAIN_HIDE_LINK_BY_REF_IN_LINKTO'')) {", "core/class/html.form.class.php:10634|check|if (!getDolGlobalString(''MAIN_HIDE_LINK_BY_REF_IN_LINKTO'')) {", "core/class/html.form.class.php:10664|check|if (getDolGlobalString(''MAIN_HIDE_LINK_BY_REF_IN_LINKTO'')) {", "core/class/html.form.class.php:10730|check|if ($num > 0 || !getDolGlobalString(''MAIN_HIDE_LINK_BY_REF_IN_LINKTO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_MESSAGES_ON_CARD', 'bool', NULL, 'ticket', 'When enabled, hides the message thread section on the ticket card page.', 'Checked in ticket/card.php:1707 via negation: the message section is rendered only when this constant is falsy. No admin UI write path is present in the payload.', 'Enabling this constant suppresses the message section on the ticket card. Leaving it unset allows the message section to be displayed.', 'Truthy value to hide messages on card; unset or 0 to show.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:1707|check|if (!getDolGlobalString(''MAIN_HIDE_MESSAGES_ON_CARD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_POWERED_BY', 'bool', NULL, 'public', 'Hides the ''Powered by Dolibarr'' branding notice on public-facing pages.', 'Checked as a negated condition across 12+ occurrences in public pages (public/recruitment, public/project, public/eventorganization, core/lib/company.lib.php). When set, the branding block is not rendered.', 'Setting this constant removes the Dolibarr branding footer from all public portal pages; unsetting it restores the notice.', 'Any truthy value hides the branding; unset displays it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:2878|check|if (!getDolGlobalString(''MAIN_HIDE_POWERED_BY'')) {", "public/recruitment/view.php:358|check|if (!getDolGlobalString(''MAIN_HIDE_POWERED_BY'')) {", "public/project/index.php:155|check|if (!getDolGlobalString(''MAIN_HIDE_POWERED_BY'')) {", "public/eventorganization/subscriptionok.php:137|check|if (!getDolGlobalString(''MAIN_HIDE_POWERED_BY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_TOP_MENU', 'bool', NULL, 'core', 'When enabled, hides the top navigation menu bar from the Dolibarr interface.', 'Read in core/class/conf.class.php:1315, the boolean value is cast to int and stored in $this->dol_hide_topmenu. No admin UI page is listed.', 'Enabling this constant removes the top menu from all pages, which can be useful for embedded or kiosk deployments.', '1 = hide top menu; 0 or unset = show top menu.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1315|read|$this->dol_hide_topmenu = (int) (bool) getDolGlobalInt(''MAIN_HIDE_TOP_MENU'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_VERSION', 'bool', NULL, 'core', 'Hides the Dolibarr version number from the page footer.', 'Read in admin/ihm.php:529 as a yes/no select, and checked at main.inc.php:2375 where the version is shown only when this is 0.', 'Setting to 1 suppresses the version display in the footer; setting to 0 or unsetting shows the version.', '0 = version shown (default); 1 = version hidden', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:529|read|print $form->selectyesno(''MAIN_HIDE_VERSION'',$conf->global->MAIN_HIDE_VERSION,1);", "main.inc.php:2375|check|if (!getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'') && getDolGlobalInt(''MAIN_HIDE_VERSION'') == 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HIDE_WARNING_TO_ENCOURAGE_SMTP_SETUP', 'bool', NULL, 'admin', 'Suppresses the warning message that encourages administrators to configure SMTP when the default PHP mail() sender is active.', 'Checked in admin/mails.php:717 and core/menus/standard/eldy.lib.php:1204 paired with MAIN_MAIL_SENDMODE. Set to 1 via dolibarr_set_const in admin/mails.php:140. A comment at admin/mails.php:716 notes the constant is treated as 1 by default if not set.', 'Setting this to 1 hides the SMTP setup nudge from the mail admin page and the navigation menu. Unsetting it restores the warning.', 'Note MAIN_HIDE_WARNING_TO_ENCOURAGE_SMTP_SETUP is set to 1 by default if not set. 1 = hide warning; absent/0 = show warning.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:716  // Note MAIN_HIDE_WARNING_TO_ENCOURAGE_SMTP_SETUP is set to 1 by default if not set", "admin/mails.php:717|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail'') == ''mail'' && getDolGlobalString(''MAIN_HIDE_WARNING_TO_ENCOURAGE_SMTP_SETUP'')) {", "admin/mails.php:140|write|dolibarr_set_const($db, ''MAIN_HIDE_WARNING_TO_ENCOURAGE_SMTP_SETUP'', 1, ''chaine'', 1, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HOME', 'string', NULL, 'admin', 'Stores the HTML content displayed on the Dolibarr home/login page as a custom welcome message.', 'Written via admin/ihm.php:296 using dol_htmlcleanlastbr and restricted HTML input. Read in core/lib/security2.lib.php:286 via make_substitutions and displayed on the login page when set (checked at line 283). Edited in admin/ihm.php:713 via DolEditor.', 'If set to HTML content, that content is rendered on the home/login page after variable substitutions. Clearing it removes the custom welcome message.', 'HTML string with optional substitution variables. Empty/unset = no custom home message.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ihm.php:296|write|dolibarr_set_const($db, \"MAIN_HOME\", dol_htmlcleanlastbr(GETPOST(\"main_home\", ''restricthtml'')), ''chaine'', 0, '''', $conf->entity);", "core/lib/security2.lib.php:283|check|if (getDolGlobalString(''MAIN_HOME'')) {", "core/lib/security2.lib.php:286|read|$texttoshow = make_substitutions(getDolGlobalString(''MAIN_HOME''), $substitutionarray, $langs);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HOME_PAGE', 'string', NULL, 'core', 'Overrides the default home page URL for a user, checked per-user first then falling back to the global constant.', 'Read in core/menus/standard/eldy.lib.php:77 via getDolUserString, meaning a per-user value takes precedence over the global one. No admin UI write detected; must be set manually in the database or conf.php.', 'Changing this value redirects users to a different page upon login. Without it set, the default Dolibarr home page is used.', 'Any valid internal Dolibarr URL path string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:77|read|$homepage = getDolUserString(''MAIN_HOME_PAGE'', getDolGlobalString(''MAIN_HOME_PAGE''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HOOK_DEBUG', 'string', NULL, 'core', 'Enables debug logging for the hook manager, outputting information about hook execution.', 'Checked via getDolGlobalInt at core/class/hookmanager.class.php:322 and 371. When set to a non-zero value, hook invocation details are written to the debug output.', 'Enabling this constant produces verbose hook execution traces useful for module development; it should be disabled in production.', '0 or empty = hook debug disabled; any non-zero integer = hook execution debug output enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/hookmanager.class.php:322|check|if (getDolGlobalInt(''MAIN_HOOK_DEBUG'')) {", "core/class/hookmanager.class.php:371|check|if (getDolGlobalInt(''MAIN_HOOK_DEBUG'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HTML_FOOTER', 'string', NULL, 'core', 'Injects custom HTML content into the footer of Dolibarr pages, including login and authentication pages.', 'Read at core/tpl/login.tpl.php:600, core/tpl/passwordforgotten.tpl.php:349, core/tpl/passwordreset.tpl.php:373, and core/lib/functions.lib.php:13060 where the value is printed directly. Also referenced in a docblock at core/lib/functions.lib.php:13029.', 'When set, the raw HTML string is output at the bottom of the page body on login, password-forgotten, password-reset, and main application pages.', 'Any valid HTML string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:13029  * \t\tconf->global->MAIN_HTML_FOOTER", "core/lib/functions.lib.php:13060|read|print getDolGlobalString(''MAIN_HTML_FOOTER'') . \"\\n\";", "core/tpl/login.tpl.php:600|read|print getDolGlobalString(''MAIN_HTML_FOOTER'');", "core/tpl/passwordforgotten.tpl.php:349|read|print getDolGlobalString(''MAIN_HTML_FOOTER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HTML_HEADER', 'string', NULL, 'core', 'Stores additional HTML content injected into the <head> section of every Dolibarr page.', 'Initialized in main.inc.php:211-212 if unset, appended to via main.inc.php:214 from renderers, and printed in main.inc.php:2129. Five occurrences in one file. No admin UI write is present.', 'Setting this constant causes its content to be output inside the HTML head element on every page, allowing custom meta tags, scripts, or styles to be injected globally.', 'Any valid HTML string intended for the <head> section; unset results in an empty string being used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:211|check|if (!getDolGlobalString(''MAIN_HTML_HEADER'')) {", "main.inc.php:212|write|$conf->global->MAIN_HTML_HEADER = '''';", "main.inc.php:2129|read|print getDolGlobalString(''MAIN_HTML_HEADER'') . \"\\n\";", "main.inc.php:214|read|$conf->global->MAIN_HTML_HEADER .= $renderer->renderHead();"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_HTML_TITLE', 'string', NULL, 'societe', 'Controls the format of the HTML page title by specifying a keyword pattern (e.g. ''projectnameonly'', ''thirdpartynameonly'').', 'Checked across 49 occurrences in project pages (projet/card.php, ganttview.php, note.php, tasks.php, etc.) and other modules, using preg_match to detect keywords such as ''projectnameonly'' or ''thirdpartynameonly''. A comment reference exists at core/class/conf.class.php:1018.', 'When unset, the default composite page title is used. When set to a keyword value, the title is simplified to only the entity name (project name or third-party name).', 'String keyword: ''projectnameonly'' = show only project name in title; ''thirdpartynameonly'' = show only third-party name; empty/unset = default title format.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/ganttview.php:96|check|if (getDolGlobalString(''MAIN_HTML_TITLE'') && preg_match(''/projectnameonly/'', getDolGlobalString(''MAIN_HTML_TITLE'')) && $object->name) {", "societe/project.php:129|check|if (getDolGlobalString(''MAIN_HTML_TITLE'') && preg_match(''/thirdpartynameonly/'', getDolGlobalString(''MAIN_HTML_TITLE'')) && $object->name) {", "projet/card.php:640|check|if (getDolGlobalString(''MAIN_HTML_TITLE'') && preg_match(''/projectnameonly/'', getDolGlobalString(''MAIN_HTML_TITLE''))) {", "// MAIN_HTML_TITLE"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IBAN_IS_NEVER_MANDATORY', 'string', NULL, 'compta', 'Makes the IBAN field optional on bank accounts regardless of country-level validation rules.', 'When set, the IBAN validation that would otherwise make the field mandatory is skipped. Checked twice in compta/bank/class/account.class.php:1793 and :1848.', 'Enabling this allows saving bank accounts without providing an IBAN, overriding any mandatory validation. Disabling restores normal IBAN requirements.', '0 or empty = IBAN may be mandatory per normal rules; non-empty = IBAN is never mandatory', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:1793|check|if (getDolGlobalString(''MAIN_IBAN_IS_NEVER_MANDATORY'')) {", "compta/bank/class/account.class.php:1848|check|if (getDolGlobalString(''MAIN_IBAN_IS_NEVER_MANDATORY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IGNORE_CONTACTS_ON_CLONING', 'string', NULL, 'comm', 'Skips copying contacts when cloning a proposal.', 'Checked in comm/propal/class/propal.class.php:1605; when truthy, the contact-duplication step is bypassed during proposal cloning. Only one occurrence found; no admin UI.', 'When set, cloned proposals will not inherit the contacts from the source proposal.', 'Truthy integer/string (contacts not copied) or empty/unset (contacts copied).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:1605|check|if (!$error && !getDolGlobalInt(''MAIN_IGNORE_CONTACTS_ON_CLONING'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IHM_CUSTOM_CSS', 'string', NULL, 'admin', 'Stores custom CSS content that is injected into every page of the Dolibarr interface.', 'When set, custom CSS is output directly into page responses via theme/custom.css.php:58. It is written via admin/ihm.php:341 and read in main.inc.php:1970 before being applied. Configurable through the admin UI at admin/ihm.php.', 'Changing this value immediately affects the visual appearance of all pages. Clearing it removes any custom CSS overrides.', 'Any valid CSS string; empty or unset means no custom CSS is applied.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/custom.css.php:58|read|print getDolGlobalString(''MAIN_IHM_CUSTOM_CSS'');", "main.inc.php:1970|check|if (getDolGlobalString(''MAIN_IHM_CUSTOM_CSS'')) {", "admin/ihm.php:341|write|dolibarr_set_const($db, \"MAIN_IHM_CUSTOM_CSS\", $csscontent, ''chaine'', 0, '''', $conf->entity);", "admin/ihm.php:757|read|$customcssValue = getDolGlobalString(''MAIN_IHM_CUSTOM_CSS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IHM_PARAMS_REV', 'string', NULL, 'modulebuilder', 'An integer revision counter incremented whenever UI/IHM parameters or module configurations are changed.', 'Incremented by dolibarr_set_const in admin/ihm.php (lines 93, 119, 270, 349) and admin/modules.php (lines 428, 452, 460, 469) whenever UI settings change. Refreshed before forging parameter lines as noted at main.inc.php:1792.', 'Incrementing this value forces browsers to reload cached UI assets; it is managed automatically by the admin interface.', 'Integer; auto-incremented on each UI parameter save', 0, 0, 'admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/modules.php|admin/modules.php|admin/modules.php|admin/modules.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/modules.php|admin/modules.php|admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1792  // Refresh value of MAIN_IHM_PARAMS_REV before forging the parameter line.", "admin/ihm.php:93|write|dolibarr_set_const($db, \"MAIN_IHM_PARAMS_REV\", getDolGlobalInt(''MAIN_IHM_PARAMS_REV'') + 1, ''chaine'', 0, '''', $conf->entity);", "admin/modules.php:428|write|dolibarr_set_const($db, \"MAIN_IHM_PARAMS_REV\", getDolGlobalInt(''MAIN_IHM_PARAMS_REV'') + 1, ''chaine'', 0, '''', $conf->entity);", "admin/modules.php:469|write|dolibarr_set_const($db, \"MAIN_IHM_PARAMS_REV\", (getDolGlobalInt(''MAIN_IHM_PARAMS_REV'') + 1), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IMAGE_PUBLIC_PAYMENT', 'string', NULL, 'public', 'Specifies the URL of an image displayed on public payment pages (new payment, payment OK, payment KO).', 'Checked and read at public/payment/newpayment.php:1056-1058, public/payment/paymentok.php:279-281, and public/payment/paymentko.php:315-317; when set, an img element is rendered with this URL as the src. No admin UI write found.', 'When set, the specified image is shown on all public payment status pages; when unset, no image is displayed.', 'A URL string pointing to an image; empty/unset means no image is shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/paymentko.php:315|check|if (getDolGlobalString(''MAIN_IMAGE_PUBLIC_PAYMENT'')) {", "public/payment/newpayment.php:1058|read|print ''<img id=\"idMAIN_IMAGE_PUBLIC_PAYMENT\" src=\"''.getDolGlobalString(''MAIN_IMAGE_PUBLIC_PAYMENT'').''\">'';", "public/payment/paymentok.php:281|read|print ''<img id=\"idMAIN_IMAGE_PUBLIC_PAYMENT\" src=\"'' . getDolGlobalString(''MAIN_IMAGE_PUBLIC_PAYMENT'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_IMAP_USE_PHPIMAP', 'bool', NULL, 'emailcollector', 'Switches the email collector to use the PHP IMAP library instead of the native IMAP extension.', 'Documented at admin/emailcollector_list.php:781: ''MAIN_IMAP_USE_PHPIMAP: Enable use of the PHP Imap library''. Configured via a selectarray in admin/emailcollector_list.php:791 and checked throughout emailcollector/class/emailcollector.class.php at 8+ locations to branch all IMAP connection and mail-fetch logic.', 'Enabling this constant causes all email collection operations to use the PHP IMAP library code path instead of native IMAP functions; disabling it uses the native path.', 'Any truthy value enables the PHP IMAP library; 0 or unset uses native IMAP.', 0, 0, 'admin/emailcollector_card.php|admin/emailcollector_card.php|admin/emailcollector_list.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/emailcollector_list.php:781  // MAIN_IMAP_USE_PHPIMAP: Enable use of the PHP Imap library", "admin/emailcollector_list.php:791|read|print $form->selectarray(\"MAIN_IMAP_USE_PHPIMAP\", $arrval, getDolGlobalString(\"MAIN_IMAP_USE_PHPIMAP\"));", "emailcollector/class/emailcollector.class.php:1210|check|if (getDolGlobalString(''MAIN_IMAP_USE_PHPIMAP'')) {", "admin/emailcollector_card.php:613|read|$morehtml = $form->textwithpicto($langs->trans(\"NbOfEmailsInInbox\"), ''Connect string = ''.$connectstringserver.''<br>Option MAIN_IMAP_USE_PHPIMAP = ''.getDolGlobalInt(''MAIN_IMAP_USE_P"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD', 'string', NULL, 'theme', 'When enabled (together with MAIN_DISABLE_GLOBAL_BOXSTATS being unset), shows the global statistics box inside the opened dashboard.', 'Checked in theme/eldy/info-box.inc.php:254 and theme/md/info-box.inc.php:400, always in conjunction with the negation of MAIN_DISABLE_GLOBAL_BOXSTATS. No admin UI write path is present in the payload.', 'Enabling this constant (while MAIN_DISABLE_GLOBAL_BOXSTATS is unset) causes the global statistics box to be rendered in the dashboard. Leaving it unset suppresses the box regardless of MAIN_DISABLE_GLOBAL_BOXSTATS.', 'Truthy value to show global stats box in dashboard; unset or 0 to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/info-box.inc.php:254|check|<?php if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_BOXSTATS'') && getDolGlobalString(''MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD'')) { ?>", "theme/md/info-box.inc.php:400|check|<?php if (!getDolGlobalString(''MAIN_DISABLE_GLOBAL_BOXSTATS'') && getDolGlobalString(''MAIN_INCLUDE_GLOBAL_STATS_IN_OPENED_DASHBOARD'')) { ?>"]', 'medium', NULL);
