INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_CONTRACT_TERMSOFSALE', 'string', NULL, 'core', 'Stores the filename of the terms-of-sale document to be concatenated into contract PDFs.', 'The filename value is read at admin/pdf_other.php:457 and core/modules/contract/doc/pdf_strato.modules.php:495 when both this constant and MAIN_PDF_ADD_TERMSOFSALE_CONTRACT are set. Also displayed as a tooltip in contrat/card.php:2393. Configurable via admin/pdf_other.php.', 'Setting this to a valid filename causes that file to be appended to generated contract PDFs when MAIN_PDF_ADD_TERMSOFSALE_CONTRACT is also enabled.', 'A filename string pointing to the terms-of-sale document; empty/unset = no terms file concatenated.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf_other.php:457|read|$termofsale = getDolGlobalString(\"MAIN_INFO_CONTRACT_TERMSOFSALE\");", "core/modules/contract/doc/pdf_strato.modules.php:494|check|if (getDolGlobalString(''MAIN_INFO_CONTRACT_TERMSOFSALE'') && getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_CONTRACT'')) {", "core/modules/contract/doc/pdf_strato.modules.php:495|read|$termsofsalefilename = getDolGlobalString(''MAIN_INFO_CONTRACT_TERMSOFSALE'');", "contrat/card.php:2393|read|$tooltipAfterComboOfModels = $langs->trans(\"AccordingToYourSetupTheFileWillBeConcatenated\", getDolGlobalString(''MAIN_INFO_CONTRACT_TERMSOFSALE''));"]', 'high', NULL);
