INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_LOCALTAX_CALC', 'string', NULL, 'compta', 'Specifies a prefix or calculation mode code used when building the local tax calculation identifier in tax reports.', 'Read in compta/localtax/quadri_detail.php:91 and compta/localtax/clients.php:138, where its value is concatenated with the $local variable to form the $calc identifier used in local tax report queries. No admin UI write path is present in the payload.', 'Changing this value alters the calculation mode prefix used in local tax report queries, which affects which tax data is retrieved and displayed.', 'String prefix code concatenated with the local tax type identifier (e.g. ''1'' or ''2'') to form the calc mode selector.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/localtax/quadri_detail.php:91|read|$calc = getDolGlobalString(''MAIN_INFO_LOCALTAX_CALC'').$local;", "compta/localtax/clients.php:138|read|$calc = getDolGlobalString(''MAIN_INFO_LOCALTAX_CALC'').$local;"]', 'medium', NULL);
