INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_COUNTRY', 'string', NULL, 'societe', 'Stores the company''s country identifier (format ''id:code:label'') used for setup validation and SEPA generation.', 'Written via admin/company.php:103. Checked in admin/index.php:86, core/redirect_if_setup_not_complete.inc.php:41, hrm/index.php:80, and core/menus/standard/eldy.lib.php:1179 to detect incomplete setup. Read in societe/class/societe.class.php:4807 and bonprelevement.class.php:2690 by exploding on '':'' to extract the country code. Configured via admin/company.php.', 'Without this constant the setup is considered incomplete and users are redirected; the country code extracted from it is used in third-party address logic and SEPA XML generation.', 'String in ''id:code:label'' format (e.g. ''1:FR:France'')', 0, 0, 'admin/index.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:103|write|dolibarr_set_const($db, \"MAIN_INFO_SOCIETE_COUNTRY\", $s, ''chaine'', 0, '''', $conf->entity);", "core/redirect_if_setup_not_complete.inc.php:41|check|if (!getDolGlobalString(''MAIN_INFO_SOCIETE_NOM'') || !getDolGlobalString(''MAIN_INFO_SOCIETE_COUNTRY'')) {", "societe/class/societe.class.php:4807|read|$tmp = explode('':'', getDolGlobalString(''MAIN_INFO_SOCIETE_COUNTRY''));", "compta/prelevement/class/bonprelevement.class.php:2690|read|$country = explode('':'', getDolGlobalString(''MAIN_INFO_SOCIETE_COUNTRY''));"]', 'high', NULL);
