INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_LOGO_NO_BACKGROUND', 'string', NULL, 'core', 'Selects the company logo variant without background for use in menu banners.', 'Checked in core/menus/standard/auguria.lib.php:167 and core/menus/standard/eldy.lib.php:584. When set, the no-background logo is used in the top menu area instead of the standard logo.', 'Setting this constant switches the displayed company logo to the transparent/no-background version in the Auguria and Eldy menu themes.', 'Non-empty = no-background logo used; empty or unset = standard logo used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/auguria.lib.php:167|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_NO_BACKGROUND'')) {", "core/menus/standard/eldy.lib.php:584|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_NO_BACKGROUND'')) {"]', 'medium', NULL);
