INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_LOGO_SQUARRED', 'string', NULL, 'theme', 'Stores the filename of the company''s square-format logo image.', 'Checked and read across theme/eldy/manifest.json.php and theme/md/manifest.json.php (lines 111, 139, 142-143 in eldy; 108, 139-140 in md) to use as PWA icon. Read in societe/class/societe.class.php at line 4905. A comment notes: ''Logo is inside MAIN_INFO_SOCIETE_LOGO_SQUARRED/_MINI/_SMALL else MAIN_INFO_SOCIETE_LOGO/_MINI/_SMALL''.', 'Changing this constant changes the square logo used as the PWA manifest icon in the eldy and md themes.', 'Filename string of the square logo image stored in the logos/ directory', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/multicompany_page.php:131  // Logo is inside MAIN_INFO_SOCIETE_LOGO_SQUARRED/_MINI/_SMALL else MAIN_INFO_SOCIETE_LOGO/_MINI/_SMALL", "theme/eldy/manifest.json.php:143|read|$iconRelativePath = ''logos/'' . getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED'');", "theme/md/manifest.json.php:140|read|$iconRelativePath = ''logos/'' . getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED'');", "societe/class/societe.class.php:4905|read|$this->logo_squarred = getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI', 'string', NULL, 'theme', 'Stores the filename of the company''s mini square-format logo image used in menus and PWA icons.', 'Read in societe/class/societe.class.php at line 4907, core/menus/standard/auguria.lib.php at line 164, and core/menus/standard/eldy.lib.php at line 581. Checked and read in theme/eldy/manifest.json.php (lines 112-113) and theme/md/manifest.json.php (lines 109-110) for PWA icon selection.', 'Changing this constant changes the mini square logo used in menu rendering and as the primary PWA manifest icon in the eldy and md themes.', 'Filename string of the mini square logo image stored in the logos/thumbs/ directory', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/menus/standard/auguria.lib.php:164|read|$mysoc->logo_squarred_mini = (!getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI'') ? '''' : $conf->global->MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI);", "core/menus/standard/eldy.lib.php:581|read|$mysoc->logo_squarred_mini = getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI'');", "theme/eldy/manifest.json.php:113|read|$iconRelativePath = ''logos/thumbs/'' . getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI'');", "societe/class/societe.class.php:4907|read|$this->logo_squarred_mini = getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO_SQUARRED_MINI'');"]', 'high', NULL);
