INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_MAIL', 'string', NULL, 'public', 'Stores the company email address used as the default sender and for mail configuration checks.', 'Set via admin/company.php:131 and admin/mails.php. Read and displayed in admin/mails.php:646-647 and 931 as the ''CompanyEmail'' option. Used at core/class/html.formmail.class.php:714 and admin/mails.php:1101 to extract the sender domain for mail tests. Referenced in 36 occurrences across admin and core files.', 'When not set, mail configuration checks warn about a missing company email and the sender domain cannot be determined. When set, it serves as the default company sender address throughout the mailing system.', 'String (valid email address); empty/unset = no default company email configured.', 0, 0, 'admin/company.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:131|write|dolibarr_set_const($db, \"MAIN_INFO_SOCIETE_MAIL\", GETPOST(\"mail\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails.php:646|read|''label'' => $langs->trans(''CompanyEmail'').'' (''.getDolGlobalString(''MAIN_INFO_SOCIETE_MAIL'', $langs->trans(\"NotDefined\")).'')'',", "admin/mails.php:1100|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_MAIL'')) {", "core/class/html.formmail.class.php:714|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_MAIL'')) {"]', 'high', NULL);
