INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_TOWN', 'string', NULL, 'compta', 'Stores the company''s city/town name used in SEPA XML address lines and the application footer.', 'Configured via admin/company.php (written at line 124). Read in compta/prelevement/class/bonprelevement.class.php (lines 2722, 2746, 2788, 2812) alongside ZIP to compose address lines, and in societe/class/societe.class.php:4794 to set the company town property.', 'Changing this value updates the city displayed in the application footer and embedded in SEPA XML payment files.', 'Free-form string (city or town name).', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:124|write|dolibarr_set_const($db, \"MAIN_INFO_SOCIETE_TOWN\", GETPOST(\"MAIN_INFO_SOCIETE_TOWN\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "compta/prelevement/class/bonprelevement.class.php:2722|read|$addressline2 = strtr(getDolGlobalString(''MAIN_INFO_SOCIETE_ZIP'') . (... ? '' '' : '''') ...", "societe/class/societe.class.php:4794|read|$this->town = getDolGlobalString(''MAIN_INFO_SOCIETE_TOWN'');", "main.inc.php:3515|read|print ''<tr><td>''.dol_escape_htmltag(getDolGlobalString(''MAIN_INFO_SOCIETE_ADDRESS'')).''<br>''.dol_escape_htmltag(getDolGlobalString(''MAIN_INFO_SOCIETE_ZIP''))..."]', 'high', NULL);
