INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_WEB', 'string', NULL, 'core', 'Stores the website URL of the company.', 'Written via admin/company.php at line 132. Read in societe/class/societe.class.php at line 4855 and displayed in the page footer via main.inc.php at lines 3522-3523.', 'Changing this constant updates the company website URL shown in the admin interface and page footer.', 'URL string', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:132|write|dolibarr_set_const($db, \"MAIN_INFO_SOCIETE_WEB\", GETPOST(\"web\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "main.inc.php:3522|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_WEB'')) {", "main.inc.php:3523|read|print ''<tr><td style=\"padding-left: 1em\" class=\"small\">''.$langs->trans(\"Web\").'' : ''.dol_escape_htmltag(getDolGlobalString(''MAIN_INFO_SOCIETE_WEB'')).''</td></tr>'';", "societe/class/societe.class.php:4855|read|$this->url = getDolGlobalString(''MAIN_INFO_SOCIETE_WEB'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_YOUTUBE_URL', 'string', NULL, 'societe', 'Stores the YouTube URL of the company.', 'Read in societe/class/societe.class.php at line 4862 to populate the youtube_url property. No admin UI write was found in the payload.', 'Changing this constant updates the company YouTube URL used in company records.', 'YouTube URL string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4862|read|$youtube_url = getDolGlobalString(''MAIN_INFO_SOCIETE_YOUTUBE_URL'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_SOCIETE_ZIP', 'string', NULL, 'compta', 'Stores the company''s postal/ZIP code used in SEPA XML address lines and the application footer.', 'Configured via admin/company.php (written at line 125). Read in compta/prelevement/class/bonprelevement.class.php (lines 2722, 2746, 2788, 2812) to compose address lines in SEPA XML, and in societe/class/societe.class.php:4793 to set the company zip property.', 'Changing this value updates the ZIP code shown in the application footer and included in SEPA XML payment file address lines.', 'Free-form string (postal/ZIP code).', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:125|write|dolibarr_set_const($db, \"MAIN_INFO_SOCIETE_ZIP\", GETPOST(\"MAIN_INFO_SOCIETE_ZIP\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "compta/prelevement/class/bonprelevement.class.php:2746|read|$XML_SEPA_INFO .= ''<AdrLine>''.dolEscapeXML(dol_trunc(dol_string_nospecial(dol_string_unaccent(getDolGlobalString(''MAIN_INFO_SOCIETE_ZIP'')...", "societe/class/societe.class.php:4793|read|$this->zip = getDolGlobalString(''MAIN_INFO_SOCIETE_ZIP'');", "main.inc.php:3515|read|print ''<tr><td>''.dol_escape_htmltag(getDolGlobalString(''MAIN_INFO_SOCIETE_ADDRESS'')).''<br>''.dol_escape_htmltag(getDolGlobalString(''MAIN_INFO_SOCIETE_ZIP''))..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_TVAINTRA', 'string', NULL, 'admin', 'Stores the company''s intra-community VAT number used across tax forms and third-party records.', 'Written via admin/taxes.php (line 137) and admin/company.php (line 239). Read in societe/class/societe.class.php:4895 (`$this->tva_intra = getDolGlobalString(''MAIN_INFO_TVAINTRA''); // VAT number, not necessarily INTRA.`), used in the Greek VAT check (checkVatGr.php:30) and displayed in the top-bar dropdown (main.inc.php:2487).', 'Changing this value updates the company VAT number shown in documents, the top-bar info panel, and used in VAT cross-checks.', 'String (VAT number, e.g. ''FR12345678901''); empty means no VAT number is configured.', 0, 0, 'admin/company.php|admin/taxes.php|admin/taxes.php|admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4895|read|$this->tva_intra = getDolGlobalString(''MAIN_INFO_TVAINTRA''); // VAT number, not necessarily INTRA.", "societe/checkvat/checkVatGr.php:30|read|$myafm = preg_replace(''/\\D/'', '''', getDolGlobalString(''MAIN_INFO_TVAINTRA'')); // Get Vat from request after removing non-digit characters", "admin/taxes.php:137|write|dolibarr_set_const($db, \"MAIN_INFO_TVAINTRA\", GETPOST(\"tva\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "main.inc.php:2487|read|$dropdownBody .= ''<br><b>''.$langs->trans(\"VATIntraShort\").''</b>: <span>''.dol_print_profids(getDolGlobalString(\"MAIN_INFO_TVAINTRA\"), ''VAT'').''</span>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_TVA_DAY_DEADLINE_SUBMISSION', 'string', NULL, 'admin', 'Stores the day-of-month deadline for VAT submission as configured in the tax settings admin page.', 'Written via dolibarr_set_const in admin/taxes.php:141 from the POST field ''deadline_day_vat'', and displayed in the form at admin/taxes.php:209 with a placeholder showing '':21''. The admin UI is admin/taxes.php.', 'Changing this value updates the configured VAT submission deadline day displayed and used within tax administration workflows.', 'A day-of-month integer (e.g. 21); empty or unset means no deadline configured.', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/taxes.php:141|write|dolibarr_set_const($db, \"MAIN_INFO_TVA_DAY_DEADLINE_SUBMISSION\", GETPOSTINT(\"deadline_day_vat\"), ''chaine'', 0, '''', $conf->entity);", "admin/taxes.php:209|read|print ''<input placeholder=\"''.$langs->trans(\"Example\").'':21\" name=\"deadline_day_vat\" id=\"deadline_day_vat\" class=\"minwidth200\" value=\"''.getDolGlobalString(''MAIN_INFO_TVA_DAY_DEADLIN"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_VALUE_LOCALTAX1', 'string', NULL, 'admin', 'Stores the company-level local tax 1 (IRPF or equivalent) rate configured in the admin company setup.', 'Written via admin/company.php:263 (reset to 0) and 265 (set from POST ''lt1''). Read at core/lib/functions.lib.php:8144 to return the local tax 1 rate. Managed through admin/company.php UI.', 'Changing this value alters the local tax 1 rate applied in tax calculations for the entity.', 'Numeric string representing the local tax 1 rate; 0 = no local tax 1', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/company.php:263|write|dolibarr_set_const($db, \"MAIN_INFO_VALUE_LOCALTAX1\", 0, ''chaine'', 0, '''', $conf->entity);", "admin/company.php:265|write|dolibarr_set_const($db, \"MAIN_INFO_VALUE_LOCALTAX1\", GETPOST(''lt1'', ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "core/lib/functions.lib.php:8144|read|return getDolGlobalString(''MAIN_INFO_VALUE_LOCALTAX1'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_VALUE_LOCALTAX2', 'string', NULL, 'admin', 'Stores the company-level local tax 2 rate configured in the admin company setup.', 'Written via admin/company.php:271 (reset to 0) and 273 (set from POST ''lt2''). Read at core/lib/functions.lib.php:8158 to return the local tax 2 rate. Managed through admin/company.php UI.', 'Changing this value alters the local tax 2 rate applied in tax calculations for the entity.', 'Numeric string representing the local tax 2 rate; 0 = no local tax 2', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/company.php:271|write|dolibarr_set_const($db, \"MAIN_INFO_VALUE_LOCALTAX2\", 0, ''chaine'', 0, '''', $conf->entity);", "admin/company.php:273|write|dolibarr_set_const($db, \"MAIN_INFO_VALUE_LOCALTAX2\", GETPOST(''lt2'', ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "core/lib/functions.lib.php:8158|read|return getDolGlobalString(''MAIN_INFO_VALUE_LOCALTAX2'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INFO_VAT_RETURN', 'string', NULL, 'compta', 'Specifies the VAT return frequency, used to compute default date ranges on VAT reports.', 'Written via admin/taxes.php (line 139) and shown as a select array (line 203). Read in compta/tva/initdatesforvat.inc.php to branch date logic: line 54 checks for value 2 (quarterly), line 57 for value 3 (yearly), and line 69 for value 1 (monthly).', 'Changing this value alters the default date range pre-filled on VAT declaration forms to match the selected reporting frequency.', '1 = monthly; 2 = quarterly; 3 = yearly; empty or 2 = quarterly (default).', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:139|write|dolibarr_set_const($db, \"MAIN_INFO_VAT_RETURN\", GETPOST(\"MAIN_INFO_VAT_RETURN\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "compta/tva/initdatesforvat.inc.php:54|check|if (!getDolGlobalString(''MAIN_INFO_VAT_RETURN'') || getDolGlobalInt(''MAIN_INFO_VAT_RETURN'') == 2) { // quaterly vat, we take last past complete quarter", "compta/tva/initdatesforvat.inc.php:57|read|} elseif (getDolGlobalInt(''MAIN_INFO_VAT_RETURN'') == 3) { // yearly vat", "compta/tva/initdatesforvat.inc.php:69|read|} elseif (getDolGlobalInt(''MAIN_INFO_VAT_RETURN'') == 1) {\t// monthly vat, we take last past complete month"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INPUT_DESC_HEIGHT', 'string', NULL, 'core', 'Sets the number of rows for description textarea inputs across several modules.', 'When set, the integer value is used as the row count ($nbrows) for description textareas in projet/tasks.php, contrat/card.php, and core/tpl/objectline_create.tpl.php and objectline_edit.tpl.php. Read at projet/tasks/task.php:568 via getDolGlobalInt with a default of 0.', 'Without this constant, description textareas use their default height. Setting it overrides the row count in all affected pages.', 'Integer (number of rows); 0 or unset = default height.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/task.php:568|read|$nbrows = getDolGlobalInt(''MAIN_INPUT_DESC_HEIGHT'', 0);", "projet/tasks.php:882|check|if (getDolGlobalString(''MAIN_INPUT_DESC_HEIGHT'')) {", "contrat/card.php:1872|check|if (getDolGlobalString(''MAIN_INPUT_DESC_HEIGHT'')) {", "core/tpl/objectline_create.tpl.php:449|check|if (getDolGlobalString(''MAIN_INPUT_DESC_HEIGHT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_INVERT_SENDER_RECIPIENT', 'string', NULL, 'core', 'Swaps the sender and recipient address block positions in generated PDF documents.', 'Configured via admin/pdf.php:159 and read across 64 occurrences in PDF modules. Also set programmatically in memory at master.inc.php:326 and api/class/api_access.class.php:180, and auto-applied for German companies at master.inc.php:324 when not already set.', 'Enabling this moves the sender address to the left and the recipient to the right (or vice versa) in PDF document headers; the value is automatically set to 1 for German companies.', '0 = sender left, recipient right (default); 1 = sender and recipient positions inverted.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["master.inc.php:324|read|if ($mysoc->country_code == ''DE'' && !isset($conf->global->MAIN_INVERT_SENDER_RECIPIENT)) {", "master.inc.php:326|write|$conf->global->MAIN_INVERT_SENDER_RECIPIENT = 1;", "admin/pdf.php:159|write|dolibarr_set_const($db, \"MAIN_INVERT_SENDER_RECIPIENT\", GETPOST(\"MAIN_INVERT_SENDER_RECIPIENT\"), ''chaine'', 0, '''', $conf->entity);", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:932|check|if (getDolGlobalString(''MAIN_INVERT_SENDER_RECIPIENT'')) $posx = $this->marge_gauche;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_JQUERY_JNOTIFY_BOTTOM', 'string', NULL, 'theme', 'When enabled, positions jQuery jNotify notification popups at the bottom of the screen.', 'Checked in theme/eldy/global.inc.php:7368 and theme/md/style.css.php:7192 to conditionally apply bottom-positioned notification CSS. Two occurrences across two files. No admin UI write is present.', 'Enabling this constant moves notification popups to the bottom of the viewport in both the Eldy and MD themes.', 'Boolean flag; unset or 0 = notifications positioned at default location; any truthy value = notifications at bottom.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:7368|check|<?php if (getDolGlobalString(''MAIN_JQUERY_JNOTIFY_BOTTOM'')) { ?>", "theme/md/style.css.php:7192|check|<?php if (getDolGlobalString(''MAIN_JQUERY_JNOTIFY_BOTTOM'')) { ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_JQUERY_JNOTIFY_UNDER_MENU', 'string', NULL, 'theme', 'When enabled, positions jQuery jNotify notification popups below the menu bar.', 'Checked in theme/eldy/global.inc.php:7372 and theme/md/style.css.php:7196 to conditionally apply under-menu notification positioning CSS. Two occurrences across two files. No admin UI write is present.', 'Enabling this constant moves notification popups to appear beneath the menu bar in both the Eldy and MD themes.', 'Boolean flag; unset or 0 = default notification position; any truthy value = notifications shown under menu.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:7372|check|<?php if (getDolGlobalString(''MAIN_JQUERY_JNOTIFY_UNDER_MENU'')) { ?>", "theme/md/style.css.php:7196|check|<?php if (getDolGlobalString(''MAIN_JQUERY_JNOTIFY_UNDER_MENU'')) { ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_JS_GRAPH', 'string', NULL, 'core', 'Specifies the JavaScript graphing library to use for charts, defaulting to ''chart''.', 'Checked in main.inc.php:2000 to decide whether to load the chart.js library, and read in core/class/dolgraph.class.php:243 to set the active library.', 'Changing this value switches the charting library used for all graphs in Dolibarr.', ''''' or unset = ''chart'' (Chart.js) is used; any other string = that library name is used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2000|check|if (empty($disableforlogin) && (!getDolGlobalString(''MAIN_JS_GRAPH'') || getDolGlobalString(''MAIN_JS_GRAPH'') == ''chart'') && !defined(''DISABLE_JS_GRAPH'')) {", "core/class/dolgraph.class.php:243|read|$this->_library = (!getDolGlobalString(''MAIN_JS_GRAPH'') ? ''chart'' : $conf->global->MAIN_JS_GRAPH);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_JS_SWITCH_AGENDA', 'string', NULL, 'comm', 'Enables JavaScript-based show/hide switching for additional agenda events beyond the displayed limit.', 'Written at runtime to value 1 in comm/action/index.php:1951 and public/bookcal/index.php:612. Read at comm/action/index.php:2031 to decide whether to render additional items, and at :2438 to show a switch link when more items exist.', 'This constant is set programmatically at runtime rather than via configuration; it controls whether overflow agenda entries are rendered with a JS toggle.', '1 = JS switch enabled (set at runtime); empty/unset = no JS switch', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["$conf->global->MAIN_JS_SWITCH_AGENDA = 1;", "if ($i < $maxprint || $maxprint == 0 || getDolGlobalString(''MAIN_JS_SWITCH_AGENDA'')) {", "if (getDolGlobalString(''MAIN_JS_SWITCH_AGENDA'') && $itoshow > $ireallyshown && $maxprint) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_JUMP_TAG', 'string', NULL, 'supplier_proposal', 'Enables URL anchor fragments appended to redirect URLs after actions on document pages, scrolling the browser to a specific section.', 'Checked and read across 9 occurrences including supplier_proposal/card.php (lines 2353, 2377, 2383), comm/propal/card.php (lines 3720, 3593), societe/paymentmodes.php:1713, recruitment/recruitmentjobposition_card.php:434, and compta/paiement/cheque/card.php:273.', 'Enabling this setting appends anchor fragments (e.g. `#builddoc`, `#reopen`, `#close`) to action URLs so the browser scrolls to the relevant section after a page action.', 'Truthy string (non-empty) = anchor fragments added to action URLs; empty/not set = no anchor fragments.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:2353|read|print ''…href=\"''.$_SERVER[\"PHP_SELF\"].''?id=''.$object->id.''&action=reopen&token=''.newToken().(!getDolGlobalString(''MAIN_JUMP_TAG''…", "societe/paymentmodes.php:1713|read|$out .= ''<form action=\"''.$_SERVER[\"PHP_SELF\"].(!getDolGlobalString(''MAIN_JUMP_TAG'') ? '''' : ''#builddoc'').''\" name=\"''.$forname.''\"…", "compta/paiement/cheque/card.php:273|read|header(''Location: ''.$_SERVER[\"PHP_SELF\"].''?id=''.$object->id.(!getDolGlobalString(''MAIN_JUMP_TAG'') ? '''' : ''#builddoc''));", "recruitment/recruitmentjobposition_card.php:434|read|print ''<a class=\"butAction\" href=\"''.$_SERVER[\"PHP_SELF\"].''?id=''.$object->id.''&action=closeas&token=''.newToken().(!getDolGlobalString(''MAIN_JUMP_TAG'') ? '''' : ''#close'').''\"'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_KEEP_REF_CUSTOMER_ON_CLONING', 'string', NULL, 'comm', 'Preserves the customer reference field when cloning a proposal or order.', 'Checked in comm/propal/class/propal.class.php:1504 and :1589, and in commande/class/commande.class.php:1338. When falsy (default), the customer reference is cleared on clone; when set, it is retained.', 'Setting this constant causes cloned proposals and orders to carry the original customer reference, which may create duplicate references in the system.', 'Truthy string (customer ref kept) or empty/unset (customer ref cleared on clone).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:1504|check|if (!getDolGlobalString(''MAIN_KEEP_REF_CUSTOMER_ON_CLONING'')) {", "comm/propal/class/propal.class.php:1589|check|if (!getDolGlobalString(''MAIN_KEEP_REF_CUSTOMER_ON_CLONING'')) {", "commande/class/commande.class.php:1338|check|if (!getDolGlobalString(''MAIN_KEEP_REF_CUSTOMER_ON_CLONING'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LANDING_PAGE', 'string', NULL, 'user', 'Defines the default landing page URL that users are redirected to after login.', 'Read in main.inc.php:1106 and core/menus/standard/eldy.lib.php:1155 as a fallback when no user-level override is set. Also displayed in user/param_ihm.php:442 and :564 as the global default.', 'Setting this redirects all users without a personal landing-page preference to the specified URL after login.', 'Any valid Dolibarr-relative URL string; empty/unset = use system default', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1106|read|$landingpage = getDolUserString(''MAIN_LANDING_PAGE'', getDolGlobalString(''MAIN_LANDING_PAGE''));", "core/menus/standard/eldy.lib.php:1155|read|$landingpage = getDolUserString(''MAIN_LANDING_PAGE'', getDolGlobalString(''MAIN_LANDING_PAGE''));", "user/param_ihm.php:564|read|print(!getDolGlobalString(''MAIN_LANDING_PAGE'') ? '''' : $conf->global->MAIN_LANDING_PAGE);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LANGUAGES_ALLOWED', 'bool', NULL, 'core', 'Restricts the list of languages available to those explicitly listed, filtering out all others.', 'Checked in core/class/translate.class.php:946. The inline comment at line 945 states: ''We must keep only languages into MAIN_LANGUAGES_ALLOWED''. When set, only language codes present in the comma-separated list are kept. No admin UI write is present.', 'When set, only the specified language codes are available in the system, preventing users from selecting unlisted languages. When unset, all languages are available.', 'Comma-separated list of language codes (e.g. ''fr_FR,en_US''); empty or unset to allow all languages.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/translate.class.php:945  // We must keep only languages into MAIN_LANGUAGES_ALLOWED", "core/class/translate.class.php:946|check|if (getDolGlobalString(''MAIN_LANGUAGES_ALLOWED'') && !in_array($dir, explode('','', getDolGlobalString(''MAIN_LANGUAGES_ALLOWED'')))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LANG_DEFAULT', 'string', NULL, 'webservices', 'Sets the default language/locale for the Dolibarr instance.', 'Configurable via admin/ihm.php, admin/website.php, and admin/dict.php UI. Read in master.inc.php:307 and api/class/api_access.class.php:211 as the fallback language when no user or request language is specified. The modulebuilder template comments show ''auto'' as a valid value meaning automatic detection.', 'Changing this affects the language used for all users who have not set a personal language preference, including API responses and public pages.', 'Language code string (e.g. ''fr_FR'', ''en_US'') or ''auto'' for automatic detection', 0, 0, 'admin/ihm.php|admin/website.php|admin/dict.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/myobject_list.php:29  //if (! defined(''MAIN_LANG_DEFAULT''))        define(''MAIN_LANG_DEFAULT'', ''auto'');\t\t\t\t\t// Force LANG (language) to a particular value", "master.inc.php:307|read|$langcode = (GETPOST(''lang'', ''aZ09'') ? GETPOST(''lang'', ''aZ09'', 1) : getDolGlobalString(''MAIN_LANG_DEFAULT'', ''auto''));", "admin/ihm.php:269|write|dolibarr_set_const($db, \"MAIN_LANG_DEFAULT\", GETPOST(\"MAIN_LANG_DEFAULT\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "api/class/api_access.class.php:211|read|$langcode = getDolGlobalString(''MAIN_LANG_DEFAULT'', ''auto'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LASTBOX_ON_OBJECT_DATE', 'string', NULL, 'core', 'Sorts dashboard ''last records'' boxes by the object''s own date instead of the modification date.', 'Checked in at least 8 box files (box_propales.php:105, box_commandes.php:120, box_factures_fourn.php:107, box_supplier_orders.php:102, box_contracts.php:94, box_factures.php:112, box_supplier_orders_awaiting_reception.php:98). The title text at box_propales.php:77 switches from ''LastModified'' to ''Last'' based on this constant.', 'Enabling this causes the last-records dashboard widgets to order by the document date rather than the last-modified timestamp, changing which records appear at the top.', 'Empty/not set = sort by modification date; any truthy string = sort by object date', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_propales.php:105|check|if (getDolGlobalString(''MAIN_LASTBOX_ON_OBJECT_DATE'')) {", "core/boxes/box_commandes.php:120|check|if (getDolGlobalString(''MAIN_LASTBOX_ON_OBJECT_DATE'')) {", "core/boxes/box_propales.php:77|read|$text = $langs->trans(\"BoxTitleLast\".(getDolGlobalString(''MAIN_LASTBOX_ON_OBJECT_DATE'') ? \"\" : \"Modified\").\"Propals\", $max);", "core/boxes/box_factures.php:112|check|if (getDolGlobalString(''MAIN_LASTBOX_ON_OBJECT_DATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LAST_PING_KO_DATE', 'string', NULL, 'core', 'Records the date and time of the most recent failed ping attempt to Dolibarr''s registration/ping service.', 'Written automatically by the AJAX handler at core/ajax/pingresult.php when a ping fails; the comment notes it erases the last value. Not set via the admin UI.', 'This is a system-recorded timestamp; modifying it would misrepresent when the instance last experienced a ping failure.', 'Date string in ''dayhourlog'' GMT format (e.g. ''20240101120000'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/ajax/pingresult.php:93|write|dolibarr_set_const($db, ''MAIN_LAST_PING_KO_DATE'', dol_print_date($now, ''dayhourlog'', ''gmt''), ''chaine'', 0, '''', $conf->entity); // erase last value"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LAST_REGISTRATION_KO_DATE', 'string', NULL, 'core', 'Records the date and time of the most recent failed registration attempt to Dolibarr''s ping/registration service.', 'Written automatically by the AJAX handler at core/ajax/pingresult.php when registration fails; the comment notes it erases the last value. Not set via the admin UI.', 'This is a system-recorded timestamp; modifying it would misrepresent when the instance last experienced a registration failure.', 'Date string in ''dayhourlog'' GMT format (e.g. ''20240101120000'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/ajax/pingresult.php:105|write|dolibarr_set_const($db, ''MAIN_LAST_REGISTRATION_KO_DATE'', dol_print_date($now, ''dayhourlog'', ''gmt''), ''chaine'', 0, '''', $conf->entity); // erase last value"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LEGALFORM_IN_ADDRESS', 'string', NULL, 'core', 'Controls whether the recipient company''s legal form code is appended to the address block on PDF documents.', 'Checked at core/lib/pdf.lib.php:674; when truthy and the target company has a legal form code, it is appended to the address string. No admin UI write is present; must be set manually.', 'Enabling this adds the legal form code to the recipient address on generated PDFs.', 'Truthy string (non-empty) = include legal form in address; absent/empty = omit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:674|check|if (getDolGlobalString(''MAIN_LEGALFORM_IN_ADDRESS'') && !empty($targetcompany->forme_juridique_code)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIMIT_FOR_MASS_ACTIONS', 'string', NULL, 'core', 'Maximum number of records that can be processed in a single mass action operation.', 'Read in core/actions_massactions.inc.php:127 and eventorganization/core/actions_massactions_mail.inc.php:72, both with a fallback default of 1000 into $maxformassaction. No admin UI page is listed.', 'Lowering this value prevents excessively large mass actions that could overload the server; raising it allows larger batches, defaulting to 1000 if unset.', 'Integer record count. Default fallback is 1000.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_massactions.inc.php:127|read|$maxformassaction = getDolGlobalInt(''MAIN_LIMIT_FOR_MASS_ACTIONS'', 1000);", "eventorganization/core/actions_massactions_mail.inc.php:72|read|$maxformassaction = getDolGlobalInt(''MAIN_LIMIT_FOR_MASS_ACTIONS'', 1000);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_ALLOW_PRIVATE_NOTES', 'bool', NULL, 'expedition', 'Controls whether the private notes column is available (enabled) in shipment and order list views.', 'Read in expedition/list.php:161 and commande/list_det.php:234: the ''NotePrivate'' column''s ''enabled'' flag is set to the inverse of this constant. When the constant is truthy the column is disabled; when falsy the column is enabled.', 'Enabling this constant removes the private notes column from the list views; disabling restores it.', 'Truthy (non-empty) = private notes column disabled in lists; empty/unset = column enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/list.php:161|read|''enabled'' => (string) (int) (!getDolGlobalString(''MAIN_LIST_ALLOW_PRIVATE_NOTES'')), ''position'' => 140),", "commande/list_det.php:234|read|''enabled'' => (string) (int) (!getDolGlobalString(''MAIN_LIST_ALLOW_PRIVATE_NOTES'')), ''position'' => 140),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_ALLOW_PUBLIC_NOTES', 'bool', NULL, 'expedition', 'Controls whether the public notes column is available (enabled) in shipment and order list views.', 'Read in expedition/list.php:160 and commande/list_det.php:233: the ''NotePublic'' column''s ''enabled'' flag is set to the inverse of this constant. When the constant is truthy the column is disabled; when falsy the column is enabled.', 'Enabling this constant removes the public notes column from the list views; disabling restores it.', 'Truthy (non-empty) = public notes column disabled in lists; empty/unset = column enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/list.php:160|read|''enabled'' => (string) (int) (!getDolGlobalString(''MAIN_LIST_ALLOW_PUBLIC_NOTES'')), ''position'' => 135),", "commande/list_det.php:233|read|''enabled'' => (string) (int) (!getDolGlobalString(''MAIN_LIST_ALLOW_PUBLIC_NOTES'')), ''position'' => 135),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_FILTER_ON_DAY', 'string', NULL, 'compta', 'When enabled, date filter inputs on list views include a day field in addition to month and year.', 'Commented out in core/class/conf.class.php:906 with the note that it adds a day input field to date filters. Checked in compta/deplacement/list.php:176 to conditionally apply day-level filtering.', 'Enabling this constant makes date range filters on list views include a day selector. Leaving it unset restricts date filters to month/year granularity.', '1 = show day input field on date filters; unset or 0 = day field not shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:906  //$this->global->MAIN_LIST_FILTER_ON_DAY=1;\t\t// On filter that show date, we must show input field for day before or after month", "compta/deplacement/list.php:176|check|if (getDolGlobalString(''MAIN_LIST_FILTER_ON_DAY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_HIDE_PRIVATE_NOTES', 'bool', NULL, 'fourn', 'Hides the ''Private Note'' column from list views across multiple modules when enabled.', 'Checked across 11+ list pages including compta/facture/list.php:319, reception/list.php:150, supplier_proposal/list.php:217, fourn/commande/list.php:225, fichinter/list.php:157, fourn/facture/list.php:242, societe/list.php:337, and contrat/list.php:210. No admin UI writes this constant.', 'When non-zero, the private note column is disabled (not shown) in all supported list views; when zero or unset, the column is available.', 'Integer: 1 to hide private note columns; 0 or unset to show them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/list.php:319|read|''f.note_private'' => array(''label'' => ''NotePrivate'', ''checked'' => ''0'', ''position'' => 521, ''enabled'' => (!getDolGlobalInt(''MAIN_LIST_HIDE_PRIVATE_NOTES''))),", "reception/list.php:150|read|''e.note_private'' => array(''label'' => ''NotePrivate'', ''checked'' => ''0'', ''position'' => 521, ''enabled'' => (getDolGlobalInt(''MAIN_LIST_HIDE_PRIVATE_NOTES'') ? ''0'' : ''1'')),", "societe/list.php:337|read|''s.note_private'' => array(''label'' => ''NotePrivate'', ''checked'' => ''0'', ''position'' => 521, ''enabled'' => (string) (int) (!getDolGlobalInt(''MAIN_LIST_HIDE_PRIVATE_NOTES''))),", "fourn/commande/list.php:225|read|''cf.note_private'' => array(''label'' => ''NotePrivate'', ''checked'' => ''0'', ''enabled'' => (string) (int) (!getDolGlobalInt(''MAIN_LIST_HIDE_PRIVATE_NOTES'')), ''position'' => 760),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_HIDE_PUBLIC_NOTES', 'bool', NULL, 'fourn', 'Hides the ''Public Note'' column from list views across multiple modules when enabled.', 'Checked across 10+ list pages including compta/facture/list.php:318, reception/list.php:149, supplier_proposal/list.php:216, fourn/commande/list.php:224, fichinter/list.php:156, fourn/facture/list.php:241, societe/list.php:336, and contrat/list.php:209. No admin UI writes this constant.', 'When non-zero, the public note column is disabled (not shown) in all supported list views; when zero or unset, the column is available.', 'Integer: 1 to hide public note columns; 0 or unset to show them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/list.php:318|read|''f.note_public'' => array(''label'' => ''NotePublic'', ''checked'' => ''0'', ''position'' => 520, ''enabled'' => (!getDolGlobalInt(''MAIN_LIST_HIDE_PUBLIC_NOTES''))),", "reception/list.php:149|read|''e.note_public'' => array(''label'' => ''NotePublic'', ''checked'' => ''0'', ''position'' => 520, ''enabled'' => (getDolGlobalInt(''MAIN_LIST_HIDE_PUBLIC_NOTES'') ? ''0'' : ''1'')),", "societe/list.php:336|read|''s.note_public'' => array(''label'' => ''NotePublic'', ''checked'' => ''0'', ''position'' => 520, ''enabled'' => (string) (int) (!getDolGlobalInt(''MAIN_LIST_HIDE_PUBLIC_NOTES''))),", "fourn/commande/list.php:224|read|''cf.note_public'' => array(''label'' => ''NotePublic'', ''checked'' => ''0'', ''enabled'' => (string) (int) (!getDolGlobalInt(''MAIN_LIST_HIDE_PUBLIC_NOTES'')), ''position'' => 750),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_ORDER_LINK_DONT_USE_STATUS', 'bool', NULL, 'commande', 'Suppresses status-based filtering when generating order links in list views.', 'Checked in commande/list.php:2475: when the integer value is non-zero, order links are generated without applying a status condition.', 'Setting this to a non-zero value removes the status constraint from order link generation, causing all orders to be linked regardless of status.', '0 = use status in order links (default); non-zero = ignore status in order links.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:2475|check|if (getDolGlobalInt(''MAIN_LIST_ORDER_LINK_DONT_USE_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LIST_SHOW_REF_EXT', 'bool', NULL, 'salaries', 'Controls visibility of the external reference (ref_ext) field in list views and object definitions.', 'When set to a non-zero integer, the ref_ext field is marked visible in multiple object class definitions (salary, invoice, adherent, contact, propal, commande) and enabled in product/list.php and societe/list.php column arrays. Read via getDolGlobalInt across 9 occurrences in at least 8 files.', 'When 0 or unset, ref_ext columns are hidden in list views. When set to a non-zero value, the external reference column is shown.', 'Integer: non-zero = ref_ext visible; 0 or unset = hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/list.php:264|read|''p.ref_ext'' => array(''label'' => ''RefExt'', ''checked'' => ''-1'', ''position'' => 6, ''visible'' => getDolGlobalInt(''MAIN_LIST_SHOW_REF_EXT'')),", "salaries/class/salary.class.php:218|read|$this->fields[''ref_ext''][''visible''] = getDolGlobalInt(''MAIN_LIST_SHOW_REF_EXT'');", "societe/list.php:301|read|''s.ref_ext'' => array(\"label\" => \"RefExt\", ''position'' => 4, ''checked'' => ''-1'', ''enabled'' => (string) getDolGlobalInt(''MAIN_LIST_SHOW_REF_EXT'')),", "contact/class/contact.class.php:392|read|$this->fields[''ref_ext''][''visible''] = getDolGlobalInt(''MAIN_LIST_SHOW_REF_EXT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGEVENTS_DISABLE_ALL', 'bool', NULL, 'core', 'Disables all event logging performed by the Logevents trigger.', 'Checked in core/triggers/interface_20_all_Logevents.class.php:95; when truthy, the trigger returns early without recording any log event.', 'Enabling this constant stops all audit/event log entries from being written, disabling the full activity trail for all Dolibarr objects.', 'Empty/not set = logging enabled; any truthy string = all event logging disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_all_Logevents.class.php:95|check|if (getDolGlobalString(''MAIN_LOGEVENTS_DISABLE_ALL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGIN_BACKGROUND', 'string', NULL, 'core', 'Stores the filename of the background image displayed on the Dolibarr login page.', 'Written in admin/ihm.php:314, deleted in admin/ihm.php:98, and read in admin/ihm.php:96 and :737 to display a preview. Used in core/tpl/login.tpl.php:242 to apply the background image style. Twenty occurrences across multiple files; configurable via admin/ihm.php.', 'Setting this value applies the specified image as the login page background. Removing it reverts to the default login page appearance.', 'String filename of an image stored under the mycompany logos directory; unset = no custom login background.', 0, 0, 'admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:314|write|dolibarr_set_const($db, \"MAIN_LOGIN_BACKGROUND\", $original_file, ''chaine'', 0, '''', $conf->entity);", "admin/ihm.php:96|read|$logofile = $conf->mycompany->dir_output.''/logos/'' . getDolGlobalString(''MAIN_LOGIN_BACKGROUND'');", "core/tpl/login.tpl.php:242|read|print !getDolGlobalString(''MAIN_LOGIN_BACKGROUND'') ? '' style=\"background-size: cover; background-position: center center; background-attachment: fixed; background-repeat: no-repeat", "admin/ihm.php:737|read|print ''<img class=\"marginleftonly boxshadow valignmiddle\" width=\"100\" src=\"'' . DOL_URL_ROOT . ''/viewimage.php?modulepart=mycompany&amp;file='' . urlencode(''logos/'' . getDolGlobalStr"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGIN_BACKGROUND_STYLE', 'string', NULL, 'core', 'Overrides the CSS background style string applied to the login, password-forgotten, and password-reset pages.', 'Read in core/tpl/login.tpl.php:241, core/tpl/passwordforgotten.tpl.php:147, and core/tpl/passwordreset.tpl.php:185 to override the $backstyle variable. No admin UI write was found; HIDDEN_GUESS is 1.', 'When set, the specified CSS style string replaces the computed background style on all three authentication pages.', 'Any valid CSS background style string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:241|read|$backstyle = getDolGlobalString(''MAIN_LOGIN_BACKGROUND_STYLE'', $backstyle);", "core/tpl/passwordforgotten.tpl.php:147|read|$backstyle = getDolGlobalString(''MAIN_LOGIN_BACKGROUND_STYLE'', $backstyle);", "core/tpl/passwordreset.tpl.php:185|read|$backstyle = getDolGlobalString(''MAIN_LOGIN_BACKGROUND_STYLE'', $backstyle);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGIN_BADCHARUNAUTHORIZED', 'string', NULL, 'user', 'Defines the set of characters that are forbidden in Dolibarr login names.', 'Read in core/lib/openid_connect.lib.php:126 and user/class/user.class.php at lines 1838 and 2250 with a default of '',@<>"\''''.', 'Changing this value alters which characters are rejected during login name validation; removing a character from the list allows it in usernames, while adding one tightens restrictions.', 'String of forbidden characters (default '',@<>"\'''' ); each character in the string is individually checked against the login name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/openid_connect.lib.php:126|read|$badChars = getDolGlobalString(''MAIN_LOGIN_BADCHARUNAUTHORIZED'', '',@<>\"\\\"'');", "user/class/user.class.php:1838|read|$badCharUnauthorizedIntoLoginName = getDolGlobalString(''MAIN_LOGIN_BADCHARUNAUTHORIZED'', '',@<>\"\\\"'');", "user/class/user.class.php:2250|read|$badCharUnauthorizedIntoLoginName = getDolGlobalString(''MAIN_LOGIN_BADCHARUNAUTHORIZED'', '',@<>\"\\\"'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGIN_ENABLE_PASSWORD_AUTOCOMPLETE', 'bool', NULL, 'core', 'Enables browser autocomplete on the password field of the login form.', 'Referenced once at core/tpl/login.tpl.php:320 on the password input element. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant allows browsers to autofill the password field on the login page.', '0 (disabled) or 1 (enabled)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:320|read|<input type=\"password\" id=\"password\" maxlength=\"128\" placeholder=\"...\" name=\"password\" class=\"flat input-icon-password minwidth150 input-nobott"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOGOUT_GOTO_URL', 'string', NULL, 'user', 'Overrides the default post-logout redirect URL, replacing the standard index.php destination.', 'Read at user/logout.php:90-91 to set the redirect target after session destruction. Displayed (read-only) in admin/openid_connect.php:326 with a default fallback of DOL_MAIN_URL_ROOT/index.php.', 'Setting this constant redirects users to a custom URL after logout instead of the Dolibarr home page; useful for SSO portals or custom landing pages.', 'String; a valid URL. Default (when unset) is DOL_MAIN_URL_ROOT/index.php.', 0, 0, 'admin/openid_connect.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["user/logout.php:90|check|if (getDolGlobalString(''MAIN_LOGOUT_GOTO_URL'')) {", "user/logout.php:91|read|$url = getDolGlobalString(''MAIN_LOGOUT_GOTO_URL'');", "admin/openid_connect.php:326|read|print ''<input class=\"minwidth400 centpercent\" value=\"'' . dol_escape_htmltag(getDolGlobalString(''MAIN_LOGOUT_GOTO_URL'', DOL_MAIN_URL_ROOT . \"/index.php\")) . ''\" disabled>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOG_ON_ONE_LINE', 'string', NULL, 'core', 'Forces log entries to be written on a single line, suppressing line breaks within log messages.', 'Checked as an integer in core/lib/functions.lib.php:136. No admin UI write detected.', 'Enabling this constant compacts multi-line log output into single lines, which can simplify log parsing. Disabling it allows multi-line log entries.', 'Non-zero integer = single-line log; 0 or absent = normal multi-line log.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:136|check|if (getDolGlobalInt(\"MAIN_LOG_ON_ONE_LINE\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_LOW_MEMORY_DUMP', 'string', NULL, 'admin', 'Enables low-memory mode for database export operations, reducing peak memory usage at the cost of speed.', 'Read in admin/tools/dolibarr_export.php:309 as the default state of a ''lowmemorydump'' checkbox, and in admin/tools/export.php:124 to set the $lowmemorydump integer flag used during the export process.', 'Enabling this flag activates a lower-memory export strategy; disabling it uses the standard export path.', '0 = standard export (default); 1 = low-memory export mode.', 0, 0, 'admin/tools/export.php|admin/tools/dolibarr_export.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/dolibarr_export.php:309|read|getDolGlobalInt(''MAIN_LOW_MEMORY_DUMP'')", "admin/tools/export.php:124|read|$lowmemorydump = (int) (GETPOSTISSET(\"lowmemorydump\") ? GETPOSTINT(\"lowmemorydump\") : getDolGlobalInt(''MAIN_LOW_MEMORY_DUMP''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAILFORM_DISABLE_ENTERKEY', 'bool', NULL, 'core', 'Disables the Enter key submission in mail and ticket form text areas.', 'The COMMENTS state: ''Disable enter key if option MAIN_MAILFORM_DISABLE_ENTERKEY is set'' (core/class/html.formmail.class.php:1165 and core/class/html.formticket.class.php:1928). Checked at the corresponding lines 1166 and 1929.', 'Enabling this prevents accidental form submission via the Enter key in email and ticket compose forms; disabling it restores default Enter key behaviour.', 'truthy = disable Enter key in mail/ticket forms; empty/not set = Enter key works normally', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:1165  // Disable enter key if option MAIN_MAILFORM_DISABLE_ENTERKEY is set", "core/class/html.formticket.class.php:1928  // Disable enter key if option MAIN_MAILFORM_DISABLE_ENTERKEY is set"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_ADD_INLINE_IMAGES_IF_DATA', 'string', NULL, 'core', 'Enables conversion of data-URI inline images to proper inline email attachments.', 'When set, images with src="data:image/..." are converted to inline attachments in the email. The code comment at core/class/CMailFile.class.php:344 states this is on by default because Gmail does not support src="data:image...".', 'Disabling this causes data-URI images to remain as-is, which may break rendering in Gmail and other clients that do not support inline data URIs.', 'On by default because Gmail does not support src="data:image..."; any non-empty string value enables the conversion.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:344|check|if (getDolGlobalString(''MAIN_MAIL_ADD_INLINE_IMAGES_IF_DATA'')) {\t// On by default because Gmail does not support src=\"data:image...\""]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_ADD_INLINE_IMAGES_IF_IN_MEDIAS', 'string', NULL, 'core', 'Enables embedding of inline images from the medias library into outgoing emails.', 'When set, the CMailFile constructor processes images stored in the medias directory and embeds them as inline attachments. Documented in core/class/CMailFile.class.php:2065 as off by default. Checked at core/class/CMailFile.class.php:327.', 'Enabling this causes images referenced from the medias directory to be embedded inline in emails; leaving it unset keeps this behavior off by default.', 'Off by default; any non-empty string value enables inline image embedding from medias.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:2065  * This is called in the CMailFile constructor but only if MAIN_MAIL_ADD_INLINE_IMAGES_IF_IN_MEDIAS is set (Off by default)", "core/class/CMailFile.class.php:327|check|if (getDolGlobalString(''MAIN_MAIL_ADD_INLINE_IMAGES_IF_IN_MEDIAS'')) {\t// Off by default"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_ALLOW_SENDMAIL_F', 'bool', NULL, 'core', 'Allows use of the sendmail -f option to set the envelope sender address from the From header.', 'Documented at core/class/CMailFile.class.php:1015: forcing using the option -f of sendmail is possible if constant MAIN_MAIL_ALLOW_SENDMAIL_F is defined. Also referenced at line 1683 regarding the SMTP header and command-line sender.', 'Enabling this passes the -f flag to the sendmail command, setting the envelope sender; disabling it omits the flag.', 'Any non-empty string value enables the -f sendmail option.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1015  // So forcing using the option -f of sendmail is possible if constant MAIN_MAIL_ALLOW_SENDMAIL_F is defined.", "core/class/CMailFile.class.php:1683  // SMTP header, with a value guessed by command line tool. See option MAIN_MAIL_ALLOW_SENDMAIL_F to provide email to the command line tool."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_HOLIDAY_TO', 'string', NULL, 'holiday', 'Specifies a BCC email address to receive copies of all holiday notification emails.', 'Read in five locations across holiday/card_group.php and holiday/card.php as the $sendtobcc variable (lines 803, 586, 717, 802, 969). Covers multiple notification events (submission, approval, refusal, etc.). No admin UI write is present.', 'Setting this constant causes all holiday-related notification emails to be blind-carbon-copied to the specified address. Leaving it unset disables the BCC.', 'An email address string; empty or unset = no BCC.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/card_group.php:803|read|$sendtobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_HOLIDAY_TO'');", "holiday/card.php:586|read|$sendtobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_HOLIDAY_TO'');", "holiday/card.php:717|read|$sendtobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_HOLIDAY_TO'');", "holiday/card.php:802|read|$sendtobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_HOLIDAY_TO'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_INVOICE_TO', 'string', NULL, 'core', 'Specifies a BCC email address to automatically copy when sending invoice emails.', 'Checked and read in core/class/html.formmail.class.php:1372–1373 when the model is ''facture_send''. Also appended to BCC in core/actions_massactions.inc.php:533. The COMMENT states: ''$autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...''', 'Setting this to an email address causes all invoice send emails to include that address as a hidden BCC recipient; clearing it disables the autocopy.', 'string (email address); empty = no autocopy', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_sendmails.inc.php:380  // $autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...", "core/class/html.formmail.class.php:1372|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_INVOICE_TO'') && !empty($this->param[''models'']) && $this->param[''models''] == ''facture_send'') {", "core/class/html.formmail.class.php:1373|read|$showinfobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_INVOICE_TO'');", "core/actions_massactions.inc.php:533|read|$sendtobcc .= (!getDolGlobalString(''MAIN_MAIL_AUTOCOPY_INVOICE_TO'') ? '''' : (($sendtobcc ? \", \" : \"\") . getDolGlobalString(''MAIN_MAIL_AUTOCOPY_INVOICE_TO'')));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_ORDER_TO', 'string', NULL, 'core', 'Specifies a BCC email address to automatically copy when sending order emails.', 'Checked and read in core/class/html.formmail.class.php:1369–1370 when the model is ''order_send''. Also appended to BCC in core/actions_massactions.inc.php:530. The COMMENT states: ''$autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...''', 'Setting this to an email address causes all order send emails to include that address as a hidden BCC recipient; clearing it disables the autocopy.', 'string (email address); empty = no autocopy', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_sendmails.inc.php:380  // $autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...", "core/class/html.formmail.class.php:1369|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_ORDER_TO'') && !empty($this->param[''models'']) && $this->param[''models''] == ''order_send'') {", "core/class/html.formmail.class.php:1370|read|$showinfobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_ORDER_TO'');", "core/actions_massactions.inc.php:530|read|$sendtobcc .= (!getDolGlobalString(''MAIN_MAIL_AUTOCOPY_ORDER_TO'') ? '''' : (($sendtobcc ? \", \" : \"\") . getDolGlobalString(''MAIN_MAIL_AUTOCOPY_ORDER_TO'')));"]', 'high', NULL);
