INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_PROPOSAL_TO', 'string', NULL, 'core', 'Specifies a BCC email address to automatically copy when sending proposal emails.', 'Checked and read in core/class/html.formmail.class.php:1366–1367 when the model is ''propal_send''. Also appended to BCC in core/actions_massactions.inc.php:527. The COMMENT states: ''$autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...''', 'Setting this to an email address causes all proposal send emails to include that address as a hidden BCC recipient; clearing it disables the autocopy.', 'string (email address); empty = no autocopy', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_sendmails.inc.php:380  // $autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...", "core/class/html.formmail.class.php:1366|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_PROPOSAL_TO'') && !empty($this->param[''models'']) && $this->param[''models''] == ''propal_send'') {", "core/class/html.formmail.class.php:1367|read|$showinfobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_PROPOSAL_TO'');", "core/actions_massactions.inc.php:527|read|$sendtobcc .= (!getDolGlobalString(''MAIN_MAIL_AUTOCOPY_PROPOSAL_TO'') ? '''' : (($sendtobcc ? \", \" : \"\") . getDolGlobalString(''MAIN_MAIL_AUTOCOPY_PROPOSAL_TO'')));"]', 'high', NULL);
