INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_SHIPMENT_TO', 'string', NULL, 'core', 'Specifies a BCC email address to automatically copy when sending shipment emails.', 'Checked and read in core/class/html.formmail.class.php:1387–1388 when the model is ''shipping_send''. No mass-action occurrence is present in the payload.', 'Setting this to an email address causes all shipment send emails to include that address as a hidden BCC recipient; clearing it disables the autocopy.', 'string (email address); empty = no autocopy', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:1387|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SHIPMENT_TO'') && !empty($this->param[''models'']) && $this->param[''models''] == ''shipping_send'') {", "core/class/html.formmail.class.php:1388|read|$showinfobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SHIPMENT_TO'');"]', 'medium', NULL);
