INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO', 'string', NULL, 'core', 'Specifies a BCC email address to automatically copy when sending supplier proposal emails.', 'Checked and read in core/class/html.formmail.class.php:1375–1376 when the model is ''supplier_proposal_send''. Also appended to BCC in core/actions_massactions.inc.php:536. The COMMENT states: ''$autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...''', 'Setting this to an email address causes all supplier proposal send emails to include that address as a hidden BCC recipient; clearing it disables the autocopy.', 'string (email address); empty = no autocopy', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_sendmails.inc.php:380  // $autocopy can be MAIN_MAIL_AUTOCOPY_PROPOSAL_TO, MAIN_MAIL_AUTOCOPY_ORDER_TO, MAIN_MAIL_AUTOCOPY_INVOICE_TO, MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO...", "core/class/html.formmail.class.php:1375|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO'') && !empty($this->param[''models'']) && $this->param[''models''] == ''supplier_proposal_send'') {", "core/class/html.formmail.class.php:1376|read|$showinfobcc = getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO'');", "core/actions_massactions.inc.php:536|read|$sendtobcc .= (!getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO'') ? '''' : (($sendtobcc ? \", \" : \"\") . getDolGlobalString(''MAIN_MAIL_AUTOCOPY_SUPPLIER_PROPOSAL_TO'')));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_AUTOCOPY_TO', 'string', NULL, 'core', 'Specifies one or more email addresses to automatically BCC on every outgoing email sent by Dolibarr.', 'Configured via the mail admin UI (admin/mails.php:130, :662). The value supports special tokens such as __USER_EMAIL__ in addition to plain addresses (core/class/CMailFile.class.php:394). When set, the value is split by comma and each address is added as BCC to all outgoing emails (core/class/CMailFile.class.php:395, :396).', 'Setting this causes every outgoing email to be BCC''d to the listed addresses. Clearing it stops the automatic BCC.', 'Comma-separated list of email addresses. Supports token __USER_EMAIL__. Example: ''email@example.com, __USER_EMAIL__''.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/CMailFile.class.php:215  *\t@param \tstring\t\t$addr_bcc            \tEmail bcc (Note: This is autocompleted with MAIN_MAIL_AUTOCOPY_TO if defined)", "core/class/CMailFile.class.php:394  // For example MAIN_MAIL_AUTOCOPY_TO can be ''email@example.com, __USER_EMAIL__, ...''", "core/class/CMailFile.class.php:395|check|if (getDolGlobalString(''MAIN_MAIL_AUTOCOPY_TO'')) {", "core/class/CMailFile.class.php:396|read|$listofemailstoadd = explode('','', getDolGlobalString(''MAIN_MAIL_AUTOCOPY_TO''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_DEBUG', 'string', NULL, 'core', 'Enables verbose debug logging for the email sending subsystem.', 'When set, debug output is written at multiple points throughout core/class/CMailFile.class.php (lines 1040, 1066, 1234, 1240, 1257, 1278, 1421, 1438, and at least one more). No admin UI manages this constant.', 'Enabling this generates extensive debug output for email operations; it should be disabled in production to avoid log bloat.', 'Any non-empty string value enables debug logging.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1421|check|if (getDolGlobalString(''MAIN_MAIL_DEBUG'')) {", "core/class/CMailFile.class.php:1040|check|if (getDolGlobalString(''MAIN_MAIL_DEBUG'')) {", "core/class/CMailFile.class.php:1066|check|if (getDolGlobalString(''MAIN_MAIL_DEBUG'')) {", "core/class/CMailFile.class.php:1234|check|if (getDolGlobalString(''MAIN_MAIL_DEBUG'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_DEBUG_ERR_WITH_DATE', 'string', NULL, 'core', 'Controls date-based rotation of the email debug error log file.', 'When set, the email error log is archived or rotated with a date suffix at core/class/CMailFile.class.php:1600. No admin UI manages this constant.', 'Enabling this causes the debug error log to be date-stamped and archived; disabling it leaves the error log without rotation.', 'Any non-empty string value enables date-based error log rotation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1600|check|if (getDolGlobalString(''MAIN_MAIL_DEBUG_ERR_WITH_DATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_DEBUG_LOG_WITH_DATE', 'string', NULL, 'core', 'Controls archiving of the email debug log file with a date suffix.', 'When set to a non-zero integer, the debug log output file is archived using archiveOrBackupFile() with this value as the rotation parameter at core/class/CMailFile.class.php:1562. Checked at line 1560.', 'Setting this to a positive integer causes the debug log to be rotated/archived with date; leaving it unset or zero skips archiving.', 'Integer; passed to archiveOrBackupFile() as the rotation parameter.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1560|check|if (getDolGlobalInt(''MAIN_MAIL_DEBUG_LOG_WITH_DATE'')) {", "core/class/CMailFile.class.php:1562|read|archiveOrBackupFile($outputfile, getDolGlobalInt(''MAIN_MAIL_DEBUG_LOG_WITH_DATE''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_DEFAULT_FROMTYPE', 'string', NULL, 'admin', 'Sets the default sender type used for outgoing emails.', 'Written and read in admin/mails.php (e.g. lines 131, 652, 951-958). The value is compared to ''robot'', ''user'', and ''company'' string constants, and also matched against ''senderprofile_*'' patterns for stored sender profiles. Defaults to ''user'' in fallback reads at lines 1199 and core/tpl/massactions_pre.tpl.php:262.', 'Changing this value alters the pre-selected From address type in email send forms; it affects all outgoing email compositions that do not override the sender explicitly.', '''robot'' = system robot address; ''user'' = logged-in user address; ''company'' = company address; ''senderprofile_N'' = stored sender profile N', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:951|check|if (getDolGlobalString(''MAIN_MAIL_DEFAULT_FROMTYPE'') === ''robot'') {", "admin/mails.php:953|read|} elseif (getDolGlobalString(''MAIN_MAIL_DEFAULT_FROMTYPE'') === ''user'') {", "admin/mails.php:955|read|} elseif (getDolGlobalString(''MAIN_MAIL_DEFAULT_FROMTYPE'') === ''company'') {", "admin/mails.php:131|write|dolibarr_set_const($db, ''MAIN_MAIL_DEFAULT_FROMTYPE'', GETPOST(''MAIN_MAIL_DEFAULT_FROMTYPE'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_DO_NOT_USE_SIGN', 'bool', NULL, 'admin', 'Suppresses inclusion of the user''s email signature in outgoing mail templates when enabled.', 'Checked in admin/mails.php, admin/mails_emailing.php, admin/mails_passwordreset.php, and admin/mails_ticket.php. In each, the substitution variable __USER_SIGNATURE__ and __SENDEREMAIL_SIGNATURE__ are set to empty string when this constant is set.', 'Enabling this constant removes user signatures from all outgoing emails across the system. Disabling restores signature insertion when a user signature is defined.', 'Empty/unset = user signature included if present; non-empty = user signature suppressed', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:66|read|''__USER_SIGNATURE__'' => (($user->signature && !getDolGlobalString(''MAIN_MAIL_DO_NOT_USE_SIGN'')) ? $usersignature : '''')", "admin/mails.php:67|read|''__SENDEREMAIL_SIGNATURE__'' => (($user->signature && !getDolGlobalString(''MAIN_MAIL_DO_NOT_USE_SIGN'')) ? $usersignature : '''')", "admin/mails_emailing.php:57|read|''__USER_SIGNATURE__'' => (($user->signature && !getDolGlobalString(''MAIN_MAIL_DO_NOT_USE_SIGN'')) ? $usersignature : '''')", "admin/mails_ticket.php:57|read|''__USER_SIGNATURE__'' => (($user->signature && !getDolGlobalString(''MAIN_MAIL_DO_NOT_USE_SIGN'')) ? $usersignature : '''')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_DKIM_DOMAIN', 'string', NULL, 'admin', 'Stores the domain name used in the DKIM email signature.', 'Written at admin/mails.php:124. Read in core/class/CMailFile.class.php:1415 as the domain component of the DKIM signature. Displayed and edited via admin/mails.php:603 and 841.', 'Setting this to the correct domain is required for valid DKIM signatures; an incorrect or empty value will cause DKIM signing to fail or produce invalid signatures.', 'Domain name string (e.g. ''example.com''); empty = DKIM domain not configured', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:124|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_DKIM_DOMAIN\", GETPOST(\"MAIN_MAIL_EMAIL_DKIM_DOMAIN\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/class/CMailFile.class.php:1415|read|$domainName = getDolGlobalString(''MAIN_MAIL_EMAIL_DKIM_DOMAIN'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_DKIM_ENABLED', 'bool', NULL, 'admin', 'Enables DKIM email signing for outgoing messages sent via the CMailFile class.', 'Written at admin/mails.php:123. Checked in core/class/CMailFile.class.php:1413 before applying DKIM signing. Also displayed and managed via admin/mails.php (lines 302, 592, 830).', 'Enabling this constant activates DKIM signing on outgoing emails using the configured domain, selector, and private key; disabling it sends emails without DKIM signatures.', '0 = DKIM signing disabled; 1 = DKIM signing enabled', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:123|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_DKIM_ENABLED\", GETPOSTINT(\"MAIN_MAIL_EMAIL_DKIM_ENABLED\"), ''chaine'', 0, '''', $conf->entity);", "core/class/CMailFile.class.php:1413|check|if (getDolGlobalString(''MAIN_MAIL_EMAIL_DKIM_ENABLED'')) {", "admin/mails.php:830|read|print yn(getDolGlobalInt(''MAIN_MAIL_EMAIL_DKIM_ENABLED''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY', 'string', NULL, 'admin', 'Stores the PEM-encoded RSA private key used to sign outgoing emails with DKIM.', 'Written at admin/mails.php:126. Read in core/class/CMailFile.class.php:1414 as the private key for DKIM signing. Displayed as a textarea at admin/mails.php:613 and summarised at line 851.', 'Setting this to a valid RSA private key (matching the public key published in DNS) enables DKIM signing; an invalid or mismatched key produces invalid DKIM signatures.', 'PEM-encoded RSA private key string; empty = DKIM private key not configured', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:126|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY\", GETPOST(\"MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/class/CMailFile.class.php:1414|read|$privateKey = getDolGlobalString(''MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY'');", "admin/mails.php:613|read|print ''<td><textarea id=\"MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY\" name=\"MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY\" rows=\"15\" cols=\"100\">''.getDolGlobalString(''MAIN_MAIL_EMAIL_DKIM_PRIVATE_KEY'').''</"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_DKIM_SELECTOR', 'string', NULL, 'admin', 'Stores the DNS selector used to locate the DKIM public key for signature verification.', 'Written at admin/mails.php:125. Read in core/class/CMailFile.class.php:1416 as the selector component of the DKIM signature. Displayed and edited via admin/mails.php:608 and 846.', 'Setting the correct selector is required for receiving mail servers to locate the DKIM public key in DNS; an incorrect value causes DKIM verification failure.', 'DNS selector string (e.g. ''dkim'', ''mail''); empty = DKIM selector not configured', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:125|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_DKIM_SELECTOR\", GETPOST(\"MAIN_MAIL_EMAIL_DKIM_SELECTOR\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/class/CMailFile.class.php:1416|read|$selector = getDolGlobalString(''MAIN_MAIL_EMAIL_DKIM_SELECTOR'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_FROM', 'string', 'robot@domain.com', 'admin', 'Sets the default sender email address used for all outgoing emails from Dolibarr.', 'Written by admin/mails.php:128 and read in 53 locations. admin/mails.php:921 warns when it is not set, and admin/ticket.php:205-216 copies its value into ticket notification email constants. admin/mails_passwordreset.php:748 checks it alongside MAIN_MAIL_EMAIL_FROM_PASSWORDRESET for password-reset emails.', 'Changing this value alters the From address on all system-generated emails; leaving it unset triggers warnings in the mail admin panel.', 'Valid email address string; default ''robot@domain.com'' (as shown in TYPE default).', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:128|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_FROM\", GETPOST(\"MAIN_MAIL_EMAIL_FROM\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails.php:921|check|if (!getDolGlobalString(''MAIN_MAIL_EMAIL_FROM'')) {", "admin/ticket.php:205|read|$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_FROM'', getDolGlobalString(''MAIN_MAIL_EMAIL_FROM''), ''chaine'', 0, $notification_email_description, $conf->entity);", "admin/mails_passwordreset.php:748|check|if (!getDolGlobalString(''MAIN_MAIL_EMAIL_FROM'') && !getDolGlobalString(''MAIN_MAIL_EMAIL_FROM_PASSWORDRESET'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_FROM_PASSWORDRESET', 'string', NULL, 'admin', 'Overrides the default sender email address used specifically for password-reset notification emails.', 'Configured via admin/mails_passwordreset.php (UI write at line 109). When set, it is used as the From address for password-reset emails instead of MAIN_MAIL_EMAIL_FROM (user/class/user.class.php:2826). The value is validated as an email address at admin/mails_passwordreset.php:750.', 'If left empty, the system falls back to MAIN_MAIL_EMAIL_FROM. If set to an invalid email address, a warning icon is displayed and the send may fail.', 'Any valid email address string; empty string causes fallback to MAIN_MAIL_EMAIL_FROM.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:743|check|if (!getDolGlobalString(''MAIN_MAIL_EMAIL_FROM_PASSWORDRESET'')) {", "admin/mails_passwordreset.php:750|read|} elseif (getDolGlobalString(''MAIN_MAIL_EMAIL_FROM_PASSWORDRESET'') && !isValidEmail(getDolGlobalString(''MAIN_MAIL_EMAIL_FROM_PASSWORDRESET''))) {", "user/class/user.class.php:2826|read|getDolGlobalString(\"MAIN_MAIL_EMAIL_FROM_PASSWORDRESET\", getDolGlobalString(\"MAIN_MAIL_EMAIL_FROM\")),", "admin/mails_passwordreset.php:109|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_FROM_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_EMAIL_FROM_PASSWORDRESET\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_HOLIDAY_FROM', 'string', NULL, 'holiday', 'Overrides the sender email address used specifically for holiday request notification emails.', 'Read in holiday/card.php at line 512. When set, its value is used as the From address for holiday emails; otherwise falls back to the value of MAIN_MAIL_EMAIL_FROM.', 'Setting this constant overrides the From address for holiday emails only; leaving it unset uses the global MAIN_MAIL_EMAIL_FROM address.', 'A valid email address string; falls back to MAIN_MAIL_EMAIL_FROM if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["holiday/card.php:512|read|$emailFrom = getDolGlobalString(''MAIN_MAIL_EMAIL_HOLIDAY_FROM'', getDolGlobalString(''MAIN_MAIL_EMAIL_FROM''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED', 'bool', NULL, 'admin', 'Allows the SMTP mailer to accept self-signed TLS certificates from the mail server.', 'Written at admin/mails.php:121, read and displayed at lines 272, 300, 579, and 815. Managed via the admin mail configuration UI (admin/mails.php).', 'Enabling this constant disables certificate validation for SMTP connections, which is insecure but necessary for some private mail servers with self-signed certificates.', '0 = self-signed certificates rejected; 1 = self-signed certificates accepted for SMTP', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:121|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED\", GETPOSTINT(\"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails.php:579|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED'', (getDolGlobalString(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SE", "admin/mails.php:815|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_EMAILING', 'bool', NULL, 'admin', 'Allows self-signed SSL/TLS certificates on SMTP connections used for mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 108). Displayed as a yes/no selector (line 553) and summary (line 695). Also sets a JS variable at lines 247 and 275.', 'Enabling this accepts self-signed certificates on the emailing SMTP server; disabling enforces certificate validation.', 'Yes/No (selectyesno); 1 = self-signed certificates allowed, 0 = not allowed.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:108|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_EMAILING\", GETPOST(\"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_EMAILING\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:553|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_EMAILING'', ...", "admin/mails_emailing.php:695|read|print yn(getDolGlobalInt(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_EMAILING''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET', 'bool', NULL, 'admin', 'Allows self-signed TLS certificates on the SMTP connection used specifically for password reset emails.', 'Written at admin/mails_passwordreset.php:106 and read/displayed at :250, :278, :552, :714. Rendered as a yes/no selector and read as integer at :714 via getDolGlobalInt.', 'Enabling disables certificate validation for password reset SMTP, which may be necessary for internal mail servers with self-signed certificates but reduces security. Disabling enforces valid certificates.', '1/truthy = allow self-signed certificate; 0/empty = require valid certificate.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:106|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:552|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET'', (getDolGlobalString(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET'') ? getDolGlobalString(''M", "admin/mails_passwordreset.php:714|read|print yn(getDolGlobalInt(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_PASSWORDRESET''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_TICKET', 'bool', NULL, 'admin', 'Allows self-signed SSL/TLS certificates on the SMTP server used for ticket emails.', 'Written in admin/mails_ticket.php at line 106 and read/rendered at lines 248, 276, 547, and 689. Displayed as a yes/no select in the admin UI.', 'Enabling this constant bypasses SSL certificate validation for the ticket email SMTP connection, which allows use of self-signed certificates but reduces security.', '1 = allow self-signed certificates; 0 or empty = require valid certificates.', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:106|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_TICKET\", GETPOST(\"MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:689|read|print yn(getDolGlobalInt(''MAIN_MAIL_EMAIL_SMTP_ALLOW_SELF_SIGNED_TICKET''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_STARTTLS', 'string', NULL, 'admin', 'Enables STARTTLS encryption upgrade for SMTP connections.', 'Read in admin/mails.php:566 as a yes/no select and displayed at admin/mails.php:798. Written via admin/mails.php:120. A commented-out line in core/class/CMailFile.class.php:1999 shows the original intent to set the SMTP host to ''tls://'' when this constant and openssl are available.', 'Setting this to 1 enables STARTTLS negotiation on the SMTP connection; setting it to 0 disables it.', '1 = STARTTLS enabled; 0 = STARTTLS disabled.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/CMailFile.class.php:1999  //if (getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS'') && function_exists(''openssl_open'')) $host=''tls://''.$host;", "admin/mails.php:566|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_STARTTLS'', (getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS'') : 0), 1);", "admin/mails.php:120|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_STARTTLS\", GETPOSTINT(\"MAIN_MAIL_EMAIL_STARTTLS\"), ''chaine'', 0, '''', $conf->entity);", "debugbar/class/DataCollector/DolibarrCollector.php:116|read|$info .= $langs->trans(''TLS/STARTTLS'').'': <strong>''.getDolGlobalString(\"MAIN_MAIL_EMAIL_TLS\").''</strong> / <strong>''.getDolGlobalString(\"MAIN_MAIL_EMAIL_STARTTLS\").''</strong><br>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_STARTTLS_EMAILING', 'string', NULL, 'admin', 'Enables STARTTLS encryption for SMTP connections used specifically for mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 107). Displayed as a yes/no selector (line 540) and summary (line 678). Also sets a JS variable at lines 245 and 273.', 'Enabling STARTTLS upgrades the SMTP connection to encrypted for mass emails; disabling sends without STARTTLS.', 'Yes/No (selectyesno); 1 = STARTTLS enabled, 0 = STARTTLS disabled.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:107|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_STARTTLS_EMAILING\", GETPOST(\"MAIN_MAIL_EMAIL_STARTTLS_EMAILING\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:540|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_STARTTLS_EMAILING'', (getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_EMAILING'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_EMAILING'') : 0", "admin/mails_emailing.php:678|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_EMAILING''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET', 'string', NULL, 'admin', 'Enables STARTTLS upgrade for the SMTP connection used specifically for password reset emails.', 'Written at admin/mails_passwordreset.php:105 and read/displayed at :248, :276, :539, :697. Rendered as a yes/no selector in the admin UI.', 'Enabling upgrades the password reset SMTP connection to TLS via STARTTLS. Disabling sends without STARTTLS on that specific connection.', '1/truthy = use STARTTLS; 0/empty = no STARTTLS for password reset SMTP.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:105|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:539|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET'', (getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_PASS", "admin/mails_passwordreset.php:697|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_PASSWORDRESET''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_STARTTLS_TICKET', 'string', NULL, 'admin', 'Enables STARTTLS negotiation for SMTP connections used when sending ticket emails.', 'Written in admin/mails_ticket.php at line 105 and read/rendered at lines 246, 274, 534, and 672. Displayed as a yes/no select in the admin UI.', 'Enabling this constant causes the ticket email SMTP client to issue a STARTTLS command to upgrade the connection to TLS. Disabling it skips STARTTLS negotiation.', '1 = enable STARTTLS; 0 or empty = disable STARTTLS.', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:105|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_STARTTLS_TICKET\", GETPOST(\"MAIN_MAIL_EMAIL_STARTTLS_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:534|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_STARTTLS_TICKET'', (getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_TICKET'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_STARTTLS_TICKET'') : 0), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_TLS', 'string', NULL, 'admin', 'Enables SSL/TLS encryption for SMTP connections.', 'Read in admin/mails.php:553 as a yes/no select field and displayed at admin/mails.php:781. Written via admin/mails.php:119. Also referenced alongside MAIN_MAIL_EMAIL_STARTTLS in the debugbar at debugbar/class/DataCollector/DolibarrCollector.php:116.', 'Setting this to 1 enables TLS encryption on the SMTP connection; setting it to 0 disables it.', '1 = TLS enabled; 0 = TLS disabled.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:553|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_TLS'', (getDolGlobalString(''MAIN_MAIL_EMAIL_TLS'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_TLS'') : 0), 1);", "admin/mails.php:119|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_TLS\", GETPOSTINT(\"MAIN_MAIL_EMAIL_TLS\"), ''chaine'', 0, '''', $conf->entity);", "debugbar/class/DataCollector/DolibarrCollector.php:116|read|$info .= $langs->trans(''TLS/STARTTLS'').'': <strong>''.getDolGlobalString(\"MAIN_MAIL_EMAIL_TLS\").''</strong> / <strong>''.getDolGlobalString(\"MAIN_MAIL_EMAIL_STARTTLS\").''</strong><br>'';", "admin/mails.php:781|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_TLS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_TLS_EMAILING', 'string', NULL, 'admin', 'Enables TLS encryption for SMTP connections used specifically for mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 106). Displayed as a yes/no selector (line 527) and summary (line 661). Also sets a JS variable at lines 243 and 271 for dynamic UI updates.', 'Enabling TLS encrypts the SMTP connection for mass emails; disabling sends without TLS encryption.', 'Yes/No (selectyesno); 1 = TLS enabled, 0 = TLS disabled.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:106|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_TLS_EMAILING\", GETPOST(\"MAIN_MAIL_EMAIL_TLS_EMAILING\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:527|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_TLS_EMAILING'', (getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_EMAILING'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_EMAILING'') : 0), 1);", "admin/mails_emailing.php:661|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_EMAILING''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_TLS_PASSWORDRESET', 'string', NULL, 'admin', 'Enables TLS encryption for the SMTP connection used specifically for password reset emails.', 'Written at admin/mails_passwordreset.php:104 and read/displayed at :246, :274, :525, :680. Rendered as a yes/no selector in the admin UI. Enables TLS when truthy.', 'Enabling forces TLS on the password reset SMTP connection. Disabling sends without TLS on that specific connection.', '1/truthy = use TLS; 0/empty = no TLS for password reset SMTP.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:104|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_TLS_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_EMAIL_TLS_PASSWORDRESET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:525|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_TLS_PASSWORDRESET'', (getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_PASSWORDRESET'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_PASSWORDRESET'') : 0", "admin/mails_passwordreset.php:680|read|print yn(getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_PASSWORDRESET''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_EMAIL_TLS_TICKET', 'string', NULL, 'admin', 'Enables TLS encryption for SMTP connections used when sending ticket emails.', 'Written in admin/mails_ticket.php at line 104 and read/rendered at lines 244, 272, 521, and 655. Displayed as a yes/no select in the admin UI.', 'Enabling this constant activates TLS for ticket email SMTP connections. Disabling it sends mail without TLS encryption.', '1 = enable TLS; 0 or empty = disable TLS.', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:104|write|dolibarr_set_const($db, \"MAIN_MAIL_EMAIL_TLS_TICKET\", GETPOST(\"MAIN_MAIL_EMAIL_TLS_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:521|read|print $form->selectyesno(''MAIN_MAIL_EMAIL_TLS_TICKET'', (getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_TICKET'') ? getDolGlobalString(''MAIN_MAIL_EMAIL_TLS_TICKET'') : 0), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_ENABLED_USER_DEST_SELECT', 'bool', NULL, 'core', 'Enables a user-selector UI in email composition forms, allowing users to be chosen as To/CC recipients.', 'Set via admin/mails.php:103 and displayed with a yes/no selector at line 667; checked in core/class/html.formmail.class.php:804 and 853 and in core/actions_sendmails.inc.php:266, 307, 464 to conditionally render and process user recipient selection.', 'When enabled, email forms show a user picker for To and CC fields; when disabled, the user picker is not shown and user IDs in recipient lists are not processed.', '0 or empty = user destination selector disabled; non-zero = enabled.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:103|write|dolibarr_set_const($db, \"MAIN_MAIL_ENABLED_USER_DEST_SELECT\", GETPOSTINT(\"MAIN_MAIL_ENABLED_USER_DEST_SELECT\"), ''chaine'', 0, '''', $conf->entity);", "core/class/html.formmail.class.php:804|check|if (!empty($this->withtouser) && is_array($this->withtouser) && getDolGlobalString(''MAIN_MAIL_ENABLED_USER_DEST_SELECT'')) {", "core/actions_sendmails.inc.php:266|check|if (getDolGlobalString(''MAIN_MAIL_ENABLED_USER_DEST_SELECT'')) {", "core/actions_sendmails.inc.php:464|check|if (is_array($sendtouserid) && count($sendtouserid) > 0 && getDolGlobalString(''MAIN_MAIL_ENABLED_USER_DEST_SELECT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_ERRORS_TO', 'string', NULL, 'admin', 'Specifies the email address to which mail delivery errors are sent.', 'Configured via admin/mails.php:129 and read in multiple invoice and supplier invoice class files (compta/facture/class/facture-rec.class.php:1607, compta/facture/class/facture.class.php:6369, fourn/class/fournisseur.facture.class.php:3670) as ''$errors_to = getDolGlobalString(''MAIN_MAIL_ERRORS_TO'')''. Validated as a proper email at admin/mails.php:971.', 'When set to a valid email address, mail errors are forwarded to that address; when empty or invalid, error routing is not configured.', 'Empty/not set = no error email address configured; valid email string = address to receive mail delivery error notifications.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:971|check|if (getDolGlobalString(''MAIN_MAIL_ERRORS_TO'') && !isValidEmail(getDolGlobalString(''MAIN_MAIL_ERRORS_TO''))) {", "compta/facture/class/facture-rec.class.php:1607|read|$errors_to = getDolGlobalString(''MAIN_MAIL_ERRORS_TO'');", "compta/facture/class/facture.class.php:6369|read|$errors_to = getDolGlobalString(''MAIN_MAIL_ERRORS_TO'');", "admin/mails.php:129|write|dolibarr_set_const($db, \"MAIN_MAIL_ERRORS_TO\", GETPOST(\"MAIN_MAIL_ERRORS_TO\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_FORCE_CONTENT_TYPE_TO_HTML', 'string', NULL, 'core', 'Forces all outgoing emails to use HTML content type regardless of the message format.', 'When set, overrides the content type of outgoing emails to HTML. Checked in core/class/CMailFile.class.php:317. No admin UI writes this constant; it must be set manually.', 'Setting this forces all emails to HTML format; unsetting it allows the default content type determination logic to apply.', 'Any non-empty string value enables the override; empty or unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:317|check|if (getDolGlobalString(''MAIN_MAIL_FORCE_CONTENT_TYPE_TO_HTML'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_FORCE_FROM', 'string', NULL, 'core', 'Forces the sender (From) address of all outgoing emails to a fixed value.', 'When set, the From header is overwritten with this constant''s value at core/class/CMailFile.class.php:477, overriding any dynamically computed sender address.', 'Changing this replaces the From address on all outgoing emails; removing it restores the default sender computation.', 'Any valid email address string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:476|check|if (getDolGlobalString(''MAIN_MAIL_FORCE_FROM'')) {", "core/class/CMailFile.class.php:477|read|$from = getDolGlobalString(''MAIN_MAIL_FORCE_FROM'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_FORCE_NOT_SENDING_TO', 'string', NULL, 'core', 'Specifies a comma-separated list of email addresses that must be removed from To, CC, and BCC before sending.', 'When set, the value is parsed as a comma-separated list and used to strip matching addresses from all recipient fields. Described in core/class/CMailFile.class.php:422 as: parse To, CC and BCC to remove MAIN_MAIL_FORCE_NOT_SENDING_TO. Used at lines 421-423.', 'Setting this prevents emails from being delivered to the listed addresses; it is typically used in test environments to block accidental sends to real recipients.', 'Comma-separated list of email addresses to suppress from all outgoing mail.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:422  // Parse to, cc and bcc to remove MAIN_MAIL_FORCE_NOT_SENDING_TO", "core/class/CMailFile.class.php:423|read|$listofemailstonotsendto = explode('','', getDolGlobalString(''MAIN_MAIL_FORCE_NOT_SENDING_TO''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_FORCE_NOT_SENDING_TO_REPLACE', 'string', NULL, 'core', 'Specifies a replacement email address that substitutes blocked recipients in To, CC, and BCC fields.', 'When a recipient is removed because it matches MAIN_MAIL_FORCE_NOT_SENDING_TO, this constant''s value is inserted in its place for To (line 436), CC (line 451), and BCC (line 466) in core/class/CMailFile.class.php. Requires the corresponding replace flag to be active.', 'Setting this redirects blocked recipients to a single address rather than simply dropping them, useful for capturing test emails.', 'A single email address string used as the replacement recipient.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:435|check|if ($replaceto && getDolGlobalString(''MAIN_MAIL_FORCE_NOT_SENDING_TO_REPLACE'')) {", "core/class/CMailFile.class.php:436|read|$tabto[] = getDolGlobalString(''MAIN_MAIL_FORCE_NOT_SENDING_TO_REPLACE'');", "core/class/CMailFile.class.php:451|read|$tabcc[] = getDolGlobalString(''MAIN_MAIL_FORCE_NOT_SENDING_TO_REPLACE'');", "core/class/CMailFile.class.php:466|read|$tabbcc[] = getDolGlobalString(''MAIN_MAIL_FORCE_NOT_SENDING_TO_REPLACE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_FORCE_SENDTO', 'string', NULL, 'admin', 'Forces all outgoing emails to be redirected to a specific email address, overriding the normal recipient.', 'When set to a valid email address, all outgoing emails are sent to this address instead of the intended recipient. Configured via the admin UI at admin/mails.php, which validates the value with isValidEmail(). Saved via dolibarr_set_const as type ''chaine''.', 'Changing this to a valid address redirects all system emails to that address, which is useful for testing. Clearing it restores normal email delivery.', 'Any valid email address string; empty string disables the override.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails.php:880|check|if (getDolGlobalString(''MAIN_MAIL_FORCE_SENDTO'')) {", "admin/mails.php:881|check|if (!isValidEmail(getDolGlobalString(''MAIN_MAIL_FORCE_SENDTO''))) {", "admin/mails.php:627|read|print ''<input class=\"flat width300\" name=\"MAIN_MAIL_FORCE_SENDTO\" value=\"''.getDolGlobalString(''MAIN_MAIL_FORCE_SENDTO'').''\" />'';", "admin/mails.php:102|write|dolibarr_set_const($db, \"MAIN_MAIL_FORCE_SENDTO\", GETPOST(\"MAIN_MAIL_FORCE_SENDTO\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_HIDE_CUSTOM_SENDING_METHOD_FOR_PASSWORD_RESET', 'bool', NULL, 'core', 'Hides the custom mail sending method option specifically for password-reset emails.', 'Checked once in core/lib/admin.lib.php at line 2150: the custom sending method is shown only when this constant is NOT set. No admin UI write is present.', 'Enabling this forces password-reset emails to use the default mail method, hiding any custom SMTP/method selection.', 'Truthy (non-empty) = custom method hidden for password reset; empty/unset = custom method available.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/admin.lib.php:2150|check|if (!getDolGlobalString(''MAIN_MAIL_HIDE_CUSTOM_SENDING_METHOD_FOR_PASSWORD_RESET'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_NO_FULL_EMAIL', 'string', NULL, 'core', 'Suppresses the display name portion of email addresses, keeping only the bare address.', 'When set, core/class/CMailFile.class.php:2361 returns null for the name component of an address, and line 2312 gates related formatting logic. Only the bare email address is used without an associated display name.', 'Enabling this strips display names from all email addresses in the system; disabling it preserves full name+address formatting.', 'Any non-empty string value suppresses display names; empty or unset preserves them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:2312|check|if (getDolGlobalString(''MAIN_MAIL_NO_FULL_EMAIL'')) {", "core/class/CMailFile.class.php:2361|read|$ret[$email] = getDolGlobalString(''MAIN_MAIL_NO_FULL_EMAIL'') ? null : $name;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_NO_RETURN_PATH_FOR_MODE_MAIL', 'string', NULL, 'core', 'Suppresses the Return-Path header when sending email via PHP mail() mode.', 'When absent (i.e., the negated check passes), a Return-Path header is added at core/class/CMailFile.class.php:1681. Setting this constant prevents that header from being emitted.', 'Setting this omits the Return-Path header in mail() mode; leaving it unset causes Return-Path to be included.', 'Any non-empty string value suppresses the Return-Path header.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1681|check|if (!getDolGlobalString(''MAIN_MAIL_NO_RETURN_PATH_FOR_MODE_MAIL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_NO_WITH_TO_SELECTED', 'string', NULL, 'admin', 'Prevents sending an email when no ''To'' recipient has been selected in the mail form.', 'Configurable via the admin UI at admin/mails.php (written at line 104, displayed at lines 671 and 1001). Checked in core/class/html.formmail.class.php:1258.', 'Enabling this blocks email sends when no recipient is selected; disabling it allows sending without a mandatory To address.', 'truthy (yes) = block send when no To selected; empty/no = allow send without To', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:104|write|dolibarr_set_const($db, ''MAIN_MAIL_NO_WITH_TO_SELECTED'', GETPOSTINT(''MAIN_MAIL_NO_WITH_TO_SELECTED''), ''chaine'', 0, '''', $conf->entity);", "admin/mails.php:671|read|print $form->selectyesno(''MAIN_MAIL_NO_WITH_TO_SELECTED'', getDolGlobalString(''MAIN_MAIL_NO_WITH_TO_SELECTED''), 1);", "core/class/html.formmail.class.php:1258|check|if (!getDolGlobalInt(''MAIN_MAIL_NO_WITH_TO_SELECTED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_OVERRIDE_AUTHORITATIVE_DNS', 'string', NULL, 'admin', 'Overrides the authoritative DNS servers used for SPF record lookups in the mail admin page.', 'When set, admin/mails.php explodes the value by comma and uses the resulting list as custom DNS servers instead of the default authoritative ones. The inline code comment gives the example: ''eg 8.8.8.8, x.x.x.x''. Only one occurrence in the payload.', 'Setting this to a comma-separated list of DNS server addresses replaces the default authoritative DNS servers for SPF validation; leaving it unset uses system defaults.', 'Comma-separated DNS server addresses, e.g. ''8.8.8.8, x.x.x.x''; empty or unset uses system defaults.', 0, 0, 'admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails.php:1130|read|$authns = (getDolGlobalString(''MAIN_MAIL_OVERRIDE_AUTHORITATIVE_DNS'') ? explode('','', getDolGlobalString(''MAIN_MAIL_OVERRIDE_AUTHORITATIVE_DNS'')) : null); // eg 8.8.8.8, x.x.x.x"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_REPLACE_EVENT_TITLE_BY_EMAIL_SUBJECT', 'string', NULL, 'partnership', 'When set, replaces the agenda event title with the email subject when sending emails that log events.', 'Checked in partnership/class/partnershiputils.class.php:229 and :453, core/actions_sendmails.inc.php:454, and core/actions_massactions.inc.php:705. 4 occurrences across 3 files.', 'When unset, the event title retains its default value. When set, the email subject line is used as the agenda event title for logged mail events.', 'Truthy value = email subject used as event title; empty/unset = default event title retained.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:229|check|if (getDolGlobalString(''MAIN_MAIL_REPLACE_EVENT_TITLE_BY_EMAIL_SUBJECT'')) {", "core/actions_sendmails.inc.php:454|check|if (getDolGlobalString(''MAIN_MAIL_REPLACE_EVENT_TITLE_BY_EMAIL_SUBJECT'')) {", "core/actions_massactions.inc.php:705|check|if (getDolGlobalString(''MAIN_MAIL_REPLACE_EVENT_TITLE_BY_EMAIL_SUBJECT'')) {", "partnership/class/partnershiputils.class.php:453|check|if (getDolGlobalString(''MAIN_MAIL_REPLACE_EVENT_TITLE_BY_EMAIL_SUBJECT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_REPLY_TO', 'string', NULL, 'comm', 'Sets the system-wide default Reply-To email address, used as a fallback for mailing campaigns.', 'Referenced in comm/mailing/card.php:902 as the fallback value for the ''replyto'' field when MAILING_EMAIL_REPLYTO is not set, via getDolGlobalString(''MAILING_EMAIL_REPLYTO'', getDolGlobalString(''MAIN_MAIL_REPLY_TO'')).', 'Setting this value provides a system-level Reply-To default for mailings. It is overridden by MAILING_EMAIL_REPLYTO when that constant is set.', 'A valid email address string; empty = no default Reply-To address', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:902|read|print ''<td>''.img_picto('''', ''email'', ''class=\"pictofixedwidth\"'').''<input class=\"flat minwidth200\" name=\"replyto\" value=\"''.getDolGlobalString(''MAILING_EMAIL_REPLYTO'', getDolGlobalStri"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMAIL_FORCE_ADDPARAM', 'string', NULL, 'core', 'Appends additional custom parameters to the sendmail command invocation.', 'When set, its value is appended as extra parameters to the sendmail command at core/class/CMailFile.class.php:1024. No admin UI manages this constant.', 'Setting this injects arbitrary additional flags into the sendmail call; incorrect values may break email delivery.', 'Any string value passed verbatim as additional sendmail command-line parameters.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1024|check|if (getDolGlobalString(''MAIN_MAIL_SENDMAIL_FORCE_ADDPARAM'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMAIL_FORCE_BA', 'string', NULL, 'core', 'Forces sendmail to use the -ba option, which reads the From or Sender header to set the envelope sender.', 'Documented at core/class/CMailFile.class.php:1020: To force usage of -ba option. This option tells sendmail to read From: or Sender: to setup sender. Also mentioned at line 1014 as an alternative to MAIN_MAIL_ALLOW_SENDMAIL_F.', 'Enabling this instructs sendmail to derive the sender from the mail headers; disabling it leaves sendmail''s default sender determination in place.', 'Any non-empty string value forces the -ba sendmail option.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:1020|check|if (getDolGlobalString(''MAIN_MAIL_SENDMAIL_FORCE_BA'')) {    // To force usage of -ba option. This option tells sendmail to read From: or Sender: to setup sender", "core/class/CMailFile.class.php:1014  // You can try to set this option to have the command use the From. if it does not work, you can also try the MAIN_MAIL_SENDMAIL_FORCE_BA."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMODE', 'string', NULL, 'admin', 'Selects the transport method used to send outgoing emails.', 'Read extensively throughout admin/mails.php (64 total occurrences) to determine which sending backend is active. The default fallback value used throughout the code is ''mail''. Accepted values include ''mail'', ''smtps'', and ''swiftmailer'', which govern which SMTP configuration sections are displayed and used.', 'Changing this value switches the email transport; setting it to ''smtps'' or ''swiftmailer'' requires valid SMTP server settings, while ''mail'' uses the PHP mail() function.', 'Values observed in code: ''mail'' (PHP mail function, default), ''smtps'', ''swiftmailer''.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_ingoing.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:405|check|if (!$conf->use_javascript_ajax && $linuxlike && getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail'') == ''mail'') {", "admin/mails.php:467|check|if (!empty($conf->use_javascript_ajax) || (in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail''), array(''smtps'', ''swiftmailer'')))) {", "core/menus/standard/eldy.lib.php:1209|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE'') && in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE''), array(''smtps'', ''swiftmail'')) && !getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMODE_', 'string', NULL, 'core', 'Sets the mail sending mode for a specific mail context, overriding the global send mode for that context.', 'This is a dynamic constant: the actual key is ''MAIN_MAIL_SENDMODE_'' + smtpContextKey. Read in core/class/CMailFile.class.php at lines 250, 507, 958, and 1980 to determine the sending mode for the current mail context. No admin UI write is present for the dynamic variant.', 'Setting a context-specific send mode overrides the global MAIN_MAIL_SENDMODE for that mail context (e.g. emailing, password reset).', 'String send mode identifier (e.g. ''mail'', ''smtps'', ''swiftmailer''); empty/unset = falls back to global MAIN_MAIL_SENDMODE.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["CMailFile.class.php:250|read|$smtpContextSendMode = getDolGlobalString(''MAIN_MAIL_SENDMODE_''.$smtpContextKey);", "CMailFile.class.php:507|read|$smtpContextSendMode = getDolGlobalString(''MAIN_MAIL_SENDMODE_''.$smtpContextKey);", "CMailFile.class.php:958|read|$smtpContextSendMode = getDolGlobalString(''MAIN_MAIL_SENDMODE_''.$smtpContextKey);", "CMailFile.class.php:1980|read|$smtpContextSendMode = getDolGlobalString(''MAIN_MAIL_SENDMODE_''.$smtpContextKey);"]', 'medium', NULL);
