INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMODE_PASSWORDRESET', 'string', NULL, 'admin', 'Selects the mail sending method used specifically for password reset emails, overriding the default mail send mode.', 'Written and read extensively in admin/mails_passwordreset.php (31 occurrences). When set and not ''default'', a dedicated send mode is used for password reset emails. Supported values include ''mail'', ''smtps'', ''swiftmailer''.', 'Changing this value switches the transport used for password reset emails independently of the global mail mode. Setting to ''default'' or leaving unset falls back to the system default mail mode.', 'String: ''mail'' = PHP mail(); ''smtps'' = SMTP/S; ''swiftmailer'' = SwiftMailer; ''default'' or unset = use global MAIN_MAIL_SENDMODE.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:625|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE_PASSWORDRESET'') && getDolGlobalString(''MAIN_MAIL_SENDMODE_PASSWORDRESET'') != ''default'') {", "admin/mails_passwordreset.php:627|check|if ($linuxlike && (getDolGlobalString(''MAIN_MAIL_SENDMODE_PASSWORDRESET'') == ''mail'')) {", "admin/mails_passwordreset.php:445|check|if (!empty($conf->use_javascript_ajax) || in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE_PASSWORDRESET''), array(''smtps'', ''swiftmailer''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SENDMODE_TICKET', 'string', NULL, 'admin', 'Specifies the mail sending method used for ticket-related emails, overriding the default global mail send mode.', 'Configured in admin/mails_ticket.php (31 occurrences including reads and checks); when set to a non-''default'' value, ticket emails use the specified transport. Values ''smtps'' and ''swiftmailer'' trigger additional SMTP configuration fields in the admin UI.', 'Changing this value switches the mail transport for ticket emails. Setting it to ''smtps'' or ''swiftmailer'' exposes SMTP host/port/credential fields; leaving it as ''default'' inherits the global mail send mode.', '''default'' = use global send mode; ''smtps'' = use SMTPS/PHPMailer; ''swiftmailer'' = use SwiftMailer.', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:600|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE_TICKET'') && getDolGlobalString(''MAIN_MAIL_SENDMODE_TICKET'') != ''default'') {", "admin/mails_ticket.php:442|check|if (!empty($conf->use_javascript_ajax) || in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE_TICKET''), array(''smtps'', ''swiftmailer''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_AUTH_TYPE', 'string', NULL, 'admin', 'Specifies the SMTP authentication method used when sending emails via SMTPS or Swiftmailer.', 'Controls which authentication protocol is used for outgoing SMTP connections. Default value if not defined is ''LOGIN'' (but login/pass may be empty and they won''t be provided in such a case). The value ''XOAUTH2'' triggers OAuth2-based authentication paths in both admin/mails.php and admin/mails_ingoing.php. Configurable via the admin UI at admin/mails.php.', 'Switching from ''LOGIN'' to ''XOAUTH2'' requires OAuth2 credentials to be configured; reverting disables OAuth2 and falls back to username/password authentication.', '''LOGIN'' (default), ''XOAUTH2''', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails_ingoing.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// Note: Default value for MAIN_MAIL_SMTPS_AUTH_TYPE if not defined is ''LOGIN'' (but login/pass may be empty and they won''t be provided in such a case)", "admin/mails.php:761|check|if (in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail''), array(''smtps'', ''swiftmailer'')) && getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE'') != \"XOAUTH2\") {", "admin/mails.php:766|check|if (in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE'', ''mail''), array(''smtps'', ''swiftmailer'')) && getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE'') === \"XOAUTH2\") {", "core/class/smtps.class.php:671|check|if (!getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING', 'string', NULL, 'admin', 'Sets the SMTP authentication type (e.g. LOGIN or XOAUTH2) used for mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 101). Read at line 623 with default ''LOGIN''. Checked at lines 641 and 646 to branch between credential-based and OAuth2 display in the admin summary.', 'Changing this to ''XOAUTH2'' switches mass emailing to OAuth2 authentication; ''LOGIN'' uses standard username/password credentials.', '''LOGIN'' = standard credential authentication; ''XOAUTH2'' = OAuth2 token authentication.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:101|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING\", GETPOST(\"MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:623|read|$authtype = getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING'', ''LOGIN'');", "admin/mails_emailing.php:641|check|if (in_array(...) && getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING'') != \"XOAUTH2\") {", "admin/mails_emailing.php:646|check|if (in_array(...) && getDolGlobalString(''MAIN_MAIL_SMTPS_AUTH_TYPE_EMAILING'') === \"XOAUTH2\") {"]', 'high', NULL);
