INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_ID_TICKET', 'string', NULL, 'admin', 'Specifies the SMTP authentication username used for sending ticket emails.', 'Written in admin/mails_ticket.php at line 94 and read at lines 471, 478, and 631. Displayed in the admin UI with a superadmin tooltip.', 'Setting this constant provides the login credential for SMTP authentication when sending ticket emails. If unset, no username is submitted to the SMTP server.', 'A string containing the SMTP login/username (e.g. an email address or account name).', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:94|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_ID_TICKET\", GETPOST(\"MAIN_MAIL_SMTPS_ID_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:471|read|$mainstmpid = getDolGlobalString(''MAIN_MAIL_SMTPS_ID_TICKET'');", "admin/mails_ticket.php:631|read|print ''<tr class=\"oddeven hideifdefault\"><td>''.$langs->trans(\"MAIN_MAIL_SMTPS_ID\").''</td><td>''.getDolGlobalString(''MAIN_MAIL_SMTPS_ID_TICKET'').''</td></tr>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_OAUTH_SERVICE', 'string', NULL, 'admin', 'Identifies the OAuth2 service provider used for SMTP authentication.', 'Written at admin/mails.php:117 and via admin/oauth.php:162 (renamed when a provider label changes). Read and displayed at admin/mails.php:536, 538, 544, 767, and admin/mails_ingoing.php:130 to select and show the active OAuth service for outgoing mail.', 'Changing this value switches the OAuth2 provider used for SMTP authentication; an incorrect value will prevent mail sending.', 'String in the format ''PROVIDER-label'' identifying the configured OAuth2 service (e.g. ''GOOGLE-myaccount''); empty = no OAuth service selected', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php|admin/oauth.php|admin/mails_ingoing.php|admin/oauth.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails.php:117|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_OAUTH_SERVICE\", GETPOST(\"MAIN_MAIL_SMTPS_OAUTH_SERVICE\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/oauth.php:161|check|if (getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE'') == $oldname) {", "admin/oauth.php:162|write|if (!dolibarr_set_const($db, ''MAIN_MAIL_SMTPS_OAUTH_SERVICE'', strtoupper($oldprovider).''-''.$newlabel, ''chaine'', 0, '''', $conf->entity)) {", "admin/mails.php:536|read|print $form->selectarray(''MAIN_MAIL_SMTPS_OAUTH_SERVICE'', $oauthservices, getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING', 'string', NULL, 'admin', 'Selects the OAuth2 service used for SMTP authentication in mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 104). Displayed as a dropdown (selectarray at line 509) populated from available OAuth services. The selected key is also stored in a hidden input (line 517) and shown in the summary (line 647).', 'Changing this value switches the OAuth2 provider used for SMTP authentication in mass emailing; selecting an unconfigured service will prevent email delivery.', 'String key corresponding to an OAuth service name configured in Dolibarr; empty = no OAuth service.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:104|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING\", GETPOST(\"MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:509|read|print $form->selectarray(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING'', $oauthservices, getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING''));", "admin/mails_emailing.php:647|read|$text = $oauthservices[getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_EMAILING'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET', 'string', NULL, 'admin', 'Selects the OAuth service provider used for SMTP authentication in password reset emails.', 'Written at admin/mails_passwordreset.php:102 and read at :507, :509, :515, :666. Rendered as a select array of available OAuth services; the selected value identifies the OAuth provider key.', 'Changing this value switches the OAuth provider for password reset SMTP authentication. Leaving unset means no OAuth service is configured for this channel.', 'String: OAuth service key identifying the provider; empty/unset = no OAuth service configured for password reset emails.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:102|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:507|read|print $form->selectarray(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET'', $oauthservices, getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET''));", "admin/mails_passwordreset.php:666|read|$text = $oauthservices[getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_PASSWORDRESET'')];"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET', 'string', NULL, 'admin', 'Selects the OAuth2 service used for SMTP authentication when sending ticket emails.', 'Written in admin/mails_ticket.php at line 102 and read at lines 504, 506, 512, and 641 where it selects the OAuth service from the list of available OAuth services.', 'Setting this constant to an OAuth service key enables OAuth2-based SMTP authentication for ticket emails. If unset or invalid, no OAuth service is selected.', 'A key string identifying one of the configured OAuth services (values come from $oauthservices array at runtime).', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:102|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET\", GETPOST(\"MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:641|read|$text = $oauthservices[getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET'')];", "admin/mails_ticket.php:504|read|print $form->selectarray(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET'', $oauthservices, getDolGlobalString(''MAIN_MAIL_SMTPS_OAUTH_SERVICE_TICKET''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_PW', 'string', NULL, 'admin', 'Stores the SMTP authentication password used when connecting to the SMTP server.', 'Read in admin/mails.php:515 and admin/mails.php:762, where it is masked with asterisks before display. Written via admin/mails.php:111 using the ''password'' filter. Also shown masked in the debugbar at debugbar/class/DataCollector/DolibarrCollector.php:115.', 'Changing this value updates the password used for SMTP authentication; an incorrect password prevents email delivery.', 'String. SMTP authentication password. Stored encrypted; displayed as masked asterisks in the UI.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:762|read|print ''<tr class=\"oddeven\"><td>''.$langs->trans(\"MAIN_MAIL_SMTPS_PW\").''</td><td>''.preg_replace(''/./'', ''*'', getDolGlobalString(''MAIN_MAIL_SMTPS_PW'')).''</td></tr>'';", "admin/mails.php:111|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_PW\", GETPOST(\"MAIN_MAIL_SMTPS_PW\", ''password''), ''chaine'', 0, '''', $conf->entity);", "debugbar/class/DataCollector/DolibarrCollector.php:115|read|$info .= $langs->trans(''Pwd'').'': <strong>''.preg_replace(''/./'', ''*'', getDolGlobalString(\"MAIN_MAIL_SMTPS_PW\")).''</strong><br>'';", "admin/mails.php:515|read|$mainsmtppw = getDolGlobalString(''MAIN_MAIL_SMTPS_PW'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_PW_EMAILING', 'string', NULL, 'admin', 'Stores the SMTP authentication password used for mass emailing.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 98, using ''password'' filter). Read at lines 489 and 496 for connection setup, and displayed masked (asterisks) in the admin summary at line 642.', 'Changing this value updates the SMTP password for mass emailing; an incorrect value will cause authentication failures.', 'String (SMTP password); empty = no password.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:98|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_PW_EMAILING\", GETPOST(\"MAIN_MAIL_SMTPS_PW_EMAILING\", ''password''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:642|read|print ''...<td>''.preg_replace(''/./'', ''*'', getDolGlobalString(''MAIN_MAIL_SMTPS_PW_EMAILING'')).''</td>...''", "admin/mails_emailing.php:489|read|$mainsmtppw = getDolGlobalString(''MAIN_MAIL_SMTPS_PW_EMAILING'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_PW_PASSWORDRESET', 'string', NULL, 'admin', 'Stores the SMTP authentication password used specifically for password reset emails.', 'Written at admin/mails_passwordreset.php:96 (using ''password'' sanitization) and read at :489, :496, :661 (displayed masked with asterisks). Configurable via the admin UI.', 'Changing this value updates the SMTP password for the password reset email channel. The value is stored in the database; ensure the database is secured appropriately.', 'String: SMTP password (stored as-is, displayed masked); empty/unset = no dedicated password for password reset emails.', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:96|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_PW_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_SMTPS_PW_PASSWORDRESET\", ''password''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:489|read|$mainsmtppw = getDolGlobalString(''MAIN_MAIL_SMTPS_PW_PASSWORDRESET'');", "admin/mails_passwordreset.php:661|read|print ''<tr class=\"oddeven hideifdefault\"><td>''.$langs->trans(\"MAIN_MAIL_SMTPS_PW\").''</td><td>''.preg_replace(''/./'', ''*'', getDolGlobalString(''MAIN_MAIL_SMTPS_PW_PASSWORDRESET'')).''</t"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTPS_PW_TICKET', 'string', NULL, 'admin', 'Specifies the SMTP authentication password used for sending ticket emails.', 'Written in admin/mails_ticket.php at line 96 (with ''password'' sanitization) and read at lines 486, 493, and 636 where it is masked with asterisks in the display.', 'Setting this constant provides the password for SMTP authentication when sending ticket emails. The value is stored as plaintext in the database and should be treated as sensitive.', 'A plaintext password string for SMTP authentication.', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:96|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTPS_PW_TICKET\", GETPOST(\"MAIN_MAIL_SMTPS_PW_TICKET\", ''password''), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:636|read|print ''<tr class=\"oddeven hideifdefault\"><td>''.$langs->trans(\"MAIN_MAIL_SMTPS_PW\").''</td><td>''.preg_replace(''/./'', ''*'', getDolGlobalString(''MAIN_MAIL_SMTPS_PW_TICKET'')).''</td></tr>"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_PORT', 'string', '', 'admin', 'Specifies the TCP port used to connect to the SMTP server for sending emails.', 'Read in admin/mails.php:182 as an integer (falling back to PHP ini smtp_port) and displayed at admin/mails.php:736. Written via admin/mails.php:107 and shown in the debugbar at debugbar/class/DataCollector/DolibarrCollector.php:113.', 'Changing this value alters the port used for SMTP connections; incorrect values prevent email delivery.', 'Integer port number. Empty string means use PHP ini smtp_port setting as fallback.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:182|read|$port = getDolGlobalInt(''MAIN_MAIL_SMTP_PORT'', (int) ini_get(''smtp_port''));", "admin/mails.php:107|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_PORT\", GETPOSTINT(\"MAIN_MAIL_SMTP_PORT\"), ''chaine'', 0, '''', $conf->entity);", "debugbar/class/DataCollector/DolibarrCollector.php:113|read|$info .= $langs->trans(''Port'').'': <strong>''.getDolGlobalString(\"MAIN_MAIL_SMTP_PORT\").''</strong><br>'';", "admin/mails.php:444|read|$mainport = getDolGlobalString(''MAIN_MAIL_SMTP_PORT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_PORT_EMAILING', 'string', NULL, 'admin', 'Sets the SMTP port used specifically for mass emailing, overriding the global SMTP port.', 'Configured via admin/mails_emailing.php (dolibarr_set_const at line 94). Read as an int at line 152 with a fallback to the PHP ini smtp_port, and as a string at line 422 for connection setup. Displayed in the admin UI at line 618.', 'Changing this port number redirects mass-emailing SMTP connections to the specified port; an incorrect value will prevent email delivery.', 'Integer SMTP port number (e.g. 25, 465, 587); empty/unset = falls back to PHP ini smtp_port.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_emailing.php:94|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_PORT_EMAILING\", GETPOST(\"MAIN_MAIL_SMTP_PORT_EMAILING\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_emailing.php:152|read|$port = getDolGlobalInt(''MAIN_MAIL_SMTP_PORT_EMAILING'', (int) ini_get(''smtp_port''));", "admin/mails_emailing.php:422|read|$mainport = getDolGlobalString(''MAIN_MAIL_SMTP_PORT_EMAILING'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_PORT_PASSWORDRESET', 'string', NULL, 'admin', 'Sets the SMTP port used specifically for password reset email sending.', 'Written at admin/mails_passwordreset.php:92 and read at :154 (with fallback to php.ini smtp_port) and :422. Configurable via the admin UI at admin/mails_passwordreset.php.', 'Changing this value sets the TCP port for SMTP connections used only for password reset emails. Leaving unset falls back to the PHP ini smtp_port setting.', 'Integer port number (e.g. 25, 465, 587); unset = fallback to ini_get(''smtp_port'').', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:92|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_PORT_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_SMTP_PORT_PASSWORDRESET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:154|read|$port = getDolGlobalInt(''MAIN_MAIL_SMTP_PORT_PASSWORDRESET'', (int) ini_get(''smtp_port''));", "admin/mails_passwordreset.php:422|read|$mainport = getDolGlobalString(''MAIN_MAIL_SMTP_PORT_PASSWORDRESET'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_PORT_TICKET', 'string', NULL, 'admin', 'Specifies the SMTP port used for sending ticket emails, overriding the global SMTP port.', 'Written in admin/mails_ticket.php at line 92 and read at lines 152 and 419; falls back to PHP ini smtp_port when unset. Configurable via admin/mails_ticket.php UI.', 'Setting this constant changes the TCP port used for SMTP connections when sending ticket emails. If unset, the PHP ini smtp_port value is used.', 'Integer port number (e.g. 25, 465, 587).', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:92|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_PORT_TICKET\", GETPOST(\"MAIN_MAIL_SMTP_PORT_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:152|read|$port = getDolGlobalInt(''MAIN_MAIL_SMTP_PORT_TICKET'', (int) ini_get(''smtp_port''));", "admin/mails_ticket.php:419|read|$mainport = getDolGlobalString(''MAIN_MAIL_SMTP_PORT_TICKET'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_SERVER', 'string', '', 'comm', 'Specifies the hostname or IP address of the SMTP server used for sending emails.', 'Read in admin/mails.php:186 as the SMTP server address (falling back to PHP ini SMTP setting) and displayed at admin/mails.php:728. Used in comm/mailing/targetemailing.php:479-481 and debugbar/class/DataCollector/DolibarrCollector.php:112. Written via admin/mails.php:108.', 'Changing this value redirects all outgoing email through the specified server; leaving it empty while using smtps or swiftmailer mode triggers a configuration warning in the menu.', 'Hostname or IP address string. Empty string means use PHP ini SMTP setting as fallback.', 0, 0, 'admin/mails.php|admin/mails.php|admin/mails.php|admin/mails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails.php:186|read|$server = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'', ini_get(''SMTP''));", "core/menus/standard/eldy.lib.php:1209|check|if (getDolGlobalString(''MAIN_MAIL_SENDMODE'') && in_array(getDolGlobalString(''MAIN_MAIL_SENDMODE''), array(''smtps'', ''swiftmail'')) && !getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'')) {", "debugbar/class/DataCollector/DolibarrCollector.php:112|read|$info .= $langs->trans(''Server'').'': <strong>''.getDolGlobalString(\"MAIN_MAIL_SMTP_SERVER\").''</strong><br>'';", "admin/mails.php:108|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_SERVER\", GETPOST(\"MAIN_MAIL_SMTP_SERVER\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_SERVER_EMAILING', 'string', NULL, 'comm', 'Specifies the SMTP server hostname used for mass emailing campaigns, overriding the global SMTP server setting.', 'Written via admin/mails_emailing.php:95, read at line 156 with fallback to ini_get(''SMTP'') and at line 390. Displayed in comm/mailing/card.php:1229 and targetemailing.php:479 with fallback to getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'').', 'Changing this constant redirects outbound emailing campaign messages to the specified SMTP server. If unset, the system falls back to the global MAIN_MAIL_SMTP_SERVER or PHP ini SMTP setting.', 'Hostname or IP string of the SMTP server for emailing. Empty/unset = fall back to MAIN_MAIL_SMTP_SERVER.', 0, 0, 'admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php|admin/mails_emailing.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/mails_emailing.php:156|read|$server = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_EMAILING'', ini_get(''SMTP''));", "admin/mails_emailing.php:95|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_SERVER_EMAILING\", GETPOST(\"MAIN_MAIL_SMTP_SERVER_EMAILING\"), ''chaine'', 0, '''', $conf->entity);", "comm/mailing/targetemailing.php:479|read|print '' <span class=\"opacitymedium\">(''.getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_EMAILING'', getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'')).'')</span>'';", "comm/mailing/card.php:1229|read|print '' <span class=\"opacitymedium\">(''.getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_EMAILING'', getDolGlobalString(''MAIN_MAIL_SMTP_SERVER'')).'')</span>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_SERVER_PASSWORDRESET', 'string', NULL, 'admin', 'Sets the SMTP server hostname used specifically for password reset email sending.', 'Written at admin/mails_passwordreset.php:93 and read at :158 (with fallback to php.ini SMTP) and :390. Configurable via the admin UI at admin/mails_passwordreset.php.', 'Changing this value routes password reset emails through a different SMTP host. Leaving unset falls back to the PHP ini SMTP setting.', 'String: SMTP hostname (e.g. ''smtp.example.com''); unset = fallback to ini_get(''SMTP'').', 0, 0, 'admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php|admin/mails_passwordreset.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_passwordreset.php:93|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_SERVER_PASSWORDRESET\", GETPOST(\"MAIN_MAIL_SMTP_SERVER_PASSWORDRESET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_passwordreset.php:158|read|$server = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_PASSWORDRESET'', ini_get(''SMTP''));", "admin/mails_passwordreset.php:390|read|$mainserver = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_PASSWORDRESET'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_SMTP_SERVER_TICKET', 'string', NULL, 'admin', 'Specifies the SMTP server hostname used for sending ticket emails, overriding the global SMTP server.', 'Written in admin/mails_ticket.php at line 93 and read at lines 156 and 387; falls back to PHP ini SMTP value when unset. Configurable via admin/mails_ticket.php UI.', 'Setting this constant routes ticket email through the specified SMTP server. If unset, the PHP ini SMTP setting is used.', 'Hostname or IP address of the SMTP server (e.g. ''smtp.example.com'').', 0, 0, 'admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php|admin/mails_ticket.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mails_ticket.php:93|write|dolibarr_set_const($db, \"MAIN_MAIL_SMTP_SERVER_TICKET\", GETPOST(\"MAIN_MAIL_SMTP_SERVER_TICKET\"), ''chaine'', 0, '''', $conf->entity);", "admin/mails_ticket.php:156|read|$server = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_TICKET'', ini_get(''SMTP''));", "admin/mails_ticket.php:387|read|$mainserver = getDolGlobalString(''MAIN_MAIL_SMTP_SERVER_TICKET'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAIL_USE_MULTI_PART', 'bool', NULL, 'core', 'Enables multipart/alternative email structure so both plain-text and HTML parts are sent together.', 'When set, core/class/smtps.class.php selects multipart encoding paths at lines 1782, 1803, 1703, and 1687; core/class/CMailFile.class.php adds plain-text parts at lines 1831 and 1845. The X-Dolibarr-Option header at smtps.class.php:1604 reflects the active state.', 'Enabling this sends emails with both HTML and plain-text parts; disabling it sends only the HTML part without a text alternative.', 'Any non-empty string value enables multipart/alternative structure.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/smtps.class.php:1604|read|$_header .= ''X-Dolibarr-Option: ''.($conf->global->MAIN_MAIL_USE_MULTI_PART ? ''MAIN_MAIL_USE_MULTI_PART'' : ''No MAIN_MAIL_USE_MULTI_PART'').\"\\r\\n\";", "core/class/CMailFile.class.php:1831|check|if (!$this->atleastoneimage && $strContentAltText && getDolGlobalString(''MAIN_MAIL_USE_MULTI_PART'')) {    // Add plain text message part before html part", "core/class/smtps.class.php:1782|check|if (!array_key_exists(''image'', $this->_msgContent) && $_content[''dataText''] && getDolGlobalString(''MAIN_MAIL_USE_MULTI_PART'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MANIFEST_APPLI_BG_COLOR', 'string', NULL, 'theme', 'Sets the background_color value in the PWA web app manifest used when the application is launched as a PWA.', 'Read in theme/eldy/manifest.json.php:90 and theme/md/manifest.json.php:87 to set $manifest->background_color. Falls back to ''#ffffff'' if unset. No admin UI write path is present in the payload.', 'Setting this value changes the splash-screen background colour shown when the PWA is launched. Leaving it unset defaults to white (#ffffff).', 'CSS hex colour string. Defaults to ''#ffffff''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/manifest.json.php:90|read|$manifest->background_color = getDolGlobalString(''MAIN_MANIFEST_APPLI_BG_COLOR'', \"#ffffff\");", "theme/md/manifest.json.php:87|read|$manifest->background_color = getDolGlobalString(''MAIN_MANIFEST_APPLI_BG_COLOR'', \"#ffffff\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MANIFEST_APPLI_LOGO_URL', 'string', NULL, 'theme', 'Specifies the URL of the icon to include in the PWA web app manifest.', 'Checked and read in theme/eldy/manifest.json.php:101, :103 and theme/md/manifest.json.php:98, :100 to set $icon->src in the manifest icons array. No admin UI write path is present in the payload.', 'Setting this to a valid image URL causes the PWA manifest to include that image as its application icon. Leaving it unset omits the custom icon entry from the manifest.', 'URL string pointing to an image file to use as the PWA application icon.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/manifest.json.php:101|check|if (getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL'')) {", "theme/eldy/manifest.json.php:103|read|$icon->src = getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL'');", "theme/md/manifest.json.php:98|check|if (getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL'')) {", "theme/md/manifest.json.php:100|read|$icon->src = getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MANIFEST_APPLI_LOGO_URL_SIZE', 'string', NULL, 'theme', 'Specifies the pixel dimension of the PWA manifest icon, used to set the sizes attribute in the manifest icon entry.', 'Read in theme/eldy/manifest.json.php:105 and theme/md/manifest.json.php:102 to construct $icon->sizes as "<value>x<value>". Conditioned on MAIN_MANIFEST_APPLI_LOGO_URL being set (theme/eldy/manifest.json.php:104; theme/md/manifest.json.php:101).', 'Setting this to a pixel value (e.g. 192) causes the manifest icon sizes attribute to be set to ''<value>x<value>''. Leaving it unset omits the sizes attribute.', 'Integer pixel size (e.g. 192). Used to form sizes attribute as ''<value>x<value>''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/manifest.json.php:105|read|$icon->sizes = getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL_SIZE'') . \"x\" . getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL_SIZE'');", "theme/md/manifest.json.php:101|check|if (getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL_SIZE'')) {", "theme/md/manifest.json.php:102|read|$icon->sizes = getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL_SIZE'') . \"x\" . getDolGlobalString(''MAIN_MANIFEST_APPLI_LOGO_URL_SIZE'');", "theme/eldy/manifest.json.php:104|read|if ($conf->global->MAIN_MANIFEST_APPLI_LOGO_URL_SIZE) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MANIFEST_APPLI_THEME_COLOR', 'string', NULL, 'theme', 'Sets the theme_color value in the PWA web app manifest, overriding the default top-menu background colour.', 'Read in both theme/eldy/manifest.json.php:85 and theme/md/manifest.json.php:82 to set $manifest->theme_color. Falls back to THEME_ELDY_TOPMENU_BACK1, then to ''#F05F40'' if neither is set. No admin UI write path is present in the payload.', 'Setting this value changes the browser chrome/toolbar colour shown when the application is installed as a PWA.', 'CSS hex colour string (e.g. ''#F05F40''). Falls back to THEME_ELDY_TOPMENU_BACK1 or ''#F05F40''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/manifest.json.php:85|read|$manifest->theme_color = getDolGlobalString(''MAIN_MANIFEST_APPLI_THEME_COLOR'', getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'', ''#F05F40''));", "theme/md/manifest.json.php:82|read|$manifest->theme_color = getDolGlobalString(''MAIN_MANIFEST_APPLI_THEME_COLOR'', getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'', ''#F05F40''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MANIFEST_DISPLAY', 'string', NULL, 'theme', 'Sets the display mode in the PWA web app manifest, controlling how the application window is presented when installed.', 'Read in theme/eldy/manifest.json.php:95 and theme/md/manifest.json.php:92 to set $manifest->display. Falls back to ''minimal-ui'' if unset. No admin UI write path is present in the payload.', 'Changing this value alters the PWA display mode (e.g. fullscreen, standalone, minimal-ui, browser). Leaving it unset defaults to ''minimal-ui''.', 'PWA display mode string. Defaults to ''minimal-ui''. Valid values per Web App Manifest spec: ''fullscreen'', ''standalone'', ''minimal-ui'', ''browser''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/manifest.json.php:95|read|$manifest->display = getDolGlobalString(''MAIN_MANIFEST_DISPLAY'', \"minimal-ui\");", "theme/md/manifest.json.php:92|read|$manifest->display = getDolGlobalString(''MAIN_MANIFEST_DISPLAY'', \"minimal-ui\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MASSACTION_CREATEBILLS_REDIRECT_IF_MANY', 'string', NULL, 'commande', 'When set to 1, redirects to the invoice list after a mass ''create bills'' action that produces more than one invoice.', 'Checked in commande/list.php:727: when the constant equals 1 and multiple invoices were created, the response redirects to the invoice list.', 'Setting this to 1 enables automatic redirection to the invoice list after a mass billing action producing multiple invoices.', '1 = redirect to invoice list when multiple are created; 0 or unset = no redirect.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:727|check|if (getDolGlobalInt(''MAIN_MASSACTION_CREATEBILLS_REDIRECT_IF_MANY'') == 1) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MASSACTION_CREATEBILLS_REDIRECT_IF_ONE', 'string', NULL, 'commande', 'When set to 1, redirects directly to the created invoice after a mass ''create bills'' action that produces exactly one invoice.', 'Checked in commande/list.php:718: when the constant equals 1 and exactly one invoice was created, the response redirects to that invoice.', 'Setting this to 1 enables automatic redirection to the single created invoice after a mass billing action.', '1 = redirect to invoice when only one is created; 0 or unset = no redirect.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:718|check|if (getDolGlobalInt(''MAIN_MASSACTION_CREATEBILLS_REDIRECT_IF_ONE'') == 1) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAXLIST_OVERLOAD', 'string', NULL, 'compta', 'Overrides the default maximum number of records (500) fetched for invoice and order index pages.', 'Read in 23 locations including compta/facture/index.php:55, fourn/facture/index.php:52 and :54, compta/index.php:79 and :81, and commande/index.php:68. Default fallback is 500 where not set.', 'Setting this constant changes the cap on draft and open record counts displayed on invoice and order dashboard pages.', 'Integer; overrides the default 500-record limit on dashboard list pages', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/index.php:55|read|$maxDraftCount = getDolGlobalInt(''MAIN_MAXLIST_OVERLOAD'', $max);", "fourn/facture/index.php:52|read|$maxDraftCount = getDolGlobalInt(''MAIN_MAXLIST_OVERLOAD'', 500);", "compta/index.php:79|read|$maxDraftCount = !getDolGlobalString(''MAIN_MAXLIST_OVERLOAD'') ? 500 : $conf->global->MAIN_MAXLIST_OVERLOAD;", "commande/index.php:68|read|$maxDraftCount = !getDolGlobalString(''MAIN_MAXLIST_OVERLOAD'') ? 500 : $conf->global->MAIN_MAXLIST_OVERLOAD;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAXTABS_IN_CARD', 'string', NULL, 'core', 'Sets the maximum number of tabs displayed in an entity card view, defaulting to 99 if not defined.', 'Read as an integer in core/lib/functions.lib.php:3192 with a default of 99. No admin UI write detected.', 'Lowering this value limits the number of tabs shown on card views, hiding excess tabs. The default of 99 effectively shows all tabs.', 'Integer; default 99 (show all tabs). Set to a lower integer to cap the number of visible tabs.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3192|read|$limittoshow = getDolGlobalInt(''MAIN_MAXTABS_IN_CARD'', 99);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_CURRENCY_TOT', 'string', NULL, 'core', 'Sets the maximum decimal places for currency total amounts, falling back to MAIN_MAX_DECIMALS_TOT.', 'Read at core/lib/functions.lib.php:7965 with MAIN_MAX_DECIMALS_TOT as the default fallback. Also used in core/modules/facture/doc/pdf_sponge.modules.php:2147 to compute a maximum decimal bound for invoice PDF generation.', 'Adjusting this value changes decimal precision for totals in financial outputs including invoice PDFs.', 'Integer value representing decimal places; if unset, falls back to MAIN_MAX_DECIMALS_TOT', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7965|read|$nbofdectoround = getDolGlobalInt(''MAIN_MAX_DECIMALS_CURRENCY_TOT'', getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT''));\t\t// TODO Use param of currency", "core/modules/facture/doc/pdf_sponge.modules.php:2147|read|$maxnbofdec = getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT'') + getDolGlobalInt(''MAIN_MAX_DECIMALS_CURRENCY_TOT'', getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT'')) + 1;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_CURRENCY_UNIT', 'string', NULL, 'core', 'Sets the maximum decimal places for currency unit amounts, falling back to MAIN_MAX_DECIMALS_UNIT.', 'Read at core/lib/functions.lib.php:7963 via getDolGlobalInt with MAIN_MAX_DECIMALS_UNIT as the fallback default. A TODO comment notes future per-currency parameterisation.', 'Changing this value alters the decimal precision used for unit-level currency amounts in financial calculations.', 'Integer value representing decimal places; if unset, falls back to MAIN_MAX_DECIMALS_UNIT', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7963|read|$nbofdectoround = getDolGlobalInt(''MAIN_MAX_DECIMALS_CURRENCY_UNIT'', getDolGlobalInt(''MAIN_MAX_DECIMALS_UNIT''));\t// TODO Use param of currency"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_SHOWN', 'bool', NULL, 'core', 'Sets the maximum number of decimal places displayed for amounts in the Dolibarr interface.', 'Read in admin/limits.php:187,218 for the admin UI, core/lib/functions.lib.php:7789 for PHP formatting, and core/js/lib_head.js.php:1396,1475 for JavaScript formatting. The comment in core/lib/functions.lib.php:7725 notes: ''1=Truncate if there is more decimals than MAIN_MAX_DECIMALS_SHOWN (default), 0=Does not truncate.''', 'Reducing this value truncates displayed decimal precision across the interface; a value containing ''...'' triggers special truncation logic in the PHP formatter.', 'Integer number of decimal places to show; may also contain ''...'' to trigger truncation mode', 0, 0, 'admin/limits.php|admin/limits.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["1=Truncate if there is more decimals than MAIN_MAX_DECIMALS_SHOWN (default), 0=Does not truncate.", "$nbdecimalmaxshown = (int) str_replace(''...'', '''', getDolGlobalString(''MAIN_MAX_DECIMALS_SHOWN''));", "if (preg_match(''/\\.\\.\\./'', getDolGlobalString(''MAIN_MAX_DECIMALS_SHOWN''))) {", "var main_max_dec_shown = <?php echo (int) str_replace(''.'', '''', getDolGlobalString(''MAIN_MAX_DECIMALS_SHOWN'')); ?>;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_STOCK', 'string', NULL, 'core', 'Sets the maximum number of decimal places used when rounding stock quantities.', 'Read via getDolGlobalInt at core/lib/functions.lib.php:7961 with a default of 5. The comment at line 7847 identifies it as the ''MS'' rounding mode: ''MS''=Round to Max for stock quantity (MAIN_MAX_DECIMALS_STOCK).', 'Reducing this value decreases precision for stock quantity display and calculations; increasing it allows finer-grained stock figures.', '''MS'' rounding mode uses this constant; integer value representing decimal places; default is 5', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7847  *                                                                  ''MS''=Round to Max for stock quantity (MAIN_MAX_DECIMALS_STOCK)", "core/lib/functions.lib.php:7961|read|$nbofdectoround = getDolGlobalInt(''MAIN_MAX_DECIMALS_STOCK'', 5);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_TOT', 'string', NULL, 'core', 'Defines the maximum number of decimal places used when displaying total amounts.', 'Configured via admin/limits.php:184 and referenced in core/lib/price.lib.php:428, core/class/commonobject.class.php:4239, core/modules/facture/doc/pdf_sponge.modules.php:2147, and core/lib/functions.lib.php:7726. Used as the total-amount rounding precision in price calculations and PDF generation.', 'Reducing this value lowers the precision for displayed totals across invoices, salaries, and PDF documents; it also affects rounding tolerance checks.', 'Positive integer representing the maximum number of decimal digits for total amounts (e.g., 2)', 0, 0, 'admin/limits.php|admin/limits.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:7726  *\t\t@param\tint<-1,max>\t\t\t\t$rounding\t\tMINIMUM number of decimal to show: 0=no change, -1=we use min(getDolGlobalString(''MAIN_MAX_DECIMALS_UNIT''), getDolGlobalString(''MAIN_MAX_DECIMALS_TOT''))", "core/class/commonobject.class.php:4239|read|$maxdiff = (10 * pow(10, -1 * getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT'', 0)));", "core/modules/facture/doc/pdf_sponge.modules.php:2147|read|$maxnbofdec = getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT'') + getDolGlobalInt(''MAIN_MAX_DECIMALS_CURRENCY_TOT'', getDolGlobalInt(''MAIN_MAX_DECIMALS_TOT'')) + 1;", "admin/limits.php:184|read|print ''</td><td><input class=\"flat right\" name=\"''.$mainmaxdecimalstot.''\" size=\"3\""]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MAX_DECIMALS_UNIT', 'string', NULL, 'core', 'Defines the maximum number of decimal places used when displaying unit prices.', 'Configured via admin/limits.php:180 and referenced in core/lib/price.lib.php:416/427, core/lib/functions.lib.php:7726, and compta/facture/class/facture.class.php:6115. COMMENTS confirm: ''MU=Round to Max unit price (MAIN_MAX_DECIMALS_UNIT)'' and ''rounding=-1 uses min(MAIN_MAX_DECIMALS_UNIT, MAIN_MAX_DECIMALS_TOT)''.', 'Reducing this value decreases the precision shown for unit prices throughout invoices, price lists, and PDF documents; increasing it raises display precision.', 'Positive integer representing the maximum number of decimal digits for unit prices (e.g., 5)', 0, 0, 'admin/limits.php|admin/limits.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:7845  *                                                                  ''MU''=Round to Max unit price (MAIN_MAX_DECIMALS_UNIT)", "core/lib/functions.lib.php:7726  *\t\t@param\tint<-1,max>\t\t\t\t$rounding\t\tMINIMUM number of decimal to show: 0=no change, -1=we use min(getDolGlobalString(''MAIN_MAX_DECIMALS_UNIT''), getDolGlobalString(''MAIN_MAX_DECIMALS_TOT''))", "compta/facture/class/facture.class.php:6115|read|$rounding = min(getDolGlobalString(''MAIN_MAX_DECIMALS_UNIT''), getDolGlobalString(''MAIN_MAX_DECIMALS_TOT''));", "admin/limits.php:180|read|print ''</td><td><input class=\"flat right\" name=\"''.$mainmaxdecimalsunit.''\" size=\"3\" value=\"''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MEMBER_CODE_ALWAYS_REQUIRED', 'string', NULL, 'core', 'When enabled, makes the member code mandatory even when the underlying code generator allows null codes.', 'Checked at core/modules/member/modules_member.class.php:97. When truthy and $this->code_null is non-empty (indicating the generator allows blank codes), the code is still enforced as required.', 'Enabling forces all member records to have a non-empty code regardless of the code module''s null-allowed setting. Disabling defers to the code module''s own requirement.', 'Truthy = member code always required; empty/unset = defer to code module setting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/member/modules_member.class.php:97|check|if (getDolGlobalString(''MAIN_MEMBER_CODE_ALWAYS_REQUIRED'') && !empty($this->code_null)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MEMORY_LIMIT_ARCHIVE_DATAROOT', 'string', NULL, 'admin', 'Overrides the PHP memory limit applied during the data-root file archive export.', 'Read in admin/tools/export_files.php:113 and assigned to $MemoryLimit, which is used to set the PHP memory limit for the archive operation.', 'Setting a value raises or lowers the PHP memory ceiling for the archive export; leaving it empty uses the server default.', 'Any PHP memory limit string (e.g. ''512M'', ''1G'').', 0, 0, 'admin/tools/export_files.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/export_files.php:113|read|$MemoryLimit = getDolGlobalString(''MAIN_MEMORY_LIMIT_ARCHIVE_DATAROOT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MEMORY_LIMIT_DUMP', 'string', NULL, 'core', 'Sets the PHP memory limit applied during database dump operations.', 'Read in core/class/utils.class.php:452 and used as the memory limit for dump execution. No admin UI manages this constant.', 'Setting this raises or lowers the PHP memory ceiling during dump; leaving it unset relies on the default PHP memory_limit.', 'PHP memory limit string, e.g. ''256M'' or ''512M''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/utils.class.php:452|read|$MemoryLimit = getDolGlobalString(''MAIN_MEMORY_LIMIT_DUMP'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENUFRONT_SMARTPHONE', 'string', 'eldy_menu.php', 'admin', 'Specifies the menu handler file used for the smartphone front-office (public portal mobile) interface.', 'Written in admin/menus.php at line 82 and read at lines 206 and 209. Referenced in install/upgrade2.php at line 4524 alongside MAIN_MENUFRONT_STANDARD. Can be overridden by MAIN_MENUFRONT_SMARTPHONE_FORCED.', 'Changing this value switches the mobile menu theme for the public portal. An upgrade script checks for the deprecated ''auguria_menu'' value.', 'String filename of a menu handler module (default: ''eldy_menu.php'')', 0, 0, 'admin/menus.php|admin/menus.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, \"MAIN_MENUFRONT_SMARTPHONE\", GETPOST(''MAIN_MENUFRONT_SMARTPHONE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "|| getDolGlobalString(''MAIN_MENUFRONT_STANDARD'') == ''auguria_menu'' || getDolGlobalString(''MAIN_MENUFRONT_SMARTPHONE'') == ''auguria_menu'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENUFRONT_SMARTPHONE_FORCED', 'string', NULL, 'admin', 'Forces a specific frontend smartphone menu module, overriding the user-selected frontend smartphone menu.', 'Read and checked in admin/menus.php at lines 206, 208, 209. When set to a value matching ''/smartphone/'', it is used as the forced frontend smartphone menu, overriding MAIN_MENUFRONT_SMARTPHONE.', 'When set, the forced frontend smartphone menu is always applied regardless of user selection. When unset, MAIN_MENUFRONT_SMARTPHONE is used.', 'A menu module identifier string containing ''smartphone''; empty or unset to use the user-selected frontend menu.', 0, 0, 'admin/menus.php|admin/menus.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/menus.php:208|check|if (getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED'') && preg_match(''/smartphone/'', getDolGlobalString(\"MAIN_MENUFRONT_SMARTPHONE_FORCED\"))", "admin/menus.php:206|read|$formadmin->select_menu(getDolGlobalString(''MAIN_MENUFRONT_SMARTPHONE_FORCED'', getDolGlobalString(''MAIN_MENUFRONT_SMARTPHONE'')), ''MAIN_MENUFRONT_SMARTPHONE'', array_merge($dirstanda", "admin/menus.php:209|read||| (!getDolGlobalString(''MAIN_MENUFRONT_SMARTPHONE_FORCED'') && getDolGlobalString(''MAIN_MENU_SMARTPHONE'') && preg_match(''/smartphone/'', getDolGlobalString(''MAIN_MENUFRONT_SMARTPHON'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENUFRONT_STANDARD', 'string', 'eldy_menu.php', 'core', 'Specifies the menu handler file used for the standard front-office (public portal) interface.', 'Written in admin/menus.php at line 81 and read in main.inc.php at line 1374 and core/get_menudiv.php at line 280. Defaults to ''eldy_menu.php'' when unset. Can be overridden by MAIN_MENUFRONT_STANDARD_FORCED.', 'Changing this value switches the menu theme for the public-facing portal. An upgrade script checks for the deprecated ''auguria_menu'' value.', 'String filename of a menu handler module (default: ''eldy_menu.php'')', 0, 0, 'admin/menus.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, \"MAIN_MENUFRONT_STANDARD\", GETPOST(''MAIN_MENUFRONT_STANDARD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$conf->standard_menu = getDolGlobalString(''MAIN_MENUFRONT_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENUFRONT_STANDARD'', ''eldy_menu.php''));", "|| getDolGlobalString(''MAIN_MENUFRONT_STANDARD'') == ''auguria_menu'' || getDolGlobalString(''MAIN_MENUFRONT_SMARTPHONE'') == ''auguria_menu'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENUFRONT_STANDARD_FORCED', 'string', NULL, 'core', 'Forces a specific front-office standard menu handler, overriding the user-configured front menu.', 'Read in main.inc.php:1374 and core/get_menudiv.php:280 as the authoritative front-office menu file, falling back to MAIN_MENUFRONT_STANDARD or ''eldy_menu.php''. Also presented in admin/menus.php:190.', 'When set, this overrides the admin-configured front-office menu; removing it restores the MAIN_MENUFRONT_STANDARD selection.', 'Any valid menu handler filename (e.g. ''eldy_menu.php''); empty/unset = MAIN_MENUFRONT_STANDARD or ''eldy_menu.php'' is used', 0, 0, 'admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1374|read|$conf->standard_menu = getDolGlobalString(''MAIN_MENUFRONT_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENUFRONT_STANDARD'', ''eldy_menu.php''));", "core/get_menudiv.php:280|read|$conf->standard_menu = (!getDolGlobalString(''MAIN_MENUFRONT_STANDARD_FORCED'') ? (!getDolGlobalString(''MAIN_MENUFRONT_STANDARD'') ? ''eldy_menu.php'' : $conf->global->MAIN_MENUFRONT_ST", "admin/menus.php:190|read|$formadmin->select_menu(getDolGlobalString(''MAIN_MENUFRONT_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENUFRONT_STANDARD'')), ''MAIN_MENUFRONT_STANDARD'', $dirstandard, !getDolGlobalS"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_CHEQUE_DEPOSIT_ON', 'string', NULL, 'core', 'Forces the cheque deposit menu entry to appear even when the invoice module is not enabled.', 'Checked in core/menus/standard/eldy.lib.php:2168 as an OR condition alongside isModEnabled(''invoice''); when set, the cheque deposit entry is shown regardless of invoice module state.', 'Setting this constant makes the cheque deposit menu visible independently of the invoice module. Without it, the entry requires the invoice module to be active.', 'Non-empty = force cheque deposit menu; absent/empty = requires invoice module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:2168|check|if (!getDolGlobalString(''BANK_DISABLE_CHECK_DEPOSIT'') && isModEnabled(''bank'') && (isModEnabled(''invoice'') || getDolGlobalString(''MAIN_MENU_CHEQUE_DEPOSIT_ON''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_HIDE_UNAUTHORIZED', 'bool', NULL, 'core', 'Hides menu entries for which the current user has no permission, instead of showing them disabled.', 'Checked in 8 occurrences across auguria.lib.php, eldy.lib.php, auguria_menu.php, eldy_menu.php, empty.php, and functions.lib.php. The admin/ihm.php write line is commented out, indicating the setting is not actively saved via the UI form. When set, menu items the user cannot access are hidden rather than greyed out.', 'Enabling this constant removes unauthorized menu entries from view entirely; disabling it shows them in a disabled state.', 'Non-empty = unauthorized menu items hidden; empty or unset = shown disabled', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/auguria.lib.php:558|check|if (getDolGlobalString(''MAIN_MENU_HIDE_UNAUTHORIZED'') && empty($menu_array[$i][''enabled''])) {", "core/menus/standard/eldy.lib.php:981|check|if (getDolGlobalString(''MAIN_MENU_HIDE_UNAUTHORIZED'') && empty($menu_array[$i][''enabled''])) {", "core/menus/standard/auguria.lib.php:747|check|if (!$menuentry[''perms''] && getDolGlobalString(''MAIN_MENU_HIDE_UNAUTHORIZED'')) {", "admin/ihm.php:281|write|//dolibarr_set_const($db, \"MAIN_MENU_HIDE_UNAUTHORIZED\", GETPOST(\"MAIN_MENU_HIDE_UNAUTHORIZED\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_INVERT', 'string', NULL, 'core', 'When enabled, inverts the top menu layout by swapping the logo and menu positions.', 'Checked in core/menus/standard/auguria.lib.php:162, core/menus/standard/eldy.lib.php:579, main.inc.php:2193, theme/eldy/global.inc.php:3295, theme/md/style.css.php:3360, and others. Read in auguria.lib.php:550 and eldy.lib.php:973 to append ''invert'' CSS class. Ten occurrences across multiple files. No admin UI write is present.', 'Enabling this constant applies an ''invert'' CSS class to the top menu container and suppresses logo display in the standard menu position.', 'Boolean flag; unset or 0 = standard menu layout; any truthy value = inverted menu layout.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2193|read|print ''<div id=\"tmenu_tooltip''.(!getDolGlobalString(''MAIN_MENU_INVERT'') ? '''' : ''invert'').''\" class=\"tmenu\">''.\"\\n\";", "core/menus/standard/eldy.lib.php:973|read|$invert = !getDolGlobalString(''MAIN_MENU_INVERT'') ? \"\" : \"invert\";", "core/menus/standard/auguria.lib.php:162|check|if (!getDolGlobalString(''MAIN_MENU_INVERT'') && getDolGlobalString(''MAIN_SHOW_LOGO'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {", "theme/eldy/global.inc.php:3295|check|<?php if (!getDolGlobalString(''MAIN_MENU_INVERT'')) { ?>"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_LEFT_DROPDOWN', 'string', NULL, 'core', 'Enables a dropdown style for the left-side menu.', 'Checked at main.inc.php:3326 as an integer to conditionally render the left menu as a dropdown.', 'Enabling this changes the left navigation menu to a dropdown presentation.', '0 or unset = standard left menu; non-zero = left menu rendered as dropdown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3326|check|if (getDolGlobalInt(''MAIN_MENU_LEFT_DROPDOWN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_SMARTPHONE', 'string', 'eldy_menu.php', 'admin', 'Specifies the menu handler file used for the smartphone (mobile back-office) interface.', 'Written in admin/menus.php at line 79 and read in admin/menus/edit.php at line 65. Can be overridden by MAIN_MENU_SMARTPHONE_FORCED. The admin page checks whether the selected value matches a smartphone-type menu.', 'Changing this value switches the mobile menu theme. An upgrade script checks for the deprecated ''auguria_menu'' value.', 'String filename of a menu handler module (default: ''eldy_menu.php'')', 0, 0, 'admin/menus.php|admin/menus.php|admin/menus.php|admin/menus/edit.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, \"MAIN_MENU_SMARTPHONE\", GETPOST(''MAIN_MENU_SMARTPHONE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "|| (!getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED'') && getDolGlobalString(''MAIN_MENU_SMARTPHONE'') && preg_match(''/smartphone/'', getDolGlobalString(''MAIN_MENU_SMARTPHONE'')))) {", "if (getDolGlobalString(''MAIN_MENU_STANDARD'') == ''auguria_menu'' || getDolGlobalString(''MAIN_MENU_SMARTPHONE'') == ''auguria_menu''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_SMARTPHONE_FORCED', 'string', NULL, 'admin', 'Forces a specific backend smartphone menu module, overriding the user-selected smartphone menu.', 'Read and checked in admin/menus.php at lines 197, 199, 200. When set to a value matching ''/smartphone/'', it is used as the forced menu for the smartphone backend layout; it overrides MAIN_MENU_SMARTPHONE.', 'When set, administrators cannot override the smartphone menu through normal selection; the forced menu is always applied. When unset, the user-selected MAIN_MENU_SMARTPHONE value is used.', 'A menu module identifier string containing ''smartphone''; empty or unset to use the user-selected menu.', 0, 0, 'admin/menus.php|admin/menus.php|admin/menus.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/menus.php:199|check|if (getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED'') && preg_match(''/smartphone/'', getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED''))", "admin/menus.php:197|read|$formadmin->select_menu(getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED'', getDolGlobalString(''MAIN_MENU_SMARTPHONE'')), ''MAIN_MENU_SMARTPHONE'', array_merge($dirstandard, $dirsmartph", "admin/menus.php:200|read||| (!getDolGlobalString(''MAIN_MENU_SMARTPHONE_FORCED'') && getDolGlobalString(''MAIN_MENU_SMARTPHONE'') && preg_match(''/smartphone/'', getDolGlobalString(''MAIN_MENU_SMARTPHONE'')))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_STANDARD', 'string', 'eldy_menu.php', 'core', 'Specifies the menu handler file used for the standard (back-office) interface.', 'Written in admin/menus.php at line 78 and read in main.inc.php at line 1371 and core/get_menudiv.php at line 278. Defaults to ''eldy_menu.php'' when unset. Can be overridden by MAIN_MENU_STANDARD_FORCED.', 'Changing this value switches the menu theme for all back-office users. An upgrade script at install/upgrade2.php checks for the deprecated ''auguria_menu'' value.', 'String filename of a menu handler module (default: ''eldy_menu.php'')', 0, 0, 'admin/menus.php|admin/menus/index.php|admin/menus/edit.php|admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, \"MAIN_MENU_STANDARD\", GETPOST(''MAIN_MENU_STANDARD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$conf->standard_menu = getDolGlobalString(''MAIN_MENU_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENU_STANDARD'', ''eldy_menu.php''));", "if (getDolGlobalString(''MAIN_MENU_STANDARD'') == ''auguria_menu'' || getDolGlobalString(''MAIN_MENU_SMARTPHONE'') == ''auguria_menu''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MENU_STANDARD_FORCED', 'string', NULL, 'core', 'Forces a specific standard (back-office) menu handler, overriding the user-configured menu.', 'Read in main.inc.php:1371 and core/get_menudiv.php:278 as the authoritative menu file, falling back to MAIN_MENU_STANDARD or ''eldy_menu.php''. Also displayed in admin/menus.php:187.', 'When set, this overrides the admin-configured standard menu; removing it restores the MAIN_MENU_STANDARD selection.', 'Any valid menu handler filename (e.g. ''eldy_menu.php''); empty/unset = MAIN_MENU_STANDARD or ''eldy_menu.php'' is used', 0, 0, 'admin/menus.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1371|read|$conf->standard_menu = getDolGlobalString(''MAIN_MENU_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENU_STANDARD'', ''eldy_menu.php''));", "core/get_menudiv.php:278|read|$conf->standard_menu = (!getDolGlobalString(''MAIN_MENU_STANDARD_FORCED'') ? (!getDolGlobalString(''MAIN_MENU_STANDARD'') ? ''eldy_menu.php'' : $conf->global->MAIN_MENU_STANDARD) : $conf", "admin/menus.php:187|read|$formadmin->select_menu(getDolGlobalString(''MAIN_MENU_STANDARD_FORCED'', getDolGlobalString(''MAIN_MENU_STANDARD'')), ''MAIN_MENU_STANDARD'', $dirstandard, !getDolGlobalString(''MAIN_MEN"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MESSAGE_INSTALL_MODULES_DISABLED_CONTACT_US', 'bool', NULL, 'website', 'Stores a language key displayed as a warning message when module installation or certain website/modulebuilder actions are disabled.', 'Checked in admin/modules.php:1510–1513 where its value is used as a translation key for an info_admin warning; also checked in website/index.php:616, 2756, 4671, modulebuilder/index.php:3259, and core/lib/website2.lib.php:1097 to gate restricted actions.', 'When set with a non-numeric translation key, a warning message is shown to administrators and certain module/website install actions are blocked.', 'Empty/unset = no restriction; a translation key string = warning displayed and actions disabled; a numeric value = numeric check applies.', 0, 0, 'admin/modules.php|admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/modules.php:1510|check|if (getDolGlobalString(''MAIN_MESSAGE_INSTALL_MODULES_DISABLED_CONTACT_US'')) {", "admin/modules.php:1512|check|if (!is_numeric(getDolGlobalString(''MAIN_MESSAGE_INSTALL_MODULES_DISABLED_CONTACT_US''))) {", "admin/modules.php:1513|read|$message = info_admin($langs->trans(getDolGlobalString(''MAIN_MESSAGE_INSTALL_MODULES_DISABLED_CONTACT_US'')), 0, 0, ''warning'');", "website/index.php:616|check|if (getDolGlobalString(''MAIN_MESSAGE_INSTALL_MODULES_DISABLED_CONTACT_US'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO', 'string', NULL, 'admin', 'Prefix for a family of constants defining level thresholds for the meteo (weather/mood indicator) feature in the admin delays dashboard.', 'Written in admin/delais.php:213. The full constant name is built dynamically as MAIN_METEO + plus + _LEVEL + i, where plus and i are loop variables.', 'Changing these level constants adjusts the thresholds that determine the meteo indicator color/state in the dashboard.', 'Integer level value; exact semantics depend on the specific MAIN_METEO*_LEVEL* constant suffix.', 0, 0, 'admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["dolibarr_set_const($db, ''MAIN_METEO''.$plus.''_LEVEL''.$i, GETPOSTINT(''MAIN_METEO''.$plus.''_LEVEL''.$i), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_LEVEL0', 'string', NULL, 'admin', 'Specifies a custom label or value for the level-0 (lowest) threshold in the dashboard weather/meteo indicator.', 'Read in admin/delais.php lines 343-344: when non-empty the value overrides the default level-0 label ($level0) used in the meteo delay indicator display.', 'Changing this value alters the label shown for the best-performance band in the meteo dashboard widget.', 'Any non-empty string label for the level-0 threshold.', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:343|check|if (getDolGlobalString(''MAIN_METEO_LEVEL0'')) {", "admin/delais.php:344|read|$level0 = getDolGlobalString(''MAIN_METEO_LEVEL0'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_LEVEL1', 'string', NULL, 'admin', 'Specifies a custom label or value for the level-1 threshold in the dashboard weather/meteo indicator.', 'Read in admin/delais.php lines 347-348: when non-empty the value overrides the default level-1 label ($level1).', 'Changing this value alters the label shown for the level-1 performance band in the meteo dashboard widget.', 'Any non-empty string label for the level-1 threshold.', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:347|check|if (getDolGlobalString(''MAIN_METEO_LEVEL1'')) {", "admin/delais.php:348|read|$level1 = getDolGlobalString(''MAIN_METEO_LEVEL1'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_LEVEL2', 'string', NULL, 'admin', 'Specifies a custom label or value for the level-2 threshold in the dashboard weather/meteo indicator.', 'Read in admin/delais.php lines 351-352: when non-empty the value overrides the default level-2 label ($level2).', 'Changing this value alters the label shown for the level-2 performance band in the meteo dashboard widget.', 'Any non-empty string label for the level-2 threshold.', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:351|check|if (getDolGlobalString(''MAIN_METEO_LEVEL2'')) {", "admin/delais.php:352|read|$level2 = getDolGlobalString(''MAIN_METEO_LEVEL2'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_LEVEL3', 'string', NULL, 'admin', 'Specifies a custom label or value for the level-3 (highest) threshold in the dashboard weather/meteo indicator.', 'Read in admin/delais.php lines 355-356: when non-empty the value overrides the default level-3 label ($level3).', 'Changing this value alters the label shown for the worst-performance band in the meteo dashboard widget.', 'Any non-empty string label for the level-3 threshold.', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:355|check|if (getDolGlobalString(''MAIN_METEO_LEVEL3'')) {", "admin/delais.php:356|read|$level3 = getDolGlobalString(''MAIN_METEO_LEVEL3'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_PERCENTAGE_LEVEL0', 'string', NULL, 'admin', 'Defines the upper percentage boundary for the level-0 band in the dashboard meteo delay indicator.', 'Displayed as an editable field in admin/delais.php:388 and shown read-only at line 435. The percentage value determines the upper limit of the best-performance band.', 'Changing this value shifts the boundary of the level-0 performance band in the meteo widget.', 'Integer percentage value (e.g. ''20'' means <= 20%).', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:388|read|<input ... name=\"MAIN_METEO_PERCENTAGE_LEVEL0\" value=\"''.getDolGlobalString(...).''\"", "admin/delais.php:435|read|print '' &lt;= '' . getDolGlobalString(''MAIN_METEO_PERCENTAGE_LEVEL0'').''&nbsp;%</td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_PERCENTAGE_LEVEL1', 'string', NULL, 'admin', 'Defines the upper percentage boundary for the level-1 band in the dashboard meteo delay indicator.', 'Displayed as an editable field in admin/delais.php:391 and shown read-only at line 438.', 'Changing this value shifts the boundary of the level-1 performance band in the meteo widget.', 'Integer percentage value (e.g. ''40'' means <= 40%).', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:391|read|<input ... name=\"MAIN_METEO_PERCENTAGE_LEVEL1\" value=\"''.getDolGlobalString(...).''\"", "admin/delais.php:438|read|print '' &lt;= '' . getDolGlobalString(''MAIN_METEO_PERCENTAGE_LEVEL1'').''&nbsp;%</td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_PERCENTAGE_LEVEL2', 'string', NULL, 'admin', 'Defines the upper percentage boundary for the level-2 band in the dashboard meteo delay indicator.', 'Displayed as an editable field in admin/delais.php:394 and shown read-only at line 441.', 'Changing this value shifts the boundary of the level-2 performance band in the meteo widget.', 'Integer percentage value (e.g. ''60'' means <= 60%).', 0, 0, 'admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:394|read|<input ... name=\"MAIN_METEO_PERCENTAGE_LEVEL2\" value=\"''.getDolGlobalString(...).''\"", "admin/delais.php:441|read|print '' &lt;= '' . getDolGlobalString(''MAIN_METEO_PERCENTAGE_LEVEL2'').''&nbsp;%</td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_METEO_PERCENTAGE_LEVEL3', 'string', NULL, 'admin', 'Defines the upper percentage boundary for the level-3 band in the dashboard meteo delay indicator; values above this fall into the worst band.', 'Displayed as an editable field in admin/delais.php:397, shown read-only at line 444, and used as the lower bound of the worst band at line 447.', 'Changing this value shifts the boundaries of both the level-3 and the worst-performance band in the meteo widget.', 'Integer percentage value (e.g. ''80'' means <= 80% for level-3; > 80% is the worst band).', 0, 0, 'admin/delais.php|admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/delais.php:397|read|<input ... name=\"MAIN_METEO_PERCENTAGE_LEVEL3\" value=\"''.getDolGlobalString(...).''\"", "admin/delais.php:444|read|print '' &lt;= '' . getDolGlobalString(''MAIN_METEO_PERCENTAGE_LEVEL3'').''&nbsp;%</td>'';", "admin/delais.php:447|read|print '' &gt; '' . getDolGlobalString(''MAIN_METEO_PERCENTAGE_LEVEL3'').''&nbsp;%</td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING', 'bool', NULL, 'core', 'Sets the minimum number of non-auto-enabled modules that must be active before setup-warning messages are suppressed.', 'Read via getDolGlobalInt with a default of 1 across admin/modules.php:727, admin/index.php:153, core/lib/admin.lib.php:780, imports/import.php:370, exports/export.php:488, categories/index.php:121, core/redirect_if_setup_not_complete.inc.php:45, and core/menus/standard/eldy.lib.php:1185. The inline comment on each occurrence reads ''If only minimal initial modules enabled''.', 'If the count of non-auto-enabled active modules falls below this threshold, setup-incomplete warnings are shown to admin users. Increasing the value raises the threshold, causing warnings to appear more often.', 'Integer; default is 1. Setting to 0 suppresses all such warnings regardless of active modules.', 0, 0, 'admin/modules.php|admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/modules.php:727|check|if (getDolGlobalInt(''MAIN_SETUP_MODULES_DESC'') || $nbmodulesnotautoenabled < getDolGlobalInt(''MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING'', 1)) {\t// If only minimal initial modules enab", "admin/index.php:153|check|if ($nbmodulesnotautoenabled < getDolGlobalInt(''MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING'', 1)) {\t// If only minimal initial modules enabled", "core/redirect_if_setup_not_complete.inc.php:45|check|if ($nbmodulesnotautoenabled < getDolGlobalInt(''MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING'', 1)) {", "core/menus/standard/eldy.lib.php:1185|check|if ($nbmodulesnotautoenabled < getDolGlobalInt(''MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING'', 1)) {\t// If only minimal initial modules enabled)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULES_FOR_EXTERNAL', 'string', NULL, 'product', 'Comma-separated list of module names enabled for external (portal) users.', 'The value is split by comma and used throughout the codebase to filter which modules are accessible to external users, appearing in security checks (core/lib/security.lib.php:603), menu generation (core/menus/standard/auguria.lib.php:52), and numerous dashboard boxes. Over 53 occurrences across multiple files.', 'Modules not listed here are hidden or restricted for external users. Adding or removing a module name from this list grants or revokes external user access to that module''s features.', 'Comma-separated module names (e.g. ''invoice,order,product''); empty = no modules enabled for external users', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/security.lib.php:603|read|$listofmodules = explode('','', getDolGlobalString(''MAIN_MODULES_FOR_EXTERNAL''));", "core/boxes/box_comptes.php:57|read|$listofmodulesforexternal = explode('','', getDolGlobalString(''MAIN_MODULES_FOR_EXTERNAL''));", "core/menus/standard/auguria.lib.php:52|read|$listofmodulesforexternal = explode('','', getDolGlobalString(''MAIN_MODULES_FOR_EXTERNAL''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULES_SHOW_LINENUMBERS', 'bool', NULL, 'admin', 'Shows line numbers alongside module entries in the modules administration list.', 'Checked at admin/modules.php:1237. When set, line numbers are rendered next to module items in the list view.', 'Enabling this constant adds line number indicators to the modules list, which is useful for debugging or navigation. Disabling removes them.', 'Empty/unset = line numbers hidden; non-empty = line numbers shown', 0, 0, 'admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1237|check|if (getDolGlobalString(''MAIN_MODULES_SHOW_LINENUMBERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_', 'string', NULL, 'core', 'A prefix pattern used to check whether a named Dolibarr module is active or to retrieve its associated handler class.', 'Read at api/class/api_setup.class.php:3227 as ''$active = getDolGlobalString(''MAIN_MODULE_''.$moduleName)'' to check module activation status. Also used in core/class/CSMSFile.class.php:183 and core/class/html.formsms.class.php:261 with the pattern ''MAIN_MODULE_''.strtoupper($sendmode).''_SMS'', where the comment states: ''$conf->global->MAIN_MODULE_XXX_SMS looks like a value ''class@module''''.', 'The value for a specific MAIN_MODULE_X constant indicates whether module X is active and/or provides the handler class reference for that module''s functionality.', 'Not set = module not active; non-empty string = module active (for base module flags) or ''class@module'' string (for SMS/handler variants like MAIN_MODULE_XXX_SMS).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_setup.class.php:3227|read|$active = getDolGlobalString(''MAIN_MODULE_''.$moduleName);", "core/class/CSMSFile.class.php:183|read|$classmoduleofsender = getDolGlobalString(''MAIN_MODULE_''.strtoupper($sendmode).''_SMS'', $sendmode);\t// $conf->global->MAIN_MODULE_XXX_SMS looks like a value ''class@module''", "core/class/html.formsms.class.php:261|read|$classmoduleofsender = getDolGlobalString(''MAIN_MODULE_''.strtoupper($sendmode).''_SMS'', $sendmode);\t// $conf->global->MAIN_MODULE_XXX_SMS looks like a value ''class@module''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_CAN_OVERWRITE_COMMONICONS', 'string', NULL, 'core', 'Allows an external module to override the common Dolibarr icon set when set to a truthy integer.', 'Checked via getDolGlobalInt at core/lib/functions.lib.php:6397. When truthy, the icon resolution logic permits module-supplied icons to replace built-in common icons.', 'Enabling this constant lets a module replace standard icons globally; disabling it enforces the default icon set regardless of any module overrides.', '0 or empty = common icons cannot be overridden by modules; any non-zero integer = module override permitted', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:6397|check|if (getDolGlobalInt(''MAIN_MODULE_CAN_OVERWRITE_COMMONICONS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_DOLISTORE_API_KEY', 'string', NULL, 'admin', 'Sets the API key used to authenticate requests to the Dolistore API.', 'Read in admin/remotestore/class/externalModules.class.php:153 with a default of ''dolistorepublicapi''.', 'Changing this key authenticates Dolistore API requests under a different account or access level.', 'String, default ''dolistorepublicapi''.', 0, 0, 'admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/remotestore/class/externalModules.class.php:153|read|$this->dolistore_api_key = getDolGlobalString(''MAIN_MODULE_DOLISTORE_API_KEY'', ''dolistorepublicapi'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_DOLISTORE_API_SRV', 'string', NULL, 'admin', 'Sets the base URL of the Dolistore API server used to fetch available external modules.', 'Read in admin/remotestore/class/externalModules.class.php:152 with a default of ''https://www.dolistore.com/api/''; an inline comment lists alternative values including ''https://admin2.dolibarr.org/''.', 'Changing this URL redirects all Dolistore API requests to a different server, such as a staging or alternative store endpoint.', 'String URL, default ''https://www.dolistore.com/api/''.', 0, 0, 'admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/remotestore/class/externalModules.class.php:152|read|$this->dolistore_api_url = getDolGlobalString(''MAIN_MODULE_DOLISTORE_API_SRV'', ''https://www.dolistore.com/api/'');\t// ''https://www.dolistore.com/api/'', ''https://admin2.dolibarr.org/"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_DOLISTORE_BASIC_LOGIN', 'string', NULL, 'admin', 'Stores the HTTP Basic Authentication login used to access the Dolistore API.', 'Read in both admin/modules.php:1369 and admin/remotestore/class/externalModules.class.php:210 to build authenticated requests to the Dolistore remote store.', 'Setting this value enables authenticated access to Dolistore, which is required when the store enforces HTTP Basic Auth. Leaving it empty results in unauthenticated requests.', 'A username string for HTTP Basic Auth against the Dolistore API; empty = no Basic Auth login sent', 0, 0, 'admin/modules.php|admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1369|read|$basicAuthLogin = getDolGlobalString(''MAIN_MODULE_DOLISTORE_BASIC_LOGIN'');", "admin/remotestore/class/externalModules.class.php:210|read|$basicAuthLogin = getDolGlobalString(''MAIN_MODULE_DOLISTORE_BASIC_LOGIN'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_DOLISTORE_BASIC_PASSWORD', 'string', NULL, 'admin', 'Stores the HTTP Basic Authentication password used to access the Dolistore API.', 'Read in both admin/modules.php:1370 and admin/remotestore/class/externalModules.class.php:211 alongside MAIN_MODULE_DOLISTORE_BASIC_LOGIN to authenticate requests to the Dolistore remote store.', 'Setting this value provides the password for authenticated Dolistore API access. It should be treated as a sensitive credential.', 'A password string for HTTP Basic Auth against the Dolistore API; empty = no Basic Auth password sent', 0, 0, 'admin/modules.php|admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:1370|read|$basicAuthPassword = getDolGlobalString(''MAIN_MODULE_DOLISTORE_BASIC_PASSWORD'');", "admin/remotestore/class/externalModules.class.php:211|read|$basicAuthPassword = getDolGlobalString(''MAIN_MODULE_DOLISTORE_BASIC_PASSWORD'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_DOLISTORE_SHOP_URL', 'string', NULL, 'admin', 'Sets the base URL of the Dolistore shop used for module browsing links.', 'Read in admin/remotestore/class/externalModules.class.php:154 with a default of ''https://www.dolistore.com''.', 'Changing this URL redirects shop-browsing links to a different store endpoint.', 'String URL, default ''https://www.dolistore.com''.', 0, 0, 'admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/remotestore/class/externalModules.class.php:154|read|$this->shop_url  = getDolGlobalString(''MAIN_MODULE_DOLISTORE_SHOP_URL'', ''https://www.dolistore.com'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_MULTICOMPANY', 'string', NULL, 'core', 'Indicates whether the MultiCompany module is enabled.', 'Checked in core/modules/DolibarrModules.class.php:2346, main.inc.php:2517, and user/class/user.class.php:3167 to gate multi-entity logic.', 'When set, multi-company/entity features are activated across the application; unsetting it disables those code paths.', ''''' or unset = MultiCompany module disabled; any truthy value = MultiCompany module enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/DolibarrModules.class.php:2346|check|if (!getDolGlobalString(''MAIN_MODULE_MULTICOMPANY'') || $conf->entity == 1) {", "main.inc.php:2517|check|if (getDolGlobalString(''MAIN_MODULE_MULTICOMPANY'')) {", "user/class/user.class.php:3167|check|if (getDolGlobalString(''MAIN_MODULE_MULTICOMPANY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_PRELEVEMENT_CONCAT', 'string', NULL, 'compta', 'Unknown concatenation flag referenced in the direct debit class; its exact behaviour is unclear from code alone.', 'Read once in compta/prelevement/class/bonprelevement.class.php:423 with an inline comment stating it is unused. No admin UI write path exists.', 'Exact behavior unclear from code alone.', 'Integer (purpose undocumented per inline comment)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:423|read|$concat = getDolGlobalInt(''MAIN_MODULE_PRELEVEMENT_CONCAT'');\t// ??? what is this for. Seems not used."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_SETUP_ON_LIST_BY_DEFAULT', 'string', NULL, 'admin', 'Sets the default display mode of the modules list page (e.g. kanban or list view).', 'Written by admin/modules.php:194 when switching views. Read in both admin/modules.php:197 and core/lib/admin.lib.php:778 with a fallback of ''commonkanban''. The value drives the initial rendering mode of the module management UI.', 'Changing this value alters which view mode is shown by default when opening the modules list. The effect is immediate on the next page load.', 'String view mode identifier; ''commonkanban'' = kanban view (default); ''common'' = list view', 0, 0, 'admin/modules.php|admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:197|read|$mode = getDolGlobalString(''MAIN_MODULE_SETUP_ON_LIST_BY_DEFAULT'', ''commonkanban'');", "core/lib/admin.lib.php:778|read|$mode = getDolGlobalString(''MAIN_MODULE_SETUP_ON_LIST_BY_DEFAULT'', ''commonkanban'');", "admin/modules.php:193|check|if ($mode == ''common'' && !getDolGlobalString(''MAIN_MODULE_SETUP_ON_LIST_BY_DEFAULT'')) {", "admin/modules.php:194|write|dolibarr_set_const($db, \"MAIN_MODULE_SETUP_ON_LIST_BY_DEFAULT\", $mode, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_WEBSERVICES', 'string', NULL, 'webservices', 'Guards access to all legacy SOAP webservice endpoints; each server script rejects requests when this constant is not set.', 'Checked at entry of every webservice script including webservices/server_other.php:64, server_invoice.php:67, server_contact.php:62, server_supplier_invoice.php:63, server_project.php:66, server_order.php:65, server_user.php:65, and webservices/index.php:49.', 'Without this constant set, all SOAP webservice endpoints return an error and deny access; setting it enables the webservices module.', 'Non-empty = webservices enabled; empty/absent = webservices blocked', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webservices/server_other.php:64|check|if (!getDolGlobalString(''MAIN_MODULE_WEBSERVICES'')) {", "webservices/server_invoice.php:67|check|if (!getDolGlobalString(''MAIN_MODULE_WEBSERVICES'')) {", "webservices/server_contact.php:62|check|if (!getDolGlobalString(''MAIN_MODULE_WEBSERVICES'')) {", "webservices/index.php:49|check|if (!getDolGlobalString(''MAIN_MODULE_WEBSERVICES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MODULE_XXX_SMS', 'string', NULL, 'core', 'Stores the class@module identifier for the SMS sending provider module, where XXX is the uppercased send mode name.', 'Read in core/class/CSMSFile.class.php:183 and core/class/html.formsms.class.php:261 via getDolGlobalString. The constant name is built dynamically from the send mode. A code comment explains the expected value format.', 'Changing this constant redirects SMS sending to a different provider class and module.', 'A string in the format ''class@module'', e.g. ''MySmsSender@mymodule''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$classmoduleofsender = getDolGlobalString(''MAIN_MODULE_''.strtoupper($sendmode).''_SMS'', $sendmode);\t// $conf->global->MAIN_MODULE_XXX_SMS looks like a value ''class@module''", "$classmoduleofsender = getDolGlobalString(''MAIN_MODULE_''.strtoupper($sendmode).''_SMS'', $sendmode);\t// $conf->global->MAIN_MODULE_XXX_SMS looks like a value ''class@module''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MONNAIE', 'string', 'EUR', 'societe', 'Stores the default currency code used by the company.', 'Written in admin/company.php at line 127 via the company admin UI. Read in societe/class/societe.class.php at line 4797 and in intracommreport/class/intracommreport.class.php at line 333 for intracomm declarations.', 'Changing this constant updates the currency code applied to the company''s financial documents and intracomm reports.', 'ISO 4217 currency code string (default: ''EUR'')', 0, 0, 'admin/company.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/company.php:127|write|dolibarr_set_const($db, \"MAIN_MONNAIE\", GETPOST(\"currency\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "intracommreport/class/intracommreport.class.php:333|read|$declaration->addChild(''currencyCode'', $conf->global->MAIN_MONNAIE);", "societe/class/societe.class.php:4797|read|$this->currency_code = getDolGlobalString(''MAIN_MONNAIE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MOTD', 'string', NULL, 'index.php', 'Stores the Message of the Day HTML content displayed on the Dolibarr home dashboard.', 'Set via admin/ihm.php using a rich-text editor (dolibarr_notes style). On index.php:99 the value is sanitised (br tags normalised) and on index.php:103 variable substitutions are applied before display. Shown only when the constant is non-empty.', 'Setting this value causes a formatted message to appear on the dashboard for all users; clearing it removes the message.', 'HTML string (rich text). Empty or unset means no message is shown.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:98|check|if (getDolGlobalString(''MAIN_MOTD'')) {", "index.php:99|read|$conf->global->MAIN_MOTD = preg_replace(''/<br(\\s[\\sa-zA-Z_=\"]*)?\\/?>/'', ''<br>'', getDolGlobalString(''MAIN_MOTD''));", "index.php:103|read|$texttoshow = make_substitutions(getDolGlobalString(''MAIN_MOTD''), $substitutionarray, $langs);", "admin/ihm.php:263|write|dolibarr_set_const($db, \"MAIN_MOTD\", dol_htmlcleanlastbr(GETPOST(\"main_motd\", ''restricthtml'')), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MOTD_SETUPPAGE', 'string', NULL, 'admin', 'Defines a message-of-the-day (MOTD) text displayed on the Dolibarr admin setup/home page.', 'Read and processed in admin/index.php:61-77; HTML br tags are normalized and translation placeholders of the form __(...) __ are replaced with translated strings before display. Configurable via admin/index.php.', 'Setting this string displays a custom message on the admin home page. The message supports HTML br tags and Dolibarr translation key placeholders.', 'Empty = no MOTD displayed; any string = HTML content shown on the admin setup page (supports __( translationkey )__ placeholders)', 0, 0, 'admin/index.php|admin/index.php|admin/index.php|admin/index.php|admin/index.php|admin/index.php|admin/index.php|admin/index.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/index.php:62|write|$conf->global->MAIN_MOTD_SETUPPAGE = preg_replace(''/<br(\\s[\\sa-zA-Z_=\"]*)?\\/?>/i'', ''<br>'', getDolGlobalString(''MAIN_MOTD_SETUPPAGE''));", "admin/index.php:66|read|while (preg_match(''/__\\(([a-zA-Z|@]+)\\)__/i'', getDolGlobalString(''MAIN_MOTD_SETUPPAGE''), $reg) && $i < 100) {", "admin/index.php:77|read|print dol_htmlentitiesbr(getDolGlobalString(''MAIN_MOTD_SETUPPAGE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MULTILANGS', 'string', NULL, 'core', 'Enables multi-language support across Dolibarr, activating language selectors and per-language content fields.', 'Checked via getDolGlobalInt in 390 occurrences across nearly all modules. When enabled, language columns appear in email template lists (admin/mails_templates.php:814), per-language product texts are activated (supplier_proposal/card.php:864), and language selection widgets are shown. A docblock in core/class/html.formfile.class.php references the constant by name as the condition for showing language options.', 'When disabled, all multi-language UI elements are hidden and language-specific content paths are bypassed. Enabling it activates language selectors and multi-language document generation throughout the application.', 'Integer: non-zero = multi-language mode enabled; 0 or unset = single language mode.', 0, 0, 'product/admin/product.php|admin/mails_templates.php|admin/mails_templates.php|admin/mails_templates.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/mails_templates.php:672|check|if (!getDolGlobalInt(''MAIN_MULTILANGS'')) {", "admin/mails_templates.php:814|read|$valuetoshow = (!getDolGlobalInt(''MAIN_MULTILANGS'') ? ''&nbsp;'' : $langs->trans(\"Language\"));", "supplier_proposal/card.php:864|check|if (getDolGlobalInt(''MAIN_MULTILANGS'') && getDolGlobalString(''PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE'')) {", "*      @param      integer\t\t\t\t$forcenomultilang\tDo not show language option (even if MAIN_MULTILANGS defined)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MULTILANG_TRANSLATE_EVEN_IF_MODIFIED', 'string', NULL, 'core', 'Controls whether multilingual translation is applied to field values even if they have been manually modified.', 'Read at core/lib/pdf.lib.php:1966 with inline comment: ''By default if value was modified manually, we keep it (no translation because we don''t know if translation is still accurate)''. No admin UI write is present.', 'Enabling this forces translation of manually-modified values in multilingual PDF generation, overriding the default behavior of preserving manual edits.', 'Truthy string (non-empty) = translate even if manually modified; absent/empty = skip translation for modified values.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1966|read|$translatealsoifmodified = getDolGlobalString(''MAIN_MULTILANG_TRANSLATE_EVEN_IF_MODIFIED''); // By default if value was modified manually, we keep it (no translation because we don''t"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MYMODULE_SHOW_PAGE_OF_AGENDA', 'bool', NULL, 'modulebuilder', 'Template constant controlling whether the agenda/events tab is shown for a custom module object.', 'Read in modulebuilder/template/lib/mymodule_myobject.lib.php:40 to set the showtabofpageagenda variable used in tab rendering. This is a modulebuilder template placeholder.', 'Setting this to a non-zero value enables the agenda tab on the custom module object page; leaving it unset hides the tab.', '0 or not set = agenda tab hidden; non-zero integer = agenda tab shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/lib/mymodule_myobject.lib.php:40|read|$showtabofpageagenda = getDolGlobalInt(''MAIN_MYMODULE_SHOW_PAGE_OF_AGENDA'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MYMODULE_SHOW_PAGE_OF_CONTACT', 'bool', NULL, 'modulebuilder', 'Template constant controlling whether the contacts tab is shown for a custom module object.', 'Read in modulebuilder/template/lib/mymodule_myobject.lib.php:37 to set the showtabofpagecontact variable used in tab rendering. This is a modulebuilder template placeholder.', 'Setting this to a non-zero value enables the contacts tab on the custom module object page; leaving it unset hides the tab.', '0 or not set = contacts tab hidden; non-zero integer = contacts tab shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/lib/mymodule_myobject.lib.php:37|read|$showtabofpagecontact = getDolGlobalInt(''MAIN_MYMODULE_SHOW_PAGE_OF_CONTACT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MYMODULE_SHOW_PAGE_OF_DOCUMENT', 'bool', NULL, 'modulebuilder', 'Template constant controlling whether the documents tab is shown for a custom module object.', 'Read in modulebuilder/template/lib/mymodule_myobject.lib.php:39 to set the showtabofpagedocument variable used in tab rendering. This is a modulebuilder template placeholder.', 'Setting this to a non-zero value enables the documents tab on the custom module object page; leaving it unset hides the tab.', '0 or not set = documents tab hidden; non-zero integer = documents tab shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/lib/mymodule_myobject.lib.php:39|read|$showtabofpagedocument = getDolGlobalInt(''MAIN_MYMODULE_SHOW_PAGE_OF_DOCUMENT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_MYMODULE_SHOW_PAGE_OF_NOTE', 'bool', NULL, 'modulebuilder', 'Template constant controlling whether the notes tab is shown for a custom module object.', 'Read in modulebuilder/template/lib/mymodule_myobject.lib.php:38 to set the showtabofpagenote variable used in tab rendering. This is a modulebuilder template placeholder.', 'Setting this to a non-zero value enables the notes tab on the custom module object page; leaving it unset hides the tab.', '0 or not set = notes tab hidden; non-zero integer = notes tab shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/lib/mymodule_myobject.lib.php:38|read|$showtabofpagenote = getDolGlobalInt(''MAIN_MYMODULE_SHOW_PAGE_OF_NOTE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NB_OF_YEAR_IN_MEMBERSHIP_WIDGET_GRAPH', 'string', NULL, 'core', 'Sets the number of years of data displayed in membership dashboard widgets and graphs.', 'Read as an integer at adherents/index.php:105, core/boxes/box_members_by_type.php:84, and core/boxes/box_members_by_tags.php:83. The value is passed to $numberyears for limiting the year range in membership charts. No admin UI is provided.', 'Changing this value increases or decreases the number of years shown in membership statistic widgets on the dashboard.', 'A positive integer representing the number of years to display; 0 or unset = no years shown (default behavior depends on widget code).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/index.php:105|read|$numberyears = getDolGlobalInt(\"MAIN_NB_OF_YEAR_IN_MEMBERSHIP_WIDGET_GRAPH\");", "core/boxes/box_members_by_type.php:84|read|$numberyears = getDolGlobalInt(\"MAIN_NB_OF_YEAR_IN_MEMBERSHIP_WIDGET_GRAPH\");", "core/boxes/box_members_by_tags.php:83|read|$numberyears = getDolGlobalInt(\"MAIN_NB_OF_YEAR_IN_MEMBERSHIP_WIDGET_GRAPH\", 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NB_OF_YEAR_IN_WIDGET_GRAPH', 'string', NULL, 'core', 'Sets the number of years displayed in dashboard graph widgets.', 'Read as an integer with default fallbacks in six graph box files. Default is 3 years for per-month graphs (e.g. box_graph_orders_permonth.php:130, box_graph_invoices_permonth.php:128 with inline comment ''// Default is 3 years'') and 5 years for the per-year invoice graph (box_graph_invoices_peryear.php:121).', 'Increasing this value extends the historical range shown in dashboard graphs; decreasing it narrows the view to more recent years.', 'Integer; default 3 for per-month graphs, default 5 for per-year invoice graph when not set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_graph_orders_permonth.php:130|read|$startyear = $endyear - getDolGlobalInt(''MAIN_NB_OF_YEAR_IN_WIDGET_GRAPH'', 3) + 1;", "core/boxes/box_graph_invoices_peryear.php:121|read|$numberyears = getDolGlobalInt(''MAIN_NB_OF_YEAR_IN_WIDGET_GRAPH'', 5);", "core/boxes/box_graph_invoices_permonth.php:128|read|$startyear = $endyear - getDolGlobalInt(''MAIN_NB_OF_YEAR_IN_WIDGET_GRAPH'', 3) + 1;\t// Default is 3 years", "core/boxes/box_graph_invoices_supplier_permonth.php:128|read|$startyear = $endyear - getDolGlobalInt(''MAIN_NB_OF_YEAR_IN_WIDGET_GRAPH'', 3) + 1;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NEED_EXPORT_PERMISSION_TO_READ_STATISTICS', 'string', NULL, 'core', 'Restricts access to statistics pages so that users must hold the export permission in addition to normal read rights.', 'Checked as an integer in core/menus/standard/eldy.lib.php:1481, 1438 and commande/stats/index.php:58. No admin UI write detected; must be set manually.', 'Enabling this constant blocks statistics pages for users lacking the export permission. Without it, statistics are accessible to all users with standard read access.', 'Non-zero integer = export permission required; 0 or absent = no extra restriction.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:1481|check|if (getDolGlobalInt(''MAIN_NEED_EXPORT_PERMISSION_TO_READ_STATISTICS'')) {", "commande/stats/index.php:58|check|if (getDolGlobalInt(''MAIN_NEED_EXPORT_PERMISSION_TO_READ_STATISTICS'')) {", "core/menus/standard/eldy.lib.php:1438|check|if (getDolGlobalInt(''MAIN_NEED_EXPORT_PERMISSION_TO_READ_STATISTICS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NGINX_FIX', 'string', NULL, 'api', 'Applies a workaround in the API entry point for Nginx server environments that mishandle certain request headers.', 'Only one occurrence in api/index.php:131. When set, a conditional code path is taken to fix Nginx-specific request handling.', 'Enabling this activates the Nginx compatibility fix in the API; it should only be set when running behind an Nginx server that requires it.', 'Empty/0 = no Nginx fix applied; truthy = Nginx compatibility workaround activated', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/index.php:131|check|if (getDolGlobalString(''MAIN_NGINX_FIX'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NON_WORKING_DAYS_INCLUDE_FRIDAY', 'string', NULL, 'core', 'Includes Friday as a non-working day in working-day calculations.', 'Read as an integer in core/lib/date.lib.php at lines 788 and 1051 to determine whether Friday should be excluded from working-day counts. Also controls display in admin/holiday.php:516.', 'Enabling this constant causes Friday to be treated as a weekend/holiday day in all deadline and working-day calculations, which is relevant for regions with a Friday–Saturday weekend.', '0 or unset = Friday is a working day; non-zero = Friday is excluded from working days.', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/date.lib.php:788|read|$includefriday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_FRIDAY'', 0);", "core/lib/date.lib.php:1051|read|$excludefriday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_FRIDAY'', 0);", "admin/holiday.php:516|check|if (getDolGlobalString(''MAIN_NON_WORKING_DAYS_INCLUDE_FRIDAY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NON_WORKING_DAYS_INCLUDE_MONDAY', 'string', NULL, 'core', 'Marks Monday as a non-working day for holiday and working-day calculations.', 'Checked by admin/holiday.php:500 to display Monday in the non-working days UI, and by projet/class/project.class.php:2698. Read in core/lib/date.lib.php:785 and :1048 as $includemonday/$excludemonday (both default 0).', 'Enabling this constant excludes Monday from working-day counts in leave and project duration calculations.', 'Non-zero = Monday treated as non-working; 0 or unset = Monday is a working day.', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/holiday.php:500|check|if (getDolGlobalString(''MAIN_NON_WORKING_DAYS_INCLUDE_MONDAY'')) {", "core/lib/date.lib.php:785|read|$includemonday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_MONDAY'', 0);", "core/lib/date.lib.php:1048|read|$excludemonday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_MONDAY'', 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NON_WORKING_DAYS_INCLUDE_SATURDAY', 'string', NULL, 'core', 'Marks Saturday as a non-working day for holiday and working-day calculations.', 'Checked by admin/holiday.php:532 to display Saturday in the non-working days UI, and by projet/class/project.class.php:2706. Read in core/lib/date.lib.php:791 and :1054 as $includesaturday/$excludesaturday (both default 1), and in holiday/document.php:221 and holiday/card.php:1434.', 'Enabling this constant (or relying on its default of 1) excludes Saturday from working-day counts in leave and project duration calculations.', 'Non-zero = Saturday treated as non-working day (default 1); 0 = Saturday counted as working day.', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/holiday.php:532|check|if (getDolGlobalString(''MAIN_NON_WORKING_DAYS_INCLUDE_SATURDAY'')) {", "core/lib/date.lib.php:791|read|$includesaturday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SATURDAY'', 1);", "holiday/document.php:221|read|$includesaturday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SATURDAY'', 1);", "holiday/card.php:1434|read|$includesaturday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SATURDAY'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NON_WORKING_DAYS_INCLUDE_SUNDAY', 'string', NULL, 'core', 'Marks Sunday as a non-working day for holiday and working-day calculations.', 'Checked by admin/holiday.php:548 to display Sunday in the non-working days UI, and by projet/class/project.class.php:2710. Read in core/lib/date.lib.php:794 and :1057 as $includesunday/$excludesunday (both default 1), and in holiday/document.php:222 and holiday/card.php:1435.', 'Enabling this constant (or relying on its default of 1) excludes Sunday from working-day counts in leave and project duration calculations.', 'Non-zero = Sunday treated as non-working day (default 1); 0 = Sunday counted as working day.', 0, 0, 'admin/holiday.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/holiday.php:548|check|if (getDolGlobalString(''MAIN_NON_WORKING_DAYS_INCLUDE_SUNDAY'')) {", "core/lib/date.lib.php:794|read|$includesunday = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SUNDAY'', 1);", "holiday/document.php:222|read|$includesunday   = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SUNDAY'', 1);", "holiday/card.php:1435|read|$includesunday   = getDolGlobalInt(''MAIN_NON_WORKING_DAYS_INCLUDE_SUNDAY'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NON_WORKING_DAYS_INCLUDE_TUESDAY', 'string', NULL, 'projet', 'Marks Tuesday as a non-working day for project duration calculations.', 'Used in a single location: projet/class/project.class.php:2702, which checks this constant to exclude Tuesday from working-day spans.', 'Enabling this constant excludes Tuesday from working-day counts in project duration calculations.', 'Non-zero = Tuesday treated as non-working; 0 or unset = Tuesday is a working day.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/project.class.php:2702|check|if (getDolGlobalString(''MAIN_NON_WORKING_DAYS_INCLUDE_TUESDAY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NOT_INCLUDE_ZERO_VAT_IN_REPORTS', 'string', NULL, 'core', 'Excludes VAT lines with a zero rate from tax reports and summaries.', 'Checked in at least 10 places in core/lib/tax.lib.php (lines 214, 272, 408, 454, 568, 765, 807, 945, and more) to skip zero-VAT entries when building report datasets.', 'Enabling this constant cleans up tax reports by omitting zero-rate VAT lines, which is useful for businesses that apply VAT exemptions and want simplified reporting.', 'Empty/unset = zero-rate VAT included in reports; truthy value = zero-rate VAT lines are excluded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/tax.lib.php:214|check|if (getDolGlobalString(''MAIN_NOT_INCLUDE_ZERO_VAT_IN_REPORTS'')) {", "core/lib/tax.lib.php:272|check|if (getDolGlobalString(''MAIN_NOT_INCLUDE_ZERO_VAT_IN_REPORTS'')) {", "core/lib/tax.lib.php:408|check|if (getDolGlobalString(''MAIN_NOT_INCLUDE_ZERO_VAT_IN_REPORTS'')) {", "core/lib/tax.lib.php:454|check|if (getDolGlobalString(''MAIN_NOT_INCLUDE_ZERO_VAT_IN_REPORTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NOT_INSTALLED', 'string', '1', 'core', 'Flags that Dolibarr has not been fully installed, triggering a redirect to the installation wizard.', 'Checked in main.inc.php:306 alongside MAIN_NOT_UPGRADED to redirect users to the install process. Also checked in install/check.php:514. Default is ''1''. Two occurrences across two files. No admin UI write is present.', 'When this constant is set to a truthy value, all requests are redirected to the installation wizard. It is cleared upon successful installation.', 'String/integer; ''1'' or truthy = installation not complete (redirects to install); unset or ''0'' = installation complete.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:306|check|if (getDolGlobalString(''MAIN_NOT_INSTALLED'') || getDolGlobalString(''MAIN_NOT_UPGRADED'')) {", "install/check.php:514|check|if (getDolGlobalInt(\"MAIN_NOT_INSTALLED\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NOT_UPGRADED', 'string', NULL, 'core', 'Flags that Dolibarr has not been upgraded to the current version, triggering a redirect to the upgrade wizard.', 'Checked in main.inc.php:306 alongside MAIN_NOT_INSTALLED to redirect users to the upgrade process. Only one occurrence in the payload. No admin UI write is present.', 'When this constant is set, all requests are redirected to the upgrade wizard until the upgrade is completed and this flag is cleared.', 'Boolean flag; any truthy value = upgrade required (redirects to upgrade); unset or falsy = no upgrade pending.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:306|check|if (getDolGlobalString(''MAIN_NOT_INSTALLED'') || getDolGlobalString(''MAIN_NOT_UPGRADED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NO_BOOKMARKS_FOR_LANDING_PAGES', 'string', NULL, 'user', 'Suppresses the bookmarks widget on landing pages of the user interface.', 'Checked in user/param_ihm.php: the bookmarks section is rendered only when this constant is not set. No admin UI entry is present.', 'Setting this constant hides the bookmarks widget on landing pages; leaving it unset allows the widget to be displayed.', 'Any truthy value to suppress bookmarks on landing pages; empty or unset to show them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/param_ihm.php:259|check|if (!getDolGlobalString(''MAIN_NO_BOOKMARKS_FOR_LANDING_PAGES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NO_INPUT_PRICE_WITH_TAX', 'string', NULL, 'core', 'Disables the price-with-tax input column on invoice and order line entry forms.', 'When enabled, the tax-inclusive price input is hidden in line edit templates (core/tpl/subtotal_edit.tpl.php:85, objectline_title.tpl.php:127, objectline_view.tpl.php:449) and colspan handling is adjusted. Also set programmatically to 1 in master.inc.php:358 and api/class/api_access.class.php:204. No admin UI is provided.', 'Enabling this constant removes the price-with-tax input from line entry forms, forcing users to enter only pre-tax prices.', '1 = price-with-tax input hidden; 0 or unset = price-with-tax input shown when enabled by the form.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/subtotal_edit.tpl.php:84  // Handling colspan if MAIN_NO_INPUT_PRICE_WITH_TAX conf is enabled", "core/tpl/subtotal_view.tpl.php:105  // Handling colspan if MAIN_NO_INPUT_PRICE_WITH_TAX conf is enabled", "master.inc.php:358|write|$conf->global->MAIN_NO_INPUT_PRICE_WITH_TAX = 1;", "api/class/api_access.class.php:204|write|$conf->global->MAIN_NO_INPUT_PRICE_WITH_TAX = 1;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NO_MULTIDIR_FOR_ODT', 'string', NULL, 'core', 'Disables multi-directory scanning when resolving ODT template paths for document generators.', 'Checked in modulebuilder/template/core/modules/mymodule/doc/doc_generic_myobject_odt.modules.php:187, core/modules/asset/doc/doc_generic_asset_odt.modules.php:160, core/modules/societe/doc/doc_generic_odt.modules.php:141, and core/modules/bom/doc/doc_generic_bom_odt.modules.php:173. No admin UI write was found; HIDDEN_GUESS is 1.', 'When set, the ODT document generators skip scanning additional directories and use only the primary template directory.', '0 (scan multiple dirs) or 1 (single dir only)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/doc_generic_myobject_odt.modules.php:187|check|if (!getDolGlobalString(''MAIN_NO_MULTIDIR_FOR_ODT'')) {", "core/modules/asset/doc/doc_generic_asset_odt.modules.php:160|check|if (!getDolGlobalString(''MAIN_NO_MULTIDIR_FOR_ODT'')) {", "core/modules/societe/doc/doc_generic_odt.modules.php:141|check|if (!getDolGlobalString(''MAIN_NO_MULTIDIR_FOR_ODT'')) {", "core/modules/bom/doc/doc_generic_bom_odt.modules.php:173|check|if (!getDolGlobalString(''MAIN_NO_MULTIDIR_FOR_ODT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NO_UPGRADE_REDIRECT_ON_LEVEL_3_CHANGE', 'string', NULL, 'core', 'When enabled, suppresses the automatic redirect to the upgrade wizard for minor (level 3) version changes.', 'Checked in main.inc.php:326 combined with a comparison of the version component ($rescomp < 3) to decide whether to redirect. Only one occurrence in the payload. No admin UI write is present.', 'Enabling this constant prevents forced redirects to the upgrade wizard when only a patch-level version change is detected.', 'Boolean flag; unset or 0 = redirect enforced for all version changes; any truthy value = redirect suppressed for level 3 changes.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:326|check|if (!getDolGlobalString(''MAIN_NO_UPGRADE_REDIRECT_ON_LEVEL_3_CHANGE'') || $rescomp < 3) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NUMBERING_FILTER_ON_INT_ONLY', 'string', NULL, 'core', 'Restricts numbering sequence filtering to integer-only values when set.', 'Checked in core/lib/functions2.lib.php:1168 via getDolGlobalInt; when non-zero, the sequence search applies an integer-only filter to candidate values.', 'Enabling this changes the SQL filter applied when looking up the next sequence number, excluding non-integer records from the search set.', '0 or unset = no integer-only filter; non-zero integer = filter on integers only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:1168|check|if (getDolGlobalInt(''MAIN_NUMBERING_FILTER_ON_INT_ONLY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_NUMBERING_OFFSET_ONLY_FOR_FIRST', 'string', NULL, 'core', 'When set, prevents the numbering offset from being applied to counters that are not the first in the sequence.', 'Read in core/lib/functions2.lib.php:1201 in an elseif branch: the offset is applied to catch up a counter only when this constant is not set; setting it disables that catch-up logic.', 'Setting this causes the mask offset to apply only on the very first sequence number, leaving subsequent counters unaffected by the configured offset.', 'Empty/unset = apply offset catch-up whenever counter is below offset; any non-empty string = skip offset catch-up.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:1201|read|} elseif ($counter < $maskoffset && !getDolGlobalString(''MAIN_NUMBERING_OFFSET_ONLY_FOR_FIRST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OBJECTLINE_CREATE_EMPTY_QTY_BY_DEFAULT', 'string', NULL, 'core', 'Controls whether the quantity field defaults to empty instead of 1 on the document line creation form.', 'In core/tpl/objectline_create.tpl.php:532, if this constant is not set the default quantity is 1; if set, the quantity field is rendered empty.', 'Setting this constant causes new document lines to start with a blank quantity, requiring the user to enter a value manually.', 'Truthy value = quantity field empty by default; empty/unset = quantity defaults to 1.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:532|read|<?php $default_qty = (!getDolGlobalString(''MAIN_OBJECTLINE_CREATE_EMPTY_QTY_BY_DEFAULT'') ? 1 : ''''); ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ODF_ZIP_PROXY', 'string', NULL, 'core', 'Selects the ZIP proxy library used when creating ODT documents from templates.', 'Read across 23 occurrences in ODT generation modules as: ''ZIP_PROXY'' => getDolGlobalString(''MAIN_ODF_ZIP_PROXY'', ''PclZipProxy''), // PhpZipProxy or PclZipProxy. Got "bad compression method" error when using PhpZipProxy.', 'Changing this value switches the ZIP library used for ODT generation; PclZipProxy is the default due to compatibility issues with PhpZipProxy.', 'String: ''PclZipProxy'' (default) or ''PhpZipProxy''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:365|read|''ZIP_PROXY''\t\t  => getDolGlobalString(''MAIN_ODF_ZIP_PROXY'', ''PclZipProxy''), // PhpZipProxy or PclZipProxy. Got \"bad compression method\" error when using PhpZipProxy.", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:365|read|''ZIP_PROXY''\t\t  => getDolGlobalString(''MAIN_ODF_ZIP_PROXY'', ''PclZipProxy''), // PhpZipProxy or PclZipProxy. Got \"bad compression method\" error when using PhpZipProxy.", "core/modules/member/doc/doc_generic_member_odt.class.php:322|read|''ZIP_PROXY''\t\t  => getDolGlobalString(''MAIN_ODF_ZIP_PROXY'', ''PclZipProxy''), // PhpZipProxy or PclZipProxy. Got \"bad compression method\" error when using PhpZipProxy."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ODT_ADD_SLASH_FOR_WINDOWS', 'string', NULL, 'core', 'Adds a triple-slash prefix to the LibreOffice user-installation path when converting ODT files, required on Windows environments.', 'Read at includes/odtphp/odf.php line 904 in the soffice command construction; the prefix ''///'' is prepended to the path only when this constant is set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant fixes LibreOffice path resolution for ODT-to-PDF conversion on Windows by prepending ''///'' to the user-installation URI.', 'Boolean/string flag; absent/falsy = no slash prefix; truthy = ''///'' prefix added to LibreOffice path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/odtphp/odf.php:904|read|$command =''soffice --headless -env:UserInstallation=file:''.escapeshellarg((getDolGlobalString(''MAIN_ODT_ADD_SLASH_FOR_WINDOWS'') ? ''///'' : '''').dol_sanitizePathName($conf->user->dir_"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ODT_AS_PDF', 'string', NULL, 'core', 'Enables automatic conversion of generated ODT documents to PDF using an external converter command.', 'Checked across 29 occurrences in ODT generation modules; includes/odtphp/odf.php:892 checks for the specific value ''libreoffice''. A code comment at odf.php:910 documents the full usage: ''MAIN_ODT_AS_PDF should be "sudo -u unoconv /usr/bin/unoconv" and userunoconv must have sudo to be root by adding file /etc/sudoers.d/unoconv with content www-data ALL=(unoconv) NOPASSWD: /usr/bin/unoconv''.', 'Setting this to a command string (e.g. ''libreoffice'' or a unoconv sudo command) causes ODT files to be converted to PDF after generation.', 'String: empty or unset = ODT only; ''libreoffice'' = use LibreOffice; full command path (e.g. ''sudo -u unoconv /usr/bin/unoconv'') = use unoconv.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["includes/odtphp/odf.php:892|check|if (getDolGlobalString(''MAIN_ODT_AS_PDF'') == ''libreoffice'') {", "includes/odtphp/odf.php:910  // MAIN_ODT_AS_PDF should be   \"sudo -u unoconv /usr/bin/unoconv\" and userunoconv must have sudo to be root by adding file /etc/sudoers.d/unoconv with content  www-data ALL=(unoconv) NOPASSWD: /usr/bin/unoconv .", "core/modules/contract/doc/doc_generic_contract_odt.modules.php:469|check|if (getDolGlobalString(''MAIN_ODT_AS_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ODT_AS_PDF_DEL_SOURCE', 'string', NULL, 'core', 'Deletes the source ODT file after converting it to PDF.', 'Checked at includes/odtphp/odf.php line 1017; the source ODT file deletion is performed only when this constant is set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant causes the source ODT file to be removed after a successful ODT-to-PDF conversion.', 'Boolean/string flag; absent/falsy = source ODT kept; truthy = source ODT deleted after conversion.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/odtphp/odf.php:1017|check|if (getDolGlobalString(''MAIN_ODT_AS_PDF_DEL_SOURCE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ODT_AS_PDF_OMIT_TEMPLATE_NAME', 'string', NULL, 'core', 'Omits the template name from the generated PDF filename when converting ODT invoice documents to PDF.', 'Checked once in core/modules/facture/doc/doc_generic_invoice_odt.modules.php at line 274; when truthy, the template name is excluded from the output file name.', 'Enabling this constant produces PDF filenames without the template name suffix. Disabling it (or leaving unset) includes the template name in the filename.', 'Truthy string to omit template name from PDF filename; empty/unset to include it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/facture/doc/doc_generic_invoice_odt.modules.php:274|check|if (getDolGlobalString(''MAIN_ODT_AS_PDF_OMIT_TEMPLATE_NAME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OLD_IMAGE_LINKS', 'string', NULL, 'core', 'When enabled, uses legacy image link format instead of the current image URL scheme.', 'Checked at core/class/html.form.class.php:11203 and :11223. When truthy, the old image link rendering path is taken; when falsy, the current scheme is used.', 'Enabling may be necessary for backward compatibility with older templates or custom code expecting the legacy URL format. Disabling uses the current image URL scheme.', 'Truthy = use old/legacy image link format; empty/unset = use current image URL scheme.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:11203|check|if (getDolGlobalString(''MAIN_OLD_IMAGE_LINKS'')) {", "core/class/html.form.class.php:11223|check|if (getDolGlobalString(''MAIN_OLD_IMAGE_LINKS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ONLY_LOGIN_ALLOWED', 'bool', NULL, 'core', 'Restricts application login to the specified username(s), effectively locking the system to one user.', 'Written via admin/tools/listsessions.php (lines 89, 96). Checked in main.inc.php (lines 173, 187, 3496) to enforce login restriction and in user/card.php:2235. The comment at main.inc.php:172 states: ''If software has been locked. Only login getDolGlobalString(''MAIN_ONLY_LOGIN_ALLOWED'') is allowed.''', 'When set, any user whose login is not in the semicolon-separated list is rejected at authentication time, effectively locking the system.', 'String: semicolon-separated username(s) allowed to log in; empty/unset to allow all users.', 0, 0, 'admin/tools/listsessions.php|admin/tools/listsessions.php|admin/tools/listsessions.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// If software has been locked. Only login getDolGlobalString(''MAIN_ONLY_LOGIN_ALLOWED'') is allowed.", "main.inc.php:187|check|if (session_id() && isset($_SESSION[\"dol_login\"]) && !in_array($_SESSION[\"dol_login\"], explode('';'', getDolGlobalString(''MAIN_ONLY_LOGIN_ALLOWED'')))) {", "admin/tools/listsessions.php:89|write|if (dolibarr_set_const($db, ''MAIN_ONLY_LOGIN_ALLOWED'', $user->login, ''text'', 1, ''Logon is restricted to a particular user'', 0) < 0) {", "admin/tools/listsessions.php:254|check|if (!getDolGlobalString(''MAIN_ONLY_LOGIN_ALLOWED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OPENIDURL_PERUSER', 'string', NULL, 'user', 'Enables per-user OpenID URL support on user profile pages when OpenID authentication is active.', 'Checked in user/card.php at lines 1921 and 2804, conjunctively with a check that main_authentication contains ''openid''. When set, an OpenID URL field is shown on the user card.', 'Enabling this constant adds a per-user OpenID URL field to user profile pages when OpenID authentication is configured; leaving it unset suppresses this field.', 'Truthy value to enable per-user OpenID URL field; empty or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/card.php:2804|check|if (isset($conf->file->main_authentication) && preg_match(''/openid/'', $conf->file->main_authentication) && getDolGlobalString(''MAIN_OPENIDURL_PERUSER'')) {", "user/card.php:1921|check|if (isset($conf->file->main_authentication) && preg_match(''/openid/'', $conf->file->main_authentication) && getDolGlobalString(''MAIN_OPENIDURL_PERUSER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OPENSURVEY_CSS_URL', 'string', NULL, 'public', 'Specifies a custom CSS URL to inject into the public OpenSurvey interface.', 'Checked and read at public/opensurvey/index.php:109-110; when set, a stylesheet link tag using the constant''s value (with a lang query parameter) is prepended to the page head.', 'Setting this constant loads a custom stylesheet on the public survey page; leaving it unset uses the default page styling.', 'Empty/unset = no custom stylesheet; a URL string = that CSS URL is linked in the page head.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/opensurvey/index.php:109|check|if (getDolGlobalString(''MAIN_OPENSURVEY_CSS_URL'')) {", "public/opensurvey/index.php:110|read|$head = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"''.getDolGlobalString(''MAIN_OPENSURVEY_CSS_URL'').''?lang=''.$langs->defaultlang.''\">''.\"\n\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OPTIMIZEFORCOLORBLIND', 'string', NULL, 'core', 'Activates a color-blind-optimized CSS class on the UI for the current user.', 'Set per-user at main.inc.php:1229 from the user preference, then checked at main.inc.php:1477-1478 to append a ''colorblind-<value>'' CSS class. Theme files theme/eldy/theme_vars.inc.php:38-39 and theme/md/theme_vars.inc.php:34-35 also branch on this value including the specific value ''flashy''.', 'Setting this changes the color palette applied via CSS for accessibility; the value ''flashy'' triggers a specific high-contrast variant.', ''''' or unset = no color-blind optimization; any non-empty string = colorblind CSS class suffix appended (e.g. ''flashy'' for flashy variant)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1228  // set MAIN_OPTIMIZEFORCOLORBLIND for user", "main.inc.php:1478|read|$tmpcsstouse .= '' colorblind-''.strip_tags(getDolGlobalString(''MAIN_OPTIMIZEFORCOLORBLIND''));", "theme/eldy/theme_vars.inc.php:39|check|if (getDolGlobalString(''MAIN_OPTIMIZEFORCOLORBLIND'') == ''flashy'') {", "theme/md/theme_vars.inc.php:35|check|if (getDolGlobalString(''MAIN_OPTIMIZEFORCOLORBLIND'') == ''flashy'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OPTIMIZEFORTEXTBROWSER', 'string', NULL, 'core', 'Switches the UI to a stripped-down text-browser-compatible mode by suppressing JavaScript-heavy elements.', 'Used in 229 locations. A comment at main.inc.php:241 notes it is set globally before the login part, and main.inc.php:1218 re-evaluates it for the user after login. Checks like main.inc.php:2287 suppress print/help links and version display when the constant is set.', 'Setting this constant removes JavaScript-dependent UI widgets (tooltips, AJAX features, version banner, print/help links) to ensure compatibility with text-only browsers.', 'Non-empty = text-browser optimisation active; empty/unset = normal UI.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Set global MAIN_OPTIMIZEFORTEXTBROWSER (must be before login part)", "// Set MAIN_OPTIMIZEFORTEXTBROWSER for user (must be after login part)", "main.inc.php:2287|check|if (!getDolGlobalString(''MAIN_PRINT_DISABLELINK'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {", "main.inc.php:2382|check|if (getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OPTIMIZE_SPEED', 'string', NULL, 'core', 'Bitmask controlling performance optimizations such as APC/APCu shared memory caching.', 'Checked as a bitmask in core/lib/memory.lib.php:134 and 239 and core/class/translate.class.php:337 and 521 with ''& 0x02'' to enable APCu-based caching. The comment at memory.lib.php:134 notes: ''This is a really not reliable cache ! Use Memcached instead.'' Configurable via admin/system/dolibarr.php.', 'Setting bit 0x02 enables APCu shared memory caching for translations and other data, which is noted as unreliable; higher or other bit values may control additional optimizations.', 'Integer bitmask; 0x02 bit = enable APCu caching (unreliable, prefer Memcached); 0 or unset = no APCu caching.', 0, 0, 'admin/system/dolibarr.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/memory.lib.php:134|read|} elseif (getDolGlobalInt(''MAIN_OPTIMIZE_SPEED'') & 0x02) {\t// This is a really not reliable cache ! Use Memcached instead.", "core/lib/memory.lib.php:239|read|} elseif (getDolGlobalInt(''MAIN_OPTIMIZE_SPEED'') & 0x02) {\t// This is a really not reliable cache ! Use Memcached instead.", "admin/system/dolibarr.php:260|check|if (getDolGlobalInt(''MAIN_OPTIMIZE_SPEED'') & 0x02) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ORDERLIST_CREATEBILLS_ONEBYTHIRD', 'string', NULL, 'commande', 'Sets the default value for the ''one bill per third party'' option in the order-list mass billing form.', 'Read in commande/list.php:1678 as the default value for the selectyesno dropdown named ''createbills_onebythird'', with ''no'' as the fallback default.', 'Changing this value alters the pre-selected option in the mass billing form; ''yes'' pre-selects grouping invoices by third party.', '''yes'' = group by third party pre-selected; ''no'' = one bill per order pre-selected (default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:1678|read|print $form->selectyesno(''createbills_onebythird'', getDolGlobalString(''MAIN_ORDERLIST_CREATEBILLS_ONEBYTHIRD'', ''no''), 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ORGANIZATION_FOR_PING', 'string', NULL, 'blockedlog', 'Overrides the organization name sent in blockedlog registration/ping requests, defaulting to ''Association Dolibarr''.', 'Read at blockedlog/admin/registration.php:273, blockedlog/admin/documentation.php:143, and blockedlog/admin/blockedlog.php:146, all with the same default ''Association Dolibarr''. Configurable via admin UI on those pages.', 'Changing this value updates the organization name transmitted to the ping server in registration requests.', 'Any string; default is ''Association Dolibarr''.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/documentation.php|blockedlog/admin/blockedlog.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$organization_for_ping = getDolGlobalString(''MAIN_ORGANIZATION_FOR_PING'', \"Association Dolibarr\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ORGANIZATION_URL_PRIVACY', 'string', NULL, 'blockedlog', 'Overrides the data privacy policy URL sent in blockedlog registration requests, defaulting to the Dolibarr GDPR page.', 'Read at blockedlog/admin/registration.php:274, blockedlog/admin/documentation.php:144, and blockedlog/admin/blockedlog.php:147, all with the default ''https://www.dolibarr.org/legal-privacy-gdpr.php''. Configurable via admin UI.', 'Changing this value updates the privacy policy URL included in blockedlog registration payloads.', 'A valid URL string; default is ''https://www.dolibarr.org/legal-privacy-gdpr.php''.', 0, 0, 'blockedlog/admin/registration.php|blockedlog/admin/documentation.php|blockedlog/admin/blockedlog.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$dataprivacy_url = getDolGlobalString(''MAIN_ORGANIZATION_URL_PRIVACY'', \"https://www.dolibarr.org/legal-privacy-gdpr.php\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OVERRIDE_TIME_LIMIT', 'string', NULL, 'core', 'Overrides the PHP maximum execution time during database upgrade scripts.', 'Checked and applied in install/upgrade2.php at lines 94-95 using set_time_limit(). If the value is a non-zero integer, it replaces PHP''s default execution time limit for the upgrade process.', 'Setting a higher value prevents upgrade scripts from timing out on large databases. Setting it to 0 removes the time limit entirely for the upgrade session.', 'Integer seconds; 0 = no time limit; unset = PHP default applies', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalInt(''MAIN_OVERRIDE_TIME_LIMIT'')) {", "@set_time_limit(getDolGlobalInt(''MAIN_OVERRIDE_TIME_LIMIT''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OVERWRITE_THEME_PATH', 'string', NULL, 'core', 'Specifies a custom filesystem path that overrides the default theme directory lookup.', 'Checked and read at core/lib/functions.lib.php:6065-6066. When set, the path is used as the base for resolving theme assets: the code appends ''/theme/'' and the active theme name, accommodating modules whose theme directory name differs from the module name.', 'Setting an incorrect path will cause theme assets to be unresolvable, breaking the UI appearance for the active theme.', 'Any valid filesystem path string pointing to the custom theme root; empty/unset = default theme path used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:6065|check|if (getDolGlobalString(''MAIN_OVERWRITE_THEME_PATH'')) {", "core/lib/functions.lib.php:6066|read|$path = getDolGlobalString(''MAIN_OVERWRITE_THEME_PATH'') . ''/theme/'' . $theme; // If the theme does not have the same name as the module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_OVERWRITE_THEME_RES', 'string', NULL, 'theme', 'Specifies an external module name whose resources (CSS, images) override the active theme''s assets.', 'Read in theme/eldy/style.css.php:182-183 and theme/md/style.css.php:189-190 to set $path and $theme for resource lookup. Also used in core/lib/functions.lib.php:6068 to construct the path for image resources from an external module. No admin UI is present.', 'Setting this value causes the theme to load CSS and image assets from the specified external module instead of the built-in theme directory.', 'String: name of the external module whose theme resources should be used (e.g. ''mybranding'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:182|read|$path = ''/'' . getDolGlobalString(''MAIN_OVERWRITE_THEME_RES'');", "theme/eldy/style.css.php:183|read|$theme = getDolGlobalString(''MAIN_OVERWRITE_THEME_RES'');", "core/lib/functions.lib.php:6068|read|$path = getDolGlobalString(''MAIN_OVERWRITE_THEME_RES'') . ''/theme/'' . getDolGlobalString(''MAIN_OVERWRITE_THEME_RES'');", "core/lib/functions.lib.php:6067|read|} elseif (getDolGlobalString(''MAIN_OVERWRITE_THEME_RES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PAGESIZE_CHOICES', 'string', NULL, 'core', 'Provides a custom comma-separated list of page-size options for pagination selectors.', 'Checked and read at core/lib/functions.lib.php:7596-7597. When set, its value is used directly as the available page-size choices in the pagination UI, overriding any default list.', 'Changing this value alters the page-size options users can select in all paginated list views.', 'A comma-separated string of integer values representing available page sizes (e.g. ''10,25,50,100''); empty/unset = default choices used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7596|check|if (getDolGlobalString(''MAIN_PAGESIZE_CHOICES'')) {", "core/lib/functions.lib.php:7597|read|$pagesizechoices = getDolGlobalString(''MAIN_PAGESIZE_CHOICES'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PAIMENTS_SHOW_ALL_INVOICE_TYPES', 'bool', NULL, 'compta', 'Controls whether all invoice types are displayed in the payment entry form, or only the default subset.', 'Read in compta/paiement.php:67 and fourn/facture/paiement.php:79 via getDolGlobalInt with a default of 0. No admin UI is configured.', 'Enabling this constant causes the payment form to list invoices of all types, not just the default selection.', '0 = show default invoice types only (default); non-zero = show all invoice types.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:67|read|$displayAllInvoices = getDolGlobalInt(''MAIN_PAIMENTS_SHOW_ALL_INVOICE_TYPES'', 0);", "fourn/facture/paiement.php:79|read|$displayAllInvoices = getDolGlobalInt(''MAIN_PAIMENTS_SHOW_ALL_INVOICE_TYPES'', 0);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PASSWORD_FORGOTLINK', 'string', NULL, 'core', 'Provides a custom URL to replace the default ''Forgot password'' link on the login page.', 'Checked and read at core/tpl/login.tpl.php:432-433. When set, the value is used as the URL for the forgot-password link. No admin UI write was found; HIDDEN_GUESS is 1.', 'Setting this redirects the forgot-password flow to an external or custom URL instead of the built-in Dolibarr password reset page.', 'Any valid URL string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/login.tpl.php:432|check|if (getDolGlobalString(''MAIN_PASSWORD_FORGOTLINK'')) {", "core/tpl/login.tpl.php:433|read|$url = getDolGlobalString(''MAIN_PASSWORD_FORGOTLINK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PAYMENT_DONATION_REF_PREFIX', 'string', NULL, 'accountancy', 'Sets the reference prefix string used for donation payment entries in the treasury journal.', 'Read once in accountancy/journal/treasuryjournal.php:778. The default value when unset is ''D''. No admin UI is configured.', 'Changing this prefix alters the reference strings generated for donation payment journal entries.', 'Any string; default is ''D''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/treasuryjournal.php:778|read|$prefix_ref = getDolGlobalString(''MAIN_PAYMENT_DONATION_REF_PREFIX'', ''D'');"]', 'low', NULL);
