INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ADDALSOTARGETDETAILS', 'string', NULL, 'core', 'Forces inclusion of the recipient''s phone, fax, email, and URL details in the target address block on PDF documents regardless of the rendering mode.', 'Checked across 10 occurrences in core/lib/pdf.lib.php and multiple PDF module files (e.g. :580, :595, :601, :607). When truthy it acts as an unconditional override equivalent to specifying ''targetwithdetails'' mode. No admin UI write is present.', 'Enabling this always adds contact details (phone, fax, email, URL) to the recipient address block, overriding default mode-based logic.', 'Truthy string (non-empty) = always show target contact details; absent/empty = details shown only when mode includes ''targetwithdetails''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:578|check|if (getDolGlobalString(''MAIN_PDF_ADDALSOTARGETDETAILS'') || preg_match(''/targetwithdetails/'', $mode)) {", "core/lib/pdf.lib.php:580|check|if (getDolGlobalString(''MAIN_PDF_ADDALSOTARGETDETAILS'') || $mode == ''targetwithdetails'' || preg_match(''/targetwithdetails_phone/'', $mode)) {", "core/lib/pdf.lib.php:595|check|if (getDolGlobalString(''MAIN_PDF_ADDALSOTARGETDETAILS'') || $mode == ''targetwithdetails'' || preg_match(''/targetwithdetails_fax/'', $mode)) {", "core/lib/pdf.lib.php:601|check|if (getDolGlobalString(''MAIN_PDF_ADDALSOTARGETDETAILS'') || $mode == ''targetwithdetails'' || preg_match(''/targetwithdetails_email/'', $mode)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ADD_TERMSOFSALE_CONTRACT', 'string', NULL, 'admin', 'Determines whether and how terms-of-sale are appended to generated contract PDFs.', 'Read at admin/pdf_other.php:451 to conditionally display the file selector, and at core/modules/contract/doc/pdf_strato.modules.php:494 to decide whether to concatenate the terms file when both this constant and MAIN_INFO_CONTRACT_TERMSOFSALE are set. Also checked at contrat/card.php:2392 to show PDF model selection. Configurable via admin/pdf_other.php:127.', 'Setting this constant to a non-zero value causes the terms-of-sale file (defined by MAIN_INFO_CONTRACT_TERMSOFSALE) to be concatenated to contract PDFs.', '0 or unset = no terms appended; non-zero integer = terms-of-sale file appended to contract PDF.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf_other.php:127|write|dolibarr_set_const($db, \"MAIN_PDF_ADD_TERMSOFSALE_CONTRACT\", GETPOST(\"MAIN_PDF_ADD_TERMSOFSALE_CONTRACT\", ''int''), ''chaine'', 0, '''', $conf->entity);", "core/modules/contract/doc/pdf_strato.modules.php:494|check|if (getDolGlobalString(''MAIN_INFO_CONTRACT_TERMSOFSALE'') && getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_CONTRACT'')) {", "admin/pdf_other.php:451|check|if (getDolGlobalString(\"MAIN_PDF_ADD_TERMSOFSALE_CONTRACT\")) {", "contrat/card.php:2392|check|if (getDolGlobalString(''MAIN_PDF_ADD_TERMSOFSALE_CONTRACT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ADD_TERMSOFSALE_INVOICE', 'string', NULL, 'admin', 'Controls whether and how a terms-of-sale document is appended to invoice PDFs.', 'Configurable via admin/pdf_other.php (written at line 130, read at line 526). Checked in core/modules/facture/doc/pdf_octopus.modules.php:1039 and pdf_sponge.modules.php:1109 to append the terms-of-sale file to generated invoice PDFs.', 'Setting this constant to a non-zero value causes the terms-of-sale file (specified by MAIN_INFO_INVOICE_TERMSOFSALE) to be concatenated to invoice PDFs during generation.', '0 or unset = no terms-of-sale appended; non-zero = terms-of-sale file is appended to invoice PDF.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf_other.php:130|write|dolibarr_set_const($db, \"MAIN_PDF_ADD_TERMSOFSALE_INVOICE\", GETPOST(\"MAIN_PDF_ADD_TERMSOFSALE_INVOICE\", ''int''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:526|read|print $form->selectarray(\"MAIN_PDF_ADD_TERMSOFSALE_INVOICE\", $arrval, getDolGlobalString(''MAIN_PDF_ADD_TERMSOFSALE_INVOICE''));", "core/modules/facture/doc/pdf_octopus.modules.php:1039|check|if (getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_INVOICE'') && $termsofsalefilename) {", "core/modules/facture/doc/pdf_sponge.modules.php:1109|check|if (getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_INVOICE'') && $termsofsalefilename) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ADD_TERMSOFSALE_ORDER', 'string', NULL, 'admin', 'Controls whether the terms-of-sale document is automatically appended to generated order PDFs.', 'Managed via the admin UI at admin/pdf_other.php (written by dolibarr_set_const, displayed as a select array). Checked in pdf_einstein.modules.php and pdf_eratosthene.modules.php combined with a non-empty $termsofsalefilename, and in commande/card.php for tooltip display.', 'Enabling this causes the file named in MAIN_INFO_ORDER_TERMSOFSALE to be concatenated to order PDFs. Disabling it prevents terms-of-sale concatenation even if the filename is configured.', '0 or empty = no terms-of-sale appended; non-zero = terms-of-sale PDF appended to order PDFs.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:124|dolibarr_set_const($db, \"MAIN_PDF_ADD_TERMSOFSALE_ORDER\", GETPOST(\"MAIN_PDF_ADD_TERMSOFSALE_ORDER\", ''int''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:404|print $form->selectarray(\"MAIN_PDF_ADD_TERMSOFSALE_ORDER\", $arrval, getDolGlobalString(''MAIN_PDF_ADD_TERMSOFSALE_ORDER''));", "pdf_einstein.modules.php:645|if (getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_ORDER'') && $termsofsalefilename) {", "commande/card.php:3687|if (getDolGlobalString(''MAIN_PDF_ADD_TERMSOFSALE_ORDER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ADD_TERMSOFSALE_PROPAL', 'string', NULL, 'admin', 'Controls whether a terms-of-sale document is appended to proposal PDFs.', 'When set, the PDF generation for proposals (azur, cyan templates) appends the file specified by MAIN_INFO_PROPAL_TERMSOFSALE. Configurable via admin/pdf_other.php. Seen in pdf_cyan.modules.php:946, pdf_azur.modules.php:775, and comm/propal/card.php:3760.', 'Enabling this automatically concatenates the terms-of-sale PDF to every proposal document; disabling it omits the attachment.', 'Empty/unset = no terms-of-sale appended; truthy value = terms-of-sale file is concatenated to the proposal PDF.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf_other.php:121|write|dolibarr_set_const($db, \"MAIN_PDF_ADD_TERMSOFSALE_PROPAL\", GETPOST(\"MAIN_PDF_ADD_TERMSOFSALE_PROPAL\", ''int''), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:946|check|if (getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_PROPAL'') && $termsofsalefilename) {", "core/modules/propale/doc/pdf_azur.modules.php:775|check|if (getDolGlobalInt(''MAIN_PDF_ADD_TERMSOFSALE_PROPAL'') && $termsofsalefilename) {", "admin/pdf_other.php:325|read|print $form->selectarray(\"MAIN_PDF_ADD_TERMSOFSALE_PROPAL\", $arrval, getDolGlobalString(''MAIN_PDF_ADD_TERMSOFSALE_PROPAL''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DASH_BETWEEN_LINES', 'string', NULL, 'core', 'Draws a dashed separator line between PDF document line items.', 'Checked in 43 locations across stock, stocktransfer, expedition, commande, facture, and other PDF modules at positions such as core/modules/stocktransfer/doc/pdf_eagle.modules.php:679 and core/modules/commande/doc/pdf_einstein.modules.php:567. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant causes a dashed line to be drawn between each line item in generated PDFs, except after the last item.', '0 (no dash lines) or 1 (dash lines between items)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:679|check|if (getDolGlobalString(''MAIN_PDF_DASH_BETWEEN_LINES'') && $i < ($nblines - 1)) {", "core/modules/commande/doc/pdf_einstein.modules.php:567|check|if (getDolGlobalString(''MAIN_PDF_DASH_BETWEEN_LINES'') && $i < ($nblines - 1)) {", "core/modules/expedition/doc/pdf_rouget.modules.php:619|check|if (getDolGlobalString(''MAIN_PDF_DASH_BETWEEN_LINES'') && $i < ($nblines - 1)) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:736|check|if (getDolGlobalInt(''MAIN_PDF_DASH_BETWEEN_LINES'') && $i < ($nblines - 1)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DATA_ON_FIRST_PAGE', 'string', NULL, 'core', 'Forces line items data to start on the first page of generated PDFs rather than beginning on a subsequent page.', 'Checked across 48 occurrences in PDF generation modules (e.g. core/modules/contract/doc/pdf_strato.modules.php:413, core/modules/stock/doc/pdf_standard_stock.modules.php:361). A commented example is present at modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:566.', 'Enabling this displays data starting on the first page; disabling it allows the layout engine to defer data to subsequent pages.', '0 or unset = data placement determined by layout engine; 1 = data starts on first page.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:413|check|if (getDolGlobalString(''MAIN_PDF_DATA_ON_FIRST_PAGE'')) {", "core/modules/stock/doc/pdf_standard_stock.modules.php:361|check|if (getDolGlobalString(''MAIN_PDF_DATA_ON_FIRST_PAGE'')) {", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:518|check|if (getDolGlobalString(''MAIN_PDF_DATA_ON_FIRST_PAGE'')) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:566  // \t\tif (getDolGlobalInt(''MAIN_PDF_DATA_ON_FIRST_PAGE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DATE_TEXT', 'string', NULL, 'core', 'Specifies custom text to display for the date field on proposal PDF documents.', 'Checked in pdf_cyan.modules.php:1797 and pdf_azur.modules.php:1666. When set, a custom date text block is rendered on the PDF. No admin UI write is present.', 'Setting this constant causes a custom date text element to appear on proposal PDFs in both cyan and azur templates. Leaving it unset suppresses that element.', 'A non-empty string = custom date label shown on PDF; empty or unset = section omitted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:1797|check|if (getDolGlobalString(''MAIN_PDF_DATE_TEXT'')) {", "core/modules/propale/doc/pdf_azur.modules.php:1666|check|if (getDolGlobalString(''MAIN_PDF_DATE_TEXT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DELIVERY_DATE_TEXT', 'string', NULL, 'core', 'Specifies custom text to display for the delivery date field on proposal PDF documents.', 'Checked in pdf_cyan.modules.php:1100 and pdf_azur.modules.php:948. When set, a delivery date text block is rendered on the proposal PDF. No admin UI write is present.', 'Setting this constant causes a delivery date text area to appear on proposal PDFs; leaving it unset suppresses that section.', 'A non-empty string = custom delivery date label/text shown on PDF; empty or unset = section omitted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:1100|check|if (getDolGlobalString(''MAIN_PDF_DELIVERY_DATE_TEXT'')) {", "core/modules/propale/doc/pdf_azur.modules.php:948|check|if (getDolGlobalString(''MAIN_PDF_DELIVERY_DATE_TEXT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DISABLESOURCEDETAILS', 'bool', NULL, 'core', 'Disables the inclusion of source company detail lines in generated PDF documents.', 'Checked in core/lib/pdf.lib.php:477; when absent or falsy, source details are included in the PDF output.', 'Enabling this constant removes source company details from PDFs, producing a more minimal document header.', 'Truthy value to disable source details; absent or falsy to include them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:477|check|if (!getDolGlobalString(''MAIN_PDF_DISABLESOURCEDETAILS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DISABLE_COL_HEAD_TITLE', 'bool', NULL, 'core', 'Disables printing of column header titles in the line items table of generated PDF documents.', 'Read in 20 PDF generation modules; used as $hidetop = getDolGlobalInt(''MAIN_PDF_DISABLE_COL_HEAD_TITLE'') (e.g. core/modules/commande/doc/pdf_eratosthene.modules.php:202) and as a boolean check to skip header rendering.', 'Enabling this suppresses column titles on the line items table in all affected PDF document types.', '0 or unset = column headers shown; 1 = column headers hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/commande/doc/pdf_eratosthene.modules.php:202|read|$hidetop = getDolGlobalInt(''MAIN_PDF_DISABLE_COL_HEAD_TITLE'');", "core/modules/propale/doc/pdf_cyan.modules.php:195|read|$hidetop = getDolGlobalInt(''MAIN_PDF_DISABLE_COL_HEAD_TITLE'');", "core/modules/facture/doc/pdf_octopus.modules.php:303|check|if (getDolGlobalString(''MAIN_PDF_DISABLE_COL_HEAD_TITLE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_DONOTREPEAT_HEAD', 'string', NULL, 'core', 'Prevents the document header from being repeated on subsequent pages of generated PDFs.', 'Read across 182 occurrences in PDF modules; controls both the tab_top_newpage position (e.g. core/modules/contract/doc/pdf_strato.modules.php:276: $tab_top_newpage = (!getDolGlobalInt(''MAIN_PDF_DONOTREPEAT_HEAD'') ? 42 : 10)) and conditional header re-drawing.', 'Enabling this suppresses the header on pages after the first, reducing repeated content; disabling it (default) repeats the header on every page.', '0 or unset = header repeated on each page; 1 = header printed on first page only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:276|read|$tab_top_newpage = (!getDolGlobalInt(''MAIN_PDF_DONOTREPEAT_HEAD'') ? 42 : 10);", "core/modules/commande/doc/pdf_einstein.modules.php:332|read|$tab_top_newpage = (!getDolGlobalInt(''MAIN_PDF_DONOTREPEAT_HEAD'') ? 42 + $top_shift : 10);", "core/modules/commande/doc/pdf_eratosthene.modules.php:887|check|if (!getDolGlobalInt(''MAIN_PDF_DONOTREPEAT_HEAD'') && $i != $pageposbeforeprintlines) {", "core/modules/facture/doc/pdf_sponge.modules.php:1074|check|if (!getDolGlobalInt(''MAIN_PDF_DONOTREPEAT_HEAD'') && $i != $pageposbeforeprintlines) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_ENABLE_COL_HEAD_TITLE_REPEAT', 'bool', NULL, 'core', 'When set, repeats column header titles on each page of multi-page PDF documents.', 'Checked in five locations across pdf_eratosthene.modules.php, pdf_cyan.modules.php, and pdf_sponge.modules.php. Two checks guard the initial header rendering and three guard repeated header rendering on subsequent pages.', 'Enabling this causes column headers to be re-drawn at the top of every page in multi-page PDFs. Disabling (or leaving unset) prints column headers only on the first page.', '0 or unset = column headers printed once; non-zero = column headers repeated on each PDF page.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eratosthene.modules.php:373|if (!$hidetop && getDolGlobalInt(''MAIN_PDF_ENABLE_COL_HEAD_TITLE_REPEAT'')) {", "pdf_cyan.modules.php:362|if (!$hidetop && getDolGlobalInt(''MAIN_PDF_ENABLE_COL_HEAD_TITLE_REPEAT'')) {", "pdf_eratosthene.modules.php:862|if (getDolGlobalInt(''MAIN_PDF_ENABLE_COL_HEAD_TITLE_REPEAT'')) {", "pdf_sponge.modules.php:1048|if (getDolGlobalInt(''MAIN_PDF_ENABLE_COL_HEAD_TITLE_REPEAT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_FORCE_FONT', 'string', NULL, 'core', 'Forces all PDF documents to use a specific font instead of the locale-determined default.', 'Checked in core/lib/pdf.lib.php:275; when set, the stored font name is returned as the PDF font.', 'Setting this value overrides the font selection for all generated PDFs; clearing it restores locale-based font selection.', 'A valid PDF font name string recognized by the PDF library.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:275|check|if (getDolGlobalString(''MAIN_PDF_FORCE_FONT'')) {", "core/lib/pdf.lib.php:276|read|return $conf->global->MAIN_PDF_FORCE_FONT;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_FORCE_FONT_SIZE', 'string', NULL, 'core', 'Forces all PDF documents to use a specific font size instead of the default.', 'Checked in core/lib/pdf.lib.php:302; when set, the stored size value overrides the computed font size.', 'Setting this value overrides the default font size for all generated PDFs; clearing it restores dynamic font size selection.', 'A numeric string representing the font size in points.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:302|check|if (getDolGlobalString(''MAIN_PDF_FORCE_FONT_SIZE'')) {", "core/lib/pdf.lib.php:303|read|$size = getDolGlobalString(''MAIN_PDF_FORCE_FONT_SIZE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_FORMAT', 'string', NULL, 'core', 'Sets the default paper format used when generating PDF documents.', 'Written in admin/pdf.php:71 and read in core/lib/pdf.lib.php:91-102. When absent or set to ''auto'', the format is auto-detected from locale; otherwise the stored value is used directly.', 'Changing this value changes the paper size for all generated PDFs; setting to ''auto'' or leaving empty restores locale-based auto-detection.', 'A paper format string such as ''A4'', ''letter'', or ''auto'' to enable auto-detection.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:98|check|if ($mode == ''auto'' || !getDolGlobalString(''MAIN_PDF_FORMAT'') || getDolGlobalString(''MAIN_PDF_FORMAT'') == ''auto'') {", "core/lib/pdf.lib.php:102|read|$pdfformat = getDolGlobalString(''MAIN_PDF_FORMAT'');", "admin/pdf.php:71|write|dolibarr_set_const($db, \"MAIN_PDF_FORMAT\", GETPOST(\"MAIN_PDF_FORMAT\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:312|read|$selected = getDolGlobalString(''MAIN_PDF_FORMAT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_FRAME_CORNER_RADIUS', 'string', NULL, 'core', 'Sets the corner radius (in points) for frames and boxes in generated PDF documents.', 'Configured via admin/pdf.php:156 (write) and :540 (UI select). Read in 41 occurrences across all PDF module classes as $this->corner_radius. Defaults to 0 (square corners).', 'Changing this constant affects the corner rounding of all PDF document frames across all supported modules.', 'Integer in points (default: 0 = square corners); selectable values shown in admin/pdf.php', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:156|write|dolibarr_set_const($db, \"MAIN_PDF_FRAME_CORNER_RADIUS\", GETPOSTINT(\"MAIN_PDF_FRAME_CORNER_RADIUS\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:540|read|print $form->selectarray(\"MAIN_PDF_FRAME_CORNER_RADIUS\", $arrval, getDolGlobalInt(''MAIN_PDF_FRAME_CORNER_RADIUS'', 0));", "core/modules/action/doc/pdf_standard_actions.class.php:160|read|$this->corner_radius = getDolGlobalInt(''MAIN_PDF_FRAME_CORNER_RADIUS'', 0);", "core/modules/asset/doc/pdf_standard_asset.modules.php:117|read|$this->corner_radius = getDolGlobalInt(''MAIN_PDF_FRAME_CORNER_RADIUS'', 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_FREETEXT_HEIGHT', 'string', NULL, 'core', 'Sets the height in millimetres reserved for free text output at the bottom of the last page of generated PDFs.', 'Read across 41 occurrences in PDF modules as: $heightforfreetext = getDolGlobalInt(''MAIN_PDF_FREETEXT_HEIGHT'', 5); // Height reserved to output the free text on last page.', 'Increasing this value reserves more vertical space for the free text zone; decreasing it reduces this space with a default of 5 mm.', 'Integer (millimetres). Default: 5.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:348|read|$heightforfreetext = getDolGlobalInt(''MAIN_PDF_FREETEXT_HEIGHT'', 5); // Height reserved to output the free text on last page", "core/modules/contract/doc/pdf_strato.modules.php:227|read|$heightforfreetext = getDolGlobalInt(''MAIN_PDF_FREETEXT_HEIGHT'', 5); // Height reserved to output the free text on last page", "core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:272|read|$heightforfreetext = getDolGlobalInt(''MAIN_PDF_FREETEXT_HEIGHT'', 5); // Height reserved to output the free text on last page"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_HIDE_CHQ_ADDRESS', 'bool', NULL, 'core', 'When set, suppresses the cheque/payment address block from generated PDF documents.', 'Checked across at least 16 occurrences in multiple PDF modules: pdf_eagle_proforma, pdf_einstein, pdf_eratosthene, pdf_octopus, and others, consistently guarding the rendering of a cheque address section.', 'Enabling this removes the cheque address block from all affected PDF types. Disabling (or leaving unset) causes the address block to be printed.', 'Empty/unset = show cheque address; any truthy value = hide cheque address.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eagle_proforma.modules.php:984|if (!getDolGlobalString(''MAIN_PDF_HIDE_CHQ_ADDRESS'')) {", "pdf_einstein.modules.php:853|if (!getDolGlobalString(''MAIN_PDF_HIDE_CHQ_ADDRESS'')) {", "pdf_eratosthene.modules.php:1117|if (!getDolGlobalString(''MAIN_PDF_HIDE_CHQ_ADDRESS'')) {", "pdf_octopus.modules.php:1567|if (!getDolGlobalString(''MAIN_PDF_HIDE_CHQ_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE', 'bool', NULL, 'core', 'Hides the customer accounting code from the recipient block in generated PDF documents.', 'Read via admin/pdf.php:570 (select UI) and checked in 12 locations including core/modules/contract/doc/pdf_strato.modules.php:738, core/modules/expedition/doc/pdf_rouget.modules.php:1005, and core/modules/facture/doc/pdf_octopus.modules.php:2171.', 'When enabled, the customer accounting code is not printed in the recipient section of PDFs across invoices, orders, contracts, and expedition documents.', '0 (show accounting code) or 1 (hide accounting code)', 0, 0, 'admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:570|read|print $form->selectarray(\"MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE\", $arrval, getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE''));", "core/modules/contract/doc/pdf_strato.modules.php:738|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE'') && $object->thirdparty->code_compta_client) {", "core/modules/facture/doc/pdf_octopus.modules.php:2171|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE'') && $object->thirdparty->code_compta_client) {", "core/modules/expedition/doc/pdf_rouget.modules.php:1005|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_ACCOUNTING_CODE'') && !empty($object->thirdparty->code_compta_client)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_HIDE_CUSTOMER_CODE', 'bool', NULL, 'core', 'Hides the customer code from the recipient block in generated PDF documents.', 'Read via admin/pdf.php:559 (select UI) and checked in 12 locations including core/modules/contract/doc/pdf_strato.modules.php:731, core/modules/expedition/doc/pdf_rouget.modules.php:998, and core/modules/facture/doc/pdf_octopus.modules.php:2164.', 'When enabled, the customer code is not printed in the recipient section of PDFs across invoices, orders, contracts, and expedition documents.', '0 (show customer code) or 1 (hide customer code)', 0, 0, 'admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:559|read|print $form->selectarray(\"MAIN_PDF_HIDE_CUSTOMER_CODE\", $arrval, getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_CODE''));", "core/modules/contract/doc/pdf_strato.modules.php:731|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_CODE'') && $object->thirdparty->code_client) {", "core/modules/facture/doc/pdf_octopus.modules.php:2164|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_CODE'') && $object->thirdparty->code_client) {", "core/modules/expedition/doc/pdf_rouget.modules.php:998|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_CUSTOMER_CODE'') && !empty($object->thirdparty->code_client)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_HIDE_SENDER_NAME', 'bool', NULL, 'core', 'Hides the sender company name from the sender block in generated PDF documents.', 'Written via admin/pdf.php:114 and rendered in the admin UI at admin/pdf.php:356 with selectyesno. Checked in 13 locations including core/modules/contract/doc/pdf_strato.modules.php:784 and core/modules/commande/doc/pdf_einstein.modules.php:1541.', 'When enabled, the company name is omitted from the sender section of PDFs while other sender details remain.', '0 (sender name shown) or 1 (sender name hidden)', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:113  /*if (GETPOSTISSET(''MAIN_PDF_HIDE_SENDER_NAME'')) {", "admin/pdf.php:114|write|dolibarr_set_const($db, \"MAIN_PDF_HIDE_SENDER_NAME\", GETPOST(\"MAIN_PDF_HIDE_SENDER_NAME\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:356|read|print $form->selectyesno(''MAIN_PDF_HIDE_SENDER_NAME'', getDolGlobalInt(''MAIN_PDF_HIDE_SENDER_NAME''), 1);", "core/modules/contract/doc/pdf_strato.modules.php:784|check|if (!getDolGlobalString(''MAIN_PDF_HIDE_SENDER_NAME'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_MAIN_HIDE_SECOND_TAX', 'bool', NULL, 'admin', 'Hides the second tax column in PDF documents.', 'Configurable via the admin UI at admin/pdf.php (written at line 173, displayed at line 467). When not set, the second tax is shown; when set, core/lib/pdf.lib.php:2415 skips the second tax output.', 'Enabling this removes the second tax from PDFs; disabling it shows the second tax.', 'truthy (yes) = hide second tax; empty/no = show second tax', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:173|write|dolibarr_set_const($db, \"MAIN_PDF_MAIN_HIDE_SECOND_TAX\", GETPOST(\"MAIN_PDF_MAIN_HIDE_SECOND_TAX\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:467|read|$text .= $form->selectyesno(''MAIN_PDF_MAIN_HIDE_SECOND_TAX'', getDolGlobalInt(''MAIN_PDF_MAIN_HIDE_SECOND_TAX''), 1);", "core/lib/pdf.lib.php:2415|check|if (!getDolGlobalString(''MAIN_PDF_MAIN_HIDE_SECOND_TAX'')) {"]', 'high', NULL);
