INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_NO_CUSTOMER_CODE', 'string', NULL, 'admin', 'Suppresses printing of the customer code on PDF documents when enabled.', 'Written in admin/pdf.php:165 via dolibarr_set_const.', 'When enabled, the customer code field is omitted from generated PDFs.', 'Non-empty/truthy = customer code hidden on PDFs; empty/unset = customer code shown.', 0, 0, 'admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["dolibarr_set_const($db, \"MAIN_PDF_NO_CUSTOMER_CODE\", GETPOST(\"MAIN_PDF_NO_CUSTOMER_CODE\"), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_NO_RECIPENT_FRAME', 'string', NULL, 'core', 'Removes the recipient address frame from generated PDF documents.', 'Written via admin/pdf.php:110 and rendered in the admin UI at admin/pdf.php:419. Checked in 13 locations including core/modules/contract/doc/pdf_strato.modules.php:834, core/modules/expedition/doc/pdf_rouget.modules.php:1146, and core/modules/commande/doc/pdf_einstein.modules.php:1587.', 'When enabled, the recipient address box is omitted from all affected PDF documents.', '0 (recipient frame shown) or 1 (recipient frame hidden)', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:110|write|dolibarr_set_const($db, \"MAIN_PDF_NO_RECIPENT_FRAME\", GETPOST(\"MAIN_PDF_NO_RECIPENT_FRAME\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:419|read|print $form->selectarray(\"MAIN_PDF_NO_RECIPENT_FRAME\", $arrval, getDolGlobalString(''MAIN_PDF_NO_RECIPENT_FRAME''));", "core/modules/contract/doc/pdf_strato.modules.php:834|check|if (!getDolGlobalString(''MAIN_PDF_NO_RECIPENT_FRAME'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:1587|check|if (!getDolGlobalString(''MAIN_PDF_NO_RECIPENT_FRAME'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_NO_SENDER_FRAME', 'string', NULL, 'core', 'Removes the sender address frame from generated PDF documents.', 'Written via admin/pdf.php:107 and rendered in the admin UI at admin/pdf.php:410. Checked in 13 locations including core/modules/contract/doc/pdf_strato.modules.php:773, core/modules/expedition/doc/pdf_rouget.modules.php:1089, and core/modules/commande/doc/pdf_einstein.modules.php:1529.', 'When enabled, the sender address box is omitted from all affected PDF documents.', '0 (sender frame shown) or 1 (sender frame hidden)', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:107|write|dolibarr_set_const($db, \"MAIN_PDF_NO_SENDER_FRAME\", GETPOST(\"MAIN_PDF_NO_SENDER_FRAME\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:410|read|print $form->selectarray(\"MAIN_PDF_NO_SENDER_FRAME\", $arrval, getDolGlobalString(''MAIN_PDF_NO_SENDER_FRAME''));", "core/modules/contract/doc/pdf_strato.modules.php:773|check|if (!getDolGlobalString(''MAIN_PDF_NO_SENDER_FRAME'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:1529|check|if (!getDolGlobalString(''MAIN_PDF_NO_SENDER_FRAME'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_PROPAL_USE_ELECTRONIC_SIGNING', 'bool', NULL, 'admin', 'Enables electronic signing support in proposal PDF documents.', 'Written in admin/pdf_other.php at line 87 and displayed as a select array at line 278. Checked in core/modules/propale/doc/pdf_cyan.modules.php at line 2057 and pdf_azur.modules.php at line 1879 to conditionally include signing metadata.', 'Enabling this constant causes proposal PDFs to include electronic signing fields or metadata. Disabling it omits those elements from generated PDFs.', 'Truthy value to enable electronic signing in proposal PDFs; empty/unset to disable.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:87|write|dolibarr_set_const($db, \"MAIN_PDF_PROPAL_USE_ELECTRONIC_SIGNING\", GETPOST(\"MAIN_PDF_PROPAL_USE_ELECTRONIC_SIGNING\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:2057|check|if (getDolGlobalString(''MAIN_PDF_PROPAL_USE_ELECTRONIC_SIGNING'')) {", "core/modules/propale/doc/pdf_azur.modules.php:1879|check|if (getDolGlobalString(''MAIN_PDF_PROPAL_USE_ELECTRONIC_SIGNING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT', 'string', NULL, 'core', 'Controls whether the unit price (amount excl. tax) column is displayed on reception PDFs.', 'Displayed as a select in admin/pdf_other.php at line 778. Checked in pdf_squille.modules.php at lines 98, 579, 786, and 883 to conditionally render the amount HT column.', 'Enabling this constant adds a unit price (HT) column to reception PDFs. Disabling it (or leaving unset) omits the price column from receptions.', 'Truthy string to display amount HT column; empty/unset to hide it.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:778|read|print $form->selectarray(\"MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT\", $arrval, getDolGlobalString(''MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT''));", "core/modules/reception/doc/pdf_squille.modules.php:98|check|if (getDolGlobalString(''MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT'')) {", "core/modules/reception/doc/pdf_squille.modules.php:579|check|if (getDolGlobalString(''MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT'')) {", "core/modules/reception/doc/pdf_squille.modules.php:786|check|if (getDolGlobalString(''MAIN_PDF_RECEPTION_DISPLAY_AMOUNT_HT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_REMOVE_BREAK_BEFORE_COUNTRY', 'string', NULL, 'core', 'Suppresses the newline inserted before the country name in PDF address blocks.', 'Checked at core/lib/pdf.lib.php:573 and :575; when truthy, the newline separator before the country string is omitted, causing the country to appear on the same line as the preceding address element. No admin UI write is present.', 'Enabling this removes the line break before the country, compacting the address layout on PDF documents.', 'Truthy string (non-empty) = no newline before country; absent/empty = newline inserted before country.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:573|read|$stringaddress .= (($stringaddress && !getDolGlobalString(''MAIN_PDF_REMOVE_BREAK_BEFORE_COUNTRY'')) ? \"\\n\" : '''')...", "core/lib/pdf.lib.php:575|read|$stringaddress .= (($stringaddress && !getDolGlobalString(''MAIN_PDF_REMOVE_BREAK_BEFORE_COUNTRY'')) ? \"\\n\" : '''')..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_SHOW_SOURCE_PHONE_MOBILE', 'bool', NULL, 'core', 'Enables display of the source company''s mobile phone number in generated PDF documents.', 'Checked in core/lib/pdf.lib.php:483; when set and the source company has a mobile phone, it is included in the PDF.', 'Enabling adds the company mobile phone number to PDF documents; disabling omits it.', 'Truthy value to show mobile phone in PDFs; absent or falsy to hide it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:483|check|if ($sourcecompany->phone_mobile && getDolGlobalString(''MAIN_PDF_SHOW_SOURCE_PHONE_MOBILE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_TITLE_BACKGROUND_COLOR', 'string', NULL, 'core', 'Sets the background colour of column title rows in generated PDF documents as a comma-separated RGB value.', 'Checked across 71 occurrences; code comments across multiple modules show the expected format: //$conf->global->MAIN_PDF_TITLE_BACKGROUND_COLOR=''230,230,230'';. No admin UI write is present.', 'Setting this value applies a background colour to column header rows in generated PDFs; leaving it unset uses no background colour.', 'String in ''R,G,B'' format (e.g. ''230,230,230''); empty or unset = no background colour.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/product/doc/pdf_standard.modules.php:646  //$conf->global->MAIN_PDF_TITLE_BACKGROUND_COLOR=''230,230,230'';", "core/modules/stock/doc/pdf_standard_stock.modules.php:648  //$conf->global->MAIN_PDF_TITLE_BACKGROUND_COLOR=''230,230,230'';", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:700|check|if (getDolGlobalString(''MAIN_PDF_TITLE_BACKGROUND_COLOR'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_TITLE_TEXT_COLOR', 'string', NULL, 'core', 'Sets the RGB color for title text in proposal PDF documents generated by the cyan template.', 'Checked and read in pdf_cyan.modules.php at lines 1659, 1660, and 1666. The value is parsed with explode('','', ...) to extract RGB components, applied to title text rendering. No admin UI write is present.', 'Setting this constant overrides the default title text color in the cyan proposal PDF template. Leaving it unset causes the template to use its built-in default color.', 'A comma-separated RGB string (e.g. ''255,0,0''); empty or unset = default color used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:1659|check|if (getDolGlobalString(''MAIN_PDF_TITLE_TEXT_COLOR'')) {", "core/modules/propale/doc/pdf_cyan.modules.php:1660|read|$arrayColorTextTitle = explode('','', getDolGlobalString(''MAIN_PDF_TITLE_TEXT_COLOR''));", "core/modules/propale/doc/pdf_cyan.modules.php:1666|check|if (getDolGlobalString(''MAIN_PDF_TITLE_TEXT_COLOR'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_USE_ISO_LOCATION', 'bool', NULL, 'core', 'Switches PDF documents to ISO-standard address block placement, adjusting recipient box width and vertical position.', 'Configured via admin/pdf.php:162 and read across 66 occurrences; controls $posy (40 vs 42) and $widthrecbox (92 vs 100) in PDF header address rendering (e.g. core/modules/contract/doc/pdf_strato.modules.php:822, core/modules/stocktransfer/doc/pdf_eagle.modules.php:1194).', 'Enabling this adjusts address block dimensions and position to conform to ISO envelope window standards; disabling uses wider non-ISO layout.', '0 or unset = non-ISO layout (widthrecbox=100, posy=42); 1 = ISO layout (widthrecbox=92, posy=40).', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:162|write|dolibarr_set_const($db, \"MAIN_PDF_USE_ISO_LOCATION\", GETPOST(\"MAIN_PDF_USE_ISO_LOCATION\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/contract/doc/pdf_strato.modules.php:822|read|$widthrecbox = getDolGlobalString(''MAIN_PDF_USE_ISO_LOCATION'') ? 92 : 100;", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:873|read|$posy = getDolGlobalString(''MAIN_PDF_USE_ISO_LOCATION'') ? 40 : 42;", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:1156|read|$widthrecbox = getDolGlobalInt(''MAIN_PDF_USE_ISO_LOCATION'') ? 92 : 100;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PDF_USE_LARGE_LOGO', 'bool', NULL, 'core', 'Switches the company logo in PDF document headers to a larger version.', 'Checked across 20 occurrences in PDF generation modules using !getDolGlobalInt(''MAIN_PDF_USE_LARGE_LOGO'') to choose between standard and large logo rendering paths. No admin UI write is present.', 'Enabling this causes PDF modules to use the larger logo variant in document headers.', '0 or unset = standard logo; 1 = large logo.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:762|check|if (!getDolGlobalInt(''MAIN_PDF_USE_LARGE_LOGO'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:1387|check|if (!getDolGlobalInt(''MAIN_PDF_USE_LARGE_LOGO'')) {", "core/modules/expedition/doc/pdf_rouget.modules.php:952|check|if (!getDolGlobalInt(''MAIN_PDF_USE_LARGE_LOGO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PHONE_SEPAR', 'string', NULL, 'core', 'Sets a custom separator character inserted between phone number segments in display output.', 'Checked and read in core/lib/functions.lib.php:4844-4845; when set, the separator string is used to format phone numbers. No admin UI write detected.', 'Changing this value alters the visual formatting of phone numbers throughout the application. Without it, the default phone number format is used.', 'Any string separator character or sequence (e.g., ''.'', ''-'', '' '').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:4844|check|if (getDolGlobalString(''MAIN_PHONE_SEPAR'')) {", "core/lib/functions.lib.php:4845|read|$separ = getDolGlobalString(''MAIN_PHONE_SEPAR'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_POPUP_CALENDAR', 'string', NULL, 'core', 'Selects the calendar/datepicker widget type used for date input fields throughout the application.', 'Read at core/class/html.form.class.php:7831. The comment at :7828 says ''You can set MAIN_POPUP_CALENDAR to "eldy" or "jquery"''. When unset or set to ''eldy'', jQuery datepicker is used; when set to ''none'', no popup is shown (javascript check at :7830). Any other value is used directly.', 'Setting to ''none'' disables the popup calendar on all date fields. Setting to ''eldy'' or leaving unset uses jQuery. Changing this affects UX on all date inputs across the application.', 'You can set MAIN_POPUP_CALENDAR to ''eldy'' or ''jquery''; ''none'' = no popup; unset or ''eldy'' = use jQuery datepicker.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7828  // You can set MAIN_POPUP_CALENDAR to ''eldy'' or ''jquery''", "core/class/html.form.class.php:7830|check|if (!empty($conf->use_javascript_ajax) && (!getDolGlobalString(''MAIN_POPUP_CALENDAR'') || getDolGlobalString(''MAIN_POPUP_CALENDAR'') != \"none\")) {", "core/class/html.form.class.php:7831|read|$usecalendar = ((!getDolGlobalString(''MAIN_POPUP_CALENDAR'') || getDolGlobalString(''MAIN_POPUP_CALENDAR'') == ''eldy'') ? ''jquery'' : getDolGlobalString(\"MAIN_POPUP_CALENDAR\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_POPUP_CALENDAR_ON_FOCUS', 'string', NULL, 'core', 'When enabled, the calendar popup opens automatically when a date field receives focus.', 'Checked at core/class/html.form.class.php:7911. When unset (falsy), the code takes the branch that prevents the popup from opening on focus; when set, the opposite branch is taken.', 'Enabling causes date picker popups to appear on field focus, which improves UX but may interfere with keyboard navigation. Leaving unset disables focus-triggered opening.', 'Truthy = open calendar on focus; empty/unset = do not open calendar on focus.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7911|check|if (!getDolGlobalString(''MAIN_POPUP_CALENDAR_ON_FOCUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PRINT_DISABLELINK', 'bool', NULL, 'core', 'Disables the print link/button shown in the page toolbar.', 'Checked at main.inc.php:2287 alongside MAIN_OPTIMIZEFORTEXTBROWSER to suppress the print link.', 'Enabling this hides the print link from the page toolbar.', '0 or unset = print link shown; 1 (truthy) = print link hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2287|check|if (!getDolGlobalString(''MAIN_PRINT_DISABLELINK'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PRODUCT_DISABLE_CUSTOMCOUNTRYCODE', 'bool', NULL, 'compta', 'Suppresses display of a product''s customs code and country of origin on document line forms.', 'When unset, reception/card.php:1018, compta/facture/card.php:2691, commande/card.php:1306, comm/propal/card.php:1569, expedition/card.php:1281, compta/facture/card-rec.php:695, and fourn/facture/card-rec.php:632 display the product''s customcode/country_code. Setting this constant hides that information. No admin UI write path exists.', 'Enabling this constant hides customs tariff code and country-of-origin fields on all document line forms; disabling it shows those fields when the product has a customcode or country_code set.', 'Truthy string/bool=customs info hidden, empty/0=customs info shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:1018|check|if (!getDolGlobalString(''MAIN_PRODUCT_DISABLE_CUSTOMCOUNTRYCODE'') && (!empty($prod->customcode) || !empty($prod->country_code))) {", "compta/facture/card.php:2691|check|if (!getDolGlobalString(''MAIN_PRODUCT_DISABLE_CUSTOMCOUNTRYCODE'') && (!empty($prod->customcode) || !empty($prod->country_code))) {", "commande/card.php:1306|check|if (!getDolGlobalString(''MAIN_PRODUCT_DISABLE_CUSTOMCOUNTRYCODE'') && (!empty($prod->customcode) || !empty($prod->country_code))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PRODUCT_FORCE_INDEX', 'string', NULL, 'core', 'Specifies the database index name to force on product search queries via a USE INDEX hint.', 'In core/class/html.form.class.php, the value of this constant is sanitized and inserted into a USE INDEX() SQL clause when MAIN_SEARCH_PRODUCT_FORCE_INDEX is also set. Only one read occurrence; no admin UI write; hidden setting.', 'Setting this to a valid index name directs the product search query to use that specific index; the index must exist on the product table or the query will fail.', 'A valid database index name string for the product table.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3243|read|$sql .= \" USE INDEX (\" . $this->db->sanitize(getDolGlobalString(''MAIN_PRODUCT_FORCE_INDEX'')) . \")\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PRODUCT_PERENTITY_SHARED', 'string', NULL, 'accountancy', 'When enabled, uses per-entity product accounting account tables (ppe.*) instead of the global product table (p.*) for account mapping.', 'Configured via accountancy/admin/index.php:493. Checked in 54 locations including accountancy/admin/productaccount.php:224, :335, :345, :412, and product/class/product.class.php:1220. SQL field references switch between ''p.'' and ''ppe.'' prefixes depending on this flag (accountancy/admin/productaccount.php:356).', 'Enabling this constant activates per-entity product accounting accounts so that each entity in a multi-company setup can have its own account assignments for products.', 'Non-empty = use per-entity product account table (ppe.*); empty/unset = use shared product table (p.*)', 0, 0, 'accountancy/admin/index.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php|accountancy/admin/productaccount.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/index.php:493|check|if (getDolGlobalString(''MAIN_PRODUCT_PERENTITY_SHARED'')) {", "accountancy/admin/productaccount.php:356|read|$sql .= natural_search((!getDolGlobalString(''MAIN_PRODUCT_PERENTITY_SHARED'') ? \"p.\" : \"ppe.\") . $db->sanitize($accountancy_field_name), $search_current_account);", "accountancy/admin/productaccount.php:224|check|if (getDolGlobalString(''MAIN_PRODUCT_PERENTITY_SHARED'')) {", "product/class/product.class.php:1220|check|if (!$error && getDolGlobalString(''MAIN_PRODUCT_PERENTITY_SHARED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PRODUCT_REF_NOT_EDITABLE', 'string', NULL, 'product', 'Makes the product reference field read-only on the product edit card.', 'Checked at product/card.php line 2082 with a negated condition; the reference field is editable only when this constant is not set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant prevents users from editing the product reference on the product card.', 'Boolean/string flag; absent/falsy = reference editable; truthy = reference read-only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:2082|check|if (!getDolGlobalString(''MAIN_PRODUCT_REF_NOT_EDITABLE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROFID1_IN_ADDRESS', 'string', NULL, 'admin', 'Controls whether the recipient company''s professional ID 1 is included in the address block on PDF documents.', 'Written via admin/company.php:95 and admin/pdf.php:88, and checked at core/lib/pdf.lib.php:680; when truthy and idprof1 is set, it is appended to the target address.', 'Enabling this adds professional ID 1 to the recipient address block on generated PDFs.', 'Truthy string (non-empty) = include idprof1 in address; absent/empty = omit.', 0, 0, 'admin/pdf.php|admin/company.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/company.php:95|write|$res = dolibarr_set_const($db, \"MAIN_PROFID1_IN_ADDRESS\", 1, ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:88|write|dolibarr_set_const($db, \"MAIN_PROFID1_IN_ADDRESS\", GETPOST(\"MAIN_PROFID1_IN_ADDRESS\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/pdf.lib.php:680|check|if (getDolGlobalString(''MAIN_PROFID1_IN_ADDRESS'') && !empty($targetcompany->idprof1)) {"]', 'high', NULL);
