INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN', 'string', NULL, 'compta', 'Enables automatic propagation of contacts from an origin document to a newly created document.', 'Checked in 6 locations: compta/facture/class/facture.class.php:819, compta/facture/card.php:2088, commande/card.php:553, contrat/class/contrat.class.php:1142, expedition/class/expedition.class.php:683, and commande/class/commande.class.php:1213. Each site copies contacts from the origin object when this constant is set. No admin UI is present.', 'Enabling this causes contacts associated with an origin document (order, proposal, etc.) to be automatically linked to the newly created document (invoice, contract, shipment, etc.).', '0 or unset = contacts not propagated; truthy value = contacts from origin document are copied to the new document.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:819|check|if (!$error && $this->id && getDolGlobalString(''MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN'') && (!empty($this->origin_type) || !empty($this->origin)) && !empty($this->origin_id)) {", "commande/card.php:553|check|if (getDolGlobalString(''MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN'')) {", "contrat/class/contrat.class.php:1142|check|if (!$error && $this->id && getDolGlobalString(''MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN'') && !empty($this->origin) && !empty($this->origin_id)) {", "commande/class/commande.class.php:1213|check|if (!$error && getDolGlobalString(''MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN'') && !empty($this->origin) && !empty($this->origin_id)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROPAL_CHOOSE_ODT_DOCUMENT', 'string', NULL, 'core', 'When set to a value greater than 0, enables the user to choose an ODT document template at generation time for proposals, users, and user groups.', 'Read as integer via getDolGlobalInt in core/modules/propale/doc/doc_generic_proposal_odt.modules.php:127, core/modules/user/doc/doc_generic_user_odt.modules.php:113, and core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:114. The boolean $odtChosen controls whether template selection UI is shown.', 'Setting to a positive integer enables runtime ODT template selection for the covered document types. Setting to 0 or leaving unset uses the default preconfigured template.', 'Integer > 0 = enable ODT template chooser; 0 or unset = use default template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/user/doc/doc_generic_user_odt.modules.php:113|read|$odtChosen = getDolGlobalInt(''MAIN_PROPAL_CHOOSE_ODT_DOCUMENT'') > 0;", "core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:114|read|$odtChosen = getDolGlobalInt(''MAIN_PROPAL_CHOOSE_ODT_DOCUMENT'') > 0;", "core/modules/propale/doc/doc_generic_proposal_odt.modules.php:127|read|$odtChosen = getDolGlobalInt(''MAIN_PROPAL_CHOOSE_ODT_DOCUMENT'') > 0;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROXY_HOST', 'string', NULL, 'core', 'Sets the HTTP proxy hostname used for outbound cURL and IMAP connections.', 'Configured via admin/proxy.php:69 and read by core/lib/geturl.lib.php:53, paypal/lib/paypalfunctions.lib.php:67, and core/lib/functions2.lib.php:2040 to configure the proxy host for outbound connections.', 'Setting this enables proxy routing for outbound HTTP connections; leaving it empty disables proxy use (subject to MAIN_PROXY_USE).', 'String (hostname or IP address of the proxy server).', 0, 0, 'admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/proxy.php:69|write|$result += dolibarr_set_const($db, ''MAIN_PROXY_HOST'', GETPOST(\"MAIN_PROXY_HOST\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/geturl.lib.php:53|read|$PROXY_HOST = getDolGlobalString(''MAIN_PROXY_HOST'');", "paypal/lib/paypalfunctions.lib.php:67|read|$PROXY_HOST = getDolGlobalString(''MAIN_PROXY_HOST'');", "core/lib/functions2.lib.php:2040|read|$proxyhost = (!$proxyuse ? false : getDolGlobalString(''MAIN_PROXY_HOST''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROXY_PASS', 'string', NULL, 'core', 'Sets the password for authenticating with the HTTP proxy for outbound connections.', 'Configured via admin/proxy.php:72 (rendered as a password input) and read by core/lib/geturl.lib.php:56, paypal/lib/paypalfunctions.lib.php:70, and core/lib/functions2.lib.php:2043 to supply proxy authentication credentials.', 'Setting this enables proxy password authentication; leaving it empty means no password is sent to the proxy.', 'String (proxy authentication password); empty = no proxy authentication password.', 0, 0, 'admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/proxy.php:72|write|$result += dolibarr_set_const($db, ''MAIN_PROXY_PASS'', GETPOST(\"MAIN_PROXY_PASS\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/geturl.lib.php:56|read|$PROXY_PASS = getDolGlobalString(''MAIN_PROXY_PASS'');", "paypal/lib/paypalfunctions.lib.php:70|read|$PROXY_PASS = getDolGlobalString(''MAIN_PROXY_PASS'');", "core/lib/functions2.lib.php:2043|read|$proxypass = (!$proxyuse ? false : getDolGlobalString(''MAIN_PROXY_PASS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROXY_PORT', 'string', NULL, 'core', 'Sets the HTTP proxy port used for outbound cURL and IMAP connections.', 'Configured via admin/proxy.php:70 and read by core/lib/geturl.lib.php:54, paypal/lib/paypalfunctions.lib.php:68, and core/lib/functions2.lib.php:2041 to configure the proxy port for outbound connections.', 'Setting this to a valid port number routes outbound connections through that proxy port; an incorrect port prevents proxy connectivity.', 'Integer (port number of the proxy server).', 0, 0, 'admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/proxy.php:70|write|$result += dolibarr_set_const($db, ''MAIN_PROXY_PORT'', GETPOST(\"MAIN_PROXY_PORT\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/geturl.lib.php:54|read|$PROXY_PORT = getDolGlobalInt(''MAIN_PROXY_PORT'');", "paypal/lib/paypalfunctions.lib.php:68|read|$PROXY_PORT = getDolGlobalString(''MAIN_PROXY_PORT'');", "core/lib/functions2.lib.php:2041|read|$proxyport = (!$proxyuse ? false : getDolGlobalString(''MAIN_PROXY_PORT''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROXY_USE', 'string', NULL, 'core', 'Enables or disables the use of an HTTP proxy for outbound cURL and IMAP connections.', 'Configured via a yes/no select in admin/proxy.php:168 and read by core/lib/geturl.lib.php:52, paypal/lib/paypalfunctions.lib.php:71, and core/lib/functions2.lib.php:2039 to determine whether proxy settings are applied.', 'Setting to 1 activates proxy routing for outbound connections using MAIN_PROXY_HOST/PORT/USER/PASS; setting to 0 disables proxy use.', '0 = proxy disabled; 1 = proxy enabled.', 0, 0, 'admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/proxy.php:68|write|$result += dolibarr_set_const($db, ''MAIN_PROXY_USE'', GETPOST(\"MAIN_PROXY_USE\"), ''chaine'', 0, '''', $conf->entity);", "admin/proxy.php:168|read|print $form->selectyesno(''MAIN_PROXY_USE'', getDolGlobalInt(''MAIN_PROXY_USE''), 1);", "core/lib/geturl.lib.php:52|read|$USE_PROXY = getDolGlobalInt(''MAIN_PROXY_USE'');", "core/lib/functions2.lib.php:2039|read|$proxyuse = getDolGlobalString(''MAIN_PROXY_USE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PROXY_USER', 'string', NULL, 'core', 'Sets the username for authenticating with the HTTP proxy for outbound connections.', 'Configured via admin/proxy.php:71 and read by core/lib/geturl.lib.php:55, paypal/lib/paypalfunctions.lib.php:69, and core/lib/functions2.lib.php:2042 to supply proxy authentication credentials.', 'Setting this enables proxy authentication; leaving it empty means no username is sent to the proxy.', 'String (proxy authentication username); empty = no proxy authentication username.', 0, 0, 'admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/proxy.php:71|write|$result += dolibarr_set_const($db, ''MAIN_PROXY_USER'', GETPOST(\"MAIN_PROXY_USER\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/geturl.lib.php:55|read|$PROXY_USER = getDolGlobalString(''MAIN_PROXY_USER'');", "paypal/lib/paypalfunctions.lib.php:69|read|$PROXY_USER = getDolGlobalString(''MAIN_PROXY_USER'');", "core/lib/functions2.lib.php:2042|read|$proxyuser = (!$proxyuse ? false : getDolGlobalString(''MAIN_PROXY_USER''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PUBLIC_NOTE_IN_ADDRESS', 'string', NULL, 'core', 'Controls whether the public note of the recipient company is appended to the address block on PDF documents.', 'Checked at core/lib/pdf.lib.php:724; when truthy, the target company''s public note is added to the address string. No admin UI write is present; must be set manually.', 'Enabling this appends the recipient''s public note to the address block on generated PDFs.', 'Truthy string (non-empty) = include public note in address; absent/empty = omit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:724|check|if (getDolGlobalString(''MAIN_PUBLIC_NOTE_IN_ADDRESS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_PURGE_ACCEPT_NBSECONDSOLD', 'string', NULL, 'admin', 'Specifies the minimum age in seconds a file must have before the purge tool will delete it.', 'Checked in admin/tools/purge.php:134: when non-zero, only files older than this number of seconds are eligible for deletion.', 'Setting a value protects recently created files from being purged; leaving it unset or zero removes the age restriction.', 'Integer number of seconds (0 or unset = no age restriction).', 0, 0, 'admin/tools/purge.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/purge.php:134|check|if (getDolGlobalInt(''MAIN_PURGE_ACCEPT_NBSECONDSOLD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_RECRUITMENT_CSS_URL', 'string', NULL, 'public', 'URL of a custom CSS stylesheet injected into the public recruitment pages.', 'Checked in public/recruitment/view.php:292 and public/recruitment/index.php:112; when set, the URL is used to build a `<link>` tag with a lang query parameter appended. No admin UI write path is present.', 'Setting this to a valid CSS URL applies a custom stylesheet to the public-facing recruitment list and job-view pages, overriding default styles.', 'Any valid CSS URL string', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''MAIN_RECRUITMENT_CSS_URL'')) {", "$head = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"'' . getDolGlobalString(''MAIN_RECRUITMENT_CSS_URL'').''?lang=''.$langs->defaultlang.''\">''.\"\n\";", "public/recruitment/view.php:292|check", "public/recruitment/index.php:112|check"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_REMOTE_GITHUBREPO_CACHE_DELAY', 'string', NULL, 'admin', 'Sets the cache duration in seconds for GitHub repository data fetched by the remote store module.', 'Read in admin/remotestore/class/externalModules.class.php:178 as an integer with a default of 86400 (one day).', 'Increasing the value reduces API calls to GitHub; decreasing it causes more frequent refreshes of repository data.', 'Integer seconds, default 86400.', 0, 0, 'admin/remotestore/class/externalModules.class.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/remotestore/class/externalModules.class.php:178|read|$cachedelayforgithubrepo = getDolGlobalInt(''MAIN_REMOTE_GITHUBREPO_CACHE_DELAY'', 86400);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_REMOVE_DROPDOWN_CREATE_BUTTONS_ON_ORDER', 'string', NULL, 'comm', 'Removes dropdown behaviour from the create-related action buttons on proposal and order cards.', 'When set to a non-zero integer, action buttons that would normally render as dropdown menus are rendered as plain buttons instead. Affects both comm/propal/card.php:3685 and commande/card.php:3622.', 'Enabling this simplifies the UI by flattening dropdown button groups, which may affect usability for users who rely on grouped actions.', '0 or unset = dropdown buttons enabled; non-zero = dropdown buttons replaced by plain buttons.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3685|read|\"areDropdownButtons\" => !getDolGlobalInt(\"MAIN_REMOVE_DROPDOWN_CREATE_BUTTONS_ON_ORDER\"),", "commande/card.php:3622|read|\"areDropdownButtons\"\t=> !getDolGlobalInt(\"MAIN_REMOVE_DROPDOWN_CREATE_BUTTONS_ON_ORDER\")"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_REMOVE_INSTALL_WARNING', 'string', NULL, 'index.php', 'Suppresses the post-installation security warning displayed on the Dolibarr home page.', 'Checked in index.php:130; when absent or falsy the install warning is displayed. Set to 1 automatically by install/step5.php:365 at the end of the installation wizard. No admin UI is present.', 'Setting this to 1 removes the install-directory warning from the home page; leaving it unset keeps the warning visible as a security reminder.', 'Integer: 1 = warning suppressed; 0 or unset = warning displayed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:130|check|if (!getDolGlobalString(''MAIN_REMOVE_INSTALL_WARNING'')) {", "install/step5.php:365|write|$conf->global->MAIN_REMOVE_INSTALL_WARNING = 1;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_REPEATTASKONEACHTAB', 'string', NULL, 'fourn', 'Displays agenda task widgets repeatedly on each tab of supplier order and commercial order cards.', 'When set together with the agenda module being enabled and the object being in status 1, fourn/card.php:1102 and comm/card.php:1817 render agenda task blocks per tab. A secondary check at fourn/card.php:1120 and comm/card.php:1833 also conditions task display on this constant.', 'Enabling this constant causes task blocks to appear on each card tab; disabling it suppresses that repetition.', 'Truthy value repeats task display on each tab; absent or falsy disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/card.php:1102|check|if (isModEnabled(''agenda'') && getDolGlobalString(''MAIN_REPEATTASKONEACHTAB'') && $object->status == 1) {", "comm/card.php:1817|check|if (isModEnabled(''agenda'') && getDolGlobalString(''MAIN_REPEATTASKONEACHTAB'') && $object->status == 1) {", "fourn/card.php:1120|check|if (getDolGlobalString(''MAIN_REPEATTASKONEACHTAB'')) {", "comm/card.php:1833|check|if (getDolGlobalString(''MAIN_REPEATTASKONEACHTAB'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_RESTRICTHTML_ONLY_VALID_HTML', 'string', NULL, 'admin', 'Enforces strict HTML validity checks on user-supplied HTML content during sanitization.', 'Managed via admin/system/security.php (read at lines 976, 1000; written at lines 979, 983, 1003, 1007). Checked in core/lib/functions.lib.php:9589 to apply strict HTML validation during the dol_htmlwithnojs sanitization pass. The security admin page tests compatibility of this setting before enabling.', 'Enabling this constant causes invalid HTML in user content to be rejected or sanitized more aggressively; disabling it allows lenient HTML through.', '0 or empty = HTML validity not strictly enforced; 1 = only valid HTML accepted during sanitization', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/security.php:974  // Test compatibility of MAIN_RESTRICTHTML_ONLY_VALID_HTML", "admin/system/security.php:979|write|$conf->global->MAIN_RESTRICTHTML_ONLY_VALID_HTML = 1;", "core/lib/functions.lib.php:9589|check|if (!empty($out) && getDolGlobalInt(''MAIN_RESTRICTHTML_ONLY_VALID_HTML'') && $check != ''restricthtmlallowunvalid'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_RESTRICTHTML_ONLY_VALID_HTML_TIDY', 'string', NULL, 'admin', 'Enables the PHP Tidy extension to clean and validate HTML during content sanitization.', 'Managed via admin/system/security.php (read at lines 977, 995, 1001; written at lines 980, 984, 1004, 1008). Checked at core/lib/functions.lib.php:9702 during the sanitization pipeline when valid-HTML enforcement is active and link-script checks are not bypassed.', 'Enabling this constant invokes PHP Tidy on HTML content; if Tidy is unavailable the check will fail silently or produce errors.', '0 or empty = Tidy not used; 1 = PHP Tidy used to clean HTML during sanitization', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/security.php:998  // Test compatibility of MAIN_RESTRICTHTML_ONLY_VALID_HTML_TIDY", "admin/system/security.php:1004|write|$conf->global->MAIN_RESTRICTHTML_ONLY_VALID_HTML_TIDY = 1;", "core/lib/functions.lib.php:9702|check|if (!empty($out) && getDolGlobalInt(''MAIN_RESTRICTHTML_ONLY_VALID_HTML_TIDY'') && !in_array($check, array(''restricthtmlallowunvalid'', ''restricthtmlallowlinkscript'')) && $outishtml)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_RESTRICTHTML_REMOVE_ALSO_BAD_ATTRIBUTES', 'string', NULL, 'admin', 'Enables removal of disallowed HTML attributes in addition to disallowed tags during HTML sanitization.', 'The comment at core/lib/functions.lib.php:9313 states ''This method is used for example by dol_htmlwithnojs() when option MAIN_RESTRICTHTML_REMOVE_ALSO_BAD_ATTRIBUTES is set to 1.'' Checked at line 9788. Also managed via admin/system/security.php (read, written, and displayed there).', 'Setting this to 1 makes the HTML sanitizer strip unsafe attributes (e.g. event handlers) from allowed tags; without it only disallowed tags are removed.', '0 or empty = only bad tags removed; 1 = bad attributes also removed during HTML sanitization', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:9313  *  This method is used for example by dol_htmlwithnojs() when option MAIN_RESTRICTHTML_REMOVE_ALSO_BAD_ATTRIBUTES is set to 1.", "core/lib/functions.lib.php:9788|check|if (getDolGlobalString(''MAIN_RESTRICTHTML_REMOVE_ALSO_BAD_ATTRIBUTES'')) {", "admin/system/security.php:978|write|$conf->global->MAIN_RESTRICTHTML_REMOVE_ALSO_BAD_ATTRIBUTES = 0;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ROUNDING_RULE_TOT', 'string', NULL, 'core', 'Sets the rounding rule applied to invoice/order totals during price calculation.', 'Configured via admin/limits.php (read at lines 191 and 222). Used in core/lib/price.lib.php: checked at line 388, saved/restored at lines 409 and 429 when a foreign rounding rule is temporarily applied, and logged at line 457. A comment in margin/lib/margins.lib.php:140 notes: ''Also we must not apply rounding on non decimal rule defined by option MAIN_ROUNDING_RULE_TOT''.', 'Changing this rule alters how line and total amounts are rounded in price calculations; switching between rules can cause small differences in computed totals.', 'Rounding rule identifier string; empty = no special rounding rule.', 0, 0, 'admin/limits.php|admin/limits.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["margin/lib/margins.lib.php:140  // Also we must not apply rounding on non decimal rule defined by option MAIN_ROUNDING_RULE_TOT", "core/lib/price.lib.php:388|check|if (getDolGlobalString(''MAIN_ROUNDING_RULE_TOT'')) {", "core/lib/price.lib.php:409|read|$savMAIN_ROUNDING_RULE_TOT = getDolGlobalString(''MAIN_ROUNDING_RULE_TOT'');", "core/lib/price.lib.php:457|read|dol_syslog(''Price.lib::calcul_price_total MAIN_ROUNDING_RULE_TOT=''.getDolGlobalString(''MAIN_ROUNDING_RULE_TOT'')..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_ROUNDOFTOTAL_NOT_TOTALOFROUND_SUPPLIER', 'string', NULL, 'fourn', 'Selects the tax rounding calculation rule used for supplier invoices.', 'Read in fourn/facture/card.php at line 3692. When unset or falsy the rule is ''totalofround''; when set the rule switches to ''roundoftotal''.', 'Changing this value alters how tax totals are computed on supplier invoices, which can produce small differences in rounded amounts.', '0 or unset = totalofround; 1 = roundoftotal', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$calculationrule = (!getDolGlobalString(''MAIN_ROUNDOFTOTAL_NOT_TOTALOFROUND_SUPPLIER'') ? ''totalofround'' : ''roundoftotal'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SALETAX_AUTOSWITCH_I_CS_FOR_INDIA', 'string', NULL, 'core', 'Enables automatic switching between IGST and CGST/SGST tax types for Indian sellers based on buyer location.', 'Checked in core/lib/functions.lib.php:8656 when the seller country code is ''IN''; exposed as a boolean to JavaScript in core/tpl/objectline_create.tpl.php:687.', 'When enabled and the seller is Indian, the system switches between integrated and central/state GST tax codes automatically based on transaction parameters.', 'Truthy boolean = IGST/CGST-SGST auto-switch active; false/unset = no automatic switching.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/functions.lib.php:8656|check|if ($seller_country_code == ''IN'' && getDolGlobalString(''MAIN_SALETAX_AUTOSWITCH_I_CS_FOR_INDIA'')) {", "core/tpl/objectline_create.tpl.php:687|read|''MAIN_SALETAX_AUTOSWITCH_I_CS_FOR_INDIA'' => (bool) getDolGlobalInt(''MAIN_SALETAX_AUTOSWITCH_I_CS_FOR_INDIA''),", "core/tpl/objectline_create.tpl.php:764  * @property {boolean} conf.MAIN_SALETAX_AUTOSWITCH_I_CS_FOR_INDIA"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SAVE_FILE_CONTENT_AS_TEXT', 'string', NULL, 'ecm', 'Selects the text extraction engine used to index file content as plain text for full-text search.', 'Controls whether and how file content is extracted as text and stored for indexing. The inline comment states: ''Can be \''\'', \''pdftotext\'' or \''docling\''''. Used across core/lib/files.lib.php and multiple ecm/class/ecmfiles.class.php methods. No admin UI write; hidden setting.', 'Setting this to ''pdftotext'' or ''docling'' activates full-text indexation of uploaded files using the respective tool; leaving it empty disables text content extraction.', ''''' (disabled), ''pdftotext'', ''docling''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2338|read|$useFullTextIndexation = getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT'');\t// Can be '''', ''pdftotext'' or ''docling''", "ecm/class/ecmfiles.class.php:321|check|if (getDolGlobalString(\"MAIN_SAVE_FILE_CONTENT_AS_TEXT\")) {", "core/class/html.formfile.class.php:275|check|if (getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT'')) {", "ecm/class/ecmfiles.class.php:433|check|if (getDolGlobalString(\"MAIN_SAVE_FILE_CONTENT_AS_TEXT\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SAVE_FILE_CONTENT_AS_TEXT_DOCLING', 'string', NULL, 'core', 'Specifies the command-line path or invocation for the docling binary used in full-text file indexation.', 'In core/lib/files.lib.php, when MAIN_SAVE_FILE_CONTENT_AS_TEXT is ''docling'', this constant overrides the default ''docling'' command. The inline comment labels it ''Command line for docling''. Default fallback is the string ''docling''. No admin UI write; hidden setting.', 'Setting this to a custom path or command allows a non-default docling installation to be used for text extraction; leaving it unset uses the default ''docling'' command.', 'A shell command string for docling; defaults to ''docling'' if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2342|read|} elseif (getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT_DOCLING'')) {\t// Command line for docling", "core/lib/files.lib.php:4136|read|$cmd = getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT_DOCLING'', ''docling'').\" --from pdf --to text ''\"."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SAVE_FILE_CONTENT_AS_TEXT_PDFTOTEXT', 'string', NULL, 'core', 'Specifies the command-line path or invocation for the pdftotext binary used in full-text file indexation.', 'In core/lib/files.lib.php, when MAIN_SAVE_FILE_CONTENT_AS_TEXT is ''pdftotext'', this constant overrides the default ''pdftotext'' command. The default fallback is the string ''pdftotext''. No admin UI write; hidden setting.', 'Setting this to a custom path or command allows a non-default pdftotext installation to be used for text extraction; leaving it unset uses the default ''pdftotext'' command.', 'A shell command string for pdftotext; defaults to ''pdftotext'' if not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2340|check|if (getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT_PDFTOTEXT'')) {\t\t// Command line for pdftotext", "core/lib/files.lib.php:4104|read|$cmd = getDolGlobalString(''MAIN_SAVE_FILE_CONTENT_AS_TEXT_PDFTOTEXT'', ''pdftotext'') . \" \" . $params .\" ''\"."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCHBOX_CONTENT_LOADED_BEFORE_KEY', 'string', NULL, 'core', 'Controls whether the search box dropdown content is pre-loaded before a key is pressed.', 'Read at main.inc.php:3262 as a parameter to selectArrayFilter, affecting the pre-load behavior of the search combo.', 'Enabling this pre-loads search results before user input, which changes search responsiveness.', '0 or unset = content not pre-loaded; 1 (truthy) = content loaded before keypress', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3262|read|$searchform .= $form->selectArrayFilter(''searchselectcombo'', $arrayresult, (string) $selected, ''accesskey=\"s\"'', 1, 0, (getDolGlobalString(''MAIN_SEARCHBOX_CONTENT_LOADED_BEFORE_KEY''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCHFORM_ADHERENT_DISABLED', 'bool', NULL, 'core', 'Disables the member (adherent) entry in the global search box.', 'Checked in core/ajax/selectsearchbox.php:84. When set, the member search option is not added to the search box results.', 'Setting this constant removes the member search shortcut from the global search; clearing it restores it for users with the adherent read right.', 'Any non-empty value = disable member search form entry; empty/unset = show entry', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (isModEnabled(''member'') && !getDolGlobalString(''MAIN_SEARCHFORM_ADHERENT_DISABLED'') && $user->hasRight(''adherent'', ''lire'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCHFORM_CONTACT', 'string', NULL, 'user', 'Stores user-specific search form state for the contact search in the user interface preferences.', 'Read at user/param_ihm.php:89 as part of the $searchformconst array alongside MAIN_SEARCHFORM_SOCIETE and MAIN_SEARCHFORM_PRODUITSERVICE. No admin UI write found in the payload.', 'This value persists per-user search form configuration for the contact search widget.', 'A string representing saved search form state.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/param_ihm.php:89|read|$searchformconst=array($conf->global->MAIN_SEARCHFORM_SOCIETE,$conf->global->MAIN_SEARCHFORM_CONTACT,$conf->global->MAIN_SEARCHFORM_PRODUITSERVICE);"]', 'low', NULL);
