INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CATEGORY_CUSTOMER_ON_CONTRACT_LIST', 'string', NULL, 'contrat', 'Enables a customer category filter in the contract list when the Category module is active.', 'Checked once at contrat/list.php:882; when set and the Category module is active and the user has category read rights, a category filter is rendered in the contract list. No admin UI is provided.', 'Enabling this constant adds a customer category dropdown filter to the contract list view.', 'Non-empty/truthy = category filter shown; empty/unset = filter not shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/list.php:882|check|if (getDolGlobalString(''MAIN_SEARCH_CATEGORY_CUSTOMER_ON_CONTRACT_LIST'') && isModEnabled(\"category\") && $user->hasRight(''categorie'', ''lire'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CATEGORY_CUSTOMER_ON_PROJECT_LIST', 'string', NULL, 'projet', 'Enables a customer-category filter column on the project list page.', 'Checked in projet/list.php:1378 to conditionally display the customer category filter, requiring both the category module and the user''s read right on categories. No admin UI write path exists.', 'Enabling this constant adds a customer category filter to the project list; disabling or leaving it unset hides that filter.', 'Truthy string=filter shown, empty/unset=hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/list.php:1378|check|if (getDolGlobalString(''MAIN_SEARCH_CATEGORY_CUSTOMER_ON_PROJECT_LIST'') && isModEnabled(\"category\") && $user->hasRight(''categorie'', ''lire'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CATEGORY_CUSTOMER_ON_TASK_LIST', 'string', NULL, 'projet', 'Enables category filter UI for customer categories on the project task list page.', 'Checked once at projet/tasks/list.php:830: `if (getDolGlobalString(''MAIN_SEARCH_CATEGORY_CUSTOMER_ON_TASK_LIST'') && isModEnabled("category") && $user->hasRight(''categorie'', ''lire''))`. Only 1 occurrence in 1 file.', 'When unset or the category module is disabled, no customer category filter is shown on the task list. When set (and the user has category read rights), a category filter appears on the task list.', 'Truthy value = customer category filter shown on task list; empty/unset = filter hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/list.php:830|check|if (getDolGlobalString(''MAIN_SEARCH_CATEGORY_CUSTOMER_ON_TASK_LIST'') && isModEnabled(\"category\") && $user->hasRight(''categorie'', ''lire'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CATEGORY_PRODUCT_ON_LISTS', 'string', NULL, 'product', 'Adds a product category filter to the stock inventory list page when the category module is enabled.', 'Checked at product/inventory/list.php:487 inside a condition that also verifies isModEnabled(''category'') and category read rights. No comment is present in the payload.', 'Enabling this constant exposes a category-based search filter on the inventory list, allowing users to narrow inventory by product category.', 'Any truthy value shows the category filter; unset hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/inventory/list.php:487|check|if (getDolGlobalString(''MAIN_SEARCH_CATEGORY_PRODUCT_ON_LISTS'') && isModEnabled(''category'') && $user->hasRight(''categorie'', ''lire'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CAT_OR_BY_DEFAULT', 'string', NULL, 'projet', 'Sets the default category search operator (OR/AND) used across list views when no session preference is stored.', 'Read across 33 occurrences in at least 8 list pages including projet/list.php, projet/tasks/list.php, supplier_proposal/list.php, and knowledgemanagement/knowledgerecord_list.php. When a session value is not set for the operator, the constant value is used as the default (e.g. `$searchCategoryCustomerOperator = getDolGlobalString(''MAIN_SEARCH_CAT_OR_BY_DEFAULT'')`).', 'When unset, list views default to their built-in operator (typically AND). When set to a truthy value, the OR operator is applied by default for category searches across all affected list views.', 'Truthy value = OR operator as default for category search; empty/unset = AND operator (built-in default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/list.php:80|read|} elseif (getDolGlobalString(''MAIN_SEARCH_CAT_OR_BY_DEFAULT'')) {", "projet/tasks/list.php:81|read|$searchCategoryCustomerOperator = getDolGlobalString(''MAIN_SEARCH_CAT_OR_BY_DEFAULT'');", "projet/list.php:145|read|} elseif (getDolGlobalString(''MAIN_SEARCH_CAT_OR_BY_DEFAULT'')) {", "knowledgemanagement/knowledgerecord_list.php:65|read|$searchCategoryKnowledgemanagementOperator = getDolGlobalString(''MAIN_SEARCH_CAT_OR_BY_DEFAULT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CAT_PROJECT_OR_BY_DEFAULT', 'string', NULL, 'projet', 'Sets the default operator used when filtering project lists by project category.', 'Read in projet/list.php:137-138 as the fallback value for $searchCategoryUserOperator when no session-based project-category operator is present. No admin UI write path exists.', 'Changing this value alters the default logical operator applied to project-category filters on the project list.', 'Operator string value (e.g. ''0'' or ''1'' depending on form usage)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/list.php:137|read|} elseif (getDolGlobalString(''MAIN_SEARCH_CAT_PROJECT_OR_BY_DEFAULT'')) {", "projet/list.php:138|read|$searchCategoryUserOperator = getDolGlobalString(''MAIN_SEARCH_CAT_PROJECT_OR_BY_DEFAULT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_CAT_USER_OR_BY_DEFAULT', 'string', NULL, 'projet', 'Sets the default operator used when filtering project lists by user category.', 'Read in projet/list.php:130-131 as the fallback value for $searchCategoryUserOperator when no session-based operator is present. No admin UI write path exists.', 'Changing this value alters the default logical operator (e.g. AND/OR) applied to user-category filters on the project list.', 'Operator string value (e.g. ''0'' or ''1'' depending on form usage)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/list.php:130|read|} elseif (getDolGlobalString(''MAIN_SEARCH_CAT_USER_OR_BY_DEFAULT'')) {", "projet/list.php:131|read|$searchCategoryUserOperator = getDolGlobalString(''MAIN_SEARCH_CAT_USER_OR_BY_DEFAULT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_DIRECT_OPEN_IF_ONLY_ONE', 'string', NULL, 'hrm', 'Automatically opens the single result when a search returns exactly one record.', 'Checked in 58 locations across list pages (e.g. accountancy/admin/template/list.php:316, admin/emailcollector_list.php:348, projet/tasks/list.php:603). The pattern consistently checks: result count == 1 AND this constant is set AND a global search term is present.', 'Enabling this constant causes list searches yielding exactly one result to redirect directly to that record''s detail page instead of showing the list.', 'Non-zero/non-empty = auto-open single result; 0 or unset = always show list.', 0, 0, 'accountancy/admin/template/list.php|admin/emailcollector_list.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/admin/template/list.php:316|check|if ($num == 1 && getDolGlobalInt(''MAIN_SEARCH_DIRECT_OPEN_IF_ONLY_ONE'') && $search_all && !$page) {", "admin/emailcollector_list.php:348|check|if ($num == 1 && getDolGlobalInt(''MAIN_SEARCH_DIRECT_OPEN_IF_ONLY_ONE'') && $search_all && !$page) {", "projet/tasks/list.php:603|check|if ($num == 1 && getDolGlobalString(''MAIN_SEARCH_DIRECT_OPEN_IF_ONLY_ONE'') && $search_all) {", "partnership/partnership_list.php:499|check|if ($num == 1 && getDolGlobalString(''MAIN_SEARCH_DIRECT_OPEN_IF_ONLY_ONE'') && $search_all && !$page) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_FORM_ON_HOME_AREAS', 'string', NULL, 'product', 'Controls whether a legacy search form is displayed on module home/index pages.', 'Checked in product/index.php:120, reception/index.php:73, don/index.php:104, hrm/index.php:133, and product/stock/index.php:72. Code comments note it ''may be useless due to the global search combo''. No admin UI write path exists.', 'Enabling this constant causes additional search forms to appear on several module index pages; disabling or leaving it unset hides them.', 'Truthy string=search form shown, empty/unset=hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/index.php:120|check|if (getDolGlobalString(''MAIN_SEARCH_FORM_ON_HOME_AREAS'')) {     // This may be useless due to the global search combo", "hrm/index.php:133|check|if (getDolGlobalString(''MAIN_SEARCH_FORM_ON_HOME_AREAS'')) {     // This is useless due to the global search combo", "don/index.php:104|check|if (getDolGlobalString(''MAIN_SEARCH_FORM_ON_HOME_AREAS'')) {     // TODO Add a search into global search combo so we can remove this", "reception/index.php:73|check|if (getDolGlobalString(''MAIN_SEARCH_FORM_ON_HOME_AREAS'')) {     // This may be useless due to the global search combo"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_PRODUCT_BY_FOURN_REF', 'string', NULL, 'core', 'Includes supplier reference numbers in the product search query, allowing products to be found by their supplier''s reference.', 'When set, core/class/html.form.class.php adds a JOIN or condition on supplier reference fields in the product search SQL. Two check occurrences in the file. No admin UI write; hidden setting.', 'Enabling this constant allows users to find products by typing a supplier reference; disabling it (or leaving unset) restricts search to internal product references and labels.', 'Non-empty (truthy) enables supplier reference search; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3372|check|if (getDolGlobalString(''MAIN_SEARCH_PRODUCT_BY_FOURN_REF'')) {", "core/class/html.form.class.php:3387|check|if (getDolGlobalString(''MAIN_SEARCH_PRODUCT_BY_FOURN_REF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_PRODUCT_FORCE_INDEX', 'string', NULL, 'core', 'Forces a specific database index hint to be applied to product search queries.', 'When set, core/class/html.form.class.php appends a USE INDEX() hint to the product search SQL query. Works together with MAIN_PRODUCT_FORCE_INDEX which supplies the index name. Only one occurrence; no admin UI write; hidden setting.', 'Enabling this constant triggers an index hint in product search queries; disabling it lets the database optimizer choose the index freely.', 'Non-empty (truthy) enables the USE INDEX hint; empty or undefined uses the optimizer default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3242|check|if (getDolGlobalString(''MAIN_SEARCH_PRODUCT_FORCE_INDEX'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEARCH_PROJECT_USER_PROJECTSINDEX', 'string', NULL, 'projet', 'Sets the default user filter applied on the projects index and activity index pages.', 'The value is read directly into the $search_project_user variable at projet/index.php:56 and projet/activity/index.php:54, pre-populating the user search filter on those pages.', 'Setting this constant changes the default user scope for the project list and activity index pages.', 'String: a user identifier value used to pre-filter the project list. Empty = no default filter.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/index.php:56|read|$search_project_user = getDolGlobalString(''MAIN_SEARCH_PROJECT_USER_PROJECTSINDEX'');", "projet/activity/index.php:54|read|$search_project_user = getDolGlobalString(''MAIN_SEARCH_PROJECT_USER_PROJECTSINDEX'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ALLOW_TOTP', 'bool', NULL, 'user', 'Enables two-factor authentication (2FA/TOTP) support on user profile pages.', 'Checked in user/card.php at line 2099. Per the code comment: ''MAIN_SECURITY_ALLOW_TOTP=1 to enabled 2FA''. When set along with appropriate permissions, the TOTP setup section is displayed.', 'Setting this to 1 enables the TOTP/2FA configuration section on user profile pages; leaving it unset hides 2FA options.', 'MAIN_SECURITY_ALLOW_TOTP=1 to enabled 2FA', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/card.php:2005  // MAIN_SECURITY_ALLOW_TOTP=1 to enabled 2FA", "user/card.php:2099|check|if (getDolGlobalString(''MAIN_SECURITY_ALLOW_TOTP'') && $permissiontoeditpasswordandsee) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML', 'bool', NULL, 'barcode', 'Switches product/barcode label security filter from ''alphanohtml'' (strip all HTML) to ''restricthtml'' (allow basic HTML).', 'Comments at product/card.php:136 and core/class/extrafields.class.php:2964 state: ''by default alphanohtml (better security); hidden conf MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML allows basic html''. All three occurrences (barcode/printsheet.php:80, product/card.php:140, core/class/extrafields.class.php:2968) use a ternary to select the filter level.', 'Enabling this constant allows basic HTML markup in product and barcode labels; leaving it unset enforces the safer alphanohtml filter that strips all HTML.', 'Unset/0 = ''alphanohtml'' (no HTML allowed); non-empty = ''restricthtml'' (basic HTML allowed).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// by default ''alphanohtml'' (better security); hidden conf MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML allows basic html", "barcode/printsheet.php:80|read|$security_check = !getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML'') ? ''alphanohtml'' : ''restricthtml'';", "product/card.php:140|read|$label_security_check = !getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML'') ? ''alphanohtml'' : ''restricthtml'';", "core/class/extrafields.class.php:2968|read|$label_security_check = !getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_LABELS_WITH_HTML'') ? ''alphanohtml'' : ''restricthtml'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ALLOW_UNSECURED_REF_LABELS', 'bool', NULL, 'product', 'Relaxes input sanitisation for product reference and label fields, allowing characters that would otherwise be rejected.', 'Checked in product/class/product.class.php:972, :1401, and :936, as well as product/card.php:113 and :137, core/class/extrafields.class.php:2965, and barcode/printsheet.php:71 and :77. When set, the stricter validation path for product refs/labels is bypassed.', 'Enabling this constant weakens input validation on product reference and label fields; disabling enforces the default strict sanitisation.', 'Non-empty = unsecured refs/labels allowed; 0 or unset = strict sanitisation enforced.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/class/product.class.php:972|check|if (getDolGlobalInt(''MAIN_SECURITY_ALLOW_UNSECURED_REF_LABELS'')) {", "product/card.php:113|check|if (getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_REF_LABELS'')) {", "core/class/extrafields.class.php:2965|check|if (getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_REF_LABELS'')) {", "barcode/printsheet.php:71|check|if (getDolGlobalString(''MAIN_SECURITY_ALLOW_UNSECURED_REF_LABELS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ANTI_SSRF_SERVER_IP', 'string', NULL, 'core', 'Sets a comma-separated list of allowed server IP addresses for the anti-SSRF (Server-Side Request Forgery) filter on outbound HTTP requests.', 'Displayed in admin/system/security.php:817 and checked in core/lib/geturl.lib.php at lines 450 and 461 to allow or block outbound requests to specific IPs. The inline comment at line 30 documents: ''you can set MAIN_SECURITY_ANTI_SSRF_SERVER_IP to set static ip of server''.', 'When set, outbound HTTP requests are checked against this list: requests to IPs in the list are blocked or allowed depending on the SSRF filter logic. Misconfiguration can block legitimate requests or leave SSRF vulnerabilities open.', 'Comma-separated list of IP address strings; empty or unset disables the static IP override for the anti-SSRF filter.', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/geturl.lib.php:30  * - you can set MAIN_SECURITY_ANTI_SSRF_SERVER_IP to set static ip of server", "core/lib/geturl.lib.php:450|check|if (getDolGlobalString(''MAIN_SECURITY_ANTI_SSRF_SERVER_IP'') && in_array($iptocheck, explode('','', getDolGlobalString(''MAIN_SECURITY_ANTI_SSRF_SERVER_IP'')))) {", "core/lib/geturl.lib.php:461|check|if (getDolGlobalString(''MAIN_SECURITY_ANTI_SSRF_SERVER_IP'') && !in_array($iptocheck, explode('','', getDolGlobalString(''MAIN_SECURITY_ANTI_SSRF_SERVER_IP'')))) {", "admin/system/security.php:817|read|print ''<strong>MAIN_SECURITY_ANTI_SSRF_SERVER_IP</strong> = ''.getDolGlobalString(''MAIN_SECURITY_ANTI_SSRF_SERVER_IP'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefined\").''</s"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_CSRF_TOKEN_RENEWAL_ON_EACH_CALL', 'string', NULL, 'core', 'Controls whether the CSRF token is renewed on every page call instead of once per session.', 'When set to 1, a new CSRF token is generated on each page request rather than persisting for the full session. Referenced in main.inc.php:348 and documented in core/class/conf.class.php:1351.', 'Enabling this reduces the window for CSRF token replay attacks but is explicitly noted as not recommended; the comment at main.inc.php:349 warns it can cause issues if a user submits data from a cached page.', '0 or unset = renew token once per session (default); 1 = renew token on every page call (not recommended)', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:1351  // Note: Set MAIN_SECURITY_CSRF_TOKEN_RENEWAL_ON_EACH_CALL=1 to have a renewal of token at each page call instead of each session (not recommended)", "main.inc.php:349  // Note: Using MAIN_SECURITY_CSRF_TOKEN_RENEWAL_ON_EACH_CALL is not recommended: if a user succeed in entering a data from", "main.inc.php:348|check|if (!isset($_SESSION[''newtoken'']) || getDolGlobalInt(''MAIN_SECURITY_CSRF_TOKEN_RENEWAL_ON_EACH_CALL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_CSRF_WITH_TOKEN', 'string', NULL, 'core', 'Controls the level of CSRF token enforcement applied to form submissions and actions.', 'Checked in main.inc.php:362 to activate token validation on requests, with stricter enforcement at values >= 2 (main.inc.php:372) and >= 3 (main.inc.php:366 for mass actions). Managed via admin/system/security.php and admin/modules.php. Module enable/disable operations detect changes to this value.', 'Higher values enforce stricter CSRF checking; setting it to 0 or leaving it unset disables token-based CSRF protection.', 'Integer level: 0 or unset = disabled; 1 = basic token check; 2 = stricter check; 3 = also enforces token on mass actions.', 0, 0, 'admin/modules.php|admin/modules.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:362|check|if ((!defined(''NOCSRFCHECK'') && empty($dolibarr_nocsrfcheck) && getDolGlobalInt(''MAIN_SECURITY_CSRF_WITH_TOKEN'')) || defined(''CSRFCHECK_WITH_TOKEN'')) {", "main.inc.php:366|check|if ((GETPOSTISSET(''massaction'') || $tmpaction) && getDolGlobalInt(''MAIN_SECURITY_CSRF_WITH_TOKEN'') >= 3) {", "main.inc.php:372|read|} elseif (getDolGlobalInt(''MAIN_SECURITY_CSRF_WITH_TOKEN'') >= 2) {", "modulebuilder/template/myobject_agenda.php:32  //if (! defined(''NOTOKENRENEWAL''))           define(''NOTOKENRENEWAL'', ''1'');\t\t\t\t// Do not roll the Anti CSRF token (used if MAIN_SECURITY_CSRF_WITH_TOKEN is on)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_DISABLEFORGETPASSLINK', 'bool', NULL, 'admin', 'Disables the ''forgot password'' link on the Dolibarr login page.', 'Configurable via admin/security.php (write at line 152 to set ''1'', line 154 to delete). Checked at user/passwordforgotten.php line 51 (blocks access), admin/security.php lines 476, 480, 485, and core/lib/security2.lib.php lines 271-272 (controls link rendering).', 'Setting this constant hides and blocks the forgot-password link and page, preventing users from self-resetting their passwords. Clearing it restores the link.', '"1" = forgot-password link disabled; absent/deleted = forgot-password link enabled.', 0, 0, 'admin/security.php|admin/security.php|admin/security.php|admin/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security.php:152|write|dolibarr_set_const($db, \"MAIN_SECURITY_DISABLEFORGETPASSLINK\", ''1'', ''chaine'', 0, '''', $conf->entity);", "user/passwordforgotten.php:51|check|if (getDolGlobalString(''MAIN_SECURITY_DISABLEFORGETPASSLINK'')) {", "core/lib/security2.lib.php:271|check|if (!getDolGlobalString(''MAIN_SECURITY_DISABLEFORGETPASSLINK'') || getDolGlobalString(''MAIN_HELPCENTER_LINKTOUSE'')) {", "core/lib/security2.lib.php:272|check|if (!getDolGlobalString(''MAIN_SECURITY_DISABLEFORGETPASSLINK'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA', 'bool', NULL, 'admin', 'Enables CAPTCHA verification on the Dolibarr login form and other public-facing forms.', 'When set to a truthy value, CAPTCHA challenges are activated for login and other public forms. Managed via admin/security_captcha.php and reported in admin/system/security.php:507-508.', 'Enabling this adds bot-protection to the login process; disabling it removes the CAPTCHA challenge, making forms accessible without solving a CAPTCHA.', '0 or unset = CAPTCHA disabled; 1 (truthy) = CAPTCHA enabled', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_captcha.php:230|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA'')) {", "main.inc.php:591|check|if ($test && GETPOST(''actionlogin'', ''aZ09'') == ''login'' && GETPOST(\"username\", \"alpha\", 2) && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA'') && !isset($_SESSION[''dol_bypass_antis", "admin/system/security.php:508|read|print yn(!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA'') ? 0 : 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_DONATION', 'bool', NULL, 'public', 'Enables CAPTCHA verification on the public donation submission form.', 'Checked in admin/security_captcha.php and public/donations/new.php at multiple points including form load and submission validation.', 'Enabling requires CAPTCHA on the public donation form, preventing automated submissions.', 'Truthy value to enable CAPTCHA; absent or falsy to disable.', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_captcha.php:242|check|if (isModEnabled(''don'') && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_DONATION'')) {", "public/donations/new.php:109|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_DONATION'')) {", "public/donations/new.php:225|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_DONATION'') && is_object($captchaobj)) {", "public/donations/new.php:564|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_DONATION'') && is_object($captchaobj)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_HANDLER', 'bool', NULL, 'public', 'Specifies the CAPTCHA handler/plugin to use when CAPTCHA is enabled.', 'Selects which CAPTCHA implementation is used across login (main.inc.php:596), ticket creation (public/ticket/create_ticket.php:117), donations (public/donations/new.php:111), membership (public/members/new.php:116), and recruitment (public/recruitment/view.php:117). Written via admin/security_captcha.php:74.', 'Changing this value switches the CAPTCHA provider used on all public-facing forms; if the named handler is unavailable, CAPTCHA rendering will fail.', '''standard'' (default if unset); any installed CAPTCHA handler identifier (e.g. ''standard'')', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_captcha.php:74|write|if (!dolibarr_set_const($db, ''MAIN_SECURITY_ENABLECAPTCHA_HANDLER'', GETPOST(\"value\", \"aZ09\"), ''chaine'', 0, '''', $conf->entity)) {", "admin/security_captcha.php:246|read|$selectedcaptcha = getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_HANDLER'', ''standard'');", "main.inc.php:596|read|$captcha = getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_HANDLER'', ''standard'');", "core/class/html.formticket.class.php:801|read|$captcha = getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_HANDLER'', ''standard'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_MEMBER', 'bool', NULL, 'admin', 'Enables CAPTCHA verification on the public member self-registration form.', 'Checked in admin/security_captcha.php and public/members/new.php at multiple points. Displayed in admin/system/security.php as a security indicator.', 'Enabling requires CAPTCHA on the public member registration form, reducing automated member creation.', 'Truthy value to enable CAPTCHA; absent or falsy to disable.', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_captcha.php:239|check|if (isModEnabled(''member'') && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_MEMBER'')) {", "public/members/new.php:114|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_MEMBER'')) {", "public/members/new.php:388|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_MEMBER'') && is_object($captchaobj)) {", "admin/system/security.php:526|read|print yn(!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_MEMBER'') ? 0 : 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_RECRUITMENT', 'bool', NULL, 'public', 'Enables CAPTCHA verification on the public recruitment application form.', 'Checked in admin/security_captcha.php and public/recruitment/view.php at form load and submission points.', 'Enabling requires CAPTCHA on the public recruitment view, reducing automated job application submissions.', 'Truthy value to enable CAPTCHA; absent or falsy to disable.', 0, 0, 'admin/security_captcha.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_captcha.php:216|check|if (!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_RECRUITMENT'')) {", "public/recruitment/view.php:115|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_RECRUITMENT'')) {", "public/recruitment/view.php:186|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_RECRUITMENT'') && is_object($captchaobj)) {", "public/recruitment/view.php:501|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_RECRUITMENT'') && is_object($captchaobj)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_THIRDPARTY', 'bool', NULL, 'admin', 'Enables CAPTCHA verification on the public third-party (company) self-registration form.', 'Checked in admin/security_captcha.php and public/company/new.php. When enabled and the societe module is active, CAPTCHA is required on the public company creation page.', 'Enabling adds CAPTCHA to the public company registration form, reducing automated spam submissions.', 'Truthy value to enable CAPTCHA; absent or falsy to disable.', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_captcha.php:233|check|if (isModEnabled(''societe'') && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRDPARTY'')) {", "public/company/new.php:186|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRDPARTY'')) {", "public/company/new.php:435|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRDPARTY'')) {", "admin/security_captcha.php:160|check|if (!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRDPARTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_THIRPARTY', 'bool', NULL, 'admin', 'Enables CAPTCHA verification on the third-party (contact/company) public forms.', 'Read in admin/system/security.php:519-520 to display the current CAPTCHA status for third-party forms as a tick icon and yes/no label.', 'When enabled, public third-party forms require CAPTCHA completion; when disabled no CAPTCHA is shown.', 'Bool-like string: empty/unset = CAPTCHA disabled; non-empty = CAPTCHA enabled.', 0, 0, 'admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/system/security.php:519|read|print !getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRPARTY'') ? '''' : img_picto('''', ''tick'').'' '';", "admin/system/security.php:520|read|print yn(!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_THIRPARTY'') ? 0 : 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLECAPTCHA_TICKET', 'bool', NULL, 'admin', 'Enables CAPTCHA verification on the public ticket creation form.', 'Checked in admin/security_captcha.php, admin/ticket_public.php, core/class/html.formticket.class.php, and public/ticket/create_ticket.php. Displayed in admin/system/security.php as a security status indicator.', 'Enabling requires CAPTCHA completion on the public ticket submission form, preventing automated ticket spam.', 'Truthy value to enable CAPTCHA; absent or falsy to disable.', 0, 0, 'admin/security_captcha.php|admin/security_captcha.php|admin/ticket_public.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_captcha.php:236|check|if (isModEnabled(''ticket'') && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_TICKET'')) {", "core/class/html.formticket.class.php:797|check|if ($public && getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_TICKET'')) {", "public/ticket/create_ticket.php:115|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_TICKET'')) {", "admin/system/security.php:514|read|print yn(!getDolGlobalString(''MAIN_SECURITY_ENABLECAPTCHA_TICKET'') ? 0 : 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_ENABLE_SENDPASSWORD', 'bool', NULL, 'user', 'Controls whether the ''send password by email'' feature is available on the forgotten-password page.', 'When set, the forgotten-password page at user/passwordforgotten.php:256 enables the option to send the user''s password via email. Without it the send-password path is skipped entirely.', 'Enabling this constant allows passwords to be emailed to users; disabling it (or leaving unset) hides that option on the forgotten-password page.', 'Empty/unset = feature disabled; any truthy value = feature enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/passwordforgotten.php:256|check|if (getDolGlobalString(''MAIN_SECURITY_ENABLE_SENDPASSWORD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCECSP', 'string', NULL, 'admin', 'Stores the Content-Security-Policy header value to be sent on every response.', 'Written via admin/security_headers_http.php (lines 132, 205, 236) and read into $contentsecuritypolicy at main.inc.php:1600. Comments in template files show that setting it to ''none'' disables all Content Security Policies.', 'Setting this causes Dolibarr to emit an enforced Content-Security-Policy header, restricting which resources browsers may load.', 'Any valid CSP directive string; ''none'' = disable all Content Security Policies; empty/unset = header not sent', 0, 0, 'admin/security_headers_http.php|admin/security_headers_http.php|admin/system/security.php|admin/security_headers_http.php|admin/security_headers_http.php|admin/security_headers_http.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["//if (! defined(''MAIN_SECURITY_FORCECSP''))   define(''MAIN_SECURITY_FORCECSP'', ''none'');\t\t\t\t// Disable all Content Security Policies", "admin/security_headers_http.php:132|write|$res = dolibarr_set_const($db, ''MAIN_SECURITY_FORCECSP'', $securitycspstring, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1600|read|$contentsecuritypolicy = getDolGlobalString(''MAIN_SECURITY_FORCECSP'');", "admin/security_headers_http.php:50|read|$forceCSP = getDolGlobalString(\"MAIN_SECURITY_FORCECSP\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCECSPRO', 'string', NULL, 'admin', 'Stores the Content-Security-Policy-Report-Only header value to be sent on every response.', 'Written via admin/security_headers_http.php:237 and read into $contentsecuritypolicy at main.inc.php:1560. Displayed in admin/system/security.php:689 and the headers admin page at :399.', 'Setting this causes Dolibarr to emit a Content-Security-Policy-Report-Only header, enabling CSP violation reporting without enforcement.', 'Any valid CSP directive string; empty/unset = header not sent', 0, 0, 'admin/security_headers_http.php|admin/security_headers_http.php|admin/system/security.php|admin/system/security.php|admin/security_headers_http.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_headers_http.php:237|write|$res5 = dolibarr_set_const($db, ''MAIN_SECURITY_FORCECSPRO'', $securitycspro, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1560|read|$contentsecuritypolicy = getDolGlobalString(''MAIN_SECURITY_FORCECSPRO'');", "admin/security_headers_http.php:396|check|if (getDolGlobalString(\"MAIN_SECURITY_FORCECSPRO\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCEPP', 'string', NULL, 'admin', 'Stores the Permissions-Policy HTTP header value to be sent on every response.', 'Written via admin/security_headers_http.php:235 and read at main.inc.php:1651 with an empty default. Displayed in the security summary at admin/system/security.php:684.', 'Setting this causes Dolibarr to emit a Permissions-Policy header, controlling which browser features and APIs are available to the page.', 'Any valid Permissions-Policy directive string; empty/unset = header not sent', 0, 0, 'admin/security_headers_http.php|admin/system/security.php|admin/security_headers_http.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_headers_http.php:235|write|$res3 = dolibarr_set_const($db, ''MAIN_SECURITY_FORCEPP'', $securitypp, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1651|read|$pp = getDolGlobalString(''MAIN_SECURITY_FORCEPP'', \"\");", "admin/system/security.php:684|read|print ''<strong>MAIN_SECURITY_FORCEPP</strong> = ''.getDolGlobalString(''MAIN_SECURITY_FORCEPP'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefined\").''</span>'').'' &nbsp; <span cl"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCERP', 'string', NULL, 'admin', 'Stores the Referrer-Policy HTTP header value to be sent on every response.', 'Written via admin/security_headers_http.php:233 and read at main.inc.php:1631 with a default of ''same-origin''. Displayed in the security summary at admin/system/security.php:678.', 'Changing this value alters the Referrer-Policy header sent to browsers, affecting how much referrer information is included in requests originating from Dolibarr pages.', 'Any valid Referrer-Policy directive string (e.g. ''same-origin'', ''no-referrer''); empty/unset = defaults to ''same-origin''', 0, 0, 'admin/security_headers_http.php|admin/system/security.php|admin/security_headers_http.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_headers_http.php:233|write|$res1 = dolibarr_set_const($db, ''MAIN_SECURITY_FORCERP'', $securityrp, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1631|read|$referrerpolicy = getDolGlobalString(''MAIN_SECURITY_FORCERP'', \"same-origin\");", "admin/system/security.php:678|read|print ''<strong>MAIN_SECURITY_FORCERP</strong> = ''.getDolGlobalString(''MAIN_SECURITY_FORCERP'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefined\").''</span>'').'' &nbsp; <span cl"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCESTS', 'string', NULL, 'admin', 'Stores the Strict-Transport-Security (HSTS) HTTP header value to be sent on every response.', 'Written via admin/security_headers_http.php:234 and read at main.inc.php:1641 with an empty default. Displayed in the security summary at admin/system/security.php:681.', 'Setting this causes Dolibarr to emit an HSTS header, instructing browsers to only access the site over HTTPS for the declared duration.', 'Any valid Strict-Transport-Security directive string (e.g. ''max-age=31536000''); empty/unset = header not sent', 0, 0, 'admin/security_headers_http.php|admin/system/security.php|admin/security_headers_http.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_headers_http.php:234|write|$res2 = dolibarr_set_const($db, ''MAIN_SECURITY_FORCESTS'', $securitysts, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1641|read|$sts = getDolGlobalString(''MAIN_SECURITY_FORCESTS'', \"\");", "admin/system/security.php:681|read|print ''<strong>MAIN_SECURITY_FORCESTS</strong> = ''.getDolGlobalString(''MAIN_SECURITY_FORCESTS'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefined\").''</span>'').'' &nbsp; <span "]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_FORCE_ACCESS_CONTROL_ALLOW_ORIGIN', 'bool', NULL, 'core', 'Controls whether Dolibarr sends a forced Access-Control-Allow-Origin HTTP header.', 'Checked at main.inc.php:1536 to conditionally emit the CORS header. Displayed in the security summary at admin/system/security.php:699.', 'Enabling this sends an Access-Control-Allow-Origin header on responses, which affects cross-origin resource sharing behavior for browser clients.', '0 or unset = header not forced; any truthy value = Access-Control-Allow-Origin header is emitted', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1536|check|if (getDolGlobalString(''MAIN_SECURITY_FORCE_ACCESS_CONTROL_ALLOW_ORIGIN'')) {", "admin/system/security.php:699|read|print ''<strong>MAIN_SECURITY_FORCE_ACCESS_CONTROL_ALLOW_ORIGIN</strong> = ''.getDolGlobalString(''MAIN_SECURITY_FORCE_ACCESS_CONTROL_ALLOW_ORIGIN'', ''<span class=\"opacitymedium\">''.$la"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_HASH_ALGO', 'string', NULL, 'core', 'Specifies the hashing algorithm used for password storage; recommended value is ''password_hash''.', 'Displayed and checked in admin/system/security.php:838-848 and used in core/lib/security.lib.php:274 and :368. COMMENTS confirm: ''If constant MAIN_SECURITY_HASH_ALGO is defined, we use this function as hashing function (recommended value is "password_hash")'' and the auto/0 type falls back to this constant or md5.', 'Setting this to ''password_hash'' enables PHP''s native password_hash/password_verify functions for secure password storage; if unset or set to ''md5'', passwords are hashed with MD5.', '''password_hash'' = use PHP password_hash/password_verify; ''md5'' or empty = use MD5 hashing', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/security.lib.php:253  *  If constant MAIN_SECURITY_HASH_ALGO is defined, we use this function as hashing function (recommended value is ''password_hash'')", "core/lib/security.lib.php:258  *                                                                                                                          ''auto'' or ''0'': will use MAIN_SECURITY_HASH_ALGO else md5", "admin/system/security.php:842|check|if (getDolGlobalString(''MAIN_SECURITY_HASH_ALGO'') != ''password_hash'') {", "adherents/class/adherent.class.php:3069|check|if (!getDolGlobalString(''MAIN_SECURITY_HASH_ALGO'') || getDolGlobalString(''MAIN_SECURITY_HASH_ALGO'') == ''md5'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_MAXFILESIZE_DOWNLOADED', 'string', NULL, 'admin', 'Sets the maximum file size (in bytes) allowed for file downloads.', 'Configured via admin/security_file.php:108 and read at webportal/controllers/document.controller.class.php:267, core/lib/geturl.lib.php:163, and webportal/controllers/viewimage.controller.class.php:278 as ''$fileSizeMax = getDolGlobalInt(''MAIN_SECURITY_MAXFILESIZE_DOWNLOADED'')''. Also displayed in admin/system/security.php:638.', 'Setting a positive integer limits file downloads to that size in bytes; setting to 0 or leaving empty disables the size check.', '0 or not set = no file size limit enforced; positive integer = maximum allowed download size in bytes.', 0, 0, 'admin/security_file.php|admin/system/security.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/controllers/document.controller.class.php:267|read|$fileSizeMax = getDolGlobalInt(''MAIN_SECURITY_MAXFILESIZE_DOWNLOADED'');", "core/lib/geturl.lib.php:163|read|$maxsize = getDolGlobalInt(''MAIN_SECURITY_MAXFILESIZE_DOWNLOADED'');", "admin/security_file.php:108|write|$res8 = dolibarr_set_const($db, \"MAIN_SECURITY_MAXFILESIZE_DOWNLOADED\", GETPOST(''MAIN_SECURITY_MAXFILESIZE_DOWNLOADED'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/system/security.php:638|read|print ''<strong>''.$langs->trans(\"MAIN_SECURITY_MAXFILESIZE_DOWNLOADED\").''</strong> = ''.getDolGlobalString(''MAIN_SECURITY_MAXFILESIZE_DOWNLOADED'',"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS', 'string', NULL, 'admin', 'Maximum number of file attachments permitted per form submission.', 'Written via admin/security_other.php:92 and displayed at line 204 and admin/system/security.php:552. Enforced in core/lib/files.lib.php:2029 where it is read with a fallback default of 10 into $maxfilesinform.', 'Lowering this value restricts the number of files a user can attach to a single form; raising it allows more attachments, defaulting to 10 if unset.', 'Integer count of attachments per form. Default fallback is 10.', 0, 0, 'admin/security_other.php|admin/system/security.php|admin/security_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_other.php:92|write|$res5 = dolibarr_set_const($db, \"MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS\", GETPOST(\"MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS\", ''alphanohtml''), ''int'', 0, '''', $conf->entity);", "core/lib/files.lib.php:2029|read|$maxfilesinform = getDolGlobalInt(\"MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS\", 10);", "admin/security_other.php:204|read|print ''<input class=\"flat right width50\" name=\"MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS\" type=\"text\" value=\"''.getDolGlobalInt(\"MAIN_SECURITY_MAX_ATTACHMENT_ON_FORMS\", 10).''\">''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT', 'string', NULL, 'admin', 'Maximum number of images permitted in HTML content before the content is rejected for security reasons.', 'Written via admin/security_other.php:86, displayed in the security admin UI at line 188 and admin/system/security.php:544. Enforced in core/lib/functions.lib.php:9816 where $nblinks is compared against this constant with a fallback default of 1000.', 'Lowering this value restricts how many images can appear in user-submitted HTML, reducing the attack surface for image-based injection; raising it or leaving it unset allows up to 1000 images by default.', 'Integer count of images. Default fallback is 1000. 0 = no images allowed.', 0, 0, 'admin/security_other.php|admin/system/security.php|admin/security_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_other.php:86|write|$res3 = dolibarr_set_const($db, \"MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT\", GETPOST(\"MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT\", ''alphanohtml''), ''int'', 0, '''', $conf->entity);", "core/lib/functions.lib.php:9816|check|if ($nblinks > getDolGlobalInt(\"MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT\", 1000)) {", "admin/security_other.php:188|read|print ''<input class=\"flat right width50\" name=\"MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT\" type=\"text\" value=\"''.getDolGlobalInt(''MAIN_SECURITY_MAX_IMG_IN_HTML_CONTENT'').''\">''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH', 'string', NULL, 'admin', 'Sets the maximum number of consecutive failed authentication attempts before a login is blocked.', 'Written via admin/security_other.php:95 and read at line 212 with a default of 100. Checked in core/login/functions_dolibarr.php:73: if ($nbevents <= getDolGlobalInt(''MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH'', 100)).', 'Lowering this value makes the brute-force lockout trigger sooner. Raising it allows more failed attempts before blocking. If unset, the default of 100 applies.', 'Integer. Default: 100 when unset.', 0, 0, 'admin/security_other.php|admin/security_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/login/functions_dolibarr.php:73|check|if ($nbevents <= getDolGlobalInt(\"MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH\", 100)) {", "admin/security_other.php:95|write|$res6 = dolibarr_set_const($db, \"MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH\", GETPOST(\"MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH\", ''alphanohtml''), ''int'', 0, '''', $conf->entity);", "admin/security_other.php:212|read|print ''<input class=\"flat right width50\" name=\"MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH\" type=\"text\" value=\"''.getDolGlobalInt(\"MAIN_SECURITY_MAX_NUMBER_FAILED_AUTH\", 100).''\">''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS', 'string', NULL, 'public', 'Maximum number of POST requests allowed per IP address on public-facing pages before the request is blocked.', 'Written via admin/security_other.php:89 and displayed at line 196 and admin/system/security.php:548. Read with a fallback default of 200 across multiple public pages: public/recruitment/view.php:233, public/eventorganization/attendee_new.php:325, public/company/new.php:222, public/opensurvey/studs.php:110/166. The COMMENTS note its purpose: ''Test MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS''.', 'Lowering this value tightens rate-limiting on public forms, reducing abuse risk; raising it or leaving unset defaults to 200 allowed POSTs per IP.', 'Integer count of POST requests per IP. Default fallback is 200.', 0, 0, 'admin/security_other.php|admin/system/security.php|admin/security_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["// Test MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS", "admin/security_other.php:89|write|$res4 = dolibarr_set_const($db, \"MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS\", ...)", "public/recruitment/view.php:233|read|$nb_post_max = getDolGlobalInt(\"MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS\", 200);", "public/eventorganization/attendee_new.php:325|read|$nb_post_max = getDolGlobalInt(\"MAIN_SECURITY_MAX_POST_ON_PUBLIC_PAGES_BY_IP_ADDRESS\", 200);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_SALT', 'string', NULL, 'core', 'A cryptographic salt string prepended to passwords before hashing when the hashing algorithm is not ''password_hash''.', 'Set during installation via install/step5.php:281 to a random value. Read in core/lib/security.lib.php:292-293: if defined and hash type is not ''4'' or ''openldap'' and nosalt is not set, the salt is prepended to the chain before hashing. Comments state: ''It creates the login admin and set the MAIN_SECURITY_SALT to a random value'' and ''If constant MAIN_SECURITY_SALT is defined, we use it as a salt (used only if hashing algorithm is something else than "password_hash")''.', 'Changing or removing this salt after users are created will invalidate all existing password hashes, locking out all users.', 'Any non-empty string used as a password salt. Set automatically during installation.', 0, 0, 'admin/system/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/security.lib.php:254  *  If constant MAIN_SECURITY_SALT is defined, we use it as a salt (used only if hashing algorithm is something else than ''password_hash'').", "core/lib/security.lib.php:292|check|if (getDolGlobalString(''MAIN_SECURITY_SALT'') && $type != ''4'' && $type !== ''openldap'' && empty($nosalt)) {", "core/lib/security.lib.php:293|read|$chain = getDolGlobalString(''MAIN_SECURITY_SALT'') . $chain;", "install/step5.php:31  *         It creates the login admin and set the MAIN_SECURITY_SALT to a random value."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_SHOW_MORE_INFO', 'bool', NULL, 'admin', 'Enables display of additional security information on the security administration page.', 'Checked in admin/system/security.php:151 to conditionally render extra security details in the admin UI.', 'When set, additional security diagnostic information is shown on the security admin page.', 'Bool-like string: empty/unset = extra info hidden; non-empty = extra info shown.', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/system/security.php:151|check|if (getDolGlobalString(''MAIN_SECURITY_SHOW_MORE_INFO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_USE_DEFAULT_PERMISSIONS', 'bool', NULL, 'core', 'Grants a default set of permissions to users when this constant is enabled.', 'Checked once in core/lib/admin.lib.php at line 935. No admin UI write is present in the payload; only one occurrence found.', 'Enabling this causes default permissions to be applied; exact permission set depends on the surrounding code block in admin.lib.php.', 'Truthy (non-empty) = default permissions applied; empty/unset = no default permissions.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/admin.lib.php:935|check|if (getDolGlobalString(''MAIN_SECURITY_USE_DEFAULT_PERMISSIONS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SECURITY_USE_SANDBOX_FOR_HTMLWITHNOJS', 'bool', NULL, 'core', 'Enables sandbox iframe wrapping for HTML content rendered without JavaScript (not yet working per comments).', 'Checked at core/lib/functions.lib.php:9570. The function parameter comment at line 9564 states ''1=Allow use of option MAIN_SECURITY_USE_SANDBOX_FOR_HTMLWITHNOJS for html sanitizing (not yet working)''. The constant is only consulted when $nouseofiframesandbox is 0.', 'Setting this constant has no confirmed production effect as the feature is marked not yet working in the code comments.', '0 or empty = sandbox not used; any truthy value = sandbox iframe attempted for HTML-without-JS content (not yet working)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:9564  * @param\tint     $nouseofiframesandbox\t\t0=Default, 1=Allow use of option MAIN_SECURITY_USE_SANDBOX_FOR_HTMLWITHNOJS for html sanitizing (not yet working)", "core/lib/functions.lib.php:9570|check|if (empty($nouseofiframesandbox) && getDolGlobalString(''MAIN_SECURITY_USE_SANDBOX_FOR_HTMLWITHNOJS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SEE_SUBORDINATES', 'string', NULL, 'core', 'Allows a manager to see records (interventions, orders, etc.) belonging to their subordinate users.', 'Checked across 7 occurrences in fichinter/list.php:73 and 362, core/lib/security.lib.php:1108 and 1219, core/class/commonobject.class.php:2609, and commande/list.php:86 and 1027. When enabled and $userschilds is populated, subordinates'' records are included in lists.', 'Enabling this constant expands list views so managers see records assigned to users below them in the hierarchy, in addition to their own.', 'Boolean/truthy: non-empty enables subordinate visibility.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalInt(''MAIN_SEE_SUBORDINATES'')) {", "if (getDolGlobalInt(''MAIN_SEE_SUBORDINATES'') && $userschilds) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SERVER_TZ', 'string', NULL, 'admin', 'Stores the server timezone identifier used by Dolibarr for date/time operations.', 'Displayed in admin/system/dolibarr.php:326 as a system information label. A commented example in core/class/conf.class.php:682 shows the expected format: //$this->global->MAIN_SERVER_TZ=''Europe/Paris'';', 'If not defined, the timezone is reported as ''NotDefined'' in the system information page.', 'String: a valid PHP timezone identifier, e.g. ''Europe/Paris''.', 0, 0, 'admin/system/dolibarr.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/system/dolibarr.php:326|read|$txt .= $langs->trans(\"Dolibarr constant MAIN_SERVER_TZ\").'': ''.getDolGlobalString(''MAIN_SERVER_TZ'', $langs->trans(\"NotDefined\"));", "core/class/conf.class.php:682  //$this->global->MAIN_SERVER_TZ=''Europe/Paris'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SESSION_TIMEOUT', 'string', NULL, 'admin', 'Sets the user session timeout duration in seconds for the Dolibarr application.', 'Configurable via admin/security_other.php (write at lines 83, 168, 180) and admin/system/security.php (write at line 532, display at line 540). Enforced at admin/security_other.php line 83 with bounds: max(120, min(3600*24, value)). Also applied in public/webportal/webportal.main.inc.php line 228.', 'Changing this value alters how long inactive sessions remain valid; the minimum enforced value is 120 seconds and the maximum is 86400 seconds (24 hours).', 'Integer (seconds); minimum 120, maximum 86400. From admin/security_other.php:83: dolibarr_set_const($db, "MAIN_SESSION_TIMEOUT", max(120, min(3600 * 24, GETPOSTINT("MAIN_SESSION_TIMEOUT"))), ''chaine'', 0, '''', $conf->entity);', 0, 0, 'admin/security_other.php|admin/security_other.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/security_other.php|admin/security_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security_other.php:83|write|$res2 = dolibarr_set_const($db, \"MAIN_SESSION_TIMEOUT\", max(120, min(3600 * 24, GETPOSTINT(\"MAIN_SESSION_TIMEOUT\"))), ''chaine'', 0, '''', $conf->entity);\t// Between 120 and 86400", "admin/security_other.php:180|read|print ''<input class=\"flat right width75\" name=\"MAIN_SESSION_TIMEOUT\" type=\"text\" value=\"''.getDolGlobalInt(''MAIN_SESSION_TIMEOUT'').''\">.strtolower($langs->trans(\"Seconds\"));", "admin/system/security.php:540|read|print '': ''.getDolGlobalInt(''MAIN_SESSION_TIMEOUT'').'' ''.strtolower($langs->trans(\"Seconds\"));", "public/webportal/webportal.main.inc.php:228|check|if (getDolGlobalString(''MAIN_SESSION_TIMEOUT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SETUP_MODULES_DESC', 'string', NULL, 'admin', 'Enables display of a descriptive help section on the modules setup page when fewer than the minimum required modules are enabled.', 'Read at admin/modules.php:727 in combination with MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING. The inline comment clarifies: ''If only minimal initial modules enabled''. When set, the description/help section is shown.', 'Enabling this constant forces the descriptive section to appear on the modules list regardless of how many modules are active.', '0 or unset = description shown only based on module count threshold; non-zero = description always shown', 0, 0, 'admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:727|check|if (getDolGlobalInt(''MAIN_SETUP_MODULES_DESC'') || $nbmodulesnotautoenabled < getDolGlobalInt(''MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING'', 1)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SETUP_MODULES_INFO', 'string', NULL, 'admin', 'Defines a translation key for a custom informational message displayed on the modules setup page.', 'Read in admin/modules.php:730-731. The code comment states: ''Add a custom info message. A good usage for SaaS in combination with option MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING.'' The value is passed through $langs->trans() to produce the rendered message.', 'Setting this to a valid translation key causes a custom info banner to appear on the modules admin page, useful for SaaS deployments to guide users.', 'A translation key string whose translated value is shown as an info message; empty or unset = no custom message', 0, 0, 'admin/modules.php|admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:730|check|if (getDolGlobalString(''MAIN_SETUP_MODULES_INFO'')) {  // Add a custom info message. A good usage for SaaS in combination with option MAIN_MIN_NB_ENABLED_MODULE_FOR_WARNING.", "admin/modules.php:731|read|$deschelp .= ''<div class=\"info\">''.$langs->trans(getDolGlobalString(''MAIN_SETUP_MODULES_INFO'')).\"<br></div>\\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOWDATABASENAMEINHELPPAGESLINK', 'bool', NULL, 'core', 'Appends the database name to help page links for easier debugging or support.', 'Checked at main.inc.php:2368 to conditionally include the database name in help links.', 'Enabling this adds the database name to help URLs, which can assist support staff in identifying the instance.', '0 or unset = database name not shown in help links; 1 (truthy) = database name appended', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2368|check|if (getDolGlobalString(''MAIN_SHOWDATABASENAMEINHELPPAGESLINK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_ALL_FILES_ON_DOCUMENT_TOOLTIP', 'bool', NULL, 'webportal', 'When enabled, forces document tooltips to display all attached files rather than only a subset.', 'Checked in core/class/html.formfile.class.php:1182 and webportal/class/html.formwebportal.class.php:248. When the flag $allfiles is false, this constant can override it to show all files.', 'Enabling this constant causes all files to be included in document tooltips across the standard UI and the web portal.', 'Truthy (non-empty) to show all files; empty/unset to respect the default $allfiles flag.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/html.formwebportal.class.php:248|check|if ($allfiles || getDolGlobalString(''MAIN_SHOW_ALL_FILES_ON_DOCUMENT_TOOLTIP'')) {", "core/class/html.formfile.class.php:1182|check|if ($allfiles || getDolGlobalString(''MAIN_SHOW_ALL_FILES_ON_DOCUMENT_TOOLTIP'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_COMPANY_NAME_IN_BANNER_ADDRESS', 'bool', NULL, 'core', 'Shows the company name in the address banner for contact objects.', 'Checked in core/class/commonpeople.class.php:196. When set and the current element is a contact, the associated company name is included in the banner address block.', 'Setting this constant adds the company name to the contact''s address banner display.', 'Non-empty = company name shown in banner; empty or unset = not shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonpeople.class.php:196|check|if ($this->element == ''contact'' && getDolGlobalString(''MAIN_SHOW_COMPANY_NAME_IN_BANNER_ADDRESS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_ECOTAX_DICTIONNARY', 'bool', NULL, 'admin', 'Forces the ecotax dictionary entry to appear in the admin dictionary list even when the ecotax module is not enabled.', 'Read at admin/dict.php:567 where the ecotax dictionary visibility condition is: product module enabled AND (ecotax module enabled OR this constant is set). Configurable via admin/dict.php.', 'Setting this constant makes the ecotax dictionary visible without enabling the full ecotax module; leaving it unset requires the ecotax module to be active.', 'Empty/unset = ecotax dict shown only if ecotax module enabled; any truthy value = ecotax dict always shown when product module is enabled.', 0, 0, 'admin/dict.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/dict.php:567|read|$tabcond[DICT_ECOTAXE] = (isModEnabled(\"product\") && (isModEnabled(''ecotax'') || getDolGlobalString(''MAIN_SHOW_ECOTAX_DICTIONNARY'')));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_EXTREF', 'bool', NULL, 'compta', 'Enables display of the external reference field on the cheque deposit card.', 'Checked in compta/paiement/cheque/card.php:668. When set, additional UI output for the external reference is rendered.', 'Setting this constant adds the external reference field to the cheque deposit card view; leaving it unset hides that field.', 'Any non-empty value = show external reference field; empty/unset = hide it', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolGlobalString(''MAIN_SHOW_EXTREF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_FACNUMBER_IN_DISCOUNT_LIST', 'bool', NULL, 'core', 'Displays the source invoice number alongside discounts in the discount selection list.', 'In core/class/html.form.class.php, when this constant is set and the discount has a fk_facture_source, the source invoice number is appended to the discount label. Only one occurrence; no admin UI write; hidden setting.', 'Enabling this constant adds the originating invoice reference to each discount entry in the selector; disabling it shows discounts without that reference.', 'Non-empty (truthy) shows invoice number in discount list; empty or undefined hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:2150|check|if (getDolGlobalString(''MAIN_SHOW_FACNUMBER_IN_DISCOUNT_LIST'') && !empty($obj->fk_facture_source)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_GLOBAL_REF_CUSTOMER_SUPPLIER', 'bool', NULL, 'compta', 'Controls the CSS width class applied to the customer/supplier reference column on the invoice list.', 'Read in compta/facture/list.php at line 2482. When set to a non-zero integer, a wider CSS class (''minwidth400 maxwidth400'') is applied; otherwise a narrower nowrap class is used.', 'Enabling this constant widens the customer/supplier reference column on the invoice list, allowing longer reference strings to display without truncation.', '0 or unset = narrow column (nowrap tdoverflowmax200); 1 = wider column (minwidth400 maxwidth400)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$tdcss = (getDolGlobalInt(''MAIN_SHOW_GLOBAL_REF_CUSTOMER_SUPPLIER'') ? ''class=\"minwidth400 maxwidth400\"'' : ''class=\"nowrap tdoverflowmax200\"'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_HT_ON_SUMMARY', 'bool', NULL, 'core', 'Shows pre-tax (HT) amounts in addition to tax-inclusive amounts on the accounting summary dashboard.', 'Checked at 19 points in compta/index.php (e.g., lines 186, 258, 285, 335, 388, 416, 676, 736) to conditionally render HT columns or rows alongside standard totals. No admin UI is provided.', 'Enabling this constant adds pre-tax amount columns to the accounting summary dashboard, providing visibility into amounts before tax.', 'Non-empty/truthy = HT amounts shown on summary; empty/unset = only tax-inclusive amounts shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/index.php:186|check|if (getDolGlobalString(''MAIN_SHOW_HT_ON_SUMMARY'')) {", "compta/index.php:258|check|if (getDolGlobalString(''MAIN_SHOW_HT_ON_SUMMARY'')) {", "compta/index.php:285|check|if (getDolGlobalString(''MAIN_SHOW_HT_ON_SUMMARY'')) {", "compta/index.php:335|check|if (getDolGlobalString(''MAIN_SHOW_HT_ON_SUMMARY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_INFO_ON_LINKED_ELEMENTS_OF_SITUATION_INVOICE', 'bool', NULL, 'core', 'Enables display of information about linked elements on situation invoice PDFs.', 'Read at two points in pdf_octopus.modules.php (lines 3426 and 3786) to conditionally render linked-element information sections. No admin UI write is present.', 'Enabling this causes linked-element info blocks to appear in situation invoice PDFs; disabling suppresses those blocks.', 'Truthy (non-empty) = linked-element info shown; empty/unset = info hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_octopus.modules.php:3426|check|if (getDolGlobalString(''MAIN_SHOW_INFO_ON_LINKED_ELEMENTS_OF_SITUATION_INVOICE'')) {", "pdf_octopus.modules.php:3786|check|if (getDolGlobalString(''MAIN_SHOW_INFO_ON_LINKED_ELEMENTS_OF_SITUATION_INVOICE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_LANGUAGE_CODE', 'bool', NULL, 'core', 'Displays language codes instead of (or alongside) language names in language selection UI elements when enabled.', 'Checked in core/class/translate.class.php:954 as an alternative condition to usecode==1 for displaying language codes. No admin UI write is present.', 'When enabled, language codes are shown in language selectors; when unset, language names are displayed unless the usecode parameter is set programmatically.', 'Truthy value (e.g. 1) to show language codes; 0 or empty to show names.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/translate.class.php:954|check|if ($usecode == 1 || getDolGlobalString(''MAIN_SHOW_LANGUAGE_CODE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_LOGIN', 'bool', NULL, 'core', 'Displays the user login name alongside the user''s display name in user selection widgets.', 'When set, core/class/html.form.class.php and core/class/html.formother.class.php include the login in user selector labels. Two occurrences across two files. No admin UI write; hidden setting.', 'Enabling this constant appends the login name to user entries in selectors; disabling it shows only the display name.', 'Non-empty (truthy) shows login in user selectors; empty or undefined hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:2455|check|if (getDolGlobalString(''MAIN_SHOW_LOGIN'')) {", "core/class/html.formother.class.php:625|check|if (getDolGlobalString(''MAIN_SHOW_LOGIN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_LOGO', 'bool', NULL, 'core', 'Controls whether the company logo is displayed in the menu header area.', 'Checked in core/menus/standard/eldy.lib.php:579, core/menus/standard/auguria.lib.php:162, and main.inc.php:3510 to display the logo. Set to 0 in menu files eldy_menu.php:179 and auguria_menu.php:179 under certain conditions.', 'Enabling this shows the company logo in the menu header alongside the navigation; disabling it hides it.', '0 = logo hidden; 1 (truthy) = logo shown (requires MAIN_INFO_SOCIETE_LOGO to be set)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/menus/standard/eldy.lib.php:579|check|if (!getDolGlobalString(''MAIN_MENU_INVERT'') && getDolGlobalString(''MAIN_SHOW_LOGO'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'')) {", "main.inc.php:3510|check|if (getDolGlobalString(''MAIN_SHOW_LOGO'') && !getDolGlobalString(''MAIN_OPTIMIZEFORTEXTBROWSER'') && getDolGlobalString(''MAIN_INFO_SOCIETE_LOGO'')) {", "core/menus/standard/eldy_menu.php:179|write|$conf->global->MAIN_SHOW_LOGO = 0;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_ONLY_CODE_MULTICURRENCY', 'bool', NULL, 'compta', 'Suppresses display of the multicurrency amount column when the multicurrency code is not set.', 'Checked in compta/facture/list.php at line 2917. When this constant is not set and a multicurrency code exists on the object, the multicurrency column content is rendered.', 'Setting this constant hides the multicurrency amount even when a currency code is present, showing only the code.', '0 or unset = multicurrency amount shown when code present; 1 = only currency code shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''MAIN_SHOW_ONLY_CODE_MULTICURRENCY'') && !empty($obj->multicurrency_code)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_PASSWORD_INTO_LOG', 'bool', NULL, 'core', 'Controls whether passwords are included in log output; by default passwords are masked.', 'Checked with negation in core/lib/functions.lib.php:2829; passwords are masked unless this constant is set. No admin UI write detected.', 'Setting this constant exposes passwords in log output, which is a security risk. Without it, passwords are masked in logs.', 'Non-empty = passwords visible in log; absent/empty = passwords masked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:2829|check|if (!getDolGlobalString(''MAIN_SHOW_PASSWORD_INTO_LOG'')) {"]', 'low', NULL);
