INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_PREVIEW_PICTO_EVEN_ON_PHONE', 'bool', NULL, 'core', 'Forces display of file-preview icons on mobile (phone layout) even when the layout would normally suppress them.', 'Checked in core/class/html.formfile.class.php:2433 alongside a phone layout detection and JavaScript availability check. No admin UI write is present.', 'When enabled, preview icons are shown on phone-layout pages; when not set, preview icons are hidden on phone layouts.', 'Truthy value (e.g. 1) to show preview icons on phone; empty or 0 to hide them on phone.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formfile.class.php:2433|check|if (($conf->browser->layout != ''phone'' || getDolGlobalString(''MAIN_SHOW_PREVIEW_PICTO_EVEN_ON_PHONE'')) && !empty($conf->use_javascript_ajax)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_PRICE_WITH_TAX_IN_SUMMARIES', 'bool', NULL, 'comm', 'Shows prices inclusive of tax in order and supplier order summary sections.', 'When set, additional tax-inclusive price rows are rendered in the summary panels of fourn/card.php (lines 891, 938) and comm/card.php (lines 1510, 1560, 1615, 1710). No admin UI writes are present in the payload.', 'Enabling this constant adds tax-inclusive price display to order summaries; disabling it hides those rows.', 'Truthy value shows tax-inclusive prices; absent or falsy hides them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/card.php:891|check|if (getDolGlobalString(''MAIN_SHOW_PRICE_WITH_TAX_IN_SUMMARIES'')) {", "fourn/card.php:938|check|if (getDolGlobalString(''MAIN_SHOW_PRICE_WITH_TAX_IN_SUMMARIES'')) {", "comm/card.php:1510|check|if (getDolGlobalString(''MAIN_SHOW_PRICE_WITH_TAX_IN_SUMMARIES'')) {", "comm/card.php:1560|check|if (getDolGlobalString(''MAIN_SHOW_PRICE_WITH_TAX_IN_SUMMARIES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_PRODUCT_ACTIVITY_TRIM', 'bool', NULL, 'product', 'Enables a quarterly product activity section on the product index dashboard page.', 'Checked in product/index.php:677; when set and the invoice module is enabled and the user has invoice read rights, the quarterly activity block is shown.', 'Enabling adds a quarterly sales activity widget to the product dashboard; disabling hides it.', 'Truthy value to show quarterly product activity; absent or falsy to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/index.php:677|check|if (isModEnabled(\"invoice\") && $user->hasRight(''facture'', ''lire'') && getDolGlobalString(''MAIN_SHOW_PRODUCT_ACTIVITY_TRIM'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_REF_CUSTOMER_INVOICES', 'bool', NULL, 'comm', 'Shows the customer reference column in the invoice list on the commercial (customer) card.', 'Checked in comm/card.php at lines 1618 and 1690 to conditionally include the customer reference column in the invoices tab.', 'Enabling this constant adds a customer reference column to the invoices table on customer cards.', 'Truthy value = customer reference column shown; empty/unset = column hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/card.php:1618|check|if (getDolGlobalString(''MAIN_SHOW_REF_CUSTOMER_INVOICES'')) {", "comm/card.php:1690|check|if (getDolGlobalString(''MAIN_SHOW_REF_CUSTOMER_INVOICES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_REGION_IN_STATE_SELECT', 'bool', NULL, 'core', 'Controls whether the region is displayed alongside the state/province in address selection dropdowns.', 'Checked in societe/card.php, contact/card.php, resource/class/html.formresource.class.php:367, and webportal/class/webportalmember.class.php:474 across 18 occurrences in multiple files. Values 1 and 2 both trigger region display; value 1 also passes through to getFullAddress calls.', 'Setting to 1 or 2 causes the region name to appear in state/province selection widgets; the exact difference between 1 and 2 is not documented in the payload.', '0 or unset = no region shown; 1 = show region; 2 = show region (alternate mode)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1654|check|if ((getDolGlobalInt(''MAIN_SHOW_REGION_IN_STATE_SELECT'') == 1 || getDolGlobalInt(''MAIN_SHOW_REGION_IN_STATE_SELECT'') == 2)) {", "webportal/class/webportalmember.class.php:474|check|if (getDolGlobalInt(''MAIN_SHOW_REGION_IN_STATE_SELECT'') == 1 && $this->region) {", "resource/class/html.formresource.class.php:367|check|if (getDolGlobalInt(''MAIN_SHOW_REGION_IN_STATE_SELECT'') == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_STATE_CODE', 'bool', NULL, 'resource', 'Controls whether state/province codes are shown in address dropdowns alongside or instead of the full state name.', 'Read in resource/class/html.formresource.class.php:364-365 and core/class/html.formcompany.class.php:335-336. When set, the code checks for values 1, 2, or ''all'' to determine display mode.', 'Changing this value alters how state/province selections are displayed in address forms; setting it to 1, 2, or ''all'' enables code display while leaving it unset hides codes.', '1=show code (mode 1), 2=show code (mode 2), ''all''=show all codes; empty/unset=do not show state code', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["getDolGlobalString(''MAIN_SHOW_STATE_CODE'') &&", "(getDolGlobalInt(''MAIN_SHOW_STATE_CODE'') == 1 || getDolGlobalInt(''MAIN_SHOW_STATE_CODE'') == 2 || getDolGlobalString(''MAIN_SHOW_STATE_CODE'') === ''all'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_TECHNICAL_ID', 'bool', NULL, 'hrm', 'Shows the internal database row ID (technical ID) of records in the detail view UI.', 'Checked in 58 locations. When set, pages like societe/card.php:2340, contact/card.php:993, user/card.php:2436 display the rowid. When unset, class-level logic (e.g. partnership/class/partnership.class.php:239) hides the rowid field from the fields array when a ref exists.', 'Enabling this constant displays the internal database ID alongside the business reference on record detail pages; disabling hides it.', 'Non-empty = technical ID shown; 0 or unset = technical ID hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:2340|check|if (getDolGlobalString(''MAIN_SHOW_TECHNICAL_ID'')) {", "contact/card.php:993|check|if (getDolGlobalString(''MAIN_SHOW_TECHNICAL_ID'')) {", "partnership/class/partnership.class.php:239|check|if (!getDolGlobalString(''MAIN_SHOW_TECHNICAL_ID'') && isset($this->fields[''rowid'']) && !empty($this->fields[''ref''])) {", "user/card.php:2436|check|if (getDolGlobalString(''MAIN_SHOW_TECHNICAL_ID'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_TUNING_INFO', 'bool', NULL, 'core', 'Enables display of performance tuning information in the page footer or debug output.', 'Checked at core/lib/functions.lib.php:13223 against both the environment variable and this global constant. The comment at main.inc.php:45 states ''For optional tuning. Enabled if environment variable MAIN_SHOW_TUNING_INFO is defined.'' The docblock at line 13032 also lists this constant alongside the env var.', 'Setting this constant activates tuning/profiling output in pages; it can also be enabled via the server environment variable of the same name.', '0 or empty (and env var unset) = tuning info hidden; any truthy value or env var set = tuning info displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["main.inc.php:45  // For optional tuning. Enabled if environment variable MAIN_SHOW_TUNING_INFO is defined.", "core/lib/functions.lib.php:13032  * \t\tjs for conf->global->MAIN_SHOW_TUNING_INFO or $_SERVER[\"MAIN_SHOW_TUNING_INFO\"]", "core/lib/functions.lib.php:13223|check|if (!empty($_SERVER[''MAIN_SHOW_TUNING_INFO'']) || getDolGlobalString(''MAIN_SHOW_TUNING_INFO'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_UNSELECTABLES_IN_SELECT_INTERVENTIONS', 'bool', NULL, 'core', 'Controls whether unselectable intervention entries are shown in the intervention select dropdown.', 'Read at core/class/html.formintervention.class.php:73 and assigned to $hideunselectables. Note: the variable name suggests the constant value is used as the hide flag. No admin UI; hidden setting.', 'Setting to a non-zero value hides unselectable interventions from the dropdown. Exact behavior beyond the guard is unclear from code alone.', '0 or empty = unselectable interventions not specially handled; non-zero = controls visibility of unselectable interventions in select', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formintervention.class.php:73|read|$hideunselectables = getDolGlobalInt(''MAIN_SHOW_UNSELECTABLES_IN_SELECT_INTERVENTIONS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SHOW_VERSION', 'bool', NULL, 'core', 'Displays the Dolibarr version number in the page footer, distinct from MAIN_HIDE_VERSION.', 'Checked at main.inc.php:3335 together with MAIN_BUGTRACK_ENABLELINK, and independently at :3341 to output the version string. The comment at :3341 notes the version is already on the help picto and login page.', 'Enabling this adds an explicit version display in the footer area.', '0 or unset = version not shown via this constant; 1 (truthy) = version shown in footer', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3335|check|if (getDolGlobalString(''MAIN_SHOW_VERSION'') || getDolGlobalString(''MAIN_BUGTRACK_ENABLELINK'')) {", "main.inc.php:3341|check|if (getDolGlobalString(''MAIN_SHOW_VERSION'')) {    // Version is already on help picto and on login page."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SIGN_CSS_URL', 'string', NULL, 'public', 'Stores the URL of a custom CSS stylesheet injected into the public online signature page.', 'Checked at public/onlinesign/newonlinesign.php:237 and the URL is used at line 238 to build a <link> stylesheet tag including the current language parameter. No admin UI write is present.', 'Setting this constant injects a custom stylesheet into the signature page, allowing visual customization; leaving it unset uses the default styles.', 'String URL of the CSS file; unset/empty = no custom stylesheet injected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/onlinesign/newonlinesign.php:237|check|if (getDolGlobalString(''MAIN_SIGN_CSS_URL'')) {", "public/onlinesign/newonlinesign.php:238|read|$head = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"'' . getDolGlobalString(''MAIN_SIGN_CSS_URL'').''?lang=''.$langs->defaultlang.''\">''.\"\n\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SIZE_LISTE_LIMIT', 'string', '20', 'admin', 'Sets the maximum number of records displayed per page in list views across the application.', 'Read in core/class/conf.class.php:1029 to populate $this->liste_limit (defaulting to 15 when absent). Managed via admin/ihm.php:272 and admin/system/perf.php:724 where high values trigger a performance warning. Default value is ''20''.', 'Increasing this value shows more records per list page but can significantly slow page rendering; admin/system/perf.php warns when the value exceeds the recommended maximum.', 'Positive integer. Default is 20. Value of 0 or negative is flagged as invalid by admin/ihm.php:472.', 0, 0, 'admin/ihm.php|admin/ihm.php|admin/ihm.php|admin/system/perf.php|admin/system/perf.php|admin/system/perf.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:1029|read|$this->liste_limit = getDolGlobalInt(''MAIN_SIZE_LISTE_LIMIT'', 15);", "admin/system/perf.php:724|check|if (getDolGlobalInt(''MAIN_SIZE_LISTE_LIMIT'') > $MAXRECOMMENDED) {", "admin/ihm.php:468|check|if (getDolGlobalInt(''MAIN_SIZE_LISTE_LIMIT'') > 0) {", "admin/ihm.php:272|write|dolibarr_set_const($db, \"MAIN_SIZE_LISTE_LIMIT\", GETPOSTINT(\"MAIN_SIZE_LISTE_LIMIT\"), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SIZE_SHORTLIST_LIMIT', 'string', '3', 'fourn', 'Sets the maximum number of items displayed in short lists across dashboard and index pages.', 'Configurable via admin/ihm.php:273 and displayed in the admin UI at admin/ihm.php:479. Read with a fallback of 5 in multiple index pages (projet/index.php:65, fourn/commande/index.php:51, compta/facture/index.php:54, and many others — 34 total occurrences).', 'Increasing this value shows more items in short lists on dashboard widgets; decreasing it reduces the number of rows displayed.', 'Integer: number of items to show in short lists. Default is ''3'' (stored) with a code-level fallback of 5 when not set.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:273|write|dolibarr_set_const($db, \"MAIN_SIZE_SHORTLIST_LIMIT\", GETPOSTINT(\"MAIN_SIZE_SHORTLIST_LIMIT\"), ''chaine'', 0, '''', $conf->entity);", "projet/index.php:65|read|$max = getDolGlobalInt(''MAIN_SIZE_SHORTLIST_LIMIT'', 5);", "fourn/commande/index.php:51|read|$max = getDolGlobalInt(''MAIN_SIZE_SHORTLIST_LIMIT'', 5);", "fourn/card.php:488|read|$MAXLIST = getDolGlobalInt(''MAIN_SIZE_SHORTLIST_LIMIT'', 5);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SIZE_SHORTLIST_LIMIT_LAST_MODIFIED_TICKETS', 'string', NULL, 'ticket', 'Overrides the default maximum number of tickets shown in the ''last modified tickets'' short list on the ticket dashboard.', 'Read in ticket/index.php:386 as an integer override for the $max variable that controls the number of entries in the last-modified-tickets list. No admin UI write path is present in the payload.', 'Setting this to a higher or lower integer changes how many recently modified tickets appear in the dashboard short list.', 'Positive integer; falls back to the default $max value if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/index.php:386|read|$tmpmax = getDolGlobalInt(''MAIN_SIZE_SHORTLIST_LIMIT_LAST_MODIFIED_TICKETS'', $max);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SMS_DEBUG', 'string', NULL, 'core', 'Enables debug logging in the SMS sending class (CSMSFile).', 'Checked in core/class/CSMSFile.class.php at lines 175, 221, and 228; when truthy, the class executes additional debug code paths during SMS dispatch.', 'Enabling this constant activates debug branches in the SMS class, which may produce additional log output. Disabling it suppresses those branches.', 'Truthy string to enable debug mode; empty/unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CSMSFile.class.php:228|check|if (getDolGlobalString(''MAIN_SMS_DEBUG'')) {", "core/class/CSMSFile.class.php:175|check|if (getDolGlobalString(''MAIN_SMS_DEBUG'')) {", "core/class/CSMSFile.class.php:221|check|if (getDolGlobalString(''MAIN_SMS_DEBUG'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SMS_FROM', 'string', NULL, 'admin', 'Stores the default sender phone number used for outgoing SMS messages.', 'Defines the global SMS sender address. Configured via admin/sms.php where it is written with dolibarr_set_const and displayed in the settings form. It is also validated against isValidPhone and used as the default ''from'' address in actioncomm.class.php when sending SMS.', 'Changing this value alters the sender number shown to recipients of SMS messages. If set to an invalid phone number, a validation warning is triggered in the admin UI.', 'A valid phone number string; validated by isValidPhone.', 0, 0, 'admin/sms.php|admin/sms.php|admin/sms.php|admin/sms.php|admin/sms.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/sms.php:66|write|dolibarr_set_const($db, \"MAIN_SMS_FROM\", GETPOST(\"MAIN_SMS_FROM\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/sms.php:245|check|if (getDolGlobalString(''MAIN_SMS_FROM'') && !isValidPhone(getDolGlobalString(''MAIN_SMS_FROM''))) {", "admin/sms.php:280|read|$formsms->fromsms = (GETPOSTISSET(''fromsms'') ? GETPOST(''fromsms'') : getDolGlobalString(''MAIN_SMS_FROM'', $user->user_mobile));", "comm/action/class/actioncomm.class.php:3007|read|$from = getDolGlobalString(''MAIN_SMS_FROM'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SMS_SENDMODE', 'string', NULL, 'core', 'Selects the SMS sending provider module used by Dolibarr.', 'Stores the identifier of the active SMS sending method (e.g. a module name). Written via admin/sms.php:64, read by core/class/CSMSFile.class.php:182 which uses it to load the appropriate SMS driver. The comment on that line reads: ''$conf->global->MAIN_SMS_SENDMODE looks like a value ''module''''.', 'Changing this value switches the SMS backend; clearing it disables SMS sending entirely as CSMSFile.class.php:138 returns early when the constant is empty.', 'String: identifier of the SMS module/provider; empty/unset = SMS sending disabled.', 0, 0, 'admin/sms.php|admin/sms.php|admin/sms.php|admin/sms.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/CSMSFile.class.php:182|read|$sendmode = getDolGlobalString(''MAIN_SMS_SENDMODE'');  // $conf->global->MAIN_SMS_SENDMODE looks like a value ''module''", "core/class/CSMSFile.class.php:138|check|if (!getDolGlobalString(''MAIN_SMS_SENDMODE'')) {", "admin/sms.php:64|write|dolibarr_set_const($db, \"MAIN_SMS_SENDMODE\", GETPOST(\"MAIN_SMS_SENDMODE\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/sms.php:202|read|print $form->selectarray(''MAIN_SMS_SENDMODE'', $listofmethods, getDolGlobalString(''MAIN_SMS_SENDMODE''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SMTPS_ADD_TLS_TO_HOST_FOR_HELO', 'string', NULL, 'core', 'Appends ''tls'' to the SMTP hostname used in the HELO/EHLO command when TLS is active.', 'Checked in core/class/smtps.class.php:562 and :749; when TLS is in use and this constant is set, the host string for HELO is modified.', 'Enabling this constant alters the HELO hostname sent during TLS SMTP sessions, which may be required by some mail servers.', 'Bool-like string: empty/unset = HELO host unchanged; non-empty = ''tls'' appended to HELO host.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/smtps.class.php:562|check|if ($usetls && getDolGlobalString(''MAIN_SMTPS_ADD_TLS_TO_HOST_FOR_HELO'')) {", "core/class/smtps.class.php:749|check|if ($usetls && getDolGlobalString(''MAIN_SMTPS_ADD_TLS_TO_HOST_FOR_HELO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SOCIETE_SHOW_COMPLETE_NAME', 'bool', NULL, 'societe', 'Controls whether the third-party name column in list view is shown without a CSS overflow truncation class.', 'When set, the name cell in the third-party list omits the tdoverflowmax200 CSS class, allowing the full name to display without truncation. No admin UI; must be set directly in the database.', 'Enabling this prevents long company names from being truncated in the list. Disabling it restricts the name column width to 200px.', 'Truthy = full name displayed without truncation; empty/falsy = name truncated at 200px', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/list.php:1983|read|print ''<td''.(getDolGlobalString(''MAIN_SOCIETE_SHOW_COMPLETE_NAME'') ? '''' : '' class=\"tdoverflowmax200\"'').'' data-key=\"ref\">'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_START_WEEK', 'string', NULL, 'core', 'Sets the first day of the week for calendars and date pickers (0 = Sunday, 1 = Monday).', 'Read in core/lib/date.lib.php:684 and core/datepicker.php:227 to determine the week start day. A comment at projet/activity/perday.php:665 clarifies: ''For monday, must be 0 for monday if MAIN_START_WEEK = 1, must be 1 for monday if MAIN_START_WEEK = 0''. The admin UI at admin/ihm.php:282 writes the value and admin/ihm.php:490 renders the selector.', 'Changing this value shifts the starting column of all calendar and date-picker widgets across the application.', '0 = Sunday is first day of week; 1 = Monday is first day of week.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// For monday, must be 0 for monday if MAIN_START_WEEK = 1, must be 1 for monday if MAIN_START_WEEK = 0", "// numstartworkingday and numendworkingday are default start and end date of working days (1 means sunday if MAIN_START_WEEK is 0, 1 means monday if MAIN_START_WEEK is 1)", "core/lib/date.lib.php:684|read|$start_week = getDolGlobalInt(''MAIN_START_WEEK'', 1);", "core/datepicker.php:227|read|$startday = getDolGlobalInt(''MAIN_START_WEEK'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_STATS_GRAPHS_SHOW_N_YEARS', 'bool', NULL, 'adherents', 'Sets the number of years displayed on statistics graphs; defaults to 2 if unset, capped between 1 and 10.', 'Read via the expression `(!getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS'') ? 2 : max(1, min(10, getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS''))))` across 17 occurrences in at least 8 stats pages including salaries, projet, reception, compta/facture, fichinter, ticket, and compta/deplacement.', 'When unset or 0, stats graphs show 2 years of data. When set, the value is clamped between 1 and 10 to determine how many years are shown.', 'Integer 1–10 = number of years shown; 0 or unset = 2 years (default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["salaries/stats/index.php:66|read|$startyear = $year - (!getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS'') ? 2 : max(1, min(10, getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS''))));", "projet/tasks/stats/index.php:59|read|$startyear = $year - (!getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS'') ? 2 : max(1, min(10, getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS''))));", "compta/facture/stats/index.php:89|read|$startyear = $year - (!getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS'') ? 2 : max(1, min(10, getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS''))));", "ticket/stats/index.php:67|read|$startyear = $year - (!getDolGlobalString(''MAIN_STATS_GRAPHS_SHOW_N_YEARS'') ? 2 : max(1, min(10, getDolGlobalInt(''MAIN_STATS_GRAPHS_SHOW_N_YEARS''))));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_STATUS_USES_IMAGES', 'string', NULL, 'core', 'Switches status badge rendering from CSS-based labels to image-based icons.', 'Read at core/lib/functions.lib.php:14408 and 14456. When set, the status rendering function selects an image-based output path; when unset and $displayMode is set, a CSS label path is used instead.', 'Enabling this constant replaces CSS status badges with image icons throughout the UI; disabling it uses the modern CSS-based status display.', '0 or empty = CSS-based status labels; any truthy value = image-based status icons', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:14408|read|} elseif (getDolGlobalString(''MAIN_STATUS_USES_IMAGES'')) {", "core/lib/functions.lib.php:14456|read|} elseif (!getDolGlobalString(''MAIN_STATUS_USES_IMAGES'') && !empty($displayMode)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_STORE_COMPUTED_EXTRAFIELDS', 'string', NULL, 'core', 'Controls whether computed extra-field values are persisted to the database.', 'Checked in core/class/commonobject.class.php:7460 and :6994 to decide whether to save computed values. Also checked in admin templates (core/tpl/admin_extrafields_add.tpl.php:223 and core/tpl/admin_extrafields_edit.tpl.php:297) to show or hide related admin options.', 'Enabling this causes computed extra-field results to be stored in the database on save, allowing them to be queried and filtered. Disabling it means computed values are derived on the fly and not persisted.', 'Empty/not set = computed values not stored; any truthy string = computed values persisted', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:7460|check|if (getDolGlobalString(''MAIN_STORE_COMPUTED_EXTRAFIELDS'')) {", "core/tpl/admin_extrafields_add.tpl.php:223|check|<?php if (!getDolGlobalString(''MAIN_STORE_COMPUTED_EXTRAFIELDS'')) { ?>", "core/class/commonobject.class.php:6994|check|if (getDolGlobalString(''MAIN_STORE_COMPUTED_EXTRAFIELDS'')) {", "core/tpl/admin_extrafields_edit.tpl.php:297|check|<?php if (!getDolGlobalString(''MAIN_STORE_COMPUTED_EXTRAFIELDS'')) { ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_STORE_FULL_EVENT_IN_GMT', 'string', NULL, 'comm', 'Controls whether full-day agenda events are stored in GMT instead of local time.', 'Read into $tzforfullday in comm/action/peruser.php:896, comm/action/index.php:963, comm/action/card.php at lines 91, 374, 925, core/lib/xcal.lib.php:211, and comm/action/document.php at lines 250 and 264. The comment at core/lib/xcal.lib.php:209 states: ''Using option MAIN_STORE_FULL_EVENT_IN_GMT=1 change the behaviour to store in GMT for full day event.''', 'Setting this constant to 1 changes full-day event storage to use GMT, which affects how events are exported and displayed across timezones.', '1 = store full-day events in GMT; empty/unset = local time used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/xcal.lib.php:209  // Using option MAIN_STORE_FULL_EVENT_IN_GMT=1 change the behaviour to store in GMT for full day event. This must become", "comm/action/peruser.php:896|read|$tzforfullday = getDolGlobalString(''MAIN_STORE_FULL_EVENT_IN_GMT'');", "comm/action/index.php:963|read|$tzforfullday = getDolGlobalString(''MAIN_STORE_FULL_EVENT_IN_GMT'');", "comm/action/card.php:91|read|$tzforfullday = getDolGlobalString(''MAIN_STORE_FULL_EVENT_IN_GMT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUBMODULE_DELIVERY', 'string', NULL, 'core', 'Enables the Delivery submodule within the Expedition (Shipments) module, activating delivery-order creation and tracking.', 'Toggled via admin/delivery.php (lines 81 write-on, 85 write-off). Checked in core/lib/sendings.lib.php lines 59, 373, 525, and expedition/class/expedition.class.php line 1223. COMMENT at admin/delivery.php:72 notes: ''We force MAIN_SUBMODULE_EXPEDITION to on because this var is still used. TODO We should remove it, only MAIN_SUBMODULE_DELIVERY must be used.''', 'Enabling this constant activates the delivery submodule, adding delivery-related tabs, actions, and SQL joins across the shipments workflow. Disabling it hides delivery functionality.', '"1" = delivery submodule enabled; absent or deleted = disabled. From admin/delivery.php:81: dolibarr_set_const($db, "MAIN_SUBMODULE_DELIVERY", "1", ''chaine'', 0, '''', $conf->entity);', 0, 0, 'admin/delivery.php|admin/delivery.php|admin/delivery.php|admin/delivery.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/delivery.php:72  // Shipment note. We force MAIN_SUBMODULE_EXPEDITION to on because this var is still used. TODO We should remove it, only MAIN_SUBMODULE_DELIVERY must be used.", "admin/delivery.php:81|write|dolibarr_set_const($db, \"MAIN_SUBMODULE_DELIVERY\", \"1\", ''chaine'', 0, '''', $conf->entity);", "core/lib/sendings.lib.php:59|check|if (getDolGlobalInt(''MAIN_SUBMODULE_DELIVERY'') && $user->hasRight(''expedition'', ''delivery'', ''lire'')) {", "expedition/class/expedition.class.php:1223|check|if (getDolGlobalInt(''MAIN_SUBMODULE_DELIVERY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUBMODULE_EXPEDITION', 'string', NULL, 'core', 'Enables the shipment submodule; a legacy flag kept because it is still used alongside MAIN_SUBMODULE_DELIVERY.', 'Forced to ''1'' in admin/delivery.php:75 and :80 when the shipping module is enabled. The comment at admin/delivery.php:72 notes this variable should eventually be removed in favour of MAIN_SUBMODULE_DELIVERY. Checked in 18+ locations across delivery and order code.', 'If not set, certain shipment creation and stock movement paths in delivery/class/delivery.class.php are blocked. Enabling it re-activates shipment-related UI and logic.', '''1'' = shipment submodule active; empty/unset = inactive.', 0, 0, 'admin/delivery.php|admin/delivery.php|admin/delivery.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/delivery.php:72  // Shipment note. We force MAIN_SUBMODULE_EXPEDITION to on because this var is still used. TODO We should remove it, only MAIN_SUBMODULE_DELIVERY must be used.", "admin/delivery.php:75|write|dolibarr_set_const($db, \"MAIN_SUBMODULE_EXPEDITION\", \"1\", ''chaine'', 0, '''', $conf->entity);", "delivery/class/delivery.class.php:219|check|if (!getDolGlobalInt(''MAIN_SUBMODULE_EXPEDITION'')) {", "core/lib/expedition.lib.php:95|check|if (getDolGlobalString(''MAIN_SUBMODULE_EXPEDITION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUBMODULE_RECEPTION', 'string', NULL, 'core', 'Enables the reception sub-module within the reception module, activating reception-specific menu entries.', 'When the reception module is enabled but this constant is not set, admin/reception_setup.php:64 sets it to ''1'' automatically. Read in core/lib/reception.lib.php at lines 138 and 149 to conditionally include reception menu items.', 'Disabling this constant (setting to empty) hides reception-specific navigation even if the reception module is active.', 'Empty/unset = reception sub-module inactive; ''1'' = reception sub-module active.', 0, 0, 'admin/reception_setup.php|admin/reception_setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/reception_setup.php:62|check|if (isModEnabled(''reception'') && !getDolGlobalString(''MAIN_SUBMODULE_RECEPTION'')) {", "admin/reception_setup.php:64|write|dolibarr_set_const($db, \"MAIN_SUBMODULE_RECEPTION\", \"1\", ''chaine'', 0, '''', $conf->entity);", "core/lib/reception.lib.php:138|check|if (getDolGlobalString(''MAIN_SUBMODULE_RECEPTION'')) {", "core/lib/reception.lib.php:149|check|if (getDolGlobalString(''MAIN_SUBMODULE_RECEPTION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUPPLIER_PROPOSAL_CHOOSE_ODT_DOCUMENT', 'string', NULL, 'core', 'Selects an alternative ODT document template for supplier proposal generation.', 'Read in core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:114 via getDolGlobalInt. When the value is greater than 0, $odtChosen is set to true, indicating that a specific ODT template has been selected rather than the default.', 'Setting this to a positive integer activates an alternative ODT template for supplier proposal documents; leaving it at 0 uses the default template.', '0 or unset = default ODT template used; positive integer = alternative ODT template selected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-18T20:28:13+00:00', NULL, NULL, NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUPPORT_SHARED_CONTACT_BETWEEN_THIRDPARTIES', 'string', NULL, 'core', 'Enables an unstable experimental feature allowing contacts to be shared across multiple third-parties.', 'Checked in core/lib/company.lib.php:97; documented at societe/societecontact.php:28 as ''Used when the unstable option MAIN_SUPPORT_SHARED_CONTACT_BETWEEN_THIRDPARTIES is on.'' No admin UI write path is present in the payload.', 'Enabling this option activates contact-sharing behaviour across third-parties; it is explicitly labelled unstable and may produce unexpected results.', 'Any truthy value activates the shared-contact feature; unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["societe/societecontact.php:28  *     \t\t\t\tUsed when the unstable option MAIN_SUPPORT_SHARED_CONTACT_BETWEEN_THIRDPARTIES is on.", "core/lib/company.lib.php:97|check|if (getDolGlobalString(''MAIN_SUPPORT_SHARED_CONTACT_BETWEEN_THIRDPARTIES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SUSPEND_FACTURE_REC_ON_MAX_GEN_REACHED', 'string', NULL, 'compta', 'Automatically suspends a recurring invoice template when its maximum generation count is reached.', 'Checked at compta/facture/class/facture-rec.class.php:2294: ''if (getDolGlobalInt(''MAIN_SUSPEND_FACTURE_REC_ON_MAX_GEN_REACHED'') && $this->isMaxNbGenReached())''. No admin UI write path is present.', 'When enabled, recurring invoice templates are automatically suspended once the configured maximum number of generations is reached; when disabled, templates continue generating indefinitely.', '0 or not set = recurring invoices continue past max generation count; non-zero = recurring invoice suspended when max generation count is reached.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture-rec.class.php:2294|check|if (getDolGlobalInt(''MAIN_SUSPEND_FACTURE_REC_ON_MAX_GEN_REACHED'') && $this->isMaxNbGenReached()) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SYSLOG_DISABLE_FILE', 'bool', NULL, 'core', 'Disables writing log entries to the file during a request when set, suppressing file-based log output.', 'Checked at core/modules/syslog/mod_syslog_file.php:167 to skip writing to the log file. No admin UI; hidden setting.', 'Enabling this suppresses file log writes. Exact behavior beyond the guard check is unclear from code alone.', '0 or empty = file logging proceeds normally; non-empty = file logging disabled for the request', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_file.php:167|check|if (getDolGlobalString(''MAIN_SYSLOG_DISABLE_FILE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SYSLOG_DISABLE_SYSLOG', 'bool', NULL, 'core', 'Disables syslog output within the syslog log handler.', 'Checked in core/modules/syslog/mod_syslog_syslog.php:116 to conditionally bypass the actual syslog() call.', 'When set, log entries are not forwarded to the system syslog even if the syslog handler is active.', 'Bool-like string: empty/unset = syslog output enabled; non-empty = syslog output disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_syslog.php:116|check|if (getDolGlobalString(''MAIN_SYSLOG_DISABLE_SYSLOG'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_SYSLOG_SHOW_DELAY', 'bool', NULL, 'core', 'Includes timing/delay information in syslog file entries when enabled.', 'Checked at core/modules/syslog/mod_syslog_file.php:175 to conditionally append delay data to log lines. No admin UI; hidden setting.', 'Enabling this adds execution delay information to log entries, useful for performance diagnostics. Leaving unset omits delay data.', '0 or empty = no delay info in log; non-empty = delay information included in log entries', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_file.php:175|check|if (getDolGlobalString(''MAIN_SYSLOG_SHOW_DELAY'')) {"]', 'low', NULL);
