INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TE_PRIVATE_FIRST_AND_LASTNAME_TO_UPPER', 'string', NULL, 'core', 'Forces first and last name to uppercase for private (individual) third-party contacts.', 'Checked in core/class/commonpeople.class.php:363. When set, both the first name and last name of private contacts are converted to uppercase.', 'Enabling this constant causes first and last names on private contacts to be stored and displayed in uppercase.', 'Non-empty = names uppercased; empty or unset = original case preserved', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonpeople.class.php:363|check|if (getDolGlobalString(''MAIN_TE_PRIVATE_FIRST_AND_LASTNAME_TO_UPPER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_THEME', 'string', NULL, 'core', 'Sets the active visual theme (skin) for the Dolibarr interface.', 'Written via admin/ihm.php:118 with dolibarr_set_const. Read in core/lib/usergroups.lib.php:373 as $selected_theme and displayed at line 409. Checked at line 467 to identify the currently selected theme directory. Comment at admin/ihm.php:116: ''To be sure we don''t have this constant set for all entities''.', 'Changing this constant switches the UI theme for all users in the entity. The theme name must correspond to a valid theme directory on disk.', 'String: name of the theme directory (e.g. ''eldy''). Must match an available theme.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ihm.php:118|write|dolibarr_set_const($db, \"MAIN_THEME\", GETPOST(\"main_theme\", ''aZ09''), ''chaine'', 0, '''', $conf->entity);", "core/lib/usergroups.lib.php:373|read|$selected_theme = getDolGlobalString(''MAIN_THEME'');", "core/lib/usergroups.lib.php:467|check|if ($subdir == getDolGlobalString(''MAIN_THEME'')) {", "admin/ihm.php:116  //dolibarr_del_const($db, \"MAIN_THEME\", 0);\t// To be sure we don''t have this constant set for all entities"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TOOLTIP_PRICELOG_HISTORY_LIMIT', 'string', NULL, 'fourn', 'Sets the maximum number of supplier price log entries shown in the product tooltip history.', 'Read in fourn/class/fournisseur.product.class.php:1401 as an integer with a default of 10 when not set. Only one occurrence found; HIDDEN_GUESS is 1.', 'Increasing this value shows more historical price entries in the tooltip; the default when not set is 10 entries.', 'Integer: number of log entries to display; default = 10 when not set', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.product.class.php:1401|read|$logPrices = $this->listProductFournisseurPriceLog($this->product_fourn_price_id, ''pfpl.datec'', ''DESC'', getDolGlobalInt(''MAIN_TOOLTIP_PRICELOG_HISTORY_LIMIT'', 10)); // set sort ord"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TRIGGER_DEBUG', 'string', NULL, 'core', 'Enables debug output during trigger execution in the interfaces class.', 'Checked as an integer at core/class/interfaces.class.php:82; when non-zero the trigger dispatcher emits additional debug information. No comment is present in the payload.', 'Enabling debug mode on triggers aids troubleshooting but may expose internal trigger data in output; exact output format is not described in the available code.', 'Integer value; 0 or unset disables debug, non-zero enables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/interfaces.class.php:82|check|if (getDolGlobalInt(''MAIN_TRIGGER_DEBUG'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TRUNCATE_TIMELINE_MESSAGE', 'string', NULL, 'core', 'Sets the number of lines at which timeline/chatter messages are truncated in the UI.', 'Read via getDolGlobalInt at core/lib/functions.lib.php:17031 with a default of 3. The integer value controls how many lines of a timeline message are shown before truncation.', 'Increasing this value shows more lines of each timeline message before truncation; decreasing it collapses messages more aggressively.', 'Integer representing the number of lines to show before truncating; default is 3', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:17031|read|$truncateLines = getDolGlobalInt(''MAIN_TRUNCATE_TIMELINE_MESSAGE'', 3);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TVAINTRA_IN_SOURCE_ADDRESS', 'string', NULL, 'core', 'Controls whether the company''s intra-community VAT number is included in the source address block on PDF documents.', 'When enabled, the sender''s VAT intra number is appended to the address string in PDF generation (core/lib/pdf.lib.php:500). No admin UI write is present; the constant must be set manually.', 'Enabling this adds the VAT intra number to the issuing company''s address block on all generated PDFs.', 'Truthy string (non-empty) = include VAT intra in source address; absent/empty = omit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:500|check|if (getDolGlobalString(''MAIN_TVAINTRA_IN_SOURCE_ADDRESS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TVAINTRA_NOT_IN_ADDRESS', 'string', NULL, 'admin', 'Controls whether the recipient''s intra-community VAT number is excluded from the address block on PDF documents.', 'Configured via admin/pdf.php (written with dolibarr_set_const at line 122, rendered as a yes/no selector at line 367). Checked at core/lib/pdf.lib.php:662: when truthy, the VAT number is omitted from the target address.', 'Enabling this removes the recipient''s VAT intra number from the address block on generated PDFs; disabling it (default) includes the number.', '1 = exclude VAT intra from address; 0 or absent = include VAT intra in address.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:122|write|dolibarr_set_const($db, \"MAIN_TVAINTRA_NOT_IN_ADDRESS\", GETPOST(\"MAIN_TVAINTRA_NOT_IN_ADDRESS\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:367|read|print $form->selectyesno(''MAIN_TVAINTRA_NOT_IN_ADDRESS'', getDolGlobalInt(''MAIN_TVAINTRA_NOT_IN_ADDRESS''), 1);", "core/lib/pdf.lib.php:662|check|if (!getDolGlobalString(''MAIN_TVAINTRA_NOT_IN_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_TYPES_TO_SHOW_PICTO', 'bool', NULL, 'core', 'Defines the comma-separated list of extrafield types for which a picto icon is shown.', 'Read twice in core/class/commonobject.class.php:9803 and 9811, split by comma to build the list of types. Defaults to ''email,phone,ip,password''.', 'Modifying this constant changes which extrafield types display a picto icon next to their value.', 'Comma-separated string of type names (default: ''email,phone,ip,password'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:9803|read|$listoftypestoshowpicto = explode('','', getDolGlobalString(''MAIN_TYPES_TO_SHOW_PICTO'', ''email,phone,ip,password''));", "core/class/commonobject.class.php:9811|read|$listoftypestoshowpicto = explode('','', getDolGlobalString(''MAIN_TYPES_TO_SHOW_PICTO'', ''email,phone,ip,password''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_UMASK', 'string', NULL, 'core', 'Sets the file permission mask (umask) used when creating files and directories in Dolibarr.', 'Written via admin/security_file.php:103 and displayed in the admin UI at admin/security_file.php:206. Read across core/lib/files.lib.php (lines 769, 859, 986, 1103, 2784) and core/class/conf.class.php:932 via octdec() conversion. Default fallback used in core/class/utils.class.php:1100 is ''0664''.', 'Changing this value controls the permission bits set on newly created files and directories. An incorrect mask can prevent file access or expose files to unintended users.', 'Octal string, e.g. ''0666'' — ''0'' by default means getDolGlobalString(''MAIN_UMASK''); example: ''0666''', 0, 0, 'admin/security_file.php|admin/system/security.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/files.lib.php:769  * @param\tstring\t\t\t\t\t\t$newmask\t\t\t       Mask for new file. ''0'' by default means getDolGlobalString(''MAIN_UMASK''). Example: ''0666''.", "admin/security_file.php:103|write|$res4 = dolibarr_set_const($db, \"MAIN_UMASK\", $tmpumask, ''chaine'', 0, '''', $conf->entity);", "core/class/conf.class.php:932|read|$tmpumask = (octdec(getDolGlobalString(''MAIN_UMASK'')) & 0666);", "admin/security_file.php:206|read|print ''<input class=\"flat width75 right\" name=\"MAIN_UMASK\" type=\"text\" spellcheck=\"false\" value=\"''.dol_escape_htmltag(getDolGlobalString(''MAIN_UMASK'')).\"''>\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_UNACCENT_USE_TRANSLITERATOR', 'bool', NULL, 'core', 'Enables the PHP intl Transliterator for accent removal instead of the default method, when the intl extension is loaded.', 'Checked in core/lib/functions.lib.php:2105 with an extension_loaded(''intl'') guard. No admin UI write detected.', 'Enabling this constant switches accent-stripping to use PHP''s Transliterator, which requires the intl extension. Without it, the default unaccent method is used.', 'Non-empty = use intl Transliterator; absent/empty = use default method. Requires extension_loaded(''intl'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:2105|check|if (extension_loaded(''intl'') && getDolGlobalString(''MAIN_UNACCENT_USE_TRANSLITERATOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_UNIT_PRICE_WITH_TAX_IS_FOR_ALL_TAXES', 'string', NULL, 'comm', 'Intended to enable unit price entry inclusive of all taxes; currently a work-in-progress feature.', 'Checked in core/tpl/objectline_edit.tpl.php:270. Code comments in api/class/api_access.class.php:203, master.inc.php:357, comm/propal/class/propal.class.php:978, and comm/propal/card.php:1242 indicate this is ''Work In Progress'' and ''TODO Implement''.', 'The feature is not fully implemented; enabling this constant activates only partial support for all-tax unit price entry.', 'Truthy integer = all-taxes-inclusive unit price mode (partial implementation); empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["api/class/api_access.class.php:203  // Work In Progress to support all taxes into unit price entry when MAIN_UNIT_PRICE_WITH_TAX_IS_FOR_ALL_TAXES is set.", "master.inc.php:357  // Work In Progress to support all taxes into unit price entry when MAIN_UNIT_PRICE_WITH_TAX_IS_FOR_ALL_TAXES is set.", "comm/propal/class/propal.class.php:978  // TODO Implement  if (getDolGlobalInt(''MAIN_UNIT_PRICE_WITH_TAX_IS_FOR_ALL_TAXES'')) ?", "comm/propal/card.php:1242  // TODO Implement  if (getDolGlobalInt(''MAIN_UNIT_PRICE_WITH_TAX_IS_FOR_ALL_TAXES''))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_UNKNOWN_CUSTOMERS_ARE_COMPANIES', 'string', NULL, 'societe', 'Sets the default company/individual classification for customers of unknown type.', 'Read as an integer with a default value in societe/class/societe.class.php at line 4470 to determine whether unknown customers are treated as companies.', 'Changing this constant alters how unknown-type customers are classified (company vs. individual) when the type cannot be determined.', 'Integer value used as default; exact semantics depend on calling context', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4470|read|$isACompany = getDolGlobalInt(''MAIN_UNKNOWN_CUSTOMERS_ARE_COMPANIES'', $defaultvalue);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_UPLOAD_DOC', 'string', '2048', 'core', 'Sets the maximum allowed file upload size in kilobytes for document uploads across Dolibarr.', 'Written via admin/security_file.php:102 and configurable in the admin security UI. Read in admin/modules.php:1560 and admin/geoipmaxmind.php:202 as $max (in Kb). The comment in core/class/conf.class.php:1131 confirms the unit: ''$this->maxfilesize = ... (int) $this->global->MAIN_UPLOAD_DOC * 1024''. Also analyzed alongside PHP upload_max_filesize and post_max_size per core/lib/security.lib.php:1418.', 'Reducing the value restricts the maximum uploadable file size across the application. Increasing it allows larger uploads, subject to PHP server-side limits.', 'Integer (in kilobytes); default is 2048. Empty or 0 disables upload size enforcement by this constant.', 0, 0, 'admin/security_file.php|admin/security_file.php|admin/modules.php|admin/modules.php|admin/geoipmaxmind.php|admin/geoipmaxmind.php|admin/security_file.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/modules.php:1560|read|$max = getDolGlobalString(''MAIN_UPLOAD_DOC''); // In Kb", "core/class/conf.class.php:1131  //$this->maxfilesize = (empty($this->global->MAIN_UPLOAD_DOC) ? 0 : (int) $this->global->MAIN_UPLOAD_DOC * 1024);", "core/lib/security.lib.php:1418  *  Analyze among: upload_max_filesize, post_max_size, MAIN_UPLOAD_DOC", "admin/security_file.php:102|write|$res3 = dolibarr_set_const($db, ''MAIN_UPLOAD_DOC'', GETPOST(''MAIN_UPLOAD_DOC'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_URL_FOR_PING', 'string', NULL, 'blockedlog', 'Overrides the default URL used to send blockedlog registration and tracking pings.', 'Read at blockedlog/lib/blockedlog.lib.php:406 and core/lib/functions2.lib.php:3147, both with the default ''https://ping.dolibarr.org/''. No admin UI writes this value.', 'Setting this constant redirects all registration and usage pings to the specified URL instead of the official Dolibarr ping server.', 'A valid URL string; default is ''https://ping.dolibarr.org/''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$url_for_ping = getDolGlobalString(''MAIN_URL_FOR_PING'', \"https://ping.dolibarr.org/\");", "$url_for_ping = getDolGlobalString(''MAIN_URL_FOR_PING'', \"https://ping.dolibarr.org/\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USER_PROFILE_CSS_URL', 'string', NULL, 'public', 'Specifies the URL of a custom CSS stylesheet to inject into the public user profile view page.', 'In public/users/view.php at lines 237-238, when set a link tag pointing to this URL (with a lang query parameter) is added to the page head. No admin UI write path is present.', 'Setting this applies a custom stylesheet to the public user profile page; leaving it unset uses the default styles.', 'String: URL of the CSS file to inject into the public user profile page', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/users/view.php:237|check|if (getDolGlobalString(''MAIN_USER_PROFILE_CSS_URL'')) {", "public/users/view.php:238|read|$head = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"'' . getDolGlobalString(''MAIN_USER_PROFILE_CSS_URL'').''?lang=''.$langs->defaultlang.''\">''."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USER_SEPARATOR_CHAR_FOR_GENERATED_LOGIN', 'string', NULL, 'core', 'Defines the separator character used when auto-generating user login names.', 'Read in both core/lib/functions2.lib.php:2005 and user/card.php:1079 with a default of ''.'' when not set; the value is used to join name components into the generated login string.', 'Changing this alters the format of all subsequently auto-generated logins (e.g. switching from ''j.doe'' to ''j_doe'').', 'Any single character string; default ''.''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:2005|read|$charforseparator = getDolGlobalString(\"MAIN_USER_SEPARATOR_CHAR_FOR_GENERATED_LOGIN\", ''.'');", "user/card.php:1079|read|$charforseparator = getDolGlobalString(\"MAIN_USER_SEPARATOR_CHAR_FOR_GENERATED_LOGIN\", ''.'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_ADVANCED_PERMS', 'bool', NULL, 'hrm', 'Enables advanced (granular) permission checks throughout the application, requiring dedicated validate/delete rights beyond basic create rights.', 'Checked in 327 locations. admin/security_other.php:144 shows the toggle; admin/perms.php:275 shows advanced permission labels only when enabled. Across module cards (e.g. fourn/commande/card.php:163, fichinter/card.php:1870), the pattern is: without this constant, basic create right suffices; with it, a dedicated advanced right is required.', 'Enabling this constant enforces stricter role separation, requiring users to have specific advanced rights to validate or delete records; disabling falls back to checking only the basic create right.', 'Non-empty = advanced permissions enforced; 0 or unset = basic permission model.', 0, 0, 'admin/security_other.php|admin/perms.php|admin/perms.php|admin/perms.php|admin/perms.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/security_other.php:144|check|if (!getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'')) {", "fourn/commande/card.php:163|check|$usercanvalidate = ((!getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'') && !empty($usercancreate)) || (getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'') && $user->hasRight(\"fournisseur\", \"", "fichinter/card.php:1870|check|if ((!getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'') && $user->hasRight(''ficheinter'', ''creer'')) || (getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'') && $user->hasRight(''ficheinter'', ''f", "admin/perms.php:275|check|if (getDolGlobalString(''MAIN_USE_ADVANCED_PERMS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_ALTERNATE_TRANSLATION_FOR', 'bool', NULL, 'core', 'Specifies which object fields use alternate (extra-language) translations instead of the default language.', 'COMMENTS at core/class/extralanguages.class.php lines 75-76 define the format: ''elementA:fieldname,fieldname2;elementB:...'' with example ''societe:name,town;contact:firstname,lastname''. Checked at line 103 and parsed via explode at line 104.', 'Setting this constant causes the listed fields on the specified objects to be displayed using alternate-language values from the extra-languages system. Clearing it disables alternate translation for all objects.', 'You must set variable MAIN_USE_ALTERNATE_TRANSLATION_FOR=elementA:fieldname,fieldname2;elementB:... Example: MAIN_USE_ALTERNATE_TRANSLATION_FOR=societe:name,town;contact:firstname,lastname', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/extralanguages.class.php:75  *  You must set variable MAIN_USE_ALTERNATE_TRANSLATION_FOR=elementA:fieldname,fieldname2;elementB:...", "core/class/extralanguages.class.php:76  *  Example: MAIN_USE_ALTERNATE_TRANSLATION_FOR=societe:name,town;contact:firstname,lastname", "core/class/extralanguages.class.php:103|check|if (getDolGlobalString(''MAIN_USE_ALTERNATE_TRANSLATION_FOR'')) {", "core/class/extralanguages.class.php:104|read|$tmpelement = explode('';'', getDolGlobalString(''MAIN_USE_ALTERNATE_TRANSLATION_FOR''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_AUTOWRAP_ON_FREETEXT', 'bool', NULL, 'core', 'Enables automatic text wrapping for the free text field content on PDF documents.', 'Checked at core/lib/pdf.lib.php:1619; when truthy, auto-wrap behavior is applied to the free text block. No admin UI write is present; must be set manually.', 'Enabling this causes long lines in the free text field to wrap automatically in generated PDFs.', 'Truthy string (non-empty) = enable auto-wrap on free text; absent/empty = no auto-wrap.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1619|check|if (getDolGlobalString(''MAIN_USE_AUTOWRAP_ON_FREETEXT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_BACKGROUND_ON_PDF', 'bool', NULL, 'core', 'Specifies the filename of a background image (from the company logos directory) to overlay on PDF documents.', 'Checked at core/lib/pdf.lib.php:752; when set to a non-empty value other than ''-1'', the file path is constructed as $conf->mycompany->dir_output.''/logos/'' + the constant value (line 753). An inline comment warns this option can make TCPDF generation unstable. No admin UI write is present.', 'Setting this to a valid logo filename adds a background image to all generated PDFs; setting it to ''-1'' or leaving it empty disables the background.', 'Non-empty string (not ''-1'') = filename of background image; ''-1'' or absent = no background image.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:752|check|if (getDolGlobalString(''MAIN_USE_BACKGROUND_ON_PDF'') && (getDolGlobalString(''MAIN_USE_BACKGROUND_ON_PDF'') != ''-1'')) {\t\t// Warning, this option make TCPDF generation being crazy and", "core/lib/pdf.lib.php:753|read|$filepath = $conf->mycompany->dir_output.''/logos/'' . getDolGlobalString(''MAIN_USE_BACKGROUND_ON_PDF'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_BACKGROUND_ON_PDF_ALPHA', 'bool', NULL, 'core', 'Sets the alpha (opacity) level for the background image applied to PDF documents.', 'Checked at core/lib/pdf.lib.php:756 and :760; when set, the value is used to control transparency of the background image defined by MAIN_USE_BACKGROUND_ON_PDF. No admin UI write is present.', 'Changing this value alters how transparent the PDF background image appears on generated documents.', 'Numeric alpha value (0.0–1.0 range implied); absent/empty = default opacity used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:756|check|if (getDolGlobalString(''MAIN_USE_BACKGROUND_ON_PDF_ALPHA'')) {", "core/lib/pdf.lib.php:760|check|if (getDolGlobalString(''MAIN_USE_BACKGROUND_ON_PDF_ALPHA'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_CACHE_FOR_TRANSLATION', 'bool', NULL, 'admin', 'Enables caching of translation data, typically used in conjunction with the Memcached module.', 'Checked at admin/translation.php:382 alongside memcached availability to decide whether translation cache is active. Only one occurrence found.', 'Enabling this can improve performance by caching translation lookups; disabling forces translations to be loaded fresh each request.', '0 or empty = no translation cache; 1 = enable translation cache (works with memcached or standalone)', 0, 0, 'admin/translation.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/translation.php:382|check|if (isModEnabled(''memcached'') || getDolGlobalInt(''MAIN_USE_CACHE_FOR_TRANSLATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_COMPANY_NAME_OF_CONTACT', 'bool', NULL, 'core', 'Controls whether the contact''s own company name is used in place of the thirdparty name when the contact belongs to a different company.', 'Checked across 86 occurrences in ODT and PDF generation modules; the guard condition is: $object->contact->socid != $object->thirdparty->id && (!isset($conf->global->MAIN_USE_COMPANY_NAME_OF_CONTACT) || getDolGlobalString(''MAIN_USE_COMPANY_NAME_OF_CONTACT'')).', 'Enabling this causes generated documents to display the contact''s own company name when the contact is linked to a different thirdparty; disabling it always uses the document''s thirdparty name.', '0 = always use thirdparty name; 1 or unset = use contact''s company name when contact belongs to a different company.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:325|check|if ($object->contact->socid != $object->thirdparty->id && (!isset($conf->global->MAIN_USE_COMPANY_NAME_OF_CONTACT) || getDolGlobalString(''MAIN_USE_COMPANY_NAME_OF_CONTACT''))) {", "core/lib/pdf.lib.php:663|check|if ($usecontact && is_object($targetcontact) && getDolGlobalInt(''MAIN_USE_COMPANY_NAME_OF_CONTACT'')) {", "core/modules/contract/doc/pdf_strato.modules.php:807|check|if ($usecontact && ($object->contact->socid != $object->thirdparty->id) && (!isset($conf->global->MAIN_USE_COMPANY_NAME_OF_CONTACT) || getDolGlobalString(''MAIN_USE_COMPANY_NAME_OF_CONTACT''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_CONNECT_TIMEOUT', 'bool', NULL, 'admin', 'Sets the cURL connection timeout in seconds for outbound HTTP and email collector connections.', 'Configured via admin/proxy.php:66 and read by core/lib/functions2.lib.php:2044, core/lib/geturl.lib.php:149, admin/emailcollector_card.php:572, emailcollector/class/emailcollector.class.php:1194, and paypal/lib/paypal.lib.php:506 with varying defaults of 5 or 10 seconds.', 'Increasing this value allows slower servers more time to accept connections; decreasing it causes faster failure on unresponsive hosts.', 'Integer (seconds). Defaults to 5 or 10 depending on context if unset.', 0, 0, 'admin/emailcollector_card.php|admin/proxy.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/emailcollector_card.php:572|read|$timeoutconnect = getDolGlobalInt(''MAIN_USE_CONNECT_TIMEOUT'', 5);", "core/lib/functions2.lib.php:2044|read|$timeout = getDolGlobalInt(''MAIN_USE_CONNECT_TIMEOUT'', 10); // Connection timeout", "paypal/lib/paypal.lib.php:506|read|curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, getDolGlobalInt(''MAIN_USE_CONNECT_TIMEOUT'', 5));", "admin/proxy.php:66|write|$result += dolibarr_set_const($db, ''MAIN_USE_CONNECT_TIMEOUT'', GETPOST(\"MAIN_USE_CONNECT_TIMEOUT\"), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_DOL_EVAL_NEW', 'bool', NULL, 'core', 'Switches the dol_eval function to use a newer evaluation implementation.', 'Checked at core/lib/functions.lib.php:11959. When truthy, an alternative code path for expression evaluation is taken inside dol_eval.', 'Enabling this constant activates a newer eval code path; disabling it uses the legacy implementation.', '0 or empty = legacy dol_eval implementation; any truthy value = new dol_eval implementation used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:11959|check|if (getDolGlobalString(\"MAIN_USE_DOL_EVAL_NEW\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_EXIF_ROTATION', 'bool', NULL, 'core', 'Enables automatic image rotation based on EXIF orientation data when serving image attachments.', 'Checked at document.php line 383 (for non-attachment JPEG images) and core/lib/images.lib.php line 687 (applies EXIF orientation correction); rotation is applied only when this constant is set and the image format is supported.', 'Enabling this constant causes uploaded JPEG images to be auto-rotated to their correct orientation based on EXIF data. Disabling it leaves images in their raw orientation.', 'Boolean flag; absent/falsy = EXIF rotation disabled; truthy = EXIF rotation enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["document.php:383|check|if (!$attachment && getDolGlobalString(''MAIN_USE_EXIF_ROTATION'') && image_format_supported($fullpath_original_file_osencoded) == 1) {", "core/lib/images.lib.php:687|check|if ($ort && getDolGlobalString(''MAIN_USE_EXIF_ROTATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_EXPENSE_IK', 'bool', NULL, 'expensereport', 'Enables the expense report kilometric indemnity (IK) feature, including IK tax categories and ranges in the dictionary.', 'Read in admin/dict.php:588-589 to conditionally show DICT_EXP_TAX_CAT and DICT_EXP_TAX_RANGE dictionary tabs. Checked across expensereport/card.php, expensereport/class/expensereport.class.php, user/bank.php, and core/lib/expensereport.lib.php. The comment in admin/expensereport_ik.php:26 states: ''Page to display expense tax ik. Used when MAIN_USE_EXPENSE_IK is set.''', 'Enabling this constant activates the IK indemnity workflow for expense reports, adds dictionary entries for tax categories and ranges, and shows related UI on user bank and expense card pages.', 'Any non-empty value = enable expense IK feature; empty/unset = IK feature disabled', 0, 0, 'admin/dict.php|admin/dict.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["Page to display expense tax ik. Used when MAIN_USE_EXPENSE_IK is set.", "$tabcond[DICT_EXP_TAX_CAT] = isModEnabled(''expensereport'') && getDolGlobalString(''MAIN_USE_EXPENSE_IK'');", "if (getDolGlobalString(''MAIN_USE_EXPENSE_IK'')) {", "if (!getDolGlobalString(''MAIN_USE_EXPENSE_IK'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_EXTRAFIELDS_ICON', 'bool', NULL, 'core', 'Controls whether icons are displayed alongside extra fields labels in the UI.', 'Checked (negated) at core/class/extrafields.class.php:3173; when not set, icons are shown. No admin UI; hidden setting.', 'Setting this to a truthy value hides extra field icons. Leaving unset allows icon display.', '0 or empty = extra field icons shown; non-empty = extra field icons hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/extrafields.class.php:3173|check|if (!getDolGlobalString(''MAIN_USE_EXTRAFIELDS_ICON'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_FPDF', 'bool', NULL, 'core', 'Forces the use of the FPDF library instead of TCPDF for PDF generation across all document modules.', 'Checked across 46 occurrences in PDF generation modules (e.g. recruitment, contracts, invoices, stock) at points where the PDF library is instantiated; no admin UI write is present.', 'Enabling this switches the PDF rendering engine from TCPDF to FPDF; disabling it (or leaving unset) uses TCPDF.', '0 or unset = use TCPDF; 1 = use FPDF.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:159|check|if (getDolGlobalString(''MAIN_USE_FPDF'')) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:181|check|if (getDolGlobalInt(''MAIN_USE_FPDF'')) {", "core/modules/stock/doc/pdf_standard_stock.modules.php:180|check|if (getDolGlobalString(''MAIN_USE_FPDF'')) {", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:207|check|if (getDolGlobalString(''MAIN_USE_FPDF'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_GEOPHP', 'bool', NULL, 'core', 'Enables loading of the geoPHP library for geographic/map data processing.', 'Checked at main.inc.php:1923 and :2082 to include the geoPHP library, and at core/class/extrafields.class.php:3176 to conditionally skip geo-field rendering.', 'Enabling this makes geoPHP available for geographic extra fields; disabling it suppresses geo-related features.', '0 or unset = geoPHP not loaded; 1 (truthy) = geoPHP loaded', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1923|check|if (getDolGlobalString(''MAIN_USE_GEOPHP'')) {", "main.inc.php:2082|check|if (getDolGlobalString(''MAIN_USE_GEOPHP'')) {", "core/class/extrafields.class.php:3176|check|if (!getDolGlobalString(''MAIN_USE_GEOPHP'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_HOURMIN_IN_DATE_RANGE', 'bool', NULL, 'core', 'Enables hour and minute selection in date range inputs on contract lines and object line templates.', 'When set to a non-zero integer, date range pickers in core/tpl/objectline_create.tpl.php:625 and objectline_view.tpl.php:185 switch from ''day'' format to ''dayhour'' format. Also read at contrat/card.php:95 and core/tpl/objectline_edit.tpl.php:436. No admin UI is provided.', 'Enabling this constant causes date range fields on contract lines to display and require hour/minute entry in addition to the date.', '0 or unset = date only (''day'' format); non-zero integer = date with hour and minute (''dayhour'' format).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_view.tpl.php:185|read|$format = (getDolGlobalInt(''MAIN_USE_HOURMIN_IN_DATE_RANGE'') ? ''dayhour'' : ''day'');", "core/tpl/objectline_create.tpl.php:625|read|print $form->selectDate($date_start, ''date_start'', getDolGlobalInt(''MAIN_USE_HOURMIN_IN_DATE_RANGE''), getDolGlobalInt(''MAIN_USE_HOURMIN_IN_DATE_RANGE''), 1, \"addproduct\", 1, 0);", "contrat/card.php:95|read|$usehm = getDolGlobalInt(''MAIN_USE_HOURMIN_IN_DATE_RANGE'');", "core/tpl/objectline_edit.tpl.php:436|read|$hourmin = getDolGlobalInt(''MAIN_USE_HOURMIN_IN_DATE_RANGE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_HTML5_COLOR_SELECTOR', 'bool', NULL, 'core', 'Forces use of an HTML5 native color picker instead of the JavaScript-based color selector.', 'Checked in core/class/html.formother.class.php:888; when set (non-zero), the JS/jmobile color selector is skipped in favour of the HTML5 input[type=color] element.', 'When enabled, the color picker UI switches to the browser''s native HTML5 color input, disabling the custom JS widget.', 'Int-like: 0 or unset = JS color selector used; non-zero = HTML5 native selector used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formother.class.php:888|check|if (empty($conf->dol_use_jmobile) && !empty($conf->use_javascript_ajax) && !getDolGlobalInt(''MAIN_USE_HTML5_COLOR_SELECTOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_HTML5_LIMIT_SELECTOR', 'bool', NULL, 'core', 'Switches the page-size selector to use an HTML5 number input instead of a select dropdown.', 'Checked at core/lib/functions.lib.php:7600 and 7630. When truthy, the pagination widget renders an HTML5 limit input; otherwise the default select-based widget is rendered.', 'Enabling this constant replaces the dropdown page-size selector with a free-form number input, affecting usability of pagination controls.', '0 or empty = select-based page-size selector; any truthy value = HTML5 number input selector', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:7600|check|if (getDolGlobalString(''MAIN_USE_HTML5_LIMIT_SELECTOR'')) {", "core/lib/functions.lib.php:7630|check|if (getDolGlobalString(''MAIN_USE_HTML5_LIMIT_SELECTOR'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_JQUERY_JEDITABLE', 'bool', NULL, 'core', 'Enables the jQuery jEditable plugin for in-place editing of fields in the UI.', 'When set, main.inc.php:2005 loads the jEditable JavaScript library and core/class/html.form.class.php:173 activates in-place editing widgets. The ajax endpoints core/ajax/saveinplace.php and core/ajax/loadinplace.php block requests when this constant is absent. Comments note it ''Was used in past when option "Edit In Place" is set''.', 'Enabling this constant activates in-place editing across the UI; disabling it falls back to standard form-based editing and blocks the inplace AJAX endpoints.', 'Truthy value enables in-place editing; absent or falsy disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/ajax/loadinplace.php:23  *       \t\t\tWas used in past when option \"Edit In Place\" is set (MAIN_USE_JQUERY_JEDITABLE).", "core/ajax/saveinplace.php:23  *       \t\t\tWas used in past when option \"Edit In Place\" is set (MAIN_USE_JQUERY_JEDITABLE).", "main.inc.php:2005|check|if (getDolGlobalString(''MAIN_USE_JQUERY_JEDITABLE'') && !defined(''DISABLE_JQUERY_JEDITABLE'')) {", "core/ajax/saveinplace.php:98|check|if (!getDolGlobalString(''MAIN_USE_JQUERY_JEDITABLE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_JQUERY_MULTISELECT', 'bool', NULL, 'core', 'Enables and specifies the jQuery multi-select plugin (e.g. Select2) to load globally.', 'Checked in main.inc.php:1885 and :2023 alongside the REQUIRE_JQUERY_MULTISELECT constant to decide whether to load the plugin. Read in main.inc.php:2025 and core/class/html.form.class.php:10032 to determine which plugin variant to use, defaulting to ''select2''.', 'Enabling this loads the multi-select widget globally; the value determines which plugin variant is used.', ''''' or unset = plugin not loaded globally (only per-page via REQUIRE_JQUERY_MULTISELECT); any valid plugin name = that plugin is loaded (e.g. ''select2'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1885|check|if (!defined(''DISABLE_SELECT2'') && (getDolGlobalString(''MAIN_USE_JQUERY_MULTISELECT'') || defined(''REQUIRE_JQUERY_MULTISELECT''))) {     // jQuery plugin \"mutiselect\", \"multiple-sele", "main.inc.php:2025|read|$tmpplugin = !getDolGlobalString(''MAIN_USE_JQUERY_MULTISELECT'') ? constant(''REQUIRE_JQUERY_MULTISELECT'') : getDolGlobalString(''MAIN_USE_JQUERY_MULTISELECT'');", "core/class/html.form.class.php:10032|read|$tmpplugin = getDolGlobalString(''MAIN_USE_JQUERY_MULTISELECT'', (defined(''REQUIRE_JQUERY_MULTISELECT'') ? constant(''REQUIRE_JQUERY_MULTISELECT'') : ''select2''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_JQUERY_THEME', 'bool', NULL, 'core', 'Specifies a custom jQuery UI theme to load instead of the default.', 'Checked and read in main.inc.php:1873-1874 and core/lib/security2.lib.php:306-307 to set the $jquerytheme variable used when loading jQuery UI CSS.', 'Setting this replaces the default jQuery UI theme with the named theme; unsetting it reverts to the default.', 'Any valid jQuery UI theme name string; empty/unset = default jQuery UI theme is used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:1873|check|if (getDolGlobalString(''MAIN_USE_JQUERY_THEME'')) {", "main.inc.php:1874|read|$jquerytheme = getDolGlobalString(''MAIN_USE_JQUERY_THEME'');", "core/lib/security2.lib.php:307|read|$jquerytheme = getDolGlobalString(''MAIN_USE_JQUERY_THEME'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_LOCATION_INCOTERMS_DICTIONNARY', 'bool', NULL, 'core', 'Enables the use of the location_incoterms dictionary to supply incoterm location values via AJAX.', 'Checked in core/ajax/locationincoterms.php:85 via getDolGlobalString(''MAIN_USE_LOCATION_INCOTERMS_DICTIONNARY''). When set, the AJAX handler returns data from the location_incoterms table; otherwise the request returns nothing.', 'If enabled, incoterm location fields are populated from a dedicated dictionary table. If unset, the location dictionary lookup is skipped.', 'Non-empty string = enabled. Empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/locationincoterms.php:76|read|dol_syslog(''location_incoterms call with MAIN_USE_LOCATION_INCOTERMS_DICTIONNARY=''.getDolGlobalString(''MAIN_USE_LOCATION_INCOTERMS_DICTIONNARY'', ''''));", "core/ajax/locationincoterms.php:85|check|if (getDolGlobalString(''MAIN_USE_LOCATION_INCOTERMS_DICTIONNARY'')) {   // Use location_incoterms"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_METEO_WITH_PERCENTAGE', 'bool', NULL, 'admin', 'Switches the dashboard weather/health indicator between an absolute-value mode and a percentage-based calculation mode.', 'Checked throughout admin/delais.php to toggle between two display sections (''standard'' and ''percentage'') and their corresponding threshold configuration forms. When enabled, percentage-based thresholds are used; otherwise absolute values are used. Configurable via admin/delais.php.', 'Changing this setting alters how the dashboard health indicator is calculated and displayed, and which threshold configuration UI is shown in the admin panel.', 'Boolean flag: truthy = percentage mode; 0 or unset = absolute/standard mode.', 0, 0, 'admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php|admin/delais.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/delais.php:363|read|print ''<div id=\"standard\" ''.(!getDolGlobalString(''MAIN_USE_METEO_WITH_PERCENTAGE'') ? '''' : ''style=\"display:none;\").''>'';", "admin/delais.php:383|read|print ''<div id=\"percentage\" ''.(!getDolGlobalString(''MAIN_USE_METEO_WITH_PERCENTAGE'') ? ''style=\"display:none;\"'' : '''').''>'';", "admin/delais.php:203|write|dolibarr_set_const($db, \"MAIN_USE_METEO_WITH_PERCENTAGE\", GETPOST(\"MAIN_USE_METEO_WITH_PERCENTAGE\"), ''chaine'', 0, '''', $conf->entity);", "admin/delais.php:207|check|if (getDolGlobalString(''MAIN_USE_METEO_WITH_PERCENTAGE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_NEW_SUPPLIERMOD', 'bool', NULL, 'core', 'Switches from the legacy combined ''fournisseur'' module to the new separate supplier_order and supplier_invoice modules.', 'Checked in 59 occurrences across societe/card.php, fourn/recap-fourn.php, compta/index.php, comm/index.php and many others. Each check gates features on whether the old ''fournisseur'' module (without this constant) or the new split modules (with this constant) are in use.', 'When set, the application uses the dedicated supplier_order and supplier_invoice modules instead of the legacy fournisseur module; changing this affects which menus, tabs, and features are available.', '0 or unset = legacy fournisseur module used; non-empty = new separate supplier modules used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/recap-fourn.php:95|check|if ((isModEnabled(\"fournisseur\") && $user->hasRight(\"fournisseur\", \"facture\", \"lire\") && !getDolGlobalString(''MAIN_USE_NEW_SUPPLIERMOD'')) || (isModEnabled(\"supplier_invoice\") && $u", "societe/card.php:1514|check|if ((isModEnabled(\"fournisseur\") && $user->hasRight(''fournisseur'', ''lire'') && !getDolGlobalString(''MAIN_USE_NEW_SUPPLIERMOD'')) || (isModEnabled(\"supplier_order\") && $user->hasRight", "compta/index.php:299|check|if ((isModEnabled(''fournisseur'') && !getDolGlobalString(''MAIN_USE_NEW_SUPPLIERMOD'') && $user->hasRight(\"fournisseur\", \"facture\", \"lire\")) || (isModEnabled(''supplier_invoice'') && $u"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_OLD_SEARCH_FORM', 'bool', NULL, 'core', 'Forces the legacy search form instead of the modern AJAX search box.', 'Written programmatically at main.inc.php:3252 and checked at :3259 and :3285 to switch between the old and new search form implementations.', 'Enabling this reverts the top search box to the legacy form; disabling or unsetting it uses the modern AJAX search.', '0 or unset = modern AJAX search used; 1 = legacy search form used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3252|write|$conf->global->MAIN_USE_OLD_SEARCH_FORM = 1;", "main.inc.php:3259|check|if (!empty($conf->use_javascript_ajax) && !getDolGlobalString(''MAIN_USE_OLD_SEARCH_FORM'')) {", "main.inc.php:3285|read|} elseif ($conf->use_javascript_ajax && getDolGlobalString(''MAIN_USE_OLD_SEARCH_FORM'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_PROPAL_REFCLIENT_FOR_ORDER', 'bool', NULL, 'commande', 'Copies the client reference from the source proposal into the order when creating an order from a proposal.', 'Checked in commande/card.php:2322 alongside checks for a non-empty $origin and $originid, meaning it only applies when an order is created from an existing source document. No admin UI write is present.', 'Setting this constant causes the client reference from the originating proposal to be carried over to the new order. Leaving it unset omits this automatic copy.', 'Truthy = proposal client reference copied to order; falsy or unset = not copied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:2322|check|if (getDolGlobalString(''MAIN_USE_PROPAL_REFCLIENT_FOR_ORDER'') && !empty($origin) && !empty($originid)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_RESPONSE_TIMEOUT', 'bool', NULL, 'admin', 'Sets the cURL response (read) timeout in seconds for outbound HTTP and email collector connections.', 'Configured via admin/proxy.php:67 and overridden in-memory at admin/system/dolibarr.php:133 and admin/tools/update.php:103. Read by core/lib/functions2.lib.php:2045, core/lib/geturl.lib.php:150, admin/emailcollector_card.php:573, and paypal/lib/paypal.lib.php:507 with a default of 20–30 seconds.', 'Increasing this value allows more time for slow responses; decreasing it may cause premature timeouts on long-running requests.', 'Integer (seconds). Defaults to 20 or 30 depending on context if unset.', 0, 0, 'admin/emailcollector_card.php|admin/proxy.php|admin/system/dolibarr.php|admin/tools/update.php|admin/proxy.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/dolibarr.php:133|write|$conf->global->MAIN_USE_RESPONSE_TIMEOUT = 10;", "core/lib/functions2.lib.php:2045|read|$response_timeout = getDolGlobalInt(''MAIN_USE_RESPONSE_TIMEOUT'', 30); // Response timeout", "paypal/lib/paypal.lib.php:507|read|curl_setopt($ch, CURLOPT_TIMEOUT, getDolGlobalInt(''MAIN_USE_RESPONSE_TIMEOUT'', 30));", "admin/emailcollector_card.php:573|read|$timeoutread = getDolGlobalInt(''MAIN_USE_RESPONSE_TIMEOUT'', 20);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TITLE_FOR_CONTACT', 'bool', NULL, 'contact', 'Enables display and editing of a civility/title field on contact cards.', 'Checked in contact/card.php:711 and contact/card.php:1019 to conditionally render the title field in view and edit modes.', 'Enabling this constant adds a civility or title field to contact record forms, allowing honorifics to be stored per contact.', 'Empty/not set = title field hidden; any truthy string = title field shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/card.php:711|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_CONTACT'')) {", "contact/card.php:1019|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_CONTACT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TITLE_FOR_MEMBER', 'bool', NULL, 'adherents', 'Enables a civility/title field on member creation and editing forms.', 'Checked at adherents/card.php:1192 and adherents/card.php:1429; when set, the title/civility selector is rendered in the member form. No admin UI is provided.', 'Enabling this constant adds a title or civility field to the member creation and editing forms.', 'Non-empty/truthy = title field shown; empty/unset = title field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:1192|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_MEMBER'')) {", "adherents/card.php:1429|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_MEMBER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TITLE_FOR_USER', 'bool', NULL, 'user', 'Enables the display and editing of a title/civility field on user profile pages.', 'Checked in user/card.php at lines 1032 and 2619. When set, the title field is rendered in user creation and editing forms.', 'Enabling this constant adds a title/civility input to user profile forms; leaving it unset hides the title field.', 'Truthy value to show title field; empty or unset to hide it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/card.php:1032|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_USER'')) {", "user/card.php:2619|check|if (getDolGlobalString(''MAIN_USE_TITLE_FOR_USER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TOP_MENU_IMPORT_FILE', 'bool', NULL, 'core', 'Enables or specifies a file-import button/URL in the top navigation menu bar.', 'Checked at main.inc.php:2250 and core/upload_page.php:90. When the value is a non-numeric string, it is used directly as the upload page URL (main.inc.php:2781, core/upload_page.php:91). The comment at main.inc.php:2763 documents the function called when set to 1 or a URL string.', 'Setting to 1 enables the default import page; setting to a URL string uses that URL as the import destination; unsetting hides the button.', '0 or unset = import button hidden; 1 = default import page used; non-numeric string = URL used as the import page', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2763  * Called when MAIN_USE_TOP_MENU_IMPORT_FILE is set to 1 or to an URL string.", "main.inc.php:2780|check|if (!is_numeric(getDolGlobalString(''MAIN_USE_TOP_MENU_IMPORT_FILE''))) {", "main.inc.php:2781|read|$urlforuploadpage = getDolGlobalString(''MAIN_USE_TOP_MENU_IMPORT_FILE'');", "core/upload_page.php:90|check|if (getDolGlobalString(''MAIN_USE_TOP_MENU_IMPORT_FILE'') && !is_numeric(getDolGlobalString(''MAIN_USE_TOP_MENU_IMPORT_FILE''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TOP_MENU_QUICKADD_DROPDOWN', 'bool', NULL, 'core', 'Enables a quick-add dropdown button in the top navigation menu bar.', 'Checked at main.inc.php:2242 to include the quick-add dropdown, and at theme/eldy/style.css.php:374 for related CSS. The comment at main.inc.php:2693 documents the function called when this option is set.', 'Enabling this adds a quick-add dropdown to the top menu; disabling or unsetting it hides it.', '0 or unset = quick-add dropdown hidden; 1 (truthy) = quick-add dropdown shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2693  * Called when option MAIN_USE_TOP_MENU_QUICKADD_DROPDOWN is set", "main.inc.php:2242|check|if (getDolGlobalString(''MAIN_USE_TOP_MENU_QUICKADD_DROPDOWN'')) {", "theme/eldy/style.css.php:374|check|if (getDolGlobalString(''MAIN_USE_TOP_MENU_QUICKADD_DROPDOWN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_TOP_MENU_SEARCH_DROPDOWN', 'bool', NULL, 'theme', 'When enabled, replaces the default search bar with a dropdown search widget in the top menu.', 'Checked in main.inc.php:2237, :3249, theme/eldy/global.inc.php:2595, theme/eldy/style.css.php:377, and theme/md/style.css.php:4116 to conditionally render the dropdown search UI. Five occurrences across four files. No admin UI write is present.', 'Enabling this constant activates a dropdown search widget in the top navigation menu and suppresses the standard inline search.', 'Boolean flag; unset or 0 = standard search bar; any truthy value = dropdown search widget.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:2237|check|if (getDolGlobalString(''MAIN_USE_TOP_MENU_SEARCH_DROPDOWN'')) {", "main.inc.php:3249|check|if (!getDolGlobalString(''MAIN_USE_TOP_MENU_SEARCH_DROPDOWN'')) {", "theme/eldy/global.inc.php:2595|check|<?php if (getDolGlobalString(''MAIN_USE_TOP_MENU_SEARCH_DROPDOWN'')) { ?>", "theme/eldy/style.css.php:377|check|if (getDolGlobalString(''MAIN_USE_TOP_MENU_SEARCH_DROPDOWN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_VAT_OF_PRODUCT_FOR_INDIVIDUAL_CUSTOMER_OUT_OF_EEC', 'bool', NULL, 'core', 'Applies the product''s own VAT rate to individual (non-company) customers located outside the EEC.', 'Checked at core/lib/functions.lib.php:8703. The comment at line 8702 states ''I don''t see any use case that need this rule, this case is on only if MAIN_USE_VAT_OF_PRODUCT_FOR_INDIVIDUAL_CUSTOMER_OUT_OF_EEC set''.', 'Enabling this constant activates an otherwise-unused VAT rule that applies the product''s VAT rate to non-EEC individual customers; without it the standard out-of-EEC VAT logic applies.', '0 or empty = standard VAT logic for individual customers outside EEC; any truthy value = product VAT rate applied for those customers', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:8702  // I don''t see any use case that need this rule, this case is on only if MAIN_USE_VAT_OF_PRODUCT_FOR_INDIVIDUAL_CUSTOMER_OUT_OF_EEC set", "core/lib/functions.lib.php:8703|check|if (empty($vatrule) && getDolGlobalString(''MAIN_USE_VAT_OF_PRODUCT_FOR_INDIVIDUAL_CUSTOMER_OUT_OF_EEC'') && empty($buyer_in_cee)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_VAT_ZERO_FOR_COMPANIES_IN_EEC_EVEN_IF_VAT_ID_UNKNOWN', 'bool', NULL, 'core', 'Forces VAT rate to zero for EEC companies even when their VAT ID is unknown or unverified.', 'Checked at core/lib/functions.lib.php:8601 and 8680. When this constant is absent or falsy, EEC companies without a known VAT ID are subject to normal VAT rules; when truthy, zero VAT is applied regardless.', 'Enabling this constant reduces VAT charged to EEC companies lacking a verified VAT ID; disabling it ensures VAT is applied normally in those cases.', '0 or empty = standard VAT rules apply for EEC companies without VAT ID; any truthy value = zero VAT forced for EEC companies even without VAT ID', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:8601|check|if ($isacompany && !getDolGlobalString(''MAIN_USE_VAT_ZERO_FOR_COMPANIES_IN_EEC_EVEN_IF_VAT_ID_UNKNOWN'')) {", "core/lib/functions.lib.php:8680|check|if ($isacompany && !getDolGlobalString(''MAIN_USE_VAT_ZERO_FOR_COMPANIES_IN_EEC_EVEN_IF_VAT_ID_UNKNOWN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_ZIPARCHIVE_FOR_ZIP_COMPRESS', 'bool', NULL, 'core', 'Forces use of PHP''s ZipArchive class for creating ZIP archives instead of the default method.', 'In core/lib/files.lib.php, when ZipArchive class exists and this constant is set, ZipArchive is used for compression. A commented-out line (2818) shows the same pattern was considered for decompression but not activated. No admin UI write; hidden setting.', 'Enabling this constant switches ZIP creation to use PHP''s ZipArchive extension; disabling it uses the default compression method.', 'Non-empty (truthy) enables ZipArchive for compression; empty or undefined uses the default method.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2543|check|if (class_exists(''ZipArchive'') && getDolGlobalString(''MAIN_USE_ZIPARCHIVE_FOR_ZIP_COMPRESS'')) {", "//if (class_exists(''ZipArchive'') && !empty($conf->global->MAIN_USE_ZIPARCHIVE_FOR_ZIP_COMPRESS))"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_ZIPARCHIVE_FOR_ZIP_UNCOMPRESS', 'bool', NULL, 'core', 'Controls whether PHP''s ZipArchive class or PclZip is used for extracting ZIP archives.', 'In core/lib/files.lib.php, when ODTPHP_PATHTOPCLZIP is defined and this constant is NOT set, PclZip is used for decompression. Setting this constant causes ZipArchive to be preferred over PclZip. No admin UI write; hidden setting.', 'Enabling this constant uses ZipArchive for ZIP extraction when both libraries are available; disabling it (or leaving unset) uses PclZip when ODTPHP_PATHTOPCLZIP is defined.', 'Non-empty (truthy) prefers ZipArchive for decompression; empty or undefined prefers PclZip when available.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2660|check|if (defined(''ODTPHP_PATHTOPCLZIP'') && !getDolGlobalString(''MAIN_USE_ZIPARCHIVE_FOR_ZIP_UNCOMPRESS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_USE_ZIPTOWN_DICTIONNARY', 'bool', NULL, 'core', 'Controls whether zip/town lookups use the official public zip-town dictionary or company address data.', 'Checked and logged in core/ajax/ziptown.php (lines 55, 67, 80, 94). The comment at line 56 states verbatim: ''If MAIN_USE_ZIPTOWN_DICTIONNARY is set, we make a search into public data (official list of zip/town). If not we search into company data, so we must check we have read permission.''', 'Setting this switches the zip/town autocomplete source from company records (requiring read permission) to the public official dictionary.', 'Empty/unset = search company address data (requires read permission); any non-empty string = search official public zip/town dictionary.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/ziptown.php:56  // If MAIN_USE_ZIPTOWN_DICTIONNARY is set, we make a search into public data (official list of zip/town). If not we search into company data, so we must check we have read permission.", "core/ajax/ziptown.php:55|check|if (!getDolGlobalString(''MAIN_USE_ZIPTOWN_DICTIONNARY'')) {", "core/ajax/ziptown.php:80|check|if (getDolGlobalString(''MAIN_USE_ZIPTOWN_DICTIONNARY'')) {   // Use zip-town table"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VAT_DEFAULT_IF_AUTODETECT_FAILS', 'string', NULL, 'core', 'Sets the fallback VAT rate used when automatic VAT detection cannot determine the correct rate.', 'When VAT auto-detection fails, the system reads this constant to supply a default tax rate (core/lib/functions.lib.php:8471). Setting it to ''none'' suppresses any default rate, as forced in expense reports (expensereport/card.php:2666). Used in both the form helper (core/class/html.form.class.php:7565) and AJAX product lookups (comm/remx.php:476).', 'Setting to ''none'' prevents any VAT from being pre-filled when detection fails. Setting to a numeric rate string causes that rate to be applied automatically across invoices, proposals, and expense reports.', '''none'' = no default VAT applied; a numeric string (e.g. ''20'') = that rate is used as fallback', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["expensereport/card.php:2665  // If option to have no default VAT on expense report is on, we force MAIN_VAT_DEFAULT_IF_AUTODETECT_FAILS", "core/lib/functions.lib.php:8466  // Forced value if autodetect fails. MAIN_VAT_DEFAULT_IF_AUTODETECT_FAILS can be", "core/class/html.form.class.php:7562  // We will use the rate defined into MAIN_VAT_DEFAULT_IF_AUTODETECT_FAILS", "expensereport/card.php:2666|write|$conf->global->MAIN_VAT_DEFAULT_IF_AUTODETECT_FAILS = ''none'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VAT_LABEL_IS_POSITIVE_RATES', 'string', NULL, 'core', 'Forces the VAT selector to display only positive rates, mirroring behaviour already applied for Indian companies.', 'Checked at core/class/html.form.class.php:7623 alongside the country code ''IN'' check. When the company is Indian OR this constant is set, positive-rate display logic is applied.', 'Enabling causes the VAT label/selector to show only positive rates globally. Disabling restricts that behaviour to Indian companies.', 'Truthy = display positive VAT rates label globally; empty/unset = apply only for country_code == ''IN''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7623|check|if ($mysoc->country_code == ''IN'' || getDolGlobalString(''MAIN_VAT_LABEL_IS_POSITIVE_RATES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VERSION_FIRST_INSTALL', 'string', NULL, 'core', 'Records the Dolibarr version at which this instance was first installed.', 'Written in install/step5.php at line 333 during first install inside a dedicated transaction (comment: ''Insert MAIN_VERSION_FIRST_INSTALL in a dedicated transaction. So if it fails (when first install was already done), we can do other following requests.''). Read in install/upgrade2.php at line 5400 with DOL_VERSION as fallback.', 'This constant is set once at installation and used by upgrade logic to determine the original install version. Modifying it manually could affect upgrade path decisions.', 'Dolibarr version string (e.g. ''17.0.0'') set at first installation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Insert MAIN_VERSION_FIRST_INSTALL in a dedicated transaction. So if it fails (when first install was already done), we can do other following requests.", "$conf->global->MAIN_VERSION_FIRST_INSTALL = $targetversion;", "$firstInstallVersion = getDolGlobalString(''MAIN_VERSION_FIRST_INSTALL'', DOL_VERSION);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VERSION_LAST_INSTALL', 'string', NULL, 'core', 'Stores the Dolibarr version string at the time of the last fresh installation.', 'Set by install/step5.php during first install as documented in comments at lines 32 and 87. Read extensively across admin/system/dolibarr.php, blockedlog/admin/filecheck.php, and install/check.php (18+ occurrences) to detect version mismatches and warn when an update process may be required.', 'If this value does not match DOL_VERSION, admin pages display a warning that the update process may need to be run. It is used by filecheck to compare against the running version.', 'A Dolibarr version string (e.g. ''18.0.1''); set automatically during installation.', 0, 0, 'blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php|admin/system/dolibarr.php|admin/system/dolibarr.php|admin/system/dolibarr.php|admin/system/dolibarr.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["*         It set the value for MAIN_VERSION_LAST_INSTALL", "// Define targetversion used to update MAIN_VERSION_LAST_INSTALL for first install", "if (DOL_VERSION != getDolGlobalString(''MAIN_VERSION_LAST_INSTALL'')) {", "print '' ''.img_warning($langs->trans(\"RunningUpdateProcessMayBeRequired\", DOL_VERSION, getDolGlobalString(''MAIN_VERSION_LAST_INSTALL'')));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VERSION_LAST_UPGRADE', 'string', NULL, 'core', 'Records the Dolibarr version string at which the last database upgrade was successfully completed.', 'Written by install/step5.php during installation and upgrade processes. Checked in admin/system/dolibarr.php:108/:115 and blockedlog/admin/filecheck.php:90/:97 to detect version mismatches requiring an upgrade run. COMMENTS confirm: ''It updates the value for MAIN_VERSION_LAST_UPGRADE'' and ''Current version is $conf->global->MAIN_VERSION_LAST_UPGRADE''.', 'If this value does not match DOL_VERSION, the admin UI displays a warning that the upgrade process must be run; it is set automatically by the installer and should not be changed manually.', 'Version string matching Dolibarr release format (e.g., ''19.0.0''); set automatically by install/upgrade process', 0, 0, 'blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php|blockedlog/admin/filecheck.php|admin/system/dolibarr.php|admin/system/dolibarr.php|admin/system/dolibarr.php|admin/system/dolibarr.php|admin/system/dolibarr.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["install/step5.php:36  *         It updates the value for MAIN_VERSION_LAST_UPGRADE.", "install/upgrade2.php:329  // Current version is $conf->global->MAIN_VERSION_LAST_UPGRADE", "admin/system/dolibarr.php:115|check|if (DOL_VERSION != getDolGlobalString(''MAIN_VERSION_LAST_UPGRADE'')) {", "blockedlog/admin/filecheck.php:97|check|if (in_array(versioncompare(versiondolibarrarray(), preg_split(''/[\\-\\.]/'', getDolGlobalString(''MAIN_VERSION_LAST_UPGRADE''))), array(-2, -1, 1, 2))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VIEW_LINE_NUMBER', 'string', NULL, 'core', 'Adds a line-number column to document and list line item tables.', 'Checked in 48 locations across template files and card pages (e.g. reception/tpl/objectline_title.tpl.php:69, reception/card.php:2425, variants/tpl/productattributevalueline_title.tpl.php:49). A comment at core/class/commonobject.class.php:9790 notes that an additional td column is output when this constant is set.', 'Enabling this constant prepends a row-number column to line item tables on cards and templates throughout the application.', 'Non-empty = line number column shown; 0 or unset = no line number column.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/tpl/objectline_title.tpl.php:69|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER'')) {", "reception/card.php:2425|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER'')) {", "variants/tpl/productattributevalueline_title.tpl.php:49|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER'')) {", "// a first td column was already output (and may be another on before if MAIN_VIEW_LINE_NUMBER set), so this td is the next one"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VIEW_LINE_NUMBER_IN_LIST', 'string', NULL, 'compta', 'Displays a line number column in list views throughout Dolibarr.', 'Checked in 20 occurrences across compta/tva/list.php, fourn/paiement/list.php, compta/facture/list.php, compta/sociales/list.php, and compta/bank/various_payment/list.php among others. Each check gates the rendering of a line number column.', 'When enabled, list pages show an additional column with the sequential row number, aiding navigation in long lists.', '0 or unset = no line numbers; non-empty = line numbers shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/tva/list.php:431|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER_IN_LIST'')) {", "fourn/paiement/list.php:429|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER_IN_LIST'')) {", "compta/facture/list.php:2444|check|if (getDolGlobalString(''MAIN_VIEW_LINE_NUMBER_IN_LIST'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VOLUME_DEFAULT_ROUND', 'string', NULL, 'expedition', 'Sets the default rounding precision for volume display in dimension summary sections.', 'Passed as the rounding parameter to showDimensionInBestUnit() in reception/card.php:2269 and 2260, expedition/card.php:3024 and 3015, expedition/shipment.php:512, comm/propal/card.php:3326, and commande/card.php:3235. The default fallback is -1. No admin UI write path exists.', 'Changing this value alters how many decimal places are shown for volume totals on reception, shipment, proposal, and order pages.', 'Integer precision value passed to showDimensionInBestUnit(); default fallback is -1', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:2269|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));", "expedition/card.php:3024|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));", "commande/card.php:3235|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_VOLUME_DEFAULT_UNIT', 'string', NULL, 'expedition', 'Sets the default unit for volume display in dimension summary sections.', 'Passed as the forceunitoutput parameter to showDimensionInBestUnit() across reception, expedition, proposals, and orders (7 occurrences). The default fallback is ''no''. No admin UI write path exists.', 'Changing this value forces volume totals to be displayed in a specific unit; ''no'' lets the function select the most appropriate unit.', '''no'' or numeric string (-3, -6, ...) compared to $unit; default fallback is ''no''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:2269|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));", "expedition/card.php:3024|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));", "commande/card.php:3235|read|print showDimensionInBestUnit($totalVolume, 0, \"volume\", $langs, getDolGlobalInt(''MAIN_VOLUME_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_VOLUME_DEFAULT_UNIT'', ''no''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_WAREHOUSE_LIST_DISPLAY_MODE', 'bool', NULL, 'product', 'Controls the display mode of the warehouse list in the product warehouse selector.', 'Checked in product/class/html.formproduct.class.php:262 and :266 to determine whether warehouses are shown flat or filtered by parent. The comment at line 247 states: ''Set Hidden conf MAIN_WAREHOUSE_LIST_DISPLAY_MODE at 0 || 1 || 2 to unlock display''.', 'Changing this constant alters how warehouses are presented in the selector: flat listing, hierarchical, or filtered by parent.', 'Set Hidden conf MAIN_WAREHOUSE_LIST_DISPLAY_MODE at 0 || 1 || 2 to unlock display', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/class/html.formproduct.class.php:247  * Set Hidden conf MAIN_WAREHOUSE_LIST_DISPLAY_MODE at 0 || 1 || 2 to unlock display", "product/class/html.formproduct.class.php:262|check|if (empty($tab[''parent_id'']) || getDolGlobalInt(''MAIN_WAREHOUSE_LIST_DISPLAY_MODE'') === 1) {", "product/class/html.formproduct.class.php:266|check|if (getDolGlobalInt(''MAIN_WAREHOUSE_LIST_DISPLAY_MODE'') !== 2 || (getDolGlobalInt(''MAIN_WAREHOUSE_LIST_DISPLAY_MODE'') === 2 && empty($this->cache_warehouses[$tab[''parent_id'']][''par"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_WEIGHT_DEFAULT_ROUND', 'string', NULL, 'expedition', 'Sets the default rounding precision for weight display in dimension summary sections.', 'Passed as the rounding parameter to showDimensionInBestUnit() in reception/card.php:2208, comm/propal/card.php:3320, expedition/shipment.php:508, expedition/card.php:2963, expedition/list.php:1630, and commande/card.php:3229. The default fallback is -1. No admin UI write path exists.', 'Changing this value alters how many decimal places are shown for weight totals on reception, shipment, proposal, and order pages.', 'Integer precision value passed to showDimensionInBestUnit(); default fallback is -1', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:2208|read|print showDimensionInBestUnit($totalWeight, 0, \"weight\", $langs, getDolGlobalInt(''MAIN_WEIGHT_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_WEIGHT_DEFAULT_UNIT'', ''no''));", "expedition/card.php:2963|read|print showDimensionInBestUnit($totalWeight, 0, \"weight\", $langs, getDolGlobalInt(''MAIN_WEIGHT_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_WEIGHT_DEFAULT_UNIT'', ''no''));", "commande/card.php:3229|read|print showDimensionInBestUnit($totalWeight, 0, \"weight\", $langs, getDolGlobalInt(''MAIN_WEIGHT_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_WEIGHT_DEFAULT_UNIT'', ''no''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_WEIGHT_DEFAULT_UNIT', 'string', NULL, 'expedition', 'Sets the default unit for weight display in dimension summary sections.', 'Passed as the forceunitoutput parameter to showDimensionInBestUnit() across reception, expedition, proposals, and orders. Documented in core/lib/functions.lib.php:8013 as ''no'' or a numeric exponent (-3, -6, ...) relative to the base unit. The default fallback is ''no''.', 'Changing this value forces weight totals to be displayed in a specific unit rather than automatically chosen; ''no'' lets the function select the most appropriate unit.', '''no'' or numeric string (-3, -6, ...) compared to $unit (as documented in core/lib/functions.lib.php:8013); default fallback is ''no''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* @param   string      $forceunitoutput    ''no'' or numeric (-3, -6, ...) compared to $unit (In most case, this value is value defined into $conf->global->MAIN_WEIGHT_DEFAULT_UNIT)", "reception/card.php:2208|read|print showDimensionInBestUnit($totalWeight, 0, \"weight\", $langs, getDolGlobalInt(''MAIN_WEIGHT_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_WEIGHT_DEFAULT_UNIT'', ''no''));", "expedition/card.php:2963|read|print showDimensionInBestUnit($totalWeight, 0, \"weight\", $langs, getDolGlobalInt(''MAIN_WEIGHT_DEFAULT_ROUND'', -1), getDolGlobalString(''MAIN_WEIGHT_DEFAULT_UNIT'', ''no''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAIN_WORKBOARD_SHOW_TOTAL_WO_TAX', 'bool', NULL, 'index.php', 'Shows the pre-tax (excluding VAT) total amount in workboard board blocks instead of the tax-inclusive amount.', 'Checked in index.php:666 and index.php:782 alongside $board->total > 0 to decide whether to display the tax-exclusive total column. No admin UI is present.', 'Enabling this constant causes workboard financial blocks to display amounts excluding tax.', 'Boolean flag: truthy = show pre-tax totals; 0 or unset = show default totals.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:666|check|if ($board->total > 0 && getDolGlobalString(''MAIN_WORKBOARD_SHOW_TOTAL_WO_TAX'')) {", "index.php:782|check|if ($board->total > 0 && getDolGlobalString(''MAIN_WORKBOARD_SHOW_TOTAL_WO_TAX'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MARGIN_METHODE_FOR_DISCOUNT', 'string', NULL, 'core', 'Selects the method used to account for global discounts when calculating margins.', 'Written and read via the admin UI at margin/admin/margin.php (lines 75, 214) and evaluated in core/class/html.formmargin.class.php (lines 125–148). Value ''1'' treats global discount as a product, ''2'' as a service, ''3'' applies it only on total.', 'Changing the method changes how global discounts affect margin calculations. Method 1 and 2 distribute the discount as a product or service line respectively; method 3 applies it only to the overall total.', '1 = remise globale considérée comme produit; 2 = remise globale considérée comme service; 3 = remise globale prise en compte uniqt sur total.', 0, 0, 'margin/admin/margin.php|margin/admin/margin.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formmargin.class.php:126|check|if (getDolGlobalString(''MARGIN_METHODE_FOR_DISCOUNT'') == ''1'') { // remise globale considérée comme produit", "core/class/html.formmargin.class.php:138|read|} elseif (getDolGlobalString(''MARGIN_METHODE_FOR_DISCOUNT'') == ''2'') { // remise globale considérée comme service", "core/class/html.formmargin.class.php:148|read|} elseif (getDolGlobalString(''MARGIN_METHODE_FOR_DISCOUNT'') == ''3'') { // remise globale prise en compte uniqt sur total", "margin/admin/margin.php:75|write|if (dolibarr_set_const($db, ''MARGIN_METHODE_FOR_DISCOUNT'', GETPOST(''MARGIN_METHODE_FOR_DISCOUNT''), ''chaine'', 0, '''', $conf->entity) <= 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MARGIN_SHOW_MARGIN_ON_PAYMENT', 'bool', NULL, 'compta', 'Enables display of margin information on payment card pages when the margin module is active.', 'Checked in compta/paiement/card.php alongside isModEnabled(''margin'') to conditionally render margin-related sections. No admin UI is present; must be set directly in the database.', 'When enabled with the margin module active, margin data is shown on payment cards. When disabled or unset, margin sections are hidden on payment pages.', 'Truthy integer/string (margin shown) or empty/unset (margin hidden).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["compta/paiement/card.php:523|check|if (isModEnabled(''margin'') && getDolGlobalInt(''MARGIN_SHOW_MARGIN_ON_PAYMENT'')) {", "compta/paiement/card.php:546|check|if (isModEnabled(''margin'') && getDolGlobalInt(''MARGIN_SHOW_MARGIN_ON_PAYMENT'')) {", "compta/paiement/card.php:580|check|if (isModEnabled(''margin'') && getDolGlobalInt(''MARGIN_SHOW_MARGIN_ON_PAYMENT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MARGIN_SHOW_ON_CONTRACT', 'bool', NULL, 'contrat', 'Enables display of margin information on the contract card when the Margin module is active.', 'All five occurrences in contrat/card.php check both isModEnabled(''margin'') and this constant before rendering margin-related sections (e.g., at lines 1756, 1653, 1786, 1920, 1961). No admin UI is provided.', 'Setting this constant causes margin data to appear on the contract detail page, provided the Margin module is also enabled.', 'Non-empty/truthy = margin sections shown on contract card; empty/unset = margin sections hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/card.php:1756|check|if (isModEnabled(''margin'') && getDolGlobalString(''MARGIN_SHOW_ON_CONTRACT'')) {", "contrat/card.php:1653|check|if (isModEnabled(''margin'') && getDolGlobalString(''MARGIN_SHOW_ON_CONTRACT'')) {", "contrat/card.php:1786|check|if (isModEnabled(''margin'') && getDolGlobalString(''MARGIN_SHOW_ON_CONTRACT'')) {", "contrat/card.php:1920|check|if (isModEnabled(''margin'') && getDolGlobalString(''MARGIN_SHOW_ON_CONTRACT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MARGIN_TOP_ZERO_UL', 'string', NULL, 'core', 'Removes the top margin from unordered list elements rendered in PDF documents.', 'Checked at core/lib/pdf.lib.php:1868; when truthy, CSS top-margin for UL elements is set to zero. No admin UI write is present; must be set manually.', 'Enabling this eliminates the top margin above unordered lists in PDF content, resulting in tighter vertical spacing.', 'Truthy string (non-empty) = set UL top margin to zero; absent/empty = default UL top margin used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1868|check|if (getDolGlobalString(''MARGIN_TOP_ZERO_UL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MARGIN_TYPE', 'string', NULL, 'margin', 'Determines the cost basis used for margin calculations across invoices, orders, and proposals.', 'Set via margin/admin/margin.php:80 and checked in 27+ locations. Comments at core/class/commonobject.class.php:10017-10018 and margin/admin/margin.php describe the values: ''1'' uses the buy price, ''pmp'' uses the weighted average price (prix moyen pondere), and ''costprice'' uses the product''s defined cost price. Admin UI available at margin/admin/margin.php.', 'Changing this value switches the cost reference used for margin computation across all document types; incorrect configuration leads to inaccurate margin reporting.', '''1'' = use buy price; ''pmp'' = use weighted average price (pmp); ''costprice'' = use product cost price.', 0, 0, 'margin/admin/margin.php|margin/admin/margin.php|margin/admin/margin.php|margin/admin/margin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:10017  *   elseif calculation MARGIN_TYPE = ''costprice'' and costprice is defined, use costprice as buyprice", "core/class/commonobject.class.php:10018  *\t elseif calculation MARGIN_TYPE = ''pmp'' and pmp is calculated, use pmp as buyprice", "margin/admin/margin.php:128|check|if (getDolGlobalString(''MARGIN_TYPE'') == ''1'') {", "margin/admin/margin.php:135|check|if (getDolGlobalString(''MARGIN_TYPE'') == ''pmp'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MASS_ACTION_EMAIL_ON_DIFFERENT_THIRPARTIES_ADD_CUSTOM_EMAIL', 'string', NULL, 'core', 'Enables adding a custom email address when sending mass-action emails to different third parties.', 'Checked once in core/class/html.formmail.class.php:836. No admin UI write is present.', 'Enabling this allows users to specify a custom email in mass-action email forms targeting multiple third parties; disabling it hides this option.', 'truthy = show custom email input; empty/not set = hide custom email input', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.formmail.class.php:836|check|if (getDolGlobalString(''MASS_ACTION_EMAIL_ON_DIFFERENT_THIRPARTIES_ADD_CUSTOM_EMAIL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAXREFONDOC', 'string', NULL, 'commande', 'Sets the maximum number of linked order references displayed on documents and list views.', 'Checked in fourn/commande/list.php:601, core/lib/pdf.lib.php:3002, and commande/list.php:462 and :668 via getDolGlobalInt with a default of 10. No admin UI is configured.', 'Increasing this value allows more linked order references to be shown on PDFs and list views. Setting to 0 or a negative value suppresses linked-order display.', 'Integer; default is 10.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/list.php:601|check|if ($currentIndex <= (getDolGlobalInt(\"MAXREFONDOC\") ? getDolGlobalInt(\"MAXREFONDOC\") : 10)) {", "core/lib/pdf.lib.php:3002|check|if (count($objects) > 1 && count($objects) <= getDolGlobalInt(\"MAXREFONDOC\", 10) && !getDolGlobalString($optiontohidelinkedorders)) {", "commande/list.php:668|check|if ($currentIndex <= getDolGlobalInt(\"MAXREFONDOC\", 10)) {", "commande/list.php:462|check|if (empty($objecttmp->note_public) && getDolGlobalInt(\"MAXREFONDOC\", 10)>0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAX_EXTRAFIELDS_TO_SHOW_IN_TOOLTIP', 'bool', NULL, 'core', 'Sets the maximum number of extra fields displayed in object tooltips.', 'Read in core/class/commonobject.class.php:1021 with a default of 3. Controls how many extrafields are rendered inside hover tooltips.', 'Increasing the value shows more extrafield data in tooltips; decreasing it reduces tooltip verbosity.', 'Integer (default: 3)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:1021|read|$MAX_EXTRAFIELDS_TO_SHOW_IN_TOOLTIP = getDolGlobalInt(''MAX_EXTRAFIELDS_TO_SHOW_IN_TOOLTIP'', 3);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAX_FOR_TEST_EXPORT', 'string', NULL, 'exports', 'Developer-only constant to limit export size during testing on large databases; currently inactive (commented out).', 'Referenced only in a comment at exports/class/export.class.php:764: ''//$MAXFORTEST = getDolGlobalInt("MAX_FOR_TEST_EXPORT"); // For test on large database, we can set it to a non zero value and uncomment code that use it later to limit the export size''. The code reading this constant is commented out.', 'This constant has no active effect in the current codebase as the code using it is commented out. It is intended for developer testing only.', '//$MAXFORTEST = getDolGlobalInt(''MAX_FOR_TEST_EXPORT'');' || char(9) || '// For test on large database, we can set it to a non zero value and uncomment code that use it later to limit the export size', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["//$MAXFORTEST = getDolGlobalInt(''MAX_FOR_TEST_EXPORT'');\t// For test on large database, we can set it to a non zero value and uncomment code that use it later to limit the export size"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MAX_YEAR_SELECT_DATE', 'string', NULL, 'core', 'Sets the maximum selectable year in date selector fields.', 'Read as integer at core/class/html.form.class.php:7892 via getDolGlobalInt with a fallback of (current year + 100). Controls the $maxYear variable used when rendering year drop-downs.', 'Decreasing this value restricts users from selecting future years in date fields. Leaving unset defaults to 100 years after the current year.', 'Integer year value (e.g. 2050, 2100); unset = current year plus 100.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7892|read|$maxYear = getDolGlobalInt(''MAX_YEAR_SELECT_DATE'', (idate(''Y'') + 100));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_ADDON', 'string', NULL, 'core', 'Specifies the class name of the member reference numbering module to use, defaulting to ''mod_member_simple''.', 'Used in core/modules/modAdherent.class.php:365-366 to set the ''class'' and ''path'' keys for the active numbering module. The default value ''mod_member_simple'' is passed as the second argument to getDolGlobalString.', 'Changing this value switches the member numbering algorithm to the specified module class. An unset value causes the system to use the default ''mod_member_simple'' module.', 'Any valid module class name string (e.g., ''mod_member_simple'', ''mod_member_custom''); default: ''mod_member_simple''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["modAdherent.class.php:365|''class'' => getDolGlobalString(''MEMBER_ADDON'', ''mod_member_simple''),", "modAdherent.class.php:366|''path''=>\"/core/modules/member/\".getDolGlobalString(''MEMBER_ADDON'', ''mod_member_simple'').''.php''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_ADDON_PDF_ODT', 'string', NULL, 'adherents', 'Stores the name of the ODT template selected for generating member PDF documents.', 'Managed via the admin UI at adherents/admin/member.php. The value is written with dolibarr_set_const (:148) and deleted when a different template is chosen (:142). It is checked against available template names to mark the active selection (:501).', 'Changing or clearing this value switches or removes the ODT template used when generating member card PDF documents.', 'String name of the ODT template file; empty = no ODT template selected', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php|adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:501|check|if (getDolGlobalString(''MEMBER_ADDON_PDF_ODT'') == $name) {", "adherents/admin/member.php:148|write|dolibarr_set_const($db, \"MEMBER_ADDON_PDF_ODT\", $value, ''chaine'', 0, '''', $conf->entity);", "adherents/admin/member.php:141|check|if (getDolGlobalString(''MEMBER_ADDON_PDF_ODT'') == \"$value\") {", "adherents/admin/member.php:142|write|dolibarr_del_const($db, ''MEMBER_ADDON_PDF_ODT'', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) containing custom ODT templates for member document generation.', 'Read in core/modules/member/doc/doc_generic_member_odt.class.php at lines 123 and 150. At line 123, the value is split by comma to build a list of directories to search for ODT template files. No admin UI write is present.', 'When set, the member ODT document generator searches the specified directories for template files. When unset or empty, only default directories are searched.', 'Comma-separated list of directory paths; empty to use defaults only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/member/doc/doc_generic_member_odt.class.php:123|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''MEMBER_ADDON_PDF_ODT_PATH''))));", "core/modules/member/doc/doc_generic_member_odt.class.php:150|read|$texte .= getDolGlobalString(''MEMBER_ADDON_PDF_ODT_PATH'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_ALLOW_CHANGE_OF_TYPE', 'bool', NULL, 'public', 'Controls whether a member''s type can be changed during the public payment/subscription process.', 'Rendered as a yes/no selector (with inverted logic) in adherents/admin/member.php:620. Checked twice in public/payment/newpayment.php:1771 and :1778 to conditionally display or allow type-change options.', 'Enabling this allows members to select a different membership type during payment; disabling locks the type.', '0 = type change not allowed; 1 = type change allowed during payment', 0, 0, 'adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:620|read|print $form->selectyesno(''MEMBER_ALLOW_CHANGE_OF_TYPE'', (getDolGlobalInt(''MEMBER_ALLOW_CHANGE_OF_TYPE'') ? 0 : 1), 1);", "public/payment/newpayment.php:1778|check|if (getDolGlobalString(''MEMBER_ALLOW_CHANGE_OF_TYPE'')) {", "public/payment/newpayment.php:1771|check|if (getDolGlobalString(''MEMBER_ALLOW_CHANGE_OF_TYPE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_CAN_CONVERT_CUSTOMERS_TO_MEMBERS', 'string', NULL, 'societe', 'When enabled, allows converting customer third parties into association members from the third-party card.', 'Checked in societe/card.php:3542 alongside a check that the third party is a customer (client == 1 or 3) and no existing member link exists. Only one occurrence in the payload. No admin UI write is present.', 'Enabling this constant makes a conversion action available on third-party cards for customers, allowing them to be registered as association members.', 'Boolean flag; unset or 0 = conversion action not available; any truthy value = conversion action shown for customers.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:3542|check|if ($result == 0 && ($object->client == 1 || $object->client == 3) && getDolGlobalString(''MEMBER_CAN_CONVERT_CUSTOMERS_TO_MEMBERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_CODEMEMBER_ADDON', 'string', NULL, 'adherents', 'Selects the module used to generate member reference codes, defaulting to mod_member_simple.', 'Stores the name of the active member code generation module. Read in adherents/class/adherent.class.php to load the appropriate module class. Configured via adherents/admin/member.php.', 'Changing this value switches the algorithm used to auto-generate member reference numbers. The default is mod_member_simple.', 'Module name string, e.g. ''mod_member_simple'' (default)', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/class/adherent.class.php:715|read|$modulenum = getDolGlobalString(''MEMBER_CODEMEMBER_ADDON'', ''mod_member_simple'');", "adherents/admin/member.php:369|check|if (getDolGlobalString(''MEMBER_CODEMEMBER_ADDON'', ''mod_member_simple'') == \"$file\") {", "adherents/admin/member.php:230|write|$result = dolibarr_set_const($db, \"MEMBER_CODEMEMBER_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_COUNTERS_ARE_PUBLIC', 'string', NULL, 'adherents', 'Controls whether member count statistics are displayed publicly on the member registration page.', 'Written via adherents/admin/website.php:94, read in public/members/new.php:1337 to set the $publiccounters variable. Admin UI at adherents/admin/website.php:292 uses selectyesno.', 'Enabling this constant makes member count information visible on the public registration page.', '0 (counters hidden) or 1 (counters public)', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/website.php:94|write|$res = dolibarr_set_const($db, \"MEMBER_COUNTERS_ARE_PUBLIC\", $publiccounters, ''chaine'', 0, '''', $conf->entity);", "adherents/admin/website.php:292|read|print $form->selectyesno(\"MEMBER_COUNTERS_ARE_PUBLIC\", getDolGlobalInt(''MEMBER_COUNTERS_ARE_PUBLIC''), 1, false, 0, 1);", "public/members/new.php:1337|read|$publiccounters = getDolGlobalString(\"MEMBER_COUNTERS_ARE_PUBLIC\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_CUSTOM_MASK', 'string', NULL, 'core', 'Stores the numbering mask pattern used by the custom member reference numbering module.', 'Used in core/modules/member/mod_member_custom.php in two locations (lines 91 and 139) where the mask is retrieved and used to generate member reference numbers.', 'Changing the mask pattern alters how new member references are formatted. Clearing it causes the custom numbering module to have no mask to apply.', 'Any string = mask pattern for member reference generation; empty/unset = no mask pattern.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_member_custom.php:91|$mask = getDolGlobalString(''MEMBER_CUSTOM_MASK'');", "mod_member_custom.php:139|$mask = getDolGlobalString(''MEMBER_CUSTOM_MASK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_DISABLE_STATE', 'bool', NULL, 'adherents', 'Disables the state/province field for member records.', 'Checked in adherents/card.php:1249 and :1506 to conditionally show state-related UI. Also used in webportal/class/webportalmember.class.php:126 to control field visibility with enabled=''!getDolGlobalString("MEMBER_DISABLE_STATE")''.', 'When enabled, the state/province field is hidden and not processed for member records including in the web portal.', '0 or unset = state field enabled; non-empty = state field disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:1249|check|if (!getDolGlobalString(''MEMBER_DISABLE_STATE'')) {", "webportal/class/webportalmember.class.php:126|read|''state_id'' => array(''type'' => ''integer'', ''label'' => ''State id'', ''enabled'' => ''!getDolGlobalString(\"MEMBER_DISABLE_STATE\")'', ''visible'' => -5, ''position'' => 90, ''showonheader'' => 1,)"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_DONOTSEARCH_ANYWHERE', 'string', NULL, 'core', 'When enabled, restricts member search queries to prefix-only matches to allow database index usage.', 'Read at core/class/html.form.class.php:8894. When falsy, $prefix is ''%'' (leading wildcard); when truthy, $prefix is '''' (no leading wildcard). The inline comment states ''Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on''.', 'Enabling improves search performance on large member tables. Disabling allows substring matching at the cost of index usage.', 'Truthy = prefix-only search (index-friendly); empty/unset = substring search with leading wildcard.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:8894|read|$prefix = !getDolGlobalString(''MEMBER_DONOTSEARCH_ANYWHERE'') ? ''%'' : ''''; // Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_ENABLE_PUBLIC', 'bool', NULL, 'adherents', 'Enables the public membership subscription page and related public features for the Members module.', 'Written via adherents/admin/website.php:70-91 and checked in core/class/html.formmail.class.php:2139 and comm/mailing/card.php:337. The admin UI at adherents/admin/website.php reads and writes this constant. It controls access to public member-facing features.', 'Disabling this constant hides the public membership form and prevents public-facing member subscription flows from operating.', '0 (public page disabled) or 1 (public page enabled)', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/website.php:70|write|dolibarr_set_const($db, ''MEMBER_ENABLE_PUBLIC'', 1, ''chaine'', 0, '''', $conf->entity);", "adherents/admin/website.php:72|write|dolibarr_set_const($db, ''MEMBER_ENABLE_PUBLIC'', 0, ''chaine'', 0, '''', $conf->entity);", "core/class/html.formmail.class.php:2139|check|if (getDolGlobalString(''MEMBER_ENABLE_PUBLIC'')) {", "comm/mailing/card.php:337|check|if (getDolGlobalString(''MEMBER_ENABLE_PUBLIC'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_EXT_URL_SUBSCRIPTION_INFO', 'string', NULL, 'public', 'Specifies an external URL linked as an information icon on the public member subscription and payment forms.', 'Checked and read at public/payment/newpayment.php:1987-1988 and public/members/new.php:1137-1139; when set, a link with an icon is rendered pointing to this URL with target=_blank.', 'When set, users on the member or payment form can follow this link for additional subscription information.', 'An external URL string; empty/unset means no info link is shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:1987|check|if (getDolGlobalString(''MEMBER_EXT_URL_SUBSCRIPTION_INFO'')) {", "public/payment/newpayment.php:1988|read|print '' - <a href=\"'' . getDolGlobalString(''MEMBER_EXT_URL_SUBSCRIPTION_INFO'').''\" rel=\"external\" target=\"_blank\"", "public/members/new.php:1137|check|if (getDolGlobalString(''MEMBER_EXT_URL_SUBSCRIPTION_INFO'')) {", "public/members/new.php:1139|read|print ''<a href=\"'' . getDolGlobalString(''MEMBER_EXT_URL_SUBSCRIPTION_INFO'').''\" rel=\"external\" target=\"_blank\" rel=\"noopener noreferrer\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_HIDE_VOTE_ALLOWED', 'bool', NULL, 'adherents', 'Controls whether the ''vote allowed'' field is hidden on the public member registration form.', 'Written at adherents/admin/website.php:97 with inverted logic for retrocompatibility. Read at adherents/admin/website.php:240 and public/members/new.php:1338.', 'Setting this to 1 hides the vote-allowed field on the public member form. Note: logic is reversed for retrocompatibility: ''hide -> show''.', '0 (vote allowed field shown) or 1 (vote allowed field hidden) — logic inverted for retrocompatibility', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/website.php:97|write|$res = dolibarr_set_const($db, \"MEMBER_HIDE_VOTE_ALLOWED\", $showvoteallowed ? 0 : 1, ''chaine'', 0, '''', $conf->entity); // Logic is reversed for retrocompatibility: \"hide -> show\"", "adherents/admin/website.php:240|read|$hidevoteallowed = getDolGlobalInt(''MEMBER_HIDE_VOTE_ALLOWED'');", "public/members/new.php:1338|read|$hidevoteallowed = getDolGlobalString(\"MEMBER_HIDE_VOTE_ALLOWED\");"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_MIN_AMOUNT', 'string', NULL, 'public', 'Sets the minimum payment amount enforced for member subscriptions and public membership payments.', 'Defines a floor amount for member payments. Used in public/members/new.php and public/payment/newpayment.php via max() to ensure the payment amount never falls below this value. Also checked in public/payment/paymentok.php:640 to reject payments below the minimum. Configurable via adherents/admin/website.php.', 'Setting this value prevents members from paying less than the specified amount during subscription; payments below the minimum are rejected or raised to the minimum.', 'Numeric string representing the minimum amount (e.g. ''10''). 0 or empty means no enforced minimum beyond zero.', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/members/new.php:34  *  MEMBER_MIN_AMOUNT                   Minimum amount", "public/payment/paymentok.php:640|check|if ($FinalPaymentAmt < getDolGlobalInt(''MEMBER_MIN_AMOUNT'') || $FinalPaymentAmt < $minimumamount) {", "public/payment/newpayment.php:1982|read|$amount = max(0, (float) $amount, (float) getDolGlobalInt(\"MEMBER_MIN_AMOUNT\"));", "adherents/admin/website.php:93|write|$res = dolibarr_set_const($db, \"MEMBER_MIN_AMOUNT\", $minamount, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_MOD_SIMPLE_LPAD', 'string', NULL, 'core', 'Sets the zero-padding width applied to member reference numbers in the simple numbering module.', 'Used in core/modules/member/mod_member_simple.php as the pad length for str_pad() with STR_PAD_LEFT to zero-prefix the numeric part of the member reference.', 'Changing this value alters the minimum digit width of generated member reference numbers. An unset value causes str_pad to default to no padding.', 'Integer = total character width of zero-padded number (e.g., 5 yields ''00042''); unset/0 = no padding.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_member_simple.php:148|$max = str_pad((string) $max, getDolGlobalInt(''MEMBER_MOD_SIMPLE_LPAD''), \"0\", STR_PAD_LEFT);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_AMOUNT', 'string', NULL, 'public', 'Sets the default subscription amount used on the public member auto-subscribe form.', 'Documented at public/members/new.php:33 as ''Default amount for auto-subscribe form''. Written via adherents/admin/website.php:92. Read in public/members/new.php:990, :1395 and public/payment/newpayment.php:1970 and public/payment/paymentok.php:619 when no amount is provided. Note: do not set if MEMBER_NEWFORM_DOLIBARRTURNOVER is used.', 'When set, the form uses this amount as the default subscription fee when no amount is otherwise determined. Conflicts with MEMBER_NEWFORM_DOLIBARRTURNOVER.', 'Default amount for auto-subscribe form — numeric amount string; empty/unset means no default amount forced', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/members/new.php:33  *  MEMBER_NEWFORM_AMOUNT               Default amount for auto-subscribe form", "public/members/new.php:1014  // Do not set a default amount MEMBER_NEWFORM_AMOUNT if you use MEMBER_NEWFORM_DOLIBARRTURNOVER", "public/payment/newpayment.php:1970|read|$amount = getDolGlobalString(''MEMBER_NEWFORM_AMOUNT'');", "adherents/admin/website.php:92|write|$res = dolibarr_set_const($db, \"MEMBER_NEWFORM_AMOUNT\", $amount, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_ASK_TITLE', 'string', NULL, 'public', 'When enabled, displays a title/civility field on the public member registration form.', 'Checked at public/members/new.php:860; when set, a title field is rendered in the form. No admin UI write found.', 'When enabled, registrants can enter their title or civility on the member form; when unset, this field is hidden.', '0 or unset = title field hidden; non-zero = title field shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:860|check|if (getDolGlobalString(''MEMBER_NEWFORM_ASK_TITLE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_DOLIBARRTURNOVER', 'string', NULL, 'public', 'Shows a turnover field on the public member registration form, specific to the Dolibarr foundation.', 'Checked at public/members/new.php:379, :1013, :1156, :1172 and public/payment/newpayment.php:1821 to show or hide the turnover field and adjust amount defaults. The comment at new.php:36 describes it as ''Show field turnover (specific for dolibarr foundation)''.', 'When enabled, the turnover field is shown on the member form and default amounts from MEMBER_NEWFORM_AMOUNT are suppressed.', 'Show field turnover (specific for dolibarr foundation)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:36  *  MEMBER_NEWFORM_DOLIBARRTURNOVER     Show field turnover (specific for dolibarr foundation)", "public/members/new.php:1014  // Do not set a default amount MEMBER_NEWFORM_AMOUNT if you use MEMBER_NEWFORM_DOLIBARRTURNOVER", "public/payment/newpayment.php:1839  // Do not set a default amount MEMBER_NEWFORM_AMOUNT if you use MEMBER_NEWFORM_DOLIBARRTURNOVER", "public/members/new.php:379|check|if (getDolGlobalString(''MEMBER_NEWFORM_DOLIBARRTURNOVER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_FORCECOUNTRYCODE', 'string', NULL, 'public', 'Forces a specific country on public member and event attendee registration forms when no country has been selected.', 'The COMMENT in public/members/new.php:40 states ''MEMBER_NEWFORM_FORCECOUNTRYCODE  Force country''. Used across public/members/new.php, public/project/suggestbooth.php, public/project/suggestconference.php, and public/eventorganization/attendee_new.php to pre-populate country_id. No admin UI write path is present.', 'Setting this pre-selects a country on public member and attendee registration forms when the user has not chosen one.', 'String: ISO country code (e.g. ''FR'', ''US'') used to force the country selection on public forms', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:40  *  MEMBER_NEWFORM_FORCECOUNTRYCODE     Force country", "public/members/new.php:308|read|$country_id = getDolGlobalInt(\"MEMBER_NEWFORM_FORCECOUNTRYCODE\", GETPOSTINT(''country_id''));", "public/members/new.php:906|read|$country_id = getCountry(getDolGlobalString(''MEMBER_NEWFORM_FORCECOUNTRYCODE''), ''2'', $db, $langs);", "public/project/suggestbooth.php:688|check|if (!$country_id && getDolGlobalString(''MEMBER_NEWFORM_FORCECOUNTRYCODE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_FORCEMORPHY', 'string', NULL, 'public', 'Forces a specific legal nature (physical/moral) on the public member registration form.', 'Documented at public/members/new.php:39 as ''Force nature of member (mor/phy)''. Written via adherents/admin/website.php:106-108 and read at public/members/new.php:429 and :851.', 'When set, the registration form pre-fills and locks the member''s nature to the specified value, preventing user selection.', 'Force nature of member (mor/phy) — ''phy'' for physical person, ''mor'' for moral/legal entity; empty/unset allows user selection', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/members/new.php:39  *  MEMBER_NEWFORM_FORCEMORPHY          Force nature of member (mor/phy)", "adherents/admin/website.php:268|read|$forcenature = getDolGlobalString(''MEMBER_NEWFORM_FORCEMORPHY''); // ''phy'' or ''mor''", "public/members/new.php:429|read|$adh->morphy      = getDolGlobalString(\"MEMBER_NEWFORM_FORCEMORPHY\", GETPOST(''morphy''));", "public/members/new.php:755|check|if (!getDolGlobalString(''MEMBER_NEWFORM_FORCEMORPHY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_FORCETYPE', 'string', NULL, 'public', 'Forces a specific member type on the public member registration form instead of letting the user choose.', 'Documented at public/members/new.php:38 as ''Force type of member''. Written via adherents/admin/website.php:101-103 and read at public/members/new.php:427, :972, :1206 to set the member type ID.', 'When set, the public registration form pre-selects and locks the member type to the given ID, overriding user selection.', 'Force type of member — integer ID of the member type to force; empty/unset allows user selection', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/members/new.php:38  *  MEMBER_NEWFORM_FORCETYPE            Force type of member", "adherents/admin/website.php:103|write|$res = dolibarr_set_const($db, \"MEMBER_NEWFORM_FORCETYPE\", $forcetype, ''chaine'', 0, '''', $conf->entity);", "public/members/new.php:972|read|$typeid = getDolGlobalInt(''MEMBER_NEWFORM_FORCETYPE'', GETPOSTINT(''typeid''));", "public/members/new.php:685|check|if (getDolGlobalString(''MEMBER_SKIP_TABLE'') || getDolGlobalString(''MEMBER_NEWFORM_FORCETYPE'') || in_array($action, array(''create'', ''subscription''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_PAYONLINE', 'string', NULL, 'public', 'Specifies which online payment method to suggest on the public member registration form after subscription.', 'Documented at public/members/new.php:35 as ''Suggest payment with all, paypal, paybox, stripe, ...''. Written via adherents/admin/website.php:99 and checked in public/members/new.php:582, :600, :1135.', 'When set, the registration form redirects to the online payment flow for the specified payment provider after subscription. ''-1'' disables the online payment suggestion.', 'Suggest payment with ''all'', ''paypal'', ''paybox'', ''stripe'', ... — ''-1'' disables; empty/unset means no payment suggestion', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/members/new.php:35  *  MEMBER_NEWFORM_PAYONLINE            Suggest payment with ''all'', ''paypal'', ''paybox'', ''stripe'', ...", "public/members/new.php:1135|check|if (getDolGlobalString(''MEMBER_NEWFORM_PAYONLINE'')) {\t// Can be ''all'', ''paypal'', ''paybox'', ''stripe''...", "public/members/new.php:600|check|if (getDolGlobalString(''MEMBER_NEWFORM_PAYONLINE'') != ''-1'' && getDolGlobalString(''MEMBER_NEWFORM_PAYONLINE'') != ''all'') {", "adherents/admin/website.php:99|write|$res = dolibarr_set_const($db, \"MEMBER_NEWFORM_PAYONLINE\", $payonline, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NEWFORM_TEXT', 'string', NULL, 'public', 'Sets a translation key whose translated text is displayed at the bottom of the public member registration form.', 'Checked and read at public/members/new.php:664-665; the value is passed through $langs->trans() before being printed. No admin UI write found.', 'If set, the translated value of this key appears as a text message at the bottom of the member registration form.', 'A translation key string; the translated text is rendered on the form.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:664|check|if (getDolGlobalString(''MEMBER_NEWFORM_TEXT'')) {", "public/members/new.php:665|read|print $langs->trans(getDolGlobalString(''MEMBER_NEWFORM_TEXT'')).\"<br>\\n\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NO_DEFAULT_LABEL', 'string', NULL, 'adherents', 'Suppresses automatic generation of a default subscription label during subscription creation.', 'Checked once at adherents/subscription.php:1030; when not set, the code enters the block that assigns a default label to the subscription. No admin UI is provided.', 'Setting this constant prevents the automatic default label from being applied to new subscriptions.', 'Empty/unset = default label is generated; non-empty = default label generation skipped.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:1030|check|if (!getDolGlobalString(''MEMBER_NO_DEFAULT_LABEL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_NO_SYNC_LINKED_THIRDPARTY', 'string', NULL, 'adherents', 'Suppresses automatic synchronization of member data to the linked third-party record.', 'Read once at adherents/card.php:421 as $nosyncthirdparty; when non-zero, synchronization to the linked third-party is skipped. No admin UI is provided.', 'Enabling this constant prevents member data changes from being propagated to the associated third-party record.', 'Non-zero integer = sync disabled; 0 or unset = sync enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:421|read|$nosyncthirdparty = getDolGlobalInt(''MEMBER_NO_SYNC_LINKED_THIRDPARTY'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_PHOTO_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'adherents', 'Allows member photo files to be downloaded without authentication.', 'Checked once at adherents/card.php:458; when set, the code enables external (unauthenticated) access to member photo files. No admin UI is provided.', 'Enabling this constant makes member photos publicly accessible without requiring a login.', 'Non-empty/truthy = external download allowed; empty/unset = download requires authentication.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/card.php:458|check|if (getDolGlobalString(''MEMBER_PHOTO_ALLOW_EXTERNAL_DOWNLOAD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_PUBLIC_CSS', 'string', NULL, 'public', 'Specifies a custom CSS URL injected into the public member card and list pages.', 'Checked and read at public/members/public_card.php:92-93 and public/members/public_list.php:135-136; when set, a link element pointing to this URL is added to the page head. No admin UI write found.', 'When set, the specified CSS file is loaded on public member pages, allowing visual customization of those pages.', 'A URL string pointing to a CSS file; empty/unset means no extra stylesheet is loaded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/public_card.php:92|check|if (getDolGlobalString(''MEMBER_PUBLIC_CSS'')) {", "public/members/public_card.php:93|read|$morehead = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"'' . getDolGlobalString(''MEMBER_PUBLIC_CSS'').''\">'';", "public/members/public_list.php:135|check|if (getDolGlobalString(''MEMBER_PUBLIC_CSS'')) {", "public/members/public_list.php:136|read|$morehead = ''<link rel=\"stylesheet\" type=\"text/css\" href=\"'' . getDolGlobalString(''MEMBER_PUBLIC_CSS'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_PUBLIC_ENABLED', 'bool', NULL, 'public', 'Enables or disables the public-facing member pages (public card, public list, and public subscription form).', 'Set via the admin UI at adherents/admin/member.php:181 and rendered as a yes/no selector at :613. The three public pages (public_card.php:87, public_list.php:128, new.php:954) gate their output on this constant.', 'Disabling this constant blocks public access to member directory and subscription pages. Enabling makes them accessible without login.', '0 = public member pages disabled; 1 = public member pages enabled', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member.php:613|read|print $form->selectyesno(''MEMBER_PUBLIC_ENABLED'', getDolGlobalInt(''MEMBER_PUBLIC_ENABLED''), 1, false, 0, 1);", "public/members/public_card.php:87|check|if (!getDolGlobalString(''MEMBER_PUBLIC_ENABLED'')) {", "public/members/public_list.php:128|check|if (!getDolGlobalString(''MEMBER_PUBLIC_ENABLED'')) {", "public/payment/newpayment.php:954 (via new.php)|check|if (getDolGlobalString(''MEMBER_PUBLIC_ENABLED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_PUBLIC_INTERFACE', 'string', NULL, 'public', 'Sets the topic/title string displayed in the public member registration page header.', 'Read at public/members/new.php:186 as the topic argument to htmlPrintOnlineHeader(). No admin UI write found.', 'If set, the public member registration page header displays this custom topic string.', 'Any string used as the public member interface header topic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:186|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''MEMBER_PUBLIC_INTERFACE''), ''MEMBER_IMAGE_PUBLIC_REGISTRATION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_REMINDER_EMAIL', 'string', NULL, 'adherents', 'Enables the membership expiration reminder email feature.', 'When not set, the reminder email option is suppressed in the member email admin page and reminder emails are skipped in adherents/class/adherent.class.php. No admin UI write for this constant itself; must be enabled separately.', 'Enabling this activates the expiration reminder email workflow. Disabling it prevents reminder emails from being sent.', 'Truthy = reminder emails enabled; empty/falsy = disabled', 0, 0, 'adherents/admin/member_emails.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/member_emails.php:203|check|if ($const == ''ADHERENT_EMAIL_TEMPLATE_REMIND_EXPIRATION'' && !getDolGlobalString(''MEMBER_REMINDER_EMAIL'')) {", "adherents/class/adherent.class.php:3245|check|if (!getDolGlobalString(''MEMBER_REMINDER_EMAIL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SEARCH_MEMBER_PUBLIC_FORM_CREATE', 'string', NULL, 'public', 'When enabled, triggers a search for an existing member before creating a new one on the public member registration form.', 'Checked as an integer at public/members/new.php:230 on the ''add'' action when the nofetchmember parameter is not posted; when non-zero, an existing member lookup is performed first. No admin UI write found.', 'When enabled, duplicate member records are less likely because the form attempts to match an existing member before creating a new one.', '0 or unset = no pre-search; non-zero = search existing member before creating', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:230|check|if (empty($reshook) && getDolGlobalInt(\"MEMBER_SEARCH_MEMBER_PUBLIC_FORM_CREATE\") && $action == ''add'' && !GETPOSTISSET(\"nofetchmember\")) {\t// Test on permission not required here"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SKIP_TABLE', 'string', NULL, 'adherents', 'Controls whether the membership type table is skipped (hidden) on the public member registration form.', 'Written at adherents/admin/website.php:95 with inverted logic for retrocompatibility (''skip -> show''). Read at adherents/admin/website.php:231 and checked at public/members/new.php:685.', 'Setting this to 1 skips (hides) the membership type selection table on the public form. Note: logic is reversed for retrocompatibility: ''skip -> show''.', '0 (table shown) or 1 (table skipped/hidden) — logic inverted for retrocompatibility', 0, 0, 'adherents/admin/website.php|adherents/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/admin/website.php:95|write|$res = dolibarr_set_const($db, \"MEMBER_SKIP_TABLE\", $showtable ? 0 : 1, ''chaine'', 0, '''', $conf->entity); // Logic is reversed for retrocompatibility: \"skip -> show\"", "public/members/new.php:685|check|if (getDolGlobalString(''MEMBER_SKIP_TABLE'') || getDolGlobalString(''MEMBER_NEWFORM_FORCETYPE'') || in_array($action, array(''create'', ''subscription''))) {", "adherents/admin/website.php:231|read|$skiptable = getDolGlobalInt(''MEMBER_SKIP_TABLE'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SUBSCRIPTION_START_AFTER', 'string', NULL, 'adherents', 'Defines a duration offset to add to the current date when computing the start date of a new member subscription.', 'The value is parsed as a duration string (numeric prefix + unit suffix, e.g., ''1m'', ''3m'', ''1Y'') using substr at adherents/subscription.php:988 and public/payment/paymentok.php:676, passed to dol_time_plus_duree. Also used in stats at adherents/stats/index.php:66. Configurable via adherents/admin/member.php:184.', 'Setting this constant shifts the subscription start date forward by the specified duration from today instead of using the current date directly.', 'A duration string with a numeric part and a unit character (e.g., ''1m'' = 1 month, ''3m'' = 3 months, ''1Y'' = 1 year); empty/unset = subscription starts on current date.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/payment/paymentok.php:676|read|$datesubscription = dol_time_plus_duree($now, (int) substr(getDolGlobalString(''MEMBER_SUBSCRIPTION_START_AFTER''), 0, -1), substr(getDolGlobalString(''MEMBER_SUBSCRIPTION_START_AFTER'')", "adherents/subscription.php:988|read|$datefrom = dol_time_plus_duree($now, (int) substr(getDolGlobalString(''MEMBER_SUBSCRIPTION_START_AFTER''), 0, -1), substr(getDolGlobalString(''MEMBER_SUBSCRIPTION_START_AFTER''), -1))", "adherents/subscription.php:987|check|if (getDolGlobalString(''MEMBER_SUBSCRIPTION_START_AFTER'')) {", "adherents/admin/member.php:184|write|$res9 = dolibarr_set_const($db, ''MEMBER_SUBSCRIPTION_START_AFTER'', GETPOST(''MEMBER_SUBSCRIPTION_START_AFTER'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF', 'string', NULL, 'adherents', 'Snaps the subscription start date to the first day of the specified period (month, quarter, or year).', 'After the start date is computed, adherents/subscription.php:993-998 and public/payment/paymentok.php:679-684 check this constant and snap the date to the first day of the month (''m''), first day of the quarter (''3m''), or first day of the year (''Y''). Configurable via adherents/admin/member.php:183.', 'Setting this constant causes subscription start dates to be rounded down to the first day of the chosen period, which affects billing alignment.', '''m'' = first day of current month; ''3m'' = first day of current quarter; ''Y'' = first day of current year; empty/0 = no snapping.', 0, 0, 'adherents/admin/member.php|adherents/admin/member.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:993|check|if (getDolGlobalString(''MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF'') === \"m\") {", "adherents/subscription.php:995|read|} elseif (getDolGlobalString(''MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF'') === \"3m\") {", "adherents/subscription.php:998|read|} elseif (getDolGlobalString(''MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF'') === \"Y\") {", "adherents/admin/member.php:183|write|$res8 = dolibarr_set_const($db, ''MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF'', GETPOST(''MEMBER_SUBSCRIPTION_START_FIRST_DAY_OF'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SUBSCRIPTION_SUGGEST_END_OF_MONTH', 'string', NULL, 'adherents', 'Suggests the end of the current month as the subscription end date during subscription creation.', 'Checked once at adherents/subscription.php:1010; when set to a non-zero integer, the subscription end date is suggested as the end of the current month. No admin UI is provided.', 'Enabling this constant pre-fills the subscription end date with the last day of the current month.', 'Non-zero integer = end-of-month suggested; 0 or unset = no suggestion.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:1010|check|if (getDolGlobalInt(''MEMBER_SUBSCRIPTION_SUGGEST_END_OF_MONTH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_SUBSCRIPTION_SUGGEST_END_OF_YEAR', 'string', NULL, 'adherents', 'Suggests the end of the current year as the subscription end date during subscription creation.', 'Checked once at adherents/subscription.php:1012 as an elseif branch; when set, the subscription end date is suggested as the end of the current year. No admin UI is provided.', 'Enabling this constant pre-fills the subscription end date with the last day of the current year.', 'Non-empty/truthy = end-of-year suggested; empty/unset = no suggestion.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["adherents/subscription.php:1012|read|} elseif (getDolGlobalInt(''MEMBER_SUBSCRIPTION_SUGGEST_END_OF_YEAR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMBER_URL_REDIRECT_SUBSCRIPTION', 'string', NULL, 'public', 'Specifies a URL to redirect to after a member registration or company subscription form is submitted.', 'Read at public/company/new.php:237-238 and public/members/new.php:575-576 as the redirect target after form submission. The comment in new.php:37 describes it as a ''hidden option, by default we just show a message on same page or redirect to the payment page''.', 'If set, submitting the registration form redirects the user to this URL instead of showing an inline message or the payment page.', 'Url to redirect once registration form has been submitted (hidden option, by default we just show a message on same page or redirect to the payment page)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/members/new.php:37  *  MEMBER_URL_REDIRECT_SUBSCRIPTION    Url to redirect once registration form has been submitted (hidden option, by default we just show a message on same page or redirect to the payment page)", "public/company/new.php:237|read|} elseif (getDolGlobalString(''MEMBER_URL_REDIRECT_SUBSCRIPTION'')) {", "public/members/new.php:575|read|} elseif (getDolGlobalString(''MEMBER_URL_REDIRECT_SUBSCRIPTION'')) {", "public/company/new.php:262  // If MEMBER_URL_REDIRECT_SUBSCRIPTION is set to an url, we never go here because a redirect was done to this url."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MEMCACHED_SERVER', 'string', NULL, 'core', 'Specifies the Memcached server address (host:port) used for distributed caching.', 'Read in core/lib/memory.lib.php (lines 88, 118, 195, 221) via explode('':'', ...) to connect to the Memcached server; checked in core/class/translate.class.php and core/lib/functions.lib.php when the memcached module is enabled. Configurable via admin/system/perf.php.', 'Setting this enables Memcached-backed caching for translations and other shared data; leaving it unset disables Memcached even if the module is enabled.', '''host:port'' string (e.g. ''127.0.0.1:11211''); empty/unset = Memcached not used.', 0, 0, 'admin/system/perf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/memory.lib.php:88|read|$tmparray = explode('':'', getDolGlobalString(''MEMCACHED_SERVER''));", "core/class/translate.class.php:335|check|if (isModEnabled(''memcached'') && getDolGlobalString(''MEMCACHED_SERVER'')) {", "core/lib/functions.lib.php:13227|check|if (getDolGlobalString(''MEMCACHED_SERVER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MENU_HIDE_EMAIL_TEMPLATES', 'bool', NULL, 'core', 'Hides the email templates menu entry for internal users when set.', 'Checked as an integer with negation in core/menus/standard/eldy.lib.php:2569, also restricted to internal users (empty $user->socid). No admin UI write detected.', 'Setting this constant removes the email templates menu link for internal users. Without it, the link is visible to internal users.', 'Non-zero = hide menu entry; 0 or absent = show menu entry.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:2569|check|if (!getDolGlobalInt(''MENU_HIDE_EMAIL_TEMPLATES'') && empty($user->socid)) { // limit to internal users"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MIGRATION_FLAG_INVOICE_MODELS_V20', 'string', NULL, 'core', 'Flags that the invoice template migration for version 20 has been completed, preventing the migration from running again.', 'Written twice in install/upgrade2.php (lines 5409 and 5456) after completing the invoice model upgrade, and read at line 5398 to check whether to skip the migration. The write comment states: ''To flag the upgrade of invoice template has been set''.', 'If this flag is absent the migration script will re-run the invoice template upgrade. Once set it acts as an idempotency guard.', '0 or unset = migration not yet done; 1 = migration completed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, ''MIGRATION_FLAG_INVOICE_MODELS_V20'', 1, ''chaine'', 0, ''To flag the upgrade of invoice template has been set'', 0);", "$lock = getDolGlobalInt(''MIGRATION_FLAG_INVOICE_MODELS_V20'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MIN_DELAY_EXPENSEREPORTS_TO_PAY', 'string', NULL, 'core', 'Number of days before approved expense reports pending payment trigger a warning indicator.', 'Read in core/class/conf.class.php:1283 and :1287, the value (multiplied by 86400) populates $this->warning_delays[''expense_report_payment''] and $this->expensereport->payment->warning_delay. No admin UI page is listed.', 'Setting a non-zero value causes the system to flag approved expense reports that have not been paid within the configured number of days.', 'Integer number of days (no default set). 0 means no warning is triggered.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/conf.class.php:1283|read|$this->warning_delays[''expense_report_payment''] = getDolGlobalInt(''MIN_DELAY_EXPENSEREPORTS_TO_PAY'') * 86400;", "core/class/conf.class.php:1287|read|$this->expensereport->payment->warning_delay = getDolGlobalInt(''MIN_DELAY_EXPENSEREPORTS_TO_PAY'') * 86400;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MIN_YEAR_SELECT_DATE', 'string', NULL, 'core', 'Sets the minimum selectable year in date selector fields.', 'Read as integer at core/class/html.form.class.php:7891 via getDolGlobalInt with a fallback of (current year - 100). Controls the $minYear variable used when rendering year drop-downs.', 'Increasing this value restricts users from selecting older years in date fields. Leaving unset defaults to 100 years before the current year.', 'Integer year value (e.g. 1900, 2000); unset = current year minus 100.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7891|read|$minYear = getDolGlobalInt(''MIN_YEAR_SELECT_DATE'', (idate(''Y'') - 100));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODEL_FAC_REC_AUTHOR', 'string', NULL, 'compta', 'Preserves the original author of a recurring invoice template when generating the recurring invoice, instead of using the current user.', 'Checked in a single location at compta/facture/class/facture.class.php:568. The comment at :569 explicitly states the intent. No admin UI is present.', 'When set, the author of a recurring invoice is taken from the recurring invoice template''s author rather than the current logged-in user.', '0 or unset = current user is set as invoice author; truthy value = original recurring invoice template author is preserved.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:568|check|if (getDolGlobalString(''MODEL_FAC_REC_AUTHOR'')) {", "compta/facture/class/facture.class.php:569  // If option MODEL_FAC_REC_AUTHOR is set, we want the same author than the author of recurring invoice instead of current user"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_ADD_DOCUMENT_ROOT', 'string', NULL, 'modulebuilder', 'Adds DOL_DOCUMENT_ROOT as an additional module search path in the Module Builder.', 'Checked in modulebuilder/index.php:147 alongside MAIN_FEATURES_LEVEL >= 2 to include DOL_DOCUMENT_ROOT as a readable path, and at line 226 to conditionally add it as a module directory. No admin UI.', 'When set, the Module Builder scans DOL_DOCUMENT_ROOT for modules in addition to the standard custom directories.', 'Truthy string (DOL_DOCUMENT_ROOT added) or empty/unset (not added unless MAIN_FEATURES_LEVEL >= 2).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/index.php:147|check|if ($dirread != DOL_DOCUMENT_ROOT && (getDolGlobalInt(''MAIN_FEATURES_LEVEL'') >= 2 || getDolGlobalString(''MODULEBUILDER_ADD_DOCUMENT_ROOT''))) {", "modulebuilder/index.php:226|check|if (getDolGlobalString(''MODULEBUILDER_ADD_DOCUMENT_ROOT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_ASCIIDOCTOR', 'string', NULL, 'modulebuilder', 'Stores the path to the asciidoctor binary used to generate HTML documentation for modules.', 'Configured via modulebuilder/admin/setup.php:53 (written with dolibarr_set_const) and rendered as a text input at line 194. Used in core/class/utils.class.php:949 to build the asciidoctor command, and checked at line 856 to determine if documentation generation is available.', 'When set, module documentation can be generated as HTML using asciidoctor. When unset (and MODULEBUILDER_ASCIIDOCTORPDF is also unset), documentation generation is unavailable.', 'Absolute path string to the asciidoctor executable; empty/unset disables HTML doc generation.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:53|write|$res2 = dolibarr_set_const($db, ''MODULEBUILDER_ASCIIDOCTOR'', GETPOST(''MODULEBUILDER_ASCIIDOCTOR'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/class/utils.class.php:949|read|$command = getDolGlobalString(''MODULEBUILDER_ASCIIDOCTOR'') . '' ''.$destfile.'' -n -o ''.$dirofmoduledoc.''/''.$FILENAMEDOC;", "core/class/utils.class.php:856|check|if (!getDolGlobalString(''MODULEBUILDER_ASCIIDOCTOR'') && !getDolGlobalString(''MODULEBUILDER_ASCIIDOCTORPDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_ASCIIDOCTORPDF', 'string', NULL, 'modulebuilder', 'Stores the path to the asciidoctor-pdf binary used to generate PDF documentation for modules.', 'Configured via modulebuilder/admin/setup.php:54 (written with dolibarr_set_const) and rendered as a text input at line 202. Used in core/class/utils.class.php:964 to build the asciidoctor-pdf command, and checked at line 856 alongside MODULEBUILDER_ASCIIDOCTOR.', 'When set, module documentation can be generated as PDF using asciidoctor-pdf. When both this and MODULEBUILDER_ASCIIDOCTOR are unset, documentation generation is unavailable.', 'Absolute path string to the asciidoctor-pdf executable; empty/unset disables PDF doc generation.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:54|write|$res3 = dolibarr_set_const($db, ''MODULEBUILDER_ASCIIDOCTORPDF'', GETPOST(''MODULEBUILDER_ASCIIDOCTORPDF'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "core/class/utils.class.php:964|read|$command = getDolGlobalString(''MODULEBUILDER_ASCIIDOCTORPDF'') . '' ''.$destfile.'' -n -o ''.$dirofmoduledoc.''/''.$FILENAMEDOCPDF;", "core/class/utils.class.php:856|check|if (!getDolGlobalString(''MODULEBUILDER_ASCIIDOCTOR'') && !getDolGlobalString(''MODULEBUILDER_ASCIIDOCTORPDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_DEFAULTPICTO', 'string', NULL, 'modulebuilder', 'Stores the default picto/icon value pre-filled when creating a new module in Module Builder.', 'Read in modulebuilder/index.php:3485 as the default for the idpicto input field, falling back to ''fa-file''. Only one occurrence; no admin UI write path in the payload.', 'When set, the picto field for new modules is pre-populated with this icon identifier.', 'String picto identifier (e.g. ''fa-file''); defaults to ''fa-file'' if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/index.php:3485|read|print ''<input type=\"text\" name=\"idpicto\" value=\"''.(GETPOSTISSET(''idpicto'') ? GETPOST(''idpicto'') : getDolGlobalString(''MODULEBUILDER_DEFAULTPICTO'', ''fa-file'')).''\""]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_AUTHOR', 'string', NULL, 'modulebuilder', 'Stores the author/copyright string injected into generated module file headers.', 'Configured via modulebuilder/admin/setup.php:58 (written with dolibarr_set_const) and rendered as a text input at line 172. Used in modulebuilder/index.php:417 and :1670 to replace the placeholder ''---Replace with your own copyright and developer email---'' in generated files.', 'When set, generated module files carry this author string in their copyright headers.', 'Free-form string (author name and optionally email); empty/unset leaves the placeholder in generated files.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:58|write|$res7 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_AUTHOR'', GETPOST(''MODULEBUILDER_SPECIFIC_AUTHOR'', ''restricthtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/index.php:416|check|if (getDolGlobalString(''MODULEBUILDER_SPECIFIC_AUTHOR'')) {", "modulebuilder/index.php:417|read|$arrayreplacement[''---Replace with your own copyright and developer email---''] = dol_print_date($now, ''%Y'').\"\\t\\t\" . getDolGlobalString(''MODULEBUILDER_SPECIFIC_AUTHOR'');", "modulebuilder/index.php:1670|read|$arrayreplacement[''---Replace with your own copyright and developer email---''] = dol_print_date($now, ''%Y'').'' '' . getDolGlobalString(''MODULEBUILDER_SPECIFIC_AUTHOR'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_EDITOR_NAME', 'string', NULL, 'modulebuilder', 'Stores the editor/vendor name injected into generated module metadata.', 'Configured via modulebuilder/admin/setup.php:55 (written with dolibarr_set_const) and rendered as a text input at line 150. Used in modulebuilder/index.php:3499 as the default for the editorname field, falling back to $mysoc->name.', 'When set, generated modules carry this editor name in their metadata; defaults to the company name if unset.', 'Free-form string (editor/vendor name); falls back to $mysoc->name if unset.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:55|write|$res4 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_EDITOR_NAME'', GETPOST(''MODULEBUILDER_SPECIFIC_EDITOR_NAME'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/admin/setup.php:150|read|print ''<input id=\"MODULEBUILDER_SPECIFIC_EDITOR_NAME\" type=\"text\" name=\"MODULEBUILDER_SPECIFIC_EDITOR_NAME\" value=\"''.getDolGlobalString(''MODULEBUILDER_SPECIFIC_EDITOR_NAME'').''\">'';", "modulebuilder/index.php:3499|read|print ''<input type=\"text\" name=\"editorname\" value=\"''.(GETPOSTISSET(''editorname'') ? GETPOST(''editorname'') : getDolGlobalString(''MODULEBUILDER_SPECIFIC_EDITOR_NAME'', $mysoc->name)).''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_EDITOR_URL', 'string', NULL, 'modulebuilder', 'Stores the editor/vendor URL injected into generated module metadata.', 'Configured via modulebuilder/admin/setup.php:56 (written with dolibarr_set_const) and rendered as a text input at line 157. Used in modulebuilder/index.php:3505 as the default for the editorurl field, falling back to $mysoc->url.', 'When set, generated modules carry this URL in their editor metadata; defaults to the company URL if unset.', 'URL string; falls back to $mysoc->url if unset.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:56|write|$res5 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_EDITOR_URL'', GETPOST(''MODULEBUILDER_SPECIFIC_EDITOR_URL'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/admin/setup.php:157|read|print ''<input id=\"MODULEBUILDER_SPECIFIC_EDITOR_URL\" type=\"text\" name=\"MODULEBUILDER_SPECIFIC_EDITOR_URL\" value=\"''.getDolGlobalString(''MODULEBUILDER_SPECIFIC_EDITOR_URL'').''\">'';", "modulebuilder/index.php:3505|read|print ''<input type=\"text\" name=\"editorurl\" value=\"''.(GETPOSTISSET(''editorurl'') ? GETPOST(''editorurl'') : getDolGlobalString(''MODULEBUILDER_SPECIFIC_EDITOR_URL'', $mysoc->url)).''\""]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_FAMILY', 'string', NULL, 'modulebuilder', 'Stores the default module family pre-selected when creating a new module in Module Builder.', 'Configured via modulebuilder/admin/setup.php:57 (written with dolibarr_set_const) and rendered as a text input at line 165. Used in modulebuilder/index.php:3476 as the selected value for the family dropdown, falling back to ''other''.', 'When set, the module family dropdown is pre-selected with this value when creating new modules.', 'String family key (e.g. ''hr'', ''other''); defaults to ''other'' if unset.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:57|write|$res6 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_FAMILY'', GETPOST(''MODULEBUILDER_SPECIFIC_FAMILY'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/admin/setup.php:165|read|print ''<input id=\"MODULEBUILDER_SPECIFIC_FAMILY\" type=\"text\" name=\"MODULEBUILDER_SPECIFIC_FAMILY\" value=\"''.getDolGlobalString(''MODULEBUILDER_SPECIFIC_FAMILY'').''\">'';", "modulebuilder/index.php:3476|read|print ''<option value=\"hr\"''.($key == getDolGlobalString(''MODULEBUILDER_SPECIFIC_FAMILY'', ''other'') ? '' selected=\"selected\"'' : '''')."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_README', 'string', NULL, 'modulebuilder', 'Stores the README content written to generated module README.md files.', 'Configured via modulebuilder/admin/setup.php:52 (written with dolibarr_set_const) and rendered as a textarea at line 187. Used in modulebuilder/index.php:431 to write the content directly to the module''s README.md.', 'When set, generated modules receive a README.md with this content. When unset, the default README behaviour applies.', 'Free-form string (README markdown content); empty/unset means no custom README is written.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:52|write|$res1 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_README'', GETPOST(''MODULEBUILDER_SPECIFIC_README'', ''restricthtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/index.php:428|check|if (getDolGlobalString(''MODULEBUILDER_SPECIFIC_README'')) {", "modulebuilder/index.php:431|read|file_put_contents($destdir.''/README.md'', getDolGlobalString(\"MODULEBUILDER_SPECIFIC_README\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SPECIFIC_VERSION', 'string', NULL, 'modulebuilder', 'Stores the default version string pre-filled when creating a new module in Module Builder.', 'Configured via modulebuilder/admin/setup.php:59 (written with dolibarr_set_const) and rendered as a text input at line 179. Used in modulebuilder/index.php:3454 as the default value for the version field, falling back to ''1.0''.', 'When set, new modules created in Module Builder are pre-populated with this version string.', 'Version string (e.g. ''1.0''); defaults to ''1.0'' if unset.', 0, 0, 'modulebuilder/admin/setup.php|modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:59|write|$res8 = dolibarr_set_const($db, ''MODULEBUILDER_SPECIFIC_VERSION'', GETPOST(''MODULEBUILDER_SPECIFIC_VERSION'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "modulebuilder/admin/setup.php:179|read|print ''<input id=\"MODULEBUILDER_SPECIFIC_VERSION\" type=\"text\" name=\"MODULEBUILDER_SPECIFIC_VERSION\" value=\"''.getDolGlobalString(''MODULEBUILDER_SPECIFIC_VERSION'').''\">'';", "modulebuilder/index.php:3454|read|print ''<input type=\"text\" name=\"version\" class=\"width75\" value=\"''.(GETPOSTISSET(''version'') ? GETPOST(''version'') : getDolGlobalString(''MODULEBUILDER_SPECIFIC_VERSION'', ''1.0'')).''\""]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_SUPPORT_COMPATIBILITY_V16', 'string', NULL, 'modulebuilder', 'Enables generation of compatibility code for Dolibarr v16 in the Module Builder.', 'Checked in modulebuilder/index.php:307 via getDolGlobalInt. Only one occurrence; no admin UI.', 'When set, the Module Builder includes v16 compatibility scaffolding in generated module files.', 'Truthy integer (v16 compatibility code included) or empty/unset (not included).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/index.php:307|check|if (getDolGlobalInt(''MODULEBUILDER_SUPPORT_COMPATIBILITY_V16'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULEBUILDER_USE_ABOUT', 'bool', NULL, 'modulebuilder', 'Controls whether the Module Builder includes an ''About'' page scaffold for new modules.', 'Checked in modulebuilder/admin/setup.php:138 and modulebuilder/index.php:335. Configurable via modulebuilder/admin/setup.php.', 'When enabled, the Module Builder generates an About page for new modules. When disabled, the About page scaffold is omitted.', 'Truthy string (About page included) or empty/unset (About page omitted).', 0, 0, 'modulebuilder/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["modulebuilder/admin/setup.php:138|check|if (!getDolGlobalString(''MODULEBUILDER_USE_ABOUT'')) {", "modulebuilder/index.php:335|check|if (getDolGlobalString(''MODULEBUILDER_USE_ABOUT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_COLLAB_DISABLED', 'bool', NULL, 'core', 'Controls whether the Collab module is hidden/disabled in the module list.', 'Assigned directly to $this->hidden in core/modules/modCollab.class.php via getDolGlobalInt(). When non-zero, the module is treated as hidden. No admin UI write is present; hidden setting.', 'Setting this to a non-zero integer hides the Collab module from the module list; setting it to 0 or leaving it undefined makes the module visible.', 'Integer: non-zero hides the module; 0 or undefined makes it visible.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modCollab.class.php:67|read|$this->hidden = getDolGlobalInt(''MODULE_COLLAB_DISABLED''); // A condition to disable module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_CRON_DISABLED', 'bool', NULL, 'core', 'Hides or disables the Cron module from the module list when set to a non-zero value.', 'Read at core/modules/modCron.class.php:67 and assigned to $this->hidden to conditionally hide the Cron module. No admin UI; hidden setting.', 'Setting to 1 hides the Cron module from the modules list, effectively disabling it. Setting to 0 or leaving unset keeps the module visible.', '0 or empty = Cron module visible; 1 = Cron module hidden/disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modCron.class.php:67|read|$this->hidden = getDolGlobalInt(''MODULE_CRON_DISABLED''); // A condition to disable module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_MYMODULE_DISABLED', 'bool', NULL, 'modulebuilder', 'Controls whether the MyModule template module is hidden/disabled in the module list.', 'Read in modulebuilder/template/core/modules/modMyModule.class.php:147 where its integer value is assigned to $this->hidden to conditionally hide the module.', 'Setting this to a non-zero value hides the module from the module list.', '0 = module visible; non-zero = module hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/modMyModule.class.php:147|read|$this->hidden = getDolGlobalInt(''MODULE_MYMODULE_DISABLED''); // A condition to disable module;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_NAME', 'string', NULL, 'core', 'Placeholder constant name representing a module''s activation flag, used in documentation of the noconfverification parameter.', 'Appears in core/lib/admin.lib.php:1193 inside a PHPDoc comment for a function parameter. It describes how $conf->global->MODULE_NAME is normally verified when enabling a module, and noconfverification skips that check.', 'No runtime effect; this is a documentation placeholder illustrating the module activation verification mechanism.', 'Not a real constant; used as a generic placeholder in PHPDoc.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["* \t@param\t\tint\t\t\t$noconfverification\t\tRemove verification of $conf->global->MODULE_NAME variable for module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_SOCIALNETWORKS_DISABLED', 'bool', NULL, 'core', 'Controls whether the Social Networks module is hidden from the module list.', 'Read in core/modules/modSocialNetworks.class.php:65 and assigned to $this->hidden, which hides the module when the integer value is non-zero.', 'Setting this to a non-zero integer hides the Social Networks module from the module management UI.', '0 = module visible (default); non-zero integer = module hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modSocialNetworks.class.php:65|read|$this->hidden = getDolGlobalInt(''MODULE_SOCIALNETWORKS_DISABLED''); // A condition to hide module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_UPLOAD_MAX_EXECUTION_TIME', 'string', NULL, 'admin', 'Sets the maximum PHP execution time in seconds allowed when deploying (uploading) an external module.', 'Read in admin/modules.php:139 with a default of 300 seconds (5 minutes) if not defined. The comment in the code states ''// 5mn if not defined''.', 'Increasing this value allows more time for large module uploads. Decreasing it may cause timeouts for complex module deployments.', 'Integer number of seconds; default is 300 (5 minutes) when not set.', 0, 0, 'admin/modules.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/modules.php:139|read|$max_execution_time_for_deploy = getDolGlobalInt(''MODULE_UPLOAD_MAX_EXECUTION_TIME'', 300); // 5mn if not defined"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MODULE_WEBSITE_DISABLED', 'bool', NULL, 'core', 'When set to 1, hides/disables the Website module so it does not appear in the module list.', 'Read at core/modules/modWebsite.class.php:65 via getDolGlobalInt and assigned to $this->hidden. A non-zero value marks the module as hidden.', 'Setting to 1 disables the Website module entirely for the entity. Setting to 0 or leaving unset keeps the module available.', '1 = module hidden/disabled; 0 or unset = module active.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modWebsite.class.php:65|read|$this->hidden = getDolGlobalInt(''MODULE_WEBSITE_DISABLED''); // A condition to disable module"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MOUVEMENT_ADDON_PDF', 'string', NULL, 'product', 'Specifies the PDF template model name to use when generating stock movement documents.', 'In product/stock/class/mouvementstock.class.php, when a PDF generation is triggered and this constant is set, its value is used as the model name ($modele). No admin UI write is present; hidden setting. Two read occurrences.', 'Setting this to a valid PDF template name enables PDF generation for stock movements using that template; leaving it unset skips that template selection branch.', 'A string matching a stock movement PDF template module name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/class/mouvementstock.class.php:1277|read|} elseif (getDolGlobalString(''MOUVEMENT_ADDON_PDF'')) {", "product/stock/class/mouvementstock.class.php:1278|read|$modele = getDolGlobalString(''MOUVEMENT_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MO_ALSO_CANCEL_CONSUMED_AND_PRODUCED_LINES_BY_DEFAULT', 'string', NULL, 'mrp', 'Sets the default state of the ''also cancel consumed and produced lines'' checkbox when cancelling a Manufacturing Order.', 'Checked in mrp/mo_card.php:557 and mrp/mo_production.php:640. The value is used to set the default checkbox value: when the constant is falsy the default is 0 (unchecked); when truthy the default is 1 (checked).', 'Enabling this causes the cancellation dialog to default to also cancelling consumed and produced lines; disabling it defaults to leaving those lines intact.', 'Empty/0 = checkbox defaults to unchecked (do not cancel lines); truthy = checkbox defaults to checked (cancel lines)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["mrp/mo_card.php:557|read|''value'' => !getDolGlobalString(''MO_ALSO_CANCEL_CONSUMED_AND_PRODUCED_LINES_BY_DEFAULT'') ? 0 : 1", "mrp/mo_production.php:640|read|''value'' => !getDolGlobalString(''MO_ALSO_CANCEL_CONSUMED_AND_PRODUCED_LINES_BY_DEFAULT'') ? 0 : 1"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_AUTO_SET_REMAINING_QUANTITIES_TO_BE_CONSUMED', 'string', NULL, 'mrp', 'Automatically pre-fills remaining quantities to consume on production lines when the consume-or-produce action is submitted.', 'Checked in mrp/mo_production.php at line 1420. When this constant is absent, the code requires explicit posting of a quantity for each line (GETPOSTISSET check).', 'Without this flag, a consumption submission that omits a quantity value for a line is skipped. Enabling it causes the system to auto-fill remaining quantities, reducing manual input.', '0 or unset = missing quantities skipped; 1 = remaining quantities auto-filled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if ($action == ''consumeorproduce'' && !getDolGlobalString(''MRP_AUTO_SET_REMAINING_QUANTITIES_TO_BE_CONSUMED'') && !GETPOSTISSET(''qty-''.$line->id.''-''.$i)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_BOX_LAST_MOS_SHOW_VALIDATE_USER', 'bool', NULL, 'core', 'Shows the validating user column in the last manufacturing orders dashboard box.', 'Checked in core/boxes/box_mos.php:128 to conditionally include a column for the user who validated each MO. Only one occurrence; no admin UI.', 'When enabled, the MO dashboard box displays an additional column showing which user validated each manufacturing order.', 'Truthy string (validate user column shown) or empty/unset (column hidden).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/boxes/box_mos.php:128|check|if (getDolGlobalString(''MRP_BOX_LAST_MOS_SHOW_VALIDATE_USER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_ADDON', 'string', NULL, 'mrp', 'Specifies the numbering module class used to generate Manufacturing Order reference numbers.', 'Written in admin/mrp.php at line 147 and read in mrp/class/mo.class.php at lines 1071-1075. The value is the class name of the addon; the corresponding PHP file is loaded to call the numbering logic. The source comment states the number is ''defined into MRP_MO_ADDON''.', 'Changing this constant switches the MO reference numbering scheme. If the specified class file does not exist, MO number generation will fail.', 'String class name of a numbering module (e.g. ''mod_mo_simple'')', 0, 0, 'admin/mrp.php|admin/mrp.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["*  defined into MRP_MO_ADDON", "$classname = getDolGlobalString(''MRP_MO_ADDON'');", "$file = getDolGlobalString(''MRP_MO_ADDON'') . \".php\";", "if (getDolGlobalString(''MRP_MO_ADDON'') == $file) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF model used to generate Manufacturing Order documents.', 'Written and read in admin/mrp.php (lines 126, 132, 135, 402) and read in mrp/class/mo.class.php at lines 1743-1744. A module comment describes it as ''Name of default PDF model of MO'' with default value ''vinci''.', 'Changing this value switches which PDF template is used when printing or downloading a Manufacturing Order.', 'String name of a PDF model module (e.g. ''vinci'')', 0, 0, 'admin/mrp.php|admin/mrp.php|admin/mrp.php|admin/mrp.php|admin/mrp.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["//1=>array(''MRP_MO_ADDON_PDF'', ''chaine'', ''vinci'', ''Name of default PDF model of MO'', 0),", "$modele = getDolGlobalString(''MRP_MO_ADDON_PDF'');", "if (getDolGlobalString(\"MRP_MO_ADDON_PDF\") == $name) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) for ODT document templates used by the generic MRP manufacturing order ODT module.', 'Read in doc_generic_mo_odt.modules.php at line 126 (split into a list of dirs), line 153 (display in UI), and line 161 (checked for existence). No admin UI write via dolibarr_set_const is present in the payload.', 'Changing this path redirects the module to a different set of ODT template directories; setting it to a non-existent path disables ODT template loading.', 'Comma-separated directory path(s); empty = no custom ODT path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["doc_generic_mo_odt.modules.php:126|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim($conf->global->MRP_MO_ADDON_PDF_ODT_PATH)));", "doc_generic_mo_odt.modules.php:153|read|$texte .= getDolGlobalString(''MRP_MO_ADDON_PDF_ODT_PATH'');", "doc_generic_mo_odt.modules.php:161|check|if (getDolGlobalString(''MRP_MO_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_ADVANCED_MASK', 'string', NULL, 'core', 'Stores the numbering mask used by the Advanced MRP manufacturing order numbering module.', 'Read in mod_mo_advanced.php at lines 89 (UI display) and 142 (mask retrieval for reference generation). No dolibarr_set_const write is present in the payload.', 'Changing this mask alters how new manufacturing order reference numbers are generated by the Advanced module.', 'A mask pattern string; empty = no mask.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["mod_mo_advanced.php:89|read|value=''...getDolGlobalString(''MRP_MO_ADVANCED_MASK'')...", "mod_mo_advanced.php:142|read|$mask = getDolGlobalString(''MRP_MO_ADVANCED_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Sets the watermark text displayed on draft Manufacturing Orders (MO) PDF documents.', 'Written at admin/mrp.php:150 via dolibarr_set_const and read at admin/mrp.php:494 into a text input in the admin UI, making it configurable through the admin panel.', 'Changing this value updates the watermark string shown on draft MO documents; an empty value removes the watermark.', 'Any string = used as the draft watermark text; empty = no watermark.', 0, 0, 'admin/mrp.php|admin/mrp.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/mrp.php:150|write|$res = dolibarr_set_const($db, \"MRP_MO_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "admin/mrp.php:494|read|print ''<input class=\"flat minwidth200\" type=\"text\" name=\"MRP_MO_DRAFT_WATERMARK\" value=\"''.dol_escape_htmltag(getDolGlobalString(''MRP_MO_DRAFT_WATERMARK'')).''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_MO_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Manufacturing Order (MO) documents in the MRP module.', 'Written in admin/mrp.php:164 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on MRP manufacturing order PDFs.', 'Arbitrary string text.', 0, 0, 'admin/mrp.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"MRP_MO_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_NEVER_CONSUME_MORE_THAN_EXPECTED', 'string', NULL, 'mrp', 'Prevents consumption of a BOM component beyond its planned quantity during production.', 'Checked in mrp/mo_production.php at line 1425. When set, the condition blocks consumption if the already-consumed amount equals or exceeds the planned line quantity.', 'Enabling this constant enforces strict adherence to BOM quantities; consumption entries that would exceed the planned amount are rejected.', '0 or unset = over-consumption allowed; 1 = consumption capped at planned quantity', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''MRP_NEVER_CONSUME_MORE_THAN_EXPECTED'') && ($line->qty - $alreadyconsumed) <= 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MRP_SHOW_COST_FOR_CONSUMPTION', 'bool', NULL, 'mrp', 'Shows cost/price fields on production consumption lines for users with the cost-update permission.', 'Checked in mrp/mo_production.php at six locations (lines 894, 971, 1117, 1207, 1351, 1446), always combined with the permissiontoupdatecost check.', 'When enabled, users who have the cost-update permission see cost input fields on each consumption line during production. When disabled, those fields are hidden.', '0 or unset = cost fields hidden on consumption lines; 1 = cost fields shown for authorized users', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if ($permissiontoupdatecost && getDolGlobalString(''MRP_SHOW_COST_FOR_CONSUMPTION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_ALLOW_EXPORT_ACCOUNTING_DOC_FOR_ALL_ENTITIES', 'bool', NULL, 'compta', 'Allows exporting accounting documents across all entities in a multi-company setup.', 'When set, compta/accounting-files.php enables cross-entity export when no specific entity is selected (line 138) and shows an otherwise greyed-out export option (lines 661-662).', 'Enabling this grants users the ability to export accounting files for all entities at once, which may expose financial data from entities the user would not normally access.', 'Empty/unset = export limited to the current entity; truthy value = cross-entity export enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["compta/accounting-files.php:138|check|if (empty($entity) && getDolGlobalString(''MULTICOMPANY_ALLOW_EXPORT_ACCOUNTING_DOC_FOR_ALL_ENTITIES'')) {", "compta/accounting-files.php:662|check|if (getDolGlobalString(''MULTICOMPANY_ALLOW_EXPORT_ACCOUNTING_DOC_FOR_ALL_ENTITIES'')) {", "compta/accounting-files.php:661|read|print '' &nbsp; <span class=\"marginleftonly marginrightonly''.(!getDolGlobalString(''MULTICOMPANY_ALLOW_EXPORT_ACCOUNTING_DOC_FOR_ALL_ENTITIES'') ? '' opacitymedium'' : '''').''\">''.$langs->"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_BACKWARD_COMPATIBILITY', 'string', NULL, 'user', 'Enables a legacy (backward-compatibility) code path for multi-company user queries, flagged as a questionable business rule by developers.', 'Checked at user/class/user.class.php:1382 and :1447. Both locations carry the comment: ''@FIXME Test on MULTICOMPANY_BACKWARD_COMPATIBILITY is a very strange business rules because the select should be always the [same]''.', 'Enabling this constant activates a non-standard user-selection code path for multi-company setups; the code itself flags this as a design issue.', 'Empty/unset = standard code path; any truthy value = legacy backward-compatible code path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// @FIXME Test on MULTICOMPANY_BACKWARD_COMPATIBILITY is a very strange business rules because the select should be always the", "user/class/user.class.php:1382|check|if (getDolGlobalString(''MULTICOMPANY_BACKWARD_COMPATIBILITY'')) {", "user/class/user.class.php:1447|check|if (getDolGlobalString(''MULTICOMPANY_BACKWARD_COMPATIBILITY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_ENTITY_IN_EXPORT_IF_SHARED', 'string', NULL, 'core', 'Adds an entity field to export definitions for shared objects in multi-company mode.', 'When set, multiple module export definitions (modSociete, modFacture, modPropale, modCommande, modAgenda, modProjet) include an entity column in their export field lists. Used across 8 occurrences in core/modules/. No admin UI write; hidden setting.', 'Enabling this constant adds an entity discriminator column to exports for shared records in multi-company setups; disabling it omits that column.', 'Non-empty (truthy) includes entity field in exports; empty or undefined excludes it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modSociete.class.php:295|check|if (getDolGlobalString(''MULTICOMPANY_ENTITY_IN_EXPORT_IF_SHARED'')) {", "core/modules/modFacture.class.php:559|check|if (getDolGlobalString(''MULTICOMPANY_ENTITY_IN_EXPORT_IF_SHARED'')) {", "core/modules/modPropale.class.php:235|check|if (getDolGlobalString(''MULTICOMPANY_ENTITY_IN_EXPORT_IF_SHARED'')) {", "core/modules/modAgenda.class.php:455|check|if (getDolGlobalString(''MULTICOMPANY_ENTITY_IN_EXPORT_IF_SHARED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_INVOICE_SHARING_ENABLED', 'bool', NULL, 'compta', 'Enables sharing of invoices and treasury data across entities in a multi-company setup.', 'Checked in compta/paiement/card.php:519, :572 and compta/bank/treso.php:223, :237, :353. All checks require isModEnabled(''multicompany''). No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant allows invoice payment and treasury views to include data from other entities when the multicompany module is active.', '0 (sharing disabled) or 1 (sharing enabled)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement/card.php:519|check|if (isModEnabled(''multicompany'') && getDolGlobalString(''MULTICOMPANY_INVOICE_SHARING_ENABLED'')) {", "compta/bank/treso.php:223|check|if (getDolGlobalInt(''MULTICOMPANY_INVOICE_SHARING_ENABLED'')) {", "compta/bank/treso.php:353|check|if (isModEnabled(''multicompany'') && isset($mc) && getDolGlobalString(\"MULTICOMPANY_INVOICE_SHARING_ENABLED\")) {", "compta/paiement/card.php:572|check|if (isModEnabled(''multicompany'') && isset($mc) && getDolGlobalString(''MULTICOMPANY_INVOICE_SHARING_ENABLED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_PMP_PER_ENTITY_ENABLED', 'bool', NULL, 'product', 'Enables per-entity weighted average price (PMP) calculation in a multi-company setup.', 'Always checked alongside MULTICOMPANY_PRODUCT_SHARING_ENABLED in product/stock/class/entrepot.class.php:721, product/stock/card.php:708, product/stock/list.php:239, and product/class/product.class.php:2984. No admin UI.', 'When both this constant and MULTICOMPANY_PRODUCT_SHARING_ENABLED are set, PMP is calculated per entity rather than globally.', 'Truthy string (per-entity PMP active) or empty/unset (global PMP).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/class/entrepot.class.php:721|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'') && getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {", "product/stock/card.php:708|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'') && getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {", "product/stock/list.php:239|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'') && getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {", "product/class/product.class.php:2984|check|if (getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_PRODUCT_SHARING_ENABLED', 'bool', NULL, 'product', 'Enables sharing of products across entities in a multi-company setup.', 'Checked in product/class/product.class.php:2983, product/stock/replenish.php:96, and warehouse/stock pages. Often paired with MULTICOMPANY_PMP_PER_ENTITY_ENABLED to conditionally apply per-entity PMP logic.', 'When enabled, products are visible and usable across entities. This affects warehouse replenishment queries and PMP (weighted average price) calculation scope.', 'Truthy string (product sharing active) or empty/unset (products are per-entity).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:2983|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'')) {", "product/stock/replenish.php:96|check|if ($count == 1 && (empty($fk_entrepot) || $fk_entrepot <= 0) && getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'')) {", "product/stock/class/entrepot.class.php:721|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'') && getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {", "product/stock/card.php:708|check|if (getDolGlobalString(''MULTICOMPANY_PRODUCT_SHARING_ENABLED'') && getDolGlobalString(''MULTICOMPANY_PMP_PER_ENTITY_ENABLED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_TRANSVERSE_MODE', 'string', NULL, 'user', 'Enables transverse (cross-entity) user mode in multi-company setups, allowing a single user to access multiple entities.', 'Checked in 65 locations including societe/class/societe.class.php:2905, core/multicompany_page.php:157, core/login functions (functions_openid_connect.php:53, functions_dolibarr.php:45, functions_ldap.php:50), and holiday/class/holiday.class.php:1936 and :2026. Code comments at user/perms.php:335 and user/class/user.class.php:1459 warn about duplicate records that occur in this mode.', 'Enabling transverse mode allows users to operate across entities without re-logging; the associated comments warn of potential duplicate records in permission tables.', 'Non-empty = transverse mode enabled (user can access multiple entities); empty/unset = standard per-entity isolation (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:2905|check|if (isModEnabled(''multicompany'') && getDolGlobalString(''MULTICOMPANY_TRANSVERSE_MODE'')) {", "core/multicompany_page.php:157|check|if (getDolGlobalInt(''MULTICOMPANY_TRANSVERSE_MODE'')\t&& !empty($user->entity) && $mc->checkRight($user->id, (string) $entityid) < 0) {", "user/perms.php:335  // but when using MULTICOMPANY_TRANSVERSE_MODE, we may have inserted record that make rubbish result here due to the duplicate record of", "user/class/user.class.php:1459  // but when using MULTICOMPANY_TRANSVERSE_MODE, we may have inserted record that make rubbish result here due to the duplicate record of"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICOMPANY_TRANSVERSE_MODE_FIX_WHEN_GU_CONTAINS_0', 'string', NULL, 'user', 'Activates a fix for multicompany transverse mode when the user group set contains a 0 entry.', 'Checked once in user/perms.php at line 337. When set, a corrective code path is executed to handle the edge case where the groupuser data contains a 0 value in transverse mode.', 'Setting this constant enables the transverse mode fix; leaving it unset skips the fix and the edge case is not handled.', 'Truthy value to enable the fix; empty or unset to skip it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/perms.php:337|check|if (getDolGlobalString(\"MULTICOMPANY_TRANSVERSE_MODE_FIX_WHEN_GU_CONTAINS_0\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_ALTERNATE_SOURCE', 'string', NULL, 'admin', 'Specifies an alternate source currency code used as a reference when computing multicurrency exchange rates.', 'Read in admin/multicurrency.php:414 via a text input with placeholder ''EUR''. The write line at :148 is commented out. The admin comment clarifies the example value.', 'Setting this constant changes the reference currency used in alternate rate computations; the write path is currently commented out.', 'Currency code string, e.g. ''EUR''.', 0, 0, 'admin/multicurrency.php|admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["//dolibarr_set_const($db, ''MULTICURRENCY_ALTERNATE_SOURCE'', GETPOST(''MULTICURRENCY_ALTERNATE_SOURCE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "print ''<input type=\"text\" name=\"MULTICURRENCY_ALTERNATE_SOURCE\" value=\"''.$conf->global->MULTICURRENCY_ALTERNATE_SOURCE.''\" size=\"10\" placeholder=\"EUR\" />&nbsp;''; // Example: EUR"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_APP_ENDPOINT', 'string', NULL, 'admin', 'Stores the URL endpoint of the external currency rate API used for fetching exchange rates.', 'Set via admin/multicurrency.php:147 and read at multicurrency/class/multicurrency.class.php:116 as `$urlendpoint = getDolGlobalString(''MULTICURRENCY_APP_ENDPOINT'', self::MULTICURRENCY_APP_ENDPOINT_DEFAULT)`. The admin UI at admin/multicurrency.php:408 shows the current value with the class default as placeholder. 3 occurrences across 2 files.', 'When unset, the class-defined default endpoint URL is used. When set, requests for exchange rate data are sent to the specified URL.', 'String (URL); unset = MultiCurrency::MULTICURRENCY_APP_ENDPOINT_DEFAULT (class constant).', 0, 0, 'admin/multicurrency.php|admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:147|write|dolibarr_set_const($db, ''MULTICURRENCY_APP_ENDPOINT'', GETPOST(''MULTICURRENCY_APP_ENDPOINT'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "multicurrency/class/multicurrency.class.php:116|read|$urlendpoint = getDolGlobalString(\"MULTICURRENCY_APP_ENDPOINT\", self::MULTICURRENCY_APP_ENDPOINT_DEFAULT);", "admin/multicurrency.php:408|read|... value=\"'' . getDolGlobalString(''MULTICURRENCY_APP_ENDPOINT'', MultiCurrency::MULTICURRENCY_APP_ENDPOINT_DEFAULT)..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_APP_KEY', 'string', NULL, 'admin', 'Stores the API key used to authenticate requests to the external currency rate provider.', 'Set via admin/multicurrency.php:145 and read at multicurrency/class/multicurrency.class.php:114 and :686 where it is sent as an ''apikey'' HTTP header. The admin UI at admin/multicurrency.php:387 checks for its presence before allowing rate synchronization. 5 occurrences across 2 files.', 'When not set, currency rate synchronization from the external provider is blocked. When set, the key is included in API requests for fetching exchange rates.', 'String (API key); empty/unset = rate sync blocked.', 0, 0, 'admin/multicurrency.php|admin/multicurrency.php|admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:145|write|dolibarr_set_const($db, ''MULTICURRENCY_APP_KEY'', GETPOST(''MULTICURRENCY_APP_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/multicurrency.php:387|check|if (!getDolGlobalString(''MULTICURRENCY_APP_KEY'')) {", "multicurrency/class/multicurrency.class.php:114|read|$key = getDolGlobalString(\"MULTICURRENCY_APP_KEY\");", "multicurrency/class/multicurrency.class.php:686|read|$addheaders = array(''apikey: ''.getDolGlobalString(''MULTICURRENCY_APP_KEY''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_APP_SOURCE', 'string', NULL, 'multicurrency', 'Specifies the base currency code used as the source for exchange rate conversions; defaults to ''USD''.', 'Set via admin/multicurrency.php:146 and read at multicurrency/class/multicurrency.class.php:115 as `$source = getDolGlobalString(''MULTICURRENCY_APP_SOURCE'', ''USD'')`. Checked at multicurrency.class.php:641 to compare against the current currency. 4 occurrences across 2 files.', 'When unset, USD is used as the base currency for rate fetching. When set to another currency code, rates are fetched relative to that currency.', 'String (ISO currency code, e.g. ''USD''); unset = ''USD'' (default).', 0, 0, 'admin/multicurrency.php|admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:146|write|dolibarr_set_const($db, ''MULTICURRENCY_APP_SOURCE'', GETPOST(''MULTICURRENCY_APP_SOURCE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "multicurrency/class/multicurrency.class.php:115|read|$source = getDolGlobalString(''MULTICURRENCY_APP_SOURCE'', ''USD'');", "multicurrency/class/multicurrency.class.php:641|check|if (getDolCurrency() != getDolGlobalString(''MULTICURRENCY_APP_SOURCE'')) {", "admin/multicurrency.php:402|read|print ''<input type=\"text\" name=\"MULTICURRENCY_APP_SOURCE\" value=\"'' . getDolGlobalString(''MULTICURRENCY_APP_SOURCE'').'''' size=\"10\" placeholder=\"USD\" />&nbsp;''; // Default: USD"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_BUY_PRICE_IN_CURRENCY', 'string', NULL, 'admin', 'Controls whether purchase prices are stored and displayed in the transaction currency rather than the base currency.', 'Read in admin/multicurrency.php:261 via a yes/no selector form, making it a standard boolean admin setting.', 'Enabling this option causes buy prices to be recorded in the foreign currency; disabling it keeps them in the base currency.', '1 = buy price in transaction currency; 0 = buy price in base currency.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["print $form->selectyesno(\"MULTICURRENCY_BUY_PRICE_IN_CURRENCY\",$conf->global->MULTICURRENCY_BUY_PRICE_IN_CURRENCY,1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_DISABLE_SYNC_CURRENCYLAYER', 'bool', NULL, 'multicurrency', 'Disables automatic currency rate synchronization from the external provider when set.', 'Checked at admin/multicurrency.php:361 (to gate the sync option display) and multicurrency/class/multicurrency.class.php:671 (to skip the sync call). 2 occurrences across 2 files.', 'When unset, currency rate synchronization from the external API is available and can run. When set, synchronization is blocked at both the UI and class levels.', 'Truthy value = synchronization disabled; empty/unset = synchronization enabled.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:361|check|if (!getDolGlobalString(''MULTICURRENCY_DISABLE_SYNC_CURRENCYLAYER'')) {", "multicurrency/class/multicurrency.class.php:671|check|if (getDolGlobalString(''MULTICURRENCY_DISABLE_SYNC_CURRENCYLAYER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_MODIFY_RATE_APPLICATION', 'string', NULL, 'admin', 'Determines which unit price field (base-currency or transaction-currency) is recalculated when an exchange rate is modified.', 'Read in admin/multicurrency.php:275 via a selectarray form. The available choices are ''PU_DOLIBARR'' and ''PU_CURRENCY'', corresponding to the two price fields.', 'Changing this setting alters which price column is recomputed on rate updates, affecting consistency between stored prices and displayed amounts.', '''PU_DOLIBARR'' = recalculate the base-currency unit price; ''PU_CURRENCY'' = recalculate the transaction-currency unit price.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["print $form->selectarray(''MULTICURRENCY_MODIFY_RATE_APPLICATION'', array(''PU_DOLIBARR'' => ''PU_DOLIBARR'', ''PU_CURRENCY'' => ''PU_CURRENCY''), $conf->global->MULTICURRENCY_MODIFY_RATE_AP"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_SHOW_ALSO_MAIN_CURRENCY_ON_PDF', 'bool', NULL, 'core', 'Controls whether the main currency totals are also displayed alongside multicurrency totals on PDF documents.', 'Checked across 8 occurrences in core/lib/pdf.lib.php and multiple invoice/order/proposal PDF modules. The commented-out line at pdf.lib.php:1061 shows the conditional: when value is 0, multicurrency details are skipped. No admin UI write is present.', 'Setting this to 0 hides main currency totals when multicurrency is active and the exchange rate is not 1; non-zero values show both currencies.', '0 = do not show main currency alongside multicurrency; non-zero or absent = show main currency totals as well.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1061  //if (!isModEnabled(\"multicurrency\") || $object->multicurrency_tx == 1 || getDolGlobalInt(''MULTICURRENCY_SHOW_ALSO_MAIN_CURRENCY_ON_PDF'') == 0) {", "core/modules/facture/doc/pdf_octopus.modules.php:1796|check|if (!isModEnabled(\"multicurrency\") || $object->multicurrency_tx == 1 || getDolGlobalInt(''MULTICURRENCY_SHOW_ALSO_MAIN_CURRENCY_ON_PDF'') == 0) {", "core/modules/facture/doc/pdf_sponge.modules.php:2047|check|if (!isModEnabled(\"multicurrency\") || $object->multicurrency_tx == 1 || getDolGlobalInt(''MULTICURRENCY_SHOW_ALSO_MAIN_CURRENCY_ON_PDF'') == 0) {", "core/modules/propale/doc/pdf_cyan.modules.php:1530|check|if (!isModEnabled(\"multicurrency\") || $object->multicurrency_tx == 1 || getDolGlobalInt(''MULTICURRENCY_SHOW_ALSO_MAIN_CURRENCY_ON_PDF'') == 0) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_CURRENCY_ON_DOCUMENT', 'bool', NULL, 'admin', 'Controls whether currency selection is displayed on documents in the multicurrency admin configuration.', 'Read at admin/multicurrency.php:248 where its integer value is used as the selected option in a select-array form control. Configurable via admin/multicurrency.php.', 'Changing this integer value alters the currency-on-document display option in the multicurrency configuration UI.', 'Integer select value; 0 or unset = default option selected; other integers = corresponding option selected.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/multicurrency.php:248|read|print $form->selectarray(\"MULTICURRENCY_USE_CURRENCY_ON_DOCUMENT\", $arrval, getDolGlobalInt(\"MULTICURRENCY_USE_CURRENCY_ON_DOCUMENT\"));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_LIMIT_BY_CURRENCY', 'bool', NULL, 'admin', 'When enabled (with the multicompany module), forces credit-limit checks to use a defined currency code instead of an empty default.', 'Checked at admin/limits.php:48, 142, 169, and 232 in combination with isModEnabled(''multicompany''). A COMMENT at admin/limits.php:49 states: ''When MULTICURRENCY_USE_LIMIT_BY_CURRENCY is on, we use always a defined currency code instead of '''' even for default.''', 'Enabling this constant changes limit calculations to always use an explicit currency code; disabling it falls back to an empty currency code for the default entity.', 'Empty/unset = use empty string for default currency in limit checks; any truthy value = use a defined currency code.', 0, 0, 'admin/limits.php|admin/limits.php|admin/limits.php|admin/limits.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// When MULTICURRENCY_USE_LIMIT_BY_CURRENCY is on, we use always a defined currency code instead of '''' even for default.", "admin/limits.php:48|check|if (isModEnabled(''multicompany'') && getDolGlobalString(''MULTICURRENCY_USE_LIMIT_BY_CURRENCY'')) {", "admin/limits.php:142|check|if (isModEnabled(''multicompany'') && getDolGlobalString(''MULTICURRENCY_USE_LIMIT_BY_CURRENCY'')) {", "admin/limits.php:232|check|if (isModEnabled(''multicompany'') && getDolGlobalString(''MULTICURRENCY_USE_LIMIT_BY_CURRENCY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_ORIGIN_TX', 'bool', NULL, 'fourn', 'When creating a document from a source document, reuses the original multicurrency exchange rate instead of fetching the current rate.', 'Shown as a select array in admin/multicurrency.php (line 235). Checked across at least 10 files including supplier_proposal/card.php:1519, fourn/commande/card.php:1930, compta/facture/card.php:3808, and expedition/class/expedition.class.php:954 (`if (getDolGlobalString(''MULTICURRENCY_USE_ORIGIN_TX'') && !empty($objectsrc->multicurrency_tx))`).', 'Enabling this setting preserves the exchange rate from the source document when creating derived documents, ensuring currency consistency across linked records.', '0 = use current exchange rate; 1 = reuse origin document exchange rate.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:235|read|print $form->selectarray(\"MULTICURRENCY_USE_ORIGIN_TX\", $arrval, getDolGlobalInt(\"MULTICURRENCY_USE_ORIGIN_TX\"));", "supplier_proposal/card.php:1519|check|if (getDolGlobalString(''MULTICURRENCY_USE_ORIGIN_TX'') && !empty($objectsrc->multicurrency_tx)) {", "fourn/commande/card.php:1930|check|if (getDolGlobalString(''MULTICURRENCY_USE_ORIGIN_TX'') && !empty($objectsrc->multicurrency_tx)) {", "expedition/class/expedition.class.php:954|check|if (getDolGlobalString(''MULTICURRENCY_USE_ORIGIN_TX'') && !empty($this->thirdparty->multicurrency_tx)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_RATE_DIRECT', 'bool', NULL, 'multicurrency', 'Enables display and use of the direct exchange rate column in the multicurrency rate management page.', 'When set, multicurrency/multicurrency_rate.php:321 applies direct-rate logic and the ''RateDirect'' column is enabled in the rate list (multicurrency_rate.php:121). Also affects the HTML form at core/class/html.form.class.php:6966. Only 3 occurrences across 2 files.', 'When unset, the direct rate column is hidden and direct-rate logic is skipped. When set, the direct rate field is shown and used.', 'Truthy value = direct rate column enabled; empty/unset = hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["multicurrency/multicurrency_rate.php:321|check|if (getDolGlobalString(''MULTICURRENCY_USE_RATE_DIRECT'')) {", "core/class/html.form.class.php:6966|check|if (getDolGlobalString(''MULTICURRENCY_USE_RATE_DIRECT'')) {", "multicurrency/multicurrency_rate.php:121|read|''cr.rate_direct'' => array(''label'' => ''RateDirect'', ''checked'' => ''0'', ''enabled'' => (!getDolGlobalString(''MULTICURRENCY_USE_RATE_DIRECT'') ? ''0'' : ''1'')),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_RATE_INDIRECT', 'bool', NULL, 'multicurrency', 'Deprecated constant that previously controlled use of the indirect exchange rate; no longer active.', 'A comment in multicurrency/multicurrency_rate.php:319 states ''MULTICURRENCY_USE_RATE_INDIRECT <-- is deprecated''. The only occurrence is a commented-out block at multicurrency_rate.php:338, indicating the feature is inactive.', 'This constant has no active effect; changing it does not alter system behavior as the code referencing it is commented out.', 'Deprecated; any value is ignored.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* MULTICURRENCY_USE_RATE_INDIRECT <-- is deprecated", "/* if (getDolGlobalString(''MULTICURRENCY_USE_RATE_INDIRECT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE', 'bool', NULL, 'multicurrency', 'Controls whether the exchange rate closest to the document date is used instead of the current rate.', 'Set via admin/multicurrency.php:222 as a select array value. Checked at multicurrency/class/multicurrency.class.php:552 (`if (getDolGlobalString(''MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE'') && !empty($date_document))`) and :564. 3 occurrences across 2 files.', 'When unset, the current exchange rate is applied to documents. When set, the system looks up the rate that was in effect on the document''s date.', 'Integer/string: truthy = use rate on document date; 0 or unset = use current rate.', 0, 0, 'admin/multicurrency.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/multicurrency.php:222|read|print $form->selectarray(\"MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE\", $arrval, getDolGlobalInt(\"MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE\"));", "multicurrency/class/multicurrency.class.php:552|check|if (getDolGlobalString(''MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE'') && !empty($date_document)) {\t// Use last known rate compared to document date", "multicurrency/class/multicurrency.class.php:564|check|if (getDolGlobalString(''MULTICURRENCY_USE_RATE_ON_DOCUMENT_DATE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYDATA_AADE_KEY', 'string', NULL, 'admin', 'Stores the AADE (Greek tax authority) API subscription key for MyData e-invoicing integration.', 'Written at admin/company.php:281 from POST ''MYDATA_AADE_KEY''. Displayed as a password input at admin/company.php:920. Managed via the admin company setup UI.', 'Changing this value updates the AADE API key used to authenticate MyData e-invoicing submissions.', 'String representing the AADE API subscription key; empty = no MyData key configured', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/company.php:281|write|dolibarr_set_const($db, \"MYDATA_AADE_KEY\", GETPOST(\"MYDATA_AADE_KEY\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/company.php:920|read|print ''<input class=\"minwidth300\" type=\"password\" name=\"MYDATA_AADE_KEY\" value=\"''.getDolGlobalString(''MYDATA_AADE_KEY'').''\"'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYDATA_AADE_USER', 'string', NULL, 'admin', 'Stores the AADE (Greek tax authority) API username for MyData e-invoicing integration.', 'Written at admin/company.php:280 from POST ''MYDATA_AADE_USER''. Displayed as a text input at admin/company.php:915. Managed via the admin company setup UI.', 'Changing this value updates the AADE API username used for MyData e-invoicing submissions to the Greek tax authority.', 'String representing the AADE API username; empty = no MyData user configured', 0, 0, 'admin/company.php|admin/company.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/company.php:280|write|dolibarr_set_const($db, \"MYDATA_AADE_USER\", GETPOST(\"MYDATA_AADE_USER\", ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/company.php:915|read|print ''<input class=\"minwidth300\" type=\"text\" name=\"MYDATA_AADE_USER\" value=\"''.getDolGlobalString(''MYDATA_AADE_USER'').''\"'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYMODULE_DRAFT_WATERMARK', 'string', NULL, 'modulebuilder', 'Sets the watermark text printed on PDFs for MyModule objects in draft status.', 'Checked and read at modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:947-948. This is a module-builder placeholder constant. No admin UI write was found; HIDDEN_GUESS is 1.', 'When set and the object is in draft status, the specified text is rendered as a watermark via pdf_watermark() on the generated PDF.', 'Any string to display as watermark; empty/unset means no watermark', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:947|check|if (getDolGlobalString(''MYMODULE_DRAFT_WATERMARK'') && $object->status == $object::STATUS_DRAFT) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:948|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', dol_escape_htmltag(getDolGlobalString(''MYMODULE_DRAFT_WATERMARK'')));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYMODULE_ENABLE_PERMISSION_CHECK', 'bool', NULL, 'modulebuilder', 'Enables permission checking in the module builder template pages for custom module objects.', 'When set, template pages (card, list, note, contact, agenda, document) in modulebuilder/template/ read this constant into $enablepermissioncheck to conditionally enforce access controls. No admin UI is present; it must be set directly.', 'Enabling this constant activates permission enforcement on custom module object pages; disabling it bypasses those checks.', 'Integer flag: 1 = permission check enabled, 0 or unset = permission check disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/myobject_card.php:148|read|$enablepermissioncheck = getDolGlobalInt(''MYMODULE_ENABLE_PERMISSION_CHECK'');", "modulebuilder/template/myobject_list.php:209|read|$enablepermissioncheck = getDolGlobalInt(''MYMODULE_ENABLE_PERMISSION_CHECK'');", "modulebuilder/template/myobject_note.php:120|read|$enablepermissioncheck = getDolGlobalInt(''MYMODULE_ENABLE_PERMISSION_CHECK'');", "modulebuilder/template/myobject_contact.php:95|read|$enablepermissioncheck = getDolGlobalInt(''MYMODULE_ENABLE_PERMISSION_CHECK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYMODULE_MYOBJECT_ADDON', 'string', NULL, 'modulebuilder', 'Specifies the numbering module class to use for MyObject reference generation in the module builder template.', 'Checked and read in modulebuilder/template/class/myobject.class.php at lines 1140–1148; defaults to ''mod_myobject_standard'' when unset. Also referenced in modulebuilder/template/core/modules/modMyModule.class.php:447–448 for the module class and path configuration.', 'Changing this value switches the active numbering module for MyObject; if unset, the system falls back to ''mod_myobject_standard''.', 'A class name string matching a numbering module under /core/modules/mymodule/, e.g. ''mod_myobject_standard'' or ''mod_myobject_advanced''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/class/myobject.class.php:1140|check|if (!getDolGlobalString(''MYMODULE_MYOBJECT_ADDON'')) {", "modulebuilder/template/class/myobject.class.php:1141|write|$conf->global->MYMODULE_MYOBJECT_ADDON = ''mod_myobject_standard'';", "modulebuilder/template/class/myobject.class.php:1147|read|$file = getDolGlobalString(''MYMODULE_MYOBJECT_ADDON'').\".php\";", "modulebuilder/template/core/modules/modMyModule.class.php:447|read|''class''=>(!getDolGlobalString(''MYMODULE_MYOBJECT_ADDON'') ? ''mod_myobject_standard'' : getDolGlobalString(''MYMODULE_MYOBJECT_ADDON'')),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYMODULE_MYOBJECT_ADDON_PDF_ODT_PATH', 'string', NULL, 'modulebuilder', 'Specifies the file-system path to the ODT template used for generating MyObject PDF documents in custom module builder templates.', 'Read once at modulebuilder/template/core/modules/mymodule/doc/doc_generic_myobject_odt.modules.php:128 via trim(). No admin UI write was found; HIDDEN_GUESS is 1. This constant is a module-builder placeholder intended to be renamed for real modules.', 'Changing this path alters which ODT template file is loaded when generating documents for this custom object type.', 'A valid file-system path string to an ODT template file', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/doc_generic_myobject_odt.modules.php:128|read|$odtPath = trim(getDolGlobalString(''MYMODULE_MYOBJECT_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYMODULE_MYOBJECT_ADVANCED_MASK', 'string', NULL, 'modulebuilder', 'Stores the numbering mask used by the advanced numbering module for MyObject in the module builder template.', 'Read in modulebuilder/template/core/modules/mymodule/mod_myobject_advanced.php at lines 94 and 145 to supply and apply the mask value for advanced reference generation.', 'Changing or clearing this value alters the mask applied when generating references for MyObject instances using the advanced numbering module.', 'Any string mask pattern accepted by the advanced numbering module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/mod_myobject_advanced.php:94|read|$text .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskvalue\" value=\"''.getDolGlobalString(''MYMODULE_MYOBJECT_ADVANCED_MASK'').''\">''", "modulebuilder/template/core/modules/mymodule/mod_myobject_advanced.php:145|read|$mask = getDolGlobalString(''MYMODULE_MYOBJECT_ADVANCED_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYOBJECT_ADDON_PDF', 'string', NULL, 'modulebuilder', 'Specifies the PDF generation module to use for MyObject documents in the module builder template.', 'Read in modulebuilder/template/class/myobject.class.php:1210 with a default fallback of ''standard_myobject'' when not set.', 'Changing this value switches the PDF template used when generating documents for MyObject; if unset, the system uses ''standard_myobject''.', 'A string naming a PDF module, defaulting to ''standard_myobject''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/class/myobject.class.php:1210|read|$modele = getDolGlobalString(''MYOBJECT_ADDON_PDF'', ''standard_myobject'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYOBJECT_DRAFT_WATERMARK', 'string', NULL, 'modulebuilder', 'Sets the watermark text printed on PDF documents for MyObject records in draft status.', 'Checked and read at modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:190-191. This is a module-builder placeholder constant intended to be renamed for real modules.', 'When set and the object is in draft status, the specified text is rendered as a watermark on the generated PDF.', 'Any string to display as watermark; empty/unset means no watermark', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:190|check|if (getDolGlobalString(''MYOBJECT_DRAFT_WATERMARK'') && $object->status == $object::STATUS_DRAFT) {", "modulebuilder/template/core/modules/mymodule/doc/pdf_standard_myobject.modules.php:191|read|$this->watermark = getDolGlobalString(''MYOBJECT_DRAFT_WATERMARK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MYSQL_OLD_OPTION_DISABLE_FK', 'bool', NULL, 'admin', 'Controls whether MySQL foreign-key checks are disabled during database export.', 'Checked at admin/tools/dolibarr_export.php:261 and :382; when set the export tool suppresses foreign-key constraint enforcement for the export operation. Configurable via the admin UI at admin/tools/dolibarr_export.php.', 'Enabling this constant can allow export of data that would otherwise violate referential integrity; disabling it keeps foreign-key checks active during export.', 'Empty/unset = foreign-key checks active; any truthy value = foreign-key checks disabled during export.', 0, 0, 'admin/tools/dolibarr_export.php|admin/tools/dolibarr_export.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/dolibarr_export.php:261|check|if (getDolGlobalString(''MYSQL_OLD_OPTION_DISABLE_FK'')) {", "admin/tools/dolibarr_export.php:382|check|if (getDolGlobalString(''MYSQL_OLD_OPTION_DISABLE_FK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('MY_SETUP_PARAM', 'string', NULL, 'product', 'Placeholder constant name used in field ''enabled'' condition examples across many entity class definitions.', 'MY_SETUP_PARAM is not a real operational constant but a documentation placeholder. It appears in 61 locations across multiple class files (e.g. opensurvey/class/opensurveysondage.class.php:90, variants/class/ProductAttribute.class.php:79) exclusively inside PHPDoc comment examples illustrating how the ''enabled'' field condition can reference a global constant.', 'Changing or setting this constant has no operational effect; it exists solely as an illustrative placeholder name in docblock examples.', 'Not applicable — placeholder only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["''enabled'' is a condition when the field must be managed (Example: 1 or ''getDolGlobalInt(\"MY_SETUP_PARAM\")'' or ''isModEnabled(\"multicurrency\")'' ...)", "''enabled'' is a condition when the field must be managed (Example: 1 or ''getDolGlobalString(\"MY_SETUP_PARAM\")''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NBLINES_TO_DUPLICATE_TOTAL_TIMESPENT_ON_TOP', 'string', NULL, 'projet', 'Sets the minimum task count above which a duplicate total time-spent row is shown at the top of the weekly/daily activity table.', 'Used in projet/activity/perweek.php:720 and projet/activity/perday.php:693 to decide whether to render a summary row at the top when JavaScript/AJAX is enabled and the task list is long. Default value is 10.', 'Increasing the threshold reduces how often the duplicate header row appears; decreasing it causes it to appear for smaller task lists.', 'Integer (default 10); display triggers when task count >= this value', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/activity/perweek.php:720|check|if ($conf->use_javascript_ajax && count($tasksarray) >= getDolGlobalInt(''NBLINES_TO_DUPLICATE_TOTAL_TIMESPENT_ON_TOP'', 10)) {", "projet/activity/perday.php:693|check|if ($conf->use_javascript_ajax && count($tasksarray) >= getDolGlobalInt(''NBLINES_TO_DUPLICATE_TOTAL_TIMESPENT_ON_TOP'', 10)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NB_REC_FACT_GEN_BY_CALL', 'string', NULL, 'fourn', 'Limits the number of recurring supplier invoices generated per cron/script call.', 'Read at fourn/class/fournisseur.facture-rec.class.php:1384-1385: ''if (getDolGlobalInt(''NB_REC_FACT_GEN_BY_CALL''))'' then ''$sql .= $this->db->plimit(getDolGlobalInt(''NB_REC_FACT_GEN_BY_CALL''))''. No admin UI write path is present.', 'When set to a positive integer, the SQL query fetching recurring supplier invoices for generation is limited to that number of records per call; when not set, no limit is applied.', '0 or not set = no limit on recurring supplier invoices generated per call; positive integer = maximum records processed per call.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.facture-rec.class.php:1384|check|if (getDolGlobalInt(''NB_REC_FACT_GEN_BY_CALL'')) {", "fourn/class/fournisseur.facture-rec.class.php:1385|read|$sql .= $this->db->plimit(getDolGlobalInt(''NB_REC_FACT_GEN_BY_CALL''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NDF_CC_EMAILS', 'string', NULL, 'expensereport', 'Specifies one or more CC email addresses to include when sending expense report notification emails.', 'Read at expensereport/card.php:670 into $emailCC; the value is used directly as the CC recipient list for expense report emails.', 'Setting this constant adds the specified addresses as CC recipients on expense report emails; leaving it empty sends emails without CC.', 'Empty/unset = no CC addresses; a valid email address string (or comma-separated list) = used as CC.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expensereport/card.php:670|read|$emailCC = getDolGlobalString(''NDF_CC_EMAILS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NDF_EXPLODE_CHAR', 'string', NULL, 'core', 'Defines the separator character used to split expense-report reference numbers in the jade numbering module.', 'Read in core/modules/expensereport/mod_expensereport_jade.php:141; defaults to ''-'' when not set. No admin UI write is present.', 'Changing this character alters how generated reference numbers are split and formatted by the jade module; the default is ''-''.', 'Single separator character string; defaults to ''-'' when empty or unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/mod_expensereport_jade.php:141|read|$expld_car = (!getDolGlobalString(''NDF_EXPLODE_CHAR'')) ? \"-\" : $conf->global->NDF_EXPLODE_CHAR;"]', 'low', NULL);
