INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_CONTACT', 'bool', NULL, 'core', 'Disables the confirmation email sent to the contact linked to a notification event.', 'Read in admin/notification.php:241 as a select array value, checked in core/class/notify.class.php:209 to suppress contact confirmation messages.', 'Enabling this prevents the linked contact from receiving a confirmation notification email. Leaving unset allows confirmation messages to be sent to the contact.', '0 or empty = confirmation message sent to contact; non-empty = confirmation message to contact disabled', 0, 0, 'admin/notification.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/notify.class.php:209|check|if (getDolGlobalString(''NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_CONTACT'')) {", "admin/notification.php:241|read|print $form->selectarray(\"NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_CONTACT\", $arrval, getDolGlobalString(''NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_CONTACT''));"]', 'medium', NULL);
