INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_USER', 'bool', NULL, 'core', 'Disables the confirmation email sent to the user who triggered a notification event.', 'Read in admin/notification.php:228 as a select array value, checked in core/class/notify.class.php:201 to suppress user confirmation messages.', 'Enabling this prevents the triggering user from receiving a confirmation notification email. Leaving unset allows confirmation messages to be sent to the user.', '0 or empty = confirmation message sent to user; non-empty = confirmation message to user disabled', 0, 0, 'admin/notification.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/notify.class.php:201|check|if (getDolGlobalString(''NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_USER'')) {", "admin/notification.php:228|read|print $form->selectarray(\"NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_USER\", $arrval, getDolGlobalString(''NOTIFICATION_EMAIL_DISABLE_CONFIRM_MESSAGE_USER''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NOTIFICATION_EMAIL_FROM', 'string', NULL, 'admin', 'Specifies the sender email address used for notification emails dispatched by the notification system.', 'Written in admin/notification.php:105 and validated as a proper email at :214. Read in core/class/notify.class.php:665 as the $from address when sending notifications.', 'Setting a valid email address overrides the default sender for all notification emails. An invalid address is rejected by the admin UI; leaving empty uses the system default.', 'Valid email address string; empty = system default sender used', 0, 0, 'admin/notification.php|admin/notification.php|admin/notification.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/notify.class.php:665|read|$from = getDolGlobalString(''NOTIFICATION_EMAIL_FROM'');", "admin/notification.php:105|write|$result = dolibarr_set_const($db, \"NOTIFICATION_EMAIL_FROM\", GETPOST(\"email_from\", \"alphawithlgt\"), ''chaine'', 0, '''', $conf->entity);", "admin/notification.php:214|check|if (getDolGlobalString(''NOTIFICATION_EMAIL_FROM'') && !isValidEmail(getDolGlobalString(''NOTIFICATION_EMAIL_FROM''))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NOTIFICATION_FIXEDEMAIL_', 'string', NULL, 'admin', 'Stores a fixed email address and threshold for a specific notification event, keyed by event code and threshold level.', 'Set via the admin UI at admin/notification.php. The constant name is dynamic, combining event code and threshold (e.g. NOTIFICATION_FIXEDEMAIL_<event>_THRESHOLD_HIGHER_<level>). The payload shows a deletion call, indicating management of per-event fixed email notification targets.', 'Removing or changing these constants alters which fixed email addresses receive threshold-based notifications for specific events.', 'String (email address or notification config); name includes event code and threshold suffix.', 0, 0, 'admin/notification.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/notification.php:144|write|dolibarr_del_const($db, ''NOTIFICATION_FIXEDEMAIL_''.$reg[1].''_THRESHOLD_HIGHER_''.$reg[2], $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('NW_RECEIPTNUMBERFORMAT', 'string', NULL, 'compta', 'Selects an alternative receipt number format for bank entries.', 'Checked via getDolGlobalInt at compta/bank/bankentries_list.php:971; when non-zero, a different receipt number format is applied. No admin UI write occurrence found.', 'Setting a non-zero integer value changes the receipt number format displayed in the bank entries list.', '0 or empty = default receipt number format; non-zero integer = alternative format', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/bankentries_list.php:971|check|if (getDolGlobalInt(''NW_RECEIPTNUMBERFORMAT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_', 'string', NULL, 'core', 'Family of dynamic constants prefixed OAUTH_ storing OAuth2 provider credentials (ID, SECRET, URLCALLBACK, SCOPE, TENANT) keyed by provider name.', 'Read dynamically across admin/oauthlogintokens.php (lines 170-172, 186), admin/emailcollector_card.php (lines 457-459), and admin/oauth.php:451 using patterns like OAUTH_{PROVIDER}_ID, OAUTH_{PROVIDER}_SECRET, OAUTH_{PROVIDER}_URLCALLBACK, OAUTH_{PROVIDER}_SCOPE, OAUTH_{PROVIDER}_TENANT. Stored and displayed via the admin OAuth configuration UI.', 'Setting the correct ID, SECRET, and URLCALLBACK constants for a provider enables OAuth2 authentication and token management for that service; incorrect values will cause authentication failures.', 'String; values are provider-specific client IDs, secrets, callback URLs, scope lists, and tenant IDs supplied by the OAuth2 provider.', 0, 0, 'admin/emailcollector_card.php|admin/emailcollector_card.php|admin/emailcollector_card.php|admin/oauthlogintokens.php|admin/oauthlogintokens.php|admin/oauthlogintokens.php|admin/oauthlogintokens.php|admin/oauth.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/oauthlogintokens.php:170|read|getDolGlobalString(''OAUTH_''.$keyforoauthservice.''_ID''),", "admin/oauthlogintokens.php:171|read|getDolGlobalString(''OAUTH_''.$keyforoauthservice.''_SECRET''),", "admin/oauthlogintokens.php:186|read|$scopes = explode('','', getDolGlobalString(''OAUTH_''.strtoupper($tmp[0]).(empty($tmp[1]) ? '''' : ''-''.$tmp[1]).''_SCOPE''));", "admin/oauth.php:451|read|print ''<td><input type=\"text\" size=\"100\" id=\"OAUTH_''.$keybeforeprovider.($keyforprovider ? ''-''.$keyforprovider : '''').''_TENANT\" name=\"OAUTH_''.$keybeforeprovider.($keyforprovider ? ''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_ADD_SCOPE_AND_TENANT_IN_REFRESH_MESSAGE', 'string', NULL, 'core', 'Adds scope and tenant information to the OAuth2 token refresh message for debugging purposes.', 'Checked at includes/OAuth/OAuth2/Service/AbstractService.php:223. The payload also shows the activation pattern at line 222 as a commented example: ''//global $conf; $conf->global->OAUTH_ADD_SCOPE_AND_TENANT_IN_REFRESH_MESSAGE = 1;'', indicating it is set directly in code for debugging.', 'Enabling this constant enriches OAuth2 refresh-related messages with scope and tenant details, aiding diagnostics of token refresh failures.', 'Integer 1 to enable; unset or 0 to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/OAuth/OAuth2/Service/AbstractService.php:222  //global $conf; $conf->global->OAUTH_ADD_SCOPE_AND_TENANT_IN_REFRESH_MESSAGE = 1;", "includes/OAuth/OAuth2/Service/AbstractService.php:223|check|if (getDolGlobalString(''OAUTH_ADD_SCOPE_AND_TENANT_IN_REFRESH_MESSAGE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_DEBUG', 'string', NULL, 'core', 'Enables debug logging for OAuth HTTP client requests (cURL and stream clients).', 'Checked in includes/OAuth/Common/Http/Client/CurlClient.php:126 and includes/OAuth/Common/Http/Client/StreamClient.php:93, with a function_exists guard ensuring safety outside full Dolibarr context.', 'Enabling this activates OAuth request debug output; disabling it suppresses debug logging.', 'truthy = enable OAuth debug logging; empty/not set = no debug output', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/OAuth/Common/Http/Client/CurlClient.php:126|check|if (function_exists(''getDolGlobalString'') && getDolGlobalString(''OAUTH_DEBUG'')) {", "includes/OAuth/Common/Http/Client/StreamClient.php:93|check|if (function_exists(''getDolGlobalString'') && getDolGlobalString(''OAUTH_DEBUG'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_GOOGLE_FORCE_PROMPT_ON_LOGIN', 'string', NULL, 'core', 'Controls the OAuth2 approval_prompt parameter sent to Google during authentication, defaulting to ''auto''.', 'Read in core/modules/oauth/google_oauthcallback.php:189 with a fallback default of ''auto''. The inline comment notes that it can be set to ''force''.', 'Setting this to ''force'' causes Google to always show the OAuth consent screen, even when consent was previously granted; ''auto'' (default) skips the screen when consent is cached.', 'Can be ''force'' or ''auto'' (default when empty).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/oauth/google_oauthcallback.php:189|read|$approval_prompt = getDolGlobalString(''OAUTH_GOOGLE_FORCE_PROMPT_ON_LOGIN'', ''auto'');\t// Can be ''force''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_GOOGLE_ID', 'string', NULL, 'core', 'Stores the Google OAuth client ID used by the Google Cloud Print module.', 'Used in a single location in core/modules/printing/printgcp.modules.php:114, where it is assigned to $this->google_id for use in OAuth authentication with Google Cloud Print.', 'Setting this to the correct Google OAuth client ID enables the GCP printing module to authenticate with Google. Clearing it disables OAuth-based Google Cloud Print integration.', 'Any non-empty string = Google OAuth client ID; empty/unset = GCP OAuth not configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["printgcp.modules.php:114|$this->google_id = getDolGlobalString(''OAUTH_GOOGLE_ID'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_GOOGLE_SECRET', 'string', NULL, 'core', 'Stores the Google OAuth client secret used by the Google Cloud Print module.', 'Used in a single location in core/modules/printing/printgcp.modules.php:115, where it is assigned to $this->google_secret for use in OAuth authentication with Google Cloud Print.', 'Setting this to the correct Google OAuth client secret enables the GCP printing module to authenticate with Google. Clearing it disables OAuth-based Google Cloud Print integration.', 'Any non-empty string = Google OAuth client secret; empty/unset = GCP OAuth not configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["printgcp.modules.php:115|$this->google_secret = getDolGlobalString(''OAUTH_GOOGLE_SECRET'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_MICROSOFT', 'string', NULL, 'core', 'Placeholder constant related to Microsoft OAuth tenant configuration (currently commented out).', 'The sole occurrence in includes/OAuth/Common/Storage/DoliStorage.php:399 is a commented-out line referencing this constant for tenant resolution. The COMMENT in the payload reads: ''//$this->tenant = getDolGlobalString(''OAUTH_MICROSOFT''.($this->keyforprovider ? ''-''.$this->keyforprovider : '''').''_TENANT'');''. No active read or write exists.', 'This constant has no active effect as its only usage is commented out.', 'Exact behavior unclear from code alone', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["includes/OAuth/Common/Storage/DoliStorage.php:399  //$this->tenant = getDolGlobalString(''OAUTH_MICROSOFT''.($this->keyforprovider ? ''-''.$this->keyforprovider : '''').''_TENANT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_SERVICE_SOCIAL_NETWORK', 'string', NULL, 'admin', 'Selects the OAuth service used for social network (Fediverse) integration.', 'Configured via admin/fediverse.php (dolibarr_set_const at line 96). Displayed as a dropdown (selectarray at line 355) and read at line 357 for the currently selected OAuth key.', 'Changing this value switches which OAuth provider is used for social network posting; selecting an unconfigured service will break Fediverse integration.', 'String key corresponding to a configured OAuth service; empty = no OAuth service selected.', 0, 0, 'admin/fediverse.php|admin/fediverse.php|admin/fediverse.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fediverse.php:96|write|dolibarr_set_const($db, \"OAUTH_SERVICE_SOCIAL_NETWORK\", GETPOST(\"OAUTH_SERVICE_SOCIAL_NETWORK\", ''alphanohtml''), ''chaine'', 0, '''', $conf->entity);", "admin/fediverse.php:355|read|print $form->selectarray(''OAUTH_SERVICE_SOCIAL_NETWORK'', $oauthservicesStringKeys, (string) getDolGlobalString(\"OAUTH_SERVICE_SOCIAL_NETWORK\"));", "admin/fediverse.php:357|read|$selectedKey = (string) getDolGlobalString(''OAUTH_SERVICE_SOCIAL_NETWORK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OAUTH_WORDPRESS_AUTHORIZATION_METHOD_QUERY_STRING', 'string', NULL, 'core', 'Switches the WordPress OAuth2 authorization method between Bearer header and query-string token delivery.', 'Used in includes/OAuth/OAuth2/Service/WordPress.php:76. When empty, the method defaults to AUTHORIZATION_METHOD_HEADER_BEARER; when set, it uses AUTHORIZATION_METHOD_QUERY_STRING.', 'Enabling this constant changes how the OAuth access token is transmitted to the WordPress API, which may be required by certain WordPress configurations.', 'Non-empty = use query string authorization; empty/unset = use Bearer header authorization.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["return empty($conf->global->OAUTH_WORDPRESS_AUTHORIZATION_METHOD_QUERY_STRING) ? static::AUTHORIZATION_METHOD_HEADER_BEARER : static::AUTHORIZATION_METHOD_QUERY_STRING;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OBJECTELEMENT_FIELDNAME', 'string', NULL, 'core', 'Overrides the field name used to return an object element value when no dedicated table or hook provides it.', 'Used in core/class/commonobject.class.php:6520 as a fallback in the element-field resolution chain. When set, the constant value is returned directly. The code comment notes it is better to use a dedicated table instead.', 'If set, the object element resolution skips further lookups and returns the constant''s value, which may override correct data if misconfigured.', 'Any string field name; empty/unset means this fallback is not used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["* 3) If not but a constant $conf->global->OBJECTELEMENT_FIELDNAME is set, we return it (It is better to use the dedicated table)."]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ODT_ADD_DOLIBARR_ID', 'string', NULL, 'core', 'Controls whether the Dolibarr internal ID is appended to substitution variables in ODT document generation for companies.', 'Checked once in core/modules/societe/doc/doc_generic_odt.modules.php at line 441. When set, the Dolibarr internal ID is added to the document variable set during ODT generation.', 'Enabling this constant adds the Dolibarr internal object ID to the substitution variables available in generated ODT documents.', 'Truthy value to include Dolibarr ID; empty or unset to omit it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/societe/doc/doc_generic_odt.modules.php:441|check|if (getDolGlobalString(''ODT_ADD_DOLIBARR_ID'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ODT_ENABLE_ALL_TAGS_IN_SUBSTITUTIONS', 'bool', NULL, 'core', 'Enables inclusion of all substitution tags (including extended ones) when generating ODT documents.', 'Checked at core/lib/functions.lib.php:11249. When truthy, the substitution tag list passed to the ODT template engine is extended beyond the default set.', 'Enabling this constant expands the set of tags available for ODT template substitution; disabling it restricts substitutions to the default tag set.', '0 or empty = default substitution tags only; any truthy value = all tags included in ODT substitutions', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:11249|check|if (getDolGlobalString(''ODT_ENABLE_ALL_TAGS_IN_SUBSTITUTIONS'')) {"]', 'low', NULL);
