INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_PAYMENT_CSS_URL', 'string', NULL, 'public', 'URL of a custom CSS stylesheet applied to public online payment pages.', 'Written via paypal/admin/paypal.php:87, paybox/admin/paybox.php:85, and stripe/admin/stripe.php:137. Checked in public payment and event pages (e.g. public/eventorganization/subscriptionok.php:176, public/project/index.php:214) to include the stylesheet when set.', 'When set, the specified CSS file is included on all public payment pages, allowing visual customization of the payment interface.', 'String: URL of the custom CSS file (e.g. ''https://example.com/payment.css''); empty to use default styles.', 0, 0, 'paybox/admin/paybox.php|stripe/admin/stripe.php|paypal/admin/paypal.php|paypal/admin/paypal.php|paybox/admin/paybox.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:85|write|$result = dolibarr_set_const($db, \"ONLINE_PAYMENT_CSS_URL\", GETPOST(''ONLINE_PAYMENT_CSS_URL'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:577|read|print ''<input class=\"width500\" type=\"text\" name=\"ONLINE_PAYMENT_CSS_URL\" value=\"'' . getDolGlobalString(''ONLINE_PAYMENT_CSS_URL'').''\"...>;", "public/eventorganization/subscriptionok.php:176|check|if (getDolGlobalString(''ONLINE_PAYMENT_CSS_URL'')) {", "public/project/index.php:214|check|if (getDolGlobalString(''ONLINE_PAYMENT_CSS_URL'')) {"]', 'high', NULL);
