INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_PAYMENT_SENDEMAIL', 'string', NULL, 'public', 'Email address(es) to notify when an online payment is completed or fails.', 'Written via paypal/admin/paypal.php:107, paybox/admin/paybox.php:101, and stripe/admin/stripe.php:153. Read in public/payment/paymentok.php:2144 and public/payment/paymentko.php:215 as the recipient for payment notification emails.', 'When set, payment confirmation and failure notifications are sent to the specified address(es).', 'String: email address or comma-separated list of addresses to notify on payment events.', 0, 0, 'paybox/admin/paybox.php|stripe/admin/stripe.php|paypal/admin/paypal.php|paypal/admin/paypal.php|paybox/admin/paybox.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:101|write|$result = dolibarr_set_const($db, \"ONLINE_PAYMENT_SENDEMAIL\", GETPOST(''ONLINE_PAYMENT_SENDEMAIL'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "public/payment/paymentok.php:2144|read|$sendemail = getDolGlobalString(''ONLINE_PAYMENT_SENDEMAIL'');", "public/payment/paymentko.php:215|read|$sendemail = getDolGlobalString(''ONLINE_PAYMENT_SENDEMAIL'');", "stripe/admin/stripe.php:602|read|print ''<input class=\"minwidth200\" type=\"text\" name=\"ONLINE_PAYMENT_SENDEMAIL\" value=\"'' . getDolGlobalString(''ONLINE_PAYMENT_SENDEMAIL'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_PAYMENT_WAREHOUSE', 'string', NULL, 'stripe', 'Specifies the warehouse used when recording stock movements triggered by online payments.', 'The write call in stripe/admin/stripe.php:158 is commented out, meaning this constant is currently not actively set via the admin UI. Exact behavior is unclear from code alone.', 'Exact behavior unclear from code alone. Setting a warehouse ID here would direct stock movements from online payment processing to that warehouse.', 'Warehouse ID (positive integer as string); empty string means no warehouse selected.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["stripe/admin/stripe.php:158  //$result = dolibarr_set_const($db, \"ONLINE_PAYMENT_WAREHOUSE\", (GETPOST(''ONLINE_PAYMENT_WAREHOUSE'', ''alpha'') > 0 ? GETPOST(''ONLINE_PAYMENT_WAREHOUSE'', ''alpha'') : ''''), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_RECRUITMENT_LOGO', 'string', NULL, 'public', 'Path or URL of a custom logo displayed on the public recruitment pages.', 'Read in public/recruitment/view.php:332-333 and public/recruitment/index.php:152 where it is fetched into `$logosmall` for rendering. No admin UI write path is present.', 'When set, the specified logo image is shown on public recruitment pages instead of the default Dolibarr logo.', 'File path or URL string pointing to an image', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["} elseif (getDolGlobalString(''ONLINE_RECRUITMENT_LOGO'')) {", "$logosmall = getDolGlobalString(''ONLINE_RECRUITMENT_LOGO'');", "public/recruitment/view.php:332|read"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_RECRUITMENT_LOGO_', 'string', NULL, 'public', 'Path or URL of an alternate logo variant for the public recruitment index page (note trailing underscore in constant name).', 'Read once at public/recruitment/index.php:153 into `$logosmall`. No admin UI write path is present. The trailing underscore in the name distinguishes it from ONLINE_RECRUITMENT_LOGO.', 'When set, this value overrides the logo displayed on the recruitment index page.', 'File path or URL string pointing to an image', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$logosmall = getDolGlobalString(''ONLINE_RECRUITMENT_LOGO_'');", "public/recruitment/index.php:153|read"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_SIGN_NEWFORM_TEXT', 'string', NULL, 'public', 'Stores custom introductory text displayed on the public online signature form.', 'Checked at public/onlinesign/newonlinesign.php:290; the value is appended to $text at line 295 and also matched against a parenthesis pattern via preg_match at line 292 to extract inner content. No admin UI write is present.', 'Setting this constant injects custom text into the signature form header; leaving it unset shows no custom text.', 'String text to display; if wrapped in parentheses like ''(text)'', inner content is extracted; unset/empty = no custom text.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/onlinesign/newonlinesign.php:290|check|if (getDolGlobalString(''ONLINE_SIGN_NEWFORM_TEXT'')) {", "public/onlinesign/newonlinesign.php:292|read|if (preg_match(''/^\\((.*)\\)$/'', $conf->global->ONLINE_SIGN_NEWFORM_TEXT, $reg)) {", "public/onlinesign/newonlinesign.php:295|read|$text .= getDolGlobalString(''ONLINE_SIGN_NEWFORM_TEXT'') . \"<br>\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ONLINE_USER_LOGO', 'string', NULL, 'public', 'Specifies the URL of a small logo image to display on the public user profile page.', 'In public/users/view.php at lines 478-479, the value is read into $logosmall for conditional display. No admin UI write path is present.', 'Setting this causes a custom logo to appear on the public user view page; leaving it unset uses the default display.', 'String: URL of the logo image to display on the public user profile page', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/users/view.php:478|read|} elseif (getDolGlobalString(''ONLINE_USER_LOGO'')) {", "public/users/view.php:479|read|$logosmall = getDolGlobalString(''ONLINE_USER_LOGO'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSTREETMAP_ENABLE_MAPS', 'bool', NULL, 'core', 'Enables an OpenStreetMap link on thirdparty (company/societe) address fields when the OpenStreetMap module is active.', 'Checked in core/lib/functions.lib.php:5383 for element types ''thirdparty'' or ''societe'' with isModEnabled(''openstreetmap''). No admin UI write detected.', 'Setting this constant adds an OpenStreetMap link to thirdparty address displays. Without it, no map link appears.', 'Non-empty = show OpenStreetMap link on thirdparty; absent/empty = no link. Requires openstreetmap module enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5383|check|if (($element == ''thirdparty'' || $element == ''societe'') && isModEnabled(''openstreetmap'') && getDolGlobalString(''OPENSTREETMAP_ENABLE_MAPS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSTREETMAP_ENABLE_MAPS_CONTACTS', 'bool', NULL, 'core', 'Enables an OpenStreetMap link on contact address fields when the OpenStreetMap module is active.', 'Checked in core/lib/functions.lib.php:5386 for element type ''contact'' with isModEnabled(''openstreetmap''). No admin UI write detected.', 'Setting this constant adds an OpenStreetMap link to contact address displays. Without it, no map link appears on contact records.', 'Non-empty = show OpenStreetMap link on contacts; absent/empty = no link. Requires openstreetmap module enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5386|check|if ($element == ''contact'' && isModEnabled(''openstreetmap'') && getDolGlobalString(''OPENSTREETMAP_ENABLE_MAPS_CONTACTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSTREETMAP_ENABLE_MAPS_MEMBERS', 'bool', NULL, 'core', 'Enables an OpenStreetMap link on member address fields when the OpenStreetMap module is active.', 'Checked in core/lib/functions.lib.php:5389 for element type ''member'' with isModEnabled(''openstreetmap''). No admin UI write detected.', 'Setting this constant adds an OpenStreetMap link to member address displays. Without it, no map link appears on member records.', 'Non-empty = show OpenStreetMap link on members; absent/empty = no link. Requires openstreetmap module enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5389|check|if ($element == ''member'' && isModEnabled(''openstreetmap'') && getDolGlobalString(''OPENSTREETMAP_ENABLE_MAPS_MEMBERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSTREETMAP_ENABLE_MAPS_USERS', 'bool', NULL, 'core', 'Enables OpenStreetMap map display on user records when the openstreetmap module is active.', 'When set, the application checks both that the openstreetmap module is enabled and that this constant is truthy before rendering a map for user elements. Seen in core/lib/functions.lib.php:5392.', 'Disabling this constant suppresses the map widget on user pages even when the openstreetmap module is loaded.', '0 or empty = map disabled for users; any truthy value = map enabled for users', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:5392|check|if ($element == ''user'' && isModEnabled(''openstreetmap'') && getDolGlobalString(''OPENSTREETMAP_ENABLE_MAPS_USERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSURVEY_ENABLE_PUBLIC_INTERFACE', 'bool', NULL, 'public', 'Enables the public-facing OpenSurvey interface; the code forces it to 1 if not already set.', 'Checked at public/opensurvey/index.php:118; at :116 the code writes $conf->global->OPENSURVEY_ENABLE_PUBLIC_INTERFACE = 1 if the constant is not already defined, then gates further processing on its presence.', 'When unset the code self-enables the interface by writing 1; explicitly disabling it (setting to a falsy value before the code runs) would block access to the public survey page.', '0 = public interface disabled (access blocked at :118); 1 or unset = public interface enabled (code forces to 1).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/opensurvey/index.php:116|write|$conf->global->OPENSURVEY_ENABLE_PUBLIC_INTERFACE = 1;", "public/opensurvey/index.php:118|check|if (!getDolGlobalString(''OPENSURVEY_ENABLE_PUBLIC_INTERFACE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPENSURVEY_PUBLIC_INTERFACE_TOPIC', 'string', NULL, 'public', 'Specifies the topic/title string used in the public OpenSurvey interface page header.', 'Read at public/opensurvey/index.php:133 as a parameter to htmlPrintOnlineHeader; the value is passed as the topic argument for the public survey header.', 'Setting this constant customizes the title displayed in the public survey page header; leaving it unset passes an empty string.', 'Any string = used as the public interface page topic/title; empty/unset = no custom topic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/opensurvey/index.php:133|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''OPENSURVEY_PUBLIC_INTERFACE_TOPIC''), ''OPENSURVEY_IMAGE_PUBLIC_INTERFACE'', ''ONLINE_OPENSURVEY_LOGO_''.$suffix, ''ONLINE_OP"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('OPTIMIZEFORTEXTBROWSER', 'string', NULL, 'core', 'Activates text-browser optimizations, suppressing certain UI elements incompatible with text-only browsers.', 'Checked in core/class/html.formfile.class.php at lines 346 and 352 to conditionally skip rendering elements. No admin UI write is present.', 'When enabled, UI elements that require JavaScript or graphical rendering are hidden or skipped, improving compatibility with text browsers.', 'Truthy value (e.g. 1) to enable text-browser optimizations; 0 or empty to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formfile.class.php:346|check|if (getDolGlobalString(''OPTIMIZEFORTEXTBROWSER'')) {", "core/class/html.formfile.class.php:352|check|if (getDolGlobalString(''OPTIMIZEFORTEXTBROWSER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Allows external download links to be generated for sales order documents.', 'Checked at core/lib/functions.lib.php:10733. The condition additionally verifies that an object is present and its element type is ''commande'' (sales order).', 'Enabling this constant permits generation of external download URLs for sales orders; disabling it suppresses that link generation.', '0 or empty = external download not allowed for orders; any truthy value = external download link generated for commande objects', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:10733|check|if (getDolGlobalString(''ORDER_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''commande'') {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_ALLOW_POS_SOURCE_EDIT', 'bool', NULL, 'commande', 'Allows editing of the POS (point of sale) source field on an order even without an active TakePos module or existing module_source.', 'Checked in commande/card.php:3004 in an OR condition with isModEnabled(''takepos'') and $object->module_source. When set, the POS source field becomes editable regardless of other conditions. No admin UI write is present.', 'Setting this constant makes the POS source field editable on all orders. Leaving it unset restricts POS source editing to orders linked to TakePos or with an existing module_source.', 'Truthy = POS source field always editable; falsy or unset = editable only when TakePos is enabled or module_source is set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3004|check|if (isModEnabled(''takepos'') || $object->module_source || getDolGlobalString(''ORDER_ALLOW_POS_SOURCE_EDIT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_BILLING_ALL_CUSTOMER', 'string', NULL, 'commande', 'Enables a billing action that creates invoices for all orders of a customer at once.', 'Checked in commande/list.php:2549 and commande/list_det.php:1715: the bulk-bill-all-customer option is shown or executed only when the invoice module is enabled and this constant is non-empty.', 'Enabling this constant adds a billing action that processes all customer orders together; leaving it empty hides that option.', 'Empty = per-order billing only (default); any non-empty value = bulk all-customer billing enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:2549|check|if (isModEnabled(''invoice'') && getDolGlobalString(''ORDER_BILLING_ALL_CUSTOMER'')) {", "commande/list_det.php:1715|check|if (isModEnabled(''invoice'') && getDolGlobalString(''ORDER_BILLING_ALL_CUSTOMER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_BILL_AFTER_VALIDATION', 'string', NULL, 'index.php', 'When enabled, shows only orders that have been validated (not yet billed) in the customer orders dashboard block.', 'Checked in index.php:237; when set the orders block filters to post-validation orders awaiting billing. No admin UI is present.', 'Setting this constant changes the orders workboard block to display validated-but-unbilled orders instead of the default view.', 'Boolean flag: truthy = filter to validated orders; 0 or unset = default order display.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["index.php:237|check|if (getDolGlobalInt(''ORDER_BILL_AFTER_VALIDATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_BOX_LAST_ORDERS_SHOW_VALIDATE_USER', 'bool', NULL, 'core', 'Shows the user who validated each order in the last-orders dashboard box.', 'Checked in core/boxes/box_commandes.php:174 to conditionally add the validator''s identity to the widget output.', 'Enabling this constant adds a ''validated by'' user field to each row in the last-orders dashboard widget.', 'Empty/not set = validator not shown; any truthy string = validator displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_commandes.php:174|check|if (getDolGlobalString(''ORDER_BOX_LAST_ORDERS_SHOW_VALIDATE_USER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_BOX_LAST_ORDERS_VALIDATED_ONLY', 'string', NULL, 'core', 'Restricts the last-orders dashboard box to show only validated orders.', 'Checked in core/boxes/box_commandes.php:105 to filter the query to validated orders only.', 'Enabling this constant causes the last-orders dashboard widget to exclude draft and cancelled orders, showing only validated ones.', 'Empty/not set = all statuses shown; any truthy string = validated orders only', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_commandes.php:105|check|if (getDolGlobalString(''ORDER_BOX_LAST_ORDERS_VALIDATED_ONLY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_BOX_LAST_SHIPMENTS_VALIDATED_ONLY', 'string', NULL, 'core', 'Restricts the last shipments dashboard box to show only validated shipments.', 'Checked in core/boxes/box_shipments.php:103 to filter the shipment list query.', 'Enabling this constant filters the shipments box to exclude draft or cancelled shipments, showing only those with a validated status.', 'Truthy value = validated shipments only; empty/unset = all shipments shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_shipments.php:103|check|if (getDolGlobalString(''ORDER_BOX_LAST_SHIPMENTS_VALIDATED_ONLY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_CLOSE_TEMPLATE', 'string', NULL, 'core', 'Specifies the email template label to use when sending the order-close notification.', 'Read at core/class/notify.class.php:791 as $labeltouse for the order close event notification. No admin UI; hidden setting.', 'Setting a template label directs the notification system to use that email template for order-close events. Leaving empty uses the default notification template.', 'String email template label; empty = default notification template used for order close events', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/notify.class.php:791|read|$labeltouse = getDolGlobalString(''ORDER_CLOSE_TEMPLATE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_DISABLE_CLASSIFY_BILLED_FROM_ORDER', 'bool', NULL, 'commande', 'Disables the ''classify as billed'' action on validated customer orders.', 'Checked in commande/card.php:3639 and commande/card.php:3644, in combination with WORKFLOW_BILL_ON_SHIP and other conditions. When set, the classify-as-billed button is hidden. No admin UI write is present.', 'Setting this constant removes the ability to manually mark an order as billed directly from the order card. Leaving it unset (alongside other conditions) allows the action.', 'Truthy = classify-as-billed action hidden; falsy or unset = action available when other conditions are met.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3639|check|if ($usercancreate && $object->status >= Commande::STATUS_VALIDATED && !getDolGlobalString(''ORDER_DISABLE_CLASSIFY_BILLED_FROM_ORDER'') && !getDolGlobalString(''WORKFLOW_BILL_ON_SHIP", "commande/card.php:3644|check|if ($usercancreate && $object->status >= Commande::STATUS_VALIDATED && !getDolGlobalString(''ORDER_DISABLE_CLASSIFY_BILLED_FROM_ORDER'') && !getDolGlobalString(''WORKFLOW_BILL_ON_SHIP"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_DISABLE_DELIVERY_DATE', 'bool', NULL, 'commande', 'Disables the delivery date field on customer orders.', 'Checked at commande/list.php:1068 to conditionally include the delivery date column, and used in fourn/class/fournisseur.commande.class.php:393 to set the ''enabled'' attribute of the ''date_livraison'' field definition. Also controls column visibility in commande/list.php:240 and commande/list_det.php:210.', 'When enabled, the delivery date field is hidden and disabled across order lists and detail views; when disabled or not set, the delivery date is shown.', '0 or not set = delivery date field visible and enabled; non-zero = delivery date field hidden and disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["commande/list.php:1068|check|if (!getDolGlobalString(''ORDER_DISABLE_DELIVERY_DATE'')) {", "fourn/class/fournisseur.commande.class.php:393|read|''date_livraison'' => array(''type'' => ''datetime'', ''label'' => ''DeliveryDate'', ''enabled'' => ''getDolGlobalInt(\"ORDER_DISABLE_DELIVERY_DATE\") ? 0 : 1'', ''visible'' => 1, ''position'' => 74),", "commande/list.php:240|read|''c.delivery_date'' => array(''label'' => \"DateDeliveryPlanned\", ''checked'' => ''1'', ''enabled'' => (string) (int) !getDolGlobalString(''ORDER_DISABLE_DELIVERY_DATE''), ''position'' => 65,"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_DISABLE_SHIPPABLE_ICON_ON_CARD', 'bool', NULL, 'core', 'Disables the shippable status icon displayed on sales order line views and edit forms.', 'Checked in core/tpl/objectline_view.tpl.php:477, core/tpl/objectline_title.tpl.php:141, core/tpl/objectline_edit.tpl.php:307, and commande/card.php:3112. The icon appears only when stock and shipping modules are enabled and the constant is not set.', 'Setting this constant removes the shippable icon from order line displays, regardless of stock or shipping module state.', '0 (icon shown) or 1 (icon hidden)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_view.tpl.php:477|check|if ($object->element == ''commande'' && isModEnabled(''stock'') && isModEnabled(''shipping'') && !getDolGlobalString(''ORDER_DISABLE_SHIPPABLE_ICON_ON_CARD'')", "core/tpl/objectline_title.tpl.php:141|check|if ($object->element == ''commande'' && isModEnabled(''stock'') && isModEnabled(''shipping'') && !getDolGlobalString(''ORDER_DISABLE_SHIPPABLE_ICON_ON_CARD'')", "commande/card.php:3112|check|if (isModEnabled(''stock'') && isModEnabled(''shipping'') && !getDolGlobalString(''ORDER_DISABLE_SHIPPABLE_ICON_ON_CARD'') && !empty($object->delivery_date)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_DONT_REOPEN_BILLED', 'string', NULL, 'commande', 'Prevents reopening of billed orders that are in closed or cancelled status.', 'Checked via getDolGlobalInt in commande/card.php:3477. The condition allows reopening only if the order is not billed or if this constant is not set. No admin UI write is present.', 'Setting this constant blocks users from reopening an order that has been marked as billed, even if they have creation rights. Leaving it unset permits reopening billed closed or cancelled orders.', 'Non-zero integer = billed orders cannot be reopened; 0 or unset = reopening allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3477|check|if (($object->status == Commande::STATUS_CLOSED || $object->status == Commande::STATUS_CANCELED) && $usercancreate && (!$object->billed || !getDolGlobalInt(''ORDER_DONT_REOPEN_BILLE"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_ENABLE_NEGATIVE', 'bool', NULL, 'commande', 'Permits validation of orders with a negative total amount.', 'Checked in commande/card.php:3518 as part of the validation button condition. Without this constant, validation requires total_ttc >= 0. No admin UI write is present.', 'Setting this constant allows orders with a negative total to be validated. Leaving it unset blocks validation of negative-total orders.', 'Truthy = negative total orders can be validated; falsy or unset = only non-negative totals allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3518|check|if ($object->status == Commande::STATUS_DRAFT && ($object->total_ttc >= 0 || getDolGlobalString(''ORDER_ENABLE_NEGATIVE'')) && $usercanvalidate) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_ENABLE_NEGATIVE_QTY', 'bool', NULL, 'commande', 'Allows negative quantities to be entered on customer order lines.', 'Checked in commande/card.php:1037 and commande/card.php:1707. When not set, a negative quantity triggers a blocking error. No admin UI write is present.', 'Setting this constant permits order lines with negative quantities to be saved. Leaving it unset causes negative quantities to be rejected.', 'Truthy = negative quantities allowed; falsy or unset = negative quantities blocked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:1037|check|if ($qty < 0 && !getDolGlobalString(''ORDER_ENABLE_NEGATIVE_QTY'')) {", "commande/card.php:1707|check|if ($qty < 0 && !getDolGlobalString(''ORDER_ENABLE_NEGATIVE_QTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to sales order documents.', 'Written in admin/order.php:173 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on sales order PDFs.', 'Arbitrary string text.', 0, 0, 'admin/order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"ORDER_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_HIDE_ONLINE_PAYMENT_ON_ORDER', 'bool', NULL, 'commande', 'Hides the online payment action or link on the customer order card.', 'Checked in commande/card.php:3715. When set, the online payment option is suppressed on the order card. No admin UI write is present.', 'Setting this constant removes the online payment link or button from the order card UI. Leaving it unset keeps the online payment option visible.', 'Truthy = online payment option hidden; falsy or unset = online payment option shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:3715|check|if (getDolGlobalString(''ORDER_HIDE_ONLINE_PAYMENT_ON_ORDER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_MANAGE_MIN_AMOUNT', 'string', NULL, 'fourn', 'Enables minimum order amount enforcement for both customer and supplier orders.', 'Checked across 6 occurrences in fourn/commande/card.php:2737, fourn/card.php:438, comm/card.php:574, commande/card.php:3312, and societe/class/societe.class.php:243-244. When enabled, the order_min_amount and supplier_order_min_amount fields become active on third-party records.', 'Enabling this activates minimum order amount fields on third-party records and blocks order validation when the order total is below the configured minimum.', 'Empty/0 = no minimum amount enforced; truthy = minimum amount enforcement active', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2737|check|if (getDolGlobalString(''ORDER_MANAGE_MIN_AMOUNT'') && $object->total_ht < $object->thirdparty->supplier_order_min_amount) {", "commande/card.php:3312|check|if (getDolGlobalString(''ORDER_MANAGE_MIN_AMOUNT'') && $object->total_ht < $object->thirdparty->order_min_amount) {", "societe/class/societe.class.php:243|read|''order_min_amount'' => array(''type'' => ''double(24,8)'', ''label'' => ''Order min amount'', ''enabled'' => ''isModEnabled(\"order\") && getDolGlobalInt(\"ORDER_MANAGE_MIN_AMOUNT\")''", "societe/class/societe.class.php:244|read|''supplier_order_min_amount'' => array(''type'' => ''double(24,8)'', ''label'' => ''Supplier order min amount'', ''enabled'' => ''isModEnabled(\"order\") && getDolGlobalInt(\"ORDER_MANAGE_MIN_AMOU"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_MASS_ACTION_BILLED_LINK_EXPEDITIONS', 'string', NULL, 'commande', 'When set, the mass ''mark as billed'' action on orders also links the related expeditions/shipments.', 'Checked in commande/list.php:502: the additional expedition-linking logic is executed only when this constant is non-empty.', 'Enabling this constant causes bulk billing of orders to additionally update linked shipment records; leaving it empty skips that step.', 'Empty = expedition linking disabled (default); any non-empty value = expedition linking enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:502|check|if (getDolGlobalString(''ORDER_MASS_ACTION_BILLED_LINK_EXPEDITIONS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_NOCHECK_ONSALE_PRODUCTS_ONVALID', 'string', NULL, 'commande', 'Disables the check that all order line products are active/on-sale when validating a customer order.', 'Checked in commande/class/commande.class.php:537; when falsy, the validation method calls checkActiveProductInLines() to reject orders containing inactive products.', 'When enabled (truthy), orders containing inactive or off-sale products can be validated without error.', 'Bool-like string: empty/0 = check enforced; non-empty/1 = check disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:537|check|if (!getDolGlobalBool(''ORDER_NOCHECK_ONSALE_PRODUCTS_ONVALID'') && !$this->checkActiveProductInLines()) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_REOPEN_TO_DRAFT', 'string', NULL, 'commande', 'Controls whether a validated or closed customer order can be reopened back to draft status.', 'Checked in commande/class/commande.class.php:690 to block reopening when the constant is absent, and in commande/card.php:265 to show the reopen-to-draft action in the UI.', 'When enabled, users can revert a non-draft order to draft status; when disabled or unset, this action is blocked.', 'Int-like: 0 or unset = reopening blocked; non-zero = reopening allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:690|check|if ($this->status <= self::STATUS_DRAFT && !getDolGlobalInt(''ORDER_REOPEN_TO_DRAFT'')) {", "commande/card.php:265|check|if (getDolGlobalInt(''ORDER_REOPEN_TO_DRAFT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_REQUIRE_SOURCE', 'string', NULL, 'commande', 'Requires that a source be set on a customer order before it can be validated.', 'Checked in commande/class/commande.class.php:1027; if set and the order source is negative (unset), validation is blocked.', 'Enabling this constant enforces that orders must have an explicit source field before validation.', 'Bool-like string: empty/unset = source not required; non-empty = source required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:1027|check|if (getDolGlobalString(''ORDER_REQUIRE_SOURCE'') && $this->source < 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_SHIPABLE_STATUS_DISABLED_BY_DEFAULT', 'bool', NULL, 'commande', 'Disables the ''shippable'' status filter in the order list by default when set.', 'Checked in commande/list.php:2056 and commande/list_det.php:1271: when non-empty, the shippable-status filter is not applied by default.', 'Enabling this constant suppresses the default shippable-status filter, showing all orders regardless of shippability.', 'Empty = shippable filter active by default; any non-empty value = filter disabled by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:2056|check|if (getDolGlobalString(''ORDER_SHIPABLE_STATUS_DISABLED_BY_DEFAULT'')) {", "commande/list_det.php:1271|check|if (getDolGlobalString(''ORDER_SHIPABLE_STATUS_DISABLED_BY_DEFAULT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('ORDER_SHOW_POS', 'bool', NULL, 'commande', 'Forces the display of point-of-sale (POS) columns in the order list even when cashdesk and takepos modules are disabled.', 'Read in commande/list.php:221: $showpos is set to ''1'' when cashdesk or takepos modules are enabled, or when this constant is a non-zero integer.', 'Setting this to a non-zero value enables POS-related columns in the order list independently of POS module activation.', '0 = POS columns hidden unless a POS module is active (default); non-zero integer = POS columns always shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/list.php:221|read|$showpos = (isModEnabled(''cashdesk'') || isModEnabled(''takepos'') || getDolGlobalInt(''ORDER_SHOW_POS'')) ? ''1'' : ''0'';"]', 'low', NULL);
