INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_ADDON_PDF', 'string', NULL, 'partnership', 'Specifies the PDF model name used to generate partnership documents when set.', 'Read in partnership/class/partnership.class.php:1351–1352 where, when the constant is set, the PDF model name is taken from it. No admin UI write path exists in the payload.', 'Setting this value selects the PDF template used for partnership document generation.', 'String PDF model name; empty/unset = use object''s own model_pdf value', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnership.class.php:1351|read|} elseif (getDolGlobalString(''PARTNERSHIP_ADDON_PDF'')) {", "partnership/class/partnership.class.php:1352|read|$modele = getDolGlobalString(''PARTNERSHIP_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_ADVANCED_MASK', 'string', NULL, 'partnership', 'Stores the numbering mask pattern used by the advanced partnership reference numbering module.', 'Read in 2 locations within partnership/core/modules/partnership/mod_partnership_advanced.php: line 86 populates the mask input field in the UI and line 139 reads the mask for generating reference numbers.', 'Changing this value alters the reference number pattern generated by the advanced partnership numbering module.', 'Mask pattern string (e.g. containing prefix, date, and sequence tokens); empty = no mask defined.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/core/modules/partnership/mod_partnership_advanced.php:86|read|$text .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskPartnership\" value=\"''.getDolGlobalString(''PARTNERSHIP_ADVANCED_MASK'').''\">''", "partnership/core/modules/partnership/mod_partnership_advanced.php:139|read|$mask = getDolGlobalString(''PARTNERSHIP_ADVANCED_MASK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL', 'string', NULL, 'public', 'Specifies the email address to notify when a new partnership request is submitted.', 'In public/partnership/new.php at lines 375 and 397, the value is used as the notification recipient address and passed through makeSubstitution for variable replacement. No admin UI write path is present.', 'Setting this enables automatic email notification of new partnership registrations to the specified address.', 'String: email address to receive partnership auto-registration notifications', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:375|read|getDolGlobalString(''PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL'')) {", "public/partnership/new.php:397|read|$partnership->makeSubstitution(getDolGlobalString(''PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL'')),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL_SUBJECT', 'string', NULL, 'public', 'Specifies the subject line of the notification email sent when a new partnership request is submitted.', 'In public/partnership/new.php at lines 374 and 394, the value is used as the email subject (with a fallback of ''Partnership request''). No admin UI write path is present.', 'Setting this customizes the email subject for partnership auto-registration notifications; the default fallback ''Partnership request'' is used if unset.', 'String: email subject line for the partnership registration notification', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:374|check|if (getDolGlobalString(''MAIN_INFO_SOCIETE_MAIL'') && getDolGlobalString(''PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL_SUBJECT'') &&", "public/partnership/new.php:394|read|''[''.$appli.''] ''.getDolGlobalString(''PARTNERSHIP_AUTOREGISTER_NOTIF_MAIL_SUBJECT'', ''Partnership request''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_BACKLINKS_TO_CHECK', 'string', NULL, 'partnership', 'Stores a pipe-separated list of URL patterns (regex) that must be present on a partner''s website as backlinks.', 'Set via partnership/admin/setup.php:80 and read at setup.php:178. Used in partnership/class/partnershiputils.class.php:569 in a preg_match call against fetched web content. Also controls visibility of url_to_check, count_last_url_check_error, and last_check_backlink fields in partnership.class.php. In public/partnership/new.php:620, the value is exploded by ''|'' to get the list of patterns.', 'When unset, backlink checking is inactive and related fields are hidden. When set, the scheduler checks partner websites for matching content and triggers warnings or cancellations on failure.', 'String: pipe-separated list of regex patterns to match against partner website content; empty/unset = backlink checking disabled.', 0, 0, 'partnership/admin/setup.php|partnership/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/admin/setup.php:80|write|dolibarr_set_const($db, \"PARTNERSHIP_BACKLINKS_TO_CHECK\", GETPOST(\"PARTNERSHIP_BACKLINKS_TO_CHECK\"), ''chaine'', 0, '''', $conf->entity);", "partnership/class/partnershiputils.class.php:569|check|if ($webcontent && getDolGlobalString(''PARTNERSHIP_BACKLINKS_TO_CHECK'') && preg_match(''/'' . getDolGlobalString(''PARTNERSHIP_BACKLINKS_TO_CHECK'').''/'', $webcontent)) {", "public/partnership/new.php:620|read|$listofkeytocheck = explode(''|'', getDolGlobalString(''PARTNERSHIP_BACKLINKS_TO_CHECK''));", "partnership/class/partnership.class.php:123|read|''url_to_check'' => array(''type'' => ''url'', ''label'' => ''UrlToCheck'', ''enabled'' => ''getDolGlobalString(\"PARTNERSHIP_BACKLINKS_TO_CHECK\")'', ..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_EMAIL_TEMPLATE_AUTOREGISTER', 'string', NULL, 'public', 'Specifies the email template identifier used when automatically sending a registration email for a new partnership request.', 'Read in public/partnership/new.php:348 and assigned directly to $labeltouse, which drives the email template selection for the auto-registration workflow.', 'Changing this constant changes the email template sent to users upon submitting a partnership registration form.', 'String identifier of an email template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$labeltouse = $conf->global->PARTNERSHIP_EMAIL_TEMPLATE_AUTOREGISTER;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_ENABLE_PUBLIC', 'bool', NULL, 'partnership', 'Enables the public partnership registration page.', 'Configured via partnership/admin/website.php (multiple write occurrences). Checked in partnership/admin/website.php:152, :171, :224 to control UI display, and in public/partnership/new.php:87 to gate the public form — returning an error if the constant is not set.', 'When enabled, the public URL for partnership applications is activated; when disabled or unset, the public page is inaccessible.', '0 = public page disabled; 1 = public page enabled', 0, 0, 'partnership/admin/website.php|partnership/admin/website.php|partnership/admin/website.php|partnership/admin/website.php|partnership/admin/website.php|partnership/admin/website.php|partnership/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/partnership/new.php:87|check|if (!getDolGlobalString(''PARTNERSHIP_ENABLE_PUBLIC'')) {", "partnership/admin/website.php:64|write|dolibarr_set_const($db, ''PARTNERSHIP_ENABLE_PUBLIC'', 1, ''chaine'', 0, '''', $conf->entity);", "partnership/admin/website.php:66|write|dolibarr_set_const($db, ''PARTNERSHIP_ENABLE_PUBLIC'', 0, ''chaine'', 0, '''', $conf->entity);", "partnership/admin/website.php:164|read|print ''<input type=\"hidden\" id=\"PARTNERSHIP_ENABLE_PUBLIC\" name=\"PARTNERSHIP_ENABLE_PUBLIC\" value=\"''.(!getDolGlobalString(''PARTNERSHIP_ENABLE_PUBLIC'') ? 0 : 1).''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_IS_MANAGED_FOR', 'string', NULL, 'partnership', 'Determines whether the partnership module links partnerships to third-party companies or to members.', 'Written by partnership/admin/setup.php:66. The selector at partnership/admin/setup.php:136-137 offers ''thirdparty'' and ''member'' options, defaulting to ''thirdparty''. Read in partnership/partnership_card.php:93, partnership/partnership_contact.php:66, partnership/partnership_agenda.php:99, and public/partnership/new.php:207 to switch object linkage and UI behaviour.', 'Changing this value switches partnership records to link to either third-party companies (''thirdparty'') or member records (''member''), affecting all partnership creation, display, and navigation pages.', '''thirdparty'' = partnerships linked to third-party companies (default); ''member'' = partnerships linked to member records.', 0, 0, 'partnership/admin/setup.php|partnership/admin/setup.php|partnership/admin/setup.php|partnership/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/admin/setup.php:136|read|print ''<option value=\"thirdparty\" ''.((getDolGlobalString(''PARTNERSHIP_IS_MANAGED_FOR'', ''thirdparty'') == ''thirdparty'') ? ''selected'' : '''').''>''.$langs->trans(\"ThirdParty\").''</option>''", "partnership/admin/setup.php:137|read|print ''<option value=\"member\" ''.((getDolGlobalString(''PARTNERSHIP_IS_MANAGED_FOR'', ''thirdparty'') == ''member'') ? ''selected'' : '''').''>''.$langs->trans(\"Members\").''</option>'';", "public/partnership/new.php:207|check|if (getDolGlobalString(''PARTNERSHIP_IS_MANAGED_FOR'', ''thirdparty'') == ''thirdparty'') {", "partnership/partnership_card.php:93|read|$managedfor \t\t\t= getDolGlobalString(''PARTNERSHIP_IS_MANAGED_FOR'', ''thirdparty'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_MAIL_FROM', 'string', NULL, 'public', 'Specifies the sender email address for notification emails sent from the public partnership registration form.', 'In public/partnership/new.php at line 392, the value is read into $from and used as the From header of the notification email. No admin UI write path is present.', 'Setting this controls the From address of partnership registration notification emails.', 'String: email address to use as the sender for partnership notification emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:392|read|$from = getDolGlobalString(''PARTNERSHIP_MAIL_FROM'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_MAX_BACKLINK_ERROR_FOR_CANCEL', 'string', NULL, 'partnership', 'Sets the maximum number of consecutive backlink check errors before a partnership is cancelled; defaults to PARTNERSHIP_MIN_BACKLINK_ERROR_FOR_CANCEL + 2.', 'Read once at partnership/class/partnershiputils.class.php:386: `$nbmaxbacklinkerrorforcancel = (int) getDolGlobalString(''PARTNERSHIP_MAX_BACKLINK_ERROR_FOR_CANCEL'', (int) $nbminbacklinkerrorforcancel + 2)`. Only 1 occurrence in 1 file.', 'When unset, the maximum error threshold is set to the minimum threshold plus 2. Setting a custom value overrides this upper bound for cancellation.', 'Integer; unset = PARTNERSHIP_MIN_BACKLINK_ERROR_FOR_CANCEL + 2 (default); any positive integer = custom maximum.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:386|read|$nbmaxbacklinkerrorforcancel = (int) getDolGlobalString(''PARTNERSHIP_MAX_BACKLINK_ERROR_FOR_CANCEL'', (int) $nbminbacklinkerrorforcancel + 2);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL', 'string', NULL, 'partnership', 'Sets the maximum number of partnership expiration cancellations processed per scheduler call; defaults to 25 if unset.', 'Read at partnership/class/partnershiputils.class.php:89 with fallback: `$MAXPERCALL = (!getDolGlobalString(''PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL'') ? 25 : $conf->global->PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL)`. The docblock at line 72 documents this as the batch size for the scheduled cancellation action.', 'When unset, the scheduler processes at most 25 partnership expirations per call. Setting a higher or lower value changes the batch size for the auto-cancel scheduled task.', 'Integer; unset or 0 = 25 (default limit per call); any positive integer = custom batch limit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* Action executed by scheduler to cancel status of partnership when subscription is expired + x days. (Max number of action batch per call = $conf->global->PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL)", "$MAXPERCALL = (!getDolGlobalString(''PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL'') ? 25 : $conf->global->PARTNERSHIP_MAX_EXPIRATION_CANCEL_PER_CALL); // Limit to 25 per call"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_MAX_WARNING_BACKLINK_PER_CALL', 'string', NULL, 'partnership', 'Sets the maximum number of backlink checks performed per scheduler call; defaults to 10 if unset.', 'Read at partnership/class/partnershiputils.class.php:300: `$maxpercall = getDolGlobalInt(''PARTNERSHIP_MAX_WARNING_BACKLINK_PER_CALL'', 10)`. The docblock at line 285 documents this as the batch size for the backlink-check scheduled action. 2 occurrences in 1 file.', 'When unset, the scheduler processes at most 10 partner backlink checks per call. Setting a custom value changes the batch size.', 'Integer; unset = 10 (default limit per call); any positive integer = custom batch limit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* Action executed by scheduler to check if Dolibarr backlink not found on partner website. (Max number of action batch per call = $conf->global->PARTNERSHIP_MAX_WARNING_BACKLINK_PER_CALL)", "partnership/class/partnershiputils.class.php:300|read|$maxpercall = getDolGlobalInt(''PARTNERSHIP_MAX_WARNING_BACKLINK_PER_CALL'', 10);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_MIN_BACKLINK_ERROR_FOR_CANCEL', 'string', NULL, 'partnership', 'Sets the minimum number of consecutive backlink check errors required before a partnership cancellation is triggered; defaults to 3.', 'Read once at partnership/class/partnershiputils.class.php:385: `$nbminbacklinkerrorforcancel = (int) getDolGlobalString(''PARTNERSHIP_MIN_BACKLINK_ERROR_FOR_CANCEL'', 3)`. Only 1 occurrence in 1 file.', 'When unset, at least 3 consecutive backlink errors are needed before cancellation is considered. Setting a higher value requires more errors before cancellation.', 'Integer; unset = 3 (default minimum errors); any positive integer = custom minimum.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:385|read|$nbminbacklinkerrorforcancel = (int) getDolGlobalString(''PARTNERSHIP_MIN_BACKLINK_ERROR_FOR_CANCEL'', 3);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NBDAYS_AFTER_MEMBER_EXPIRATION_BEFORE_CANCEL', 'string', NULL, 'partnership', 'Defines the number of grace days after member subscription expiration before a partnership is automatically cancelled.', 'Set via partnership/admin/setup.php:77 and read at setup.php:149 and partnership/class/partnershiputils.class.php:99 as $gracedelay. A commented-out reference at partnershiputils.class.php:313 also shows its use as an integer grace delay.', 'When set, partnerships are cancelled only after the specified number of days past member expiration. Changing this value lengthens or shortens the grace period before auto-cancellation.', 'Integer (number of days); unset = implementation-defined default delay.', 0, 0, 'partnership/admin/setup.php|partnership/admin/setup.php|partnership/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:99|read|$gracedelay = getDolGlobalString(''PARTNERSHIP_NBDAYS_AFTER_MEMBER_EXPIRATION_BEFORE_CANCEL'');", "partnership/admin/setup.php:77|write|dolibarr_set_const($db, \"PARTNERSHIP_NBDAYS_AFTER_MEMBER_EXPIRATION_BEFORE_CANCEL\", GETPOSTINT(\"PARTNERSHIP_NBDAYS_AFTER_MEMBER_EXPIRATION_BEFORE_CANCEL\"), ''chaine'', 0, '''', $conf->entity);", "/*$gracedelay = getDolGlobalInt(''PARTNERSHIP_NBDAYS_AFTER_MEMBER_EXPIRATION_BEFORE_CANCEL'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NEWFORM_AMOUNT', 'string', NULL, 'partnership', 'Stores the default amount pre-filled in the new partnership request form on the public-facing website.', 'Set and read in partnership/admin/website.php:186 via an admin text input. The value is written directly into the form field for the partnership amount.', 'Changing this value alters the default amount displayed to users on the partnership registration form.', 'Numeric string representing a monetary amount.', 0, 0, 'partnership/admin/website.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["print ''<input type=\"text\" class=\"right width75\" id=\"PARTNERSHIP_NEWFORM_AMOUNT\" name=\"PARTNERSHIP_NEWFORM_AMOUNT\" value=\"''.(!empty($conf->global->PARTNERSHIP_NEWFORM_AMOUNT) ? $con"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NEWFORM_FORCECOUNTRYCODE', 'string', NULL, 'public', 'Forces a specific country on the public partnership registration form when no country has been selected.', 'In public/partnership/new.php at lines 643-644, when no country_id is set, this constant''s value is used to look up and assign a country. No admin UI write path is present.', 'Setting this pre-selects a country on the public partnership form when the user has not chosen one.', 'String: ISO country code (e.g. ''FR'', ''US'') used to force the country selection', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:643|check|if (!$country_id && getDolGlobalString(''PARTNERSHIP_NEWFORM_FORCECOUNTRYCODE'')) {", "public/partnership/new.php:644|read|$country_id = getCountry($conf->global->PARTNERSHIP_NEWFORM_FORCECOUNTRYCODE, ''2'', $db, $langs);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NEWFORM_FORCETYPE', 'string', NULL, 'public', 'Forces a specific partnership type on the public registration form, hiding the type selector and pre-filling the value.', 'In public/partnership/new.php at lines 593-595, when set the type name is printed and a hidden input is injected; when not set the type selector is shown (line 599). The COMMENT at line 220 shows the intended usage: ''$partnership->typeid = $conf->global->PARTNERSHIP_NEWFORM_FORCETYPE ? $conf->global->PARTNERSHIP_NEWFORM_FORCETYPE : GETPOST(''typeid'', ''int'')''.', 'Setting this locks the partnership type to the specified ID on the public form; leaving it unset allows the user to choose.', 'Integer: ID of the partnership type to force; 0 or unset = user selects type', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:220  //$partnership->typeid               = $conf->global->PARTNERSHIP_NEWFORM_FORCETYPE ? $conf->global->PARTNERSHIP_NEWFORM_FORCETYPE : GETPOST(''typeid'', ''int'');", "public/partnership/new.php:593|check|if (getDolGlobalInt(''PARTNERSHIP_NEWFORM_FORCETYPE'')) {", "public/partnership/new.php:594|read|print $listofpartnership[getDolGlobalInt(''PARTNERSHIP_NEWFORM_FORCETYPE'')];", "public/partnership/new.php:595|read|print ''<input type=\"hidden\" id=\"partnershiptype\" name=\"partnershiptype\" value=\"'' . getDolGlobalInt(''PARTNERSHIP_NEWFORM_FORCETYPE'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NEWFORM_PAYONLINE', 'string', NULL, 'public', 'Controls which online payment provider is offered to users after completing the public partnership registration form.', 'Configured via partnership/admin/website.php (line 205) with a selectarray of payment provider values. In public/partnership/new.php at lines 422-468, the value selects among ''all'', ''paybox'', ''paypal'', ''stripe'', or ''-1'' (none).', 'Changing this determines whether and which payment provider link is shown after partnership registration; ''-1'' suppresses online payment.', ''''' or unset = no payment link; ''-1'' = disabled; ''all'' = all providers; ''paybox'' = Paybox; ''paypal'' = PayPal; ''stripe'' = Stripe', 0, 0, 'partnership/admin/website.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["partnership/admin/website.php:205|read|print $form->selectarray(\"PARTNERSHIP_NEWFORM_PAYONLINE\", $listofval, ...", "public/partnership/new.php:423|check|if (getDolGlobalString(''PARTNERSHIP_NEWFORM_PAYONLINE'') == ''all'') {", "public/partnership/new.php:438|read|} elseif (getDolGlobalString(''PARTNERSHIP_NEWFORM_PAYONLINE'') == ''paybox'') {", "public/partnership/new.php:453|read|} elseif (getDolGlobalString(''PARTNERSHIP_NEWFORM_PAYONLINE'') == ''paypal'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_NEWFORM_TEXT', 'string', NULL, 'public', 'Specifies a translation key whose translated text is printed on the public partnership registration form page.', 'In public/partnership/new.php at lines 550-551, when set the constant value is used as a translation key and the result is printed on the form. No admin UI write path is present.', 'Setting this causes a translated message to appear on the public partnership form; leaving it unset suppresses the message.', 'String: a Dolibarr translation key whose translated value is displayed on the partnership form', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:550|check|if (getDolGlobalString(''PARTNERSHIP_NEWFORM_TEXT'')) {", "public/partnership/new.php:551|read|print $langs->trans(getDolGlobalString(''PARTNERSHIP_NEWFORM_TEXT'')).\"<br>\\n\";"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_PUBLIC_INTERFACE_TOPIC', 'string', NULL, 'public', 'Sets the topic/title string passed to the online header of the public partnership registration form.', 'Used in public/partnership/new.php at line 126 as the topic argument to htmlPrintOnlineHeader. No admin UI write path is present.', 'Changing this value alters the topic text displayed in the public header of the partnership registration page.', 'String: any text value used as the page topic header', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:126|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''PARTNERSHIP_PUBLIC_INTERFACE_TOPIC''), ''PARTNERSHIP_IMAGE_PUBLIC_REGISTRATION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_SENDMAIL_IF_AUTO_CANCEL', 'string', NULL, 'partnership', 'Specifies the email template label to use when a partnership is automatically cancelled; defaults to ''SendingEmailOnPartnershipCanceled''.', 'Read once at partnership/class/partnershiputils.class.php:169: `$labeltemplate = ''(''.getDolGlobalString(''PARTNERSHIP_SENDMAIL_IF_AUTO_CANCEL'', ''SendingEmailOnPartnershipCanceled'').'')''`. Only 1 occurrence in 1 file.', 'When unset, the default template ''SendingEmailOnPartnershipCanceled'' is used for auto-cancel notification emails. When set, the specified template label overrides the default.', 'String (email template label); unset = ''SendingEmailOnPartnershipCanceled'' (default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:169|read|$labeltemplate = ''(''.getDolGlobalString(''PARTNERSHIP_SENDMAIL_IF_AUTO_CANCEL'', ''SendingEmailOnPartnershipCanceled'').'')'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_SENDMAIL_IF_NO_LINK', 'string', NULL, 'partnership', 'Specifies the email template label used when a partner''s backlink is not found; defaults to ''SendingEmailOnPartnershipWillSoonBeCanceled''.', 'Read once at partnership/class/partnershiputils.class.php:395: `$labeltemplate = ''(''.getDolGlobalString(''PARTNERSHIP_SENDMAIL_IF_NO_LINK'', ''SendingEmailOnPartnershipWillSoonBeCanceled'').'')''`. Only 1 occurrence in 1 file.', 'When unset, the default template ''SendingEmailOnPartnershipWillSoonBeCanceled'' is used for missing-backlink notifications. When set, the specified template label is used instead.', 'String (email template label); unset = ''SendingEmailOnPartnershipWillSoonBeCanceled'' (default).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["partnership/class/partnershiputils.class.php:395|read|$labeltemplate = ''(''.getDolGlobalString(''PARTNERSHIP_SENDMAIL_IF_NO_LINK'', ''SendingEmailOnPartnershipWillSoonBeCanceled'').'')'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PARTNERSHIP_URL_REDIRECT_SUBSCRIPTION', 'string', NULL, 'public', 'Defines the URL to redirect the user to after a partnership registration is successfully submitted.', 'The COMMENT in public/partnership/new.php:513 states ''If PARTNERSHIP_URL_REDIRECT_SUBSCRIPTION is set to url we never go here because a redirect was done to this url.'' At lines 414-415, when set the user is redirected to this URL. No admin UI write path is present.', 'Setting this redirects submitters to a custom URL on successful partnership registration; leaving it unset uses the default post-submission behavior.', 'String: absolute URL for post-submission redirect; when set, the default confirmation page is never shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/partnership/new.php:513  // If PARTNERSHIP_URL_REDIRECT_SUBSCRIPTION is set to url we never go here because a redirect was done to this url.", "public/partnership/new.php:414|read|} elseif (getDolGlobalString(''PARTNERSHIP_URL_REDIRECT_SUBSCRIPTION'')) {", "public/partnership/new.php:415|read|$urlback = getDolGlobalString(''PARTNERSHIP_URL_REDIRECT_SUBSCRIPTION'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the bank account ID used to record Paybox payments in the Dolibarr bank account system.', 'Written via admin UI at paybox/admin/paybox.php:81 and displayed as a select at :244. Read at public/payment/paymentok.php:710, :1105, :1255, :1400, :1536, and :1775 as the target bank account ID for recording payments.', 'Changing this redirects all Paybox payment recordings to the newly specified bank account.', 'An integer bank account ID as stored in the Dolibarr bank accounts table.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["paybox/admin/paybox.php:81|write|$result = dolibarr_set_const($db, \"PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS\", GETPOSTINT(''PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS''), ''chaine'', 0, '''', $conf->entity);", "paybox/admin/paybox.php:244|read|$form->select_comptes($conf->global->PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS, ''PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS'', 0, '''', 1);", "public/payment/paymentok.php:710|read|$accountid = getDolGlobalString(''PAYBOX_BANK_ACCOUNT_FOR_PAYMENTS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_CGI_URL_V1', 'string', NULL, 'paybox', 'URL of the Paybox CGI endpoint (version 1) used to redirect payment requests.', 'Configured via paybox/admin/paybox.php (written at line 57, displayed at line 220). Read in paybox/lib/paybox.lib.php (lines 69-70) to set the URLPAYBOX variable.', 'If not set, the URLPAYBOX variable is not populated from this constant and V1 payment redirection will not function.', 'String: URL of the Paybox V1 CGI payment endpoint.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:57|write|$result = dolibarr_set_const($db, \"PAYBOX_CGI_URL_V1\", GETPOST(''PAYBOX_CGI_URL_V1'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paybox/lib/paybox.lib.php:69|check|if (getDolGlobalString(''PAYBOX_CGI_URL_V1'')) {", "paybox/lib/paybox.lib.php:70|read|$URLPAYBOX = getDolGlobalString(''PAYBOX_CGI_URL_V1'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_CGI_URL_V2', 'string', NULL, 'paybox', 'URL of the Paybox CGI endpoint (version 2) used to redirect payment requests.', 'Configured via paybox/admin/paybox.php (written at line 61, displayed at line 228). Read in paybox/lib/paybox.lib.php (lines 72-73) to set the URLPAYBOX variable, and referenced in public/payment/newpayment.php:1073 for HTML comment output.', 'When set, the V2 URL overrides V1 as the URLPAYBOX destination for payment redirection.', 'String: URL of the Paybox V2 CGI payment endpoint.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:61|write|$result = dolibarr_set_const($db, \"PAYBOX_CGI_URL_V2\", GETPOST(''PAYBOX_CGI_URL_V2'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paybox/lib/paybox.lib.php:72|check|if (getDolGlobalString(''PAYBOX_CGI_URL_V2'')) {", "paybox/lib/paybox.lib.php:73|read|$URLPAYBOX = getDolGlobalString(''PAYBOX_CGI_URL_V2'');", "public/payment/newpayment.php:1073|read|print ''<!-- PAYBOX_CGI_URL = ''.getDolGlobalString(''PAYBOX_CGI_URL_V2'').'' -->''.\"\\n\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_HASH', 'string', NULL, 'paybox', 'Hash algorithm name used to sign Paybox payment requests (set automatically by the library).', 'Written programmatically in paybox/lib/paybox.lib.php:93 (set to ''sha512'') and read at line 129 as PBX_HASH. No admin UI writes this constant.', 'This constant is set at runtime by the Paybox library; changing it manually could break request signing.', 'String: hash algorithm name (set to ''sha512'' by the Paybox library).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/lib/paybox.lib.php:93|write|$conf->global->PAYBOX_HASH = ''sha512'';", "paybox/lib/paybox.lib.php:129|read|$PBX_HASH = getDolGlobalString(''PAYBOX_HASH'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_HMAC_KEY', 'string', NULL, 'paybox', 'Stores the Paybox HMAC secret key (encoded) used to sign payment requests.', 'Written (encoded) via admin UI at paybox/admin/paybox.php:114, displayed (decoded) for editing at :198, and read (decoded) at paybox/lib/paybox.lib.php:154 to produce the binary signing key for Paybox requests.', 'If incorrect or unset, Paybox payment request signing will fail. The value is stored encoded using dol_encode and decoded at runtime.', 'A hexadecimal HMAC key string (stored encoded).', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["paybox/admin/paybox.php:114|write|$result = dolibarr_set_const($db, \"PAYBOX_HMAC_KEY\", dol_encode(GETPOST(''PAYBOX_HMAC_KEY'', ''alpha'')), ''chaine'', 0, '''', $conf->entity);", "paybox/admin/paybox.php:198|read|print ''<input size=\"100\" type=\"text\" name=\"PAYBOX_HMAC_KEY\" value=\"''.dol_decode($conf->global->PAYBOX_HMAC_KEY).''\">'';", "paybox/lib/paybox.lib.php:154|read|$binKey = pack(\"H*\", dol_decode($conf->global->PAYBOX_HMAC_KEY));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_IBS_DEVISE', 'string', NULL, 'paybox', 'Currency code used in Paybox payment requests (IBS_DEVISE).', 'Checked and conditionally set at runtime in paybox/admin/paybox.php (lines 143-144). Displayed as a read-only field at line 211. A commented-out write at line 56 shows that direct admin UI saving of this constant was disabled.', 'If not set, the Paybox library sets a default currency value automatically at line 144.', 'String: ISO 4217 numeric currency code (e.g. ''978'' for EUR).', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["//$result=dolibarr_set_const($db, \"PAYBOX_IBS_DEVISE\", GETPOST(\"PAYBOX_IBS_DEVISE\"),''chaine'',0,'''',$conf->entity);", "paybox/admin/paybox.php:143|check|if (!getDolGlobalString(''PAYBOX_IBS_DEVISE'')) {", "paybox/admin/paybox.php:144|write|$conf->global->PAYBOX_IBS_DEVISE = $IBS_DEVISE;", "paybox/admin/paybox.php:211|read|print ''<input size=\"32\" type=\"text\" name=\"PAYBOX_IBS_DEVISE\" value=\"''.$conf->global->PAYBOX_IBS_DEVISE.''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_IBS_RANG', 'string', NULL, 'paybox', 'Paybox rank number (IBS_RANG) identifying the payment terminal in Paybox payment requests.', 'Configured via paybox/admin/paybox.php (written at lines 69 and 140, displayed at line 185). Read in paybox/lib/paybox.lib.php (lines 57-58) to set the IBS_RANG parameter.', 'Without a valid rank number, Paybox payment requests will not identify the terminal correctly.', 'String: Paybox rank number provided by the Paybox service.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:69|write|$result = dolibarr_set_const($db, \"PAYBOX_IBS_RANG\", GETPOST(''PAYBOX_IBS_RANG'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paybox/admin/paybox.php:139|check|if (!getDolGlobalString(''PAYBOX_IBS_RANG'')) {", "paybox/lib/paybox.lib.php:57|check|if (getDolGlobalString(''PAYBOX_IBS_RANG'')) {", "paybox/lib/paybox.lib.php:58|read|$IBS_RANG = getDolGlobalString(''PAYBOX_IBS_RANG'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_IBS_SITE', 'string', NULL, 'paybox', 'Paybox site number (IBS_SITE) used to identify the merchant site in Paybox payment requests.', 'Configured via paybox/admin/paybox.php (written at lines 65 and 136, displayed at line 178). Read in paybox/lib/paybox.lib.php (lines 53-54) to set the IBS_SITE parameter.', 'Without a valid site number, Paybox payment processing will not function correctly.', 'String: Paybox site number provided by the Paybox service.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:65|write|$result = dolibarr_set_const($db, \"PAYBOX_IBS_SITE\", GETPOST(''PAYBOX_IBS_SITE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paybox/admin/paybox.php:135|check|if (!getDolGlobalString(''PAYBOX_IBS_SITE'')) {", "paybox/lib/paybox.lib.php:53|check|if (getDolGlobalString(''PAYBOX_IBS_SITE'')) {", "paybox/lib/paybox.lib.php:54|read|$IBS_SITE = getDolGlobalString(''PAYBOX_IBS_SITE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_PAYMENT_MODE_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the payment mode ID used to record Paybox payments in the Dolibarr payment system.', 'Read as an integer at public/payment/paymentok.php at lines 579, 1022, 1168, 1323, 1462, 1701, and 1919 and assigned to $paymentTypeId for recording payments. No admin UI write found in this file.', 'Setting this to a valid payment mode ID ensures Paybox payments are recorded with the correct payment type.', 'An integer payment mode ID.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/paymentok.php:579|read|$paymentTypeId = getDolGlobalInt(''PAYBOX_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1022|read|$paymentTypeId = getDolGlobalInt(''PAYBOX_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1168|read|$paymentTypeId = getDolGlobalInt(''PAYBOX_PAYMENT_MODE_FOR_PAYMENTS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYBOX_PBX_IDENTIFIANT', 'string', NULL, 'paybox', 'Paybox merchant identifier (PBX_IDENTIFIANT) used to authenticate payment requests to the Paybox gateway.', 'Configured via paybox/admin/paybox.php (written at line 73, displayed at line 192). Read in paybox/lib/paybox.lib.php (lines 49-50) to populate the PBX_IDENTIFIANT parameter for payment requests.', 'Without a valid identifier, Paybox payment requests will not be authenticated and online payments will fail.', 'String: Paybox merchant identifier provided by the Paybox service.', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paybox/admin/paybox.php:73|write|$result = dolibarr_set_const($db, \"PAYBOX_PBX_IDENTIFIANT\", GETPOST(''PAYBOX_PBX_IDENTIFIANT'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paybox/lib/paybox.lib.php:49|check|if (getDolGlobalString(''PAYBOX_PBX_IDENTIFIANT'')) {", "paybox/lib/paybox.lib.php:50|read|$PBX_IDENTIFIANT = getDolGlobalString(''PAYBOX_PBX_IDENTIFIANT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_ADDDAYS', 'string', NULL, 'admin', 'Number of days added to the current date to compute the execution date for bank transfer (credit transfer) orders.', 'Set via admin/paymentbybanktransfer.php:115, read as an integer default 0 at :210, and used in compta/prelevement/create.php:332 as $delayindays for credit transfer creation.', 'Increasing this value delays the execution date of bank transfer orders by the specified number of days.', 'Integer number of days (default 0 = no additional delay).', 0, 0, 'admin/paymentbybanktransfer.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/paymentbybanktransfer.php:115|write|$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_ADDDAYS\", GETPOST(\"PAYMENTBYBANKTRANSFER_ADDDAYS\"), ''chaine'', 0, '''', $conf->entity);", "admin/paymentbybanktransfer.php:210|read|$addDaysValue = getDolGlobalInt(''PAYMENTBYBANKTRANSFER_ADDDAYS'', 0);", "compta/prelevement/create.php:332|read|$delayindays = getDolGlobalInt(''PAYMENTBYBANKTRANSFER_ADDDAYS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_CUSTOM_CATEGORY_PURPOSE', 'string', NULL, 'compta', 'Sets a custom CategoryPurpose code in SEPA credit transfer XML.', 'Read once in bonprelevement.class.php:2500 as $categoryPurpose with a default fallback of ''CORE''. No admin UI write path exists.', 'Setting this constant overrides the default ''CORE'' category purpose code in SEPA bank transfer XML; the value must be a valid ISO 20022 CategoryPurpose code.', 'ISO 20022 CategoryPurpose code string; default fallback is ''CORE''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2500|read|$categoryPurpose = getDolGlobalString(''PAYMENTBYBANKTRANSFER_CUSTOM_CATEGORY_PURPOSE'', ''CORE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_CUSTOM_LOCAL_INSTRUMENT', 'string', NULL, 'compta', 'Sets a custom LocalInstrument code in SEPA credit transfer XML.', 'Read once in bonprelevement.class.php:2693 as $localInstrument with a default fallback of ''CORE''. No admin UI write path exists.', 'Setting this constant overrides the default ''CORE'' local instrument code in SEPA bank transfer XML; the value must be a valid ISO 20022 LocalInstrument code.', 'ISO 20022 LocalInstrument code string; default fallback is ''CORE''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2693|read|$localInstrument = getDolGlobalString(''PAYMENTBYBANKTRANSFER_CUSTOM_LOCAL_INSTRUMENT'', ''CORE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_END_TO_END', 'string', NULL, 'admin', 'Stores the end-to-end identifier template used in bank transfer (direct debit/SEPA) payment files.', 'Set via the admin UI at admin/paymentbybanktransfer.php. The value is taken directly from the POST field of the same name.', 'Changing this value alters the end-to-end reference included in generated bank transfer payment files.', 'Free string (end-to-end reference identifier).', 0, 0, 'admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/paymentbybanktransfer.php:105|write|$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_END_TO_END\", GETPOST(\"PAYMENTBYBANKTRANSFER_END_TO_END\"), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_FORCE_HIGH_PRIORITY', 'string', NULL, 'compta', 'Forces high-priority processing in SEPA credit transfer XML generation.', 'Checked once in bonprelevement.class.php:2493 to conditionally apply high-priority logic. No admin UI write path exists.', 'Enabling this constant triggers high-priority handling in the SEPA bank transfer XML output; without it the default priority is used.', 'Truthy string/bool=high priority forced, empty/0=default priority', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2493|check|if (getDolGlobalString(''PAYMENTBYBANKTRANSFER_FORCE_HIGH_PRIORITY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_ICS', 'string', NULL, 'admin', 'Stores the ICS (Identifiant Créancier SEPA) code used for direct debit / bank transfer payment orders.', 'Written and read in admin/paymentbybanktransfer.php:92 and :183. The value is saved via dolibarr_set_const and displayed in an admin text input, confirming it is configured through the admin UI.', 'Changing this value updates the SEPA creditor identifier embedded in generated direct debit files, which is required to be correct for bank processing.', 'String; a valid SEPA ICS/creditor identifier code.', 0, 0, 'admin/paymentbybanktransfer.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_ICS\", GETPOST(\"PAYMENTBYBANKTRANSFER_ICS\"), ''chaine'', 0, '''', $conf->entity);", "print ''<input type=\"text\" name=\"PAYMENTBYBANKTRANSFER_ICS\" value=\"''.$conf->global->PAYMENTBYBANKTRANSFER_ICS.''\" size=\"15\" ></td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_ID_BANKACCOUNT', 'string', NULL, 'compta', 'Stores the ID of the bank account used for outgoing bank transfer (payment by bank transfer) operations.', 'Configured via admin/paymentbybanktransfer.php. Read in compta/prelevement/class/bonprelevement.class.php at lines :1121, :1896, :2662 to determine the bank account for bank-transfer type operations. core/lib/prelevement.lib.php:108 checks for its presence. 15 occurrences across admin and core files.', 'Without this constant set, bank transfer order generation will fail or warn (checked in core/lib/prelevement.lib.php:108); the value must reference a valid current bank account.', 'Integer: ID of the bank account (compte courant) to use for bank transfers; empty = no default account set', 0, 0, 'admin/paymentbybanktransfer.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/paymentbybanktransfer.php:68|write|$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_ID_BANKACCOUNT\", $id, ''chaine'', 0, '''', $conf->entity);", "compta/prelevement/class/bonprelevement.class.php:1121|read|$fk_bank_account = ($type == ''bank-transfer'' ? getDolGlobalInt(''PAYMENTBYBANKTRANSFER_ID_BANKACCOUNT'') : getDolGlobalInt(''PRELEVEMENT_ID_BANKACCOUNT''));", "core/lib/prelevement.lib.php:108|check|if (!getDolGlobalString(''PAYMENTBYBANKTRANSFER_ID_BANKACCOUNT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_USER', 'string', NULL, 'admin', 'Stores the Dolibarr user ID responsible for generating bank transfer (credit transfer) files.', 'Set via admin/paymentbybanktransfer.php and read as a user selector. Checked in core/lib/prelevement.lib.php:112 to block file generation if absent.', 'If unset, bank transfer file generation is blocked; the designated user receives related notifications or responsibilities.', 'A valid Dolibarr user ID (integer stored as string). Empty string means no user assigned.', 0, 0, 'admin/paymentbybanktransfer.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/paymentbybanktransfer.php:97|write|$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_USER\", GETPOST(\"PAYMENTBYBANKTRANSFER_USER\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/prelevement.lib.php:112|check|if (!getDolGlobalString(''PAYMENTBYBANKTRANSFER_USER'')) {", "admin/paymentbybanktransfer.php:191|read|print $form->select_dolusers(getDolGlobalString(''PAYMENTBYBANKTRANSFER_USER''), ''PAYMENTBYBANKTRANSFER_USER'', 1, null, 0, '''', '''', ''0'', 0, 0, '''', 0, '''', ''minwidth200 maxwidth500'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTBYBANKTRANSFER_USTRD', 'string', NULL, 'admin', 'Stores the unstructured remittance information (UStrd) template used in bank transfer payment files.', 'Set via the admin UI at admin/paymentbybanktransfer.php. The value is taken directly from the POST field of the same name.', 'Changing this value alters the unstructured remittance information included in generated bank transfer payment files.', 'Free string (unstructured remittance text).', 0, 0, 'admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/paymentbybanktransfer.php:110|write|$res = dolibarr_set_const($db, \"PAYMENTBYBANKTRANSFER_USTRD\", GETPOST(\"PAYMENTBYBANKTRANSFER_USTRD\"), ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTORDER_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the active PDF template addon for payment orders (direct-debit / bank-transfer orders).', 'Checked at admin/paymentbybanktransfer.php line 329 and admin/prelevement.php line 342 to identify which PDF model is currently selected in the admin UI.', 'Changing this value switches the PDF template used when generating payment order documents.', 'String; value equals the name of the selected PDF addon module (e.g. ''sepamandate''). Set via admin/paymentbybanktransfer.php or admin/prelevement.php.', 0, 0, 'admin/paymentbybanktransfer.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/paymentbybanktransfer.php:329|check|if (getDolGlobalString(''PAYMENTORDER_ADDON_PDF'') == $name)", "admin/prelevement.php:342|check|if (getDolGlobalString(''PAYMENTORDER_ADDON_PDF'') == $name)"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTS_FOURN_REPORT_GROUP_BY_MOD', 'string', NULL, 'core', 'Groups supplier payment report lines by payment mode (paiement_code) in the PDF payment report.', 'Documented at core/modules/rapport/pdf_paiement.class.php:340: ''If global param PAYMENTS_FOURN_REPORT_GROUP_BY_MOD is set, payment fourn are ordered by paiement_code''. Configured via admin/supplier_payment.php with a yes/no selector and persisted via dolibarr_set_const.', 'Enabling grouping reorganises the supplier payment PDF to cluster entries by payment mode; disabling it produces a flat, ungrouped report.', 'Yes/no integer (1=group by payment mode, 0=no grouping); set via selectyesno in admin UI.', 0, 0, 'admin/supplier_payment.php|admin/supplier_payment.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/rapport/pdf_paiement.class.php:340  // If global param PAYMENTS_FOURN_REPORT_GROUP_BY_MOD is set, payment fourn are ordered by paiement_code", "admin/supplier_payment.php:147|write|$res = dolibarr_set_const($db, \"PAYMENTS_FOURN_REPORT_GROUP_BY_MOD\", GETPOSTINT(''PAYMENTS_FOURN_REPORT_GROUP_BY_MOD''), ''chaine'', 0, '''', $conf->entity);", "admin/supplier_payment.php:466|read|print $form->selectyesno(\"PAYMENTS_FOURN_REPORT_GROUP_BY_MOD\", getDolGlobalString(\"PAYMENTS_FOURN_REPORT_GROUP_BY_MOD\"), 1);", "core/modules/rapport/pdf_paiement.class.php:341|check|if (getDolGlobalString(''PAYMENTS_FOURN_REPORT_GROUP_BY_MOD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENTS_REPORT_GROUP_BY_MOD', 'string', NULL, 'core', 'When enabled, groups and orders payments by payment mode (paiement_code) in the payments PDF report.', 'Comment in core/modules/rapport/pdf_paiement.class.php:298: ''If global param PAYMENTS_REPORT_GROUP_BY_MOD is set, payment are ordered by paiement_code''. Checked at lines 299, 545, 592, and 619 of pdf_paiement.class.php. Written via admin/payment.php:97.', 'Enabling this constant reorders payments in the PDF report by payment mode. Disabling it reverts to the default ordering.', 'Non-empty/non-zero = group by payment mode. 0 or empty = default ordering.', 0, 0, 'admin/payment.php|admin/payment.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/rapport/pdf_paiement.class.php:298  // If global param PAYMENTS_REPORT_GROUP_BY_MOD is set, payment are ordered by paiement_code", "core/modules/rapport/pdf_paiement.class.php:299|check|if (getDolGlobalString(''PAYMENTS_REPORT_GROUP_BY_MOD'')) {", "admin/payment.php:97|write|$res = dolibarr_set_const($db, \"PAYMENTS_REPORT_GROUP_BY_MOD\", GETPOSTINT(''PAYMENTS_REPORT_GROUP_BY_MOD''), ''chaine'', 0, '''', $conf->entity);", "admin/payment.php:294|read|print $form->selectyesno(\"PAYMENTS_REPORT_GROUP_BY_MOD\", getDolGlobalInt(''PAYMENTS_REPORT_GROUP_BY_MOD''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_ADDON', 'string', NULL, 'compta', 'Specifies the numbering module (addon) used to generate payment reference numbers.', 'Written in admin/payment.php:87 and compta/paiement/class/paiement.class.php:1266; read and checked across 17 occurrences in admin/payment.php, admin/supplier_payment.php, and compta/paiement/class/paiement.class.php. Default fallback is ''mod_payment_cicada''.', 'Changing this constant switches the payment reference numbering module, affecting how all new payment references are generated.', 'String PHP filename (e.g. ''mod_payment_cicada'' or ''mod_payment_cicada.php''); empty = defaults to ''mod_payment_cicada''.', 0, 0, 'admin/payment.php|admin/payment.php|admin/payment.php|admin/supplier_payment.php|admin/payment.php|admin/payment.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/payment.php:56|write|$conf->global->PAYMENT_ADDON = ''mod_payment_cicada.php'';", "admin/payment.php:87|write|dolibarr_set_const($db, \"PAYMENT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "compta/paiement/class/paiement.class.php:1265|check|if (!getDolGlobalString(''PAYMENT_ADDON'')) {", "compta/paiement/class/paiement.class.php:1266|write|$conf->global->PAYMENT_ADDON = ''mod_payment_cicada'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_ANT_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the ''Ant'' automatic numbering module for payment references.', 'Used exclusively within core/modules/payment/mod_payment_ant.php. At line 99 it is shown in a configuration input; at line 145 it is loaded as the active mask for payment reference generation.', 'Changing the mask alters the format of newly generated payment reference numbers; existing references are unaffected.', 'Any mask string accepted by the payment numbering module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/payment/mod_payment_ant.php:99|read|value=\"''.getDolGlobalString(''PAYMENT_ANT_MASK'').''\"", "core/modules/payment/mod_payment_ant.php:145|read|$mask = getDolGlobalString(''PAYMENT_ANT_MASK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_NEWFORM_TEXT', 'string', NULL, 'public', 'Sets a text (or translation key in parentheses) displayed at the bottom of the public payment form.', 'Checked at public/payment/newpayment.php:1088, :1091, and :1094; if the value is wrapped in parentheses it is treated as a translation key, otherwise it is printed as-is. No admin UI write found.', 'When set, the specified text or its translation appears at the bottom of the public payment form.', 'A plain text string, or a translation key wrapped in parentheses e.g. ''(MyKey)''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:1088|check|if (getDolGlobalString(''PAYMENT_NEWFORM_TEXT'')) {", "public/payment/newpayment.php:1091|check|if (preg_match(''/^\\((.*)\\)$/'', getDolGlobalString(''PAYMENT_NEWFORM_TEXT''), $reg)) {", "public/payment/newpayment.php:1094|read|$text .= getDolGlobalString(''PAYMENT_NEWFORM_TEXT'') . \"<br>\\n\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_SECURITY_ACCEPT_ANY_TOKEN', 'string', NULL, 'stripe', 'Disables token validation on the public payment page, allowing payments without a valid security token.', 'Checked in stripe/admin/stripe.php:667, paypal/admin/paypal.php:327, and public/payment/newpayment.php:390. When not set, the payment page enforces token validation; when set, the token check is bypassed.', 'Enabling this weakens payment page security by removing token verification, which is a security risk in production environments.', 'Empty/0 = token validation enforced; truthy = any token accepted (security check bypassed)', 0, 0, 'stripe/admin/stripe.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/payment/newpayment.php:390|check|if (!getDolGlobalString(''PAYMENT_SECURITY_ACCEPT_ANY_TOKEN'')) {", "stripe/admin/stripe.php:667|check|if (getDolGlobalString(''PAYMENT_SECURITY_ACCEPT_ANY_TOKEN'')) {", "paypal/admin/paypal.php:327|check|if (getDolGlobalString(''PAYMENT_SECURITY_ACCEPT_ANY_TOKEN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_SECURITY_TOKEN', 'string', NULL, 'core', 'Shared secret token used to validate the authenticity of online payment callback requests.', 'Written via paypal/admin/paypal.php:112, paybox/admin/paybox.php:106, stripe/admin/stripe.php:163, and auto-generated at install/step5.php:289 using random bytes. Used across 76 occurrences to authenticate payment return URLs and callbacks.', 'If empty or incorrect, payment callback validation will fail, preventing online payment confirmation from being processed securely.', 'String: random secret token (auto-generated with bin2hex(random_bytes(12)) at install time).', 0, 0, 'paybox/admin/paybox.php|paybox/admin/paybox.php|stripe/admin/stripe.php|paypal/admin/paypal.php|paypal/admin/paypal.php|paybox/admin/paybox.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["install/step5.php:289|write|dolibarr_set_const($db, \"PAYMENT_SECURITY_TOKEN\", bin2hex(random_bytes(12)), ''chaine'', 0, '''', 0); // All entities", "paybox/admin/paybox.php:285|read|print ''<input size=\"48\" type=\"text\" id=\"PAYMENT_SECURITY_TOKEN\" name=\"PAYMENT_SECURITY_TOKEN\" value=\"'' . getDolGlobalString(''PAYMENT_SECURITY_TOKEN'').''\">'';", "stripe/admin/stripe.php:663|read|print ''<input class=\"minwidth300\"  type=\"text\" id=\"PAYMENT_SECURITY_TOKEN\" name=\"PAYMENT_SECURITY_TOKEN\" value=\"'' . getDolGlobalString(''PAYMENT_SECURITY_TOKEN'').''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_SECURITY_TOKEN_UNIQUE', 'string', NULL, 'core', 'Determines whether the payment security token is unique per transaction or shared (static) across all payment links.', 'Written in paypal/admin/paypal.php, stripe/admin/stripe.php, and paybox/admin/paybox.php. Read and checked in admin/system/security.php at lines 749 and 761 and rendered as a select in all three payment-module admin pages.', 'Using a unique token per transaction increases security by preventing token replay. A shared static token is less secure but simpler to manage.', '0 = shared/static token; 1 = unique token per transaction', 0, 0, 'paypal/admin/paypal.php|admin/system/security.php|admin/system/security.php|stripe/admin/stripe.php|paybox/admin/paybox.php|paypal/admin/paypal.php|paybox/admin/paybox.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''PAYMENT_SECURITY_TOKEN_UNIQUE'')) {", "$result = dolibarr_set_const($db, \"PAYMENT_SECURITY_TOKEN_UNIQUE\", GETPOST(''PAYMENT_SECURITY_TOKEN_UNIQUE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "print $form->selectarray(\"PAYMENT_SECURITY_TOKEN_UNIQUE\", $arrval, getDolGlobalString(''PAYMENT_SECURITY_TOKEN_UNIQUE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYMENT_USE_NEW_PRICE_FOR_CONTRACTLINES', 'bool', NULL, 'public', 'When enabled, forces contract line prices to be refreshed from the current product price during public payment processing.', 'Checked at public/payment/newpayment.php:1488 for contract lines that have a linked product; when set, the new product price is applied. No admin UI write found.', 'If enabled, contract line amounts are overridden with the current product price at payment time.', '0 or unset = use existing contract line price; non-zero = use current product price', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:1488|check|if ($contractline->fk_product && getDolGlobalString(''PAYMENT_USE_NEW_PRICE_FOR_CONTRACTLINES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_ADD_PAYMENT_URL', 'string', NULL, 'paypal', 'Controls whether a payment URL is added to PayPal-related pages or emails.', 'Written at paypal/admin/paypal.php line 91 and rendered as a yes/no selector at line 276. It is a boolean-style string constant set through the PayPal admin configuration page.', 'When enabled, a payment URL is included in the relevant context; when disabled it is omitted.', '0 = do not add payment URL; 1 = add payment URL', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$result = dolibarr_set_const($db, \"PAYPAL_ADD_PAYMENT_URL\", GETPOST(''PAYPAL_ADD_PAYMENT_URL'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "print $form->selectyesno(\"PAYPAL_ADD_PAYMENT_URL\", getDolGlobalString(''PAYPAL_ADD_PAYMENT_URL''), 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_ALLOW_NOTES', 'bool', NULL, 'paypal', 'Enables the customer notes field on the PayPal checkout page.', 'Checked at paypal/lib/paypal.lib.php:218 only. Only 1 occurrence and no admin UI.', 'Enabling this constant adds a notes/comments field to the PayPal checkout experience.', 'Boolean/truthy: non-empty enables the notes field.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''PAYPAL_ALLOW_NOTES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_EXPRESS', 'string', NULL, 'paypal', 'Enables or disables the PayPal Express Checkout API mode in the PayPal module configuration.', 'Read via a yes/no select form element at paypal/admin/paypal.php:248; value is set through the admin UI.', 'When enabled, the PayPal integration uses the Express Checkout API flow.', '0 = disabled; 1 = enabled (yes/no select in admin UI)', 0, 0, 'paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["paypal/admin/paypal.php:248|read|print $form->selectyesno(\"PAYPAL_API_EXPRESS\",$conf->global->PAYPAL_API_EXPRESS);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_INTEGRAL_OR_PAYPALONLY', 'string', NULL, 'paypal', 'Selects the PayPal payment mode: integral checkout (hosted form), PayPal-only button, or credit-card-only mode.', 'Written via paypal/admin/paypal.php:83 and read at line 242 in a select array with keys ''integral'' and ''paypalonly''. Checked in paypal/lib/paypal.lib.php at lines 87, 94, 99, and 104 for '''', ''paypalonly'', ''integral'', and ''cconly'' respectively. Also checked in public/payment/newpayment.php.', 'The chosen mode determines which PayPal checkout flow is invoked; an unrecognized or empty value falls back to a default branch at paypal.lib.php:87.', '''integral'' = full hosted PayPal checkout; ''paypalonly'' = PayPal button only; ''cconly'' = credit card only; empty = default fallback.', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["print $form->selectarray(\"PAYPAL_API_INTEGRAL_OR_PAYPALONLY\", array(''integral''=> $langs->trans(''PaypalModeIntegral''), ''paypalonly''=> $langs->trans(''PaypalModeOnlyPaypal'')), getDolG...", "if (getDolGlobalString(''PAYPAL_API_INTEGRAL_OR_PAYPALONLY'') == ''paypalonly'') {", "if (getDolGlobalString(''PAYPAL_API_INTEGRAL_OR_PAYPALONLY'') == ''integral'') {", "if (getDolGlobalString(''PAYPAL_API_INTEGRAL_OR_PAYPALONLY'') == ''cconly'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_PASSWORD', 'string', NULL, 'paypal', 'Stores the PayPal API password credential used for authenticating PayPal NVP API calls.', 'Configured via the admin UI at paypal/admin/paypal.php and read by paypal/lib/paypal.lib.php:472, paypalfunctions.lib.php:62, and public/payment/paymentok.php:94 to authenticate PayPal API requests.', 'Without a valid API password, PayPal payment processing will fail. Changing this to an incorrect value breaks all PayPal-related transactions.', 'String (PayPal API password credential).', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/admin/paypal.php:63|write|$result = dolibarr_set_const($db, \"PAYPAL_API_PASSWORD\", GETPOST(''PAYPAL_API_PASSWORD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paypal/lib/paypal.lib.php:472|read|$PAYPAL_API_PASSWORD = getDolGlobalString(''PAYPAL_API_PASSWORD'');", "paypal/lib/paypalfunctions.lib.php:62|read|$PAYPAL_API_PASSWORD = getDolGlobalString(''PAYPAL_API_PASSWORD'');", "public/payment/paymentok.php:94|read|$PAYPAL_API_PASSWORD = getDolGlobalString(''PAYPAL_API_PASSWORD'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_SANDBOX', 'string', NULL, 'paypal', 'Switches the PayPal payment integration between sandbox (test) and live mode.', 'Configured via paypal/admin/paypal.php. When set, sandbox API endpoints are used in paypal/lib/paypal.lib.php:462 and paypal/lib/paypalfunctions.lib.php:52. Read and written in 10 occurrences. The commented-out check in societe/paymentmodes.php:908 confirms the sandbox intent.', 'When set, PayPal operates in test/sandbox mode using test credentials; when unset, live PayPal API calls are made.', '0 or unset = live mode; non-empty = sandbox/test mode', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/lib/paypal.lib.php:462|check|if (getDolGlobalString(''PAYPAL_API_SANDBOX'')/* || GETPOST(''forcesandbox'', ''alpha'') */) {\t\t// We can force sand box with param ''forcesandbox''", "paypal/lib/paypalfunctions.lib.php:52|check|if (getDolGlobalString(''PAYPAL_API_SANDBOX'')/* || GETPOST(''forcesandbox'', ''alpha'') */) {\t\t// We can force sand box with param ''forcesandbox''", "paypal/admin/paypal.php:134|write|$res = dolibarr_set_const($db, \"PAYPAL_API_SANDBOX\", $liveenable, ''yesno'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_SIGNATURE', 'string', NULL, 'paypal', 'Stores the PayPal API signature credential used for authenticating PayPal NVP API calls.', 'Configured via the admin UI at paypal/admin/paypal.php and read by paypal/lib/paypal.lib.php:473, paypalfunctions.lib.php:63, and public/payment/paymentok.php:95 to authenticate PayPal API requests.', 'Without a valid API signature, PayPal payment processing will fail. Changing this to an incorrect value breaks all PayPal-related transactions.', 'String (PayPal API signature credential).', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/admin/paypal.php:67|write|$result = dolibarr_set_const($db, \"PAYPAL_API_SIGNATURE\", GETPOST(''PAYPAL_API_SIGNATURE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paypal/lib/paypal.lib.php:473|read|$PAYPAL_API_SIGNATURE = getDolGlobalString(''PAYPAL_API_SIGNATURE'');", "paypal/lib/paypalfunctions.lib.php:63|read|$PAYPAL_API_SIGNATURE = getDolGlobalString(''PAYPAL_API_SIGNATURE'');", "public/payment/paymentok.php:95|read|$PAYPAL_API_SIGNATURE = getDolGlobalString(''PAYPAL_API_SIGNATURE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_API_USER', 'string', NULL, 'paypal', 'Stores the PayPal API username credential used for authenticating PayPal NVP API calls.', 'Configured via the admin UI at paypal/admin/paypal.php and read by paypal/lib/paypal.lib.php:471, paypalfunctions.lib.php:61, and public/payment/paymentok.php:93 to authenticate PayPal API requests.', 'Without a valid API username, PayPal payment processing will fail. Changing this to an incorrect value breaks all PayPal-related transactions.', 'String (PayPal API username credential).', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/admin/paypal.php:59|write|$result = dolibarr_set_const($db, \"PAYPAL_API_USER\", GETPOST(''PAYPAL_API_USER'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "paypal/lib/paypal.lib.php:471|read|$PAYPAL_API_USER = getDolGlobalString(''PAYPAL_API_USER'');", "paypal/lib/paypalfunctions.lib.php:61|read|$PAYPAL_API_USER = getDolGlobalString(''PAYPAL_API_USER'');", "public/payment/paymentok.php:93|read|$PAYPAL_API_USER = getDolGlobalString(''PAYPAL_API_USER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_BANK_ACCOUNT', 'string', NULL, 'compta', 'Specifies the bank account ID to associate with PayPal payments when recording them in Dolibarr.', 'Checked and read in compta/paiement.php:383 and :384. When the constant is set, its value is used as the $accountid for the PayPal payment entry. No admin UI is configured.', 'Setting this constant directs PayPal payments to a specific bank account record; leaving it unset causes the PayPal payment path to skip the account assignment.', 'Integer or string bank account identifier; empty = no PayPal bank account configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:383|check|if (getDolGlobalString(''PAYPAL_BANK_ACCOUNT'')) {", "compta/paiement.php:384|read|$accountid = getDolGlobalString(''PAYPAL_BANK_ACCOUNT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the Dolibarr bank account ID into which PayPal payments are recorded.', 'Written via the admin UI at paypal/admin/paypal.php and read in public/payment/paymentok.php at multiple points (lines 713, 1107, 1257, 1402, 1538, 1777) to identify the target bank account when recording incoming PayPal payments.', 'If unset or invalid, PayPal payment confirmation pages cannot link the received payment to a bank account entry. Setting a valid account ID ensures automatic reconciliation.', 'Integer bank account ID as stored in Dolibarr''s bank account table', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$result = dolibarr_set_const($db, \"PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS\", GETPOSTINT(''PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS''), ''chaine'', 0, '''', $conf->entity);", "$form->select_comptes(getDolGlobalString(''PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS''), ''PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS'', 0, '''', 1);", "$accountid = getDolGlobalString(''PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS'');", "$bankaccountid = getDolGlobalString(''PAYPAL_BANK_ACCOUNT_FOR_PAYMENTS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_BRANDNAME', 'string', NULL, 'paypal', 'Stores a custom brand name passed to PayPal as the BRANDNAME parameter on the checkout page.', 'Checked at paypal/lib/paypal.lib.php:277 and read at line 278, appended to the NVP string as BRANDNAME. Only 2 occurrences and no admin UI.', 'Setting this constant overrides the default brand name shown on the PayPal-hosted checkout page.', 'A string brand name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''PAYPAL_BRANDNAME'')) {", "$nvpstr = $nvpstr.\"&BRANDNAME=\".urlencode(getDolGlobalString(''PAYPAL_BRANDNAME'')); // BRANDNAME"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_CUSTOMER_SERVICE_NUMBER', 'string', NULL, 'paypal', 'Stores the customer service hotline phone number passed to PayPal as the CUSTOMERSERVICENUMBER parameter.', 'Checked at paypal/lib/paypal.lib.php:228 and read at line 229 with the comment ''// Hotline phone number'', appended to the NVP string as CUSTOMERSERVICENUMBER.', 'Setting this constant includes the phone number in PayPal API requests, which PayPal may display to customers during checkout.', 'A string phone number.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''PAYPAL_CUSTOMER_SERVICE_NUMBER'')) {", "$nvpstr .= \"&CUSTOMERSERVICENUMBER=\".urlencode(getDolGlobalString(''PAYPAL_CUSTOMER_SERVICE_NUMBER'')); // Hotline phone number"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_ENABLE_TRANSACTION_MANAGEMENT', 'bool', NULL, 'compta', 'Enables PayPal transaction management integration during payment recording, allowing PayPal transactions to be captured or voided.', 'Checked once in compta/paiement.php:382 in a condition that also requires the paypalplus module to be enabled and $facture->ref_ext to be non-empty. No admin UI is configured.', 'Enabling this constant activates the PayPal transaction management code path when recording payments linked to an external PayPal reference.', 'Truthy (non-empty / 1) = PayPal transaction management enabled; falsy (empty / 0) = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/paiement.php:382|check|if (isModEnabled(''paypalplus'') && getDolGlobalString(''PAYPAL_ENABLE_TRANSACTION_MANAGEMENT'') && !empty($facture->ref_ext)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_LOGOIMG', 'string', NULL, 'paypal', 'When set (alongside a company logo), includes the company logo image in the PayPal checkout page.', 'Checked at paypal/lib/paypal.lib.php:266 with the condition that both this constant and $mysoc->logo must be set. Only 1 occurrence and no admin UI.', 'Enabling this constant (with a company logo configured) causes the logo to be passed to the PayPal checkout page.', 'Boolean/truthy: non-empty enables logo display (requires $mysoc->logo to also be set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''PAYPAL_LOGOIMG'') && $mysoc->logo) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_NOTETOBUYER', 'string', NULL, 'paypal', 'Sets the note-to-buyer message sent to the customer during a PayPal Express Checkout transaction.', 'When set, the value is appended as the NOTETOBUYER parameter in the PayPal NVP API string. Used in paypal/lib/paypal.lib.php:281.', 'If set, buyers receive the configured note during checkout; if unset, no NOTETOBUYER field is sent to PayPal.', 'Any non-empty string (free text shown to buyer).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/lib/paypal.lib.php:280|check|if (getDolGlobalString(''PAYPAL_NOTETOBUYER'')) {", "paypal/lib/paypal.lib.php:281|read|$nvpstr = $nvpstr.\"&NOTETOBUYER=\".urlencode(getDolGlobalString(''PAYPAL_NOTETOBUYER'')); // PAYPAL_NOTETOBUYER"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_PAYMENT_MODE_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the payment mode ID used to record PayPal payments in the Dolibarr payment system.', 'Read as an integer at public/payment/paymentok.php at lines 582, 1025, 1171, 1465, 1704, and 1922 and assigned to $paymentTypeId for recording payments. No admin UI write found.', 'Setting this to a valid payment mode ID ensures PayPal payments are recorded with the correct payment type.', 'An integer payment mode ID.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/paymentok.php:582|read|$paymentTypeId = getDolGlobalInt(''PAYPAL_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1025|read|$paymentTypeId = getDolGlobalInt(''PAYPAL_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1171|read|$paymentTypeId = getDolGlobalInt(''PAYPAL_PAYMENT_MODE_FOR_PAYMENTS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_REQUIRE_VALID_SHIPPING_ADDRESS', 'string', NULL, 'paypal', 'When set, requires a valid shipping address during PayPal checkout; when not set, skips the shipping address requirement.', 'Checked at paypal/lib/paypal.lib.php:221 with a negated condition: the no-shipping flag is set when this constant is NOT set. Only 1 occurrence and no admin UI.', 'Leaving this constant unset causes the PayPal checkout to bypass the shipping address requirement. Setting it enforces a valid shipping address.', 'Boolean/truthy: non-empty requires a valid shipping address; empty/unset disables the requirement.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''PAYPAL_REQUIRE_VALID_SHIPPING_ADDRESS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_SECURITY_TOKEN', 'string', NULL, 'comm', 'Shared secret token used to generate hashed secure keys for PayPal payment links in mass mailings.', 'Used exclusively in comm/mailing/card.php. The token is hashed via dol_hash() to produce __SECUREKEYPAYPAL__, __SECUREKEYPAYPAL_MEMBER__, __SECUREKEYPAYPAL_ORDER__, and __SECUREKEYPAYPAL_INVOICE__ substitution values for mailing templates.', 'Setting this token enables PayPal payment link generation in mailing campaigns. Clearing it disables PayPal link substitution variables.', 'A secret string used as the base for SHA-based hashing; empty = PayPal secure keys not generated', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:341|check|if (isModEnabled(''paypal'') && getDolGlobalString(''PAYPAL_SECURITY_TOKEN'')) {", "comm/mailing/card.php:342|read|$substitutionarray[''__SECUREKEYPAYPAL__''] = dol_hash(getDolGlobalString(''PAYPAL_SECURITY_TOKEN''), ''2'');", "comm/mailing/card.php:345|read|$substitutionarray[''__SECUREKEYPAYPAL_MEMBER__''] = dol_hash(getDolGlobalString(''PAYPAL_SECURITY_TOKEN''), ''2'');", "comm/mailing/card.php:351|read|$substitutionarray[''__SECUREKEYPAYPAL_ORDER__''] = dol_hash(getDolGlobalString(''PAYPAL_SECURITY_TOKEN''), ''2'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_SECURITY_TOKEN_UNIQUE', 'string', NULL, 'comm', 'Controls whether a unique per-record token is used for PayPal secure key generation in mailing substitution.', 'Checked four times in comm/mailing/card.php (lines 344, 350, 356, 362). When not set, the token is combined with a record-specific identifier (source_id) to produce unique per-record hashes for member, order, and invoice payment links.', 'When this constant is empty/unset, each PayPal link hash is unique per record (source_id appended). When set, a single shared hash is used for all records of each type.', 'Empty/unset = per-record unique token (source_id appended); non-empty = shared token (no source_id appended)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/card.php:344|check|if (!getDolGlobalString(''PAYPAL_SECURITY_TOKEN_UNIQUE'')) {", "comm/mailing/card.php:350|check|if (!getDolGlobalString(''PAYPAL_SECURITY_TOKEN_UNIQUE'')) {", "comm/mailing/card.php:356|check|if (!getDolGlobalString(''PAYPAL_SECURITY_TOKEN_UNIQUE'')) {", "comm/mailing/card.php:362|check|if (!getDolGlobalString(''PAYPAL_SECURITY_TOKEN_UNIQUE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PAYPAL_SSLVERSION', 'string', NULL, 'paypal', 'Sets the SSL/TLS version used for cURL connections to the PayPal API.', 'Configured via a select dropdown in paypal/admin/paypal.php:221. Applied at paypal/lib/paypal.lib.php:489 via curl_setopt CURLOPT_SSLVERSION; defaults to 1 (TLSv1) if unset.', 'Changing this value changes the TLS protocol version used for PayPal API communications; an incompatible value may cause connection failures.', '1 = TLSv1, 6 = TLSv1.2', 0, 0, 'paypal/admin/paypal.php|paypal/admin/paypal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["paypal/admin/paypal.php:221|read|print $form->selectarray(\"PAYPAL_SSLVERSION\", array(''1''=> $langs->trans(''TLSv1''), ''6''=> $langs->trans(''TLSv1.2'')), getDolGlobalString(''PAYPAL_SSLVERSION''));", "paypal/lib/paypal.lib.php:489|read|curl_setopt($ch, CURLOPT_SSLVERSION, (!getDolGlobalString(''PAYPAL_SSLVERSION'') ? 1 : $conf->global->PAYPAL_SSLVERSION));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ACCOUNTANCY_BALANCE_ADD_POSITION', 'string', NULL, 'core', 'Controls whether positional/layout data is added to the accountancy balance PDF export.', 'Read as a boolean integer in core/modules/accountancy/doc/pdf_balance.modules.php:755 and used as the ''status'' field in the position configuration array. No admin UI manages this constant.', 'Enabling this activates position metadata in the balance PDF output; disabling it omits it.', 'Non-zero integer value enables position addition; 0 or unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/accountancy/doc/pdf_balance.modules.php:755|read|''status'' => (bool) getDolGlobalInt(''PDF_ACCOUNTANCY_BALANCE_ADD_POSITION''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ACCOUNTANCY_LEDGER_ADD_POSITION', 'string', NULL, 'core', 'Controls whether positional/layout data is added to the accountancy ledger and bookkeeping PDF exports.', 'Read as a boolean integer in core/modules/accountancy/doc/pdf_ledger.modules.php:795 and core/modules/accountancy/doc/pdf_bookkeeping.modules.php:737, used as the ''status'' field in the position configuration array for both modules.', 'Enabling this activates position metadata in ledger and bookkeeping PDF outputs; disabling it omits it.', 'Non-zero integer value enables position addition; 0 or unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/accountancy/doc/pdf_ledger.modules.php:795|read|''status'' => (bool) getDolGlobalInt(''PDF_ACCOUNTANCY_LEDGER_ADD_POSITION''),", "core/modules/accountancy/doc/pdf_bookkeeping.modules.php:737|read|''status'' => (bool) getDolGlobalInt(''PDF_ACCOUNTANCY_LEDGER_ADD_POSITION''),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ADD_MORE_AFTER_SOURCE_ADDRESS', 'string', NULL, 'core', 'Appends custom text to the source address block on PDF documents.', 'The value of this constant is read and concatenated directly to the address string in core/lib/pdf.lib.php:550, preceded by a newline if the address is non-empty. No admin UI write is present; must be set manually.', 'Setting this constant injects arbitrary text after the issuing company''s address on all generated PDFs.', 'Any non-empty string = text appended after source address; absent/empty = nothing appended.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:549|check|if (getDolGlobalString(''PDF_ADD_MORE_AFTER_SOURCE_ADDRESS'')) {", "core/lib/pdf.lib.php:550|read|$stringaddress .= ($stringaddress ? \"\\n\" : '''') . getDolGlobalString(''PDF_ADD_MORE_AFTER_SOURCE_ADDRESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ADD_POSITION', 'string', NULL, 'core', 'Controls whether a position (line number) column is included in PDF documents across multiple templates as a global fallback.', 'Used in six locations across pdf_espadon, pdf_eratosthene, pdf_octopus, pdf_sponge, pdf_cornas, and pdf_cyan modules. In each case it serves as a fallback when the template-specific position constant (e.g., PDF_ESPADON_ADD_POSITION) is falsy.', 'Setting this to a truthy value enables the position column in all supported PDF templates that do not have a template-specific override. Clearing it disables the position column globally as a fallback.', '0 or unset = no position column (as fallback); non-zero = position column enabled in all templates that check it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_espadon.modules.php:1375|''status'' => getDolGlobalInt(''PDF_ESPADON_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),", "pdf_eratosthene.modules.php:1983|''status'' => (getDolGlobalInt(''PDF_ERATOSTHENE_ADD_POSITION'') || getDolGlobalInt(''PDF_ERATOSHTENE_ADD_POSITION'')) ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),", "pdf_octopus.modules.php:2424|''status'' => getDolGlobalInt(''PDF_SPONGE_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),", "pdf_cornas.modules.php:1578|''status'' => getDolGlobalInt(''PDF_CORNAS_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ALLOW_DISPLAY_LINKED_OBJECT_FOR_OTHER_SOC', 'bool', NULL, 'core', 'Allows linked objects from a different third party to be displayed in PDF documents.', 'Checked once in core/lib/pdf.lib.php:2953 as a boolean guard. No admin UI write is present.', 'Enabling this permits cross-third-party linked object information to appear in PDFs; disabling it restricts display to the document''s own third party.', 'truthy = allow display of linked objects from other third parties; empty/false = restrict to same third party', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2953|check|if (getDolGlobalBool(\"PDF_ALLOW_DISPLAY_LINKED_OBJECT_FOR_OTHER_SOC\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ALLOW_HTML_FOR_FREE_TEXT', 'bool', NULL, 'admin', 'Enables HTML rendering in the free text (public note) field on PDF documents.', 'Checked across 22 occurrences in numerous admin pages (admin/bom.php:520, admin/expensereport.php:485, admin/propal.php:655, admin/supplier_order.php:506, etc.) where the absence of this constant triggers a plain-text fallback. Admin UI writes are present across many modules.', 'Enabling this allows HTML markup in the free text field to be rendered as formatted content on PDFs instead of plain text.', 'Truthy string (non-empty) = render HTML in free text; absent/empty = use plain text in free text field.', 0, 0, 'admin/bom.php|admin/expensereport.php|admin/supplier_order.php|admin/delivery.php|admin/propal.php|admin/holiday.php|admin/supplier_proposal.php|admin/contract.php|admin/chequereceipts.php|admin/expedition.php|admin/supplier_invoice.php|admin/order.php|admin/fichinter.php|admin/mrp.php|admin/invoice.php|takepos/admin/receipt.php|takepos/admin/receipt.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/bom.php:520|check|if (!getDolGlobalString(''PDF_ALLOW_HTML_FOR_FREE_TEXT'')) {", "admin/expensereport.php:485|check|if (!getDolGlobalString(''PDF_ALLOW_HTML_FOR_FREE_TEXT'')) {", "admin/propal.php:655|check|if (!getDolGlobalString(''PDF_ALLOW_HTML_FOR_FREE_TEXT'')) {", "admin/supplier_order.php:506|check|if (!getDolGlobalString(''PDF_ALLOW_HTML_FOR_FREE_TEXT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_BANK_HIDE_NUMBER_SHOW_ONLY_BICIBAN', 'bool', NULL, 'core', 'Hides the bank account number from PDF bank detail blocks, showing only BIC and IBAN.', 'Checked at core/lib/pdf.lib.php:1273; when truthy, the bank account number is omitted. The inline comment notes that some countries still require the bank number and BIC/IBAN is not sufficient for them. No admin UI write is present.', 'Enabling this removes the bank account number from PDF documents, leaving only BIC/IBAN visible.', 'Truthy string (non-empty) = hide bank number, show only BIC/IBAN; absent/empty = show bank number.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1273|check|if (!getDolGlobalString(''PDF_BANK_HIDE_NUMBER_SHOW_ONLY_BICIBAN'')) {    // Note that some countries still need bank number, BIC/IBAN not enough for them"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_BOLD_PRODUCT_LABEL', 'string', NULL, 'admin', 'Controls whether the product label is rendered in bold in PDF line item blocks.', 'Configured via admin/pdf.php (written at line 202, rendered as a yes/no selector at line 621). Checked at core/lib/pdf.lib.php:2009; when truthy and a label is present, bold formatting is applied.', 'Enabling this makes product labels bold in generated PDF documents.', '1 = bold product label; 0 or absent = normal weight product label.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:202|write|dolibarr_set_const($db, \"PDF_BOLD_PRODUCT_LABEL\", GETPOST(''PDF_BOLD_PRODUCT_LABEL'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:621|read|print $form->selectyesno(''PDF_BOLD_PRODUCT_LABEL'', getDolGlobalInt(''PDF_BOLD_PRODUCT_LABEL''), 1);", "core/lib/pdf.lib.php:2009|check|if (!empty($libelleproduitservice) && getDolGlobalString(''PDF_BOLD_PRODUCT_LABEL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_BOLD_PRODUCT_REF_AND_PERIOD', 'string', NULL, 'core', 'Makes the product reference and period text bold in PDF document lines.', 'Configurable via the admin UI at admin/pdf.php (written at line 205, displayed at line 632). When set, bold formatting is applied to product references and period labels in core/lib/pdf.lib.php at lines 2177 and 2215.', 'Enabling this bolds the product reference and period in PDF lines; disabling it uses normal weight text.', 'truthy (yes) = bold product ref and period; empty/no = normal weight', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:205|write|dolibarr_set_const($db, \"PDF_BOLD_PRODUCT_REF_AND_PERIOD\", GETPOST(''PDF_BOLD_PRODUCT_REF_AND_PERIOD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:632|read|print $form->selectyesno(''PDF_BOLD_PRODUCT_REF_AND_PERIOD'', getDolGlobalInt(''PDF_BOLD_PRODUCT_REF_AND_PERIOD''), 1);", "core/lib/pdf.lib.php:2177|check|if (!empty($ref_prodserv) && getDolGlobalString(''PDF_BOLD_PRODUCT_REF_AND_PERIOD'')) {", "core/lib/pdf.lib.php:2215|check|if (getDolGlobalString(''PDF_BOLD_PRODUCT_REF_AND_PERIOD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_CORNAS_ADD_POSITION', 'string', NULL, 'core', 'Enables display of the position (line number) column in supplier order PDFs generated by the Cornas module.', 'Read in pdf_cornas.modules.php at line 1578 within the column status map; falls back to PDF_ADD_POSITION when not set. No admin UI write is present.', 'Enabling this causes the position column to appear in Cornas supplier order PDFs; disabling causes the fallback PDF_ADD_POSITION to be evaluated.', 'Truthy integer = position column enabled; 0 or unset = falls back to PDF_ADD_POSITION.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_cornas.modules.php:1578|read|''status'' => getDolGlobalInt(''PDF_CORNAS_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_CYAN_ADD_POSITION', 'string', NULL, 'core', 'Enables the position column in the cyan proposal PDF template, with fallback to PDF_ADD_POSITION.', 'Read in pdf_cyan.modules.php:2115. The value is evaluated as an integer; if non-zero it enables the position column, otherwise PDF_ADD_POSITION is checked as a fallback. No admin UI write is present.', 'Setting this constant to a non-zero value activates the position column specifically for the cyan proposal PDF template. If unset or zero, the template falls back to PDF_ADD_POSITION.', 'Non-zero integer = position column enabled for cyan template; 0 or unset = fallback to PDF_ADD_POSITION.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:2115|read|''status'' => getDolGlobalInt(''PDF_CYAN_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_DIFFSIZE_CONTENT', 'string', NULL, 'core', 'Sets the font size offset (relative to base font size) used for content rows in PDF line item tables.', 'Read at core/lib/pdf.lib.php:1242 using getDolGlobalInt with a default of 4. No admin UI write is present; must be set manually.', 'Changing this value adjusts the font size for content rows in PDF line item tables.', 'Integer offset value; default = 4 (added to base font size). Any integer is accepted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1242|read|$diffsizecontent = getDolGlobalInt(''PDF_DIFFSIZE_CONTENT'', 4);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_DIFFSIZE_TITLE', 'string', NULL, 'core', 'Sets the font size offset (relative to base font size) used for column title rows in PDF line item tables.', 'Read across 15 occurrences in multiple PDF module files (commande, facture, supplier_order, propale, etc.) using getDolGlobalInt with a default of 3 (e.g. core/modules/commande/doc/pdf_einstein.modules.php:733). No admin UI write is present.', 'Changing this value alters the font size of header/title rows in PDF line item tables across all document types.', 'Integer offset value; default = 3 (added to base font size). Any integer is accepted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/commande/doc/pdf_einstein.modules.php:733|read|$diffsizetitle = getDolGlobalInt(''PDF_DIFFSIZE_TITLE'', 3);", "core/modules/commande/doc/pdf_eratosthene.modules.php:998|read|$diffsizetitle = getDolGlobalInt(''PDF_DIFFSIZE_TITLE'', 3);", "core/modules/facture/doc/pdf_octopus.modules.php:1556|read|$diffsizetitle = getDolGlobalInt(''PDF_DIFFSIZE_TITLE'', 3);", "core/modules/facture/doc/pdf_sponge.modules.php:1622|read|$diffsizetitle = getDolGlobalInt(''PDF_DIFFSIZE_TITLE'', 3);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_DISABLE_MYCOMPANY_LOGO', 'bool', NULL, 'core', 'Disables printing of the company logo in the header of generated PDF documents.', 'Checked across 16 occurrences in PDF generation modules using !getDolGlobalInt(''PDF_DISABLE_MYCOMPANY_LOGO'') to conditionally skip logo rendering. No admin UI write is present.', 'Enabling this removes the company logo from all generated PDF document headers.', '0 or unset = company logo shown; 1 = company logo hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:756|check|if (!getDolGlobalInt(''PDF_DISABLE_MYCOMPANY_LOGO'')) {", "core/modules/commande/doc/pdf_einstein.modules.php:1381|check|if (!getDolGlobalInt(''PDF_DISABLE_MYCOMPANY_LOGO'')) {", "core/modules/facture/doc/pdf_octopus.modules.php:1981|check|if (!getDolGlobalInt(''PDF_DISABLE_MYCOMPANY_LOGO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ERATOSHTENE_ADD_POSITION', 'string', NULL, 'core', 'Alias/typo variant of PDF_ERATOSTHENE_ADD_POSITION; when set, enables the position column in the eratosthene order PDF template.', 'Used in a single location in core/modules/commande/doc/pdf_eratosthene.modules.php:1983, ORed with PDF_ERATOSTHENE_ADD_POSITION (the correctly spelled variant) before falling back to PDF_ADD_POSITION.', 'Setting this to a truthy value has the same effect as PDF_ERATOSTHENE_ADD_POSITION: the position column is enabled for the eratosthene template. It exists as a typo-tolerant fallback alongside the correctly named constant.', '0 or unset = no effect (falls back to PDF_ADD_POSITION unless PDF_ERATOSTHENE_ADD_POSITION is set); non-zero = position column enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eratosthene.modules.php:1983|''status'' => (getDolGlobalInt(''PDF_ERATOSTHENE_ADD_POSITION'') || getDolGlobalInt(''PDF_ERATOSHTENE_ADD_POSITION'')) ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ERATOSTHENE_ADD_POSITION', 'string', NULL, 'core', 'When set, enables the position column in the eratosthene order PDF template, taking priority over the generic PDF_ADD_POSITION setting.', 'Used in a single location in core/modules/commande/doc/pdf_eratosthene.modules.php:1983 as the primary check (ORed with PDF_ERATOSHTENE_ADD_POSITION) for the position column status, with PDF_ADD_POSITION as fallback.', 'Setting this to a truthy value activates the position column specifically for the eratosthene PDF template. When unset, the column status falls back to the value of PDF_ADD_POSITION.', '0 or unset = falls back to PDF_ADD_POSITION; non-zero = position column enabled for eratosthene template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eratosthene.modules.php:1983|''status'' => (getDolGlobalInt(''PDF_ERATOSTHENE_ADD_POSITION'') || getDolGlobalInt(''PDF_ERATOSHTENE_ADD_POSITION'')) ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ESPADON_ADD_POSITION', 'string', NULL, 'core', 'When set, enables the position column in the espadon shipping PDF template, taking priority over the generic PDF_ADD_POSITION setting.', 'Used in a single location in core/modules/expedition/doc/pdf_espadon.modules.php:1375 as the primary check for the position column status, with PDF_ADD_POSITION as fallback when this constant is falsy.', 'Setting this to a truthy value activates the position column specifically for the espadon PDF template. When unset, the column status falls back to the value of PDF_ADD_POSITION.', '0 or unset = falls back to PDF_ADD_POSITION; non-zero = position column enabled for espadon template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_espadon.modules.php:1375|''status'' => getDolGlobalInt(''PDF_ESPADON_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_EXPENSEREPORT_NO_PAYMENT_DETAILS', 'string', NULL, 'core', 'When enabled, suppresses the payment details section in expense report PDFs even when payments exist.', 'Checked at core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:529. The payment details block is only rendered when $sumPayments > 0 AND this constant is not set.', 'Enabling hides payment breakdown information from expense report PDFs. Disabling (leaving unset) shows payment details when payments are present.', 'Truthy = hide payment details in expense report PDF; empty/unset = show payment details when payments exist.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expensereport/doc/pdf_standard_expensereport.modules.php:529|check|if ($sumPayments > 0 && !getDolGlobalString(''PDF_EXPENSEREPORT_NO_PAYMENT_DETAILS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_BACKGROUND_COLOR', 'string', NULL, 'core', 'Sets the RGB background color for the footer area on PDF documents.', 'Checked and read across 6 occurrences in core/lib/pdf.lib.php (:1644, :1645, :1670, :1696, :1697, :1724); the value is parsed via sscanf ''%d, %d, %d'' to extract R, G, B components. No admin UI write is present.', 'Setting this value applies a colored background to the PDF footer region; when absent the footer uses no background fill.', 'RGB string in format ''R, G, B'' (e.g. ''240, 240, 240''); absent/empty = no footer background color.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1644|check|if (getDolGlobalString(''PDF_FOOTER_BACKGROUND_COLOR'')) {", "core/lib/pdf.lib.php:1645|read|[$r, $g, $b] = sscanf($conf->global->PDF_FOOTER_BACKGROUND_COLOR, ''%d, %d, %d'');", "core/lib/pdf.lib.php:1670|check|if (!getDolGlobalString(''PDF_FOOTER_BACKGROUND_COLOR'')) {", "core/lib/pdf.lib.php:1697|read|[$r, $g, $b] = sscanf($conf->global->PDF_FOOTER_BACKGROUND_COLOR, ''%d, %d, %d'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_DISABLE_PAGEBREAK', 'bool', NULL, 'core', 'Disables automatic page breaks within the footer block on PDF documents.', 'Checked at core/lib/pdf.lib.php:1681 and :1685 using strict comparison to integer 1. No admin UI write is present; must be set manually.', 'Setting this to 1 prevents page breaks from being inserted inside the PDF footer block.', '1 = disable page breaks in footer; 0 or absent = page breaks allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1681|check|if (getDolGlobalInt(''PDF_FOOTER_DISABLE_PAGEBREAK'') === 1) {", "core/lib/pdf.lib.php:1685|check|if (getDolGlobalInt(''PDF_FOOTER_DISABLE_PAGEBREAK'') === 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_HIDDEN', 'string', NULL, 'core', 'Hides the footer block entirely on PDF documents.', 'Checked at core/lib/pdf.lib.php:1722; when the integer value is non-zero the footer rendering block is skipped. No admin UI write is present; must be set manually.', 'Setting this to a non-zero value suppresses the footer from appearing on generated PDFs.', 'Non-zero integer = hide footer; 0 or absent = show footer.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1722|check|if (!getDolGlobalInt(''PDF_FOOTER_HIDDEN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_PAGE_NUMBER_X', 'string', NULL, 'core', 'Sets the horizontal position offset (in PDF units) for the page number in the PDF footer.', 'Read at core/lib/pdf.lib.php:1766 via getDolGlobalInt with default 0; used together with PDF_FOOTER_PAGE_NUMBER_Y in a SetXY call to position the page number. No admin UI write is present.', 'Changing this value shifts the page number horizontally within the PDF footer.', 'Integer (PDF units, offset from default position); default = 0 (no offset).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1766|read|$pdf->SetXY($dims[''wk''] - $dims[''rm''] - 18 - getDolGlobalInt(''PDF_FOOTER_PAGE_NUMBER_X'', 0), -$posy - getDolGlobalInt(''PDF_FOOTER_PAGE_NUMBER_Y'', 0));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_PAGE_NUMBER_Y', 'string', NULL, 'core', 'Sets the vertical position offset (in PDF units) for the page number in the PDF footer.', 'Read at core/lib/pdf.lib.php:1766 via getDolGlobalInt with default 0; used together with PDF_FOOTER_PAGE_NUMBER_X in a SetXY call to position the page number. No admin UI write is present.', 'Changing this value shifts the page number vertically within the PDF footer.', 'Integer (PDF units, offset from default position); default = 0 (no offset).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1766|read|$pdf->SetXY($dims[''wk''] - $dims[''rm''] - 18 - getDolGlobalInt(''PDF_FOOTER_PAGE_NUMBER_X'', 0), -$posy - getDolGlobalInt(''PDF_FOOTER_PAGE_NUMBER_Y'', 0));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_TEXT_COLOR', 'string', NULL, 'core', 'Sets the RGB text color for the footer on PDF documents.', 'Checked at core/lib/pdf.lib.php:1606 and read at :1607 using sscanf with format ''%d, %d, %d'' to extract R, G, B components. No admin UI write is present; must be set manually.', 'Setting this value changes the color of footer text on all generated PDFs.', 'RGB string in format ''R, G, B'' (e.g. ''0, 0, 0'' for black); absent/empty = default color used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1606|check|if (getDolGlobalString(''PDF_FOOTER_TEXT_COLOR'')) {", "core/lib/pdf.lib.php:1607|read|[$r, $g, $b] = sscanf(getDolGlobalString(''PDF_FOOTER_TEXT_COLOR''), ''%d, %d, %d'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FOOTER_TOP_MARGIN', 'string', NULL, 'core', 'Sets the top margin (in PDF units) for the footer block on PDF documents.', 'Checked and read across 4 occurrences in core/lib/pdf.lib.php (:1675, :1676, :1729, :1730); the value is cast to float and subtracted from the y-position to determine footer placement.', 'Changing this value adjusts the vertical gap between the document body and the footer on generated PDFs.', 'Numeric value (float, in PDF units); 0 = no margin; absent = default footer position used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1675|check|if (getDolGlobalString(''PDF_FOOTER_TOP_MARGIN'') || getDolGlobalInt(''PDF_FOOTER_TOP_MARGIN'') === 0) {", "core/lib/pdf.lib.php:1676|read|$posy -= (float) getDolGlobalString(''PDF_FOOTER_TOP_MARGIN'');", "core/lib/pdf.lib.php:1729|check|if (getDolGlobalString(''PDF_FOOTER_TOP_MARGIN'') || getDolGlobalInt(''PDF_FOOTER_TOP_MARGIN'') === 0) {", "core/lib/pdf.lib.php:1730|read|$posy -= (float) getDolGlobalString(''PDF_FOOTER_TOP_MARGIN'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_FREETEXT_DISABLE_PAGEBREAK', 'bool', NULL, 'core', 'Disables automatic page breaks within the free text block on PDF documents.', 'Checked across 4 occurrences in core/lib/pdf.lib.php (:1651, :1663, :1703, :1715) using strict comparison to integer 1. No admin UI write is present; must be set manually.', 'Setting this to 1 prevents page breaks from being inserted inside the free text block, keeping it on a single page regardless of length.', '1 = disable page breaks in free text block; 0 or absent = page breaks allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:1651|check|if (getDolGlobalInt(''PDF_FREETEXT_DISABLE_PAGEBREAK'') === 1) {", "core/lib/pdf.lib.php:1663|check|if (getDolGlobalInt(''PDF_FREETEXT_DISABLE_PAGEBREAK'') === 1) {", "core/lib/pdf.lib.php:1703|check|if (getDolGlobalInt(''PDF_FREETEXT_DISABLE_PAGEBREAK'') === 1) {", "core/lib/pdf.lib.php:1715|check|if (getDolGlobalInt(''PDF_FREETEXT_DISABLE_PAGEBREAK'') === 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_HIDE_LINKED_OBJECT_IN_PUBLIC_NOTE', 'bool', NULL, 'core', 'Prevents linked objects from being appended to the public note section of PDFs.', 'Checked in core/lib/pdf.lib.php:3083 alongside a context flag to avoid double-appending. When set, the linked-object block is skipped for the public note.', 'Enabling this omits linked object details from the public note in PDFs; disabling it allows them to be appended.', 'truthy = hide linked objects in public note; empty/not set = append linked objects to public note', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:3083|check|if (empty($object->context[''DolPublicNoteAppendedGetLinkedObjects'']) && !getDolGlobalString(\"PDF_HIDE_LINKED_OBJECT_IN_PUBLIC_NOTE\")) { // Check if already appended before add to a"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_HIDE_PRODUCT_LABEL_IN_SUPPLIER_LINES', 'bool', NULL, 'core', 'Hides the product label in supplier reference lines on PDF documents.', 'Checked at core/lib/pdf.lib.php:2006; when truthy, the product label is suppressed from supplier line rendering. No admin UI write is present; must be set manually.', 'Enabling this removes the product label from supplier reference entries in PDF line item blocks.', 'Truthy string (non-empty) = hide product label in supplier lines; absent/empty = show product label.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2006|check|if (!getDolGlobalString(''PDF_HIDE_PRODUCT_LABEL_IN_SUPPLIER_LINES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_HIDE_PRODUCT_REF_IN_SUPPLIER_LINES', 'bool', NULL, 'core', 'Controls whether and how the product reference is hidden or replaced in supplier document lines on PDFs.', 'Checked in core/lib/pdf.lib.php at lines 2123, 2128, and 2130. When not set, the common case applies (ref shown). Value 1 and value 2 trigger distinct alternate display paths.', 'Setting to 0 or empty shows the product reference (common case). Setting to 1 or 2 activates alternate display modes for supplier line references.', '0 or empty = show product ref (common case); 1 = first alternate mode; 2 = second alternate mode', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2123|check|if (!getDolGlobalString(''PDF_HIDE_PRODUCT_REF_IN_SUPPLIER_LINES'')) {  // Common case", "core/lib/pdf.lib.php:2128|read|} elseif (getDolGlobalInt(''PDF_HIDE_PRODUCT_REF_IN_SUPPLIER_LINES'') == 1) {", "core/lib/pdf.lib.php:2130|read|} elseif (getDolGlobalInt(''PDF_HIDE_PRODUCT_REF_IN_SUPPLIER_LINES'') == 2) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME', 'string', NULL, 'core', 'Controls whether and how the third-party alias is appended to the company name in PDFs.', 'Written in admin/pdf.php:195 and read in core/lib/pdf.lib.php:400-412. Value 2 places the alias on a separate line; any truthy value appends the alias to the name.', 'Changing this value alters how third-party names are displayed in all generated PDFs that include company names.', '0 = do not include alias; 1 = append alias to name; 2 = alias on separate line.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:400|check|if (($includealias || getDolGlobalInt(''PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME'')) && !empty($thirdparty->name_alias)) {", "core/lib/pdf.lib.php:401|check|if (getDolGlobalInt(''PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME'') == 2) {", "admin/pdf.php:195|write|dolibarr_set_const($db, \"PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME\", GETPOST(''PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:447|read|print $form->selectarray(\"PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME\", $arrval, getDolGlobalInt(''PDF_INCLUDE_ALIAS_IN_THIRDPARTY_NAME''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_INVOICE_HIDE_PRICE_EXCL_TAX', 'bool', NULL, 'core', 'Hides the price-excluding-tax column in invoice PDFs when enabled.', 'Read in pdf_sponge.modules.php at line 2807 within the column status map: the excl-tax price column is active only when neither this constant nor PDF_PURCHASE_INVOICE_HIDE_PRICE_EXCL_TAX is truthy. No admin UI write is present.', 'Enabling this removes the excl-tax price column from the relevant invoice PDF layout; disabling restores it.', 'Truthy bool = column hidden; false/unset = column shown (subject also to PDF_PURCHASE_INVOICE_HIDE_PRICE_EXCL_TAX).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_sponge.modules.php:2807|read|''status'' => !getDolGlobalBool(''PDF_INVOICE_HIDE_PRICE_EXCL_TAX'') && !getDolGlobalBool(''PDF_PURCHASE_INVOICE_HIDE_PRICE_EXCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_INVOICE_SHOW_BALANCE_SUMMARY', 'bool', NULL, 'admin', 'Controls whether a balance summary section is shown on invoice PDFs for non-draft invoices.', 'Written in admin/pdf_other.php at lines 162 and 163 (set/del) and displayed as a select at line 615. Checked in pdf_octopus.modules.php at line 1355 and pdf_sponge.modules.php at line 1421, both requiring invoice status > STATUS_DRAFT.', 'Enabling this constant adds a balance summary block to invoice PDFs when the invoice is not in draft status. Disabling it omits the balance summary.', 'Non-zero integer to show balance summary on non-draft invoices; 0 or unset to hide it.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:162|write|dolibarr_set_const($db, \"PDF_INVOICE_SHOW_BALANCE_SUMMARY\", GETPOSTINT(\"PDF_INVOICE_SHOW_BALANCE_SUMMARY\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/facture/doc/pdf_octopus.modules.php:1355|check|if ($object->status > Facture::STATUS_DRAFT && getDolGlobalInt(''PDF_INVOICE_SHOW_BALANCE_SUMMARY'')) {", "core/modules/facture/doc/pdf_sponge.modules.php:1421|check|if ($object->status > Facture::STATUS_DRAFT && getDolGlobalInt(''PDF_INVOICE_SHOW_BALANCE_SUMMARY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_INVOICE_SHOW_PRICE_INCL_TAX', 'bool', NULL, 'admin', 'Controls whether invoice PDFs display prices inclusive of tax.', 'Displayed as a select array in admin/pdf_other.php at line 492. Read in core/modules/facture/doc/pdf_sponge.modules.php at line 2818 via getDolGlobalBool combined with PDF_PURCHASE_INVOICE_SHOW_PRICE_INCL_TAX to set the price display status flag.', 'Enabling this constant causes invoice PDFs to show tax-inclusive prices. Disabling it (or when PDF_PURCHASE_INVOICE_SHOW_PRICE_INCL_TAX is also set) reverts to tax-exclusive display.', 'Truthy/1 = show price incl. tax; falsy/0 or unset = show price excl. tax.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:492|read|print $form->selectarray(\"PDF_INVOICE_SHOW_PRICE_INCL_TAX\", $arrval, getDolGlobalString(''PDF_INVOICE_SHOW_PRICE_INCL_TAX''));", "core/modules/facture/doc/pdf_sponge.modules.php:2818|read|''status'' => getDolGlobalBool(''PDF_INVOICE_SHOW_PRICE_INCL_TAX'') && !getDolGlobalBool(''PDF_PURCHASE_INVOICE_SHOW_PRICE_INCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_INVOICE_SHOW_VAT_ANALYSIS', 'bool', NULL, 'core', 'Controls whether a VAT analysis section is shown on invoice PDFs, overriding the default behavior of showing VAT detail.', 'Configured via admin/pdf_other.php (written at line 158/159, rendered as a select array at line 603). Checked across 10 occurrences in core/lib/pdf.lib.php and invoice PDF modules. The comment at line 915 states: ''by default, we show detail of vat here''.', 'Changing this value toggles whether the VAT analysis breakdown section is included in generated invoice PDFs.', '0 or absent = show VAT detail by default; non-zero = alter VAT analysis display as per selected value.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:915|check|if (!getDolGlobalInt(''PDF_INVOICE_SHOW_VAT_ANALYSIS'')) {\t// by default, we show detail of vat here", "admin/pdf_other.php:158|write|dolibarr_set_const($db, \"PDF_INVOICE_SHOW_VAT_ANALYSIS\", GETPOSTINT(\"PDF_INVOICE_SHOW_VAT_ANALYSIS\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:603|read|print $form->selectarray(\"PDF_INVOICE_SHOW_VAT_ANALYSIS\", $arrval, getDolGlobalInt(''PDF_INVOICE_SHOW_VAT_ANALYSIS''));", "core/modules/facture/doc/pdf_octopus.modules.php:1266|check|if ($object->total_tva != 0 && getDolGlobalInt(''PDF_INVOICE_SHOW_VAT_ANALYSIS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_LOCALTAX1_LABEL_IS_CODE_OR_RATE', 'string', NULL, 'core', 'Controls whether the local tax 1 label in PDF tax summaries shows the tax code, rate, or neither.', 'Checked across 8 occurrences in core/lib/pdf.lib.php and PDF modules (commande, propale). The only documented value is ''nocodenorate'', which suppresses both code and rate from the label. No admin UI write is present.', 'Setting this to ''nocodenorate'' removes the tax code and rate from local tax 1 labels in PDF documents.', '''nocodenorate'' = show neither code nor rate in local tax 1 label; other values or absent = default label behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:838|check|if (getDolGlobalString(''PDF_LOCALTAX1_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/commande/doc/pdf_einstein.modules.php:1022|check|if (getDolGlobalString(''PDF_LOCALTAX1_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/commande/doc/pdf_eratosthene.modules.php:1283|check|if (getDolGlobalString(''PDF_LOCALTAX1_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/propale/doc/pdf_azur.modules.php:1219|check|if (getDolGlobalString(''PDF_LOCALTAX1_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_LOCALTAX2_LABEL_IS_CODE_OR_RATE', 'string', NULL, 'core', 'Controls whether the local tax 2 label in PDF tax summaries shows the tax code, rate, or neither.', 'Checked across 9 occurrences in core/lib/pdf.lib.php and PDF modules (commande, propale). The only documented value is ''nocodenorate'', which suppresses both code and rate from the label. No admin UI write is present.', 'Setting this to ''nocodenorate'' removes the tax code and rate from local tax 2 labels in PDF documents.', '''nocodenorate'' = show neither code nor rate in local tax 2 label; other values or absent = default label behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:875|check|if (getDolGlobalString(''PDF_LOCALTAX2_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/commande/doc/pdf_einstein.modules.php:1058|check|if (getDolGlobalString(''PDF_LOCALTAX2_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/commande/doc/pdf_eratosthene.modules.php:1319|check|if (getDolGlobalString(''PDF_LOCALTAX2_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/propale/doc/pdf_azur.modules.php:1255|check|if (getDolGlobalString(''PDF_LOCALTAX2_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ORDER_HIDE_PRICE_EXCL_TAX', 'bool', NULL, 'core', 'When set, hides the price excluding tax column from the eratosthene order PDF template.', 'Used in a single location in core/modules/commande/doc/pdf_eratosthene.modules.php:2115 where the column status is set to the negation of this constant.', 'Enabling this removes the excl-tax price column from eratosthene order PDFs. Disabling (or leaving unset) shows the column.', 'Empty/unset = price excl. tax column shown; any truthy value = price excl. tax column hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_eratosthene.modules.php:2115|''status'' => !getDolGlobalString(''PDF_ORDER_HIDE_PRICE_EXCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_ORDER_SHOW_PRICE_INCL_TAX', 'bool', NULL, 'core', 'When set, shows the price including tax column in the eratosthene order PDF template.', 'Managed via the admin UI at admin/pdf_other.php as a select array. Used in a single PDF location in core/modules/commande/doc/pdf_eratosthene.modules.php:2126 where the column status is read via getDolGlobalBool.', 'Enabling this adds an incl-tax price column to eratosthene order PDFs. Disabling (or leaving unset) hides that column.', '0 or empty = incl-tax price column hidden; non-zero = incl-tax price column shown.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:370|print $form->selectarray(\"PDF_ORDER_SHOW_PRICE_INCL_TAX\", $arrval, getDolGlobalString(''PDF_ORDER_SHOW_PRICE_INCL_TAX''));", "pdf_eratosthene.modules.php:2126|''status'' => getDolGlobalBool(''PDF_ORDER_SHOW_PRICE_INCL_TAX''),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_PROPAL_HIDE_PRICE_EXCL_TAX', 'bool', NULL, 'core', 'Hides the price excluding tax column on proposal PDF documents generated by the cyan template.', 'Read in pdf_cyan.modules.php:2249 where its negation determines the ''status'' field of the price excl. tax column. When set, the column is disabled. No admin UI write is present.', 'Setting this constant suppresses the price-excluding-tax column in the cyan proposal PDF. Unsetting it keeps the column visible.', 'Truthy = price excl. tax column hidden; falsy or unset = column shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:2249|read|''status'' => !getDolGlobalString(''PDF_PROPAL_HIDE_PRICE_EXCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_PROPAL_SHOW_PRICE_INCL_TAX', 'bool', NULL, 'admin', 'Controls whether proposal PDFs display prices inclusive of tax.', 'Displayed as a select array in admin/pdf_other.php at line 290. Read in core/modules/propale/doc/pdf_cyan.modules.php at line 2260 via getDolGlobalBool to set the ''status'' flag for the price-incl-tax display option.', 'Enabling this constant causes proposal PDFs to show tax-inclusive prices. Disabling it shows prices excluding tax.', 'Truthy/1 = show price incl. tax; falsy/0 or unset = show price excl. tax.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:290|read|print $form->selectarray(\"PDF_PROPAL_SHOW_PRICE_INCL_TAX\", $arrval, getDolGlobalString(''PDF_PROPAL_SHOW_PRICE_INCL_TAX''));", "core/modules/propale/doc/pdf_cyan.modules.php:2260|read|''status'' => getDolGlobalBool(''PDF_PROPAL_SHOW_PRICE_INCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_PURCHASE_INVOICE_HIDE_PRICE_EXCL_TAX', 'bool', NULL, 'core', 'Hides the price-excluding-tax column in purchase invoice PDFs when enabled.', 'Read in pdf_sponge.modules.php at line 2807 together with PDF_INVOICE_HIDE_PRICE_EXCL_TAX: the column is shown only when both flags are falsy. No admin UI write is present.', 'Enabling this removes the excl-tax price column from purchase invoice PDFs; the effect is combined with PDF_INVOICE_HIDE_PRICE_EXCL_TAX.', 'Truthy bool = column hidden; false/unset = column shown (combined with PDF_INVOICE_HIDE_PRICE_EXCL_TAX).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_sponge.modules.php:2807|read|''status'' => !getDolGlobalBool(''PDF_INVOICE_HIDE_PRICE_EXCL_TAX'') && !getDolGlobalBool(''PDF_PURCHASE_INVOICE_HIDE_PRICE_EXCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_PURCHASE_INVOICE_SHOW_PRICE_INCL_TAX', 'bool', NULL, 'core', 'Shows the price-including-tax column specifically for purchase invoices in PDFs.', 'Read in pdf_sponge.modules.php at line 2818: the incl-tax column status is true only when PDF_INVOICE_SHOW_PRICE_INCL_TAX is truthy AND this constant is NOT truthy. No admin UI write is present.', 'Enabling this suppresses the incl-tax column for purchase invoices even when the global incl-tax flag is on; disabling defers to PDF_INVOICE_SHOW_PRICE_INCL_TAX.', 'Truthy bool = incl-tax column suppressed for purchase invoices; false/unset = follows PDF_INVOICE_SHOW_PRICE_INCL_TAX.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_sponge.modules.php:2818|read|''status'' => getDolGlobalBool(''PDF_INVOICE_SHOW_PRICE_INCL_TAX'') && !getDolGlobalBool(''PDF_PURCHASE_INVOICE_SHOW_PRICE_INCL_TAX''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION', 'string', NULL, 'core', 'Enables PDF encryption/security when generating PDF documents.', 'Checked in admin/pdf.php:294 and core/lib/pdf.lib.php:199; when set, the PDF generation path applies encryption settings.', 'Enabling activates PDF encryption; further encryption parameters (rights, passwords, strength) are then read from related constants.', 'Truthy value to enable PDF encryption; absent or falsy to generate unencrypted PDFs.', 0, 0, 'admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:294|check|if (getDolGlobalString(''PDF_SECURITY_ENCRYPTION'')) {", "core/lib/pdf.lib.php:199|check|if (getDolGlobalString(''PDF_SECURITY_ENCRYPTION'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION_OWNERPASS', 'string', NULL, 'core', 'Stores the owner (permissions) password for encrypted PDF documents.', 'Read in core/lib/pdf.lib.php:219; when absent, null is used, meaning no owner password is set.', 'Setting an owner password restricts modification of PDF permissions without that password.', 'A plain-text password string; null/absent means no owner password.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:219|read|$pdfownerpass = (getDolGlobalString(''PDF_SECURITY_ENCRYPTION_OWNERPASS'') ? getDolGlobalString(''PDF_SECURITY_ENCRYPTION_OWNERPASS'') : null);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION_PUBKEYS', 'string', NULL, 'core', 'Stores a JSON-encoded array of public keys for certificate-based PDF encryption.', 'Read in core/lib/pdf.lib.php:226; when absent, null is used (no certificate-based encryption). The comment notes ''Json format in llx_const''.', 'Setting this value enables certificate-based PDF encryption using the provided public keys; absent or null disables it.', 'JSON-encoded array of public key strings. Default: null (disabled).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:226|read|$pubkeys = (getDolGlobalString(''PDF_SECURITY_ENCRYPTION_PUBKEYS'') ? json_decode(getDolGlobalString(''PDF_SECURITY_ENCRYPTION_PUBKEYS''), true) : null); // Json format in llx_const"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION_RIGHTS', 'string', NULL, 'core', 'Stores a JSON-encoded array of allowed operations for encrypted PDF documents.', 'Read in core/lib/pdf.lib.php:213 with a fallback of array(''modify'', ''copy'') when absent. The value is decoded from JSON stored in llx_const.', 'Changing this value alters which operations (e.g. modify, copy, print) are permitted in encrypted PDFs; removing it restores the default of modify and copy.', 'JSON-encoded array of permission strings, e.g. ''["modify","copy"]''. Default: array(''modify'', ''copy'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:213|read|$pdfrights = (getDolGlobalString(''PDF_SECURITY_ENCRYPTION_RIGHTS'') ? json_decode(getDolGlobalString(''PDF_SECURITY_ENCRYPTION_RIGHTS''), true) : array(''modify'', ''copy'')); // Json for"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION_STRENGTH', 'string', NULL, 'core', 'Sets the encryption strength level for PDF security.', 'Read in core/lib/pdf.lib.php:222 with a default of 0 via getDolGlobalInt.', 'Changing this value alters the encryption algorithm strength applied to generated PDFs.', 'Integer encryption strength level. Default: 0.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:222|read|$encstrength = getDolGlobalInt(''PDF_SECURITY_ENCRYPTION_STRENGTH'', 0);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SECURITY_ENCRYPTION_USERPASS', 'string', NULL, 'core', 'Stores the user (open) password for encrypted PDF documents.', 'Read in core/lib/pdf.lib.php:216 and passed to the PDF encryption routine.', 'Setting this value requires recipients to enter this password to open encrypted PDFs.', 'A plain-text password string. Empty string means no user password required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:216|read|$pdfuserpass = getDolGlobalString(''PDF_SECURITY_ENCRYPTION_USERPASS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SHOW_EMAIL_AFTER_USER_CONTACT', 'bool', NULL, 'core', 'Shows the contact user''s email address in parentheses after their name in PDF issuer blocks.', 'Used in 60 occurrences across all PDF module files. The email is appended in the carac_emetteur string when this constant is set and the user email is available. Works in combination with PDF_SHOW_PHONE_AFTER_USER_CONTACT.', 'Setting this constant adds the contact user''s email address to the issuer block in all PDF documents.', 'Non-zero = email shown after contact name; 0 or unset = email not shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:754|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_PHONE_AFTER_USER_CONTACT'') || getDolGlobalInt(''PDF_SHOW_EMAIL_AFTER_USER_CONTACT'')) ? '' ('' : '''';", "core/modules/contract/doc/pdf_strato.modules.php:757|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_EMAIL_AFTER_USER_CONTACT'') && !empty($object->user->email)) ? $object->user->email : '''';", "core/modules/expedition/doc/pdf_rouget.modules.php:1071|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_EMAIL_AFTER_USER_CONTACT'') && !empty($object->user->email)) ? $object->user->email : '''';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SHOW_LINK_TO_ONLINE_PAYMENT', 'bool', NULL, 'core', 'Controls whether a link to an online payment page is included in generated invoice PDFs.', 'Set via admin/pdf.php using dolibarr_set_const. The value is read by pdf_octopus and pdf_sponge modules to conditionally insert the payment link. Configurable through the admin UI (admin/pdf.php).', 'When enabled, generated invoice PDFs include an online payment link; when disabled the link is omitted.', 'Yes/No (selectyesno); truthy = show link, falsy = hide link.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf.php:187|write|dolibarr_set_const($db, \"PDF_SHOW_LINK_TO_ONLINE_PAYMENT\", GETPOST(''PDF_SHOW_LINK_TO_ONLINE_PAYMENT'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:671|read|print $form->selectyesno(''PDF_SHOW_LINK_TO_ONLINE_PAYMENT'', getDolGlobalInt(''PDF_SHOW_LINK_TO_ONLINE_PAYMENT''), 1);", "pdf_octopus.modules.php:1527|check|if (getDolGlobalString(''PDF_SHOW_LINK_TO_ONLINE_PAYMENT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SHOW_PHONE_AFTER_USER_CONTACT', 'bool', NULL, 'core', 'Shows the contact user''s phone number in parentheses after their name in PDF issuer blocks.', 'Used in 60 occurrences across all PDF module files. The phone is appended in the carac_emetteur string when this constant is set and office_phone is available. Works in combination with PDF_SHOW_EMAIL_AFTER_USER_CONTACT.', 'Setting this constant adds the contact user''s phone number to the issuer block in all PDF documents.', 'Non-zero = phone shown after contact name; 0 or unset = phone not shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/contract/doc/pdf_strato.modules.php:754|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_PHONE_AFTER_USER_CONTACT'') || getDolGlobalInt(''PDF_SHOW_EMAIL_AFTER_USER_CONTACT'')) ? '' ('' : '''';", "core/modules/contract/doc/pdf_strato.modules.php:755|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_PHONE_AFTER_USER_CONTACT'') && !empty($object->user->office_phone)) ? $object->user->office_phone : '''';", "core/modules/expedition/doc/pdf_rouget.modules.php:1069|read|$carac_emetteur .= (getDolGlobalInt(''PDF_SHOW_PHONE_AFTER_USER_CONTACT'') && !empty($object->user->office_phone)) ? $object->user->office_phone : '''';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SHOW_PROJECT', 'bool', NULL, 'core', 'Controls whether the linked project reference is shown on generated PDF documents.', 'Written via admin/pdf.php:130 (set when user selects ''showprojectref'') and read at admin/pdf.php:547 in combination with PDF_SHOW_PROJECT_TITLE: $showprojectref = !getDolGlobalString(''PDF_SHOW_PROJECT'') ? (!getDolGlobalString(''PDF_SHOW_PROJECT_TITLE'') ? ''no'' : ''showprojectlabel'') : ''showprojectref''. Checked across 21 occurrences in PDF modules.', 'Setting this causes PDF documents to display the linked project reference number; it takes precedence over PDF_SHOW_PROJECT_TITLE.', '0 or unset = project reference not shown; 1 = project reference shown.', 0, 0, 'admin/pdf.php|admin/pdf.php|admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:130|write|dolibarr_set_const($db, \"PDF_SHOW_PROJECT\", GETPOST(\"PDF_SHOW_PROJECT_REF_OR_LABEL\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:547|read|$showprojectref = !getDolGlobalString(''PDF_SHOW_PROJECT'') ? (!getDolGlobalString(''PDF_SHOW_PROJECT_TITLE'') ? ''no'' : ''showprojectlabel'') : ''showprojectref'';", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:830|check|if (getDolGlobalString(''PDF_SHOW_PROJECT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SHOW_PROJECT_TITLE', 'bool', NULL, 'core', 'Controls whether the linked project label is shown on generated PDF documents.', 'Written via admin/pdf.php:134 (set when user selects ''showprojectlabel'') and read at admin/pdf.php:547 in combination with PDF_SHOW_PROJECT: $showprojectref = !getDolGlobalString(''PDF_SHOW_PROJECT'') ? (!getDolGlobalString(''PDF_SHOW_PROJECT_TITLE'') ? ''no'' : ''showprojectlabel'') : ''showprojectref''. Checked across 22 occurrences in PDF modules.', 'Setting this causes PDF documents to display the linked project label; it takes effect only when PDF_SHOW_PROJECT is not set.', '0 or unset = project label not shown; 1 = project label shown (when PDF_SHOW_PROJECT is unset).', 0, 0, 'admin/pdf.php|admin/pdf.php|admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/pdf.php:134|write|dolibarr_set_const($db, \"PDF_SHOW_PROJECT_TITLE\", GETPOST(\"PDF_SHOW_PROJECT_REF_OR_LABEL\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:547|read|$showprojectref = !getDolGlobalString(''PDF_SHOW_PROJECT'') ? (!getDolGlobalString(''PDF_SHOW_PROJECT_TITLE'') ? ''no'' : ''showprojectlabel'') : ''showprojectref'';", "core/modules/asset/doc/pdf_standard_asset.modules.php:890|check|if (getDolGlobalString(''PDF_SHOW_PROJECT_TITLE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SPONGE_ADD_POSITION', 'string', NULL, 'core', 'Enables display of the position (line number) column in PDF invoices generated by the Sponge/Octopus modules.', 'Read by both pdf_octopus (line 2424) and pdf_sponge (line 2659) when building the column status map. Falls back to PDF_ADD_POSITION if not set. No admin UI write is present.', 'Enabling this causes the position column to appear in generated invoice PDFs; disabling causes the fallback PDF_ADD_POSITION to be evaluated instead.', 'Truthy integer = position column enabled; 0 or unset = falls back to PDF_ADD_POSITION.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_octopus.modules.php:2424|read|''status'' => getDolGlobalInt(''PDF_SPONGE_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),", "pdf_sponge.modules.php:2659|read|''status'' => getDolGlobalInt(''PDF_SPONGE_ADD_POSITION'') ? true : (getDolGlobalInt(''PDF_ADD_POSITION'') ? true : false),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_SWISS_QRCODE_USE_OWNER_OF_ACCOUNT_AS_CREDITOR', 'bool', NULL, 'core', 'Uses the bank account owner as the creditor in the Swiss QR-code payment slip on invoice PDFs instead of the company.', 'Checked at core/class/commoninvoice.class.php:2356 when a bank account is linked to the invoice. No admin UI; hidden setting.', 'Enabling this changes the creditor field in the Swiss QR payment code to reflect the bank account owner rather than the default company.', '0 or empty = company is creditor in Swiss QR code; non-empty = bank account owner is used as creditor', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/commoninvoice.class.php:2356|check|if ($bankaccount->id > 0 && getDolGlobalString(''PDF_SWISS_QRCODE_USE_OWNER_OF_ACCOUNT_AS_CREDITOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_USE_A', 'bool', NULL, 'admin', 'Selects the PDF/A compliance level (PDF/A-1 or PDF/A-3) for generated PDF documents.', 'Written in admin/pdf.php:198 and read in admin/pdf.php:678 and core/lib/pdf.lib.php:190 with inline comment ''// PDF/A-1 ou PDF/A-3''. Default is 0 (no PDF/A).', 'Setting a non-zero value enables PDF/A archival compliance mode; setting to 0 disables it.', 'Integer: 0 = no PDF/A compliance (default); 1 = PDF/A-1; 3 = PDF/A-3.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:678|read|$pdfa = getDolGlobalInt(''PDF_USE_A'', 0); \t// PDF/A-1 ou PDF/A-3", "core/lib/pdf.lib.php:190|read|$pdfa = getDolGlobalInt(''PDF_USE_A'', 0); \t// PDF/A-1 ou PDF/A-3", "admin/pdf.php:198|write|dolibarr_set_const($db, \"PDF_USE_A\", GETPOST(''PDF_USE_A'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_USE_ALSO_LANGUAGE_CODE', 'bool', NULL, 'core', 'Specifies a secondary language code to use when generating PDFs, e.g. for translating third-party names.', 'Configured via admin/pdf.php. Read in 78 occurrences across many modules. Comments in core/class/commonobject.class.php:6577, :6646, :7281 describe it as used for the name of a thirdparty when a secondary language is needed in PDFs.', 'When set, PDF generation uses a second language (e.g. for bilingual PDFs or when the third-party''s preferred language differs from the system default).', 'Language code string (e.g. ''de_DE'') or empty/unset to use only the default language', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:6577  *  Used for example when PDF_USE_ALSO_LANGUAGE_CODE is set to a language for the name of a thirdparty.", "admin/pdf.php:180|write|dolibarr_set_const($db, \"PDF_USE_ALSO_LANGUAGE_CODE\", GETPOST(''PDF_USE_ALSO_LANGUAGE_CODE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:216|check|if (getDolGlobalString(''PDF_USE_ALSO_LANGUAGE_CODE'') && $outputlangs->defaultlang != getDolGlobalString(''PDF_USE_ALSO_LANGUAGE_CODE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PDF_VAT_LABEL_IS_CODE_OR_RATE', 'string', NULL, 'core', 'Controls whether the VAT label in PDF tax summaries shows the rate only, code only, or neither.', 'Checked across 12 occurrences in core/lib/pdf.lib.php and PDF modules (commande, propale). Documented values are ''rateonly'', ''codeonly'', and ''nocodenorate'' as seen at lines 931, 933, 935. No admin UI write is present.', 'Setting this value changes how VAT is identified in tax summary labels across all PDF document types.', '''rateonly'' = show rate only; ''codeonly'' = show code only; ''nocodenorate'' = show neither code nor rate; absent = show both code and rate.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:931|check|if (getDolGlobalString(''PDF_VAT_LABEL_IS_CODE_OR_RATE'') == ''rateonly'') {", "core/lib/pdf.lib.php:933|read|} elseif (getDolGlobalString(''PDF_VAT_LABEL_IS_CODE_OR_RATE'') == ''codeonly'') {", "core/lib/pdf.lib.php:935|read|} elseif (getDolGlobalString(''PDF_VAT_LABEL_IS_CODE_OR_RATE'') == ''nocodenorate'') {", "core/modules/commande/doc/pdf_einstein.modules.php:1089|check|if (getDolGlobalString(''PDF_VAT_LABEL_IS_CODE_OR_RATE'') == ''rateonly'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('POSITION_ADDON_PDF', 'string', NULL, 'hrm', 'Specifies the PDF addon module used to generate PDF documents for HRM position records.', 'Read at hrm/class/position.class.php lines 1102 and 1103; if the constant is set, its value is used as the PDF model name for generating position documents.', 'Changing this value switches the PDF template used when generating HRM position documents. Clearing it disables PDF generation via this constant.', 'String; value equals the name of the PDF addon module to use.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/position.class.php:1102|read|} elseif (getDolGlobalString(''POSITION_ADDON_PDF'')) {", "hrm/class/position.class.php:1103|read|$modele = getDolGlobalString(''POSITION_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_ADDDAYS', 'string', NULL, 'admin', 'Number of days added to the current date to compute the execution date for direct debit orders.', 'Set via admin/prelevement.php:115 and displayed as an input field at :226. Defaulted to 0 at :224 when unset. Read as an integer at compta/prelevement/create.php:330 and stored in $delayindays.', 'Increasing this value delays the execution date of direct debit orders by the specified number of days.', 'Integer number of days (default 0 = no additional delay).', 0, 0, 'admin/prelevement.php|admin/prelevement.php|admin/prelevement.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/prelevement.php:223|check|if (!getDolGlobalString(''PRELEVEMENT_ADDDAYS'')) {", "admin/prelevement.php:224|write|$conf->global->PRELEVEMENT_ADDDAYS = 0;", "admin/prelevement.php:226|read|print ''<input type=\"text\" name=\"PRELEVEMENT_ADDDAYS\" value=\"''.getDolGlobalString(''PRELEVEMENT_ADDDAYS'').''\"  class=\"width50\"></td>'';", "compta/prelevement/create.php:330|read|$delayindays = getDolGlobalInt(''PRELEVEMENT_ADDDAYS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_BIC', 'string', NULL, 'admin', 'Stores the BIC/SWIFT code for the bank used in SEPA direct debit and bank transfer operations.', 'Written in admin/prelevement.php:83 and admin/paymentbybanktransfer.php:83 via dolibarr_set_const, sourced from $account->bic.', 'Changing this value updates the BIC code in generated SEPA files; an incorrect BIC will cause bank rejection.', 'String BIC/SWIFT code.', 0, 0, 'admin/prelevement.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"PRELEVEMENT_BIC\", $account->bic,''chaine'',0,'''',$conf->entity);", "$res = dolibarr_set_const($db, \"PRELEVEMENT_BIC\", $account->bic,''chaine'',0,'''',$conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_CODE_BANQUE', 'string', NULL, 'compta', 'Stores the bank code used in direct debit file generation (now deprecated and expected to be empty).', 'Written by admin/prelevement.php:73 and admin/paymentbybanktransfer.php:73 from the bank account''s code_banque. The comment at compta/prelevement/create.php:145 explicitly states this should be empty as it is no longer used.', 'This constant is a legacy field; according to the source comment it should be empty and is no longer used in modern direct debit file generation.', '// getDolGlobalString(''PRELEVEMENT_CODE_BANQUE'') and getDolGlobalString(''PRELEVEMENT_CODE_GUICHET'') should be empty (we don''t use them anymore)', 0, 0, 'admin/prelevement.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/create.php:145  // getDolGlobalString(''PRELEVEMENT_CODE_BANQUE'') and getDolGlobalString(''PRELEVEMENT_CODE_GUICHET'') should be empty (we don''t use them anymore)", "admin/prelevement.php:73|write|$res = dolibarr_set_const($db, \"PRELEVEMENT_CODE_BANQUE\", $account->code_banque,''chaine'',0,'''',$conf->entity);", "compta/prelevement/create.php:146|read|$result = $bprev->create(getDolGlobalString(''PRELEVEMENT_CODE_BANQUE''), getDolGlobalString(''PRELEVEMENT_CODE_GUICHET''), $mode, $format, ...);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_CODE_GUICHET', 'string', NULL, 'compta', 'Stores the branch/counter code used in direct debit file generation (now deprecated and expected to be empty).', 'Written by admin/prelevement.php:75 and admin/paymentbybanktransfer.php:75 from the bank account''s code_guichet. The comment at compta/prelevement/create.php:145 explicitly states this should be empty as it is no longer used.', 'This constant is a legacy field; according to the source comment it should be empty and is no longer used in modern direct debit file generation.', '// getDolGlobalString(''PRELEVEMENT_CODE_BANQUE'') and getDolGlobalString(''PRELEVEMENT_CODE_GUICHET'') should be empty (we don''t use them anymore)', 0, 0, 'admin/prelevement.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/create.php:145  // getDolGlobalString(''PRELEVEMENT_CODE_BANQUE'') and getDolGlobalString(''PRELEVEMENT_CODE_GUICHET'') should be empty (we don''t use them anymore)", "admin/prelevement.php:75|write|$res = dolibarr_set_const($db, \"PRELEVEMENT_CODE_GUICHET\", $account->code_guichet,''chaine'',0,'''',$conf->entity);", "compta/prelevement/create.php:146|read|$result = $bprev->create(getDolGlobalString(''PRELEVEMENT_CODE_BANQUE''), getDolGlobalString(''PRELEVEMENT_CODE_GUICHET''), $mode, $format, ...);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_END_TO_END', 'string', NULL, 'compta', 'Sets a custom static EndToEndId value in SEPA direct debit XML, overriding the auto-generated invoice-based identifier.', 'When non-empty, bonprelevement.class.php:2426 inserts this value as <EndToEndId> for debit entries instead of the auto-generated ''DD-<ref>'' pattern; similarly bonprelevement.class.php:2487 for credit transfer (''CT-<ref>'' fallback). Configured via admin/prelevement.php and admin/paymentbybanktransfer.php.', 'Setting a non-empty value replaces the per-invoice EndToEndId in SEPA XML with this fixed string; leaving it empty causes the system to generate unique IDs from invoice references.', 'Non-empty string=fixed EndToEndId used in SEPA XML, empty=auto-generated ''DD-<ref>'' or ''CT-<ref>''', 0, 0, 'admin/prelevement.php|admin/paymentbybanktransfer.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2426|read|$XML_DEBITOR .= ''\t\t\t\t\t<EndToEndId>'' . ((getDolGlobalString(''PRELEVEMENT_END_TO_END'') != \"\") ? $conf->global->PRELEVEMENT_END_TO_END : (''DD-'' . dol_trunc($row_idfac . ''-'' . $row_ref", "compta/prelevement/class/bonprelevement.class.php:2487|read|$XML_CREDITOR .= ''\t\t\t\t\t<EndToEndId>'' . ((getDolGlobalString(''PRELEVEMENT_END_TO_END'') != \"\") ? getDolGlobalString(\"PRELEVEMENT_END_TO_END\") : (''CT-'' . dol_trunc($row_idfac . ''-'' .", "admin/prelevement.php:208|read|print ''<input type=\"text\" name=\"PRELEVEMENT_END_TO_END\" value=\"''.getDolGlobalString(''PRELEVEMENT_END_TO_END'').''\" class=\"width100\"></td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_IBAN', 'string', NULL, 'admin', 'Stores the IBAN for the bank account used in SEPA direct debit and bank transfer operations.', 'Written in admin/prelevement.php:81 and admin/paymentbybanktransfer.php:81 via dolibarr_set_const, sourced from $account->iban.', 'Changing this value updates the IBAN included in generated SEPA files; an incorrect IBAN will cause bank rejection.', 'String IBAN value.', 0, 0, 'admin/prelevement.php|admin/paymentbybanktransfer.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"PRELEVEMENT_IBAN\", $account->iban,''chaine'',0,'''',$conf->entity);", "$res = dolibarr_set_const($db, \"PRELEVEMENT_IBAN\", $account->iban,''chaine'',0,'''',$conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_ICS', 'string', NULL, 'core', 'Stores the Creditor Identifier (ICS) used in SEPA direct-debit mandate documents and standing-order processing.', 'Configured via admin/prelevement.php (write at line 93, displayed at line 189). It is also read in core/modules/bank/doc/pdf_sepamandate.modules.php:280 to populate the ICS field of generated SEPA mandate PDFs when the object-level ICS is empty.', 'Removing or changing this value affects the ICS printed on SEPA mandate PDFs and potentially on direct-debit file generation; an absent value leaves the ICS field blank.', 'Any valid SEPA Creditor Identifier string.', 0, 0, 'admin/prelevement.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/prelevement.php:189|read|print ''<input type=\"text\" name=\"PRELEVEMENT_ICS\" value=\"''.$conf->global->PRELEVEMENT_ICS.''\"", "core/modules/bank/doc/pdf_sepamandate.modules.php:279|check|if (empty($ics) && getDolGlobalString(''PRELEVEMENT_ICS'')) {", "core/lib/prelevement.lib.php:111  //if (empty($conf->global->PRELEVEMENT_ICS)) return -1;", "core/lib/prelevement.lib.php:119  //if (empty($conf->global->PRELEVEMENT_ICS)) return -1;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_ID_BANKACCOUNT', 'string', NULL, 'compta', 'Stores the ID of the bank account used for direct debit (prélèvement) operations.', 'Configured via admin/prelevement.php. Read in compta/prelevement/class/bonprelevement.class.php at lines :1121, :1896, :2662 to determine the bank account for non-bank-transfer (direct debit) operations. core/lib/prelevement.lib.php:116 checks for its presence. 16 occurrences across admin and core files.', 'Without this constant set, direct debit order generation will fail or warn (checked in core/lib/prelevement.lib.php:116); the value must reference a valid current bank account.', 'Integer: ID of the bank account (compte courant) to use for direct debits; empty = no default account set', 0, 0, 'admin/prelevement.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/prelevement.php:68|write|$res = dolibarr_set_const($db, \"PRELEVEMENT_ID_BANKACCOUNT\", $id, ''chaine'', 0, '''', $conf->entity);", "compta/prelevement/class/bonprelevement.class.php:1121|read|$fk_bank_account = ($type == ''bank-transfer'' ? getDolGlobalInt(''PAYMENTBYBANKTRANSFER_ID_BANKACCOUNT'') : getDolGlobalInt(''PRELEVEMENT_ID_BANKACCOUNT''));", "core/lib/prelevement.lib.php:116|check|if (!getDolGlobalString(''PRELEVEMENT_ID_BANKACCOUNT'')) {"]', 'high', NULL);
