INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_SEPA_SHOW_REQUESTS', 'bool', NULL, 'core', 'Controls whether SEPA direct debit request details are shown for non-bank-transfer, non-salary payment types.', 'When enabled, the direct debit request view is displayed for payment objects that are neither bank-transfer nor salary type. Checked in core/lib/prelevement.lib.php:56.', 'Disabling hides SEPA request details in the direct debit UI for those payment object types.', 'Truthy value to enable display; absent or falsy to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/prelevement.lib.php:56|check|if (getDolGlobalString(''PRELEVEMENT_SEPA_SHOW_REQUESTS'') && $object->type != ''bank-transfer'' && $object->type != ''salary'') {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_USER', 'string', NULL, 'admin', 'Stores the Dolibarr user ID responsible for generating direct debit (prelevement) files.', 'Set via admin/prelevement.php and displayed as a user selector. Checked in core/lib/prelevement.lib.php:120 to block direct debit file generation if absent.', 'If unset, direct debit file generation is blocked; the assigned user carries responsibility for direct debit operations.', 'A valid Dolibarr user ID (integer stored as string). Empty string means no user assigned.', 0, 0, 'admin/prelevement.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/prelevement.php:97|write|$res = dolibarr_set_const($db, \"PRELEVEMENT_USER\", GETPOST(\"PRELEVEMENT_USER\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/prelevement.lib.php:120|check|if (!getDolGlobalString(''PRELEVEMENT_USER'')) {", "admin/prelevement.php:198|read|print $form->select_dolusers(getDolGlobalInt(''PRELEVEMENT_USER''), ''PRELEVEMENT_USER'', 1, null, 0, '''', '''', ''0'', 0, 0, '''', 0, '''', ''minwidth200 maxwidth500'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRELEVEMENT_USTRD', 'string', NULL, 'admin', 'Sets a custom unstructured remittance information (Ustrd) string in SEPA direct debit XML.', 'When non-empty, bonprelevement.class.php:2475 inserts this value as <Ustrd> instead of the auto-generated reference+comment string. Configured via admin/prelevement.php (lines 109 and 217).', 'Setting a non-empty value replaces the per-invoice remittance information in SEPA direct debit XML with this fixed string; leaving it empty causes the system to generate the Ustrd from the invoice reference and comment.', 'Non-empty string=fixed Ustrd used, empty=auto-generated from invoice ref and comment', 0, 0, 'admin/prelevement.php|admin/prelevement.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/prelevement.php:109|write|$res = dolibarr_set_const($db, \"PRELEVEMENT_USTRD\", GETPOST(\"PRELEVEMENT_USTRD\"), ''chaine'', 0, '''', $conf->entity);", "compta/prelevement/class/bonprelevement.class.php:2475|read|$XML_DEBITOR .= ''\t\t\t\t\t<Ustrd>'' . getDolGlobalString(''PRELEVEMENT_USTRD'', dolEscapeXML(dol_trunc(dol_string_nospecial(dol_string_unaccent($row_ref . ($row_comment ? '' - '' . $row_com", "admin/prelevement.php:217|read|print ''<input type=\"text\" name=\"PRELEVEMENT_USTRD\" value=\"''.getDolGlobalString(''PRELEVEMENT_USTRD'').''\" class=\"width100\"></td>'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PREVIEW_PICTO_ON_LEFT_OF_NAME', 'string', NULL, 'core', 'Moves the file-preview icon to the left of the filename in file listings when enabled.', 'Checked in core/class/html.formfile.class.php at lines 987 and 1012 to control icon placement relative to the filename. No admin UI write is present.', 'When set, the preview icon appears to the left of the filename; when not set, it appears to the right or in the default position.', 'Truthy integer (e.g. 1) to place preview icon on the left; 0 or empty for default placement.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formfile.class.php:987|check|if (getDolGlobalInt(''PREVIEW_PICTO_ON_LEFT_OF_NAME'')) {", "core/class/html.formfile.class.php:1012|check|if (!getDolGlobalInt(''PREVIEW_PICTO_ON_LEFT_OF_NAME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTING_GCP_DEFAULT', 'string', NULL, 'core', 'Stores the ID of the default Google Cloud Print printer to use for print jobs.', 'Used in core/modules/printing/printgcp.modules.php in three locations: line 245 to mark a printer as selected in the list, line 370 to check if a default is configured, and line 371 to assign the printer ID for job submission.', 'Setting this to a valid GCP printer ID causes print jobs to be sent to that printer by default. Clearing it requires the user to select a printer each time.', 'Any non-empty string matching a GCP printer ID = default printer; empty/unset = no default printer configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["printgcp.modules.php:245|if (getDolGlobalString(''PRINTING_GCP_DEFAULT'') == $printer_det[''id'']) {", "printgcp.modules.php:370|if (getDolGlobalString(''PRINTING_GCP_DEFAULT'')) {", "printgcp.modules.php:371|$printer_id = getDolGlobalString(''PRINTING_GCP_DEFAULT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_HOST', 'string', NULL, 'core', 'Specifies the hostname or IP address of the IPP (Internet Printing Protocol) print server.', 'Read once in core/modules/printing/printipp.modules.php at line 100, assigned to $this->host for use by the PrintIPP printing module.', 'Setting this constant to a valid host enables the PrintIPP module to connect to the print server. If unset, the host is empty and printing will fail.', 'Hostname or IP address string of the IPP print server.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:100|read|$this->host = getDolGlobalString(''PRINTIPP_HOST'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_PASSWORD', 'string', NULL, 'core', 'Specifies the password for authenticating with the IPP print server.', 'Read once in core/modules/printing/printipp.modules.php at line 103, assigned to $this->password for use by the PrintIPP printing module.', 'Setting this constant provides the password credential for IPP authentication. If unset, no password is submitted to the print server.', 'Password string for IPP server authentication.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:103|read|$this->password = getDolGlobalString(''PRINTIPP_PASSWORD'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_PORT', 'string', NULL, 'core', 'Specifies the TCP port of the IPP print server.', 'Read once in core/modules/printing/printipp.modules.php at line 101, assigned to $this->port for use by the PrintIPP printing module.', 'Setting this constant to the correct port allows the PrintIPP module to connect to the print server on the right port. If unset, the port is empty and connection will fail.', 'TCP port number string for the IPP print server (typically 631).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:101|read|$this->port = getDolGlobalString(''PRINTIPP_PORT'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_SSL', 'string', NULL, 'core', 'Enables SSL/TLS for the connection to the IPP print server.', 'Read once in core/modules/printing/printipp.modules.php at line 104 using getDolGlobalInt, assigned to $this->ssl for use by the PrintIPP printing module.', 'Setting this constant to a non-zero integer enables SSL for the IPP connection. If unset or zero, SSL is not used.', 'Non-zero integer to enable SSL; 0 or unset to disable SSL.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:104|read|$this->ssl = getDolGlobalInt(''PRINTIPP_SSL'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_URI_DEFAULT', 'string', NULL, 'core', 'Specifies the default printer URI used by the PrintIPP module when no specific printer is selected.', 'Checked and read in core/modules/printing/printipp.modules.php at lines 153, 154, 155, and 224. When set, the module uses this URI as the default printer and logs it; it is also compared against available printer values in the selection UI at line 224.', 'Setting this constant causes the PrintIPP module to route print jobs to the specified printer URI by default. If unset, no default printer is pre-selected.', 'A URI string identifying the default IPP printer (e.g. ''ipp://printserver/printers/myprinter'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:153|check|if (getDolGlobalString(''PRINTIPP_URI_DEFAULT'')) {", "core/modules/printing/printipp.modules.php:154|read|dol_syslog(\"Will use default printer conf->global->PRINTIPP_URI_DEFAULT = \".getDolGlobalString(''PRINTIPP_URI_DEFAULT''));", "core/modules/printing/printipp.modules.php:155|read|$ipp->setPrinterURI(getDolGlobalString(''PRINTIPP_URI_DEFAULT''));", "core/modules/printing/printipp.modules.php:224|check|if (getDolGlobalString(''PRINTIPP_URI_DEFAULT'') == $value) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRINTIPP_USER', 'string', NULL, 'core', 'Specifies the username for authenticating with the IPP print server.', 'Read once in core/modules/printing/printipp.modules.php at line 102, assigned to $this->user for use by the PrintIPP printing module.', 'Setting this constant provides the username credential for IPP authentication. If unset, no username is submitted to the print server.', 'Username string for IPP server authentication.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/printing/printipp.modules.php:102|read|$this->user = getDolGlobalString(''PRINTIPP_USER'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCTBATCH_LOT_ADDON', 'string', NULL, 'product', 'Specifies the lot numbering add-on module for batch-tracked products, e.g. ''mod_lot_advanced''.', 'Configurable via the admin UI at product/admin/product_lot.php (written at lines 97 and 103, checked at line 254). Read in product/card.php at lines 1559, 1575, 2173, 2204, and 2717 to conditionally enable advanced lot mask features.', 'Setting this to ''mod_lot_advanced'' activates advanced lot numbering with product-specific masks; other values use the corresponding add-on module.', 'string module name, e.g. ''mod_lot_advanced''; default set to ''mod_lot_advanced'' on reset', 0, 0, 'product/admin/product_lot.php|product/admin/product_lot.php|product/admin/product_lot.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product_lot.php:97|write|dolibarr_set_const($db, \"PRODUCTBATCH_LOT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "product/admin/product_lot.php:103|write|dolibarr_set_const($db, \"PRODUCTBATCH_LOT_ADDON\", ''mod_lot_advanced'', ''chaine'', 0, '''', $conf->entity);", "product/card.php:1559|check|if ((getDolGlobalString(''PRODUCTBATCH_LOT_ADDON'') == ''mod_lot_advanced'')", "product/card.php:1575|check|if (getDolGlobalString(''PRODUCTBATCH_LOT_USE_PRODUCT_MASKS'') && getDolGlobalString(''PRODUCTBATCH_LOT_ADDON'') == ''mod_lot_advanced'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCTBATCH_LOT_ADDONS', 'string', NULL, 'product', 'Name of the active lot/batch numbering add-on module used for product lots.', 'Checked in product/admin/product_lot.php:102; if the submitted value is ''1'' and the constant does not equal ''mod_lot_advanced'', a specific code path is taken. Configured via the product lot admin page.', 'Changing this value switches the lot-numbering add-on; setting it to a non-existent module name will break lot number generation.', 'String module name, e.g. ''mod_lot_advanced''.', 0, 0, 'product/admin/product_lot.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product_lot.php:102|check|if ($value == ''1'' && getDolGlobalString(''PRODUCTBATCH_LOT_ADDONS'') !== ''mod_lot_advanced'') {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCTBATCH_LOT_USE_PRODUCT_MASKS', 'bool', NULL, 'product', 'Controls whether lot-number generation uses the mask defined on the individual product rather than the global lot-number addon mask.', 'Configurable via product/admin/product_lot.php (line 101 write). Checked in core/modules/product_batch/mod_lot_advanced.php and multiple locations in product/card.php to decide whether to apply the per-product mask when PRODUCTBATCH_LOT_ADDON is ''mod_lot_advanced''.', 'Enabling this constant causes lot numbers to follow the mask configured per product instead of the global addon mask. It only has effect when PRODUCTBATCH_LOT_ADDON equals ''mod_lot_advanced''.', 'Enabled or disabled via admin UI; stored as bool. No explicit value enumeration in COMMENTS.', 0, 0, 'product/admin/product_lot.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product_lot.php:101|write|dolibarr_set_const($db, \"PRODUCTBATCH_LOT_USE_PRODUCT_MASKS\", $value, ''bool'', 0, '''', $conf->entity);", "product/card.php:1575|check|if (getDolGlobalString(''PRODUCTBATCH_LOT_USE_PRODUCT_MASKS'') && getDolGlobalString(''PRODUCTBATCH_LOT_ADDON'') == ''mod_lot_advanced'') {", "core/modules/product_batch/mod_lot_advanced.php:100|check|if (getDolGlobalString(''PRODUCTBATCH_LOT_USE_PRODUCT_MASKS'')) {", "core/modules/product_batch/mod_lot_advanced.php:155|check|if (getDolGlobalString(''PRODUCTBATCH_LOT_USE_PRODUCT_MASKS'') && !empty($object->fk_product)) {"]', 'high', NULL);
