INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ADDON_PDF_ODT_PATH', 'string', 'DOL_DATA_ROOT/doctemplates/products', 'core', 'Specifies one or more directory paths where ODT templates for product documents are searched.', 'Read in core/modules/product/doc/doc_generic_product_odt.modules.php:125 where it is split into a list of directories, displayed at line 152, and checked at line 160. The default value is ''DOL_DATA_ROOT/doctemplates/products''.', 'If set, additional directories beyond the default are scanned for product ODT templates.', 'String: comma- or newline-separated directory paths; default ''DOL_DATA_ROOT/doctemplates/products''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/product/doc/doc_generic_product_odt.modules.php:125|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''PRODUCT_ADDON_PDF_ODT_PATH''))));", "core/modules/product/doc/doc_generic_product_odt.modules.php:152|read|$texte .= getDolGlobalString(''PRODUCT_ADDON_PDF_ODT_PATH'');", "core/modules/product/doc/doc_generic_product_odt.modules.php:160|check|if (getDolGlobalString(''PRODUCT_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ADD_FORM_ADD_TO', 'string', NULL, 'product', 'Enables ''Add to object'' areas on the product card, allowing the product to be added directly to other objects from the product view.', 'COMMENTS in product/card.php at lines 1109 and 3164 document its purpose. Checked at line 3167 in product/card.php; the ''Add to'' areas are rendered only when this constant is set, the product has an id, the action is view/empty, and the product has a sell status.', 'Setting this constant shows ''Add to'' form sections on the product card for active products. Clearing it removes those sections.', 'From COMMENTS: ''// Add product into object (when PRODUCT_ADD_FORM_ADD_TO is set)'' and ''* All the "Add to" areas if PRODUCT_ADD_FORM_ADD_TO is set''. Truthy = sections shown; absent/falsy = sections hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1109  // Add product into object (when PRODUCT_ADD_FORM_ADD_TO is set)", "product/card.php:3164  * All the \"Add to\" areas if PRODUCT_ADD_FORM_ADD_TO is set", "product/card.php:3167|check|if (getDolGlobalString(''PRODUCT_ADD_FORM_ADD_TO'') && $object->id && ($action == '''' || $action == ''view'') && $object->status) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ADD_NET_MEASURE', 'string', NULL, 'product', 'Enables a net-measure field on the product card, corresponding to the ''net_measure'' measuring style.', 'Checked at product/card.php lines 1762, 2404, and 2972; the net-measure block is rendered only when this constant is set. The COMMENT in core/lib/product.lib.php:974 documents '''' (empty string) as the style identifier for the net_measure option tied to this constant.', 'Setting this constant adds a net-measure field to the product card. Clearing it removes that field.', ''''' = ''net_measure'' for option PRODUCT_ADD_NET_MEASURE (from COMMENT: core/lib/product.lib.php:974 @param string $measuring_style Style of unit: ''weight'', ''volume'', ..., '''' = ''net_measure'' for option PRODUCT_ADD_NET_MEASURE)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/product.lib.php:974  *\t@param  string\t\t$measuring_style    Style of unit: ''weight'', ''volume'', ..., '''' = ''net_measure'' for option PRODUCT_ADD_NET_MEASURE", "product/card.php:1762|check|if (getDolGlobalString(''PRODUCT_ADD_NET_MEASURE'')) {", "product/card.php:2404|check|if (getDolGlobalString(''PRODUCT_ADD_NET_MEASURE'')) {", "product/card.php:2972|check|if (getDolGlobalString(''PRODUCT_ADD_NET_MEASURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ADD_TYPE_IN_DOCUMENTS', 'string', NULL, 'core', 'Adds the product type information into generated documents (PDF and doc outputs).', 'When set, the product type is included in document lines. The comment in both core/lib/pdf.lib.php:2113 and core/lib/doc.lib.php:118 reads: ''In standard mode, we do not show this'', indicating this overrides the default hidden behaviour.', 'Enabling this causes the product type to appear in generated documents; by default (not set) it is not shown.', 'truthy = add product type in documents; empty/not set = do not show (standard mode)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2113|check|if (getDolGlobalString(''PRODUCT_ADD_TYPE_IN_DOCUMENTS'')) {   // In standard mode, we do not show this", "core/lib/doc.lib.php:118|check|if (getDolGlobalString(''PRODUCT_ADD_TYPE_IN_DOCUMENTS'')) {   // In standard mode, we do not show this"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_AJAX_SEARCH_ON_DESCRIPTION', 'string', NULL, 'core', 'Extends product AJAX search to also match against product descriptions in addition to references and labels.', 'When set, core/class/html.form.class.php includes the product description field in the search SQL conditions. Only one check occurrence; no admin UI write; hidden setting.', 'Enabling this constant broadens product searches to include description text; disabling it (or leaving unset) limits search to reference and label fields.', 'Non-empty (truthy) enables description matching in AJAX product search; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3364|check|if (getDolGlobalString(''PRODUCT_AJAX_SEARCH_ON_DESCRIPTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Allows PDF files in the product context to be served for external (unauthenticated) download.', 'In core/lib/files.lib.php, when a file is a PDF, the request URI contains ''product'', and this constant is set, the file is made available for external download. No admin UI write; hidden setting.', 'Enabling this constant allows product PDF files to be downloaded externally; disabling it (or leaving unset) restricts download to authenticated sessions.', 'Non-empty (truthy) enables external download for product PDFs; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/files.lib.php:2147|check|if ($TFile[''type''][$i] == ''application/pdf'' && strpos($_SERVER[\"REQUEST_URI\"], ''product'') !== false && getDolGlobalString(''PRODUCT_ALLOW_EXTERNAL_DOWNLOAD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_BATCH_ADDON_PDF', 'string', NULL, 'product', 'Name of the PDF document template model used for product lot/batch documents.', 'Written by product/admin/product_lot.php:158-161 via dolibarr_set_const and $conf->global assignment. Read at product/stock/class/productlot.class.php:1324-1325 to select the PDF model. Checked for match against available model names at product/admin/product_lot.php:496.', 'Changing this value switches the PDF template used when generating documents for product lots; an invalid value will cause document generation to fail.', 'String name of a PDF model class available in the product lot module.', 0, 0, 'product/admin/product_lot.php|product/admin/product_lot.php|product/admin/product_lot.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product_lot.php:158|write|if (dolibarr_set_const($db, \"PRODUCT_BATCH_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "product/stock/class/productlot.class.php:1324|read|} elseif (getDolGlobalString(''PRODUCT_BATCH_ADDON_PDF'')) {", "product/stock/class/productlot.class.php:1325|read|$modele = getDolGlobalString(''PRODUCT_BATCH_ADDON_PDF'');", "product/admin/product_lot.php:496|check|if (getDolGlobalString(''PRODUCT_BATCH_ADDON_PDF'') == $name) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_BEST_SUPPLIER_PRICE_PRESELECTED', 'string', NULL, 'core', 'When enabled, pre-selects the best (lowest) supplier price option in supplier product select lists when no specific supplier is selected.', 'Checked at core/class/html.form.class.php:4484 and :4510. When unset, another default selection logic applies; when set, the first entry (i==0) is pre-selected regardless of other conditions, effectively pre-selecting the best-priced supplier.', 'Enabling changes the default pre-selection in supplier combo boxes to the first (best-priced) supplier entry. Disabling leaves selection to the standard logic.', 'Truthy = pre-select first/best supplier price entry; empty/unset = use default selection logic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:4484|check|if (!getDolGlobalString(''PRODUCT_BEST_SUPPLIER_PRICE_PRESELECTED'')) {", "core/class/html.form.class.php:4510|check|if ($num == 1 || ($selected_supplier > 0 && $objp->fk_soc == $selected_supplier) || ($i == 0 && getDolGlobalString(''PRODUCT_BEST_SUPPLIER_PRICE_PRESELECTED''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_CANVAS_ABILITY', 'string', NULL, 'product', 'Enables or specifies a canvas (custom product type) capability for products.', 'Checked in product/admin/product.php:788; when the constant is set, a canvas-related code path is executed. Configurable via product admin UI.', 'Setting this constant activates the canvas product feature; exact behavior depends on the canvas module configured.', 'String value identifying the canvas module; unset or empty = canvas feature disabled.', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product.php:788|check|if (getDolGlobalString(''PRODUCT_CANVAS_ABILITY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_CAN_EDIT_WAP', 'string', NULL, 'product', 'Allows manual editing of the Weighted Average Price (WAP) on supplier price records.', 'Checked at product/price_suppliers.php:443; when set, the WAP field becomes editable. No admin UI write found.', 'Enabling this permits users to manually override the computed WAP on supplier product records.', '0 or empty = WAP field is read-only; non-empty = WAP field is editable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/price_suppliers.php:443|check|if (getDolGlobalString(''PRODUCT_CAN_EDIT_WAP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_CHARGES', 'string', NULL, 'fourn', 'Enables tracking and display of supplier charges (additional costs) per product-supplier price record.', 'Checked in product/price_suppliers.php:795 to conditionally show the charges column, and in fourn/class/fournisseur.product.class.php (lines 151, 765, 876, 1044) to load the ''charges'' field from the database. Also used in takepos/invoice.php:923 for POS charge handling. No admin UI write found; HIDDEN_GUESS is 1.', 'When enabled, the supplier price list shows a ''Charges'' column and the fourn_charges property is populated; when disabled, the charges field is ignored.', 'Any non-empty value = enabled; empty = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/price_suppliers.php:795|check|if (getDolGlobalString(''PRODUCT_CHARGES'')) {", "fourn/class/fournisseur.product.class.php:151|read|public $fourn_charges;\t// when getDolGlobalString(''PRODUCT_CHARGES'') is set", "product/price_suppliers.php:1244|check|if (!empty($arrayfields[''pfp.charges''][''checked''])) {\t// Possible only when getDolGlobalString(''PRODUCT_CHARGES'') is set", "takepos/invoice.php:923|check|if (getDolGlobalString(''PRODUCT_CHARGES'') && $pf->fourn_charges > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_CODEPRODUCT_ADDON', 'string', NULL, 'product', 'Selects the module class used to generate or validate product reference codes.', 'Configured via product/admin/product.php (written with dolibarr_set_const). Read in product/class/product.class.php:1075 and product/card.php:148 and :1461 to load the product code module, defaulting to ''mod_codeproduct_leopard'' when unset.', 'Changing this value switches the product code generation algorithm. New product codes will be generated by the selected module.', 'String class name of the product code module; defaults to ''mod_codeproduct_leopard''.', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product.php:102|write|if (dolibarr_set_const($db, \"PRODUCT_CODEPRODUCT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity) > 0) {", "product/class/product.class.php:1075|read|$module = getDolGlobalString(''PRODUCT_CODEPRODUCT_ADDON'', ''mod_codeproduct_leopard'');", "product/card.php:148|read|$module = getDolGlobalString(''PRODUCT_CODEPRODUCT_ADDON'', ''mod_codeproduct_leopard'');", "product/card.php:1461|read|$module = getDolGlobalString(''PRODUCT_CODEPRODUCT_ADDON'', ''mod_codeproduct_leopard'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DENY_CHANGE_PRODUCT_TYPE', 'string', NULL, 'product', 'Prevents users from changing a product''s type (product vs. service) after creation.', 'Checked in 9 locations. In product/card.php:2628, product/price.php:1055, :1134, :1149, :1376, variants/combinations.php:443, product/composition/card.php:268, and product/price_suppliers.php:425, the type field editfieldkey is replaced with a read-only label when this constant is set.', 'Enabling this constant removes the type-change control from product edit forms, locking the product/service classification after initial creation.', 'Non-empty = type change denied (read-only display); 0 or unset = type change allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/card.php:2628|read|print (!getDolGlobalString(''PRODUCT_DENY_CHANGE_PRODUCT_TYPE'')) ? $form->editfieldkey(\"Type\", ''fk_product_type'', (string) $object->type, $object, (int) $usercancreate, $typeformat)", "product/price.php:1055|read|print (!getDolGlobalString(''PRODUCT_DENY_CHANGE_PRODUCT_TYPE'')) ? $form->editfieldkey(\"Type\", ''fk_product_type'', (string) $object->type, $object, 0, $typeformat) : $langs->trans(''T", "variants/combinations.php:443|read|print (!getDolGlobalString(''PRODUCT_DENY_CHANGE_PRODUCT_TYPE'')) ? $form->editfieldkey(\"Type\", ''fk_product_type'', (string) $object->type, $object, (int) $usercancreate, $typeformat)"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DESC_IN_LIST', 'string', NULL, 'contrat', 'When enabled, displays the product description in contract service list views.', 'Checked in contrat/services_list.php:888 to conditionally print the description when it is non-empty. Only one occurrence in the payload. No admin UI write is present.', 'Enabling this constant causes product descriptions to appear in the contract services list when a description is available.', 'Boolean flag; unset or 0 = description not shown in list; any truthy value = description shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contrat/services_list.php:888|check|if (!empty($obj->description) && getDolGlobalString(''PRODUCT_DESC_IN_LIST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_ACCOUNTING', 'bool', NULL, 'product', 'Disables accounting-code fields on the product card and removes accounting columns from the product list.', 'Checked at product/card.php lines 1889, 2483, and 2730 with negated conditions. Also used in product/list.php lines 301-305 to control the enabled state of accountancy sell, sell-intra, sell-export, buy, and buy-intra code columns.', 'Setting this constant hides all accountancy code fields from the product card and disables those columns in the product list. Clearing it restores them.', 'Boolean flag; absent/falsy = accounting fields shown; truthy = accounting fields hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1889|check|if (!getDolGlobalString(''PRODUCT_DISABLE_ACCOUNTING'')) {", "product/list.php:301|read|$alias_product_perentity . ''.accountancy_code_sell'' => array(''label'' => \"ProductAccountancySellCode\", ''checked'' => ''0'', ''enabled'' => (string) (int) !getDolGlobalString(''PRODUCT_DIS", "product/list.php:304|read|$alias_product_perentity . ''.accountancy_code_buy'' => array(''label'' => \"ProductAccountancyBuyCode\", ''checked'' => ''0'', ''enabled'' => (string) (int) !getDolGlobalString(''PRODUCT_DISAB", "product/card.php:2730|check|if (!getDolGlobalString(''PRODUCT_DISABLE_ACCOUNTING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_CUSTOMS_INFO', 'bool', NULL, 'product', 'Disables the customs information section on the product card for physical (non-service) products.', 'Checked at product/card.php lines 1780, 2421, and 2994 with negated conditions combined with a check that the product is not a service; the customs info block is rendered only when this constant is not set.', 'Setting this constant hides customs-related fields from physical product cards. It has no effect on service products, which already exclude customs info.', 'Boolean flag; absent/falsy = customs info shown for non-services; truthy = customs info hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1780|check|if (!getDolGlobalString(''PRODUCT_DISABLE_CUSTOMS_INFO'') && empty($type)) {", "product/card.php:2421|check|if (!$object->isService() && !getDolGlobalString(''PRODUCT_DISABLE_CUSTOMS_INFO'')) {", "product/card.php:2994|check|if (!$object->isService() && !getDolGlobalString(''PRODUCT_DISABLE_CUSTOMS_INFO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_EATBY', 'bool', NULL, 'product', 'Disables the ''eat-by (best before) date'' field for product lot/serial tracking.', 'Checked in 53 occurrences across product/stock/tpl/stockcorrection.tpl.php, product/stock/productlot_card.php, product/stock/class/productlot.class.php:1167, reception/dispatch.php, and many others. Commented-out references in takepos/invoice.php:833 confirm field-hiding intent.', 'When enabled, the eat-by/best-before date field is hidden from product lot forms, stock correction templates, and reception dispatch pages.', '0 or unset = eat-by date field shown; non-empty = eat-by date field hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/stock/tpl/stockcorrection.tpl.php:235|check|if (!getDolGlobalString(''PRODUCT_DISABLE_EATBY'')) {", "product/stock/productlot_card.php:406|check|if (!getDolGlobalString(''PRODUCT_DISABLE_EATBY'')) {", "product/stock/class/productlot.class.php:1167|check|if (isDolTms($this->eatby) && !getDolGlobalString(''PRODUCT_DISABLE_EATBY'')) {", "takepos/invoice.php:833  //if (!getDolGlobalString(''PRODUCT_DISABLE_EATBY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_NATURE', 'bool', NULL, 'product', 'Hides the product nature field (product type/composition selector) from product cards and composition pages.', 'Checked in product/card.php:1719,2355,2909 and product/composition/card.php:304. When set, the nature field is not rendered on the product form.', 'Enabling this constant hides the nature field entirely; disabling it restores the field on product edit and view pages.', 'Any non-empty value = disable (hide) nature field; empty/unset = show nature field', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!getDolGlobalString(''PRODUCT_DISABLE_NATURE'')) {", "product/composition/card.php:304|check|if (!getDolGlobalString(''PRODUCT_DISABLE_NATURE'')) {", "product/card.php:1719|check|if (!getDolGlobalString(''PRODUCT_DISABLE_NATURE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_PRICES', 'bool', NULL, 'product', 'Disables the prices section on the product card.', 'Checked at product/card.php line 1842 with a negated condition; the prices block is rendered only when this constant is not set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant hides pricing fields from the product card.', 'Boolean flag; absent/falsy = prices shown; truthy = prices hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1842|check|if (!getDolGlobalString(''PRODUCT_DISABLE_PRICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_PROPAGATE_CUSTOMER_PRICES_ON_CHILD_COMPANIES', 'bool', NULL, 'product', 'Disables automatic propagation of customer-specific prices to child/subsidiary companies.', 'Checked in product/class/productcustomerprice.class.php:1003 to skip the price-propagation step for child companies.', 'Enabling this constant prevents customer price records from being copied to child companies when a price is saved on the parent company.', 'Empty/not set = prices propagated to child companies; any truthy string = propagation disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/class/productcustomerprice.class.php:1003|check|if (getDolGlobalString(''PRODUCT_DISABLE_PROPAGATE_CUSTOMER_PRICES_ON_CHILD_COMPANIES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_PUBLIC_URL', 'bool', NULL, 'product', 'Disables the public URL section on the product card so it is not shown to users.', 'Checked at three locations in product/card.php (lines 1648, 2282, 2837) using a negated condition; the public URL block is rendered only when this constant is not set.', 'Setting this constant hides the public URL field on the product card. Clearing it restores the display of the public URL.', 'Boolean flag; absent/falsy = public URL shown; truthy = public URL hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1648|check|if (!getDolGlobalString(''PRODUCT_DISABLE_PUBLIC_URL'')) {", "product/card.php:2282|check|if (!getDolGlobalString(''PRODUCT_DISABLE_PUBLIC_URL'')) {", "product/card.php:2837|check|if (!getDolGlobalString(''PRODUCT_DISABLE_PUBLIC_URL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_SELLBY', 'bool', NULL, 'product', 'Disables the ''sell-by date'' field for product lot/serial tracking.', 'Checked in 53 occurrences across reception/card.php, mrp/mo_movements.php, product/reassortlot.php, product/stock/tpl/stockcorrection.tpl.php, product/stock/productlot_card.php, and many others. The read at product/stock/tpl/stockcorrection.tpl.php:93 assigns it to $disableSellBy. Commented-out references in product/stock/stats and product/stock/index.php confirm field-hiding intent.', 'When enabled, the sell-by date field is hidden from product lot forms, stock correction templates, and reception cards throughout the application.', '0 or unset = sell-by date field shown; non-empty = sell-by date field hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:2758|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SELLBY'')) {", "product/stock/tpl/stockcorrection.tpl.php:93|read|$disableSellBy = getDolGlobalInt(''PRODUCT_DISABLE_SELLBY'');", "product/stock/productlot_card.php:396|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SELLBY'')) {", "mrp/mo_movements.php:152|check|if (getDolGlobalString(''PRODUCT_DISABLE_SELLBY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_SIZE', 'bool', NULL, 'product', 'Disables size-related fields (length, width, height) on the product card and list columns.', 'Checked at product/card.php lines 1738, 2380, and 2939, and used in product/list.php (lines 276-280) to control the enabled state of length, length_units, width, width_units, and height columns.', 'Setting this constant hides size fields (length, width, height) from the product card and removes those columns from the product list. Clearing it restores them.', 'Boolean flag; absent/falsy = size fields shown; truthy = size fields hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1738|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SIZE'')) {", "product/list.php:276|read|''p.length'' => array(''label'' => ''Length'', ''checked'' => ''0'', ''enabled'' => (string) (int) (isModEnabled(\"product\") && !getDolGlobalString(''PRODUCT_DISABLE_SIZE'') && $type != ''1'')", "product/list.php:278|read|''p.width'' => array(''label'' => ''Width'', ''checked'' => ''0'', ''enabled'' => (string) (int) (isModEnabled(\"product\") && !getDolGlobalString(''PRODUCT_DISABLE_SIZE'') && $type != ''1'')", "product/list.php:280|read|''p.height'' => array(''label'' => ''Height'', ''checked'' => ''0'', ''enabled'' => (string) (int) (isModEnabled(\"product\") && !getDolGlobalString(''PRODUCT_DISABLE_SIZE'') && $type != ''1'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_STATE', 'bool', NULL, 'product', 'Disables the product-state (status/lifecycle) field on the product card.', 'Checked at product/card.php lines 1794 and 2435 with negated conditions; the state section is rendered only when this constant is not set.', 'Setting this constant hides the product state field from the product card. Only 2 occurrences found; exact behavior unclear from code alone.', 'Boolean flag; absent/falsy = state field shown; truthy = state field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1794|check|if (!getDolGlobalString(''PRODUCT_DISABLE_STATE'')) {", "product/card.php:2435|check|if (!getDolGlobalString(''PRODUCT_DISABLE_STATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_STOCK_LEVELS', 'bool', NULL, 'product', 'Disables the display of stock-level information on the product card.', 'Checked at product/card.php lines 1668 and 1681 with negated conditions; stock-level sections are rendered only when this constant is not set.', 'Enabling this constant hides stock-level fields from the product card. Only 2 occurrences found; exact behavior unclear from code alone.', 'Boolean flag; absent/falsy = stock levels shown; truthy = stock levels hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1668|check|if (!getDolGlobalString(''PRODUCT_DISABLE_STOCK_LEVELS'')) {", "product/card.php:1681|check|if (!getDolGlobalString(''PRODUCT_DISABLE_STOCK_LEVELS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_SURFACE', 'bool', NULL, 'product', 'Disables the surface field on the product card and list view.', 'Checked at product/card.php lines 1747, 2389, 2956, 2959, 2960, 2962, and 2965, and in product/list.php line 282 to control the enabled state of the surface column.', 'Setting this constant hides the surface field from the product card and removes the surface column from the product list. It also suppresses the separator between surface and volume when both are disabled.', 'Boolean flag; absent/falsy = surface field shown; truthy = surface field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1747|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SURFACE'')) {", "product/card.php:2959|read|print (getDolGlobalString(''PRODUCT_DISABLE_SURFACE'') ? '''' : $langs->trans(\"Surface\"));", "product/card.php:2956|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SURFACE'') || !getDolGlobalString(''PRODUCT_DISABLE_VOLUME'')) {", "product/list.php:282|read|''p.surface'' => array(''label'' => ''Surface'', ''checked'' => ''0'', ''enabled'' => (string) (int) (isModEnabled(\"product\") && !getDolGlobalString(''PRODUCT_DISABLE_SURFACE'') && $type != ''1'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_VOLUME', 'bool', NULL, 'product', 'Disables the volume field on the product card and list view.', 'Checked at product/card.php lines 1754, 2396, 2956, 2960, 2961, 2965, and 2966, and in product/list.php line 284 to control the enabled state of the volume column.', 'Setting this constant hides the volume field from the product card and removes the volume column from the product list. It also suppresses the separator between surface and volume when both are disabled.', 'Boolean flag; absent/falsy = volume field shown; truthy = volume field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1754|check|if (!getDolGlobalString(''PRODUCT_DISABLE_VOLUME'')) {", "product/card.php:2961|read|print (getDolGlobalString(''PRODUCT_DISABLE_VOLUME'') ? '''' : $langs->trans(\"Volume\")).''</td><td>'';", "product/card.php:2956|check|if (!getDolGlobalString(''PRODUCT_DISABLE_SURFACE'') || !getDolGlobalString(''PRODUCT_DISABLE_VOLUME'')) {", "product/list.php:284|read|''p.volume'' => array(''label'' => ''Volume'', ''checked'' => ''0'', ''enabled'' => (string) (int) (isModEnabled(\"product\") && !getDolGlobalString(''PRODUCT_DISABLE_VOLUME'') && $type != ''1'')"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISABLE_WEIGHT', 'bool', NULL, 'product', 'Disables the weight field on the product card and list views.', 'Checked at product/card.php lines 1728, 2372, and 2929 with negated conditions; the weight input/display block is rendered only when this constant is not set.', 'Setting this constant hides the weight field on the product card. Removing it restores the weight field.', 'Boolean flag; absent/falsy = weight field shown; truthy = weight field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:1728|check|if (!getDolGlobalString(''PRODUCT_DISABLE_WEIGHT'')) {", "product/card.php:2372|check|if (!getDolGlobalString(''PRODUCT_DISABLE_WEIGHT'')) {", "product/card.php:2929|check|if (!getDolGlobalString(''PRODUCT_DISABLE_WEIGHT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DISPLAY_VAT_INCL_PRICES', 'string', NULL, 'product', 'Enables display of VAT-inclusive (TTC) prices on the product price page.', 'Checked at product/price.php lines 1413 and 1426; VAT-inclusive price and minimum price blocks are shown only when this constant is set and the corresponding price_ttc / price_min_ttc values are non-empty.', 'Setting this constant causes VAT-inclusive prices to be displayed on the product price page alongside the base prices. Clearing it hides those blocks.', 'Boolean/string flag; absent/falsy = TTC prices hidden; truthy = TTC prices shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/price.php:1413|check|if (getDolGlobalString(''PRODUCT_DISPLAY_VAT_INCL_PRICES'') && !empty($object->price_ttc)) {", "product/price.php:1426|check|if (getDolGlobalString(''PRODUCT_DISPLAY_VAT_INCL_PRICES'') && !empty($object->price_min_ttc)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DONOTSEARCH_ANYWHERE', 'string', NULL, 'core', 'Restricts product search to prefix-only matching, enabling database index use and improving search performance.', 'When set, core/class/html.form.class.php omits the leading ''%'' wildcard from LIKE patterns, allowing the database to use an index. The inline comment states: ''Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on''. The performance admin page (admin/system/perf.php) reports this optimization as active when enabled.', 'Enabling this constant makes product searches prefix-only (faster, index-friendly) but prevents mid-string matches; disabling it allows searching anywhere in the product name or reference.', 'Non-empty (truthy) enables prefix-only search; empty or undefined enables full wildcard search.', 0, 0, 'admin/system/perf.php|admin/system/perf.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3346|read|$prefix = getDolGlobalString(''PRODUCT_DONOTSEARCH_ANYWHERE'') ? '''' : ''%''; // Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on", "core/class/html.form.class.php:4078|read|$prefix = getDolGlobalString(''PRODUCT_DONOTSEARCH_ANYWHERE'') ? '''' : ''%''; // Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on", "admin/system/perf.php:686|check|if (!getDolGlobalString(''PRODUCT_DONOTSEARCH_ANYWHERE'')) {", "admin/system/perf.php:690|read|print img_picto('''', ''tick'', ''class=\"pictofixedwidth\"'').'' ''.$langs->trans(\"YouHaveXObjectAndSearchOptimOn\", $nb, $langs->transnoentitiesnoconv(\"ProductsOrServices\"), ''PRODUCT_DONOTS"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_DRAFT_WATERMARK', 'string', NULL, 'core', 'Defines a watermark text applied to product PDF documents when the product is in draft status.', 'Checked in core/modules/product/doc/pdf_standard.modules.php:744: the watermark is applied only when $object->status == 0 (draft) and this constant is non-empty.', 'Setting a value causes draft-product PDFs to display the specified watermark text; leaving it empty suppresses the watermark.', 'Any non-empty string to use as the watermark label.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/product/doc/pdf_standard.modules.php:744|check|if ($object->status == 0 && getDolGlobalString(''PRODUCT_DRAFT_WATERMARK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ELEPHANT_ADD_WHERE', 'string', NULL, 'core', 'Provides an additional SQL WHERE clause fragment appended during product-code uniqueness checks in the Elephant numbering module.', 'Checked and applied in core/modules/product/mod_codeproduct_elephant.php lines 211-212: when non-empty, the value is sanitised with dol_string_nospecial/dol_string_unaccent and appended to the uniqueness query.', 'Setting this constant restricts the product-code uniqueness check to a subset of products matching the extra condition; incorrect SQL syntax will break code generation.', 'Any valid SQL WHERE sub-expression (without leading AND/OR; e.g. ''entity=1'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/product/mod_codeproduct_elephant.php:211|check|if (getDolGlobalString(''PRODUCT_ELEPHANT_ADD_WHERE'')) {", "core/modules/product/mod_codeproduct_elephant.php:212|read|$where = '' AND (''.dol_string_nospecial(dol_string_unaccent(getDolGlobalString(''PRODUCT_ELEPHANT_ADD_WHERE'')), ''_'', array('','', ''@'', ''\"'', \"|\", \";\", \":\")).'')''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ELEPHANT_MASK_PRODUCT', 'string', NULL, 'core', 'Defines the numbering mask for products (type=0) in the ''Elephant'' product-code numbering module.', 'Used in core/modules/product/mod_codeproduct_elephant.php: displayed in a configuration field (line 107) and applied as the active mask for product-code generation (lines 187, 232, 277). Activated only when $type == 0 and the constant is non-empty (line 186).', 'Changing this mask alters the auto-generated codes for new products; existing product codes are not retroactively changed.', 'Any mask string accepted by the Elephant numbering module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/product/mod_codeproduct_elephant.php:186|check|if ($type == 0 && getDolGlobalString(''PRODUCT_ELEPHANT_MASK_PRODUCT'')) {", "core/modules/product/mod_codeproduct_elephant.php:187|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_PRODUCT'');", "core/modules/product/mod_codeproduct_elephant.php:232|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_PRODUCT'');", "core/modules/product/mod_codeproduct_elephant.php:277|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_PRODUCT'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ELEPHANT_MASK_SERVICE', 'string', NULL, 'core', 'Defines the numbering mask for services (type=1) in the ''Elephant'' product-code numbering module.', 'Used in core/modules/product/mod_codeproduct_elephant.php: displayed in a configuration field (line 115) and applied as the active mask for service-code generation (lines 189, 237, 280). Activated only when $type == 1 and the constant is non-empty (line 188).', 'Changing this mask alters the auto-generated codes for new services; existing service codes are not retroactively changed.', 'Any mask string accepted by the Elephant numbering module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/product/mod_codeproduct_elephant.php:188|read|} elseif ($type == 1 && getDolGlobalString(''PRODUCT_ELEPHANT_MASK_SERVICE'')) {", "core/modules/product/mod_codeproduct_elephant.php:189|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_SERVICE'');", "core/modules/product/mod_codeproduct_elephant.php:237|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_SERVICE'');", "core/modules/product/mod_codeproduct_elephant.php:280|read|$mask = getDolGlobalString(''PRODUCT_ELEPHANT_MASK_SERVICE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_GENERATE_REF_AFTER_FORM', 'string', NULL, 'product', 'Defers automatic product reference generation until after the creation form is submitted rather than pre-filling it.', 'Checked in product/card.php at lines 534, 736, 798, and 1512. When not set, the ref is pre-filled before form display; when set, generation is skipped pre-form and triggered post-submission.', 'Enabling this means the product reference is not shown in the creation form and is generated on save; disabling it pre-fills the reference in the form.', 'truthy = generate ref after form submit; empty/not set = pre-fill ref in form', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:736|check|if (!$ref && getDolGlobalString(''PRODUCT_GENERATE_REF_AFTER_FORM'')) {", "product/card.php:534|check|if (!getDolGlobalString(''PRODUCT_GENERATE_REF_AFTER_FORM'')) {", "product/card.php:798|check|if (!getDolGlobalString(''PRODUCT_GENERATE_REF_AFTER_FORM'')) {", "product/card.php:1512|check|if (!getDolGlobalString(''PRODUCT_GENERATE_REF_AFTER_FORM'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_HIDE_ADD_CONTACT_THIPARTY', 'bool', NULL, 'product', 'Hides the ''add third-party contact'' action on the product contact page.', 'Checked at product/contact.php line 171; the add-third-party-contact section is hidden when this constant is set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant prevents the add-third-party-contact option from appearing on the product contact page.', 'Boolean flag; absent/falsy = add-third-party-contact shown; truthy = add-third-party-contact hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/contact.php:171|check|if (getDolGlobalString(''PRODUCT_HIDE_ADD_CONTACT_THIPARTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_HIDE_ADD_CONTACT_USER', 'bool', NULL, 'product', 'Hides the ''add user contact'' action on the product contact page.', 'Checked at product/contact.php line 168; the add-user-contact section is hidden when this constant is set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant prevents the add-user-contact option from appearing on the product contact page.', 'Boolean flag; absent/falsy = add-user-contact shown; truthy = add-user-contact hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/contact.php:168|check|if (getDolGlobalString(''PRODUCT_HIDE_ADD_CONTACT_USER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_ID_FOR_FREE_AMOUNT_INVOICE', 'string', NULL, 'public', 'Specifies the product ID used as the line item when creating a free-amount public invoice.', 'Checked at public/invoice/new.php:99 to gate the free-amount invoice feature, and read at :201 as the integer product ID assigned to the invoice line. Described in the file header comment as ''Product ID used for free amount invoice line''.', 'If not set, the free-amount invoice flow is blocked. If set, the specified product is used for the invoice line item.', 'Product ID used for free amount invoice line', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/invoice/new.php:34  *  PRODUCT_ID_FOR_FREE_AMOUNT_INVOICE            Product ID used for free amount invoice line", "public/invoice/new.php:99|check|if (!getDolGlobalString(''PRODUCT_ID_FOR_FREE_AMOUNT_INVOICE'')) {", "public/invoice/new.php:201|read|$productIdForFreeAmountInvoice = (int) getDolGlobalString(''PRODUCT_ID_FOR_FREE_AMOUNT_INVOICE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_LOAD_EXTRAFIELD_INTO_OBJECTLINES', 'string', NULL, 'core', 'Controls whether product extra fields are loaded into document object lines.', 'Exposed as a boolean to JavaScript in core/tpl/objectline_create.tpl.php:693 and documented as a JS property at line 767.', 'When enabled, product extra fields are loaded into document lines, making them available on the line creation form.', 'Truthy boolean = extra fields loaded; false/unset = extra fields not loaded into lines.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:693|read|''PRODUCT_LOAD_EXTRAFIELD_INTO_OBJECTLINES'' => (bool) getDolGlobalInt(''PRODUCT_LOAD_EXTRAFIELD_INTO_OBJECTLINES''),", "core/tpl/objectline_create.tpl.php:767  * @property {boolean} conf.PRODUCT_LOAD_EXTRAFIELD_INTO_OBJECTLINES"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_LOT_ENABLE_QUALITY_CONTROL', 'bool', NULL, 'product', 'Enables quality-control fields (including end-of-life date) on product lot records.', 'Checked at product/card.php lines 1809, 2451, and 3006, and at product/stock/productlot_card.php line 428. Also controls the enabled state of the ''eol_date'' field in product/stock/class/productlot.class.php line 157 via getDolGlobalInt. Commented-out usage in stats files (commande_fournisseur.php, expedition.php, reception.php) indicates planned but inactive extensions.', 'Enabling this constant activates quality-control fields such as the end-of-life date on lot cards and the product card lot section. Disabling it hides those fields.', 'Boolean flag; absent/falsy = quality control disabled; truthy = quality control enabled. COMMENTS show the constant is referenced but currently inactive in several stats files.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/class/productlot.class.php:157|read|''eol_date'' => array(''type'' => ''date'', ''label'' => ''EndOfLife'', ''enabled'' => ''getDolGlobalInt(\"PRODUCT_LOT_ENABLE_QUALITY_CONTROL\") ? 1 : 0 ''", "product/card.php:1809|check|if (getDolGlobalString(''PRODUCT_LOT_ENABLE_QUALITY_CONTROL'')) {", "product/stock/productlot_card.php:428|check|if (getDolGlobalString(''PRODUCT_LOT_ENABLE_QUALITY_CONTROL'')) {", "product/stock/stats/commande_fournisseur.php:200  //      if (getDolGlobalString(''PRODUCT_LOT_ENABLE_QUALITY_CONTROL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_LOT_ENABLE_TRACEABILITY', 'bool', NULL, 'product', 'Enables traceability fields (manufacturing date, destruction date) on product lot records.', 'When enabled, the ''manufacturing_date'' and ''scrapping_date'' fields on productlot objects become active (enabled condition returns 1). Several stat pages have traceability-related code commented out pending this flag. Used in product/stock/class/productlot.class.php and product/stock/productlot_card.php. No admin UI write; hidden setting.', 'Enabling this constant activates traceability date fields on lot records; disabling it hides those fields.', 'Non-zero integer (truthy) enables traceability; 0 or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/class/productlot.class.php:158|read|''scrapping_date'' => array(''type'' => ''date'', ''label'' => ''DestructionDate'', ''enabled'' => ''getDolGlobalInt(\"PRODUCT_LOT_ENABLE_TRACEABILITY\") ? 1 : 0''", "product/stock/class/productlot.class.php:154|read|''manufacturing_date'' => array(''type'' => ''date'', ''label'' => ''ManufacturingDate'', ''enabled'' => ''getDolGlobalInt(\"PRODUCT_LOT_ENABLE_TRACEABILITY\") ? 1 : 0''", "product/stock/productlot_card.php:415|check|if (getDolGlobalString(''PRODUCT_LOT_ENABLE_TRACEABILITY'')) {", "//      if (getDolGlobalString(''PRODUCT_LOT_ENABLE_TRACEABILITY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_MAX_LENGTH_COMBO', 'string', NULL, 'core', 'Sets the maximum character length for product labels displayed in product combobox/selector widgets.', 'In core/class/html.form.class.php, getDolGlobalInt(''PRODUCT_MAX_LENGTH_COMBO'', 48) is used to truncate product labels in two selector methods. The default fallback is 48 characters. No admin UI write; hidden setting.', 'Increasing this value shows longer product labels in selectors; decreasing it truncates labels more aggressively; the default is 48 characters.', 'Integer character count; default is 48.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3595|read|$maxlengtharticle = getDolGlobalInt(''PRODUCT_MAX_LENGTH_COMBO'', 48);", "core/class/html.form.class.php:4016|read|$maxlengtharticle = getDolGlobalInt(''PRODUCT_MAX_LENGTH_COMBO'', 48);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_MAX_VISIBLE_PHOTO', 'string', NULL, 'core', 'Sets the maximum number of product photos displayed in the product view, defaulting to 5.', 'Read as an integer in core/lib/functions.lib.php:3427 with a default of 5. No admin UI write detected.', 'Increasing this value shows more product photos simultaneously. Decreasing it limits the visible photo count.', 'Integer; default 5. Set to a higher integer to display more photos.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3427|read|$maxvisiblephotos = getDolGlobalInt(''PRODUCT_MAX_VISIBLE_PHOTO'', 5);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_MINIMUM_RECOMMENDED_PRICE', 'string', NULL, 'product', 'Enforces a minimum recommended price based on the highest supplier price multiplied by this constant.', 'Checked in product/class/product.class.php:7083 and extensively in product/price.php (lines 516, 806, 956, 1719, 1807, 1879, 2033). The docblock comment at product/class/product.class.php:7076 states: ''Minimum recommended price that is higher price among all suppliers * PRODUCT_MINIMUM_RECOMMENDED_PRICE''.', 'When set, saving a product price below the computed minimum triggers an error or warning. This prevents selling below the supplier cost threshold.', 'Numeric string used as a multiplier against the highest supplier price; empty/unset disables the minimum price check.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:7076  * @return int            Minimum recommended price that is higher price among all suppliers * PRODUCT_MINIMUM_RECOMMENDED_PRICE", "product/class/product.class.php:7083|check|if (getDolGlobalString(''PRODUCT_MINIMUM_RECOMMENDED_PRICE'')) {", "product/price.php:516|check|if (getDolGlobalString(''PRODUCT_MINIMUM_RECOMMENDED_PRICE'') && $newprice_min < $maxpricesupplier) {", "product/price.php:806|check|if (getDolGlobalString(''PRODUCT_MINIMUM_RECOMMENDED_PRICE'') && $prodcustprice->price_min < (float) $maxpricesupplier) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_NODISPLAYIFNOPHOTO', 'string', NULL, 'core', 'Hides the product photo display area entirely when no photo is available.', 'Checked in core/lib/functions.lib.php:3435; when set, the photo block is suppressed if no photos exist. No admin UI write detected.', 'Setting this constant removes the empty photo placeholder from product views. Without it, the photo area is shown even when no image is attached.', 'Non-empty = hide photo area when no photo; absent/empty = always show photo area.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3435|check|if (getDolGlobalString(''PRODUCT_NODISPLAYIFNOPHOTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_PRICE_BASE_TYPE', 'string', 'HT', 'product', 'Sets the default price base type (tax-excluded or tax-included) for products.', 'Configured via product/admin/product.php (written with dolibarr_set_const). Read in product/class/product.class.php:1003-1004 to set the product''s price_base_type when it is empty, and rendered as a select in product/admin/product.php:639 and product/card.php:1863. Default value is ''HT''.', 'Changing this value alters the default pricing mode offered when creating or editing products.', '''HT'' (tax-excluded, default) or ''TTC'' (tax-included).', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product.php:148|write|$res = dolibarr_set_const($db, \"PRODUCT_PRICE_BASE_TYPE\", $value, ''chaine'', 0, '''', $conf->entity);", "product/class/product.class.php:1003|check|if (empty($this->price_base_type) && getDolGlobalString(''PRODUCT_PRICE_BASE_TYPE'')) {", "product/class/product.class.php:1004|read|$this->price_base_type = getDolGlobalString(''PRODUCT_PRICE_BASE_TYPE'');", "product/admin/product.php:639|read|print $form->selectPriceBaseType(getDolGlobalString(''PRODUCT_PRICE_BASE_TYPE''), \"price_base_type\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_PRICE_SUPPLIER_NO_LOG', 'string', NULL, 'fourn', 'Disables logging of supplier price changes for products.', 'Checked in fourn/class/fournisseur.product.class.php at lines 596 and 689; when not set, a price change log entry is created. No admin UI write found; HIDDEN_GUESS is 1.', 'When enabled, changes to supplier prices are not logged, reducing audit trail entries; when disabled or not set, price changes are recorded in the log.', 'Any non-empty value = logging disabled; empty/not set = logging enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.product.class.php:596|check|if (!$error && !getDolGlobalString(''PRODUCT_PRICE_SUPPLIER_NO_LOG'')) {", "fourn/class/fournisseur.product.class.php:689|check|if (!$error && !getDolGlobalString(''PRODUCT_PRICE_SUPPLIER_NO_LOG'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_PRICE_UNIQ', 'string', NULL, 'product', 'Enforces a single unique price per product, disabling per-customer or multi-level pricing.', 'Written to value 1 in product/admin/product.php:133 and checked in product/class/api_products.class.php:442, product/list.php:969, and core/actions_massactions.inc.php:1384 to gate price-related actions.', 'Enabling this enforces a single price per product; it blocks mass-action and API operations that would set per-customer prices when combined with related pricing constants.', '0 or not set = multiple prices allowed; 1 = unique price enforced', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:133|write|dolibarr_set_const($db, ''PRODUCT_PRICE_UNIQ'', 1, ''chaine'', 0, '''', $conf->entity);", "product/class/api_products.class.php:442|check|if ($result > 0 && (getDolGlobalString(''PRODUCT_PRICE_UNIQ'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES''))) {", "product/list.php:969|check|if (getDolGlobalString(''PRODUCT_PRICE_UNIQ'')", "core/actions_massactions.inc.php:1384|check|if (getDolGlobalString(''PRODUCT_PRICE_UNIQ'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_QUICKSEARCH_ON_FIELDS', 'string', NULL, 'product', 'Defines a custom set of database fields to search when performing a quick search on the product list.', 'COMMENT at product/list.php:243 documents the format: ''p.ref=ProductRef;p.label=ProductLabel;p.description=Description;p.note=Note;''. Checked at line 244; if set, the value is parsed via dolExplodeIntoArray at line 245 to override the default search fields.', 'Setting this constant replaces the default product quick-search fields with the specified set. Clearing it restores the default fields.', 'From COMMENT: getDolGlobalString(''PRODUCT_QUICKSEARCH_ON_FIELDS'') = ''p.ref=ProductRef;p.label=ProductLabel;p.description=Description;p.note=Note;''. Format: ''db_field=LangKey;...''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/list.php:243  // Personalized search criteria. Example: getDolGlobalString(''PRODUCT_QUICKSEARCH_ON_FIELDS'') = ''p.ref=ProductRef;p.label=ProductLabel;p.description=Description;p.note=Note;''", "product/list.php:244|check|if (getDolGlobalString(''PRODUCT_QUICKSEARCH_ON_FIELDS'')) {", "product/list.php:245|read|$fieldstosearchall = dolExplodeIntoArray(getDolGlobalString(''PRODUCT_QUICKSEARCH_ON_FIELDS''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SEARCH_AUTOFOCUS', 'string', NULL, 'core', 'Enables autofocus on the product search input field in product selection comboboxes.', 'In core/class/html.form.class.php, the autofocus HTML attribute on the product search input is controlled by this constant. Present in four read occurrences across multiple product selector methods. No admin UI write; hidden setting.', 'Enabling this constant causes the product search field to receive focus automatically when the selector opens; disabling it leaves focus management to the browser default.', 'Non-empty (truthy) enables autofocus on product search input; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:2946|read|$out .= ''<input type=\"text\" class=\"minwidth100\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_val", "core/class/html.form.class.php:8383|read|$out .= ''<input type=\"text\" class=\"minwidth100\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_value . ''\"''", "core/class/html.form.class.php:8609|read|$out .= ''<input type=\"text\" class=\"minwidth100\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_value . ''\"''", "core/class/html.form.class.php:8842|read|$out .= ''<input type=\"text\" class=\"minwidth100\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_value . ''\"''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SEARCH_AUTO_SELECT_IF_ONLY_ONE', 'string', NULL, 'core', 'Automatically selects the single matching product when an autocomplete search returns exactly one result.', 'In core/class/html.form.class.php, this constant is passed as an argument to ajax_autocompleter() for the product selector. Only one occurrence in the payload; no admin UI write; hidden setting.', 'Enabling this constant causes the product autocomplete to auto-select the result when only one match exists; disabling it requires the user to manually confirm the selection.', 'Non-zero integer enables auto-selection on single result; 0 or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:2951|read|$out .= ajax_autocompleter((string) $selected, $htmlname, DOL_URL_ROOT . ''/product/ajax/products.php'', $urloption, getDolGlobalInt(''PRODUIT_USE_SEARCH_TO_SELECT''), getDolGlobalInt("]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SHOW_DESCRIPTION_IN_TOOLTIP', 'bool', NULL, 'product', 'Appends the product description to its tooltip when the product has a non-empty description.', 'Checked in product/class/product.class.php:5817 alongside a non-empty description check. Only one occurrence; no admin UI.', 'When enabled, the product''s description field is included in hover tooltips, providing additional context inline.', 'Truthy string (description shown in tooltip) or empty/unset (description not included in tooltip).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:5817|check|if (!empty($this->description) && getDolGlobalString(''PRODUCT_SHOW_DESCRIPTION_IN_TOOLTIP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SHOW_DIMENSIONS_IN_COMBO', 'bool', NULL, 'core', 'Displays product dimensions alongside the product label in combobox selectors.', 'When set, core/class/html.form.class.php appends dimension information to the product label in the selector widget. Only one occurrence in the payload; no admin UI write; hidden setting.', 'Enabling this constant adds dimension data to product labels in selectors; disabling it (or leaving unset) shows only the standard label.', 'Non-empty (truthy) shows dimensions in product combo; empty or undefined hides them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3633|check|if (getDolGlobalString(''PRODUCT_SHOW_DIMENSIONS_IN_COMBO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SHOW_ORIGIN_IN_COMBO', 'bool', NULL, 'core', 'Displays the product''s country of origin alongside the product label in combobox selectors.', 'When set and an origin value is present ($outorigin), core/class/html.form.class.php appends the origin to the product label in three distinct selector rendering locations. No admin UI write; hidden setting.', 'Enabling this constant adds the origin country/region to product labels in selectors; disabling it (or leaving unset) shows only the standard label.', 'Non-empty (truthy) shows origin in product combo; empty or undefined hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3622|check|if ($outorigin && getDolGlobalString(''PRODUCT_SHOW_ORIGIN_IN_COMBO'')) {", "core/class/html.form.class.php:3686|check|if ($outorigin && getDolGlobalString(''PRODUCT_SHOW_ORIGIN_IN_COMBO'')) {", "core/class/html.form.class.php:3703|check|if ($outorigin && getDolGlobalString(''PRODUCT_SHOW_ORIGIN_IN_COMBO'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SHOW_SUB_SUB_PRODUCTS', 'bool', NULL, 'product', 'Controls whether sub-sub-products (nested composition levels) are shown on the product composition card.', 'Checked in product/composition/card.php:703. When not set, the code block that renders sub-sub-products is skipped.', 'Setting this constant enables display of nested product compositions beyond one level; leaving it unset limits the view to immediate sub-products.', 'Any non-empty value = show sub-sub-products; empty/unset = hide sub-sub-products', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (!getDolGlobalString(''PRODUCT_SHOW_SUB_SUB_PRODUCTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_SORT_BY_CATEGORY', 'string', NULL, 'core', 'Sorts the product list in comboboxes by product category rather than by the default order.', 'When set, core/class/html.form.class.php adds an ORDER BY clause on categorie_product_id. The value 1 sorts ascending; any other truthy value sorts descending. Three occurrences in the file. No admin UI write; hidden setting.', 'Setting this to 1 sorts products by category ascending in selectors; setting it to another truthy value sorts descending; leaving it unset uses the default sort order.', '1 = sort by category ASC; other non-empty value = sort by category DESC; empty or undefined = default order.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3193|check|if (getDolGlobalString(''PRODUCT_SORT_BY_CATEGORY'')) {", "core/class/html.form.class.php:3402|read|$sql .= \" ORDER BY categorie_product_id \".(getDolGlobalInt(''PRODUCT_SORT_BY_CATEGORY'') == 1 ? \"ASC\" : \"DESC\");", "core/class/html.form.class.php:3401|check|if (getDolGlobalString(''PRODUCT_SORT_BY_CATEGORY'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_STATS_WITH_PARENT_PROD_IF_INCDEC', 'string', NULL, 'product', 'Includes parent product statistics when a product''s stock is set to increment/decrement.', 'Checked in product/class/product.class.php at lines 3548, 3679, 3896, 4149, 4220, 4292. Also appears commented-out in product/stock/class/productlot.class.php:879, :954, :1027, indicating the feature is not yet active for lot-level stats.', 'When enabled, product usage statistics aggregate data from the parent product where applicable. The commented-out occurrences in productlot.class.php indicate lot-level aggregation is not yet implemented.', 'Truthy string (parent stats included) or empty/unset (no parent aggregation).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:3548|check|if (getDolGlobalString(''PRODUCT_STATS_WITH_PARENT_PROD_IF_INCDEC'')) {", "product/class/product.class.php:3679|check|if (getDolGlobalString(''PRODUCT_STATS_WITH_PARENT_PROD_IF_INCDEC'')) {", "product/stock/class/productlot.class.php:879  //          if (getDolGlobalString(''PRODUCT_STATS_WITH_PARENT_PROD_IF_INCDEC'')) {", "product/stock/class/productlot.class.php:954  //          if (getDolGlobalString(''PRODUCT_STATS_WITH_PARENT_PROD_IF_INCDEC'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_STOCK_LIST_SHOW_VIRTUAL_WITH_NO_PHYSICAL', 'bool', NULL, 'product', 'Controls whether virtual stock is shown for products that have no physical stock in the reassort list.', 'Checked in product/reassort.php:197; when absent or falsy, products with no physical stock do not display virtual stock.', 'Enabling shows virtual stock figures even when physical stock is zero or absent.', 'Truthy value to show virtual stock with no physical stock; absent or falsy to hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/reassort.php:197|check|if (!getDolGlobalString(''PRODUCT_STOCK_LIST_SHOW_VIRTUAL_WITH_NO_PHYSICAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_STOCK_LIST_SHOW_WITH_PRECALCULATED_DENORMALIZED_PHYSICAL_STOCK', 'bool', NULL, 'product', 'Switches the product stock reassort list to use pre-calculated denormalized physical stock values instead of real-time computation.', 'Checked at multiple points in product/reassort.php (lines 156, 169, 196, 268, 280, 291) to branch between denormalized and live stock data paths.', 'Enabling uses pre-calculated stock figures, which is faster but reflects a snapshot; disabling computes stock in real time.', 'Truthy value to use denormalized physical stock; absent or falsy to use real-time stock computation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/reassort.php:156|check|if (getDolGlobalString(''PRODUCT_STOCK_LIST_SHOW_WITH_PRECALCULATED_DENORMALIZED_PHYSICAL_STOCK'')) {", "product/reassort.php:169|check|if (!getDolGlobalString(''PRODUCT_STOCK_LIST_SHOW_WITH_PRECALCULATED_DENORMALIZED_PHYSICAL_STOCK'')) {", "product/reassort.php:268|check|if (getDolGlobalString(''PRODUCT_STOCK_LIST_SHOW_WITH_PRECALCULATED_DENORMALIZED_PHYSICAL_STOCK'')) {", "product/reassort.php:280|check|if (!getDolGlobalString(''PRODUCT_STOCK_LIST_SHOW_WITH_PRECALCULATED_DENORMALIZED_PHYSICAL_STOCK'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_CUSTOMER_PACKAGING', 'bool', NULL, 'product', 'Enables a customer-specific packaging quantity field on product prices.', 'Configured via product/admin/product.php:180. Checked in product/price.php:501, :1433, :1726, and compta/facture/class/facture.class.php:4339. A COMMENT notes it is not implemented/supported in certain customer price modes and is disabled there.', 'When enabled, a packaging field appears on customer price forms and is used during invoice line processing. Enabling it in unsupported customer price modes has no effect as the system disables it.', 'Empty/0 = customer packaging disabled; truthy = customer packaging enabled', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:1387  // In on of this customer price modes, option PRODUCT_USE_CUSTOMER_PACKAGING is not implemented/supported, so we disable it", "product/admin/product.php:180|write|$res = dolibarr_set_const($db, \"PRODUCT_USE_CUSTOMER_PACKAGING\", $value, ''chaine'', 0, '''', $conf->entity);", "product/price.php:298|read|$packaging = getDolGlobalString(''PRODUCT_USE_CUSTOMER_PACKAGING'') ? price2num(GETPOST(''packaging'', ''alpha''), ''MS'') : null;", "compta/facture/class/facture.class.php:4339|check|if (getDolGlobalString(''PRODUCT_USE_CUSTOMER_PACKAGING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_DEPRECATED_ASSEMBLY_AND_STOCK_KIT_TYPE', 'bool', NULL, 'product', 'Enables deprecated assembly and stock kit product type handling on the product composition card.', 'Checked in product/composition/card.php:479. When set, deprecated kit/assembly type code paths are executed instead of the current logic.', 'Enabling this constant reactivates legacy kit/assembly type behavior; it should only be set when migrating data that relies on the old type model.', 'Any non-empty value = use deprecated assembly/stock kit type; empty/unset = use current logic', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolGlobalString(''PRODUCT_USE_DEPRECATED_ASSEMBLY_AND_STOCK_KIT_TYPE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_LINK_PATH_FOR_PHOTO', 'bool', NULL, 'core', 'Enables use of a symbolic link path instead of the direct path for product photos.', 'Checked in core/class/commonobject.class.php:10172 and read in core/lib/functions.lib.php:3431. When set, photo URLs are constructed using the link path variant.', 'Setting this constant changes how product photo URLs are resolved, switching from direct file paths to link-based paths.', 'Non-zero = use link path for photo; 0 or unset = use direct path', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:10172|check|if (getDolGlobalInt(''PRODUCT_USE_LINK_PATH_FOR_PHOTO'')) {", "core/lib/functions.lib.php:3431|read|$useLinkPathPhoto = getDolGlobalInt(''PRODUCT_USE_LINK_PATH_FOR_PHOTO'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_OLD_PATH_FOR_PHOTO', 'bool', NULL, 'core', 'Forces product photo resolution to use the legacy directory path structure.', 'Checked in 32 locations across core/class/commonobject.class.php:10135, core/lib/functions.lib.php:8923, core/lib/files.lib.php:442, and numerous PDF modules. A TODO comment at core/lib/files.lib.php:443 notes this will be removed once deprecated.', 'Enabling this constant routes photo lookups to the old path structure instead of the current one; disabling it uses the modern path. Marked for future removal.', '0 (modern path, default) or 1 (legacy path)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/files.lib.php:443  // TODO Remove this when PRODUCT_USE_OLD_PATH_FOR_PHOTO will be removed", "core/class/commonobject.class.php:10161  /*if (getDolGlobalInt(''PRODUCT_USE_OLD_PATH_FOR_PHOTO''))    // For backward compatibility, we scan also old dirs", "core/lib/files.lib.php:442|check|if ($modulepart == ''produit'' && getDolGlobalInt(''PRODUCT_USE_OLD_PATH_FOR_PHOTO'')) {", "core/class/commonobject.class.php:10135|check|if (getDolGlobalInt(''PRODUCT_USE_OLD_PATH_FOR_PHOTO'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION', 'bool', NULL, 'product', 'Enables use of an additional ''other'' field in product translations.', 'Checked extensively in product/class/product.class.php (lines 2041, 2047, 2053, 2081, 2088, 2094) and product/traduction.php (lines 280, 352). The class comment at product/class/product.class.php:145 documents ''Product other fields PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION''. No admin UI.', 'When enabled, the product translation interface and logic include an additional field, extending the data stored per language.', 'Truthy string (other field active) or empty/unset (other field not used).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:145  * Product other fields PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION", "product/class/product.class.php:2041|check|if (getDolGlobalString(''PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION'')) {", "product/traduction.php:280|check|if (getDolGlobalString(''PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION'')) {", "product/traduction.php:352|check|if (getDolGlobalString(''PRODUCT_USE_OTHER_FIELD_IN_TRANSLATION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_SUB_COST_PRICES_IF_COST_PRICE_EMPTY', 'bool', NULL, 'fourn', 'When enabled, falls back to sub-component cost prices when a product''s primary cost price is empty.', 'Checked in fourn/ajax/getSupplierPrices.php at lines 134 and 153 when the resolved price is empty. No admin UI writes this constant.', 'When set, the AJAX supplier-price lookup will attempt to use sub-product cost prices as a fallback if the main cost price is empty.', 'Truthy (non-empty) to enable the fallback; empty/unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/ajax/getSupplierPrices.php:134|check|if (empty($price) && getDolGlobalString(''PRODUCT_USE_SUB_COST_PRICES_IF_COST_PRICE_EMPTY'')) {", "fourn/ajax/getSupplierPrices.php:153|check|if (empty($price) && getDolGlobalString(''PRODUCT_USE_SUB_COST_PRICES_IF_COST_PRICE_EMPTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_SUPPLIER_PACKAGING', 'bool', NULL, 'fourn', 'Enables the use of supplier-defined packaging quantities on supplier order lines.', 'Configured via product/admin/product.php:175 and checked in multiple supplier order and product class files (fourn/class/fournisseur.commande.class.php:720, :2157, :3213; fourn/class/fournisseur.orderline.class.php:220; fourn/class/fournisseur.product.class.php:563, :626; product/price_suppliers.php:612) to apply packaging logic.', 'When enabled, supplier order quantities are constrained or adjusted according to supplier packaging units; when disabled, no packaging logic is applied.', '0 or not set = supplier packaging not used; non-zero = supplier packaging quantities enforced on order lines.', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:175|write|$res = dolibarr_set_const($db, \"PRODUCT_USE_SUPPLIER_PACKAGING\", $value, ''chaine'', 0, '''', $conf->entity);", "fourn/class/fournisseur.commande.class.php:720|check|if (getDolGlobalString(''PRODUCT_USE_SUPPLIER_PACKAGING'')) {", "fourn/class/fournisseur.orderline.class.php:220|check|if (getDolGlobalInt(''PRODUCT_USE_SUPPLIER_PACKAGING'')) {", "fourn/class/fournisseur.product.class.php:563|check|if (getDolGlobalString(''PRODUCT_USE_SUPPLIER_PACKAGING'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUCT_USE_UNITS', 'bool', NULL, 'core', 'Enables the product unit-of-measure feature, showing a unit field on product lines throughout the application.', 'Configured via product/admin/product.php:772 (yes/no selector). A comment at product/admin/product.php:767 states: ''Kept as hidden feature only. PRODUCT_USE_UNITS is hidden for the moment. Because it seems to be a duplicated feature with already existing field to store unit of product''. Checked in 118 locations including reception/tpl/objectline_view.tpl.php:122, objectline_title.tpl.php:81, objectline_create.tpl.php:146, objectline_edit.tpl.php:139, and mrp/mo_production.php:1588 and :1657.', 'Enabling this constant shows the unit column on product order/reception/production lines; it is currently kept as a hidden feature because it duplicates existing unit storage functionality.', 'Non-empty/truthy = show product unit field on lines; empty/unset = hide (default, hidden feature)', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:767  /* Kept as hidden feature only. PRODUCT_USE_UNITS is hidden for the moment. Because it seems to be a duplicated feature with already existing field to store unit of product", "reception/tpl/objectline_view.tpl.php:122|check|if (getDolGlobalInt(''PRODUCT_USE_UNITS'')) {\t\t// For product, unit is shown only if option PRODUCT_USE_UNITS is on", "product/admin/product.php:772|read|print $form->selectyesno(\"activate_units\",$conf->global->PRODUCT_USE_UNITS,1);", "mrp/mo_production.php:1588|check|if (getDolGlobalInt(''PRODUCT_USE_UNITS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_ATTRIBUTES_HIDECHILD', 'bool', NULL, 'variants', 'Hides child variant products from product lists and selection forms when enabled.', 'Set via variants/admin/admin.php:53 and read at variants/admin/admin.php:95. Checked at accountancy/admin/productaccount.php:572 and core/class/html.form.class.php:3301 to suppress child variants from appearing in product selectors and accounting product lists.', 'When enabled, child product variants are hidden from product lists and form selectors. When disabled, all variants including children are shown.', 'Truthy value = child variants hidden; empty/unset = child variants shown.', 0, 0, 'variants/admin/admin.php|accountancy/admin/productaccount.php|variants/admin/admin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["variants/admin/admin.php:53|write|if (!dolibarr_set_const($db, ''PRODUIT_ATTRIBUTES_HIDECHILD'', $value, ''chaine'', 0, '''', $conf->entity)) {", "accountancy/admin/productaccount.php:572|check|if (isModEnabled(''variants'') && getDolGlobalInt(''PRODUIT_ATTRIBUTES_HIDECHILD'')) {", "core/class/html.form.class.php:3301|check|if (getDolGlobalString(''PRODUIT_ATTRIBUTES_HIDECHILD'')) {", "variants/admin/admin.php:95|read|print $form->selectyesno(\"PRODUIT_ATTRIBUTES_HIDECHILD\", getDolGlobalString(''PRODUIT_ATTRIBUTES_HIDECHILD''), 1).''</td></tr>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_ATTRIBUTES_HIDECHILD_BUT_ALLOW_SEARCH_IN_EAN13', 'bool', NULL, 'core', 'Allows searching for child product variants by EAN13 barcode even when child variants are otherwise hidden in the product selector.', 'In core/class/html.form.class.php, this constant enables a code path that includes child variant EAN13 barcodes in the search even when attribute-based child hiding is active. Only one occurrence; no admin UI write; hidden setting.', 'Enabling this constant exposes child product variants for EAN13-based searches despite the hide-children setting; disabling it (or leaving unset) fully hides child variants from the selector.', 'Non-empty (truthy) enables EAN13 search on hidden child variants; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3302|check|if (getDolGlobalString(''PRODUIT_ATTRIBUTES_HIDECHILD_BUT_ALLOW_SEARCH_IN_EAN13'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_ATTRIBUTES_SEPARATOR', 'string', NULL, 'variants', 'Defines the separator character used between attribute value references when building product variant reference codes.', 'Written by variants/admin/admin.php:58 and read in variants/admin/admin.php:99 (defaulting to ''_'') and variants/class/ProductCombination.class.php:862 where it is appended between the base product ref and the attribute value ref.', 'Changing this value alters the separator character between attribute codes in automatically generated variant product references.', 'Any string; default ''_''.', 0, 0, 'variants/admin/admin.php|variants/admin/admin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["variants/admin/admin.php:99|read|$separator = getDolGlobalString(''PRODUIT_ATTRIBUTES_SEPARATOR'', ''_'');", "variants/class/ProductCombination.class.php:862|read|$newproduct->ref .= getDolGlobalString(''PRODUIT_ATTRIBUTES_SEPARATOR'', ''_'') . $prodattrval->ref;", "variants/admin/admin.php:58|write|if (!dolibarr_set_const($db, ''PRODUIT_ATTRIBUTES_SEPARATOR'', GETPOST(''PRODUIT_ATTRIBUTES_SEPARATOR''), ''chaine'', 0, '''', $conf->entity)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_AUTOFILL_DESC', 'string', NULL, 'fourn', 'Controls whether the product description field is automatically filled from the product record when adding a line to a document.', 'Written via product/admin/product.php (line 166) and displayed as a selector (line 731). Checked across at least 12 files including supplier_proposal/card.php:886, fourn/commande/card.php:710, comm/propal/card.php:1560 (`if (getDolGlobalInt(''PRODUIT_AUTOFILL_DESC'') == 0)`). COMMENT: `@property {int} conf.PRODUIT_AUTOFILL_DESC`.', 'When set to 0, the description is not auto-filled from the product, allowing manual entry; other values enable automatic description filling.', 'Integer; 0 = do not auto-fill description; other values = auto-fill description from product record.', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:771  * @property {int} conf.PRODUIT_AUTOFILL_DESC", "supplier_proposal/card.php:886|check|if (getDolGlobalInt(''PRODUIT_AUTOFILL_DESC'') == 0) {", "fourn/commande/card.php:710|check|if (getDolGlobalInt(''PRODUIT_AUTOFILL_DESC'') == 0) {", "product/admin/product.php:166|write|$res = dolibarr_set_const($db, \"PRODUIT_AUTOFILL_DESC\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_CUSTOMER_PRICES', 'string', NULL, 'product', 'Enables per-customer price management for products, allowing different prices per third party.', 'When set, customer-specific price records are used in product price lookups and displayed in the product price tab. Configured via product/admin/product.php. It is mutually exclusive with PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES.', 'Enabling this activates a dedicated pricing tab per product and applies customer-specific prices in proposals and orders. Disabling it reverts to standard pricing logic.', 'Truthy = per-customer prices enabled; empty/falsy = disabled', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:613|check|if (getDolGlobalString(''PRODUIT_CUSTOMER_PRICES'')) {", "comm/propal/class/propal.class.php:1517|check|if ($update_prices === true && getDolGlobalString(''PRODUIT_CUSTOMER_PRICES'')) {", "product/price.php:1932|check|if (getDolGlobalString(''PRODUIT_CUSTOMER_PRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES'')) {", "product/admin/product.php:128|write|$res = dolibarr_set_const($db, ''PRODUIT_CUSTOMER_PRICES'', 0, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES', 'string', NULL, 'product', 'Enables both per-customer specific prices and multi-level price lists simultaneously for products.', 'Written via product/admin/product.php:129 (reset to 0) and checked in 66+ locations including product/admin/product.php, societe/class/societe.class.php:2245, and product/ajax/products.php:214. Often tested alongside PRODUIT_MULTIPRICES and PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES; also checked with PRODUIT_CUSTOMER_PRICES at ajax/products.php:214.', 'Enabling this constant activates a combined pricing mode supporting both customer-specific prices and price levels; it is reset to 0 when conflicting pricing modes are activated.', 'Any non-empty/non-zero value = enabled; ''0'' or empty = disabled', 0, 0, 'product/admin/product.php|product/admin/product.php|product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:129|write|$res = dolibarr_set_const($db, ''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES'', 0, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:628|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES''))", "product/ajax/products.php:214|check|if ((getDolGlobalString(''PRODUIT_CUSTOMER_PRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES'')) && !empty($socid)) {", "societe/class/societe.class.php:2245|check|if ((getDolGlobalString(''PRODUIT_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES''))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_CUSTOMER_PRICES_BY_QTY', 'string', NULL, 'product', 'Enables quantity-based customer pricing for products.', 'Managed via product/admin/product.php (read and write). Checked across product/price.php, core/lib/ajax.lib.php, product/ajax/products.php, and line templates to activate quantity-tier price lookups. Comment at core/tpl/objectline_create.tpl.php:1251 notes it works only if the product combo is not AJAX-based.', 'Enabling this activates quantity-break price tables for products, affecting price resolution in proposals, orders, and invoices. Disabling it hides quantity-based pricing controls.', '0 or not set = disabled; any truthy string = enabled', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/ajax.lib.php:222  // For customer price when PRODUIT_CUSTOMER_PRICES_BY_QTY is on", "core/tpl/objectline_create.tpl.php:1251  /* To process customer price per quantity (PRODUIT_CUSTOMER_PRICES_BY_QTY works only if combo product is not an ajax after x key pressed) */", "product/admin/product.php:130|write|$res = dolibarr_set_const($db, ''PRODUIT_CUSTOMER_PRICES_BY_QTY'', 0, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:610|check|if (getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_BY_QTY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES', 'string', NULL, 'product', 'Enables quantity-based pricing combined with multi-level price lists for products.', 'Written via product/admin/product.php:131 (reset to 0) and checked in 51+ locations including product/admin/product.php, societe/class/societe.class.php:2245, and product/ajax/products.php. Often tested alongside PRODUIT_MULTIPRICES and PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES to determine the active pricing mode. The JS comment at core/tpl/objectline_create.tpl.php:766 confirms the constant is exposed as a boolean config.', 'Enabling this constant activates a pricing mode that combines quantity-break prices with multi-level price lists; it is mutually exclusive with other pricing modes and is reset to 0 when conflicting modes are activated.', 'Any non-empty/non-zero value = enabled; ''0'' or empty = disabled', 0, 0, 'product/admin/product.php|product/admin/product.php|product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:766  * @property {boolean} conf.PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES", "product/admin/product.php:131|write|$res = dolibarr_set_const($db, ''PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES'', 0, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:628|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES''))", "societe/class/societe.class.php:2245|check|if ((getDolGlobalString(''PRODUIT_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_BY_QTY_MULTIPRICES'') || getDolGlobalString(''PRODUIT_CUSTOMER_PRICES_AND_MULTIPRICES''))"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_CUSTOMER_PRICES_PDF_REF_MODE', 'string', NULL, 'core', 'Selects the reference display mode for customer-specific prices in PDF documents.', 'Used in core/lib/pdf.lib.php:2155 inside a switch statement. The specific case values are not listed in the payload.', 'Changing this constant alters which product reference field is printed on PDFs for customer-specific pricing.', 'Integer or string switch-case values; exact values not documented in the available payload.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["switch ($conf->global->PRODUIT_CUSTOMER_PRICES_PDF_REF_MODE) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_DEFAULT_BARCODE_TYPE', 'string', NULL, 'product', 'Stores the default barcode type (format) used when generating barcodes for products.', 'Written by admin/barcode.php:97 and displayed as a selector at admin/barcode.php:537. Read in core/modules/barcode/mod_barcode_product_standard.php:192 to determine the barcode type for automatic numbering, and consulted in barcode/printsheet.php:130 and product/card.php:1619 when no explicit type is set on the record.', 'Setting this value changes the barcode format applied to products when no per-product override exists; clearing it disables the default.', 'Stores a barcode type ID (integer as string) referencing the selected format; empty = no default.', 0, 0, 'admin/barcode.php|admin/barcode.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/barcode.php:97|write|$res = dolibarr_set_const($db, \"PRODUIT_DEFAULT_BARCODE_TYPE\", $coder_id, ''chaine'', 0, '''', $conf->entity);", "core/modules/barcode/mod_barcode_product_standard.php:192|read|$type = getDolGlobalString(''PRODUIT_DEFAULT_BARCODE_TYPE'');", "barcode/printsheet.php:130|check|if (empty($fk_barcode_type) && getDolGlobalString(''PRODUIT_DEFAULT_BARCODE_TYPE'')) {", "product/card.php:1619|check|if (empty($fk_barcode_type) && getDolGlobalString(''PRODUIT_DEFAULT_BARCODE_TYPE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_DESC_IN_FORM', 'string', NULL, 'core', 'Controls whether and how product descriptions are displayed in document line-item forms.', 'Written by product/admin/product.php:154 and read as an integer in multiple files including main.inc.php:1260, contrat/card.php:1716, and core/tpl/objectline_view.tpl.php:190. The value is also mirrored to PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE in core/class/conf.class.php:1048.', 'Changing this value alters whether product descriptions appear inline on forms such as contract lines and order lines.', '0 = description not shown; 1 = description shown in form', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:154|write|$res = dolibarr_set_const($db, \"PRODUIT_DESC_IN_FORM\", $value, ''chaine'', 0, '''', $conf->entity);", "main.inc.php:1260|check|if (getDolGlobalInt(''PRODUIT_DESC_IN_FORM'') == 1) {", "contrat/card.php:1716|check|if (!getDolGlobalInt(''PRODUIT_DESC_IN_FORM'')) {", "core/tpl/objectline_view.tpl.php:190|check|if (!getDolGlobalInt(''PRODUIT_DESC_IN_FORM'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE', 'string', NULL, 'core', 'Controls whether the product description is displayed in document line forms, adapting to the device type.', 'Set initially in core/class/conf.class.php:1047 and checked in 24 locations including reception/card.php:1749, delivery/card.php:615, contrat/card.php:1724, core/tpl/objectline_view.tpl.php:272, and admin/fckeditor.php:110. Configured via admin/fckeditor.php.', 'Enabling this constant causes the product description to be shown inline in document line forms; disabling it hides the description from those forms.', 'Integer/bool (truthy=description shown in form, 0/empty=hidden)', 0, 0, 'admin/fckeditor.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Set PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE, may be modified later according to browser", "reception/card.php:1749|check|if (getDolGlobalInt(''PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE'')) {", "core/tpl/objectline_view.tpl.php:272|check|if ($line->fk_product > 0 && getDolGlobalInt(''PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE'')) {", "admin/fckeditor.php:110|check|if ($const == ''PRODUCTDESC'' && getDolGlobalInt(''PRODUIT_DESC_IN_FORM_ACCORDING_TO_DEVICE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_FOURN_TEXTS', 'string', NULL, 'product', 'Enables use of supplier-specific product descriptions on supplier documents instead of the standard product description.', 'Written via product/admin/product.php (line 170). Checked across 8 files including supplier_proposal/card.php:882 (`if (!empty($productsupplier->desc_supplier) && getDolGlobalString(''PRODUIT_FOURN_TEXTS''))`), fourn/commande/card.php:706, fourn/facture/card.php:1775, and core/class/html.form.class.php (lines 4030, 4090).', 'Enabling this setting causes supplier-specific descriptions to replace standard product descriptions on supplier proposals, orders, and invoices.', 'Truthy string (non-empty) = use supplier description when available; empty/not set = always use standard product description.', 0, 0, 'product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:882|check|if (!empty($productsupplier->desc_supplier) && getDolGlobalString(''PRODUIT_FOURN_TEXTS'')) {", "fourn/commande/card.php:706|check|if (!empty($productsupplier->desc_supplier) && getDolGlobalString(''PRODUIT_FOURN_TEXTS'')) {", "fourn/facture/card.php:1775|check|if (!empty($productsupplier->desc_supplier) && getDolGlobalString(''PRODUIT_FOURN_TEXTS'')) {", "product/admin/product.php:170|write|$res = dolibarr_set_const($db, \"PRODUIT_FOURN_TEXTS\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_LIMIT_SIZE', 'string', NULL, 'product', 'Sets the maximum number of products returned in product selection dropdowns.', 'Defines the numeric limit passed to select_produits() and select_produits_list() calls across line-creation templates and Ajax product search. Default value of 1000 is set in core/class/conf.class.php when the constant is not defined. Configured via product/admin/product.php.', 'Reducing this value limits the number of products loaded in selectors, which can improve performance on large catalogues. Setting it to 0 or a non-positive value bypasses the limit in stock transfer views.', 'Positive integer = maximum products returned (default 1000); 0 or negative = no cap applied in some contexts', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:1042  // Set PRODUIT_LIMIT_SIZE if never defined", "product/admin/product.php:719|read|print ''<td class=\"right\"><input size=\"3\" type=\"text\" class=\"flat\" name=\"value_PRODUIT_LIMIT_SIZE\" value=\"'' . getDolGlobalString(''PRODUIT_LIMIT_SIZE'', 1000).''\">''", "product/stock/massstockmove.php:700|check|if (getDolGlobalInt(''PRODUIT_LIMIT_SIZE'') <= 0) {", "product/ajax/products.php:339|read|$arrayresult = $form->select_produits_list(0, $htmlname, $type, getDolGlobalInt(''PRODUIT_LIMIT_SIZE'', 1000), ..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_MULTIPRICES', 'string', NULL, 'product', 'Enables the multi-price level feature, allowing products to have multiple price lists (one per customer segment).', 'Checked in 124 locations across product, variant, and sales pages. A comment at product/class/api_products.class.php:381 states ''if PRODUIT_MULTIPRICES is set (1 price per segment)''. Admin logic at product/admin/product.php:127 resets it to 0 when deactivated, and product/admin/product.php:87 auto-sets PRODUIT_MULTIPRICES_LIMIT to 5 when activated without a limit.', 'Enabling this constant activates the multi-price level system, requiring each product to maintain prices per defined level; disabling reverts to a single-price model.', 'Non-empty = multi-price levels active; 0 or unset = single price per product.', 0, 0, 'product/admin/product.php|product/admin/product.php|product/admin/product.php|product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* if PRODUIT_MULTIPRICES is set (1 price per segment)", "* @param bool|bool[]               $price_var_percent      Is the price variation value a relative variation (in %)? (it is an array if global constant \"PRODUIT_MULTIPRICES\" is on)", "product/admin/product.php:127|write|$res = dolibarr_set_const($db, ''PRODUIT_MULTIPRICES'', 0, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:87|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES'') && !getDolGlobalString(''PRODUIT_MULTIPRICES_LIMIT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_MULTIPRICES_ALLOW_AUTOCALC_PRICELEVEL', 'bool', NULL, 'core', 'Enables automatic price-level calculation rules for products using the multi-price feature.', 'Checked in core/lib/product.lib.php:403 (requires PRODUIT_MULTIPRICES also set) and product/price.php:1787. The comment in product/admin/price_rules.php:21 states: ''This page is a tab in the setup of module Product if option PRODUIT_MULTIPRICES_ALLOW_AUTOCALC_PRICELEVEL is set.''', 'Enabling this constant activates price-rule auto-calculation for multi-price levels and adds a price rules configuration tab in the product module setup.', 'Any non-empty value = enable auto-calculation of multi-price levels; empty/unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["This page is a tab in the setup of module Product if option PRODUIT_MULTIPRICES_ALLOW_AUTOCALC_PRICELEVEL is set.", "if (getDolGlobalString(''PRODUIT_MULTIPRICES'') && getDolGlobalString(''PRODUIT_MULTIPRICES_ALLOW_AUTOCALC_PRICELEVEL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_MULTIPRICES_LIMIT', 'string', NULL, 'product', 'Sets the number of price levels available when the multi-price feature is enabled.', 'Written by product/admin/product.php:88 (auto-set to 5 when PRODUIT_MULTIPRICES is enabled without a limit) and :117 (user-defined value). Read in product/admin/price_rules.php:59 and :159 as $produit_multiprices_limit, and in product/price.php:95 where it is reset to 5 when not set.', 'Changing this value controls how many distinct price levels are available per product when multi-pricing is active.', 'Integer string; default 5 when auto-set. Represents the count of price levels.', 0, 0, 'product/admin/product.php|product/admin/product.php|product/admin/price_rules.php|product/admin/price_rules.php|product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:88|write|dolibarr_set_const($db, ''PRODUIT_MULTIPRICES_LIMIT'', 5, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:117|write|$res = dolibarr_set_const($db, \"PRODUIT_MULTIPRICES_LIMIT\", GETPOST(''value_PRODUIT_MULTIPRICES_LIMIT''), ''chaine'', 0, '''', $conf->entity);", "product/admin/price_rules.php:59|read|$produit_multiprices_limit = getDolGlobalInt(''PRODUIT_MULTIPRICES_LIMIT'');", "* @param \tint \t$clean \t\tLevels of PRODUIT_MULTIPRICES_LIMIT"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_MULTIPRICES_USE_VAT_PER_LEVEL', 'bool', NULL, 'product', 'Enables per-price-level VAT rates when multi-price levels are active; kept for backward compatibility only.', 'Checked in product/price.php:1087 and product/price.php:1129 with the explicit comment ''using this option is a bug. kept for backward compatibility''. Also checked in comm/propal/class/propal.class.php:1536 and product/class/product.class.php:2443. Affects which VAT fields are stored per price level.', 'Enabling this activates a legacy behaviour where each multi-price level can carry its own VAT rate, which is documented in the code as a bug kept only for backward compatibility.', '0 or not set = single VAT rate across all price levels; 1 = per-level VAT (legacy/deprecated behavior)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/price.php:1087|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES_USE_VAT_PER_LEVEL'')) {  // using this option is a bug. kept for backward compatibility", "product/class/product.class.php:3195  // Next two fields are used only if PRODUIT_MULTIPRICES_USE_VAT_PER_LEVEL is on", "comm/propal/class/propal.class.php:1536|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES_USE_VAT_PER_LEVEL'')) {  // using this option is a bug. kept for backward compatibility", "product/class/product.class.php:2443|check|if (getDolGlobalString(''PRODUIT_MULTIPRICES_USE_VAT_PER_LEVEL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_PDF_MERGE_PROPAL', 'string', NULL, 'product', 'When enabled, merges the product data sheet PDF into proposal (quote) PDF documents.', 'COMMENTS state: ''Kept as hidden feature only. PRODUIT_PDF_MERGE_PROPAL can be added manually. Still did not understand how this feature works.'' Written via product/admin/product.php:160 and read/checked in product/document.php:42/143/307 and core/modules/propale/doc/pdf_cyan.modules.php:967 and pdf_azur.modules.php:796.', 'Enabling this constant causes proposal PDF generation to append product data sheet PDFs; behavior is noted as a hidden feature that is not fully understood per the source comments.', '1 or any truthy value = merge product PDF into proposal PDF; 0 or unset = no merge.', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["/* Kept as hidden feature only. PRODUIT_PDF_MERGE_PROPAL can be added manually. Still did not understand how this feature works.", "product/admin/product.php:160|write|$res = dolibarr_set_const($db, \"PRODUIT_PDF_MERGE_PROPAL\", $value, ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:967|check|if (getDolGlobalString(''PRODUIT_PDF_MERGE_PROPAL'')) {", "product/document.php:143|check|if (getDolGlobalString(''PRODUIT_PDF_MERGE_PROPAL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_RESTRICT_STOCK_INCDEC_IF_SUBPRODUCTS_ENABLED', 'bool', NULL, 'admin', 'Restricts manual stock increase/decrease operations when a product has sub-products (bill of materials) enabled.', 'When enabled, prevents direct stock movements on products that have sub-product components. Configured via admin/stock.php (ADMIN_UI). Only one occurrence found at admin/stock.php:235.', 'Enabling this prevents direct stock adjustments on composite products, forcing stock changes to go through sub-product movements instead.', '0 or empty = stock inc/dec allowed regardless of sub-products; 1 = stock inc/dec restricted when sub-products are enabled', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/stock.php:235|check|if (getDolGlobalString(''PRODUIT_RESTRICT_STOCK_INCDEC_IF_SUBPRODUCTS_ENABLED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_SOUSPRODUITS', 'string', NULL, 'expedition', 'Enables the sub-products (kit/assembly) feature, allowing products to have child components.', 'Checked across 31+ occurrences including admin/stock.php:232, compta/facture/class/facture.class.php:4310, mrp/class/mo.class.php:328, and product/stock/class/mouvementstock.class.php:672. When enabled, sub-product stock movements are triggered alongside parent product operations.', 'Enabling this activates kit/assembly logic throughout invoicing, stock movements, and MRP; disabling it suppresses sub-product-related processing across these modules.', 'Empty/0 = sub-products disabled; truthy = sub-products enabled', 0, 0, 'admin/stock.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/admin/product.php:150  /*$value = GETPOST(''PRODUIT_SOUSPRODUITS'', ''alpha'');", "compta/facture/class/facture.class.php:4310|check|if (getDolGlobalInt(''PRODUIT_SOUSPRODUITS'')) {", "product/stock/class/mouvementstock.class.php:672|check|if (!$error && getDolGlobalString(''PRODUIT_SOUSPRODUITS'') && !getDolGlobalString(''PRODUIT_SOUSPRODUITS_ALWAYS_DISABLE_CHILDREN_STOCK_MOVE'')", "mrp/class/mo.class.php:328|check|if (getDolGlobalString(''PRODUIT_SOUSPRODUITS'') && !getDolGlobalString(''ALLOW_USE_KITS_INTO_BOM_AND_MO'') && $this->fk_product > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_SOUSPRODUITS_ALSO_ENABLE_PARENT_STOCK_MOVE', 'bool', NULL, 'expedition', 'Enables stock movements on the parent product (kit) in addition to its sub-products.', 'Checked in 10 occurrences across expedition/class/expedition.class.php, product/stock/product.php, product/stock/class/mouvementstock.class.php, and expedition/dispatch.php. By default, kit parents have stock moves disabled; this constant re-enables them with the inline comment ''For kit parent, we disable stock move, ex''.', 'Enabling this constant causes stock movements to be recorded for the parent kit product as well as for its children; disabling it restricts movements to sub-products only.', 'Non-zero = parent stock move enabled; 0 or unset = parent stock move disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["expedition/class/expedition.class.php:1822|check|if ($can_update_stock && (empty($obj->iskit) || getDolGlobalInt(''PRODUIT_SOUSPRODUITS_ALSO_ENABLE_PARENT_STOCK_MOVE'')) && !empty($obj->incdec)) {", "product/stock/class/mouvementstock.class.php:337|check|if ($product->isStockManaged() && ($productChildrenNb == 0 || getDolGlobalInt(''PRODUIT_SOUSPRODUITS_ALSO_ENABLE_PARENT_STOCK_MOVE''))) { // For kit parent, we disable stock move, ex", "product/stock/product.php:797|check|if (!$iskit || getDolGlobalInt(''PRODUIT_SOUSPRODUITS_ALSO_ENABLE_PARENT_STOCK_MOVE'')) {", "expedition/dispatch.php:916|check|if (!getDolGlobalInt(''PRODUIT_SOUSPRODUITS_ALSO_ENABLE_PARENT_STOCK_MOVE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_SOUSPRODUITS_ALWAYS_DISABLE_CHILDREN_STOCK_MOVE', 'bool', NULL, 'product', 'Prevents child sub-product stock movements from being triggered automatically when a parent product stock move occurs.', 'In product/stock/class/mouvementstock.class.php, child stock moves are only executed when PRODUIT_SOUSPRODUITS is enabled and this constant is not set and the local $disablestockchangeforsubproduc flag is empty. Setting this constant suppresses all automatic child stock moves. No admin UI; hidden setting.', 'Enabling this constant disables automatic stock movements for sub-products when a parent product is moved; disabling it allows child stock moves to proceed.', 'Non-empty (truthy) disables child stock moves; empty or undefined allows them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/class/mouvementstock.class.php:672|check|if (!$error && getDolGlobalString(''PRODUIT_SOUSPRODUITS'') && !getDolGlobalString(''PRODUIT_SOUSPRODUITS_ALWAYS_DISABLE_CHILDREN_STOCK_MOVE'') && empty($disablestockchangeforsubproduc"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE', 'string', NULL, 'core', 'Enables display of product labels and descriptions in the language of the associated third party rather than the interface language.', 'Written via product/admin/product.php (line 157) and shown as a yes/no selector (line 782). Checked across at least 36 files in conjunction with `MAIN_MULTILANGS` (e.g. supplier_proposal/card.php:864: `if (getDolGlobalInt(''MAIN_MULTILANGS'') && getDolGlobalString(''PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE''))`). COMMENT: `@property {boolean} conf.PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE`.', 'Enabling this setting causes product texts to be fetched and displayed in the third party''s configured language when multilingual mode is active.', '0 or empty = product texts shown in interface language; 1 = product texts shown in third-party language (requires MAIN_MULTILANGS).', 0, 0, 'product/admin/product.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_create.tpl.php:770  * @property {boolean} conf.PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE", "supplier_proposal/card.php:864|check|if (getDolGlobalInt(''MAIN_MULTILANGS'') && getDolGlobalString(''PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE'')) {", "product/admin/product.php:157|write|$res = dolibarr_set_const($db, \"PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE\", $value, ''chaine'', 0, '''', $conf->entity);", "product/admin/product.php:782|read|print $form->selectyesno(\"activate_viewProdTextsInThirdpartyLanguage\", getDolGlobalInt(''PRODUIT_TEXTS_IN_THIRDPARTY_LANGUAGE''), 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PRODUIT_USE_SEARCH_TO_SELECT', 'bool', NULL, 'core', 'Controls whether an AJAX search-to-select widget is used instead of a dropdown list when selecting products/services.', 'Written via product/admin/product.php:163 and read/checked extensively across admin/system/perf.php, core/class/html.form.class.php (lines 2835, 2951, 3451, 3961), and product/admin/product.php:711. The perf page displays recommendations based on the product count and this setting.', 'Enabling this constant replaces the full product dropdown with an AJAX autocomplete field, which is strongly recommended for large product catalogs to avoid performance issues.', 'Integer value: 0 = dropdown list; 1 = search-to-select with AJAX (threshold-based); higher values adjust search behavior. Configured via product admin UI.', 0, 0, 'product/admin/product.php|admin/system/perf.php|admin/system/perf.php|product/admin/product.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/system/perf.php:544|check|if (!getDolGlobalString(''PRODUIT_USE_SEARCH_TO_SELECT'')) {", "product/admin/product.php:163|write|$res = dolibarr_set_const($db, \"PRODUIT_USE_SEARCH_TO_SELECT\", $value, ''chaine'', 0, '''', $conf->entity);", "core/class/html.form.class.php:2835|check|if (!empty($conf->use_javascript_ajax) && getDolGlobalString(''PRODUIT_USE_SEARCH_TO_SELECT'')) {", "core/class/html.form.class.php:2951|read|$out .= ajax_autocompleter((string) $selected, $htmlname, DOL_URL_ROOT . ''/product/ajax/products.php'', $urloption, getDolGlobalInt(''PRODUIT_USE_SEARCH_TO_SELECT''), getDolGlobalInt("]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROFORMA_PDF_WITH_SUFFIX', 'string', NULL, 'core', 'Stores a suffix string appended to the filename of proforma PDF documents generated from orders.', 'Checked in core/modules/commande/doc/pdf_einstein.modules.php:227-228. When the requested model is ''proforma'' and this constant is set, its value is used as the $suffix variable for the generated PDF filename.', 'Setting a non-empty value causes proforma PDFs to include the specified suffix in their filename. Clearing it results in no suffix being added.', 'Any non-empty string = suffix appended to proforma PDF filename; empty/unset = no suffix.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_einstein.modules.php:227|if (getDolGlobalString(''PROFORMA_PDF_WITH_SUFFIX'')) {", "pdf_einstein.modules.php:228|$suffix = (GETPOST(''model'') == ''proforma'') ? getDolGlobalString(''PROFORMA_PDF_WITH_SUFFIX'') : '''';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ADDON', 'string', NULL, 'projet', 'Selects the numbering module used to generate project reference numbers.', 'Written by projet/admin/project.php:229 and used in 9 locations. projet/class/project.class.php:1796 and projet/card.php:683 load the module name with default ''mod_project_simple''. emailcollector/class/emailcollector.class.php:3514 and projet/class/api_projects.class.php:355 also read it for ref generation.', 'Changing this value switches the project reference numbering algorithm to the specified module; using an invalid module name prevents reference generation.', 'Module class name string, e.g. ''mod_project_simple''; default ''mod_project_simple''.', 0, 0, 'projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/admin/project.php:229|write|dolibarr_set_const($db, \"PROJECT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "projet/class/project.class.php:1796|read|$obj = getDolGlobalString(''PROJECT_ADDON'', ''mod_project_simple'');", "projet/card.php:683|read|$modele = getDolGlobalString(''PROJECT_ADDON'', ''mod_project_simple'');", "core/modules/modProjet.class.php:323|read|''class'' => getDolGlobalString(''PROJECT_ADDON'', ''mod_project_simple''),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ADDON_PDF', 'string', NULL, 'projet', 'Selects the PDF document generation template used for project documents.', 'A comment at projet/class/project.class.php:2106 states ''Create an intervention document on disk using template defined into PROJECT_ADDON_PDF''. Written by projet/admin/project.php:200 (set) and :188/:209 (delete). Read in projet/class/project.class.php:2126-2127 to load the PDF model; core/tpl/card_presend.tpl.php:130 disables PDF sending when no template is set.', 'Setting this constant designates the PDF template for project document generation; clearing it disables PDF generation for projects.', 'PDF template name string; empty = no PDF template selected.', 0, 0, 'projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["*  Create an intervention document on disk using template defined into PROJECT_ADDON_PDF", "projet/admin/project.php:200|write|dolibarr_set_const($db, \"PROJECT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity);", "projet/class/project.class.php:2126|read|} elseif (getDolGlobalString(''PROJECT_ADDON_PDF'')) {", "core/tpl/card_presend.tpl.php:130|check|if ($object->element == ''project'' && !getDolGlobalString(''PROJECT_ADDON_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) for ODT document templates used by the generic project ODT module.', 'Read in doc_generic_project_odt.modules.php at line 413 (split into list of dirs), line 440 (display in UI), and line 448 (existence check). No admin UI write via dolibarr_set_const is present in the payload.', 'Changing this path redirects the module to a different set of ODT template directories; an invalid path disables ODT template loading.', 'Comma-separated directory path(s); empty = no custom ODT path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["doc_generic_project_odt.modules.php:413|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''PROJECT_ADDON_PDF_ODT_PATH''))));", "doc_generic_project_odt.modules.php:440|read|$texte .= getDolGlobalString(''PROJECT_ADDON_PDF_ODT_PATH'');", "doc_generic_project_odt.modules.php:448|check|if (getDolGlobalString(''PROJECT_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ADD_SUBTOTAL_LINES', 'string', NULL, 'projet', 'Controls whether subtotal lines are added to project-related document output.', 'When this constant is not set, a specific code branch in projet/element.php:1971 is executed, indicating the subtotal line logic is skipped when the constant is empty.', 'Setting this constant enables the inclusion of subtotal lines in the relevant project output; leaving it empty disables that branch.', 'Empty/0 = subtotal lines not added; non-empty = subtotal lines added.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:1971|check|if (!getDolGlobalString(''PROJECT_ADD_SUBTOTAL_LINES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ALLOW_COMMENT_ON_PROJECT', 'bool', NULL, 'projet', 'Enables the comments section on project-level pages when set to a truthy value.', 'When enabled, the project card and task sub-pages fetch and display comments on the project object itself. Checked at core/lib/project.lib.php:331 and projet/contact.php:333 among 27 total occurrences. Several occurrences are commented-out, indicating the feature was partially rolled back in some modules.', 'When disabled, no comment blocks are shown on project-level views. When enabled, comments are loaded and displayed for the project object across task sub-pages.', 'Truthy value (non-empty string) = project comments shown; empty/unset = project comments hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/contact.php:333|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_PROJECT'') && empty($object->comments)) {", "core/lib/project.lib.php:331|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_PROJECT'')) {", "projet/tasks/task.php:324|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_PROJECT'') && method_exists($projectstatic, ''fetchComments'') && empty($projectstatic->comments)) {", "// if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_PROJECT'') && method_exists($object, ''fetchComments'') && empty($object->comments)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ALLOW_COMMENT_ON_TASK', 'bool', NULL, 'projet', 'Enables the comments section on project task pages when set to a truthy value.', 'When enabled, task sub-pages (task.php, contact.php, time.php, note.php, document.php) fetch and display comments on tasks. Checked at core/lib/project.lib.php:481 and across multiple projet/tasks/ pages.', 'When disabled (or not set), the comments section is not rendered on any task sub-page. When enabled, comment blocks appear on all task-related views.', 'Truthy value (non-empty string) = comments shown; empty/unset = comments hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/project.lib.php:481|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_TASK'')) {", "projet/tasks/task.php:320|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_TASK'') && empty($object->comments)) {", "projet/tasks/time.php:946|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_TASK'') && empty($object->comments)) {", "projet/tasks/note.php:65|check|if (getDolGlobalString(''PROJECT_ALLOW_COMMENT_ON_TASK'') && method_exists($object, ''fetchComments'') && empty($object->comments)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ALLOW_SPLIT_TIMESPENT', 'bool', NULL, 'projet', 'Allows splitting a time-spent entry into multiple sub-entries on the time tracking page.', 'Checked at projet/tasks/time.php:2194 and projet/tasks/time.php:2582. Only 2 occurrences in 1 file.', 'When unset, the split action for time entries is not available. When set, users can split a single time-spent record.', 'Truthy value = split time-spent entries allowed; empty/unset = split not available.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/time.php:2194|check|if (getDolGlobalString(''PROJECT_ALLOW_SPLIT_TIMESPENT'')) {", "projet/tasks/time.php:2582|check|if (getDolGlobalString(''PROJECT_ALLOW_SPLIT_TIMESPENT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY', 'bool', NULL, 'core', 'Controls which third-party companies'' projects can be linked to a document — empty means only the document''s own third-party, ''all'' means all companies, or a comma-separated list of third-party IDs.', 'When empty, only projects belonging to the document''s third-party are shown. When set to ''all'' or a list of IDs, cross-company project linking is permitted. Logic in core/class/html.formprojet.class.php:198 reads: ''PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY is "all" or a list of ids separated by coma''. Written via projet/admin/project.php:244 with comment ''Allow to disable this configuration if empty value''.', 'Setting to ''all'' enables linking projects from any third-party; setting to a comma-separated list of IDs restricts linking to those specific third parties; leaving empty restricts linking to the document''s own third-party.', 'Empty = only document''s own third-party projects shown; ''all'' = all companies'' projects available; comma-separated integer IDs = projects from those specific third-party IDs are also available.', 0, 0, 'projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.formprojet.class.php:198|read|} elseif (getDolGlobalString(''PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'') != ''all'') {    // PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY is ''all'' or a list of ids separated by coma.", "projet/admin/project.php:244|write|dolibarr_set_const($db, ''PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'', $projectToSelect, ''chaine'', 0, '''', $conf->entity); //Allow to disable this configuration if empty value", "core/class/html.formprojet.class.php:196|check|if (!getDolGlobalString(''PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'')) {", "core/class/html.formprojet.class.php:259|read|} elseif (!getDolGlobalString(''PROJECT_ALLOW_TO_LINK_FROM_OTHER_COMPANY'') && $socid > 0 && (!empty($obj->fk_soc) && $obj->fk_soc != $socid)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ALWAYS_DISCARD_CLOSED_PROJECTS_IN_SELECT', 'string', NULL, 'core', 'Always excludes closed projects from project selection dropdowns regardless of other filter settings.', 'When set to a non-zero integer, closed projects are filtered out in core/class/html.formprojet.class.php:175. No admin UI manages this constant.', 'Enabling this ensures closed projects never appear in selection lists; disabling it allows the default inclusion logic to apply.', 'Non-zero integer value enables permanent exclusion of closed projects.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formprojet.class.php:175|check|if (getDolGlobalInt(''PROJECT_ALWAYS_DISCARD_CLOSED_PROJECTS_IN_SELECT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_BILL_TIME_SPENT', 'string', NULL, 'projet', 'Enables billing of time spent on project tasks, showing invoicing-related columns and actions.', 'When set alongside PROJECT_HIDE_TASKS being unset, time-tracking pages (projet/tasks/time.php, task.php, contact.php, note.php) display invoicing columns and actions for time entries. Referenced in at least 24 occurrences across the projet module.', 'Without this constant set, billing columns and actions for time entries are not displayed. Enabling it activates time-invoicing workflows on task pages.', 'Truthy value (non-empty string) = billing of time spent enabled; empty/unset = billing disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/time.php:1890|check|if (!getDolGlobalString(''PROJECT_HIDE_TASKS'') && getDolGlobalString(''PROJECT_BILL_TIME_SPENT'')) {", "projet/tasks/task.php:388|check|if (!getDolGlobalString(''PROJECT_HIDE_TASKS'') && getDolGlobalString(''PROJECT_BILL_TIME_SPENT'')) {", "projet/tasks/contact.php:257|check|if (!getDolGlobalString(''PROJECT_HIDE_TASKS'') && getDolGlobalString(''PROJECT_BILL_TIME_SPENT'')) {", "projet/tasks/note.php:195|check|if (!getDolGlobalString(''PROJECT_HIDE_TASKS'') && getDolGlobalString(''PROJECT_BILL_TIME_SPENT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CAN_ALWAYS_LINK_TO_ALL_CUSTOMERS', 'string', NULL, 'compta', 'When enabled, allows a project to be linked to any customer when selecting it on invoices, proposals, and orders, regardless of the current third-party context.', 'Checked in compta/facture/card.php:4571, comm/propal/card.php:2537, and commande/card.php:2456 in the project selector call. Without this constant, the project list is filtered to the current third-party.', 'Enabling this constant removes the third-party filter from the project selector on invoice, proposal, and order forms.', '0 or unset = project selector filtered to current third-party; truthy = all projects shown regardless of third-party.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4571|read|print $formproject->select_projects((($socid > 0 && !getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_CUSTOMERS'')) ? $socid : -1), (string) $projectid, ''projectid'', 0, 0, 1, 1, 0", "comm/propal/card.php:2537|read|print img_picto('''', ''project'', ''class=\"pictofixedwidth\"'').$formproject->select_projects((($soc->id > 0 && !getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_CUSTOMERS'')) ? $soc->i", "commande/card.php:2456|read|print img_picto('''', ''project'', ''class=\"pictofixedwidth\"'').$formproject->select_projects((($soc->id > 0  && !getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_CUSTOMERS'')) ? $soc->"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CAN_ALWAYS_LINK_TO_ALL_SUPPLIERS', 'string', NULL, 'fourn', 'Allows linking a project to any supplier regardless of the document''s associated third-party.', 'When set, the socid filter passed to form_project is replaced with the object''s own socid (or -1 to show all), as seen in supplier_proposal/card.php:1671 and multiple info/note/document pages. Without it, only suppliers matching the document''s third-party are shown. Referenced across 29 occurrences in multiple supplier-related files.', 'Enabling this setting allows projects from any supplier to be linked to supplier proposals and related documents, bypassing the third-party filter.', 'Empty/0 = only projects linked to the document''s supplier are shown; non-empty = all supplier projects are available for linking.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1671|read|} elseif ((int) $soc->id == 0 || getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_SUPPLIERS'')) {", "supplier_proposal/info.php:109|read|$morehtmlref .= $form->form_project(..., (getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_SUPPLIERS'') ? $object->socid : -1), ...)", "projet/card.php:845|check|if (!getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_SUPPLIERS'') && empty($conf->dol_use_jmobile)) {", "supplier_proposal/contact.php:174|read|$morehtmlref .= $form->form_project(..., (!getDolGlobalString(''PROJECT_CAN_ALWAYS_LINK_TO_ALL_SUPPLIERS'') ? $object->socid : -1), ...)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CAN_OVERWRITE_TIMESTPENT_HOURLY_RATE_WITH_LASTONE', 'string', NULL, 'projet', 'Allows the last entered hourly rate for time spent to overwrite the previously stored rate on a project task.', 'When enabled, the hourly rate (THM) on time-spent records is overwritten with the most recently entered value. Checked in projet/element.php at lines 1744 and 1812.', 'Enabling this setting causes the system to replace the stored hourly rate on time-spent entries with the latest one provided.', 'Empty/0 = disabled (existing rate preserved); non-empty = enabled (rate overwritten with latest value).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:1744|check|if (getDolGlobalString(''PROJECT_CAN_OVERWRITE_TIMESTPENT_HOURLY_RATE_WITH_LASTONE'')) {", "projet/element.php:1812|check|if (getDolGlobalString(''PROJECT_CAN_OVERWRITE_TIMESTPENT_HOURLY_RATE_WITH_LASTONE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CLASSIFY_CLOSED_WHEN_ALL_TASKS_DONE', 'string', NULL, 'projet', 'Automatically closes a project when all of its tasks are marked as done.', 'When enabled, the task completion logic in projet/class/task.class.php:715 triggers an automatic project status change to closed once all tasks are completed.', 'Enabling this setting causes projects to be automatically closed when every task reaches a done state.', 'Empty/0 = disabled (project not auto-closed); non-empty = enabled (project auto-closed when all tasks done).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/task.class.php:715|check|if (!$error && getDolGlobalString(''PROJECT_CLASSIFY_CLOSED_WHEN_ALL_TASKS_DONE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CREATE_NO_DRAFT', 'string', NULL, 'projet', 'Skips the draft status when creating a new project, setting it directly to an active state.', 'Checked in projet/card.php:216 after a project creation action; when set and no error occurred, the draft step is bypassed.', 'Enabling this setting causes new projects to be created in an active (non-draft) status immediately.', 'Empty/0 = project created in draft status (default); non-empty = project created without draft step.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/card.php:216|check|if (getDolGlobalString(''PROJECT_CREATE_NO_DRAFT'') && !$error) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_CREATE_ON_OVERVIEW_DISABLED', 'bool', NULL, 'projet', 'Disables the ''create new element'' button on the project elements overview page when set.', 'Checked once at projet/element.php:1263: `if (!getDolGlobalString(''PROJECT_CREATE_ON_OVERVIEW_DISABLED'') && $urlnew)`. Only 1 occurrence in 1 file.', 'When unset, a ''create new'' button is shown on the project overview when a creation URL is available. When set, this button is suppressed.', 'Truthy value = create button disabled on project overview; empty/unset = create button shown (if $urlnew is set).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:1263|check|if (!getDolGlobalString(''PROJECT_CREATE_ON_OVERVIEW_DISABLED'') && $urlnew) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_DEFAULT_OPPORTUNITY_STATUS_FOR_ONLINE_LEAD', 'string', NULL, 'projet', 'Sets the default opportunity status assigned to projects created via the public online lead form.', 'Written via projet/admin/website.php:80 and read in both projet/admin/website.php:51 and public/project/new.php:185 to pre-set the opportunity status on new leads.', 'Changing this value alters the initial opportunity status applied to projects submitted through the public lead form.', 'Integer: ID of an opportunity status. Empty = no default status pre-assigned.', 0, 0, 'projet/admin/website.php|projet/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/admin/website.php:80|write|$res = dolibarr_set_const($db, \"PROJECT_DEFAULT_OPPORTUNITY_STATUS_FOR_ONLINE_LEAD\", $defaultoppstatus, ''chaine'', 0, '''', $conf->entity);", "projet/admin/website.php:51|read|$defaultoppstatus = getDolGlobalInt(''PROJECT_DEFAULT_OPPORTUNITY_STATUS_FOR_ONLINE_LEAD'');", "public/project/new.php:185|read|$defaultoppstatus = getDolGlobalInt(''PROJECT_DEFAULT_OPPORTUNITY_STATUS_FOR_ONLINE_LEAD'');"]', 'medium', NULL);
