INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_DISABLE_UNLINK_FROM_OVERVIEW', 'bool', NULL, 'projet', 'Prevents non-admin users from unlinking elements from the project overview page.', 'When set, the unlink action on the project overview is restricted to admin users only. Referenced in projet/element.php:1480 with the inline note ''PROJECT_DISABLE_UNLINK_FROM_OVERVIEW is empty by default, so this test true''.', 'Enabling this setting disallows standard users from removing element links from the project overview; only administrators retain the ability.', 'Empty/0 = unlinking allowed for all users (default); non-empty = unlinking restricted to admins.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:1480|check|if (!getDolGlobalString(''PROJECT_DISABLE_UNLINK_FROM_OVERVIEW'') || $user->admin) {\t\t// PROJECT_DISABLE_UNLINK_FROM_OVERVIEW is empty by default, so this test true"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_DISPLAY_LINKED_BY_CONTACT', 'string', NULL, 'core', 'Shows projects linked via contacts on the third-party page in addition to directly linked projects.', 'Checked at core/lib/company.lib.php:1096; when set, an additional project query through contact linkage is executed. No comment is present in the payload.', 'Enabling this constant broadens the project list shown on a third-party record to include projects associated through contacts; this may increase query cost on large datasets.', 'Any truthy value enables contact-based project display; unset limits to directly linked projects.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:1096|check|if (getDolGlobalString(''PROJECT_DISPLAY_LINKED_BY_CONTACT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ELEMENTS_FOR_MINUS_MARGIN', 'string', NULL, 'projet', 'Defines a comma-separated list of element types to include as negative contributors to the project margin calculation.', 'Checked at projet/element.php:812 and read at :818 as `$newelementforminusmargin = explode('','', getDolGlobalString(''PROJECT_ELEMENTS_FOR_MINUS_MARGIN''))`. 2 occurrences in 1 file.', 'When unset, no additional element types contribute negatively to project margin. When set, the listed element types are subtracted from the margin sum.', 'String: comma-separated list of element type identifiers; empty/unset = no extra negative margin elements.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:812|check|if (getDolGlobalString(''PROJECT_ELEMENTS_FOR_MINUS_MARGIN'')) {", "projet/element.php:818|read|$newelementforminusmargin = explode('','', getDolGlobalString(''PROJECT_ELEMENTS_FOR_MINUS_MARGIN''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ELEMENTS_FOR_PLUS_MARGIN', 'string', NULL, 'projet', 'Defines a comma-separated list of element types to include as positive contributors to the project margin calculation.', 'Checked at projet/element.php:801 and read at :807 as `$newelementforplusmargin = explode('','', getDolGlobalString(''PROJECT_ELEMENTS_FOR_PLUS_MARGIN''))`. 2 occurrences in 1 file.', 'When unset, no additional element types contribute positively to project margin. When set, the listed element types are added to the positive margin sum.', 'String: comma-separated list of element type identifiers; empty/unset = no extra positive margin elements.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:801|check|if (getDolGlobalString(''PROJECT_ELEMENTS_FOR_PLUS_MARGIN'')) {", "projet/element.php:807|read|$newelementforplusmargin = explode('','', getDolGlobalString(''PROJECT_ELEMENTS_FOR_PLUS_MARGIN''));"]', 'low', NULL);
