INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_LINKED_ELEMENT_DEFAULT_FILTER_YEAR', 'string', NULL, 'projet', 'When set, applies a default year filter to linked elements on the project elements overview page.', 'Checked once at projet/element.php:173: `if (!GETPOSTISSET(''datesrfc'') && !GETPOSTISSET(''datesday'') && getDolGlobalString(''PROJECT_LINKED_ELEMENT_DEFAULT_FILTER_YEAR''))`. Only 1 occurrence in 1 file.', 'When unset, no default year filter is applied to linked elements on the project overview. When set, the year filter is applied automatically unless the user has already submitted date parameters.', 'Truthy value = default year filter applied; empty/unset = no default year filter.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:173|check|if (!GETPOSTISSET(''datesrfc'') && !GETPOSTISSET(''datesday'') && getDolGlobalString(''PROJECT_LINKED_ELEMENT_DEFAULT_FILTER_YEAR'')) {"]', 'low', NULL);
