INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_ONLY_PAYED_INVOICE_ON_PROFIT', 'string', NULL, 'projet', 'When set, only fully paid (closed) invoices are counted in the project profit calculation.', 'Checked once at projet/element.php:988: `if (getDolGlobalString(''PROJECT_ONLY_PAYED_INVOICE_ON_PROFIT'') && $element->status != Facture::STATUS_CLOSED)`. Only 1 occurrence in 1 file.', 'When unset, all invoices regardless of payment status contribute to project profit. When set, only invoices with STATUS_CLOSED are included.', 'Truthy value = only paid invoices counted in profit; empty/unset = all invoices counted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:988|check|if (getDolGlobalString(''PROJECT_ONLY_PAYED_INVOICE_ON_PROFIT'') && $element->status != Facture::STATUS_CLOSED) {"]', 'low', NULL);
