INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TASK_ADDON_PDF', 'string', NULL, 'projet', 'Specifies the PDF template module used to generate PDF documents for project tasks.', 'According to the comment at projet/class/task.class.php:2592: ''Create an intervention document on disk using template defined into PROJECT_TASK_ADDON_PDF''. The value is read at projet/class/task.class.php:2610 and managed via projet/admin/project.php (multiple write operations). core/tpl/card_presend.tpl.php:133 checks for its absence.', 'Setting this constant selects the PDF template for project task documents; leaving it empty suppresses task PDF generation in some paths.', 'String: name of a PDF template module. Empty = no PDF template selected (PDF generation suppressed or uses default).', 0, 0, 'projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/task.class.php:2592  *  Create an intervention document on disk using template defined into PROJECT_TASK_ADDON_PDF", "projet/class/task.class.php:2610|read|} elseif (getDolGlobalString(''PROJECT_TASK_ADDON_PDF'')) {", "core/tpl/card_presend.tpl.php:133|check|if ($object->element == ''project_task'' && !getDolGlobalString(''PROJECT_TASK_ADDON_PDF'')) {", "projet/admin/project.php:211|write|if (dolibarr_set_const($db, \"PROJECT_TASK_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
