INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TASK_TIME_MONTH', 'string', NULL, 'projet', 'Filters the task time activity index to display only entries for a specific month.', 'Checked in projet/activity/index.php:313; when set, a month-specific filter is applied to the task time list.', 'Setting this constant restricts the activity index display to the specified month.', 'String: month value used as a filter. Empty = no month filter applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/activity/index.php:313|check|if (getDolGlobalString(''PROJECT_TASK_TIME_MONTH'')) {"]', 'low', NULL);
