INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TASK_UNIVERSAL_MASK', 'string', NULL, 'core', 'Defines the numbering mask pattern used by the ''universal'' task reference generator for project tasks.', 'Read at core/modules/project/task/mod_task_universal.php:95 (UI display) and :140 (mask application). No admin UI file listed; hidden setting.', 'Changing the mask alters how task reference numbers are generated for new tasks when the universal numbering module is active.', 'String mask pattern following Dolibarr mask syntax (e.g. ''{YYYY}{MM}{0000}''); empty = no mask configured', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/project/task/mod_task_universal.php:140|read|$mask = getDolGlobalString(''PROJECT_TASK_UNIVERSAL_MASK'');", "core/modules/project/task/mod_task_universal.php:95|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"masktask\" value=\"''.getDolGlobalString(''PROJECT_TASK_UNIVERSAL_MASK'').''\">'',"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_THIRDPARTY_REQUIRED', 'string', NULL, 'projet', 'Makes the third-party (customer) field mandatory when creating or editing a project.', 'Checked in 5 locations. projet/class/project.class.php:473 returns an error when the constant is set and no socid is provided. projet/card.php:836, :838, :1250, :1252 wrap the third-party label in a ''fieldrequired'' span when this constant is non-empty.', 'Setting this constant forces users to link a project to a third-party record; leaving it unset makes the third-party field optional.', 'Non-empty = third-party field required; 0 or unset = optional.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/project.class.php:473|check|if (getDolGlobalString(''PROJECT_THIRDPARTY_REQUIRED'') && !($this->socid > 0)) {", "projet/card.php:836|read|print(!getDolGlobalString(''PROJECT_THIRDPARTY_REQUIRED'') ? '''' : ''<span class=\"fieldrequired\">'');", "projet/card.php:838|read|print(!getDolGlobalString(''PROJECT_THIRDPARTY_REQUIRED'') ? '''' : ''</span>'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIMESHEET_DISABLEBREAK_ON_PROJECT', 'bool', NULL, 'projet', 'Removes the break/pause columns from timesheet views, collapsing the timesheet display to contiguous time blocks.', 'When set, break-related columns are removed and colspan values are increased by 2 in timesheet tables, as seen in projet/activity/perweek.php:717 (''$colspan = 1 + (!getDolGlobalString(...) ? 0 : 2)'') and core/lib/project.lib.php:1570. Checked across 27 occurrences in core/lib/project.lib.php and projet/activity/* files.', 'Enabling this setting hides break/pause time columns from the timesheet per-day, per-week, and per-month views.', 'Empty/0 = break columns shown (default); non-empty = break columns hidden, colspan adjusted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/activity/perweek.php:717|read|$colspan = 1 + (!getDolGlobalString(''PROJECT_TIMESHEET_DISABLEBREAK_ON_PROJECT'') ? 0 : 2);", "core/lib/project.lib.php:1570|read|$colspan=5+(empty($conf->global->PROJECT_TIMESHEET_DISABLEBREAK_ON_PROJECT)?0:2);", "core/lib/project.lib.php:1648|check|if (getDolGlobalString(''PROJECT_TIMESHEET_DISABLEBREAK_ON_PROJECT'')) {", "projet/activity/permonth.php:545|check|if (!getDolGlobalString(''PROJECT_TIMESHEET_DISABLEBREAK_ON_PROJECT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIMESHEET_PREVENT_AFTER_MONTHS', 'string', NULL, 'projet', 'Freezes timesheet entry after a configurable number of months, preventing edits to old time records.', 'An integer value representing the number of months after which timesheet entries are locked. Set via projet/admin/project.php:248 with the note ''Allow to disable this configuration if empty''. Checked extensively in projet/class/task.class.php and core/lib/project.lib.php (17+ occurrences across multiple files).', 'Setting a positive integer locks timesheet entries older than that many months; setting it to empty or zero disables the freeze.', 'Integer >= 1 = number of months after which timesheets are frozen; empty or 0 = no freeze (disabled).', 0, 0, 'projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/admin/project.php:248|write|dolibarr_set_const($db, ''PROJECT_TIMESHEET_PREVENT_AFTER_MONTHS'', intval($timesheetFreezeDuration), ''chaine'', 0, '''', $conf->entity); //Allow to disable this configuration if empty", "projet/class/task.class.php:1643|check|if (getDolGlobalInt(''PROJECT_TIMESHEET_PREVENT_AFTER_MONTHS'')) {", "core/lib/project.lib.php:1492|check|if (getDolGlobalInt(''PROJECT_TIMESHEET_PREVENT_AFTER_MONTHS'')) {", "projet/admin/project.php:868|read|print ''<input type=\"number\" class=\"width50\" id=\"timesheetFreezeDuration\" name=\"timesheetFreezeDuration\" min=\"0\" step=\"1\""]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIMES_SPENT_FORMAT', 'string', NULL, 'core', 'Sets the output format for the total times-spent display in project and task list views.', 'Checked at projet/tasks/list.php:1145, core/lib/project.lib.php:823, and core/lib/project.lib.php:2960. 3 occurrences across 2 files.', 'When unset, the default time format is used for times-spent totals. When set, the specified format overrides the default rendering.', 'String (format identifier); empty/unset = default format.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/list.php:1145|check|if (getDolGlobalString(''PROJECT_TIMES_SPENT_FORMAT'')) {", "core/lib/project.lib.php:823|check|if (getDolGlobalString(''PROJECT_TIMES_SPENT_FORMAT'')) {", "core/lib/project.lib.php:2960|check|if (getDolGlobalString(''PROJECT_TIMES_SPENT_FORMAT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIME_SHOW_TASK_NOT_ASSIGNED', 'bool', NULL, 'projet', 'Controls the visibility of tasks not assigned to the current user on timesheet views; defaults to 2 when not set.', 'Read in projet/activity/permonth.php:667, projet/activity/perday.php:636, and projet/activity/perweek.php:756 into $restrictviewformytask with a code-level default of 2.', 'Changing this value alters which tasks are shown to the current user on timesheet pages (assigned-only vs. all tasks).', 'Integer: controls task visibility filter on timesheet views. Defaults to 2 when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/activity/permonth.php:667|read|$restrictviewformytask = getDolGlobalInt(''PROJECT_TIME_SHOW_TASK_NOT_ASSIGNED'', 2);", "projet/activity/perday.php:636|read|$restrictviewformytask = getDolGlobalInt(''PROJECT_TIME_SHOW_TASK_NOT_ASSIGNED'', 2);", "projet/activity/perweek.php:756|read|$restrictviewformytask = getDolGlobalInt(''PROJECT_TIME_SHOW_TASK_NOT_ASSIGNED'', 2);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIME_SPEND_WARNING_PERCENT', 'string', NULL, 'core', 'Sets the percentage over the planned time budget at which a warning is triggered on project timesheets.', 'Read at core/lib/project.lib.php lines 1102, 2979, and 3096 (each occurrence is identical). The warning ratio is computed as (1 + PROJECT_TIME_SPEND_WARNING_PERCENT / 100); if not set, a default of 1.10 (10% over budget) is used.', 'Setting this constant adjusts the threshold at which time-overspend warnings appear on project timesheets. If unset, the default is 10% over the planned time.', 'Numeric percentage; e.g. ''20'' means warnings trigger at 120% of planned time. Default effective value when unset: 10 (1.10 ratio).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/project.lib.php:1102|read|$warningRatio = getDolGlobalString(''PROJECT_TIME_SPEND_WARNING_PERCENT'') ? (1 + $conf->global->PROJECT_TIME_SPEND_WARNING_PERCENT / 100) : 1.10;", "core/lib/project.lib.php:2979|read|$warningRatio = getDolGlobalString(''PROJECT_TIME_SPEND_WARNING_PERCENT'') ? (1 + $conf->global->PROJECT_TIME_SPEND_WARNING_PERCENT / 100) : 1.10;", "core/lib/project.lib.php:3096|read|$warningRatio = getDolGlobalString(''PROJECT_TIME_SPEND_WARNING_PERCENT'') ? (1 + $conf->global->PROJECT_TIME_SPEND_WARNING_PERCENT / 100) : 1.10;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIME_SPENT_FORMAT', 'string', NULL, 'core', 'Sets the output format for individual time-spent entries in project task list views.', 'The value is read into $timespentoutputformat at projet/tasks/list.php:1146, core/lib/project.lib.php:824, and core/lib/project.lib.php:2961. 3 occurrences across 2 files.', 'When unset, the default time format is used for individual time-spent entries. When set, the specified format controls their rendering.', 'String (format identifier); empty/unset = default format.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/list.php:1146|read|$timespentoutputformat = getDolGlobalString(''PROJECT_TIME_SPENT_FORMAT'');", "core/lib/project.lib.php:824|read|$timespentoutputformat = getDolGlobalString(''PROJECT_TIME_SPENT_FORMAT'');", "core/lib/project.lib.php:2961|read|$timespentoutputformat = getDolGlobalString(''PROJECT_TIME_SPENT_FORMAT'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_TIME_SPENT_INTO_INVOICE_USE_VALUE', 'bool', NULL, 'projet', 'When set, uses the time-spent monetary value (rather than quantity) when inserting time entries into an invoice.', 'Checked twice in projet/tasks/time.php (lines 758 and 766) when processing time-to-invoice conversion. Only 2 occurrences in 1 file.', 'When unset, time entries are invoiced using their default quantity/rate logic. When set, the monetary value of time spent is used directly.', 'Truthy value = use monetary value of time spent; empty/unset = use default quantity logic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/time.php:758|check|if (getDolGlobalString(''PROJECT_TIME_SPENT_INTO_INVOICE_USE_VALUE'')) {", "projet/tasks/time.php:766|check|if (getDolGlobalString(''PROJECT_TIME_SPENT_INTO_INVOICE_USE_VALUE'')) {"]', 'low', NULL);
