INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_URL_REDIRECT_LEAD', 'string', NULL, 'public', 'Defines the URL to redirect the user to after a lead is successfully submitted via the public project form.', 'In public/project/new.php at lines 384-385, when set the user is redirected to this URL after lead submission. No admin UI write path is present.', 'Setting this redirects submitters to a custom URL on success; leaving it unset uses the default post-submission behavior.', 'String: absolute or relative URL for post-submission redirect', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/new.php:384|read|} elseif (getDolGlobalString(''PROJECT_URL_REDIRECT_LEAD'')) {", "public/project/new.php:385|read|$urlback = getDolGlobalString(''PROJECT_URL_REDIRECT_LEAD'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_USE_OPPORTUNITIES', 'bool', NULL, 'projet', 'Enables the CRM opportunity tracking features within the project module.', 'Checked in 97 locations. Used to conditionally show opportunity-related tabs and fields in projet/class/project.class.php:1294, projet/element.php:410, and numerous task/contact/note pages. Without this constant, opportunity probability and stage fields are hidden.', 'Enabling this constant activates opportunity probability, stage, and related fields on project records; disabling hides the entire opportunity management UI.', 'Non-empty = opportunity features enabled; 0 or unset = opportunity features hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/project.class.php:1294|check|if (getDolGlobalString(''PROJECT_USE_OPPORTUNITIES'')) {", "projet/element.php:410|check|if (getDolGlobalString(''PROJECT_USE_OPPORTUNITIES'') && !empty($object->usage_opportunity)) {", "projet/tasks/task.php:371|check|if (getDolGlobalString(''PROJECT_USE_OPPORTUNITIES'') || !getDolGlobalString(''PROJECT_HIDE_TASKS'') || isModEnabled(''eventorganization'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_USE_REAL_COST_FOR_TIME_INVOICING', 'bool', NULL, 'projet', 'When set, uses the real cost value instead of a standard rate when generating invoices from time spent on project tasks.', 'Checked at projet/tasks/time.php:521 via getDolGlobalInt. Only 1 occurrence in 1 file.', 'When unset, the default rate is used for time invoicing. When set, the real cost figure is applied instead.', 'Truthy integer = use real cost for time invoicing; 0 or unset = use default rate.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/tasks/time.php:521|check|if (getDolGlobalInt(''PROJECT_USE_REAL_COST_FOR_TIME_INVOICING'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJECT_USE_SEARCH_TO_SELECT', 'bool', NULL, 'core', 'Enables an autocomplete search input instead of a dropdown for selecting projects on forms.', 'Checked in core/class/html.form.class.php at lines 8702 and 8943, and in core/class/html.formprojet.class.php:101. Written via projet/admin/project.php:238. Also referenced in admin/system/perf.php:607 which shows a performance note when the option is enabled.', 'Enabling this setting replaces project dropdowns with a search-to-select autocomplete input, which improves performance when there are many projects.', 'Empty/0 = dropdown selector (default); non-empty = autocomplete search input.', 0, 0, 'projet/admin/project.php|admin/system/perf.php|admin/system/perf.php|projet/admin/project.php|projet/admin/project.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.form.class.php:8702|check|if (getDolGlobalString(''PROJECT_USE_SEARCH_TO_SELECT'')) {", "core/class/html.formprojet.class.php:101|check|if (!empty($conf->use_javascript_ajax) && getDolGlobalString(''PROJECT_USE_SEARCH_TO_SELECT'')) {", "admin/system/perf.php:607|check|if (!getDolGlobalString(''PROJECT_USE_SEARCH_TO_SELECT'')) {", "projet/admin/project.php:238|write|if (dolibarr_set_const($db, \"PROJECT_USE_SEARCH_TO_SELECT\", $companysearch, ''chaine'', 0, '''', $conf->entity)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROJET_VISIBILITY', 'string', NULL, 'projet', 'Sets the default visibility scope for projects submitted via the public lead form.', 'Written via projet/admin/website.php:77 and read in the admin UI at projet/admin/website.php:165 (as a selectarray) and in public/project/new.php:192.', 'Changing this value alters the visibility attribute applied to projects created through the public lead form.', 'String: a visibility scope value (options populated via a selectarray in the admin UI). Empty = no default visibility set.', 0, 0, 'projet/admin/website.php|projet/admin/website.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/admin/website.php:77|write|$res = dolibarr_set_const($db, \"PROJET_VISIBILITY\", $visibility, ''chaine'', 0, '''', $conf->entity);", "projet/admin/website.php:165|read|print $form->selectarray(''PROJET_VISIBILITY'', $arrayofchoices, getDolGlobalInt(''PROJET_VISIBILITY''), 0);", "public/project/new.php:192|read|$visibility = getDolGlobalString(''PROJET_VISIBILITY'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON', 'string', NULL, 'core', 'Selects the numbering module class used to generate proposal reference numbers.', 'Configured via admin/propal.php (written with dolibarr_set_const). Read in comm/propal/class/propal.class.php:3751 to instantiate the numbering class, and in core/modules/modPropale.class.php to specify the module class and path. The comment states the numbering module is ''defined into PROPALE_ADDON''. Defaults to mod_propale_marbre when unset.', 'Changing this value switches the algorithm used to generate proposal reference numbers. All new proposals will use the new module; existing references are unaffected.', 'String class name of the numbering module (e.g. ''mod_propale_marbre''); defaults to mod_propale_marbre.', 0, 0, 'admin/propal.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:3741  *  defined into PROPALE_ADDON", "comm/propal/class/propal.class.php:3751|read|$classname = getDolGlobalString(''PROPALE_ADDON'');", "core/modules/modPropale.class.php:387|read|''class''=>(!getDolGlobalString(''PROPALE_ADDON'') ? ''mod_propale_marbre'' : $conf->global->PROPALE_ADDON),", "admin/propal.php:207|write|dolibarr_set_const($db, \"PROPALE_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON_PDF', 'string', NULL, 'admin', 'Selects the default PDF generation module for proposals.', 'Configured via admin/propal.php (written and deleted with dolibarr_set_const/dolibarr_del_const). Read in comm/propal/class/propal.class.php:4031-4032 to determine the PDF model, and used as a fallback default in comm/propal/card.php:2564.', 'Changing this value changes the PDF template used for generating proposal documents. Deleting it falls back to the system default.', 'String name of a PDF model module.', 0, 0, 'admin/propal.php|admin/propal.php|admin/propal.php|admin/propal.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/propal.php:194|write|if (dolibarr_set_const($db, \"PROPALE_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "comm/propal/class/propal.class.php:4031|read|} elseif (getDolGlobalString(''PROPALE_ADDON_PDF'')) {", "comm/propal/class/propal.class.php:4032|read|$modele = getDolGlobalString(''PROPALE_ADDON_PDF'');", "comm/propal/card.php:2564|read|$preselected = getDolGlobalString(''PROPALE_ADDON_PDF_ODT_DEFAULT'', getDolGlobalString(\"PROPALE_ADDON_PDF\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON_PDF_ODT_CLOSED', 'string', NULL, 'comm', 'Specifies the ODT PDF model to use for closed (signed/refused) proposals.', 'Read in comm/propal/class/propal.class.php:2688 and :2797 to select the PDF model when a proposal is in a closed state; also exposed in core/modules/propale/doc/doc_generic_proposal_odt.modules.php for configuration. Falls back to the proposal''s default model if unset.', 'Changing this value changes the document template applied when generating PDFs for closed proposals.', 'String name of an ODT module class; falls back to $this->model_pdf if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:2688|read|$modelpdf = getDolGlobalString(''PROPALE_ADDON_PDF_ODT_CLOSED'', $this->model_pdf);", "comm/propal/class/propal.class.php:2797|read|$modelpdf = getDolGlobalString(''PROPALE_ADDON_PDF_ODT_CLOSED'', $this->model_pdf);", "core/modules/propale/doc/doc_generic_proposal_odt.modules.php:211|read|$texte .= $form->selectarray(''value4'', $list, getDolGlobalString(''PROPALE_ADDON_PDF_ODT_CLOSED''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON_PDF_ODT_DEFAULT', 'string', NULL, 'comm', 'Specifies the default ODT document template to use when generating proposal PDF/ODT documents.', 'This constant stores the name of the default ODT template for proposals. It is read in comm/propal/card.php:2564 and in the ODT module setup at core/modules/propale/doc/doc_generic_proposal_odt.modules.php:199. Falls back to PROPALE_ADDON_PDF if unset.', 'Changing this value alters which ODT template is pre-selected when generating proposal documents.', 'String: name of the ODT template file; empty/unset = falls back to PROPALE_ADDON_PDF value.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:2564|read|$preselected = getDolGlobalString(''PROPALE_ADDON_PDF_ODT_DEFAULT'', getDolGlobalString(\"PROPALE_ADDON_PDF\"));", "core/modules/propale/doc/doc_generic_proposal_odt.modules.php:199|read|$texte .= $form->selectarray(''value2'', $list, getDolGlobalString(''PROPALE_ADDON_PDF_ODT_DEFAULT''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Sets the directory path where ODT templates for proposal documents are stored.', 'Read in core/modules/propale/doc/doc_generic_proposal_odt.modules.php:128 via trim(getDolGlobalString(...)). No admin UI write is present.', 'Changing this constant redirects the proposal ODT module to look for templates in the specified directory. Leaving it unset uses the module''s compiled-in default path.', 'A filesystem path string; empty or unset = module default path used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/doc_generic_proposal_odt.modules.php:128|read|$odtPath = trim(getDolGlobalString(''PROPALE_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_ADDON_PDF_ODT_TOBILL', 'string', NULL, 'comm', 'Specifies the ODT PDF model to use for proposals in ''to bill'' status.', 'Read in comm/propal/class/propal.class.php:2693 to select the PDF model for proposals awaiting billing, and exposed in core/modules/propale/doc/doc_generic_proposal_odt.modules.php for selection. Only two occurrences; no admin UI write path found.', 'Changing this value changes the document template applied when generating PDFs for proposals in the ''to bill'' state.', 'String name of an ODT module class; falls back to $this->model_pdf if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:2693|read|$modelpdf = getDolGlobalString(''PROPALE_ADDON_PDF_ODT_TOBILL'', $this->model_pdf);", "core/modules/propale/doc/doc_generic_proposal_odt.modules.php:205|read|$texte .= $form->selectarray(''value3'', $list, getDolGlobalString(''PROPALE_ADDON_PDF_ODT_TOBILL''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_DRAFT_WATERMARK', 'string', NULL, 'core', 'Defines the watermark text printed on draft proposal PDF documents.', 'Written at admin/propal.php:153. Read and applied in core/modules/propale/doc/pdf_cyan.modules.php:181-182 and pdf_azur.modules.php:214-215 where it is assigned to $this->watermark when the proposal is in draft status. The commented module definition at core/modules/modPropale.class.php:116 also references this constant.', 'Setting this value stamps the specified text as a watermark on all draft proposal PDFs; clearing it removes the watermark.', 'Any string to use as the watermark text on draft proposals; empty = no watermark', 0, 0, 'admin/propal.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:181|check|if ($object->status == $object::STATUS_DRAFT && getDolGlobalString(''PROPALE_DRAFT_WATERMARK'')) {", "core/modules/propale/doc/pdf_cyan.modules.php:182|read|$this->watermark = getDolGlobalString(''PROPALE_DRAFT_WATERMARK'');", "admin/propal.php:153|write|$res = dolibarr_set_const($db, \"PROPALE_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "core/modules/modPropale.class.php:116  /*$this->const[$r][0] = \"PROPALE_DRAFT_WATERMARK\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_KEEP_OLD_SIGNATURE_INFO', 'string', NULL, 'comm', 'Preserves existing signature information on a proposal instead of overwriting it.', 'Checked in comm/propal/class/propal.class.php:2664; when falsy (default), signature data is reset. When set, the old signature info is retained. Only one occurrence; no admin UI.', 'Enabling this constant prevents signature fields from being cleared during proposal updates or status changes.', 'Truthy string (old signature kept) or empty/unset (signature info overwritten).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:2664|check|if (!getDolGlobalString(''PROPALE_KEEP_OLD_SIGNATURE_INFO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_NOCHECK_ONSALE_PRODUCTS_ONVALID', 'string', NULL, 'comm', 'Disables the check for active/on-sale products when validating a proposal.', 'Checked in comm/propal/class/propal.class.php:2096 via getDolGlobalBool; when truthy, the checkActiveProductInLines() call is skipped during proposal validation.', 'When set, proposals containing inactive or off-sale products can still be validated without error.', 'Truthy bool/string (check skipped) or empty/unset (check enforced).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:2096|check|if (!getDolGlobalBool(''PROPALE_NOCHECK_ONSALE_PRODUCTS_ONVALID'') && !$this->checkActiveProductInLines()) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_SAPHIR_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the Saphir module for commercial proposal references.', 'Read in core/modules/propale/mod_propale_saphir.php at lines 95 and 147 to determine the mask string for generating proposal reference numbers. If unset or empty, an empty string is used as the mask.', 'Changing this value alters the format of commercial proposal reference numbers generated by the Saphir module; leaving it unset results in an empty mask.', 'Any valid mask string for proposal numbering; empty string if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/mod_propale_saphir.php:95|read|$mask = !getDolGlobalString(''PROPALE_SAPHIR_MASK'') ? '''' : $conf->global->PROPALE_SAPHIR_MASK;", "core/modules/propale/mod_propale_saphir.php:147|read|$mask = !getDolGlobalString(''PROPALE_SAPHIR_MASK'') ? '''' : $conf->global->PROPALE_SAPHIR_MASK;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPALE_VALIDITY_DURATION', 'string', NULL, 'comm', 'Sets the default validity duration (in days) for new commercial proposals.', 'Configured via admin/propal.php where it is written with dolibarr_set_const and rendered as a text input. Read in comm/propal/class/propal.class.php:464 to initialize the proposal''s duree_validite field.', 'Changing this value alters the default expiry window applied to newly created proposals. Existing proposals are not affected.', 'Integer string representing number of days.', 0, 0, 'admin/propal.php|admin/propal.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/propal.php:146|write|$res = dolibarr_set_const($db, \"PROPALE_VALIDITY_DURATION\", $value, ''chaine'', 0, '''', $conf->entity);", "admin/propal.php:641|read|print \"<input size=\\\"3\\\" class=\\\"flat\\\" type=\\\"text\\\" name=\\\"PROPALE_VALIDITY_DURATION\\\" value=\\\"\" . getDolGlobalString(''PROPALE_VALIDITY_DURATION'').\"\\\"></td>\";", "comm/propal/class/propal.class.php:464|read|$this->duree_validite = getDolGlobalInt(''PROPALE_VALIDITY_DURATION'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_CLONE_DATE_DELIVERY', 'string', NULL, 'comm', 'Controls whether the delivery date is copied when cloning a proposal.', 'Checked in comm/propal/card.php at lines 220 and 2760; when set and a delivery date exists on the source proposal, the date is carried over to the clone.', 'Enabling this preserves the original delivery date on cloned proposals; leaving it unset means clones start without a delivery date.', 'Empty/unset = delivery date not cloned; any non-empty string = delivery date cloned if present.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:220|check|if (getDolGlobalString(''PROPAL_CLONE_DATE_DELIVERY'')) {", "comm/propal/card.php:2760|check|if (getDolGlobalString(''PROPAL_CLONE_DATE_DELIVERY'') && !empty($object->delivery_date)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_CLONE_ON_CREATE_PAGE', 'string', NULL, 'comm', 'Enables an option on the proposal creation page to select an existing proposal to clone.', 'When active, the proposal creation page displays a field allowing the user to pick an existing proposal to clone. Referenced in comm/propal/card.php at lines 518, 2664, and 2668.', 'Enabling this changes the creation workflow to offer a clone-from option; disabling it hides the clone selector and goes directly to a blank new proposal.', 'Empty/unset = standard creation page; truthy value = shows clone-selection field during creation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:518  // If we select proposal to clone during creation (when option PROPAL_CLONE_ON_CREATE_PAGE is on)", "comm/propal/card.php:2664|check|if (!getDolGlobalString(''PROPAL_CLONE_ON_CREATE_PAGE'')) {", "comm/propal/card.php:2668|check|if (getDolGlobalString(''PROPAL_CLONE_ON_CREATE_PAGE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_CLOSE_REFUSED_TEMPLATE', 'string', NULL, 'core', 'Specifies the notification template name to use when a sales proposal is closed as refused.', 'Read in core/class/notify.class.php:804 to select the label of the notification template for refused proposals. No admin UI write is present; this is a hidden configuration constant.', 'If unset, no specific template is selected for refused-proposal notifications, falling back to default notify logic.', 'String: name of a notification template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/notify.class.php:804|read|$labeltouse = getDolGlobalString(''PROPAL_CLOSE_REFUSED_TEMPLATE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_DISABLE_AUTOUPDATE_ON_CLOSE', 'bool', NULL, 'comm', 'Disables automatic PDF regeneration when a proposal is closed.', 'Checked in comm/propal/class/propal.class.php:2707 alongside MAIN_DISABLE_PDF_AUTOUPDATE; when this constant is set, the auto-update of the PDF on proposal close is skipped. No admin UI.', 'When enabled, closing a proposal will not trigger an automatic PDF rebuild, which may leave the stored PDF out of date.', 'Truthy integer/string (auto-update disabled) or empty/unset (auto-update runs).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:2707|check|if (!getDolGlobalString(''MAIN_DISABLE_PDF_AUTOUPDATE'') && !getDolGlobalInt(''PROPAL_DISABLE_AUTOUPDATE_ON_CLOSE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_DISABLE_SIGNATURE', 'bool', NULL, 'core', 'Disables the customer signature block on proposal PDF documents.', 'Checked in four locations across pdf_cyan.modules.php and pdf_azur.modules.php. When set, the signature section height is forced to 0 and the signature block rendering is skipped (lines 347, 378, 931, 759). No admin UI write is present.', 'Setting this constant removes the customer signature area from proposal PDFs in both cyan and azur templates. Unsetting it restores the signature block with calculated height.', 'Truthy = signature block hidden; falsy or unset = signature block shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:931|check|if (!getDolGlobalString(''PROPAL_DISABLE_SIGNATURE'')) {", "core/modules/propale/doc/pdf_azur.modules.php:759|check|if (!getDolGlobalString(''PROPAL_DISABLE_SIGNATURE'')) {", "core/modules/propale/doc/pdf_cyan.modules.php:347|read|$heightforsignature = !getDolGlobalString(''PROPAL_DISABLE_SIGNATURE'') ? (pdfGetHeightForHtmlContent($pdf, $outputlangs->transnoentities(\"ProposalCustomerSignature\")) + 10) : 0;", "core/modules/propale/doc/pdf_azur.modules.php:378|read|$heightforsignature = !getDolGlobalString(''PROPAL_DISABLE_SIGNATURE'') ? (pdfGetHeightForHtmlContent($pdf, $outputlangs->transnoentities(\"ProposalCustomerSignature\")) + 10) : 0;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_DISALLOW_REOPEN', 'bool', NULL, 'comm', 'Prevents re-opening a proposal that has already been accepted or refused when set.', 'Checked in comm/propal/card.php:150 via getDolGlobalBool; when true, the re-open action is suppressed.', 'Setting this enforces a one-way workflow where accepted or refused proposals cannot be reverted to an earlier status.', '0 or unset = re-opening allowed; 1/true = re-opening disallowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:150|check|if (getDolGlobalBool(''PROPAL_DISALLOW_REOPEN'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_ENABLE_NEGATIVE', 'bool', NULL, 'comm', 'Allows a proposal to be validated even when its total amount is negative.', 'When set, a draft proposal with a negative total and at least one line can be sent for validation. Seen in comm/propal/card.php:3572.', 'Without this constant, proposals with a negative total cannot be moved forward in the workflow; enabling it removes that restriction.', 'Empty/unset = negative-total proposals cannot be validated; truthy value = negative totals allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3572|read||| ($object->status == Propal::STATUS_DRAFT && getDolGlobalString(''PROPAL_ENABLE_NEGATIVE'') && count($object->lines) > 0)"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_ENABLE_NEGATIVE_QTY', 'bool', NULL, 'comm', 'Allows negative quantities on proposal lines when set to a non-empty value.', 'Checked in comm/propal/card.php:1304; when not set, a negative quantity triggers a validation error.', 'Enabling this permits negative line quantities on proposals, which can be used for discount or credit lines.', 'Empty/unset = negative quantities rejected; any non-empty string = negative quantities allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:1304|check|if ($qty < 0 && !getDolGlobalString(''PROPAL_ENABLE_NEGATIVE_QTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_LIST_SHOW_NOTES', 'bool', NULL, 'comm', 'Controls whether proposal notes are shown inline in the proposals list view.', 'Read once in comm/propal/list.php:1944 via getDolGlobalInt(''PROPAL_LIST_SHOW_NOTES'', 1) as the $shownotes parameter of getNomUrl(). The default fallback of 1 means notes are shown unless the constant is explicitly set to 0.', 'Setting to 0 hides proposal notes from the list. The default behaviour (unset or 1) shows notes.', 'Integer: 1 = show notes (default when unset), 0 = hide notes.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/list.php:1944|read|print $object->getNomUrl(1, '''', '''', 0, 1, getDolGlobalInt(''PROPAL_LIST_SHOW_NOTES'', 1));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_REOPEN_UNSIGNED_ONLY', 'string', NULL, 'comm', 'Restricts the re-open action on proposals to those in the ''not signed'' status only.', 'When set, only proposals with STATUS_NOTSIGNED can be re-opened; when absent, proposals in other closed statuses may also be re-opened. Seen in comm/propal/card.php:3591.', 'Enabling this prevents re-opening proposals that were closed for reasons other than non-signature, enforcing a stricter lifecycle.', 'Empty/unset = re-open allowed for multiple statuses; truthy value = re-open restricted to STATUS_NOTSIGNED only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3591|check|if (((getDolGlobalString(''PROPAL_REOPEN_UNSIGNED_ONLY'') && $object->status == Propal::STATUS_NOTSIGNED) || (!getDolGlobalString(''PROPAL_REOPEN_UNSIGNED_ONLY'') && ($object->status ="]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SIGNATURE_ON_ALL_PAGES', 'string', NULL, 'core', 'Controls whether the online signature image is stamped on every page of the proposal PDF rather than a specific page only.', 'Checked in core/ajax/onlineSign.php:212 and :241 via getDolGlobalString(''PROPAL_SIGNATURE_ON_ALL_PAGES''). When truthy the signature block is rendered on every page; when falsy it is rendered only if $propalsignonspecificpage matches the current page.', 'Enabling this constant causes the signature image to appear on every page of the proposal PDF. Disabling it restricts signature placement to the page indicated by PROPAL_SIGNATURE_ON_SPECIFIC_PAGE.', 'Non-empty string = enabled (stamp on all pages). Empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:212|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_ON_ALL_PAGES\") || $propalsignonspecificpage == $i) {", "core/ajax/onlineSign.php:241|check|if (!getDolGlobalString(\"PROPAL_SIGNATURE_ON_ALL_PAGES\") && !$propalsignonspecificpage) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SIGNATURE_ON_SPECIFIC_PAGE', 'string', NULL, 'core', 'Sets the specific PDF page number on which the signature image is placed when signing a proposal online.', 'Read once in core/ajax/onlineSign.php:189 via getDolGlobalInt(''PROPAL_SIGNATURE_ON_SPECIFIC_PAGE'') and stored in $propalsignonspecificpage, which is then compared against the current page index to decide where to embed the signature image.', 'If set to a page number, the signature image is placed only on that page of the proposal PDF. If unset or zero, placement falls back to other logic controlled by PROPAL_SIGNATURE_ON_ALL_PAGES.', 'Integer page number (1-based). 0 or unset means no specific page targeted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:189|read|$propalsignonspecificpage = getDolGlobalInt(\"PROPAL_SIGNATURE_ON_SPECIFIC_PAGE\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SIGNATURE_WFORIMG', 'string', NULL, 'core', 'Sets the width of the signature image inserted into the proposal PDF during online signing.', 'Checked and read in core/ajax/onlineSign.php:226-227 and :254-255 via getDolGlobalString(''PROPAL_SIGNATURE_WFORIMG''). When set, the value is passed as $param[''wforimg''] to the PDF rendering layer.', 'If set, the signature image is rendered at the specified width in the proposal PDF. If unset, the default image width applies.', 'Numeric or string value representing the image width passed to the PDF engine. Empty/unset = default width.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:226|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_WFORIMG\")) {", "core/ajax/onlineSign.php:227|read|$param[''wforimg''] = getDolGlobalString(\"PROPAL_SIGNATURE_WFORIMG\");", "core/ajax/onlineSign.php:254|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_WFORIMG\")) {", "core/ajax/onlineSign.php:255|read|$param[''wforimg''] = getDolGlobalString(\"PROPAL_SIGNATURE_WFORIMG\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SIGNATURE_XFORIMGSTART', 'string', NULL, 'core', 'Sets the X coordinate (horizontal offset) for positioning the signature image on the proposal PDF page.', 'Checked and read in core/ajax/onlineSign.php:216-217 and :244-245 via getDolGlobalString(''PROPAL_SIGNATURE_XFORIMGSTART''). When set, the value is passed as $param[''xforimgstart''] to the PDF rendering layer.', 'If set, overrides the default horizontal position of the signature image on the proposal PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the X coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:216|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_XFORIMGSTART\")) {", "core/ajax/onlineSign.php:217|read|$param[''xforimgstart''] = getDolGlobalString(\"PROPAL_SIGNATURE_XFORIMGSTART\");", "core/ajax/onlineSign.php:244|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_XFORIMGSTART\")) {", "core/ajax/onlineSign.php:245|read|$param[''xforimgstart''] = getDolGlobalString(\"PROPAL_SIGNATURE_XFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SIGNATURE_YFORIMGSTART', 'string', NULL, 'core', 'Sets the Y coordinate (vertical offset) for positioning the signature image on the proposal PDF page.', 'Checked and read in core/ajax/onlineSign.php:221-222 and :249-250 via getDolGlobalString(''PROPAL_SIGNATURE_YFORIMGSTART''). When set, the value is passed as $param[''yforimgstart''] to the PDF rendering layer.', 'If set, overrides the default vertical position of the signature image on the proposal PDF. If unset, the default positioning logic applies.', 'Numeric or string value representing the Y coordinate passed to the PDF engine. Empty/unset = default position.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:221|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_YFORIMGSTART\")) {", "core/ajax/onlineSign.php:222|read|$param[''yforimgstart''] = getDolGlobalString(\"PROPAL_SIGNATURE_YFORIMGSTART\");", "core/ajax/onlineSign.php:249|check|if (getDolGlobalString(\"PROPAL_SIGNATURE_YFORIMGSTART\")) {", "core/ajax/onlineSign.php:250|read|$param[''yforimgstart''] = getDolGlobalString(\"PROPAL_SIGNATURE_YFORIMGSTART\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPAL_SKIP_ACCEPT_REFUSE', 'string', NULL, 'comm', 'Bypasses the accept/refuse step in the proposal workflow, allowing direct transition from draft or validated to signed/refused.', 'Checked 8 times across comm/propal/card.php and comm/propal/list.php; when set, the status check at card.php:833 allows sign action from draft, card.php:915 sets new status to STATUS_DRAFT instead of STATUS_VALIDATED on reopen, and the accept/refuse buttons at card.php:2783, 2929, 3706 are hidden.', 'Setting this simplifies the proposal workflow by removing the intermediate accept/refuse status, which changes available actions and button labels.', 'Empty/unset = standard accept/refuse workflow; any non-empty string = skip accept/refuse step.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:833|check|if ($object->status == $object::STATUS_VALIDATED || (getDolGlobalString(''PROPAL_SKIP_ACCEPT_REFUSE'') && $object->status == $object::STATUS_DRAFT)) {", "comm/propal/card.php:915|read|$newstatus = (getDolGlobalInt(''PROPAL_SKIP_ACCEPT_REFUSE'') ? Propal::STATUS_DRAFT : Propal::STATUS_VALIDATED);", "comm/propal/card.php:2783|check|if (!getDolGlobalString(''PROPAL_SKIP_ACCEPT_REFUSE'')) {", "comm/propal/list.php:507|check|if ($tmpproposal->status == $tmpproposal::STATUS_VALIDATED || (getDolGlobalString(''PROPAL_SKIP_ACCEPT_REFUSE'') && $tmpproposal->status == $tmpproposal::STATUS_DRAFT)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for commercial proposal documents.', 'Checked in core/class/commonobject.class.php:6376 and core/lib/functions.lib.php:10728. When set, a public download link is generated for proposal (propal) objects.', 'Enabling this constant exposes proposal documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6376|check|if (getDolGlobalInt(\"PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10728|check|if (getDolGlobalString(''PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''propal'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_ALLOW_ONLINESIGN', 'bool', NULL, 'webportal', 'Enables the online signature feature for commercial proposals, showing a signature link in the web portal.', 'Checked in core/class/commonobject.class.php:6373 and read in comm/propal/card.php:3779 as $useonlinesignature. Also read in webportal/class/html.formlistwebportal.class.php:281 to add the ''signature_link'' column when the propal module is active.', 'When non-zero, a signature link column is displayed in proposal lists and the online signature workflow is enabled; when zero or unset, this feature is hidden.', 'Integer: 1 to enable online signature for proposals; 0 or unset to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:6373|check|if (getDolGlobalInt(\"PROPOSAL_ALLOW_ONLINESIGN\")) {", "comm/propal/card.php:3779|read|$useonlinesignature = getDolGlobalInt(''PROPOSAL_ALLOW_ONLINESIGN'');", "webportal/class/html.formlistwebportal.class.php:281|read|$this->arrayfields[''signature_link''] = array(...''enabled'' => $this->element == ''propal'' && isModEnabled(''propal'') && getDolGlobal..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_ARE_NOT_BILLABLE', 'string', NULL, 'comm', 'Prevents the creation of invoices from signed proposals.', 'When set, the ''create invoice'' action is hidden on signed proposals. The check appears twice in comm/propal/card.php (lines 3671 and 3695), covering both standard and deposit invoice buttons.', 'Enabling this constant blocks the billing workflow from proposals, forcing invoices to be created independently.', 'Empty/unset = signed proposals can generate invoices; truthy value = invoice creation from proposals is disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3671|check|if ($object->status == Propal::STATUS_SIGNED && !getDolGlobalString(''PROPOSAL_ARE_NOT_BILLABLE'')) {", "comm/propal/card.php:3695|check|if ($object->status == Propal::STATUS_SIGNED && !getDolGlobalString(''PROPOSAL_ARE_NOT_BILLABLE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_AUTO_ADD_AUTHOR_AS_CONTACT', 'string', NULL, 'comm', 'Automatically adds the proposal author as a contact on the newly created proposal when set.', 'Checked in comm/propal/card.php:757; when set, the author is auto-linked as a contact after proposal creation.', 'Enabling this ensures the creating user is always a linked contact on new proposals without manual action.', 'Empty/unset = author not auto-added; any non-empty string = author added as contact automatically.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:757|check|if (getDolGlobalString(''PROPOSAL_AUTO_ADD_AUTHOR_AS_CONTACT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Proposal (quote) documents.', 'Set via the admin UI at admin/propal.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Proposal documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/propal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/propal.php:160|write|$res = dolibarr_set_const($db, \"PROPOSAL_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_HIDE_CALCULATED_WEIGHT_VOLUME', 'bool', NULL, 'comm', 'Hides the automatically calculated weight and volume section on the proposal card.', 'When set, the block displaying the calculated total weight and volume of proposal lines is suppressed. Seen in comm/propal/card.php:3313.', 'Enabling this removes weight/volume information from the proposal display, simplifying the UI for businesses that do not track shipping dimensions.', 'Empty/unset = show calculated weight/volume; truthy value = hide it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3313|check|if (!getDolGlobalString(''PROPOSAL_HIDE_CALCULATED_WEIGHT_VOLUME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_IMAGE_PUBLIC_SIGN', 'string', NULL, 'public', 'Stores the URL of an image displayed on the public proposal online signature page.', 'Checked at public/onlinesign/newonlinesign.php:280 when the source is ''proposal''; when set, the image URL is rendered as an <img> tag at line 282. No admin UI write is present.', 'Setting this constant causes a custom image to appear on the proposal signature page; leaving it unset suppresses the image.', 'String URL of the image; unset/empty = no image shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/onlinesign/newonlinesign.php:280|check|if ($source == ''proposal'' && getDolGlobalString(''PROPOSAL_IMAGE_PUBLIC_SIGN'')) {", "public/onlinesign/newonlinesign.php:282|read|print ''<img id=\"idPROPOSAL_IMAGE_PUBLIC_INTERFACE\" src=\"'' . getDolGlobalString(''PROPOSAL_IMAGE_PUBLIC_SIGN'').''\">'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_ONLINE_SIGNATURE_SECURITY_TOKEN', 'string', NULL, 'core', 'Provides the secret seed string used to generate the security token for the proposal online-signature public link.', 'Read in core/lib/signature.lib.php:99, core/ajax/onlineSign.php:82, and public/onlinesign/newonlinesign.php:149 as $securekeyseed via getDolGlobalString(''PROPOSAL_ONLINE_SIGNATURE_SECURITY_TOKEN''). No admin UI write is present; the value must be set manually.', 'If changed or cleared, any previously distributed public signature links for proposals will become invalid because the derived token will no longer match.', 'Arbitrary string (secret seed). Empty string disables token-based verification.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/signature.lib.php:99|read|$securekeyseed = getDolGlobalString(''PROPOSAL_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "core/ajax/onlineSign.php:82|read|$securekeyseed = getDolGlobalString(''PROPOSAL_ONLINE_SIGNATURE_SECURITY_TOKEN'');", "public/onlinesign/newonlinesign.php:149|read|$securekeyseed = getDolGlobalString(''PROPOSAL_ONLINE_SIGNATURE_SECURITY_TOKEN'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_PDF_HIDE_DELIVERYMODE', 'bool', NULL, 'core', 'Hides the delivery/shipping mode section on proposal PDF documents.', 'Checked in pdf_cyan.modules.php:1135 and pdf_azur.modules.php:983 as part of a condition that also requires shipping_method_id > 0. When this constant is set, the delivery mode section is suppressed. No admin UI write is present.', 'Setting this constant prevents the shipping method from appearing on proposal PDFs even when a shipping method is assigned. Unsetting it allows the section to render when a shipping method is set.', 'Truthy = delivery mode hidden on PDF; falsy or unset = delivery mode shown when applicable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/propale/doc/pdf_cyan.modules.php:1135|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_DELIVERYMODE'') && $object->shipping_method_id > 0) {", "core/modules/propale/doc/pdf_azur.modules.php:983|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_DELIVERYMODE'') && $object->shipping_method_id > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_PDF_HIDE_PAYMENTMODE', 'bool', NULL, 'core', 'Hides the payment mode section on proposal PDF documents.', 'Written in admin/pdf_other.php:93 via dolibarr_set_const, and checked in pdf_cyan.modules.php:1178 and pdf_azur.modules.php:1026. The admin UI is admin/pdf_other.php.', 'Setting this constant removes the payment mode block from proposal PDFs in both cyan and azur templates. Unsetting it allows the section to render.', 'Truthy = payment mode hidden on proposal PDF; falsy or unset = payment mode shown.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:93|write|dolibarr_set_const($db, \"PROPOSAL_PDF_HIDE_PAYMENTMODE\", GETPOST(\"PROPOSAL_PDF_HIDE_PAYMENTMODE\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:1178|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_PAYMENTMODE'')) {", "core/modules/propale/doc/pdf_azur.modules.php:1026|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_PAYMENTMODE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_PDF_HIDE_PAYMENTTERM', 'bool', NULL, 'core', 'Hides the payment terms section on proposal PDF documents.', 'Written in admin/pdf_other.php:90 via dolibarr_set_const, and checked in pdf_cyan.modules.php:1160 and pdf_azur.modules.php:1008. The admin UI is admin/pdf_other.php.', 'Setting this constant removes the payment terms block from proposal PDFs in both cyan and azur templates. Unsetting it restores the section when a payment condition code is present.', 'Truthy = payment terms hidden on proposal PDF; falsy or unset = payment terms shown when applicable.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:90|write|dolibarr_set_const($db, \"PROPOSAL_PDF_HIDE_PAYMENTTERM\", GETPOST(\"PROPOSAL_PDF_HIDE_PAYMENTTERM\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:1160|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_PAYMENTTERM'') && $object->cond_reglement_code) {", "core/modules/propale/doc/pdf_azur.modules.php:1008|check|if (!getDolGlobalString(''PROPOSAL_PDF_HIDE_PAYMENTTERM'') && $object->cond_reglement_code) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_SENDBYEMAIL_FOR_ALL_STATUS', 'string', NULL, 'comm', 'Allows the ''send by email'' action on proposals regardless of their current status.', 'By default, the send-by-email action is available only for validated or signed proposals. When this constant is set, the action becomes available for all statuses. Seen in comm/propal/card.php:3602.', 'Enabling this lets users email proposals that are still in draft or other non-standard statuses.', 'Empty/unset = email action limited to validated/signed statuses; truthy value = email action available for all statuses.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3602|check|if ($object->status == Propal::STATUS_VALIDATED || $object->status == Propal::STATUS_SIGNED || getDolGlobalString(''PROPOSAL_SENDBYEMAIL_FOR_ALL_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_SHOW_INVOICED_AMOUNT', 'bool', NULL, 'comm', 'Enables the display of invoiced HT and TTC amount columns in the proposals list view.', 'Read in comm/propal/list.php:258-266. When set, the columns p.total_ht_invoiced (AmountInvoicedHT) and p.total_invoiced (AmountInvoicedTTC), as well as their multicurrency equivalents, are made available in the proposals list.', 'If enabled, users can see how much of each proposal has been invoiced directly from the list. If unset, those columns are not rendered.', 'Non-empty string = enabled (columns available). Empty/unset = columns hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/list.php:258|read|''p.total_ht_invoiced'' => array(''label'' => \"AmountInvoicedHT\", ''checked'' => ''0'', ''enabled'' => getDolGlobalString(''PROPOSAL_SHOW_INVOICED_AMOUNT'')),", "comm/propal/list.php:259|read|''p.total_invoiced'' => array(''label'' => \"AmountInvoicedTTC\", ''checked'' => ''0'', ''enabled'' => getDolGlobalString(''PROPOSAL_SHOW_INVOICED_AMOUNT'')),", "comm/propal/list.php:265|read|''p.multicurrency_total_ht_invoiced'' => array(''label'' => ''MulticurrencyAmountInvoicedHT'', ..., ''enabled'' => ... getDolGlobalString(''PROPOSAL_SHOW_INVOICED_AMOUNT'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_SHOW_SHIPPING_ADDRESS', 'bool', NULL, 'admin', 'Controls whether the shipping address is printed on proposal PDFs.', 'Written in admin/pdf_other.php at line 99 and displayed as a select at line 313. Checked in core/modules/propale/doc/pdf_cyan.modules.php at line 1968 via getDolGlobalInt to conditionally render the shipping address block.', 'Enabling this constant causes proposal PDFs to include the customer''s shipping address. Disabling it omits the shipping address from proposals.', 'Non-zero integer to show shipping address; 0 or unset to hide it.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:99|write|dolibarr_set_const($db, \"PROPOSAL_SHOW_SHIPPING_ADDRESS\", GETPOSTINT(\"PROPOSAL_SHOW_SHIPPING_ADDRESS\"), ''chaine'', 0, '''', $conf->entity);", "core/modules/propale/doc/pdf_cyan.modules.php:1968|check|if (getDolGlobalInt(''PROPOSAL_SHOW_SHIPPING_ADDRESS'')) {", "admin/pdf_other.php:313|read|print $form->selectarray(\"PROPOSAL_SHOW_SHIPPING_ADDRESS\", $arrval, getDolGlobalString(''PROPOSAL_SHOW_SHIPPING_ADDRESS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PROPOSAL_SUGGEST_DOWN_PAYMENT_INVOICE_CREATION', 'string', NULL, 'comm', 'Suggests creating a down-payment invoice after a proposal is signed.', 'When set to a non-zero integer, the proposal card displays a prompt to create a down-payment invoice after the proposal is accepted. Seen in comm/propal/card.php:2788.', 'Enabling this adds a workflow step suggesting a deposit invoice, which users may act on or ignore.', '0 or unset = no down-payment suggestion; non-zero = shows down-payment invoice creation prompt.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:2788|check|if (getDolGlobalInt(''PROPOSAL_SUGGEST_DOWN_PAYMENT_INVOICE_CREATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('PSQL_USE_UNACCENT', 'bool', NULL, 'core', 'Enables use of the PostgreSQL unaccent extension for accent-insensitive LIKE searches.', 'Checked once at core/db/pgsql.class.php:329 when there are LIKE conditions in a query. No admin UI write was found; HIDDEN_GUESS is 1.', 'When enabled on a PostgreSQL database with the unaccent extension installed, search queries ignore accented characters, improving multilingual search results.', '0 (accent-sensitive search) or 1 (accent-insensitive via unaccent extension)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/db/pgsql.class.php:329|check|if (getDolGlobalString(''PSQL_USE_UNACCENT'') && $count_like > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEIPT_PRINTER_NB_CHARACT_BY_LINE', 'string', NULL, 'takepos', 'Sets the number of characters per line used when formatting receipt printer output.', 'Read in takepos/class/dolreceiptprinter.class.php:787 as $nbcharactbyline with a default of 48. No admin UI write is present.', 'Changing this value adjusts line wrapping for receipt text; a value smaller than the printer''s physical width causes unnecessary wrapping, while a larger value may cause truncation.', 'Integer number of characters per line; default is 48 when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/class/dolreceiptprinter.class.php:787|read|$nbcharactbyline = getDolGlobalInt(''RECEIPT_PRINTER_NB_CHARACT_BY_LINE'', 48);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_ADDON_NUMBER', 'string', NULL, 'admin', 'Specifies the numbering module class used to generate reception reference numbers.', 'Written via admin/reception_setup.php (lines 68, 171). Read in reception/class/reception.class.php (lines 241-245) to load the class file (`$file = getDolGlobalString(''RECEPTION_ADDON_NUMBER'') . ".php"`) and instantiate the numbering module.', 'Changing this value switches the numbering algorithm for reception records; the default is `mod_reception_beryl`.', 'String (module class name, e.g. ''mod_reception_beryl''); empty triggers a fallback to the default module.', 0, 0, 'admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/reception_setup.php:68|write|$conf->global->RECEPTION_ADDON_NUMBER = ''mod_reception_beryl'';", "admin/reception_setup.php:171|write|dolibarr_set_const($db, \"RECEPTION_ADDON_NUMBER\", $value, ''chaine'', 0, '''', $conf->entity);", "reception/class/reception.class.php:244|read|$file = getDolGlobalString(''RECEPTION_ADDON_NUMBER'') . \".php\";", "reception/class/reception.class.php:245|read|$classname = getDolGlobalString(''RECEPTION_ADDON_NUMBER'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF template module used to generate reception documents.', 'Set via admin/reception_setup.php (multiple read/write occurrences). The value is read in reception/class/reception.class.php:2486-2487 to select the PDF model, and displayed in a dropdown in reception/card.php:1304.', 'Changing this value switches the PDF template used for all reception document generation; an unset value falls back to a default template.', 'String: name of the PDF addon module (e.g. ''reception_rouget''); empty = use default', 0, 0, 'admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php|admin/reception_setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/class/reception.class.php:2486|read|} elseif (getDolGlobalString(''RECEPTION_ADDON_PDF'')) {", "reception/class/reception.class.php:2487|read|$modele = getDolGlobalString(''RECEPTION_ADDON_PDF'');", "admin/reception_setup.php:159|write|if (dolibarr_set_const($db, \"RECEPTION_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "reception/card.php:1304|read|print $form->selectarray(''model'', $list, getDolGlobalString(''RECEPTION_ADDON_PDF''), 0, 0, 0, '''', 0, 0, 0, '''', ''maxwidth200 widthcentpercentminusx'', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path for custom ODT templates used when generating reception PDF documents.', 'Read in core/modules/reception/doc/doc_generic_reception_odt.modules.php:111 and trimmed before use as the ODT template directory path.', 'If unset, only the default ODT template directory is used for reception documents.', 'String: a filesystem directory path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/reception/doc/doc_generic_reception_odt.modules.php:111|read|$odtPath = trim(getDolGlobalString(''RECEPTION_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_ADD_CONTACTS_IN_EXPORT', 'string', NULL, 'core', 'Includes contact records in the data export for the Reception module.', 'When set, core/modules/modReception.class.php adds contact-related rows to the export definition at lines 191, 208, 212, and 240, conditioned on both the presence of contact IDs and this constant.', 'Enabling this adds contact data columns to reception exports; disabling it limits exports to reception records without contact details.', 'Any non-empty string value enables contact inclusion in reception exports.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/modReception.class.php:191|check|if ($idcontacts && getDolGlobalString(''RECEPTION_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modReception.class.php:208|check|if ($idcontacts && getDolGlobalString(''RECEPTION_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modReception.class.php:212|check|if ($idcontacts && getDolGlobalString(''RECEPTION_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modReception.class.php:240|check|if ($idcontacts && getDolGlobalString(''RECEPTION_ADD_CONTACTS_IN_EXPORT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_ALLOW_NEGATIVE_QTY', 'bool', NULL, 'reception', 'Allows negative quantities to be entered on reception lines.', 'Checked in reception/class/reception.class.php:706: `if ($qty == 0 || ($qty < 0 && !getDolGlobalInt(''RECEPTION_ALLOW_NEGATIVE_QTY'')))`. Also referenced in a commented-out condition in reception/card.php:466.', 'Enabling this setting permits recording negative received quantities; by default, negative quantities are rejected.', '0 or empty = negative quantities rejected; 1 = negative quantities allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/class/reception.class.php:706|check|if ($qty == 0 || ($qty < 0 && !getDolGlobalInt(''RECEPTION_ALLOW_NEGATIVE_QTY''))) {", "reception/card.php:466  //if (GETPOST($qty, ''int'') > 0 || (GETPOST($qty, ''int'') == 0 && getDolGlobalString(''RECEPTION_GETS_ALL_ORDER_PRODUCTS'')) || (GETPOST($qty, ''int'') < 0 && getDolGlobalString(''RECEPTION_ALLOW_NEGATIVE_QTY''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_DRAFT_WATERMARK', 'string', NULL, 'core', 'Sets the watermark text printed on draft reception PDF documents.', 'Written via admin/reception_setup.php:102 and read in core/modules/reception/doc/pdf_squille.modules.php:164-165 to apply the watermark when the reception is in draft status.', 'Setting this constant causes draft reception PDFs to display the specified watermark text; clearing it removes the watermark.', 'String: watermark text to overlay on draft reception PDFs.', 0, 0, 'admin/reception_setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/reception_setup.php:102|write|$res = dolibarr_set_const($db, \"RECEPTION_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "core/modules/reception/doc/pdf_squille.modules.php:164|check|if ($object->status == $object::STATUS_DRAFT && (getDolGlobalString(''RECEPTION_DRAFT_WATERMARK''))) {", "core/modules/reception/doc/pdf_squille.modules.php:165|read|$this->watermark = getDolGlobalString(''RECEPTION_DRAFT_WATERMARK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to reception documents.', 'Written in admin/reception_setup.php:95 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on reception PDFs.', 'Arbitrary string text.', 0, 0, 'admin/reception_setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"RECEPTION_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_GETS_ALL_ORDER_PRODUCTS', 'string', NULL, 'reception', 'Allows reception lines with zero quantity to be included when processing order products.', 'Checked in reception/card.php:467 so that lines with a posted quantity of zero are still added to the reception when this constant is set. The associated commented-out code in reception/card.php:466 also references a negative-quantity variant.', 'Enabling this constant causes order product lines with zero quantity to be included in the reception; without it, only lines with quantity > 0 are processed.', 'Truthy string=zero-qty lines included, empty/unset=zero-qty lines excluded', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:467|check|if (GETPOSTFLOAT($qty) > 0 || (GETPOSTFLOAT($qty) == 0 && getDolGlobalString(''RECEPTION_GETS_ALL_ORDER_PRODUCTS''))) {", "reception/card.php:466  //if (GETPOST($qty, ''int'') > 0 || (GETPOST($qty, ''int'') == 0 && getDolGlobalString(''RECEPTION_GETS_ALL_ORDER_PRODUCTS'')) || (GETPOST($qty, ''int'') < 0 && getDolGlobalString(''RECEPTION_ALLOW_NEGATIVE_QTY''))) {"]', 'low', NULL);
