INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_PDF_HIDE_ORDERED', 'bool', NULL, 'core', 'Hides the ordered quantity column in reception PDF documents when enabled.', 'Displayed as a select in admin/pdf_other.php at line 767. Checked (negated) in pdf_squille.modules.php at lines 565, 720, 776, and 856; checked positively at line 116 to conditionally hide the ordered column header.', 'Enabling this constant removes the ordered quantity column from reception PDFs. Disabling it (or leaving unset) shows the ordered quantity column.', 'Truthy string to hide ordered column; empty/unset to show ordered column.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:767|read|print $form->selectarray(\"RECEPTION_PDF_HIDE_ORDERED\", $arrval, getDolGlobalString(''RECEPTION_PDF_HIDE_ORDERED''));", "core/modules/reception/doc/pdf_squille.modules.php:116|check|if (getDolGlobalString(''RECEPTION_PDF_HIDE_ORDERED'')) {", "core/modules/reception/doc/pdf_squille.modules.php:565|check|if (!getDolGlobalString(''RECEPTION_PDF_HIDE_ORDERED'')) {", "core/modules/reception/doc/pdf_squille.modules.php:776|check|if (!getDolGlobalString(''RECEPTION_PDF_HIDE_ORDERED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_PDF_HIDE_WEIGHT_AND_VOLUME', 'bool', NULL, 'core', 'Hides weight and volume columns in reception PDF documents when enabled.', 'Checked in core/modules/reception/doc/pdf_squille.modules.php:559; when unset the weight and volume section is rendered.', 'When set, weight and volume data are omitted from generated reception PDFs.', 'Bool-like string: empty/unset = weight and volume shown; non-empty = weight and volume hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/reception/doc/pdf_squille.modules.php:559|check|if (!getDolGlobalString(''RECEPTION_PDF_HIDE_WEIGHT_AND_VOLUME'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECEPTION_STANDALONE', 'string', NULL, 'reception', 'Allows creating receptions without a linked supplier order (standalone mode).', 'Checked throughout reception/card.php to enable standalone reception creation (lines 318, 763, 915, 1136, 1150, 2071, 2360) and to control supplier invoice creation availability (line 2911). No admin UI write path exists.', 'Enabling this constant permits receptions to be created and managed without a supplier order origin; disabling it requires a supplier order to be linked.', 'Truthy string=standalone mode enabled, empty/unset=order link required', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:763|check|if (!$origin  && getDolGlobalString(''RECEPTION_STANDALONE'')) {", "reception/card.php:1136|check|if ($action == ''create'' && $origin != ''supplierorder'' && !getDolGlobalString(''RECEPTION_STANDALONE'')) {", "reception/card.php:2911|check|if (isModEnabled(\"supplier_invoice\") && ($object->statut == Reception::STATUS_VALIDATED || $object->statut == Reception::STATUS_CLOSED) && !getDolGlobalString(''RECEPTION_STANDALONE", "reception/card.php:915|read|} elseif ($action == ''addline'' && !$origin && getDolGlobalString(''RECEPTION_STANDALONE'') && $permissiontoadd) {\t// Add a new line"]', 'medium', NULL);
