INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_ENABLE_PUBLIC_INTERFACE', 'bool', NULL, 'recruitment', 'Enables the public-facing recruitment interface that allows external candidates to view and apply for job positions.', 'Written in recruitment/admin/public_interface.php at lines 60, 62, and 69. Checked at lines 113, 131, and 154 of the same file and in public/recruitment/view.php at line 299, which blocks access when the flag is not set.', 'Disabling this constant blocks all access to the public recruitment pages. Enabling it allows anonymous users to browse open positions and submit applications.', '0 = public interface disabled; 1 = public interface enabled', 0, 0, 'recruitment/admin/public_interface.php|recruitment/admin/public_interface.php|recruitment/admin/public_interface.php|recruitment/admin/public_interface.php|recruitment/admin/public_interface.php|recruitment/admin/public_interface.php|recruitment/admin/public_interface.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, ''RECRUITMENT_ENABLE_PUBLIC_INTERFACE'', 1, ''chaine'', 0, '''', $conf->entity);", "if (!getDolGlobalString(''RECRUITMENT_ENABLE_PUBLIC_INTERFACE'')) {", "if (!getDolGlobalInt(''RECRUITMENT_ENABLE_PUBLIC_INTERFACE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_IMAGE_PUBLIC_INTERFACE', 'string', NULL, 'public', 'URL or path of a banner image displayed on the public recruitment interface pages.', 'Checked in public/recruitment/view.php:364 and public/recruitment/index.php:178; when set, an `<img>` tag is rendered with this value as its src. No admin UI write path is present.', 'When set, the image is displayed as a banner on both the recruitment index and job-view public pages.', 'URL or file path string pointing to an image', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''RECRUITMENT_IMAGE_PUBLIC_INTERFACE'')) {", "print ''<img id=\"idRECRUITMENT_IMAGE_PUBLIC_INTERFACE\" src=\"'' . getDolGlobalString(''RECRUITMENT_IMAGE_PUBLIC_INTERFACE'').''\">'';", "print ''<img id=\"idPROJECT_IMAGE_PUBLIC_SUGGEST_BOOTH\" src=\"'' . getDolGlobalString(''RECRUITMENT_IMAGE_PUBLIC_INTERFACE'').''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_NEWFORM_TEXT', 'string', NULL, 'public', 'Custom introductory text shown above the new-application form on public recruitment pages.', 'Checked and read in public/recruitment/view.php and public/recruitment/index.php. When the value matches a regex for a translation key wrapped in parentheses (`/^\((.*)\)$/`), it is treated as a translation key; otherwise the raw string is appended to the page output.', 'Changing this value alters the introductory text displayed to job applicants; wrapping the value in parentheses allows using a Dolibarr language translation key.', 'Plain text string, or a Dolibarr language key wrapped in parentheses e.g. ''(MyTranslationKey)''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''RECRUITMENT_NEWFORM_TEXT'')) {", "if (preg_match(''/^\\((.*)\\)$/'', getDolGlobalString(''RECRUITMENT_NEWFORM_TEXT''), $reg)) {", "$text .= getDolGlobalString(''RECRUITMENT_NEWFORM_TEXT'') . \"<br>\n\";", "if (preg_match(''/^\\((.*)\\)$/'', $conf->global->RECRUITMENT_NEWFORM_TEXT, $reg)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTCANDIDATURE_ADDON', 'string', NULL, 'recruitment', 'Specifies the numbering module class name used to generate reference numbers for recruitment candidatures.', 'Read at recruitment/class/recruitmentcandidature.class.php:1031 and 1030 to load the addon class and file. If not set (line 1023–1024), it defaults to ''mod_recruitmentcandidature_standard'' at runtime without persisting to the database.', 'Changing this value to a different addon class name changes the reference numbering scheme applied to new candidature records.', 'A string class name of a numbering module (e.g. ''mod_recruitmentcandidature_standard'' or a custom module name).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''RECRUITMENT_RECRUITMENTCANDIDATURE_ADDON'')) {", "$conf->global->RECRUITMENT_RECRUITMENTCANDIDATURE_ADDON = ''mod_recruitmentcandidature_standard'';", "$classname = getDolGlobalString(''RECRUITMENT_RECRUITMENTCANDIDATURE_ADDON'');", "$file = getDolGlobalString(''RECRUITMENT_RECRUITMENTCANDIDATURE_ADDON'') . \".php\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTCANDIDATURE_ADVANCED_MASK', 'string', NULL, 'recruitment', 'Stores the custom mask pattern used by the advanced numbering module for recruitment candidature references.', 'Read at recruitment/core/modules/recruitment/mod_recruitmentcandidature_advanced.php:86 (displayed in a form input) and at line 129 (used as the mask for reference generation). Only 2 occurrences and no admin UI write.', 'Changing this mask alters the format of auto-generated reference numbers for recruitment candidatures when the advanced numbering addon is active.', 'A string mask pattern compatible with the advanced numbering module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$mask = getDolGlobalString(''RECRUITMENT_RECRUITMENTCANDIDATURE_ADVANCED_MASK'');", "''maskcand'' value=\"''.getDolGlobalString(''RECRUITMENT_RECRUITMENTCANDIDATURE_ADVANCED_MASK'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON', 'string', NULL, 'recruitment', 'Specifies the numbering module class name used to generate reference numbers for recruitment job positions.', 'Read at recruitment/class/recruitmentjobposition.class.php:1078 and 1077 to load the addon class and file. If not set (line 1070–1071), it defaults to ''mod_recruitmentjobposition_standard'' at runtime without persisting to the database.', 'Changing this value to a different addon class name changes the reference numbering scheme applied to new job position records.', 'A string class name of a numbering module (e.g. ''mod_recruitmentjobposition_standard'' or a custom module name).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON'')) {", "$conf->global->RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON = ''mod_recruitmentjobposition_standard'';", "$classname = getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON'');", "$file = getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON'') . \".php\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON_PDF_ODT_PATH', 'string', NULL, 'recruitment', 'Specifies one or more directories (comma-separated) where custom ODT templates for recruitment job position documents are stored.', 'Read at recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:139 using explode('','', ...) and checked at line 165; the value is also displayed in the module UI at line 188.', 'Setting this to a valid directory path makes custom ODT templates available for recruitment position document generation.', 'String (comma-separated directory paths); empty = only default template directories are searched.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:139|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON_PDF_ODT_PATH''))));", "recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:165|check|if (getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON_PDF_ODT_PATH'')) {", "recruitment/core/modules/recruitment/doc/doc_generic_recruitmentjobposition_odt.modules.php:188|read|$texte .= getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADDON_PDF_ODT_PATH'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTJOBPOSITION_ADVANCED_MASK', 'string', NULL, 'recruitment', 'Stores the numbering mask pattern used by the advanced numbering module for recruitment job positions.', 'Read at recruitment/core/modules/recruitment/mod_recruitmentjobposition_advanced.php:129 to apply the mask and displayed in the module configuration UI at line 86.', 'Changing this value alters the reference number format generated for new recruitment job positions.', 'String (mask pattern, e.g. ''{AA}{0000}''); empty = no mask applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/mod_recruitmentjobposition_advanced.php:129|read|$mask = getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADVANCED_MASK'');", "recruitment/core/modules/recruitment/mod_recruitmentjobposition_advanced.php:86|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskjob\" value=\"''.getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_ADVA"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_RECRUITMENTJOBPOSITION_DRAFT_WATERMARK', 'string', NULL, 'recruitment', 'Sets the watermark text printed on PDF documents for recruitment job positions that are in draft status.', 'Checked and used at recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:741-742; the watermark is applied only when the object status is STATUS_DRAFT.', 'Setting this value causes draft recruitment position PDFs to display the specified watermark text; leaving it empty suppresses the watermark.', 'String (watermark text); empty or unset = no watermark on draft PDFs.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:741|check|if ($object->status == $object::STATUS_DRAFT && getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_DRAFT_WATERMARK'')) {", "recruitment/core/modules/recruitment/doc/pdf_standard_recruitmentjobposition.modules.php:742|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', getDolGlobalString(''RECRUITMENT_RECRUITMENTJOBPOSITION_DRAFT_WATERMARK''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RECRUITMENT_SECURITY_TOKEN', 'string', NULL, 'recruitment', 'Provides a secret token used to generate a secure key appended to public recruitment job position URLs.', 'Checked and read at recruitment/lib/recruitment_recruitmentjobposition.lib.php:141–143. When set, a SHA hash of the token is appended as ''securekey''; when not set, the raw (empty) value is appended. The block is wrapped in a commented-out conditional.', 'Setting this token causes public links to job positions to include a hashed securekey parameter, restricting access to those with the correct URL.', 'Any string secret token; empty/unset means no secure key is generated.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["/*if (getDolGlobalString(''RECRUITMENT_SECURITY_TOKEN'')) {", "if (!getDolGlobalString(''RECRUITMENT_SECURITY_TOKEN'')) $out .= ''&securekey=''.urlencode(getDolGlobalString(''RECRUITMENT_SECURITY_TOKEN''));", "else $out .= ''&securekey=''.urlencode(dol_hash(getDolGlobalString(''RECRUITMENT_SECURITY_TOKEN''), ''2''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RELOAD_PAGE_ON_CUSTOMER_CHANGE_DISABLED', 'bool', NULL, 'reception', 'Disables the automatic page reload triggered when the customer/third-party is changed on document forms.', 'Checked in reception/card.php:1183, compta/facture/card.php:3955, comm/propal/card.php:2410, expedition/card.php:1500, and commande/card.php:2342 — when unset, the page reloads on customer change. Also checked positively in don/card.php:440. No admin UI write path exists.', 'Setting this constant prevents the page from reloading when the customer field changes on invoices, orders, proposals, shipments, and receptions; the customer-context update then relies on other mechanisms.', 'Truthy string/bool=reload disabled, empty/0=reload enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/card.php:1183|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_CUSTOMER_CHANGE_DISABLED'')) {", "compta/facture/card.php:3955|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_CUSTOMER_CHANGE_DISABLED'')) {", "don/card.php:440|check|if (getDolGlobalString(''RELOAD_PAGE_ON_CUSTOMER_CHANGE_DISABLED'')) {", "commande/card.php:2342|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_CUSTOMER_CHANGE_DISABLED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RELOAD_PAGE_ON_SUPPLIER_CHANGE_DISABLED', 'bool', NULL, 'fourn', 'Disables automatic page reload when the supplier is changed on purchase documents.', 'Checked in 3 files: supplier_proposal/card.php:1571, fourn/commande/card.php:2006, and fourn/facture/card.php:2403, always as `if (!getDolGlobalString(''RELOAD_PAGE_ON_SUPPLIER_CHANGE_DISABLED''))`.', 'Setting this value suppresses the automatic page reload triggered by a supplier change, keeping the current page state intact.', 'Truthy string (non-empty) = page reload on supplier change is disabled; empty/not set = page reloads on supplier change.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1571|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_SUPPLIER_CHANGE_DISABLED'')) {", "fourn/commande/card.php:2006|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_SUPPLIER_CHANGE_DISABLED'')) {", "fourn/facture/card.php:2403|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_SUPPLIER_CHANGE_DISABLED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RELOAD_PAGE_ON_TEMPLATE_CHANGE_DISABLED', 'bool', NULL, 'compta', 'When enabled, prevents the invoice page from reloading automatically when the document template is changed.', 'Checked in compta/facture/card.php:4038 and fourn/facture/card.php:2469 to conditionally trigger a page reload on template selection change.', 'Enabling this constant means the page does not reload when the user changes the document template, which may require manual refresh to apply template changes.', '0 or unset = page reloads on template change; truthy = page reload on template change is disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4038|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_TEMPLATE_CHANGE_DISABLED'')) {", "fourn/facture/card.php:2469|check|if (!getDolGlobalString(''RELOAD_PAGE_ON_TEMPLATE_CHANGE_DISABLED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('REPLENISH_ALLOW_VARIABLESIZELIST', 'bool', NULL, 'product', 'Enables a variable-size list mode in the stock replenishment page.', 'Checked in product/stock/replenish.php:765. When set, the replenishment list supports variable sizing.', 'Setting this constant activates variable-size list rendering in the replenishment view.', 'Non-empty = variable-size list enabled; empty or unset = fixed list', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/replenish.php:765|check|if (getDolGlobalString(''REPLENISH_ALLOW_VARIABLESIZELIST'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_HIDE_ADD_CONTACT_THIPARTY', 'bool', NULL, 'resource', 'Hides the ''add third-party contact'' action on the resource contact page when set.', 'Checked in resource/contact.php:167 to suppress the add-thirdparty-contact UI, and in core/lib/resource.lib.php:45 to conditionally show the contacts tab. The comment in admin/resource.php:154 references this constant by name.', 'Setting this hides the ability to link third-party contacts to a resource, which may also affect whether the contacts tab is visible depending on RESOURCE_HIDE_ADD_CONTACT_USER.', 'Empty/unset = show; any non-empty string = hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["resource/contact.php:167|check|if (getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_THIPARTY'')) {", "core/lib/resource.lib.php:45|check|if (!getDolGlobalString(''MAIN_DISABLE_CONTACTS_TAB'') && (!getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_USER'') || !getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_THIPARTY''))) {", "admin/resource.php:154  //RESOURCE_HIDE_ADD_CONTACT_THIPARTY"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_HIDE_ADD_CONTACT_USER', 'bool', NULL, 'resource', 'Hides the ''add user contact'' action on the resource contact page when set.', 'Checked in resource/contact.php:164 to suppress the add-user-contact UI, and in core/lib/resource.lib.php:45 to conditionally show the contacts tab. The comment in admin/resource.php:153 references this constant by name.', 'Setting this hides the ability to link user contacts to a resource, which may also affect whether the contacts tab is visible depending on RESOURCE_HIDE_ADD_CONTACT_THIPARTY.', 'Empty/unset = show; any non-empty string = hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["resource/contact.php:164|check|if (getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_USER'')) {", "core/lib/resource.lib.php:45|check|if (!getDolGlobalString(''MAIN_DISABLE_CONTACTS_TAB'') && (!getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_USER'') || !getDolGlobalString(''RESOURCE_HIDE_ADD_CONTACT_THIPARTY''))) {", "admin/resource.php:153  //RESOURCE_HIDE_ADD_CONTACT_USER"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_ON_PRODUCTS', 'string', NULL, 'core', 'Enables a Resources tab on product pages.', 'Checked in core/lib/product.lib.php:162. When set and the object is a product, a resources tab is added to the product navigation.', 'Setting this constant adds a Resources tab to product pages; clearing it removes the tab.', 'Any non-empty value = show Resources tab on products; empty/unset = no tab', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if ($object->isProduct() && getDolGlobalString(''RESOURCE_ON_PRODUCTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_ON_SERVICES', 'string', NULL, 'core', 'Enables a Resources tab on service pages.', 'Checked in core/lib/product.lib.php:168. When set and the object is a service, a resources tab is added to the service navigation.', 'Setting this constant adds a Resources tab to service pages; clearing it removes the tab.', 'Any non-empty value = show Resources tab on services; empty/unset = no tab', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if ($object->isService() && getDolGlobalString(''RESOURCE_ON_SERVICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_ON_THIRDPARTIES', 'string', NULL, 'core', 'Adds a Resources tab to third-party (company) records when the resource module is enabled.', 'Checked at core/lib/company.lib.php:196 inside a condition that also verifies isModEnabled(''resource''). No comment is present in the payload describing additional semantics.', 'Enabling this constant causes a Resources tab to appear on third-party pages; disabling it hides the tab.', 'Any truthy value shows the Resources tab on third-parties; unset hides it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:196|check|if (isModEnabled(''resource'') && getDolGlobalString(''RESOURCE_ON_THIRDPARTIES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_USED_IN_EVENT_CHECK', 'string', NULL, 'comm', 'Enables availability checking of resources linked to agenda events to prevent double-booking of busy resources.', 'Checked in resource/element_resource.php:144 and comm/action/card.php:607,1076,1264. When set, the code verifies that a dolresource assigned to an action (event) is not already marked busy before allowing the assignment.', 'Enabling this constant adds a busy-resource guard on event creation and update; disabling it removes that check, allowing resources to be assigned to overlapping events without warning.', 'Any non-empty string = enable resource-in-event busy check; empty/unset = no check', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["if (getDolGlobalString(''RESOURCE_USED_IN_EVENT_CHECK'') && $objstat->element == ''action'' && $resource_type == ''dolresource'' && intval($busy) == 1) {", "if (getDolGlobalString(''RESOURCE_USED_IN_EVENT_CHECK'')) {", "if (getDolGlobalString(''RESOURCE_USED_IN_EVENT_CHECK'') && $object->element == ''action'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('RESOURCE_USE_SEARCH_TO_SELECT', 'bool', NULL, 'resource', 'Enables Ajax autocomplete search instead of a static combo box for resource selection.', 'Configured via admin/resource.php:60 (written with dolibarr_set_const) and rendered as a select at line 111. Checked in resource/class/html.formresource.class.php:152 to activate ajax_combobox, and used at line 154 to pass the threshold value to the Ajax call. A commented line at 153 shows the intended minLength usage.', 'When enabled, resource selection fields use an Ajax-powered search box. When disabled or unset, a static dropdown is used.', 'Numeric string used as the minimum character threshold for Ajax search; truthy enables search-to-select. Empty/unset uses static combo box.', 0, 0, 'admin/resource.php|admin/resource.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/resource.php:60|write|if (dolibarr_set_const($db, \"RESOURCE_USE_SEARCH_TO_SELECT\", GETPOST(''activate_RESOURCE_USE_SEARCH_TO_SELECT''), ''chaine'', 0, '''', $conf->entity)) {", "resource/class/html.formresource.class.php:152|check|if (!empty($conf->use_javascript_ajax) && getDolGlobalString(''RESOURCE_USE_SEARCH_TO_SELECT'') && !$forcecombo) {", "resource/class/html.formresource.class.php:154|read|$out .= ajax_combobox($htmlname, $event, $conf->global->RESOURCE_USE_SEARCH_TO_SELECT);", "resource/class/html.formresource.class.php:153  //$minLength = (is_numeric($conf->global->RESOURCE_USE_SEARCH_TO_SELECT)?$conf->global->RESOURCE_USE_SEARCH_TO_SELECT:2);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SALARIES_ACCOUNTING_ACCOUNT_PAYMENT', 'string', NULL, 'accountancy', 'Stores the general ledger account number used for salary payment entries in accounting journals.', 'Read in accountancy/journal/variousjournal.php (lines 195, 211, 215, 216), accountancy/journal/bankjournal.php:271 and :726, and accountancy/journal/treasuryjournal.php:574 (12+ occurrences). Checked against '''' and ''-1''; ''NotDefined'' is used as a fallback reserved word. No admin UI write found; HIDDEN_GUESS is 1.', 'If not set or set to ''-1'', salary payment entries cannot be posted in the various journal and bank journal, blocking payroll accounting.', 'String: general ledger account number; '''' or ''-1'' = not configured (treated as setup error)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/journal/bankjournal.php:271|read|$account_employee = getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT'', ''NotDefined''); // NotDefined is a reserved word", "accountancy/journal/variousjournal.php:215|read|$some_mandatory_steps_of_setup_were_not_done = !getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT'') || getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT'') == ''-1'';", "accountancy/journal/variousjournal.php:195|read||| !getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT'') || getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT'') == ''-1''", "accountancy/journal/bankjournal.php:726|read|$accountingaccountpayment->fetch(0, getDolGlobalString(''SALARIES_ACCOUNTING_ACCOUNT_PAYMENT''), true);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SALARY_MANAGEMENT_PER_WEEK', 'string', NULL, 'salaries', 'Enables weekly-based salary management mode instead of the default monthly mode.', 'Checked in salaries/card.php:769; when set, a different code branch is followed for salary period handling.', 'Enabling this setting switches the salary management UI to weekly periods.', 'Empty/0 = monthly salary management (default); non-empty = weekly salary management.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["salaries/card.php:769|check|if (getDolGlobalString(''SALARY_MANAGEMENT_PER_WEEK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SALES_ORDER_SHOW_SHIPPING_ADDRESS', 'bool', NULL, 'admin', 'When set, includes the shipping address section in generated sales order PDF documents.', 'Managed via the admin UI at admin/pdf_other.php (written by dolibarr_set_const with delete fallback, displayed as a select array). Checked in pdf_einstein.modules.php and pdf_eratosthene.modules.php before rendering the shipping address block.', 'Enabling this adds the shipping address to sales order PDFs. Disabling (or leaving unset) omits the shipping address from those documents.', '0 or empty = no shipping address on order PDF; non-zero = shipping address shown.', 0, 0, 'admin/pdf_other.php|admin/pdf_other.php|admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:102|dolibarr_set_const($db, \"SALES_ORDER_SHOW_SHIPPING_ADDRESS\", GETPOSTINT(\"SALES_ORDER_SHOW_SHIPPING_ADDRESS\"), ''chaine'', 0, '''', $conf->entity);", "admin/pdf_other.php:392|print $form->selectarray(\"SALES_ORDER_SHOW_SHIPPING_ADDRESS\", $arrval, getDolGlobalString(''SALES_ORDER_SHOW_SHIPPING_ADDRESS''));", "pdf_einstein.modules.php:1610|if (getDolGlobalInt(''SALES_ORDER_SHOW_SHIPPING_ADDRESS'')) {", "pdf_eratosthene.modules.php:1867|if (getDolGlobalInt(''SALES_ORDER_SHOW_SHIPPING_ADDRESS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SALE_ORDER_SUGGEST_DOWN_PAYMENT_INVOICE_CREATION', 'string', NULL, 'commande', 'Enables a prompt suggesting the creation of a down payment invoice on the order card.', 'Checked via getDolGlobalInt in commande/card.php:2718. When non-zero, a suggestion UI element for creating a down payment invoice is shown. No admin UI write is present.', 'Setting this constant to a non-zero value displays a down payment invoice suggestion on validated orders. Leaving it at zero or unset suppresses the suggestion.', 'Non-zero integer = down payment invoice suggestion shown; 0 or unset = suggestion hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/card.php:2718|check|if (getDolGlobalInt(''SALE_ORDER_SUGGEST_DOWN_PAYMENT_INVOICE_CREATION'')) {"]', 'low', NULL);
