INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SEARCH_FOR_NEXT_VAL_ON_START_ONLY', 'string', NULL, 'core', 'Controls whether the SQL query for the next sequence value searches with a trailing wildcard (prefix match) or exact match.', 'Used three times in core/lib/functions2.lib.php (lines 1163, 1232, 1295): when set, a ''%'' wildcard is appended to the LIKE pattern, making the search match any record whose key starts with the mask prefix rather than requiring an exact match.', 'Enabling this can cause the sequence engine to consider records from unrelated series when computing the next number, which risks gaps or skips in numbering.', 'Empty/unset = exact LIKE match (no trailing wildcard); any non-empty string = prefix match (trailing ''%'' appended).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:1163|read|$sql .= \" WHERE \".$db->sanitize($field).\" LIKE ''\".$db->escape($maskLike) . (getDolGlobalString(''SEARCH_FOR_NEXT_VAL_ON_START_ONLY'') ? \"%\" : \"\") . \"''\";", "core/lib/functions2.lib.php:1232|read|$sql .= \" WHERE \".$db->sanitize($field).\" LIKE ''\".$db->escape($maskLike) . (getDolGlobalString(''SEARCH_FOR_NEXT_VAL_ON_START_ONLY'') ? \"%\" : \"\") . \"''\";", "core/lib/functions2.lib.php:1295|read|$maskrefclient_sql .= \" WHERE \".$db->sanitize($field).\" LIKE ''\".$db->escape($maskrefclient_maskLike) . (getDolGlobalString(''SEARCH_FOR_NEXT_VAL_ON_START_ONLY'') ? \"%\" : \"\") . \"''\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SEARCH_LIMIT_AJAX', 'string', NULL, 'societe', 'Sets the maximum number of results returned by AJAX autocomplete searches, overriding module-specific limits.', 'Read in societe/ajax/ajaxcompanies.php:142: `$limit = getDolGlobalInt(''SEARCH_LIMIT_AJAX'') ?: 1000; // SEARCH_LIMIT_AJAX is a hidden option that has priority on option THIRDPARTY_LIMIT_SIZE if set.` Also read in core/class/html.form.class.php:3407: `$limit = getDolGlobalInt(''SEARCH_LIMIT_AJAX'') ?: $limit; // SEARCH_LIMIT_AJAX is a hidden option that has priority on visible option PRODUIT_LIMIT_SIZE if set.`', 'Setting this value caps the number of results in AJAX search dropdowns, overriding both THIRDPARTY_LIMIT_SIZE and PRODUIT_LIMIT_SIZE.', 'Integer (maximum result count); 0 or empty means the module-specific limit (e.g. THIRDPARTY_LIMIT_SIZE or PRODUIT_LIMIT_SIZE) applies, defaulting to 1000 for company search.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/ajax/ajaxcompanies.php:142|read|$limit = getDolGlobalInt(''SEARCH_LIMIT_AJAX'') ?: 1000;\t\t// SEARCH_LIMIT_AJAX is a hidden option that has priority on option THIRDPARTY_LIMIT_SIZE if set.", "core/class/html.form.class.php:3407|read|$limit = getDolGlobalInt(''SEARCH_LIMIT_AJAX'') ?: $limit;\t\t// SEARCH_LIMIT_AJAX is a hidden option that has priority on visible option PRODUIT_LIMIT_SIZE if set."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SECURITY_DISABLE_TEST_ON_OBFUSCATED_CONF', 'bool', NULL, 'admin', 'Disables the security test that checks for obfuscated configuration values.', 'Checked in admin/system/security.php:447; when unset the obfuscated-conf test is executed, when set it is skipped.', 'Setting this constant disables a security check, which may allow obfuscated or weak configuration values to go unreported.', 'Bool-like string: empty/unset = test enabled; non-empty = test disabled.', 0, 0, 'admin/system/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/system/security.php:447|check|if (!getDolGlobalString(''SECURITY_DISABLE_TEST_ON_OBFUSCATED_CONF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SELLYOURSAAS_MAIN_EMAIL', 'string', NULL, 'core', 'Stores the main support contact email address for the SellYourSaaS service, used in failure notification messages.', 'Referenced in core/class/commoninvoice.class.php:1895 in a commented-out concatenation to a Stripe failure message string. The constant value would be appended to the support contact prompt.', 'No active effect while commented out; if uncommented, the email address would appear in payment failure messages shown to users.', 'A valid email address string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$stripefailuremessage = ''Action required. Contact the support at '';// . $conf->global->SELLYOURSAAS_MAIN_EMAIL;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SELLYOURSAAS_NBDAYSBEFOREENDOFTRIES', 'string', NULL, 'core', 'Sets the maximum number of days before payment retries are abandoned in the SellYourSaaS billing context.', 'Referenced in core/class/commoninvoice.class.php:1849 in a commented-out line. Default is 35 days if not set.', 'No active effect while commented out; if uncommented, increasing this value extends the retry window before giving up on payment collection.', 'Integer number of days; default is 35.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// $nbdaysbeforeendoftries = (empty($conf->global->SELLYOURSAAS_NBDAYSBEFOREENDOFTRIES) ? 35 : $conf->global->SELLYOURSAAS_NBDAYSBEFOREENDOFTRIES);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SELLYOURSAAS_NBHOURSBETWEENTRIES', 'string', NULL, 'core', 'Sets the minimum number of hours required between successive automatic payment retry attempts in the SellYourSaaS billing context.', 'Referenced in core/class/commoninvoice.class.php:1848 in a commented-out line. The comment specifies the default is 49 hours and explains the rationale: must be more than 48 hours + 1 to ensure one retry per 3 daily batch runs.', 'No active effect while commented out; if uncommented, lowering this value would increase retry frequency.', 'Integer number of hours; default is 49. Comment: ''Must have more that 48 hours + 1 between each try (so 1 try every 3 daily batch)''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// $nbhoursbetweentries = (empty($conf->global->SELLYOURSAAS_NBHOURSBETWEENTRIES) ? 49 : $conf->global->SELLYOURSAAS_NBHOURSBETWEENTRIES);\t\t\t\t// Must have more that 48 hours + 1 between each try (so 1 try every 3 daily batch)"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SENDING_DRAFT_WATERMARK', 'string', NULL, 'core', 'Stores the watermark text to overlay on draft sending (merou template) PDFs.', 'Checked and applied in core/modules/expedition/doc/pdf_merou.modules.php:520-521. When the object status is 0 (draft) and this constant is set, pdf_watermark() is called with the constant''s value from $conf->global->SENDING_DRAFT_WATERMARK.', 'Setting a non-empty value causes draft merou shipping PDFs to display the specified watermark. Clearing the value removes the watermark from those PDFs.', 'Any non-empty string = watermark text displayed on draft merou PDFs; empty/unset = no watermark.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_merou.modules.php:520|if ($object->statut == 0 && (getDolGlobalString(''SENDING_DRAFT_WATERMARK''))) {", "pdf_merou.modules.php:521|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', $conf->global->SENDING_DRAFT_WATERMARK);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SEPA_FORCE_TWO_DECIMAL', 'string', NULL, 'compta', 'Forces amounts in SEPA XML files to always be formatted with exactly two decimal places.', 'Checked in bonprelevement.class.php at lines 2004, 2151, 2387, and 2695 during XML amount formatting for both direct debit and credit transfer SEPA files. No admin UI write path exists.', 'Enabling this constant overrides the default amount formatting in SEPA XML to always use two decimals; without it the standard formatting is applied.', 'Truthy string/bool=two-decimal forced, empty/0=default formatting', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:2004|check|if (getDolGlobalString(''SEPA_FORCE_TWO_DECIMAL'')) {", "compta/prelevement/class/bonprelevement.class.php:2151|check|if (getDolGlobalString(''SEPA_FORCE_TWO_DECIMAL'')) {", "compta/prelevement/class/bonprelevement.class.php:2387|check|if (getDolGlobalString(''SEPA_FORCE_TWO_DECIMAL'')) {", "compta/prelevement/class/bonprelevement.class.php:2695|check|if (getDolGlobalString(''SEPA_FORCE_TWO_DECIMAL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SEPA_USE_IDS', 'bool', NULL, 'compta', 'Switches the SEPA bank transfer ICS field to use the account''s ics_transfer value instead of the standard ics.', 'Checked in compta/bank/card.php:869 and 1218, and used in bonprelevement.class.php:1558 and 2676 to select between $account->ics_transfer and $account->ics when generating SEPA XML. No admin UI write path exists.', 'Enabling this constant causes bank transfer SEPA files to use the dedicated ics_transfer identifier; without it the standard ICS is used for both direct debits and transfers.', 'Truthy string/bool=ics_transfer used for bank transfers, empty/0=standard ics used', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/card.php:869|check|if (getDolGlobalString(\"SEPA_USE_IDS\")) {\t// Use another ICS for bank transfer", "compta/bank/card.php:1218|check|if (getDolGlobalString(\"SEPA_USE_IDS\")) {\t// ICS is not used with bank transfer !", "compta/prelevement/class/bonprelevement.class.php:1558|read|$this->emetteur_ics = (($type == ''bank-transfer'' && getDolGlobalString(\"SEPA_USE_IDS\")) ? $account->ics_transfer : $account->ics);\t// Example \"FR78ZZZ123456\""]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SERVICE_ARE_ECOMMERCE_200238EC', 'string', NULL, 'core', 'Controls VAT rate selection mode for services under EU e-commerce directive 2002/38/EC, determining whether buyer or seller country VAT rates are shown.', 'Checked in core/lib/functions.lib.php:8598 and core/class/html.form.class.php:7487 to apply e-commerce VAT rules. When set, the VAT combo list behavior changes: value 1 shows rates of both purchaser and seller countries; value 2 shows only the purchaser country rate (per comments in html.form.class.php:7489-7490).', 'Enabling this constant changes VAT rate computation for services sold to end customers, applying EU e-commerce directive rules instead of standard domestic VAT logic.', '1 = combo list shows VAT rate of purchaser and seller countries; 2 = combo list shows only the VAT rate of the purchaser country; empty/0 = standard VAT rules apply.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.form.class.php:7489  // If SERVICE_ARE_ECOMMERCE_200238EC=1 combo list vat rate of purchaser and seller countries", "core/class/html.form.class.php:7490  // If SERVICE_ARE_ECOMMERCE_200238EC=2 combo list only the vat rate of the purchaser country", "core/lib/functions.lib.php:8554  *   VATRULE 0: If we are in mode SERVICE_ARE_ECOMMERCE_200238EC and customer is not a company with a vat id, we use default product VAT in buyer country", "core/class/html.form.class.php:7487|check|if ($societe_vendeuse == $mysoc && getDolGlobalString(''SERVICE_ARE_ECOMMERCE_200238EC'')) {    // If option to have vat for end customer for services is on"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SERVICE_BOOTH_LOCATION', 'string', NULL, 'public', 'Stores the ID of the product/service used as the invoice line item for booth location fees.', 'In public/project/suggestbooth.php at line 445, the integer value is used to fetch a product that will be added as an invoice row for the booth location service. No admin UI write path is present.', 'Setting this causes a booth-location service line to be added to the invoice for booth registrations.', 'Integer: ID of the llx_product record representing the booth location service', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/project/suggestbooth.php:445|read|$resultprod = $productforinvoicerow->fetch(getDolGlobalInt(''SERVICE_BOOTH_LOCATION''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SERVICE_CONFERENCE_ATTENDEE_SUBSCRIPTION', 'string', NULL, 'public', 'Stores the ID of the product/service used as the invoice line item for conference attendee subscription fees.', 'In public/eventorganization/attendee_new.php at lines 552-553, when the integer value is greater than 0, the product is fetched and added as an invoice row. No admin UI write path is present.', 'Setting this causes a conference-subscription service line to be added to the invoice for attendee registrations.', 'Integer > 0: ID of the llx_product record representing the conference attendee subscription service', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/eventorganization/attendee_new.php:552|check|if (getDolGlobalInt(''SERVICE_CONFERENCE_ATTENDEE_SUBSCRIPTION'') > 0) {", "public/eventorganization/attendee_new.php:553|read|$resultprod = $productforinvoicerow->fetch(getDolGlobalInt(''SERVICE_CONFERENCE_ATTENDEE_SUBSCRIPTION''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SERVICE_STRICT_MANDATORY_PERIOD', 'string', NULL, 'product', 'When enabled, makes the service period (start and end dates) a strictly mandatory field when adding a service line to invoices, proposals, and orders.', 'Checked in compta/facture/card.php:5020, comm/propal/card.php:2993, and commande/card.php:2710 to enforce period entry. Also checked in product/card.php at lines 1709, 2347, and 2898 to conditionally allow or block period optionality.', 'Enabling this constant blocks submission of service lines without a defined period on invoices, proposals, and orders.', '0 or unset = service period optional; truthy = service period strictly required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:5020|check|if (getDolGlobalString(''SERVICE_STRICT_MANDATORY_PERIOD'')) {", "comm/propal/card.php:2993|check|if (getDolGlobalString(''SERVICE_STRICT_MANDATORY_PERIOD'')) {", "commande/card.php:2710|check|if (getDolGlobalString(''SERVICE_STRICT_MANDATORY_PERIOD'')) {", "product/card.php:2898|check|if (!getDolGlobalString(''SERVICE_STRICT_MANDATORY_PERIOD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_ADD_CONTACTS_IN_EXPORT', 'string', NULL, 'core', 'When enabled, includes shipment contact records in shipment export data sets.', 'Checked four times in core/modules/modExpedition.class.php (lines 257, 281, 285, 318); in each case the condition is ''if ($idcontacts && getDolGlobalString(...))'', meaning contact data is appended to the export only when the constant is set. No admin UI page is listed.', 'Enabling this constant causes contact-related fields to be added to shipment exports; leaving it unset omits contact data from those exports.', '1 or any truthy value = include contacts in export; 0 or unset = contacts excluded.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/modules/modExpedition.class.php:257|check|if ($idcontacts && getDolGlobalString(''SHIPMENT_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modExpedition.class.php:281|check|if ($idcontacts && getDolGlobalString(''SHIPMENT_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modExpedition.class.php:285|check|if ($idcontacts && getDolGlobalString(''SHIPMENT_ADD_CONTACTS_IN_EXPORT'')) {", "core/modules/modExpedition.class.php:318|check|if ($idcontacts && getDolGlobalString(''SHIPMENT_ADD_CONTACTS_IN_EXPORT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_ALLOW_NEGATIVE_QTY', 'bool', NULL, 'expedition', 'Permits negative quantities on shipment lines when enabled.', 'Checked in expedition/class/expedition.class.php:3071. When not set, quantities less than or equal to zero are rejected; when set, negative quantities pass the check.', 'Enabling this constant allows shipment lines with negative quantities, which may be used for return or correction scenarios.', 'Truthy integer (e.g. 1) to allow negative quantities; 0 or unset to reject them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expedition.class.php:3071|check|if ($qty <= 0 || ($qty < 0 && !getDolGlobalInt(''SHIPMENT_ALLOW_NEGATIVE_QTY''))) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_DONT_PREFILL_QTY', 'string', NULL, 'expedition', 'Prevents automatic pre-filling of shipment line quantities when creating a shipment from an order.', 'Checked in expedition/card.php at lines 2124, 2267, 2384, and 2515 using getDolGlobalBool with a default of false; when true, quantity fields are not pre-populated.', 'Enabling this constant requires users to manually enter quantities on each shipment line. Disabling it (or leaving unset) causes quantities to be pre-filled from the source order.', 'true/1 = do not pre-fill quantities; false/0 or unset = pre-fill quantities (default false).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/card.php:2124|check|if (getDolGlobalBool(''SHIPMENT_DONT_PREFILL_QTY'', false)) {", "expedition/card.php:2267|check|if (getDolGlobalBool(''SHIPMENT_DONT_PREFILL_QTY'', false)) {", "expedition/card.php:2384|check|if (getDolGlobalBool(''SHIPMENT_DONT_PREFILL_QTY'', false)) {", "expedition/card.php:2515|check|if (getDolGlobalBool(''SHIPMENT_DONT_PREFILL_QTY'', false)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_GETS_ALL_ORDER_PRODUCTS', 'string', NULL, 'expedition', 'When enabled, includes order lines with zero quantity in shipments, ensuring all ordered products appear even when none have been shipped.', 'Checked across expedition/card.php, expedition/class/expedition.class.php, and compta/facture/card.php at multiple lines. Controls whether zero-quantity lines are included in shipment creation and invoice generation from shipments.', 'Enabling this constant causes shipments to include all order lines regardless of quantity, which affects both shipment records and invoices generated from those shipments.', '0 or unset = only lines with qty > 0 are included in shipments; truthy = zero-quantity lines are also included.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["expedition/class/expedition.class.php:1544|check|if ($value[''q''] > 0 || ($value[''q''] == 0 && getDolGlobalString(''SHIPMENT_GETS_ALL_ORDER_PRODUCTS''))) {", "expedition/card.php:512|check|if (($totalqty > 0 || getDolGlobalString(''SHIPMENT_GETS_ALL_ORDER_PRODUCTS'')) && !$error) {\t\t// There is at least one thing to ship and no error", "compta/facture/card.php:1918|check|if ($srcobject->element == ''shipping'' && getDolGlobalString(''SHIPMENT_GETS_ALL_ORDER_PRODUCTS'') && $lines[$i]->qty == 0) {", "expedition/class/expedition.class.php:1556|check|if ($linebatch->qty == 0 && getDolGlobalString(''SHIPMENT_GETS_ALL_ORDER_PRODUCTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_ROUND_VOLUME_ON_PDF', 'string', NULL, 'core', 'Sets the number of decimal places used when rounding line-item volume on shipment PDFs.', 'Used in pdf_rouget.modules.php and pdf_espadon.modules.php as the precision argument of PHP''s round() when computing volume text per line. Defaults to 5 when unset via getDolGlobalInt(''SHIPMENT_ROUND_VOLUME_ON_PDF'', 5).', 'Changing this value alters the displayed precision of per-line volume figures on shipment PDFs. The default precision is 5 decimal places when the constant is absent.', 'Integer = number of decimal places for rounding (default 5 when unset).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:587|$voltxt = round($object->lines[$i]->volume * $object->lines[$i]->qty_shipped, getDolGlobalInt(''SHIPMENT_ROUND_VOLUME_ON_PDF'', 5))", "pdf_espadon.modules.php:715|$voltxt = round($object->lines[$i]->volume * $object->lines[$i]->qty_shipped, getDolGlobalInt(''SHIPMENT_ROUND_VOLUME_ON_PDF'', 5))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_ROUND_WEIGHT_ON_PDF', 'string', NULL, 'core', 'Sets the number of decimal places used when rounding line-item weight on shipment PDFs.', 'Used in pdf_rouget.modules.php and pdf_espadon.modules.php as the precision argument of PHP''s round() when computing weight text per line. Defaults to 5 when unset via getDolGlobalInt(''SHIPMENT_ROUND_WEIGHT_ON_PDF'', 5).', 'Changing this value alters the displayed precision of per-line weight figures on shipment PDFs. The default precision is 5 decimal places when the constant is absent.', 'Integer = number of decimal places for rounding (default 5 when unset).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:583|$weighttxt = round($object->lines[$i]->weight * $object->lines[$i]->qty_shipped, getDolGlobalInt(''SHIPMENT_ROUND_WEIGHT_ON_PDF'', 5))", "pdf_espadon.modules.php:711|$weighttxt = round($object->lines[$i]->weight * $object->lines[$i]->qty_shipped, getDolGlobalInt(''SHIPMENT_ROUND_WEIGHT_ON_PDF'', 5))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_SIGNATURE_ON_ALL_PAGES', 'string', NULL, 'core', 'Controls whether the online signature image is stamped on every page of the shipment PDF rather than a specific page only.', 'Checked in core/ajax/onlineSign.php:904 and :921 via getDolGlobalString(''SHIPMENT_SIGNATURE_ON_ALL_PAGES''). When truthy the signature block is rendered on every page of the shipment PDF.', 'Enabling this constant causes the signature image to appear on every page of the shipment PDF. Disabling it restricts signature placement to a specific page.', 'Non-empty string = enabled (stamp on all pages). Empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/ajax/onlineSign.php:904|check|if (getDolGlobalString(\"SHIPMENT_SIGNATURE_ON_ALL_PAGES\")) {", "core/ajax/onlineSign.php:921|check|if (!getDolGlobalString(\"SHIPMENT_SIGNATURE_ON_ALL_PAGES\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_STANDALONE', 'string', NULL, 'expedition', 'Allows creating shipments without an origin sales order (standalone shipment mode).', 'Checked in expedition/card.php at lines 321, 862, 1177, 1452, 1467, 2836, and 3122. When truthy and no origin order is linked, standalone shipment creation and line addition are permitted.', 'Enabling this constant allows users to create and manage shipments that are not linked to any sales order. Disabling it restricts shipment creation to order-linked workflows.', 'Truthy string to allow standalone shipments; empty/unset to require an origin order.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/card.php:862|check|if (!$origin && getDolGlobalString(''SHIPMENT_STANDALONE'')) {", "expedition/card.php:1452|check|if (!$origin && $action == ''create'' && !getDolGlobalString(''SHIPMENT_STANDALONE'')) {", "expedition/card.php:1177|read|} elseif ($action == ''addline'' && !$origin && getDolGlobalString(''SHIPMENT_STANDALONE'') && $usercancreate) {\t// Add a new line", "expedition/card.php:321|check|if (!$origin && getDolGlobalString(''SHIPMENT_STANDALONE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPMENT_SUPPORTS_SERVICES', 'string', NULL, 'expedition', 'Allows service-type products to be included in shipment/expedition lines when enabled.', 'Checked extensively across expedition/class/expedition.class.php and expedition/card.php. When set, service products are permitted in shipment lines; when not set, only physical products are allowed by default unless STOCK_SUPPORTS_SERVICES is also set.', 'Enabling this constant allows service lines to be added to shipments, affecting stock movement logic and shipment line validation across multiple files.', 'Truthy value (e.g. 1) to allow services in shipments; empty or 0 to restrict to physical products.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expedition.class.php:538|check|if (empty($this->lines[$i]->product_type) || getDolGlobalString(''STOCK_SUPPORTS_SERVICES'') || getDolGlobalString(''SHIPMENT_SUPPORTS_SERVICES'')) {", "expedition/card.php:2092|check|if ($line->product_type == Product::TYPE_SERVICE && !getDolGlobalString(''STOCK_SUPPORTS_SERVICES'') && !getDolGlobalString(''SHIPMENT_SUPPORTS_SERVICES'')) {", "expedition/card.php:2107|check|if (($line->product_type == Product::TYPE_SERVICE && getDolGlobalString(''SHIPMENT_SUPPORTS_SERVICES'')) || $product->stockable_product == Product::DISABLED_STOCK) {", "expedition/class/expedition.class.php:1282|check|if (!($entrepot_id > 0) && !getDolGlobalString(''STOCK_WAREHOUSE_NOT_REQUIRED_FOR_SHIPMENTS'') && !(getDolGlobalString(''SHIPMENT_SUPPORTS_SERVICES'') && $line->product_type == Product"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPABLE_ORDER_ICON_IN_LIST', 'string', NULL, 'commande', 'Controls whether a shippable-order icon is displayed in the customer order list view.', 'Checked in commande/class/commande.class.php:4397 and commande/list_det.php:2152; the default branch (no icon) is taken when the constant is empty, as noted by the inline comment ''Default code. Default should be this case.''', 'When set, an alternative icon display path is used in order lists; when unset the default (no icon) is used.', 'Bool-like string: empty/unset = default (no icon); non-empty = show shippable icon.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:4397|check|if (!getDolGlobalString(''SHIPPABLE_ORDER_ICON_IN_LIST'')) {", "commande/list_det.php:2152|check|if (!getDolGlobalString(''SHIPPABLE_ORDER_ICON_IN_LIST'')) {  // Default code. Default should be this case."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_DISPLAY_STOCK_ENTRY_DATE', 'string', NULL, 'expedition', 'Displays stock entry date columns in shipment and product batch selection interfaces.', 'Checked in product/class/productbatch.class.php at lines 499, 512, 520, 528, 555 and in expedition/card.php at lines 1937, 2175, 2205, with additional occurrences. Controls conditional rendering of stock entry date data in shipment line picking.', 'When enabled, the stock entry date is shown alongside batch/lot information during shipment preparation, aiding FIFO/FEFO picking decisions.', 'Truthy string (entry date column shown) or empty/unset (column hidden).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/productbatch.class.php:499|check|if (getDolGlobalString(''SHIPPING_DISPLAY_STOCK_ENTRY_DATE'')) {", "product/class/productbatch.class.php:512|check|if (getDolGlobalString(''SHIPPING_DISPLAY_STOCK_ENTRY_DATE'')) {", "expedition/card.php:1937|check|if (getDolGlobalString(''SHIPPING_DISPLAY_STOCK_ENTRY_DATE'')) {", "expedition/card.php:2205|check|if (getDolGlobalString(''SHIPPING_DISPLAY_STOCK_ENTRY_DATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_DRAFT_WATERMARK', 'string', NULL, 'core', 'Stores the watermark text to overlay on draft shipping PDFs.', 'Configurable via the admin UI at admin/expedition.php. When a shipping object is in draft status and this constant is set, its value is assigned to $this->watermark and rendered as a PDF watermark in pdf_rouget.modules.php and pdf_espadon.modules.php. Also used by pdf_eagle.modules.php for stock transfers.', 'Setting a non-empty value causes draft shipment PDFs to display the specified watermark text. Clearing the value removes the watermark from draft PDFs.', 'Any non-empty string = watermark text displayed on draft PDFs; empty/unset = no watermark.', 0, 0, 'admin/expedition.php|admin/expedition.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/expedition.php:99|$res = dolibarr_set_const($db, \"SHIPPING_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "pdf_rouget.modules.php:194|if ($object->statut == $object::STATUS_DRAFT && (getDolGlobalString(''SHIPPING_DRAFT_WATERMARK''))) {", "pdf_rouget.modules.php:195|$this->watermark = getDolGlobalString(''SHIPPING_DRAFT_WATERMARK'');", "pdf_eagle.modules.php:1034|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', $conf->global->SHIPPING_DRAFT_WATERMARK);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_EMAIL_SENDER', 'string', NULL, 'core', 'Overrides the From email address when sending shipping/delivery order emails.', 'Checked in core/tpl/card_presend.tpl.php:190 for the ''shipping'' element. When set, frommail is replaced with this value (line 191).', 'Setting this causes the From address on shipping emails to be replaced with the configured address.', 'Empty/not set = default sender used; email address string = used as From address for shipping emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:190|check|if ($object->element === ''shipping'' && getDolGlobalString(''SHIPPING_EMAIL_SENDER'')) {", "core/tpl/card_presend.tpl.php:191|read|$formmail->frommail = getDolGlobalString(''SHIPPING_EMAIL_SENDER'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_EMAIL_SENDER_NAME', 'string', NULL, 'core', 'Overrides the From display name when sending shipping/delivery order emails.', 'Read in core/tpl/card_presend.tpl.php:192 to set fromname for shipping object send scenarios.', 'Setting this replaces the sender display name in the From field of shipping emails with the configured string.', 'Empty string = default sender name used; any string = used as From display name for shipping emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:192|read|$formmail->fromname = getDolGlobalString(''SHIPPING_EMAIL_SENDER_NAME'', '''');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to shipping/expedition documents.', 'Written in admin/expedition.php:92 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on shipment PDFs.', 'Arbitrary string text.', 0, 0, 'admin/expedition.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"SHIPPING_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_PDF_DISPLAY_AMOUNT_HT', 'string', NULL, 'core', 'Enables display of pre-tax unit amounts (prices) on shipping PDF documents when set.', 'Checked in core/modules/expedition/doc/pdf_rouget.modules.php at lines 123 (with comment ''// Show also the prices''), 605, 799, and 899. Also read in core/modules/expedition/doc/pdf_espadon.modules.php at lines 1443 and 1454 to set column status. No admin UI write is present.', 'When set, price columns are rendered in shipping PDF output across multiple templates. When unset, price columns are hidden.', 'Truthy value (e.g. 1) to show prices on shipping PDFs; 0 or empty to hide them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/expedition/doc/pdf_rouget.modules.php:123|check|if (getDolGlobalString(''SHIPPING_PDF_DISPLAY_AMOUNT_HT'')) {\t// Show also the prices", "core/modules/expedition/doc/pdf_rouget.modules.php:605|check|if (getDolGlobalString(''SHIPPING_PDF_DISPLAY_AMOUNT_HT'')) {", "core/modules/expedition/doc/pdf_espadon.modules.php:1443|read|''status'' => getDolGlobalString(''SHIPPING_PDF_DISPLAY_AMOUNT_HT'') ? 1 : 0,", "core/modules/expedition/doc/pdf_espadon.modules.php:1454|read|''status'' => getDolGlobalString(''SHIPPING_PDF_DISPLAY_AMOUNT_HT'') ? 1 : 0,"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_PDF_HIDE_ORDERED', 'bool', NULL, 'core', 'When set, hides the ordered-quantity column from shipping PDF documents across multiple templates.', 'Controls whether the ordered quantity column is rendered in shipping PDFs. Checked in pdf_rouget.modules.php, pdf_espadon.modules.php, and pdf_merou.modules.php across 9 occurrences.', 'Enabling this removes the ordered quantity from printed shipment documents. Disabling (or leaving unset) causes ordered quantity to be shown.', 'Empty/unset = show ordered quantity; any truthy value = hide ordered quantity.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:145|if (getDolGlobalString(''SHIPPING_PDF_HIDE_ORDERED'')) {", "pdf_rouget.modules.php:595|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_ORDERED'')) {", "pdf_espadon.modules.php:900|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_ORDERED'')) {", "pdf_merou.modules.php:329|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_ORDERED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_PDF_HIDE_QTYTOSHIP', 'bool', NULL, 'core', 'When set, hides the quantity-to-ship column from shipping PDF documents.', 'Checked in pdf_rouget.modules.php, pdf_merou.modules.php, and pdf_espadon.modules.php before rendering or exposing the qty-to-ship column. In pdf_espadon.modules.php the value is mapped to a column status flag.', 'Enabling this removes the quantity-to-ship column from shipping PDFs. Disabling (or leaving unset) shows the column.', 'Empty/unset = show qty-to-ship column; any truthy value = hide qty-to-ship column.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:600|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_QTYTOSHIP'')) {", "pdf_rouget.modules.php:794|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_QTYTOSHIP'')) {", "pdf_merou.modules.php:334|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_QTYTOSHIP'')) {", "pdf_espadon.modules.php:1493|''status'' => !getDolGlobalString(''SHIPPING_PDF_HIDE_QTYTOSHIP''),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_PDF_HIDE_VOLUME', 'bool', NULL, 'core', 'When set, suppresses volume data from line items and totals in shipping PDF documents.', 'Checked in pdf_rouget.modules.php and pdf_espadon.modules.php before rendering per-line volume text and total volume sections. The guard combines checks on non-empty volume values with the negation of this constant.', 'Enabling this hides all volume information (per-line and totals) from shipping PDFs. Disabling (or leaving unset) allows volume to be rendered wherever non-zero values exist.', 'Empty/unset = show volume; any truthy value = hide volume.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:586|if (empty($object->lines[$i]->fk_product_type) && $object->lines[$i]->volume && !getDolGlobalString(''SHIPPING_PDF_HIDE_VOLUME'')) {", "pdf_rouget.modules.php:775|if (!empty($totalVolume) && !getDolGlobalString(''SHIPPING_PDF_HIDE_VOLUME'')) {", "pdf_espadon.modules.php:714|if (empty($object->lines[$i]->fk_product_type) && $object->lines[$i]->volume && !getDolGlobalString(''SHIPPING_PDF_HIDE_VOLUME'')", "pdf_espadon.modules.php:927|if (!empty($totalVolume) && !getDolGlobalString(''SHIPPING_PDF_HIDE_VOLUME'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_PDF_HIDE_WEIGHT_AND_VOLUME', 'bool', NULL, 'core', 'When set, suppresses the weight and volume columns from shipping PDF documents.', 'Controls whether weight and volume data appear in shipping PDFs generated by the rouget template. All four occurrences are in core/modules/expedition/doc/pdf_rouget.modules.php, checked before rendering weight/volume cells.', 'Enabling this hides weight and volume information from printed shipment documents. Disabling (or leaving unset) causes weight and volume to be rendered in the PDF.', 'Empty/unset = show weight and volume; any truthy value = hide weight and volume.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_rouget.modules.php:590|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "pdf_rouget.modules.php:807|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "pdf_rouget.modules.php:131|if (getDolGlobalString(''SHIPPING_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "pdf_rouget.modules.php:875|if (!getDolGlobalString(''SHIPPING_PDF_HIDE_WEIGHT_AND_VOLUME'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHIPPING_USE_ITS_OWN_CONTACTS', 'bool', NULL, 'core', 'Enables shipments to maintain their own independent contact list instead of inheriting contacts from the source order.', 'Checked across core/class/commonobject.class.php:1870, expedition/contact.php:70, api/class/api_setup.class.php:1211, core/tpl/contacts.tpl.php:159/:204/:233, and core/lib/sendings.lib.php:75. When not set, shipping contacts are inherited from the source order; when set, the shipment manages its own contacts. Also used at expedition/class/expedition.class.php:683 to propagate contacts from origin when enabled.', 'When enabled, shipments have their own contact management independent of the source order; when disabled, contacts are inherited from the originating order.', '0 or not set = shipping contacts inherited from source order; non-zero = shipment uses its own independent contact list.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commonobject.class.php:1870|check|if (!getDolGlobalInt(''SHIPPING_USE_ITS_OWN_CONTACTS'') && $this->element == ''shipping'' && $this->origin_id != 0) {", "expedition/contact.php:70|check|if (!getDolGlobalInt(''SHIPPING_USE_ITS_OWN_CONTACTS'') && $typeobject == ''commande'' && $object->origin_object->id && isModEnabled(''order'')) {", "api/class/api_setup.class.php:1211|check|if ($type == ''expedition'' && !getDolGlobalInt(''SHIPPING_USE_ITS_OWN_CONTACTS'')) {", "expedition/class/expedition.class.php:683|check|if (!$error && $this->id && getDolGlobalInt(''SHIPPING_USE_ITS_OWN_CONTACTS'') && getDolGlobalString(''MAIN_PROPAGATE_CONTACTS_FROM_ORIGIN'') && !empty($this->origin_type)"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHOW_DIALOG_HOMEPAGE', 'bool', NULL, 'core', 'Controls whether a dialog popup is shown on the homepage and, if so, its auto-close delay in milliseconds.', 'Checked in core/boxes/box_actions_future.php:218 and core/boxes/box_actions.php:217 for presence, and as an integer >1 at lines 260/259 for the auto-close feature. The value is multiplied by 1000 at lines 263/262 to convert to milliseconds.', 'Setting this to 1 shows the dialog without auto-close; setting it to a value greater than 1 shows the dialog and auto-closes it after (value × 1000) milliseconds.', '0 or not set = no dialog; 1 = dialog shown, no auto-close; integer > 1 = dialog shown, auto-closes after value×1000 ms', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/boxes/box_actions_future.php:218|check|if (getDolGlobalString(''SHOW_DIALOG_HOMEPAGE'')) {", "core/boxes/box_actions_future.php:260|check|if (getDolGlobalInt(''SHOW_DIALOG_HOMEPAGE'') > 1) {    // autoclose after this delay", "core/boxes/box_actions_future.php:263|read|$out .= ''}, ''.($conf->global->SHOW_DIALOG_HOMEPAGE * 1000).'');'';", "core/boxes/box_actions.php:262|read|$out .= ''}, ''.($conf->global->SHOW_DIALOG_HOMEPAGE * 1000).'');'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHOW_SOCINFO_ON_PRINT', 'bool', NULL, 'core', 'Adds company information to the page when printing, if the print CSS option is active.', 'Checked at main.inc.php:3501 when optioncss=''print'' is set and disable_show_socinfo_on_print is not passed. The comment at :3500 documents this behavior.', 'Enabling this inserts company information into the printed view of any page.', '0 or unset = company info not added on print; 1 (truthy) = company info injected when printing', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["main.inc.php:3500  // Permit to add user company information on each printed document by setting SHOW_SOCINFO_ON_PRINT", "main.inc.php:3501|check|if (getDolGlobalString(''SHOW_SOCINFO_ON_PRINT'') && GETPOST(''optioncss'', ''aZ09'') == ''print'' && empty(GETPOST(''disable_show_socinfo_on_print'', ''aZ09''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHOW_SUBPRODUCT_REF_IN_PDF', 'bool', NULL, 'admin', 'Controls whether the product reference of sub-products (kit components) is displayed in PDF line items.', 'Configured via admin/pdf.php (written at line 183, rendered as a yes/no selector at line 643). Checked at core/lib/pdf.lib.php:2021. The payload comment states: ''SHOW_SUBPRODUCT_REF_IN_PDF - Option to show the detail of product ref for kits.''', 'Enabling this shows the individual component references for kit/bundle products in generated PDFs.', 'SHOW_SUBPRODUCT_REF_IN_PDF - Option to show the detail of product ref for kits. 1 = show sub-product ref; 0 or absent = hide sub-product ref.', 0, 0, 'admin/pdf.php|admin/pdf.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/pdf.php:637  // SHOW_SUBPRODUCT_REF_IN_PDF - Option to show the detail of product ref for kits.", "admin/pdf.php:183|write|dolibarr_set_const($db, \"SHOW_SUBPRODUCT_REF_IN_PDF\", GETPOST(''SHOW_SUBPRODUCT_REF_IN_PDF'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "admin/pdf.php:643|read|print $form->selectyesno(''SHOW_SUBPRODUCT_REF_IN_PDF'', getDolGlobalInt(''SHOW_SUBPRODUCT_REF_IN_PDF''), 1);", "core/lib/pdf.lib.php:2021|check|if (getDolGlobalString(''SHOW_SUBPRODUCT_REF_IN_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SHOW_TOTAL_OF_PREVIOUS_LISTS_IN_LIN_PAGE', 'bool', NULL, 'accountancy', 'When enabled, shows a totals section from previous lists on the accounting line-binding (LIN) pages.', 'Checked in accountancy/expensereport/index.php:438, accountancy/customer/index.php:577, and accountancy/supplier/index.php:561. The inline comment on each check reads: ''This part of code looks strange. Why showing a report that should rely on result of this step?''', 'Enabling this constant causes an additional totals block (from a prior step''s report) to appear on binding pages; the code comment indicates this behaviour is considered questionable.', 'Non-empty/truthy = show previous-list totals on LIN pages; empty/unset = hide (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["accountancy/expensereport/index.php:438|check|if (getDolGlobalString(''SHOW_TOTAL_OF_PREVIOUS_LISTS_IN_LIN_PAGE'')) { // This part of code looks strange. Why showing a report that should rely on result of this step ?", "accountancy/customer/index.php:577|check|if (getDolGlobalString(''SHOW_TOTAL_OF_PREVIOUS_LISTS_IN_LIN_PAGE'')) { // This part of code looks strange. Why showing a report that should rely on result of this step ?", "accountancy/supplier/index.php:561|check|if (getDolGlobalString(''SHOW_TOTAL_OF_PREVIOUS_LISTS_IN_LIN_PAGE'')) { // This part of code looks strange. Why showing a report that should rely on result of this step ?"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SINVOICE_EMAIL_SENDER', 'string', NULL, 'core', 'Overrides the From email address when sending salary slip emails.', 'Read in core/tpl/card_presend.tpl.php:181 to set frommail for salary objects when INVOICE_EMAIL_SENDER is also active.', 'Setting this causes the From address on salary slip emails to be replaced with this value.', 'Empty/not set = default sender used; email address string = used as From address for salary emails', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/card_presend.tpl.php:181|read|$formmail->frommail = getDolGlobalString(''SINVOICE_EMAIL_SENDER'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SITUATION_DISPLAY_DIFF_ON_PDF', 'string', NULL, 'core', 'Controls whether the delta (difference) column is shown on situation invoice PDFs.', 'Read in core/lib/pdf.lib.php:2813 as an integer cast to bool, stored in $showDelta. No admin UI write is present.', 'Enabling this causes the incremental difference to be displayed on situation invoice PDFs; disabling it omits the delta column.', 'truthy/non-zero = show delta column; 0/empty = hide delta column', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/pdf.lib.php:2813|read|$showDelta = (bool) getDolGlobalInt(''SITUATION_DISPLAY_DIFF_ON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SKILLDET_ADDON_PDF', 'string', NULL, 'hrm', 'Selects the PDF module/template used to generate skill detail (skilldet) documents.', 'Read in hrm/class/skilldet.class.php:960-961 in an elseif branch: when set, $modele is assigned the constant''s value to determine the PDF generator for skill detail records.', 'If set, the specified PDF module is used for skill detail documents. If unset, another branch (not visible in this payload) determines the template.', 'String name of the PDF module/class for skill detail documents. Empty/unset = default or other selection logic applies.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["hrm/class/skilldet.class.php:960|read|} elseif (getDolGlobalString(''SKILLDET_ADDON_PDF'')) {", "hrm/class/skilldet.class.php:961|read|$modele = getDolGlobalString(''SKILLDET_ADDON_PDF'');"]', 'low', NULL);
