INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SMTPS_CAPTURE_PEER_CERT', 'string', NULL, 'core', 'Enables capture of the peer TLS certificate during SMTP connections.', 'When set, triggers peer certificate capture logic in the SMTP sending routine at core/class/CMailFile.class.php:642. No admin UI manages this constant.', 'Enabling this activates peer certificate capture for SMTP connections; disabling it leaves certificate capture inactive.', 'Any non-empty string value enables peer certificate capture.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:642|check|if (getDolGlobalString(''SMTPS_CAPTURE_PEER_CERT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SMTPS_FORCE_IP_V4', 'string', NULL, 'core', 'Forces SMTP connections to use IPv4 instead of the system default.', 'When set, the SMTP transport is constrained to IPv4 at core/class/CMailFile.class.php:652. No admin UI manages this constant.', 'Enabling this prevents IPv6 use for SMTP; disabling it allows the system default address family.', 'Any non-empty string value forces IPv4.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/CMailFile.class.php:652|check|if (getDolGlobalString(''SMTPS_FORCE_IP_V4'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SN_ADVANCED_MASK', 'string', NULL, 'product', 'Defines the serial-number format mask used by the advanced serial-number module when generating serial numbers for products.', 'Read in core/modules/product_batch/mod_sn_advanced.php at lines 71 and 152 as the primary mask for serial-number generation. Also read in product/card.php at lines 1563, 2177, and 2180 as a fallback when the product-level batch_mask is not set.', 'Changing this value alters how new serial numbers are formatted; existing serial numbers are not renamed. Removing the value causes the module to fall back to the product-level mask if available.', 'No COMMENTS in payload; value is a format mask string. Exact token syntax is not documented in the payload.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/card.php:2177|check|$mask = !empty($object->batch_mask) ? $object->batch_mask : getDolGlobalString(''SN_ADVANCED_MASK'');", "core/modules/product_batch/mod_sn_advanced.php:71|read|$mask = getDolGlobalString(''SN_ADVANCED_MASK'');", "core/modules/product_batch/mod_sn_advanced.php:152|read|$mask = getDolGlobalString(''SN_ADVANCED_MASK'');", "product/card.php:1563|read|$inherited_mask_sn = getDolGlobalString(''SN_ADVANCED_MASK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIAL_NETWORKS_DATA_', 'string', NULL, 'admin', 'Stores JSON configuration data for a specific social network integration, keyed by network name suffix.', 'This is a dynamic constant: the actual key is ''SOCIAL_NETWORKS_DATA_'' + socialNetworkName. Set and deleted via admin/fediverse.php (dolibarr_set_const at lines 131, 228, 256; dolibarr_del_const at line 176). Read at lines 196, 249, 473 to retrieve network-specific JSON data.', 'Setting or clearing this key adds, updates, or removes the stored configuration for the named social network integration.', 'JSON string containing social network configuration data; empty/deleted = no configuration for that network.', 0, 0, 'admin/fediverse.php|admin/fediverse.php|admin/fediverse.php|admin/fediverse.php|admin/fediverse.php|admin/fediverse.php|admin/fediverse.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/fediverse.php:131|write|$result = dolibarr_set_const($db, \"SOCIAL_NETWORKS_DATA_\".$socialNetworkName, $jsonData, ''chaine'', 0, '''', $conf->entity);", "admin/fediverse.php:176|write|$result = dolibarr_del_const($db, \"SOCIAL_NETWORKS_DATA_\".$name, $conf->entity);", "admin/fediverse.php:196|read|$result = getDolGlobalString(\"SOCIAL_NETWORKS_DATA_\".$name);", "admin/fediverse.php:473|read|$jsonData = getDolGlobalString(\"SOCIAL_NETWORKS_DATA_\".$obj->note);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ACCOUNTANCY_CODE_CUSTOMER_INVOICE_MANDATORY', 'string', NULL, 'compta', 'Blocks customer invoice validation when the third party does not have a customer accountancy code defined.', 'Set via societe/admin/societe.php:181 as a yesno type and checked in compta/facture/class/facture.class.php:3619 to raise a validation error when the third party''s code_compta_client is empty. Admin UI at societe/admin/societe.php.', 'Enabling this prevents customer invoices from being validated when the associated third party has no customer accountancy code configured.', '0/no = accountancy code not required; 1/yes = customer accountancy code is mandatory for invoice validation.', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:181|write|$res = dolibarr_set_const($db, \"SOCIETE_ACCOUNTANCY_CODE_CUSTOMER_INVOICE_MANDATORY\", $setaccountancycodecustomerinvoicemandatory, ''yesno'', 0, '''', $conf->entity);", "compta/facture/class/facture.class.php:3619|check|if (getDolGlobalString(''SOCIETE_ACCOUNTANCY_CODE_CUSTOMER_INVOICE_MANDATORY'') && empty($this->thirdparty->code_compta_client)) {"]', 'medium', NULL);
