INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ACCOUNTANCY_CODE_CUSTOMER_UNIQUE', 'string', NULL, 'societe', 'Enforces uniqueness of the customer accountancy code across all third parties.', 'Checked in societe/class/societe.class.php:1419 during validation; if the customer accountancy code is already used, an error is raised. No admin UI write found; HIDDEN_GUESS is 1. Only 1 occurrence found.', 'When enabled, saving a third party with a customer accountancy code already used by another record raises a validation error.', 'Any non-empty value = uniqueness enforced; empty = duplicates allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:1419|check|if ($vallabel && getDolGlobalString(''SOCIETE_ACCOUNTANCY_CODE_CUSTOMER_UNIQUE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ACCOUNTANCY_CODE_SUPPLIER_INVOICE_MANDATORY', 'string', NULL, 'fourn', 'Makes a supplier''s accountancy code mandatory when validating a supplier invoice.', 'Checked in fourn/class/fournisseur.facture.class.php:1879 during invoice validation; if set and the supplier has no accountancy code (code_compta_fournisseur), an error is raised. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant blocks supplier invoice validation when the supplier''s accountancy code is missing, enforcing data completeness for accounting exports.', 'Empty/not set = not mandatory; any non-empty value = mandatory', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.facture.class.php:1879|check|if (getDolGlobalString(''SOCIETE_ACCOUNTANCY_CODE_SUPPLIER_INVOICE_MANDATORY'') && empty($this->thirdparty->code_compta_fournisseur)) {"]', 'low', NULL);
