INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ADDRESSES_MANAGEMENT', 'string', NULL, 'contact', 'Switches the contact/address module terminology and behavior between a contacts-only mode and a combined contacts-and-addresses mode.', 'Read in 19 locations including core/menus/standard/eldy.lib.php:1360, fourn/contact.php:118, contact/messaging.php:222, and contact/canvas/default/actions_contactcard_default.class.php:64, :67, :70. When set, UI labels use ''Contacts''/''Contact''/''EditContact''/''NewContact''; when unset, labels use ''ContactsAddresses''/''ContactAddress''/''EditContactAddress''/''NewContactAddress''.', 'Enabling this constant changes menu labels, page titles, and UI strings throughout the contacts subsystem from address-oriented to contact-oriented terminology.', 'Truthy (non-empty / 1) = contacts-only mode (labels: ''Contacts'', ''Contact''); falsy (empty / 0) = contacts-and-addresses mode (labels: ''ContactsAddresses'', ''ContactAddress'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/menus/standard/eldy.lib.php:1360|read|$newmenu->add(\"/societe/index.php?leftmenu=thirdparties\", (getDolGlobalString(''SOCIETE_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"Contacts\") : $langs->trans(\"ContactsAddresses\"))", "fourn/contact.php:118|read|$title = (getDolGlobalString(''SOCIETE_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"ListOfContacts\") : $langs->trans(\"ListOfContactsAddresses\"));", "contact/messaging.php:222|read|$title = (getDolGlobalString(''SOCIETE_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"Contacts\") : $langs->trans(\"ContactsAddresses\"));", "contact/canvas/default/actions_contactcard_default.class.php:64|read|$out .= (getDolGlobalString(''SOCIETE_ADDRESSES_MANAGEMENT'') ? $langs->trans(\"Contact\") : $langs->trans(\"ContactAddress\"));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ADD_REF_IN_LIST', 'string', NULL, 'societe', 'Controls whether and which customer/supplier reference codes are appended to the company name in selection lists.', 'Written via societe/admin/societe.php (line 195). Checked in societe/class/societe.class.php (lines 3274, 3276, 3280, 3285) with specific integer comparisons. COMMENT: `// Search in ''code_client'' when SOCIETE_ADD_REF_IN_LIST is set to 1` (comm/propal/list.php:684).', 'Setting this value to 1 shows both customer and supplier codes; 2 shows only customer code; 3 shows only supplier code; 0 shows no codes.', '0 = no reference codes shown; 1 = show both customer and supplier codes; 2 = show customer code only; 3 = show supplier code only.', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["comm/propal/list.php:684  // Search in ''code_client'' when SOCIETE_ADD_REF_IN_LIST is set to 1", "societe/class/societe.class.php:3276|check|if (($this->client) && (!empty($this->code_client)) && (getDolGlobalInt(''SOCIETE_ADD_REF_IN_LIST'') == 1 || getDolGlobalInt(''SOCIETE_ADD_REF_IN_LIST'') == 2)) {", "societe/class/societe.class.php:3280|check|if (($this->fournisseur) && (!empty($this->code_fournisseur)) && (getDolGlobalInt(''SOCIETE_ADD_REF_IN_LIST'') == 1 || getDolGlobalInt(''SOCIETE_ADD_REF_IN_LIST'') == 3)) {", "societe/admin/societe.php:195|write|$res = dolibarr_set_const($db, \"SOCIETE_ADD_REF_IN_LIST\", $setaddrefinlist, ''yesno'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ALLOW_SEARCH_ON_ROWID', 'bool', NULL, 'societe', 'Allows searching for third parties by their internal database row ID in AJAX company search.', 'Checked in a single location: societe/ajax/ajaxcompanies.php:127.', 'Enabling this setting lets users type a numeric ID to retrieve a specific third-party record directly by rowid.', 'Truthy string (non-empty) = rowid search enabled; empty/not set = rowid search disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/ajax/ajaxcompanies.php:127|check|if (getDolGlobalString(''SOCIETE_ALLOW_SEARCH_ON_ROWID'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ASK_FOR_SHIPPING_METHOD', 'string', NULL, 'comm', 'Enables the shipping method field on third-party records and propagates it to proposals and PDF documents.', 'When enabled, a shipping method field is displayed on third-party (societe) cards and is carried over to commercial proposals. Configured via societe/admin/societe.php. PDF modules (pdf_cyan, pdf_azur) also render the shipping method when this constant is set.', 'Enabling this allows capturing a preferred shipping method per third party, which then appears on proposals and generated PDF documents. Disabling hides the field entirely.', 'Truthy = shipping method field enabled; empty/falsy = disabled', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:251|write|$res = dolibarr_set_const($db, \"SOCIETE_ASK_FOR_SHIPPING_METHOD\", $setaskforshippingmet, ''yesno'', 0, '''', $conf->entity);", "comm/propal/card.php:2487|check|if (getDolGlobalString(''SOCIETE_ASK_FOR_SHIPPING_METHOD'') && !empty($soc->shipping_method_id)) {", "core/modules/propale/doc/pdf_cyan.modules.php:1139|check|if (getDolGlobalString(''SOCIETE_ASK_FOR_SHIPPING_METHOD'') && !empty($this->emetteur->shipping_method_id)) {", "comm/card.php:629|check|if (getDolGlobalString(''SOCIETE_ASK_FOR_SHIPPING_METHOD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ASK_FOR_WAREHOUSE', 'string', NULL, 'societe', 'When enabled, displays a warehouse selection field on third-party and sales order cards.', 'Configured via admin/stock.php:823 using a select array. Checked in societe/card.php:3263 and comm/card.php:608 when the stock module is active. Three occurrences across three files.', 'Enabling this constant adds a warehouse selector to the third-party and commercial card interfaces when the stock module is enabled.', 'String value from a predefined array; unset or empty = warehouse not shown.', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:823|read|print $form->selectarray(\"SOCIETE_ASK_FOR_WAREHOUSE\", $arrval, getDolGlobalString(''SOCIETE_ASK_FOR_WAREHOUSE''));", "societe/card.php:3263|check|if (isModEnabled(''stock'') && getDolGlobalString(''SOCIETE_ASK_FOR_WAREHOUSE'')) {", "comm/card.php:608|check|if (isModEnabled(''stock'') && getDolGlobalString(''SOCIETE_ASK_FOR_WAREHOUSE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_CODECLIENT_ADDON', 'string', NULL, 'societe', 'Specifies the name of the add-on module used to generate customer codes for third parties.', 'Set via the societe admin UI (societe/admin/societe.php line 69 write, line 419 check). The value selects which code-generation module file is active. Checked extensively in societe/class/societe.class.php (lines 3813, 3847, 3878, 3919, 3966, 4008) to decide whether to invoke the add-on.', 'Changing this constant switches the customer code generation algorithm; all subsequent customer code assignments will use the newly selected add-on.', 'Name of a valid customer code add-on module (e.g. ''mod_codeclient_leopard'')', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:69|write|$result = dolibarr_set_const($db, \"SOCIETE_CODECLIENT_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "societe/admin/societe.php:419|check|if (getDolGlobalString(''SOCIETE_CODECLIENT_ADDON'') == (string) $file) {", "societe/class/societe.class.php:3813|check|if (getDolGlobalString(''SOCIETE_CODECLIENT_ADDON'')) {", "societe/class/societe.class.php:3847|check|if (getDolGlobalString(''SOCIETE_CODECLIENT_ADDON'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_CODECOMPTA_ADDON', 'string', NULL, 'societe', 'Specifies the name of the add-on module used to generate accounting codes for third parties.', 'Set via the societe admin UI (societe/admin/societe.php line 76 write, line 501 check). Read in societe/class/societe.class.php at line 4049 to load the accounting code module.', 'Changing this constant switches the accounting code generation module used when creating or updating third parties.', 'Name of a valid accounting code add-on module', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:76|write|$result = dolibarr_set_const($db, \"SOCIETE_CODECOMPTA_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "societe/admin/societe.php:501|check|if (getDolGlobalString(''SOCIETE_CODECOMPTA_ADDON'') == \"$file\") {", "societe/class/societe.class.php:4048|check|if (getDolGlobalString(''SOCIETE_CODECOMPTA_ADDON'')) {", "societe/class/societe.class.php:4049|read|$module = getDolGlobalString(''SOCIETE_CODECOMPTA_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_BANKACCOUNT', 'bool', NULL, 'societe', 'Disables the bank account (RIB) tab and related functionality for third-party records.', 'Configured via admin/bank.php (admin/bank.php:540). Checked in 6 occurrences: admin/bank.php, societe/paymentmodes.php (three times), and core/lib/company.lib.php:214. Gates both the display of bank account sections and online signing functionality.', 'When enabled, the bank account section is hidden from company/contact records and online signing options for RIB are also suppressed.', '0 or unset = bank account section enabled; non-zero = bank account section disabled', 0, 0, 'admin/bank.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/bank.php:540|check|if (!getDolGlobalInt(''SOCIETE_DISABLE_BANKACCOUNT'')) {", "core/lib/company.lib.php:214|check|if (!getDolGlobalInt(''SOCIETE_DISABLE_BANKACCOUNT'')) {", "societe/paymentmodes.php:1758|check|if (!getDolGlobalInt(''SOCIETE_DISABLE_BANKACCOUNT'') && getDolGlobalInt(\"SOCIETE_RIB_ALLOW_ONLINESIGN\")) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_BUILDDOC', 'bool', NULL, 'societe', 'Disables the document generation section on third-party and payment mode cards.', 'Checked in 3 occurrences: societe/card.php:3569 and societe/paymentmodes.php:1925 gate the build-document section; hrm/position_card.php:356 contains a commented-out reference to the same constant.', 'When enabled, users cannot generate documents (e.g. PDF) from the third-party card or payment modes pages.', '0 or unset = document generation enabled; non-empty = document generation disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["hrm/position_card.php:356  //\tif (empty($conf->global->SOCIETE_DISABLE_BUILDDOC)) {", "societe/paymentmodes.php:1925|check|if (!getDolGlobalString(''SOCIETE_DISABLE_BUILDDOC'')) {", "societe/card.php:3569|check|if (!getDolGlobalString(''SOCIETE_DISABLE_BUILDDOC'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_CONTACTS', 'bool', NULL, 'contact', 'When enabled, hides and disables the contacts management feature on third-party cards.', 'Checked across societe/card.php, societe/contact.php, contact/card.php, contact/class/contact.class.php, and contact/perso.php in 19 occurrences to gate contact-related UI and logic. No admin UI write is present.', 'Enabling this constant removes contact tabs and contact-related actions from third-party views throughout the application.', 'Boolean flag; unset or 0 = contacts enabled; any truthy value = contacts disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:3607|check|if (!getDolGlobalString(''SOCIETE_DISABLE_CONTACTS'')) {", "societe/contact.php:221|check|if (!getDolGlobalString(''SOCIETE_DISABLE_CONTACTS'')) {", "contact/class/contact.class.php:398|check|if (!getDolGlobalString(''SOCIETE_DISABLE_CONTACTS'')) {", "contact/card.php:695|check|if (!getDolGlobalString(''SOCIETE_DISABLE_CONTACTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_CUSTOMERS', 'bool', NULL, 'core', 'Disables the customer feature across Dolibarr, hiding customer-related menus, boxes, and statistics.', 'When set, customer menus and dashboard boxes are hidden and customer-related stats on the societe index are suppressed. Checked in core menus, boxes, and societe/class/societe.class.php at line 3427.', 'Enabling this constant removes customer menus and boxes from the interface and prevents customer-type logic from executing in societe.class.php.', '0 or empty = customers enabled; any truthy value = customers disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/menus/standard/eldy.lib.php:1318|check|if (isModEnabled(''societe'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'')) {", "societe/class/societe.class.php:3427|check|if (($this->client == 1 || $this->client == 3) && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'')) {", "core/boxes/box_clients.php:56|check|if (getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'')) {", "societe/index.php:139|check|if (isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS_STATS'') && ("]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_CUSTOMERS_STATS', 'bool', NULL, 'societe', 'When enabled, suppresses the customers statistics section on the thirdparty dashboard and the global state board.', 'Checked in societe/index.php:139, :168, :194 and core/boxes/box_dolibarr_state_board.php:109 in conjunction with SOCIETE_DISABLE_CUSTOMERS to gate display of customer statistics. No admin UI write path is present in the payload.', 'Enabling this constant hides customer count and statistics from the thirdparty dashboard and the global state board box.', 'Truthy value to hide customers stats; unset or 0 to show.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/index.php:139|check|if (isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS_STATS'') && (", "societe/index.php:168|check|if (isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS_STATS'')) {", "core/boxes/box_dolibarr_state_board.php:109|read|''customers'' => isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS_S"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_DEFAULT_SALESREPRESENTATIVE', 'bool', NULL, 'core', 'Prevents automatic assignment of the current user as the default sales representative when creating a new third party.', 'In core/class/html.form.class.php, the default sales representative is auto-selected only when the selected value is <= -4 or empty and this constant is not set. No admin UI write; hidden setting.', 'Enabling this constant suppresses automatic pre-selection of a default sales representative in the third-party form; disabling it allows the auto-selection to occur.', 'Non-empty (truthy) disables default sales rep assignment; empty or undefined enables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:2228|check|if ((is_numeric($selected) && ($selected < -4 || empty($selected))) && !getDolGlobalString(''SOCIETE_DISABLE_DEFAULT_SALESREPRESENTATIVE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_PARENTCOMPANY', 'bool', NULL, 'societe', 'When enabled, hides the parent company field and subsidiary display on third-party cards.', 'Checked in societe/card.php:1984, :2844, :3443, and :3584 to gate both the parent company selector and the subsidiaries list. Four occurrences in one file. No admin UI write is present.', 'Enabling this constant removes the parent company input and the subsidiaries section from third-party views.', 'Boolean flag; unset or 0 = parent company field shown; any truthy value = parent company field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1984|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PARENTCOMPANY'')) {", "societe/card.php:2844|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PARENTCOMPANY'')) {", "societe/card.php:3443|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PARENTCOMPANY'')) {", "societe/card.php:3584|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PARENTCOMPANY'') && !getDolGlobalString(''SOCIETE_DISABLE_SHOW_SUBSIDIARIES'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_PROSPECTS', 'bool', NULL, 'core', 'Disables the prospect status and all prospect-related features across the application.', 'Checked in 30+ locations including admin/dict.php:569, core/menus/standard/eldy.lib.php:1310, :1336, :1339, core/boxes/box_prospect.php:58, contact/class/contact.class.php:404, and societe/class/societe.class.php:3420. Configured via admin/dict.php. When set, prospect menu items, dictionary entries, and prospect fields are hidden.', 'Enabling this constant removes prospect-related UI elements, menu entries, and dictionary conditions throughout the application; disabling re-enables the full prospect workflow.', 'Any non-empty value = prospects disabled; empty = prospects enabled', 0, 0, 'admin/dict.php|admin/dict.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/dict.php:569|read|$tabcond[DICT_PROSPECTLEVEL] = (isModEnabled(\"societe\") && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS''));", "core/menus/standard/eldy.lib.php:1310|check|if (isModEnabled(''societe'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'')) {", "core/boxes/box_prospect.php:58|check|if (getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'')) {", "contact/class/contact.class.php:404|check|if (getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') || !getDolGlobalString(''THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES'')) {\t// Default behaviour"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_PROSPECTSCUSTOMERS', 'bool', NULL, 'societe', 'Disables the combined ''prospect-customer'' third-party status (client type 3), allowing only separate prospect or customer statuses.', 'Set via societe/admin/societe.php:265 as a ''yesno'' constant. Checked in societe/class/societe.class.php:2595, societe/card.php:1065, and core/class/html.formcompany.class.php at lines 1093 and 1113 (10 occurrences). When enabled, client type 3 (prospect+customer) is hidden from status selectors.', 'Enabling this constant removes the prospect-customer combined option from third-party status forms; existing records with client==3 may be affected as shown in societe/card.php:1065.', 'yesno: ''1'' or ''yes'' = combined status disabled; ''0'' or empty = combined status available', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:265|write|$res = dolibarr_set_const($db, \"SOCIETE_DISABLE_PROSPECTSCUSTOMERS\", $setdisableprospectcustomer, ''yesno'', 0, '''', $conf->entity);", "societe/class/societe.class.php:2595|check|if (($this->client == 2 || $this->client == 3) && !getDolGlobalInt(''SOCIETE_DISABLE_PROSPECTSCUSTOMERS'')) {", "societe/card.php:1065|check|if (getDolGlobalString(''SOCIETE_DISABLE_PROSPECTSCUSTOMERS'') && $object->client == 3) {", "core/class/html.formcompany.class.php:1093|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') && !getDolGlobalString(''SOCIETE_DISABLE_CUSTOMERS'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTSCUSTOMERS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_PROSPECTS_STATS', 'bool', NULL, 'societe', 'When enabled, suppresses the prospects statistics section on the thirdparty dashboard and the global state board.', 'Checked in societe/index.php:135, :165, :189 and core/boxes/box_dolibarr_state_board.php:110 always in conjunction with SOCIETE_DISABLE_PROSPECTS to gate the display of prospect statistics. No admin UI write path is present in the payload.', 'Enabling this constant hides prospect count and statistics from the thirdparty dashboard and the global state board box.', 'Truthy value to hide prospects stats; unset or 0 to show.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/index.php:135|check|if (isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS_STATS'') && (", "societe/index.php:165|check|if (isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS_STATS'')) {", "core/boxes/box_dolibarr_state_board.php:110|read|''prospects'' => isModEnabled(''societe'') && $user->hasRight(''societe'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') && !getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS_S"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_SHOW_SUBSIDIARIES', 'bool', NULL, 'societe', 'When enabled, hides the subsidiaries list on third-party cards even when parent company display is active.', 'Checked in societe/card.php:3584 in combination with SOCIETE_DISABLE_PARENTCOMPANY to gate the subsidiaries section. Only one occurrence in the payload. No admin UI write is present.', 'Enabling this constant suppresses the display of subsidiary third parties on the parent company card.', 'Boolean flag; unset or 0 = subsidiaries shown (if parent company display is enabled); any truthy value = subsidiaries hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:3584|check|if (!getDolGlobalString(''SOCIETE_DISABLE_PARENTCOMPANY'') && !getDolGlobalString(''SOCIETE_DISABLE_SHOW_SUBSIDIARIES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_STATE', 'bool', NULL, 'public', 'Disables the state/province field for third-party (company/contact) records.', 'Checked in 15 occurrences across societe/card.php, contact/card.php, resource/card.php, and public project pages. Each check gates the rendering or processing of the state field.', 'When enabled, the state/province field is hidden and not processed for companies, contacts, resources, and public-facing forms.', '0 or unset = state field enabled; non-empty = state field disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1653|check|if (!getDolGlobalString(''SOCIETE_DISABLE_STATE'')) {", "contact/card.php:770|check|if (!getDolGlobalString(''SOCIETE_DISABLE_STATE'')) {", "resource/card.php:331|check|if (!getDolGlobalString(''SOCIETE_DISABLE_STATE'') && $countryid > 0) {", "public/project/new.php:526|check|if (!getDolGlobalString(''SOCIETE_DISABLE_STATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_SUPPLIERS_INVOICES_STATS', 'bool', NULL, 'core', 'Suppresses the supplier invoices counter from the Dolibarr state-board dashboard widget.', 'Read in core/boxes/box_dolibarr_state_board.php:127. When set, the ''supplier_invoices'' key is excluded from the stats array regardless of whether the supplier_invoice module is enabled.', 'Setting this constant removes the supplier invoices statistic from the dashboard board; clearing it restores visibility subject to module and permission checks.', 'Any non-empty value = disable supplier invoices stats on dashboard; empty/unset = show stats', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["''supplier_invoices'' => isModEnabled(''supplier_invoice'') && $user->hasRight(''fournisseur'', ''facture'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_SUPPLIERS_INVOICES_STATS''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_SUPPLIERS_ORDERS_STATS', 'bool', NULL, 'core', 'Suppresses the supplier orders counter from the Dolibarr state-board dashboard widget.', 'Read in core/boxes/box_dolibarr_state_board.php:126. When set, the ''supplier_orders'' key is excluded from the stats array regardless of whether the supplier_order module is enabled.', 'Setting this constant removes the supplier orders statistic from the dashboard board; clearing it restores visibility subject to module and permission checks.', 'Any non-empty value = disable supplier orders stats on dashboard; empty/unset = show stats', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["''supplier_orders'' => isModEnabled(''supplier_order'') && $user->hasRight(''fournisseur'', ''commande'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_SUPPLIERS_ORDERS_STATS''),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_SUPPLIERS_PROPOSAL_STATS', 'bool', NULL, 'core', 'Suppresses the supplier proposals counter from the Dolibarr state-board dashboard widget.', 'Read in core/boxes/box_dolibarr_state_board.php:128. When set, the ''supplier_proposals'' key is excluded from the stats array regardless of whether the supplier_proposal module is enabled.', 'Setting this constant removes the supplier proposals statistic from the dashboard board; clearing it restores visibility subject to module and permission checks.', 'Any non-empty value = disable supplier proposals stats on dashboard; empty/unset = show stats', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["''supplier_proposals'' => isModEnabled(''supplier_proposal'') && $user->hasRight(''supplier_proposal'', ''lire'') && !getDolGlobalString(''SOCIETE_DISABLE_SUPPLIERS_PROPOSAL_STATS''),"]', 'low', NULL);
