INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_DISABLE_WORKFORCE', 'bool', NULL, 'societe', 'When enabled, hides the workforce (number of employees) field on third-party cards.', 'Checked in societe/card.php:3324 and :1894, :2773 to conditionally render the workforce field alongside the third-party type field. Five occurrences in one file. No admin UI write is present.', 'Enabling this constant removes the workforce input field from third-party creation and edit forms.', 'Boolean flag; unset or 0 = workforce field shown; any truthy value = workforce field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:3324|check|if (!getDolGlobalString(''SOCIETE_DISABLE_WORKFORCE'')) {", "societe/card.php:1894|check|if (!getDolGlobalString(''SOCIETE_DISABLE_WORKFORCE'')) {", "societe/card.php:2773|check|if (!getDolGlobalString(''SOCIETE_DISABLE_WORKFORCE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_EMAIL_INVOICE_MANDATORY', 'string', NULL, 'compta', 'Blocks invoice validation when the associated third party does not have a valid email address.', 'Checked in compta/facture/class/facture.class.php:3610 and fourn/class/fournisseur.facture.class.php:1871, both combined with isValidEmail() to raise a validation error. No admin UI is present.', 'Enabling this prevents invoices (customer and supplier) from being validated when the third party''s email is absent or invalid.', '0 or unset = email not required; truthy value = third party email is mandatory for invoice validation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/class/facture.class.php:3610|check|if (getDolGlobalString(''SOCIETE_EMAIL_INVOICE_MANDATORY'') && !isValidEmail($this->thirdparty->email)) {", "fourn/class/fournisseur.facture.class.php:1871|check|if (getDolGlobalString(''SOCIETE_EMAIL_INVOICE_MANDATORY'') && !isValidEmail($this->thirdparty->email)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_EMAIL_MANDATORY', 'string', NULL, 'societe', 'Makes the email field mandatory when creating or editing a third party (company or contact).', 'Checked in societe/class/societe.class.php:1373 during validation and used in societe/card.php:1691 and :2562, contact/card.php:1098, public/company/new.php:405, and societe/class/api_thirdparties.class.php:67 (11 occurrences across multiple files). No admin UI write found; HIDDEN_GUESS is 1.', 'When enabled, saving a third party or contact without a valid email address raises a validation error; the email field is marked as required in forms.', 'Any non-empty value = email mandatory; empty = optional', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:1373|check|if (getDolGlobalString(''SOCIETE_EMAIL_MANDATORY'') && !isValidEmail($this->email)) {", "societe/card.php:1691|read|print ''<tr><td>''.$form->editfieldkey(''EMail'', ''email'', '''', $object, 0, ''string'', '''', getDolGlobalInt(''SOCIETE_EMAIL_MANDATORY'')).''</td>'';", "societe/class/api_thirdparties.class.php:67|check|if (getDolGlobalString(''SOCIETE_EMAIL_MANDATORY'')) {", "societe/canvas/company/tpl/card_create.tpl.php:153|read|<td><?php echo $langs->trans(''EMail'').($conf->global->SOCIETE_EMAIL_MANDATORY ? ''*'' : ''''); ?></td>"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_EMAIL_UNIQUE', 'string', NULL, 'societe', 'Enforces uniqueness of the email address across all third parties.', 'Checked in societe/class/societe.class.php:1380 during validation; if the email is already used by another third party, an error is raised. No admin UI write found; HIDDEN_GUESS is 1. Only 1 occurrence found.', 'When enabled, saving a third party with an email address already used by another record raises a validation error.', 'Any non-empty value = uniqueness enforced; empty = duplicates allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:1380|check|if (!$error && $vallabel && getDolGlobalString(''SOCIETE_EMAIL_UNIQUE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ENABLE_PUBLIC', 'bool', NULL, 'societe', 'Enables the public-facing company self-registration interface.', 'Written in societe/admin/public_interface.php (lines 62, 64, 71) to toggle the feature, and checked at :115, :138, and public/company/new.php:89 to gate access to the public form.', 'Enabling this opens a public URL where external users can register a company; disabling it blocks access to that URL.', '0 = public interface disabled; 1 = public interface enabled', 0, 0, 'societe/admin/public_interface.php|societe/admin/public_interface.php|societe/admin/public_interface.php|societe/admin/public_interface.php|societe/admin/public_interface.php|societe/admin/public_interface.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/public_interface.php:62|write|dolibarr_set_const($db, ''SOCIETE_ENABLE_PUBLIC'', 1, ''chaine'', 0, '''', $conf->entity);", "societe/admin/public_interface.php:64|write|dolibarr_set_const($db, ''SOCIETE_ENABLE_PUBLIC'', 0, ''chaine'', 0, '''', $conf->entity);", "public/company/new.php:89|check|if (!getDolGlobalString(''SOCIETE_ENABLE_PUBLIC'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_EUID_MANDATORY', 'string', NULL, 'societe', 'Makes the EUID (European Unique Identifier) field mandatory when creating or editing a third party.', 'Checked in societe/class/societe.class.php:1412 during validation; an error is raised if the value is absent or blank. No admin UI write found; HIDDEN_GUESS is 1. Only 1 occurrence found.', 'When enabled, saving a third party without an EUID raises a validation error.', 'Any non-empty value = mandatory; empty = optional', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:1412|check|if (getDolGlobalString(''SOCIETE_EUID_MANDATORY'') && (!isset($vallabel) || trim($vallabel) === '''')) {"]', 'low', NULL);
