INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_IDPROF1_UNIQUE', 'string', NULL, 'societe', 'Enforces uniqueness of the first professional identifier (idprof1) across all third parties.', 'Read as a boolean in societe/class/societe.class.php at line 4206 to determine whether idprof1 must be unique.', 'When enabled, duplicate values for idprof1 on third parties will be rejected during validation.', '0 or empty = not enforced; any truthy value = uniqueness enforced', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4206|read|$ret = getDolGlobalBool(''SOCIETE_IDPROF1_UNIQUE'');"]', 'low', NULL);
