INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_NO_SYNC_LINKED_MEMBER', 'string', NULL, 'societe', 'When enabled, disables synchronization of data between a third party and its linked member record.', 'Read in societe/card.php:697 into $nosyncmember to control sync behavior. Only one occurrence is present in the payload. No admin UI write is present.', 'Enabling this constant prevents member data from being synchronized when the linked third party is updated.', 'Integer flag; 0 or unset = synchronization enabled; non-zero = synchronization disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:697|read|$nosyncmember = getDolGlobalInt(''SOCIETE_NO_SYNC_LINKED_MEMBER'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_ON_SEARCH_AND_LIST_GO_ON_CUSTOMER_OR_SUPPLIER_CARD', 'string', NULL, 'societe', 'When clicking a third party in search results or lists, redirects directly to the customer or supplier card instead of the generic third-party card.', 'Written via societe/admin/societe.php:322 and admin/mailing.php:121 as a ''yesno'' constant. Checked in societe/class/societe.class.php:3265 and societe/list.php:934 to alter the navigation target URL.', 'Enabling this constant changes the click behaviour on third-party lists to open the role-specific card (customer or supplier); disabling opens the generic third-party card.', 'yesno: ''1'' or ''yes'' = go to customer/supplier card; ''0'' or empty = go to generic third-party card', 0, 0, 'societe/admin/societe.php|admin/mailing.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:322|write|$res = dolibarr_set_const($db, \"SOCIETE_ON_SEARCH_AND_LIST_GO_ON_CUSTOMER_OR_SUPPLIER_CARD\", $setonsearchandlistgooncustomerorsuppliercard, ''yesno'', 0, '''', $conf->entity);", "admin/mailing.php:121|write|$res = dolibarr_set_const($db, \"SOCIETE_ON_SEARCH_AND_LIST_GO_ON_CUSTOMER_OR_SUPPLIER_CARD\", $setonsearchandlistgooncustomerorsuppliercard, ''yesno'', 0, '''', $conf->entity);", "societe/class/societe.class.php:3265|check|if (getDolGlobalString(''SOCIETE_ON_SEARCH_AND_LIST_GO_ON_CUSTOMER_OR_SUPPLIER_CARD'')) {", "societe/list.php:934|check|if (getDolGlobalString(''SOCIETE_ON_SEARCH_AND_LIST_GO_ON_CUSTOMER_OR_SUPPLIER_CARD'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_RIB_ALLOW_ONLINESIGN', 'bool', NULL, 'societe', 'Enables online signing of RIB (bank account) documents for third-party records.', 'Checked in 5 occurrences in societe/paymentmodes.php and core/class/commonobject.class.php:6398. Always used in conjunction with SOCIETE_DISABLE_BANKACCOUNT check; core/class/commonobject.class.php:6398 checks it specifically for the ''societe_rib'' element.', 'When enabled (and bank account is not disabled), online signing links/actions are displayed for RIB documents on third-party payment modes pages.', '0 or unset = online signing disabled; non-zero = online signing enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/paymentmodes.php:1758|check|if (!getDolGlobalInt(''SOCIETE_DISABLE_BANKACCOUNT'') && getDolGlobalInt(\"SOCIETE_RIB_ALLOW_ONLINESIGN\")) {", "core/class/commonobject.class.php:6398|check|if ($this->element == ''societe_rib'' && getDolGlobalInt(\"SOCIETE_RIB_ALLOW_ONLINESIGN\")) {", "societe/paymentmodes.php:1908|check|if (!getDolGlobalInt(''SOCIETE_DISABLE_BANKACCOUNT'') && getDolGlobalInt(\"SOCIETE_RIB_ALLOW_ONLINESIGN\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_RIB_ONLINE_SIGNATURE_SECURITY_TOKEN', 'string', NULL, 'public', 'Stores the security token seed used to validate online signature requests for bank account (RIB) documents.', 'Read at public/onlinesign/newonlinesign.php:155 into $securekeyseed. No admin UI write is present.', 'Changing this token invalidates existing signature links; leaving it unset disables token-based signature security.', 'String security token seed; unset/empty = no token-based validation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/onlinesign/newonlinesign.php:155|read|$securekeyseed = getDolGlobalString(''SOCIETE_RIB_ONLINE_SIGNATURE_SECURITY_TOKEN'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_SHOW_FIELD_IN_TOOLTIP', 'bool', NULL, 'societe', 'Specifies which additional third-party fields (e.g. VAT number, EUID, profid1-3) are shown in the company tooltip.', 'Read in societe/class/societe.class.php at lines 3179, 3183, 3187, 3188, 3191, 3194, and more (11 occurrences). The value is checked with strpos() for keywords ''vatnumber'', ''euid'', ''profid1'', ''profid2'', ''profid3'' to conditionally include each field in the tooltip HTML. No admin UI write found; HIDDEN_GUESS is 1.', 'Setting this to a comma-separated or space-separated string of field keys causes those fields to appear in the third-party hover tooltip; leaving it empty shows only the default tooltip content.', 'String: space/comma-separated field keys (e.g. ''vatnumber euid profid1 profid2 profid3''); empty = no extra fields shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:3179|check|if (!empty($this->tva_intra) || (getDolGlobalString(''SOCIETE_SHOW_FIELD_IN_TOOLTIP'') && strpos($conf->global->SOCIETE_SHOW_FIELD_IN_TOOLTIP, ''vatnumber'') !== false)) {", "societe/class/societe.class.php:3183|check|if (!empty($this->euid) || (getDolGlobalString(''SOCIETE_SHOW_FIELD_IN_TOOLTIP'') && strpos($conf->global->SOCIETE_SHOW_FIELD_IN_TOOLTIP, ''euid'') !== false)) {", "societe/class/societe.class.php:3188|read|if (strpos($conf->global->SOCIETE_SHOW_FIELD_IN_TOOLTIP, ''profid1'') !== false && $langs->trans(''ProfId1''.$this->country_code) != ''-'') {", "societe/class/societe.class.php:3187|check|if (getDolGlobalString(''SOCIETE_SHOW_FIELD_IN_TOOLTIP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_SHOW_VAT_IN_LIST', 'bool', NULL, 'societe', 'Shows the intra-community VAT number column in the third-party list view.', 'When enabled, the intra-community VAT number (tva_intra) is displayed alongside the company name in the third-party selector dropdown. Configured via societe/admin/societe.php.', 'Enabling this adds the VAT number to the company selector list display. Disabling it hides that field from the list.', 'Truthy = show VAT number in list; empty/falsy = hide', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:879|check|if (getDolGlobalString(''SOCIETE_SHOW_VAT_IN_LIST'')) {", "core/class/html.form.class.php:1724|check|if (getDolGlobalString(''SOCIETE_SHOW_VAT_IN_LIST'') && !empty($obj->tva_intra)) {", "societe/admin/societe.php:209|write|$res = dolibarr_set_const($db, \"SOCIETE_SHOW_VAT_IN_LIST\", $setvatinlist, ''yesno'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_SORT_ON_TYPEENT', 'string', NULL, 'commande', 'Controls whether the third-party type list is sorted by a numeric position field rather than alphabetically.', 'Configured via admin/dict.php (lines 324, 371, 418, 465). Read in compta/facture/stats/index.php:324, compta/stats/cabyprodserv.php:497, and societe/card.php (lines 1889, 2769) to determine sort direction or apply position-based ordering.', 'When set, a ''position'' column is included in type-entity dictionary queries and sort parameters use position order; when unset, sorting defaults to label ascending (''ASC'').', 'String: sort direction string such as ''ASC'' or ''NONE''; empty/unset means sort by label ASC.', 0, 0, 'admin/dict.php|admin/dict.php|admin/dict.php|admin/dict.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/dict.php:324|read|$tabsqlsort[DICT_TYPENT] = \"country DESC,\".(getDolGlobalString(''SOCIETE_SORT_ON_TYPEENT'') ? '' t.position ASC,'' : '''').\" libelle ASC\";", "admin/dict.php:371|read|$tabfield[DICT_TYPENT] = \"code,libelle,module,country_id,country\".(getDolGlobalString(''SOCIETE_SORT_ON_TYPEENT'') ? '',position'' : '''');", "compta/facture/stats/index.php:324|read|$sortparam_typent = getDolGlobalString(''SOCIETE_SORT_ON_TYPEENT'', ''ASC''); // NONE means we keep sort of original array, so we sort on position. ASC, means next function will sort o...", "societe/card.php:2769|read|print $form->selectarray(\"typent_id\", $formcompany->typent_array(0), $object->typent_id, 1, 0, 0, '''', 0, 0, 0, (!getDolGlobalString(''SOCIETE_SORT_ON_TYPEENT'') ? ''ASC'' : $conf->glob..."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_USE_SEARCH_TO_SELECT', 'bool', NULL, 'societe', 'Sets the minimum number of characters required before the AJAX company search is triggered.', 'Read in a single location: societe/ajax/company.php:132 as `if (dol_strlen($filter) < getDolGlobalInt(''SOCIETE_USE_SEARCH_TO_SELECT''))`.', 'Setting this value to a positive integer requires the user to type at least that many characters before the autocomplete search fires.', 'Integer (minimum character count); 0 or empty means the search fires without a minimum character threshold.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/ajax/company.php:132|check|if (dol_strlen($filter) < getDolGlobalInt(''SOCIETE_USE_SEARCH_TO_SELECT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_VAT_INTRA_INVOICE_MANDATORY', 'string', NULL, 'compta', 'Controls whether an intra-EU VAT number is mandatory on invoices, optionally restricted to EEC customers only.', 'Checked in societe/admin/societe.php:763 and compta/facture/class/facture.class.php:3628. When set to ''eeconly'', the VAT number requirement applies only to EEC-zone third parties; any other truthy value applies the requirement globally.', 'When enabled, invoices cannot be validated for third parties lacking a VAT intra number. Setting to ''eeconly'' restricts this enforcement to EEC customers only.', '''eeconly'' = mandatory only for EEC-zone third parties; any other truthy value = mandatory for all third parties; empty/0 = not required', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:763|check|if (getDolGlobalString(''SOCIETE_VAT_INTRA_INVOICE_MANDATORY'') == ''eeconly'') {", "compta/facture/class/facture.class.php:3628|check|if (getDolGlobalString(''SOCIETE_VAT_INTRA_INVOICE_MANDATORY'') == ''eeconly'') {", "compta/facture/class/facture.class.php:3635|read|} elseif (getDolGlobalString(''SOCIETE_VAT_INTRA_INVOICE_MANDATORY'') && ($this->thirdparty->tva_assuj) && empty($this->thirdparty->tva_intra)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_VAT_INTRA_MANDATORY', 'string', NULL, 'societe', 'Makes the intra-community VAT number mandatory for VAT-liable third parties.', 'Checked in societe/class/societe.class.php:1396 (only when tva_assuj is set and the value is empty) and in societe/admin/societe.php:753. Only 2 occurrences found.', 'When enabled, saving a VAT-liable third party without a VAT intra number raises a validation error.', 'Any non-empty value = mandatory for VAT-liable third parties; empty = optional', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:753|check|if (getDolGlobalString(''SOCIETE_VAT_INTRA_MANDATORY'')) {", "societe/class/societe.class.php:1396|check|if ($this->tva_assuj && !$vallabel && getDolGlobalString(''SOCIETE_VAT_INTRA_MANDATORY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SOCIETE_VAT_INTRA_UNIQUE', 'string', NULL, 'societe', 'Enforces uniqueness of the intra-community VAT number across all third parties.', 'Checked in societe/class/societe.class.php:1389 during validation and also in societe/admin/societe.php:744 in the admin panel. Only 2 occurrences found.', 'When enabled, saving a third party with a VAT intra number already used by another record raises a validation error.', 'Any non-empty value = uniqueness enforced; empty = duplicates allowed', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/admin/societe.php:744|check|if (getDolGlobalString(''SOCIETE_VAT_INTRA_UNIQUE'')) {", "societe/class/societe.class.php:1389|check|if ($vallabel && getDolGlobalString(''SOCIETE_VAT_INTRA_UNIQUE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFERLINE_ADDON_PDF', 'string', NULL, 'product', 'Selects the PDF template module for stock-transfer-line document generation.', 'Read in product/stock/stocktransfer/class/stocktransferline.class.php at lines 986-987 to determine which PDF model to apply. No admin UI write is present.', 'When set, the specified PDF module is used for stock-transfer-line documents. When unset, the default model is applied.', 'Name of a valid stock-transfer-line PDF module; empty or unset to use the default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/stocktransfer/class/stocktransferline.class.php:986|read|} elseif (getDolGlobalString(''STOCKTRANSFERLINE_ADDON_PDF'')) {", "product/stock/stocktransfer/class/stocktransferline.class.php:987|read|$modele = getDolGlobalString(''STOCKTRANSFERLINE_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_ADDON_PDF', 'string', NULL, 'product', 'Specifies the PDF template module name used to generate stock transfer documents.', 'Read at product/stock/stocktransfer/class/stocktransfer.class.php:1050–1051 to select the PDF generation module, and at product/stock/stocktransfer/stocktransfer_card.php:489 as the pre-selected template in the document generation UI.', 'Changing this value switches the PDF template used for stock transfer documents. Leaving it unset causes no specific template to be pre-selected via this constant.', 'String: PDF module name (e.g. ''pdf_eagle''); empty/unset = no pre-selection via this constant.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/stocktransfer/class/stocktransfer.class.php:1050|read|} elseif (getDolGlobalString(''STOCKTRANSFER_ADDON_PDF'')) {", "product/stock/stocktransfer/class/stocktransfer.class.php:1051|read|$modele = getDolGlobalString(''STOCKTRANSFER_ADDON_PDF'');", "product/stock/stocktransfer/stocktransfer_card.php:489|read|$preselected = getDolGlobalString(''STOCKTRANSFER_ADDON_PDF'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_DRAFT_WATERMARK', 'string', NULL, 'core', 'Defines the watermark text printed on stock-transfer PDF documents that are in draft status.', 'Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php:1033 and core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php:1213, both conditioned on the document being in status 0 (draft). When set, the watermark text is applied.', 'When set, draft stock-transfer PDFs display the specified watermark string. When unset, no watermark is applied to draft documents.', 'Arbitrary watermark text string; empty or unset means no watermark on drafts.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:1033|check|if ($object->statut == 0 && (getDolGlobalString(''STOCKTRANSFER_DRAFT_WATERMARK''))) {", "core/modules/stocktransfer/doc/pdf_eagle_proforma.modules.php:1213|check|if ($object->status == 0 && getDolGlobalString(''STOCKTRANSFER_DRAFT_WATERMARK'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_PDF_DISPLAY_AMOUNT_HT', 'string', NULL, 'core', 'Enables display of pre-tax unit amounts (prices) on stock-transfer PDF documents when set.', 'Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php at lines 132 (commented block), 665, 857, and 968 (commented block). Lines 132 and 968 are commented-out code; lines 665 and 857 are active checks that conditionally render price columns. The COMMENTS show: ''// Show also the prices''.', 'When set, price columns are shown in stock-transfer PDF output. Note: some price-display blocks are currently commented out in the code.', 'Truthy value (e.g. 1) to show prices on PDF; 0 or empty to hide them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:132  /*if (getDolGlobalString(''STOCKTRANSFER_PDF_DISPLAY_AMOUNT_HT'')) {\t// Show also the prices", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:665|check|if (getDolGlobalString(''STOCKTRANSFER_PDF_DISPLAY_AMOUNT_HT'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:857|check|if (getDolGlobalString(''STOCKTRANSFER_PDF_DISPLAY_AMOUNT_HT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_PDF_HIDE_ORDERED', 'bool', NULL, 'core', 'Hides the ''ordered'' quantity column from stock-transfer PDF documents when enabled.', 'Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php at lines 155 (commented block), 803, and 852. Active checks at lines 803 and 852 suppress the ordered-quantity column when the constant is set.', 'Enabling this constant removes the ordered quantity column from stock-transfer PDFs.', 'Truthy value (e.g. 1) to hide the ordered column; 0 or empty to show it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:803|check|if (!getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_ORDERED'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:852|check|if (!getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_ORDERED'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:155  /*if (getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_ORDERED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_PDF_HIDE_WEIGHT_AND_VOLUME', 'bool', NULL, 'core', 'Hides weight and volume columns from stock-transfer PDF documents when enabled.', 'Checked in core/modules/stocktransfer/doc/pdf_eagle.modules.php at lines 140, 528, 633, 865, and 941. When set, weight/volume sections are skipped; when not set, they are rendered.', 'Enabling this constant removes weight and volume data from generated stock-transfer PDFs, which simplifies the document layout.', 'Truthy value (e.g. 1) to hide weight/volume; 0 or empty to show them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/doc/pdf_eagle.modules.php:633|check|if (!getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:865|check|if (!getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:140|check|if (getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_WEIGHT_AND_VOLUME'')) {", "core/modules/stocktransfer/doc/pdf_eagle.modules.php:941|check|if (!getDolGlobalString(''STOCKTRANSFER_PDF_HIDE_WEIGHT_AND_VOLUME'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_STOCKTRANSFERLINE_ADDON', 'string', NULL, 'product', 'Selects the active numbering module for stock-transfer line references.', 'Read and conditionally set in product/stock/stocktransfer/class/stocktransferline.class.php. If not set, it defaults to ''mod_stocktransferline_standard'' (line 916). The value is used to load the corresponding module file (line 922) and class (line 923).', 'Changing this constant switches the numbering module for stock-transfer lines; the chosen module file must exist.', 'Name of a valid stock-transfer-line numbering module; default is ''mod_stocktransferline_standard''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/stocktransfer/class/stocktransferline.class.php:915|check|if (!getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFERLINE_ADDON'')) {", "product/stock/stocktransfer/class/stocktransferline.class.php:916|write|$conf->global->STOCKTRANSFER_STOCKTRANSFERLINE_ADDON = ''mod_stocktransferline_standard'';", "product/stock/stocktransfer/class/stocktransferline.class.php:922|read|$file = getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFERLINE_ADDON'') . \".php\";", "product/stock/stocktransfer/class/stocktransferline.class.php:923|read|$classname = getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFERLINE_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_STOCKTRANSFER_ADDON', 'string', NULL, 'product', 'Specifies the numbering module class name used to generate stock transfer reference numbers.', 'Checked and read at product/stock/stocktransfer/class/stocktransfer.class.php:982–990. When unset, the code defaults to ''mod_stocktransfer_standard'' (written to conf->global at :983). When set, the stored value is used as $classname and $file to load the numbering module.', 'Changing this value switches the reference numbering module for stock transfers. Leaving unset uses ''mod_stocktransfer_standard'' as the default.', 'String: PHP class name of the numbering module (e.g. ''mod_stocktransfer_standard''); unset = defaults to ''mod_stocktransfer_standard''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/stocktransfer/class/stocktransfer.class.php:982|check|if (!getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFER_ADDON'')) {", "product/stock/stocktransfer/class/stocktransfer.class.php:983|write|$conf->global->STOCKTRANSFER_STOCKTRANSFER_ADDON = ''mod_stocktransfer_standard'';", "product/stock/stocktransfer/class/stocktransfer.class.php:990|read|$classname = getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFER_ADDON'');", "product/stock/stocktransfer/class/stocktransfer.class.php:989|read|$file = getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFER_ADDON'') . \".php\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCKTRANSFER_STOCKTRANSFER_ADVANCED_MASK', 'string', NULL, 'core', 'Defines the reference number mask for the ''advanced'' stock-transfer numbering module.', 'Read in core/modules/stocktransfer/mod_stocktransfer_advanced.php at lines 96 and 149 to render the mask input and generate references. No admin UI write outside the module configuration page.', 'Changing the mask alters the format of newly generated stock-transfer reference numbers; existing references are unaffected.', 'Mask string (as supported by the advanced module''s mask syntax); empty string disables custom formatting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stocktransfer/mod_stocktransfer_advanced.php:149|read|$mask = getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFER_ADVANCED_MASK'');", "core/modules/stocktransfer/mod_stocktransfer_advanced.php:96|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat\" size=\"24\" name=\"maskStockTransfer\" value=\"''.getDolGlobalString(''STOCKTRANSFER_STOCKTRANSFER_ADV"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ADDON_PDF', 'string', NULL, 'admin', 'Selects the PDF generation module (addon) used for warehouse/stock movement documents.', 'Written at admin/stock.php:196 and 199; read at admin/stock.php:718, 190, and product/stock/class/entrepot.class.php:1037-1038. The value is matched against available PDF module names to select the active one for stock document generation.', 'Changing this value switches the PDF template used when generating stock/warehouse documents.', 'String matching the name of the installed stock PDF addon module; empty = no addon selected', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/stock.php:196|write|if (dolibarr_set_const($db, \"STOCK_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/stock.php:718|check|if (getDolGlobalString(''STOCK_ADDON_PDF'') == $name) {", "product/stock/class/entrepot.class.php:1037|read|} elseif (getDolGlobalString(''STOCK_ADDON_PDF'')) {", "product/stock/class/entrepot.class.php:1038|read|$modele = getDolGlobalString(''STOCK_ADDON_PDF'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies one or more comma/newline-separated directory paths where ODT stock document templates are searched.', 'Read and checked at core/modules/stock/doc/doc_generic_stock_odt.modules.php:123, :150, :158. The value is split by commas/newlines into a list of directories; when non-empty the configured paths are used instead of or alongside defaults.', 'Changing this value redirects the ODT template search to the specified directories. Leaving it unset causes the module to use its built-in default template location.', 'String: comma or newline-separated directory paths; empty/unset = use module default template path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stock/doc/doc_generic_stock_odt.modules.php:123|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''STOCK_ADDON_PDF_ODT_PATH''))));", "core/modules/stock/doc/doc_generic_stock_odt.modules.php:158|check|if (getDolGlobalString(''STOCK_ADDON_PDF_ODT_PATH'')) {", "core/modules/stock/doc/doc_generic_stock_odt.modules.php:150|read|$texte .= getDolGlobalString(''STOCK_ADDON_PDF_ODT_PATH'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE', 'bool', NULL, 'product', 'Enables per-warehouse minimum and desired stock level limits in replenishment.', 'Configured via admin/stock.php:888 and checked in 21 occurrences across product/stock/replenish.php and core/modules/modProduct.class.php. When set with a warehouse filter active, per-warehouse stock thresholds are used instead of global product thresholds.', 'Enabling this constant activates per-warehouse stock limit fields in replenishment; disabling it uses global product-level stock thresholds.', 'Non-empty = per-warehouse limits enabled; empty or unset = global limits used', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/stock.php:888|read|print $form->selectarray(\"STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE\", $arrval, getDolGlobalString(''STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE''));", "product/stock/replenish.php:404|check|if (getDolGlobalString(''STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE'') && $fk_entrepot > 0) {", "product/stock/replenish.php:633|check|if (empty($fk_entrepot) && getDolGlobalString(''STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE'')) {", "core/modules/modProduct.class.php:820|check|if (getDolGlobalString(''STOCK_ALLOW_ADD_LIMIT_STOCK_BY_WAREHOUSE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ALLOW_DELETE_OF_MOVEMENT', 'bool', NULL, 'product', 'Allows users with delete permission to delete individual stock movement records.', 'Checked in product/stock/movement_list.php:1125 in conjunction with $permissiontodelete. When set, a delete action is rendered for each movement row.', 'Enabling this constant exposes a delete action on stock movement records for authorized users; disabling it prevents deletion of movement history.', 'Non-empty = delete action enabled; empty or unset = deletion not available', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/movement_list.php:1125|check|if (getDolGlobalString(''STOCK_ALLOW_DELETE_OF_MOVEMENT'') && $permissiontodelete) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ALLOW_VIRTUAL_STOCK_PER_WAREHOUSE', 'bool', NULL, 'product', 'Enables per-warehouse virtual stock calculation.', 'Checked in product/class/product.class.php:6511 alongside $this->stock_warehouse, and in product/stock/replenish.php:894. No admin UI.', 'When enabled, virtual stock figures are computed and displayed per warehouse rather than globally across all warehouses.', 'Truthy string (per-warehouse virtual stock active) or empty/unset (global virtual stock only).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6511|check|if (!empty($this->stock_warehouse) && getDolGlobalString(''STOCK_ALLOW_VIRTUAL_STOCK_PER_WAREHOUSE'')) {", "product/stock/replenish.php:894|check|if (getDolGlobalString(''STOCK_ALLOW_VIRTUAL_STOCK_PER_WAREHOUSE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_ALWAYS_SHOW_FULL_ARBO', 'bool', NULL, 'product', 'Forces the warehouse tree/path to always display the full hierarchy rather than just the label.', 'Read at admin/stock.php:900 in a select array form. Used at product/stock/class/entrepot.class.php:902 where the full path is shown if either $showfullpath is set or this constant is truthy.', 'Enabling this constant makes warehouse labels always show their full hierarchical path; disabling it shows only the immediate label unless the caller requests the full path.', '0 or empty = show warehouse label only by default; any truthy value = always show full warehouse hierarchy path', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/class/entrepot.class.php:902|read|$result .= (($showfullpath || getDolGlobalString(''STOCK_ALWAYS_SHOW_FULL_ARBO'')) ? $this->get_full_arbo() : $this->label);", "admin/stock.php:900|read|print $form->selectarray(\"STOCK_ALWAYS_SHOW_FULL_ARBO\", $arrval, getDolGlobalString(''STOCK_ALWAYS_SHOW_FULL_ARBO''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_BILL', 'string', NULL, 'compta', 'Controls whether stock levels are updated (decremented) when a customer invoice is validated.', 'Configured via admin/stock.php (written at line 90 via del, displayed at line 303). Checked in compta/facture/class/facture.class.php (lines 3205, 3744, 4082) on invoice validation, and in product/class/product.class.php:3701 for virtual stock computation. A comment at facture.class.php:3743 states: ''If active (STOCK_CALCULATE_ON_BILL), we decrement the main product and its components at invoice validation''.', 'When set, validating a customer invoice triggers stock decrement for invoiced products (excluding deposit invoices); clearing it disables this automatic stock movement.', 'Truthy (non-empty) to enable stock decrement on invoice validation; empty/unset to disable.', 0, 0, 'admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// If active (STOCK_CALCULATE_ON_BILL), we decrement the main product and its components at invoice validation", "compta/facture/class/facture.class.php:3205|check|if ($this->type != self::TYPE_DEPOSIT && $result >= 0 && isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_BILL'') && $idwarehouse != -1) {", "compta/facture/card.php:757|check|if ($object->type != Facture::TYPE_DEPOSIT && getDolGlobalString(''STOCK_CALCULATE_ON_BILL'')) {", "product/class/product.class.php:3701|check|if ($forVirtualStock && getDolGlobalString(''STOCK_CALCULATE_ON_BILL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_RECEPTION', 'string', NULL, 'reception', 'Determines whether and when stock movements are automatically recorded upon reception of goods.', 'Written via admin/stock.php (line 98 deletes, line 452 reads value). Checked across at least 25 occurrences in reception/class/reception.class.php (lines 681, 1428, 1728, 2351) and fourn/commande/card.php:2976. COMMENT: references alongside `STOCK_CALCULATE_ON_SUPPLIER_BILL`, `STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER`, `STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER`, `STOCK_CALCULATE_ON_RECEPTION_CLOSE`.', 'Setting a non-zero value triggers automatic stock entry creation at the point of reception; the precise moment depends on the selected option value.', 'Integer; 0 or empty = no automatic stock movement on reception; positive integer values select specific trigger points (e.g. on validation, on closing).', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/modules/modReception.class.php:289  /\"DELETE FROM \".MAIN_DB_PREFIX.\"const WHERE name IN (''STOCK_CALCULATE_ON_SUPPLIER_BILL'', ''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER'', ''STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER'', ''STOCK_CALCULATE_ON_RECEPTION'', ''STOCK_CALCULATE_ON_RECEPTION_CLOSE'')", "reception/class/reception.class.php:681|check|if (!$error && isModEnabled(''stock'') && getDolGlobalInt(''STOCK_CALCULATE_ON_RECEPTION'')) {", "reception/class/reception.class.php:1428|check|if (isModEnabled(''stock'') && ((getDolGlobalInt(''STOCK_CALCULATE_ON_RECEPTION'') && $this->status > Reception::STATUS_DRAFT)", "admin/stock.php:452|read|print $form->selectarray(\"STOCK_CALCULATE_ON_RECEPTION\", $arrval, getDolGlobalString(''STOCK_CALCULATE_ON_RECEPTION''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_RECEPTION_CLOSE', 'string', NULL, 'reception', 'Triggers stock movement calculation when a reception is closed rather than at another stock event.', 'Configured via admin/stock.php UI. When set, stock is calculated on reception close events in reception/class/reception.class.php:2053 and :2214. The module modReception comments note this constant as part of the stock calculation mode family. core/class/conf.class.php:957 notes it is forced when lot/serial module is enabled.', 'Changing this affects the timing of stock inventory updates: stock movements are recorded at reception close instead of at other reception stages.', '0 or unset = no stock calculation on close; 1 = stock calculated on reception close', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/conf.class.php:957  // If module lot/serial enabled, we force the inc/dec mode to STOCK_CALCULATE_ON_SHIPMENT_CLOSE and STOCK_CALCULATE_ON_RECEPTION_CLOSE", "reception/class/reception.class.php:2053|check|if (!$error && isModEnabled(''stock'') && getDolGlobalInt(''STOCK_CALCULATE_ON_RECEPTION_CLOSE'')) {", "admin/stock.php:471|read|print $form->selectarray(\"STOCK_CALCULATE_ON_RECEPTION_CLOSE\", $arrval, getDolGlobalString(''STOCK_CALCULATE_ON_RECEPTION_CLOSE''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SHIPMENT', 'string', NULL, 'product', 'Triggers stock movements (decrease) when a shipment is validated.', 'Written (deleted) in admin/stock.php at line 92 and rendered as a select at line 349. Checked in expedition/class/expedition.class.php at line 1055 and in product/class/product.class.php at line 6469 to trigger the stock decrement on shipment validation. Admin comments confirm ''STOCK_CALCULATE_ON_SHIPMENT is ok so not disable''.', 'Enabling this constant causes stock levels to be decremented at shipment validation time. It is mutually exclusive with other STOCK_CALCULATE_ON_* modes.', '0 or unset = no stock movement on shipment validation; 1 = stock decremented on shipment validation', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// STOCK_CALCULATE_ON_SHIPMENT is ok so not disable", "if (!$error && isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SHIPMENT'')) {", "if (getDolGlobalString(''STOCK_CALCULATE_ON_SHIPMENT'') || getDolGlobalString(''STOCK_CALCULATE_ON_SHIPMENT_CLOSE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SHIPMENT_CLOSE', 'string', NULL, 'product', 'Triggers stock movements (decrease) when a shipment is closed rather than when it is validated.', 'Written (deleted/inserted) in admin/stock.php and referenced in core/modules/modExpedition.class.php and core/class/conf.class.php. Checked in expedition/class/expedition.class.php at lines 2996 and 3207, and in expedition/card.php at line 2679. A conf.class.php comment states: ''If module lot/serial enabled, we force the inc/dec mode to STOCK_CALCULATE_ON_SHIPMENT_CLOSE and STOCK_CALCULATE_ON_RECEPTION_CLOSE''.', 'When the lot/serial module is active this mode is forced automatically. Enabling it defers stock decrements to shipment closure instead of validation.', '0 or unset = no stock movement on shipment close; 1 = stock decremented on shipment close', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// If module lot/serial enabled, we force the inc/dec mode to STOCK_CALCULATE_ON_SHIPMENT_CLOSE and STOCK_CALCULATE_ON_RECEPTION_CLOSE", "// STOCK_CALCULATE_ON_SHIPMENT_CLOSE is ok so not disabled", "if (isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SHIPMENT_CLOSE'')) {", "/\"INSERT INTO \".MAIN_DB_PREFIX.\"const (name, value, entity) VALUES (''STOCK_CALCULATE_ON_SHIPMENT_CLOSE'', 1, \".((int) $conf->entity).\")\""]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SHIPMENT_DISPATCH_ORDER', 'string', NULL, 'expedition', 'Triggers stock movement calculation when dispatching a shipment order, provided the stock module is enabled.', 'Used in expedition/dispatch.php:323. The condition checks that the posted quantity is positive, the stock module is enabled, and this constant is non-empty before processing the stock calculation.', 'When enabled, dispatching a shipment order updates stock levels; when disabled or empty, no stock movement is recorded at dispatch.', 'Non-empty = stock calculation active on dispatch; empty/unset = no stock update.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (!$error && GETPOST($ent, ''int'') > 0 && isModEnabled(''stock'') && !empty($conf->global->STOCK_CALCULATE_ON_SHIPMENT_DISPATCH_ORDER)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SUPPLIER_BILL', 'string', NULL, 'fourn', 'Controls whether and how stock movements are triggered automatically when a supplier invoice is validated or unvalidated.', 'Configured via admin/stock.php and checked across fourn/class/fournisseur.facture.class.php and fourn/facture/card.php (16+ occurrences). The admin page at admin/stock.php:408 presents a select array of values for this constant.', 'When set, validating or unvalidating a supplier invoice automatically updates stock levels; unsetting it disables automatic stock movements on supplier billing.', 'Selected value from admin UI array (e.g. specific stock movement type codes); empty = disabled', 0, 0, 'admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:408|read|print $form->selectarray(\"STOCK_CALCULATE_ON_SUPPLIER_BILL\", $arrval, getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_BILL''));", "fourn/class/fournisseur.facture.class.php:1910|check|if (isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_BILL'')) {", "fourn/facture/card.php:238|check|if (isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_BILL'') && $qualified_for_stock_change) {", "core/modules/modReception.class.php:289  //\"DELETE FROM \".MAIN_DB_PREFIX.\"const WHERE name IN (''STOCK_CALCULATE_ON_SUPPLIER_BILL'', ...) AND enti"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER', 'string', NULL, 'product', 'Specifies the stock movement type triggered when a supplier order line is dispatched.', 'Configured via admin/stock.php:100 (deleted when reset) and :490 (select form). Checked in fourn/class/fournisseur.commande.class.php:2385, fourn/commande/dispatch.php:447 and :493, and fourn/commande/card.php:2976 and :2991. Also referenced in admin/stock.php:261 and modReception.class.php:289 as part of the stock calculation constant family.', 'When set, dispatching a supplier order line triggers a stock movement of the specified type; when not set, no stock movement occurs on dispatch.', 'Not set = no stock movement on dispatch; numeric value = stock movement type to apply on dispatch.', 0, 0, 'admin/stock.php|admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:2385|check|if (!$error && $entrepot > 0 && isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER'')) {", "admin/stock.php:490|read|print $form->selectarray(\"STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER\", $arrval, getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER''));", "fourn/commande/dispatch.php:493|check|if ($entrepot > 0 && isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER'')) {", "admin/stock.php:100|write|dolibarr_del_const($db, ''STOCK_CALCULATE_ON_SUPPLIER_DISPATCH_ORDER'', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER', 'string', NULL, 'fourn', 'Specifies the stock movement type triggered when a supplier order is validated/approved.', 'Configured via admin/stock.php:97 (deleted when reset) and :430 (select form). Checked in fourn/class/fournisseur.commande.class.php:1359, fourn/commande/card.php:1215, :1239, :2312, and product/stock/lib/replenishment.lib.php:123 to trigger stock changes on approval. Also referenced in modReception.class.php:289 as part of the stock calculation constant family.', 'When set, approving a supplier order triggers a stock movement of the specified type; when not set, no stock is moved on validation.', 'Not set = no stock movement on supplier order validation; numeric value = stock movement type to apply on validation.', 0, 0, 'admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:1359|check|if (!$error && $movetoapprovestatus && isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER'')) {", "admin/stock.php:430|read|print $form->selectarray(\"STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER\", $arrval, getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER''));", "fourn/commande/card.php:1239|check|if (isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER'') && $qualified_for_stock_change) {", "admin/stock.php:97|write|dolibarr_del_const($db, ''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER'', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER_INCLUDE_DRAFT', 'string', NULL, 'product', 'Includes draft supplier orders in virtual stock calculations.', 'Checked in product/class/product.class.php:6489 with an inline comment: ''By default, draft means "does not exist", so we do not include them by default, except if option is''. Only one occurrence; no admin UI.', 'When enabled, draft supplier orders are counted in virtual stock. By default drafts are excluded.', 'Truthy string (supplier order drafts included) or empty/unset (drafts excluded).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6489|check|if (getDolGlobalString(''STOCK_CALCULATE_ON_SUPPLIER_VALIDATE_ORDER_INCLUDE_DRAFT'')) {\t// By default, draft means \"does not exist\", so we do not include them by default, except if o"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_VALIDATE_ORDER', 'string', NULL, 'commande', 'Triggers stock movements (decrease) when a customer order is validated.', 'Written (deleted) in admin/stock.php at line 91 and rendered as a select at line 325. Checked in commande/class/commande.class.php at lines 579, 713, and 919 with the condition getDolGlobalInt == 1. A phpdoc comment confirms: ''Warehouse ID to use for stock change (Used only if option STOCK_CALCULATE_ON_VALIDATE_ORDER is on)''.', 'Enabling this constant causes inventory to be decremented at order validation. It is mutually exclusive with other STOCK_CALCULATE_ON_* modes.', '0 or unset = no stock movement on order validation; 1 = stock decremented on order validation', 0, 0, 'admin/stock.php|admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["@param\tint\t\t$idwarehouse\tWarehouse ID to use for stock change (Used only if option STOCK_CALCULATE_ON_VALIDATE_ORDER is on)", "if ($result >= 0 && isModEnabled(''stock'') && getDolGlobalInt(''STOCK_CALCULATE_ON_VALIDATE_ORDER'') == 1) {", "if (isModEnabled(''stock'') && getDolGlobalString(''STOCK_CALCULATE_ON_VALIDATE_ORDER'') && $qualified_for_stock_change) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_ON_VALIDATE_ORDER_INCLUDE_DRAFT', 'string', NULL, 'product', 'Includes draft customer orders in virtual stock calculations when validating an order.', 'Checked in product/class/product.class.php:6472 with an inline comment: ''By default, draft means "does not exist", so we do not include them by default, except if option is''. Only one occurrence; no admin UI.', 'When enabled, draft orders are factored into virtual stock, reducing the apparent available stock. By default drafts are excluded.', 'Truthy string (drafts included) or empty/unset (drafts excluded).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6472|check|if (getDolGlobalString(''STOCK_CALCULATE_ON_VALIDATE_ORDER_INCLUDE_DRAFT'')) {\t// By default, draft means \"does not exist\", so we do not include them by default, except if option is"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CALCULATE_VIRTUAL_STOCK_TRANSVERSE_MODE', 'string', NULL, 'product', 'Switches virtual stock calculation to use the ''stock'' entity scope across all entities instead of the module-specific entity scope.', 'Checked in product/class/product.class.php at multiple points (lines 3655, 3810, 3871, 3951, 4011) and in product/stock/replenish.php (lines 457, 470, 484): when truthy and forVirtualStock is active, getEntity is called with ''stock'' instead of ''commande'', ''supplier_order'', ''expedition'', or ''mrp''.', 'Enabling this constant causes virtual stock queries to span all entities sharing the stock entity scope rather than being restricted to the per-module entity scope.', 'Truthy string (transverse/stock entity scope used) or empty/unset (module-specific entity scope used).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:3655|read|$sql .= \" AND c.entity IN (\".getEntity($forVirtualStock && getDolGlobalString(''STOCK_CALCULATE_VIRTUAL_STOCK_TRANSVERSE_MODE'') ? ''stock'' : ''commande'').\")\"", "product/class/product.class.php:3810|read|$sql .= \" AND c.entity IN (\".getEntity($forVirtualStock && getDolGlobalString(''STOCK_CALCULATE_VIRTUAL_STOCK_TRANSVERSE_MODE'') ? ''stock'' : ''supplier_order'').\")\"", "product/stock/replenish.php:457|read|$sqlCommandesCli .= \" WHERE c1.rowid = cd1.fk_commande AND c1.entity IN (\".getEntity(getDolGlobalString(''STOCK_CALCULATE_VIRTUAL_STOCK_TRANSVERSE_MODE'') ? ''stock'' : ''commande'').\")", "product/stock/replenish.php:484|read|$sqlCommandesFourn .= \" AND c3.entity IN (\".getEntity(getDolGlobalString(''STOCK_CALCULATE_VIRTUAL_STOCK_TRANSVERSE_MODE'') ? ''stock'' : ''supplier_order'').\")\""]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CONSUMPTION_FROM_MANUFACTURING_WAREHOUSE', 'string', NULL, 'mrp', 'Forces material consumption during production to use the warehouse assigned to the Manufacturing Order instead of a separately selected warehouse.', 'Checked in mrp/mo_production.php at lines 560, 1247, 1271, and 1531. A source comment states: ''When STOCK_CONSUMPTION_FROM_MANUFACTURING_WAREHOUSE is set, we always use the warehouse of the MO, the same than production.''', 'When enabled, the production consumption form ignores the per-line warehouse selector and always applies movements against the MO''s warehouse. When disabled, operators can choose a different warehouse per consumption line.', '0 or unset = operator selects warehouse per line; 1 = MO warehouse is always used for consumption', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// When STOCK_CONSUMPTION_FROM_MANUFACTURING_WAREHOUSE is set, we always use the warehouse of the MO, the same than production.", "if (getDolGlobalString(''STOCK_CONSUMPTION_FROM_MANUFACTURING_WAREHOUSE'') && $tmpwarehouse->id > 0) {", "if (!getDolGlobalString(''STOCK_CONSUMPTION_FROM_MANUFACTURING_WAREHOUSE'') || empty($tmpwarehouse->id)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_CORRECT_STOCK_IN_SHIPMENT', 'string', NULL, 'expedition', 'Enables stock correction logic within the shipment processing workflow when set.', 'Checked in expedition/shipment.php:806 as a boolean gate for a stock correction code path. No admin UI write and no COMMENTS are present in the payload.', 'When set, the shipment processing code enters a stock correction branch; when unset, that branch is skipped.', 'Truthy value (e.g. 1) to enable stock correction in shipments; 0 or empty to skip.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/shipment.php:806|check|if (getDolGlobalString(''STOCK_CORRECT_STOCK_IN_SHIPMENT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DEFAULT_BATCH', 'string', NULL, 'product', 'Defines a default lot/batch number string to use when no specific lot is assigned.', 'Checked and read in product/class/product.class.php:1520-1521: when set, its value is used as $valueforundefinedlot. Only two occurrences; no admin UI.', 'When set, stock movements without an explicit lot will use this value as the default batch identifier.', 'String representing the default lot/serial number; empty/unset means no default batch is applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:1520|check|if (getDolGlobalString(''STOCK_DEFAULT_BATCH'')) {", "product/class/product.class.php:1521|read|$valueforundefinedlot = getDolGlobalString(''STOCK_DEFAULT_BATCH'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DETAIL_ON_WAREHOUSE', 'string', NULL, 'product', 'Enables per-warehouse stock detail columns in the product stock reassort list.', 'Checked in product/reassort.php at lines 448, 531, and 612. An inline TODO comment notes this feature should eventually move to product/list page field selection.', 'Enabling adds warehouse-level stock breakdown columns to the reassort view; disabling shows only aggregate stock.', 'Truthy value to show per-warehouse stock detail; absent or falsy to show aggregate only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/reassort.php:531|check|if (getDolGlobalString(''STOCK_DETAIL_ON_WAREHOUSE'')) {\t// TODO This should be moved into the selection of fields on page product/list", "product/reassort.php:612|check|if (getDolGlobalString(''STOCK_DETAIL_ON_WAREHOUSE'')) {\t// TODO This should be moved into the selection of fields on page product/list", "product/reassort.php:448|check|if (getDolGlobalString(''STOCK_DETAIL_ON_WAREHOUSE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DISABLE_OPTIM_LOAD', 'bool', NULL, 'product', 'Forces load_stock to run regardless of user stock permissions, overriding the default optimization that skips it.', 'When set, bypasses the permission check that normally gates the load_stock call in product/list.php:1738. Documented at product/list.php:1737 with the comment that this constant forces load_stock whatever the permissions on stock.', 'Disabling the optimization causes stock data to be loaded unconditionally on product lists, which increases database load but ensures stock information is always present.', 'Any truthy value forces load_stock; unset or empty uses permission-based optimization.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/list.php:1737  // STOCK_DISABLE_OPTIM_LOAD can be set to force load_stock whatever is permissions on stock.", "product/list.php:1738|check|if ((isModEnabled(''stock'') && $user->hasRight(''stock'', ''lire'') && $search_type != 1) || getDolGlobalString(''STOCK_DISABLE_OPTIM_LOAD'')) {\t// To optimize call of load_stock"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DISALLOW_NEGATIVE_TRANSFER', 'bool', NULL, 'expedition', 'Prevents stock movements that would result in negative warehouse stock levels.', 'Configured via admin/stock.php:519 and checked in product/stock/class/mouvementstock.class.php:461, compta/facture/class/facture.class.php:3827, and expedition/card.php:2150. When enabled, stock transfers are blocked if the warehouse quantity would go below zero.', 'Enabling this setting blocks shipment and invoice stock deductions when available warehouse stock is zero or less, preventing negative inventory balances.', '0 = allow negative stock transfers; 1 = disallow negative stock transfers', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:519|read|print $form->selectarray(\"STOCK_DISALLOW_NEGATIVE_TRANSFER\", $arrval, getDolGlobalInt(''STOCK_DISALLOW_NEGATIVE_TRANSFER''));", "product/stock/class/mouvementstock.class.php:461|check|if ($movestock && $qty < 0 && getDolGlobalInt(''STOCK_DISALLOW_NEGATIVE_TRANSFER'')) {", "expedition/card.php:2150|check|if (getDolGlobalInt(''STOCK_DISALLOW_NEGATIVE_TRANSFER'')) {", "expedition/card.php:2334|check|if ($stock_warehouse->real > 0 || !getDolGlobalInt(''STOCK_DISALLOW_NEGATIVE_TRANSFER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DO_WE_BILL_ORDER_OR_SHIPMENTECEPTION_FOR_VIRTUALSTOCK', 'string', NULL, 'product', 'Controls whether virtual stock is calculated based on orders or shipment receptions.', 'Read in product/class/product.class.php:6466 as $weBillOrderOrShipmentReception with a default of ''order''. Only one occurrence; no admin UI.', 'Changing this value switches the reference point for virtual stock computation between order lines and shipment/reception lines.', 'String: ''order'' (default) or ''reception''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6466|read|$weBillOrderOrShipmentReception = getDolGlobalString(''STOCK_DO_WE_BILL_ORDER_OR_SHIPMENTECEPTION_FOR_VIRTUALSTOCK'', ''order'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_DRAFT_WATERMARK', 'string', NULL, 'core', 'Specifies the watermark text printed on PDF stock documents that are in draft status.', 'Checked and read at core/modules/stock/doc/pdf_standard_stock.modules.php:742–743. When the stock object is in draft status (statut == 0) and this constant is non-empty, pdf_watermark() is called with the constant''s value as the watermark text.', 'Setting a value causes draft stock PDFs to display that text as a watermark. Leaving it empty or unset disables the draft watermark feature.', 'String: watermark text to display (e.g. ''DRAFT''); empty/unset = no watermark on draft stock PDFs.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/stock/doc/pdf_standard_stock.modules.php:742|check|if ($object->statut == 0 && (getDolGlobalString(''STOCK_DRAFT_WATERMARK''))) {", "core/modules/stock/doc/pdf_standard_stock.modules.php:743|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', $conf->global->STOCK_DRAFT_WATERMARK);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_EXCLUDE_DISCOUNT_FOR_PMP', 'string', NULL, 'fourn', 'Excludes line discounts from the purchase price used for average weighted cost (PMP) calculation.', 'Documented in reception/dispatch.php:241: ''$price should take into account discount (except if option STOCK_EXCLUDE_DISCOUNT_FOR_PMP is on)''. Same comment in expedition/dispatch.php:341 and fourn/class/fournisseur.commande.class.php:2388. Checked in 5 occurrences across reception, expedition, and supplier order/invoice classes.', 'When enabled, discounts are excluded when computing the average cost price (PMP); when disabled (default), discounts reduce the price used for PMP calculation.', '0 or unset = discounts included in PMP calculation; non-empty = discounts excluded', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/dispatch.php:241  // $price should take into account discount (except if option STOCK_EXCLUDE_DISCOUNT_FOR_PMP is on)", "expedition/dispatch.php:341  // $price should take into account discount (except if option STOCK_EXCLUDE_DISCOUNT_FOR_PMP is on)", "fourn/class/fournisseur.commande.class.php:2388  // $price should take into account discount (except if option STOCK_EXCLUDE_DISCOUNT_FOR_PMP is on)", "reception/dispatch.php:684|check|if (!empty($objp->remise_percent) && !getDolGlobalString(''STOCK_EXCLUDE_DISCOUNT_FOR_PMP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_EXCLUDE_VIRTUAL_PRODUCTS', 'string', NULL, 'expedition', 'Excludes kit/virtual products from stock management in shipment processing when set.', 'Read in expedition/class/expedition.class.php:1329 via getDolGlobalInt. The inline comment at line 1331 documents: ''If STOCK_EXCLUDE_VIRTUAL_PRODUCTS is set, we do not manage stock for kits/virtual products.'' No admin UI write is present.', 'Enabling this constant causes the shipment code to skip stock movements for virtual/kit products, which affects inventory accuracy for bundled items.', 'Truthy integer (e.g. 1) to exclude virtual products from stock management; 0 or unset to include them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expedition.class.php:1331  // If STOCK_EXCLUDE_VIRTUAL_PRODUCTS is set, we do not manage stock for kits/virtual products.", "expedition/class/expedition.class.php:1329|read||| ($isavirtualproduct && !getDolGlobalInt(''STOCK_EXCLUDE_VIRTUAL_PRODUCTS''))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_EXPEDITION_NO_MORE_THAN_ORDER', 'string', NULL, 'expedition', 'Prevents shipping lines from exceeding the ordered quantity on the corresponding order line.', 'Checked at expedition/class/expeditionligne.class.php:409 and :687. When truthy and a source order line (fk_elementdet) and expedition exist, the shipped quantity is validated against the ordered quantity.', 'Enabling enforces strict quantity control on shipments, preventing over-shipment. Disabling allows shipping more than ordered.', 'Truthy = block shipment quantities exceeding the order line quantity; empty/unset = no quantity cap enforced.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expeditionligne.class.php:409|check|if (getDolGlobalString(''STOCK_EXPEDITION_NO_MORE_THAN_ORDER'') && !empty($this->fk_elementdet) && !empty($this->fk_expedition)) {", "expedition/class/expeditionligne.class.php:687|check|if (getDolGlobalString(''STOCK_EXPEDITION_NO_MORE_THAN_ORDER'') && !empty($this->fk_elementdet)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_INVENTORY_ADD_A_VALUE_DATE', 'string', NULL, 'product', 'Enables a date_inventory (value date) field on stock inventory records.', 'Read as an enabled condition in the field definition array at product/inventory/class/inventory.class.php:99; the date field is rendered only when this constant returns a non-zero integer. No comment is present in the payload.', 'Enabling this constant adds a Date Value column to stock inventory records; disabling it hides the field.', 'Integer; non-zero enables the date field, 0 or unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/inventory/class/inventory.class.php:99|read|''date_inventory''     => array(''type'' => ''date'', ''label'' => ''DateValue'', ''visible'' => 1, ''enabled'' => ''getDolGlobalInt(\"STOCK_INVENTORY_ADD_A_VALUE_DATE\")'', ''position'' => 35, ''cssli"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MOVEMENT_INTO_PROJECT_OVERVIEW', 'string', NULL, 'projet', 'Enables display of stock movement data on the project elements overview page and in project ODT documents.', 'Read at projet/element.php:754 and core/modules/project/doc/doc_generic_project_odt.modules.php:1032 as the ''test'' condition for including stock movement sections. 2 occurrences across 2 files.', 'When unset, stock movements are not shown in the project elements overview or ODT export. When set and the stock module is enabled, stock movements are included.', 'Truthy value = stock movements shown in project overview and ODT; empty/unset = hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/element.php:754|read|''test'' => isModEnabled(''stock'') && $user->hasRight(''stock'', ''mouvement'', ''lire'') && getDolGlobalString(''STOCK_MOVEMENT_INTO_PROJECT_OVERVIEW'')", "core/modules/project/doc/doc_generic_project_odt.modules.php:1032|read|''test'' => (isModEnabled(''stock'') && $user->hasRight(''stock'', ''mouvement'', ''lire'') && getDolGlobalString(''STOCK_MOVEMENT_INTO_PROJECT_OVERVIEW''))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MOVEMENT_LIST_HIDE_UNIT_PRICE', 'bool', NULL, 'product', 'Hides the unit purchase price column in the stock movement list.', 'Read in product/stock/movement_list.php:154 as the negated condition for the ''enabled'' flag of the ''m.price'' column.', 'Setting this constant removes the unit purchase price column from the stock movement list display.', 'Non-zero = unit price column hidden; 0 or unset = column shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/movement_list.php:154|read|''m.price'' => array(''label'' => \"UnitPurchaseValue\", ''checked'' => ''0'', ''position'' => 210, ''enabled'' => (string) (int) (!getDolGlobalInt(''STOCK_MOVEMENT_LIST_HIDE_UNIT_PRICE'')))"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MUST_BE_ENOUGH_FOR_INVOICE', 'string', NULL, 'compta', 'Requires sufficient stock to be available before an invoice line can trigger a stock movement.', 'Configured via admin/stock.php:533 and checked in compta/facture/class/facture.class.php:4307 and :4659. When set and the product is stock-managed, the system verifies adequate stock before allowing the invoice stock deduction.', 'When enabled, invoicing a stock-managed product without sufficient available stock will be blocked or trigger an error.', 'Empty/0 = no stock check enforced; truthy = stock must be sufficient before invoice stock deduction', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:533|read|print $form->selectarray(\"STOCK_MUST_BE_ENOUGH_FOR_INVOICE\", $arrval, getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_INVOICE''));", "compta/facture/class/facture.class.php:4307|check|if (getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_INVOICE'') && $product->isStockManaged()) {", "compta/facture/class/facture.class.php:4659|check|if (getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_INVOICE'') && $product->isStockManaged()) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MUST_BE_ENOUGH_FOR_ORDER', 'string', NULL, 'commande', 'Requires sufficient stock before a sales order can be validated, blocking orders when stock is insufficient for managed products.', 'When set, order validation checks stock levels for managed products at commande/class/commande.class.php:1680 and :3238. Configurable via admin/stock.php using a select array.', 'If enabled, orders for products with insufficient stock will be blocked at validation time. Disabling allows orders regardless of available stock.', 'Empty = no stock check enforced; non-empty truthy value = stock must be sufficient for order validation', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["commande/class/commande.class.php:1680|check|if (getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_ORDER'') && $product->isStockManaged()) {", "commande/class/commande.class.php:3238|check|if (getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_ORDER'') && $product->isStockManaged()) {", "admin/stock.php:547|read|print $form->selectarray(\"STOCK_MUST_BE_ENOUGH_FOR_ORDER\", $arrval, getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_ORDER''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MUST_BE_ENOUGH_FOR_PROPOSAL', 'string', NULL, 'comm', 'Blocks adding a product line to a proposal when real stock is insufficient.', 'Checked in comm/propal/class/propal.class.php:729 during line addition: if stock is managed, real stock is below quantity requested, and this constant is set, an error condition is triggered. No admin UI is present.', 'When enabled, proposals cannot include product quantities exceeding available real stock. When unset, no stock sufficiency check is enforced on proposals.', 'Truthy string (stock check enforced) or empty/unset (no check).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/class/propal.class.php:729|check|if ($product->isStockManaged() && $product->stock_reel < $qty && getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_PROPOSAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT', 'string', NULL, 'expedition', 'Controls whether sufficient stock is required before a shipment line can be added.', 'Checked in expedition/class/expedition.class.php at lines 1288 and 1561, and exposed in admin/stock.php via a select array (line 561). The inline comment at line 1242 states: ''If STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT is not set, you can add a shipment line, even if not enough into stock''.', 'When set, the system enforces stock availability for shipment lines, blocking lines where stock is insufficient. When not set, shipment lines can be added regardless of stock levels.', 'Value from the configured select array in admin/stock.php; default (''0'' or unset) means no stock check enforced.', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expedition.class.php:1242  * If STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT is not set, you can add a shipment line, even if not enough into stock", "admin/stock.php:561|read|print $form->selectarray(\"STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT\", $arrval, getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT''));", "expedition/class/expedition.class.php:1288|check|if (getDolGlobalString(''STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT'')) {", "expedition/class/expedition.class.php:1561|check|if (getDolGlobalString(\"STOCK_MUST_BE_ENOUGH_FOR_SHIPMENT\", ''0'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_REPLENISH_ADD_CHECKBOX_INCLUDE_DRAFT_ORDER', 'string', NULL, 'product', 'Adds a checkbox in the replenishment view to optionally include draft purchase orders in stock calculations.', 'Checked in product/stock/replenish.php:816. When set, the UI renders a checkbox allowing users to include draft orders when computing stock to buy.', 'Enabling this constant gives users the option to factor in draft orders during replenishment; disabling it hides that checkbox.', 'Non-empty = include-draft-order checkbox shown; empty or unset = checkbox hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/replenish.php:816|check|if (getDolGlobalString(''STOCK_REPLENISH_ADD_CHECKBOX_INCLUDE_DRAFT_ORDER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_SHOW_ALL_BATCH_BY_DEFAULT', 'bool', NULL, 'product', 'Shows all batch/lot rows expanded by default in the warehouse stock view.', 'Read in product/stock/product.php:1132 and :1246. When set, batch rows are rendered visible by default; when not set, they are collapsed and a ''(+)'' toggle is shown.', 'Enabling this constant expands all batch detail rows on page load; disabling it collapses them, requiring user interaction to expand.', 'Non-empty = all batch rows visible by default; empty or unset = batch rows collapsed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/product.php:1132|read|print(!getDolGlobalString(''STOCK_SHOW_ALL_BATCH_BY_DEFAULT'') ? ''(+)'' : ''(-)'');", "product/stock/product.php:1246|read|print \"\\n\".''<tr style=\"display:''.(!getDolGlobalString(''STOCK_SHOW_ALL_BATCH_BY_DEFAULT'') ? ''none'' : ''visible'').''\" class=\"batch_warehouse''.$entrepotstatic->id.''\"><td class=\"left\">''"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_SHOW_VIRTUAL_STOCK_IN_PRODUCTS_COMBO', 'bool', NULL, 'core', 'When enabled, shows virtual stock levels alongside physical stock in product combo/select lists.', 'Checked at core/class/html.form.class.php:3722 and :4312 inside product combo-generation functions. The comment at :3569 explicitly warns this is a ''slow option''. When the $novirtualstock parameter is empty AND this constant is set, virtual stock is loaded and displayed.', 'Enabling this option slows down combo list generation. Disabling it (or leaving unset) skips virtual stock loading and keeps combo rendering fast.', 'Truthy (non-empty/non-zero) = show virtual stock; empty/unset = do not show virtual stock.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:3569  * @param int<0,1>\t$novirtualstock Do not load virtual stock, even if slow option STOCK_SHOW_VIRTUAL_STOCK_IN_PRODUCTS_COMBO is on.", "core/class/html.form.class.php:3722|check|if (empty($novirtualstock) && getDolGlobalString(''STOCK_SHOW_VIRTUAL_STOCK_IN_PRODUCTS_COMBO'')) {  // Warning, this option may slow down combo list generation"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_SUPPORTS_SERVICES', 'string', NULL, 'product', 'Enables stock movement tracking for service-type products, not just physical products.', 'Shown as a select array in admin/stock.php:875. Checked across 99 occurrences including reception/class/reception.class.php:903, reception/card.php (lines 1824, 1844), fourn/class/fournisseur.commande.class.php:3780, and mrp/mo_production.php (lines 1455, 1913).', 'Enabling this setting includes service-type products in stock calculations and movements alongside physical products.', '0 or empty = only physical products tracked in stock; non-zero = services also tracked in stock.', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:875|read|print $form->selectarray(\"STOCK_SUPPORTS_SERVICES\", $arrval, getDolGlobalString(''STOCK_SUPPORTS_SERVICES''));", "reception/card.php:1824|check|if ($line->product_type == Product::TYPE_PRODUCT || getDolGlobalString(''STOCK_SUPPORTS_SERVICES'')) {", "reception/card.php:1844|check|if ($line->product_type == Product::TYPE_PRODUCT || getDolGlobalString(''STOCK_SUPPORTS_SERVICES'')) {   // Type of product need stock change ?", "fourn/class/fournisseur.commande.class.php:3780|check|if (!getDolGlobalString(''STOCK_SUPPORTS_SERVICES'') && $line->product_type > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_SUPPORT_SERVICES', 'string', NULL, 'bom', 'Enables stock movement tracking for service-type products (not only physical goods).', 'When not set, stock movement creation is skipped for contract lines and service items. Checked in bom/tpl/objectline_create.tpl.php and product/stock/movement_list.php.', 'When disabled, stock movements are not recorded for services. Enabling it allows stock operations to apply to service products as well.', 'Truthy = services can have stock movements; empty/falsy = services excluded from stock', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["bom/tpl/objectline_create.tpl.php:62|check|if (!empty($object->element) && $object->element == ''contrat'' && !getDolGlobalString(''STOCK_SUPPORT_SERVICES'')) {", "product/stock/movement_list.php:168|check|if (!getDolGlobalString(''STOCK_SUPPORT_SERVICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_UPDATE_AWP_EVEN_WHEN_ENTRY_PRICE_IS_NULL', 'string', NULL, 'product', 'Allows the average weighted price (AWP) to be updated on stock movements even when the entry price is zero, for supplier order and invoice origins.', 'In product/stock/class/mouvementstock.class.php, the AWP update logic normally requires price > 0. When this constant is set, a zero price is also accepted for movements of type ''order_supplier'' or ''invoice_supplier''. No admin UI; hidden setting.', 'Enabling this constant allows zero-price supplier stock entries to update the AWP; disabling it (or leaving unset) skips AWP updates when price is zero.', 'Non-empty (truthy) enables AWP update at zero price for supplier origins; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["product/stock/class/mouvementstock.class.php:583|check|if ($price > 0 || (getDolGlobalString(''STOCK_UPDATE_AWP_EVEN_WHEN_ENTRY_PRICE_IS_NULL'') && $price == 0 && in_array($this->origin_type, array(''order_supplier'', ''invoice_supplier''))))"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_USERSTOCK_AUTOCREATE', 'string', NULL, 'admin', 'Controls automatic creation of a personal warehouse for a user when MAIN_DEFAULT_WAREHOUSE_USER is also set.', 'When both MAIN_DEFAULT_WAREHOUSE_USER and STOCK_USERSTOCK_AUTOCREATE are set, user/class/user.class.php:1909 auto-creates the user''s personal stock warehouse. Configurable via admin/stock.php.', 'Enabling auto-creation ensures each user has a personal warehouse created automatically; disabling requires manual warehouse assignment.', 'Empty = no auto-creation; non-empty = automatically create user warehouse when MAIN_DEFAULT_WAREHOUSE_USER is set', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/user.class.php:1909|check|if (getDolGlobalString(''MAIN_DEFAULT_WAREHOUSE_USER'') && getDolGlobalString(''STOCK_USERSTOCK_AUTOCREATE'')) {", "admin/stock.php:810|read|print $form->selectarray(\"STOCK_USERSTOCK_AUTOCREATE\", $arrval, getDolGlobalString(''STOCK_USERSTOCK_AUTOCREATE''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_USE_REAL_STOCK_BY_DEFAULT_FOR_REPLENISHMENT', 'bool', NULL, 'product', 'Determines whether real stock or virtual stock is used by default in the replenishment view.', 'Configured via admin/stock.php:598 and read in product/stock/replenish.php:135. When set, real stock is used (virtual stock flag set to 0); when not set, virtual stock is used by default.', 'Changing this constant switches the default stock reference used in replenishment calculations between real and virtual stock levels.', 'Non-empty = real stock used by default; empty or unset = virtual stock used by default', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/stock.php:598|read|print $form->selectarray(\"STOCK_USE_REAL_STOCK_BY_DEFAULT_FOR_REPLENISHMENT\", $arrval, getDolGlobalString(''STOCK_USE_REAL_STOCK_BY_DEFAULT_FOR_REPLENISHMENT''));", "product/stock/replenish.php:135|read|$usevirtualstock = getDolGlobalString(''STOCK_USE_REAL_STOCK_BY_DEFAULT_FOR_REPLENISHMENT'') ? 0 : 1;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_USE_WAREHOUSE_BY_USER', 'bool', NULL, 'core', 'Enables per-user warehouse assignment, restricting stock operations to the warehouse assigned to the current user.', 'Checked at core/lib/stock.lib.php line 58; the per-user warehouse filtering logic runs only when this constant is set. Only 1 occurrence found; exact behavior unclear from code alone.', 'Setting this constant activates user-level warehouse filtering in stock operations.', 'Boolean flag; absent/falsy = warehouse not filtered by user; truthy = warehouse filtered by user assignment.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/stock.lib.php:58|check|if (getDolGlobalString(''STOCK_USE_WAREHOUSE_BY_USER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_USE_WAREHOUSE_USAGE', 'bool', NULL, 'product', 'Enables the warehouse_usage field on warehouse records to classify warehouse purpose.', 'Checked via getDolGlobalInt at product/stock/card.php:532 and used as the ''enabled'' condition for the ''warehouse_usage'' field definition in product/stock/class/entrepot.class.php:191.', 'Enabling this constant activates the warehouse usage/classification field in the warehouse entity; disabling it hides that field.', '0 or empty = warehouse_usage field disabled; any non-zero integer = warehouse_usage field enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/stock/card.php:532|check|if (getDolGlobalInt(\"STOCK_USE_WAREHOUSE_USAGE\")) {", "product/stock/class/entrepot.class.php:191|read|''warehouse_usage'' => array(''type'' => ''integer'', ''label'' => ''WarehouseUsage'', ''enabled'' => ''getDolGlobalInt(\"STOCK_USE_WAREHOUSE_USAGE\")'', ''visible'' => 1, ''position'' => 400, ''defaul"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_WAREHOUSE_NOT_REQUIRED_FOR_RECEPTIONS', 'bool', NULL, 'reception', 'Allows adding a reception line without specifying a stock warehouse/source.', 'When set, the warehouse validation check is bypassed in reception.class.php:984. Documented in reception/class/reception.class.php:948: ''If STOCK_WAREHOUSE_NOT_REQUIRED_FOR_RECEPTIONS is set, you can add a reception line, with no stock source defined.''', 'Without this constant, receptions require a valid warehouse (entrepot_id > 0); enabling it removes that requirement and allows warehouse-less reception lines.', '0 or unset = warehouse required; 1 = warehouse not required', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/class/reception.class.php:948  * If STOCK_WAREHOUSE_NOT_REQUIRED_FOR_RECEPTIONS is set, you can add a reception line, with no stock source defined", "reception/class/reception.class.php:984|check|if (!($entrepot_id > 0) && !getDolGlobalInt(''STOCK_WAREHOUSE_NOT_REQUIRED_FOR_RECEPTIONS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STOCK_WAREHOUSE_NOT_REQUIRED_FOR_SHIPMENTS', 'bool', NULL, 'expedition', 'Allows shipment lines to be saved without a source warehouse when enabled.', 'Checked in expedition/class/expedition.class.php:1282. The inline comment at line 1241 documents the behavior: ''If STOCK_WAREHOUSE_NOT_REQUIRED_FOR_SHIPMENTS is set, you can add a shipment line, with no stock source defined''. No admin UI write is present.', 'Enabling this constant removes the warehouse validation requirement for shipment lines, allowing shipments without a defined source warehouse.', 'Truthy value (e.g. 1) to skip warehouse requirement; empty or 0 to require a warehouse.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["expedition/class/expedition.class.php:1241  * If STOCK_WAREHOUSE_NOT_REQUIRED_FOR_SHIPMENTS is set, you can add a shipment line, with no stock source defined", "expedition/class/expedition.class.php:1282|check|if (!($entrepot_id > 0) && !getDolGlobalString(''STOCK_WAREHOUSE_NOT_REQUIRED_FOR_SHIPMENTS'') && !(getDolGlobalString(''SHIPMENT_SUPPORTS_SERVICES'') && $line->product_type == Product"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPECONNECT_PRINCIPAL', 'string', NULL, 'stripe', 'Identifies the principal entity ID for Stripe Connect, used to gate application fee logic.', 'Checked in a single location at stripe/class/stripe.class.php:567 to determine whether the current entity differs from the Stripe Connect principal before applying a stripe fee. No admin UI is present.', 'If the current entity does not match this value and a stripe fee is configured, the fee will be applied; otherwise it is skipped.', 'Integer entity ID of the Stripe Connect principal entity.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/class/stripe.class.php:567|check|if ($conf->entity != getDolGlobalInt(''STRIPECONNECT_PRINCIPAL'') && $stripefee > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_ALLOW_LOCAL_CARD', 'bool', NULL, 'societe', 'Enables the use of locally stored card data in Stripe payment mode UI.', 'Checked in 3 occurrences in societe/paymentmodes.php: at :1205 and :1236 to conditionally display local card UI, and at :1500 to adjust column span based on its presence.', 'When enabled, additional UI elements for local card data are shown in the Stripe payment modes page.', '0 or unset = local card option hidden; non-empty = local card option shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/paymentmodes.php:1205|check|if (getDolGlobalString(''STRIPE_ALLOW_LOCAL_CARD'')) {", "societe/paymentmodes.php:1236|check|if (getDolGlobalString(''STRIPE_ALLOW_LOCAL_CARD'')) {", "societe/paymentmodes.php:1500|read|$colspan = (getDolGlobalString(''STRIPE_ALLOW_LOCAL_CARD'') ? 10 : 9);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_APPLICATION_FEE', 'string', NULL, 'stripe', 'Sets a fixed monetary application fee added to Stripe payment transactions.', 'Displayed in stripe/admin/stripe.php:320 and used in stripe/class/stripe.class.php:408 in the fee formula alongside the percentage fee. Admin UI available at stripe/admin/stripe.php.', 'Changing this value directly changes the fixed component of the computed Stripe application fee for each transaction.', 'Numeric monetary amount in the account currency (e.g. ''0.30''); 0 or unset = no fixed fee.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:320|read|print price(getDolGlobalString(''STRIPE_APPLICATION_FEE''));", "stripe/class/stripe.class.php:408|read|$fee = $amount * ((float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_PERCENT\", ''0'') / 100) + (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE\", ''0'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_APPLICATION_FEE_MAXIMAL', 'string', NULL, 'stripe', 'Caps the computed Stripe application fee at a maximum monetary value.', 'Used exclusively in stripe/class/stripe.class.php:410-411 to clamp the fee: if the computed fee is at or above this value (and this value is greater than STRIPE_APPLICATION_FEE_MINIMAL), the fee is set to this maximum. No admin UI is present.', 'Setting a maximal fee prevents the application fee from exceeding a configured ceiling, regardless of the percentage or fixed fee computations.', 'Numeric monetary amount; 0 or unset = no maximum cap applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/class/stripe.class.php:410|check|if ($fee >= (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MAXIMAL\", ''0'') && (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MAXIMAL\", ''0'') > (float) getDolGlobalString(\"STR...", "stripe/class/stripe.class.php:411|read|$fee = (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MAXIMAL\", ''0'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_APPLICATION_FEE_MINIMAL', 'string', NULL, 'stripe', 'Sets a minimum monetary floor for the computed Stripe application fee.', 'Read in stripe/class/stripe.class.php:412-413 and displayed in stripe/admin/stripe.php:321. If the computed fee falls below this value, the fee is set to this minimum. Admin UI is available at stripe/admin/stripe.php.', 'Setting a minimal fee ensures the application fee is never below the configured floor, regardless of transaction amount.', 'Numeric monetary amount in the account currency; 0 or unset = no minimum floor applied.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:321|read|print '' ''.$langs->getCurrencySymbol(getDolCurrency()).'' ''.$langs->trans(\"minimum\").'' ''.price(getDolGlobalString(''STRIPE_APPLICATION_FEE_MINIMAL''))...", "stripe/class/stripe.class.php:412|read|} elseif ($fee < (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MINIMAL\", ''0'')) {", "stripe/class/stripe.class.php:413|read|$fee = (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MINIMAL\", ''0'');", "stripe/class/stripe.class.php:410|check|if ($fee >= (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MAXIMAL\", ''0'') && (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_MAXIMAL\", ''0'') > (float) getDolGlobalString(\"STR..."]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_APPLICATION_FEE_PERCENT', 'string', NULL, 'stripe', 'Sets the percentage-based application fee deducted from Stripe payments.', 'Displayed in stripe/admin/stripe.php:318 and used in stripe/class/stripe.class.php:408 in the formula: fee = amount * (STRIPE_APPLICATION_FEE_PERCENT / 100) + STRIPE_APPLICATION_FEE. Admin UI available at stripe/admin/stripe.php.', 'Changing the percentage directly changes the application fee computed for each Stripe transaction; combined with the fixed fee and bounded by minimal/maximal constants.', 'Decimal number representing a percentage (e.g. ''2.5'' = 2.5%); 0 or unset = no percentage fee.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:318|read|print price(getDolGlobalString(''STRIPE_APPLICATION_FEE_PERCENT''));", "stripe/class/stripe.class.php:408|read|$fee = $amount * ((float) getDolGlobalString(\"STRIPE_APPLICATION_FEE_PERCENT\", ''0'') / 100) + (float) getDolGlobalString(\"STRIPE_APPLICATION_FEE\", ''0'');", "stripe/class/stripe.class.php:407|check|if (getDolGlobalString(\"STRIPE_APPLICATION_FEE_PERCENT\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_AUTO_RECORD_PAYOUT', 'string', NULL, 'stripe', 'Enables automatic recording of Stripe payout events (payout.created and payout.paid) received via webhook.', 'Configured via stripe/admin/stripe.php:630. The payout.create and payout.paid webhook hooks are registered as active only when this constant is truthy (stripe/admin/stripe.php:47-48). Processing occurs in public/stripe/ipn.php:207 and :253.', 'Enabling this causes Dolibarr to automatically record bank payout entries when Stripe sends payout webhook events; disabling it means those events are ignored.', '0 = payout auto-recording disabled; truthy = payout.created and payout.paid webhooks are processed and recorded', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:47|read|$listofsupportedhooks[] = array(''code'' => ''payout.create'', ''status'' => getDolGlobalString(''STRIPE_AUTO_RECORD_PAYOUT'') ? 1 : 0);", "stripe/admin/stripe.php:48|read|$listofsupportedhooks[] = array(''code'' => ''payout.paid'', ''status'' => getDolGlobalString(''STRIPE_AUTO_RECORD_PAYOUT'') ? 1 : 0);", "public/stripe/ipn.php:207|check|if ($event->type == ''payout.created'' && getDolGlobalString(''STRIPE_AUTO_RECORD_PAYOUT'')) {", "public/stripe/ipn.php:253|read|} elseif ($event->type == ''payout.paid'' && getDolGlobalString(''STRIPE_AUTO_RECORD_PAYOUT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_AUTO_RECORD_PAYOUT_LABEL', 'string', NULL, 'public', 'Sets a custom label appended to payout descriptions when Stripe payouts are automatically recorded via IPN.', 'Read at public/stripe/ipn.php:266 and appended to the event description; defaults to ''autorecord by IPN, see Stripe setup'' if not set.', 'The value appears as part of the label on automatically recorded payout entries.', 'Any string; defaults to ''autorecord by IPN, see Stripe setup'' if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:266|read|$label = $event->data->object->description.'' - ''.getDolGlobalString(''STRIPE_AUTO_RECORD_PAYOUT_LABEL'', ''autorecord by IPN, see Stripe setup'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_BANCONTACT', 'string', NULL, 'stripe', 'Enables the Bancontact payment method option in Stripe payment processing.', 'Selected via admin UI at stripe/admin/stripe.php:527 and checked in stripe/class/stripe.class.php:493 and :768 to include Bancontact as a payment method type.', 'Enabling this adds Bancontact to the list of Stripe payment method types offered during checkout.', '0 or unset = Bancontact disabled; truthy value = Bancontact enabled.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:527|read|print $form->selectarray(\"STRIPE_BANCONTACT\", $arrval, $conf->global->STRIPE_BANCONTACT);", "stripe/class/stripe.class.php:493|check|if (getDolGlobalInt(''STRIPE_BANCONTACT'')) {", "stripe/class/stripe.class.php:768|check|if (getDolGlobalString(''STRIPE_BANCONTACT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS', 'string', NULL, 'stripe', 'Specifies the Dolibarr bank account ID used as the destination account when recording Stripe bank transfer payouts.', 'Configured via stripe/admin/stripe.php:127. Used in public/stripe/ipn.php:275 to fetch the destination account for bank transfer IPN events.', 'Setting this to the correct bank account ensures Stripe payout transfers are booked to the right Dolibarr account; leaving it unset will cause the account fetch to fail.', 'Integer ID of a Dolibarr bank account', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:127|write|$result = dolibarr_set_const($db, \"STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS\", GETPOSTINT(''STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:643|read|$form->select_comptes(getDolGlobalString(''STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS''), ''STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS'', 0, '''', 1);", "public/stripe/ipn.php:275|read|$accountto->fetch(getDolGlobalInt(''STRIPE_BANK_ACCOUNT_FOR_BANKTRANSFERS''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_BANK_ACCOUNT_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the Dolibarr bank account ID used to record incoming Stripe payments and SEPA transactions.', 'Configured via stripe/admin/stripe.php:119 and used in public/stripe/ipn.php:605, :272, :1198 and core/class/commoninvoice.class.php:1714. A comment at commoninvoice.class.php:1714 states: ''Bank account used for SEPA direct debit or credit transfer. Must be the Stripe account in Dolibarr.''', 'Setting this to the correct bank account ID ensures Stripe payment receipts and SEPA operations are recorded against the right Dolibarr account; an incorrect ID will misdirect payment entries.', 'Integer ID of a Dolibarr bank account', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/commoninvoice.class.php:1714|read|$fk_bank_account = getDolGlobalInt(''STRIPE_BANK_ACCOUNT_FOR_PAYMENTS'');\t\t// Bank account used for SEPA direct debit or credit transfer. Must be the Stripe account in Dolibarr.", "stripe/admin/stripe.php:119|write|$result = dolibarr_set_const($db, \"STRIPE_BANK_ACCOUNT_FOR_PAYMENTS\", GETPOSTINT(''STRIPE_BANK_ACCOUNT_FOR_PAYMENTS''), ''chaine'', 0, '''', $conf->entity);", "public/stripe/ipn.php:605|read|$bankaccountid = getDolGlobalInt(\"STRIPE_BANK_ACCOUNT_FOR_PAYMENTS\");", "public/stripe/ipn.php:1198|read|$accountfrom->fetch(getDolGlobalInt(''STRIPE_BANK_ACCOUNT_FOR_PAYMENTS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_CARD_PRESENT', 'string', NULL, 'stripe', 'Enables Stripe card-present (in-person/terminal) payment mode for point-of-sale integration.', 'Checked across stripe/class/stripe.class.php, takepos/admin/terminal.php:251, takepos/pay.php:630 and :741 to activate terminal-specific payment flows. Selected in admin UI at stripe/admin/stripe.php:428 and takepos/admin/terminal.php.', 'Enabling this switches Stripe payment processing to terminal/card-present mode; online payment intent reuse is disabled when this flag is active.', '0 or unset = online payment mode; truthy value = card-present terminal mode.', 0, 0, 'takepos/admin/terminal.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/terminal.php:251|check|if (isModEnabled(''stripe'') && getDolGlobalString(''STRIPE_CARD_PRESENT'')) {", "stripe/admin/stripe.php:428|read|print $form->selectarray(\"STRIPE_CARD_PRESENT\", $arrval, $conf->global->STRIPE_CARD_PRESENT);", "stripe/class/stripe.class.php:506|check|if (getDolGlobalInt(''STRIPE_CARD_PRESENT'')) {", "stripe/class/stripe.class.php:557|check|if (getDolGlobalInt(''STRIPE_CARD_PRESENT'') && $mode == ''terminal'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_DEBUG', 'string', NULL, 'public', 'Enables debug logging in the Stripe IPN handler.', 'Checked at public/stripe/ipn.php:121; when set, additional debug output is produced during IPN processing. No admin UI write found.', 'When enabled, the Stripe IPN handler outputs debug information; this should not be enabled in production.', 'Any non-empty value enables debug output; empty/unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:121|check|if (getDolGlobalString(''STRIPE_DEBUG'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_DELETE_STRIPE_ACCOUNT_WHEN_DELETING_THIRDPARTY', 'string', NULL, 'core', 'Controls whether the corresponding Stripe customer account is deleted when a Dolibarr thirdparty is deleted.', 'Checked in core/triggers/interface_80_modStripe_Stripe.class.php:189 to gate the Stripe account deletion call when the thirdparty delete trigger fires.', 'When set, deleting a thirdparty also deletes the linked Stripe customer account; when unset, the Stripe account is preserved.', 'Empty/unset = Stripe account preserved on thirdparty deletion; non-empty = Stripe account deleted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_80_modStripe_Stripe.class.php:189|check|if (getDolGlobalString(''STRIPE_DELETE_STRIPE_ACCOUNT_WHEN_DELETING_THIRDPARTY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_FORCE_VERSION', 'string', NULL, 'stripe', 'Forces a specific Stripe API version for all Stripe API calls.', 'Read at stripe/config.php:53 with a default fallback: ''\Stripe\Stripe::setApiVersion(getDolGlobalString(''STRIPE_FORCE_VERSION'', "2022-11-15")); // force version API''. No admin UI write path is present.', 'Setting this constant overrides the default API version (2022-11-15) used for all Stripe calls; removing it reverts to the hardcoded default.', 'Not set = uses default ''2022-11-15''; string = Stripe API version string to enforce (e.g. ''2023-10-16'').', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/config.php:53|read|\\Stripe\\Stripe::setApiVersion(getDolGlobalString(''STRIPE_FORCE_VERSION'', \"2022-11-15\")); // force version API"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_GIROPAY', 'string', NULL, 'stripe', 'Enables the Giropay payment method option in Stripe payment processing.', 'Selected via admin UI at stripe/admin/stripe.php:555 and checked in stripe/class/stripe.class.php:499 and :551 to include Giropay as a payment method type.', 'Enabling this adds Giropay to the list of Stripe payment method types offered during checkout.', '0 or unset = Giropay disabled; truthy value = Giropay enabled.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:555|read|print $form->selectarray(\"STRIPE_GIROPAY\", $arrval, $conf->global->STRIPE_GIROPAY);", "stripe/class/stripe.class.php:499|check|if (getDolGlobalInt(''STRIPE_GIROPAY'')) {", "stripe/class/stripe.class.php:551|check|if (getDolGlobalInt(''STRIPE_GIROPAY'')) {"]', 'medium', NULL);
