INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_IPN_SEND_EMAIL_ON_DIRECT_DEBIT_CONFIRMATION', 'string', NULL, 'public', 'Specifies the email template label to use when sending a confirmation email upon direct debit confirmation via Stripe IPN.', 'Checked at public/stripe/ipn.php:692 to decide whether to send an email, and read at :696 as the label to identify the email template. No admin UI write found.', 'When set, a confirmation email using this template label is sent upon direct debit confirmation; when unset, no email is sent.', 'An email template label string; empty/unset disables the confirmation email.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:692|check|if (getDolGlobalString(''STRIPE_IPN_SEND_EMAIL_ON_DIRECT_DEBIT_CONFIRMATION'')) {", "public/stripe/ipn.php:696|read|$labeltouse = getDolGlobalString(''STRIPE_IPN_SEND_EMAIL_ON_DIRECT_DEBIT_CONFIRMATION'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_KLARNA', 'string', NULL, 'stripe', 'Enables the Klarna payment method option in Stripe payment processing.', 'Selected via admin UI at stripe/admin/stripe.php:514 and checked in stripe/class/stripe.class.php:490 and :554 to include Klarna as a payment method type.', 'Enabling this adds Klarna to the list of Stripe payment method types offered during checkout.', '0 or unset = Klarna disabled; truthy value = Klarna enabled.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:514|read|print $form->selectarray(\"STRIPE_KLARNA\", $arrval, $conf->global->STRIPE_KLARNA);", "stripe/class/stripe.class.php:490|check|if (getDolGlobalInt(''STRIPE_KLARNA'')) {", "stripe/class/stripe.class.php:554|check|if (getDolGlobalInt(''STRIPE_KLARNA'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE', 'string', NULL, 'stripe', 'Switches the Stripe payment integration between live (production) and sandbox (test) mode.', 'Configured via stripe/admin/stripe.php and takepos/admin/terminal.php. When set, live Stripe credentials and endpoints are used (stripe/admin/stripe.php:439); when unset, sandbox mode is active (stripe/admin/stripe.php:450). Read in 29 occurrences across stripe and payment modules.', 'Setting to live mode enables real payment processing; unsetting or setting to 0 keeps the integration in sandbox/test mode where no real charges are made.', '0 or unset = sandbox/test mode; non-empty = live/production mode', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|takepos/admin/terminal.php|takepos/admin/terminal.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:439|check|if (getDolGlobalString(''STRIPE_LIVE'')/* && !GETPOST(''forcesandbox'', ''alpha'') */) {", "stripe/admin/stripe.php:450|check|if (isModEnabled(''stripe'') && (!getDolGlobalString(''STRIPE_LIVE'')/* || GETPOST(''forcesandbox'', ''alpha'') */)) {", "stripe/admin/stripe.php:185|write|$res = dolibarr_set_const($db, \"STRIPE_LIVE\", $liveenable, ''yesno'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:238|read|print $form->selectarray(\"STRIPE_LIVE\", $arrval, $conf->global->STRIPE_LIVE);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE_PUBLISHABLE_KEY', 'string', NULL, 'stripe', 'Stores the Stripe live-mode publishable API key used for client-side Stripe integration in production.', 'Configured via stripe/admin/stripe.php:98 and read at stripe/config.php:40. A commented-out line at stripe/admin/stripe.php:346 shows it was previously considered for security hashing: ''//$url .= ''?securitykey=''.dol_hash(''stripeipn-''.$dolibarr_main_instance_unique_id.''-''.getDolGlobalString(''STRIPE_LIVE_PUBLISHABLE_KEY''), ''md5'');''.', 'Setting a valid live publishable key enables client-side Stripe live-mode elements; an absent key disables them.', 'Empty/not set = Stripe live publishable key not configured; string starting with ''pk_live_' || ''' = valid Stripe live publishable key.', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/config.php:40|read|\"publishable_key\" => getDolGlobalString(''STRIPE_LIVE_PUBLISHABLE_KEY'')", "stripe/admin/stripe.php:98|write|$result = dolibarr_set_const($db, \"STRIPE_LIVE_PUBLISHABLE_KEY\", GETPOST(''STRIPE_LIVE_PUBLISHABLE_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:346  //$url .= ''?securitykey=''.dol_hash(''stripeipn-''.$dolibarr_main_instance_unique_id.''-''.getDolGlobalString(''STRIPE_LIVE_PUBLISHABLE_KEY''), ''md5'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE_SECRET_KEY', 'string', NULL, 'stripe', 'Stores the Stripe live-mode secret API key used to authenticate server-side Stripe API calls in production.', 'Configured via stripe/admin/stripe.php:102 and read at stripe/config.php:39 and stripe/admin/stripe.php:364, where it is passed to \Stripe\Stripe::setApiKey(). Used alongside STRIPE_LIVE_WEBHOOK_KEY and STRIPE_LIVE_WEBHOOK_ID.', 'Setting a valid live secret key enables Stripe live-mode payment processing; an invalid or absent key disables live Stripe integration.', 'Empty/not set = Stripe live mode not configured; string starting with ''sk_live_' || ''' = valid Stripe live secret key.', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/config.php:39|read|\"secret_key\"      => getDolGlobalString(''STRIPE_LIVE_SECRET_KEY''),", "stripe/admin/stripe.php:364|read|\\Stripe\\Stripe::setApiKey(getDolGlobalString(''STRIPE_LIVE_SECRET_KEY''));", "stripe/admin/stripe.php:361|check|if (getDolGlobalString(''STRIPE_LIVE_WEBHOOK_KEY'') && getDolGlobalString(''STRIPE_LIVE_SECRET_KEY'') && getDolGlobalString(''STRIPE_LIVE_WEBHOOK_ID'')) {", "stripe/admin/stripe.php:102|write|$result = dolibarr_set_const($db, \"STRIPE_LIVE_SECRET_KEY\", GETPOST(''STRIPE_LIVE_SECRET_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE_WEBHOOK_CONNECT_KEY', 'string', NULL, 'public', 'Stores the Stripe live mode webhook endpoint secret used to verify IPN signature in production.', 'Read at public/stripe/ipn.php:74 and assigned to $endpoint_secret for live mode webhook signature verification. No admin UI write found.', 'If incorrect or unset, Stripe IPN signature verification will fail in live mode, rejecting incoming production webhook events.', 'A Stripe live webhook endpoint secret string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:74|read|$endpoint_secret = getDolGlobalString(''STRIPE_LIVE_WEBHOOK_CONNECT_KEY'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE_WEBHOOK_ID', 'string', NULL, 'stripe', 'Stores the Stripe live-mode webhook endpoint ID used to verify and retrieve the live webhook configuration.', 'Configured via stripe/admin/stripe.php:106 and read/checked at :339, :361, :365, :367. Used together with STRIPE_LIVE_WEBHOOK_KEY and STRIPE_LIVE_SECRET_KEY to validate the live webhook endpoint via the Stripe API.', 'Changing this value changes which Stripe live webhook endpoint Dolibarr validates and uses for live-mode IPN processing.', 'String Stripe webhook endpoint ID for live mode (e.g., ''we_x...'')', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:106|write|$result = dolibarr_set_const($db, \"STRIPE_LIVE_WEBHOOK_ID\", GETPOST(''STRIPE_LIVE_WEBHOOK_ID'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:361|check|if (getDolGlobalString(''STRIPE_LIVE_WEBHOOK_KEY'') && getDolGlobalString(''STRIPE_LIVE_SECRET_KEY'') && getDolGlobalString(''STRIPE_LIVE_WEBHOOK_ID'')) {", "stripe/admin/stripe.php:365|read|$endpoint = \\Stripe\\WebhookEndpoint::retrieve(getDolGlobalString(''STRIPE_LIVE_WEBHOOK_ID''));", "stripe/admin/stripe.php:367|check|if (GETPOST(''webhook'', ''alpha'') == getDolGlobalString(''STRIPE_LIVE_WEBHOOK_ID'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LIVE_WEBHOOK_KEY', 'string', NULL, 'stripe', 'Stores the Stripe live-mode webhook signing secret used to verify incoming live webhook request signatures.', 'Configured via stripe/admin/stripe.php:110 and used in public/stripe/ipn.php:84 as the endpoint_secret for live signature verification. Also checked at stripe/admin/stripe.php:361 alongside STRIPE_LIVE_SECRET_KEY and STRIPE_LIVE_WEBHOOK_ID.', 'Changing or clearing this value breaks webhook signature validation for live-mode Stripe events, causing all live webhook events to fail verification.', 'String Stripe webhook signing secret for live mode (e.g., ''whsec_...'')', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:110|write|$result = dolibarr_set_const($db, \"STRIPE_LIVE_WEBHOOK_KEY\", GETPOST(''STRIPE_LIVE_WEBHOOK_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "public/stripe/ipn.php:84|read|$endpoint_secret = getDolGlobalString(''STRIPE_LIVE_WEBHOOK_KEY'');", "stripe/admin/stripe.php:361|check|if (getDolGlobalString(''STRIPE_LIVE_WEBHOOK_KEY'') && getDolGlobalString(''STRIPE_LIVE_SECRET_KEY'') && getDolGlobalString(''STRIPE_LIVE_WEBHOOK_ID'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_LOCATION', 'string', NULL, 'takepos', 'Stores the Stripe Terminal location ID used to filter readers for in-person payment processing.', 'Configured via stripe/admin/stripe.php:132 and read in takepos/admin/terminal.php:274-276 to filter Stripe Terminal readers by location. Also checked at takepos/pay.php:142 and :193 to include the location parameter in the Stripe Terminal client-side integration.', 'Setting this to a valid Stripe location ID enables Stripe Terminal reader filtering by location; leaving it empty retrieves all readers.', 'Empty/not set = no location filter applied; Stripe location ID string = only readers at that location are listed and used.', 0, 0, 'stripe/admin/stripe.php|takepos/admin/terminal.php|takepos/admin/terminal.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/terminal.php:274|read|$readers = \\Stripe\\Terminal\\Reader::all(null, array(\"location\" => getDolGlobalString(''STRIPE_LOCATION''), \"stripe_account\" => $stripeacc));", "stripe/admin/stripe.php:132|write|$result = dolibarr_set_const($db, \"STRIPE_LOCATION\", GETPOST(''STRIPE_LOCATION'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/pay.php:142|check|if (getDolGlobalString(''STRIPE_LOCATION'')) {", "stripe/ajax/ajax.php:70|read|$usestripeterminals = getDolGlobalString(''STRIPE_LOCATION'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_NO_DUPLICATE_CHECK', 'string', NULL, 'public', 'Disables the duplicate payment check in the Stripe IPN handler.', 'Checked at public/stripe/ipn.php:946; the adjacent comment at :945 notes the duplicate check can be removed when this is set. No admin UI write found.', 'When set, the IPN handler skips duplicate payment detection, which may result in duplicate records if the same event is processed multiple times.', 'Any non-empty value disables duplicate check; empty/unset enables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:945  // so we can remove the test on STRIPE_NO_DUPLICATE_CHECK", "public/stripe/ipn.php:946|check|if (getDolGlobalString(''STRIPE_NO_DUPLICATE_CHECK'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_PAYMENT_MODE_FOR_PAYMENTS', 'string', NULL, 'public', 'Specifies the payment mode ID used to record Stripe payments in the Dolibarr payment system.', 'Read as an integer at public/payment/paymentok.php at lines 585, 1028, 1174, 1329, 1468, 1707, and 1925 and assigned to $paymentTypeId for recording payments. No admin UI write found.', 'Setting this to a valid payment mode ID ensures Stripe payments are recorded with the correct payment type.', 'An integer payment mode ID.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/paymentok.php:585|read|$paymentTypeId = getDolGlobalInt(''STRIPE_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1028|read|$paymentTypeId = getDolGlobalInt(''STRIPE_PAYMENT_MODE_FOR_PAYMENTS'');", "public/payment/paymentok.php:1174|read|$paymentTypeId = getDolGlobalInt(''STRIPE_PAYMENT_MODE_FOR_PAYMENTS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_REUSE_EXISTING_INTENT_IF_FOUND', 'bool', NULL, 'stripe', 'Controls whether an existing Stripe payment intent is reused when found, instead of creating a new one.', 'Checked in a single location at stripe/class/stripe.class.php:419, combined with a check that STRIPE_CARD_PRESENT is not set. No admin UI is present.', 'Enabling this causes the code to reuse an existing payment intent for an object rather than creating a new one, provided card-present mode is disabled.', '0 or unset = do not reuse existing intent; 1 = reuse existing intent if found.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/class/stripe.class.php:419|check|if (is_object($object) && getDolGlobalInt(''STRIPE_REUSE_EXISTING_INTENT_IF_FOUND'') && !getDolGlobalInt(''STRIPE_CARD_PRESENT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_SAVE_TAX_IDS', 'string', NULL, 'stripe', 'Controls whether customer tax IDs are saved on the Stripe side during payment processing.', 'Checked in stripe/class/stripe.class.php:254, core/triggers/interface_80_modStripe_Stripe.class.php:156, and public/payment/newpayment.php:705 before transmitting tax info to Stripe. All three sites include an inline warning that enabling this may cause errors when saving customers.', 'Enabling this causes tax ID data to be sent to Stripe, which may result in Stripe API errors for certain customer types. Disabling it skips tax ID transmission entirely.', '0 or unset = do not save tax IDs to Stripe; any truthy value = save tax IDs (warning: may cause errors).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/class/stripe.class.php:254|check|if (getDolGlobalString(''STRIPE_SAVE_TAX_IDS'')) {\t// We setup to save Tax info on Stripe side. Warning: This may result in error when saving customer", "core/triggers/interface_80_modStripe_Stripe.class.php:156|check|if (getDolGlobalString(''STRIPE_SAVE_TAX_IDS'')) {\t// We setup to save Tax info on Stripe side. Warning: This may result in error when saving customer", "public/payment/newpayment.php:705|check|if (getDolGlobalString(''STRIPE_SAVE_TAX_IDS'')) {\t// We setup to save Tax info on Stripe side. Warning: This may result in error when saving customer"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_SEPA_CREDIT_TRANSFER', 'string', NULL, 'salaries', 'Enables Stripe SEPA Credit Transfer payment mode for supplier payments and customer invoices.', 'Configured via stripe/admin/stripe.php:501. Checked in salaries/virement_request.php:651, compta/facture/prelevement.php:1061, and core/class/commoninvoice.class.php:1628 where credit transfer availability is conditioned on this constant.', 'When set, SEPA Credit Transfer options appear on salary transfer request and invoice pre-levy pages; when absent, the credit-transfer path is suppressed.', 'Non-empty string = SEPA Credit Transfer enabled; empty = disabled', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:501|read|print $form->selectarray(\"STRIPE_SEPA_CREDIT_TRANSFER\", $arrval, getDolGlobalString(''STRIPE_SEPA_CREDIT_TRANSFER''));", "salaries/virement_request.php:651|check|if (getDolGlobalString(''STRIPE_SEPA_CREDIT_TRANSFER'')) {", "compta/facture/prelevement.php:1061|check|if (getDolGlobalString(''STRIPE_SEPA_CREDIT_TRANSFER'')) {", "core/class/commoninvoice.class.php:1628|check|if ($type != ''direct-debit'' && !getDolGlobalString(''STRIPE_SEPA_CREDIT_TRANSFER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_SEPA_DIRECT_DEBIT', 'string', NULL, 'stripe', 'Enables and configures Stripe SEPA Direct Debit payment mode in Dolibarr.', 'Configured via stripe/admin/stripe.php (select array at line 491). Checked in stripe/class/stripe.class.php:487 and :765 to gate SEPA debit processing, and in compta/facture/prelevement.php:915 and :922 when the Stripe module is active.', 'When set, SEPA Direct Debit flows become available on supplier salary requests and customer invoice pre-levy pages; when unset those flows are suppressed.', 'Non-empty string value = SEPA Direct Debit enabled; empty = disabled', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:491|read|print $form->selectarray(\"STRIPE_SEPA_DIRECT_DEBIT\", $arrval, getDolGlobalString(''STRIPE_SEPA_DIRECT_DEBIT''));", "stripe/class/stripe.class.php:487|check|if (getDolGlobalInt(''STRIPE_SEPA_DIRECT_DEBIT'')) {", "compta/facture/prelevement.php:915|check|if (isModEnabled(''stripe'') && getDolGlobalString(''STRIPE_SEPA_DIRECT_DEBIT'')) {", "salaries/virement_request.php:643|check|if (getDolGlobalString(''STRIPE_SEPA_DIRECT_DEBIT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_SEPA_DIRECT_DEBIT_SHOW_OLD_BUTTON', 'bool', NULL, 'salaries', 'When enabled, shows a legacy SEPA direct-debit button that is otherwise hidden in favour of the STRIPE_SEPA_DIRECT_DEBIT mode.', 'Checked in salaries/virement_request.php:515 and compta/facture/prelevement.php:869. The inline comments in both locations state: ''This is hidden, prefer to use mode enabled with STRIPE_SEPA_DIRECT_DEBIT''.', 'Enabling this constant re-exposes the old SEPA direct-debit UI button; leaving it disabled keeps that button hidden.', 'Non-empty/truthy = show old button; empty/falsy = hide (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["salaries/virement_request.php:515|check|if (getDolGlobalString(''STRIPE_SEPA_DIRECT_DEBIT_SHOW_OLD_BUTTON'')) {\t// This is hidden, prefer to use mode enabled with STRIPE_SEPA_DIRECT_DEBIT", "compta/facture/prelevement.php:869|check|if (getDolGlobalString(''STRIPE_SEPA_DIRECT_DEBIT_SHOW_OLD_BUTTON'')) {\t// This is hidden, prefer to use mode enabled with STRIPE_SEPA_DIRECT_DEBIT"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_SOFORT', 'string', NULL, 'stripe', 'Enables the Sofort payment method option in Stripe payment processing.', 'Selected via admin UI at stripe/admin/stripe.php:569 and checked in stripe/class/stripe.class.php:502 and :775 to include Sofort as a payment method type.', 'Enabling this adds Sofort to the list of Stripe payment method types offered during checkout.', '0 or unset = Sofort disabled; truthy value = Sofort enabled.', 0, 0, 'stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:569|read|print $form->selectarray(\"STRIPE_SOFORT\", $arrval, $conf->global->STRIPE_SOFORT);", "stripe/class/stripe.class.php:502|check|if (getDolGlobalInt(''STRIPE_SOFORT'')) {", "stripe/class/stripe.class.php:775|check|if (getDolGlobalString(''STRIPE_SOFORT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TERMINAL_SIMULATED', 'string', NULL, 'takepos', 'Provides the test card number used to enable Stripe Terminal simulation mode in TakePos.', 'Read at takepos/pay.php:192, :448, and :449; when set and $servicestatus is empty, the Stripe Terminal is configured in simulated mode using the constant''s value as the test card number.', 'Setting this constant activates Stripe Terminal simulation with the specified test card number; leaving it unset disables simulation mode.', 'Empty/unset = live Stripe Terminal mode; a Stripe test card number string = simulated terminal with that card.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/pay.php:192|check|simulated: <?php if (empty($servicestatus) && getDolGlobalString(''STRIPE_TERMINAL_SIMULATED'')) { ?> true <?php } else { ?> false <?php } ?>", "takepos/pay.php:449|read|terminal.setSimulatorConfiguration({testCardNumber: ''<?php echo dol_escape_js(getDolGlobalString(''STRIPE_TERMINAL_SIMULATED'')); ?>''});"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TEST_PUBLISHABLE_KEY', 'string', NULL, 'stripe', 'Stores the Stripe test-mode publishable API key used for client-side Stripe integration in test mode.', 'Configured via stripe/admin/stripe.php:82 and read at stripe/config.php:36. A commented-out line at stripe/admin/stripe.php:264 shows it was previously considered for security hashing: ''//$url .= ''&securitykey=''.dol_hash(''stripeipn-''.$dolibarr_main_instance_unique_id.''-''.getDolGlobalString(''STRIPE_TEST_PUBLISHABLE_KEY''), ''md5'');''.', 'Setting a valid test publishable key enables client-side Stripe test-mode elements; an absent key disables them.', 'Empty/not set = Stripe test publishable key not configured; string starting with ''pk_test_' || ''' = valid Stripe test publishable key.', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/config.php:36|read|\"publishable_key\" => getDolGlobalString(''STRIPE_TEST_PUBLISHABLE_KEY'')", "stripe/admin/stripe.php:82|write|$result = dolibarr_set_const($db, \"STRIPE_TEST_PUBLISHABLE_KEY\", GETPOST(''STRIPE_TEST_PUBLISHABLE_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:264  //$url .= ''&securitykey=''.dol_hash(''stripeipn-''.$dolibarr_main_instance_unique_id.''-''.getDolGlobalString(''STRIPE_TEST_PUBLISHABLE_KEY''), ''md5'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TEST_SECRET_KEY', 'string', NULL, 'stripe', 'Stores the Stripe test-mode secret API key used to authenticate server-side Stripe API calls in test mode.', 'Configured via stripe/admin/stripe.php:86 and read at stripe/config.php:35 and stripe/admin/stripe.php:282, where it is passed to \Stripe\Stripe::setApiKey(). It is also validated for UTF-8 correctness before use.', 'Setting a valid test secret key enables Stripe test-mode payment processing; an invalid or absent key disables Stripe test integration.', 'Empty/not set = Stripe test mode not configured; string starting with ''sk_test_' || ''' = valid Stripe test secret key.', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/config.php:35|read|\"secret_key\"      => getDolGlobalString(''STRIPE_TEST_SECRET_KEY''),", "stripe/admin/stripe.php:282|read|\\Stripe\\Stripe::setApiKey(getDolGlobalString(''STRIPE_TEST_SECRET_KEY''));", "stripe/admin/stripe.php:280|check|if (utf8_check(getDolGlobalString(''STRIPE_TEST_SECRET_KEY''))) {", "stripe/admin/stripe.php:86|write|$result = dolibarr_set_const($db, \"STRIPE_TEST_SECRET_KEY\", GETPOST(''STRIPE_TEST_SECRET_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TEST_WEBHOOK_CONNECT_KEY', 'string', NULL, 'public', 'Stores the Stripe test mode webhook endpoint secret used to verify IPN (Instant Payment Notification) signatures.', 'Read at public/stripe/ipn.php:70 and assigned to $endpoint_secret, which is used to verify the Stripe webhook signature in test mode. No admin UI write found.', 'If incorrect or unset, Stripe IPN signature verification will fail in test mode, rejecting incoming webhook events.', 'A Stripe test webhook endpoint secret string.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/stripe/ipn.php:70|read|$endpoint_secret = getDolGlobalString(''STRIPE_TEST_WEBHOOK_CONNECT_KEY'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TEST_WEBHOOK_ID', 'string', NULL, 'stripe', 'Stores the Stripe test-mode webhook endpoint ID used to verify and retrieve the webhook configuration.', 'Configured via stripe/admin/stripe.php:90 and read/checked at :256, :279, :283, :285. Used together with STRIPE_TEST_WEBHOOK_KEY and STRIPE_TEST_SECRET_KEY to validate the test webhook endpoint via the Stripe API.', 'Changing this value changes which Stripe test webhook endpoint Dolibarr validates and uses for test-mode IPN processing.', 'String Stripe webhook endpoint ID (e.g., ''we_x...'')', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:90|write|$result = dolibarr_set_const($db, \"STRIPE_TEST_WEBHOOK_ID\", GETPOST(''STRIPE_TEST_WEBHOOK_ID'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "stripe/admin/stripe.php:279|check|if (getDolGlobalString(''STRIPE_TEST_WEBHOOK_KEY'') && getDolGlobalString(''STRIPE_TEST_SECRET_KEY'') && getDolGlobalString(''STRIPE_TEST_WEBHOOK_ID'')) {", "stripe/admin/stripe.php:283|read|$endpoint = \\Stripe\\WebhookEndpoint::retrieve(getDolGlobalString(''STRIPE_TEST_WEBHOOK_ID''));", "stripe/admin/stripe.php:285|check|if (GETPOST(''webhook'', ''alpha'') == getDolGlobalString(''STRIPE_TEST_WEBHOOK_ID'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_TEST_WEBHOOK_KEY', 'string', NULL, 'stripe', 'Stores the Stripe test-mode webhook signing secret used to verify incoming webhook request signatures.', 'Configured via stripe/admin/stripe.php:94 and used in public/stripe/ipn.php:80 as the endpoint_secret for signature verification. Also checked at stripe/admin/stripe.php:279 alongside STRIPE_TEST_SECRET_KEY and STRIPE_TEST_WEBHOOK_ID.', 'Changing or clearing this value breaks webhook signature validation for test-mode Stripe events, causing all test webhook events to fail verification.', 'String Stripe webhook signing secret for test mode (e.g., ''whsec_...'')', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:94|write|$result = dolibarr_set_const($db, \"STRIPE_TEST_WEBHOOK_KEY\", GETPOST(''STRIPE_TEST_WEBHOOK_KEY'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "public/stripe/ipn.php:80|read|$endpoint_secret = getDolGlobalString(''STRIPE_TEST_WEBHOOK_KEY'');", "stripe/admin/stripe.php:279|check|if (getDolGlobalString(''STRIPE_TEST_WEBHOOK_KEY'') && getDolGlobalString(''STRIPE_TEST_SECRET_KEY'') && getDolGlobalString(''STRIPE_TEST_WEBHOOK_ID'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_USER_ACCOUNT_FOR_ACTIONS', 'string', NULL, 'stripe', 'Specifies the Dolibarr user account ID used as the actor when Stripe webhook events create records.', 'Configured via stripe/admin/stripe.php:123. Checked and used in public/stripe/ipn.php:98 and :101 where the user is fetched to perform webhook-triggered actions.', 'Setting this ensures webhook-generated records are attributed to a specific Dolibarr user; if not set, no user is fetched and actions run without a user context.', 'Integer ID of a Dolibarr user account', 0, 0, 'stripe/admin/stripe.php|stripe/admin/stripe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["stripe/admin/stripe.php:123|write|$result = dolibarr_set_const($db, \"STRIPE_USER_ACCOUNT_FOR_ACTIONS\", GETPOSTINT(''STRIPE_USER_ACCOUNT_FOR_ACTIONS''), ''chaine'', 0, '''', $conf->entity);", "public/stripe/ipn.php:98|check|if (getDolGlobalString(''STRIPE_USER_ACCOUNT_FOR_ACTIONS'')) {", "public/stripe/ipn.php:101|read|$user->fetch(getDolGlobalInt(''STRIPE_USER_ACCOUNT_FOR_ACTIONS''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_USE_IDEMPOTENCY_BY_DEFAULT', 'bool', NULL, 'public', 'When enabled, adds an idempotency key to Stripe payment requests by default, requiring a unique tag/ref per payment.', 'Read at public/payment/newpayment.php:2479 and :2672 to determine whether to set noidempotency_key=0. The comments at :2478 and :2671 state: ''If STRIPE_USE_IDEMPOTENCY_BY_DEFAULT is set or param noidempotency=0 is added, then with add an idempotent key, so we must use a different tag/ref for each payment (if not we will get an error)''.', 'When enabled, each Stripe payment must use a unique tag/ref; reusing the same ref with idempotency enabled will result in an error.', '0 or unset = no idempotency key by default; non-zero = idempotency key used by default (requires unique tag/ref per payment)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/payment/newpayment.php:2478  // If STRIPE_USE_IDEMPOTENCY_BY_DEFAULT is set or param noidempotency=0 is added, then with add an idempotent key, so we must use a different tag/ref for each payment (if not we will get an error).", "public/payment/newpayment.php:2479|read|$noidempotency_key = (GETPOSTISSET(''noidempotency'') ? GETPOSTINT(''noidempotency'') : (getDolGlobalInt(''STRIPE_USE_IDEMPOTENCY_BY_DEFAULT'') ? 0 : 1));", "public/payment/newpayment.php:2671  // If STRIPE_USE_IDEMPOTENCY_BY_DEFAULT is set or param noidempotency=0 is added, then with add an idempotent key, so we must use a different tag/ref for each payment (if not we will get an error)."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION', 'bool', NULL, 'public', 'Selects the Stripe payment API flow: PaymentIntent with automatic confirmation, and optionally enables SEPA/alternative payment methods.', 'Documented in public/payment/newpayment.php:30: ''When option STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION is on, we use the new PaymentIntent API''. Values 1 and 2 are defined in newpayment.php:2684-2685: 1 = use intent object (suggest card payment mode only), 2 = use payment object (suggest both card and SEPA). 24 occurrences across stripe and payment files.', 'Setting to 1 uses the PaymentIntent API (card only); setting to 2 uses the payment object API enabling SEPA and other payment methods; unset uses the legacy flow.', '0 or unset = legacy Stripe flow; 1 = PaymentIntent API (card only); 2 = payment object API (card + SEPA etc.)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/payment/newpayment.php:30  * - When option STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION is on, we use the new PaymentIntent API", "public/payment/newpayment.php:2684|write|// $conf->global->STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION = 1 = use intent object (default value, suggest card payment mode only)", "public/payment/newpayment.php:2685|write|// $conf->global->STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION = 2 = use payment object (suggest both card payment mode but also sepa, ...)", "stripe/class/stripe.class.php:370  * Note: This is used when option STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION is on when making a payment from the public/payment/newpayment.php page"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('STRIPE_USE_NEW_CHECKOUT', 'bool', NULL, 'public', 'Enables the new Stripe Checkout API for payment processing instead of the older payment intent flow.', 'Multiple comments confirm the semantics: ''When option STRIPE_USE_NEW_CHECKOUT is on, we use the new checkout API'' (public/payment/newpayment.php:31) and ''but not when using the STRIPE_USE_NEW_CHECKOUT'' (stripe/class/stripe.class.php:371, 723). Also activates SCA-ready checkout when combined with amount checks (newpayment.php:2651).', 'Enabling this constant switches Stripe payments to the Checkout session flow. Disabling uses the Payment Intent with automatic confirmation flow instead.', 'Empty/unset = Payment Intent flow; non-empty = new Stripe Checkout API flow', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["public/payment/newpayment.php:31  * - When option STRIPE_USE_NEW_CHECKOUT is on, we use the new checkout API", "stripe/class/stripe.class.php:371  * but not when using the STRIPE_USE_NEW_CHECKOUT.", "public/payment/newpayment.php:2651|check|if ($checkamount && (getDolGlobalString(''STRIPE_USE_INTENT_WITH_AUTOMATIC_CONFIRMATION'') || getDolGlobalString(''STRIPE_USE_NEW_CHECKOUT''))) {", "public/payment/newpayment.php:2748|check|if (getDolGlobalString(''STRIPE_USE_NEW_CHECKOUT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUBTOTAL_', 'string', NULL, 'compta', 'Family of constants controlling subtotal feature activation and depth limits per document type (e.g., SUBTOTAL_FACTURE, SUBTOTAL_FACTURE_MAX_DEPTH).', 'The suffixed form SUBTOTAL_{ELEMENT} enables subtotal features for a given document type, and SUBTOTAL_{ELEMENT}_MAX_DEPTH controls nesting depth, defaulting to 2 per subtotals/class/commonsubtotal.class.php:840. Managed via admin/subtotals.php. Checked across compta/facture/card.php, comm/propal/card.php, and commande/card.php.', 'Enabling a SUBTOTAL_{ELEMENT} constant activates subtotal line support for that document type; the MAX_DEPTH variant controls how many nesting levels are rendered.', 'Integer (SUBTOTAL_{ELEMENT}): non-zero = subtotal feature enabled for element; SUBTOTAL_{ELEMENT}_MAX_DEPTH: integer depth limit, defaults to 2.', 0, 0, 'admin/subtotals.php|admin/subtotals.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/subtotals.php:96|read|$const_depth = getDolGlobalString(''SUBTOTAL_'' . $const . ''_MAX_DEPTH'');", "compta/facture/card.php:6646|read|&& (getDolGlobalInt(''SUBTOTAL_TITLE_''.strtoupper($object->element)) || getDolGlobalInt(''SUBTOTAL_''.strtoupper($object->element)))) {", "subtotals/class/commonsubtotal.class.php:840|read|$max_depth = getDolGlobalString(''SUBTOTAL_''.strtoupper($this->element).''_MAX_DEPTH'', 2);", "admin/subtotals.php:200|read|print ''name=\"SUBTOTAL_'' . $const . ''_MAX_DEPTH\" value=\"'' . getDolGlobalString(''SUBTOTAL_'' . $const . ''_MAX_DEPTH'', $can_modify ? 2 : 0) . ''\">'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUBTOTAL_BACK_COLOR_LEVEL_', 'string', NULL, 'core', 'Stores the background color for subtotal lines at each nesting level (suffix is the level number, e.g., SUBTOTAL_BACK_COLOR_LEVEL_1).', 'Each suffixed variant (SUBTOTAL_BACK_COLOR_LEVEL_1, _2, etc.) holds a color string for its level. Read in admin/subtotals.php:103 for display, and consumed by subtotals/class/commonsubtotal.class.php:805 and PDF modules (pdf_espadon, pdf_eratosthene, pdf_sponge, pdf_cyan) to apply background colors to subtotal rows in generated documents.', 'Changing a color value alters the background color of the corresponding subtotal nesting level in the UI and in generated PDF documents.', 'String: a color value (e.g., hex color code). Each level has its own suffixed constant (SUBTOTAL_BACK_COLOR_LEVEL_1, SUBTOTAL_BACK_COLOR_LEVEL_2, etc.).', 0, 0, 'admin/subtotals.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/subtotals.php:103|read|$colors[''SUBTOTAL_BACK_COLOR_LEVEL_'' . ($i + 1)] = array(''level'' => $i + 1, ''color'' => getDolGlobalString(''SUBTOTAL_BACK_COLOR_LEVEL_'' . ($i + 1), $default));", "subtotals/class/commonsubtotal.class.php:805|read|return getDolGlobalString(''SUBTOTAL_BACK_COLOR_LEVEL_''.abs($level));", "core/modules/expedition/doc/pdf_espadon.modules.php:641|read|$bg_color = colorStringToArray(getDolGlobalString(\"SUBTOTAL_BACK_COLOR_LEVEL_\".abs($object->lines[$i]->qty)));", "core/modules/facture/doc/pdf_sponge.modules.php:820|read|$bg_color = colorStringToArray(getDolGlobalString(\"SUBTOTAL_BACK_COLOR_LEVEL_\".abs($object->lines[$i]->qty)));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUBTOTAL_TITLE_', 'string', NULL, 'compta', 'Per-element flag (e.g. SUBTOTAL_TITLE_PROPAL) that enables subtotal title lines on document line forms for the subtotals module.', 'The constant name is constructed dynamically as `''SUBTOTAL_TITLE_''.strtoupper($object->element)`. Checked across 12 occurrences including supplier_proposal/card.php:2315, fourn/commande/card.php:2856, compta/facture/card.php:6646, and comm/propal/card.php:3546, all requiring `isModEnabled(''subtotals'')` as well.', 'Enabling the element-specific constant activates the subtotal title line feature for that document type when the subtotals module is active.', 'Truthy string (non-empty) = subtotal title lines enabled for this element; empty/not set = feature disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:2315|check|if ($object->status == SupplierProposal::STATUS_DRAFT && isModEnabled(''subtotals'') && getDolGlobalString(''SUBTOTAL_TITLE_''.strtoupper($object->element))) {", "fourn/commande/card.php:2856|check|if ($object->status == CommandeFournisseur::STATUS_DRAFT && isModEnabled(''subtotals'') && getDolGlobalString(''SUBTOTAL_TITLE_''.strtoupper($object->element))) {", "compta/facture/card.php:6646|read|&& (getDolGlobalInt(''SUBTOTAL_TITLE_''.strtoupper($object->element)) || getDolGlobalInt(''SUBTOTAL_''.strtoupper($object->element)))) {", "comm/propal/card.php:3546|read|&& (getDolGlobalInt(''SUBTOTAL_TITLE_''.strtoupper($object->element)) || getDolGlobalInt(''SUBTOTAL_''.strtoupper($object->element)))) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_CREDIT_TULIP_MASK', 'string', NULL, 'core', 'Defines the number mask pattern used by the Tulip module to generate supplier credit note reference numbers.', 'Read in mod_facture_fournisseur_tulip.php at line 113 (displayed in a configuration input) and line 176 (used as $mask for number generation). No admin UI write outside the module configuration form is present.', 'Setting this constant controls the format of auto-generated supplier credit note numbers in the Tulip module. Leaving it unset causes the module to use an empty or default mask.', 'A mask pattern string (e.g. ''{YYYY}{MM}-{0000}''); empty or unset = no mask configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:113|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskcredit\" value=\"''.getDolGlobalString(\"SUPPLIER_CREDIT_TULIP_MASK\").''\">''", "core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:176|read|$mask = getDolGlobalString(\"SUPPLIER_CREDIT_TULIP_MASK\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_DEPOSIT_TULIP_MASK', 'string', NULL, 'core', 'Defines the number mask pattern used by the Tulip module to generate supplier deposit invoice reference numbers.', 'Read in mod_facture_fournisseur_tulip.php at line 125 (displayed in a configuration input) and line 178 (used as $mask for number generation). No admin UI write outside the module configuration form is present.', 'Setting this constant controls the format of auto-generated supplier deposit invoice numbers in the Tulip module. Leaving it unset causes the module to use an empty or default mask.', 'A mask pattern string (e.g. ''{YYYY}{MM}-{0000}''); empty or unset = no mask configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:125|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskdeposit\" value=\"''.getDolGlobalString(\"SUPPLIER_DEPOSIT_TULIP_MASK\").''\">''", "core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:178|read|$mask = getDolGlobalString(\"SUPPLIER_DEPOSIT_TULIP_MASK\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_HIDE_SUPPLIER_OBJECTLINES', 'bool', NULL, 'core', 'Hides supplier price information on object line views for users with supplier read rights.', 'Checked once at core/tpl/objectline_view.tpl.php:299 where the supplier price column is conditionally shown. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant suppresses the display of supplier pricing details on object line items even when the user has ''fournisseur.lire'' permission.', '0 (show supplier info) or 1 (hide supplier info)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/tpl/objectline_view.tpl.php:299|check|if ($user->hasRight(''fournisseur'', ''lire'') && isset($line->fk_fournprice) && $line->fk_fournprice > 0 && !getDolGlobalString(''SUPPLIER_HIDE_SUPPLIER_OBJECTLINES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Sets the directory path(s) where ODT templates for supplier invoice documents are stored.', 'Read in core/modules/supplier_invoice/doc/doc_generic_supplier_invoice_odt.modules.php:133, where the value is split by comma and newline to build a list of template directories. Also read at line 163 to display the configured path. Checked at line 171. No admin UI write is present.', 'Changing this constant redirects the supplier invoice ODT module to scan the specified directory (or directories, comma-separated) for templates. Leaving it unset causes the module to use its default template location.', 'A comma- or newline-separated list of filesystem paths; empty or unset = default path used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_invoice/doc/doc_generic_supplier_invoice_odt.modules.php:133|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''SUPPLIER_INVOICE_ADDON_PDF_ODT_PATH''))));", "core/modules/supplier_invoice/doc/doc_generic_supplier_invoice_odt.modules.php:163|read|$texte .= getDolGlobalString(''SUPPLIER_INVOICE_ADDON_PDF_ODT_PATH'');", "core/modules/supplier_invoice/doc/doc_generic_supplier_invoice_odt.modules.php:171|check|if (getDolGlobalString(''SUPPLIER_INVOICE_ADDON_PDF_ODT_PATH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for supplier invoice documents.', 'Checked in core/class/commonobject.class.php:6395 and core/lib/functions.lib.php:10763. When set, a public download link is generated for invoice_supplier objects.', 'Enabling this constant exposes supplier invoice documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6395|check|if ($this->element == ''invoice_supplier'' && getDolGlobalInt(\"SUPPLIER_INVOICE_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10763|check|if (getDolGlobalString(''SUPPLIER_INVOICE_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''invoice_supplier'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED', 'bool', NULL, 'fourn', 'Allows a supplier credit note to be reused for payment even when it has only been partially refunded.', 'Checked in fourn/facture/card.php at lines 652 and 4314. When enabled, a credit-note type supplier invoice can be selected for reuse during payment even if it still has an outstanding balance.', 'Without this flag, a partially refunded credit note cannot be reused; enabling it relaxes that restriction.', '0 or unset = reuse not allowed on partially refunded credit notes; 1 = allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''SUPPLIER_INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED'') && $object->type == FactureFournisseur::TYPE_CREDIT_NOTE) {", "&& (getDolGlobalString(''SUPPLIER_INVOICE_ALLOW_REUSE_OF_CREDIT_WHEN_PARTIALLY_REFUNDED'') || $object->getSommePaiement() == 0)"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID', 'string', NULL, 'fourn', 'Allows marking a supplier invoice as paid even when the remaining balance equals the full invoice total (i.e., no payment has been recorded).', 'Checked in fourn/facture/card.php at lines 3198, 3202, 4326, 4328, and 4335. The flag unlocks the ''paid'' action and the corresponding UI button when resteapayer equals total_ttc, which would normally be blocked.', 'Without this flag, the paid action requires resteapayer to be zero or negative. Enabling it permits closing an invoice as paid before any payment is entered.', '0 or unset = can only mark paid when fully settled; 1 = can mark paid even with full outstanding balance', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if ($action == ''paid'' && ($resteapayer <= 0 || (getDolGlobalString(''SUPPLIER_INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID'') && $resteapayer == $object->total_ttc))) {", "if ($action == ''paid'' && $resteapayer > 0 && (!getDolGlobalString(''SUPPLIER_INVOICE_CAN_SET_PAID_EVEN_IF_PARTIALLY_PAID'') || $resteapayer != $object->total_ttc)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_ENABLE_NEGATIVE', 'bool', NULL, 'fourn', 'Enables the creation of negative-total supplier invoices (e.g. credit notes shown as negative standard invoices).', 'Read in fourn/facture/card.php at line 4250 as part of a compound condition that controls display of action buttons for invoice types including standard, replacement, deposit, and credit note.', 'When disabled, the UI restricts actions that would result in negative-total supplier invoices. Exact behavior depends on the full condition context visible only at runtime.', '0 or unset = negative invoices not enabled; 1 = negative invoices allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["&& ((($object->type == FactureFournisseur::TYPE_STANDARD || $object->type == FactureFournisseur::TYPE_REPLACEMENT || $object->type == FactureFournisseur::TYPE_DEPOSIT || $object->t"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_INVOICE_ENABLE_NEGATIVE_LINES', 'bool', NULL, 'fourn', 'Allows negative-price lines to be added on supplier invoices.', 'Checked in fourn/facture/card.php at lines 1679-1684. When the flag is absent, adding a line with a negative unit price (HT or TTC, in any currency) is blocked and raises an error.', 'Disabling this constant prevents entry of negative-value lines on supplier invoices. Enabling it permits credit-style lines directly on a supplier invoice.', '0 or unset = negative lines blocked; 1 = negative lines allowed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["&& (((float) $price_ht < 0 && !getDolGlobalString(''SUPPLIER_INVOICE_ENABLE_NEGATIVE_LINES'')) || $price_ht === '''')", "if (((float) $price_ht < 0 || (float) $price_ttc < 0) && !getDolGlobalString(''SUPPLIER_INVOICE_ENABLE_NEGATIVE_LINES'')) {"]', 'high', NULL);
