INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED', 'string', NULL, 'fourn', 'Sets a monetary threshold above which supplier orders require a second-level approval step.', 'Configured via admin/supplier_order.php:174 and checked at fourn/class/fournisseur.commande.class.php:1327 (''if (getDolGlobalString(''SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED'') && $this->total_ht >= getDolGlobalFloat(''SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED''))'') and fourn/commande/card.php:2919. Comments confirm: ''Second approval (if option SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED is set)'' and ''@param int $secondlevel 0=Standard approval, 1=Second level approval (used when option SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED is set)''.', 'When set to a positive amount, any supplier order with a pre-tax total at or above that amount requires a second approval before being fully approved; orders below the threshold follow standard single-level approval.', 'Not set or 0 = standard single-level approval for all orders; positive numeric value = minimum pre-tax total (excl. VAT) that triggers second-level approval.', 0, 0, 'admin/supplier_order.php|admin/supplier_order.php|admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:1288  *  @param\tint\t\t$secondlevel\t0=Standard approval, 1=Second level approval (used when option SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED is set)", "fourn/commande/card.php:2918  // Second approval (if option SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED is set)", "fourn/class/fournisseur.commande.class.php:1327|check|if (getDolGlobalString(''SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED'') && $this->total_ht >= getDolGlobalFloat(''SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED'')) {", "admin/supplier_order.php:174|write|$res2 = dolibarr_set_const($db, \"SUPPLIER_ORDER_3_STEPS_TO_BE_APPROVED\", $doubleapproval, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
