INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for supplier order documents.', 'Checked in core/class/commonobject.class.php:6392 and core/lib/functions.lib.php:10758. When set, a public download link is generated for order_supplier objects.', 'Enabling this constant exposes supplier order documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6392|check|if ($this->element == ''order_supplier'' && getDolGlobalInt(\"SUPPLIER_ORDER_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10758|check|if (getDolGlobalString(''SUPPLIER_ORDER_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''order_supplier'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_ALLOW_NEGATIVE_QTY_FOR_SUPPLIER_ORDER_RETURN', 'bool', NULL, 'reception', 'Permits negative quantities in supplier order dispatch, enabling supplier order returns.', 'Checked in 6 occurrences across reception/dispatch.php, fourn/class/fournisseur.commande.class.php:2393, expedition/dispatch.php, and fourn/commande/dispatch.php. Negative qtymouv or qty is allowed when this constant is set; dispatching negative remainder is also allowed.', 'When enabled, users can enter negative quantities during dispatch to record supplier returns; without it, negative quantities and negative remainders are rejected.', '0 or unset = negative quantities not allowed; non-empty = negative quantities allowed for returns', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/dispatch.php:246|check|if (getDolGlobalString(''SUPPLIER_ORDER_ALLOW_NEGATIVE_QTY_FOR_SUPPLIER_ORDER_RETURN'') && $qtymouv < 0) {", "fourn/class/fournisseur.commande.class.php:2393|check|if (getDolGlobalString(''SUPPLIER_ORDER_ALLOW_NEGATIVE_QTY_FOR_SUPPLIER_ORDER_RETURN'') && $qty < 0) {", "reception/dispatch.php:618|check|if ($remaintodispatch < 0 && !getDolGlobalString(''SUPPLIER_ORDER_ALLOW_NEGATIVE_QTY_FOR_SUPPLIER_ORDER_RETURN'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_AUTOADD_USER_CONTACT', 'string', NULL, 'fourn', 'Automatically adds the current user as a contact on a supplier order upon creation or validation.', 'Checked at fourn/class/fournisseur.commande.class.php:1351: ''if (getDolGlobalString(''SUPPLIER_ORDER_AUTOADD_USER_CONTACT''))''. No admin UI write path is present.', 'When enabled, the user performing the order action is automatically linked as a contact; when disabled, contacts must be added manually.', '0 or not set = no automatic contact added; non-zero = current user automatically added as contact.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:1351|check|if (getDolGlobalString(''SUPPLIER_ORDER_AUTOADD_USER_CONTACT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_CAN_UPDATE_BUYINGPRICE_DURING_RECEIPT', 'string', NULL, 'fourn', 'Allows updating the buying price of a product automatically during supplier order receipt/dispatch.', 'Checked in 12 occurrences in reception/dispatch.php, fourn/commande/dispatch.php (multiple lines), and also at reception/dispatch.php:268 and fourn/commande/dispatch.php:287 where actual price update logic executes when the constant is set.', 'When enabled, the buying price for products is updated during the dispatch/receipt process; without it, prices remain unchanged at receipt time.', '0 or unset = buying price not updated during receipt; non-empty = buying price updated during receipt', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/dispatch.php:834|check|if (getDolGlobalString(''SUPPLIER_ORDER_CAN_UPDATE_BUYINGPRICE_DURING_RECEIPT'')) {", "reception/dispatch.php:268|check|if (!$error && getDolGlobalString(''SUPPLIER_ORDER_CAN_UPDATE_BUYINGPRICE_DURING_RECEIPT'')) {", "fourn/commande/dispatch.php:287|check|if (!$error && getDolGlobalString(''SUPPLIER_ORDER_CAN_UPDATE_BUYINGPRICE_DURING_RECEIPT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_DEFAULT_PAYMENT_MODE_ID', 'string', NULL, 'fourn', 'Sets the default payment mode ID applied to new supplier orders when no payment mode is otherwise specified.', 'Checked and read in fourn/commande/card.php:1958-1959. When mode_reglement_id is empty and this constant is set, the constant value is used as the payment mode ID.', 'Setting this ensures new supplier orders have a predefined payment mode; without it, orders may be created without a payment mode when none is selected.', 'Integer ID of a payment mode; empty = no default applied', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:1958|check|if (empty($mode_reglement_id) && getDolGlobalString(''SUPPLIER_ORDER_DEFAULT_PAYMENT_MODE_ID'')) {", "fourn/commande/card.php:1959|read|$mode_reglement_id = getDolGlobalString(''SUPPLIER_ORDER_DEFAULT_PAYMENT_MODE_ID'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_DEFAULT_PAYMENT_TERM_ID', 'string', NULL, 'fourn', 'Sets the default payment term ID applied to new supplier orders when no payment term is otherwise specified.', 'Checked and read in fourn/commande/card.php:1955-1956. When cond_reglement_id is empty and this constant is set, the constant value is used as the payment term ID.', 'Setting this ensures new supplier orders have a predefined payment term; without it, orders may be created without a payment term when none is selected.', 'Integer ID of a payment term; empty = no default applied', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:1955|check|if (empty($cond_reglement_id) && getDolGlobalString(''SUPPLIER_ORDER_DEFAULT_PAYMENT_TERM_ID'')) {", "fourn/commande/card.php:1956|read|$cond_reglement_id = getDolGlobalString(''SUPPLIER_ORDER_DEFAULT_PAYMENT_TERM_ID'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_DISABLE_CLASSIFY_BILLED_FROM_SUPPLIER_ORDER', 'bool', NULL, 'fourn', 'Disables the ''classify as billed'' button on supplier orders that have no linked supplier invoices.', 'Only one occurrence in fourn/commande/card.php:3040. The button is shown when linkedObjectsIds[''invoice_supplier''] is non-empty OR when it is empty and this constant is NOT set.', 'Enabling this hides the classify-as-billed action when no supplier invoice is linked to the order, preventing premature billing classification.', 'Empty/0 = classify-as-billed available even without linked invoice; truthy = classify-as-billed hidden when no invoice linked', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:3040|check|if (!empty($object->linkedObjectsIds[''invoice_supplier'']) || (empty($object->linkedObjectsIds[''invoice_supplier'']) && !getDolGlobalInt(''SUPPLIER_ORDER_DISABLE_CLASSIFY_BILLED_FROM_"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED', 'bool', NULL, 'reception', 'Hides dispatch input rows for lines where the ordered quantity has already been fully received.', 'Documented in fourn/commande/dispatch.php:743-744: ''Nb of predefined product lines to dispatch (already done or not) if SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED is off (default) or nb of line that remain to dispatch if SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED is on.'' Also in reception/dispatch.php:604 and expedition/dispatch.php:568. 6 occurrences.', 'When enabled, only lines with remaining quantity to dispatch are shown, hiding fully-received lines; when disabled (default), all lines are shown.', '0 or unset = all lines shown (default); non-empty = only lines with remaining quantity shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/dispatch.php:743  // Nb of predefined product lines to dispatch (already done or not) if SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED is off (default)", "fourn/commande/dispatch.php:744  // or nb of line that remain to dispatch if SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED is on.", "reception/dispatch.php:604  // or nb of line that remain to dispatch if SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED is on.", "reception/dispatch.php:622|check|if ($remaintodispatch || !getDolGlobalString(''SUPPLIER_ORDER_DISABLE_STOCK_DISPATCH_WHEN_TOTAL_REACHED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_DISPATCH_FORCE_QTY_INPUT_TO_ZERO', 'string', NULL, 'reception', 'Forces the default quantity input to zero in supplier order dispatch forms instead of pre-filling the remaining quantity.', 'Checked in 3 occurrences in expedition/dispatch.php:1232, reception/dispatch.php:994, and fourn/commande/dispatch.php:1018. When set, the default value for qty inputs is 0; when unset, inputs are pre-filled with $remaintodispatch.', 'When enabled, operators must manually enter all quantities during dispatch (inputs default to 0); when disabled, inputs are pre-filled with the remaining quantity to dispatch.', '0 or unset = qty inputs pre-filled with remaining quantity; non-empty = qty inputs default to 0', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["expedition/dispatch.php:1232|read|$amounttosuggest = (GETPOSTISSET(''qty''.$suffix) ? GETPOSTINT(''qty''.$suffix) : (!getDolGlobalString(''SUPPLIER_ORDER_DISPATCH_FORCE_QTY_INPUT_TO_ZERO'') ? $remaintodispatch : 0));", "reception/dispatch.php:994|read|print ''<input id=\"qty''.$suffix.''\" onchange=\"onChangeDispatchLineQty($(this))\" name=\"qty''.$suffix.''\" data-index=\"''.$i.''\" data-type=\"text\" class=\"width50 right qtydispatchinput\" valu", "fourn/commande/dispatch.php:1018|read|print ''<input id=\"qty''.$suffix.''\" name=\"qty''.$suffix.''\" type=\"number\" step=\"any\" class=\"width50 right qtydispatchinput\" value=\"''.(GETPOSTISSET(''qty''.$suffix) ? GETPOSTINT(''qty''.$su"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_EDIT_BUYINGPRICE_DURING_RECEIPT', 'string', NULL, 'reception', 'Enables an editable buying price field during the supplier order receipt/dispatch process.', 'Checked in 6 occurrences exclusively in reception/dispatch.php and fourn/commande/dispatch.php. All occurrences include the developer note ''// Not tested !'' indicating this feature is not fully verified in code.', 'When enabled, a buying price input field is shown during dispatch so operators can edit the buying price at receipt time; the feature is marked ''Not tested'' in the source code.', '0 or unset = buying price not editable during receipt; non-empty = buying price editable during receipt', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/dispatch.php:751|check|if (getDolGlobalString(''SUPPLIER_ORDER_EDIT_BUYINGPRICE_DURING_RECEIPT'')) { // Not tested !", "reception/dispatch.php:810|check|if (getDolGlobalString(''SUPPLIER_ORDER_EDIT_BUYINGPRICE_DURING_RECEIPT'')) { // Not tested !", "fourn/commande/dispatch.php:940|check|if (getDolGlobalString(''SUPPLIER_ORDER_EDIT_BUYINGPRICE_DURING_RECEIPT'')) { // Not tested !"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_FORBID_EDIT_PROJECT', 'string', NULL, 'fourn', 'Prevents editing of the project field on supplier orders except when the order is in draft status with a provisional reference.', 'Only one occurrence in fourn/commande/card.php:189. When set, caneditproject is false unless the order is in draft status and the reference matches a provisional pattern.', 'Enabling this locks the project association on supplier orders once they leave draft status.', 'Empty/0 = project editable regardless of status; truthy = project editable only on draft orders with provisional references', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:189|read|$caneditproject = !getDolGlobalString(''SUPPLIER_ORDER_FORBID_EDIT_PROJECT'') || ($object->status == CommandeFournisseur::STATUS_DRAFT && preg_match(''/^[\\(]?PROV/i'', $object->ref));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to Supplier Order documents.', 'Set via the admin UI at admin/supplier_order.php. The $freetext variable is saved as a string constant for the current entity.', 'Changing this value updates the free-text block printed on Supplier Order documents for the entity.', 'Free string (arbitrary text).', 0, 0, 'admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/supplier_order.php:173|write|$res1 = dolibarr_set_const($db, \"SUPPLIER_ORDER_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_HIDE_VALIDATED', 'bool', NULL, 'core', 'Hides the validated supplier orders menu entry when set, removing it from the navigation.', 'Checked in core/menus/standard/eldy.lib.php:1469 with a negation: the menu item only renders when the constant is absent or empty. No admin UI write detected.', 'Setting this constant removes the validated supplier orders link from the menu. Unsetting it restores the link.', 'Non-empty = hide menu item; absent/empty = show menu item.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/eldy.lib.php:1469|check|if (!getDolGlobalString(''SUPPLIER_ORDER_HIDE_VALIDATED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_MODE_OPTIONAL', 'string', NULL, 'fourn', 'Makes the order method (mode de commande) field optional rather than required on supplier orders.', 'Only one occurrence in fourn/commande/card.php:1300. When not set (falsy), the system blocks progression if methodecommande <= 0; when set, this block is skipped.', 'Enabling this allows supplier orders to be submitted without selecting an order method; disabling it enforces method selection.', 'Empty/0 = order method required; truthy = order method optional', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:1300|read|} elseif ($methodecommande <= 0 && !getDolGlobalInt(''SUPPLIER_ORDER_MODE_OPTIONAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_MORE_THAN_WISHED', 'string', NULL, 'reception', 'Allows receiving a quantity greater than the ordered quantity on supplier orders.', 'Read in 2 locations: reception/class/reception.class.php:920 (`} elseif (getDolGlobalInt(''SUPPLIER_ORDER_MORE_THAN_WISHED'')) {`) and fourn/class/fournisseur.commande.class.php:3818 (`} elseif (getDolGlobalString(''SUPPLIER_ORDER_MORE_THAN_WISHED'')) {`).', 'Enabling this setting allows dispatching more units than were ordered on a supplier order line.', 'Truthy string or non-zero integer = over-reception allowed; empty/0 = quantity capped at ordered amount.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["reception/class/reception.class.php:920|read|} elseif (getDolGlobalInt(''SUPPLIER_ORDER_MORE_THAN_WISHED'')) {", "fourn/class/fournisseur.commande.class.php:3818|read|} elseif (getDolGlobalString(''SUPPLIER_ORDER_MORE_THAN_WISHED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_NOCHECK_ONBUY_PRODUCTS_ONVALID', 'string', NULL, 'fourn', 'Disables the check for active ''on-buy'' products when validating a supplier order.', 'Checked at fourn/class/fournisseur.commande.class.php:807: ''if (!getDolGlobalBool(''SUPPLIER_ORDER_NOCHECK_ONBUY_PRODUCTS_ONVALID'') && !$this->checkActiveProductInLines(''onbuy''))''. No admin UI write path is present.', 'When enabled, validation of supplier orders skips the check that verifies all ordered products are active for purchasing; when disabled, that check is enforced.', '0 or not set = active product check enforced on validation; non-zero = active product check skipped.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:807|check|if (!getDolGlobalBool(''SUPPLIER_ORDER_NOCHECK_ONBUY_PRODUCTS_ONVALID'') && !$this->checkActiveProductInLines(''onbuy'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_NO_DIRECT_APPROVE', 'string', NULL, 'fourn', 'Disables the direct approval button on supplier orders, requiring a separate approval workflow step.', 'Checked across 4 occurrences in fourn/commande/card.php:1215, :2883 and fourn/commande/list.php:378, :1291. When set, the direct approve action is hidden from both the order card and the list view.', 'Enabling this forces approvers to go through a dedicated approval step rather than using a single-click approval on the order.', 'Empty/0 = direct approval button visible; truthy = direct approval button hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:1215|check|if (!$error && !getDolGlobalString(''SUPPLIER_ORDER_NO_DIRECT_APPROVE'') && $usercanapprove && ...) {", "fourn/commande/card.php:2883|check|if ($usercanapprove && !getDolGlobalString(''SUPPLIER_ORDER_NO_DIRECT_APPROVE'')) {", "fourn/commande/list.php:378|check|if (!getDolGlobalString(''SUPPLIER_ORDER_NO_DIRECT_APPROVE'') && $permissiontoapprove && ...) {", "fourn/commande/list.php:1291|check|if ($permissiontoapprove && !getDolGlobalString(''SUPPLIER_ORDER_NO_DIRECT_APPROVE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_REOPEN_BY_APPROVER2_ONLY', 'string', NULL, 'fourn', 'Restricts the ability to reopen a supplier order to the second approver only.', 'Checked in fourn/commande/card.php:2962-2963. Without this constant, any authorized user can reopen; when set, only the user whose ID matches user_approve_id2 can reopen.', 'Enabling this prevents users other than the second approver from reopening a supplier order.', 'Empty/0 = any authorized user can reopen; truthy = only second approver (user_approve_id2) can reopen', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2962|check|if (!getDolGlobalString(''SUPPLIER_ORDER_REOPEN_BY_APPROVER2_ONLY'')", "fourn/commande/card.php:2963|read||| (getDolGlobalString(''SUPPLIER_ORDER_REOPEN_BY_APPROVER2_ONLY'') && $user->id == $object->user_approve_id2)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_REOPEN_BY_APPROVER_ONLY', 'string', NULL, 'fourn', 'Restricts the ability to reopen a supplier order to the first approver only.', 'Checked in fourn/commande/card.php:2955-2956. Without this constant, any authorized user can reopen; when set, only the user whose ID matches user_approve_id can reopen.', 'Enabling this prevents users other than the original first approver from reopening a supplier order.', 'Empty/0 = any authorized user can reopen; truthy = only first approver (user_approve_id) can reopen', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2955|check|if (!getDolGlobalString(''SUPPLIER_ORDER_REOPEN_BY_APPROVER_ONLY'')", "fourn/commande/card.php:2956|read||| (getDolGlobalString(''SUPPLIER_ORDER_REOPEN_BY_APPROVER_ONLY'') && $user->id == $object->user_approve_id)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_SENDBYEMAIL_FOR_ALL_STATUS', 'string', NULL, 'fourn', 'Allows the ''send by email'' action to appear on supplier orders regardless of their status.', 'Only one occurrence in fourn/commande/card.php:2944. Without this constant, the email action is limited to orders with status ACCEPTED (2), 3, 4, or 5; when set, the action is always shown.', 'Enabling this makes the send-by-email button available on supplier orders in any status, not just accepted or later statuses.', 'Empty/0 = email action limited to accepted/dispatched statuses; truthy = email action available on all statuses', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2944|check|if (in_array($object->status, array(CommandeFournisseur::STATUS_ACCEPTED, 3, 4, 5)) || getDolGlobalString(''SUPPLIER_ORDER_SENDBYEMAIL_FOR_ALL_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_STATUS_FOR_VIRTUAL_STOCK', 'string', NULL, 'product', 'Defines which supplier order statuses are included in virtual stock calculations.', 'Read in product/class/product.class.php:6431 as $filterStatus with a default of ''3,4''. Only one occurrence; no admin UI.', 'Changing this value alters which supplier order statuses count toward the virtual stock figure.', 'Comma-separated status integers; default ''3,4''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/class/product.class.php:6431|read|$filterStatus = getDolGlobalString(''SUPPLIER_ORDER_STATUS_FOR_VIRTUAL_STOCK'', ''3,4'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_TO_INVOICE_STATUS', 'string', NULL, 'fourn', 'Restricts which supplier order statuses are eligible when creating a supplier invoice from an order.', 'When set, fourn/card.php:774 appends a SQL filter requiring the order status to be in the comma-separated list provided by this constant. Without it, fourn/card.php:770 applies no status filter.', 'Setting this constant limits invoice creation to orders in the specified statuses; removing it allows invoicing from orders in any status.', 'Comma-separated list of integer status codes (e.g. ''3,4''). Empty or unset means no status restriction.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/card.php:770|check|if (!getDolGlobalString(''SUPPLIER_ORDER_TO_INVOICE_STATUS'')) {", "fourn/card.php:774|read|$sql2 .= \" AND c.fk_statut IN (\".$db->sanitize(getDolGlobalString(''SUPPLIER_ORDER_TO_INVOICE_STATUS'')).\")\";;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_USE_DISPATCH_STATUS', 'bool', NULL, 'fourn', 'Enables a dispatch approval status workflow for supplier orders, requiring all receptions to be approved before the order can be marked as fully received.', 'Shown as a select array in admin/supplier_order.php:528. COMMENT from fourn/class/fournisseur.commande.class.php:2719: `// If option SUPPLIER_ORDER_USE_DISPATCH_STATUS is on, we check all reception are approved to allow status "total/done"`. Checked across 8 occurrences including fourn/commande/dispatch.php (lines 1244, 1364) and reception/class/reception.class.php:882.', 'Enabling this setting adds an approval step to receptions and blocks the supplier order from reaching ''done'' status until all dispatches are approved.', '0 or empty = no dispatch approval required; 1 = dispatch approval workflow enabled.', 0, 0, 'admin/supplier_order.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:2719  // If option SUPPLIER_ORDER_USE_DISPATCH_STATUS is on, we check all reception are approved to allow status \"total/done\"", "fourn/commande/dispatch.php:1244|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_DISPATCH_STATUS'') && !isModEnabled(\"reception\")) {", "fourn/class/fournisseur.commande.class.php:2718|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_DISPATCH_STATUS'')) {", "reception/class/reception.class.php:882|check|if (getDolGlobalInt(''SUPPLIER_ORDER_USE_DISPATCH_STATUS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_USE_DISPATCH_STATUS_NEED_APPROVE', 'bool', NULL, 'fourn', 'Requires approval of dispatch status before a supplier order reception can be marked as done.', 'Checked at fourn/class/fournisseur.commande.class.php:2729: ''if (!$error && getDolGlobalString(''SUPPLIER_ORDER_USE_DISPATCH_STATUS_NEED_APPROVE'') && ($type == ''tot'')) { // Accept to move to reception done, only if status of all line are ok''. No admin UI write path is present.', 'When enabled, moving a supplier order reception to ''done'' (type=''tot'') is blocked unless all dispatch line statuses are approved; when disabled, no such check is enforced.', '0 or not set = no dispatch status approval required; non-zero = all dispatch lines must be approved before reception can be closed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:2729|check|if (!$error && getDolGlobalString(''SUPPLIER_ORDER_USE_DISPATCH_STATUS_NEED_APPROVE'') && ($type == ''tot'')) {\t// Accept to move to reception done, only if status of all line are ok ("]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_USE_HOUR_FOR_DELIVERY_DATE', 'bool', NULL, 'fourn', 'Enables time (hour) input in addition to date for the supplier order delivery date field.', 'Checked across 7 occurrences in fourn/commande/card.php:2059, :2494, :2615, :2623 and PDF modules core/modules/supplier_order/doc/pdf_cornas.modules.php:1366, pdf_muscadet.modules.php:1233, and core/modules/mrp/doc/pdf_vinci.modules.php:1142.', 'Enabling this adds an hour picker to the delivery date field on supplier orders and includes the time in generated PDF documents.', 'Empty/0 = date only for delivery date; truthy = date and time for delivery date', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2059|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_HOUR_FOR_DELIVERY_DATE'')) {", "fourn/commande/card.php:2494|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_HOUR_FOR_DELIVERY_DATE'')) {", "core/modules/supplier_order/doc/pdf_cornas.modules.php:1366|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_HOUR_FOR_DELIVERY_DATE'')) {", "core/modules/mrp/doc/pdf_vinci.modules.php:1142|check|if (getDolGlobalString(''SUPPLIER_ORDER_USE_HOUR_FOR_DELIVERY_DATE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_ORDER_WITH_PREDEFINED_PRICES_ONLY', 'string', NULL, 'fourn', 'Restricts supplier orders to use only products with predefined supplier prices.', 'Checked at fourn/class/fournisseur.commande.class.php:2105 and fourn/commande/card.php:999 with comment ''// Not the common case''. Also read at fourn/commande/card.php:2809: ''$senderissupplier = getDolGlobalInt(''SUPPLIER_ORDER_WITH_PREDEFINED_PRICES_ONLY'')''. No admin UI write path is present.', 'When set to 1, only products with pre-configured supplier prices can be added to supplier orders; when not set or 0, any product can be added.', '0 or not set = any product can be added (common case); 1 = only products with predefined supplier prices allowed (not the common case).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/fournisseur.commande.class.php:2105|check|if (getDolGlobalInt(''SUPPLIER_ORDER_WITH_PREDEFINED_PRICES_ONLY'') == 1) {\t// Not the common case", "fourn/commande/card.php:999|check|if (getDolGlobalInt(''SUPPLIER_ORDER_WITH_PREDEFINED_PRICES_ONLY'') == 1) {\t\t// Not the common case", "fourn/commande/card.php:2809|read|$senderissupplier = getDolGlobalInt(''SUPPLIER_ORDER_WITH_PREDEFINED_PRICES_ONLY'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PAYMENT_ADDON', 'string', NULL, 'fourn', 'Specifies the numbering module used to generate supplier payment reference numbers.', 'Checked and defaulted to ''mod_supplier_payment_bronan'' in admin/supplier_payment.php:185-186 and fourn/class/paiementfourn.class.php:790-791. The module class name is read at fourn/class/paiementfourn.class.php:802 and the corresponding file at :818. The comment at fourn/class/paiementfourn.class.php:778 confirms the role.', 'Changing this value switches the numbering module used for new supplier payment references; if unset, the default ''mod_supplier_payment_bronan'' module is used.', 'Name string of the numbering module (e.g. ''mod_supplier_payment_bronan'').', 0, 0, 'admin/supplier_payment.php|admin/supplier_payment.php|admin/supplier_payment.php|admin/supplier_payment.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/class/paiementfourn.class.php:778  *      according to numbering module defined into constant SUPPLIER_PAYMENT_ADDON", "admin/supplier_payment.php:186|write|$conf->global->SUPPLIER_PAYMENT_ADDON = ''mod_supplier_payment_bronan'';", "fourn/class/paiementfourn.class.php:802|read|$classname = getDolGlobalString(''SUPPLIER_PAYMENT_ADDON'');", "fourn/class/paiementfourn.class.php:818|read|$file = getDolGlobalString(''SUPPLIER_PAYMENT_ADDON'') . \".php\";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PAYMENT_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the PDF template module used for generating supplier payment documents.', 'Set via admin/supplier_payment.php:98 and read in fourn/class/paiementfourn.class.php:877 and fourn/paiement/card.php:445 and :418 to determine the default PDF model for supplier payments. Admin UI is available at admin/supplier_payment.php.', 'Changing this value switches the PDF layout used when generating supplier payment documents.', 'Name string of the PDF module (e.g. a module identifier matching an available PDF template).', 0, 0, 'admin/supplier_payment.php|admin/supplier_payment.php|admin/supplier_payment.php|admin/supplier_payment.php|admin/supplier_payment.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/supplier_payment.php:98|write|if (dolibarr_set_const($db, \"SUPPLIER_PAYMENT_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "fourn/paiement/card.php:445|read|$defaultpdfmodel = getDolGlobalString(''SUPPLIER_PAYMENT_ADDON_PDF'');", "fourn/paiement/card.php:418|check|$modelpdf = (!empty($object->model_pdf) ? $object->model_pdf : getDolGlobalString(''SUPPLIER_PAYMENT_ADDON_PDF''));", "fourn/class/paiementfourn.class.php:877|check|if (getDolGlobalString(''SUPPLIER_PAYMENT_ADDON_PDF'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PAYMENT_BRODATOR_MASK', 'string', NULL, 'core', 'Defines the numbering mask used for supplier payments in the Brodator numbering module.', 'Read in core/modules/supplier_payment/mod_supplier_payment_brodator.php at line 140 to retrieve the mask, and at line 94 where it is shown as an editable text input in the module configuration UI.', 'If unset, supplier payment numbering in the Brodator module has no configured mask, which may cause errors or fallback behavior during number generation.', 'A mask pattern string compatible with the Brodator supplier payment numbering module; no explicit enumeration in code.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_payment/mod_supplier_payment_brodator.php:140|read|$mask = getDolGlobalString(\"SUPPLIER_PAYMENT_BRODATOR_MASK\");", "core/modules/supplier_payment/mod_supplier_payment_brodator.php:94|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"masksupplierpayment\" value=\"''.getDolGlobalString(\"SUPPLIER_PAYMENT_BRODATOR_M"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON', 'string', NULL, 'supplier_proposal', 'Specifies the numbering module class name used to generate supplier proposal reference numbers.', 'Configured via admin/supplier_proposal.php:194. Read in supplier_proposal/class/supplier_proposal.class.php at lines 1234, 1235, 2540 to load and instantiate the module class. A docblock comment at line 2526 states: ''defined into SUPPLIER_PROPOSAL_ADDON''.', 'Changing this value switches the supplier proposal numbering module; the named PHP class file must exist under core/modules/supplier_proposal/.', 'String class name of the numbering addon (e.g. ''mod_supplier_proposal_marbre'')', 0, 0, 'admin/supplier_proposal.php|admin/supplier_proposal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:2526  *  defined into SUPPLIER_PROPOSAL_ADDON", "admin/supplier_proposal.php:194|write|dolibarr_set_const($db, \"SUPPLIER_PROPOSAL_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "supplier_proposal/class/supplier_proposal.class.php:1234|read|require_once DOL_DOCUMENT_ROOT.\"/core/modules/supplier_proposal/\" . getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON'').''.php'';", "supplier_proposal/class/supplier_proposal.class.php:1235|read|$obj = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON_PDF', 'string', NULL, 'admin', 'Specifies the default PDF model name used to generate supplier proposal documents.', 'Configured via admin/supplier_proposal.php (written at line 183, deleted at line 179, checked at lines 178 and 450). Read in supplier_proposal/class/supplier_proposal.class.php:2827–2828 and used as fallback default in supplier_proposal/card.php:1653.', 'Changing this value switches the default PDF template for supplier proposal document generation.', 'String PDF model name; empty = no default model set', 0, 0, 'admin/supplier_proposal.php|admin/supplier_proposal.php|admin/supplier_proposal.php|admin/supplier_proposal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/supplier_proposal.php:183|write|dolibarr_set_const($db, \"SUPPLIER_PROPOSAL_ADDON_PDF\", empty($value) ? '''' : $value, ''chaine'', 0, '''', $conf->entity);", "supplier_proposal/class/supplier_proposal.class.php:2827|read|} elseif (getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF'')) {", "supplier_proposal/class/supplier_proposal.class.php:2828|read|$modele = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF'');", "supplier_proposal/card.php:1653|read|$preselected = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_DEFAULT'', getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON_PDF_ODT_CLOSED', 'string', NULL, 'supplier_proposal', 'Specifies the ODT document model used for supplier proposals in the ''closed'' status.', 'Read in supplier_proposal/class/supplier_proposal.class.php:1806 with fallback to model_pdf, and in core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:205 where it populates a select array.', 'Setting this value selects the ODT template applied to supplier proposals that are in closed status.', 'String ODT model name for closed supplier proposals; empty = use default model_pdf', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:1806|read|$modelpdf = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_CLOSED'', (empty($this->model_pdf) ? '''' : $this->model_pdf));", "core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:205|read|$texte .= $form->selectarray(''value4'', $list, getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_CLOSED''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON_PDF_ODT_DEFAULT', 'string', NULL, 'supplier_proposal', 'Specifies the default ODT document template module for supplier proposals.', 'Read in supplier_proposal/card.php:1653 with fallback to `SUPPLIER_PROPOSAL_ADDON_PDF`, and in core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:193 to pre-select the value in the template list.', 'Setting this value pre-selects a specific ODT template module for supplier proposal document generation.', 'String (module name, e.g. ''doc_generic_supplier_proposal_odt''); empty means the value of SUPPLIER_PROPOSAL_ADDON_PDF is used as fallback.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1653|read|$preselected = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_DEFAULT'', getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF''));", "core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:193|read|$texte .= $form->selectarray(''value2'', $list, getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_DEFAULT''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the filesystem path to a custom ODT template file used when generating supplier proposal PDFs.', 'Read at core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:115 and trimmed before use. No admin UI; hidden setting.', 'Setting a valid path enables generation of supplier proposal PDFs from a custom ODT template; leaving empty disables ODT template use.', 'Empty = no custom ODT path; string = filesystem path to the ODT template file', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:115|read|$odtPath = trim(getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADDON_PDF_ODT_TOBILL', 'string', NULL, 'supplier_proposal', 'Specifies the ODT document model used for supplier proposals in the ''to bill'' status.', 'Read in supplier_proposal/class/supplier_proposal.class.php:1811 with fallback to model_pdf, and in core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:199 where it populates a select array.', 'Setting this value selects the ODT template applied to supplier proposals that are in to-bill status.', 'String ODT model name for to-bill supplier proposals; empty = use default model_pdf', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:1811|read|$modelpdf = getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_TOBILL'', (empty($this->model_pdf) ? '''' : $this->model_pdf));", "core/modules/supplier_proposal/doc/doc_generic_supplier_proposal_odt.modules.php:199|read|$texte .= $form->selectarray(''value3'', $list, getDolGlobalString(''SUPPLIER_PROPOSAL_ADDON_PDF_ODT_TOBILL''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ADD_BILLING_CONTACT', 'string', NULL, 'core', 'Controls whether a billing contact is added to supplier proposal PDFs.', 'Displayed as a select array in admin/pdf_other.php at line 627. Checked (negated) in pdf_zenith.modules.php at line 1431 and pdf_aurore.modules.php at line 1372; when falsy, a billing contact is included.', 'Setting this constant to a non-zero value suppresses the billing contact section in supplier proposal PDFs. Leaving it unset or zero includes the billing contact.', '0 or unset = include billing contact; non-zero = suppress billing contact.', 0, 0, 'admin/pdf_other.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/pdf_other.php:627|read|print $form->selectarray(\"SUPPLIER_PROPOSAL_ADD_BILLING_CONTACT\", $arrval, getDolGlobalInt(''SUPPLIER_PROPOSAL_ADD_BILLING_CONTACT''));", "core/modules/supplier_proposal/doc/pdf_zenith.modules.php:1431|check|if (!getDolGlobalInt(''SUPPLIER_PROPOSAL_ADD_BILLING_CONTACT'')) {", "core/modules/supplier_proposal/doc/pdf_aurore.modules.php:1372|check|if (!getDolGlobalInt(''SUPPLIER_PROPOSAL_ADD_BILLING_CONTACT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'core', 'Enables an external download link for supplier proposal documents.', 'Checked in core/class/commonobject.class.php:6389 and core/lib/functions.lib.php:10753. When set, a public download link is generated for supplier_proposal objects.', 'Enabling this constant exposes supplier proposal documents via a public URL; disabling it removes the external download option.', 'Non-zero/non-empty = external download enabled; 0 or unset = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/commonobject.class.php:6389|check|if ($this->element == ''supplier_proposal'' && getDolGlobalInt(\"SUPPLIER_PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD\")) {", "core/lib/functions.lib.php:10753|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_ALLOW_EXTERNAL_DOWNLOAD'') && is_object($object) && $object->element == ''supplier_proposal'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_AUTOADD_USER_CONTACT', 'string', NULL, 'supplier_proposal', 'When enabled, automatically adds the current user as a contact on newly created supplier proposals.', 'Read only in supplier_proposal/class/supplier_proposal.class.php:1585 where contact auto-addition logic is gated on this constant.', 'Enabling this constant causes the creating user to be automatically linked as a contact to each new supplier proposal.', 'Non-empty/truthy = auto-add user contact; empty/unset = do not auto-add (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:1585|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_AUTOADD_USER_CONTACT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_CLONE_ON_CREATE_PAGE', 'string', NULL, 'supplier_proposal', 'Controls whether the supplier proposal creation page shows a clone option instead of the standard creation form.', 'Checked 3 times in supplier_proposal/card.php (lines 1752, 1756, 1795) to toggle between the clone and standard creation page behaviour.', 'Enabling this setting alters the supplier proposal creation workflow to present cloning behaviour.', 'Truthy string (non-empty) = show clone-based creation; empty/not set = show standard creation form.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:1752|check|if (!getDolGlobalString(''SUPPLIER_PROPOSAL_CLONE_ON_CREATE_PAGE'')) {", "supplier_proposal/card.php:1756|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_CLONE_ON_CREATE_PAGE'')) {", "supplier_proposal/card.php:1795|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_CLONE_ON_CREATE_PAGE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_DRAFT_WATERMARK', 'string', NULL, 'admin', 'Sets the watermark text stamped on draft supplier proposal PDF documents.', 'Written via admin/supplier_proposal.php:129; rendered in the PDF at core/modules/supplier_proposal/doc/pdf_aurore.modules.php:191 when the proposal status is draft and this constant is set.', 'Setting this adds a visible watermark text to draft supplier proposal PDFs; removing it omits the watermark.', 'Any string value used as the watermark label on draft PDFs.', 0, 0, 'admin/supplier_proposal.php|admin/supplier_proposal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/supplier_proposal.php:129|write|$res = dolibarr_set_const($db, \"SUPPLIER_PROPOSAL_DRAFT_WATERMARK\", trim($draft), ''chaine'', 0, '''', $conf->entity);", "core/modules/supplier_proposal/doc/pdf_aurore.modules.php:190|check|if ($object->status == $object::STATUS_DRAFT && (getDolGlobalString(''SUPPLIER_PROPOSAL_DRAFT_WATERMARK''))) {", "core/modules/supplier_proposal/doc/pdf_aurore.modules.php:191|read|$this->watermark = getDolGlobalString(''SUPPLIER_PROPOSAL_DRAFT_WATERMARK'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_FREE_TEXT', 'string', NULL, 'admin', 'Stores a free-text footer or note appended to supplier proposal documents.', 'Written in admin/supplier_proposal.php:144 via dolibarr_set_const using $freetext.', 'Changing this value updates the free-text block printed on supplier proposal PDFs.', 'Arbitrary string text.', 0, 0, 'admin/supplier_proposal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"SUPPLIER_PROPOSAL_FREE_TEXT\", $freetext, ''chaine'', 0, '''', $conf->entity);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_NOCHECK_ONBUY_PRODUCTS_ONVALID', 'string', NULL, 'supplier_proposal', 'When enabled, skips the check for ''on-buy'' active products on supplier proposal validation.', 'Read only in supplier_proposal/class/supplier_proposal.class.php:1501 where validation calls checkActiveProductInLines(''onbuy'') only if this constant is falsy.', 'Enabling this constant bypasses the product buyability check during supplier proposal validation.', 'Truthy = skip onbuy product check on validation; falsy/unset = enforce check (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:1501|check|if (!getDolGlobalBool(''SUPPLIER_PROPOSAL_NOCHECK_ONBUY_PRODUCTS_ONVALID'') && !$this->checkActiveProductInLines(''onbuy'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_PDF_HIDE_PAYMENTTERMCOND', 'bool', NULL, 'core', 'Hides the payment terms and conditions block from the supplier proposal PDF when enabled.', 'Checked (negated) at core/modules/supplier_proposal/doc/pdf_aurore.modules.php:786 to decide whether to render the payment terms section. No admin UI; hidden setting.', 'Setting to a truthy value suppresses the payment conditions section from supplier proposal PDFs. Leaving unset shows payment terms when they are defined.', '0 or empty = payment terms shown in PDF; 1 = payment terms hidden in PDF', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/doc/pdf_aurore.modules.php:786|check|if (!getDolGlobalString(''SUPPLIER_PROPOSAL_PDF_HIDE_PAYMENTTERMCOND'') && ($object->cond_reglement_code || $object->cond_reglement)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_PDF_SHOW_PAYMENTTERMMODE', 'bool', NULL, 'core', 'Shows the payment mode section in the supplier proposal PDF when enabled.', 'Checked at core/modules/supplier_proposal/doc/pdf_aurore.modules.php:804 to conditionally render the payment mode block. No admin UI; hidden setting.', 'Enabling this adds a payment mode section to generated supplier proposal PDFs. Leaving unset omits this section.', '0 or empty = payment mode not shown in PDF; non-empty = payment mode shown in PDF', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/doc/pdf_aurore.modules.php:804|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_PDF_SHOW_PAYMENTTERMMODE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_SAPHIR_MASK', 'string', NULL, 'core', 'Defines the numbering mask pattern used by the ''saphir'' module for generating supplier proposal reference numbers.', 'Read at core/modules/supplier_proposal/mod_supplier_proposal_saphir.php:95 and :145 to obtain the mask for reference generation. No admin UI; hidden setting.', 'Changing the mask alters how supplier proposal reference numbers are generated. An empty mask results in an empty reference number from this module.', 'String mask pattern following Dolibarr mask syntax; empty = no mask configured (reference generation returns empty string)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/mod_supplier_proposal_saphir.php:95|read|$mask = getDolGlobalString(''SUPPLIER_PROPOSAL_SAPHIR_MASK'');", "core/modules/supplier_proposal/mod_supplier_proposal_saphir.php:145|read|$mask = !getDolGlobalString(''SUPPLIER_PROPOSAL_SAPHIR_MASK'') ? '''' : $conf->global->SUPPLIER_PROPOSAL_SAPHIR_MASK;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_USE_HOUR_FOR_DELIVERY_DATE', 'bool', NULL, 'core', 'Enables display of the time (hour) component alongside the date for the delivery date on supplier proposal PDFs.', 'When set, core/modules/supplier_proposal/doc/pdf_zenith.modules.php:1338 formats the delivery date with hour precision instead of date-only.', 'Enabling this shows hours in the delivery date field on the PDF; disabling it shows only the date.', 'Any non-empty string value enables hour display for delivery date.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_proposal/doc/pdf_zenith.modules.php:1338|check|if (getDolGlobalString(''SUPPLIER_PROPOSAL_USE_HOUR_FOR_DELIVERY_DATE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_PROPOSAL_WITH_PREDEFINED_PRICES_ONLY', 'string', NULL, 'supplier_proposal', 'When set to 1, restricts supplier proposal lines to products with predefined purchase prices only.', 'Checked in supplier_proposal/class/supplier_proposal.class.php:511 and supplier_proposal/card.php:1272 with the comment ''Not the common case''. Also checked at card.php:2244 and its value read at card.php:2245 into $senderissupplier.', 'Setting this to 1 limits supplier proposal line additions to products that have predefined purchase prices; the code notes this is not the common use case.', '1 = only predefined-price products allowed on supplier proposals; 0 or unset = no restriction (default)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/class/supplier_proposal.class.php:511|check|if (getDolGlobalInt(''SUPPLIER_PROPOSAL_WITH_PREDEFINED_PRICES_ONLY'') == 1) {\t// Not the common case", "supplier_proposal/card.php:1272|check|if (getDolGlobalInt(''SUPPLIER_PROPOSAL_WITH_PREDEFINED_PRICES_ONLY'') == 1) {\t// Not the common case", "supplier_proposal/card.php:2244|check|if (getDolGlobalInt(''SUPPLIER_PROPOSAL_WITH_PREDEFINED_PRICES_ONLY'')) {", "supplier_proposal/card.php:2245|read|$senderissupplier = getDolGlobalInt(''SUPPLIER_PROPOSAL_WITH_PREDEFINED_PRICES_ONLY'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_REF_IN_NAME', 'string', NULL, 'core', 'Controls whether the supplier reference is included in the name field on supplier PDF documents.', 'Checked across multiple supplier document generators (orders, proposals, invoices, ODT) in core/modules/supplier_order, supplier_proposal, and supplier_invoice; one occurrence in supplier_payment is commented out. When truthy, document templates include the supplier reference in the name. The COMMENTS entry shows: //if (getDolGlobalString(''SUPPLIER_REF_IN_NAME'')) {', 'Enabling this constant causes supplier reference to appear in the name field of generated supplier PDFs; disabling it omits it.', 'Truthy string to include supplier reference in name; empty/unset to omit.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_payment/doc/pdf_standard_supplierpayment.modules.php:284  //if (getDolGlobalString(''SUPPLIER_REF_IN_NAME'')) {", "core/modules/supplier_order/doc/pdf_cornas.modules.php:251|check|if (getDolGlobalString(''SUPPLIER_REF_IN_NAME'')) {", "core/modules/supplier_invoice/doc/pdf_canelle.modules.php:208|check|if (getDolGlobalString(''SUPPLIER_REF_IN_NAME'')) {", "core/modules/supplier_proposal/doc/pdf_zenith.modules.php:245|check|if (getDolGlobalString(''SUPPLIER_REF_IN_NAME'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_REPLACEMENT_TULIP_MASK', 'string', NULL, 'core', 'Defines the number mask pattern used by the Tulip module to generate supplier replacement invoice reference numbers.', 'Read in mod_facture_fournisseur_tulip.php at line 119 (displayed in a configuration input) and line 171 (used as $mask for number generation). No admin UI write outside the module configuration form is present.', 'Setting this constant controls the format of auto-generated supplier replacement invoice numbers in the Tulip module. Leaving it unset causes the module to use an empty or default mask.', 'A mask pattern string (e.g. ''{YYYY}{MM}-{0000}''); empty or unset = no mask configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:119|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskreplacement\" value=\"''.getDolGlobalString(\"SUPPLIER_REPLACEMENT_TULIP_MASK\"", "core/modules/supplier_invoice/mod_facture_fournisseur_tulip.php:171|read|$mask = getDolGlobalString(\"SUPPLIER_REPLACEMENT_TULIP_MASK\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_SHOW_STOCK_IN_PRODUCTS_COMBO', 'bool', NULL, 'product', 'Controls whether stock information is shown in the supplier product selection dropdown.', 'Read as an integer parameter passed to select_produits_fournisseurs_list() in product/ajax/products.php:341 and core/class/html.form.class.php:3977.', 'Enabling this causes stock levels to be included in the supplier product combo box, giving buyers stock visibility during order entry.', '0 or not set = stock not shown in combo; non-zero = stock shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["product/ajax/products.php:341|read|$arrayresult = $form->select_produits_fournisseurs_list($socid, \"\", $htmlname, $type, \"\", $searchkey, $status, $outjson, getDolGlobalInt(''PRODUIT_LIMIT_SIZE'', 1000), $alsoproductwi", "core/class/html.form.class.php:3977|read|$s = $this->select_produits_fournisseurs_list($socid, $selected, $htmlname, $filtertype, $filtre, '''', $status, 0, 0, $alsoproductwithnosupplierprice, $morecss, getDolGlobalInt(''SUP"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SUPPLIER_TAKE_FIRST_PRICE_IF_NO_PRICE_FOR_CURRENT_SUPPLIER', 'string', NULL, 'fourn', 'When no supplier-specific price exists for the selected supplier, uses the first available supplier price instead.', 'Checked across 4 files: supplier_proposal/card.php:843, fourn/commande/card.php:667, fourn/facture/card.php:1737, and fourn/facture/card-rec.php:523.', 'Enabling this setting ensures a price is always pre-filled on supplier documents even when the current supplier has no specific price defined.', 'Truthy string (non-empty) = use first available price as fallback; empty/not set = no fallback price applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["supplier_proposal/card.php:843|check|if (getDolGlobalString(''SUPPLIER_TAKE_FIRST_PRICE_IF_NO_PRICE_FOR_CURRENT_SUPPLIER'')) {", "fourn/commande/card.php:667|check|if (getDolGlobalString(''SUPPLIER_TAKE_FIRST_PRICE_IF_NO_PRICE_FOR_CURRENT_SUPPLIER'')) {", "fourn/facture/card.php:1737|check|if (getDolGlobalString(''SUPPLIER_TAKE_FIRST_PRICE_IF_NO_PRICE_FOR_CURRENT_SUPPLIER'')) {", "fourn/facture/card-rec.php:523|check|if (getDolGlobalString(''SUPPLIER_TAKE_FIRST_PRICE_IF_NO_PRICE_FOR_CURRENT_SUPPLIER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_DISABLE_LOGHANDLER_FILE', 'bool', NULL, 'core', 'Disables the file-based syslog handler when set to 1, preventing log output to the log file.', 'Read at core/modules/syslog/mod_syslog_file.php:75; when truthy the handler returns 0 (inactive). The inline comment states: ''Set SYSLOG_DISABLE_LOGHANDLER_FILE to 1 to disable this loghandler''. No admin UI; hidden setting.', 'Setting to 1 turns off file-based logging entirely. Leaving unset or set to 0 keeps file logging active.', '0 or empty = file log handler enabled; 1 = file log handler disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_file.php:75|read|return !getDolGlobalString(''SYSLOG_DISABLE_LOGHANDLER_FILE'') ? 1 : 0; // Set SYSLOG_DISABLE_LOGHANDLER_FILE to 1 to disable this loghandler"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_DISABLE_LOGHANDLER_SYSLOG', 'bool', NULL, 'core', 'Disables the syslog log handler module in Dolibarr''s logging system.', 'Read in core/modules/syslog/mod_syslog_syslog.php:59; the handler''s isActive() method returns 0 (inactive) when this constant is set, as noted by the inline comment ''Set SYSLOG_DISABLE_LOGHANDLER_SYSLOG to 1 to disable this loghandler''.', 'Setting this constant to 1 disables syslog-based logging; leaving it unset keeps the syslog handler active.', 'Bool-like: unset/0 = handler active; 1 = handler disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_syslog.php:59|read|return !getDolGlobalString(''SYSLOG_DISABLE_LOGHANDLER_SYSLOG'') ? 1 : 0; // Set SYSLOG_DISABLE_LOGHANDLER_SYSLOG to 1 to disable this loghandler"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_FACILITY', 'string', NULL, 'core', 'Sets the syslog facility constant name used when writing log entries to the system syslog.', 'Used in core/modules/syslog/mod_syslog_syslog.php to resolve the PHP syslog facility via defined()/constant(). The COMMENTS note: ''SYSLOG_HANDLERS = ["mod_syslog_syslog"]  facility is then defined by SYSLOG_FACILITY''. An inline comment gives ''Example LOG_USER''.', 'If set to an unknown constant name, an error is recorded; if unset the facility defaults to null.', 'String: a valid PHP syslog facility constant name, e.g. ''LOG_USER''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/lib/functions.lib.php:2767  *\tSYSLOG_HANDLERS = [\"mod_syslog_syslog\"]  \tfacility is then defined by SYSLOG_FACILITY", "core/modules/syslog/mod_syslog_syslog.php:120|check|if (getDolGlobalString(''SYSLOG_FACILITY'') && defined(getDolGlobalString(''SYSLOG_FACILITY''))) {  // Example LOG_USER", "core/modules/syslog/mod_syslog_syslog.php:100|read|$this->errors[] = $langs->trans(\"ErrorUnknownSyslogConstant\", getDolGlobalString(''SYSLOG_FACILITY''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_FILE', 'string', 'DOL_DATA_ROOT/dolibarr.log', 'core', 'Specifies the file path for the Dolibarr system log file.', 'Default value is ''DOL_DATA_ROOT/dolibarr.log''. Set during installation and upgrade in install/step5.php:261, install/upgrade2.php:314, and install/repair.php:326 from the SYSLOG_FILE constant. Read in admin/tools/purge.php:53 for log file management. Commented examples in modulebuilder templates show usage like ''DOL_DATA_ROOT/dolibarr_mydedicatedlogfile.log''.', 'Changing this redirects all system log output to the specified file path; the path must be writable by the web server.', 'File path string; default ''DOL_DATA_ROOT/dolibarr.log''.', 0, 0, 'admin/tools/purge.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["install/repair.php:326|write|$conf->global->SYSLOG_FILE = constant(''SYSLOG_FILE'');", "admin/tools/purge.php:53|read|$filelog = getDolGlobalString(''SYSLOG_FILE'');", "modulebuilder/template/class/myobject.class.php:1251|write|//$conf->global->SYSLOG_FILE = ''DOL_DATA_ROOT/dolibarr_mydedicatedlogfile.log'';", "install/step5.php:261|write|$conf->global->SYSLOG_FILE = constant(''SYSLOG_FILE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_FILE_ONEPERSESSION', 'string', NULL, 'core', 'Controls whether syslog output is split into per-session or per-user log files instead of a single shared log file.', 'Checked at core/modules/syslog/mod_syslog_file.php:134-143; value 1 creates a file per instance session key, value 2 creates a file per session key plus IP (near per-user). No admin UI; hidden setting.', 'Setting to 1 separates logs by session, to 2 separates by session and IP. Leaving unset writes all logs to the shared log file.', '0 or empty = single shared log file; 1 = file per instance session key name; 2 = file per instance session key name + IP (near per-user); other string = appended as suffix to log filename', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/syslog/mod_syslog_file.php:136|check|if (getDolGlobalInt(''SYSLOG_FILE_ONEPERSESSION'') == 1) {\t// file depend on instance session key name", "core/modules/syslog/mod_syslog_file.php:139|check|if (getDolGlobalInt(''SYSLOG_FILE_ONEPERSESSION'') == 2) {\t// file depend on instance session key name + ip so nearly per user", "core/modules/syslog/mod_syslog_file.php:134|check|if (getDolGlobalString(''SYSLOG_FILE_ONEPERSESSION'')) {", "core/modules/syslog/mod_syslog_file.php:143|read|$suffixinfilename .= ''_'' . getDolGlobalString(''SYSLOG_FILE_ONEPERSESSION'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_FILE_SAVES', 'string', NULL, 'admin', 'Sets the number of rotated log file archives to retain.', 'Comment in core/class/utils.class.php:998: ''Nb of archive to keep is defined into $conf->global->SYSLOG_FILE_SAVES''. Read at line 1018 via getDolGlobalString(''SYSLOG_FILE_SAVES'', 10) as $nbSaves. Written via admin/syslog.php:162.', 'Increasing this value retains more archived log files, consuming more disk space. Decreasing it causes older archives to be deleted sooner during rotation.', 'Integer number of archives to keep. Default: 10 when unset.', 0, 0, 'admin/syslog.php|admin/syslog.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/utils.class.php:998  * Nb of archive to keep is defined into $conf->global->SYSLOG_FILE_SAVES", "core/class/utils.class.php:1018|read|$nbSaves = intval(getDolGlobalString(''SYSLOG_FILE_SAVES'', 10));", "admin/syslog.php:162|write|$res = dolibarr_set_const($db, \"SYSLOG_FILE_SAVES\", $file_saves, ''chaine'', 0, '''', 0);", "admin/syslog.php:333|read|print ''<td colspan=\"2\"><input class=\"width50\" type=\"number\" name=\"file_saves\" placeholder=\"14\" min=\"0\" step=\"1\" value=\"''.getDolGlobalString(''SYSLOG_FILE_SAVES'').''\" />'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_HANDLERS', 'string', '["mod_syslog_file"]', 'admin', 'JSON-encoded array of active syslog handler module names that determine where Dolibarr writes log output.', 'Comment in core/lib/functions.lib.php:2766-2767: ''SYSLOG_HANDLERS = ["mod_syslog_file"] file name is then defined by SYSLOG_FILE'' and ''SYSLOG_HANDLERS = ["mod_syslog_syslog"] facility is then defined by SYSLOG_FACILITY''. Written via admin/syslog.php:126 as json_encode($activeModules). Read at line 54 via json_decode.', 'Changing this constant switches or combines the logging destinations. Selecting mod_syslog_file routes logs to a file; mod_syslog_syslog routes to the system syslog facility.', 'JSON array string. Examples: ["mod_syslog_file"] (file, path set by SYSLOG_FILE); ["mod_syslog_syslog"] (system syslog, facility set by SYSLOG_FACILITY).', 0, 0, 'admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:2766  *\tSYSLOG_HANDLERS = [\"mod_syslog_file\"]  \t\tfile name is then defined by SYSLOG_FILE", "core/lib/functions.lib.php:2767  *\tSYSLOG_HANDLERS = [\"mod_syslog_syslog\"]  \tfacility is then defined by SYSLOG_FACILITY", "admin/syslog.php:126|write|dolibarr_set_const($db, ''SYSLOG_HANDLERS'', json_encode($activeModules), ''chaine'', 0, '''', 0);", "admin/syslog.php:54|read|$activeModules = json_decode($conf->global->SYSLOG_HANDLERS);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSLOG_LEVEL', 'string', '7', 'admin', 'Sets the verbosity level of the Dolibarr syslog, using standard PHP LOG_* constants.', 'Read and written at admin/syslog.php (e.g., lines 153, 318-320) with options for LOG_EMERG through LOG_DEBUG. Checked at admin/system/perf.php:112 and admin/system/security.php:721 to warn when the level exceeds LOG_NOTICE. Default value is ''7''. Configurable via admin/syslog.php.', 'Increasing the log level above LOG_NOTICE causes verbose debug output and triggers a performance/security warning; decreasing it reduces log volume.', 'Standard PHP log level integers: LOG_EMERG=0, LOG_ALERT=1, LOG_CRIT=2, LOG_ERR=3, LOG_WARNING=4, LOG_NOTICE=5, LOG_INFO=6, LOG_DEBUG=7; default is 7.', 0, 0, 'admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/syslog.php|admin/system/perf.php|admin/system/perf.php|admin/system/security.php|admin/system/security.php|admin/syslog.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/syslog.php:318|read|print ''<option value=\"''.LOG_EMERG.''\" ''.(getDolGlobalString(''SYSLOG_LEVEL'') == LOG_EMERG ? ''selected'' : '''').''>LOG_EMERG (''.LOG_EMERG.'')</option>'';", "admin/syslog.php:319|read|print ''<option value=\"''.LOG_ALERT.''\" ''.(getDolGlobalString(''SYSLOG_LEVEL'') == LOG_ALERT ? ''selected'' : '''').''>LOG_ALERT (''.LOG_ALERT.'')</option>'';", "admin/system/perf.php:112|check|if (getDolGlobalInt(''SYSLOG_LEVEL'') > LOG_NOTICE) {", "admin/syslog.php:153|write|$res = dolibarr_set_const($db, \"SYSLOG_LEVEL\", $level, ''chaine'', 0, '''', 0);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSTEMTOOLS_MYSQLDUMP', 'string', NULL, 'admin', 'Stores the full filesystem path to the mysqldump executable used for database backups.', 'Written via admin/tools/export.php:155; read in admin/tools/dolibarr_export.php:253 and core/class/utils.class.php:301 to execute database dumps. If unset, the export pages apply fallback logic at lines 250 and 298.', 'Setting this to the correct mysqldump binary path enables database export; removing it forces the code to attempt auto-detection or fail.', 'Absolute filesystem path to the mysqldump binary.', 0, 0, 'admin/tools/dolibarr_export.php|admin/tools/dolibarr_export.php|admin/tools/export.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/export.php:155|write|dolibarr_set_const($db, ''SYSTEMTOOLS_MYSQLDUMP'', $cmddump, ''chaine'', 0, '''', 0);", "admin/tools/dolibarr_export.php:253|read|$fullpathofmysqldump = getDolGlobalString(''SYSTEMTOOLS_MYSQLDUMP'');", "core/class/utils.class.php:301|read|$cmddump = getDolGlobalString(''SYSTEMTOOLS_MYSQLDUMP'');", "admin/tools/dolibarr_export.php:250|check|if (!getDolGlobalString(''SYSTEMTOOLS_MYSQLDUMP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('SYSTEMTOOLS_POSTGRESQLDUMP', 'string', NULL, 'admin', 'Stores the full filesystem path to the pg_dump executable used for PostgreSQL database backups.', 'Written via admin/tools/export.php:195; read in admin/tools/dolibarr_export.php:430 and core/class/utils.class.php:620 to execute PostgreSQL dumps. If unset, fallback logic applies at line 427.', 'Setting this to the correct pg_dump binary path enables PostgreSQL export; removing it forces the code to attempt auto-detection or fail.', 'Absolute filesystem path to the pg_dump binary.', 0, 0, 'admin/tools/dolibarr_export.php|admin/tools/dolibarr_export.php|admin/tools/export.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/tools/export.php:195|write|dolibarr_set_const($db, ''SYSTEMTOOLS_POSTGRESQLDUMP'', $cmddump, ''chaine'', 0, '''', 0);", "admin/tools/dolibarr_export.php:430|read|$fullpathofpgdump = getDolGlobalString(''SYSTEMTOOLS_POSTGRESQLDUMP'');", "core/class/utils.class.php:620|read|$cmddump = getDolGlobalString(''SYSTEMTOOLS_POSTGRESQLDUMP'');", "admin/tools/dolibarr_export.php:427|check|if (!getDolGlobalString(''SYSTEMTOOLS_POSTGRESQLDUMP'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ADDON', 'string', NULL, 'takepos', 'Selects the numbering add-on module used to generate TakePOS invoice/ticket reference numbers.', 'Written via takepos/admin/setup.php:91 (global) and takepos/admin/terminal.php:147 (per-terminal). Checked at takepos/admin/terminal.php:384 for value ''terminal''. A commented-out line at setup.php:487 shows a formerly rendered select array for this constant.', 'Changing this value switches the numbering scheme for POS tickets; selecting ''terminal'' applies per-terminal numbering.', 'String: add-on identifier (e.g. ''0'' for default, ''terminal'' for per-terminal numbering)', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/setup.php|takepos/admin/setup.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''TAKEPOS_ADDON'') == \"terminal\") {", "//print $form->selectarray(''TAKEPOS_ADDON'', $array, (empty($conf->global->TAKEPOS_ADDON) ? ''0'' : $conf->global->TAKEPOS_ADDON), 0);", "$res = dolibarr_set_const($db, \"TAKEPOS_ADDON\", GETPOST(''TAKEPOS_ADDON'', ''alpha''), ''int'', 0, '''', $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ADD_BUTTON_OPEN_DRAWER', 'string', NULL, 'takepos', 'Adds a cash drawer open button to the TakePOS interface for the specified terminal.', 'Checked at takepos/index.php:1552; when the integer value is greater than 0 for the given terminal suffix, a drawer-open button is rendered. No admin UI write is present.', 'Setting this constant to a positive integer adds a cash drawer open control to the POS screen for that terminal; 0 or unset hides the button.', 'Integer > 0 = show open drawer button; 0 or unset = hide button.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1552|check|if (getDolGlobalInt(''TAKEPOS_ADD_BUTTON_OPEN_DRAWER''.$term) > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ADD_BUTTON_TO_ENTER_DISCOUNT_WITH_KEYBOARD', 'string', NULL, 'takepos', 'Enables an additional button in the TakePOS discount screen for keyboard-based discount entry.', 'Checked at takepos/reduction.php:242; when set, an extra UI element is rendered to allow entering discount values via keyboard. No admin UI write is present.', 'Setting this constant adds a keyboard-entry button to the discount screen; leaving it unset hides that button.', 'Non-empty string = enable keyboard discount button; unset/empty = button not shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/reduction.php:242|check|if (getDolGlobalString(''TAKEPOS_ADD_BUTTON_TO_ENTER_DISCOUNT_WITH_KEYBOARD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ALTERNATIVE_PAYMENT_SCREEN', 'string', NULL, 'takepos', 'Stores the URL of an alternative payment screen to use in TakePOS instead of the default.', 'Read at takepos/index.php:678 into $alternative_payurl. No admin UI write is present.', 'Setting this constant redirects the payment flow to a custom URL; leaving it unset uses the default TakePOS payment screen.', 'String URL of the alternative payment page; unset/empty = use default payment screen.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:678|read|$alternative_payurl = getDolGlobalString(''TAKEPOS_ALTERNATIVE_PAYMENT_SCREEN'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_AUTO_ORDER', 'string', NULL, 'takepos', 'When enabled, activates the TakePos automatic order feature, allowing products and categories to trigger auto-orders and enabling the public auto-order endpoint.', 'Checked in takepos/admin/bar.php:236 (admin UI present), viewimage.php:305 for product/category image serving with auto-order context, and takepos/public/auto_order.php:37 which blocks access when not set.', 'Enabling this constant activates the auto-order workflow in TakePos, including product image display in auto-order mode and the public auto-order page.', '0 or unset = auto-order feature disabled; truthy = auto-order feature enabled.', 0, 0, 'takepos/admin/bar.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/public/auto_order.php:37|check|if (!getDolGlobalString(''TAKEPOS_AUTO_ORDER'')) {", "viewimage.php:305|check|if (getDolGlobalString(''TAKEPOS_AUTO_ORDER'') && in_array($modulepart, array(''product'', ''category''))) {", "takepos/admin/bar.php:236|check|if (getDolGlobalInt(''TAKEPOS_AUTO_ORDER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_AUTO_PRINT_TICKETS', 'string', NULL, 'takepos', 'Enables automatic ticket printing when a TakePOS sale is fully paid.', 'Checked at takepos/invoice.php:1415; when the remaining amount to pay is 0 or less and the action is not ''history'', automatic printing is triggered. No admin UI write is present.', 'Enabling this constant causes tickets to print automatically upon payment completion; leaving it unset requires manual print actions.', 'Non-empty string/truthy = auto-print ticket on payment; unset/empty = no auto-print.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1415|check|if ($remaintopay <= 0 && getDolGlobalString(''TAKEPOS_AUTO_PRINT_TICKETS'') && $action != \"history\") {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT', 'string', NULL, 'takepos', 'Barcode parsing rule string used by TakePOS to extract product information from scanned barcodes.', 'Written via takepos/admin/setup.php:98 and displayed as a text input at setup.php:429. Read in takepos/ajax/ajax.php:183 as `$barcode_rules` for barcode processing logic.', 'Changing this value alters how scanned barcodes are interpreted when adding products to a POS sale; an incorrect rule prevents barcode-based product lookup.', 'Rule string (format determined by barcode processing logic in takepos/ajax/ajax.php)', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, ''TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT'', GETPOST(''TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$barcode_rules = getDolGlobalString(''TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT'');", "print ''<input type=\"text\" name=\"TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT\" value=\"'' . (getDolGlobalString(''TAKEPOS_BARCODE_RULE_TO_INSERT_PRODUCT'')) . ''\">'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_BAR_RESTAURANT', 'string', NULL, 'takepos', 'Enables bar and restaurant mode in TakePOS, activating table management, order printing, and related features.', 'Checked 11 times across takepos/admin/bar.php, takepos/admin/terminal.php, takepos/index.php, and takepos/invoice.php. A code comment at takepos/index.php:719 states: ''If we go here, it means $conf->global->TAKEPOS_BAR_RESTAURANT is not defined''. Configurable via takepos/admin/bar.php.', 'Without this constant set, bar/restaurant features (table ordering, order printers, supplements) are unavailable; enabling it activates the full hospitality workflow.', 'Truthy / non-empty string = bar/restaurant mode enabled; absent or empty = standard retail mode', 0, 0, 'takepos/admin/bar.php|takepos/admin/bar.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// If we go here,it means $conf->global->TAKEPOS_BAR_RESTAURANT is not defined", "if (getDolGlobalInt(''TAKEPOS_BAR_RESTAURANT'')) {", "if (getDolGlobalString(''TAKEPOS_BAR_RESTAURANT'') && getDolGlobalInt(''TAKEPOS_ORDER_PRINTERS'') && $orderprinterallowed) {", "if (!getDolGlobalString(''TAKEPOS_BAR_RESTAURANT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CAN_EDIT_IF_ALREADY_VALIDATED', 'string', NULL, 'takepos', 'Allows editing of already-validated TakePOS invoices, including draft invoices that already have a reference.', 'Checked at takepos/invoice.php:1704; the comment at line 1708 states: ''If TAKEPOS_CAN_EDIT_IF_ALREADY_VALIDATED set, we show also draft invoice that already has a reference defined''. No admin UI write is present.', 'Enabling this constant unlocks editing of validated invoices in TakePOS; leaving it unset restricts editing to unvalidated records only.', 'Non-empty string/truthy = allow editing validated invoices; unset/empty = editing restricted.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1708  // If TAKEPOS_CAN_EDIT_IF_ALREADY_VALIDATED set, we show also draft invoice that already has a reference defined", "takepos/invoice.php:1704|check|if (!getDolGlobalString(''TAKEPOS_CAN_EDIT_IF_ALREADY_VALIDATED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CAN_FORCE_BANK_ACCOUNT_DURING_PAYMENT', 'string', NULL, 'takepos', 'Enables the ability to override the bank account selection during a TakePOS payment transaction.', 'Checked in takepos/pay.php:601 and takepos/invoice.php:252 to conditionally expose a bank account selector during payment. No admin UI write is present; it must be set manually in the database.', 'When enabled, cashiers can choose a different bank account at payment time, affecting which account the payment is recorded against.', 'Non-empty string / truthy value to enable; absent or empty to disable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''TAKEPOS_CAN_FORCE_BANK_ACCOUNT_DURING_PAYMENT'')) {", "takepos/pay.php:601|check", "takepos/invoice.php:252|check"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CASHCONTROL_REPORT_SHOW_TOTAL_INCLUDING_TAXES_COLUMN', 'bool', NULL, 'compta', 'When set to a non-zero value, shows a total-including-taxes column in the TakePOS cash-control report.', 'Checked in compta/cashcontrol/report.php at lines 458 and 463, both conditioned on this constant being non-zero (default 0). No admin UI write path exists in the payload.', 'Setting this constant to a non-zero value adds an additional tax-inclusive total column to the cash control report.', '0 or unset = hide tax-inclusive total column (default); non-zero = show column', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/cashcontrol/report.php:458|check|if (getDolGlobalInt(''TAKEPOS_CASHCONTROL_REPORT_SHOW_TOTAL_INCLUDING_TAXES_COLUMN'', 0) != 0) {", "compta/cashcontrol/report.php:463|check|if (getDolGlobalInt(''TAKEPOS_CASHCONTROL_REPORT_SHOW_TOTAL_INCLUDING_TAXES_COLUMN'', 0) != 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CHANGE_PRICE_HT', 'string', NULL, 'takepos', 'Controls whether manual price entry in TakePOS uses the pre-tax (HT) amount instead of the tax-inclusive (TTC) amount.', 'Checked in takepos/index.php (multiple lines) and takepos/invoice.php:1147 to switch price-entry mode. Also drives the placeholder text in takepos/freezone.php:140, showing ''AmountHT'' when enabled.', 'When set to 1, cashiers enter pre-tax prices; when absent or 0, prices are entered tax-inclusive, affecting how line amounts are calculated and stored.', '1 = enter prices HT (pre-tax); 0 or absent = enter prices TTC (tax-inclusive)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalInt(''TAKEPOS_CHANGE_PRICE_HT'')) {", "echo ''<input type=\"text\" id=\"number\" name=\"number\" class=\"takepospay\" style=\"width:15%;\" placeholder=\"''.$langs->trans(getDolGlobalString(\"TAKEPOS_CHANGE_PRICE_HT\") ? ''AmountHT'' : ''", "} elseif (getDolGlobalInt(''TAKEPOS_CHANGE_PRICE_HT'')  == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CHOOSE_CONTACT', 'string', NULL, 'takepos', 'Enables a contact selection step within the TakePOS customer selection workflow.', 'Checked at takepos/index.php lines 669 and 1465, and at takepos/invoice.php lines 1678 and 1695. When set, a contact chooser UI element is rendered and contact-related logic is activated. No admin UI write is present.', 'Enabling this constant adds a contact picker after customer selection; leaving it unset or 0 skips the contact selection step.', 'Non-empty string/truthy = show contact chooser; 0 or unset = no contact selection.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:669|check|<?php if (getDolGlobalString(''TAKEPOS_CHOOSE_CONTACT'')) { ?>", "takepos/index.php:1465|check|if (getDolGlobalString(''TAKEPOS_CHOOSE_CONTACT'')) {", "takepos/invoice.php:1678|check|if (getDolGlobalInt(''TAKEPOS_CHOOSE_CONTACT'')) {", "takepos/invoice.php:1695|check|<?php if (getDolGlobalInt(''TAKEPOS_CHOOSE_CONTACT'') == 0) { ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_COLOR_THEME', 'string', NULL, 'takepos', 'Selects the color theme for the TakePos point-of-sale interface.', 'Written at takepos/admin/appearance.php:57 via dolibarr_set_const and read at :110 for the select control. Checked as an integer at takepos/pay.php:85, takepos/split.php:163, and takepos/index.php:125 to apply theme-specific styling.', 'Changing this value switches the visual color theme of the TakePos UI; a value of 1 activates a specific alternate theme.', '0 or unset = default theme; 1 = alternate color theme.', 0, 0, 'takepos/admin/appearance.php|takepos/admin/appearance.php|takepos/admin/appearance.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/appearance.php:57|write|$res = dolibarr_set_const($db, \"TAKEPOS_COLOR_THEME\", GETPOST(''TAKEPOS_COLOR_THEME'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/pay.php:85|check|if (getDolGlobalInt(''TAKEPOS_COLOR_THEME'') == 1) {", "takepos/split.php:163|check|if (getDolGlobalInt(''TAKEPOS_COLOR_THEME'') == 1) {", "takepos/index.php:125|check|if (getDolGlobalInt(''TAKEPOS_COLOR_THEME'') == 1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CONNECTOR_TO_WHB_CUSTOMER_DISPLAY', 'string', NULL, 'takepos', 'Specifies the connector configuration for the WHB customer display device in TakePos.', 'Checked at takepos/pay.php:537 and takepos/invoice.php:1830; when set, WHB-specific customer-display output or protocol handling is activated.', 'Setting this constant enables the WHB customer display connector in TakePos; leaving it unset uses the default customer display path (if TAKEPOS_CUSTOMER_DISPLAY is set).', 'Empty/unset = WHB connector not used; any truthy value = WHB customer display connector enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/pay.php:537|check|if (getDolGlobalString(''TAKEPOS_CONNECTOR_TO_WHB_CUSTOMER_DISPLAY'')) {", "takepos/invoice.php:1830|check|if (getDolGlobalString(''TAKEPOS_CONNECTOR_TO_WHB_CUSTOMER_DISPLAY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CONNECTOR_TO_WHB_SCALE', 'string', NULL, 'takepos', 'Enables a connector to a WHB weighing scale from the TakePOS interface.', 'Checked at takepos/index.php:1093 to conditionally render the WHB scale connector UI element. No admin UI write is present.', 'Setting this constant activates the WHB scale connector button on the POS screen; leaving it unset hides it.', 'Non-empty string/truthy = show WHB scale connector; unset/empty = hide.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1093|check|<?php if (getDolGlobalString(''TAKEPOS_CONNECTOR_TO_WHB_SCALE'')) {?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CONTROL_CASH_OPENING', 'string', NULL, 'takepos', 'Enables a cash drawer opening control check when starting a TakePOS session.', 'Checked at takepos/index.php:1150; when set, a cash opening control flow is triggered at session start. No admin UI write is present.', 'Enabling this constant activates a cash control step at POS opening; leaving it unset skips this check.', 'Non-empty string/truthy = enable cash opening control; unset/empty = skip check.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1150|check|if (getDolGlobalString(''TAKEPOS_CONTROL_CASH_OPENING'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_CUSTOMER_DISPLAY', 'string', NULL, 'takepos', 'Enables the customer-facing display feature in TakePos.', 'Checked at takepos/pay.php:532, takepos/index.php:592, takepos/invoice.php:955, and takepos/invoice.php:1824; when set, customer-display-related output or actions are triggered.', 'Enabling this constant activates the customer display integration across TakePos views; disabling it suppresses all customer-display output.', 'Empty/unset = customer display disabled; any truthy value = customer display enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/pay.php:532|check|if (getDolGlobalString(''TAKEPOS_CUSTOMER_DISPLAY'')) {", "takepos/index.php:592|check|<?php if (getDolGlobalString(''TAKEPOS_CUSTOMER_DISPLAY'')) {", "takepos/invoice.php:955|check|if (getDolGlobalString(''TAKEPOS_CUSTOMER_DISPLAY'')) {", "takepos/invoice.php:1824|check|if (getDolGlobalString(''TAKEPOS_CUSTOMER_DISPLAY'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_DELAYED_PAYMENT', 'string', NULL, 'takepos', 'Enables delayed (deferred) payment mode in TakePOS.', 'Checked once in takepos/pay.php:778 to conditionally trigger a delayed payment flow. No admin UI write path is present; must be set manually.', 'When set, the POS allows recording a sale without immediate payment collection.', 'Non-empty string / truthy value to enable; absent or empty to disable', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''TAKEPOS_DELAYED_PAYMENT'')) {", "takepos/pay.php:778|check"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_DELAYED_TERMS', 'string', NULL, 'takepos', 'Sets the payment terms ID applied to TakePOS invoices when deferred/delayed payment is used.', 'Read at takepos/invoice.php:394 in an elseif branch; when set to a non-zero integer, setPaymentTerms() is called with that value at line 395. No admin UI write is present.', 'Setting this constant applies the specified payment terms to delayed-payment invoices from TakePOS; leaving it unset skips this payment terms assignment.', 'Integer payment terms ID from the Dolibarr payment terms table; 0 or unset = no delayed terms applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:394|read|} elseif (getDolGlobalInt(\"TAKEPOS_DELAYED_TERMS\")) {", "takepos/invoice.php:395|read|$invoice->setPaymentTerms(getDolGlobalInt(\"TAKEPOS_DELAYED_TERMS\"));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_DIRECT_PAYMENT', 'string', NULL, 'takepos', 'Enables a direct payment mode in TakePOS, bypassing the standard payment screen.', 'The admin UI code is commented out in takepos/admin/setup.php:354. Checked at takepos/index.php:1504 where the direct payment flow is activated when set.', 'Enabling this constant activates the direct payment shortcut on the POS; the admin UI selectyesno widget exists but is commented out in setup.php.', 'Non-empty string/truthy = enable direct payment; unset/empty = use standard payment screen.', 0, 0, 'takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/setup.php:354  //print $form->selectyesno(\"TAKEPOS_DIRECT_PAYMENT\", $conf->global->TAKEPOS_DIRECT_PAYMENT, 1);", "takepos/index.php:1504|check|if (getDolGlobalString(''TAKEPOS_DIRECT_PAYMENT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_DISCOUNT_TTC', 'string', NULL, 'takepos', 'Controls whether discounts are calculated tax-inclusive (TTC) or tax-exclusive (HT) in TakePOS.', 'Read at takepos/invoice.php:982 within an addline() call; when set, positive amounts use ''HT'' and negative amounts use ''TTC'' for the price type parameter. No admin UI write is present.', 'Enabling this constant changes how discount lines are priced on the invoice: positive discounts are HT and negative ones are TTC; leaving it unset uses the default pricing type.', 'Non-zero integer/truthy = use TTC for negative discount amounts, HT for positive; 0 or unset = use default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:982|read|$res = $invoice->addline($desc, $number, 1, $tva_tx, $localtax1_tx, $localtax2_tx, 0, 0, '''', 0, 0, 0, 0, getDolGlobalInt(''TAKEPOS_DISCOUNT_TTC'') ? ($number >= 0 ? ''HT'' : ''TTC'') : ("]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_EMAIL_TEMPLATE_INVOICE', 'string', NULL, 'takepos', 'ID of the email template used when sending invoices by email from TakePOS.', 'Written via takepos/admin/setup.php:92 and rendered as a select list at setup.php:385. Checked in takepos/invoice.php:1411 with `> 0` guard, and read in takepos/send.php:85 as `$model_id`.', 'When set to a valid template ID, TakePOS uses that email template when emailing invoices to customers; when absent or zero, the default template or no template is used.', 'Integer: ID of a Dolibarr email template; 0 or absent = no template selected', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_EMAIL_TEMPLATE_INVOICE\", GETPOST(''TAKEPOS_EMAIL_TEMPLATE_INVOICE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''TAKEPOS_EMAIL_TEMPLATE_INVOICE'') && getDolGlobalInt(''TAKEPOS_EMAIL_TEMPLATE_INVOICE'') > 0) {", "$model_id = getDolGlobalInt(''TAKEPOS_EMAIL_TEMPLATE_INVOICE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ENABLE_SUMUP', 'bool', NULL, 'takepos', 'Enables SumUp card-payment terminal integration in TakePOS.', 'Read in takepos/admin/setup.php, takepos/admin/terminal.php, and takepos/pay.php to conditionally display SumUp-related UI and payment options. Configurable via the admin UI in takepos/admin/setup.php and takepos/admin/terminal.php.', 'When disabled, SumUp payment options and associated UI elements are hidden; when enabled, the SumUp payment flow becomes available at the POS terminal.', '0 = disabled; non-zero integer = enabled', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalInt(''TAKEPOS_ENABLE_SUMUP'')) {", "takepos/admin/setup.php:495|check", "takepos/admin/terminal.php:288|check", "takepos/pay.php:753|check"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_FOOTER', 'string', NULL, 'takepos', 'Custom HTML/text footer printed at the bottom of TakePOS receipts.', 'Written via takepos/admin/receipt.php:62 (global) and takepos/admin/terminal.php:155 (per-terminal variant). Read in takepos/receipt.php:539 via make_substitutions() to append the footer text to the receipt output.', 'Changing this value immediately affects the footer section of all subsequently generated receipts; variable substitution is applied to the stored value.', 'Any HTML or plain-text string (supports Dolibarr substitution variables)', 0, 0, 'takepos/admin/receipt.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_FOOTER\", GETPOST(''TAKEPOS_FOOTER'', ''restricthtml''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''TAKEPOS_FOOTER'') || getDolGlobalString($constFreeText)) {", "$newfreetext .= make_substitutions(getDolGlobalString(''TAKEPOS_FOOTER''), $substitutionarray);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_FORBID_SALES_TO_DEFAULT_CUSTOMER', 'string', NULL, 'takepos', 'Prevents creating sales for the default (anonymous) customer in TakePOS, requiring a specific customer to be selected.', 'Checked in takepos/admin/terminal.php:212 to conditionally show the customer selector, and in takepos/index.php:657 to enforce the restriction during a sale.', 'When enabled, cashiers cannot complete a sale without selecting a named customer; when absent or falsy, sales to the default anonymous customer are permitted.', 'Non-empty string / truthy value = forbid sales to default customer; absent or empty = allow', 0, 0, 'takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (!getDolGlobalString(''TAKEPOS_FORBID_SALES_TO_DEFAULT_CUSTOMER'')) {", "if (getDolGlobalString(''TAKEPOS_FORBID_SALES_TO_DEFAULT_CUSTOMER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_FORCE_TERMINAL_SELECT', 'string', NULL, 'takepos', 'Forces the terminal selection screen to be shown at TakePOS startup even if a terminal is already set.', 'Checked at takepos/index.php:1309; when not set, the terminal selection step is skipped. No admin UI write is present.', 'Enabling this constant always presents the terminal picker at startup; leaving it unset allows the existing terminal session to continue without re-selection.', 'Non-empty string/truthy = force terminal select; unset/empty = skip if terminal already set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1309|check|if (!getDolGlobalString(''TAKEPOS_FORCE_TERMINAL_SELECT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_GIFT_RECEIPT', 'string', NULL, 'takepos', 'Enables the gift receipt printing option in TakePOS.', 'Checked at takepos/invoice.php:1406 when customprinttemplateallowed is true; when set, the gift receipt flow is activated. The constant is reset to 0 in takepos/receipt.php:143 after use. No admin UI write is present.', 'Setting this constant triggers gift receipt generation after a TakePOS sale; the constant is then reset to 0 by receipt.php to prevent re-triggering.', 'Non-empty string/truthy = enable gift receipt; 0 or unset = no gift receipt.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1406|check|if ($customprinttemplateallowed && getDolGlobalString(''TAKEPOS_GIFT_RECEIPT'')) {", "takepos/receipt.php:143|write|$conf->global->TAKEPOS_GIFT_RECEIPT = 0;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_GROUP_SAME_PRODUCT', 'string', NULL, 'takepos', 'Controls whether identical products are grouped into a single line when added to a TakePOS sale.', 'Checked at takepos/invoice.php:879; when set, the code enters a grouping logic branch for duplicate product lines. No admin UI write is present.', 'Enabling this constant merges repeated additions of the same product into one invoice line with increased quantity; leaving it unset keeps each addition as a separate line.', 'Non-empty string/truthy = group same products; unset/empty = keep separate lines.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:879|check|if (getDolGlobalString(''TAKEPOS_GROUP_SAME_PRODUCT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HEADER', 'string', NULL, 'takepos', 'Custom HTML/text header printed at the top of TakePOS receipts.', 'Written via takepos/admin/receipt.php:61 (global) and takepos/admin/terminal.php:152 (per-terminal variant). Read in takepos/receipt.php:200 via make_substitutions() to prepend the header text to the receipt output.', 'Changing this value immediately affects the header section of all subsequently generated receipts; variable substitution is applied to the stored value.', 'Any HTML or plain-text string (supports Dolibarr substitution variables)', 0, 0, 'takepos/admin/receipt.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_HEADER\", GETPOST(''TAKEPOS_HEADER'', ''restricthtml''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''TAKEPOS_HEADER'') || getDolGlobalString($constFreeText)) {", "$newfreetext .= make_substitutions(getDolGlobalString(''TAKEPOS_HEADER''), $substitutionarray);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HEAD_BAR', 'string', NULL, 'takepos', 'Controls whether the head bar is displayed in the TakePOS point-of-sale interface.', 'Set via a yes/no selector rendered in takepos/admin/setup.php:361. The value is read and passed directly to the selectyesno form helper, making it a standard boolean admin setting.', 'Enabling or disabling this setting shows or hides the head bar in the TakePOS UI.', '1 = show head bar, 0 = hide head bar.', 0, 0, 'takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["print $form->selectyesno(\"TAKEPOS_HEAD_BAR\", $conf->global->TAKEPOS_HEAD_BAR, 1);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_CATEGORIES', 'bool', NULL, 'takepos', 'Controls whether the product category panel is hidden in the TakePOS interface.', 'Checked in takepos/admin/appearance.php:121 and in takepos/index.php at lines 1661 and 1703 to conditionally hide category-related UI elements. Value 1 hides the categories panel.', 'Setting to 1 removes the category navigation panel from the POS screen; leaving unset or 0 keeps the panel visible.', '1 = hide categories panel; 0 or unset = show categories panel.', 0, 0, 'takepos/admin/appearance.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/appearance.php:121|check|if (!getDolGlobalString(''TAKEPOS_HIDE_CATEGORIES'')) {", "takepos/index.php:1661|check|if (getDolGlobalInt(''TAKEPOS_HIDE_CATEGORIES'') == 1) {", "takepos/index.php:1703|check|<div class=\"div5<?php if (getDolGlobalInt(''TAKEPOS_HIDE_CATEGORIES'') == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_CATEGORY_IMAGES', 'bool', NULL, 'takepos', 'Controls whether category images are hidden in the TakePOS category panel.', 'Checked at takepos/index.php:1685; when not set, category images are rendered. No admin UI write is present.', 'Enabling this constant suppresses category image display on the POS screen; leaving it unset keeps category images visible.', 'Non-empty string/truthy = hide category images; unset/empty = show category images.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1685|check|if (!getDolGlobalString(''TAKEPOS_HIDE_CATEGORY_IMAGES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_DATE_OF_PRINTING', 'bool', NULL, 'takepos', 'Suppresses the printing date from appearing on TakePOS receipts.', 'Checked once in takepos/receipt.php:260 in the expression `isALNERunningVersion() || !getDolGlobalString(''TAKEPOS_HIDE_DATE_OF_PRINTING'')`, meaning the date is shown by default and hidden only when this constant is set. No admin UI write path is present.', 'When set to a truthy value, the print date is omitted from receipts; when absent or empty, the date is shown.', 'Non-empty string / truthy value = hide date; absent or empty = show date', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (isALNERunningVersion() || !getDolGlobalString(''TAKEPOS_HIDE_DATE_OF_PRINTING'')) {", "takepos/receipt.php:260|check"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_HEAD_BAR', 'bool', NULL, 'takepos', 'Controls whether the top header bar is hidden in the TakePOS interface.', 'Checked at takepos/index.php at lines 1231, 1380, 1464, 1578, 1644, and 1655 to conditionally hide or show the head bar element and adjust layout classes accordingly. No admin UI write is present.', 'Enabling this constant hides the header bar across the POS interface, freeing screen space; disabling it restores the header.', 'Non-empty string/truthy = hide header bar; unset/empty = show header bar.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1231|check|if (!getDolGlobalString(''TAKEPOS_HIDE_HEAD_BAR'')) {", "takepos/index.php:1464|check|if (getDolGlobalString(''TAKEPOS_HIDE_HEAD_BAR'')) {", "takepos/index.php:1578|check|if (getDolGlobalString(''TAKEPOS_HIDE_HEAD_BAR'')) {", "takepos/index.php:1644|check|if (getDolGlobalString(''TAKEPOS_HIDE_HEAD_BAR'') && !getDolGlobalString(''TAKEPOS_HIDE_SEARCH'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_HISTORY', 'bool', NULL, 'takepos', 'Controls whether the order/invoice history panel is hidden in the TakePOS interface.', 'Checked at takepos/index.php:1460; when not set, the history panel is rendered. No admin UI write is present.', 'Enabling this constant hides the history panel from the POS screen; leaving it unset keeps the history panel visible.', 'Non-empty string/truthy = hide history panel; unset/empty = show history panel.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1460|check|if (! getDolGlobalString(''TAKEPOS_HIDE_HISTORY'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_PRODUCT_IMAGES', 'bool', NULL, 'takepos', 'Controls whether product images are hidden throughout the TakePOS interface.', 'Checked in takepos/ajax/ajax.php:241 and in takepos/index.php at lines 390, 415, 1730, and 1736. When set, product image elements are suppressed in both the product grid and related rendering logic. No admin UI write is present.', 'Enabling this constant removes product image display from the POS screen, which can improve performance on slow connections.', 'Non-empty string/truthy = hide product images; unset/empty = show product images.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/ajax/ajax.php:241|check|if (!getDolGlobalString(''TAKEPOS_HIDE_PRODUCT_IMAGES'')) {", "takepos/index.php:390|check|<?php if (!getDolGlobalString(''TAKEPOS_HIDE_PRODUCT_IMAGES'')) {", "takepos/index.php:1730|check|if (getDolGlobalString(''TAKEPOS_HIDE_PRODUCT_IMAGES'')) {", "takepos/index.php:1736|check|<?php if ($count != $MAXPRODUCT - 2 && $count != $MAXPRODUCT - 1 && !getDolGlobalString(''TAKEPOS_HIDE_PRODUCT_IMAGES'')) { ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_PRODUCT_PRICES', 'bool', NULL, 'takepos', 'Controls whether product prices are hidden on product tiles in the TakePOS interface.', 'Checked at takepos/index.php:1727; when not set, product prices are rendered on tiles. No admin UI write is present.', 'Enabling this constant hides price labels on product tiles; leaving it unset keeps prices visible.', 'Non-empty string/truthy = hide product prices; unset/empty = show product prices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1727|check|if (!getDolGlobalString(''TAKEPOS_HIDE_PRODUCT_PRICES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_SEARCH', 'bool', NULL, 'takepos', 'Controls whether the search bar is hidden when the head bar is also hidden in TakePOS.', 'Checked at takepos/index.php:1644 in conjunction with TAKEPOS_HIDE_HEAD_BAR; the search bar is conditionally shown only when the head bar is hidden but this constant is not set. No admin UI write is present.', 'Enabling this constant suppresses the search bar even when the head bar is hidden; leaving it unset allows the search bar to appear when the head bar is hidden.', 'Non-empty string/truthy = also hide search bar; unset/empty = show search bar when head bar is hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1644|check|if (getDolGlobalString(''TAKEPOS_HIDE_HEAD_BAR'') && !getDolGlobalString(''TAKEPOS_HIDE_SEARCH'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_HIDE_STOCK_ON_LINE', 'bool', NULL, 'takepos', 'Suppresses the display of stock information on invoice lines in TakePOS.', 'In takepos/invoice.php at line 2226, stock is shown only when the constant is not set and the line has an associated product. No admin UI write path is present.', 'Setting this constant hides stock quantity information from POS invoice lines for product items.', '0 or unset = stock shown (when applicable); non-zero = stock hidden', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:2226|check|if (getDolGlobalString($constantforkey) && $line->fk_product > 0 && !getDolGlobalString(''TAKEPOS_HIDE_STOCK_ON_LINE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_LINES_TO_SHOW', 'bool', NULL, 'takepos', 'Sets the maximum number of text lines shown per product tile in the TakePOS CSS layout.', 'Set via takepos/admin/appearance.php:58 and read at line 150 via selectarray. Applied directly in takepos/css/pos.css.php:503 as the -webkit-line-clamp CSS value, defaulting to 2.', 'Increasing the value allows more product name text to be visible per tile; decreasing it truncates longer names earlier.', 'Integer number of lines; default is 2 when not set.', 0, 0, 'takepos/admin/appearance.php|takepos/admin/appearance.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/appearance.php:58|write|$res = dolibarr_set_const($db, \"TAKEPOS_LINES_TO_SHOW\", GETPOST(''TAKEPOS_LINES_TO_SHOW'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/admin/appearance.php:150|read|print $form->selectarray(''TAKEPOS_LINES_TO_SHOW'', $array, getDolGlobalInt(''TAKEPOS_LINES_TO_SHOW'', 2), 0);", "takepos/css/pos.css.php:503|read|-webkit-line-clamp: <?php echo getDolGlobalInt(''TAKEPOS_LINES_TO_SHOW'', 2); ?>;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NB_MAXCATEG', 'string', NULL, 'takepos', 'Sets the maximum number of product categories displayed in the TakePOS interface.', 'Read at takepos/index.php:94 to define $MAXCATEG, falling back to $maxcategbydefaultforthisdevice when not set. No admin UI write is present.', 'Setting this constant overrides the device-default category limit; leaving it unset uses the device-calculated default.', 'Integer maximum number of categories; unset = use device default ($maxcategbydefaultforthisdevice).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:94|read|$MAXCATEG = getDolGlobalInt(''TAKEPOS_NB_MAXCATEG'', $maxcategbydefaultforthisdevice);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NB_MAXPRODUCT', 'string', NULL, 'takepos', 'Sets the maximum number of products displayed per category page in the TakePOS interface.', 'Read at takepos/index.php:95 to define $MAXPRODUCT, falling back to $maxproductbydefaultforthisdevice when not set. No admin UI write is present.', 'Setting this constant overrides the device-default product display limit per page; leaving it unset uses the device-calculated default.', 'Integer maximum number of products; unset = use device default ($maxproductbydefaultforthisdevice).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:95|read|$MAXPRODUCT = getDolGlobalInt(''TAKEPOS_NB_MAXPRODUCT'', $maxproductbydefaultforthisdevice);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NO_CREDITNOTE', 'string', NULL, 'takepos', 'Prevents credit note creation from the TakePOS invoice view.', 'Checked at takepos/invoice.php:1865 within a combined condition that also checks the action and invoice type; when set, the credit note button or action is suppressed. No admin UI write is present.', 'Enabling this constant disables the ability to generate credit notes directly from TakePOS; leaving it unset allows credit note creation.', 'Non-empty string/truthy = disable credit note creation; unset/empty = credit notes allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1865|check|if (($action == \"valid\" || $action == \"history\" ||  ($action == \"addline\" && $invoice->status == $invoice::STATUS_CLOSED)) && $invoice->type != Facture::TYPE_CREDIT_NOTE && !getDol"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NO_FREE_ZONE_PRODUCT', 'string', NULL, 'takepos', 'Disables the free-text product entry zone in the TakePOS interface.', 'Checked at takepos/index.php:1480; when not set, the free zone product input is rendered. No admin UI write is present.', 'Enabling this constant hides the free product entry field, preventing ad-hoc product lines; leaving it unset keeps the field available.', 'Non-empty string/truthy = hide free zone product input; unset/empty = show free zone product input.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1480|check|if (!getDolGlobalString(''TAKEPOS_NO_FREE_ZONE_PRODUCT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NO_GENERIC_THIRDPARTY', 'string', NULL, 'takepos', 'Prevents the use of a generic/anonymous third-party customer in TakePOS sales.', 'Checked at takepos/index.php:666 to conditionally hide the generic customer button in the UI, and at takepos/invoice.php:1687 where a non-generic customer path is taken when the constant is set. No admin UI write is present.', 'Enabling this constant requires cashiers to always select a specific customer; leaving it unset allows sales without identifying the customer.', 'Non-zero integer/truthy = disable generic thirdparty; 0 or unset = generic thirdparty allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:666|check|<?php if (getDolGlobalInt(\"TAKEPOS_NO_GENERIC_THIRDPARTY\")) { ?>", "takepos/invoice.php:1687|read|} elseif (getDolGlobalInt(\"TAKEPOS_NO_GENERIC_THIRDPARTY\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NO_SPLIT_SALE', 'string', NULL, 'takepos', 'Disables the split sale feature in the TakePOS interface.', 'Checked at takepos/index.php:1498; when not set, the split sale button is rendered. No admin UI write is present.', 'Enabling this constant removes the split sale option from the POS screen; leaving it unset keeps split sales available.', 'Non-empty string/truthy = disable split sale; unset/empty = split sale enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1498|check|if (!getDolGlobalString(''TAKEPOS_NO_SPLIT_SALE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NUMPAD', 'string', NULL, 'takepos', 'Selects the numpad layout/mode used on the TakePos payment screen.', 'Written at takepos/admin/setup.php:88 via dolibarr_set_const and read at :338 for the select control. Checked as integer at takepos/pay.php:290, :302, and read at :629 into $numpad for rendering logic. Configurable via admin/setup.php.', 'Changing this value switches the numpad layout on the TakePos payment screen; a value of 0 activates the default numpad path.', '0 or unset = default numpad layout; other integer values = alternate numpad modes.', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/setup.php:88|write|$res = dolibarr_set_const($db, \"TAKEPOS_NUMPAD\", GETPOST(''TAKEPOS_NUMPAD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/pay.php:290|check|if (!getDolGlobalInt(\"TAKEPOS_NUMPAD\")) {", "takepos/pay.php:629|read|$numpad = getDolGlobalInt(''TAKEPOS_NUMPAD'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NUMPAD_USE_PAYMENT_ICON', 'bool', NULL, 'takepos', 'Controls whether the TakePOS payment numpad displays payment icons on its buttons.', 'Checked extensively in takepos/pay.php (26 occurrences) using the pattern `!isset(...) || getDolGlobalString(...)`, meaning the icon is shown by default when the constant is absent. No admin UI write path is present.', 'Setting this to a falsy value disables payment icons on the numpad buttons; leaving it unset or truthy keeps icons displayed by default.', 'Truthy (or absent) = show icons; falsy = hide icons', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (!isset($conf->global->TAKEPOS_NUMPAD_USE_PAYMENT_ICON) || getDolGlobalString(''TAKEPOS_NUMPAD_USE_PAYMENT_ICON'')) {", "takepos/pay.php:643|check", "takepos/pay.php:647|check"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_NUM_TERMINALS', 'string', NULL, 'takepos', 'Sets the total number of TakePOS terminals configured for the point-of-sale system.', 'Written via takepos/admin/setup.php:90 and displayed in the UI at takepos/admin/setup.php:289 with a default of ''1''. Used in takepos/invoice.php, takepos/phone.php, takepos/index.php, and compta/cashcontrol/cashcontrol_card.php to determine terminal selection logic (10 occurrences across multiple files).', 'Increasing this value makes additional terminal slots available; setting it to 1 simplifies the UI by skipping terminal selection steps.', 'Integer >= 1: number of TakePOS terminals. Defaults to ''1'' when not set.', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/setup.php:289|read|print ''<input type=\"number\" name=\"TAKEPOS_NUM_TERMINALS\" min=\"1\" class=\"width50\" value=\"'' . getDolGlobalString(''TAKEPOS_NUM_TERMINALS'', ''1'') . ''\">'';", "takepos/invoice.php:84|check|if (getDolGlobalString(''TAKEPOS_NUM_TERMINALS'') == \"1\") {", "takepos/phone.php:311|check|if (getDolGlobalString(''TAKEPOS_NUM_TERMINALS'') != \"1\" && $_SESSION[\"takeposterminal\"] == \"\") {", "compta/cashcontrol/cashcontrol_card.php:678|read|$numterminals = max(1, getDolGlobalString(''TAKEPOS_NUM_TERMINALS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ORDER_NOTES', 'string', NULL, 'takepos', 'Enables the order notes feature in TakePOS bar/restaurant mode, allowing cashiers to add notes to orders.', 'Checked in takepos/admin/bar.php:82 (value == 1) and in takepos/index.php:1544 where order notes trigger a print action via the takeposconnector. Configurable via the admin UI at takepos/admin/bar.php.', 'When set to 1, cashiers can add free-text notes to orders; when combined with the takeposconnector print method, notes are also sent to the printer.', '1 = order notes enabled; 0 or absent = disabled', 0, 0, 'takepos/admin/bar.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalInt(''TAKEPOS_ORDER_NOTES'') == 1) {", "if (getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"takeposconnector\" && getDolGlobalString(''TAKEPOS_ORDER_NOTES'') == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ORDER_PRINTER1_TO_USE', 'string', NULL, 'takepos', 'ID of the first order printer assigned to a TakePOS terminal for routing kitchen/bar order tickets (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:127 and rendered as a printer select list at terminal.php:476. Read in takepos/invoice.php:1277 as the target printer for sendToPrinter when routing order tickets to printer 1.', 'Setting this to a valid printer ID routes order tickets for printer-1 categories to that printer; leaving it unset disables routing to order printer 1.', 'Integer: ID of a configured receipt printer; 0 or absent = no order printer 1 configured', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_ORDER_PRINTER1_TO_USE\".$terminaltouse, GETPOST(''TAKEPOS_ORDER_PRINTER1_TO_USE''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "print $form->selectarray(''TAKEPOS_ORDER_PRINTER1_TO_USE''.$terminal, $printers, getDolGlobalInt(''TAKEPOS_ORDER_PRINTER1_TO_USE''.$terminal), 1);", "$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER1_TO_USE''.$_SESSI"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ORDER_PRINTER2_TO_USE', 'string', NULL, 'takepos', 'Stores the ID of the second order printer assigned to a given TakePOS terminal.', 'Set via takepos/admin/terminal.php (line 130) using dolibarr_set_const and read back at line 480 via a selectarray dropdown. Used at takepos/invoice.php:1309 when sending an order to a printer with sendToPrinter().', 'Changing the value redirects order printing to a different printer for the terminal; leaving it unset means no second order printer is used.', 'Integer printer ID as stored in the printers list; empty/0 means no second printer selected.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/terminal.php:130|write|$res = dolibarr_set_const($db, \"TAKEPOS_ORDER_PRINTER2_TO_USE\".$terminaltouse, GETPOST(''TAKEPOS_ORDER_PRINTER2_TO_USE''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/admin/terminal.php:480|read|print $form->selectarray(''TAKEPOS_ORDER_PRINTER2_TO_USE''.$terminal, $printers, getDolGlobalInt(''TAKEPOS_ORDER_PRINTER2_TO_USE''.$terminal), 1);", "takepos/invoice.php:1309|read|$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER2_TO_USE''.$_SESSI"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ORDER_PRINTER3_TO_USE', 'string', NULL, 'takepos', 'Stores the ID of the third order printer assigned to a given TakePOS terminal.', 'Set via takepos/admin/terminal.php (line 133) using dolibarr_set_const and read back at line 484 via a selectarray dropdown. Used at takepos/invoice.php:1341 when sending an order to a printer with sendToPrinter().', 'Changing the value redirects order printing to a different printer for the terminal; leaving it unset means no third order printer is used.', 'Integer printer ID as stored in the printers list; empty/0 means no third printer selected.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/terminal.php:133|write|$res = dolibarr_set_const($db, \"TAKEPOS_ORDER_PRINTER3_TO_USE\".$terminaltouse, GETPOST(''TAKEPOS_ORDER_PRINTER3_TO_USE''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/admin/terminal.php:484|read|print $form->selectarray(''TAKEPOS_ORDER_PRINTER3_TO_USE''.$terminal, $printers, getDolGlobalInt(''TAKEPOS_ORDER_PRINTER3_TO_USE''.$terminal), 1);", "takepos/invoice.php:1341|read|$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER3_TO_USE''.$_SESSI"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ORDER_PRINTERS', 'string', NULL, 'takepos', 'Number of order printers configured for TakePOS bar/restaurant mode.', 'Checked in takepos/admin/bar.php:144-149, takepos/admin/terminal.php:444 and :473 and :511, and takepos/index.php:1490. Used together with TAKEPOS_BAR_RESTAURANT to gate display of per-printer terminal configuration sections.', 'Setting this to a non-zero value enables the order printer configuration UI and routes orders to the corresponding printers; zero or absent means no order printers are configured.', 'Integer: number of order printers (e.g. 1, 2, 3); 0 or absent = no order printers', 0, 0, 'takepos/admin/bar.php|takepos/admin/bar.php|takepos/admin/terminal.php|takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$orderprinterallowed = (getDolGlobalString(''TAKEPOS_BAR_RESTAURANT'') && getDolGlobalInt(''TAKEPOS_ORDER_PRINTERS''));", "if (getDolGlobalString(''TAKEPOS_ORDER_PRINTERS'')) {", "if (getDolGlobalString(''TAKEPOS_BAR_RESTAURANT'') && getDolGlobalInt(''TAKEPOS_ORDER_PRINTERS'') && $orderprinterallowed) {", "if (getDolGlobalInt(''TAKEPOS_ORDER_PRINTERS'') && $orderprinterallowed) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINTED_CATEGORIES_1', 'string', NULL, 'takepos', 'Semicolon-delimited list of product category IDs routed to order printer 1 in TakePOS bar/restaurant mode.', 'Written via takepos/admin/orderprinters.php:76 and read in takepos/invoice.php:1240 as `$catsprinter1 = explode('';'', getDolGlobalString(''TAKEPOS_PRINTED_CATEGORIES_1''))`. The admin page checks membership using strpos to manage category assignment.', 'Changing this value determines which product categories are sent to order printer 1 when an order is placed; categories not in the list are not routed to printer 1.', 'Semicolon-delimited string of product category rowids (e.g. '';1;3;7;'')', 0, 0, 'takepos/admin/orderprinters.php|takepos/admin/orderprinters.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["dolibarr_set_const($db, \"TAKEPOS_PRINTED_CATEGORIES_1\", $printedcategories, ''chaine'', 0, '''', $conf->entity);", "$catsprinter1 = explode('';'', getDolGlobalString(''TAKEPOS_PRINTED_CATEGORIES_1''));", "if (strpos(getDolGlobalString(''TAKEPOS_PRINTED_CATEGORIES_1''), '';''.$row[\"rowid\"].'';'') !== false) {"]', 'high', NULL);
