INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINTER_TO_USE', 'string', NULL, 'takepos', 'ID of the receipt printer assigned to a TakePOS terminal (per-terminal constant, suffixed with terminal number).', 'Written via takepos/admin/terminal.php:124 and rendered as a printer select list at terminal.php:469. Read extensively in takepos/ajax/ajax.php to initiate and route print jobs, and in takepos/index.php:1537 to look up the printer name.', 'Setting this to a valid printer ID causes receipt print jobs to be sent to that printer; a value of 0 or absent falls back to the takeposconnector print method if configured.', 'Integer: ID of a configured receipt printer; 0 or absent = no dedicated printer selected', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_PRINTER_TO_USE\".$terminaltouse, GETPOST(''TAKEPOS_PRINTER_TO_USE''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalInt(''TAKEPOS_PRINTER_TO_USE''.$term) > 0) {", "$printer->initPrinter(getDolGlobalInt(''TAKEPOS_PRINTER_TO_USE''.$term));", "$printer->sendToPrinter($object, $templateidtouse, getDolGlobalInt(''TAKEPOS_PRINTER_TO_USE''.$term));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_INVOICE_DOC_INSTEAD_OF_RECEIPT', 'string', NULL, 'takepos', 'Causes TakePOS to print the full invoice document rather than a receipt-format ticket.', 'Checked at takepos/invoice.php:1380 and line 1868; when set, the invoice document printing path is taken instead of the receipt printer path. No admin UI write is present.', 'Enabling this constant replaces receipt-format printing with full invoice document printing at payment and history views.', 'Non-zero integer/truthy = print invoice document; 0 or unset = print receipt.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1380|check|if (getDolGlobalInt(''TAKEPOS_PRINT_INVOICE_DOC_INSTEAD_OF_RECEIPT'')) {", "takepos/invoice.php:1868|check|if (getDolGlobalInt(''TAKEPOS_PRINT_INVOICE_DOC_INSTEAD_OF_RECEIPT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_METHOD', 'string', NULL, 'takepos', 'Selects the printing method used by TakePOS to output receipts and order tickets.', 'Written via takepos/admin/receipt.php:81 and referenced extensively (20 occurrences) across takepos/admin/receipt.php, takepos/admin/terminal.php, takepos/ajax/ajax.php, and takepos/class/dolreceiptprinter.class.php to route print jobs through the correct mechanism.', 'Selecting an unsupported or misconfigured method prevents receipts from printing; the ''takeposconnector'' method additionally requires TAKEPOS_PRINT_SERVER to be set.', '"browser" = print via browser dialog; "receiptprinter" = use Dolibarr receipt printer module; "takeposconnector" = send to remote print server via TakePOS connector', 0, 0, 'takepos/admin/receipt.php|takepos/admin/receipt.php|takepos/admin/receipt.php|takepos/admin/receipt.php|takepos/admin/terminal.php|takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"takeposconnector\" && !isModEnabled(''receiptprinter'')) {", "if (getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"browser\" || getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"takeposconnector\") {", "if (isModEnabled(''receiptprinter'') || getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"receiptprinter\" || getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"takeposconnector\") {", "dolibarr_set_const($db, \"TAKEPOS_PRINT_METHOD\", GETPOST(''value'', ''alpha''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_PAYMENT_METHOD', 'string', NULL, 'takepos', 'Enables printing of the payment method on TakePOS receipts.', 'Written in takepos/admin/receipt.php:184, takepos/receipt.php:453, and takepos/receipt.php:142. Checked in takepos/receipt.php:461 to conditionally include payment method details in the receipt output.', 'When enabled, the payment method (e.g. cash, card) is printed on the receipt; when absent or false, the payment method section is omitted.', '1 = print payment method; 0 or absent = do not print', 0, 0, 'takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$conf->global->TAKEPOS_PRINT_PAYMENT_METHOD = 1;", "if (getDolGlobalString(''TAKEPOS_PRINT_PAYMENT_METHOD'')) {", "takepos/receipt.php:461|check"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_SERVER', 'string', NULL, 'takepos', 'URL or IP address of the remote print server used by the TakePOS connector to send receipt HTML for printing.', 'Stores the address of the print server for the TakePOS connector print method. Used in takepos/invoice.php and takepos/index.php to decide how to route print jobs. When the value is a URL it is posted directly; when it is an IP address the system calls TAKEPOS_PRINT_SERVER:8111/print with the receipt HTML content.', 'Without a valid URL or IP set here the takeposconnector print method cannot send receipts to the remote printer; print operations using that method will silently skip or fail.', 'Valid URL (e.g. http://192.168.1.10) or raw IP address', 0, 0, 'takepos/admin/receipt.php|takepos/admin/receipt.php|takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// If TAKEPOS_PRINT_SERVER is an URL", "// If TAKEPOS_PRINT_SERVER is an IP", "// Print by calling the receipt.php to get HTML content and send the HTML content to TAKEPOS_PRINT_SERVER:8111/print", "if (getDolGlobalString(''TAKEPOS_PRINT_METHOD'') == \"takeposconnector\" && filter_var(getDolGlobalString(''TAKEPOS_PRINT_SERVER''), FILTER_VALIDATE_URL) == true) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_WITHOUT_DETAILS', 'string', NULL, 'takepos', 'Enables condensed receipt printing that omits individual line-item details.', 'Written to 1 in takepos/admin/receipt.php:228 and to 0 in takepos/receipt.php:144. Checked in takepos/admin/receipt.php:235 and takepos/invoice.php:1403 to conditionally suppress line details in print output.', 'When enabled, printed receipts show only summary totals without individual product lines; when disabled, full line-item details are included.', '1 = print without line details; 0 = print full details', 0, 0, 'takepos/admin/receipt.php|takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$conf->global->TAKEPOS_PRINT_WITHOUT_DETAILS = 1;", "$conf->global->TAKEPOS_PRINT_WITHOUT_DETAILS = 0;", "if (getDolGlobalString(''TAKEPOS_PRINT_WITHOUT_DETAILS'')) {", "if ($customprinttemplateallowed && getDolGlobalString(''TAKEPOS_PRINT_WITHOUT_DETAILS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT', 'string', NULL, 'takepos', 'Defines the default label text printed on a TakePOS receipt when the ''print without details'' option is active.', 'Written via takepos/admin/receipt.php:65 and displayed in the admin UI at receipt.php:239 as a text input. Read at takepos/printbox.php:102 into the variable $label_default for use during receipt generation.', 'Changing this value alters the label shown on condensed receipts; leaving it empty results in no default label being applied.', 'Any string (free-text label for condensed receipts)', 0, 0, 'takepos/admin/receipt.php|takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, ''TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT'', GETPOST(''TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT'', ''alphanohtml''), ''chaine'', 0, '''', $conf->entity)", "$label_default = getDolGlobalString(''TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT'');", "print ''<input type=\"text\" name=\"TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT\" value=\"'' . getDolGlobalString(''TAKEPOS_PRINT_WITHOUT_DETAILS_LABEL_DEFAULT'') . ''\" />'';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_PRODUCT_IN_STOCK', 'string', NULL, 'takepos', 'Restricts the TakePOS product list to only show products currently in stock.', 'Checked at multiple points in takepos/ajax/ajax.php (lines 118, 283, 307, 328, 339). When set to 1, stock availability is verified against the terminal''s assigned warehouse before adding products. No admin UI write is present.', 'Enabling this constant filters out out-of-stock products from the POS product list, preventing their addition to sales orders.', '1 = only show/add products with available stock; 0 or unset = no stock filter applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/ajax/ajax.php:118|check|if (getDolGlobalInt(''TAKEPOS_PRODUCT_IN_STOCK'') == 1) {", "takepos/ajax/ajax.php:283|check|if (getDolGlobalInt(''TAKEPOS_PRODUCT_IN_STOCK'') == 1) {", "takepos/ajax/ajax.php:328|check|if (getDolGlobalInt(''TAKEPOS_PRODUCT_IN_STOCK'') == 1 && getDolGlobalInt(''CASHDESK_ID_WAREHOUSE''.$_SESSION[''takeposterminal''])) {", "takepos/ajax/ajax.php:339|check|if (getDolGlobalInt(''TAKEPOS_PRODUCT_IN_STOCK'') == 1 && !getDolGlobalInt(''CASHDESK_ID_WAREHOUSE''.$_SESSION[''takeposterminal''])) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_QR_MENU', 'string', NULL, 'takepos', 'Enables the QR code digital menu feature in TakePOS bar/restaurant mode.', 'Checked in takepos/admin/bar.php:217 to conditionally display QR menu configuration options, and in takepos/public/menu.php:45 where a falsy value exits the page entirely, preventing access to the public menu.', 'When enabled, the public QR menu endpoint is accessible and the admin shows related settings; when absent or zero, the public menu page is inaccessible.', 'Non-zero integer = QR menu enabled; 0 or absent = disabled', 0, 0, 'takepos/admin/bar.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalInt(''TAKEPOS_QR_MENU'')) {", "if (!$conf->global->TAKEPOS_QR_MENU) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_QTY_IN_STOCK', 'string', NULL, 'takepos', 'Prevents adding a product quantity to a TakePOS sale that would exceed the available stock.', 'Checked at takepos/invoice.php:886 when adding to an existing line (comparing line qty plus new qty against stock_reel) and at line 944 when adding a new line (comparing qty against stock_reel). No admin UI write is present.', 'Enabling this constant blocks over-stock additions at the POS level; leaving it unset allows sales regardless of stock levels.', 'Non-empty string/truthy = enforce stock limit; unset/empty = no stock enforcement.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:886|check|if (getDolGlobalString(''TAKEPOS_QTY_IN_STOCK'') && (($line->qty + $qty) > $prod->stock_reel)) {", "takepos/invoice.php:944|check|if (getDolGlobalString(''TAKEPOS_QTY_IN_STOCK'') && $qty > $prod->stock_reel) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_RECEIPT_NAME', 'string', NULL, 'takepos', 'Custom name or title printed on TakePOS receipts.', 'Written via takepos/admin/receipt.php:63 and displayed in the admin UI at receipt.php:167. Read at takepos/receipt.php:229 where it is printed directly on the receipt output.', 'Changing this value alters the name label appearing on all subsequently generated receipts.', 'Any string (free-text receipt name/title)', 0, 0, 'takepos/admin/receipt.php|takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_RECEIPT_NAME\", GETPOST(''TAKEPOS_RECEIPT_NAME'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''TAKEPOS_RECEIPT_NAME'')) {", "print getDolGlobalString(''TAKEPOS_RECEIPT_NAME'') . \" \";"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_REF_ADDON', 'string', NULL, 'compta', 'Specifies the numbering module used to generate reference numbers for TakePOS point-of-sale invoices.', 'Configured via takepos/admin/setup.php:124 and used in compta/facture/class/facture.class.php:5117-5121. When not set, the system defaults to ''mod_takepos_ref_simple''; the configured addon module name is loaded to generate POS invoice references.', 'Changing this value switches the reference numbering scheme for TakePOS invoices; if the specified module does not exist, invoice creation will fail.', 'String name of a TakePOS numbering module (e.g., ''mod_takepos_ref_simple''); empty defaults to ''mod_takepos_ref_simple''', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/setup.php:124|write|dolibarr_set_const($db, \"TAKEPOS_REF_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "compta/facture/class/facture.class.php:5117|check|if (!getDolGlobalString(''TAKEPOS_REF_ADDON'')) {", "compta/facture/class/facture.class.php:5118|write|$conf->global->TAKEPOS_REF_ADDON = ''mod_takepos_ref_simple'';", "compta/facture/class/facture.class.php:5121|read|$addon = getDolGlobalString(''TAKEPOS_REF_ADDON'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_REF_UNIVERSAL_MASK', 'string', NULL, 'core', 'Defines the reference number mask used by the ''ref_universal'' numbering module for TakePOS receipts.', 'Read in core/modules/takepos/mod_takepos_ref_universal.php at lines 92 and 139 to render the mask input and to format generated TakePOS reference numbers.', 'Changing the mask alters the format of newly generated TakePOS receipt references when this module is active.', 'Mask string (as supported by the universal module''s mask syntax); empty string disables custom formatting.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/takepos/mod_takepos_ref_universal.php:139|read|$mask = getDolGlobalString(''TAKEPOS_REF_UNIVERSAL_MASK'');", "core/modules/takepos/mod_takepos_ref_universal.php:92|read|$texte .= ''<td class=\"right\">''.$form->textwithpicto(''<input type=\"text\" class=\"flat minwidth175\" name=\"maskvalue\" value=\"''.getDolGlobalString(''TAKEPOS_REF_UNIVERSAL_MASK'').''\">, $t"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_ROOT_CATEGORY_ID', 'string', NULL, 'takepos', 'Specifies the root product category ID used to filter the product list in the TakePos point-of-sale interface.', 'Set via takepos/admin/setup.php:86; read and applied in takepos/ajax/ajax.php:172, takepos/index.php:149, and takepos/phone.php:162. When greater than 0, only products within the specified category tree are shown.', 'Setting this restricts the TakePos product browser to a specific category subtree; setting it to 0 or leaving it unset shows all products.', 'Integer category ID; 0 or unset means no category filter.', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/ajax/ajax.php:172|check|if (getDolGlobalInt(''TAKEPOS_ROOT_CATEGORY_ID'') > 0) {\t// A root category is defined, we must filter on products inside this category tree", "takepos/admin/setup.php:86|write|$res = dolibarr_set_const($db, \"TAKEPOS_ROOT_CATEGORY_ID\", GETPOST(''TAKEPOS_ROOT_CATEGORY_ID'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/index.php:149|check|if (getDolGlobalInt(''TAKEPOS_ROOT_CATEGORY_ID'') > 0) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SEND_INVOICE_AS_PDF', 'string', NULL, 'takepos', 'Controls whether invoices are sent as PDF attachments from the TakePOS send screen.', 'Checked at takepos/send.php:97; when not set, the code follows a different sending path. No admin UI write is present.', 'Enabling this constant causes the invoice to be attached as a PDF when sending from TakePOS; leaving it unset uses the default sending behavior.', 'Non-empty string/truthy = send invoice as PDF; unset/empty = use default send behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/send.php:97|check|if (!getDolGlobalString(''TAKEPOS_SEND_INVOICE_AS_PDF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_CATEGORY_DESCRIPTION', 'bool', NULL, 'takepos', 'Controls whether category descriptions are displayed in the TakePOS product category panel.', 'Checked at takepos/index.php lines 251, 294, and 341; value 1 triggers rendering of category description text in three different category display sections. No admin UI write is present.', 'Setting to 1 shows category descriptions in the POS category panel; leaving unset or 0 hides them.', '1 = show category descriptions; 0 or unset = hide category descriptions.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:251|check|if (getDolGlobalString(''TAKEPOS_SHOW_CATEGORY_DESCRIPTION'') == 1) { ?>", "takepos/index.php:294|check|if (getDolGlobalString(''TAKEPOS_SHOW_CATEGORY_DESCRIPTION'') == 1) { ?>", "takepos/index.php:341|check|<?php if (getDolGlobalString(''TAKEPOS_SHOW_CATEGORY_DESCRIPTION'') == 1) { ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_CUSTOMER', 'bool', NULL, 'takepos', 'Controls whether customer information is displayed on TakePOS receipts.', 'Checked once in takepos/receipt.php:246 to conditionally render the customer section on a receipt. No admin UI write path is present.', 'When set, customer details appear on printed receipts; when absent or falsy, the customer section is omitted.', 'Non-empty string / truthy value = show customer; absent or empty = hide customer', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if (getDolGlobalString(''TAKEPOS_SHOW_CUSTOMER'')) {", "takepos/receipt.php:246|check"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_HT', 'bool', NULL, 'takepos', 'Controls whether tax-exclusive (HT) amounts are displayed alongside TTC totals in the TakePOS invoice view.', 'Checked at takepos/invoice.php at lines 1876, 1933, 2272, 2304, and 2314; when set, HT price/total columns are rendered in the invoice display. No admin UI write is present.', 'Enabling this constant shows pre-tax amounts in the POS invoice view; leaving it unset displays only tax-inclusive totals.', 'Non-empty string/truthy = show HT (pre-tax) amounts; 0 or unset = show TTC only.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1876|check|if (getDolGlobalString(''TAKEPOS_SHOW_HT'')) {", "takepos/invoice.php:1933|check|if (getDolGlobalString(''TAKEPOS_SHOW_HT'')) {", "takepos/invoice.php:2272|check|if (getDolGlobalInt(''TAKEPOS_SHOW_HT'')) {", "takepos/invoice.php:2314|check|if (getDolGlobalString(''TAKEPOS_SHOW_HT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_HT_RECEIPT', 'bool', NULL, 'takepos', 'Enables display of pre-tax (HT) amounts on TakePOS receipts.', 'Written in takepos/admin/receipt.php:198 and forced to 1 in takepos/receipt.php:140 under certain conditions. Checked in takepos/receipt.php at lines 320, 338, and 360 to conditionally render HT subtotals and columns on the receipt.', 'When enabled, pre-tax line and total amounts are printed on receipts; when absent or false, only tax-inclusive amounts are shown.', '1 = show HT amounts on receipt; 0 or absent = hide HT amounts', 0, 0, 'takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$conf->global->TAKEPOS_SHOW_HT_RECEIPT = 1;", "if (getDolGlobalString(''TAKEPOS_SHOW_HT_RECEIPT'')) {", "takepos/receipt.php:320|check", "takepos/receipt.php:338|check"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_N_FIRST_LINES', 'bool', NULL, 'takepos', 'Limits the number of description lines shown per invoice line in TakePOS by controlling how many first lines of text are extracted.', 'In takepos/invoice.php, when not set the full description is shown (line 2128); when set, only the first N lines are extracted via dolGetFirstLineOfText (line 2171). No admin UI write path is present.', 'Setting a value truncates product description text on the POS invoice to the specified number of lines; leaving it unset shows the full description.', '0 or unset = show full description; positive integer N = show only first N lines', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:2128|check|if (!getDolGlobalString(''TAKEPOS_SHOW_N_FIRST_LINES'')) {", "takepos/invoice.php:2171|read|$firstline = dolGetFirstLineOfText($line->desc, getDolGlobalInt(''TAKEPOS_SHOW_N_FIRST_LINES''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_PRINT_COUNTER_ON_RECEIPT', 'bool', NULL, 'takepos', 'When enabled, shows the print counter number on TakePos receipts marked as duplicates.', 'Checked at takepos/receipt.php:302 and takepos/class/dolreceiptprinter.class.php:680. When truthy, blockedlog/lib/blockedlog.lib.php:537 appends the print counter (pos_print_counter - 1) to the DUPLICATA label on the receipt PDF.', 'Enabling this constant causes duplicate receipts to display their print count (e.g. ''DUPLICATA (no 2)''), aiding audit trail identification.', 'Boolean/truthy: non-empty value enables the feature; empty/unset disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''TAKEPOS_SHOW_PRINT_COUNTER_ON_RECEIPT'')) {", "''*** ''.$outputlangs->trans(\"DUPLICATA\").(getDolGlobalString(''TAKEPOS_SHOW_PRINT_COUNTER_ON_RECEIPT'') ? '' (no ''.($object->pos_print_counter - 1).'')'' : '''').'' ***''"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_PRODUCT_REFERENCE', 'bool', NULL, 'takepos', 'Controls how the product reference is displayed on product tiles in the TakePOS interface.', 'Set via takepos/admin/appearance.php:60 and rendered via selectarray at line 141. Checked in takepos/index.php at lines 417, 532, 831 (value==1) and lines 419, 534 (value==2); also checked in takepos/invoice.php:2145.', 'Changing the value toggles whether and how the product reference code appears on POS product tiles and invoice lines.', '1 = show product reference; 2 = show product reference in a different display mode; 0 or unset = do not show reference.', 0, 0, 'takepos/admin/appearance.php|takepos/admin/appearance.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/appearance.php:60|write|$res = dolibarr_set_const($db, \"TAKEPOS_SHOW_PRODUCT_REFERENCE\", GETPOST(''TAKEPOS_SHOW_PRODUCT_REFERENCE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/index.php:417|check|if (getDolGlobalInt(''TAKEPOS_SHOW_PRODUCT_REFERENCE'') == 1) {", "takepos/index.php:419|read|} elseif (getDolGlobalInt(''TAKEPOS_SHOW_PRODUCT_REFERENCE'') == 2) {", "takepos/invoice.php:2145|check|if (getDolGlobalInt(''TAKEPOS_SHOW_PRODUCT_REFERENCE'') == 1) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SHOW_SUBPRICE', 'bool', NULL, 'takepos', 'Controls whether a sub-price breakdown is displayed on the TakePOS invoice screen.', 'When enabled, the invoice display in takepos/invoice.php renders an additional sub-price section at lines 1928 and 2218. No admin UI write path is present.', 'Enabling this shows sub-price detail to cashiers on the POS invoice; disabling hides it.', '0 or unset = sub-price not shown; non-zero = sub-price shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/invoice.php:1928|check|if (getDolGlobalInt(\"TAKEPOS_SHOW_SUBPRICE\")) {", "takepos/invoice.php:2218|check|if (getDolGlobalInt(\"TAKEPOS_SHOW_SUBPRICE\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SORTPRODUCTFIELD', 'string', NULL, 'takepos', 'Field name used to sort products displayed in the TakePOS product catalog.', 'Written via takepos/admin/setup.php:89 and rendered as a select array at setup.php:316 with default ''rowid''. Read in takepos/ajax/ajax.php:111 as the sort field for `getObjectsInCateg` and in takepos/public/menu.php:100 for the public QR menu product listing.', 'Changing this value changes the order in which products are listed in the POS interface and the public QR menu.', 'Database field name string (e.g. ''rowid'', ''label'', ''ref''); default is ''rowid''', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_SORTPRODUCTFIELD\", GETPOST(''TAKEPOS_SORTPRODUCTFIELD'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "$prods = $object->getObjectsInCateg(\"product\", 0, $limit, $offset, getDolGlobalString(''TAKEPOS_SORTPRODUCTFIELD''), ''ASC'', $filter);", "print $form->selectarray(''TAKEPOS_SORTPRODUCTFIELD'', $array, getDolGlobalString(''TAKEPOS_SORTPRODUCTFIELD'', ''rowid''), 0, 0, 0, '''', 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SUMUP_AFFILIATE', 'string', NULL, 'takepos', 'Stores the SumUp affiliate key used to initiate SumUp payments from TakePos.', 'Written at takepos/admin/setup.php:94 via dolibarr_set_const and displayed in a text input at :508. Read at takepos/pay.php:508 where it is URL-encoded into the sumupmerchant:// deep-link URI.', 'Setting this constant with a valid SumUp affiliate key enables SumUp payment processing in TakePos; leaving it empty disables SumUp integration.', 'Any SumUp affiliate key string; empty/unset = SumUp not configured.', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/setup.php:94|write|$res = dolibarr_set_const($db, \"TAKEPOS_SUMUP_AFFILIATE\", GETPOST(''TAKEPOS_SUMUP_AFFILIATE'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/pay.php:508|read|window.open(''sumupmerchant://pay/1.0?affiliate-key=<?php echo urlencode(getDolGlobalString(''TAKEPOS_SUMUP_AFFILIATE'')) ?>&app-id=<?php echo urlencode(getDolGlobalString(''TAKEPOS_SU"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SUMUP_APPID', 'string', NULL, 'takepos', 'Stores the SumUp application ID used to initiate SumUp payments from TakePos.', 'Written at takepos/admin/setup.php:95 via dolibarr_set_const and displayed in a text input at :513. Read at takepos/pay.php:508 where it is URL-encoded into the sumupmerchant:// deep-link URI alongside TAKEPOS_SUMUP_AFFILIATE.', 'Setting this constant with a valid SumUp app ID enables SumUp payment processing in TakePos; leaving it empty disables SumUp integration.', 'Any SumUp application ID string; empty/unset = SumUp not configured.', 0, 0, 'takepos/admin/setup.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/setup.php:95|write|$res = dolibarr_set_const($db, \"TAKEPOS_SUMUP_APPID\", GETPOST(''TAKEPOS_SUMUP_APPID'', ''alpha''), ''chaine'', 0, '''', $conf->entity);", "takepos/pay.php:508|read|window.open(''sumupmerchant://pay/1.0?affiliate-key=<?php echo urlencode(getDolGlobalString(''TAKEPOS_SUMUP_AFFILIATE'')) ?>&app-id=<?php echo urlencode(getDolGlobalString(''TAKEPOS_SU"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SUPPLEMENTS', 'string', NULL, 'takepos', 'Enables the supplements (add-ons) feature in TakePOS bar/restaurant mode, allowing additional products to be linked to order lines.', 'Checked in takepos/admin/bar.php:181, takepos/index.php:1486, and takepos/invoice.php:860. A commented-out line in the payload (takepos/admin/bar.php:177) reads: `//print $form->selectyesno("TAKEPOS_SUPPLEMENTS", $conf->global->TAKEPOS_SUPPLEMENTS, 1);` indicating this was formerly a yes/no UI toggle.', 'When enabled, cashiers can select supplement products to attach to order lines; when absent or disabled, the supplements UI is not shown.', 'Truthy / non-zero integer = supplements enabled; 0 or absent = disabled', 0, 0, 'takepos/admin/bar.php|takepos/admin/bar.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["//print $form->selectyesno(\"TAKEPOS_SUPPLEMENTS\", $conf->global->TAKEPOS_SUPPLEMENTS, 1);", "if (getDolGlobalInt(''TAKEPOS_SUPPLEMENTS'')) {", "if (getDolGlobalString(''TAKEPOS_SUPPLEMENTS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_SUPPLEMENTS_CATEGORY', 'string', NULL, 'takepos', 'ID of the product category whose members are offered as supplements in TakePOS.', 'Written via takepos/admin/bar.php:68 and takepos/admin/setup.php:87. Read in takepos/ajax/ajax.php:98 as `$category = getDolGlobalInt(''TAKEPOS_SUPPLEMENTS_CATEGORY'')` and in takepos/invoice.php:864 to filter supplement candidates by category.', 'Changing this value changes which product category is presented as supplements; an incorrect ID results in no supplements being available.', 'Integer: ID of a Dolibarr product category; empty = no supplements category set', 0, 0, 'takepos/admin/bar.php|takepos/admin/bar.php|takepos/admin/setup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$res = dolibarr_set_const($db, \"TAKEPOS_SUPPLEMENTS_CATEGORY\", $suplement_category, ''chaine'', 0, '''', $conf->entity);", "$category = getDolGlobalInt(''TAKEPOS_SUPPLEMENTS_CATEGORY'');", "$found = (array_search(getDolGlobalInt(''TAKEPOS_SUPPLEMENTS_CATEGORY''), array_column($categories, ''id'')));", "//print $form->selectCategories(Categorie::TYPE_PRODUCT, ''TAKEPOS_SUPPLEMENTS_CATEGORY'', null);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TEMPLATE_TO_USE_FOR_INVOICES', 'bool', NULL, 'takepos', 'Selects the print template used for invoices on a given TakePOS terminal.', 'Set via takepos/admin/terminal.php (line 136) and displayed via selectarray at line 507. Read in takepos/ajax/ajax.php:460 as templateidtouse before calling sendToPrinter() at line 490.', 'Changing the template changes the layout/format of printed invoices for the terminal; the code notes it may not be ignored by sendToPrinter().', 'Integer template ID from the templates list; empty/0 means no specific template selected.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/terminal.php:136|write|$res = dolibarr_set_const($db, \"TAKEPOS_TEMPLATE_TO_USE_FOR_INVOICES\".$terminaltouse, GETPOST(''TAKEPOS_TEMPLATE_TO_USE_FOR_INVOICES''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $con", "takepos/ajax/ajax.php:460|read|$templateidtouse = getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_INVOICES''.$term);\t// Note that this may not be ignored by the sendToPrinter()", "takepos/ajax/ajax.php:490|read|$printer->sendToPrinter($object, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_INVOICES''.$term), getDolGlobalInt(''TAKEPOS_PRINTER_TO_USE''.$term));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS', 'bool', NULL, 'takepos', 'Selects the print template used for orders on a given TakePOS terminal.', 'Set via takepos/admin/terminal.php (line 139) and displayed via selectarray at line 514. Read in takepos/invoice.php at lines 1277, 1309, and 1341 when calling sendToPrinter() for each of the three order printers.', 'Changing the template changes the layout/format of printed order tickets for the terminal across all order printers.', 'Integer template ID from the templates list; empty/0 means no specific template selected.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/admin/terminal.php:139|write|$res = dolibarr_set_const($db, \"TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS\".$terminaltouse, GETPOST(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$terminaltouse, ''alpha''), ''chaine'', 0, '''', $conf->e", "takepos/invoice.php:1277|read|$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER1_TO_USE''.$_SESSI", "takepos/invoice.php:1309|read|$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER2_TO_USE''.$_SESSI", "takepos/invoice.php:1341|read|$ret = $printer->sendToPrinter($invoice, getDolGlobalInt(''TAKEPOS_TEMPLATE_TO_USE_FOR_ORDERS''.$_SESSION[\"takeposterminal\"]), getDolGlobalInt(''TAKEPOS_ORDER_PRINTER3_TO_USE''.$_SESSI"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TERMINAL_NAME_', 'string', NULL, 'takepos', 'Stores the display name for each TakePOS terminal (suffix is the terminal number, e.g., TAKEPOS_TERMINAL_NAME_1).', 'Each suffixed variant holds the name for its terminal. Written via takepos/admin/terminal.php:86 and read in compta/cashcontrol/cashcontrol_card.php:680, compta/cashcontrol/report.php:162, core/lib/takepos.lib.php:61, and takepos/index.php at lines 1242 and 1321. Falls back to the translated ''TerminalName'' string when not set.', 'Setting a terminal name customises its label throughout the TakePOS UI and cash control reports.', 'String: display name for the terminal. Defaults to translated ''TerminalName {N}'' when empty.', 0, 0, 'takepos/admin/terminal.php|takepos/admin/terminal.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["takepos/admin/terminal.php:204|read|print ''<input type=\"text\" name=\"terminalname''.$terminal.''\" value=\"''.getDolGlobalString(\"TAKEPOS_TERMINAL_NAME_\".$terminal, $langs->trans(\"TerminalName\", $terminal)).''\" >'';", "compta/cashcontrol/report.php:162|read|$nameterminal = getDolGlobalString(\"TAKEPOS_TERMINAL_NAME_\".$object->posnumber);", "core/lib/takepos.lib.php:61|read|$head[$h][1] = getDolGlobalString(''TAKEPOS_TERMINAL_NAME_''.$i, $langs->trans(\"TerminalName\", $i));", "takepos/index.php:1242|read|echo getDolGlobalString(\"TAKEPOS_TERMINAL_NAME_\".$_SESSION[\"takeposterminal\"], $langs->trans(\"TerminalName\", $_SESSION[\"takeposterminal\"]));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TERMINAL_NAME_1', 'string', NULL, 'takepos', 'Stores a custom display name for TakePOS terminal number 1.', 'Read at takepos/index.php:1317 as the label for the terminal 1 selection button, falling back to the translated ''TerminalName'' string with argument 1. No admin UI write is present.', 'Setting this constant overrides the default terminal 1 label on the terminal selection screen; leaving it unset uses the translated default.', 'String label for terminal 1; unset = use default translated terminal name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1317|read|<button type=\"button\" class=\"block\" onclick=\"location.href=''index.php?setterminal=1''\"><?php print getDolGlobalString(\"TAKEPOS_TERMINAL_NAME_1\", $langs->trans(\"TerminalName\", 1)); ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TERMINAL_NB_FOR_PUBLIC', 'string', NULL, 'takepos', 'Defines the default terminal number used for public TakePOS order submission.', 'Read at takepos/public/auto_order.php:42 to set the session terminal, with a comment stating the default terminal for public submission is 1. No admin UI write is present.', 'Changing this value routes public-facing auto-orders to a different terminal number; leaving unset defaults to terminal 1.', 'Integer terminal number; default is 1 when not set.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/public/auto_order.php:42|read|$_SESSION[\"takeposterminal\"] = getDolGlobalInt(''TAKEPOS_TERMINAL_NB_FOR_PUBLIC'', 1);\t// Default terminal for public submission is 1"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_TICKET_VAT_GROUPPED', 'string', NULL, 'takepos', 'Enables grouping of VAT amounts by rate on TakePOS receipts.', 'Written in takepos/admin/receipt.php:122 and in takepos/receipt.php:141. Checked in takepos/receipt.php:387 to conditionally render grouped VAT summary lines at the bottom of the receipt.', 'When enabled, the receipt displays a VAT summary grouped by tax rate; when absent, VAT is not grouped on the ticket.', '1 = group VAT by rate on receipt; 0 or absent = no VAT grouping', 0, 0, 'takepos/admin/receipt.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$conf->global->TAKEPOS_TICKET_VAT_GROUPPED = 1;", "if (getDolGlobalString(''TAKEPOS_TICKET_VAT_GROUPPED'')) {", "takepos/receipt.php:387|check"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_USE_ARROW_ON_NAVBAR', 'bool', NULL, 'takepos', 'Controls whether arrow navigation elements are shown or hidden in the TakePOS navigation bar CSS.', 'Checked in takepos/css/pos.css.php at line 354 (when set, applies a CSS rule) and line 980 (when not set, applies an alternative CSS rule). No admin UI write is present.', 'Enabling this constant switches the navbar CSS to show arrow-style navigation; disabling it applies the alternative CSS block.', 'Non-empty string/truthy = use arrow style on navbar; unset/empty = use default navbar style.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/css/pos.css.php:354|check|if (getDolGlobalString(''TAKEPOS_USE_ARROW_ON_NAVBAR'')) {", "takepos/css/pos.css.php:980|check|if (!getDolGlobalString(''TAKEPOS_USE_ARROW_ON_NAVBAR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_USE_DEFAULT_VATRATE_FOR_FREEZONE', 'bool', NULL, 'takepos', 'When enabled, applies the default VAT rate to free-zone product lines instead of prompting the user to select one.', 'Checked once in takepos/freezone.php:150 to determine whether to enforce the default VAT rate for a free-zone action. No admin UI write path is present.', 'Without this constant set, users must explicitly select a VAT rate for free-zone entries; with it set, the default rate is applied automatically.', 'Non-empty string / truthy value = use default VAT rate; absent or empty = prompt for VAT rate', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["if ($action == ''freezone'' && !getDolGlobalString(\"TAKEPOS_USE_DEFAULT_VATRATE_FOR_FREEZONE\") && $user->hasRight(''takepos'', ''run'')) {", "takepos/freezone.php:150|check"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAKEPOS_WEIGHING_SCALE', 'string', NULL, 'takepos', 'Enables weighing scale integration in the TakePOS interface.', 'Checked at takepos/index.php:598 to conditionally render a weighing scale UI element, and at line 1582 for related scale logic. No admin UI write is present.', 'Setting this constant activates the weighing scale widget and associated logic on the POS screen; leaving it unset disables scale integration.', 'Non-empty string/truthy = enable weighing scale; unset/empty = disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:598|check|<?php if (getDolGlobalString(''TAKEPOS_WEIGHING_SCALE'')) { ?>", "takepos/index.php:1582|check|if (getDolGlobalString(''TAKEPOS_WEIGHING_SCALE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TARGET_ADDON_PDF', 'string', NULL, 'webhook', 'Specifies the PDF model name to use for webhook target document generation.', 'In webhook/class/target.class.php at lines 1034-1035, when set the value is used as the $modele for PDF generation. No admin UI write path is present.', 'Setting this selects a specific PDF model for webhook target documents; leaving it unset falls through to other model-selection logic.', 'String: name of the PDF model to use for webhook target document generation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["webhook/class/target.class.php:1034|read|} elseif (getDolGlobalString(''TARGET_ADDON_PDF'')) {", "webhook/class/target.class.php:1035|read|$modele = getDolGlobalString(''TARGET_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_ADD_CLONE_FOR_NEXT_MONTH_CHECKBOX', 'string', NULL, 'compta', 'Shows a checkbox on the social tax card to clone the entry for the next month.', 'Checked once at compta/sociales/card.php:478 to conditionally render the clone-for-next-month checkbox. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant adds a UI checkbox allowing users to duplicate a social tax record into the following month directly from the card.', '0 (checkbox hidden) or 1 (checkbox shown)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/sociales/card.php:478|check|if (getDolGlobalString(''TAX_ADD_CLONE_FOR_NEXT_MONTH_CHECKBOX'')) {"]', 'low', NULL);
