INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_MODE', 'string', NULL, 'compta', 'Selects the general VAT liability timing mode for the company.', 'Configured via admin/taxes.php (read at line 78, written at line 88). Comments at lines 63, 68, and 73 of admin/taxes.php define: ''TAX_MODE=0 (most cases in FR)'', ''TAX_MODE=1 (option, VAT is due at invoice date)'', ''TAX_MODE=2 (option, VAT is due on payment date)''. Read by compta/tva/quadri_detail.php:95, index.php:73, clients.php:88, stats/byratecountry.php:130, and PDF modules.', 'Changing this value alters when VAT liability is recognised: at tax event (0), at invoice date (1), or at payment date (2), affecting VAT declaration reports and PDF generation.', '0 = VAT due at tax event (most cases in FR, default); 1 = VAT due at invoice date; 2 = VAT due at payment date', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:63  // TAX_MODE=0 (most cases in FR):", "admin/taxes.php:68  // TAX_MODE=1 (option, VAT is due at invoice date):", "admin/taxes.php:73  // TAX_MODE=2 (option, VAT is due on payment date):", "compta/tva/quadri_detail.php:95|read|$modetax = getDolGlobalInt(''TAX_MODE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_MODE_BUY_PRODUCT', 'string', NULL, 'compta', 'Specifies the VAT recovery timing for purchased products: ''invoice'' (recoverable at invoice date) or ''payment'' (recoverable at payment date).', 'Configured via admin/taxes.php:124. Checked in compta/tva/quadri_detail.php:794 and :192, compta/tva/clients.php:668, and core/lib/tax.lib.php:164 and :717.', 'Setting this to ''payment'' delays VAT recovery on purchased products to payment date; ''invoice'' allows recovery at invoice receipt.', '''invoice'' = VAT recoverable at invoice date for purchased products; ''payment'' = VAT recoverable at payment date', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:124|write|$res = dolibarr_set_const($db, ''TAX_MODE_BUY_PRODUCT'', $valuebuyproduct, ''chaine'', 0, '''', $conf->entity);", "core/lib/tax.lib.php:164|read||| ($direction == ''buy'' && getDolGlobalString(''TAX_MODE_BUY_PRODUCT'') == ''invoice'')) {", "compta/tva/quadri_detail.php:794|check|if (getDolGlobalString(''TAX_MODE_BUY_PRODUCT'') == ''payment'' || getDolGlobalString(''TAX_MODE_BUY_SERVICE'') == ''payment'') {", "compta/tva/quadri_detail.php:192|check|if (getDolGlobalString(''TAX_MODE_BUY_SERVICE'') == ''invoice'' && getDolGlobalString(''TAX_MODE_BUY_PRODUCT'') == ''invoice'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_MODE_BUY_SERVICE', 'string', NULL, 'compta', 'Specifies the VAT recovery timing for purchased services: ''invoice'' (recoverable at invoice date) or ''payment'' (recoverable at payment date).', 'Configured via admin/taxes.php:132. Checked in compta/tva/quadri_detail.php:794 and :192, compta/tva/clients.php:668, and core/lib/tax.lib.php:359 and :898.', 'Setting this to ''payment'' delays VAT recovery on purchased services to payment date; ''invoice'' allows recovery at invoice receipt.', '''invoice'' = VAT recoverable at invoice date for purchased services; ''payment'' = VAT recoverable at payment date', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:132|write|$res = dolibarr_set_const($db, ''TAX_MODE_BUY_SERVICE'', $valuebuyservice, ''chaine'', 0, '''', $conf->entity);", "core/lib/tax.lib.php:359|read||| ($direction == ''buy'' && getDolGlobalString(''TAX_MODE_BUY_SERVICE'') == ''invoice'')) {", "compta/tva/quadri_detail.php:794|check|if (getDolGlobalString(''TAX_MODE_BUY_PRODUCT'') == ''payment'' || getDolGlobalString(''TAX_MODE_BUY_SERVICE'') == ''payment'') {", "compta/tva/quadri_detail.php:192|check|if (getDolGlobalString(''TAX_MODE_BUY_SERVICE'') == ''invoice'' && getDolGlobalString(''TAX_MODE_BUY_PRODUCT'') == ''invoice'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_MODE_SELL_PRODUCT', 'string', NULL, 'compta', 'Specifies the VAT liability timing for sold products: ''invoice'' (due at invoice date) or ''payment'' (due at payment date).', 'Configured via admin/taxes.php:120. Checked in compta/tva/quadri_detail.php:558, compta/tva/index.php:446 and :485, compta/tva/clients.php:477, and compta/localtax pages. A commented line at compta/localtax/quadri_detail.php:160 shows ''RulesVATDueProducts'' and ''RulesVATInProducts'' labels keyed to ''invoice'' and ''payment'' respectively.', 'Setting this to ''payment'' delays VAT recognition on product sales to payment receipt; ''invoice'' recognises VAT at invoice creation.', '''invoice'' = VAT due at invoice date for sold products; ''payment'' = VAT due at payment receipt for sold products', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:120|write|$res = dolibarr_set_const($db, ''TAX_MODE_SELL_PRODUCT'', $valuesellproduct, ''chaine'', 0, '''', $conf->entity);", "compta/tva/index.php:446|check|if (($type == 0 && getDolGlobalString(''TAX_MODE_SELL_PRODUCT'') == ''invoice'')", "compta/tva/clients.php:477|check|if (getDolGlobalString(''TAX_MODE_SELL_PRODUCT'') == ''payment'' || getDolGlobalString(''TAX_MODE_SELL_SERVICE'') == ''payment'') {", "compta/localtax/quadri_detail.php:160  /*if (getDolGlobalString(''TAX_MODE_SELL_PRODUCT'') == ''invoice'') $description.=$langs->trans(\"RulesVATDueProducts\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_MODE_SELL_SERVICE', 'string', NULL, 'compta', 'Specifies the VAT liability timing for sold services: ''invoice'' (due at invoice date) or ''payment'' (due at payment date).', 'Configured via admin/taxes.php:128. Checked in compta/tva/quadri_detail.php:558, compta/tva/clients.php:477, compta/localtax/quadri_detail.php:162, core/lib/tax.lib.php:358 and :897, and compta/tva/index.php:447.', 'Setting this to ''payment'' delays VAT recognition on service sales to payment receipt; ''invoice'' recognises VAT at invoice creation.', '''invoice'' = VAT due at invoice date for sold services; ''payment'' = VAT due at payment receipt for sold services', 0, 0, 'admin/taxes.php|admin/taxes.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/taxes.php:128|write|$res = dolibarr_set_const($db, ''TAX_MODE_SELL_SERVICE'', $valuesellservice, ''chaine'', 0, '''', $conf->entity);", "compta/tva/index.php:447|read||| ($type == 1 && getDolGlobalString(''TAX_MODE_SELL_SERVICE'') == ''invoice'')) {", "core/lib/tax.lib.php:358|check|if (($direction == ''sell'' && getDolGlobalString(''TAX_MODE_SELL_SERVICE'') == ''invoice'')", "compta/localtax/quadri_detail.php:162|check|if (getDolGlobalString(''TAX_MODE_SELL_SERVICE'') == ''invoice'') $description.=''<br>''.$langs->trans(\"RulesVATDueServices\");"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TAX_REPORT_EXTRA_REPORT', 'string', NULL, 'compta', 'Enables an extra report section in the VAT/tax client report page.', 'Checked in compta/tva/clients.php:181 to conditionally render additional report content. Only 1 occurrence found in the payload.', 'When set, an extra report block is displayed on the tax client report page; the exact content of this extra report is not specified in the payload.', '0 or unset = no extra report; non-empty = extra report shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/tva/clients.php:181|check|if (getDolGlobalString(''TAX_REPORT_EXTRA_REPORT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TCPDF_THROW_ERRORS_INSTEAD_OF_DIE', 'string', NULL, 'barcode', 'Controls whether TCPDF errors throw a PHP exception or call die() when generating PDF documents.', 'A comment at core/lib/pdf.lib.php:169 states: ''TCPDF_THROW_ERRORS_INSTEAD_OF_DIE = 0 to restore the legacy die() behavior.'' The check at core/lib/pdf.lib.php:170 defaults to ''1''. barcode/printsheet.php temporarily overrides it to 1 at line 359 and restores the previous value at line 370.', 'When set to 1 (default), TCPDF errors raise exceptions that can be caught; setting to 0 reverts to the legacy die() call on PDF errors.', '1 = throw exception on TCPDF error (default); 0 = call die() on TCPDF error (legacy behavior).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// TCPDF_THROW_ERRORS_INSTEAD_OF_DIE = 0 to restore the legacy die() behavior.", "core/lib/pdf.lib.php:170|check|if (getDolGlobalString(''TCPDF_THROW_ERRORS_INSTEAD_OF_DIE'', ''1'')) {", "barcode/printsheet.php:359|write|$conf->global->TCPDF_THROW_ERRORS_INSTEAD_OF_DIE = 1;", "barcode/printsheet.php:370|write|$conf->global->TCPDF_THROW_ERRORS_INSTEAD_OF_DIE = $previousConf;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ADD_BACKGROUND_ON_INPUT', 'string', NULL, 'theme', 'When enabled, applies a background color to input fields in the Eldy and MD themes.', 'Checked in theme/eldy/global.inc.php:379 and :404 to toggle between background and no-background CSS rules, and in theme/md/style.css.php:633 for the MD theme. Three occurrences across two files. No admin UI write is present.', 'Enabling this constant adds a background color to input fields; disabling it removes that background.', 'Boolean flag; unset or 0 = no background on inputs; any truthy value = background applied.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:379|check|<?php if (!getDolGlobalString(''THEME_ADD_BACKGROUND_ON_INPUT'')) { ?>", "theme/eldy/global.inc.php:404|check|<?php if (getDolGlobalString(''THEME_ADD_BACKGROUND_ON_INPUT'')) { ?>", "theme/md/style.css.php:633|check|<?php if (!getDolGlobalString(''THEME_ADD_BACKGROUND_ON_INPUT'')) { ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_CUSTOM_CSS', 'string', NULL, 'theme', 'Stores custom CSS content injected at the end of the Eldy and MD theme stylesheets.', 'Read and printed in theme/eldy/global.inc.php:9590 unconditionally, and checked then printed in theme/md/style.css.php:9266-9267. Three occurrences across two files. No admin UI write is present in the payload.', 'Setting this constant injects arbitrary CSS at the end of the theme stylesheet, overriding any earlier theme rules.', 'Any valid CSS string; unset or empty = no custom CSS injected.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:9590|read|print getDolGlobalString(''THEME_CUSTOM_CSS'');", "theme/md/style.css.php:9266|check|if (getDolGlobalString(''THEME_CUSTOM_CSS'')) {", "theme/md/style.css.php:9267|read|print getDolGlobalString(''THEME_CUSTOM_CSS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_DARKMODEENABLED', 'bool', NULL, 'theme', 'Enables dark mode rendering for the Eldy theme, with a secondary value controlling the dark mode variant.', 'Configured via the IHM admin UI (admin/ihm.php:131, :128). Checked throughout the Eldy theme files to apply dark-mode CSS (theme/eldy/btn.inc.php:62, :64; theme/eldy/global.inc.php:225, :227, :6228, :6230). A value of 2 selects a different dark mode variant from value 1.', 'Setting this to 1 activates dark mode. Setting it to 2 activates a variant dark mode. Unsetting it returns the theme to light mode.', '0 or unset = light mode; 1 = dark mode; 2 = dark mode variant.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/btn.inc.php:62|check|if (getDolGlobalString(''THEME_DARKMODEENABLED'')) {", "theme/eldy/btn.inc.php:64|check|if (getDolGlobalInt(''THEME_DARKMODEENABLED'') != 2) {", "theme/eldy/global.inc.php:225|check|if (getDolGlobalInt(''THEME_DARKMODEENABLED'')) {", "theme/eldy/global.inc.php:227|check|if (getDolGlobalInt(''THEME_DARKMODEENABLED'') != 2) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BACKBODY', 'string', NULL, 'theme', 'Stores the custom background colour (RGB triplet) for the main content area in the Eldy and MD themes.', 'Read in theme/eldy/style.css.php:255 and theme/md/style.css.php to set $colorbackbody; used only when THEME_ELDY_ENABLE_PERSONALIZED is active. A colour picker is displayed in the group/user settings at core/lib/usergroups.lib.php:826. Configurable via admin/ihm.php. The comment at core/lib/usergroups.lib.php:800 labels it ''Background color for main area THEME_ELDY_BACKBODY''.', 'Changing this value alters the background colour of the main page area for all users (unless overridden per-user).', 'String: RGB triplet as ''R,G,B'' (e.g. ''255,255,255'' for white). Empty or unset uses the theme default.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/lib/usergroups.lib.php:800  // Background color for main area THEME_ELDY_BACKBODY", "theme/eldy/style.css.php:255|check|$colorbackbody = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_BACKBODY'') ? $colorbackbody : $conf->global->THEME_ELDY_BACKBODY)", "admin/ihm.php:153|write|dolibarr_set_const($db, ''THEME_ELDY_BACKBODY'', $val, ''chaine'', 0, '''', $conf->entity);", "core/lib/usergroups.lib.php:826|read|print $formother->selectColor(colorArrayToHex(colorStringToArray(getDolGlobalString(''THEME_ELDY_BACKBODY''), array()), ''''), ''THEME_ELDY_BACKBODY'', ...);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BACKTABACTIVE', 'string', NULL, 'theme', 'Stores the background colour (RGB triplet) for the active/selected tab in the Eldy and MD themes.', 'Set to ''234,234,234'' as a default in theme/eldy/style.css.php:248 and theme/md/style.css.php:254 when personalisation is disabled. Read in style.css.php:261 and md/style.css.php:266 into $colorbacktabactive. No admin UI write is present.', 'Changing this value alters the background colour of the currently selected tab across the UI.', 'String: RGB triplet as ''R,G,B'' (default ''234,234,234''). Empty or unset falls back to theme default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:248|write|$conf->global->THEME_ELDY_BACKTABACTIVE = ''234,234,234'';", "theme/md/style.css.php:254|write|$conf->global->THEME_ELDY_BACKTABACTIVE = ''234,234,234'';", "theme/eldy/style.css.php:261|check|$colorbacktabactive = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_BACKTABACTIVE'') ? $colorbacktabactive : $conf->global->THEME_ELDY_BACK", "theme/md/style.css.php:266|check|$colorbacktabactive = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_BACKTABACTIVE'', $colorbacktabactive) : getDolUserString(''THEME_ELDY_BACKT"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BACKTABCARD1', 'string', NULL, 'theme', 'Stores the background colour (RGB triplet) for card/record tab panels in the Eldy and MD themes.', 'Set to ''255,255,255'' as a default in theme/eldy/style.css.php:247 and theme/md/style.css.php:253 when THEME_ELDY_ENABLE_PERSONALIZED is disabled. Read in style.css.php:260 and md/style.css.php:265 into $colorbacktabcard1. No admin UI write is present.', 'Changing this value alters the background colour of card view tab content areas.', 'String: RGB triplet as ''R,G,B'' (default ''255,255,255''). Empty or unset falls back to theme default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:247|write|$conf->global->THEME_ELDY_BACKTABCARD1 = ''255,255,255''; // card", "theme/md/style.css.php:253|write|$conf->global->THEME_ELDY_BACKTABCARD1 = ''255,255,255''; // card", "theme/eldy/style.css.php:260|check|$colorbacktabcard1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_BACKTABCARD1'') ? $colorbacktabcard1 : $conf->global->THEME_ELDY_BACKTA", "theme/md/style.css.php:265|check|$colorbacktabcard1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_BACKTABCARD1'', $colorbacktabcard1) : getDolUserString(''THEME_ELDY_BACKTAB"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BACKTITLE1', 'string', NULL, 'theme', 'Sets the background colour of title bars in the Eldy and MD themes.', 'Configured via the IHM admin UI (admin/ihm.php:181). The value is applied to the $colorbacktitle1 CSS variable in both theme/eldy/style.css.php:259 and theme/md/style.css.php:264, and also used for light/dark colour detection in theme/eldy/info-box.inc.php:114. Per-user personalisation overrides the global value when THEME_ELDY_ENABLE_PERSONALIZED is set.', 'Changing this value alters the title bar background colour across the Eldy and MD themes. When per-user personalisation is active, the user-level setting takes precedence over this global value.', 'CSS hex colour string (e.g. ''#aabbcc'').', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:259|check|$colorbacktitle1      = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_BACKTITLE1'') ? $colorbacktitle1 : $conf->global->THEME_ELDY_BACKTITLE1", "theme/md/style.css.php:264|check|$colorbacktitle1     = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_BACKTITLE1'', $colorbacktitle1) : getDolUserString(''THEME_ELDY_BACKTITLE1''", "theme/eldy/info-box.inc.php:114|check|<?php if (!colorIsLight(getDolGlobalString(''THEME_ELDY_BACKTITLE1''))) { ?>"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BORDER_RADIUS', 'string', NULL, 'theme', 'Sets the border radius (in pixels) applied to UI elements in the Eldy and MD themes when borders are enabled.', 'Written via admin/ihm.php:146. Read in theme/eldy/global.inc.php:159, theme/md/style.css.php:4701, theme/md/info-box.inc.php:20, and theme/eldy/dropdown.inc.php:28 with a default of 6. Ten occurrences across multiple files; configurable via admin/ihm.php.', 'Changing this value alters the corner rounding of UI elements across both themes. The value is only applied when THEME_ELDY_USEBORDERONTABLE is enabled.', 'Integer pixel value; default is 6 when unset.', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:146|write|dolibarr_set_const($db, ''THEME_ELDY_BORDER_RADIUS'', GETPOSTINT(''THEME_ELDY_BORDER_RADIUS''), ''chaine'', 0, '''', $conf->entity);", "theme/eldy/global.inc.php:159|read|$borderradius = getDolGlobalString(''THEME_ELDY_USEBORDERONTABLE'') ? getDolGlobalInt(''THEME_ELDY_BORDER_RADIUS'', 6) : 0;", "theme/md/style.css.php:4701|read|<?php $borderradius = getDolGlobalString(''THEME_ELDY_USEBORDERONTABLE'') ? getDolGlobalInt(''THEME_ELDY_BORDER_RADIUS'', 6) : 0; ?>", "core/lib/usergroups.lib.php:634|read|print $form->selectarray(''THEME_ELDY_BORDER_RADIUS'', $listofborderradius, getDolGlobalInt(''THEME_ELDY_BORDER_RADIUS''), 0, 0, 0, '''', 0, 0, 0, '''', ''miwdith150 widthcentpercentminusx"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_BTNACTION', 'string', NULL, 'theme', 'Stores the custom background colour (RGB triplet) for action buttons in the Eldy and MD themes.', 'Read in theme/eldy/style.css.php:274 and theme/md/style.css.php:279 into $butactionbg. A colour picker is available at core/lib/usergroups.lib.php:1125. Configurable via admin/ihm.php.', 'Changing this value alters the background colour of all primary action buttons throughout the application.', 'String: RGB triplet as ''R,G,B''. Empty or unset uses the theme default action button colour.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:274|check|$butactionbg = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_BTNACTION'') ? $butactionbg : getDolGlobalString(''THEME_ELDY_BTNACTION''", "admin/ihm.php:249|write|dolibarr_set_const($db, ''THEME_ELDY_BTNACTION'', $val, ''chaine'', 0, '''', $conf->entity);", "core/lib/usergroups.lib.php:1125|read|print $formother->selectColor(colorArrayToHex(colorStringToArray(getDolGlobalString(''THEME_ELDY_BTNACTION''), array()), ''''), ''THEME_ELDY_BTNACTION'','''',1).'' '';", "core/lib/usergroups.lib.php:1118|read|print ''<td>''.(getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'') ? getDolGlobalString(''THEME_ELDY_BTNACTION'') : $langs->trans(\"Default\")).''</td>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_ENABLE_PERSONALIZED', 'bool', NULL, 'theme', 'Gates whether per-user or global colour customisation is applied in the Eldy and MD themes.', 'When disabled (0), style.css.php resets colour variables to defaults (see commented-out lines at theme/eldy/style.css.php:203-204). When enabled, personalised colours from global or user config are applied. The comment at line 245 states this is a prerequisite for other editable colour options.', 'Disabling this constant forces all users to the default theme colours, ignoring any per-user or per-entity colour customisation.', 'Boolean flag: truthy = personalised colours applied; 0 = defaults enforced. Per comments: //$conf->global->THEME_ELDY_ENABLE_PERSONALIZED=0; disables global personalisation; //$user->conf->THEME_ELDY_ENABLE_PERSONALIZED=0; disables per-user personalisation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:203  //$conf->global->THEME_ELDY_ENABLE_PERSONALIZED=0;", "theme/eldy/style.css.php:204  //$user->conf->THEME_ELDY_ENABLE_PERSONALIZED=0;", "theme/eldy/style.css.php:245  // Case of option editable only if option THEME_ELDY_ENABLE_PERSONALIZED is on", "theme/eldy/style.css.php:246|check|if (!getDolGlobalString(''THEME_ELDY_ENABLE_PERSONALIZED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_FONT_SIZE1', 'string', NULL, 'theme', 'Sets the primary font size used in the Eldy and MD themes.', 'Controls the main font size applied in theme/eldy/style.css.php:250 and theme/md/style.css.php:256. When user personalization is disabled, the global constant value overrides the theme default; otherwise the per-user value is used. No admin UI is provided.', 'Changing this value resizes the primary text across all pages rendered by the Eldy and MD themes for users without personal theme customization.', 'A CSS font size string (e.g., ''13px'', ''0.85em''); empty/unset means the compiled theme default is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:276|check|$fontsize = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_FONT_SIZE1'') ? $fontsize : getDolGlobalString(''THEME_ELDY_FONT_SIZE1'')", "theme/md/style.css.php:281|check|$fontsize = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_FONT_SIZE1'', $fontsize) : getDolUserString(''THEME_ELDY_FONT_SIZE1'', $font", "theme/eldy/style.css.php:250|write|$conf->global->THEME_ELDY_FONT_SIZE1 = $fontsize;", "theme/md/style.css.php:256|write|$conf->global->THEME_ELDY_FONT_SIZE1 = $fontsize;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_FONT_SIZE2', 'string', NULL, 'theme', 'Sets the secondary (smaller) font size used in the Eldy and MD themes.', 'Controls the smaller font size applied in theme/eldy/style.css.php:251 (hardcoded to ''0.75em'') and theme/md/style.css.php:257 (hardcoded to ''0.7em''). When user personalization is disabled, the global constant is used; otherwise the per-user value is applied. No admin UI is provided.', 'Changing this value resizes secondary/smaller text across all pages rendered by the Eldy and MD themes for users without personal customization.', 'A CSS font size string (e.g., ''0.75em'', ''0.7em''); default written by theme code is ''0.75em'' (Eldy) or ''0.7em'' (MD).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:251|write|$conf->global->THEME_ELDY_FONT_SIZE2 = ''0.75em'';", "theme/md/style.css.php:257|write|$conf->global->THEME_ELDY_FONT_SIZE2 = ''0.7em'';", "theme/eldy/style.css.php:277|check|$fontsizesmaller = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_FONT_SIZE2'') ? $fontsize : getDolGlobalString(''THEME_ELDY_FONT_SIZE2'')", "theme/md/style.css.php:282|check|$fontsizesmaller = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_FONT_SIZE2'', $fontsize) : getDolUserString(''THEME_ELDY_FONT_SIZE2'', $font"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_LINEBREAK', 'string', NULL, 'theme', 'Stores the background colour (RGB triplet) for separator/break rows in lists in the Eldy and MD themes.', 'Set to a default value via $conf->global at theme/eldy/style.css.php:231 and theme/md/style.css.php:235 when not already defined. Read in style.css.php:266 and md/style.css.php:271 into $colorbacklinebreak. No admin UI write is present.', 'Changing this value alters the colour of visual separator rows used to group list entries.', 'String: RGB triplet as ''R,G,B''. Empty or unset triggers the theme to set a default via $conf->global.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:230|read|if (!isset($conf->global->THEME_ELDY_LINEBREAK)) {", "theme/eldy/style.css.php:231|write|$conf->global->THEME_ELDY_LINEBREAK = $colorbacklinebreak;", "theme/eldy/style.css.php:266|check|$colorbacklinebreak = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_LINEBREAK'') ? $colorbacklinebreak : $conf->global->THEME_ELDY_LINEBREA", "theme/md/style.css.php:271|check|$colorbacklinebreak = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_LINEBREAK'', $colorbacklinebreak) : getDolUserString(''THEME_ELDY_LINEBREAK"]', 'high', NULL);
