INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_TOPMENU_BACK1', 'string', NULL, 'core', 'Sets the background colour of the top horizontal menu bar in the Eldy and MD themes.', 'Written via admin/ihm.php (line 160) and read in theme/eldy/style.css.php (line 256) and theme/md/style.css.php (line 261) to set `$colorbackhmenu1`. Also referenced in main.inc.php:1750 and login/password templates.', 'Changing this value immediately alters the top-menu background colour for all users of the Eldy or MD theme.', 'String (CSS hex colour, e.g. ''#2C4E96''); empty means the theme default colour is used.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:160|write|dolibarr_set_const($db, ''THEME_ELDY_TOPMENU_BACK1'', $val, ''chaine'', 0, '''', $conf->entity);", "theme/eldy/style.css.php:256|check|$colorbackhmenu1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'') ? $colorbackhmenu1 : $conf->global->THEME_ELDY_TOPMENU…", "theme/md/style.css.php:261|check|$colorbackhmenu1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'', $colorbackhmenu1) : getDolUserString(''THEME_ELDY_TOPMENU_…", "main.inc.php:1750|check|if (getDolGlobalString(''THEME_ELDY_TOPMENU_BACK1'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_TOTAL_BACKGROUND_LIKE_HEAD', 'string', NULL, 'theme', 'When enabled, renders the total row background using the same color as table header rows in the Eldy theme.', 'Checked in theme/eldy/global.inc.php:5223 to conditionally apply the colorbacktitle1 CSS variable as the total row background. Only one occurrence in the payload. No admin UI write is present.', 'Enabling this constant makes total rows visually match header rows in Eldy theme tables.', 'Boolean flag; unset or 0 = default total row background; any truthy value = header background color applied to totals.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:5223|check|<?php if (getDolGlobalString(''THEME_ELDY_TOTAL_BACKGROUND_LIKE_HEAD'')) { ?>background: var(--colorbacktitle1);<?php } ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_USEBOLDTITLE', 'string', NULL, 'theme', 'Controls whether section titles in the Eldy and MD themes are rendered in bold.', 'Read in theme/eldy/style.css.php:207 and theme/md/style.css.php:211 into $useboldtitle, which is used to generate the corresponding CSS rule. No admin UI is present.', 'Enabling this constant makes section titles bold across the Eldy and MD themes.', 'Integer flag: 1 = bold titles; 0 or unset = normal weight titles.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:207|read|$useboldtitle = getDolGlobalInt(''THEME_ELDY_USEBOLDTITLE'');", "theme/md/style.css.php:211|read|$useboldtitle = getDolGlobalInt(''THEME_ELDY_USEBOLDTITLE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_USEBORDERONTABLE', 'string', '1', 'theme', 'Controls whether borders are rendered on tables in the Eldy and MD themes.', 'Read in theme/eldy/style.css.php:208 and theme/md/style.css.php:213 to set the $userborderontable variable. Also used in theme/eldy/global.inc.php:159, theme/md/info-box.inc.php:20, and theme/eldy/dropdown.inc.php:28 to conditionally apply border-radius. Default is ''1''. Ten occurrences across multiple files. No admin UI write is present in the payload.', 'Disabling this constant removes table borders and sets border-radius to 0 across the Eldy and MD themes.', 'Integer; 1 (default) = borders enabled; 0 = borders disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:208|read|$userborderontable = getDolGlobalInt(''THEME_ELDY_USEBORDERONTABLE'');", "theme/md/style.css.php:213|read|$userborderontable = getDolGlobalInt(''THEME_ELDY_USEBORDERONTABLE'');", "theme/eldy/global.inc.php:159|read|$borderradius = getDolGlobalString(''THEME_ELDY_USEBORDERONTABLE'') ? getDolGlobalInt(''THEME_ELDY_BORDER_RADIUS'', 6) : 0;", "core/lib/usergroups.lib.php:664|check|if (getDolGlobalString(''THEME_ELDY_USEBORDERONTABLE'') || getDolGlobalString(''THEME_SHOW_BORDER_ON_INPUT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_USECOMOACTROW', 'string', NULL, 'theme', 'Controls whether compact (higher) row height is used in list tables of the Eldy and MD themes.', 'When enabled, the CSS row height variable is set to ''300%''; when disabled or empty, it is set to ''155%'', as seen in theme/eldy/style.css.php:278 and theme/md/style.css.php:283. Configurable via admin/ihm.php:122.', 'Enabling this constant increases list row height to ''300%'', making rows taller across all list tables in the Eldy and MD themes.', 'Non-empty/truthy value = compact row height (''300%''); empty/unset = normal row height (''155%'').', 0, 0, 'admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:278|check|$heightrow = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_USECOMOACTROW'') ? ''155%'' : ''300%'') : (empty($user->conf->THEME_ELDY_USECOMOAC", "theme/md/style.css.php:283|check|$heightrow = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (getDolGlobalString(''THEME_ELDY_USECOMOACTROW'') ? ''300%'' : ''155%'') : (getDolUserString(''THEME_ELDY_USECOMOACTRO", "admin/ihm.php:122|write|dolibarr_set_const($db, \"THEME_ELDY_USECOMOACTROW\", GETPOST(''THEME_ELDY_USECOMOACTROW''), ''chaine'', 0, '''', $conf->entity);", "core/lib/usergroups.lib.php:701  //print ajax_constantonoff(''THEME_ELDY_USECOMOACTROW'', array(), null, 0, 0, 1);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_USE_CHECKED', 'bool', NULL, 'theme', 'Sets the background color applied to checked/selected rows in list tables for the Eldy and MD themes.', 'Determines the checked-row highlight color ($colorbacklinepairchecked) in theme/eldy/style.css.php:281 and theme/md/style.css.php:287. If unset or equal to ''255,255,255'', no checked highlight is applied. Configurable via admin/ihm.php:242.', 'Setting this to a non-white color enables visible highlight on checked/selected rows in list tables; setting it to ''255,255,255'' or clearing it disables the highlight.', 'A CSS RGB string (e.g., ''200,220,240''); ''255,255,255'' or unset = no checked highlight; ''1'' = checked highlight enabled with default color.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:242|write|dolibarr_set_const($db, \"THEME_ELDY_USE_CHECKED\", $val, ''chaine'', 0, '''', $conf->entity);", "theme/eldy/style.css.php:281|read|$colorbacklinepairchecked = ((!isset($conf->global->THEME_ELDY_USE_CHECKED) || getDolGlobalString(''THEME_ELDY_USE_CHECKED'') === ''255,255,255'') ? '''' : (getDolGlobalString(''THEME_ELD", "core/lib/usergroups.lib.php:1085|check|if (getDolGlobalString(''THEME_ELDY_USE_CHECKED'') == ''1'') {", "core/lib/usergroups.lib.php:1092|check|if (getDolGlobalString(''THEME_ELDY_USE_CHECKED'') == ''1'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_USE_HOVER', 'bool', NULL, 'theme', 'Sets the background color applied to hovered rows in list tables for the Eldy and MD themes.', 'Determines the hover highlight color ($colorbacklinepairhover) in theme/eldy/style.css.php:280 and theme/md/style.css.php:286. If unset or equal to ''255,255,255'', no hover color is applied. Configurable via admin/ihm.php:235.', 'Setting this to a non-white color enables visible row hover highlighting in list tables; setting it to ''255,255,255'' or clearing it disables the highlight.', 'A CSS RGB string (e.g., ''200,220,240''); ''255,255,255'' or unset = no hover highlight; ''1'' = hover enabled with default color.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ihm.php:235|write|dolibarr_set_const($db, \"THEME_ELDY_USE_HOVER\", $val, ''chaine'', 0, '''', $conf->entity);", "theme/eldy/style.css.php:280|read|$colorbacklinepairhover = ((!isset($conf->global->THEME_ELDY_USE_HOVER) || getDolGlobalString(''THEME_ELDY_USE_HOVER'') === ''255,255,255'') ? '''' : (getDolGlobalString(''THEME_ELDY_USE_", "core/lib/usergroups.lib.php:1037|check|if (getDolGlobalString(''THEME_ELDY_USE_HOVER'') == ''1'') {", "core/lib/usergroups.lib.php:1044|check|if (getDolGlobalString(''THEME_ELDY_USE_HOVER'') == ''1'') {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_VERMENU_BACK1', 'string', NULL, 'theme', 'Stores the custom background colour (RGB triplet) for the vertical navigation menu in the Eldy and MD themes.', 'Read in theme/eldy/style.css.php:257 and theme/md/style.css.php:262 into $colorbackvmenu1. A colour picker is provided at core/lib/usergroups.lib.php:768. Configurable via admin/ihm.php.', 'Changing this value alters the background colour of the left vertical navigation menu.', 'String: RGB triplet as ''R,G,B'' (e.g. ''51,51,51''). Empty or unset uses the theme default.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:257|check|$colorbackvmenu1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? (!getDolGlobalString(''THEME_ELDY_VERMENU_BACK1'') ? $colorbackvmenu1 : $conf->global->THEME_ELDY_VERMENU", "admin/ihm.php:167|write|dolibarr_set_const($db, ''THEME_ELDY_VERMENU_BACK1'', $val, ''chaine'', 0, '''', $conf->entity);", "core/lib/usergroups.lib.php:768|read|print $formother->selectColor(colorArrayToHex(colorStringToArray(getDolGlobalString(''THEME_ELDY_VERMENU_BACK1''), array()), ''''),''THEME_ELDY_VERMENU_BACK1'','''',1).'' '';", "theme/md/style.css.php:262|check|$colorbackvmenu1 = empty($user->conf->THEME_ELDY_ENABLE_PERSONALIZED) ? getDolGlobalString(''THEME_ELDY_VERMENU_BACK1'', $colorbackvmenu1) : getDolUserString(''THEME_ELDY_VERMENU_"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_WITDHOFFSET_FOR_REDUC1', 'string', NULL, 'theme', 'Sets the pixel breakpoint for the first responsive layout reduction in the Eldy and MD themes.', 'Read in theme/eldy/global.inc.php:9148, theme/md/btn.inc.php:426, and theme/md/style.css.php:8932 as the max-width value in a media query, with a default computed from the number of top menu entries. Three occurrences across three files. No admin UI write is present.', 'Changing this value shifts the screen width at which the first CSS layout reduction is applied in both themes.', 'Integer pixel value; default is computed as round($nbtopmenuentries * 90, 0) + 340 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:9148|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC1'', round($nbtopmenuentries * 90, 0) + 340); ?>px)\t/* reduction 1 */", "theme/md/btn.inc.php:426|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC1'', round($nbtopmenuentries * 90, 0) + 340); ?>px)\t/* reduction 1 */", "theme/md/style.css.php:8932|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC1'', round($nbtopmenuentries * 90, 0) + 340); ?>px)\t/* reduction 1 */"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_WITDHOFFSET_FOR_REDUC2', 'string', NULL, 'theme', 'Overrides the pixel width breakpoint at which the Eldy/MD theme applies the second-level responsive menu reduction.', 'Read in theme/eldy/btn.inc.php:377, theme/eldy/global.inc.php:9188, theme/md/btn.inc.php:434, and theme/md/style.css.php:8961 as the max-width media query breakpoint for ''reduction 2''. When unset, the breakpoint is calculated as round($nbtopmenuentries * 69, 0) + 130. No admin UI write path is present in the payload.', 'Setting this to a pixel value fixes the responsive breakpoint for the second menu-reduction level. Leaving it unset causes the breakpoint to be computed from the number of top menu entries.', 'Integer pixel value for the max-width media query breakpoint. Default computed as round($nbtopmenuentries * 69, 0) + 130.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:9188|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC2'', round($nbtopmenuentries * 69, 0) + 130); ?>px)\t/* reduction 2 */", "theme/md/style.css.php:8961|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC2'', round($nbtopmenuentries * 66, 0) + 220); ?>px)\t/* reduction 2 */", "theme/eldy/btn.inc.php:377|read|@media only screen and (max-width: <?php echo !getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC2'') ? round($nbtopmenuentries * 69, 0) + 130 : $conf->global->THEME_ELDY_WITDHOFF"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ELDY_WITDHOFFSET_FOR_REDUC3', 'string', NULL, 'theme', 'Overrides the pixel width breakpoint at which the Eldy/MD theme applies the third-level responsive menu reduction.', 'Read in theme/eldy/btn.inc.php:385, theme/eldy/global.inc.php:2174, :2755, :9220, theme/md/btn.inc.php:442, theme/md/style.css.php:2280, and :9002 as the min-width or max-width media query breakpoint for ''reduction 3''. When unset, the breakpoint is calculated as round($nbtopmenuentries * 47, 0) + 130. No admin UI write path is present in the payload.', 'Setting this to a pixel value fixes the responsive breakpoint for the third menu-reduction level. Leaving it unset causes the breakpoint to be computed from the number of top menu entries.', 'Integer pixel value for the media query breakpoint. Default computed as round($nbtopmenuentries * 47, 0) + 130.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:2174|read|@media only screen and (min-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC3'', round($nbtopmenuentries * 47, 0) + 130); ?>px)\t/* reduction 3 */", "theme/eldy/global.inc.php:2755|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC3'', round($nbtopmenuentries * 47, 0) + 130); ?>px)\t/* reduction 3 */", "theme/eldy/global.inc.php:9220|read|@media only screen and (max-width: <?php echo getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC3'', round($nbtopmenuentries * 47, 0) + 130); ?>px)\t/* reduction 3 */", "theme/md/btn.inc.php:442|read|@media only screen and (max-width: <?php echo !getDolGlobalString(''THEME_ELDY_WITDHOFFSET_FOR_REDUC3'') ? round($nbtopmenuentries * 47, 0) + 130 : getDolGlobalInt(''THEME_ELDY_WITDHO"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ENABLE_STICKY_COLUMN_ACTION', 'bool', NULL, 'theme', 'Enables CSS sticky positioning for the action column in list tables in the MD theme.', 'Checked once at theme/md/style.css.php:4595 to conditionally output sticky CSS rules. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant makes the action column remain visible when scrolling horizontally in list views using the MD theme.', '0 (not sticky) or 1 (sticky action column)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/md/style.css.php:4595|check|<?php if (getDolGlobalString(''THEME_ENABLE_STICKY_COLUMN_ACTION'')) { ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_ENABLE_STICKY_COLUMN_REF', 'bool', NULL, 'theme', 'Enables CSS sticky positioning for the reference column in list tables in the MD theme.', 'Checked once at theme/md/style.css.php:4582 to conditionally output sticky CSS rules. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant makes the reference column remain visible when scrolling horizontally in list views using the MD theme.', '0 (not sticky) or 1 (sticky reference column)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/md/style.css.php:4582|check|<?php if (getDolGlobalString(''THEME_ENABLE_STICKY_COLUMN_REF'')) { ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_FONT_FAMILY', 'string', NULL, 'theme', 'Prepends a custom font family to the CSS font stack used by the Eldy and MD themes.', 'Read in theme/eldy/style.css.php:193 and theme/md/style.css.php:196 where the value is prepended to $fontlist for CSS output. No admin UI is present.', 'Setting this value causes the specified font family to take priority in the theme''s font stack, changing the typeface rendered throughout the UI.', 'String: CSS font-family name (e.g. ''Roboto'', ''Arial''). Empty or unset uses the theme default font stack.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/style.css.php:192|check|if (getDolGlobalString(''THEME_FONT_FAMILY'')) {", "theme/eldy/style.css.php:193|read|$fontlist = getDolGlobalString(''THEME_FONT_FAMILY'').'', ''.$fontlist;", "theme/md/style.css.php:195|check|if (getDolGlobalString(''THEME_FONT_FAMILY'')) {", "theme/md/style.css.php:196|read|$fontlist = getDolGlobalString(''THEME_FONT_FAMILY'').'', ''.$fontlist;"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_INFOBOX_COLOR_ON_BACKGROUND', 'string', NULL, 'theme', 'When enabled, applies a colour-on-background style variant to info boxes in the Eldy and MD themes.', 'Checked in theme/eldy/info-box.inc.php:375, theme/md/info-box.inc.php:41, and theme/md/info-box.inc.php:489 to conditionally apply an alternative info-box rendering style. No admin UI write path is present in the payload.', 'Enabling this constant switches info boxes to a colour-on-background visual style. Leaving it unset uses the default info-box style.', 'Truthy value to enable colour-on-background style; unset or 0 for default style.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/info-box.inc.php:375|check|if (getDolGlobalString(''THEME_INFOBOX_COLOR_ON_BACKGROUND'')) {", "theme/md/info-box.inc.php:41|check|if (getDolGlobalString(''THEME_INFOBOX_COLOR_ON_BACKGROUND'')) {", "theme/md/info-box.inc.php:489|check|if (getDolGlobalString(''THEME_INFOBOX_COLOR_ON_BACKGROUND'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_MENU_COLORLOGO', 'string', NULL, 'theme', 'When enabled, uses a colour version of the logo in the menu; when disabled, a monochrome or alternative logo is used.', 'Checked in theme/eldy/main_menu_fa_icons.inc.php:138 and theme/md/main_menu_fa_icons.inc.php:106 to decide which logo variant to render in the menu. Displayed as a yes/no value in core/lib/usergroups.lib.php:602. No admin UI write path is present in the payload.', 'Enabling this constant switches the menu logo to its colour variant. Leaving it unset causes the alternative (non-colour) logo to be used.', 'Truthy value to use colour logo in menu; unset or 0 to use alternative logo.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/main_menu_fa_icons.inc.php:138|check|if (!getDolGlobalString(''THEME_MENU_COLORLOGO'')) {", "theme/md/main_menu_fa_icons.inc.php:106|check|if (!getDolGlobalString(''THEME_MENU_COLORLOGO'')) {", "core/lib/usergroups.lib.php:602|read|print yn(getDolGlobalString(''THEME_MENU_COLORLOGO''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_SATURATE_RATIO', 'string', NULL, 'theme', 'Controls the CSS saturation ratio applied to info-box colours in the Eldy and MD themes.', 'Written at runtime to $conf->global->THEME_SATURATE_RATIO in theme/eldy/info-box.inc.php:380, :383 and theme/md/info-box.inc.php:46, :49, :494, :497. The value is obtained from user input via GETPOSTFLOAT or defaulted to 0.8. Checked before applying saturation styling in theme/eldy/info-box.inc.php:392 and theme/md/info-box.inc.php:269.', 'Adjusting this value changes the CSS colour saturation intensity of info boxes. A value of 0.8 is used as the runtime default.', 'Float between 0 and 1 (e.g. 0.8). Runtime default is 0.8.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/info-box.inc.php:380|write|$conf->global->THEME_SATURATE_RATIO = 0.8;", "theme/eldy/info-box.inc.php:383|write|$conf->global->THEME_SATURATE_RATIO = GETPOSTFLOAT(''THEME_SATURATE_RATIO'');", "theme/eldy/info-box.inc.php:392|check|<?php if (getDolGlobalString(''THEME_SATURATE_RATIO'')) { ?>", "theme/md/info-box.inc.php:269|check|<?php if (getDolGlobalString(''THEME_SATURATE_RATIO'')) { ?>"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_SHOW_BORDER_ON_INPUT', 'bool', NULL, 'theme', 'When enabled, displays visible borders on input fields in the Eldy theme.', 'Checked across 24 occurrences in theme/eldy/global.inc.php to conditionally apply or suppress input border CSS rules. No admin UI write is present in the payload.', 'Enabling this constant adds visible borders to form input fields throughout the Eldy theme interface.', 'Boolean flag; unset or 0 = input borders hidden; any truthy value = input borders shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:372|check|<?php if (getDolGlobalString(''THEME_SHOW_BORDER_ON_INPUT'')) { ?>", "theme/eldy/global.inc.php:450|check|<?php if (!getDolGlobalString(''THEME_SHOW_BORDER_ON_INPUT'')) { ?>", "core/lib/usergroups.lib.php:664|check|if (getDolGlobalString(''THEME_ELDY_USEBORDERONTABLE'') || getDolGlobalString(''THEME_SHOW_BORDER_ON_INPUT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_STICKY_TOPMENU', 'string', NULL, 'theme', 'Controls the sticky behavior of the top menu bar in the Eldy and MD themes.', 'Checked in theme/eldy/global.inc.php:2581, :2646, :2661 and theme/md/style.css.php:2800 against specific string values to apply different sticky scroll behaviors. Four occurrences across two files. No admin UI write is present.', 'Changing this value alters how the top menu sticks or scrolls relative to page content.', 'String; ''disabled'' = top menu not sticky; ''scrollleftmenu_after_mainpage'' = left menu scrolls after main page; other truthy values = standard sticky behavior.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:2581|check|<?php if (getDolGlobalString(''THEME_STICKY_TOPMENU'') == ''scrollleftmenu_after_mainpage'') { ?>", "theme/eldy/global.inc.php:2646|check|<?php if (getDolGlobalString(''THEME_STICKY_TOPMENU'') != ''disabled'') {  ?>", "theme/md/style.css.php:2800|check|<?php if (getDolGlobalString(''THEME_STICKY_TOPMENU'') != ''disabled'') {  ?>"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_TOPMENU_DISABLE_IMAGE', 'bool', NULL, 'core', 'Controls whether images or text are displayed in the top menu items.', 'Written via admin/ihm.php:140 and deleted via admin/ihm.php:138. Checked across theme/eldy/global.inc.php and theme/md/style.css.php against values 2, 3, and 4. COMMENTS state: ''To show text of top menu according to option THEME_TOPMENU_DISABLE_IMAGE'' and ''Text hidden by default when option THEME_TOPMENU_DISABLE_IMAGE''. Twenty-one occurrences across multiple files.', 'Changing this value switches the top menu between image-only, text-only, and combined display modes.', 'Integer; 0 or unset = images shown (text hidden by default); 2 = text shown alongside images; 3 = specific text-only variant; 4 = another display variant.', 0, 0, 'admin/ihm.php|admin/ihm.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["theme/eldy/global.inc.php:3407  /* To show text of top menu according to option THEME_TOPMENU_DISABLE_IMAGE */", "theme/eldy/global.inc.php:3409  /* Text hidden by default when option THEME_TOPMENU_DISABLE_IMAGE */", "theme/eldy/global.inc.php:3410|check|<?php if (in_array(getDolGlobalInt(''THEME_TOPMENU_DISABLE_IMAGE''), array(2, 3, 4))) { ?>", "admin/ihm.php:140|write|dolibarr_set_const($db, ''THEME_TOPMENU_DISABLE_IMAGE'', GETPOST(''THEME_TOPMENU_DISABLE_IMAGE''), ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THEME_TOPMENU_DISABLE_TEXT', 'bool', NULL, 'core', 'Disables text labels on top-menu entries, showing only icons.', 'Checked in 6 occurrences across auguria.lib.php, eldy.lib.php, and empty.php menu files. When set, the text alongside top-menu icons is suppressed.', 'Setting this constant hides menu item labels in the top navigation bar, resulting in an icon-only menu.', 'Non-empty = text labels hidden; empty or unset = text labels shown', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/menus/standard/auguria.lib.php:271|check|if (!getDolGlobalString(''THEME_TOPMENU_DISABLE_TEXT'')) {", "core/menus/standard/eldy.lib.php:689|check|if (!getDolGlobalString(''THEME_TOPMENU_DISABLE_TEXT'')) {", "core/menus/standard/empty.php:574|check|if (!getDolGlobalString(''THEME_TOPMENU_DISABLE_TEXT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTIES_DISABLE_RELATED_OBJECT_TAB', 'bool', NULL, 'core', 'Hides the Related Objects tab on third-party records when set.', 'Read at core/lib/company.lib.php:205 as a negated check; the tab is shown only when this constant is not set. No comment is present in the payload.', 'Setting this constant removes the Related Objects tab from third-party pages, reducing UI clutter for installations that do not need cross-object navigation.', 'Any truthy value disables (hides) the tab; unset or empty shows it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/company.lib.php:205|read|&& !getDolGlobalString(''THIRDPARTIES_DISABLE_RELATED_OBJECT_TAB'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_CAN_HAVE_CUSTOMER_CATEGORY_EVEN_IF_NOT_CUSTOMER_PROSPECT', 'string', NULL, 'societe', 'When enabled, allows assigning customer categories to third parties that are not marked as customers or prospects.', 'Checked in societe/card.php:3294 alongside prospect/client status checks, and read in societe/card.php:1286 and :2278 to set JavaScript variables controlling category UI behavior. Three occurrences in one file.', 'Enabling this constant removes the customer/prospect status requirement for customer category assignment on third-party cards.', 'Boolean flag; unset or 0 = customer category only shown for customers/prospects; any truthy value = shown for all third parties.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:3294|check|if ($object->prospect || $object->client || getDolGlobalString(''THIRDPARTY_CAN_HAVE_CUSTOMER_CATEGORY_EVEN_IF_NOT_CUSTOMER_PROSPECT'')) {", "societe/card.php:1286|read|var canHaveCustomerCategoryIfNotCustomerProspectSupplier = '' . (!getDolGlobalString(''THIRDPARTY_CAN_HAVE_CUSTOMER_CATEGORY_EVEN_IF_NOT_CUSTOMER_PROSPECT'') ? ''0'' : ''1'') . '';", "societe/card.php:2278|read|var canHaveCustomerCategoryIfNotCustomerProspect = '' . (getDolGlobalInt(''THIRDPARTY_CAN_HAVE_CUSTOMER_CATEGORY_EVEN_IF_NOT_CUSTOMER_PROSPECT'') ? ''1'' : ''0'') . '';"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_CUSTOMERCODE_EQUALS_MEMBERREF', 'string', NULL, 'societe', 'Makes the customer code of a third party equal to their member reference.', 'Checked in societe/class/societe.class.php at line 4722; only one occurrence found in payload.', 'When set, the customer code is derived from or synchronized with the member reference during third-party operations.', '0 or empty = customer code generated normally; any truthy value = customer code equals member reference', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4722|check|if (getDolGlobalString(''THIRDPARTY_CUSTOMERCODE_EQUALS_MEMBERREF'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_CUSTOMERPROSPECT_BY_DEFAULT', 'string', NULL, 'societe', 'When enabled, pre-selects the customer/prospect type on new third-party creation forms.', 'Checked in societe/card.php:1049 to conditionally apply a default customer/prospect designation. Only one occurrence is present in the payload. No admin UI write is present.', 'Enabling this constant causes new third parties to default to a customer/prospect status without requiring manual selection.', 'Boolean flag; unset or 0 = no default; any truthy value = customer/prospect pre-selected by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1049|check|if (getDolGlobalString(''THIRDPARTY_CUSTOMERPROSPECT_BY_DEFAULT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_CUSTOMERTYPE_BY_DEFAULT', 'string', NULL, 'societe', 'Sets the default customer type pre-selected when creating a new third party.', 'Written in societe/admin/societe.php:111 and read in societe/admin/societe.php:955 for display in the admin UI. Used in societe/card.php:1055 and :1056 to pre-populate the client field and in :1479/:1480 to pre-select customer or prospect status based on the value.', 'Changing this value alters the default customer classification applied to all newly created third parties. A value of 1 pre-selects customer; a value of 2 pre-selects prospect.', 'Integer; 1 = customer pre-selected by default, 2 = prospect pre-selected by default, 0 or unset = no default.', 0, 0, 'societe/admin/societe.php|societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1056|read|$object->client = getDolGlobalInt(''THIRDPARTY_CUSTOMERTYPE_BY_DEFAULT'');", "societe/card.php:1479|read|$selectedcustomer = ((getDolGlobalInt(''THIRDPARTY_CUSTOMERTYPE_BY_DEFAULT'')==1 && GETPOST(\"type\", ''aZ'') != ''p'' && GETPOST(\"type\", ''aZ'') != ''f'') || (getDolGlobalInt(''THIRDPARTY_CUST", "societe/admin/societe.php:111|write|$res = dolibarr_set_const($db, \"THIRDPARTY_CUSTOMERTYPE_BY_DEFAULT\", $customertypedefault, ''chaine'', 0, '''', $conf->entity);", "societe/admin/societe.php:955|read|print $formcompany->selectProspectCustomerType(getDolGlobalInt(''THIRDPARTY_CUSTOMERTYPE_BY_DEFAULT''), ''defaultcustomertype'', ''defaultcustomertype'', ''admin'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_DEFAULT_CREATE_CONTACT', 'string', NULL, 'societe', 'Automatically creates a default contact when a new third party is created.', 'Checked in societe/class/societe.class.php at line 4738 and in societe/card.php at line 1009, where contact creation is triggered for non-private, non-individual new third parties.', 'Enabling this constant causes a contact record to be created automatically alongside new third party records that meet the conditions.', '0 or empty = no automatic contact creation; any truthy value = contact created automatically', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/class/societe.class.php:4738|check|if (getDolGlobalString(''THIRDPARTY_DEFAULT_CREATE_CONTACT'')) {", "societe/card.php:1009|check|if (getDolGlobalString(''THIRDPARTY_DEFAULT_CREATE_CONTACT'') && !GETPOSTISSET(''private'') && GETPOST(\"type\", ''aZ'') != ''f'') {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_DEFAULT_USELOCALTAX1', 'string', NULL, 'societe', 'When set, pre-checks the local tax 1 (IRPF/equivalent) subject checkbox on new third-party forms.', 'Read in societe/card.php:1837 and :1847 to conditionally set the ''checked'' attribute on the localtax1assuj_value checkbox. Only two occurrences in one file. No admin UI write is present.', 'Setting this constant causes the local tax 1 subject checkbox to appear checked by default on third-party creation forms.', 'Boolean flag; unset or 0 = checkbox unchecked by default; any truthy value = checkbox pre-checked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1837|read|print ''<input id=\"localtax1assuj_value\" name=\"localtax1assuj_value\" type=\"checkbox\" '' . (getDolGlobalString(''THIRDPARTY_DEFAULT_USELOCALTAX1'') ? ''checked=\"checked\"'' : '''') . '' value", "societe/card.php:1847|read|print ''<input id=\"localtax1assuj_value\" name=\"localtax1assuj_value\" type=\"checkbox\" '' . (getDolGlobalString(''THIRDPARTY_DEFAULT_USELOCALTAX1'') ? ''checked=\"checked\"'' : '''') . '' value"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_DEFAULT_USELOCALTAX2', 'string', NULL, 'societe', 'When set, pre-checks the local tax 2 (IRPF/equivalent) subject checkbox on new third-party forms.', 'Read in societe/card.php:1843 and :1851 to conditionally set the ''checked'' attribute on the localtax2assuj_value checkbox. Only two occurrences in one file. No admin UI write is present.', 'Setting this constant causes the local tax 2 subject checkbox to appear checked by default on third-party creation forms.', 'Boolean flag; unset or 0 = checkbox unchecked by default; any truthy value = checkbox pre-checked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1843|read|print ''<input id=\"localtax2assuj_value\" name=\"localtax2assuj_value\" type=\"checkbox\" '' . (getDolGlobalString(''THIRDPARTY_DEFAULT_USELOCALTAX2'') ? ''checked=\"checked\"'' : '''') . '' value", "societe/card.php:1851|read|print ''<input id=\"localtax2assuj_value\" name=\"localtax2assuj_value\" type=\"checkbox\" '' . (getDolGlobalString(''THIRDPARTY_DEFAULT_USELOCALTAX2'') ? ''checked=\"checked\"'' : '''') . '' value"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES', 'bool', NULL, 'contact', 'Enables prospect-level tracking on contact records (alternative addresses) in addition to the thirdparty level.', 'When not set, there is no prospect level on contact level, only on thirdparty (contact/class/contact.class.php:403). When set, prospect-related dictionary entries and UI fields are activated in admin/dict.php, contact/card.php, and contact/list.php.', 'Enabling this constant activates prospect status management on contacts; disabling it restricts prospect tracking to the thirdparty level only.', 'Empty/unset = no prospect level on contacts (default); non-empty = prospect level enabled on contacts.', 0, 0, 'admin/dict.php|admin/dict.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["contact/class/contact.class.php:403  // If THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES not set, there is no prospect level on contact level, only on thirdparty", "contact/class/contact.class.php:404|check|if (getDolGlobalString(''SOCIETE_DISABLE_PROSPECTS'') || !getDolGlobalString(''THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES'')) {\t// Default behaviour", "admin/dict.php:593|read|$tabcond[DICT_STCOMMCONTACT] = (isModEnabled(\"societe\") && getDolGlobalString(''THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES''));", "contact/card.php:1420|check|if (getDolGlobalString(''THIRDPARTY_ENABLE_PROSPECTION_ON_ALTERNATIVE_ADRESSES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_INCLUDE_PARENT_IN_LINKTO', 'string', NULL, 'core', 'When enabled, includes the parent company of the linked third party in element link-to selectors.', 'Checked at core/class/html.form.class.php:10489. When the object''s third party has a parent (parent > 0) AND this constant is set, the parent is included in the link-to list.', 'Enabling widens the set of linkable third parties to include parent companies. Disabling restricts link-to selection to only the directly associated third party.', 'Truthy = include parent thirdparty in link-to selector when parent exists; empty/unset = do not include parent.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:10489|check|if (($object->thirdparty->parent > 0) && getDolGlobalString(''THIRDPARTY_INCLUDE_PARENT_IN_LINKTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_INCLUDE_PROJECT_THIRDPARY_IN_LINKTO', 'string', NULL, 'core', 'When enabled, includes the project''s associated third party in element link-to selectors.', 'Checked at core/class/html.form.class.php:10492. When the object has an associated project (fk_project > 0) AND this constant is set, the project''s third party is added to the link-to list.', 'Enabling widens link-to selection to include the project''s third party. Disabling restricts it to directly associated parties only.', 'Truthy = include project''s thirdparty in link-to selector when project exists; empty/unset = do not include.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:10492|check|if (($object->fk_project > 0) && getDolGlobalString(''THIRDPARTY_INCLUDE_PROJECT_THIRDPARY_IN_LINKTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_LIMIT_SIZE', 'string', NULL, 'core', 'Sets the maximum number of third-party records returned in third-party search/select queries.', 'Read as an integer at core/class/html.form.class.php:7149 via getDolGlobalInt, and stored in $limit for use in third-party search queries. Exact behavior unclear from code alone (only one occurrence found).', 'Setting a low value limits search results and improves performance on large databases. Setting it to 0 or leaving it unset applies the system default limit.', 'Integer: number of records to return; 0 or unset = system default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:7149|read|$limit = getDolGlobalInt(''THIRDPARTY_LIMIT_SIZE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_LOGO_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'societe', 'When enabled, allows the third-party logo to be accessible for external download.', 'Checked in societe/card.php:608 and societe/card.php:781 to conditionally expose logo download functionality. No admin UI write is present; only two occurrences in one file.', 'Enabling this constant makes third-party logos accessible externally. Disabling it restricts logo access.', 'Boolean flag; unset or 0 = external logo download not allowed; any truthy value = allowed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:608|check|if (getDolGlobalString(''THIRDPARTY_LOGO_ALLOW_EXTERNAL_DOWNLOAD'')) {", "societe/card.php:781|check|if (getDolGlobalString(''THIRDPARTY_LOGO_ALLOW_EXTERNAL_DOWNLOAD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_MAX_NB_PROF_ID', 'string', NULL, 'societe', 'Sets the maximum number of professional ID fields displayed on third-party cards.', 'Read in societe/card.php:1752, :2621, and :3083 into $NBPROFIDMAX with a default of 6. Three occurrences in one file. No admin UI write is present.', 'Changing this value controls the upper bound of professional ID fields rendered on third-party creation and edit forms.', 'Integer; default is 6 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1752|read|$NBPROFIDMAX = getDolGlobalInt(''THIRDPARTY_MAX_NB_PROF_ID'', 6);", "societe/card.php:2621|read|$NBPROFIDMAX = getDolGlobalInt(''THIRDPARTY_MAX_NB_PROF_ID'', 6);", "societe/card.php:3083|read|$NBPROFIDMAX = getDolGlobalInt(''THIRDPARTY_MAX_NB_PROF_ID'', 6);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_MIN_NB_PROF_ID', 'string', NULL, 'societe', 'Sets the minimum number of professional ID fields displayed on third-party cards.', 'Read in societe/card.php:1751, :2620, and :3083 into $NBPROFIDMIN with a default of 2. Three occurrences in one file. No admin UI write is present.', 'Changing this value controls the lower bound of professional ID fields rendered on third-party creation and edit forms.', 'Integer; default is 2 when unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1751|read|$NBPROFIDMIN = getDolGlobalInt(''THIRDPARTY_MIN_NB_PROF_ID'', 2);", "societe/card.php:2620|read|$NBPROFIDMIN = getDolGlobalInt(''THIRDPARTY_MIN_NB_PROF_ID'', 2);", "societe/card.php:3082|read|$NBPROFIDMIN = getDolGlobalInt(''THIRDPARTY_MIN_NB_PROF_ID'', 2);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_INVOICE', 'string', NULL, 'compta', 'When enabled, copies extra fields from the linked third-party into newly created invoices.', 'Checked in compta/facture/card.php:4612 during invoice creation and in core/class/commonobject.class.php:9689 in a general extra-field propagation condition.', 'Enabling this constant causes the third-party''s extra fields to be copied to invoices, allowing custom third-party attributes to appear on invoice records.', '0 or unset = extra fields not propagated; truthy = third-party extra fields copied to invoice.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/card.php:4612|check|if (getDolGlobalString(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_INVOICE'') && !empty($soc->id)) {", "core/class/commonobject.class.php:9689|read|($this->element == ''facture'' && getDolGlobalInt(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_INVOICE''))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_ORDER', 'string', NULL, 'core', 'Enables automatic propagation of third-party extrafields to customer orders.', 'Checked in commande/card.php:2489 and core/class/commonobject.class.php:9690. When set, extrafields from the linked third-party are copied to the order on creation or update.', 'Enabling this constant causes third-party extrafield values to be copied onto new orders; disabling it leaves order extrafields unaffected by the third-party record.', 'Non-empty/non-zero = propagation enabled; empty or 0 = disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["commande/card.php:2489|check|if (getDolGlobalString(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_ORDER'') && !empty($soc->id)) {", "core/class/commonobject.class.php:9690|read||| ($this->element == ''commande'' && getDolGlobalInt(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_ORDER''))"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_PROPAL', 'string', NULL, 'comm', 'Controls whether extra fields from the linked third-party are propagated to the proposal on creation.', 'When set to a non-zero integer, extra fields from the third-party (socid) are copied to the proposal record at creation time. Seen in comm/propal/card.php:2604.', 'Enabling this causes third-party custom field values to be automatically applied to new proposals linked to that third-party.', '0 or unset = no propagation; non-zero integer = propagate third-party extra fields to proposal.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:2604|check|if (getDolGlobalInt(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_PROPAL'') && $socid > 0) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_SUPPLIER_ORDER', 'string', NULL, 'fourn', 'Propagates third-party extra fields to supplier orders when the supplier is set or changed.', 'Checked in fourn/commande/card.php:2175 and core/class/commonobject.class.php:9691. When set, extra fields from the selected third party are copied to the supplier order.', 'Enabling this ensures custom third-party attributes are automatically populated on new or updated supplier orders.', 'Empty/0 = extra fields not propagated; truthy = third-party extra fields copied to supplier order', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["fourn/commande/card.php:2175|check|if (getDolGlobalString(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_SUPPLIER_ORDER'') && !empty($societe->id)) {", "core/class/commonobject.class.php:9691|read||| ($this->element == ''order_supplier'' && getDolGlobalInt(''THIRDPARTY_PROPAGATE_EXTRAFIELDS_TO_SUPPLIER_ORDER''))"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_PUBLIC_INTERFACE_TOPIC', 'string', NULL, 'public', 'Sets the topic/title string displayed in the public third-party registration page header.', 'Read at public/company/new.php:131 as the topic argument to htmlPrintOnlineHeader(). No admin UI write found.', 'If set, the public company registration page header displays this custom topic string.', 'Any string used as the public third-party interface header topic.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/company/new.php:131|read|htmlPrintOnlineHeader($mysoc, $langs, 1, getDolGlobalString(''THIRDPARTY_PUBLIC_INTERFACE_TOPIC''), ''THIRDPARTY_PUBLIC_INTERFACE_IMAGE'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_QUICKSEARCH_ON_FIELDS', 'string', NULL, 'societe', 'Overrides the default fields used for quick-search in the third-party list with a custom semicolon-separated field=label mapping.', 'When set, the third-party list page uses the field definitions from this constant instead of its default search fields. The value is a semicolon-separated string of SQL_field=LabelKey pairs. No admin UI; must be set directly in the database.', 'Changing this value alters which database columns are searched when using the quick-search on the third-party list. Removing it restores the default search field set.', 'Semicolon-separated field=label pairs, e.g. ''s.nom=ThirdPartyName;s.name_alias=AliasNameShort;s.code_client=CustomerCode''', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/list.php:267  // Personalized search criteria. Example: $conf->global->THIRDPARTY_QUICKSEARCH_ON_FIELDS = ''s.nom=ThirdPartyName;s.name_alias=AliasNameShort;s.code_client=CustomerCode''", "societe/list.php:268|check|if (getDolGlobalString(''THIRDPARTY_QUICKSEARCH_ON_FIELDS'')) {", "societe/list.php:269|read|$fieldstosearchall = dolExplodeIntoArray(getDolGlobalString(''THIRDPARTY_QUICKSEARCH_ON_FIELDS''));"]', 'medium', NULL);
