INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_SEARCH_AUTOFOCUS', 'string', NULL, 'core', 'Enables autofocus on the third-party search input field in combobox/select widgets.', 'In core/class/html.form.class.php, the autofocus HTML attribute on the search input for third-party selection is controlled by this constant. Only one occurrence in the payload; no admin UI write; hidden setting.', 'Enabling this constant causes the third-party search field to receive focus automatically when the selector opens; disabling it leaves focus management to the browser default.', 'Non-empty (truthy) enables autofocus; empty or undefined disables it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:1438|read|$out .= ''<input type=\"text\" class=\"'' . $morecss . ''\" name=\"search_'' . $htmlname . ''\" id=\"search_'' . $htmlname . ''\" value=\"'' . $selected_input_value . ''\"''"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_SUGGEST_ALSO_ADDRESS_CREATION', 'string', NULL, 'societe', 'When enabled, presents an option to also create an address when creating a new third party.', 'Configured via societe/admin/societe.php and checked in societe/card.php:1208, :1458, :1727, :1867 and public/company/new.php:407. Six occurrences across two files.', 'Enabling this constant adds an address creation prompt to the third-party creation workflow, including the public company registration form.', 'Boolean flag; unset or 0 = address creation not suggested; any truthy value = suggestion shown.', 0, 0, 'societe/admin/societe.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1208|check|if (getDolGlobalString(''THIRDPARTY_SUGGEST_ALSO_ADDRESS_CREATION'')) {", "societe/card.php:1727|check|if (isModEnabled(''mailing'') && getDolGlobalString(''THIRDPARTY_SUGGEST_ALSO_ADDRESS_CREATION'')) {", "public/company/new.php:407|check|if (isModEnabled(''mailing'') && getDolGlobalString(''THIRDPARTY_SUGGEST_ALSO_ADDRESS_CREATION'')) {", "societe/admin/societe.php:963|check|if (getDolGlobalString(''THIRDPARTY_SUGGEST_ALSO_ADDRESS_CREATION'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('THIRDPARTY_SUPPLIER_BY_DEFAULT', 'string', NULL, 'societe', 'When enabled, pre-selects the supplier type on new third-party creation forms when supplier modules are active.', 'Checked in societe/card.php:1069 alongside supplier module checks to conditionally apply supplier status by default. Only one occurrence is present in the payload. No admin UI write is present.', 'Enabling this constant causes new third parties to default to supplier status when the supplier order or invoice module is active.', 'Boolean flag; unset or 0 = no supplier default; any truthy value = supplier pre-selected by default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["societe/card.php:1069|check|if ((isModEnabled(\"supplier_order\") || isModEnabled(\"supplier_invoice\")) && (GETPOST(\"type\") == ''f'' || (GETPOST(\"type\") == '''' && getDolGlobalString(''THIRDPARTY_SUPPLIER_BY_DEFAULT'')"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKETS_MESSAGE_FORCE_MAIL', 'string', NULL, 'core', 'When set, pre-checks the send-email checkbox on the ticket message form.', 'Used in a single location in core/class/html.formticket.class.php:1649 where the checkbox_selected variable is set to ''checked'' if getDolGlobalInt returns a truthy value (and the POST value is not explicitly ''1'').', 'Enabling this defaults the send-email checkbox to checked on the ticket message form. Disabling (or leaving unset) leaves the checkbox unchecked by default.', '0 or unset = send-email checkbox unchecked by default; non-zero = send-email checkbox pre-checked.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["html.formticket.class.php:1649|$checkbox_selected = (GETPOST(''send_email'') == \"1\" ? '' checked'' : (getDolGlobalInt(''TICKETS_MESSAGE_FORCE_MAIL'') ? ''checked'' : ''''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKETS_NO_COMPANY_ON_FORM', 'string', NULL, 'core', 'When set, hides the company/third-party field on the ticket form.', 'Used in a single location in core/class/html.formticket.class.php:214, where $this->withcompany is computed as 1 only when both this constant is falsy and the societe module is enabled.', 'Enabling this removes the company selector from the ticket form regardless of whether the societe module is active. Disabling (or leaving unset) shows the company field when the societe module is enabled.', '0 or unset = company field shown (if societe module enabled); non-zero = company field hidden.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["html.formticket.class.php:214|$this->withcompany = (int) (!getDolGlobalInt(\"TICKETS_NO_COMPANY_ON_FORM\") && isModEnabled(\"societe\"));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ADDON', 'string', NULL, 'admin', 'Specifies the numbering module class used to generate ticket reference numbers.', 'Written in admin/ticket.php at line 151 and read in ticket/class/ticket.class.php at line 2552 and emailcollector/class/emailcollector.class.php at line 3669, both with ''mod_ticket_simple'' as default.', 'Changing this constant switches the ticket reference numbering scheme. If the specified module does not exist, ticket number generation will fail.', 'String class name of a numbering module (default: ''mod_ticket_simple'')', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["dolibarr_set_const($db, \"TICKET_ADDON\", $value, ''chaine'', 0, '''', $conf->entity);", "$modele = getDolGlobalString(''TICKET_ADDON'', ''mod_ticket_simple'');", "if (getDolGlobalString(''TICKET_ADDON'') == ''mod_''.$classname) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ADDON_PDF', 'string', NULL, 'admin', 'Selects the PDF generation module (template) used when producing PDF documents for tickets.', 'Configured via the ticket admin UI (admin/ticket.php:136, :139). The selected module name is compared against available templates (admin/ticket.php:117, :509) and used at document generation time to determine which PDF module to load (ticket/class/ticket.class.php:3479, :3480).', 'Changing this value switches the PDF template applied when generating ticket documents. Deleting it (admin/ticket.php:118) reverts to the default template.', 'String name of a PDF module/template class available for the ticket module.', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ticket.php:136|write|if (dolibarr_set_const($db, \"TICKET_ADDON_PDF\", $value, ''chaine'', 0, '''', $conf->entity)) {", "ticket/class/ticket.class.php:3479|read|} elseif (getDolGlobalString(''TICKET_ADDON_PDF'')) {", "ticket/class/ticket.class.php:3480|read|$modele = getDolGlobalString(''TICKET_ADDON_PDF'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ADDON_PDF_ODT_PATH', 'string', NULL, 'core', 'Specifies the directory path(s) to scan for ODT document templates used in ticket PDF generation.', 'Read in core/modules/ticket/doc/doc_generic_ticket_odt.modules.php at line 121, where the value is split on commas and newlines to produce a list of directories to scan for ODT templates. Also displayed in the module info text at line 148.', 'Changing this value redirects the ODT template search to the specified directories; an empty or unset value results in no directories being scanned.', 'Comma- or newline-separated list of directory paths.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/ticket/doc/doc_generic_ticket_odt.modules.php:121|read|$listofdir = explode('','', preg_replace(''/[\\r\\n]+/'', '','', trim(getDolGlobalString(''TICKET_ADDON_PDF_ODT_PATH''))));", "core/modules/ticket/doc/doc_generic_ticket_odt.modules.php:148|read|$texte .= getDolGlobalString(''TICKET_ADDON_PDF_ODT_PATH'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ADD_AUTHOR_AS_CONTACT', 'string', NULL, 'ticket', 'Automatically adds the ticket author as a contact on the ticket, with mode 2 also linking external user contacts.', 'Checked in ticket/class/ticket.class.php at lines 587 and 591. At line 587 the author is added as a contact when the ticket is not created from the public interface. At line 591, when the value equals 2 and the user has a socid and contact_id, the external contact is also linked.', 'Setting to 1 adds internal authors as ticket contacts automatically. Setting to 2 additionally links external user contacts.', '0 or unset = author not added as contact; 1 = author added as contact (backoffice); 2 = author and external user contact added', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (!$error && getDolGlobalString(''TICKET_ADD_AUTHOR_AS_CONTACT'') && empty($this->context[\"createdfrompublicinterface\"])) {", "if (!empty($user->socid) && !empty($user->contact_id) && getDolGlobalInt(''TICKET_ADD_AUTHOR_AS_CONTACT'') == 2) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ASSIGN_CONTACT_TO_MESSAGE', 'string', NULL, 'ticket', 'When set, automatically searches for a contact by email address and assigns them to the ticket when a message is posted from the public area.', 'Configured via a select in admin/ticket_public.php at line 462 and checked in ticket/class/ticket.class.php at line 1942. Phpdoc at lines 1890 and 2754 describes it: ''1 if we are creating the message from a public area (so we can search contact from email to add it as contact of ticket if TICKET_ASSIGN_CONTACT_TO_MESSAGE is set)''.', 'Enabling this constant causes a contact lookup by the sender''s email on each public-area message, automatically linking the found contact to the ticket.', '0 or unset = no automatic contact assignment from email; 1 = contact searched by email and assigned', 0, 0, 'admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* @param\tint<0,1>\t$public_area\t\t0=Default, 1 if we are creating the message from a public area (so we can search contact from email to add it as contact of ticket if TICKET_ASSIGN_CONTACT_TO_MESSAGE is set)", "if ($public_area && !empty($this->origin_email) && getDolGlobalString(''TICKET_ASSIGN_CONTACT_TO_MESSAGE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_AUTO_ASSIGN_USER_CREATE', 'string', NULL, 'admin', 'Controls automatic assignment of the ticket creator as the assigned user when a ticket is created.', 'Configured via the ticket admin UI (admin/ticket.php:162, :613). Checked in ticket/card.php:334: when value is 1, the creator is assigned only if no user is already assigned; when value is 2, the creator is always assigned regardless of existing assignment.', 'Setting to 1 assigns the creator when no assignee exists. Setting to 2 always assigns the creator. Leaving it unset disables automatic assignment.', '0 or unset = no auto-assignment; 1 = assign creator if no assignee; 2 = always assign creator.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:334|check|if ((empty($fk_user_assign) && getDolGlobalInt(''TICKET_AUTO_ASSIGN_USER_CREATE'') == 1) || (getDolGlobalInt(''TICKET_AUTO_ASSIGN_USER_CREATE'') == 2)) {", "admin/ticket.php:613|read|print ''<input class=\"maxwidth50\" type=\"text\" id=\"TICKET_AUTO_ASSIGN_USER_CREATE\" name=\"TICKET_AUTO_ASSIGN_USER_CREATE\" value=\"''.getDolGlobalInt(''TICKET_AUTO_ASSIGN_USER_CREATE'').''\"", "admin/ticket.php:162|write|$res = dolibarr_set_const($db, ''TICKET_AUTO_ASSIGN_USER_CREATE'', $param_auto_assign, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_AUTO_READ_WHEN_ASSIGN', 'string', NULL, 'ticket', 'Controls whether a ticket is automatically marked as read when it is assigned.', 'Configured via a select in admin/ticket.php at line 600 and checked in ticket/class/ticket.class.php at line 1841.', 'When enabled, assigning a ticket triggers an automatic read-mark, preventing the assigned user from seeing it as unread.', '0 or unset = not auto-read on assign; 1 = auto-read on assign', 0, 0, 'admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["print $formcategory->selectarray(\"TICKET_AUTO_READ_WHEN_ASSIGN\", $arrval, getDolGlobalString(''TICKET_AUTO_READ_WHEN_ASSIGN''));", "if (getDolGlobalString(''TICKET_AUTO_READ_WHEN_ASSIGN'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_AUTO_READ_WHEN_CREATED_FROM_BACKEND', 'string', NULL, 'admin', 'Controls whether a ticket is automatically marked as read when created from the backend (admin interface).', 'Configured via the ticket admin UI (admin/ticket.php:156, :585). Checked in ticket/card.php:327 to auto-mark a newly created ticket as read when the creating user has ticket management permissions. The admin email collector list also reads this value (admin/emailcollector_list.php:803).', 'Enabling this causes tickets created from the backend to be immediately marked as read by the creating user. Leaving it unset requires manual marking.', 'Truthy value to enable auto-read on backend creation; unset or 0 to disable.', 0, 0, 'admin/ticket.php|admin/emailcollector_list.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ticket.php:156|write|$res = dolibarr_set_const($db, ''TICKET_AUTO_READ_WHEN_CREATED_FROM_BACKEND'', $param_auto_read, ''chaine'', 0, '''', $conf->entity);", "ticket/card.php:327|check|if (getDolGlobalString(''TICKET_AUTO_READ_WHEN_CREATED_FROM_BACKEND'') && $permissiontomanage) {", "admin/ticket.php:585|read|print $formcategory->selectarray(\"TICKET_AUTO_READ_WHEN_CREATED_FROM_BACKEND\", $arrval, getDolGlobalString(''TICKET_AUTO_READ_WHEN_CREATED_FROM_BACKEND''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_CHECK_NOTIFY_THIRDPARTY_AT_CREATION', 'string', NULL, 'ticket', 'Sets the default state of the ''notify thirdparty at creation'' checkbox when creating a ticket.', 'Configured via the ticket admin UI (admin/ticket.php:85, :762). Used in ticket/card.php:757 to pre-set the withnotifytiersatcreate flag on the ticket form. Also used by the email collector to set notify_tiers_at_create on programmatically created tickets (emailcollector/class/emailcollector.class.php:3642).', 'Enabling this causes the thirdparty notification checkbox to be checked by default on the ticket creation form, and sets notify_tiers_at_create on tickets created via email collection.', 'Truthy value to default-check thirdparty notification at creation; unset or 0 to default-uncheck.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:757|read|$formticket->withnotifytiersatcreate = ($notifyTiers ? 1 : (getDolGlobalString(''TICKET_CHECK_NOTIFY_THIRDPARTY_AT_CREATION'') ? 1 : 0));", "emailcollector/class/emailcollector.class.php:3642|read|$tickettocreate->notify_tiers_at_create = getDolGlobalInt(''TICKET_CHECK_NOTIFY_THIRDPARTY_AT_CREATION'');", "admin/ticket.php:85|write|$res = dolibarr_set_const($db, ''TICKET_CHECK_NOTIFY_THIRDPARTY_AT_CREATION'', $param_disable_email, ''chaine'', 0, '''', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_CLIENT_OTHER_TICKET_ONLY_OPEN', 'string', NULL, 'ticket', 'When enabled, the link to a thirdparty''s other tickets on the ticket card filters to show only open tickets.', 'Read in ticket/card.php:1039 to append a filter parameter to the ticket list URL shown in the ticket card''s reference area, restricting the linked list to open tickets when the constant is truthy. No admin UI write path is present in the payload.', 'Enabling this constant filters the ''other tickets'' link on the ticket card to show only open tickets for the associated thirdparty. Leaving it unset shows all tickets.', 'Truthy value to filter linked list to open tickets only; unset or 0 to show all tickets.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:1039|read|$morehtmlref .= '' - <a href=\"''.DOL_URL_ROOT.''/ticket/list.php?socid=''.$object->socid.''&sortfield=t.datec&sortorder=desc''.(getDolGlobalBool(''TICKET_CLIENT_OTHER_TICKET_ONLY_OPEN'') ?"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_CREATE_THIRD_PARTY_WITH_CONTACT_IF_NOT_EXIST', 'string', NULL, 'admin', 'Controls whether a third-party and contact record are automatically created when a ticket is submitted by an unknown email.', 'Documented in public/ticket/ajax/ajax.php:25 as: This option TICKET_CREATE_THIRD_PARTY_WITH_CONTACT_IF_NOT_EXIST has been removed because it is a security hole. The ajax component at line 24 is only called by the public ticket page when this option is set. admin/ticket_public.php:183 deletes the constant.', 'This option was removed due to a security vulnerability; enabling it allows unauthenticated users to create third-party records, which is a known security risk.', 'Non-zero integer value enables automatic third-party creation (deprecated, security risk).', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/ticket/ajax/ajax.php:25  *  This option TICKET_CREATE_THIRD_PARTY_WITH_CONTACT_IF_NOT_EXIST has been removed because it is a security hole.", "public/ticket/ajax/ajax.php:24  *  This ajax component is called only by the create ticket public page. And only if TICKET_CREATE_THIRD_PARTY_WITH_CONTACT_IF_NOT_EXIST is set.", "admin/ticket_public.php:183|write|$res = dolibarr_del_const($db, ''TICKET_CREATE_THIRD_PARTY_WITH_CONTACT_IF_NOT_EXIST'', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DELAY_BEFORE_FIRST_RESPONSE', 'string', NULL, 'ticket', 'Defines the number of hours within which a first response to a ticket is expected before it is flagged as overdue.', 'Configured via the ticket admin UI (admin/ticket.php:187, :633). In the ticket list, if no response has been sent and the ticket is older than this value in hours, a late warning icon is shown (ticket/list.php:1176, :1179, :1180). Checked together with TICKET_DELAY_SINCE_LAST_RESPONSE for the warning column (ticket/list.php:1171).', 'Setting this to a positive integer causes tickets with no first response older than the configured hours to display a late warning. Leaving it unset disables this first-response delay check.', 'Integer number of hours. Tickets without a first response exceeding this age are flagged as late.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/list.php:1176|check|if (getDolGlobalString(''TICKET_DELAY_BEFORE_FIRST_RESPONSE'') && $date_last_msg_sent == 0) {", "ticket/list.php:1179|check|if ($hour_diff_creation > getDolGlobalInt(''TICKET_DELAY_BEFORE_FIRST_RESPONSE'')) {", "ticket/list.php:1180|read|print \" \" . img_picto($langs->trans(''Late'') . '' : '' . $langs->trans(''TicketsDelayForFirstResponseTooLong'', getDolGlobalString(''TICKET_DELAY_BEFORE_FIRST_RESPONSE'')), ''warning'', ''st"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DELAY_SINCE_LAST_RESPONSE', 'string', NULL, 'ticket', 'Defines the number of hours after which a ticket with no recent response is flagged as overdue.', 'Configured via the ticket admin UI (admin/ticket.php:193, :643). In the ticket list, if the number of hours since the last message exceeds this value, a late warning icon is displayed (ticket/list.php:1182, :1183). Checked together with TICKET_DELAY_BEFORE_FIRST_RESPONSE to determine whether to show any warning column (ticket/list.php:1171).', 'Setting this to a positive integer triggers a visual late warning on tickets where the last response is older than the configured number of hours. Leaving it unset disables this delay check.', 'Integer number of hours. Tickets exceeding this threshold since last response are flagged as late.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/list.php:1182|read|} elseif (getDolGlobalString(''TICKET_DELAY_SINCE_LAST_RESPONSE'') && $hour_diff > getDolGlobalInt(''TICKET_DELAY_SINCE_LAST_RESPONSE'')) {", "ticket/list.php:1183|read|print \" \" . img_picto($langs->trans(''Late'') . '' : '' . $langs->trans(''TicketsDelayFromLastResponseTooLong'', getDolGlobalString(''TICKET_DELAY_SINCE_LAST_RESPONSE'')), ''warning'');", "admin/ticket.php:643|read|<input type=\"number\" value=\"''.getDolGlobalString(''TICKET_DELAY_SINCE_LAST_RESPONSE'').''\" id=\"delay_between_responses\" name=\"delay_between_responses\" class=\"width50\">"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DISABLE_ALL_MAILS', 'bool', NULL, 'core', 'Completely suppresses all outgoing emails triggered by the ticket module.', 'Checked in both the ticket email trigger (core/triggers/interface_50_modTicket_TicketEmail.class.php:85, :192) and in ticket/class/ticket.class.php:3176 before sending any ticket-related email. No admin UI write path is present in the payload.', 'Enabling this constant prevents any ticket-related notification email from being sent. Disabling it (or leaving unset) restores normal ticket email delivery.', 'Truthy value to disable all ticket emails; unset or 0 to allow emails.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modTicket_TicketEmail.class.php:85|check|if (!getDolGlobalString(''TICKET_DISABLE_ALL_MAILS'')) {", "core/triggers/interface_50_modTicket_TicketEmail.class.php:192|check|if (!getDolGlobalString(''TICKET_DISABLE_ALL_MAILS'')) {", "ticket/class/ticket.class.php:3176|check|if (getDolGlobalString(''TICKET_DISABLE_ALL_MAILS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DISABLE_MAIL_AUTOCOPY_TO', 'bool', NULL, 'core', 'Suppresses the MAIN_MAIL_AUTOCOPY_TO BCC behaviour specifically for ticket-related outgoing emails.', 'Checked in both the ticket email trigger (core/triggers/interface_50_modTicket_TicketEmail.class.php:93, :100, :197, :415, :426, :505) and in ticket/class/ticket.class.php:3220, :3283 to temporarily disable or restore MAIN_MAIL_AUTOCOPY_TO during ticket email sending. No admin UI write path is present in the payload.', 'Enabling this prevents MAIN_MAIL_AUTOCOPY_TO addresses from being BCC''d on ticket emails. Disabling it (or leaving unset) allows the global autocopy behaviour to apply to ticket emails.', 'Truthy value to suppress autocopy for ticket emails; unset or 0 to allow global autocopy.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/class/ticket.class.php:3220|check|if (getDolGlobalString(''TICKET_DISABLE_MAIL_AUTOCOPY_TO'')) {", "ticket/class/ticket.class.php:3283|check|if (getDolGlobalString(''TICKET_DISABLE_MAIL_AUTOCOPY_TO'')) {", "core/triggers/interface_50_modTicket_TicketEmail.class.php:93|check|if (getDolGlobalString(''TICKET_DISABLE_MAIL_AUTOCOPY_TO'')) {", "core/triggers/interface_50_modTicket_TicketEmail.class.php:197|check|if (!getDolGlobalString(''TICKET_DISABLE_MAIL_AUTOCOPY_TO'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DISALLOW_CLASSIFICATION_MODIFICATION_EVEN_IF_CLOSED', 'bool', NULL, 'ticket', 'When enabled, prevents modification of ticket classification fields even after the ticket is closed.', 'Checked in ticket/card.php:1272 as part of the condition controlling whether classification fields are editable: when set, the condition restricts editability to tickets with status below STATUS_NEED_MORE_INFO regardless of the ticket being closed. No admin UI write path is present in the payload.', 'Enabling this constant locks classification fields on closed tickets. Leaving it unset allows classification to be modified on closed tickets.', 'Truthy value to disallow classification modification on closed tickets; unset or 0 to allow.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:1272|check|if (isset($object->status) && ($object->status < $object::STATUS_NEED_MORE_INFO || !getDolGlobalInt(''TICKET_DISALLOW_CLASSIFICATION_MODIFICATION_EVEN_IF_CLOSED'')) && $permissiontoa"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_DONOTSEARCH_ANYWHERE', 'string', NULL, 'core', 'When enabled, restricts ticket search queries to prefix-only matches, allowing database index use instead of full-text substring search.', 'Read at core/class/html.form.class.php:8433 and :8658. When truthy, $prefix is set to '''' (no leading wildcard), enabling index usage; when falsy, $prefix is ''%'' (leading wildcard, full substring search). The inline comment explicitly states ''Can use index if TICKET_DONOTSEARCH_ANYWHERE is on''.', 'Enabling improves search performance on large ticket tables by using indexed prefix queries. Disabling allows searching anywhere in the string but prevents index use.', 'Truthy = prefix-only search (index-friendly); empty/unset = substring search with leading wildcard.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:8433|read|$prefix = getDolGlobalString(''TICKET_DONOTSEARCH_ANYWHERE'') ? '''' : ''%''; // Can use index if TICKET_DONOTSEARCH_ANYWHERE is on", "core/class/html.form.class.php:8658|read|$prefix = !getDolGlobalString(''TICKET_DONOTSEARCH_ANYWHERE'') ? ''%'' : ''''; // Can use index if PRODUCT_DONOTSEARCH_ANYWHERE is on"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_EMAIL_MUST_EXISTS', 'string', NULL, 'admin', 'Requires that the submitter''s email address corresponds to an existing contact when creating a public ticket.', 'When set, public/ticket/create_ticket.php:226 rejects ticket creation if the contact ID is negative or the contact has no linked company. admin/ticket_public.php:189 deletes the constant to disable this requirement. Also gates document access in document.php:301.', 'Enabling this enforces that only known contacts with linked companies can submit tickets via the public form; disabling it allows anyone to submit.', 'Non-zero integer value enforces the email-must-exist check; absent or zero disables it.', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/ticket/create_ticket.php:226|check|if (getDolGlobalInt(''TICKET_EMAIL_MUST_EXISTS'') && ($cid < 0 || empty($contacts[$cid]->socid))) {", "admin/ticket_public.php:189|write|$res = dolibarr_del_const($db, ''TICKET_EMAIL_MUST_EXISTS'', $conf->entity);", "document.php:301|read|} elseif ($modulepart == ''ticket'' && !getDolGlobalString(''TICKET_EMAIL_MUST_EXISTS'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ENABLE_PUBLIC_INTERFACE', 'bool', NULL, 'admin', 'Controls whether the public-facing ticket interface is accessible to unauthenticated users.', 'Configured via the public ticket admin UI (admin/ticket_public.php). When disabled, access to the public interface is blocked (public/ticket/index.php:84; admin/ticket_public.php:247). When enabled, ticket URLs for the public interface are generated (ticket/class/ticket.class.php:3061).', 'Enabling this constant opens the ticket interface to the public. Disabling it prevents unauthenticated users from accessing or submitting tickets through the public URL.', '1 = enabled, 0 = disabled.', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/ticket/index.php:84|check|if (!getDolGlobalString(''TICKET_ENABLE_PUBLIC_INTERFACE'')) {", "admin/ticket_public.php:247|check|if (!getDolGlobalInt(''TICKET_ENABLE_PUBLIC_INTERFACE'')) {", "ticket/class/ticket.class.php:3061|read|$url_public_ticket = (getDolGlobalInt(''TICKET_ENABLE_PUBLIC_INTERFACE'') ?"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_ENABLE_RESOLUTION', 'bool', NULL, 'ticket', 'Enables the resolution field and the resolution dictionary for the ticket module.', 'Read in ticket/class/ticket.class.php at line 319 as the ''enabled'' condition for the resolution field, and in core/modules/modTicket.class.php at line 204 to conditionally load the resolution dictionary. A comment states: ''Dictionary of ticket resolutions (apparently unused except if TICKET_ENABLE_RESOLUTION is on)''.', 'When disabled, the resolution field is hidden on ticket forms and the resolution dictionary is not loaded. Enabling it activates both.', '0 or unset = resolution field disabled; 1 = resolution field and dictionary enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Dictionary of ticket resolutions (apparently unused except if TICKET_ENABLE_RESOLUTION is on)", "''enabled'' => ''getDolGlobalString(\"TICKET_ENABLE_RESOLUTION\")''", "''cond'' => isModEnabled(''ticket'') && getDolGlobalString(''TICKET_ENABLE_RESOLUTION''),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_INCLUDE_LINK_TO_PUBLIC_INTERFACE_IN_MESSAGE', 'string', NULL, 'ticket', 'When enabled, includes a link to the public ticket interface in ticket notification messages.', 'Checked in ticket/class/ticket.class.php:3064 to decide whether to append a public interface link in outgoing ticket messages. No admin UI write path is present in the payload.', 'Enabling this adds a public interface URL to outgoing ticket notification messages. Disabling it omits the link.', 'Truthy value to enable; unset or 0 to disable.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/class/ticket.class.php:3064|check|if (getDolGlobalInt(''TICKET_INCLUDE_LINK_TO_PUBLIC_INTERFACE_IN_MESSAGE'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_INCLUDE_SUSPENDED_STATUS', 'string', NULL, 'ticket', 'Controls whether suspended-status tickets are included in ticket list queries and counts.', 'Checked in ticket/class/ticket.class.php:361, ticket/class/actions_ticket.class.php:512, webportal/class/webportalticket.class.php:58, and ticket/index.php:246. When not set, suspended tickets are excluded from queries; when set, ticket/index.php:246 adds suspended tickets to counts.', 'When enabled, suspended tickets appear in lists and statistics; when disabled (default), they are filtered out.', 'Truthy (non-empty) to include suspended tickets; empty/unset to exclude them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/class/actions_ticket.class.php:512|check|if (!getDolGlobalString(''TICKET_INCLUDE_SUSPENDED_STATUS'')) {", "webportal/class/webportalticket.class.php:58|check|if (!getDolGlobalString(''TICKET_INCLUDE_SUSPENDED_STATUS'')) {", "ticket/class/ticket.class.php:361|check|if (!getDolGlobalString(''TICKET_INCLUDE_SUSPENDED_STATUS'')) {", "ticket/index.php:246|check|if (getDolGlobalString(''TICKET_INCLUDE_SUSPENDED_STATUS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_LIMIT_VIEW_ASSIGNED_ONLY', 'string', NULL, 'ticket', 'Restricts internal users from viewing tickets that are not assigned to them, unless they have ticket management rights.', 'Configured via admin/ticket.php:175 and checked across 15 occurrences in ticket module pages (document.php:104, messaging.php:118, agenda.php:117, contact.php:94, index.php:187, card.php:807) with the pattern: getDolGlobalString(''TICKET_LIMIT_VIEW_ASSIGNED_ONLY'') && $object->fk_user_assign != $user->id && !$permissiontomanage.', 'Enabling this hides unassigned tickets from regular internal users; users with ticket management permission are not affected.', '0 or unset = all internal users can view all tickets; 1 = internal users can only view tickets assigned to them (unless they have management rights).', 0, 0, 'admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ticket.php:175|write|$res = dolibarr_set_const($db, ''TICKET_LIMIT_VIEW_ASSIGNED_ONLY'', $param_limit_view, ''chaine'', 0, '''', $conf->entity);", "ticket/document.php:104|check|if (!$user->socid && getDolGlobalString(''TICKET_LIMIT_VIEW_ASSIGNED_ONLY'') && $object->fk_user_assign != $user->id && !$permissiontomanage) {", "ticket/messaging.php:118|check|if (!$user->socid && (getDolGlobalString(''TICKET_LIMIT_VIEW_ASSIGNED_ONLY'') && $object->fk_user_assign != $user->id) && !$permissiontomanage) {", "ticket/index.php:187|check|if (getDolGlobalString(''TICKET_LIMIT_VIEW_ASSIGNED_ONLY'') && !$permissiontomanage) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_LINK_TO_CONTRACT_WITH_HARDLINK', 'string', NULL, 'ticket', 'When enabled, creates a hard link between tickets and contracts rather than a soft reference.', 'Checked in ticket/card.php:1066 and core/lib/contract.lib.php:58 to conditionally display or enable the hard-link contract association for tickets. No admin UI write path is present in the payload.', 'Enabling this constant activates hard-link contract association for tickets, affecting how ticket-contract relationships are stored and displayed.', 'Truthy value to enable hard-link contract association; unset or 0 for default (soft) contract linking.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:1066|check|if (getDolGlobalString(''TICKET_LINK_TO_CONTRACT_WITH_HARDLINK'')) {", "core/lib/contract.lib.php:58|check|if (isModEnabled(''ticket'') && getDolGlobalString(''TICKET_LINK_TO_CONTRACT_WITH_HARDLINK'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_MAX_VISIBLE_PHOTO', 'string', NULL, 'core', 'Sets the maximum number of ticket photos displayed in the ticket view, defaulting to 2.', 'Read as an integer in core/lib/functions.lib.php:3491 with a default of 2. No admin UI write detected.', 'Increasing this value shows more ticket photos simultaneously. Decreasing it limits the visible photo count.', 'Integer; default 2.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3491|read|$maxvisiblephotos = getDolGlobalInt(''TICKET_MAX_VISIBLE_PHOTO'', 2);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_MESSAGE_MAIL_INTRO', 'string', NULL, 'ticket', 'Sets the introductory text prepended to ticket notification email messages.', 'Written in admin/ticket.php at lines 248 and 250 and read in ticket/class/ticket.class.php at lines 2877 and 2934 (with the translation string ''TicketMessageMailIntroText'' as fallback) and in core/class/html.formticket.class.php at lines 1864 and 1867.', 'When set, this text appears at the beginning of ticket notification emails. When empty, the translation default is used instead.', 'HTML/text string; empty or unset = default translated intro text used', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$mail_intro = getDolGlobalString(''TICKET_MESSAGE_MAIL_INTRO'', '''');", "$message = getDolGlobalString(''TICKET_MESSAGE_MAIL_INTRO'', $langs->trans(''TicketMessageMailIntroText''));", "if (getDolGlobalString(''TICKET_MESSAGE_MAIL_INTRO'') || getDolGlobalString(''TICKET_MESSAGE_MAIL_SIGNATURE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_MESSAGE_MAIL_NEW', 'string', NULL, 'admin', 'Stores the custom email body template sent to users when a new ticket is created.', 'Written via admin/ticket_public.php at lines 131 and 133; read back at line 498. Used in public/ticket/create_ticket.php:458 to compose the notification email body, falling back to ''TicketNewEmailBody'' translation if empty.', 'Changing this modifies the email body sent upon new ticket creation; removing it reverts to the default translated template.', 'HTML string; defaults to the translated value of ''TicketNewEmailBody'' if not set.', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ticket_public.php:131|write|$res = dolibarr_set_const($db, ''TICKET_MESSAGE_MAIL_NEW'', $mail_new_ticket, ''chaine'', 0, '''', $conf->entity);", "admin/ticket_public.php:498|read|$mail_mesg_new = getDolGlobalString(\"TICKET_MESSAGE_MAIL_NEW\", $langs->trans(''TicketNewEmailBody''));", "public/ticket/create_ticket.php:458|read|$message  = (getDolGlobalString(''TICKET_MESSAGE_MAIL_NEW'') !== '''' ? getDolGlobalString(''TICKET_MESSAGE_MAIL_NEW'') : $langs->transnoentities(''TicketNewEmailBody'')).''<br><br>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_MESSAGE_MAIL_SIGNATURE', 'string', NULL, 'core', 'Defines the email signature appended to ticket message emails sent from the system.', 'Configured via the ticket admin UI (admin/ticket.php). The value is read into $mail_signature for use in outgoing ticket emails (core/class/html.formticket.class.php:1898; ticket/class/ticket.class.php:2932). Presence of this constant is checked alongside TICKET_MESSAGE_MAIL_INTRO to determine whether to include signature/intro blocks (core/class/html.formticket.class.php:1864, :1872).', 'Setting this value causes ticket message emails to include the specified signature text. Clearing it removes the signature from outgoing ticket emails.', 'Any string (email signature text). Empty string disables.', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/class/html.formticket.class.php:1897  /*if ($user->rights->ticket->write && !$user->socid && !empty($conf->global->TICKET_MESSAGE_MAIL_SIGNATURE)) {", "core/class/html.formticket.class.php:1864|check|if (getDolGlobalString(''TICKET_MESSAGE_MAIL_INTRO'') || getDolGlobalString(''TICKET_MESSAGE_MAIL_SIGNATURE'')) {", "ticket/class/ticket.class.php:2932|read|$message_signature = GETPOST(''mail_signature'') ? GETPOST(''mail_signature'') : getDolGlobalString(''TICKET_MESSAGE_MAIL_SIGNATURE'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NODISPLAYIFNOPHOTO', 'string', NULL, 'core', 'Hides the ticket photo display area entirely when no photo is available.', 'Checked in core/lib/functions.lib.php:3505; the photo block is suppressed when no photos exist and this constant is set. No admin UI write detected.', 'Setting this constant removes the empty photo placeholder from ticket views. Without it, the photo area is rendered even without an image.', 'Non-empty = hide photo area when no photo; absent/empty = always show photo area.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions.lib.php:3505|check|if (getDolGlobalString(''TICKET_NODISPLAYIFNOPHOTO'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS', 'string', NULL, 'ticket', 'Controls whether the main notification address (TICKET_NOTIFICATION_EMAIL_TO) is always included as a CC recipient on ticket notifications.', 'Written in admin/ticket_public.php at lines 161 and 172 and rendered as a select at line 543. Checked in ticket/class/ticket.class.php at lines 2865, 2976, and 3089 where it gates addition of TICKET_NOTIFICATION_EMAIL_TO to the sendto list. Also checked in core/class/html.formticket.class.php at line 1752.', 'When enabled, the main notification address is appended to every ticket notification send even if it is not already in the recipient list.', '0 or unset = main address not always included; 1 = main address always added as CC', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (getDolGlobalString(''TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS'') && !array_key_exists(getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_TO''), $sendto)) {", "$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS'', $param_notification_also_main_addressemail, ''chaine'', 0, '''', $conf->entity);", "print $form->selectarray(\"TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS\", $arrval, getDolGlobalInt(''TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFICATION_EMAIL_FROM', 'string', NULL, 'ticket', 'Specifies the sender email address used for all ticket notification emails.', 'Written in admin/ticket.php at lines 203 and 205 (with MAIN_MAIL_EMAIL_FROM as fallback when cleared). Read in ticket/class/ticket.class.php at lines 2906 and 3102 and core/class/html.formticket.class.php at line 1700. A phpdoc at line 3162 notes: ''Receive a copy on internal email at getDolGlobalString(TICKET_NOTIFICATION_EMAIL_FROM)''.', 'When set, all ticket notification emails use this as the From address. When unset or empty, the public ticket creation page blocks notification sending (checked at line 598).', 'Email address string; empty or unset = notification sending blocked on public interface', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["* @param int<0,1>\t\t$send_internal_cc \tReceive a copy on internal email at getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_FROM'')", "$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_FROM'', $notification_email, ''chaine'', 0, $notification_email_description, $conf->entity);", "$from = getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_FROM'');", "if (!getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_FROM'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFICATION_EMAIL_REPLYTO', 'string', NULL, 'ticket', 'Sets the reply-to email address used in ticket notification emails sent to contacts.', 'Configured via the ticket admin UI (admin/ticket.php). When set, this address is used as the Reply-To header in ticket notification emails (ticket/class/ticket.class.php:2908, :2989, :3104; core/class/html.formticket.class.php:1701). If not set, the value of MAIN_MAIL_EMAIL_FROM is used as a fallback (admin/ticket.php:216).', 'Changing this value redirects reply traffic for ticket notification emails to the specified address. Leaving it unset causes replies to go to the main mail sender address.', 'Any valid email address string.', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ticket.php:216|write|$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_REPLYTO'', getDolGlobalString(''MAIN_MAIL_EMAIL_FROM''), ''chaine'', 0, $notification_email_replyto_description, $conf->entity)", "ticket/class/ticket.class.php:2908|read|$replyto = getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_REPLYTO'');", "core/class/html.formticket.class.php:1701|read|$replyto = getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_REPLYTO'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFICATION_EMAIL_TEMPLATE', 'string', NULL, 'admin', 'Selects the email template used for ticket notification emails.', 'Written and read in admin/ticket.php. The value is selected from an array of available message/template names via a dropdown in the ticket admin UI.', 'Changing this value switches the email template applied to all outgoing ticket notifications.', 'A string key identifying a mail template from the available templates list; empty string means none selected.', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/ticket.php:237|write|$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_TEMPLATE'', $notification_email_template, ''chaine'', 0, $notification_email_template_description, $conf->entity);", "admin/ticket.php:749|read|print $form->selectarray(''TICKET_NOTIFICATION_EMAIL_TEMPLATE'', $arrayofmessagename, getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_TEMPLATE''), ''None'', 0, 0, '''', 0, 0, 0, '''', '''', 1);", "admin/ticket.php:239|write|$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_TEMPLATE'', '''', ''chaine'', 0, $notification_email_template_description, $conf->entity);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFICATION_EMAIL_TO', 'string', NULL, 'ticket', 'Specifies the primary email address to which ticket-event notifications are sent.', 'Written in admin/ticket.php at lines 226 and 228. Read and checked in ticket/class/ticket.class.php at lines 2865-2866, 2976-2977, and 3089, where it is added to the sendto list when TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS is also set. A comment in public/ticket/create_ticket.php line 490 states: ''Send email to TICKET_NOTIFICATION_EMAIL_TO''.', 'When set, this address receives ticket notifications. It works together with TICKET_NOTIFICATION_ALSO_MAIN_ADDRESS to control whether the address is included in all notification sends.', 'Email address string; empty or unset = no main notification recipient', 0, 0, 'admin/ticket.php|admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["// Send email to TICKET_NOTIFICATION_EMAIL_TO", "$res = dolibarr_set_const($db, ''TICKET_NOTIFICATION_EMAIL_TO'', $notification_email_to, ''chaine'', 0, $notification_email_to_description, $conf->entity);", "if (getDolGlobalString(''TICKET_NOTIFICATION_EMAIL_TO'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFY_AT_CLOSING', 'string', NULL, 'ticket', 'Controls whether ticket contacts are automatically notified when a ticket is closed.', 'Configured via the ticket admin UI (admin/ticket.php:168, :777). When set, the default notification checkbox on ticket close is pre-checked (ticket/card.php:827) and the list view marks tickets as selected for notification (ticket/list.php:815). The trigger also checks this value before sending close notifications to third-party contacts (core/triggers/interface_50_modTicket_TicketEmail.class.php:287).', 'Enabling this causes the notification-on-close behaviour to be active by default. Disabling it suppresses automatic close notifications unless manually overridden.', 'Truthy value to enable automatic notification at closing; unset or 0 to disable.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/card.php:827|read|$default = (getDolGlobalString(''TICKET_NOTIFY_AT_CLOSING'') ? ''-2'' : ''-3'');", "ticket/list.php:815|read|$selectedchoice = getDolGlobalString(''TICKET_NOTIFY_AT_CLOSING'') ? \"yes\" : \"no\";", "core/triggers/interface_50_modTicket_TicketEmail.class.php:287|check|if (empty($linked_contacts) && getDolGlobalString(''TICKET_NOTIFY_AT_CLOSING'') && !empty($object->fk_soc)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_NOTIFY_CUSTOMER_TICKET_ASSIGNED', 'string', NULL, 'core', 'Controls whether a notification email is sent to the customer when a ticket is assigned to a user for the first time.', 'Checked in core/triggers/interface_50_modTicket_TicketEmail.class.php:111, where it gates the sending of an assignment notification only when the ticket had no previous assignee.', 'When set, customers receive an email when their ticket is first assigned; when unset, no assignment notification is sent.', 'Empty/unset = no notification sent; non-empty = notification sent on first assignment.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_50_modTicket_TicketEmail.class.php:111|check|if (getDolGlobalString(''TICKET_NOTIFY_CUSTOMER_TICKET_ASSIGNED'') && empty($object->oldcopy->fk_user_assign)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PRODUCT_CATEGORY', 'string', NULL, 'core', 'Specifies the product category used to filter contracts when auto-linking contracts to tickets.', 'Set via admin/workflow.php:252 and rendered as a category selector at :386. Used in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:606 to filter the list of contracts by this category when linking to a ticket.', 'Changing this value restricts which contracts are candidates for auto-linking to tickets; only contracts in the specified product category are considered.', 'Integer ID of a product category; empty = no category filter applied', 0, 0, 'admin/workflow.php|admin/workflow.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/workflow.php:252|write|$res = dolibarr_set_const($db, ''TICKET_PRODUCT_CATEGORY'', $param_ticket_product_category, ''chaine'', 0, '''', $conf->entity);", "admin/workflow.php:386|read|$formcategory->selectProductCategory(getDolGlobalInt(''TICKET_PRODUCT_CATEGORY''), $htmlname, 1);", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:606|read|$list = $contrat->getListOfContracts(''all'', array(Contrat::STATUS_DRAFT, Contrat::STATUS_VALIDATED), array(getDolGlobalString(''TICKET_PRODUCT_CATEGORY'')), array(ContratLigne::STATU"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_DISPLAY_EXTERNAL_CONTRIBUTORS', 'string', NULL, 'public', 'Controls whether external contributors are displayed on the public ticket view page.', 'Checked as an integer flag at public/ticket/view.php:351; when non-zero, the external contributors section is rendered. No admin UI write found.', 'When enabled, the public ticket view includes the external contributors list; when disabled or unset, it is hidden.', '0 or unset = hidden; non-zero = displayed', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/ticket/view.php:351|check|if (getDolGlobalInt(''TICKET_PUBLIC_DISPLAY_EXTERNAL_CONTRIBUTORS'')) {"]', 'low', NULL);
