INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_DEFAULT_EMAIL', 'string', NULL, 'ticket', 'Specifies a default email address to receive notifications when a new public ticket message is posted.', 'Written in admin/ticket_public.php at line 152 and read in ticket/class/ticket.class.php at lines 2857-2858, where the address is added to the sendto list when set.', 'When set, the specified address always receives a copy of public-ticket new-message notifications. Clearing it removes this default recipient.', 'Email address string; empty or unset = no default recipient', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["$res = dolibarr_set_const($db, ''TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_DEFAULT_EMAIL'', $param_public_notification_new_message_default_email, ''chaine'', 0, '''', $conf->entity);", "if (getDolGlobalString(''TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_DEFAULT_EMAIL'')) {", "$sendto[getDolGlobalString(''TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_DEFAULT_EMAIL'')] = getDolGlobalString(''TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_DEFAULT_EMAIL'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_ENABLED', 'bool', NULL, 'ticket', 'Enables sending of notification emails when a new message is posted on a ticket from the public interface.', 'Configured via a select in admin/ticket_public.php at line 520 and checked in ticket/class/ticket.class.php at line 2823.', 'When disabled, no notification is sent for new public-area messages. Enabling it triggers the notification logic for public ticket messages.', '0 or unset = public message notifications disabled; 1 = public message notifications enabled', 0, 0, 'admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["print $form->selectarray(\"TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_ENABLED\", $arrval, getDolGlobalString(\"TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_ENABLED\"));", "if (getDolGlobalString(''TICKET_PUBLIC_NOTIFICATION_NEW_MESSAGE_ENABLED'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_SELECT_EXTERNAL_CONTRIBUTORS', 'string', NULL, 'public', 'Controls whether external contributors can be selected on the public ticket view when a society is linked.', 'Checked as an integer flag at public/ticket/view.php:364 in combination with a non-empty fk_soc; when non-zero and a society is linked, the selection UI is shown. No admin UI write found.', 'When enabled with a linked society, users on the public ticket page can select external contributors; otherwise the control is hidden.', '0 or unset = hidden; non-zero = shown (requires linked society)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/ticket/view.php:364|check|if (getDolGlobalInt(''TICKET_PUBLIC_SELECT_EXTERNAL_CONTRIBUTORS'') && !empty($object->dao->fk_soc)) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_TEXT_HELP_MESSAGE', 'string', NULL, 'admin', 'Stores the help message text displayed on the public ticket submission form.', 'Managed via the admin UI at admin/ticket_public.php (written via dolibarr_set_const, reset to the default translation on reset action). Displayed in core/class/html.formticket.class.php:565 inside a warning div. Defaults to the translation of ''TicketPublicPleaseBeAccuratelyDescribe'' when unset.', 'Setting a custom value replaces the default instructional text shown to users on the public ticket form. Clearing it restores the default translated message.', 'Any non-empty string = custom help message; empty/unset = default translation ''TicketPublicPleaseBeAccuratelyDescribe''.', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ticket_public.php:120|$res = dolibarr_set_const($db, ''TICKET_PUBLIC_TEXT_HELP_MESSAGE'', $text_help, ''chaine'', 0, '''', $conf->entity);", "admin/ticket_public.php:438|$public_text_help_message = getDolGlobalString(\"TICKET_PUBLIC_TEXT_HELP_MESSAGE\", $langs->trans(''TicketPublicPleaseBeAccuratelyDescribe''));", "html.formticket.class.php:565|print ''<div class=\"warning hideonsmartphone\">''.(getDolGlobalString(\"TICKET_PUBLIC_TEXT_HELP_MESSAGE\", $langs->trans(''TicketPublicPleaseBeAccuratelyDescribe''))).''</div>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_PUBLIC_TEXT_HOME', 'string', NULL, 'admin', 'Stores the custom introductory text displayed on the public ticket portal home page.', 'Written via admin/ticket_public.php at lines 109 and 111; read back at line 424 for display in the admin UI. Rendered on the public page at public/ticket/index.php:96 with a fallback to the translated default if unset.', 'Changing this updates the welcome text on the public ticket portal; removing it reverts to the default translated text.', 'HTML string; defaults to the translated value of ''TicketPublicDesc'' if unset.', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/ticket_public.php:109|write|$res = dolibarr_set_const($db, ''TICKET_PUBLIC_TEXT_HOME'', $text_home, ''chaine'', 0, '''', $conf->entity);", "admin/ticket_public.php:424|read|$public_text_home = getDolGlobalString(''TICKET_PUBLIC_TEXT_HOME'', ''<span class=\"opacitymedium\">''.$langs->trans(\"TicketPublicDesc\").''</span>'');", "public/ticket/index.php:96|read|print ''<p style=\"text-align: center\">''.(getDolGlobalString(\"TICKET_PUBLIC_TEXT_HOME\", ''<span class=\"opacitymedium\">''.$langs->trans(\"TicketPublicDesc\")).''</span></p>'').''</p>'';"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_SEND_INTERNAL_CC', 'string', NULL, 'ticket', 'Specifies one or more email addresses (comma-separated) to be CC''d internally on all ticket notification emails.', 'Configured via the ticket admin UI (admin/ticket.php:711). When set, the value is split by comma and used as the CC list for ticket notification emails (ticket/class/ticket.class.php:2984, :3097; core/class/html.formticket.class.php:1769).', 'Setting this value causes all ticket notification emails to include the specified addresses in CC. Clearing it removes the internal CC from ticket emails.', 'Comma-separated list of email addresses.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/class/ticket.class.php:2984|read|$sendtocc = explode('','', getDolGlobalString(\"TICKET_SEND_INTERNAL_CC\"));", "ticket/class/ticket.class.php:3096|check|if (getDolGlobalString(\"TICKET_SEND_INTERNAL_CC\")) {", "core/class/html.formticket.class.php:1769|read|$sendtocc = getDolGlobalString(''TICKET_SEND_INTERNAL_CC'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_SEND_PRIVATE_EMAIL', 'string', NULL, 'core', 'When set, suppresses the email sending option for ticket messages.', 'Checked in two locations in core/class/html.formticket.class.php (lines 1580 and 1653) before rendering or processing the send-email action for ticket messages.', 'Enabling this prevents the email notification option from being offered when adding ticket messages. Disabling (or leaving unset) allows email sending to be triggered from the ticket message form.', 'Empty/unset = email sending option available; any truthy value = email sending suppressed.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["html.formticket.class.php:1580|if (!getDolGlobalString(''TICKET_SEND_PRIVATE_EMAIL'')) {", "html.formticket.class.php:1653|if (!getDolGlobalString(''TICKET_SEND_PRIVATE_EMAIL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_SET_STATUS_ON_ANSWER', 'string', NULL, 'ticket', 'Defines the ticket status to automatically apply when a staff member answers a ticket.', 'Configured via the ticket admin UI (admin/ticket.php:623). When set to a value >= 0, answering a ticket by a non-external, non-private user triggers setStatut() with the configured status (ticket/class/ticket.class.php:3140, :3142). A value < 0 skips the automatic status change.', 'Setting this to a valid status code causes tickets to be automatically moved to that status on each staff reply. Leaving it unset or negative preserves the existing status after a reply.', 'Integer status code >= 0 to auto-set status on answer; negative value disables auto-status change.', 0, 0, 'admin/ticket.php|admin/ticket.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["ticket/class/ticket.class.php:3134  // Except if TICKET_SET_STATUS_ON_ANSWER has been defined", "ticket/class/ticket.class.php:3140|read|} elseif (getDolGlobalInt(''TICKET_SET_STATUS_ON_ANSWER'', -1) >= 0 && empty($user->socid) && empty($private)) {", "ticket/class/ticket.class.php:3142|read|$object->setStatut(getDolGlobalInt(''TICKET_SET_STATUS_ON_ANSWER''), null, '''', ''TICKET_MODIFY'');"]', 'high', NULL);
