INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_URL_PUBLIC_INTERFACE', 'string', NULL, 'public', 'Stores the base URL of the public ticket interface, overriding the default internal path.', 'Written via admin/ticket_public.php:142 and :144, and read in ticket/class/ticket.class.php:3062, core/triggers/interface_50_modTicket_TicketEmail.class.php:493, core/lib/ticket.lib.php:222, ticket/class/actions_ticket.class.php:395, and webportal/controllers/ticketlist.controller.class.php:147 (22+ occurrences). When set, it replaces the default dol_buildpath(''/public/ticket/'', ...) path.', 'Setting this constant redirects ticket-related public URLs (view, download, email links) to an external or custom URL; unsetting it falls back to the internal Dolibarr public ticket path.', 'String: full base URL (e.g. ''https://support.example.com/ticket''); empty = use default internal path via dol_buildpath', 0, 0, 'admin/ticket_public.php|admin/ticket_public.php|admin/ticket_public.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/ticket_public.php:142|write|$res = dolibarr_set_const($db, ''TICKET_URL_PUBLIC_INTERFACE'', $url_interface, ''chaine'', 0, '''', $conf->entity);", "ticket/class/ticket.class.php:3062|read|(getDolGlobalString(''TICKET_URL_PUBLIC_INTERFACE'') ? getDolGlobalString(''TICKET_URL_PUBLIC_INTERFACE'') . ''/view.php'' : dol_buildpath(''/public/ticket/view.php'', 2))", "core/triggers/interface_50_modTicket_TicketEmail.class.php:493|read|$url_public_ticket = getDolGlobalString(''TICKET_URL_PUBLIC_INTERFACE'', dol_buildpath(''/public/ticket/'', 2)).''view.php?track_id=''.urlencode($object->track_id);", "ticket/class/actions_ticket.class.php:395|read|$downloadwrapper = getDolGlobalString(''TICKET_URL_PUBLIC_INTERFACE'') ? getDolGlobalString(''TICKET_URL_PUBLIC_INTERFACE'') . ''/document.php'' : dol_buildpath(''/public/ticket/document."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TICKET_USE_SEARCH_TO_SELECT', 'bool', NULL, 'core', 'Enables an AJAX search-to-select widget instead of a plain drop-down for ticket selection fields.', 'Checked and read across 5 locations in core/class/html.form.class.php (lines 8361, 8469, 8477, 8587, 8819). When truthy and JavaScript/AJAX is enabled, an ajax_combobox is rendered with this value passed as the minimum character threshold. When falsy, a plain select list is used.', 'Enabling improves performance and usability on large ticket datasets by replacing full drop-downs with asynchronous search. Disabling reverts to a full static list.', 'Truthy integer = enable AJAX search-to-select (value used as minimum chars for search); 0/empty = use plain select.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.form.class.php:8361|check|if (!empty($conf->use_javascript_ajax) && getDolGlobalString(''TICKET_USE_SEARCH_TO_SELECT'')) {", "core/class/html.form.class.php:8469|read|$out .= ajax_combobox($htmlname, $events, getDolGlobalInt(''TICKET_USE_SEARCH_TO_SELECT''));", "core/class/html.form.class.php:8477|check|if (getDolGlobalString(''TICKET_USE_SEARCH_TO_SELECT'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TIMESPENT_', 'string', NULL, 'core', 'Prefix pattern for timespent numbering add-on module constants, used to select the active add-on class.', 'Found in core/class/timespent.class.php:989 where a write sets TIMESPENT_timespent_ADDON to a default module name. This is a dynamic constant family using the TIMESPENT_ prefix with a suffix identifying the entity.', 'Setting a specific TIMESPENT_*_ADDON constant changes the numbering module used for time-spent records.', 'String module name, e.g. ''mod_timespent_standard''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["$conf->global->TIMESPENT_timespent_ADDON = ''mod_timespent_standard'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('TIMESPENT_ALWAYS_UPDATE_THM', 'string', NULL, 'projet', 'Forces the hourly rate (THM) on a time-spent record to be updated on every save, regardless of whether the duration changed.', 'Without this constant, the THM is only recalculated when the time-spent duration has changed. When set, projet/class/task.class.php:2148 and :2168 force the THM update unconditionally.', 'Enabling this setting ensures the hourly rate is always refreshed on save; disabling it (default) recalculates THM only when the duration changes.', 'Empty/0 = disabled (THM updated only when duration changes); non-empty = enabled (THM always updated on save).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["projet/class/task.class.php:2148|check|if ($ret == 1 && (($this->timespent_old_duration != $this->timespent_duration) || getDolGlobalString(''TIMESPENT_ALWAYS_UPDATE_THM''))) {", "projet/class/task.class.php:2168|check|if (empty($timespent->thm) || getDolGlobalString(''TIMESPENT_ALWAYS_UPDATE_THM'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('URL_REDIRECTION_AFTER_CHANGEPASSWORD', 'string', NULL, 'user', 'Specifies a URL to redirect the user to after a successful password change.', 'Checked and read at user/class/user.class.php:2783-2784; when set, $url is assigned the constant''s value and used for post-change redirection.', 'Setting this constant redirects users to a custom URL after changing their password; leaving it unset uses the default post-change flow.', 'Empty/unset = default redirect behavior; any URL string = redirect to that URL after password change.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/user.class.php:2783|check|if (getDolGlobalString(''URL_REDIRECTION_AFTER_CHANGEPASSWORD'')) {", "user/class/user.class.php:2784|read|$url = getDolGlobalString(''URL_REDIRECTION_AFTER_CHANGEPASSWORD'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USERGROUP_ADDON_PDF', 'string', NULL, 'user', 'Specifies the active PDF generation module/model for user group documents.', 'Read by the user group class at user/class/usergroup.class.php to determine which PDF model to load when generating a document. The admin UI at admin/usergroup.php lets administrators select the active model by comparing against this constant.', 'Changing this value switches the PDF model used when generating user group documents; an empty or unset value disables PDF generation for user groups.', 'Any valid PDF module name available in the user group module.', 0, 0, 'admin/usergroup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/usergroup.php:224|check|if (getDolGlobalString(''USERGROUP_ADDON_PDF'') == $name) {", "user/class/usergroup.class.php:1039|check|if (getDolGlobalString(''USERGROUP_ADDON_PDF'')) {", "user/class/usergroup.class.php:1040|read|$modele = getDolGlobalString(''USERGROUP_ADDON_PDF'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USERGROUP_ADDON_PDF_ODT', 'string', NULL, 'admin', 'Stores the selected ODT document template for user group PDF generation.', 'Holds the name of the chosen ODT model for user group documents. Written and managed via the admin UI at admin/usergroup.php. When a new value is selected, the previous one is deleted and the new one is stored via dolibarr_set_const.', 'Changing this value switches the ODT template used for generating user group PDF documents; deleting it removes the active selection.', 'Any valid ODT template name available in the user group document module.', 0, 0, 'admin/usergroup.php|admin/usergroup.php|admin/usergroup.php|admin/usergroup.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/usergroup.php:82|write|if (dolibarr_set_const($db, \"USERGROUP_ADDON_PDF_ODT\", $value, ''chaine'', 0, '''', $conf->entity)) {", "admin/usergroup.php:85|write|$conf->global->USERGROUP_ADDON_PDF_ODT = $value;", "admin/usergroup.php:75|check|if (getDolGlobalString(''USERGROUP_ADDON_PDF_ODT'') == \"$value\") {", "admin/usergroup.php:76|write|dolibarr_del_const($db, ''USERGROUP_ADDON_PDF_ODT'', $conf->entity);"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USERGROUP_ADDON_PDF_ODT_CLOSED', 'string', NULL, 'core', 'Specifies the ODT template to use for user groups in a ''closed'' status.', 'Read in core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:180 as the selected value in a template selection array rendered in the module configuration form. No admin UI write is present.', 'Setting this constant pre-selects a specific ODT template for user groups with a ''closed'' status. Leaving it unset results in no pre-selection for that status.', 'A template filename string; empty or unset = no template pre-selected for ''closed'' status.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:180|read|$texte .= $form->selectarray(''value4'', $list, getDolGlobalString(''USERGROUP_ADDON_PDF_ODT_CLOSED''));"]', 'low', NULL);
