INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USERGROUP_ADDON_PDF_ODT_PATH', 'string', 'DOL_DATA_ROOT/doctemplates/usergroups', 'core', 'Sets the directory path where ODT templates for user group documents are stored.', 'Read in core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:115 via trim(getDolGlobalString(...)). The default value is DOL_DATA_ROOT/doctemplates/usergroups. No admin UI write is present.', 'Changing this constant redirects the module to look for ODT templates in the specified directory instead of the default location.', 'A filesystem path string; default is DOL_DATA_ROOT/doctemplates/usergroups.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/usergroup/doc/doc_generic_usergroup_odt.modules.php:115|read|$odtPath = trim(getDolGlobalString(''USERGROUP_ADDON_PDF_ODT_PATH''));"]', 'low', NULL);
