INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_ADDON_PDF', 'string', NULL, 'user', 'Specifies the PDF template module name used to generate documents for user records.', 'Checked and read at user/class/user.class.php:4209-4210; when set, its value is used as the PDF model name for user document generation.', 'Setting this constant changes which PDF template is used for user documents; leaving it unset falls back to the default template.', 'Empty/unset = use default PDF model; a module name string = use that PDF template.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/class/user.class.php:4209|check|if (getDolGlobalString(''USER_ADDON_PDF'')) {", "user/class/user.class.php:4210|read|$modele = getDolGlobalString(''USER_ADDON_PDF'');"]', 'low', NULL);
