INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_HIDE_EXTERNAL_IN_COMBOBOX', 'bool', NULL, 'core', 'Hides external (non-internal) users from user-selection combo boxes.', 'Checked in core/class/html.form.class.php:2320, core/class/html.formother.class.php:545, and comm/mailing/class/html.formadvtargetemailing.class.php:237. No admin UI write path and no comment are present in the payload.', 'Enabling this constant excludes external user accounts from selection dropdowns, restricting choices to internal users only.', 'Any truthy value hides external users; unset shows all users.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/class/html.formadvtargetemailing.class.php:237|check|if (getDolGlobalString(''USER_HIDE_EXTERNAL_IN_COMBOBOX'')) {", "core/class/html.form.class.php:2320|check|if (getDolGlobalString(''USER_HIDE_EXTERNAL_IN_COMBOBOX'') || $notdisabled) {", "core/class/html.formother.class.php:545|check|if (getDolUserString(''USER_HIDE_EXTERNAL_IN_COMBOBOX'', getDolGlobalString(''USER_HIDE_EXTERNAL_IN_COMBOBOX''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_HIDE_INACTIVE_IN_COMBOBOX', 'bool', NULL, 'admin', 'Hides inactive (disabled) users from user-selection combo boxes throughout the application.', 'Configured via admin/user.php with dolibarr_set_const. Documented at core/class/html.form.class.php:2214 as affecting the ''show only active users'' behaviour. Evaluated in html.form.class.php, html.formother.class.php, and comm/mailing targeting selectors.', 'When enabled, disabled user accounts are excluded from all user picker dropdowns; this reduces clutter but means those users cannot be selected for assignments even if needed.', 'Any truthy value hides inactive users; unset shows all users.', 0, 0, 'admin/user.php|admin/user.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/class/html.form.class.php:2214  * @param int<0,1> \t\t\t$notdisabled \tShow only active users (note: this will also happen, whatever is this option, if USER_HIDE_INACTIVE_IN_COMBOBOX is on).", "admin/user.php:122|write|if (dolibarr_set_const($db, \"USER_HIDE_INACTIVE_IN_COMBOBOX\", $status, ''chaine'', 0, '''', $conf->entity) > 0) {", "core/class/html.form.class.php:2314|check|if (getDolGlobalString(''USER_HIDE_INACTIVE_IN_COMBOBOX'') || $notdisabled) {", "core/class/html.formother.class.php:548|check|if (getDolUserString(''USER_HIDE_INACTIVE_IN_COMBOBOX'', getDolGlobalString(''USER_HIDE_INACTIVE_IN_COMBOBOX''))) {\t// Can be set in setup of module User."]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_HIDE_NONEMPLOYEE_IN_COMBOBOX', 'bool', NULL, 'core', 'Hides non-employee users from user-selection combo boxes.', 'Checked in core/class/html.form.class.php:2317, core/class/html.formother.class.php:542, and comm/mailing/class/html.formadvtargetemailing.class.php:234. No admin UI write path is present in the payload; no comment is present.', 'Enabling this constant filters out non-employee user accounts from selection dropdowns, narrowing picker results to employees only.', 'Any truthy value hides non-employees; unset shows all users.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/mailing/class/html.formadvtargetemailing.class.php:234|check|if (getDolGlobalString(''USER_HIDE_NONEMPLOYEE_IN_COMBOBOX'')) {", "core/class/html.form.class.php:2317|check|if (getDolGlobalString(''USER_HIDE_NONEMPLOYEE_IN_COMBOBOX'') || $notdisabled) {", "core/class/html.formother.class.php:542|check|if (getDolUserString(''USER_HIDE_NONEMPLOYEE_IN_COMBOBOX'', getDolGlobalString(''USER_HIDE_NONEMPLOYEE_IN_COMBOBOX''))) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_IMAGE_PUBLIC_INTERFACE', 'string', NULL, 'public', 'Specifies the URL of an image to display on the public user profile interface page.', 'In public/users/view.php at lines 299 and 301, when set the image URL is rendered as an img tag. No admin UI write path is present.', 'Setting this displays a banner or logo image on the public user profile page; leaving it unset shows no image.', 'String: URL of the image to display on the public user profile page', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/users/view.php:299|check|if (getDolGlobalString(''USER_IMAGE_PUBLIC_INTERFACE'')) {", "public/users/view.php:301|read|print ''<img id=\"idUSER_IMAGE_PUBLIC_INTERFACE\" src=\"'' . getDolGlobalString(''USER_IMAGE_PUBLIC_INTERFACE'').''\">'';"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_MAIL_REQUIRED', 'string', NULL, 'user', 'Makes the email address field mandatory when creating or editing a user account.', 'Configured via admin/user.php:173 and enforced in user/class/user.class.php:1841 and :2252 (validation rejects missing/invalid email). The user/card.php form marks the email field with the CSS class ''fieldrequired'' when set. Also explicitly set to 0 at install/step5.php:306 during installation to allow creating the initial user without email.', 'Enabling this constant prevents saving a user record without a valid email address; disabling it makes email optional.', 'Any truthy value makes email mandatory; 0 or unset makes it optional.', 0, 0, 'admin/user.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["user/class/user.class.php:1841|check|if (getDolGlobalString(''USER_MAIL_REQUIRED'') && !isValidEmail($this->email)) {", "user/card.php:1369|read|print ''<tr><td''.(getDolGlobalString(''USER_MAIL_REQUIRED'') ? '' class=\"fieldrequired\"'' : '''').''>''.$langs->trans(\"EMail\").''</td>'';", "install/step5.php:306|write|$conf->global->USER_MAIL_REQUIRED = 0; \t\t\t// Force global option to be sure to create a new user with no email", "admin/user.php:173|check|if (!getDolGlobalString(''USER_MAIL_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_PASSWORD_GENERATED', 'string', NULL, 'core', 'Specifies the password-generation addon module used when creating or resetting user passwords.', 'Configurable via admin/security.php (write at line 61). Checked at admin/security.php lines 274 (compared to $key) and 293 (compared to ''Perso''), and at user/class/user.class.php line 2610 and core/class/fields/passwordfield.class.php line 138. The addon class name is built as ''modGeneratePass'' + ucfirst(value) at lines 140 and 2612.', 'Changing this value switches the password-generation strategy for new and reset passwords. The value ''none'' triggers generic rule handling; ''Perso'' triggers custom password handling.', 'String; name of the password-generation addon (e.g. ''Standard'', ''Perso'', ''none''). From user/card.php:3266: $usegenericrule = getDolGlobalString(''USER_PASSWORD_GENERATED'') == ''none'' ? 1 : 0;', 0, 0, 'admin/security.php|admin/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/security.php:61|write|if (!dolibarr_set_const($db, ''USER_PASSWORD_GENERATED'', GETPOST(\"value\", \"alphanohtml\"), ''chaine'', 0, '''', $conf->entity)) {", "admin/security.php:293|check|if (getDolGlobalString(''USER_PASSWORD_GENERATED'') == \"Perso\") {", "user/card.php:3266|read|$usegenericrule = getDolGlobalString(''USER_PASSWORD_GENERATED'') == ''none'' ? 1 : 0;", "core/class/fields/passwordfield.class.php:140|read|$modGeneratePassClass = ''modGeneratePass'' . ucfirst(getDolGlobalString(''USER_PASSWORD_GENERATED''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_PASSWORD_PATTERN', 'string', NULL, 'admin', 'Defines the semicolon-separated pattern rules for the custom password generator/validator.', 'Written via admin/security.php:171 and read in admin/system/security.php:603, admin/security.php:240, and core/modules/security/generate/modGeneratePassPerso.class.php:122 where it is exploded by '';''. If unset, the module initialises it to the default ''12;1;1;0;3;1'' (line 113).', 'Changing this constant alters the minimum length, character class requirements, and other constraints applied when generating or validating user passwords.', 'String: semicolon-separated integers, default ''12;1;1;0;3;1''.', 0, 0, 'admin/system/security.php|admin/security.php|admin/security.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/security.php:171|write|dolibarr_set_const($db, \"USER_PASSWORD_PATTERN\", $pattern, ''chaine'', 0, '''', $conf->entity);", "core/modules/security/generate/modGeneratePassPerso.class.php:113|write|dolibarr_set_const($db, \"USER_PASSWORD_PATTERN\", ''12;1;1;0;3;1'', ''chaine'', 0, '''', $conf->entity);", "admin/system/security.php:603|read|$tabConf = explode(\";\", getDolGlobalString(''USER_PASSWORD_PATTERN''));"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USER_PHOTO_ALLOW_EXTERNAL_DOWNLOAD', 'bool', NULL, 'user', 'Allows user profile photos to be downloaded by external (unauthenticated) requests.', 'Checked once in user/card.php at line 656. When set, external access to user photo downloads is permitted.', 'Enabling this constant opens user photo download to external requests; leaving it unset restricts photo download to authenticated sessions.', 'Truthy value to allow external download; empty or unset to restrict.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["user/card.php:656|check|if (getDolGlobalString(''USER_PHOTO_ALLOW_EXTERNAL_DOWNLOAD'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USE_COLOR_FOR_PROSPECTION_STATUS', 'bool', NULL, 'core', 'Enables color-coded display of prospection statuses in project list views.', 'Checked at core/lib/project.lib.php line 2615 (color applied when constant is set and status array is valid) and line 2817 (fallback rendering when constant is not set).', 'Enabling this constant causes prospection status labels to be rendered with colors. Disabling it falls back to plain text status display.', 'Boolean flag; absent/falsy = plain status display; truthy = color-coded status display.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/project.lib.php:2615|check|if (is_array($listofstatus) && getDolGlobalString(''USE_COLOR_FOR_PROSPECTION_STATUS'')) {", "core/lib/project.lib.php:2817|check|if (!getDolGlobalString(''USE_COLOR_FOR_PROSPECTION_STATUS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USE_PDFTK_FOR_PDF_CONCAT', 'bool', NULL, 'core', 'When enabled, uses the pdftk command-line tool to concatenate PDF files instead of the default PHP-based method.', 'Checked in core/actions_massactions.inc.php:903; when the string value is truthy, the pdftk tool is invoked for PDF concatenation during mass actions. No admin UI page is listed.', 'Enabling this constant requires pdftk to be installed on the server; it may improve compatibility or performance for PDF merging during mass actions.', 'Any truthy string = use pdftk for PDF concatenation; 0 or unset = use default PHP PDF library.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/actions_massactions.inc.php:903|check|if (getDolGlobalString(''USE_PDFTK_FOR_PDF_CONCAT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USE_RETAINED_WARRANTY_ONLY_FOR_SITUATION_FINAL', 'bool', NULL, 'core', 'Restricts the retained warranty display on situation invoices to the final situation invoice only.', 'Used in pdf_octopus.modules.php: at line 3056 warranty from previous invoices is shown only when this constant is NOT set; at line 3146 the final-invoice-only logic is applied when it IS set. At line 175 it is force-written to 1 in the module constructor. A TODO comment (line 3138) notes that this flag should eventually be stored on invoices directly.', 'When enabled, retained warranty details appear only on the final situation invoice; when disabled, warranty from prior situation invoices is also rendered.', '1 = show retained warranty only on final situation invoice; empty/unset = show on all situation invoices.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["pdf_octopus.modules.php:3138  // TODO : add a flag on invoices to store this conf USE_RETAINED_WARRANTY_ONLY_FOR_SITUATION_FINAL", "pdf_octopus.modules.php:3056|check|if (! empty($previousInvoice->retained_warranty) && !getDolGlobalString(''USE_RETAINED_WARRANTY_ONLY_FOR_SITUATION_FINAL'')) {", "pdf_octopus.modules.php:3146|check|if ($object->isSituationInvoice() && getDolGlobalString(''USE_RETAINED_WARRANTY_ONLY_FOR_SITUATION_FINAL'')) {", "pdf_octopus.modules.php:175|write|$conf->global->USE_RETAINED_WARRANTY_ONLY_FOR_SITUATION_FINAL = 1;"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('USE_STRICT_CSV_RULES', 'bool', NULL, 'core', 'Enables strict RFC-compliant CSV formatting rules, including quoting cells that contain line breaks.', 'Checked in core/lib/functions2.lib.php:3096 and 3098; comments in exportcsv.class.php:214 and 273 say ''Clean data and add encloser if required (depending on value of USE_STRICT_CSV_RULES)'', and functions2.lib.php:3092 states: ''Rule 1 CSV: No CR, LF in cells (except if USE_STRICT_CSV_RULES is 1, we can keep record as it is but we must add quotes)''.', 'Setting to 1 allows cells with line breaks to be kept intact but forces them to be enclosed in quotes; leaving unset strips CR/LF from cell values.', '0 or unset = strip CR/LF from cells; 1 = preserve CR/LF but wrap cell in quotes.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/functions2.lib.php:3092  // Rule 1 CSV: No CR, LF in cells (except if USE_STRICT_CSV_RULES is 1, we can keep record as it is but we must add quotes)", "core/modules/export/exportcsv.class.php:214  // Clean data and add encloser if required (depending on value of USE_STRICT_CSV_RULES)", "core/lib/functions2.lib.php:3096|check|if (getDolGlobalString(''USE_STRICT_CSV_RULES'') && $oldvalue != $newvalue) {", "core/lib/functions2.lib.php:3098|check|if (getDolGlobalInt(''USE_STRICT_CSV_RULES'') == 1) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('UTF8UNICODE', 'string', NULL, 'core', 'Acts as a feature flag tested during database character-set checks to detect whether the database uses utf8unicode collation.', 'Referenced in core/lib/admin.lib.php:227 in a comment explaining that constants prefixed with VMYSQLUTF8UNICODE map to testing $conf->global->UTF8UNICODE.', 'Exact behavior unclear from code alone; the constant appears to influence character-set validation logic in admin functions.', 'Non-empty/truthy = utf8unicode mode active; exact values not documented in the available payload.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["} else { // This is a test on a constant. For example when we have -- VMYSQLUTF8UNICODE, we test constant $conf->global->UTF8UNICODE"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT', 'bool', NULL, 'product', 'Allows stock movements to be recorded directly on a variant parent product instead of requiring selection of a specific child variant.', 'Set via variants/admin/admin.php:63 and read at admin.php:104. Checked in product/stock/replenish.php:431, product/stock/product.php:996, product/stock/product.php:1016, and product/stock/product.php:1026 to control whether parent-level stock movements are permitted.', 'When unset, stock movements on parent products with variants are excluded; only specific variant children can receive stock movements. When set, parent-level stock movements are allowed.', 'Truthy value = stock movements on variant parent allowed; empty/unset = movements restricted to child variants only.', 0, 0, 'variants/admin/admin.php|variants/admin/admin.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["variants/admin/admin.php:63|write|if (!dolibarr_set_const($db, ''VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT'', GETPOST(''VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT''), ''chaine'', 0, '''', $conf->entity)) {", "product/stock/replenish.php:431|check|if (isModEnabled(''variants'') && !getDolGlobalString(''VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT'')) {\t// Add test to exclude products that has variants", "product/stock/product.php:996|check|if ($variants && !getDolGlobalString(''VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT'')) {", "product/stock/product.php:1016|check|if (!$variants || getDolGlobalString(''VARIANT_ALLOW_STOCK_MOVEMENT_ON_VARIANT_PARENT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('VATUPDATE_NO_TRANSACTION', 'string', NULL, 'product', 'When enabled, disables database transaction wrapping during the bulk VAT rate update tool.', 'Checked in product/admin/product_tools.php at lines 79 and 284; when the integer value is truthy, the BEGIN/COMMIT transaction block is skipped during VAT updates. Configurable via product/admin/product_tools.php.', 'Disabling transactions (setting to 1) means VAT update operations will not be rolled back on error, leaving data in a partially updated state if a failure occurs.', '1 = no transaction used; 0 or unset = updates wrapped in a database transaction.', 0, 0, 'product/admin/product_tools.php|product/admin/product_tools.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["product/admin/product_tools.php:79|check|if (!getDolGlobalInt(''VATUPDATE_NO_TRANSACTION'')) {", "product/admin/product_tools.php:284|check|if (!getDolGlobalInt(''VATUPDATE_NO_TRANSACTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER', 'bool', NULL, 'commande', 'Prompts the user to select a source warehouse when creating or editing sales orders, if the stock module is enabled.', 'Configured via admin/order.php (write at line 247) and admin/stock.php (select array at line 847). Checked in commande/card.php at lines 2287, 2437, and 3156, and in expedition/shipment.php:429 and commande/list.php:1760, to conditionally show a warehouse selector.', 'When enabled, a warehouse selection field appears on order forms, allowing operators to associate a source warehouse with each order line. When disabled, no warehouse prompt is shown.', 'Truthy value from the configured select array; 0 or empty to disable.', 0, 0, 'admin/stock.php|admin/order.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/order.php:247|write|$res = dolibarr_set_const($db, \"WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER\", $value, ''chaine'', 0, '''', $conf->entity);", "admin/stock.php:847|read|print $form->selectarray(\"WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER\", $arrval, getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER''));", "commande/card.php:2437|check|if (isModEnabled(''stock'') && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER'')) {", "expedition/shipment.php:429|check|if (isModEnabled(''stock'') && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_ORDER'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WAREHOUSE_ASK_WAREHOUSE_DURING_PROJECT', 'bool', NULL, 'projet', 'Enables warehouse selection on the project elements overview page for stock-related operations.', 'Set via admin/stock.php:860 using a select array. Checked at projet/element.php:522 as the ''test'' condition for rendering the warehouse-related tab/element on the project overview. 2 occurrences across 2 files.', 'When unset, no warehouse selector is shown on the project elements page. When set to a truthy value and the stock module is enabled, the warehouse selection UI appears.', 'Truthy value = warehouse selection shown on project overview; 0 or unset = hidden.', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/stock.php:860|read|print $form->selectarray(\"WAREHOUSE_ASK_WAREHOUSE_DURING_PROJECT\", $arrval, getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROJECT''));", "projet/element.php:522|read|''test'' => isModEnabled(''stock'') && $user->hasRight(''stock'', ''lire'') && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROJECT'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL', 'bool', NULL, 'comm', 'Enables warehouse selection during proposal creation and validation when the stock module is active.', 'When enabled and the stock module is active, the proposal workflow requires a warehouse to be selected during line creation and approval steps. Configurable via admin/stock.php. Seen in comm/propal/card.php and comm/propal/list.php.', 'Enabling this forces users to specify a warehouse on proposals, preventing validation without a valid warehouse selection when stock is managed.', 'Empty/unset = no warehouse prompt on proposals; truthy value = warehouse selection required.', 0, 0, 'admin/stock.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/stock.php:835|read|print $form->selectarray(\"WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL\", $arrval, getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL''));", "comm/propal/card.php:2498|check|if (isModEnabled(''stock'') && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL'')) {", "comm/propal/card.php:2349|check|if (isModEnabled(''stock'') && $warehouse_id < 0 && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL'')) {", "comm/propal/list.php:1284|check|if (isModEnabled(''stock'') && getDolGlobalString(''WAREHOUSE_ASK_WAREHOUSE_DURING_PROPAL'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WAREHOUSE_DRAFT_WATERMARK', 'bool', NULL, 'core', 'Specifies the watermark text to stamp on draft stock movement PDF documents.', 'Checked and read in core/modules/movement/doc/pdf_standard_movementstock.modules.php at lines 969–970. When the movement object status is 0 (draft) and this constant is set, pdf_watermark() is called with the constant''s value as the watermark string. No admin UI write is present.', 'Setting this constant causes a watermark to appear on draft stock movement PDFs. Leaving it unset suppresses the watermark on those documents.', 'A non-empty string = watermark text rendered on draft movement PDFs; empty or unset = no watermark.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/movement/doc/pdf_standard_movementstock.modules.php:969|check|if ($object->status == 0 && getDolGlobalString(''WAREHOUSE_DRAFT_WATERMARK'')) {", "core/modules/movement/doc/pdf_standard_movementstock.modules.php:970|read|pdf_watermark($pdf, $outputlangs, $this->page_hauteur, $this->page_largeur, ''mm'', getDolGlobalString(''WAREHOUSE_DRAFT_WATERMARK''));"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBHOOK_POST_SEND_DATA_AS_PARAM_STRING', 'string', NULL, 'core', 'Enables legacy compatibility mode that sends webhook POST data as a URL-encoded parameter string instead of JSON.', 'Checked in core/triggers/interface_95_modWebhook_WebhookTriggers.class.php:122 and webhook/target_card.php:177, both annotated ''// For compatibility with v20- versions''.', 'When set, webhook payloads are sent as URL-encoded parameter strings for compatibility with pre-v20 receivers; when unset, the current default encoding is used.', 'Empty/unset = current encoding; non-empty = URL-encoded param string (v20- compatibility mode).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_95_modWebhook_WebhookTriggers.class.php:122|check|if (getDolGlobalString(''WEBHOOK_POST_SEND_DATA_AS_PARAM_STRING'')) {\t\t// For compatibility with v20- versions", "webhook/target_card.php:177|check|if (getDolGlobalString(''WEBHOOK_POST_SEND_DATA_AS_PARAM_STRING'')) {\t\t// For compatibility with v20- versions"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBHOOK_TARGET_ADDON', 'string', NULL, 'webhook', 'Specifies the class name of the webhook target add-on module to use, defaulting to mod_target_standard.', 'In webhook/class/target.class.php at line 978, the value is read into $classname with a fallback of ''mod_target_standard''. No admin UI write path is present.', 'Changing this selects a different webhook target add-on implementation; the default ''mod_target_standard'' is used when not set.', 'String: PHP class name of the target add-on (default ''mod_target_standard'')', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["webhook/class/target.class.php:978|read|$classname = getDolGlobalString(''WEBHOOK_TARGET_ADDON'', ''mod_target_standard'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_', 'string', NULL, 'webportal', 'Dynamic prefix used to build per-module web portal access control constants (e.g. WEBPORTAL_<MODULE>_LIST_ACCESS, WEBPORTAL_<MODULE>_CARD_ACCESS).', 'Used as a runtime prefix in webportal/controllers/document.controller.class.php:190 (getDolGlobalInt(''WEBPORTAL_'' . $moduleNameUpperEn . ''_LIST_ACCESS'')) and webportal/class/html.formcardwebportal.class.php:180 (getDolGlobalString(''WEBPORTAL_'' . $elementEnUpper . ''_CARD_ACCESS'', ''hidden'')). Only 2 occurrences found; actual constants are dynamic.', 'These dynamically constructed constants control list and card access visibility for each module in the web portal; the default for card access is ''hidden''.', 'Dynamic string: ''hidden'' = not accessible; other values control access level', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/controllers/document.controller.class.php:190|check|if (getDolGlobalInt(''WEBPORTAL_'' . $moduleNameUpperEn . ''_LIST_ACCESS'')", "webportal/class/html.formcardwebportal.class.php:180|read|$elementCardAccess = getDolGlobalString(''WEBPORTAL_'' . $elementEnUpper . ''_CARD_ACCESS'', ''hidden'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_BANNER_BACKGROUND', 'string', NULL, 'webportal', 'Sets the background image or color for the web portal banner area.', 'Read in webportal/class/webPortalTheme.class.php (line 121) to set `$this->bannerBackground`.', 'Setting this value applies a custom background to the portal banner; leaving it empty uses the theme default.', 'String (CSS value or image URL); empty means default theme background.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:121|read|$this->bannerBackground = getDolGlobalString(''WEBPORTAL_BANNER_BACKGROUND'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_BANNER_BACKGROUND_IS_DARK', 'string', NULL, 'webportal', 'Indicates whether the web portal banner background is dark, to switch text to a light colour scheme.', 'Read as integer in webportal/class/webPortalTheme.class.php (line 122) to set `$this->bannerUseDarkTheme`.', 'Enabling this flag switches banner text and icons to a light colour scheme suited for dark backgrounds.', '0 = banner background is light (default); 1 = banner background is dark.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:122|read|$this->bannerUseDarkTheme = getDolGlobalInt(''WEBPORTAL_BANNER_BACKGROUND_IS_DARK'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_CDN_URL', 'string', NULL, 'webportal', 'Overrides the base CDN URL used to serve static assets (CSS, JS, images) in the web portal.', 'Read in webportal/class/context.class.php (line 217) as `$this->cdnUrl = getDolGlobalString(''WEBPORTAL_CDN_URL'', dol_buildpath(''/public/includes/'', 3))`.', 'Setting this value redirects all static asset requests in the web portal to the specified CDN URL.', 'String (CDN base URL); empty means the default local path `/public/includes/` is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/context.class.php:217|read|$this->cdnUrl = getDolGlobalString(''WEBPORTAL_CDN_URL'', dol_buildpath(''/public/includes/'', 3));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_CUSTOM_CSS', 'string', NULL, 'webportal', 'Stores the custom CSS content for the web portal, served directly as part of the portal''s custom stylesheet.', 'Written in webportal/admin/configcss.php:85 from CSS editor input. Read in webportal/admin/configcss.php:147 for display and printed directly in public/webportal/css/themes/custom.css.php:101.', 'Changing this constant updates the custom CSS applied to the public web portal immediately upon the next page load.', 'String containing raw CSS; empty/unset = no custom styles applied.', 0, 0, 'webportal/admin/configcss.php|webportal/admin/configcss.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/admin/configcss.php:85|write|dolibarr_set_const($db, \"WEBPORTAL_CUSTOM_CSS\", $csscontent, ''chaine'', 0, '''', $conf->entity);", "webportal/admin/configcss.php:147|read|$customcssValue = getDolGlobalString(''WEBPORTAL_CUSTOM_CSS'');", "public/webportal/css/themes/custom.css.php:101|read|print getDolGlobalString(''WEBPORTAL_CUSTOM_CSS'');"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_DOCUMENT_LIST_ACCESS', 'string', NULL, 'webportal', 'Controls whether the document list section is accessible in the web portal.', 'Checked at public/webportal/tpl/menu.tpl.php:86 to conditionally show the document list menu item, and read at webportal/controllers/documentlist.controller.class.php:46 to set the access right for the document list controller.', 'Setting a non-zero value grants access to the document list in the web portal; a zero or absent value hides it.', '0 or not set = document list hidden/inaccessible; non-zero = document list accessible.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:86|check|if (getDolGlobalInt(''WEBPORTAL_DOCUMENT_LIST_ACCESS'')) {", "webportal/controllers/documentlist.controller.class.php:46|read|$this->accessRight = getDolGlobalInt(''WEBPORTAL_DOCUMENT_LIST_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_FICHEINTER_LIST_ACCESS', 'string', NULL, 'webportal', 'Controls whether the web portal exposes the intervention sheets list to portal users.', 'Checked in public/webportal/tpl/menu.tpl.php:66 to show the menu item and read in webportal/controllers/ficheinterlist.controller.class.php:39 to set the controller access right. No admin UI write found; HIDDEN_GUESS is 1. Only 2 occurrences found.', 'When set to a non-zero value and the intervention module is enabled, portal users can access the intervention list; otherwise it is hidden.', 'Integer: non-zero = access enabled; 0 or not set = access disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:66|check|if (isModEnabled(''intervention'') && getDolGlobalInt(''WEBPORTAL_FICHEINTER_LIST_ACCESS'')) {", "webportal/controllers/ficheinterlist.controller.class.php:39|read|$this->accessRight = isModEnabled(''intervention'') && getDolGlobalInt(''WEBPORTAL_FICHEINTER_LIST_ACCESS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_INVOICE_LIST_ACCESS', 'string', NULL, 'public', 'Controls whether the web portal exposes the customer invoices list to portal users.', 'Checked in public/webportal/tpl/menu.tpl.php:56 and public/webportal/tpl/home.tpl.php:34 to show the menu item, and read in webportal/controllers/invoicelist.controller.class.php:40 to set the controller access right. No admin UI write found; HIDDEN_GUESS is 1.', 'When set to a non-zero value and the invoice module is enabled, portal users can access the invoices list; otherwise the list is hidden.', 'Integer: non-zero = access enabled; 0 or not set = access disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:56|check|if (isModEnabled(''invoice'') && getDolGlobalInt(''WEBPORTAL_INVOICE_LIST_ACCESS'')) {", "public/webportal/tpl/home.tpl.php:34|check|<?php if (isModEnabled(''invoice'') && getDolGlobalInt(''WEBPORTAL_INVOICE_LIST_ACCESS'')) : ?>", "webportal/controllers/invoicelist.controller.class.php:40|read|$this->accessRight = isModEnabled(''invoice'') && getDolGlobalInt(''WEBPORTAL_INVOICE_LIST_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_LOGIN_BACKGROUND', 'string', NULL, 'webportal', 'Sets the background image or color for the web portal login page.', 'Read in webportal/class/webPortalTheme.class.php (line 120) to set `$this->loginBackground`.', 'Setting this value applies a custom background to the login page; leaving it empty uses the theme default.', 'String (CSS value or image URL); empty means default theme background.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:120|read|$this->loginBackground = getDolGlobalString(''WEBPORTAL_LOGIN_BACKGROUND'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_LOGIN_BY_MEMBER_ACCOUNT', 'string', NULL, 'public', 'Controls whether web portal authentication is performed against member accounts rather than third-party (societe) accounts.', 'Checked at public/webportal/webportal.main.inc.php:192, :204, :241, and :297 to branch between member-based and third-party-based login flows. When non-zero and the member module is enabled, member account credentials are used for authentication.', 'Switching this value changes whether portal users are authenticated as members or as third-party contacts, affecting which records are accessible after login.', '0 or unset = third-party (societe) login; non-zero = member account login', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/webportal/webportal.main.inc.php:192|check|if (!$error && (isModEnabled(''societe'') && !getDolGlobalInt(''WEBPORTAL_LOGIN_BY_MEMBER_ACCOUNT''))) {", "public/webportal/webportal.main.inc.php:241|check|if (isModEnabled(''member'') && getDolGlobalInt(''WEBPORTAL_LOGIN_BY_MEMBER_ACCOUNT'') && !getDolGlobalString(''ADHERENT_LOGIN_NOT_REQUIRED'')) {", "public/webportal/webportal.main.inc.php:297|check|if (!getDolGlobalInt(''WEBPORTAL_LOGIN_BY_MEMBER_ACCOUNT'')) {", "public/webportal/webportal.main.inc.php:204|read|} elseif (!$error && isModEnabled(''member'') && getDolGlobalInt(''WEBPORTAL_LOGIN_BY_MEMBER_ACCOUNT'') && !getDolGlobalString(''ADHERENT_LOGIN_NOT_REQUIRED'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_LOGIN_BY_MODULE', 'string', NULL, 'public', 'Enables module-based login handling for the web portal by delegating authentication to registered webportallogin module parts.', 'Checked as an integer flag at public/webportal/webportal.main.inc.php:137 in conjunction with $conf->modules_parts[''webportallogin'']; when non-zero and module parts are registered, module-based login logic is invoked. No admin UI write found.', 'When enabled, the web portal login process is handled by registered module parts instead of the default mechanism.', '0 or unset = default login; non-zero = module-based login (requires registered webportallogin module parts)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/webportal/webportal.main.inc.php:137|check|if (getDolGlobalInt(''WEBPORTAL_LOGIN_BY_MODULE'') && !empty($conf->modules_parts[''webportallogin'']) && is_array($conf->modules_parts[''webportallogin''])) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_LOGIN_FORM_THEME', 'string', NULL, 'public', 'Sets the visual theme for the web portal login form.', 'Read at public/webportal/tpl/header_login.tpl.php:63 with a default of ''default'' if not set. No admin UI write found.', 'Changing this value alters the theme applied to the web portal login page.', 'A theme name string; defaults to ''default'' if unset.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["public/webportal/tpl/header_login.tpl.php:63|read|$loginFormTheme = getDolGlobalString(''WEBPORTAL_LOGIN_FORM_THEME'', ''default'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_LOGIN_LOGO_URL', 'string', NULL, 'webportal', 'Overrides the logo URL displayed on the web portal login page.', 'Read in webportal/class/webPortalTheme.class.php (line 118) to set `$this->loginLogoUrl`. Falls back to the default `$urllogo` when not defined.', 'Setting this value replaces the login page logo with the specified URL; leaving it empty uses the system default logo.', 'String (URL); empty means the default system logo URL is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:118|read|$this->loginLogoUrl = getDolGlobalString(''WEBPORTAL_LOGIN_LOGO_URL'', $urllogo);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_MEMBER_CARD_ACCESS', 'string', NULL, 'webportal', 'Controls the access level for the member card page in the web portal.', 'Read in webportal/controllers/membercard.controller.class.php at lines 43 and 72, and in public/webportal/tpl/menu.tpl.php:106, stored in $cardAccess and used to determine portal display and access. No admin UI write found; HIDDEN_GUESS is 1.', 'The value of this constant is used directly as the cardAccess variable controlling which portal users can view the member card.', 'String: access control value (exact semantics determined by controller logic); empty = no access', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/controllers/membercard.controller.class.php:43|read|$cardAccess = getDolGlobalString(''WEBPORTAL_MEMBER_CARD_ACCESS'');", "webportal/controllers/membercard.controller.class.php:72|read|$cardAccess = getDolGlobalString(''WEBPORTAL_MEMBER_CARD_ACCESS'');", "public/webportal/tpl/menu.tpl.php:106|read|$cardAccess = getDolGlobalString(''WEBPORTAL_MEMBER_CARD_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_MENU_LOGO_URL', 'string', NULL, 'webportal', 'Overrides the logo URL displayed in the web portal navigation menu.', 'Read in webportal/class/webPortalTheme.class.php (line 119) to set `$this->menuLogoUrl`. Falls back to `$this->loginLogoUrl` when not defined.', 'Setting this value replaces the menu logo with the specified URL; leaving it empty falls back to the login logo URL.', 'String (URL); empty means the login logo URL is used as fallback.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:119|read|$this->menuLogoUrl = getDolGlobalString(''WEBPORTAL_MENU_LOGO_URL'', $this->loginLogoUrl);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_ORDER_LIST_ACCESS', 'string', NULL, 'public', 'Controls whether the order list section is accessible in the web portal.', 'Checked at public/webportal/tpl/menu.tpl.php:46 and public/webportal/tpl/home.tpl.php:28 to conditionally show order-related UI, and read at webportal/controllers/orderlist.controller.class.php:41 to set the access right. The order module must also be enabled.', 'Setting a non-zero value (with the order module enabled) grants access to the order list in the web portal; a zero or absent value hides it.', '0 or not set = order list hidden/inaccessible; non-zero = order list accessible (requires order module enabled).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:46|check|if (isModEnabled(''order'') && getDolGlobalInt(''WEBPORTAL_ORDER_LIST_ACCESS'')) {", "public/webportal/tpl/home.tpl.php:28|check|<?php if (isModEnabled(''order'') && getDolGlobalInt(''WEBPORTAL_ORDER_LIST_ACCESS'')) : ?>", "webportal/controllers/orderlist.controller.class.php:41|read|$this->accessRight = isModEnabled(''order'') && getDolGlobalInt(''WEBPORTAL_ORDER_LIST_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_PARAMS_REV', 'string', NULL, 'webportal', 'Stores a revision counter for web portal CSS parameters, used as a cache-busting query string on CSS file URLs.', 'Incremented by 1 in webportal/admin/configcss.php:90 each time portal CSS settings are saved. Read in public/webportal/tpl/header.tpl.php at lines 65 and 66 as a revision query parameter on CSS file links.', 'Incrementing this value forces browsers to reload the portal CSS files, clearing cached styles after configuration changes.', 'Integer revision counter; incremented automatically on each CSS configuration save via the admin UI.', 0, 0, 'webportal/admin/configcss.php|webportal/admin/configcss.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/admin/configcss.php:90|write|dolibarr_set_const($db, \"WEBPORTAL_PARAMS_REV\", getDolGlobalInt(''WEBPORTAL_PARAMS_REV'') + 1, ''chaine'', 0, '''', $conf->entity);", "public/webportal/tpl/header.tpl.php:65|read|<link rel=\"stylesheet\" href=\"<?php print $context->rootUrl.''css/style.css.php?revision=''.getDolGlobalInt(''WEBPORTAL_PARAMS_REV''); ?>\">", "public/webportal/tpl/header.tpl.php:66|read|<link rel=\"stylesheet\" type=\"text/css\" href=\"<?php print $context->rootUrl.''css/themes/custom.css.php?revision=''.getDolGlobalInt(''WEBPORTAL_PARAMS_REV''); ?>\">"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_PARTNERSHIP_CARD_ACCESS', 'string', NULL, 'webportal', 'Controls the access level for the partnership card page in the web portal.', 'Read in webportal/controllers/partnershipcard.controller.class.php at lines 43 and 71, and in public/webportal/tpl/menu.tpl.php:121, stored in $cardAccess and used to determine portal display and access. No admin UI write found; HIDDEN_GUESS is 1.', 'The value of this constant is used directly as the cardAccess variable controlling which portal users can view the partnership card.', 'String: access control value (exact semantics determined by controller logic); empty = no access', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/controllers/partnershipcard.controller.class.php:43|read|$cardAccess = getDolGlobalString(''WEBPORTAL_PARTNERSHIP_CARD_ACCESS'');", "webportal/controllers/partnershipcard.controller.class.php:71|read|$cardAccess = getDolGlobalString(''WEBPORTAL_PARTNERSHIP_CARD_ACCESS'');", "public/webportal/tpl/menu.tpl.php:121|read|$cardAccess = getDolGlobalString(''WEBPORTAL_PARTNERSHIP_CARD_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_PRIMARY_COLOR', 'string', NULL, 'webportal', 'Overrides the primary accent colour used throughout the web portal theme.', 'Checked and read in webportal/class/webPortalTheme.class.php (lines 134-135); when set, its value overrides the default computed `$outColor`.', 'Setting this value changes the primary colour (buttons, links, highlights) across the web portal.', 'String (CSS colour value e.g. hex or rgb); empty means the theme default colour is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/webPortalTheme.class.php:134|check|if (getDolGlobalString(''WEBPORTAL_PRIMARY_COLOR'')) {", "webportal/class/webPortalTheme.class.php:135|read|$outColor = getDolGlobalString(''WEBPORTAL_PRIMARY_COLOR'');"]', 'low', NULL);
