INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_SHARED_DOCS_DIR', 'string', NULL, 'webportal', 'Specifies the directory name used for shared documents in the web portal.', 'Read at webportal/controllers/shareddocuments.controller.class.php:96 with a default fallback: ''$shared_dir_name = getDolGlobalString(''WEBPORTAL_SHARED_DOCS_DIR'', ''Documentscomptes'')''. No admin UI write path is present.', 'Setting this constant changes the directory from which shared documents are served in the web portal; the default is ''Documentscomptes''.', 'Not set = uses default directory ''Documentscomptes''; string = custom shared documents directory name.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/controllers/shareddocuments.controller.class.php:96|read|$shared_dir_name = getDolGlobalString(''WEBPORTAL_SHARED_DOCS_DIR'', ''Documentscomptes'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_SHARED_DOCUMENT_ACCESS', 'string', NULL, 'webportal', 'Controls whether the shared documents section is accessible in the web portal.', 'Checked at public/webportal/tpl/menu.tpl.php:96 to conditionally show the shared documents menu item, and read at webportal/controllers/shareddocuments.controller.class.php:36 to set the access right for the shared documents controller.', 'Setting a non-zero value grants access to the shared documents section in the web portal; a zero or absent value hides it.', '0 or not set = shared documents section hidden/inaccessible; non-zero = shared documents section accessible.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:96|check|if (getDolGlobalInt(''WEBPORTAL_SHARED_DOCUMENT_ACCESS'')) {", "webportal/controllers/shareddocuments.controller.class.php:36|read|$this->accessRight = getDolGlobalInt(''WEBPORTAL_SHARED_DOCUMENT_ACCESS'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_TICKET_LIST_ACCESS', 'string', NULL, 'webportal', 'Controls whether the web portal exposes the ticket list to portal users.', 'Checked in public/webportal/tpl/menu.tpl.php:76 to show the menu item and read in webportal/controllers/ticketlist.controller.class.php:45 to set the controller access right. No admin UI write found; HIDDEN_GUESS is 1. Only 2 occurrences found.', 'When set to a non-zero value and the ticket module is enabled, portal users can access the ticket list; otherwise it is hidden.', 'Integer: non-zero = access enabled; 0 or not set = access disabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["public/webportal/tpl/menu.tpl.php:76|check|if (isModEnabled(''ticket'') && getDolGlobalInt(''WEBPORTAL_TICKET_LIST_ACCESS'')) {", "webportal/controllers/ticketlist.controller.class.php:45|read|$this->accessRight = isModEnabled(''ticket'') && getDolGlobalInt(''WEBPORTAL_TICKET_LIST_ACCESS'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_TITLE', 'string', NULL, 'webportal', 'Overrides the application title displayed in the web portal, falling back to the company name.', 'Read in webportal/class/context.class.php (line 206) as `$this->appliName = getDolGlobalString(''WEBPORTAL_TITLE'', getDolGlobalString(''MAIN_INFO_SOCIETE_NOM''))` and in public/webportal/tpl/menu.tpl.php (line 253).', 'Setting this value replaces the company name with a custom title in the web portal header and menu.', 'String (custom title text); empty means the company name (MAIN_INFO_SOCIETE_NOM) is used.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/class/context.class.php:206|read|$this->appliName = getDolGlobalString(''WEBPORTAL_TITLE'', getDolGlobalString(''MAIN_INFO_SOCIETE_NOM''));", "public/webportal/tpl/menu.tpl.php:253|read|$brandTitle = getDolGlobalString(''WEBPORTAL_TITLE'') ? getDolGlobalString(''WEBPORTAL_TITLE'') : getDolGlobalString(''MAIN_INFO_SOCIETE_NOM'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBPORTAL_USER_LOGGED', 'string', NULL, 'webportal', 'Specifies the Dolibarr user ID used as the logged-in user identity for web portal sessions.', 'Read in webportal/admin/setup.php:78 to pre-select the user in the admin setup form, and in public/webportal/webportal.main.inc.php:278 to load the user context for portal requests.', 'Changing this value changes which Dolibarr user account is used to authenticate and authorize web portal sessions.', 'Integer user ID referencing a Dolibarr user; must be set to a valid active user for the portal to function correctly.', 0, 0, 'webportal/admin/setup.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webportal/admin/setup.php:78|read|$userList = $formSetup->form->select_dolusers(getDolGlobalInt(''WEBPORTAL_USER_LOGGED''), ''WEBPORTAL_USER_LOGGED'', 1, null, 0, '''', '''', ''0'', 0, 0, '''', 0, '''', '''', 1, 2);", "public/webportal/webportal.main.inc.php:278|read|$user_id = getDolGlobalInt(''WEBPORTAL_USER_LOGGED'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSERVICES_KEY', 'string', NULL, 'webservices', 'Stores the authentication key that SOAP webservice clients must supply to access Dolibarr webservices.', 'Configured via webservices/admin/index.php:56 (write) and displayed in the admin form at line 96. Validated in core/lib/ws.lib.php:44 where the client-supplied ''dolibarrkey'' is compared against this constant.', 'Changing this key invalidates existing client configurations; clients must be updated with the new key to continue accessing webservices.', 'Arbitrary string; must match the ''dolibarrkey'' value sent by SOAP clients', 0, 0, 'webservices/admin/index.php|webservices/admin/index.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["webservices/admin/index.php:56|write|$i += dolibarr_set_const($db, ''WEBSERVICES_KEY'', GETPOST(\"WEBSERVICES_KEY\"), ''chaine'', 0, '''', $conf->entity);", "core/lib/ws.lib.php:44|read|if (!$error && ($authentication[''dolibarrkey''] != $conf->global->WEBSERVICES_KEY)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_', 'string', NULL, 'website', 'Prefix for per-website security policy constants (e.g. WEBSITE_{id}_SECURITY_FORCECSP) that store HTTP security header values for each website.', 'Read and displayed in admin/system/security.php at lines 909–923 for each website object; consumed in core/website.inc.php:156 and website/index.php:4456 to apply Content Security Policy and other HTTP security headers.', 'Setting these per-website constants overrides the HTTP security headers served with the website; leaving them unset results in undefined/default header values.', 'Any string value representing an HTTP security header policy; unset means the header uses the default (displayed as ''Undefined'' in the admin UI).', 0, 0, 'admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php|admin/system/security.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/system/security.php:909|read|print ''<strong>WEBSITE_''.$obj->id.''_SECURITY_FORCERP</strong> = ''.getDolGlobalString(''WEBSITE_''.$obj->id.''_SECURITY_FORCERP'', ''<span class=\"opacitymedium\">''.$langs->trans(\"Undefine", "admin/system/security.php:915|check|if (getDolGlobalString(''WEBSITE_''.$obj->id.''_SECURITY_FORCECSPPRO'')) {", "core/website.inc.php:156|read|$contentsecuritypolicy = getDolGlobalString(''WEBSITE_''.$website->id.''_SECURITY_FORCECSPRO'');", "website/index.php:4456|check|if (getDolGlobalString(\"WEBSITE_\".$object->id.\"_SECURITY_FORCECSPRO\")) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ADD_CSS_TO_BODY', 'string', NULL, 'core', 'Stores additional CSS class names to inject into the body tag of website pages.', 'Checked and applied in core/lib/website.lib.php:434-435. When set, the value is appended to the existing class attribute of the <body id="bodywebsite" class="bodywebsite"> tag via str_replace.', 'Setting this constant adds the specified CSS classes to the website body tag, allowing custom styling. Clearing it leaves the body tag with its default classes only.', 'Any non-empty string = CSS class name(s) appended to the body element; empty/unset = no additional classes.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["website.lib.php:434|if (getDolGlobalString(''WEBSITE_ADD_CSS_TO_BODY'')) {", "website.lib.php:435|$content = str_replace(''<body id=\"bodywebsite\" class=\"bodywebsite'', ''<body id=\"bodywebsite\" class=\"bodywebsite '' . getDolGlobalString(''WEBSITE_ADD_CSS_TO_BODY''), $content);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ADD_PAGE_TYPE_PHPLIB', 'string', NULL, 'core', 'Controls whether PHP library page type is available when adding new website pages.', 'Checked in core/class/html.formwebsite.class.php:143; when unset the PHP library page type option is excluded from the page creation form.', 'When set, the PHP library page type becomes available as an option for new website pages.', 'Bool-like string: empty/unset = PHP library page type hidden; non-empty = PHP library page type shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/html.formwebsite.class.php:143|check|if (!getDolGlobalString(''WEBSITE_ADD_PAGE_TYPE_PHPLIB'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ADD_RSS_FEED_INTO_SITEMAP', 'string', NULL, 'website', 'Controls whether an RSS feed wrapper entry is included in the generated sitemap.', 'Checked in website/index.php:2934 alongside the $addrsswrapper condition to gate inclusion of the RSS feed entry in the sitemap output.', 'When set to a non-zero integer, the RSS feed is added to the sitemap; when unset or zero, it is omitted.', '0 or empty = RSS feed not added to sitemap; non-zero = RSS feed entry included.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:2934|check|if ($addrsswrapper && getDolGlobalInt(''WEBSITE_ADD_RSS_FEED_INTO_SITEMAP'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ALLOW_CKEDITOR', 'bool', NULL, 'website', 'Controls whether the CKEditor rich text editor is available in the website inline editor.', 'Checked in website/index.php:3679 using getDolGlobalInt to conditionally enable the CKEditor toolbar option in the website editing interface.', 'When set to a non-zero value, CKEditor is offered as an editing option in the website module; when unset or zero, it is not available.', '0 or empty = CKEditor not available; non-zero = CKEditor enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:3679|check|if (getDolGlobalInt(''WEBSITE_ALLOW_CKEDITOR'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ALLOW_FRAMES_ON_ALL_PAGES', 'bool', NULL, 'core', 'Globally permits all public website pages to be embedded in iframes, overriding per-page frame restrictions.', 'Checked in core/website.inc.php:119, 137, and 289 alongside the per-page $websitepage->allowed_in_frames flag; when set it bypasses the individual page restriction. Also checked in website template wrapper files. No admin UI is present.', 'Enabling this constant allows any page of the Dolibarr public website to be embedded in an iframe on any third-party site, which reduces clickjacking protection.', 'Boolean flag: truthy = framing allowed on all pages; 0 or unset = per-page allowed_in_frames setting is enforced.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/website.inc.php:119|check|if (empty($websitepage->allowed_in_frames) && !getDolGlobalString(''WEBSITE_ALLOW_FRAMES_ON_ALL_PAGES'')) {", "core/website.inc.php:137|check|if (empty($websitepage->allowed_in_frames) && !getDolGlobalString(''WEBSITE_ALLOW_FRAMES_ON_ALL_PAGES'')) {", "install/doctemplates/websites/website_template-association_exp/containers/wrapper.php:75|check|if (!getDolGlobalString(''WEBSITE_ALLOW_FRAMES_ON_ALL_PAGES'')) {", "website/samples/wrapper.php:80|check|if (!getDolGlobalString(''WEBSITE_ALLOW_FRAMES_ON_ALL_PAGES'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_ALLOW_OVERWRITE_GIT_SOURCE', 'bool', NULL, 'website', 'Allows overwriting of Git-tracked website source files during a site export or overwrite operation.', 'Checked in website/class/website.class.php:1787 and website/index.php:2619, :3302, :3305. When enabled, a UI element that would otherwise be hidden becomes visible. A commented-out link at website/index.php:3309 references the export-into-GIT action.', 'Enabling this constant permits overwriting files tracked by Git during website operations, which can result in loss of custom modifications to source files.', '0 (overwrite not allowed) or 1 (overwrite allowed)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:3302|read|$extraCssClass = getDolGlobalString(''WEBSITE_ALLOW_OVERWRITE_GIT_SOURCE'') ? ''hideobject'' : '''';", "website/class/website.class.php:1787|check|if (getDolGlobalString(''WEBSITE_ALLOW_OVERWRITE_GIT_SOURCE'')) {", "website/index.php:2619|check|if (getDolGlobalString(''WEBSITE_ALLOW_OVERWRITE_GIT_SOURCE'')) {", "website/index.php:3305|check|if (getDolGlobalString(''WEBSITE_ALLOW_OVERWRITE_GIT_SOURCE'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_DISABLE_CACHE_OF_CONTAINERS', 'bool', NULL, 'core', 'When set, disables cache for website container content even when a positive cache delay is configured.', 'Checked in a single location in core/lib/website.lib.php:624, where the caching block is only entered when both $cachedelay > 0 and this constant is falsy.', 'Enabling this bypasses container caching regardless of the configured cache delay. Disabling (or leaving unset) allows caching to proceed based on the cache delay.', 'Empty/unset = container caching enabled (subject to cachedelay); any truthy value = container caching disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["website.lib.php:624|if ($cachedelay > 0 && !getDolGlobalString(\"WEBSITE_DISABLE_CACHE_OF_CONTAINERS\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_DISABLE_MAIN_LANGUAGE_INTO_LANGSUBDIR', 'bool', NULL, 'core', 'Prevents the main website language from being served under a language subdirectory path.', 'Checked as a negated condition at core/lib/website2.lib.php:102 and :530, both inside blocks that also test $object->otherlang. When set, the main-language-into-subdir routing logic is skipped.', 'Enabling this constant keeps the primary language content at the root URL path rather than under a language-code subdirectory, which affects multilingual URL structure.', 'Any truthy value disables main-language subdirectory routing; unset enables it when otherlang is configured.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:102|check|if (!getDolGlobalString(''WEBSITE_DISABLE_MAIN_LANGUAGE_INTO_LANGSUBDIR'') && !empty($object->otherlang)) {", "core/lib/website2.lib.php:530|check|if (!getDolGlobalString(''WEBSITE_DISABLE_MAIN_LANGUAGE_INTO_LANGSUBDIR'') && is_object($object) && !empty($object->otherlang)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_DISALLOW_DOLLAR_UNDERSCORE', 'bool', NULL, 'core', 'Disallows use of dollar-underscore ($_) variable patterns in website PHP page execution.', 'Checked at core/lib/website2.lib.php:976; when set, processing rejects or sanitises $_ usage in website page code. No comment is present in the payload.', 'Enabling this constant adds a security restriction against $_-style variable access in website page PHP; disabling it permits such patterns.', 'Any truthy value disallows $_ usage; unset permits it.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:976|check|if (getDolGlobalString(\"WEBSITE_DISALLOW_DOLLAR_UNDERSCORE\")) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_EDITINLINE', 'string', NULL, 'website', 'Enables inline editing mode in the website editor, allowing content to be edited directly on the page.', 'Set at website/index.php:469, deleted at line 475, and blocked by a commented line at 481 (''// Force disable of edit inline''). Checked at lines 3874 and 5983, and read at line 3715 to set the JavaScript variable isEditingEnabled.', 'When enabled, the website editor activates inline editing mode; when disabled, inline editing is not available.', 'Empty/unset or 0 = inline editing disabled; 1 = inline editing enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:481  //dolibarr_set_const($db, ''WEBSITE_EDITINLINE'', 0); // Force disable of edit inline", "website/index.php:469|write|dolibarr_set_const($db, ''WEBSITE_EDITINLINE'', 1);", "website/index.php:3715|read|var isEditingEnabled = ''.(getDolGlobalString(\"WEBSITE_EDITINLINE\") ? ''true'' : ''false'').'';", "website/index.php:3874|check|if (!getDolGlobalString(''WEBSITE_EDITINLINE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_EDITINLINE_SAVE_CKEDITOR_EDIT', 'string', NULL, 'website', 'Controls the save behaviour when inline editing is performed with CKEditor in the website module.', 'Checked in website/index.php at lines 464 and 3801 to branch between two save code paths for CKEditor inline editing.', 'When set, a specific CKEditor save path is used; when unset, the alternative save path is taken.', 'Empty/unset = default save path; non-empty = CKEditor-specific save path.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:464|check|if (!getDolGlobalString(''WEBSITE_EDITINLINE_SAVE_CKEDITOR_EDIT'')) {", "website/index.php:3801|check|if (getDolGlobalString(''WEBSITE_EDITINLINE_SAVE_CKEDITOR_EDIT'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_EXPORT_KEEP_FILES_OF_PAGES', 'string', NULL, 'website', 'Preserves existing page files during a website export instead of deleting them first.', 'Checked once at website/class/website.class.php:1144. No admin UI write was found; HIDDEN_GUESS is 1.', 'When enabled, existing files in the export destination are kept before writing new content during a website export.', '0 (delete before export) or 1 (keep existing files)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/class/website.class.php:1144|check|if (!getDolGlobalInt(''WEBSITE_EXPORT_KEEP_FILES_OF_PAGES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_EXPORT_SQL_ON_SEVERAL_LINES', 'string', NULL, 'website', 'Formats exported SQL INSERT statements across multiple lines instead of a single line per record.', 'Checked at website/class/website.class.php:1196 and :1217 to choose between single-line and multi-line SQL formatting during export. No admin UI write was found; HIDDEN_GUESS is 1.', 'Enabling this constant makes the exported SQL file more readable by splitting each INSERT statement over multiple lines.', '0 (single-line SQL) or 1 (multi-line SQL)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/class/website.class.php:1196|check|if (getDolGlobalString(''WEBSITE_EXPORT_SQL_ON_SEVERAL_LINES'')) {", "website/class/website.class.php:1217|check|if (getDolGlobalString(''WEBSITE_EXPORT_SQL_ON_SEVERAL_LINES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_FORCE_DOCTYPE_HTML5', 'string', NULL, 'core', 'Forces the website page renderer to output an HTML5 doctype declaration.', 'Checked at core/lib/website2.lib.php:207; when set the HTML5 doctype is emitted. No comment is present in the payload.', 'Enabling this constant ensures pages are served with an HTML5 DOCTYPE, which affects browser rendering mode; disabling it uses whatever doctype the template provides.', 'Any truthy value forces HTML5 DOCTYPE; unset uses the template default.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:207|check|if (getDolGlobalString(''WEBSITE_FORCE_DOCTYPE_HTML5'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_MANAGE_IMAGE_FOR_PAGES', 'string', NULL, 'website', 'Controls whether image management functionality is available for website pages in the editor.', 'Checked in website/index.php:4913 using getDolGlobalInt to conditionally show image management options for pages.', 'When set to a non-zero value, image management UI is shown for website pages; when unset or zero, it is not available.', '0 or empty = image management for pages disabled; non-zero = enabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:4913|check|if (getDolGlobalInt(''WEBSITE_MANAGE_IMAGE_FOR_PAGES'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PAGE_SHOW_INTERNAL_LINKS_TO_OBJECT', 'bool', NULL, 'website', 'Controls whether internal links to related objects are displayed on website pages.', 'When enabled, the website module renders internal links connecting pages to related Dolibarr objects. Referenced at website/index.php:5049 inside a conditional block with a TODO note suggesting replacement with element_element links.', 'Enabling this shows internal object links on website pages; disabling hides them. The sole occurrence carries a TODO comment indicating the feature is provisional.', '0 or empty = disabled (no links shown); non-empty = enabled (links shown)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:5049|check|if (getDolGlobalString(''WEBSITE_PAGE_SHOW_INTERNAL_LINKS_TO_OBJECT'')) {\t// TODO Replace this with link into element_element ?"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PERF_DISABLE_COUNTERS', 'bool', NULL, 'core', 'When set, disables performance counters on website pages.', 'Checked in a single location in core/lib/website.lib.php:455. The counter rendering block is skipped when getDolGlobalInt returns a truthy value.', 'Enabling this suppresses website performance counter output. Disabling (or leaving unset) allows counters to be rendered.', '0 or unset = counters enabled; non-zero = counters disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["website.lib.php:455|if (!getDolGlobalInt(''WEBSITE_PERF_DISABLE_COUNTERS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PHP_ALLOW_DANGEROUS_CHARS', 'bool', NULL, 'core', 'Permits dangerous characters in website PHP page content that would otherwise be sanitised.', 'Checked as a negated condition at core/lib/website2.lib.php:1046 with inline comment ''If option is not on, we disallow functions to execute commands''.', 'Enabling this constant bypasses dangerous-character sanitisation in website PHP pages, which may allow injection of hazardous content; leaving it unset keeps sanitisation active.', 'Any truthy value permits dangerous characters; unset enforces sanitisation.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:1046|check|if (!getDolGlobalString(''WEBSITE_PHP_ALLOW_DANGEROUS_CHARS'')) {    // If option is not on, we disallow functions to execute commands"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PHP_ALLOW_EXEC', 'bool', NULL, 'core', 'Permits execution of system commands (exec-family functions) within website PHP pages.', 'Checked as a negated condition at core/lib/website2.lib.php:993 with inline comment ''If option is not on, we disallow functions to execute commands''.', 'Enabling this constant unlocks system command execution from website pages, which is a significant security risk; leaving it unset keeps those functions blocked.', 'Any truthy value permits exec functions; unset or 0 disallows them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:993|check|if (!getDolGlobalString(''WEBSITE_PHP_ALLOW_EXEC'')) {    // If option is not on, we disallow functions to execute commands"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PHP_ALLOW_WRITE', 'bool', NULL, 'core', 'Permits file-write operations within website PHP pages.', 'Checked as a negated condition at core/lib/website2.lib.php:998 with inline comment ''If option is not on, we disallow functions to write files''.', 'Enabling this constant allows website PHP pages to write files to the filesystem; leaving it unset blocks file-write functions for security.', 'Any truthy value permits file-write functions; unset or 0 disallows them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:998|check|if (!getDolGlobalString(''WEBSITE_PHP_ALLOW_WRITE'')) {    // If option is not on, we disallow functions to write files"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_PHP_DISALLOW_READ', 'bool', NULL, 'core', 'Disallows file-read operations within website PHP pages.', 'Checked at core/lib/website2.lib.php:1002 with inline comment ''If option is not on, we disallow functions to read files'', though the logic is inverted — it disallows reading when the constant IS set.', 'Setting this constant blocks file-read PHP functions in website pages, hardening security; leaving it unset allows file reads.', 'Any truthy value disallows file-read functions; unset permits them.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["core/lib/website2.lib.php:1002|check|if (getDolGlobalString(''WEBSITE_PHP_DISALLOW_READ'')) {    // If option is not on, we disallow functions to read files"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_REPLACE_INFO_ABOUT_USAGE_WITH_WEBSERVER', 'string', NULL, 'website', 'Stores a translation key used to replace the default web server usage information text in the website editor.', 'Checked and read in website/index.php at lines 3381 and 3383, where its value is passed to $langs->trans() and appended to the HTML info text block.', 'When set, the standard web server usage information is replaced with the translated string corresponding to this constant''s value.', 'A Dolibarr translation key string; empty/unset = default usage info shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:3381|check|if (getDolGlobalString(''WEBSITE_REPLACE_INFO_ABOUT_USAGE_WITH_WEBSERVER'')) {", "website/index.php:3383|read|$htmltext .= ''<br>''.$langs->trans(getDolGlobalString(''WEBSITE_REPLACE_INFO_ABOUT_USAGE_WITH_WEBSERVER''));"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_SITEMAPS_ADD_WEEKLY_FREQ', 'string', NULL, 'website', 'Controls whether a weekly changefreq element is added to sitemap entries in the website module.', 'Checked in website/index.php at lines 2841 and 2946 to conditionally include the changefreq attribute in generated sitemap XML.', 'When set, sitemap entries include a weekly change frequency hint for search engines; when unset, the changefreq element is omitted.', 'Empty/unset = changefreq not added; non-empty = changefreq=''weekly'' added to sitemap entries.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:2841|check|if (getDolGlobalString(''WEBSITE_SITEMAPS_ADD_WEEKLY_FREQ'')) {", "website/index.php:2946|check|if (getDolGlobalString(''WEBSITE_SITEMAPS_ADD_WEEKLY_FREQ'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEBSITE_SUBCONTAINERSINLINE', 'string', NULL, 'website', 'Enables the ''Include dynamic content'' (sub-containers inline) mode in the website editor.', 'Set programmatically in website/index.php at lines 480, 2747, and 3694 (and deleted at line 486); checked at lines 5955 and 3700. A commented line at 470 notes ''// Force disable of ''Include dynamic content''''. A comment at 5954 states ''// If mode WEBSITE_SUBCONTAINERSINLINE is on''.', 'When enabled, the website editor renders sub-containers inline within the page; when disabled, this dynamic content inclusion mode is off.', 'Empty/unset or 0 = sub-containers inline disabled; 1 = enabled (''Include dynamic content'' mode on).', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["website/index.php:470  //dolibarr_set_const($db, ''WEBSITE_SUBCONTAINERSINLINE'', 0); // Force disable of ''Include dynamic content''", "website/index.php:5954  // If mode WEBSITE_SUBCONTAINERSINLINE is on", "website/index.php:5955|check|if (getDolGlobalString(''WEBSITE_SUBCONTAINERSINLINE'')) {", "website/index.php:480|write|dolibarr_set_const($db, ''WEBSITE_SUBCONTAINERSINLINE'', 1);"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WEIGHINGSCALE_PROTOCOL', 'string', NULL, 'takepos', 'Selects the communication protocol used with the connected weighing scale.', 'Checked at takepos/index.php:1094; value ''diag06'' triggers a specific protocol branch for scale communication. No admin UI write is present.', 'Setting to ''diag06'' activates that scale protocol; other values or unset use a different code path.', '''diag06'' = use diag06 weighing scale protocol; other string = different protocol; unset = no specific protocol.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["takepos/index.php:1094|check|<?php if (getDolGlobalString(''WEIGHINGSCALE_PROTOCOL'') == \"diag06\") { ?>"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WITHDRAWAL_ALLOW_ANY_INVOICE_STATUS', 'bool', NULL, 'compta', 'Removes the invoice status restriction when building direct debit or credit transfer payment batches.', 'When unset, bonprelevement.class.php:956, 1031, 1036, compta/prelevement/index.php:125, create.php:427, demandes.php:174, and compta/paymentbybanktransfer/index.php:143 all enforce a status filter on invoices eligible for withdrawal. Setting this constant bypasses that filter. No admin UI write path exists.', 'Enabling this constant allows invoices of any status to be included in withdrawal batches; without it, only invoices meeting the default status criteria are eligible.', 'Truthy string/bool=any status allowed, empty/0=status filter enforced', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/prelevement/class/bonprelevement.class.php:956|check|if (!getDolGlobalString(''WITHDRAWAL_ALLOW_ANY_INVOICE_STATUS'')) {", "compta/prelevement/class/bonprelevement.class.php:1031|check|if (!getDolGlobalString(''WITHDRAWAL_ALLOW_ANY_INVOICE_STATUS'')) {", "compta/prelevement/index.php:125|check|if (!getDolGlobalString(''WITHDRAWAL_ALLOW_ANY_INVOICE_STATUS'')) {", "compta/prelevement/create.php:427|check|if (!getDolGlobalString(''WITHDRAWAL_ALLOW_ANY_INVOICE_STATUS'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WITHDRAWAL_WITHOUT_BIC', 'string', NULL, 'societe', 'Allows bank direct debit/withdrawal operations without requiring a valid BIC/SWIFT code.', 'Checked in 10 occurrences in societe/paymentmodes.php and compta/bank/class/account.class.php. The comment at account.class.php:1675 states: ''A non valid BIC/Swift is a problem if: it is not empty or always a problem if WITHDRAWAL_WITHOUT_BIC is not set''.', 'When set to a non-zero value, BIC/SWIFT validation is skipped for direct debit operations; when 0 or unset, BIC is mandatory for withdrawals.', '0 = BIC required; non-zero = BIC not required for withdrawals', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/bank/class/account.class.php:1675  // A non valid BIC/Swift is a problem if: it is not empty or always a problem if WITHDRAWAL_WITHOUT_BIC is not set).", "societe/paymentmodes.php:152|check|if (!GETPOST(''label'', ''alpha'') || !(GETPOST(''bank'', ''alpha'') || (getDolGlobalInt(''WITHDRAWAL_WITHOUT_BIC'') != 0))) {", "societe/paymentmodes.php:171|check|if (!GETPOST(''bic'') && (getDolGlobalInt(''WITHDRAWAL_WITHOUT_BIC'') == 0)) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WITHDRAW_STRICT_CHECK_AMOUNT', 'string', NULL, 'compta', 'Enables amount-based validation for direct debit withdrawal requests instead of request-count-based validation.', 'When set, compta/facture/prelevement.php:806 and 892 allow multiple partial withdrawal requests as long as the total does not exceed the invoice total. core/class/commoninvoice.class.php:1421 and 1573 check the sum of amounts rather than just counting requests.', 'Enabling this constant permits multiple partial debit requests up to the invoice total; disabling it enforces a simpler request-count check.', 'Truthy value enables sum-based amount checking; absent or falsy uses the default request-count check.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/facture/prelevement.php:804  // If WITHDRAW_STRICT_CHECK_AMOUNT is enabled, allow multiple partial requests as long as the total requested amount doesn''t exceed the invoice total", "core/class/commoninvoice.class.php:1420  // If WITHDRAW_STRICT_CHECK_AMOUNT is enabled, we check the sum of amounts instead of just counting requests", "compta/facture/prelevement.php:806|check|if (getDolGlobalString(''WITHDRAW_STRICT_CHECK_AMOUNT'')) {", "core/class/commoninvoice.class.php:1421|check|if (getDolGlobalString(''WITHDRAW_STRICT_CHECK_AMOUNT'')) {"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_BILL_ON_RECEPTION', 'string', NULL, 'reception', 'Controls whether the ''Billed'' column and billing workflow are active for receptions.', 'Checked in reception/card.php:2913 and 2923 to show the billing action button, and in reception/list.php:152 to enable the ''Billed'' column. Also referenced in admin/workflow.php:206 for workflow configuration. Configured via admin/workflow.php.', 'When not set to ''0'', the billed status column and create-invoice action are shown on reception pages; setting it to ''0'' hides them.', 'Any value other than ''0''=billing workflow active; ''0''=billing workflow disabled', 0, 0, 'admin/workflow.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/workflow.php:206|read|''enabled'' => isModEnabled(\"reception\") && isModEnabled(\"supplier_invoice\") && getDolGlobalString(''WORKFLOW_BILL_ON_RECEPTION'') !== ''0'',", "reception/card.php:2913|check|if (getDolGlobalString(''WORKFLOW_BILL_ON_RECEPTION'') !== ''0'') {", "reception/list.php:152|read|''e.billed'' => array(''label'' => $langs->trans(\"Billed\"), ''checked'' => ''1'', ''position'' => 1000, ''enabled'' => ''getDolGlobalString(\"WORKFLOW_BILL_ON_RECEPTION\") !== \"0\"'')"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_BILL_ON_SHIPMENT', 'string', NULL, 'commande', 'Controls whether invoicing is triggered automatically when a shipment is validated, shifting the billing workflow from order to shipment.', 'Configured via admin/workflow.php (line 189). Checked in expedition/card.php:3812 and 3821 to trigger billing actions on shipment validation, and in commande/card.php:3639 and 3644 to suppress the ''classify billed'' action on orders when active. Also controls visibility of the ''Billed'' column in list views.', 'When set (and not ''0''), the billed status is managed at the shipment level rather than the order level, affecting column visibility and billing action availability across order and shipment UIs.', 'Non-''0'' truthy string to enable billing on shipment; ''0'' or empty to disable.', 0, 0, 'admin/workflow.php', 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["admin/workflow.php:189|read|''enabled'' => isModEnabled(\"shipping\") && isModEnabled(\"invoice\") && getDolGlobalString(''WORKFLOW_BILL_ON_SHIPMENT'') !== ''0'',", "expedition/card.php:3812|check|if (getDolGlobalString(''WORKFLOW_BILL_ON_SHIPMENT'') !== ''0'') {", "commande/card.php:3639|check|if ($usercancreate && $object->status >= Commande::STATUS_VALIDATED && !getDolGlobalString(''ORDER_DISABLE_CLASSIFY_BILLED_FROM_ORDER'') && !getDolGlobalString(''WORKFLOW_BILL_ON_SHIP", "commande/list.php:267|read|''c.facture'' => array(''label'' => \"Billed\", ''checked'' => ''1'', ''enabled'' => (string) (int) (!getDolGlobalString(''WORKFLOW_BILL_ON_SHIPMENT'')), ''position'' => 995),"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_CAN_CREATE_PURCHASE_ORDER_FROM_PROPOSAL', 'string', NULL, 'comm', 'Enables a workflow button to create a purchase order directly from a signed proposal.', 'When set, the proposal card exposes an action to generate a purchase order based on the proposal content. Seen in comm/propal/card.php:3624.', 'Enabling this adds a cross-module shortcut; disabling or leaving it unset hides the purchase-order creation action on proposals.', 'Empty/unset = no purchase order creation button on proposals; truthy value = button is shown.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3624|check|if (getDolGlobalString(''WORKFLOW_CAN_CREATE_PURCHASE_ORDER_FROM_PROPOSAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_CLASSIFY_IF_AMOUNTS_ARE_DIFFERENTS', 'string', NULL, 'core', 'Allows workflow auto-classification to proceed even when invoice and order amounts differ.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:671. When set, the amount-difference check is bypassed during workflow classification.', 'Enabling this causes Dolibarr to classify orders or proposals as billed even when the invoice amount does not exactly match the order amount.', '0 or empty = classification skipped when amounts differ; non-empty = classification proceeds regardless of amount difference', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:671|check|if (getDolGlobalString(''WORKFLOW_CLASSIFY_IF_AMOUNTS_ARE_DIFFERENTS'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_DISABLE_CREATE_INVOICE_FROM_ORDER', 'bool', NULL, 'commande', 'Disables the action to create an invoice directly from an order.', 'Checked at compta/index.php:624 to hide the shortcut widget, and at commande/card.php:3610 to remove the ''create invoice'' permission entry, and at commande/card.php:3616 to hide the button. No admin UI is provided.', 'Enabling this constant removes the ''create invoice from order'' action from both the accounting dashboard and the order card, preventing direct invoice creation from orders.', 'Non-empty/truthy = invoice-from-order action disabled; empty/unset = action available.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["compta/index.php:624|check|if (isModEnabled(''invoice'') && isModEnabled(''order'') && $user->hasRight(\"commande\", \"lire\") && !getDolGlobalString(''WORKFLOW_DISABLE_CREATE_INVOICE_FROM_ORDER'')) {", "commande/card.php:3616|read|if (isModEnabled(''facture'') && $user->hasRight(''facture'', ''creer'') && empty($conf->global->WORKFLOW_DISABLE_CREATE_INVOICE_FROM_ORDER)) {", "commande/card.php:3610|read|''perm'' => ($user->hasRight(''facture'', ''creer'') && !getDolGlobalInt(''WORKFLOW_DISABLE_CREATE_INVOICE_FROM_ORDER'')),"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_ORDER', 'string', NULL, 'core', 'Automatically marks a sales order as billed when the total invoiced amount reaches the order amount.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:175, expedition/list.php:1127, and commande/list.php:1693, all guarded by the order module and workflow being enabled.', 'Enabling this causes Dolibarr to automatically set the order to ''billed'' status once cumulative invoice amounts match the order total.', '0 or empty = order not auto-classified billed by amount; non-empty = order auto-classified when invoice amounts match', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:175|check|if (isModEnabled(''order'') && !empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_ORDER'')) {", "expedition/list.php:1127|check|if (!empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_ORDER'')) {", "commande/list.php:1693|check|if (!empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_ORDER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_SUPPLIER_ORDER', 'string', NULL, 'core', 'Automatically marks a supplier order as billed when the invoiced amount reaches the order amount.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:310. The comment at line 308 explicitly documents the intent: set purchase order to ''Billed'' if this constant is set.', 'Enabling this causes Dolibarr to set supplier orders to ''billed'' automatically when invoice amounts match.', '0 or empty = supplier order not auto-classified billed; non-empty = supplier order classified billed by invoice amount', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:308  // Firstly, we set to purchase order to \"Billed\" if WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_SUPPLIER_ORDER is set.", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:310|check|if ((isModEnabled(\"supplier_order\") || isModEnabled(\"supplier_invoice\")) && getDolGlobalString(''WORKFLOW_INVOICE_AMOUNT_CLASSIFY_BILLED_SUPPLIER_ORDER'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_INVOICE_CLASSIFY_BILLED_ORDER', 'string', NULL, 'core', 'Automatically marks a sales order as billed when the linked invoice is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:413, guarded by the order module being enabled.', 'Enabling this causes Dolibarr to set the sales order to ''billed'' status automatically when an invoice linked to it is validated.', '0 or empty = order not auto-classified billed on invoice; non-empty = order classified billed on invoice validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:413|check|if (isModEnabled(''order'') && getDolGlobalString(''WORKFLOW_INVOICE_CLASSIFY_BILLED_ORDER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_INVOICE_CLASSIFY_BILLED_PROPAL', 'string', NULL, 'core', 'Automatically marks the originating proposal as billed when its linked invoice is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:199, guarded by the propal module and workflow being enabled.', 'Enabling this causes the source proposal to be set to ''billed'' status automatically when the linked invoice is validated.', '0 or empty = proposal not auto-marked billed on invoice; non-empty = proposal marked billed when invoice is validated', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:199|check|if (isModEnabled(\"propal\") && !empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_INVOICE_CLASSIFY_BILLED_PROPAL'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_INVOICE_CLASSIFY_BILLED_SUPPLIER_PROPOSAL', 'string', NULL, 'core', 'Automatically marks a supplier proposal as billed when the linked supplier invoice is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:334. The comment at line 333 explicitly states: set the linked Proposal to ''Billed'' if this constant is set.', 'Enabling this causes the linked supplier proposal to be set to ''billed'' status automatically upon invoice validation.', '0 or empty = supplier proposal not auto-classified billed; non-empty = supplier proposal marked billed on invoice validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:333  // Secondly, we set to linked Proposal to \"Billed\" if WORKFLOW_INVOICE_CLASSIFY_BILLED_SUPPLIER_PROPOSAL is set.", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:334|check|if (isModEnabled(''supplier_proposal'') && getDolGlobalString(''WORKFLOW_INVOICE_CLASSIFY_BILLED_SUPPLIER_PROPOSAL'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_ORDER_AUTOCREATE_INVOICE', 'string', NULL, 'core', 'Triggers automatic creation of an invoice when a sales order is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:115 when the invoice module is enabled. The modWorkflow comment at core/modules/modWorkflow.class.php:86 records the constant name and default value of ''1''.', 'Enabling this causes an invoice to be created automatically upon order validation; disabling requires manual invoice creation.', 'Empty or 0 = no auto-invoice creation; 1 = invoice auto-created on order validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:115|check|if (isModEnabled(''invoice'') && getDolGlobalString(''WORKFLOW_ORDER_AUTOCREATE_INVOICE'')) {", "core/modules/modWorkflow.class.php:86  //0=>array(''WORKFLOW_ORDER_AUTOCREATE_INVOICE'', ''chaine'', ''1'', ''WORKFLOW_ORDER_AUTOCREATE_INVOICE'', 0, ''current'', 0),"]', 'low', NULL);
