INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_PROPAL_AUTOCREATE_ORDER', 'string', NULL, 'core', 'Triggers automatic creation of a sales order when a proposal is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:79 when the order module is enabled. The modWorkflow comment at core/modules/modWorkflow.class.php:85 shows the constant name and default value of ''1''.', 'Enabling this causes a sales order to be created automatically upon proposal validation; disabling requires manual order creation.', 'Empty or 0 = no auto-order creation; 1 = order auto-created on proposal validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:79|check|if (isModEnabled(''order'') && getDolGlobalString(''WORKFLOW_PROPAL_AUTOCREATE_ORDER'')) {", "core/modules/modWorkflow.class.php:85  //0=>array(''WORKFLOW_PROPAL_AUTOCREATE_ORDER'', ''chaine'', ''1'', ''WORKFLOW_PROPAL_AUTOCREATE_ORDER'', 0, ''current'', 0),"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_PROPAL_NEED_INVOICE_TO_BE_CLASSIFIED_BILLED', 'string', NULL, 'comm', 'Requires at least one linked invoice to exist before a proposal can be marked as billed.', 'When set, the proposal can be classified as billed only if there are linked invoices in the arrayofinvoiceforpropal array. Without it, the billed classification is available regardless. Seen in comm/propal/card.php:3697.', 'Enabling this enforces that billing only occurs after invoices are created and linked, preventing premature status transitions.', 'Empty/unset = billed classification allowed without invoices; truthy value = at least one linked invoice required.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["comm/propal/card.php:3697|check|if ((is_array($arrayofinvoiceforpropal) && count($arrayofinvoiceforpropal) > 0) || !getDolGlobalString(''WORKFLOW_PROPAL_NEED_INVOICE_TO_BE_CLASSIFIED_BILLED'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE', 'string', NULL, 'core', 'Automatically marks a reception as billed when the linked invoice is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:382. The comment at line 381 states it sets the reception to ''Billed''. Line 357 confirms this replaced the deprecated WORKFLOW_RECEPTION_CLASSIFY_CLOSED_INVOICE. The class method is documented in reception/class/reception.class.php:2146.', 'Enabling this causes Dolibarr to classify receptions as invoiced automatically on invoice validation.', '0 or empty = reception not auto-classified billed; non-empty = reception classified as billed on invoice validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:357  // Set reception to \"Closed\" if WORKFLOW_RECEPTION_CLASSIFY_CLOSED_INVOICE is set (deprecated, WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE instead))", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:381  // Then set reception to \"Billed\" if WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE is set", "reception/class/reception.class.php:2146  *\tClassify the reception as invoiced (used for example by trigger when WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE is on)", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:382|check|if (isModEnabled(\"reception\") && !empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_RECEPTION_CLASSIFY_CLOSED_INVOICE', 'string', NULL, 'core', 'Triggers automatic classification of a reception as ''Closed'' when an associated invoice is closed, as a deprecated workflow setting.', 'Used in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:359. The comment at line 357 explicitly marks this as deprecated, recommending WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE instead.', 'When enabled, closing an invoice triggers the reception to be set to ''Closed'' status automatically; this behavior is deprecated.', 'Non-empty = enabled (reception auto-closed on invoice close); empty/unset = disabled.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["// Set reception to \"Closed\" if WORKFLOW_RECEPTION_CLASSIFY_CLOSED_INVOICE is set (deprecated, WORKFLOW_RECEPTION_CLASSIFY_BILLED_INVOICE instead))", "if (isModEnabled(\"reception\") && !empty($conf->workflow->enabled) && !empty($conf->global->WORKFLOW_RECEPTION_CLASSIFY_CLOSED_INVOICE)) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE', 'string', NULL, 'core', 'Automatically marks a shipment as billed when the linked invoice is validated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:247. The comment at line 222 identifies this as the replacement for the deprecated WORKFLOW_SHIPPING_CLASSIFY_CLOSED_INVOICE. The method it invokes is documented in expedition/class/expedition.class.php:3122.', 'Enabling this causes Dolibarr to classify the shipment as invoiced automatically upon invoice validation.', '0 or empty = shipment not auto-classified billed; non-empty = shipment classified as billed on invoice validation', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:222  // Set shipment to \"Closed\" if WORKFLOW_SHIPPING_CLASSIFY_CLOSED_INVOICE is set (deprecated, has been replaced with WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE instead))", "expedition/class/expedition.class.php:3122  *\tClassify the shipping as invoiced (used for example by trigger when WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE is on)", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:247|check|if (isModEnabled(\"shipping\") && !empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_SHIPPING_CLASSIFY_CLOSED_INVOICE', 'string', NULL, 'core', 'Deprecated: previously set shipments to ''Closed'' status when an invoice was validated; replaced by WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:223. The comment at line 222 explicitly marks it as deprecated and replaced by WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE.', 'This constant is deprecated; use WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE instead. If still set, it triggers closing of shipments on invoice validation.', '0 or empty = no effect; non-empty = shipment closed on invoice (deprecated behavior)', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:222  // Set shipment to \"Closed\" if WORKFLOW_SHIPPING_CLASSIFY_CLOSED_INVOICE is set (deprecated, has been replaced with WORKFLOW_SHIPPING_CLASSIFY_BILLED_INVOICE instead))", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:223|check|if (isModEnabled(\"shipping\") && !empty($conf->workflow->enabled) && getDolGlobalString(''WORKFLOW_SHIPPING_CLASSIFY_CLOSED_INVOICE'')) {"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_SUM_INVOICES_AMOUNT_CLASSIFY_BILLED_ORDER', 'string', NULL, 'core', 'Marks a sales order as billed when the sum of all linked invoice amounts equals the order total.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:271, guarded by both the order and workflow modules being enabled.', 'Enabling this causes Dolibarr to set the order to ''billed'' based on the cumulative sum of all linked invoices reaching the order amount.', '0 or empty = sum-based auto-classification disabled; non-empty = order auto-classified billed when sum of invoices matches', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:271|check|if (isModEnabled(''order'') && isModEnabled(''workflow'') && getDolGlobalString(''WORKFLOW_SUM_INVOICES_AMOUNT_CLASSIFY_BILLED_ORDER'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_TICKET_CLOSE_INTERVENTION', 'string', NULL, 'ticket', 'Automatically closes linked intervention records when a ticket is closed.', 'Checked in ticket/class/ticket.class.php at line 2089. The action only triggers when the intervention module is enabled.', 'Enabling this constant causes intervention records linked to a ticket to be closed automatically when the ticket is closed, reducing manual steps.', '0 or unset = linked interventions not closed automatically; 1 = linked interventions closed on ticket close', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["if (isModEnabled(''intervention'') && getDolGlobalString(''WORKFLOW_TICKET_CLOSE_INTERVENTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_TICKET_CREATE_INTERVENTION', 'string', NULL, 'core', 'Automatically creates an intervention (ficheinter) when a ticket is created or updated.', 'Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:630, guarded by the intervention, ticket, and workflow modules all being enabled.', 'Enabling this causes Dolibarr to create an intervention record automatically when ticket events are triggered.', '0 or empty = no auto-intervention creation; non-empty = intervention created automatically on ticket events', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:630|check|if (isModEnabled(''intervention'') && isModEnabled(''ticket'') && isModEnabled(''workflow'') && getDolGlobalString(''WORKFLOW_TICKET_CREATE_INTERVENTION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_TICKET_LINK_CONTRACT', 'string', NULL, 'admin', 'Enables automatic linking of a contract to a ticket based on the ticket''s third party and product category.', 'Managed via the admin UI at admin/workflow.php:225 and :376. The comment at admin/workflow.php:221 notes this depends on another workflow constant. Checked in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:598 together with TICKET_PRODUCT_CATEGORY.', 'Enabling this causes Dolibarr to automatically find and link a contract to newly created or updated tickets when the contract module, ticket module, and workflow module are all active.', '0 or empty = no auto-linking; non-empty = contracts are automatically linked to tickets', 0, 0, 'admin/workflow.php|admin/workflow.php', 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["admin/workflow.php:221  // This one depends on previous one WORKFLOW_TICKET_LINK_CONTRACT", "admin/workflow.php:225|read|''enabled'' => (isModEnabled(''ticket'') && isModEnabled(''contract'') && getDolGlobalString(''WORKFLOW_TICKET_LINK_CONTRACT'')),", "core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:598|check|if (isModEnabled(''contract'') && isModEnabled(''ticket'') && isModEnabled(''workflow'') && getDolGlobalString(''WORKFLOW_TICKET_LINK_CONTRACT'') && getDolGlobalString(''TICKET_PRODUCT_CATE"]', 'high', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKFLOW_TICKET_USE_PARENT_COMPANY_CONTRACTS', 'bool', NULL, 'core', 'Controls whether contract lookup for ticket linking includes contracts of parent companies.', 'Read in core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:600; when not set, only the ticket''s direct company ID is used; when set, parent company IDs are also included via getParentsForCompany.', 'Enabling this widens the contract search to include parent companies of the ticket''s third party, allowing contracts at higher levels of the company hierarchy to be linked.', '0 or empty = only direct company contracts considered; non-empty = parent company contracts also included', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["core/triggers/interface_20_modWorkflow_WorkflowManager.class.php:600|read|$company_ids = (!getDolGlobalString(''WORKFLOW_TICKET_USE_PARENT_COMPANY_CONTRACTS'')) ? [$object->fk_soc] : $societe->getParentsForCompany($object->fk_soc, [$object->fk_soc]);"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKSTATION_ADDON_PDF', 'string', NULL, 'workstation', 'Specifies the PDF generation module to use for workstation documents.', 'Read at workstation/class/workstation.class.php:902-903 as an elseif fallback when no other PDF model is selected. No admin UI is provided.', 'Setting this constant designates the fallback PDF module for workstation document generation.', 'A PDF module name string; empty/unset = no fallback PDF module.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["workstation/class/workstation.class.php:902|read|} elseif (getDolGlobalString(''WORKSTATION_ADDON_PDF'')) {", "workstation/class/workstation.class.php:903|read|$modele = getDolGlobalString(''WORKSTATION_ADDON_PDF'');"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKSTATION_INCLUDE_DOC_GENERATION', 'string', NULL, 'admin', 'When enabled, includes document generation capabilities in the workstation module.', 'Checked in admin/workstation.php:287; when the integer value is truthy, a document generation code path is activated. Configurable via admin/workstation.php.', 'Enabling this constant adds document generation features to the workstation module; leaving it unset omits those features.', '1 = document generation included; 0 or unset = not included.', 0, 0, 'admin/workstation.php', 1, NULL, NULL, '2026-04-21T13:29:58+00:00', '["admin/workstation.php:287|check|if (getDolGlobalInt(''WORKSTATION_INCLUDE_DOC_GENERATION'')) {"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKSTATION_WORKSTATION_ADDON', 'string', NULL, 'workstation', 'Specifies the active numbering module class name for workstations.', 'Read at workstation/class/workstation.class.php:838 as the class name to instantiate, and at line 837 to derive the include filename. When not set, it defaults to ''mod_workstation_standard'' (written at line 831). No admin UI is provided.', 'Changing this constant switches the numbering module used to generate workstation reference codes.', 'A module class name string (e.g., ''mod_workstation_standard''); empty/unset = defaults to ''mod_workstation_standard''.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["workstation/class/workstation.class.php:831|write|$conf->global->WORKSTATION_WORKSTATION_ADDON = ''mod_workstation_standard'';", "workstation/class/workstation.class.php:834|check|if (getDolGlobalString(''WORKSTATION_WORKSTATION_ADDON'')) {", "workstation/class/workstation.class.php:838|read|$classname = getDolGlobalString(''WORKSTATION_WORKSTATION_ADDON'');", "workstation/class/workstation.class.php:837|read|$file = getDolGlobalString(''WORKSTATION_WORKSTATION_ADDON'') . \".php\";"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WORKSTATION_WORKSTATION_ADVANCED_MASK', 'string', NULL, 'core', 'Defines the numbering mask used by the advanced workstation numbering module.', 'Read in core/modules/workstation/mod_workstation_advanced.php:91 to populate the mask input in the module configuration form, and at line 144 to generate workstation reference numbers.', 'Changing the mask alters the format of auto-generated workstation reference numbers.', 'String: a numbering mask pattern.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/modules/workstation/mod_workstation_advanced.php:91|read|... value=\"''.getDolGlobalString(''WORKSTATION_WORKSTATION_ADVANCED_MASK'').''\"...", "core/modules/workstation/mod_workstation_advanced.php:144|read|$mask = getDolGlobalString(''WORKSTATION_WORKSTATION_ADVANCED_MASK'');"]', 'medium', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WS_', 'string', NULL, 'core', 'Prefix for website-specific CSS custom property constants (e.g., WS_{REF}_MAIN_COLOR, WS_{REF}_SECONDARY_COLOR).', 'Used as a dynamic prefix in install/doctemplates/websites/website_template-association_exp/containers/styles.css.php:11385-11386 where the constant name is constructed at runtime from ''WS_'' + strtoupper($website->ref) + ''_MAIN_COLOR'' and ''_SECONDARY_COLOR''. No admin UI is provided.', 'Setting a constant of the form WS_{WEBSITEREF}_MAIN_COLOR or WS_{WEBSITEREF}_SECONDARY_COLOR overrides the corresponding CSS custom property for the named website template.', 'A CSS color string (e.g., ''#5d5b6a''); default fallback is ''#5d5b6a'' for main color and ''#FF7F50'' for secondary color.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T11:16:15+00:00', '["install/doctemplates/websites/website_template-association_exp/containers/styles.css.php:11385|read|--main-color: <?php print getDolGlobalString(''WS_'' . strtoupper($website->ref) . ''_MAIN_COLOR'') ?: ''#5d5b6a''; ?>;", "install/doctemplates/websites/website_template-association_exp/containers/styles.css.php:11386|read|--secondary-color: <?php print getDolGlobalString(''WS_'' . strtoupper($website->ref) . ''_SECONDARY_COLOR'') ?: ''#FF7F50''; ?>;"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('WYSIWYG_ALLOW_UPLOAD_MEDIA_FILES', 'bool', NULL, 'core', 'Enables file upload functionality within the WYSIWYG editor (CKEditor/FCKeditor) for media files.', 'Read at core/class/doleditor.class.php:123 and assigned to $uselocalbrowser to enable the local file browser in the editor. No admin UI; hidden setting.', 'Setting to 1 enables media file upload and browsing within the rich text editor. Leaving unset or 0 disables this capability.', '0 or empty = media file upload disabled in WYSIWYG; 1 = media file upload enabled', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["core/class/doleditor.class.php:123|read|$uselocalbrowser = getDolGlobalInt(\"WYSIWYG_ALLOW_UPLOAD_MEDIA_FILES\");"]', 'low', NULL);
INSERT INTO constants(name, type, default_value, module, purpose, description, impact, possible_values, hidden_setting, hidden_setting_guess, admin_ui_files, doc_quality, content_hash, hash_version, last_enriched, evidence, confidence, conf_php_wiring) VALUES('XXX', 'string', NULL, 'master.inc.php', 'Placeholder constant name used in code comments to represent a generic or example constant name.', 'Appears in master.inc.php:298 in a comment describing how constants are read from the llx_const table. Referenced in multiple mailing module files (eventorganization, thirdparties, thirdparties_services_expired, xinputuser, xinputfile, advthirdparties) as a placeholder in PHPDoc describing the label fallback mechanism.', 'This is not a real configuration constant; it is a documentation placeholder and has no runtime effect.', 'Not a real constant; used only as a placeholder in code comments.', 1, 1, NULL, 1, NULL, NULL, '2026-04-21T13:50:40+00:00', '["master.inc.php:298|read|// Here we read database (llx_const table) and define conf var $conf->global->XXX.", "core/modules/mailings/eventorganization.modules.php:31  // This label is used if no translation is found for key XXX neither MailingModuleDescXXX where XXX=name is found", "core/modules/mailings/thirdparties.modules.php:35  * @var string This label is used if no translation is found for key XXX neither MailingModuleDescXXX where XXX=name is found"]', 'low', NULL);
